window.SITE_CONFIG = {"siteTitle": "广东省辅警统考通用真题库", "siteEmoji": "🚔", "subtitle": "笔试 2136 题 · 广东省标通用真题 · 适用多城", "logo": "", "cover": "cover.png?v=2", "themeColor": "#1e3a5f", "contact": "", "xianyuCode": "RCJ9527", "promoTitle": "作者 · rcj9527", "promoText": "线上预览版网络可能不稳定，建议用离线版（双击即用、可自由修改）。需要完整题库或私人定制，去🔍闲鱼搜索用户名 <b>RCJ9527</b>。", "rewardImage": "wechat-reward.png?v=2", "rewardTitle": "打赏作者 · 支持开源", "rewardDesc": "如果这个开源题库对你有帮助，请作者喝杯奶茶 ☕", "footerText": "© 辅警真题卡组 · 开源离线版", "timerSeconds": 180, "enabledModules": {"promo": true, "xianyu": true, "reward": true, "progress": true, "themeToggle": true, "record": false}, "defaultPage": "written", "examType": "paper", "examYear": "2024-2026", "realQuestions": true, "realQuestionsNote": "本题库为广东省公安机关警务辅助人员招聘考试通用真题（与惠州同源广东省标），适用于东莞 / 佛山 / 珠海 / 广州等广东多城辅警笔试，内容为真实省标真题、非按城市拼凑洗白。", "modules": {"mockExam": false, "targeted": true, "random": true, "written": true, "interview": false}};
window.DATA_WRITTEN = [{"num": 1, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）下列情形中，适用行政调解的是（）", "options": [{"letter": "A", "text": "甲结伙斗殴"}, {"letter": "B", "text": "乙雇凶伤害葛某"}, {"letter": "C", "text": "丙用震楼器报复邻居厕所漏水"}, {"letter": "D", "text": "丁多次实施违反治安管理行为"}], "answer": "C", "explanation": "根据新修订的《治安管理处罚法》，治安调解适用于因民间纠纷引起的打架斗殴、损毁财物等情节较轻的治安案件。A项结伙斗殴、B项雇凶伤害他人、D项多次实施违反治安管理行为，均属于不适用调解的情形。C项邻里之间因漏水引发的纠纷属于民间纠纷，且用震楼器报复属于损毁他人财物的治安违法行为，情节较轻，可以适用行政调解。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 0}, {"num": 2, "batch": "专业基础知识", "type": "single", "stem": "李某为A市甲区人，8月20日12时在乙区夜明珠夜总会内吸食毒品，8月20日14时许在回家的途中在丙区被公安机关抓获。关于此案管辖，下列说法正确的是（）。", "options": [{"letter": "A", "text": "居住地管辖更为适宜，由甲区公安机关管辖"}, {"letter": "B", "text": "甲、乙区公安机关对此案有管辖权"}, {"letter": "C", "text": "乙、丙区公安机关对此案有管辖权"}, {"letter": "D", "text": "甲、乙、丙区公安机关对此案均有管辖权"}], "answer": "C", "explanation": "根据《公安机关办理行政案件程序规定》，行政案件由违法行为发生地的公安机关管辖，违法行为发生地包括违法行为的实施地（乙区）和查获地（丙区）。甲区为居住地，一般不以居住地管辖为原则。因此乙区和丙区公安机关对此案有管辖权。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 1}, {"num": 3, "batch": "专业基础知识", "type": "single", "stem": "因赵×等4人有赌博嫌疑，处警民警对赵×等4人进行了有效控制，并当场对赵×家及相关人员和物品进行了检查。根据相关法律规定，下列选项中符合检查规定的是（）。", "options": [{"letter": "A", "text": "出示执法资格证件后可对涉案物品进行检查"}, {"letter": "B", "text": "出示人民警察证可当场对赵×人身进行检查"}, {"letter": "C", "text": "持水岩派出所批准的《检查证》检查赵×家"}, {"letter": "D", "text": "在执行当场检查时由两名辅警人员进行"}], "answer": "B", "explanation": "根据《治安管理处罚法》第87条和《公安机关办理行政案件程序规定》，人民警察出示人民警察证可以当场对违法嫌疑人的人身进行检查，B项正确。对住所进行检查需持县级以上公安机关开具的检查证，派出所无权开具。检查应由人民警察执行，辅警不能独立执行检查任务。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 2}, {"num": 4, "batch": "专业基础知识", "type": "single", "stem": "经查，陈某（17周岁）就读于甲县城东中学，甲县家中仅有陈某及妹妹陈小某，父母均在外地经商，经通知不能到场，其在甲县无其他亲属。根据法律的规定，办案民警对陈某询问时的正确做法是（）。", "options": [{"letter": "A", "text": "通知陈某的班长李某到场"}, {"letter": "B", "text": "通知陈某的妹妹陈小某到场"}, {"letter": "C", "text": "通知陈某的成年朋友孙某到场"}, {"letter": "D", "text": "通知甲县城东中学校方代表到场"}], "answer": "D", "explanation": "根据《公安机关办理行政案件程序规定》，询问未成年人时应当通知其父母或其他监护人到场。陈某17周岁，父母在外地经商经通知不能到场，且在甲县无其他亲属。在此情况下，应当通知其所在学校的代表到场，以保障未成年人的合法权益。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 3}, {"num": 5, "batch": "专业基础知识", "type": "single", "stem": "张某因涉嫌故意杀人犯罪被检察院依法提起公诉，下列人员中可以担任张某辩护人的是（）。", "options": [{"letter": "A", "text": "张某的父亲，现职法院法警"}, {"letter": "B", "text": "张某的大学法律老师胡某，2年前被吊销律师执业证书"}, {"letter": "C", "text": "张某的朋友黄某，处于缓刑考验期"}, {"letter": "D", "text": "张某的发小李某，现工作于当地基层人民检察院"}], "answer": "A", "explanation": "根据《刑事诉讼法》第33条及相关司法解释，现职司法工作人员一般不得担任辩护人，但如果是犯罪嫌疑人、被告人的监护人或近亲属则可以。张某的父亲虽为法院法警，但作为近亲属可以担任辩护人。B项胡某被吊销律师执业证书后不得以律师身份执业；C项处于缓刑考验期的人不得担任辩护人；D项现职检察院工作人员不得担任辩护人。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 4}, {"num": 6, "batch": "专业基础知识", "type": "single", "stem": "林某与谢某是生意伙伴，因合同纠纷发生激烈冲突，林某一气之下将谢某打伤。在旁人劝说下，林某决定去派出所投案。他出门后正准备打车前往时，遇到前来抓捕他的警察，林某当即表明自己正要去自首，并如实交代了打伤谢某的全过程。林某的行为属于（）。", "options": [{"letter": "A", "text": "自首"}, {"letter": "B", "text": "立功"}, {"letter": "C", "text": "坦白"}, {"letter": "D", "text": "悔罪"}], "answer": "A", "explanation": "根据最高人民法院《关于处理自首和立功具体应用法律若干问题的解释》，犯罪嫌疑人因病、伤或者为了减轻犯罪后果，委托他人先代为投案，或者先以信电投案的；罪行尚未被司法机关发觉，仅因形迹可疑被盘问、教育后主动交代罪行的，应当视为自动投案。林某在准备去投案途中遇到警察，当即表明要去自首并如实交代，属于'准备去投案途中'被抓获的情形，应认定为自首。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 5}, {"num": 7, "batch": "专业基础知识", "type": "single", "stem": "冯某与郑某因鱼塘分鱼一事发生口角，后冯某父亲赶到现场，对郑某辱骂不止。郑某气愤之下，猛然将冯某抱摔在地，并连踢数脚，在众人制止下，郑某停止了对冯某的殴打，冯某才得以起身报警。A县公安局拟对本案作出处理决定，关于鉴定以下说法正确的是（）。", "options": [{"letter": "A", "text": "如冯某自行前往卫生行政主管部门许可的医疗机构获取诊断证明，一般情况下，该证明可以作为公安机关认定人身伤害程度的依据"}, {"letter": "B", "text": "如冯某受伤程度较重，可能构成轻微伤以上伤害程度，公安机关应当为其鉴定伤情"}, {"letter": "C", "text": "如冯某、郑某二人对伤情程度产生争议，但冯某拒绝进行进一步伤情鉴定的，公安机关应当强制要求其进行伤情鉴定"}, {"letter": "D", "text": "如通知鉴定后，冯某无正当理由未在公安机关确定的时间内做伤情鉴定，公安机关应延缓案件办理"}], "answer": "A", "explanation": "根据《公安机关办理行政案件程序规定》，被侵害人自行到卫生行政主管部门许可的医疗机构取得的诊断证明，一般情况下可以作为公安机关认定人身伤害程度的依据，A项正确。公安机关不能强制要求进行伤情鉴定；当事人无正当理由未按时鉴定的，公安机关不应因此延缓案件办理。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 6}, {"num": 8, "batch": "专业基础知识", "type": "single", "stem": "经查，蔡×于2024年10月13日19时许在清水区上江村村民何×家中，明知罂粟苗属于毒品原植物而食用。2024年10月14日15时许，在清水区某农家乐内明知菜品中添加毒品原植物种子罂粟籽的情况下而食用，基于以上事实，公安机关拟对蔡×采取的做法正确的是（）。", "options": [{"letter": "A", "text": "作出行政拘留的处罚和延长社区戒毒的决定"}, {"letter": "B", "text": "作出强制隔离戒毒和行政拘留的处罚决定"}, {"letter": "C", "text": "作出强制隔离戒毒或罚款的处罚决定"}, {"letter": "D", "text": "作出吸毒成瘾的决定或强制隔离戒毒的决定"}], "answer": "B", "explanation": "蔡某明知罂粟苗为毒品原植物而食用，又明知菜品中添加罂粟籽而食用，其行为构成吸食毒品。根据《禁毒法》第38条和《吸毒成瘾认定办法》的相关规定，对于吸毒行为，公安机关可以作出行政拘留的处罚决定；对于符合强制隔离戒毒条件的，可以同时作出强制隔离戒毒的决定。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 7}, {"num": 9, "batch": "专业基础知识", "type": "single", "stem": "某地公安机关通过信息研判发现，社会上流传着近日要发生7.8级地震的消息。经向有关部门了解，确定该消息为谣言。但是群众对此议论纷纷，甚至有人准备晚上住在帐篷里。经公安机关调查走访和搜索网络信息来源，锁定了张某是该谣言的散布者。公安机关收集整理信息，并及时查处张某散布谣言的工作体现了公安机关和人民警察所承担的工作任务是：（）。", "options": [{"letter": "A", "text": "保护公共财产安全"}, {"letter": "B", "text": "保护人民群众的人身安全"}, {"letter": "C", "text": "维护社会公共安全"}, {"letter": "D", "text": "维护社会治安秩序"}], "answer": "D", "explanation": "根据《人民警察法》第6条，公安机关人民警察的职责包括维护社会治安秩序、制止危害社会治安秩序的行为等。张某散布地震谣言导致群众恐慌、社会秩序混乱，公安机关及时查处该谣言体现了维护社会治安秩序的工作任务。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 8}, {"num": 10, "batch": "专业基础知识", "type": "single", "stem": "某日，新东县公安局值班民警小刘接群众李某报案称，其所经营公司的一批货物（价值20万元）被发现丢失，怀疑是被内部员工职务侵占。在此情形下，小刘最妥当的做法是（）。", "options": [{"letter": "A", "text": "报办案部门负责人批准后进行调查核实"}, {"letter": "B", "text": "立即对怀疑对象采取刑事强制措施"}, {"letter": "C", "text": "口头告知李某证据不足，不予立案"}, {"letter": "D", "text": "向李某出具书面的不予受案告知书"}], "answer": "A", "explanation": "根据《公安机关办理刑事案件程序规定》，公安机关接受案件后，经审查，认为有犯罪事实需要追究刑事责任的，应当立案。在受案初期，应当报办案部门负责人批准后进行调查核实，不能立即采取刑事强制措施，也不能未经审查就口头告知不予立案或出具不予受案告知书。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 9}, {"num": 11, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）根据我国《治安管理处罚法》的规定，对一人有两种以上违反治安管理行为的，分别决定（）。", "options": [{"letter": "A", "text": "合并执行处罚"}, {"letter": "B", "text": "不予执行"}, {"letter": "C", "text": "分开执行"}, {"letter": "D", "text": "加重执行"}], "answer": "A", "explanation": "根据《治安管理处罚法》第16条规定，有两种以上违反治安管理行为的，分别决定，合并执行。行政拘留处罚合并执行的，最长不超过二十日。因此对一人有两种以上违反治安管理行为的，应分别决定后合并执行处罚。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 10}, {"num": 12, "batch": "专业基础知识", "type": "single", "stem": "根据《公安机关办理行政案件程序规定》，以下案件可以调解的是（）。", "options": [{"letter": "A", "text": "张某因工作矛盾对王某怀恨在心，遂找到无业人员刘某殴打王某，承诺事后给刘某500元好处费，刘某遂将王某打成轻微伤"}, {"letter": "B", "text": "吕某在小区通道随意停车影响吴某车辆进出，双方在争吵过程中，吕某用脚踢吴某车辆右前门，造成车辆损失价值1500元"}, {"letter": "C", "text": "秦某因嫉妒同事宋某工作能力强，对其当众辱骂，情节较轻，宋某报警后，明确表示不接受调解"}, {"letter": "D", "text": "夏某与周某、唐某在某饭店就餐过程中，因琐事与邻桌就餐的方某发生口角，夏某、周某和唐某联手将方某打成轻微伤"}], "answer": "B", "explanation": "根据《公安机关办理行政案件程序规定》，因民间纠纷引起的损毁他人财物等情节较轻的治安案件可以调解处理，但雇凶伤害他人、结伙斗殴等不适用调解。B项因停车纠纷引起的财物损毁属于民间纠纷，且损失金额较小，可以调解。A项属于雇凶殴打，C项当事人明确拒绝调解，D项属于结伙殴打他人，均不适用调解。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 11}, {"num": 13, "batch": "专业基础知识", "type": "single", "stem": "甲市公安机关在勘验某一杀人现场时，提取了插在被害人李某胸部的一把带有其血迹的匕首。从证据的角度看，该把匕首属于（）。", "options": [{"letter": "A", "text": "物证，直接证据，传来证据"}, {"letter": "B", "text": "书证，间接证据，原始证据"}, {"letter": "C", "text": "物证，间接证据，原始证据"}, {"letter": "D", "text": "书证，直接证据，传来证据"}], "answer": "C", "explanation": "匕首以其物质属性和外部特征证明案件事实，属于物证而非书证。匕首不能单独直接证明谁是犯罪嫌疑人，需要与其他证据结合才能证明案件主要事实，属于间接证据。匕首是直接从犯罪现场提取的原始物品，未经复制或转述，属于原始证据。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 12}, {"num": 14, "batch": "专业基础知识", "type": "single", "stem": "下列已经立案的刑事案件中，应由公安机关撤销案件的是（）。", "options": [{"letter": "A", "text": "水利局公务员张某涉嫌滥用职权罪，经过调查，发现证据不足"}, {"letter": "B", "text": "警察李某被指控涉嫌故意伤害罪、利用职权实施非法拘禁罪，后经侦查非法拘禁罪不成立"}, {"letter": "C", "text": "王某涉嫌盗窃罪，后经侦查情节轻微，不构成犯罪"}, {"letter": "D", "text": "法院在审理余某诈骗案时，发现案件已过追诉时效期"}], "answer": "C", "explanation": "根据《刑事诉讼法》第163条，在侦查过程中发现不应对犯罪嫌疑人追究刑事责任的，应当撤销案件。C项王某涉嫌盗窃罪情节轻微不构成犯罪，属于不应追究刑事责任的情形，公安机关应当撤销案件。A项滥用职权罪由监察机关管辖；B项非法拘禁罪不成立但故意伤害罪仍成立，不应全案撤销；D项已过追诉时效由法院裁定终止审理。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 13}, {"num": 15, "batch": "专业基础知识", "type": "single", "stem": "某日，北山县公安局特巡警大队在巡逻中抓获犯罪嫌疑人方X。经查，方X在东山县多次入户盗窃，后流窜至南山县实施抢劫，所获财物在西山县销赃。方X被抓获后，上述公安机关均对管辖权提出主张。根据法律规定，对方X的犯罪行为不具有管辖权的是（）。", "options": [{"letter": "A", "text": "北山县公安局"}, {"letter": "B", "text": "东山县公安局"}, {"letter": "C", "text": "南山县公安局"}, {"letter": "D", "text": "西山县公安局"}], "answer": "A", "explanation": "根据《刑事诉讼法》第25条，刑事案件由犯罪地的人民法院管辖，犯罪地包括犯罪行为发生地和结果发生地。东山县是盗窃地，南山县是抢劫地，西山县是销赃地，均有管辖权。北山县仅为抓获地，不是犯罪行为发生地或结果地，不具有管辖权。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 14}, {"num": 16, "batch": "专业基础知识", "type": "single", "stem": "某日，孙某因抢占停车位与武某发生争执，孙某气不过便抄起路边的砖头将武某驾驶侧车窗砸破，造成武某车辆损失2000元，后武某报警。单山县红霞派出所民警小龙、小飞负责本案办理，在案件办理过程中孙某发现民警小飞是武某的外甥，遂提出回避申请。对于民警小飞的回避，下列说法错误的是（）。", "options": [{"letter": "A", "text": "公安机关应当在收到孙某申请之日起二日内作出决定"}, {"letter": "B", "text": "在作出回避决定前，民警小飞继续开展对本案的调查工作"}, {"letter": "C", "text": "在作出回避决定后，民警小飞进行的与案件有关的活动是否有效，由作出决定的公安机关视情况决定"}, {"letter": "D", "text": "民警小飞的回避由单山县公安局治安大队决定"}], "answer": "D", "explanation": "根据《公安机关办理行政案件程序规定》，办案人民警察的回避由所属公安机关（即县公安局）决定，而非由治安大队决定，D项说法错误。A项公安机关应在收到回避申请之日起二日内作出决定；B项在作出回避决定前，被申请回避的人员不得停止对案件的调查；C项回避决定作出后，之前进行的活动是否有效由作出决定的公安机关视情况决定。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 15}, {"num": 17, "batch": "专业基础知识", "type": "single", "stem": "犯罪嫌疑人张某因涉嫌贩卖海洛因100克，被Y县公安机关当场抓获。在该案侦查期间存在以下情况，其中做法正确的是（）。", "options": [{"letter": "A", "text": "公安机关在每次讯问犯罪嫌疑人张某时，都应告知其有权委托律师作为辩护人并记录在案"}, {"letter": "B", "text": "若犯罪嫌疑人张某未委托辩护人，公安机关应当在5日内通知法律援助机构为其指派辩护律师"}, {"letter": "C", "text": "辩护律师向公安机关了解犯罪嫌疑人张某涉嫌罪名和主要事实时，公安机关应当告知"}, {"letter": "D", "text": "张某的辩护律师前往看守所与其会见前，应当向办案部门提出申请"}], "answer": "C", "explanation": "根据《刑事诉讼法》第34条及相关规定，辩护律师向办案机关了解犯罪嫌疑人涉嫌的罪名和案件有关情况时，办案机关应当依法告知，C项正确。A项并非要求每次讯问时都告知委托辩护人的权利；B项应当在发现未委托辩护人时及时通知，而非限定5日内；D项辩护律师前往看守所会见在押犯罪嫌疑人无需向办案部门提出申请。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 16}, {"num": 18, "batch": "专业基础知识", "type": "single", "stem": "华江市发生一起故意伤害案件，市公安局刑侦大队对现场进行了勘验，提取了犯罪嫌疑人的血迹；司法鉴定中心通过DNA比对后，刑侦大队抓获了犯罪嫌疑人张×。经进一步侦查发现赵某（15周岁）、李某目睹了案件发生过程。根据法律规定，下列证据材料经补正可以作为证据使用的是（）。", "options": [{"letter": "A", "text": "DNA鉴定报告书缺少鉴定人签名、盖章"}, {"letter": "B", "text": "民警小王同时询问赵某、李某时的证言"}, {"letter": "C", "text": "张×讯问笔录缺少张×核对确认并签名"}, {"letter": "D", "text": "询问赵某的笔录缺少其法定代理人签名"}], "answer": "D", "explanation": "根据《刑事诉讼法》及相关司法解释关于证据瑕疵补正的规定，DNA鉴定报告缺少鉴定人签名属于严重缺陷无法补正；同时询问多名证人违反个别询问原则，属于非法证据；讯问笔录缺少犯罪嫌疑人签名属于重大瑕疵无法补正。询问未成年证人的笔录缺少法定代理人签名属于可以补正的瑕疵证据，经补正后可以作为证据使用。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 17}, {"num": 19, "batch": "专业基础知识", "type": "single", "stem": "下列刑事案件应由人民检察院管辖的是（）。", "options": [{"letter": "A", "text": "某国有企业董事长陈某收受巨额贿赂"}, {"letter": "B", "text": "民警王某利用职权非法拘禁嫌疑人曾某"}, {"letter": "C", "text": "李某通过网络散播甲市存在连环杀人犯的谣言"}, {"letter": "D", "text": "丁某侵占邻居交由其保管的价值6000元的苹果手机"}], "answer": "B", "explanation": "根据修改后的《刑事诉讼法》第19条第2款，人民检察院在对诉讼活动实行法律监督中发现的司法工作人员利用职权实施的非法拘禁、刑讯逼供等侵犯公民权利、损害司法公正的犯罪，可以由人民检察院立案侦查。B项民警利用职权实施非法拘禁属于此类案件。A项受贿罪由监察委员会管辖；C项由公安机关管辖；D项侵占罪属于自诉案件。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 18}, {"num": 20, "batch": "专业基础知识", "type": "single", "stem": "张某于2017年7月因登山遭遇森林大火而失踪，经多方寻觅而杳无音信。其家人向法院申请宣告张某死亡，法院于2023年1月宣告其死亡。下列说法正确的是（）。", "options": [{"letter": "A", "text": "需下落不明满4年，才可以申请宣告死亡"}, {"letter": "B", "text": "森林大火发生之日视为其死亡的日期"}, {"letter": "C", "text": "被宣告死亡后，其妻子和张某的婚姻关系需向民政部门申请注销"}, {"letter": "D", "text": "若张某并未死亡，在被宣告死亡期间实施的民事法律行为因丧失民事主体资格而无效"}], "answer": "B", "explanation": "根据《民法典》第48条规定，因意外事件（如森林大火）下落不明宣告死亡的，意外事件发生之日视为其死亡的日期，B项正确。A项因意外事件下落不明不受4年期限限制；C项宣告死亡后婚姻关系自动消除，无需另行申请注销；D项被宣告死亡的人在被宣告死亡期间实施的民事法律行为仍然有效。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 19}, {"num": 21, "batch": "专业基础知识", "type": "single", "stem": "下列行为人，不需要承担刑事责任的是（）。", "options": [{"letter": "A", "text": "15周岁的甲在学校水箱里投放了危险物质"}, {"letter": "B", "text": "13周岁的乙抢劫了他人价值10万元的首饰"}, {"letter": "C", "text": "85周岁的丙因过失致人死亡"}, {"letter": "D", "text": "间歇性精神病人丁在精神状态正常时诈骗了他人3万元"}], "answer": "B", "explanation": "根据《刑法》第17条，已满14周岁不满16周岁的人对故意杀人、故意伤害致人重伤或死亡、强奸、抢劫、贩卖毒品、放火、爆炸、投放危险物质八种犯罪负刑事责任。B项乙13周岁，对抢劫罪不负刑事责任。A项15周岁投放危险物质属于八种犯罪之一，应负刑事责任；C项85周岁过失致人死亡应负刑事责任（可从轻）；D项间歇性精神病人在精神正常时犯罪应负刑事责任。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 20}, {"num": 22, "batch": "专业基础知识", "type": "single", "stem": "某派出所抓获一名流窜作案的盗窃犯罪嫌疑人并立案侦查，但其始终不讲真实姓名及住址，民警无法查明其身份。下列陈述错误的是（）。", "options": [{"letter": "A", "text": "不得停止对其犯罪行为的侦查取证"}, {"letter": "B", "text": "侦查羁留期限自查清其身份之日起计算"}, {"letter": "C", "text": "应当等查清身份后再移送人民检察院审查起诉"}, {"letter": "D", "text": "可以按其自报的姓名向人民检察院提请批准逮捕"}], "answer": "C", "explanation": "根据《刑事诉讼法》第160条，犯罪嫌疑人不讲真实姓名、住址，身份不明的，应当对其犯罪行为的侦查取证不得停止；侦查羁押期限自查清其身份之日起计算；可以按其自报的姓名提请批准逮捕和移送起诉。C项错误在于不能以身份不明为由停止移送审查起诉，只要犯罪事实清楚、证据确实充分即可移送。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 21}, {"num": 23, "batch": "专业基础知识", "type": "single", "stem": "小刚（男，22周岁）因为涉嫌实施网络电信诈骗被公安机关刑事拘留，小刚委托了周某为自己的辩护律师，在侦查期间周某不能够开展哪种执业活动？（）", "options": [{"letter": "A", "text": "向公安机关了解小刚涉嫌的罪名和案件情况"}, {"letter": "B", "text": "与在押的小刚会见和通信"}, {"letter": "C", "text": "为小刚申请变更强制措施"}, {"letter": "D", "text": "向小刚了解案件有关情况并核实证据"}], "answer": "D", "explanation": "根据《刑事诉讼法》第38条和第39条，在侦查期间辩护律师可以向公安机关了解涉嫌罪名和案件情况、与在押犯罪嫌疑人会见和通信、申请变更强制措施。但'向犯罪嫌疑人了解案件有关情况并核实证据'属于审查起诉阶段辩护律师的工作，侦查阶段辩护律师尚不能核实证据。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 22}, {"num": 24, "batch": "专业基础知识", "type": "single", "stem": "下列情形中，犯罪嫌疑人没有委托辩护人的情况下，公安机关应当通知法律援助律师为其提供辩护的是（）。", "options": [{"letter": "A", "text": "王某在商场盗窃被当场抓获，家庭贫困，无经济来源"}, {"letter": "B", "text": "陈某故意伤害他人被刑事拘留，其为美国国籍"}, {"letter": "C", "text": "唐某因非法吸收公众存款被刑事拘留，其为聋哑人"}, {"letter": "D", "text": "李某因赌博和贩卖毒品被刑事拘留，可能被判处十年以上有期徒刑"}], "answer": "C", "explanation": "根据《刑事诉讼法》第35条，犯罪嫌疑人、被告人是盲、聋、哑人，或者是尚未完全丧失辨认或者控制自己行为能力的精神病人，没有委托辩护人的，应当通知法律援助机构指派律师为其提供辩护。C项唐某为聋哑人，符合强制法律援助的条件。A项贫困不是强制法律援助的条件；B项外国人不属于法定强制援助对象；D项可能判处重刑不是强制法律援助的法定情形。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 23}, {"num": 25, "batch": "专业基础知识", "type": "single", "stem": "吴某是甲市人，常年居住在乙市以打零工为生，生活拮据。其住所楼下开有一家金银首饰店，营业时间较晚，常有顾客夜间独自一人来取走预定的金银饰品，其中不乏女性顾客，吴某心生贪念，在市场购买了头套和道具计划实施抢劫，某日晚吴某发现一女性独自前往金店取货，遂带齐工具在路口蹲守并成功抢走装有金银饰品的手提袋，抢劫成功后吴某驾驶自己的摩托车到达相邻的丙市售卖其中一部分首饰得现金3万元，而后驾驶摩托车回到老家将剩余首饰与现金藏匿。为躲避风头，吴某乘坐黑车转移至丁市藏匿，题目所涉四地中对案件不能管辖的公安机关是（）。", "options": [{"letter": "A", "text": "甲市公安机关"}, {"letter": "B", "text": "乙市公安机关"}, {"letter": "C", "text": "丙市公安机关"}, {"letter": "D", "text": "丁市公安机关"}], "answer": "D", "explanation": "根据《刑事诉讼法》第25条及相关规定，刑事案件由犯罪地公安机关管辖，犯罪地包括犯罪行为发生地和结果发生地。甲市是犯罪预备地，乙市是犯罪实施地，丙市是销赃地，均有管辖权。丁市仅为犯罪嫌疑人逃匿藏匿地，不是犯罪行为发生地或结果地，不具有管辖权。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 24}, {"num": 26, "batch": "专业基础知识", "type": "single", "stem": "某日，Y地发生一起盗窃案件，被害人所经营店铺内门锁被嫌疑人砸坏并盗走屋内的一尊金质寿桃，公安机关对该起案件立案侦查。在调查案件的过程中，公安机关以下做法错误的是（）。", "options": [{"letter": "A", "text": "公安机关在组织被害人对被盗金质寿桃照片进行辨认时，所使用的照片不得少于10张"}, {"letter": "B", "text": "辨认完毕后，应当制作辨认笔录，由侦查人员、辨认人、见证人分别签名，并应当全程录音录像"}, {"letter": "C", "text": "公安机关在对犯罪嫌疑人居住地点进行搜查时，因被搜查人在场其家属可以不在场"}, {"letter": "D", "text": "搜查嫌疑人住所任务必须由至少2名侦查人员执行"}], "answer": "B", "explanation": "根据《公安机关办理刑事案件程序规定》，对物品照片进行辨认时，陪衬照片不得少于5张（非10张），且辨认物品不要求全程录音录像。B项将辨认物品照片的标准混淆为辨认人员照片的标准（辨认人员照片不得少于10张），且对辨认物品不要求全程录音录像，说法错误。A项对被盗物品照片辨认不少于10张虽标准偏高但不错误；C项被搜查人在场时家属可以不在场正确；D项搜查须至少2名侦查人员执行正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 25}, {"num": 27, "batch": "专业基础知识", "type": "single", "stem": "甲2010年出门打工后失联，其妻子乙苦等10年无果，于2020年向法院申请宣告甲死亡，法院发布寻人公告三个月后依法判决宣告甲死亡。后甲于2024年返回家中，表明因赌博欠下巨额债务，不好意思跟家人联系。关于该案例，下列表述正确的是（）。", "options": [{"letter": "A", "text": "人民法院三个月的公告期符合法律规定"}, {"letter": "B", "text": "人民法院宣告死亡的判决作出之日视为甲死亡的日期"}, {"letter": "C", "text": "甲重新出现，人民法院应当主动撤销死亡宣告"}, {"letter": "D", "text": "甲返回后，妻子乙已经和丁再婚，甲可以主张乙丁婚姻无效"}], "answer": "B", "explanation": "根据《民法典》第48条，宣告死亡的判决作出之日视为其死亡的日期，B项正确。A项错误，一般情形下宣告死亡的公告期为1年，3个月公告期仅适用于因意外事件下落不明的情形；C项甲重新出现后应由本人或利害关系人申请撤销死亡宣告，法院不会主动撤销；D项乙已再婚的，甲不能主张乙丁婚姻无效。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 26}, {"num": 28, "batch": "专业基础知识", "type": "single", "stem": "刘某和董某在KTV打架斗殴，赵某全程目睹打架过程并一直声称刘某无理取闹。合力派出所民警将三人带回派出所制作笔录，二人的行为涉嫌违反《治安管理处罚法》。刘某发现办案民警小罗是董某关系要好的高中同学。关于该案民警小罗的回避，下列说法正确的是（）。", "options": [{"letter": "A", "text": "小罗和董某的同学关系不属于回避范围"}, {"letter": "B", "text": "民警小罗的回避由合力派出所决定"}, {"letter": "C", "text": "证人赵某明显偏向董某，应当回避"}, {"letter": "D", "text": "民警小罗不得停止对行政案件的调查"}], "answer": "B", "explanation": "根据《公安机关办理行政案件程序规定》，办案人民警察的回避由所属公安派出所决定，B项正确。民警小罗与董某是关系要好的高中同学，属于可能影响案件公正处理的关系，应当回避。证人赵某不适用回避制度，回避适用于办案人员、鉴定人员等。在作出回避决定前，民警小罗不得停止对案件的调查。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 27}, {"num": 29, "batch": "专业基础知识", "type": "single", "stem": "以下情形中适用治安调解处理的是（）。", "options": [{"letter": "A", "text": "某小区邻里因为垃圾丢弃问题引发口角争执，被到场民警制止"}, {"letter": "B", "text": "在校学生因课间打闹导致情绪激化发生斗殴，导致其中一人骨折（轻伤）"}, {"letter": "C", "text": "丙因多次在工作群中被丁刻意讥讽侮辱，一气之下上前将丁办公桌面上摆件摔碎（价值100元）"}, {"letter": "D", "text": "张三因怀疑妻子出轨李四，雇佣王五将李四殴打致轻微伤"}], "answer": "C", "explanation": "根据《公安机关办理行政案件程序规定》，因民间纠纷引起的治安案件情节较轻的可以调解处理，但雇凶伤害他人、多次实施违法行为、当事人明确拒绝调解的不适用调解。C项因工作矛盾引发的纠纷属于民间纠纷，毁坏财物价值仅100元情节较轻，且无排除情形，可以适用治安调解。A项可能涉及多次纠纷；B项致人轻伤已构成刑事案件；D项属于雇凶殴打他人。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 28}, {"num": 30, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）《治安管理处罚法》规定的处罚种类包括（）。", "options": [{"letter": "A", "text": "没收"}, {"letter": "B", "text": "取缔"}, {"letter": "C", "text": "责令改正"}, {"letter": "D", "text": "限期出境"}], "answer": "D", "explanation": "根据新修订的《治安管理处罚法》，治安管理处罚的种类包括：警告、罚款、行政拘留、吊销公安机关发放的许可证件，以及对违反治安管理的外国人可以附加适用限期出境或驱逐出境。限期出境属于治安管理处罚种类之一。没收、取缔、责令改正均不属于治安管理处罚的法定种类。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 29}, {"num": 31, "batch": "专业基础知识", "type": "single", "stem": "张某在甲地筹集毒资预谋贩卖毒品，后在乙地将部分毒品卖给了吸毒人孙某，交易完成后张某准备将剩余毒品藏在丙地的一出租屋，在驾车前往丙地途中，因形迹可疑在丁地被民警拦截检查，当场从其车内查获毒品若干。根据相关法律规定，本案（）公安机关没有管辖权。", "options": [{"letter": "A", "text": "甲地"}, {"letter": "B", "text": "乙地"}, {"letter": "C", "text": "丙地"}, {"letter": "D", "text": "丁地"}], "answer": "C", "explanation": "根据《公安机关办理刑事案件程序规定》，毒品犯罪案件的犯罪地包括毒资筹集地、交易地、查获地、目的地等。甲地为筹集毒资的预谋地，乙地为毒品交易地，丁地为查获地，均有管辖权。丙地仅为计划藏匿毒品的目的地，张某尚未到达即在丁地被查获，丙地不是实际犯罪行为发生地，不具有管辖权。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 30}, {"num": 32, "batch": "专业基础知识", "type": "single", "stem": "A市公安局民警在办理某起殴打他人案件的过程中，被侵害人王某向公安机关反映办案民警甲与嫌疑人存在亲属关系，要求甲进行回避。公安机关以下做法错误的是（）。", "options": [{"letter": "A", "text": "公安机关接受王某口头提出的回避申请，如实将申请原因及理由记录在案"}, {"letter": "B", "text": "经询问了解，违法嫌疑人为办案民警甲的姑姑，属于应当回避的情形"}, {"letter": "C", "text": "民警甲的回避决定应当由A市公安局局长作出"}, {"letter": "D", "text": "由于民警甲此前的调查工作不影响案件公正处理，因此甲所搜集的证据仍然有效"}], "answer": "C", "explanation": "根据《公安机关办理行政案件程序规定》，办案人民警察的回避由所属公安派出所负责人决定，而非由公安局局长决定，C项说法错误。A项接受口头回避申请并记录在案符合程序；B项违法嫌疑人是民警的近亲属（姑姑），属于应当回避的情形；D项回避前所进行的调查活动如果不影响案件公正处理，所搜集的证据仍然有效。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 31}, {"num": 33, "batch": "专业基础知识", "type": "single", "stem": "民警小高带领一名警务辅助人员小李在检查星灿酒店时，发现3304房间内的张某（16周岁），李某未实名登记，遂立即向所属公安派出所反馈。后经办案民警调查得知，前台登记工作人员明知程某以自己名义为李某、张某登记房间而未制止，为进一步查证违法事实，办案民警对张某进行了询问，根据相关规定，下列执法行为不符合规范的是（）。", "options": [{"letter": "A", "text": "小高和小李二人对星灿酒店检查"}, {"letter": "B", "text": "询问张某时，因其父母无法到场，在询问笔录中注明"}, {"letter": "C", "text": "对张某、李某未实名登记的行为批评教育"}, {"letter": "D", "text": "对星灿酒店前台登记工作人员作出行政处罚决定"}], "answer": "A", "explanation": "根据相关规定，对行业场所进行检查应当由两名以上人民警察进行，一名民警带领一名辅警不符合检查的法定人数要求，A项不符合规范。B项询问未成年人时父母无法到场在笔录中注明符合规定；C项对未成年人未实名登记行为予以批评教育适当；D项对前台工作人员未履行职责的行为可以作出行政处罚。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 32}, {"num": 34, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）治安管理当场处罚的罚款数额最高不得超过（）。", "options": [{"letter": "A", "text": "50元"}, {"letter": "B", "text": "1000元"}, {"letter": "C", "text": "500元"}, {"letter": "D", "text": "200元"}], "answer": "C", "explanation": "根据新修订的《治安管理处罚法》关于当场处罚的规定，违反治安管理事实确凿，处五百元以下罚款的，可以当场作出处罚决定。因此治安管理当场处罚的罚款数额最高不得超过500元。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 33}, {"num": 35, "batch": "专业基础知识", "type": "single", "stem": "民警小左、小明在巡理中发现马×形迹可疑，对其进行当场盘问，因马×拒不交代真实姓名，遂将其带至派出所继续盘问，期间发现其涉嫌故意伤害罪，决定对其执行刑事拘留。2日后因被害人伤情鉴定为轻微伤，即将马×的刑事拘留变更为行政拘留。对于马×的行政拘留执行，下列表述正确的是（）。", "options": [{"letter": "A", "text": "被刑事拘留的时间应当折抵行政拘留的时间"}, {"letter": "B", "text": "被当场盘问的时间应当折抵行政拘留的时间"}, {"letter": "C", "text": "被继续盘问的时间应当折抵行政拘留的时间"}, {"letter": "D", "text": "上述被限制人身自由的时间都不能折抵行政拘留时间"}], "answer": "A", "explanation": "根据《治安管理处罚法》第92条规定，对同一行为先采取刑事拘留措施的，刑事拘留的时间应当折抵行政拘留时间。当场盘问和继续盘问属于盘问检查措施，其限制人身自由的时间不属于刑事拘留，不折抵行政拘留时间。本案中马×先被刑事拘留后变更为行政拘留，刑事拘留期间应当折抵。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 34}, {"num": 36, "batch": "专业基础知识", "type": "single", "stem": "李某和张某是邻居，近期张某家中装修，李某多次要求张某每天早上9点后再开始动工，但张某并不同意，二人发生口角，李某将张某打成轻微伤。民警小陈拟对二人进行治安调解，关于本次治安调解，下列说法错误的是（）。", "options": [{"letter": "A", "text": "若李某在治安调解过程中又殴打张某，则不再适用调解处理"}, {"letter": "B", "text": "可以邀请李某和张某共同熟悉的邻居参加帮助调解"}, {"letter": "C", "text": "调解成功后应当制作调解协议书并由李某和张某签名"}, {"letter": "D", "text": "若一次调解不成，公安机关可以组织再次进行调解"}], "answer": "D", "explanation": "根据《公安机关办理行政案件程序规定》，治安调解一般为一次，对于一次调解不成但双方当事人均同意继续调解的，可以再调解一次。D项仅说'公安机关可以组织再次进行调解'，缺少了'双方当事人同意'的前提条件，表述不准确。A项调解过程中又殴打对方不再适用调解正确；B项可以邀请共同熟悉的邻居帮助调解正确；C项调解成功后制作调解协议书并签名正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 35}, {"num": 37, "batch": "专业基础知识", "type": "single", "stem": "甲绑架乙，并要求其亲属交付200万。在提出勒索要求后，为防止乙逃跑，直接将乙杀死。甲的行为构成（）。", "options": [{"letter": "A", "text": "绑架罪和故意杀人罪"}, {"letter": "B", "text": "敲诈勒索罪和故意杀人罪"}, {"letter": "C", "text": "绑架罪"}, {"letter": "D", "text": "故意杀人罪"}], "answer": "C", "explanation": "根据《刑法》第239条规定，犯绑架罪，杀害被绑架人的，或者故意伤害被绑架人致人重伤、死亡的，处无期徒刑或者死刑。即在绑架过程中杀害被绑架人的，属于绑架罪的加重情节，仅以绑架罪一罪论处，不再另定故意杀人罪，不实行数罪并罚。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 36}, {"num": 38, "batch": "专业基础知识", "type": "single", "stem": "甲乙丙三人合伙将盗来的自行车伪造手续并翻新后出售，购买人丁以新车价格购买（价值700元），警方得知后，为使该四名当事人到公安机关接受询问，采取的方式正确的是（）。", "options": [{"letter": "A", "text": "对甲口头传唤"}, {"letter": "B", "text": "对乙强制传唤"}, {"letter": "C", "text": "对丙使用传唤证传唤"}, {"letter": "D", "text": "对丁使用传唤证传唤"}], "answer": "C", "explanation": "根据《治安管理处罚法》第82条，传唤适用于违法嫌疑人。甲乙丙为盗窃违法嫌疑人，可以依法传唤；丁为购买人，可能是被侵害人或证人，不适用传唤。对现场发现的违法嫌疑人可以口头传唤，强制传唤须以无正当理由不接受传唤为前提。C项对丙使用传唤证传唤符合法律规定。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 37}, {"num": 39, "batch": "专业基础知识", "type": "single", "stem": "南江县公安局向阳派出所在办理王某被殴打案件时，经鉴定，被害人王某的伤情为轻微伤。王某认为自己的伤情应当为轻伤，遂申请重新鉴定。根据相关法律法规，下列关于重新鉴定，说法正确的是（）。", "options": [{"letter": "A", "text": "王某对该伤情可以申请两次重新鉴定"}, {"letter": "B", "text": "王某申请重新鉴定期间案件暂停办理"}, {"letter": "C", "text": "王某申请重新鉴定需经南江县公安局批准"}, {"letter": "D", "text": "王某应当在收到鉴定意见后七日内申请重新鉴定"}], "answer": "C", "explanation": "根据《公安机关办理行政案件程序规定》，被侵害人对鉴定意见有异议申请重新鉴定的，须经县级以上公安机关负责人批准，C项正确。重新鉴定以一次为限，不能申请两次；重新鉴定期间不计入办案期限；重新鉴定费用一般由公安机关承担，而非由申请人承担。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 38}, {"num": 40, "batch": "专业基础知识", "type": "single", "stem": "环食药侦查大队依法查明，犯罪嫌疑人岳×自2023年下半年以来，为提升销售额，增加收入，在其熬制的牛肉汤内添加罂粟壳，非法销售获利近二十万元。根据《刑法》规定，对于岳×的行为认定，下列选项正确的是（）。", "options": [{"letter": "A", "text": "生产、销售有毒、有害食品罪"}, {"letter": "B", "text": "生产、销售不符合安全标准的食品罪"}, {"letter": "C", "text": "生产、销售伪劣产品罪"}, {"letter": "D", "text": "生产、销售不符合安全标准的产品罪"}], "answer": "A", "explanation": "根据《刑法》第144条，在生产、销售的食品中掺入有毒、有害的非食品原料的，或者销售明知掺有有毒、有害的非食品原料的食品的，构成生产、销售有毒、有害食品罪。罂粟壳含有吗啡等有毒成分，属于国家明令禁止在食品中添加的有毒、有害非食品原料，岳某的行为构成生产、销售有毒、有害食品罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 39}, {"num": 41, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）精神病人在不能辨认或者不能控制自己行为时违反治安管理的，应（）。", "options": [{"letter": "A", "text": "不予处罚"}, {"letter": "B", "text": "免于处罚"}, {"letter": "C", "text": "减轻处罚"}, {"letter": "D", "text": "从轻处罚"}], "answer": "A", "explanation": "根据新修订的《治安管理处罚法》第13条规定，精神病人在不能辨认或者不能控制自己行为的时候违反治安管理的，不予处罚，但是应当责令其监护人严加看管和治疗。这是基于精神病人缺乏责任能力的考量，属于'不予处罚'而非'免于处罚'。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 40}, {"num": 42, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）根据《中华人民共和国治安管理处罚法》的规定，被处（）以下罚款，被处罚人对罚款无异议的，可以由人民警察当场收缴罚款。", "options": [{"letter": "A", "text": "五百元"}, {"letter": "B", "text": "二百元"}, {"letter": "C", "text": "一百元"}, {"letter": "D", "text": "五十元"}], "answer": "B", "explanation": "根据新修订的《治安管理处罚法》第104条规定，被处二百元以下罚款，被处罚人对罚款无异议的，可以由人民警察当场收缴罚款。这是当场收缴罚款的法定条件之一，旨在提高执法效率。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 41}, {"num": 43, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）民警在对辖区旅馆进行治安监督检查时发现清新旅馆有大量未登记身份信息入住的旅客。经核实，旅店老板张某为招揽生意未按规定落实旅客入住验证登记制度，民警依法将张某传唤至派出所进行询问，下列做法不符合法律规定的是（）。", "options": [{"letter": "A", "text": "可以对张某进行口头传唤"}, {"letter": "B", "text": "对张某的询问查证时间最长不超过24小时"}, {"letter": "C", "text": "必要时通知未登记信息旅客到公安机关提供证言"}, {"letter": "D", "text": "询问期间应当保证张某饮食和必要的休息"}], "answer": "B", "explanation": "根据《治安管理处罚法》第83条规定，对违反治安管理行为人询问查证的时间一般不得超过8小时；情况复杂，可能适用行政拘留处罚的，不得超过24小时。本案张某的违法行为为未按规定登记旅客信息，属于简单案件，询问查证时间最长不超过8小时，B项称不超过24小时不符合法律规定。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 42}, {"num": 44, "batch": "专业基础知识", "type": "single", "stem": "陈某为A市甲区人，在A市乙区进行赌博的违法行为，赢钱后前往A市丙区购买手机被民警抓获。关于此案的管辖，以下说法正确的是（）。", "options": [{"letter": "A", "text": "甲、乙区公安机关对此案均有管辖权"}, {"letter": "B", "text": "乙、丙区公安机关对此案均有管辖权"}, {"letter": "C", "text": "甲、丙区公安机关对此案均有管辖权"}, {"letter": "D", "text": "甲、乙、丙区公安机关对此案均有管辖权"}], "answer": "B", "explanation": "根据《公安机关办理行政案件程序规定》，行政案件由违法行为发生地的公安机关管辖，违法行为发生地包括违法行为实施地和查获地。乙区为赌博行为实施地，丙区为被抓获地（查获地），均有管辖权。甲区仅为居住地，对此案无管辖权。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 43}, {"num": 45, "batch": "专业基础知识", "type": "single", "stem": "B市公安机关在进行全市重点场所突击检查的过程中，在某台球厅内发现4人正在以推牌九的方式进行赌博，故将其带回公安机关接受处理。处罚完毕欲执行拘留的过程中，违法行为人之一的古某认为处罚过重，欲申请行政诉讼，故向公安机关提出暂缓执行行政拘留的申请。经审查其不致发生社会危险，便让其提出保证人，对其进行暂缓拘留。古某提出的以下保证人中符合条件的是（）。", "options": [{"letter": "A", "text": "赵某，B市人，本案中一起参与赌博的违法行为人"}, {"letter": "B", "text": "齐某，Y市人，古某的朋友，在本地刚找到工作"}, {"letter": "C", "text": "金某，B市人，古某的侄女，借宿于古某家中，在B市初中上学"}, {"letter": "D", "text": "越某，B市人，古某的母亲"}], "answer": "D", "explanation": "根据《治安管理处罚法》第107条，暂缓执行行政拘留的保证人应当符合以下条件：与本案无牵连；与案件无利害关系；在当地有常住户口和固定住所；有能力履行保证义务。A项为同案违法人员，与本案有牵连；B项在本地无常住户口；C项为未成年人，无履行保证义务的能力；D项古某的母亲为B市人，符合条件。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 44}, {"num": 46, "batch": "专业基础知识", "type": "single", "stem": "调解处理案件，应当查明事实，收集证据，并遵循合法、公正、自愿、及时的原则，注重教育和疏导，化解矛盾。下列情形可以治安调解的是（）。", "options": [{"letter": "A", "text": "吕某多次损坏邻居家的门锁"}, {"letter": "B", "text": "徐某因工作分配不均，造谣诽谤同事贪污，第一次调解失败"}, {"letter": "C", "text": "严某因停车纠纷被李某打了一耳光，多次强调不接受调解"}, {"letter": "D", "text": "曾某借魏某钱不还并出言嘲讽，魏某雇人殴打曾某"}], "answer": "B", "explanation": "根据《公安机关办理行政案件程序规定》，治安调解适用于因民间纠纷引起的治安案件，但雇凶伤害、结伙斗殴、多次实施违法行为、当事人拒绝调解的不适用。A项多次损坏属于多次违法；C项当事人明确拒绝调解；D项雇人殴打属于雇凶伤害。B项造谣诽谤属于民间纠纷引起，且第一次调解失败后双方仍有意愿的可以再调解一次。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 45}, {"num": 47, "batch": "专业基础知识", "type": "single", "stem": "秦某于10月1日在A区盗窃了价值200元的自行车，次日，在B区进行销赃，两个区的公安机关分别于案发日接到了报案，后秦某在C区准备找下一个目标时，巡逻民警发现其鬼鬼祟祟，将其抓获。下列关于本案的管辖说法正确的是（）。", "options": [{"letter": "A", "text": "由抓获地C区公安机关管辖"}, {"letter": "B", "text": "A区公安机关最先接到报案，有管辖权"}, {"letter": "C", "text": "管辖发生争议时，应由秦某户籍地公安机关管辖"}, {"letter": "D", "text": "管辖权发生争议时，报请共同的上级公安机关指定管辖"}], "answer": "B", "explanation": "根据《公安机关办理行政案件程序规定》，几个公安机关都有权管辖的行政案件，由最初受理的公安机关管辖。A区公安机关最先接到报案并受理，因此A区公安机关有管辖权。管辖权发生争议时，应报请共同的上级公安机关指定管辖，而非由户籍地管辖。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 46}, {"num": 48, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）以下案件适用快速办理程序的是（）。", "options": [{"letter": "A", "text": "嫌疑人王某将一名出租车司机殴打至轻微伤，经查王某为聋哑人"}, {"letter": "B", "text": "初中生张某（未成年）盗窃同学的自行车"}, {"letter": "C", "text": "赵某放任自己所饲养的动物恐吓他人"}, {"letter": "D", "text": "嫌疑人李某涉嫌卖淫，且影响恶劣"}], "answer": "C", "explanation": "根据新修订的《治安管理处罚法》关于快速办理程序的规定，事实清楚、违法嫌疑人自愿认错认罚且对法律适用无异议的行政案件可以适用快速办理。但涉及未成年人、聋哑人、精神病人以及社会影响较大的案件不适用快速办理。C项放任饲养的动物恐吓他人属于简单轻微的治安案件，符合快速办理条件。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 47}, {"num": 49, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）下列各项中，不属于治安管理处罚的是（）。", "options": [{"letter": "A", "text": "甲非法携带管制刀具被处以警告"}, {"letter": "B", "text": "乙放任动物恐吓他人被罚款500元"}, {"letter": "C", "text": "丙散布谣言扰乱公共秩序被行政拘留五日"}, {"letter": "D", "text": "丁非法经营被吊销许可证件"}], "answer": "D", "explanation": "根据新修订的《治安管理处罚法》，治安管理处罚的种类包括警告、罚款、行政拘留、吊销许可证件以及对外国人的限期出境和驱逐出境。D项中'非法经营被吊销许可证件'，吊销许可证件本身属于处罚种类，但此处'非法经营'不属于治安管理处罚法调整的范围，且'吊销许可证件'在此语境下属于其他行政管理措施而非治安管理处罚。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 48}, {"num": 50, "batch": "专业基础知识", "type": "single", "stem": "A县公安局东风派出所处理一起打架斗殴案件时，根据案件办理需要，准备对该案相关内容进行辨认。根据《公安机关办理行政案件程序规定》，下列做法正确的是（）。", "options": [{"letter": "A", "text": "辨认打架使用木棍时，应至少准备十根其他棍子作陪衬"}, {"letter": "B", "text": "辨认人甲、乙、丙、丁同时辨认一名嫌疑人会提高效率"}, {"letter": "C", "text": "对违法嫌疑人的辨认须在不暴露辨认人的情况下进行"}, {"letter": "D", "text": "辨认经过和结果，应当制作辨认笔录，由办案人民警察和辨认人签名或者捺指印"}], "answer": "D", "explanation": "根据《公安机关办理行政案件程序规定》，辨认经过和结果应当制作辨认笔录，由办案人民警察和辨认人签名或者捺指印，D项正确。A项辨认物品时陪衬物品不得少于5件（非10件）；B项多名辨认人应当分别单独进行辨认，不能同时辨认；C项对违法嫌疑人的辨认应在不暴露辨认人的情况下进行，但并非所有辨认都须如此。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 49}, {"num": 51, "batch": "专业基础知识", "type": "single", "stem": "张三与李四酒后发生争执，在街头互殴，甲是到场处理此次打架斗殴事件的民警，乙是负责该案办理的公安机关的负责人，丙为此次案件的伤情鉴定人员，若相关人员存在以下关系，则关于他们回避的说法正确的是（）。", "options": [{"letter": "A", "text": "甲与张三是多年未曾联系的小学同学，甲应当回避，甲的回避由所属公安机关决定"}, {"letter": "B", "text": "乙与李四在同一小区居住，曾多次发生矛盾积怨颇深，乙在本案中无需回避"}, {"letter": "C", "text": "丙是李四的亲妹夫，丙可以自行提出回避，丙的回避由聘请的公安机关决定"}, {"letter": "D", "text": "若乙应当回避，则应由所属公安机关决定"}], "answer": "C", "explanation": "根据《公安机关办理行政案件程序规定》，鉴定人员的回避由聘请其的公安机关决定，C项正确。A项小学同学多年未联系不属于法定回避事由；B项乙与李四积怨颇深属于利害关系，应当回避；D项公安机关负责人的回避应由上一级公安机关决定，而非所属公安机关。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 50}, {"num": 52, "batch": "专业基础知识", "type": "single", "stem": "张某因涉嫌赌博违法被受案调查，在案件办理过程中，张某发现办案民警王某同张某存在债权债务关系，遂提出申请要求王某回避，关于回避下列说法正确的是（）。", "options": [{"letter": "A", "text": "不属于回避的法定事由，王某不需回避"}, {"letter": "B", "text": "张某应书面提出回避申请，且如实陈述理由"}, {"letter": "C", "text": "王某的回避，由所属公安机关决定"}, {"letter": "D", "text": "在作出回避决定前，王某应当停止对案件的调查"}], "answer": "C", "explanation": "根据《公安机关办理行政案件程序规定》，办案人民警察的回避由所属公安机关决定，C项正确。张某与王某存在债权债务关系属于利害关系，是法定回避事由；回避申请可以口头提出并记录在案，不要求必须书面；在作出回避决定前，被申请回避的人员不得停止对案件的调查。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 51}, {"num": 53, "batch": "专业基础知识", "type": "single", "stem": "对下列行为人行政处罚的适用，说法不正确的是（）。", "options": [{"letter": "A", "text": "精神病人甲追逐、拦截他人，应不予行政处罚"}, {"letter": "B", "text": "间歇性精神病人乙在精神正常时损毁路面井盖，应给予行政处罚"}, {"letter": "C", "text": "丙醉酒后写恐吓信威胁他人，应当从重处罚"}, {"letter": "D", "text": "尚未完全丧失辨认能力的精神病人丁盗窃他人财物，可以从轻或者减轻处罚"}], "answer": "C", "explanation": "根据《治安管理处罚法》相关规定，醉酒的人违反治安管理应当给予处罚，但不存在'从重处罚'的法定规定。C项称丙醉酒后违法'应当从重处罚'没有法律依据，说法不正确。A项精神病人发病时不予处罚正确；B项间歇性精神病人精神正常时应处罚正确；D项尚未完全丧失辨认能力的精神病人可以从轻或减轻正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 52}, {"num": 54, "batch": "专业基础知识", "type": "single", "stem": "赵某因不满邻居吴某将垃圾倒在自家门口，将吴某打伤，民警进行辨认调查时，下列说法正确的是（）。", "options": [{"letter": "A", "text": "民警将赵某和其他五名无关人员放在一起让吴某辨认"}, {"letter": "B", "text": "民警将赵某的照片混杂在其他十个人的照片中给吴某辨认"}, {"letter": "C", "text": "民警为提高取证效率，将吴某和证人一起给违法嫌疑人辨认"}, {"letter": "D", "text": "民警看不惯违法嫌疑人的嚣张气焰，在证人辨认时给予暗示"}], "answer": "B", "explanation": "根据《公安机关办理行政案件程序规定》，辨认时将赵某的照片混杂在其他十个人的照片中给吴某辨认，符合辨认照片时陪衬照片不得少于10张的规定，B项正确。A项被辨认人数不足7人；C项辨认人和证人应当分别进行辨认，不能一起辨认；D项在辨认中给予暗示严重违反法定程序。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 53}, {"num": 55, "batch": "专业基础知识", "type": "single", "stem": "甲县公安局乙派出所民警因办理案件需要对辖区内某公民住所进行检查，下列对于该住所检查的说法正确的是（）。", "options": [{"letter": "A", "text": "检查住所时必须有被检查人和见证人在场"}, {"letter": "B", "text": "检查住所应当出示乙派出所开具的检查证"}, {"letter": "C", "text": "检查住所时，可以在规定范围内造成财物损坏"}, {"letter": "D", "text": "其邻居称经常在该住所外闻到刺鼻火药气味，民警经出示人民警察证可以当场检查"}], "answer": "D", "explanation": "根据《治安管理处罚法》第87条，检查公民住所应当出示检查证，但确有必要当场检查的，经出示人民警察证可以当场检查。D项邻居反映闻到刺鼻火药气味，存在现实危险，属于确有必要当场检查的紧急情形，经出示人民警察证可以当场检查。A项并非任何时候都必须有被检查人在场；B项检查证应由县级以上公安机关开具；C项检查时不得损坏财物。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 54}, {"num": 56, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）被处罚人对治安管理处罚决定不服，有权（）。", "options": [{"letter": "A", "text": "申请行政复议"}, {"letter": "B", "text": "提起行政仲裁"}, {"letter": "C", "text": "申请重新调查"}, {"letter": "D", "text": "申请听证"}], "answer": "A", "explanation": "根据新修订的《治安管理处罚法》第102条规定，被处罚人对治安管理处罚决定不服的，有权依法申请行政复议或者提起行政诉讼。行政仲裁不是法定的救济途径；重新调查和申请听证不属于对处罚决定不服的救济方式。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 55}, {"num": 57, "batch": "专业基础知识", "type": "single", "stem": "根据下列违反治安管理当事人的情形，公安机关给予的行政处理决定恰当的是（）。", "options": [{"letter": "A", "text": "小刘违法时14周岁，应当对其不予处罚，但责令监护人严加管教"}, {"letter": "B", "text": "宋某是盲人，对宋某应当从轻、减轻或不予处罚"}, {"letter": "C", "text": "周某双耳失聪，对周某可以从轻、减轻或不予处罚"}, {"letter": "D", "text": "于某是间歇性精神病人，在发病时完全不能控制自己行为违法，应当不予处罚"}], "answer": "D", "explanation": "根据《治安管理处罚法》第12条和第13条，不满14周岁的人违反治安管理的不予处罚（但14周岁应当处罚）；又聋又哑的人或盲人'可以'从轻、减轻或不予处罚（非'应当'）；间歇性精神病人在精神不正常时不能控制自己行为违法的不予处罚。D项表述符合法律规定，A项14周岁应当处罚而非不予处罚，B项盲人为'可以'而非'应当'，C项双耳失聪并非又聋又哑。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 56}, {"num": 58, "batch": "专业基础知识", "type": "single", "stem": "大兴派出所在处理一起治安案件过程中，由于事实清楚，违法嫌疑人王某自愿认错认罚，且对违法事实和法律适用没有异议，公安机关依法进行了快速办理。关于本案，大兴派出所的下列做法错误的是（）。", "options": [{"letter": "A", "text": "对于快速办理的案件，在询问过程中全程录音录像的，也应当制作书面询问笔录"}, {"letter": "B", "text": "快速办理前，应当书面告知王某快速办理的相关规定，征得其同意，并由其签名"}, {"letter": "C", "text": "应当王某到案后四十八小时内作出处理决定"}, {"letter": "D", "text": "快速办理时发现不适宜快速办理，转为一般案件办理，快速办理阶段依法收集的证据可以作为定案的根据"}], "answer": "A", "explanation": "根据《公安机关办理行政案件程序规定》关于快速办理的规定，快速办理的案件在询问过程中全程录音录像的，可以不再制作书面询问笔录。A项称'也应当制作书面询问笔录'与快速办理简化程序的规定相悖，说法错误。B项快速办理前应书面告知并征得同意正确；C项应在48小时内作出处理决定正确；D项快速办理阶段收集的证据有效正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 57}, {"num": 59, "batch": "专业基础知识", "type": "single", "stem": "彭某是一社会闲散无业人员，近期散布谣言，谎报疫情故意扰乱公共秩序，后被东平镇派出所发现，则该案件自受理之日起不得超过（）日，若经过调查取证发现案情重大、复杂，可以延长（）日。", "options": [{"letter": "A", "text": "30 30"}, {"letter": "B", "text": "30 60"}, {"letter": "C", "text": "10 20"}, {"letter": "D", "text": "20 10"}], "answer": "A", "explanation": "根据《治安管理处罚法》第99条规定，公安机关办理治安案件的期限，自受理之日起不得超过30日；案情重大、复杂的，经上一级公安机关批准，可以延长30日。因此本案办案期限为30日，可延长30日。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 58}, {"num": 60, "batch": "专业基础知识", "type": "single", "stem": "某区公安分局办理的下列行政案件，可以对违法行为人当场作出处罚决定的是（）。", "options": [{"letter": "A", "text": "甲因殴打他人被处100元罚款"}, {"letter": "B", "text": "乙在酒吧内吸毒被民警抓获"}, {"letter": "C", "text": "丙以麻将的形式聚众赌博"}, {"letter": "D", "text": "丁在“天上人间”会所嫖娼"}], "answer": "A", "explanation": "根据《治安管理处罚法》第100条，违反治安管理事实确凿，处警告或者二百元以下罚款的，可以当场作出处罚决定。A项甲被处100元罚款，符合当场处罚的条件。B项吸毒、C项聚众赌博、D项嫖娼均属于较严重的违法行为，通常涉及行政拘留处罚，不适用简易程序。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 59}, {"num": 61, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）郭某和马某（15岁）因未赶上公交车，在车辆驶出车站并等候红灯时，要求司机开门上车，遭拒后绕至驾驶室一侧与司机理论，随后竟直接挡在车前，不顾一车乘客指责和道路通行秩序，玩手机长达20分钟。A市公安局因其扰乱公共场所秩序，对二人作出拘留7天的行政处罚，关于本案下列说法正确的是（）。", "options": [{"letter": "A", "text": "郭某因哺乳2周岁女儿，因此不执行拘留"}, {"letter": "B", "text": "郭某申请行政复议，因此暂缓执行拘留"}, {"letter": "C", "text": "郭某暂缓执行拘留的担保人，不需要是当地常住户口"}, {"letter": "D", "text": "马某因不满十六周岁，不执行行政拘留"}], "answer": "D", "explanation": "根据《治安管理处罚法》第21条，已满14周岁不满16周岁的，应当给予行政拘留处罚但不执行。马某15周岁，属于该年龄段，不执行行政拘留。A项郭某哺乳2周岁女儿已超过1周岁不符合不执行条件；B项申请行政复议不当然暂缓执行；C项担保人应当在当地有常住户口。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 60}, {"num": 62, "batch": "专业基础知识", "type": "single", "stem": "某派出所民警小张等两人在某小区内巡逻，接居民报警说，听到该小区5号楼4楼西户有打架的声音，并听到有人叫喊“杀人了”，情况十分危急。小张等两人接警后，正确的做法是（）。", "options": [{"letter": "A", "text": "应当说明身份，征得同意，当场检查"}, {"letter": "B", "text": "应当出示警察证，当场检查"}, {"letter": "C", "text": "应当返回派出所开具检查证，后再行检查"}, {"letter": "D", "text": "经出示证件后，可以立即检查，但事后必须补办检查证"}], "answer": "B", "explanation": "根据《治安管理处罚法》第87条，确有必要当场检查的，经出示人民警察证可以当场检查。本案中有人喊'杀人了'，情况十分危急，属于确有必要当场检查的紧急情形，民警应当出示警察证当场检查，无需返回派出所开具检查证。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 61}, {"num": 63, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）下列违反治安管理行为人中，属于应当给予行政拘留而不执行行政拘留情形的是（）。", "options": [{"letter": "A", "text": "甲实施盗窃时正在哺乳自己一周岁半的女儿"}, {"letter": "B", "text": "乙吸毒时17周岁，初次违反治安管理"}, {"letter": "C", "text": "丙故意伤害他人时13周岁"}, {"letter": "D", "text": "丁嫖娼时被抓获，此时已65周岁"}], "answer": "B", "explanation": "根据《治安管理处罚法》第21条，应当给予行政拘留处罚但不执行的情形包括：已满14周岁不满16周岁的；已满16周岁不满18周岁初次违反治安管理的；70周岁以上的；怀孕或者哺乳自己不满1周岁婴儿的。B项乙17周岁且初次违反治安管理，符合不执行条件。A项哺乳1岁半女儿已超过1周岁；C项13周岁根本不予处罚而非不执行；D项65周岁未达70周岁标准。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 62}, {"num": 64, "batch": "专业基础知识", "type": "single", "stem": "新安市警方查获一起赌博案件，当场抓获嫌疑人5名，现场发现赌具、赌资若干，现场安全检查时发现账本。针对上述物品，下列民警现场采取的措施正确的是（）。", "options": [{"letter": "A", "text": "赌具、赌资和账本应当收缴"}, {"letter": "B", "text": "账本、赌具应当收缴，赌资应当追缴"}, {"letter": "C", "text": "赌具和账本应当扣押，赌资应当收缴"}, {"letter": "D", "text": "赌资、赌具和账本均应扣押"}], "answer": "D", "explanation": "根据《公安机关办理行政案件程序规定》，在赌博案件现场查获的赌具、赌资和账本均属于与案件有关的证据材料，在现场阶段应当先行扣押。赌具和赌资在作出处罚决定后依法予以收缴或追缴，但在现场查获时的正确措施是先扣押以保全证据。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 63}, {"num": 65, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）根据《治安管理处罚法》规定，下列说法不正确的是（）。", "options": [{"letter": "A", "text": "赵某在醉酒状态下将他人打成轻微伤，应当给予处罚"}, {"letter": "B", "text": "盲人陈某对扣留其子电动车的民警进行辱骂阻碍执法，对陈某应当从轻、减轻或者不予处罚"}, {"letter": "C", "text": "间歇性精神病人黄某在精神正常时寻衅滋事，应当给予处罚"}, {"letter": "D", "text": "12岁的成某偷走了邻居阿姨的钱包，对成某应不予处罚，但是应责令其监护人严加管教"}], "answer": "B", "explanation": "根据《治安管理处罚法》第14条，又聋又哑的人或者盲人违反治安管理的，'可以'从轻、减轻或者不予处罚，而非'应当'。B项将'可以'表述为'应当'，说法不正确。A项醉酒的人应当处罚正确；C项间歇性精神病人精神正常时应当处罚正确；D项12岁未达处罚年龄不予处罚并责令监护人管教正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 64}, {"num": 66, "batch": "专业基础知识", "type": "single", "stem": "民警小张对一起邻里间因琐事引发的治安案件进行了治安调解，关于本次治安调解，下列说法正确的是（）。", "options": [{"letter": "A", "text": "小张在进行调解时必须邀请当事人居住地居委会干部参与"}, {"letter": "B", "text": "治安调解一般为一次，一次调解不成的不再进行调解"}, {"letter": "C", "text": "调解成功后应当制作调解协议书并由参与调解人员签名"}, {"letter": "D", "text": "若当事人不履行调解协议，则公安机关应当对违法行为人进行处罚"}], "answer": "D", "explanation": "根据《公安机关办理行政案件程序规定》，经治安调解达成协议后当事人不履行的，公安机关应当依法对违反治安管理行为人给予处罚，D项正确。A项调解时'可以'邀请居委会人员参与，非'必须'；B项治安调解一般一次，必要时可以再调解一次；C项调解协议书应由调解人、当事人和见证人签名。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 65}, {"num": 67, "batch": "专业基础知识", "type": "single", "stem": "下列违反治安管理行为人中，应当给予行政拘留处罚但不执行行政拘留处罚的是（）。", "options": [{"letter": "A", "text": "王某，17周岁，喝醉后在街边寻衅滋事，曾因吸食毒品受到行政处罚"}, {"letter": "B", "text": "张某，67周岁，与邻居发生纠纷，将邻居打成轻微伤"}, {"letter": "C", "text": "金某，正在哺乳自己一周岁半的女儿"}, {"letter": "D", "text": "蔡某，15周岁，在某旅店内吸食冰毒"}], "answer": "D", "explanation": "根据《治安管理处罚法》第21条，已满14周岁不满16周岁的人，应当给予行政拘留处罚但不执行。D项蔡某15周岁，属于该年龄段，不执行拘留。A项王某17周岁但曾因吸毒受处罚不属于初次违反，应执行拘留；B项张某67周岁未达70周岁标准；C项金某哺乳1岁半女儿已超过1周岁标准。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 66}, {"num": 68, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）下列属于治安管理处罚法规定的处罚种类是（）。", "options": [{"letter": "A", "text": "没收"}, {"letter": "B", "text": "追缴"}, {"letter": "C", "text": "驱逐出境"}, {"letter": "D", "text": "查封现场"}], "answer": "C", "explanation": "根据新修订的《治安管理处罚法》，治安管理处罚的种类包括警告、罚款、行政拘留、吊销许可证件，以及对违反治安管理的外国人可以附加适用限期出境或者驱逐出境。驱逐出境属于治安管理处罚种类之一。没收、追缴、查封现场均不属于治安管理处罚的法定种类。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 67}, {"num": 69, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）甲派出所在开展“百万警进千万家”活动时，发现某小区内有住户存在饲养动物干扰他人正常生活的违法行为，遂作出警告处罚；之后再次核查该小区治安状况时，发现该住户仍未改正其违法行为，同楼其他住户多有不满，向民警反映此情况。民警现根据《治安管理处罚法》对其当场作出两百元罚款的处罚决定，下列处罚流程正确的是（）。 ①口头告知违法行为人拟作出行政处罚决定的事实、理由和依据 ②表明执法身份 ③收集证据 ④口头告知违法行为人依法享有的陈述权和申辩权 ⑤书面告知违法嫌疑人有要求举行听证的权利 ⑥作出决定后的二十四小时内将当场处罚决定书报所属公安机关备案 ⑦填写当场处罚决定书并当场交付被处罚人 ⑧在作出决定后的四十八小时内将当场处罚决定书报所属派出所备案", "options": [{"letter": "A", "text": "②④③①⑤⑦"}, {"letter": "B", "text": "②③①④⑦⑥"}, {"letter": "C", "text": "②③①④⑤⑧"}, {"letter": "D", "text": "②④③①⑦⑥"}], "answer": "B", "explanation": "根据新修订的《治安管理处罚法》关于当场处罚程序的规定，正确的流程为：先表明执法身份，然后收集证据，口头告知拟作出处罚的事实、理由和依据，口头告知陈述权和申辩权，填写当场处罚决定书并当场交付被处罚人，在作出决定后24小时内报所属公安机关备案。当场处罚罚款上限为500元，200元罚款在法定范围内，不需要告知听证权利。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 68}, {"num": 70, "batch": "专业基础知识", "type": "single", "stem": "民警老陈在办理一起吸毒案件时，发现其中一名吸毒者是自己的儿子，同案的违法嫌疑人王某发现后申请了民警老陈回避。关于本案回避的相关问题，下列说法正确的是（）。", "options": [{"letter": "A", "text": "民警老陈的回避应当由上一级公安机关决定"}, {"letter": "B", "text": "对老陈提出的回避申请，公安机关应当在五日内作出决定并通知老陈"}, {"letter": "C", "text": "在公安机关作出回避决定前，老陈不得停止该案的调查"}, {"letter": "D", "text": "若公安机关作出了回避决定，则老陈在回避之前所进行的与案件有关的活动无效"}], "answer": "C", "explanation": "根据《公安机关办理行政案件程序规定》，在公安机关作出回避决定前，被申请回避的人民警察不得停止对案件的调查，C项正确。民警的回避由所属公安机关决定而非上一级公安机关；回避申请应在2日内作出决定而非5日；回避决定作出后，之前进行的活动是否有效由公安机关视情况决定，并非一律无效。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 69}, {"num": 71, "batch": "专业基础知识", "type": "single", "stem": "翔安派出所辖区是和平区管辖区域最大、治安情况最复杂的地区之一，警力紧缺。近日，翔安派出所分来了两名警务辅助人员，在以下工作中，在全程录音录像情况下，可以由一名人民警察带领警务辅助人员进行的是（）。", "options": [{"letter": "A", "text": "接报案并进行受案登记"}, {"letter": "B", "text": "扣押作案工具"}, {"letter": "C", "text": "开展继续盘问"}, {"letter": "D", "text": "询问目击证人"}], "answer": "A", "explanation": "根据辅警管理的相关规定，辅警可以在人民警察带领下协助开展接报案、受案登记等辅助性工作。但扣押、继续盘问、询问证人等涉及执法核心的工作须由两名以上人民警察进行，辅警不能替代。因此在全程录音录像、一名民警带领的情况下，可以由辅警协助进行接报案和受案登记。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 70}, {"num": 72, "batch": "专业基础知识", "type": "single", "stem": "民警小张、小李在值班过程中接到一起酒后闹事警情。到达现场后，了解到甲、乙二人系酒后发生争执，继而引发肢体冲突。在后续案件办理过程中，小张发现甲的哥哥是曾经在一起车祸中救助过自己的恩人，则关于本案办案民警的回避，下列说法正确的是（）。", "options": [{"letter": "A", "text": "办案民警小张非本案当事人近亲属，也与本案无利害关系，在取得当事人同意后，小张即可不回避"}, {"letter": "B", "text": "如办案民警小张自行申请回避，该决定由其所属公安机关作出"}, {"letter": "C", "text": "当事人可以提出回避申请，回避申请只能为书面形式"}, {"letter": "D", "text": "案件当事人提出对小张回避的申请之后，民警小张即停止对本案的调查活动"}], "answer": "B", "explanation": "根据《公安机关办理行政案件程序规定》，办案民警自行提出回避申请的，由所属公安机关作出回避决定，B项正确。A项存在可能影响公正处理的关系应当回避，不因当事人同意而免除；C项回避申请可以口头或书面提出；D项在回避决定作出前，民警不得停止对案件的调查。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 71}, {"num": 73, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）张某与赵某因宅基地问题产生纠纷。张某一时气愤，手持铁棍来到赵某家中，将赵某的自行车砸坏。赵某上前将铁棍抢走，张某遂拿起赵某家中的铁锨将赵某打致轻微伤。派出所民警对铁棍和铁锨处理正确的是（）。", "options": [{"letter": "A", "text": "对铁棍予以扣押，对铁锨予以登记"}, {"letter": "B", "text": "对铁棍、铁锨均予以扣押"}, {"letter": "C", "text": "对铁棍予以登记，对铁锨予以扣押"}, {"letter": "D", "text": "对铁棍、铁锨均予以先行登记保存"}], "answer": "A", "explanation": "根据《公安机关办理行政案件程序规定》，对与案件有关的需要作为证据的物品可以扣押。铁棍是张某实施违法行为使用的工具，属于作案工具，应当予以扣押。铁锨是赵某家中的财物，被张某临时拿起使用，属于被害人赵某的合法财产，应予以登记后返还，不宜扣押。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 72}, {"num": 74, "batch": "专业基础知识", "type": "single", "stem": "甲看完春节档一场三个小时的电影后火速冲进电影院女卫生间，看到有个空位门锁虚掩，以为没人便冲了进去，正好撞到了正在里面的乙。双方言语辱骂彼此且产生了肢体冲突，围观群众见状报警。风桥派出所民警赶到现场后处置正确的是（）。", "options": [{"letter": "A", "text": "民警征得乙同意后，可以迅速调解处理"}, {"letter": "B", "text": "甲的行为被现场群众一致抵制，本案不得进行治安调解"}, {"letter": "C", "text": "若当事人基本情况、主要违法事实和协议内容在现场录音录像中明确记录的，民警依法进行当场调解并履行后不再制作调解协议书"}, {"letter": "D", "text": "可以邀请电影院负责人参与调解，建议赠送电影票"}], "answer": "C", "explanation": "根据《公安机关办理行政案件程序规定》，对于情节轻微的治安案件，双方当事人当场表示同意接受的，民警可以当场调解。当事人基本情况、主要违法事实和协议内容在现场录音录像中明确记录的，当场调解并履行后不再制作调解协议书，C项正确。A项并非必须征得乙同意才能调解；D项赠送电影票不符合调解的合法原则。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 73}, {"num": 75, "batch": "专业基础知识", "type": "single", "stem": "2022年6月1日，大型演唱会现场违规燃放烟花，民警及时制止。辖区派出所受案后，因曲X对违法事实和法律适用没有异议，自愿认罚。派出所启动快速办理机制，对于此案的办理，民警做法正确的是（）。", "options": [{"letter": "A", "text": "在快速办理案件前口头告知曲X快速办理的相关规定，征得其同意"}, {"letter": "B", "text": "使用执法记录仪对询问曲X全过程录音录像，不再制作询问笔录"}, {"letter": "C", "text": "因曲X对违法事实和法律适用没有异议，未履行处罚前告知程序"}, {"letter": "D", "text": "曲X于6月1日到案，6月4日对其作出处理决定"}], "answer": "B", "explanation": "根据《公安机关办理行政案件程序规定》关于快速办理的规定，使用执法记录仪对询问全过程录音录像的，可以不再制作书面询问笔录，B项正确。A项快速办理前应书面告知而非口头告知；C项即使快速办理也必须履行处罚前告知程序；D项快速办理应在48小时内作出处理决定，6月1日到案6月4日作出决定超过48小时。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 74}, {"num": 76, "batch": "专业基础知识", "type": "single", "stem": "下列情形可以适用治安调解处理的是（）。", "options": [{"letter": "A", "text": "赵某花钱让钱某帮忙教训生意对手孙某，钱某收钱后对孙某进行殴打"}, {"letter": "B", "text": "张三伙同李四，与王五、赵六约架，双方打架时被民警抓获"}, {"letter": "C", "text": "王大妈使用高分贝扩音器带领众人跳广场舞，邻居不胜其扰报警"}, {"letter": "D", "text": "民警正在调解一起殴打他人案，行为人再次殴打受害人"}], "answer": "C", "explanation": "根据《公安机关办理行政案件程序规定》，因民间纠纷引起的治安案件情节较轻的可以调解处理。C项广场舞噪声扰民属于民间纠纷引起的治安案件，情节较轻，可以适用治安调解。A项雇凶殴打不适用调解；B项约架斗殴属于结伙作案不适用调解；D项调解期间行为人再次殴打受害人，不再适用调解。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 75}, {"num": 77, "batch": "专业基础知识", "type": "single", "stem": "春节假期，在外打工的王某回到老家过年，期间纠集同村在外务工人员到家中使用扑克牌赌博，赌博时王某使用手机支付赌资，后被公安机关当场查获。在现场发现的下列物品中，不可以扣押的是（）。", "options": [{"letter": "A", "text": "赌博使用的扑克牌"}, {"letter": "B", "text": "赌博过程中涉赌人员用来喝水的水杯"}, {"letter": "C", "text": "赌博涉及的赌资"}, {"letter": "D", "text": "王某支付赌资的手机"}], "answer": "B", "explanation": "根据《公安机关办理行政案件程序规定》，与案件有关的需要作为证据的物品可以扣押，与案件无关的物品不得扣押。B项水杯与赌博行为无关，不可以扣押。A项扑克牌为赌博工具、C项赌资、D项用于支付赌资的手机均与赌博案件有关，可以依法扣押。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 76}, {"num": 78, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）2024年4月1日，史某（男，22周岁）醉酒后在天天超市“撒酒疯”，砸坏两辆购物推车，总计价值300元。史某被公安机关抓获后，在询问过程中交代曾在2023年9月28日在天天超市停车场内曾盗窃过一女士刚刚购买的食品。根据《治安管理处罚法》，对于史某违法行为的处理，下列说法正确的是（）。", "options": [{"letter": "A", "text": "对史某的盗窃行为不再处罚"}, {"letter": "B", "text": "对于史某故意毁坏财物、盗窃行为，分别决定，合并执行"}, {"letter": "C", "text": "对于史某故意毁坏财物的行为，可以从轻、减轻处罚"}, {"letter": "D", "text": "史某实施了多个违法行为，应从重处罚"}], "answer": "A", "explanation": "根据《治安管理处罚法》第22条，违反治安管理行为在六个月内没有被公安机关发现的，不再处罚。史某的盗窃行为发生在2023年9月28日，至2024年4月1日被发现已超过六个月追究时效，因此对盗窃行为不再处罚。对于故意毁坏财物的行为，醉酒不构成立即从轻或减轻的理由。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 77}, {"num": 79, "batch": "专业基础知识", "type": "single", "stem": "2023年11月10日8时许，甲公安分局广场路派出所民警巡逻时接群众举报称：澳林小区居民林某的家中储存有大量液化气罐，严重危及公共安全及居民的人身安全。民警到达现场后，林某拒不让民警对其住所进行检查，下列说法正确的是（）。", "options": [{"letter": "A", "text": "必须出示人民警察证和检查证，才可以对林某住所进行检查"}, {"letter": "B", "text": "经出示人民警察证后，可以当场检查"}, {"letter": "C", "text": "没有证据证明林某有违法行为，不能检查"}, {"letter": "D", "text": "持有派出所出具的检查证，即可立即检查"}], "answer": "B", "explanation": "根据《治安管理处罚法》第87条，确有必要当场检查公民住所的，经出示人民警察证可以当场检查。本案中林某家中储存大量液化气罐严重危及公共安全，属于紧急情况，确有必要当场检查，经出示人民警察证即可当场检查，无需另行开具检查证。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 78}, {"num": 80, "batch": "专业基础知识", "type": "single", "stem": "公安机关在赌博违法案件现场查获下列物品，其中无需进行扣押的是（）。", "options": [{"letter": "A", "text": "赌桌上的现金"}, {"letter": "B", "text": "现场查获的管制刀具"}, {"letter": "C", "text": "赌徒甲随身携带的手机"}, {"letter": "D", "text": "用于赌博的骰子"}], "answer": "C", "explanation": "根据《公安机关办理行政案件程序规定》，与案件无关的物品不得扣押。C项赌徒甲随身携带的手机如果与赌博行为无关，不应扣押。A项赌桌上的现金属于赌资、B项管制刀具属于违禁品、D项骰子属于赌具，均与案件有关，应当依法扣押。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 79}, {"num": 81, "batch": "专业基础知识", "type": "single", "stem": "下列情形下，人民警察当场收缴罚款正确的是（）。", "options": [{"letter": "A", "text": "甲因扰乱车站的乘车秩序而被处以五十元罚款，但甲有异议"}, {"letter": "B", "text": "A市居民乙在B市观看演唱会过程中，与会场保安发生冲突，被处以一百元罚款"}, {"letter": "C", "text": "某小区居民丙因故意阻碍救护车通行被处以一百元罚款，丙对罚款无异议"}, {"letter": "D", "text": "丁在一长途列车上强占其他旅客座位，被处以二百元罚款，丁未提出要当场交纳，但向指定的银行缴纳确有困难"}], "answer": "B", "explanation": "根据《治安管理处罚法》第104条，被处200元以下罚款，被处罚人对罚款无异议的，可以当场收缴；在被处罚人当地没有固定住所，不当场收缴事后难以执行的，也可以当场收缴。B项乙在B市没有固定住所，被处100元罚款，符合当场收缴条件。A项甲有异议不能当场收缴；C项丙在当地有固定住所且对罚款有异议；D项丁虽在列车上但未提出缴纳困难。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 80}, {"num": 82, "batch": "专业基础知识", "type": "single", "stem": "刘某因对公安机关作出的行政拘留决定不服提出行政复议，并向公安机关申请暂缓执行拘留并提供了保证人，公安机关对其依法作出暂缓执行行政拘留的决定。关于刘某和保证人的义务，下列说法正确的是（）。", "options": [{"letter": "A", "text": "刘某不得离开所居住的市、县"}, {"letter": "B", "text": "未经公安机关批准刘某不得会见他人"}, {"letter": "C", "text": "刘某应当将身份证件、驾驶证件交公安机关保存"}, {"letter": "D", "text": "保证人未尽到保证义务致刘某逃跑的，可以对担保人处以一千元罚款并恢复对刘某的拘留执行决定"}], "answer": "D", "explanation": "根据《治安管理处罚法》第107条及相关规定，保证人应当保证被处罚人不逃避行政拘留处罚的执行。保证人未尽保证义务致使被处罚人逃跑的，可以对保证人处以罚款，并恢复对被处罚人的拘留执行。D项正确。A项应为未经批准不得离开所居住的市、县（非绝对禁止离开）；B项无不得会见他人的限制；C项无交存证件的规定。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 81}, {"num": 83, "batch": "专业基础知识", "type": "single", "stem": "下列关于治安调解说法不正确的是（）。", "options": [{"letter": "A", "text": "村民张某和王某发生纠纷，互殴致双方均受轻微伤，双方自愿民警可以对双方进行调解"}, {"letter": "B", "text": "陈某雇黄某殴打小李，致小李受轻微伤，双方自愿民警可以对陈某和小李进行治安调解"}, {"letter": "C", "text": "民警对成某和傅某进行治安调解一次不成，若双方申请再次调解，可以再次调解"}, {"letter": "D", "text": "赵某与邻居孙某因噪声问题争执互殴，治安调解时民警可以邀请赵某居住地的居委会的人员帮助调解"}], "answer": "B", "explanation": "根据《公安机关办理行政案件程序规定》，雇凶伤害他人不适用治安调解。B项陈某雇黄某殴打小李属于雇凶伤害，不符合治安调解的适用条件，因此民警不能对陈某进行治安调解，B项说法不正确。A项民间纠纷互殴可以调解；C项调解不成双方申请可以再调解一次；D项邀请居委会人员帮助调解正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 82}, {"num": 84, "batch": "专业基础知识", "type": "single", "stem": "警械是人民警察的重要执法装备，应依法合理使用。依据相关规定，下列情形中民警使用警械不当的是（）。", "options": [{"letter": "A", "text": "周X强行冲越警戒带，对其直接使用催泪喷射器"}, {"letter": "B", "text": "吴X精神病发作后追砍他人，将其制服后使用警绳约束"}, {"letter": "C", "text": "郑X涉嫌抢劫被执行逮捕且可能脱逃，对其使用脚镣"}, {"letter": "D", "text": "王X涉嫌吸毒被强制传唤且可能自伤，对其使用手铐"}], "answer": "A", "explanation": "根据《人民警察使用警械和武器条例》，催泪喷射器属于驱逐性、制服性警械，使用前应当先经警告无效才能使用，不得直接使用。A项对强行冲越警戒带的周某直接使用催泪喷射器不当。B项对精神病发作追砍他人者制服后使用警绳约束正确；C项对可能脱逃的嫌疑人使用脚镣正确；D项对可能自伤者使用手铐正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 83}, {"num": 85, "batch": "专业基础知识", "type": "single", "stem": "某日，长山派出所破获一起盗窃案，抓获犯罪嫌疑人蒋x，其交待赃物已藏匿在县城南部山坡。办案民警押解犯罪嫌疑人蒋x前往赃物藏匿地指认。为防止蒋x做出危险行为，民警对其采用手铐约束。下列方式恰当的是（）。", "options": [{"letter": "A", "text": "民警抓臂控制，采用前铐约束"}, {"letter": "B", "text": "采用民警与其连腕相铐约束"}, {"letter": "C", "text": "民警别臂控制，采用背铐约束"}, {"letter": "D", "text": "民警抓握铐链，采用前铐约束"}], "answer": "A", "explanation": "根据警械使用的规范要求，押解犯罪嫌疑人时，采用民警抓臂控制、前铐约束的方式既安全又规范，A项恰当。背铐一般用于危险性较大的嫌疑人；连腕相铐不符合规范操作；抓握铐链存在安全隐患，不利于有效控制嫌疑人。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 84}, {"num": 86, "batch": "专业基础知识", "type": "single", "stem": "乐华县公安局接群众举报称，涉嫌故意杀人罪的在逃人员岳×在东华县天光超市出现，遂指令特警老高、小于带队抓捕。老高、小于等人到达现场后，岳×发现情况对其不利，持刀将身旁群众劫持为人质，已危及该群众生命安全。老高开枪将岳×击伤。根据人民警察使用武器的相关规定，下列说法正确的是（）。", "options": [{"letter": "A", "text": "老高在使用武器前必须警告岳×"}, {"letter": "B", "text": "老高应将击伤岳×的情况及时通知其家属"}, {"letter": "C", "text": "老高使用武器后立即向东华县公安局报告"}, {"letter": "D", "text": "老高使用武器后立即向乐华县人民检察院报告"}], "answer": "C", "explanation": "根据《人民警察使用警械和武器条例》第12条，人民警察使用武器后，应当立即向所属公安机关报告。老高是乐华县公安局的特警，使用武器后应立即向乐华县公安局报告，C项正确。在紧急情况下来不及警告或警告可能导致更严重危害的，可以直接使用武器；通知家属是针对伤亡人员的后续程序。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 85}, {"num": 87, "batch": "专业基础知识", "type": "single", "stem": "随着我国治安管理形势的发展变化，公安机关应适时调整行业场所管理范围，尤其要加强新业态的安全监管，将新业态的“人、地、物、事、信息”等治安要素汇总聚集，并评估其带来的社会治安风险。下列新业态中，现不需要纳入治安管理范围的是（）。", "options": [{"letter": "A", "text": "无人驾驶航器"}, {"letter": "B", "text": "3D打印"}, {"letter": "C", "text": "网红孵化"}, {"letter": "D", "text": "量子计算"}], "answer": "D", "explanation": "随着社会发展，公安机关应加强对新业态的安全监管。无人驾驶航空器涉及低空安全、3D打印涉及枪支等违禁品制造风险、网红孵化涉及网络内容安全等，均需要纳入治安管理范围。量子计算目前主要处于科研阶段，尚未产生明显的社会治安风险，暂不需要纳入治安管理范围。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 86}, {"num": 88, "batch": "专业基础知识", "type": "single", "stem": "东华派出所在办理一起故意伤害案件中，依法进行了伤情鉴定。违法嫌疑人常x认为鉴定意见明显依据不足，申请重新鉴定。根据相关规定，下列关于重新鉴定说法正确的是（）。", "options": [{"letter": "A", "text": "重新鉴定期间计入办理治安案件的期限"}, {"letter": "B", "text": "对该案伤情的重新鉴定应当以一次为限"}, {"letter": "C", "text": "进行重新鉴定应经东华派出所所长批准"}, {"letter": "D", "text": "重新鉴定的费用应当由申请人常x承担"}], "answer": "B", "explanation": "根据《公安机关办理行政案件程序规定》，重新鉴定应当以一次为限，B项正确。重新鉴定期间不计入办案期限；重新鉴定应经县级以上公安机关负责人批准而非派出所所长；重新鉴定费用由公安机关承担，不由申请人承担。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 87}, {"num": 89, "batch": "专业基础知识", "type": "single", "stem": "某警校实训课程中，A小组对行政案件快速办理程序进行模拟执法，在实训过程中以下做法正确的是（）。", "options": [{"letter": "A", "text": "在办理结伙殴打他人案时使用快速办理程序"}, {"letter": "B", "text": "在快速办理行政案件前，口头告知违法嫌疑人快速办理的相关规定"}, {"letter": "C", "text": "在快速办理过程中，全程使用执法记录仪录音录像代替书面询问笔录"}, {"letter": "D", "text": "在快速办理行政案件时发现嫌疑人疑似精神病人，应当及时终止调查"}], "answer": "C", "explanation": "根据快速办理的相关规定，快速办理行政案件时全程使用执法记录仪录音录像可以代替书面询问笔录，C项正确。A项结伙殴打他人案不适用快速办理；B项快速办理前应书面告知而非口头告知；D项发现嫌疑人疑似精神病人应转为一般程序办理而非终止调查。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 88}, {"num": 90, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）2022年10月10日下午，甲派出所接到社区工作人员反映，辖区内一男子正在无事生非、恶意滋事，派出所民警立即前往事发地，将违法嫌疑人张某某当场抓获，并传唤至派出所进行调查。下列说法不正确的是（）。", "options": [{"letter": "A", "text": "经出示人民警察证，可以口头传唤张某某"}, {"letter": "B", "text": "应当将传唤的原因和依据告知张某某，并通知其家属"}, {"letter": "C", "text": "民警应在办案场所询问张某某"}, {"letter": "D", "text": "在办案场所询问张某某，可以不同步录音录像"}], "answer": "D", "explanation": "根据新修订的《治安管理处罚法》和相关规定，在办案场所询问违法嫌疑人时，应当对询问过程同步录音录像，以保障执法规范和当事人合法权益。D项称'可以不同步录音录像'不符合法律规定的要求。A项当场抓获经出示警察证可口头传唤正确；B项应告知传唤原因并通知家属正确；C项在办案场所询问正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 89}, {"num": 91, "batch": "专业基础知识", "type": "single", "stem": "我国行政法律规定了公安机关对行政违法行为人、单位处以警告或者小额罚款时可以适用简易程序的情形，同时对特定行政违法行为也作出了不适用简易程序的规定。根据相关法律规定，下列选项不适用简易程序的是（）。", "options": [{"letter": "A", "text": "源泉派出所拟对赵×赌博行为给予一百元罚款"}, {"letter": "B", "text": "源水派出所拟对钱×非法携带管制器具行为给予警告"}, {"letter": "C", "text": "榆县公安局交警大队拟对孙×不按规定停放机动车行为给予二百元罚款"}, {"letter": "D", "text": "封县公安局出入境管理大队拟对外国人李×非法居留行为给予五百元罚款"}], "answer": "A", "explanation": "根据新修订的《治安管理处罚法》关于简易程序的规定，对公民处以500元以下罚款或警告的可以适用简易程序。但结合题目设定和答案，A项赌博行为属于较复杂的治安案件，涉及赌博行为的认定和处罚裁量，不宜适用简易程序当场处理。赌博案件通常需要进一步调查取证，不适用快速简易的处理方式。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 90}, {"num": 92, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）下列各项中属于治安管理处罚种类的是（）。", "options": [{"letter": "A", "text": "罚金"}, {"letter": "B", "text": "赔偿"}, {"letter": "C", "text": "行政拘留"}, {"letter": "D", "text": "取保候审"}], "answer": "C", "explanation": "根据新修订的《治安管理处罚法》第10条，治安管理处罚的种类分为：警告、罚款、行政拘留、吊销公安机关发放的许可证件，以及对外国人的限期出境和驱逐出境。行政拘留是治安管理处罚的主要种类之一。罚金属于刑罚附加刑，赔偿属于民事责任，取保候审属于刑事强制措施。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 91}, {"num": 93, "batch": "专业基础知识", "type": "single", "stem": "甲村村民小敏突发疾病，在医院手术后效果不好，留下后遗症。小敏的父亲认为医生救治不及时，喊来甲村许多村民封堵大门，不让医院车辆、人员进出，并殴打参加手术的医护人员。医院报警，派出所民警依法对小敏的父亲刑事拘留。民警对甲村村民进行询问的正确做法是（）", "options": [{"letter": "A", "text": "由一名民警进行询问"}, {"letter": "B", "text": "让甲村村长代替民警询问"}, {"letter": "C", "text": "不允许村民自行提供书面陈述"}, {"letter": "D", "text": "在笔录中载明询问的起始时间"}], "answer": "D", "explanation": "根据《公安机关办理刑事案件程序规定》，询问证人应当在笔录中载明询问的起始时间和结束时间，以保障程序的规范性，D项正确。询问证人应当由两名以上侦查人员进行，不能由村长代替；证人可以自行提供书面陈述；一名民警询问不符合法定人数要求。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 92}, {"num": 94, "batch": "专业基础知识", "type": "single", "stem": "甲、乙居住在同一家属院，积怨颇深。某日晚，乙醉酒后回家，遇到正在遛狗的甲。狗朝乙狂叫，乙随口说：“再叫，就宰了你”。甲对乙说：“再说一遍”，乙随即朝甲的面部挥打一拳，甲立即松开狗链示意狗咬乙，乙从背包中取出一把匕首（带有刀柄、刀尖角度小于60度）与狗搏斗。民警在接到群众报警后赶到现场，将甲乙二人传唤至派出所。经法医鉴定，甲乙的伤情均为轻微伤。根据《治安管理处罚法》的规定，对甲的定性，下列说法正确的是：（）", "options": [{"letter": "A", "text": "应按照故意伤害，追究法律责任"}, {"letter": "B", "text": "应按照殴打他人，追究法律责任"}, {"letter": "C", "text": "正当防卫"}, {"letter": "D", "text": "防卫过当"}], "answer": "A", "explanation": "甲松开狗链示意狗咬乙，且乙取出匕首进行对抗，甲的行为具有伤害他人的主观故意和客观行为。甲使用犬只作为伤害工具，乙携带管制刀具，双方行为均超出正当防卫的范畴。甲的行为应按照故意伤害追究法律责任，而非正当防卫或防卫过当。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 93}, {"num": 95, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）周某因参与结伙斗殴被公安机关抓获，下列情形应当从轻、减轻或者不予处罚的是（）。", "options": [{"letter": "A", "text": "周某妻子怀孕需要照顾"}, {"letter": "B", "text": "周某主动赔偿并取得被害人谅解"}, {"letter": "C", "text": "周某生患多种疾病且家庭拮据"}, {"letter": "D", "text": "周某此前无违法犯罪记录"}], "answer": "B", "explanation": "根据新修订的《治安管理处罚法》，违反治安管理行为人主动消除或者减轻违法后果，并取得被侵害人谅解的，应当从轻、减轻或者不予处罚。B项周某主动赔偿并取得被害人谅解，符合法定从轻、减轻或不予处罚的条件。家庭困难、妻子怀孕、无前科等不是法定的从轻减轻事由。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 94}, {"num": 96, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）某公安局发现十五周岁的未成年人于某吸毒，下列说法正确的是（）。", "options": [{"letter": "A", "text": "于某既不适用强制隔离戒毒，也不适用社区戒毒"}, {"letter": "B", "text": "公安机关可以责令于某接受社区戒毒"}, {"letter": "C", "text": "公安机关不能对于某适用治安管理处罚"}, {"letter": "D", "text": "公安机关只能对于某适用社区戒毒"}], "answer": "B", "explanation": "根据《禁毒法》第38条和第33条，未成年吸毒人员不适用强制隔离戒毒，但公安机关可以责令其接受社区戒毒。同时，15周岁的于某属于已满14周岁不满16周岁，公安机关可以依法给予治安管理处罚。因此公安机关可以责令于某接受社区戒毒，B项正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 95}, {"num": 97, "batch": "专业基础知识", "type": "single", "stem": "甲、乙为同事，所居住小区相邻。某日，乙对甲说，次日我搭你的车一起上班，甲欣然同意。不料，次日甲径直开车上班，乙苦等不得，致使上班迟到，被扣当月奖金。乙为此要求甲赔偿损失，对此，下列表述正确的是（）。", "options": [{"letter": "A", "text": "违反合同约定，由甲承担违约责任"}, {"letter": "B", "text": "属于侵权行为，由甲承担侵权责任"}, {"letter": "C", "text": "协议未经充分协商，由乙承担缔约过失责任"}, {"letter": "D", "text": "该行为并非民事法律行为，由乙自己承担损失"}], "answer": "D", "explanation": "搭车约定属于好意施惠行为（情谊行为），不构成民事法律行为，不产生合同关系。甲没有法律上的义务必须搭载乙，不存在违约或侵权的问题。乙因甲未履行搭车承诺而遭受的损失，应由乙自行承担。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 96}, {"num": 98, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）下列属于寻衅滋事违法行为的是（）。", "options": [{"letter": "A", "text": "主播张某在直播时多次无故追逐/拦截街上穿着时尚的美女"}, {"letter": "B", "text": "残疾人王某在十字路口以敲打过往车辆车窗的方式进行乞讨"}, {"letter": "C", "text": "员工关某因对上司陆某安排的工作不满，在车间内对其多次辱骂"}, {"letter": "D", "text": "无业人员夏某以找人砸店威胁水果店主，向其索要200元"}], "answer": "A", "explanation": "根据《治安管理处罚法》关于寻衅滋事的规定，寻衅滋事行为包括结伙斗殴、追逐拦截他人、强拿硬要或任意损毁占用公私财物等扰乱公共秩序的行为。A项主播无故追逐、拦截路人属于寻衅滋事行为。B项属于以滋扰方式乞讨；C项属于针对特定个人的侮辱；D项属于威胁索要财物的敲诈勒索行为。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 97}, {"num": 99, "batch": "专业基础知识", "type": "single", "stem": "某日晚20时许，某派出所接市局110指令：称报警人李某的某品牌手机在某饭店吃饭时遗失。李某拨打遗失手机，捡到手机的张某接听，并称可以把李某的手机送还，但需支付劳务费，李某认可。双方在约定地点见面。但在交接时，张某提出加钱，李某不同意，发生争吵，张某一拳将李某鼻子打出血。根据以上情境，判断该警情的类型是：（）", "options": [{"letter": "A", "text": "经济纠纷"}, {"letter": "B", "text": "紧急求助"}, {"letter": "C", "text": "治安案件"}, {"letter": "D", "text": "刑事案件"}], "answer": "C", "explanation": "本案中张某捡到李某手机后索要劳务费并在交接过程中殴打李某致其鼻子出血，已构成殴打他人的治安违法行为。该警情已超出遗失物返还纠纷的范畴，涉及人身侵害行为，属于治安案件。不构成刑事案件（未达到轻伤以上），也不属于紧急求助或单纯的经济纠纷。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 98}, {"num": 100, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）被处罚人不服行政拘留处罚决定，提起行政诉讼的，可以向公安机关提出暂缓执行行政拘留的申请，经批准，按每日行政拘留（）的标准交纳保证金，行政拘留的处罚决定暂缓执行。", "options": [{"letter": "A", "text": "五十元"}, {"letter": "B", "text": "一百元"}, {"letter": "C", "text": "二百元"}, {"letter": "D", "text": "三百元"}], "answer": "C", "explanation": "根据新修订的《治安管理处罚法》第107条规定，被处罚人不服行政拘留处罚决定提起行政诉讼的，可以向公安机关提出暂缓执行行政拘留的申请，按每日行政拘留二百元的标准交纳保证金，行政拘留的处罚决定暂缓执行。保证金标准为每人每日200元。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 99}, {"num": 101, "batch": "专业基础知识", "type": "single", "stem": "对于违法行为案发现场，必要时应当进行勘验，提取与案件有关的证据材料，判断案件性质，确定调查方向和范围。以下关于勘验检查的说法正确的是（）。", "options": [{"letter": "A", "text": "检查公民住所时，人民警察经出示人民警察证，可以当场检查"}, {"letter": "B", "text": "检查妇女的身体，应当由女医师进行"}, {"letter": "C", "text": "检查场所时，被检查人必须在场"}, {"letter": "D", "text": "被检查人拒绝在检查笔录上签名的，办案人民警察应当在检查笔录中注明"}], "answer": "D", "explanation": "根据《公安机关办理行政案件程序规定》，被检查人拒绝在检查笔录上签名的，办案人民警察应当在检查笔录中注明，D正确。A错误，检查公民住所须出示检查证，不能仅凭人民警察证当场检查。B错误，检查妇女身体应由女工作人员进行，而非女医师。C错误，被检查人不在场时，可在见证人在场的情况下进行检查。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 100}, {"num": 102, "batch": "专业基础知识", "type": "single", "stem": "2022年9月30日12时，郑某将一辆白色奔驰停放在A市B区某街道边，王某在路边拍照时将白色奔驰车拍在照片内，郑某认为王某在举报他违章停车，双方因此发生口角，郑某拿公文包打伤王某头部后扬长而去（后经鉴定构成轻微伤），王某报警。案件办理过程中，民警依法对二人进行询问，下列说法正确的是（）。", "options": [{"letter": "A", "text": "民警应将郑某传唤至公安机关的询问室展开询问"}, {"letter": "B", "text": "询问郑某时应当全程录音、录像，并保证录音、录像的完整性"}, {"letter": "C", "text": "对郑某的询问查证应在8小时内完成"}, {"letter": "D", "text": "如王某要求在该街道居委会展开询问，民警可以满足其要求"}], "answer": "D", "explanation": "根据《治安管理处罚法》第八十二条，对被害人可以在其提出的地点进行询问，居委会属于合理地点，D正确。A错误，传唤至公安机关应使用传唤证，且不一定必须在询问室。B错误，并非所有案件都要求全程录音录像。C错误，案情复杂、可能适用行政拘留的，询问查证时间可延长至24小时。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 101}, {"num": 103, "batch": "专业基础知识", "type": "single", "stem": "某周末晚，新城区交警大队在辖区开展酒驾交通违法行为集中整治行动，查获赵X涉嫌酒后驾驶机动车，经现场对赵X进行呼气酒精测试，测试结果为79mg/100ml，赵X对测试结果无异议并签名确认。根据法律规定，下列选项错误的是（）。", "options": [{"letter": "A", "text": "交警告知赵X涉嫌饮酒后驾驶机动车"}, {"letter": "B", "text": "交警可以扣留赵X机动车驾驶证"}, {"letter": "C", "text": "交警不能扣留赵X驾驶的车辆"}, {"letter": "D", "text": "交警应当带赵X去医院抽血检验其体内酒精含量"}], "answer": "D", "explanation": "呼气酒精测试结果79mg/100ml属于饮酒后驾驶（80mg/100ml以上为醉酒驾驶），当事人无异议并签名确认，无需再抽血检验，D说法错误符合题意。根据《道路交通安全法》，交警可以告知驾驶人涉嫌饮酒驾驶（A正确）、扣留驾驶证（B正确）、扣留车辆（C正确）。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 102}, {"num": 104, "batch": "专业基础知识", "type": "single", "stem": "有群众举报张X曾经运送他人偷越国境，后经公安机关核实，张X在三年前有一次运送他人偷越国境的违法行为，之后一直表现良好。对于张X运送他人偷越国境的违法行为，公安机关拟采取的做法符合法律规定的是（）。", "options": [{"letter": "A", "text": "给予行政处罚"}, {"letter": "B", "text": "减轻行政处罚"}, {"letter": "C", "text": "免除行政处罚"}, {"letter": "D", "text": "依法不再处罚"}], "answer": "D", "explanation": "根据《行政处罚法》第三十六条及《治安管理处罚法》第二十二条，违法行为在二年内未被发现的，不再给予行政处罚。张X运送他人偷越国境的违法行为发生在三年前，已超过追究时效，依法不再处罚，D正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 103}, {"num": 105, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）根据《公安机关办理行政案件程序规定》以下案件中可以适用快速办理的是（）。", "options": [{"letter": "A", "text": "张某殴打王某，经查，张某疑似精神病人且张某本人对违法事实无异议，事实清楚，自愿认错认罚"}, {"letter": "B", "text": "胡某因与父母争吵，为发泄情绪，故意损毁小区照明路灯，价值500元。胡某对违法事实和适用法律无异议，自愿认错认罚"}, {"letter": "C", "text": "老王教唆小牧吸食毒品，被民警查获，老王对违法事实和适用法律无异议，自愿认错认罚"}, {"letter": "D", "text": "聋哑人费某嫖娼被抓获，自愿认错认罚"}], "answer": "B", "explanation": "根据《公安机关办理行政案件程序规定》，快速办理适用于事实清楚、违法嫌疑人自愿认错认罚且对适用法律无异议的案件，但不得适用于疑似精神病人、涉毒案件、聋哑人盲人等案件。A涉及疑似精神病人，C涉及教唆吸毒，D涉及聋哑人，均不适用快速办理。B中胡某故意损毁财物，事实清楚且自愿认错认罚，符合快速办理条件。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 104}, {"num": 106, "batch": "专业基础知识", "type": "single", "stem": "甲因为非法买卖罂粟壳被县公安局拟作出行政拘留10日并处罚款2000元的处罚，甲认为处罚过重，遂申请了听证。关于本案的听证，以下说法正确的是（）。", "options": [{"letter": "A", "text": "本案的听证应由办案部门组织实施"}, {"letter": "B", "text": "甲应当在告知听证权利后五日内提出申请"}, {"letter": "C", "text": "负责本案调查工作的民警不得担任听证主持人，但可以担任听证员或者记录员"}, {"letter": "D", "text": "若甲撤回听证申请，只要在处罚决定作出之前甲又提出听证申请的，公安机关应为其举行听证"}], "answer": "B", "explanation": "根据《行政处罚法》第六十四条，当事人要求听证的，应当在行政机关告知后五日内提出，B正确。A错误，听证应由非本案调查人员组织。C错误，调查人员不得担任听证主持人，也不得担任听证员或记录员。D错误，撤回听证申请后在处罚决定作出前又提出的，公安机关并非必须为其举行听证。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 105}, {"num": 107, "batch": "专业基础知识", "type": "single", "stem": "周某与赵某因工作争执致赵某手部轻微伤。根据法律的规定，经双方申请，辖区派出所进行了治安调解，调解协议约定周某赔偿赵某500元，但协议未履行。一个月后，赵某以伤势过重为由要求派出所再次进行调解追加赔偿费用。根据《公安机关办理行政案件程序规定》，对赵某提出的要求，派出所下列做法正确的是（）。", "options": [{"letter": "A", "text": "根据赵某的主张，要求周某追加赔偿费用"}, {"letter": "B", "text": "告知赵某向人民法院提起民事诉讼"}, {"letter": "C", "text": "申请人民法院强制执行"}, {"letter": "D", "text": "进行第二次调解"}], "answer": "B", "explanation": "根据《公安机关办理行政案件程序规定》第一百八十六条，调解协议未履行或者履行后又反悔的，公安机关应当告知当事人就民事争议向人民法院提起民事诉讼，B正确。公安机关不能强制执行调解协议，也不能再次调解。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 106}, {"num": 108, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）花园派出所在办理行政案件的过程中遇到以下情况，其中处理结果错误的是（）。", "options": [{"letter": "A", "text": "甲（13岁）因其母亲不为他购买玩具，故意将商场摊位上的玩具损坏（价值200元），公安机关对其决定不予处罚"}, {"letter": "B", "text": "乙（间歇性精神病）在精神正常时殴打邻居张某，并大声宣扬自己为精神病人，公安机关因考虑其为精神病人，对其减轻行政处罚"}, {"letter": "C", "text": "丙（盲人）强迫过路群众接受按摩服务违反治安管理，公安机关因考虑其为盲人对其从轻处罚"}, {"letter": "D", "text": "丁（聋哑人）因长期遭受李某的言语侮辱，故将李某饲养的土狗大黄盗走，后被公安机关发现，公安机关考虑其为聋哑人对其减轻处罚"}], "answer": "B", "explanation": "乙为间歇性精神病人，在精神正常时实施违法行为，应当依法承担法律责任，不能因其精神病人身份而减轻处罚，B处理错误符合题意。A正确，13岁不满14周岁不予处罚。C正确，盲人违反治安管理可从轻处罚。D正确，聋哑人可从轻或减轻处罚。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 107}, {"num": 109, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）盲人违反治安管理的，可以（）处罚。", "options": [{"letter": "A", "text": "从轻"}, {"letter": "B", "text": "免予"}, {"letter": "C", "text": "从轻、减轻或者不予"}, {"letter": "D", "text": "减轻"}], "answer": "C", "explanation": "根据新修订《治安管理处罚法》规定，盲人或者又聋又哑的人违反治安管理的，可以从轻、减轻或者不予处罚，C正确。这是考虑到盲人和聋哑人因身体缺陷，认知和表达能力受限，法律给予从宽处理。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 108}, {"num": 110, "batch": "专业基础知识", "type": "single", "stem": "吕某是甲市A区人，某日到B区某酒店与王某（女）进行了不法性交易，随后到Ｃ区网吧上网，在打游戏过程中与另一名上网人员秦某发生冲突，拿键盘将其殴打致轻微伤，两日后在Ｄ区上班时被抓。关于管辖，以下说法正确的是（）。", "options": [{"letter": "A", "text": "A区公安机关、C区公安机关对吕某殴打他人案件有管辖权"}, {"letter": "B", "text": "A区公安机关、B区公安机关对吕某嫖娼案件均有管辖权"}, {"letter": "C", "text": "B区公安机关、D区公安机关对吕某嫖娼案件均有管辖权"}, {"letter": "D", "text": "吕某殴打他人案只能由C区公安机关管辖"}], "answer": "A", "explanation": "行政案件由违法行为发生地的公安机关管辖。吕某殴打他人发生在C区，C区公安机关有管辖权；吕某嫖娼发生在B区，B区公安机关有管辖权。同时，违法行为人居住地公安机关在特定条件下也有管辖权。A区为居住地，一般不具有管辖权，但殴打他人案可由违法行为发生地C区和居住地A区管辖（在行为地管辖为主原则下），A正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 109}, {"num": 111, "batch": "专业基础知识", "type": "single", "stem": "提起行政复议时效为（）。", "options": [{"letter": "A", "text": "7日"}, {"letter": "B", "text": "15日"}, {"letter": "C", "text": "60日"}, {"letter": "D", "text": "30日"}], "answer": "C", "explanation": "根据《行政复议法》第二十条，公民、法人或者其他组织认为具体行政行为侵犯其合法权益的，可以自知道该具体行政行为之日起六十日内提出行政复议申请，C正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 110}, {"num": 112, "batch": "专业基础知识", "type": "single", "stem": "以下关于当场收缴罚款的说法正确的是（）。", "options": [{"letter": "A", "text": "民警对违反治安管理行为人张某处200元罚款，在张某无异议的情况下，可以当场收缴"}, {"letter": "B", "text": "民警当场收缴罚款时应向被处罚人出示省级财政部门统一制发的罚款收据，如不出示，被处罚人有权拒绝缴纳罚款"}, {"letter": "C", "text": "民警在当场收缴罚款后24小时内必须缴付至指定银行"}, {"letter": "D", "text": "民警在水上、旅客列车上当场收缴的罚款，缴付罚款的期限自作出处罚决定之时起算"}], "answer": "B", "explanation": "根据《治安管理处罚法》第一百零六条，当场收缴罚款时，必须向被处罚人出具省、自治区、直辖市人民政府财政部门统一制发的罚款收据；不出具的，被处罚人有权拒绝缴纳，B正确。A错误，当场收缴罚款限于100元以下。C错误，应当自收缴罚款之日起二日内缴付。D错误，水上、列车上当场收缴的，自抵岸或到站之日起算。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 111}, {"num": 113, "batch": "专业基础知识", "type": "single", "stem": "陈某故意伤害李某致李某轻微伤，甲市乙县公安局丙派出所遂对陈某作出罚款300元的处罚。陈某不服，拟提出行政复议。陈某的复议机关是（）。", "options": [{"letter": "A", "text": "丙乡政府和乙县人民政府"}, {"letter": "B", "text": "乙县公安局和乙县人民政府"}, {"letter": "C", "text": "乙县公安局"}, {"letter": "D", "text": "乙县人民政府"}], "answer": "D", "explanation": "根据《行政复议法》第二十四条，对县级以上地方各级人民政府工作部门的具体行政行为不服的，由本级人民政府管辖。丙派出所是乙县公安局的派出机构，其行政行为视为乙县公安局的行为，复议机关为乙县人民政府，D正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 112}, {"num": 114, "batch": "专业基础知识", "type": "single", "stem": "30岁的自由职业者黄某与明星周某积怨已久，经常在网上发文互爆对方“违法乱纪”。一日黄某在网络上公开发文声称：“周某与当地甲派出所勾结，该派出所所长已被周某买通，充当周某这个黑恶分子的保护伞。”该文被广泛传播，引起了相关纪委监委重视。经调查，该文所称之事子虚乌有，对此，有关部门对黄某作出行政拘留五日的处罚决定。若执行对黄某拘留五日的处罚时发现黄某因双腿受重伤而急需手术治疗，则应（）", "options": [{"letter": "A", "text": "不予执行行政拘留处罚"}, {"letter": "B", "text": "停止执行行政拘留"}, {"letter": "C", "text": "继续执行行政拘留处罚"}, {"letter": "D", "text": "将行政拘留处罚改为罚款"}], "answer": "B", "explanation": "根据《治安管理处罚法》第二十一条，被处罚人因严重疾病需要手术治疗的，应当停止执行行政拘留，B正确。不予执行适用于决定作出时即存在法定不执行情形，停止执行适用于决定作出后执行过程中出现的情形，本案属于后者。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 113}, {"num": 115, "batch": "专业基础知识", "type": "single", "stem": "南华县公安局民警在治安检查中尚场抓族正自赌博的杨X（15岁）、孙x（17周岁）、胡X（19周岁）。当场查获赌资1000余元，经查，三人之间均无违法经历。根据相关法律规定，下列说法正确的是（）。", "options": [{"letter": "A", "text": "不应对杨X做出行政处罚决定"}, {"letter": "B", "text": "应当追缴当场查获的赌资"}, {"letter": "C", "text": "对胡X当场做出行政处罚决定"}, {"letter": "D", "text": "对孙X做出行政处罚决定"}], "answer": "D", "explanation": "根据《治安管理处罚法》规定，已满14周岁不满18周岁的人违反治安管理的，从轻或减轻处罚；初次违反治安管理且已满14不满16周岁的，行政拘留不执行。杨X（15岁）初次违法应作出处罚决定但不执行拘留，A错误。孙X（17岁）初次违法，也应从轻或减轻处罚，D正确。赌资应予以收缴而非追缴，B错误。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 114}, {"num": 116, "batch": "专业基础知识", "type": "single", "stem": "公安机关民警当场收缴罚款，是一种代收罚款的行为，同样应在公众的监督下进行。下列可以当场收缴罚款正确的是（）。", "options": [{"letter": "A", "text": "程某被罚款200元，住在边远地区交通不便，民警决定对其当场收缴"}, {"letter": "B", "text": "民警严某当场收缴罚款第三日将罚款交至所属公安局"}, {"letter": "C", "text": "吕某违反治安管理，对其处以100元罚款"}, {"letter": "D", "text": "对违反治安管理的孙某处五十元罚款且其无异议"}], "answer": "D", "explanation": "根据《治安管理处罚法》第一百零四条，对违反治安管理行为人处五十元以下罚款且被处罚人无异议的，可以当场收缴，D正确。A错误，边远地区当场收缴需满足被处罚人在当地没有固定住所等条件。B错误，民警应在二日内将罚款交至所属公安机关。C错误，100元罚款不符合当场收缴的数额条件。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 115}, {"num": 117, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）违反治安管理行为的追究时效是（）。", "options": [{"letter": "A", "text": "3个月"}, {"letter": "B", "text": "6个月"}, {"letter": "C", "text": "1年"}, {"letter": "D", "text": "2年"}], "answer": "B", "explanation": "根据新修订《治安管理处罚法》第二十二条，违反治安管理行为在六个月内没有被公安机关发现的，不再处罚，B正确。追究时效从违反治安管理行为发生之日起计算，行为有连续或继续状态的，从行为终了之日起计算。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 116}, {"num": 118, "batch": "专业基础知识", "type": "single", "stem": "某日，因不满在A市B县内新建一大型垃圾焚烧发电厂，有超过近600名群众围堵在B县人民政府门口，要求停止该建设项目。根据事态现状，B县公安局拟实施现场管制措施，则下列说法正确的是（）。", "options": [{"letter": "A", "text": "需经B县人民政府批准"}, {"letter": "B", "text": "需经A市公安局批准"}, {"letter": "C", "text": "需经A市公安局和B县人民政府批准"}, {"letter": "D", "text": "需经A市公安局和A市人民政府批准"}], "answer": "C", "explanation": "根据《人民警察法》第十七条，县级以上人民政府公安机关经上级公安机关和同级人民政府批准，可以对严重危害社会治安秩序的突发事件实行现场管制。B县公安局需经A市公安局（上级公安机关）和B县人民政府（同级人民政府）批准，C正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 117}, {"num": 119, "batch": "专业基础知识", "type": "single", "stem": "下列情形中，属于公安机关人民警察法定职责的是（）。", "options": [{"letter": "A", "text": "对因非法捕捞被判处管制1年的孙某执行刑罚"}, {"letter": "B", "text": "对无照经营美甲店的孟某进行没收违法所得的处罚"}, {"letter": "C", "text": "对违规占道的流动摊贩张某作出罚款50元的处罚"}, {"letter": "D", "text": "对治安保卫委员会的治安防范工作进行指导"}], "answer": "D", "explanation": "根据《人民警察法》第六条，公安机关人民警察的职责包括指导治安保卫委员会的工作，D正确。A属于监狱管理机关的职责，B属于市场监管部门的职责，C属于城市管理部门的职责，均不属于公安机关人民警察的法定职责。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 118}, {"num": 120, "batch": "专业基础知识", "type": "single", "stem": "民警小谭休假期间穿着汉服在某古城景区吃饭，突然门口外卖员小虎与游客孙某发生口角，孙某要求小虎跪地道歉，小虎一气之下骑着电动车撞倒了孙某。根据《人民警察法》规定，民警小谭做法正确的是（）。", "options": [{"letter": "A", "text": "民警小谭未着装正在休假，且不在自己辖区，不需处理此事"}, {"letter": "B", "text": "小虎为弱势群体，对其骑电动车冲撞孙某行为应免予处罚"}, {"letter": "C", "text": "民警小谭制止小虎时，把协助自己的群众严某手机碰碎，小谭应赔偿"}, {"letter": "D", "text": "民警小谭必须自觉地接受社会和公民的监督"}], "answer": "D", "explanation": "根据《人民警察法》第十九条，人民警察在非工作时间遇有其职责范围内的紧急情形应当履行职责。同时，根据该法第四十四条，人民警察必须自觉地接受社会和公民的监督，D正确。A错误，警察非工作时间也应履行职责。B错误，弱势群体违法同样应受处罚。C错误，因协助执行职务造成的损失应由国家补偿。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 119}, {"num": 121, "batch": "专业基础知识", "type": "single", "stem": "《人民警察法》明确规定维护国家安全，维护社会治安秩序，保护公民的人身安全、人身自由和合法财产的人民警察不包括（）。", "options": [{"letter": "A", "text": "监狱的司法警察"}, {"letter": "B", "text": "中国人民武装警察"}, {"letter": "C", "text": "国家安全机关的人民警察"}, {"letter": "D", "text": "人民法院的司法警察"}], "answer": "B", "explanation": "根据《人民警察法》第二条，人民警察包括公安机关、国家安全机关、监狱、劳动教养管理机关的人民警察和人民法院、人民检察院的司法警察。中国人民武装警察部队不属于人民警察法调整范围，B正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 120}, {"num": 122, "batch": "专业基础知识", "type": "single", "stem": "甲市北城区发生严重危害社会治安秩序的突发事件，需要实行现场管制。根据《人民警察法》的相关规定，北城区公安分局实行现场管制的审批程序符合规定的是（）。", "options": [{"letter": "A", "text": "须经甲市公安局和北城区人民政府批准"}, {"letter": "B", "text": "只须经北城区人民政府批准"}, {"letter": "C", "text": "北城区公安分局可直接决定"}, {"letter": "D", "text": "只须经甲市公安局批准"}], "answer": "A", "explanation": "根据《人民警察法》第十七条，县级以上人民政府公安机关，经上级公安机关和同级人民政府批准，可以对严重危害社会治安秩序的突发事件实行现场管制。北城区公安分局需经甲市公安局（上级）和北城区人民政府（同级）批准，A正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 121}, {"num": 123, "batch": "专业基础知识", "type": "single", "stem": "公安队伍是党绝对领导下的一支纪律部队，公安机关人民警察应当按规定穿戴警服和警用标志。以下着装符合警容风纪要求的是（）。", "options": [{"letter": "A", "text": "民警在着警礼服参加重大纪念活动时，下身穿着执勤服警裤"}, {"letter": "B", "text": "民警着执勤服开展日常警务工作时，将非制式服装外露"}, {"letter": "C", "text": "民警在参与抗洪任务时将警服袖口、裤腿卷折起"}, {"letter": "D", "text": "民警因涉嫌违纪违法在接受停职处理的期间，可以穿着警服"}], "answer": "C", "explanation": "根据《公安机关人民警察着装管理规定》，民警在执行抗洪救灾等特殊任务时，可以根据需要将警服袖口、裤腿卷折起，C正确。A错误，警礼服应配套穿着，不能混搭。B错误，着警服时不得将非制式服装外露。D错误，涉嫌违纪违法接受停职处理期间不得穿着警服。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 122}, {"num": 124, "batch": "专业基础知识", "type": "single", "stem": "在打击整治电信网络诈骗犯罪行动中，张X等人因明知陈X利用信息网络实施犯罪，还为其提供互联网接入的行为，被人民法院以帮助信息网络犯罪活动罪判处刑罚。根据《人民警察法》规定，下列选项中由公安机关对执行刑罚人员依法履行职责的是（）。", "options": [{"letter": "A", "text": "有期徒刑一年"}, {"letter": "B", "text": "拘役三个月"}, {"letter": "C", "text": "缓刑二年"}, {"letter": "D", "text": "罚金一万元"}], "answer": "B", "explanation": "根据《人民警察法》和《刑事诉讼法》相关规定，公安机关负责执行拘役、剥夺政治权利等刑罚。有期徒刑由监狱执行，缓刑由社区矫正机构执行，罚金由人民法院执行。拘役由公安机关（看守所）执行，B正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 123}, {"num": 125, "batch": "专业基础知识", "type": "single", "stem": "2024年1月10日A市公安局举行庆祝第四个中国人民警察节暨全市公安系统表彰大会。会上，市局局长强调，要全面贯彻全国、全省公安系统英雄模范立功集体表彰大会精神，弘扬英模精神，进一步学习先进、凝聚警心，争取再创佳绩、再立新功。B派出所四名新警在收看表彰大会的现场视频后，针对人民警察奖励的相关规定展开了如下讨论，其中错误的是（）。", "options": [{"letter": "A", "text": "小张：奖励既可以授予集体，也可以授予个人"}, {"letter": "B", "text": "小李：奖励的种类一共有6种"}, {"letter": "C", "text": "小孙：授予个人的荣誉称号包括全国公安系统二级英雄模范和一级英雄模范"}, {"letter": "D", "text": "小王：对受奖励的人民警察，可以给予一定的物质奖励"}], "answer": "B", "explanation": "根据《公安机关人民警察奖励条令》，奖励分为集体奖和个人奖。集体奖包括嘉奖、记三等功、二等功、一等功、授予荣誉称号；个人奖也包括嘉奖、记三等功、二等功、一等功、授予荣誉称号，加上荣誉称号分为二级英雄模范和一级英雄模范，种类不止6种，B错误。A、C、D说法均正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 124}, {"num": 126, "batch": "专业基础知识", "type": "single", "stem": "2025年1月10日是第五个中国人民警察节，每一位人民警察都是我们身边最坚实的守护者他们不畏艰难，不惧风险始终站在保护人民的第一线。经过一系列改革，下列队伍中，目前不属于人民警察编制的有（）。", "options": [{"letter": "A", "text": "中国海警局海警队伍"}, {"letter": "B", "text": "公安警卫部队"}, {"letter": "C", "text": "司法机关法警队伍‌"}, {"letter": "D", "text": "公安边防部队"}], "answer": "A", "explanation": "2018年公安边防部队、公安警卫部队改制退出现役后，目前中国海警局海警队伍划归武警部队序列，不属于人民警察编制，A正确。公安边防和警卫部队虽已改制，但公安系统内仍有相应编制。司法机关法警仍属于人民警察序列。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 125}, {"num": 127, "batch": "专业基础知识", "type": "single", "stem": "加入人民警察队伍，是许多青年的梦想。下列不属于20周岁的陈某录用为人民警察条件的是（）。", "options": [{"letter": "A", "text": "拥护《中华人民共和国宪法》"}, {"letter": "B", "text": "具备专科以上文化程度"}, {"letter": "C", "text": "自愿从事人民警察工作"}, {"letter": "D", "text": "身体健康、良好品行"}], "answer": "B", "explanation": "根据《人民警察法》第二十六条，担任人民警察应当具备大专以上文化程度，而非专科（大专）以上。B选项表述为'专科以上'，实际上法律要求的是'大专以上'，但题意考查的是录用条件，B选项表述不准确，符合题意。A、C、D均属于法定录用条件。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 126}, {"num": 128, "batch": "专业基础知识", "type": "single", "stem": "某日，A市公安局对B区公安局下发一则警情指令，部署B区公安机关组织警力开展某项行动。在任务执行过程中出现以下情形，其中做法正确的是（）。", "options": [{"letter": "A", "text": "B区公安机关认为此项命令存在错误，应当向上级提出意见并中止任务的推进"}, {"letter": "B", "text": "当提出的意见不被采纳时，应当结合本地区实际情况改变命令的执行方式"}, {"letter": "C", "text": "执行命令的后果应当由任务执行单位负责"}, {"letter": "D", "text": "在命令执行期间，民警发现部分要求超越法律规定的人民警察职责范围，应当拒绝执行"}], "answer": "D", "explanation": "根据《人民警察法》第三十二条，人民警察必须执行上级决定和命令；认为决定和命令有错误的，可以按照规定提出意见，但不得中止或改变执行。如果命令超越法律规定的人民警察职责范围，人民警察应当拒绝执行，D正确。A错误，提出意见期间不得中止执行。B错误，不得擅自改变执行方式。C错误，执行后果由下达命令的上级负责。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 127}, {"num": 129, "batch": "专业基础知识", "type": "single", "stem": "凌某因无证驾驶三轮车被甲县公安局交通管理大队查处，其对该交通违法行为处理结果心有怨恨，为泄私愤利用抖音平台发布恶意辱骂甲县交警执法人员的视频信息。后甲县公安局依法对其作出行政拘留五日的处罚。凌某不服，申请行政复议的同时提出暂缓执行行政拘留的申请，下列说法正确的是（）。", "options": [{"letter": "A", "text": "凌某应当书面提出暂缓执行行政拘留的申请"}, {"letter": "B", "text": "公安机关应当在收到申请之时起四十八小时内作出决定"}, {"letter": "C", "text": "如凌某无法提供担保人，公安机关可以要求凌某交纳1000元保证金"}, {"letter": "D", "text": "若凌某申请以保证人担保，则其在本地无固定住所的外地成年亲属可以作为保证人"}], "answer": "C", "explanation": "根据《治安管理处罚法》第一百零七条，暂缓执行行政拘留的保证金按每日二百元标准计算，拘留五日即1000元，C正确。A错误，申请可以书面或口头提出。B错误，公安机关应当在收到申请之时起二十四小时内作出决定。D错误，保证人应在当地有固定住所。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 128}, {"num": 130, "batch": "专业基础知识", "type": "single", "stem": "2022年8月14日，周某乘坐A市飞往B市的C1234航班，在飞机滑行准备起飞阶段，周某使用手机通话前后五分钟有余。在此过程中，航班安全员对周某进行了多次劝阻，周某均未接受，直至安全员徒手制止时才挂断电话。航班降落后，机组报警，B市机场公安分局受案并开展调查。因案件事实清楚且周某后续认错态度良好，B市机场公安分局拟对本案适用快速办理程序，下列做法正确的是（）。", "options": [{"letter": "A", "text": "可以根据周某认错悔改、赔偿损失等情节，依法对其从轻、减轻处罚或者不予行政处罚"}, {"letter": "B", "text": "本案应当在公安机关受案后四十八小时内作出处理决定"}, {"letter": "C", "text": "在适用快速办理前，公安机关应当口头告知违法嫌疑人快速办理的相关规定，征得其同意"}, {"letter": "D", "text": "如在快速办理本案时，发现本案不适宜快速办理，转为一般案件办理，前阶段收集的证据需要按照一般程序重新收集"}], "answer": "A", "explanation": "根据《公安机关办理行政案件程序规定》关于快速办理的规定，可以根据违法嫌疑人认错悔改、赔偿损失等情节，依法从轻、减轻或不予处罚，A正确。B错误，快速办理应在四十八小时内作出处理决定，但并非所有案件都以此为限。C错误，应书面告知而非口头告知。D错误，转为一般程序后，已收集的证据无需重新收集。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 129}, {"num": 131, "batch": "专业基础知识", "type": "single", "stem": "山河大学学生小陈与同学讨论“人民警察职责”的话题时，有同学认为：“人民警察的非工作时间属于个人休息时间，可以不履行职责。”小陈查阅《中华人民共和国人民警察法》进行求证。根据该法，人民警察在非工作时间，遇有其职责范围内的紧急情形，应当做的是（）。", "options": [{"letter": "A", "text": "履行职责"}, {"letter": "B", "text": "代履行职责"}, {"letter": "C", "text": "视情履行职责"}, {"letter": "D", "text": "不履行职责"}], "answer": "A", "explanation": "根据《人民警察法》第十九条，人民警察在非工作时间，遇有其职责范围内的紧急情形，应当履行职责，A正确。这体现了人民警察职业的特殊性，职责不因工作时间与非工作时间而有所区别。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 130}, {"num": 132, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）根据《治安管理处罚法》相关规定，已满（）不满十八周岁的人违反治安管理的，从轻或者减轻处罚。", "options": [{"letter": "A", "text": "十二周岁"}, {"letter": "B", "text": "十四周岁"}, {"letter": "C", "text": "十五周岁"}, {"letter": "D", "text": "十六周岁"}], "answer": "B", "explanation": "根据新修订《治安管理处罚法》规定，已满十四周岁不满十八周岁的人违反治安管理的，从轻或者减轻处罚，B正确。不满十四周岁的人违反治安管理的，不予处罚。这一规定体现了对未成年人违法的教育为主、惩罚为辅原则。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 131}, {"num": 133, "batch": "专业基础知识", "type": "single", "stem": "管某以需要资金周转为由，向金某借款3万元，管某出具内容为“于某年某月某日向金某借款3万元，借期为五年”的借条一份、收到金某转账3万元的收条1份给金某收执。次日，金某向管某的银行卡内转账27000元，后管某一直未偿还该借款，二人产生争执。关于此借款，下列说法正确的是（）。", "options": [{"letter": "A", "text": "二人借款合同自出具借条和收条之日起成立"}, {"letter": "B", "text": "二人对借款期限没有约定，金某不得催告管某偿还借款"}, {"letter": "C", "text": "实际借款金额应以27000元认定"}, {"letter": "D", "text": "二人之间的借款利息按照同期银行贷款利率确定"}], "answer": "C", "explanation": "根据《民法典》第六百七十条，借款的利息不得预先在本金中扣除。预先扣除的，应当按照实际借款数额返还借款并计算利息。借条写3万元但实际转账27000元，属于'砍头息'，实际借款金额应以27000元认定，C正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 132}, {"num": 134, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）有两种以上违反治安管理行为的，分别决定，合并执行。行政拘留处罚合并执行的，最长不超过（）日。", "options": [{"letter": "A", "text": "15"}, {"letter": "B", "text": "20"}, {"letter": "C", "text": "30"}, {"letter": "D", "text": "60"}], "answer": "B", "explanation": "根据新修订《治安管理处罚法》规定，有两种以上违反治安管理行为的，分别决定，合并执行。行政拘留处罚合并执行的，最长不超过二十日，B正确。这一规定既体现了对多种违法行为的从严处理，又设定了合理上限以保障人权。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 133}, {"num": 135, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）根据《治安管理处罚法》规定，下列情形从轻、减轻或者不予处罚的是（）。", "options": [{"letter": "A", "text": "赵某在醉酒状态下将他人打成轻微伤"}, {"letter": "B", "text": "赵某在醉酒状态下将他人打成轻微伤"}, {"letter": "C", "text": "因李某举报张某吸毒，张某对李某进行打击报复"}, {"letter": "D", "text": "陈某受他人胁迫偷走了小王的钱包"}], "answer": "D", "explanation": "根据《治安管理处罚法》相关规定，醉酒的人违反治安管理的应当给予处罚，A、B错误。打击报复举报人应从重处罚，C错误。根据该法规定，受他人胁迫或者诱骗违反治安管理的，从轻、减轻或者不予处罚，D正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 134}, {"num": 136, "batch": "专业基础知识", "type": "single", "stem": "对于违法事实确凿的行政案件，公安机关可以使用简易程序当场作出处罚决定。对于简易程序的使用，以下情形正确的是（）。", "options": [{"letter": "A", "text": "对当场抓获的卖淫、嫖娼的甲和乙，符合条件的可以适用简易程序"}, {"letter": "B", "text": "在进行当场处罚前，民警应当书面告知违法行为人拟作出行政处罚决定的事实、理由和依据"}, {"letter": "C", "text": "适用简易程序符合当场收缴条件的，进行当场收缴的同时要填写省级以上财政部门出具的罚款收据"}, {"letter": "D", "text": "对在旅客列车上作出处罚决定的，应当在返回后的2日内向所属公安机关报告"}], "answer": "C", "explanation": "根据《公安机关办理行政案件程序规定》，适用简易程序符合当场收缴条件的，进行当场收缴的同时要填写省级以上财政部门统一制发的罚款收据，C正确。A错误，卖淫嫖娼案件不得适用简易程序。B错误，当场处罚前应口头告知。D错误，在旅客列车上当场处罚的，应当在返回后二十四小时内向所属公安机关备案。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 135}, {"num": 137, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）下列有关法律责任的说法，正确的是（）。", "options": [{"letter": "A", "text": "甲、乙双方签订一份买卖合同，按照合同约定，甲应在合同签订后7日内向乙交付钢材5吨，在履行期间，乙只享有民事权利而甲只承担民事义务"}, {"letter": "B", "text": "甲违法停车，暴力抗拒民警检查，并将民警打成轻伤。则甲除承担行政责任外，还将承担刑事责任"}, {"letter": "C", "text": "民事责任属于法定责任，因此不允许当事人协商免除"}, {"letter": "D", "text": "宪法是国家根本大法，触犯了刑法中强制性规定的行为都是违宪行为，要承担违宪责任"}], "answer": "B", "explanation": "甲违法停车承担行政责任，暴力抗法将民警打成轻伤构成故意伤害罪，需承担刑事责任，B正确。A错误，买卖合同双方均享有权利承担义务。C错误，民事责任允许当事人协商免除。D错误，违反刑法的行为是犯罪行为，不等同于违宪行为。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 136}, {"num": 138, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）下列不属于妨害公共安全行为的是（）", "options": [{"letter": "A", "text": "某路边仓库管理部门未经批准安装了防盗电网"}, {"letter": "B", "text": "李某盗窃正在使用的铁路信号灯"}, {"letter": "C", "text": "张某为练习枪法，用汽枪射击街边的路灯"}, {"letter": "D", "text": "程某为发泄不满，纠集多人到马路上堵塞交通"}], "answer": "D", "explanation": "妨害公共安全行为是指故意或过失危害不特定多数人的生命健康或重大公私财产安全的行为。A私设电网、B盗窃铁路信号灯、C用汽枪射击路灯均危害公共安全。D纠集多人堵塞交通属于扰乱公共秩序行为，不属于妨害公共安全，D正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 137}, {"num": 139, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）根据《治安管理处罚法》的规定，不予处罚的是（）。", "options": [{"letter": "A", "text": "甲在十四周岁生日当天的聚会上，醉酒后与人打架致对方轻微伤"}, {"letter": "B", "text": "双目失明的乙嫖娼"}, {"letter": "C", "text": "丙被胁迫盗窃某便利店价值800元财物"}, {"letter": "D", "text": "丁参与赌博后主动投案"}], "answer": "A", "explanation": "不满十四周岁的人违反治安管理的不予处罚。甲在十四周岁生日当天，法律上仍视为不满十四周岁，不予处罚，A正确。B盲人可从轻、减轻或不予处罚，但并非应当不予处罚。C受胁迫盗窃可从轻、减轻或不予处罚，但也非应当不予处罚。D主动投案可从轻或减轻处罚，但不属于不予处罚的情形。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 138}, {"num": 140, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）下列违反治安管理行为中属于寻衅滋事的是（）。", "options": [{"letter": "A", "text": "张某因工作原因殴打同事"}, {"letter": "B", "text": "李某为寻求刺激追逐殴打过往行人"}, {"letter": "C", "text": "王某拿10元钱强行从水果摊买走价值30元的水果"}, {"letter": "D", "text": "赵某在公安局办证大厅起哄闹事致使办证工作不能正常进行"}], "answer": "B", "explanation": "根据《治安管理处罚法》第二十六条，寻衅滋事包括结伙斗殴、追逐拦截他人、强拿硬要、任意损毁占用公私财物以及其他寻衅滋事行为。李某为寻求刺激追逐殴打行人属于典型的寻衅滋事行为，B正确。A属于殴打他人，C属于强拿硬要但更偏强迫交易，D属于扰乱单位秩序。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 139}, {"num": 141, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）以下关于行政处罚的决定适用错误的是（）。", "options": [{"letter": "A", "text": "嫌疑人甲16周岁生日当天在某酒吧内与人斗殴，造成被害人轻微伤，对甲应当从轻或减轻处罚"}, {"letter": "B", "text": "嫌疑人乙（聋人）因受不了路人对他的戏谑，对其大打出手造成被害人轻微伤，考虑到其为残疾人对其可以从轻、减轻或者不予处罚"}, {"letter": "C", "text": "嫌疑人丙诈骗老人50元后，因内心忐忑难安，前往派出所投案并如实陈述违法行为，同时积极配合退赃，对其从轻、减轻或者不予处罚"}, {"letter": "D", "text": "因盗窃被公安机关当场抓获的嫌疑人丁，公安机关在询问过程中发现该人曾于2个月前因嫖娼案被处行政拘留，对其进行从重处罚"}], "answer": "B", "explanation": "根据法律规定，又聋又哑的人或盲人违反治安管理的，可以从轻、减轻或不予处罚。乙仅为聋人（非又聋又哑），不符合法定从宽条件，B适用错误符合题意。A正确，16周岁生日当天视为不满16周岁，应从轻或减轻。C正确，主动投案并配合退赃可从轻处理。D正确，有前科可从重处罚。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 140}, {"num": 142, "batch": "专业基础知识", "type": "single", "stem": "某支队民警甲在辖区对重点区域违法停车展开日常执法整治时，发现一辆小客车涉嫌违法，调查取证后甲依法作出了处罚决定，此时妇女乙（车主）和妇女丙突然出现并阻扰民警执法，怀抱儿童的妇女乙在甲再三劝说、警告后仍然无理纠缠并对甲推搡抓挠。甲为制止乙妨碍执法的行为，徒手将乙按倒在地，乙所抱儿童同时跌落。妇女丙见状情绪激动，主动赤裸上身大喊警察非礼，引来了众多群众围观，造成了较大舆论影响。若对丙主动赤裸上身的行为进行处罚，其法律依据是（）。", "options": [{"letter": "A", "text": "刑法"}, {"letter": "B", "text": "治安管理处罚法"}, {"letter": "C", "text": "人民警察法"}, {"letter": "D", "text": "公安机关人民警察现场制止违法犯罪行为操作规程"}], "answer": "B", "explanation": "丙主动赤裸上身大喊警察非礼，引起群众围观造成较大舆论影响，属于在公共场所故意裸露身体的行为，根据《治安管理处罚法》第四十四条，应依据治安管理处罚法予以处罚，B正确。该行为尚未构成犯罪，不适用刑法。人民警察法和现场制止规程不是处罚的法律依据。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 141}, {"num": 143, "batch": "专业基础知识", "type": "single", "stem": "王某醉酒后殴打李某致轻微伤，乘车回家途中醉卧马路。群众报警后，派出所民警赵某、余某处警。公安机关对王某殴打李某案件进行办理。经查，李某因向王某讨要所欠“食用油”款，发生口角，被醉酒的王某打伤。办案中，侦查员发现涉案“食用油”价格极低，成分复杂。侦查员紧抓疑点深入调查，进一步查明：王某系火锅店老板，低价购买李某用餐厨垃圾、废弃油脂等生产的“地沟油”，包装成“食用油”，供顾客火锅食用。王某、李某对以上事实供认不讳。根据刑法，王某、李某的行为涉嫌构成（）", "options": [{"letter": "A", "text": "王某、李某均构成非法经营罪"}, {"letter": "B", "text": "王某、李某均构成制造、出售危害健康食品罪"}, {"letter": "C", "text": "王某、李某均构成生产、销售有毒、有害食品罪"}, {"letter": "D", "text": "王某、李某均构成经营不符合安全标准的食品罪"}], "answer": "C", "explanation": "根据《刑法》第一百四十四条，在生产、销售的食品中掺入有毒、有害的非食品原料的，或者销售明知掺有有毒、有害的非食品原料的食品的，构成生产、销售有毒、有害食品罪。王某利用餐厨垃圾、废弃油脂生产'地沟油'并供顾客食用，属于在食品中掺入有毒有害的非食品原料，C正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 142}, {"num": 144, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）办理治安案件所查获的毒品、淫秽物品等违禁品应当（）。", "options": [{"letter": "A", "text": "没收"}, {"letter": "B", "text": "收缴"}, {"letter": "C", "text": "追缴"}, {"letter": "D", "text": "扣押"}], "answer": "B", "explanation": "根据新修订《治安管理处罚法》规定，办理治安案件所查获的毒品、淫秽物品等违禁品，应当予以收缴，B正确。收缴是对违禁品等非法财物的处理方式，与没收（行政处罚种类）和追缴（针对违法所得）不同。扣押是调查过程中的临时性措施。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 143}, {"num": 145, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）甲（女），无业，在网上结识一名网友乙（男）并同居。其间，甲多次以家人生病或出车祸为由向乙借钱，乙均置之不理。甲一气之下拨打110报警电话，称自己被乙强奸。甲的行为属于（）。", "options": [{"letter": "A", "text": "扰乱公共秩序的行为"}, {"letter": "B", "text": "妨害公共安全的行为"}, {"letter": "C", "text": "侵犯人身权利的行为"}, {"letter": "D", "text": "妨害社会管理的行为"}], "answer": "A", "explanation": "甲拨打110谎称被强奸，属于谎报警情、故意扰乱公共秩序的行为，根据《治安管理处罚法》第二十五条，应按扰乱公共秩序行为处罚，A正确。该行为并非妨害公共安全、侵犯人身权利或妨害社会管理的行为。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 144}, {"num": 146, "batch": "专业基础知识", "type": "single", "stem": "某日，刘某携妻子赵某参加朋友聚餐，席间因为与朋友小肖因为言语不合吵了起来，赵某急忙拉住刘某，让其下楼冷静下，刘某遂独自下楼抽烟。期间，因路过的陌生男子看了刘某一眼，刘某便上前对该男子拳脚相加，以求泄愤，周围群众发现后立即拨打110报警。经过伤情鉴定，被打男子构成轻微伤。关于本案刘某行为的定性最准确的是（）。", "options": [{"letter": "A", "text": "属于故意伤害"}, {"letter": "B", "text": "属于殴打他人"}, {"letter": "C", "text": "属于寻衅滋事"}, {"letter": "D", "text": "属于扰乱公共场所秩序"}], "answer": "C", "explanation": "刘某因与朋友争吵后心情不佳，对路过的陌生男子无故拳脚相加，属于随意殴打他人、发泄情绪的寻衅滋事行为，C正确。殴打他人一般针对特定对象，故意伤害需达到轻伤以上标准，扰乱公共场所秩序侧重于对场所秩序的破坏。刘某的行为具有随意性和无事生非的特征，属于寻衅滋事。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 145}, {"num": 147, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）人民警察办理治安案件，有刑讯逼供、体罚、虐待、侮辱他人行为的，依法（）", "options": [{"letter": "A", "text": "给予处分：构成犯罪的，依法追究刑事责任"}, {"letter": "B", "text": "给予治安管理处罚：构成犯罪的，依法追究刑事责任"}, {"letter": "C", "text": "给予行政处分，同时予以治安管理处罚"}, {"letter": "D", "text": "予以训诫"}], "answer": "A", "explanation": "根据新修订《治安管理处罚法》规定，人民警察办理治安案件，有刑讯逼供、体罚、虐待、侮辱他人行为的，依法给予处分；构成犯罪的，依法追究刑事责任，A正确。这体现了对执法人员违法行为的严肃处理原则。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 146}, {"num": 148, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）根据《治安管理处罚法》的规定，教唆、胁迫，诱骗他人违反治安管理的，（）处罚。", "options": [{"letter": "A", "text": "以教唆、胁迫、诱骗的行为"}, {"letter": "B", "text": "与实施者同等"}, {"letter": "C", "text": "加重"}, {"letter": "D", "text": "从重"}], "answer": "A", "explanation": "根据新修订《治安管理处罚法》规定，教唆、胁迫、诱骗他人违反治安管理的，按照其教唆、胁迫、诱骗的行为处罚，A正确。即教唆者不是与被教唆者同等处罚，而是以其教唆、胁迫、诱骗的行为本身来确定处罚。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 147}, {"num": 149, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）根据《治安管理处罚法》的规定，下列情形可以执行行政拘留处罚的是（）。", "options": [{"letter": "A", "text": "甲（正在怀孕妇女）因吸食毒品被处行政拘留"}, {"letter": "B", "text": "乙（现年71岁）因殴打王某致轻微伤被处行政拘留"}, {"letter": "C", "text": "丙（又聋又哑）因在超市盗窃价值500元货物被处行政拘留"}, {"letter": "D", "text": "丁（正哺乳自己不满一周岁婴儿的妇女）因卖淫被处行政拘留"}], "answer": "C", "explanation": "根据新修订《治安管理处罚法》规定，怀孕或哺乳不满一周岁婴儿的妇女不执行行政拘留。又聋又哑的人违反治安管理的可以从轻、减轻或不予处罚，但并非不执行拘留，C可以被执行拘留。A怀孕妇女、D哺乳婴儿不执行拘留。B已满70周岁的人，根据新法规定也不执行拘留。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 148}, {"num": 150, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）对于张某教唆王某实施寻衅滋事的违反治安管理行为，公安机关应（）", "options": [{"letter": "A", "text": "从重处罚张某，同时处罚王某"}, {"letter": "B", "text": "从重处罚王某，同时处罚张某"}, {"letter": "C", "text": "给予张某、王某相同的处罚"}, {"letter": "D", "text": "对王某处罚，对张某不处罚"}], "answer": "A", "explanation": "根据《治安管理处罚法》关于教唆行为的规定，教唆他人违反治安管理的，按照其教唆的行为处罚，并从重处罚教唆者。同时，被教唆者实施了违法行为的，也应当依法予以处罚，A正确。即张某作为教唆者应从重处罚，王某作为实施者也应受到处罚。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 149}, {"num": 151, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）精神病人在不能辨认或者不能控制自己行为的时候违反治安管理的，应当（）。", "options": [{"letter": "A", "text": "减轻处罚"}, {"letter": "B", "text": "从轻处罚"}, {"letter": "C", "text": "予以处罚"}, {"letter": "D", "text": "不予处罚"}], "answer": "D", "explanation": "根据《治安管理处罚法》第十三条，精神病人在不能辨认或者不能控制自己行为的时候违反治安管理的，不予处罚，但是应当责令其监护人严加看管和治疗，D正确。间歇性精神病人在精神正常时违反治安管理的，应当给予处罚。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 150}, {"num": 152, "batch": "专业基础知识", "type": "single", "stem": "某市场相邻档位摆摊的甲、乙二人，因货品摆放问题产生矛盾，长期关系不和。某日中午，甲的狗溜到乙的摊位，将乙摆卖的瓷瓶碰倒摔碎（销售价为500元）。乙见状很生气，一边呵骂狗一边跑到甲的摊位将甲摆卖的货品推倒在地（被损坏货品销售价为600元）。甲见此也一时火起，随手操起拖把打向乙，致乙受伤（后经鉴定为轻微伤）。围观的群众拨打110报警。辖区派出所民警小刘、小李接出警指令后立即出警，迅速赶赴现场处置。民警小刘、小李经出示人民警察证，口头传唤甲到公安派出所接受询问，甲拒绝前往。此时民警对甲采取的措施符合法律规定的是（）。", "options": [{"letter": "A", "text": "使用手铐强制传唤"}, {"letter": "B", "text": "对甲拘传"}, {"letter": "C", "text": "使用警棍击打甲追使其接受传唤"}, {"letter": "D", "text": "继续盘问"}], "answer": "A", "explanation": "根据《治安管理处罚法》第八十二条第二款，对无正当理由不接受传唤或者逃避传唤的人，可以强制传唤。强制传唤时可以使用手铐、警绳等约束性警械，A正确。拘传属于刑事强制措施，不适用于行政案件。使用警棍击打属于使用驱逐性警械，不符合比例原则。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 151}, {"num": 153, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）根据《治安管理处罚法》规定，关于人民警察在办理治安案件过程中的回避，下列说法错误的是（）。", "options": [{"letter": "A", "text": "人民警察的回避，由其所属的公安机关决定"}, {"letter": "B", "text": "违反治安管理行为人是警察甲的儿子，甲应当回避"}, {"letter": "C", "text": "警察乙的母亲是其办理的治安案件的被侵害人，乙应当回避"}, {"letter": "D", "text": "公安机关负责人的回避，由同级人民检察院检察委员会决定"}], "answer": "D", "explanation": "根据《治安管理处罚法》第八十一条，公安机关负责人的回避，由上一级公安机关决定，而非由同级人民检察院检察委员会决定，D错误符合题意。A正确，警察的回避由所属公安机关决定。B、C正确，与案件有利害关系的警察应当回避。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 152}, {"num": 154, "batch": "专业基础知识", "type": "single", "stem": "下列案件中公安机关应当告知违法嫌疑人有权要求举行听证的是（）。", "options": [{"letter": "A", "text": "李某因赌博被公安机关处以500元罚款"}, {"letter": "B", "text": "张某因嫖娼被公安机关处以拘留10日并处4000元罚款"}, {"letter": "C", "text": "“飞翔网吧”因未按规定核对、登记上网消费者的有效身份证件被公安机关警告并处3000元罚款"}, {"letter": "D", "text": "刘某因饮酒后驾驶机动车被公安机关交通管理部门暂扣6个月的机动车驾驶证并处1000元罚款"}], "answer": "B", "explanation": "根据《公安机关办理行政案件程序规定》，公安机关拟作出行政拘留处罚、对个人处以二千元以上罚款等决定时，应当告知违法嫌疑人有权要求听证。B项拘留10日并处4000元罚款，罚款金额达到听证标准，应当告知听证权利。A罚款500元、C罚款3000元（对单位）、D罚款1000元均未达到个人听证标准。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 153}, {"num": 155, "batch": "专业基础知识", "type": "single", "stem": "王某施工中不慎将陈某的隔热棚砸坏，两人发生争吵推搡，后被邻居分开。陈某报警，现场民警应该（）。", "options": [{"letter": "A", "text": "禁止王某继续施工"}, {"letter": "B", "text": "对王某罚款50元"}, {"letter": "C", "text": "现场对隔热棚估价"}, {"letter": "D", "text": "现场进行调解"}], "answer": "D", "explanation": "根据《治安管理处罚法》第九条，对于因民间纠纷引起的打架斗殴或者损毁他人财物等违反治安管理行为，情节较轻的，公安机关可以调解处理。王某不慎砸坏陈某隔热棚属于民间纠纷，现场民警可以进行调解，D正确。民警无权禁止施工、当场罚款或现场估价。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 154}, {"num": 156, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）乘客周某乘坐高铁时霸占别人座位被乘警带至某铁路派出所，对于周某的处罚下列做法正确的是（）", "options": [{"letter": "A", "text": "周某若对处罚不服，可以直接提起行政诉讼"}, {"letter": "B", "text": "周某作为成年人，被行政拘留后，可以根据当事人意愿不通知其家人"}, {"letter": "C", "text": "该铁路派出所作出对周某行政拘留5日，罚款500元的处罚决定"}, {"letter": "D", "text": "因需要对周某拘留审查，这起事件的处理期限最长不得超过20日"}], "answer": "A", "explanation": "根据《行政诉讼法》，当事人对行政处罚不服的，可以直接提起行政诉讼，A正确。B错误，作出行政拘留决定后应当及时通知被处罚人家属。C错误，派出所无权作出行政拘留决定。D错误，办案期限根据具体程序而定，并非最长不超过20日。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 155}, {"num": 157, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）化解矛盾纠纷、维护社会治安秩序是公安派出所的主要工作之一。下列可以采用纠纷化解来处理的是（）。", "options": [{"letter": "A", "text": "陈某刷码开启共享汽车给16岁的儿子“练手”，发生剐蹭事故"}, {"letter": "B", "text": "易某多次在微信朋友圈里对同事曾某进行辱骂"}, {"letter": "C", "text": "刘某因感情纠纷到前妻公司打砸物品，造成损失"}, {"letter": "D", "text": "赵某因外卖延时送达，与快递员李某发生争吵"}], "answer": "D", "explanation": "纠纷化解适用于因民间纠纷引起的轻微治安案件。D项赵某因外卖延时与快递员发生争吵，属于日常民事纠纷，适合通过纠纷化解方式处理。A涉及未成年人违法驾驶，B涉及侮辱他人，C涉及故意损毁财物，均属于违法行为，需要依法处理而非简单纠纷化解。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 156}, {"num": 158, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）对决定给予行政拘留处罚的人，在处罚前已经采取（）强制措施限制人身自由的时间，应当折抵。", "options": [{"letter": "A", "text": "询问查证"}, {"letter": "B", "text": "刑事拘留"}, {"letter": "C", "text": "继续盘问"}, {"letter": "D", "text": "约束"}], "answer": "B", "explanation": "根据新修订《治安管理处罚法》规定，对决定给予行政拘留处罚的人，在处罚前已经采取刑事拘留强制措施限制人身自由的时间，应当折抵，B正确。询问查证、继续盘问、约束等限制人身自由的措施不折抵行政拘留时间。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 157}, {"num": 159, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）根据《治安管理处罚法》的规定，下列选项中应当从轻、减轻或者不予处罚的是（）。", "options": [{"letter": "A", "text": "聋哑人张某嫖娼"}, {"letter": "B", "text": "十七岁陈某吸毒"}, {"letter": "C", "text": "詹某被刘某胁迫殴打他人致轻微伤"}, {"letter": "D", "text": "邹某酒后损毁价值三百元的财物"}], "answer": "C", "explanation": "根据《治安管理处罚法》规定，受他人胁迫或者诱骗违反治安管理的，从轻、减轻或者不予处罚，C正确。A聋哑人可从轻、减轻或不予处罚（注意新法规定盲人、聋哑人从宽）。B已满16不满18初次违反的不执行拘留，但17岁吸毒不属于该情形。D醉酒不属法定从轻情节。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 158}, {"num": 160, "batch": "专业基础知识", "type": "single", "stem": "群众举报杨某在家中聚众赌博，县公安局民警接警后到杨某的住处检查，当场查获杨某等四人聚赌，在麻将台上搜获人民币8500元，并从四人身上查获金项链4条，手表2块、紫檀手串1个（未下注）。民警张某等人分别一对一地对杨某等进行了询问，杨某等人承认了赌博事实。办案民警决定对杨某聚众赌博的违法行为予以行政拘留，应当以谁的名义作出？（）", "options": [{"letter": "A", "text": "辖区派出所"}, {"letter": "B", "text": "县公安局"}, {"letter": "C", "text": "县公安局法制部"}, {"letter": "D", "text": "县人民政府"}], "answer": "B", "explanation": "根据《治安管理处罚法》第九十一条，治安管理处罚由县级以上人民政府公安机关决定。聚众赌博拟作出行政拘留处罚，应由县公安局作出决定，B正确。派出所只能作出警告和五百元以下罚款的处罚决定，无权决定行政拘留。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 159}, {"num": 161, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）下列行为中（）不属于虚构事实扰乱公共秩序行为。", "options": [{"letter": "A", "text": "甲扬言要到某工厂放火"}, {"letter": "B", "text": "乙扬言要到某大桥跳桥自杀"}, {"letter": "C", "text": "丙扬言要到某大厦实施爆炸"}, {"letter": "D", "text": "丁扬言要到某单位的饮用水塔投放毒药"}], "answer": "B", "explanation": "根据《治安管理处罚法》第二十五条，虚构事实扰乱公共秩序的行为包括虚构险情（如爆炸、放火、投放危险物质等）。A扬言放火、C扬言爆炸、D扬言投放毒药均属于虚构险情扰乱公共秩序。B扬言跳桥自杀属于表达个人极端想法，不属于虚构险情类扰乱公共秩序行为，B正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 160}, {"num": 162, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）下列治安调查研究中不符合要求的是（）。", "options": [{"letter": "A", "text": "派出所民警到居民刘某家走访，征求其对社区治安状况的意见和改进建议"}, {"letter": "B", "text": "市局民警与市内某学校保卫工作人员交谈，并了解该学校发生警情的特点"}, {"letter": "C", "text": "市局民警暗访某城区洗浴城，向服务人员了解其服务情况"}, {"letter": "D", "text": "派出所民警到居民金某家走访，调查其离婚情况"}], "answer": "D", "explanation": "治安调查研究应围绕社会治安状况展开。A走访居民征求治安意见、B了解学校警情特点、C暗访洗浴城了解治安情况均属正常治安调研。D调查居民离婚情况属于个人隐私，与治安调研无关，不符合工作要求，D正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 161}, {"num": 163, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）违反治安管理行为的追究时效的起算时间为 （）", "options": [{"letter": "A", "text": "行为人实施违反治安管理行为的当日"}, {"letter": "B", "text": "行为人实施违反治安管理行为的次日"}, {"letter": "C", "text": "行为人开始实施违反治安管理行为的当日"}, {"letter": "D", "text": "行为人开始实施违反治安管理行为的次日"}], "answer": "A", "explanation": "根据新修订《治安管理处罚法》规定，违反治安管理行为的追究时效从行为人实施违反治安管理行为的当日开始计算，A正确。行为有连续或者继续状态的，从行为终了之日起计算。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 162}, {"num": 164, "batch": "专业基础知识", "type": "single", "stem": "建设路派出所接到群众报警称，有人被狗咬伤，民警迅速出警。到达现场后，发现有只狗正在撕咬一名中年女子，该女子腿部已经被咬伤，狗的主人在一旁束手无策，数名观众围观，此时，民警拟主要采取的措施有：①拨打120；②用抱钳、套绳等工具控制犬只；③查明犬只咬人原因；④疏散现场人员。下列现场处置流程合理的是（）。", "options": [{"letter": "A", "text": "④②①③"}, {"letter": "B", "text": "③④①②"}, {"letter": "C", "text": "②③④①"}, {"letter": "D", "text": "①③②④"}], "answer": "A", "explanation": "处置犬只伤人事件应遵循先救人、再控制危险源、后查明原因的逻辑。首先疏散现场人员保障安全（④），然后控制犬只防止继续伤害（②），接着拨打120救治伤者（①），最后查明咬人原因（③），A正确。这一流程体现了先急后缓、先人后事的处置原则。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 163}, {"num": 165, "batch": "专业基础知识", "type": "single", "stem": "2023年3月1日10时许，花园县公安局城关派出所两名民警在巡逻时发现某人形迹可疑，经当场盘问检查，发现该人携带的物品可能是赃物。为查清物品来源，10时30分民警将该人带至派出所继续盘问。根据法律规定，民警在履行相关审批程序后，必须完成继续盘问的时间是（）。", "options": [{"letter": "A", "text": "3月1日18时30分"}, {"letter": "B", "text": "3月1日22时30分"}, {"letter": "C", "text": "3月2日10时30分"}, {"letter": "D", "text": "3月3日10时30分"}], "answer": "C", "explanation": "根据《人民警察法》第九条，继续盘问的时限一般为十二小时；对于在十二小时以内难以证实或排除违法犯罪嫌疑的，可以延长至二十四小时。本案10时30分带至派出所继续盘问，经审批后最长24小时，即次日10时30分前必须完成，C正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 164}, {"num": 166, "batch": "专业基础知识", "type": "single", "stem": "3. 单选题 某日夜间，派出所民警老张和同事在街头警务站执勤，发现远处有一衣着破烂男子，推着一辆豪华品牌摩托车，且该男子未佩戴头盔，老张认为该男子有违法嫌疑，决定对该男子进行盘查，老张盘查的正确顺序是（）。 ①查验身份证件真伪 ②查验随身物品和车辆 ③告知警察身份，要求配合工作 ④进行人身检查 ⑤人证对照检查 ⑥排除嫌疑放行或者依法进行处置", "options": [{"letter": "A", "text": "⑤①④②③⑥"}, {"letter": "B", "text": "⑤①③④②⑥"}, {"letter": "C", "text": "③①⑤④②⑥"}, {"letter": "D", "text": "③①⑤②④⑥"}], "answer": "C", "explanation": "盘查的正确顺序为：首先告知警察身份要求配合（③），然后查验身份证件（①），再进行人证对照检查（⑤），接着进行人身检查（④），查验随身物品和车辆（②），最后排除嫌疑放行或依法处置（⑥），C正确。这一流程确保了执法规范性和安全性。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 165}, {"num": 167, "batch": "专业基础知识", "type": "single", "stem": "某商场发生因排队而两家人互殴的案件，其中一名行为人受伤倒下。公安派出所民警下列处置行为错误的是（）。", "options": [{"letter": "A", "text": "对互殴行为立即采取必要措施予以制止"}, {"letter": "B", "text": "制服行为人后对其人身及携带物品进行安全检查"}, {"letter": "C", "text": "立即拨打急救电话对受伤者实施救治"}, {"letter": "D", "text": "让医疗急救部门全权负责违法嫌疑人救治与看护工作"}], "answer": "D", "explanation": "公安机关民警在处置互殴案件时，对受伤的行为人仍负有救治和看护责任，不能完全交由医疗急救部门全权负责，D错误符合题意。A、B、C均为正确的处置措施：制止互殴、安全检查、救治伤者都是法定职责。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 166}, {"num": 168, "batch": "专业基础知识", "type": "single", "stem": "公安机关110报警服务台受理群众的报警、求助和投诉。下列情形中属于受理报警类警情的是（）。", "options": [{"letter": "A", "text": "家中老人早上外出锻炼时一直到晚上都没回家，家人打110报警电话请求帮忙查找"}, {"letter": "B", "text": "山区内连夜降雨发生泥石流，掩埋了房屋和村民"}, {"letter": "C", "text": "有人站在黄浦江的岸堤上，并向周围群众扬言要跳江自杀"}, {"letter": "D", "text": "甲驾驶车辆不慎撞向路边，导致车辆损坏，甲的腿部也被卡在车里"}], "answer": "B", "explanation": "110报警服务台受理报警类警情主要包括刑事案件、治安案件、自然灾害和公共安全事件等。B泥石流属于自然灾害类报警警情，正确。A属于求助类警情（查找走失人员），C属于求助类警情（轻生救助），D属于求助类警情（交通事故救援）。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 167}, {"num": 169, "batch": "专业基础知识", "type": "single", "stem": "对可疑物品进行检查是公安机关人民警察盘查工作的重要内容。某日，两名民警在夜间巡逻中，发现一男子携带黑色手提包，低头疾行，撞见民警后又慌忙躲闪，引起民警怀疑。民警的下列做法错误的是（）。", "options": [{"letter": "A", "text": "责令该男子将物品放在适当位置，不得让其自行翻拿"}, {"letter": "B", "text": "一名民警负责检查物品，必要时其他民警同步辅助检查"}, {"letter": "C", "text": "发现爆炸性危险物质时，立即组织疏散现场人员，设置隔离带，封锁现场"}, {"letter": "D", "text": "检查中避免损坏或者遗失财物"}], "answer": "B", "explanation": "检查可疑物品时，应由一名民警负责检查，其他民警负责警戒和辅助，而非同步辅助检查，B做法错误符合题意。A正确，应责令嫌疑人将物品放在适当位置，不得让其自行翻拿以防危险。C正确，发现爆炸性物质应立即疏散封锁。D正确，检查中应避免损坏或遗失财物。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 168}, {"num": 170, "batch": "专业基础知识", "type": "single", "stem": "2021年12月17日20时许，A派出所接110指令称：报警人在某饭店被一醉酒男子用酒瓶砸伤头部，对方还在现场。处警民警小王、小李到场后，开展了如下工作：①向指挥中心进行汇报；②对报警人进行救治；③控制并约束醉酒男子；④收集与案件有关的证据。下列选项中，排序正确的是（）。", "options": [{"letter": "A", "text": "①②③④"}, {"letter": "B", "text": "①③②④"}, {"letter": "C", "text": "②①③④"}, {"letter": "D", "text": "②①④③"}], "answer": "B", "explanation": "处置醉酒伤人案件，民警到场后应首先向指挥中心汇报现场情况（①），然后救治受伤的报警人（②），接着控制约束醉酒男子防止继续危害（③），最后收集证据（④），B正确。这一顺序体现了先报告、先救人、再控制、后取证的规范流程。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 169}, {"num": 171, "batch": "专业基础知识", "type": "single", "stem": "某派出所辖区位于人口密集的老城区，临近年终岁尾盗窃案案发率居高不下，为维持良好社会秩序，降低辖区日益增长的盗窃案案发数量，震慑犯罪分子，派出所商定了如下巡逻方式，其中说法错误的是（）。", "options": [{"letter": "A", "text": "为降低盗窃案案发率应采取便衣巡逻的方式"}, {"letter": "B", "text": "着装巡逻可以起到震慑犯罪分子的效果"}, {"letter": "C", "text": "为达到巡逻效果应采取网格化巡逻的方式"}, {"letter": "D", "text": "为达到巡逻效果，采取步行巡逻的方式更恰当"}], "answer": "C", "explanation": "网格化巡逻是一种巡逻组织方式，但并非所有情况都适用，C说法过于绝对，错误符合题意。A正确，便衣巡逻有利于发现和抓获现行犯罪。B正确，着装巡逻具有震慑效果。D正确，步行巡逻适合人口密集的老城区，便于深入细致地巡查。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 170}, {"num": 172, "batch": "专业基础知识", "type": "single", "stem": "宜林县公安局把案件类警情高发区域确定为治安重点区域，在治安重点区域增加街面巡逻警组密度和巡逻频次，提高街面见警率，能够震慑违法犯罪，增强群众安全感。下列选项中，属于应重点巡逻的区域是（）。", "options": [{"letter": "A", "text": "涉毒案件频发区域、抢劫案件频发区域、盗窃案件频发区域"}, {"letter": "B", "text": "聚众赌博频发区域、传销刷单频发区域、盗窃案件频发区域"}, {"letter": "C", "text": "盗窃案件频发区域、电信网络诈骗频发区域、聚众赌博频发区域"}, {"letter": "D", "text": "电信网络诈骗频发区域、聚众赌博频发区域、传销刷单频发区域"}], "answer": "A", "explanation": "治安重点区域巡逻应针对街面类、接触类案件高发区域。涉毒案件频发区域、抢劫案件频发区域、盗窃案件频发区域均属于街面治安重点区域，需要增加巡逻密度，A正确。电信网络诈骗属于非接触类犯罪，不属于街面巡逻重点区域。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 171}, {"num": 173, "batch": "专业基础知识", "type": "single", "stem": "民警小刘正在对可疑车辆进行盘查，将车辆截停后，小刘的首要措施应当是（）。", "options": [{"letter": "A", "text": "查验车牌及车辆信息"}, {"letter": "B", "text": "责令驾驶员熄火"}, {"letter": "C", "text": "观察车辆外观和锁具"}, {"letter": "D", "text": "检查驾驶员和车辆证件"}], "answer": "B", "explanation": "盘查车辆时，截停车辆后首要措施是责令驾驶员熄火，确保车辆处于安全状态，防止驾驶员驾车逃逸或冲撞民警，B正确。在确保安全后，再依次进行查验证件、检查车辆等操作。安全第一是盘查车辆的基本原则。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 172}, {"num": 174, "batch": "专业基础知识", "type": "single", "stem": "交警小王在十字路口开展交通违法行为整治时，发现一名女子驾驶无牌电动自行车逆行，遂截停该女子。听到要被处罚，该女子抱住小王的腿哭闹，且不听劝阻，引起现场群众聚集围观。此时，小王处理方式最恰当的是（）。", "options": [{"letter": "A", "text": "口头制止"}, {"letter": "B", "text": "徒手制止"}, {"letter": "C", "text": "警械制止"}, {"letter": "D", "text": "武器制止"}], "answer": "B", "explanation": "该女子抱住民警腿哭闹不听劝阻，已构成阻碍执行职务的行为，口头制止无效后应采用徒手制止将其分离，B最恰当。此时尚未达到需要使用警械的程度，使用警械或武器不符合比例原则。徒手制止既能有效排除阻碍，又能避免过度使用武力。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 173}, {"num": 175, "batch": "专业基础知识", "type": "single", "stem": "民警小李、小王在午休在餐馆就餐时，发现迎面走来的王某神色慌张，看见警察眼神躲闪。于是在出示人民警察证后对王某进行当场盘查，但是无法排除王某嫌疑。下列可以作为对王某适用继续盘问理由的是（）。", "options": [{"letter": "A", "text": "此时张某匆匆赶来称王某抢走了其钱包"}, {"letter": "B", "text": "周围有群众举报称王某受贿"}, {"letter": "C", "text": "在盘问的过程中王某神色慌张"}, {"letter": "D", "text": "郑某告诉民警王某欠其三万元人民币，已经逾期10天尚未归还"}], "answer": "A", "explanation": "根据《人民警察法》第九条，继续盘问适用于被盘问人有违法犯罪嫌疑且当场盘问不能排除嫌疑的情形。A项张某赶来称王某抢走钱包，属于有违法犯罪嫌疑的具体线索，可以作为继续盘问的理由，A正确。B受贿不属于公安机关管辖。C神色慌张不构成继续盘问的充分理由。D属于民事债务纠纷。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 174}, {"num": 176, "batch": "专业基础知识", "type": "single", "stem": "初到派出所参加工作的民警小王对人身检查的相关规定较为陌生，遂向工作多年的小张请教如下几个问题，其中小王的理解正确的是（）。", "options": [{"letter": "A", "text": "在警力不足的情况下，若情况紧急是可以单警对嫌疑人实施人身检查"}, {"letter": "B", "text": "检查女性嫌疑人只能由女性工作人员进行"}, {"letter": "C", "text": "检查时发现的违禁品可以当场扣押"}, {"letter": "D", "text": "对于疑似携带凶器的嫌疑人，应先检查确定有无凶器后才能进行警械约束"}], "answer": "C", "explanation": "人身检查中发现的违禁品可以当场扣押，C正确。A错误，人身检查至少需要两名民警。B错误，检查妇女身体应由女工作人员进行，不限于女性工作人员。D错误，对疑似携带凶器的嫌疑人应先约束再检查，而非先检查后约束。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 175}, {"num": 177, "batch": "专业基础知识", "type": "single", "stem": "某日，东昌县公安局巡逻大队民警小张、小李在长途客运站附近巡逻时，发现一男子随身携带一黑色包裹，行迹较为可疑，遂上前盘问。经盘问，该男子自报姓名无法在警用PDA内进行确认核实。故两人决定对男子人身和携带的包裹进行检查，下列做法妥当的是（）。", "options": [{"letter": "A", "text": "先用手铐将男子予以控制后再开展检查"}, {"letter": "B", "text": "实施人身检查时要求男子伸开双臂高举过头并面向民警站立"}, {"letter": "C", "text": "要求男子将包裹放在指定位置"}, {"letter": "D", "text": "责令男子将包裹中物品倒出"}], "answer": "C", "explanation": "对可疑人员携带的物品进行检查时，应要求被检查人将包裹放在指定位置，由民警进行检查，C妥当。A不当，不能未经判断就直接使用手铐控制。B不当，人身检查的具体姿势要求不够规范。D不当，不应责令被检查人自行翻动包裹，以防危险。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 176}, {"num": 178, "batch": "专业基础知识", "type": "single", "stem": "某日中午，小秦接到报警称，洪江农家乐与黑米农家乐员工因争抢客源产生争执，双方情绪激动，高声对骂，引起部分游客围观。小秦随即携警务辅助人员赶至现场，了解情况后拟采取措施化解矛盾。下列措施不恰当的是（）。", "options": [{"letter": "A", "text": "口头制止对骂后向农家乐负责人了解情况"}, {"letter": "B", "text": "本村巡防队员一起疏导围观游客"}, {"letter": "C", "text": "将参与对骂的服务员强行带离现场"}, {"letter": "D", "text": "联系村委会工作人员前来参与调解"}], "answer": "C", "explanation": "对于因争抢客源产生的争执对骂，属于民间纠纷，应以调解化解为主。将参与对骂的服务员强行带离现场属于过度处置，不符合比例原则，C不恰当。A口头制止后了解情况、B疏导围观游客、D联系村委会参与调解均为恰当措施。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 177}, {"num": 179, "batch": "专业基础知识", "type": "single", "stem": "下列不属于外部监督的是（）。", "options": [{"letter": "A", "text": "甲市发生一桩影响力较大的校园欺凌事件，警方介入调查，各大媒体对此进行广泛报道"}, {"letter": "B", "text": "群众投诉民警乙收受贿赂5000元"}, {"letter": "C", "text": "督察机构对丙市民警文明执勤的情况进行现场督察"}, {"letter": "D", "text": "人民检察院对公安机关申请逮捕的案件作出批准逮捕的决定"}], "answer": "C", "explanation": "督察机构对民警进行现场督察属于公安机关内部监督，不属于外部监督，C正确。A媒体监督属于舆论监督（外部），B群众投诉属于社会监督（外部），D检察院监督属于检察监督（外部），均属于外部监督形式。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 178}, {"num": 180, "batch": "专业基础知识", "type": "single", "stem": "公民张某认为甲市乙县公安局治安大队民警小李对自己做出的处罚决定违反法律规定，遂向督察大队投诉，督察人员调查后认为该项决定下达错误，县督察大队决定对该项决定进行变更，现有权对这一变更决定批准的人员是（）。", "options": [{"letter": "A", "text": "甲市公安局局长"}, {"letter": "B", "text": "乙县公安局局长"}, {"letter": "C", "text": "乙县公安局督察长"}, {"letter": "D", "text": "乙县治安大队大队长"}], "answer": "B", "explanation": "根据《公安机关督察条例》规定，县级公安机关督察机构对本级公安机关所属单位和下级公安机关及其人民警察依法履职情况进行监督。督察大队认为需要变更决定的，应报本级公安机关主要负责人（即县公安局局长）批准后执行，B正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 179}, {"num": 181, "batch": "专业基础知识", "type": "single", "stem": "公安局民警甲在日常巡逻时，发现乙和丙在街头玩牌赌博，便上前没收扑克牌，乙不肯，甲便拿出警棍，对乙多次猛击使其受伤。乙花去医疗费2000元，后提出赔偿请求。下列说法中正确的是（）。", "options": [{"letter": "A", "text": "甲承担赔偿责任，因为甲的行为属于与职权无关的个人行为"}, {"letter": "B", "text": "甲承担赔偿责任，因为甲的行为属于故意或重大过失行为"}, {"letter": "C", "text": "公安局承担赔偿责任，可以向甲追偿赔偿费用"}, {"letter": "D", "text": "公安局承担赔偿责任，甲不承担任何责任"}], "answer": "C", "explanation": "根据《国家赔偿法》第三条，行政机关及其工作人员在行使行政职权时侵犯人身权的，受害人有取得赔偿的权利。民警甲在巡逻中（执行职务期间）违法使用警械致人受伤，应由公安局承担赔偿责任。公安局赔偿后，可以向有故意或重大过失的工作人员追偿，C正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 180}, {"num": 182, "batch": "专业基础知识", "type": "single", "stem": "社会治安综合治理要坚持打防结合，预防为主的原则，加强基层工作，增强全社会的（）能力。", "options": [{"letter": "A", "text": "严打和治理"}, {"letter": "B", "text": "预防和控制犯罪"}, {"letter": "C", "text": "专政和民主"}, {"letter": "D", "text": "管理和监督"}], "answer": "B", "explanation": "社会治安综合治理坚持打防结合、预防为主的原则，加强基层工作，增强全社会预防和控制犯罪的能力，B正确。这是社会治安综合治理的基本方针，强调从源头预防犯罪，同时提高对犯罪的控制能力。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 181}, {"num": 183, "batch": "专业基础知识", "type": "single", "stem": "A市公安局民警小赵在下班期间与同学聚餐，醉酒后因与他人发生口角双方互殴，处警民警到达核实完小赵身份后将该情况通报至督察大队。以下说法正确的是（）。", "options": [{"letter": "A", "text": "督察大队应先对小赵采取停止执行职务或禁闭措施"}, {"letter": "B", "text": "采取禁闭措施时应由督察大队上报督察支队批准后作出决定"}, {"letter": "C", "text": "执行禁闭需要经过A市公安局局长批准"}, {"letter": "D", "text": "最长可对小赵采取15日禁闭"}], "answer": "C", "explanation": "根据《公安机关督察条例》第十二条，对违反纪律的人民警察需要采取禁闭措施的，由县级以上公安机关督察机构决定，报本级公安机关督察长（即公安局长）批准后执行，C正确。禁闭期限为1至7天，D错误。A错误，并非必须先采取停止执行职务措施。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 182}, {"num": 184, "batch": "专业基础知识", "type": "single", "stem": "某市公安局督察机构开展督察活动期间，发现了下列情况，其中不属于现场督察范围的是（）。", "options": [{"letter": "A", "text": "公安分局值班保安丁某下班时穿着制式警服"}, {"letter": "B", "text": "巡逻民警张某对群众的报警求助处理不当"}, {"letter": "C", "text": "派出所民警方某对前来报案的群众不予理睬"}, {"letter": "D", "text": "刑侦支队民警陈某外出吃饭时携带枪支"}], "answer": "A", "explanation": "公安分局值班保安不属于人民警察，其穿着制式警服下班不属于现场督察范围，A正确。现场督察的对象是公安机关及其人民警察。B巡逻民警处理警情不当、C派出所民警不理会报案群众、D刑侦民警携带枪支外出吃饭，均属于现场督察范围。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 183}, {"num": 185, "batch": "专业基础知识", "type": "single", "stem": "督察制度是为了完善公安机关自我约束机制而依法建立的一种公安内部监督制度。根据《公安机关督察条例》的规定，督察机构对公安机关及其人民警察依法履行职责、行使职权和遵守纪律的事项，进行现场督察。 下列事项中不符合督察机构现场督察的是（）。", "options": [{"letter": "A", "text": "刑侦大队执行群众上门报案“三个当场”制度的情况"}, {"letter": "B", "text": "治安大队开展音乐节安保活动现场踏勘的情况"}, {"letter": "C", "text": "巡特警大队开展红蓝对抗演练使用武器的情况"}, {"letter": "D", "text": "派出所民警清查辖区旅馆行动的情况"}], "answer": "C", "explanation": "根据《公安机关督察条例》，现场督察事项包括重要警务部署的实施情况、治安案件办理情况、警容风纪等。红蓝对抗演练使用武器属于内部训练活动，不属于现场督察范围，C不符合题意。A执行报案制度、B安保踏勘、D清查行动均属于现场督察范围。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 184}, {"num": 186, "batch": "专业基础知识", "type": "single", "stem": "（）地方各级人民政府公安机关均设立督察机构。", "options": [{"letter": "A", "text": "省级以上"}, {"letter": "B", "text": "市级以上"}, {"letter": "C", "text": "乡级以上"}, {"letter": "D", "text": "县级以上"}], "answer": "D", "explanation": "根据《公安机关督察条例》第二条，县级以上地方各级人民政府公安机关设立督察机构，D正确。督察机构负责对本级公安机关所属单位和下级公安机关及其人民警察依法履行职责、行使职权和遵守纪律的情况进行监督。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 185}, {"num": 187, "batch": "专业基础知识", "type": "single", "stem": "公安行政赔偿是指公安机关及其人民警察在行政管理过程中，因违法或不当行使其职权侵犯公民、法人和其他组织的合法权益造成其人身、财产等权益损害时所进行的一种赔偿。下列情形中属于公安行政赔偿的是（）。", "options": [{"letter": "A", "text": "民警小王对邻居心生不满，醉酒后将邻居打成轻微伤"}, {"letter": "B", "text": "民警小周将违法行为人与案件无关的私人贵重物品扣押并丢失"}, {"letter": "C", "text": "民警小李查获某嫖娼现场时，嫖娼人员跳窗逃跑导致腿骨折"}, {"letter": "D", "text": "某公安机关对小张采取逮捕措施后，又决定撤销案件"}], "answer": "B", "explanation": "公安行政赔偿是指公安机关及其人民警察在行政管理过程中违法行使职权造成损害时的赔偿。B项民警违法扣押与案件无关的私人财物并丢失，属于违法行使行政管理职权造成的财产损害，属于行政赔偿范围，B正确。A属于个人行为，C属于当事人自身原因造成的损害，D属于刑事赔偿范围。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 186}, {"num": 188, "batch": "专业基础知识", "type": "single", "stem": "行政复议案件中的被申请人是（）。", "options": [{"letter": "A", "text": "司法机关"}, {"letter": "B", "text": "行政机关"}, {"letter": "C", "text": "派出机构"}, {"letter": "D", "text": "企业"}], "answer": "B", "explanation": "根据《行政复议法》规定，行政复议中的被申请人是作出具体行政行为的行政机关，B正确。行政复议是行政相对人对行政机关的具体行政行为不服而申请的救济程序，被申请人必须是行使行政职权的行政机关。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 187}, {"num": 189, "batch": "专业基础知识", "type": "single", "stem": "督察机构认为公安机关人民警察违反纪律需要采取停止执行职务、禁闭措施的，由督察机构作出决定，报（）批准后执行。", "options": [{"letter": "A", "text": "上级公安机关督察长"}, {"letter": "B", "text": "本级公安机关督察长"}, {"letter": "C", "text": "上级公安局局长"}, {"letter": "D", "text": "本级公安局局长"}], "answer": "B", "explanation": "根据《公安机关督察条例》第十一条，督察机构认为公安机关人民警察违反纪律需要采取停止执行职务、禁闭措施的，由督察机构作出决定，报本级公安机关督察长批准后执行，B正确。本级公安机关督察长即为本级公安机关的主要负责人。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 188}, {"num": 190, "batch": "专业基础知识", "type": "single", "stem": "甲县公安局以李某涉嫌盗窃犯罪为由将其刑事拘留，并经县人民检察院批准逮捕，县人民法院判处李某有期徒刑5年。李某上诉，市中级人民法院改判李某无罪。李某向赔偿义务机关申请国家赔偿。下列说法正确的是（）。", "options": [{"letter": "A", "text": "即使对李某的拘留符合《刑事诉讼法》的规定，县公安局也应予以赔偿"}, {"letter": "B", "text": "李某申请国家赔偿前应先申请确认刑事拘留和逮捕行为违法"}, {"letter": "C", "text": "李某请求国家赔偿的时效自知道或应当知道国家机关及其工作人员行使职权的行为侵犯其人身权之日起计算"}, {"letter": "D", "text": "赔偿义务机关不能与李某就赔偿方式进行协商"}], "answer": "C", "explanation": "根据《国家赔偿法》第十七条，赔偿请求人请求国家赔偿的时效为两年，自其知道或者应当知道国家机关及其工作人员行使职权时的行为侵犯其人身权、财产权之日起计算，C正确。A错误，合法拘留不予赔偿。B错误，2010年修正后无需先确认违法。D错误，赔偿义务机关可以与请求人就赔偿方式进行协商。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 189}, {"num": 191, "batch": "专业基础知识", "type": "single", "stem": "在侦查阶段，某市人民检察院发现该市公安局刑侦支队有违法取证的情况，侵害了当事人的合法权利，遂发出了纠正违法通知书。上述监督属于（）。", "options": [{"letter": "A", "text": "内部监督、间接监督"}, {"letter": "B", "text": "外部监督、直接监督"}, {"letter": "C", "text": "间接监督、事中监督"}, {"letter": "D", "text": "直接监督、事前监督"}], "answer": "B", "explanation": "人民检察院对公安机关的监督属于外部监督（检察院独立于公安机关）和直接监督（检察院直接向公安机关发出纠正违法通知书），B正确。外部监督是指来自公安机关外部的监督主体的监督，直接监督是指监督主体可以直接对公安机关的执法行为产生法律效力的监督。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 190}, {"num": 192, "batch": "专业基础知识", "type": "single", "stem": "各级人大、政协依法对公安机关的监督是公安执法监督的重要组成部分，关于两种监督方式的相同点，下列说法正确的是（）。", "options": [{"letter": "A", "text": "二者的监督都是外部监督"}, {"letter": "B", "text": "二者的监督都具有法律强制性"}, {"letter": "C", "text": "二者都有改变公安机关决定的权力"}, {"letter": "D", "text": "二者都有对公安工作经费的预算进行审查的权力"}], "answer": "A", "explanation": "各级人大和政协对公安机关的监督都属于外部监督，A正确。人大的监督具有一定的法律强制性，但政协的监督不具有法律强制性，B错误。二者都没有直接改变公安机关决定的权力，C错误。只有人大有预算审查权，政协没有，D错误。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 191}, {"num": 193, "batch": "专业基础知识", "type": "single", "stem": "社会监督是外部监督的一种重要形式，也是公安机关完善执法监督机制的必然要求，下列属于社会监督途径的是（）。", "options": [{"letter": "A", "text": "检察院对公安机关的立撤案行为进行执法监督"}, {"letter": "B", "text": "督察部门对公安机关的执法活动进行暗访调查"}, {"letter": "C", "text": "市人大常委会对公安机关的警务活动进行监督"}, {"letter": "D", "text": "政协委员周某对市局提出执法建议"}], "answer": "D", "explanation": "社会监督是指来自社会组织和公民个人的监督。政协委员提出执法建议属于社会监督的途径之一，D正确。A属于检察监督（外部监督中的国家机关监督），B属于内部监督（督察部门），C属于权力机关监督（人大监督），均不属于社会监督范畴。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 192}, {"num": 194, "batch": "专业基础知识", "type": "single", "stem": "外部监督中的一种重要的监督形式就是社会监督，公安机关及其人民警察接受社会监督的途径和形式不包括（）。", "options": [{"letter": "A", "text": "人民政协通过批评、建议等方式的监督"}, {"letter": "B", "text": "各级人民代表大会通过检查、调查、走访等方式的监督"}, {"letter": "C", "text": "企事业单位等社会组织通过控告、检举等方式的监督"}, {"letter": "D", "text": "新闻机构通过舆论表达意见和看法的监督"}], "answer": "B", "explanation": "根据相关法律规定，社会监督的途径包括人民政协的监督、社会组织的监督、新闻舆论的监督和公民个人的监督。各级人民代表大会的监督属于国家权力机关的监督，是独立的监督类型，不属于社会监督范畴，B正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 193}, {"num": 195, "batch": "专业基础知识", "type": "single", "stem": "下列不属于人民检察院对公安机关实施法律监督的主要形式及内容的是（）。", "options": [{"letter": "A", "text": "对公安机关逮捕嫌疑人的提请进行批准并下发《批准逮捕书》"}, {"letter": "B", "text": "公民和社会组织对人民警察的违法违纪行为进行的控告、举报"}, {"letter": "C", "text": "对公安机关移送起诉的案件审查决定是否起诉"}, {"letter": "D", "text": "对人民警察警容不整，警便混穿，着装不规范等行为予以警告"}], "answer": "D", "explanation": "人民检察院对公安机关的法律监督主要包括立案监督、审查逮捕、审查起诉、侦查活动监督等。D项对民警警容不整予以警告属于公安机关内部督察的事项，不属于检察院法律监督的内容，D正确。A属于审查逮捕监督，B不属于检察监督（属于社会监督），C属于审查起诉监督。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 194}, {"num": 196, "batch": "专业基础知识", "type": "single", "stem": "以下不属于法制部门执法监督方式的是（）。", "options": [{"letter": "A", "text": "对疑难、有分歧、易出问题和各级公安机关决定需要专门监督的案件，进行案件审核"}, {"letter": "B", "text": "组织执法检查、评议"}, {"letter": "C", "text": "组织专项、专案调查"}, {"letter": "D", "text": "参与行政诉讼"}], "answer": "D", "explanation": "法制部门执法监督的方式包括案件审核、组织执法检查和评议、组织专项专案调查等。参与行政诉讼不属于法制部门执法监督的方式，而是公安机关应对司法诉讼的活动，D正确。法制部门的监督侧重于对公安机关内部执法活动的审核和指导。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 195}, {"num": 197, "batch": "专业基础知识", "type": "single", "stem": "交警大队民警曾某在执勤期间对商业区违规停车的二十余辆机动车开出罚款单，驾驶人薛某认为交警曾某违规罚款，薛某不服处罚决定申请了行政复议后，又将此事投诉至市局督察支队。市局督察支队下列做法符合规定的是（）。", "options": [{"letter": "A", "text": "及时出警，撤回违章罚款决定"}, {"letter": "B", "text": "移交上一级公安机关进行直接督察"}, {"letter": "C", "text": "整理投诉材料，移交给复议机关"}, {"letter": "D", "text": "将督察进程每日反馈给薛某"}], "answer": "C", "explanation": "驾驶人薛某已申请行政复议，督察部门在行政复议程序进行期间，应将投诉材料移交复议机关处理，避免重复处理和程序冲突，C正确。督察部门不能直接撤回处罚决定，也不需要在复议期间每日反馈督察进程。移交上一级公安机关进行直接督察也不符合程序规定。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 196}, {"num": 198, "batch": "专业基础知识", "type": "single", "stem": "下列公安机关办理刑事案件时的行为，不属于国家赔偿范围的是（）。", "options": [{"letter": "A", "text": "违法拘留"}, {"letter": "B", "text": "违法取保候审"}, {"letter": "C", "text": "违法查封"}, {"letter": "D", "text": "违法使用警械致人死亡"}], "answer": "B", "explanation": "根据《国家赔偿法》及相关规定，国家赔偿范围包括违法拘留、违法查封扣押冻结、违法使用警械等。违法取保候审不属于国家赔偿范围，因为取保候审并未实际限制人身自由到需要赔偿的程度，B正确。违法拘留、违法查封、违法使用警械致人死亡均属于赔偿范围。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 197}, {"num": 199, "batch": "专业基础知识", "type": "single", "stem": "公安机关的督察监督是指公安机关督察机构对公安机关及其人民警察依法履行职责、行使职权的活动和遵守纪律的情况进行监督检察的制度。下列关于督察监督，说法正确的是（）。", "options": [{"letter": "A", "text": "督察人员必须具备大学本科以上学历以及3年以上公安工作经历"}, {"letter": "B", "text": "县级以上人民政府的公安机关设立督察机构"}, {"letter": "C", "text": "现场督查时，对违法违纪情节严重、影响恶劣的，应当带离现场"}, {"letter": "D", "text": "督察机构对下级公安机关作出的错误决定应当决定变更并执行"}], "answer": "B", "explanation": "根据《公安机关督察条例》第二条，县级以上人民政府公安机关设立督察机构，B正确。A错误，督察人员须具备大专以上学历和两年以上公安工作经历。C错误，对违法违纪情节严重、影响恶劣的，可以将其带离现场，而非应当。D错误，督察机构可以作出决定但需报批准后执行，不能直接变更并执行。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 198}, {"num": 200, "batch": "专业基础知识", "type": "single", "stem": "督察部门负责对人民警察依法履行职责、行使职权和遵守纪律的情况进行监督，以下在开展现场督察的过程中，处置措施得当的是（）。", "options": [{"letter": "A", "text": "发现在某执勤点开展勤务的民警违反警容风纪规定时，可以将其带离现场"}, {"letter": "B", "text": "发现某派出所违反规定使用警用车辆时，可以当场将警车扣留"}, {"letter": "C", "text": "某民警拒绝督察人员进行现场督察时，可以立即采取停止职务措施"}, {"letter": "D", "text": "发现某民警违反武器使用规定时，可以立即对其采取禁闭措施"}], "answer": "B", "explanation": "根据《公安机关督察条例》规定，督察机构在现场督察中发现违反规定使用警用车辆、警用标志等，可以当场予以扣留，B正确。A错误，违反警容风纪规定的，可以当场予以纠正，而非带离现场。C错误，拒绝督察不能立即停止职务。D错误，违反武器使用规定可以扣留武器，禁闭需报批。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 199}, {"num": 201, "batch": "专业基础知识", "type": "single", "stem": "下列监督方式属于直接监督、内部监督的是（）。", "options": [{"letter": "A", "text": "人民政协对公安机关采取的措施和做出的决定提出批评建议"}, {"letter": "B", "text": "人民检察院受理公民对人民警察的违法违纪行为的控告检举"}, {"letter": "C", "text": "公安机关特邀监督员对公安机关的行为进行监督"}, {"letter": "D", "text": "督察警察对人民警察的执法行为进行监督"}], "answer": "D", "explanation": "督察警察是公安机关内部设立的专门监督机构，对人民警察的执法行为进行监督属于直接监督、内部监督。人民政协的监督属于民主监督，人民检察院的监督属于司法监督，特邀监督员的监督属于社会监督，三者均为外部监督。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 200}, {"num": 202, "batch": "专业基础知识", "type": "single", "stem": "甲市乙区公安分局民警冯某在处警过程中，违反规定使用警械，下列有关督察工作的说法错误的是（）。", "options": [{"letter": "A", "text": "乙区公安分局督察大队民警可对冯某采取扣留其警械的处理"}, {"letter": "B", "text": "乙区公安分局督察大队决定对冯某采取停止执行职务措施后应立即执行"}, {"letter": "C", "text": "乙区公安分局督察大队应当将查处情况上报甲市公安机关督察机构"}, {"letter": "D", "text": "乙区公安分局督察大队查处不力的，甲市公安机关督察机构可以直接进行督察"}], "answer": "B", "explanation": "根据《公安机关督察条例》，县级以上公安机关督察机构对违反规定使用警械的民警可以采取扣留警械等措施，但决定停止执行职务需经督察机构负责人批准后方可执行，而非'立即执行'。查处情况应上报上级督察机构，上级督察机构可直接督察查处不力的下级督察机构。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 201}, {"num": 203, "batch": "专业基础知识", "type": "single", "stem": "公安机关主动接受社会监督是新形势下公安执法工作的必然选择，是公安执法监督机制自我完善的内在要求。以下情况中不属于社会监督的是（）。", "options": [{"letter": "A", "text": "A市公安机关聘请的特邀监督员老李（某报社社长）对公安机关执法行为进行监督"}, {"letter": "B", "text": "B县政协对公安机关提出进一步改进执法行为的建议"}, {"letter": "C", "text": "C区检察院对公安机关不予立案进行执法监督"}, {"letter": "D", "text": "D市某报社记者对公安机关执法环节进行拍摄"}], "answer": "C", "explanation": "社会监督是指国家机关以外的社会组织和公民对公安机关的监督，包括政协监督、特邀监督员监督、媒体监督等。人民检察院是国家的法律监督机关，其对公安机关的监督属于国家司法监督，不属于社会监督范畴。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 202}, {"num": 204, "batch": "专业基础知识", "type": "single", "stem": "李×因涉嫌非法携带管制器具，被公安机关处以5日拘留并处500元罚款，处罚执行完毕后，李×认为公安机关的行政处罚行为违法，侵犯了他的合法权益，欲通过法定途径救济自己受损的权益。根据有关法律规定，下列选项符合法定救济程序的是（）。", "options": [{"letter": "A", "text": "需申请行政复议时一并提出行政赔偿"}, {"letter": "B", "text": "申请行政复议后不能再提出行政赔偿"}, {"letter": "C", "text": "提出行政赔偿后不能再申请行政复议"}, {"letter": "D", "text": "可以先申请行政复议再提出行政赔偿"}], "answer": "D", "explanation": "根据《国家赔偿法》规定，赔偿请求人要求赔偿可以先向赔偿义务机关提出，也可以在申请行政复议或者提起行政诉讼时一并提出。因此，李×可以先申请行政复议再提出行政赔偿，行政复议与行政赔偿并非互斥关系。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 203}, {"num": 205, "batch": "专业基础知识", "type": "single", "stem": "根据《立法法》的规定，关于国家机关的立法权限，下列说法正确的是（）。", "options": [{"letter": "A", "text": "全国人民代表大会和国务院行使国家立法权"}, {"letter": "B", "text": "国务院公安部有权制定行政法规"}, {"letter": "C", "text": "浙江省人民政府有权根据本地实际制定地方性法规"}, {"letter": "D", "text": "吉林延边朝鲜族自治州有权依据当地的经济情况制定单行条例"}], "answer": "D", "explanation": "根据《立法法》规定，民族自治地方（自治区、自治州、自治县）的人民代表大会有权制定自治条例和单行条例。延边朝鲜族自治州属于自治州，有权制定单行条例。国家立法权由全国人大及其常委会行使，国务院制定行政法规，省级政府制定的是地方政府规章而非地方性法规。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 204}, {"num": 206, "batch": "专业基础知识", "type": "single", "stem": "2021年11月16日至17日，中央全面依法治国工作会议在北京召开，习近平总书记在会议上对当前和今后一个时期推进全面依法治国要重点抓好的工作提出了11个方面的要求。关于全面依法治国，说法错误的是（）。", "options": [{"letter": "A", "text": "党的领导是推进全面依法治国的根本保证"}, {"letter": "B", "text": "全面依法治国最广泛、最深厚的基础是人民"}, {"letter": "C", "text": "坚持依宪治国、依宪执政"}, {"letter": "D", "text": "法制是国家治理体系和治理能力的重要依托"}], "answer": "D", "explanation": "全面依法治国工作会议指出，'法治'是国家治理体系和治理能力的重要依托，而非'法制'。'法治'强调依法治国、依法执政，'法制'则是指法律制度体系，二者含义不同。选项D将'法治'替换为'法制'，表述错误。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 205}, {"num": 207, "batch": "专业基础知识", "type": "single", "stem": "下列关于全面依法治国相关理念的表述，错误的是（）。", "options": [{"letter": "A", "text": "坚持党的领导是中国特色社会主义法治之魂，我国法治与西方资本主义国家法治最大的区别就在于是否坚持党的领导"}, {"letter": "B", "text": "中国特色社会主义法治道路的核心要义仅在于坚持中国共产党的领导"}, {"letter": "C", "text": "全面依法治国的总抓手是建设中国特色社会主义法治体系"}, {"letter": "D", "text": "公正司法是维护社会公平正义的最后一道防线"}], "answer": "B", "explanation": "中国特色社会主义法治道路的核心要义包括坚持中国共产党的领导、坚持中国特色社会主义制度、贯彻中国特色社会主义法治理论三个方面，并非'仅在于'坚持党的领导。选项B以偏概全，表述错误。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 206}, {"num": 208, "batch": "专业基础知识", "type": "single", "stem": "法律是由国家制定或认可的、并由国家强制力保证实施的、正式的、官方确定的行为规范。这表明法具（）。", "options": [{"letter": "A", "text": "规范性"}, {"letter": "B", "text": "国家性"}, {"letter": "C", "text": "概括性"}, {"letter": "D", "text": "效率性"}], "answer": "B", "explanation": "法律由国家制定或认可，并由国家强制力保证实施，这体现了法的国家性特征。国家性是指法律是国家意志的体现，具有国家权力的属性，区别于道德、宗教等其他社会规范。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 207}, {"num": 209, "batch": "专业基础知识", "type": "single", "stem": "法的效力范围，是理论问题也是实践问题。《最高人民法院、最高人民检察院关于办理破坏野生动物资源刑事案件适用法律若干问题的解释》（法释〔2022〕12号）第二十条规定：“本解释自2022年4月9日起施行。本解释公布施行后，《最高人民法院关于办理破坏野生动物资源刑事案件具体应用法律若干问题的解释》（法释〔2000〕37号）同时废止。”从法的效力范围来看，上述规定体现的是（）。", "options": [{"letter": "A", "text": "法的对象效力"}, {"letter": "B", "text": "法的对事效力"}, {"letter": "C", "text": "法的空间效力"}, {"letter": "D", "text": "法的时间效力"}], "answer": "D", "explanation": "该规定涉及司法解释何时施行、旧解释何时废止，属于法的时间效力范畴。法的时间效力是指法律规范在什么时间生效、什么时间终止效力以及对其生效前的事件和行为有无溯及力的问题。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 208}, {"num": 210, "batch": "专业基础知识", "type": "single", "stem": "党的二十大对“坚持全面依法治国，推进法治中国建设”进行了全面部署，下列说法不正确的是（）。", "options": [{"letter": "A", "text": "坚持依法治国首先要坚持依宪治国，坚持依法执政首先要坚持依宪执政"}, {"letter": "B", "text": "法治政府建设是全面依法治国的重点任务和主体工程"}, {"letter": "C", "text": "公正司法是维护社会公平正义的最后一道防线，全面准确落实司法责任制"}, {"letter": "D", "text": "法治政府是构筑法治国家的基础，努力使尊法学法守法用法在全社会蔚然成风"}], "answer": "D", "explanation": "党的二十大报告指出，'法治社会是构筑法治国家的基础'，而非'法治政府是构筑法治国家的基础'。法治政府建设是全面依法治国的重点任务和主体工程，法治社会是基础，二者定位不同。选项D混淆了法治政府和法治社会的定位。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 209}, {"num": 211, "batch": "专业基础知识", "type": "single", "stem": "“法律不能使人人平等，但是在法律面前人人是平等的”。下列选项与该句体现的含义相近的是（）。 ①法律如果推不开特权的门，也一定跨不进人民的心 ②法不阿贵，绳不挠曲 ③枪炮作响法无声 ④法律政令者，吏民规矩绳墨也", "options": [{"letter": "A", "text": "①②③"}, {"letter": "B", "text": "①②④"}, {"letter": "C", "text": "①③④"}, {"letter": "D", "text": "②③④"}], "answer": "B", "explanation": "题干强调法律面前人人平等。①'法律推不开特权的门'体现反对特权、人人平等；②'法不阿贵，绳不挠曲'意为法律不偏袒权贵；④'法律政令者，吏民规矩绳墨也'说明法律是所有官吏和百姓的共同准则。③'枪炮作响法无声'指战争时期法律失去效力，与平等无关。故选①②④。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 210}, {"num": 212, "batch": "专业基础知识", "type": "single", "stem": "南山派出所为全力做好困难儿童、空巢老人等困难群体、弱势群体的帮扶工作，积极开展走访，深入到群众中去，为他们解决实际生活中的困难，为弱势群体送去温暖。这直接揭示了公安工作的（）。", "options": [{"letter": "A", "text": "根本原则"}, {"letter": "B", "text": "根本路线"}, {"letter": "C", "text": "基本方针"}, {"letter": "D", "text": "基本政策"}], "answer": "B", "explanation": "派出所积极走访困难儿童、空巢老人等弱势群体，深入基层为群众解决实际困难，直接体现了公安工作的根本路线——群众路线。群众路线要求一切为了群众、一切依靠群众，从群众中来、到群众中去。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 211}, {"num": 213, "batch": "专业基础知识", "type": "single", "stem": "公安工作的根本原则是坚持党对公安工作的（）。", "options": [{"letter": "A", "text": "全面领导"}, {"letter": "B", "text": "直接领导"}, {"letter": "C", "text": "绝对领导"}, {"letter": "D", "text": "实际领导"}], "answer": "C", "explanation": "公安工作的根本原则是坚持党对公安工作的绝对领导。这是由公安机关的性质和任务决定的，确保公安工作始终保持正确的政治方向，是公安工作最根本的政治保证。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 212}, {"num": 214, "batch": "专业基础知识", "type": "single", "stem": "新安市刑侦局在办理一起黑社会组织犯罪案件时，侦查人员历时5个多月，询问300余人，收集证据材料达8万多页，最终该团伙犯罪证据确凿，将团伙头目张某等人绳之以法，本案最主要体现的公安工作基本政策是（）。", "options": [{"letter": "A", "text": "严肃与谨慎相结合政策"}, {"letter": "B", "text": "依法从重从快惩处刑事犯罪分子的政策"}, {"letter": "C", "text": "重证据，重调查研究，严禁逼供信的政策"}, {"letter": "D", "text": "教育与处罚相结合的政策"}], "answer": "C", "explanation": "侦查人员历时5个多月，询问300余人，收集证据材料达8万多页，体现了重证据、重调查研究、严禁逼供信的公安工作基本政策。该政策要求在办案中以事实为根据、以法律为准绳，通过深入细致的调查研究获取确凿证据，而非依赖口供。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 213}, {"num": 215, "batch": "专业基础知识", "type": "single", "stem": "公安工作是我国人民政府的重要行政行为，下列工作内容属于公安专业工作的是（）。", "options": [{"letter": "A", "text": "公安厅社会科学研究工作"}, {"letter": "B", "text": "法制民警参加出庭应诉"}, {"letter": "C", "text": "110指挥中心下达处警指令"}, {"letter": "D", "text": "基层户政管理工作"}], "answer": "D", "explanation": "公安专业工作是指公安机关依法履行的专门业务工作，包括刑事侦查、治安管理、户籍管理、出入境管理等。基层户政管理工作属于公安专业工作。社会科学研究属于公安科研工作，参加出庭应诉属于公安法制工作，下达处警指令属于公安指挥工作。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 214}, {"num": 216, "batch": "专业基础知识", "type": "single", "stem": "以下情形中体现出公安机关治安管理处罚基本政策的是（）。", "options": [{"letter": "A", "text": "公安机关全面搜集犯罪团伙所用证据后，对刑事犯罪分子严厉打击"}, {"letter": "B", "text": "公安机关在讯问犯罪嫌疑人的过程中，重视案件相关证据与调查结果，未采取刑讯逼供等错误方式强迫他人认罪"}, {"letter": "C", "text": "公安机关在对犯罪嫌疑人进行讯问的过程中，充分保障嫌疑人的饮食和休息，全力保障人权"}, {"letter": "D", "text": "因王某受郑某教唆违反治安管理，因此公安机关对王某不予处罚，对郑某从重处罚"}], "answer": "D", "explanation": "根据《治安管理处罚法》规定，教唆他人违反治安管理的，对教唆者从重处罚；被教唆者受教唆而违法的，可以不予处罚。选项D体现了教育与处罚相结合的基本政策，即对受教唆者以教育为主不予处罚，对教唆者依法从重处罚。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 215}, {"num": 217, "batch": "专业基础知识", "type": "single", "stem": "某市公安机关规定：非本市核发机动车号牌载客汽车前两次在本通告禁行区域内违反禁行规定的，不予处罚，自第三次违反禁行规定起进行罚款处罚。该规定体现公安机关的基本政策是（）。", "options": [{"letter": "A", "text": "宽严相济政策"}, {"letter": "B", "text": "严肃与谨慎相结合政策"}, {"letter": "C", "text": "便民利民惠民政策"}, {"letter": "D", "text": "教育与处罚相结合政策"}], "answer": "D", "explanation": "前两次违反禁行规定不予处罚，第三次起进行罚款，体现了教育与处罚相结合的政策。该政策要求在执法中坚持教育在先、处罚在后，通过教育使行为人认识错误、自觉守法，对屡教不改者再施以处罚。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 216}, {"num": 218, "batch": "专业基础知识", "type": "single", "stem": "电信诈骗犯罪严重侵害群众利益，一些受害群众几十年的积蓄被骗一空，有的甚至家破人亡。公安机关对那些老百姓深恶痛绝的犯罪分子，要坚决依法打击，体现了公安机关的专政职能，切实增强人民群众获得感和安全感，体现了公安机关的民主职能。公安机关专政职能和民主职能之间既有区别，又有联系，下列说法错误的是（）。", "options": [{"letter": "A", "text": "两者对象不同"}, {"letter": "B", "text": "两者手段不同"}, {"letter": "C", "text": "专政职能是实现民主职能的基本保障"}, {"letter": "D", "text": "民主职能是发挥专政职能的基本保障"}], "answer": "D", "explanation": "公安机关的专政职能与民主职能对象不同、手段不同。专政职能是民主职能的基本保障，民主职能是专政职能的基本条件。选项D将二者关系颠倒，应为专政职能是民主职能的基本保障，而非民主职能是专政职能的基本保障。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 217}, {"num": 219, "batch": "专业基础知识", "type": "single", "stem": "以下关于公安历史沿革的说法错误的是（）。", "options": [{"letter": "A", "text": "湖南保卫局是中国历史上最早的专职警察机构"}, {"letter": "B", "text": "国家政治保卫局是中国共产党在中央机关设立的最早的保卫组织"}, {"letter": "C", "text": "社会部的成立时间晚于陕甘宁边区人民警察的成立时间"}, {"letter": "D", "text": "公安部第一任部长为罗瑞卿"}], "answer": "B", "explanation": "国家政治保卫局是中国共产党在中央苏区（而非中央机关）设立的最早的保卫组织，成立于1931年。选项B将'中央苏区'表述为'中央机关'，不够准确。湖南保卫局确为中国历史上最早的专职警察机构，公安部第一任部长确为罗瑞卿。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 218}, {"num": 220, "batch": "专业基础知识", "type": "single", "stem": "Y市组织2023年新入职民警开展培训工作，在自我介绍环节上4名新警依次进行发言，其中发言内容错误的是（）。", "options": [{"letter": "A", "text": "甲：“我是市局环侦支队的民警，我平时的主要工作是指导协调各分局环侦大队开展案件侦查等相关工作，我的岗位属于公安领导工作”"}, {"letter": "B", "text": "乙：“我是市局办公室的民警，我平时的主要工作是为领导工作提供信息服务、草拟文件、组织会议，我的岗位属于公安秘书工作”"}, {"letter": "C", "text": "丙：“我是分局指挥中心民警，我平时的主要工作是下达领导工作指令，统一调度各警种、各部门开展相关业务，我的岗位属于公安指挥工作”"}, {"letter": "D", "text": "丁：“我是分局派出所的民警，我平时主要负责出警处理各类案件，打击违法犯罪，我的岗位属于公安专业工作”"}], "answer": "A", "explanation": "环侦支队的主要工作是指导协调各分局环侦大队开展案件侦查等，属于公安专业工作，而非公安领导工作。公安领导工作是指公安机关各级领导干部所从事的决策、组织、协调等工作。公安秘书工作、公安指挥工作和公安专业工作的描述均正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 219}, {"num": 221, "batch": "专业基础知识", "type": "single", "stem": "A市公安局为满足群众需求，在社区成立警务室，定期组织相关警种开展上门服务，让群众足不出户就能办证、入户、车辆年检等业务，变“群众上门”为“上群众门”切实解决群众急难愁盼问题。关于A市公安局的工作方法，下列正确的观点有（）。", "options": [{"letter": "A", "text": "贯彻了公安工作的基本方针"}, {"letter": "B", "text": "贯彻了公安工作的根本原则"}, {"letter": "C", "text": "贯彻了公安工作的根本路线"}, {"letter": "D", "text": "贯彻了公安工作的基本政策"}], "answer": "C", "explanation": "A市公安局在社区成立警务室、开展上门服务，变'群众上门'为'上群众门'，体现了深入群众、服务群众的工作方法，贯彻了公安工作的根本路线即群众路线。群众路线要求公安机关一切为了群众、一切依靠群众。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 220}, {"num": 222, "batch": "专业基础知识", "type": "single", "stem": "东海市公安局围绕“智能化办案区管理系统的应用及办案区的管理与使用”等规范执法内容，针对执法办案民警集中难、培训难的问题，推出了“岗位大练兵、法制小课堂”的送教下基层执法培训模式，以不同岗位、不同警种随时集中、随时进行问题分析的小课堂形式，对日常案件办理中常见的问题进行全面快速的培训。关于“送教下基层执法培训”，下列说法正确的是（）。", "options": [{"letter": "A", "text": "属于公安指挥工作"}, {"letter": "B", "text": "属于公安政治工作"}, {"letter": "C", "text": "属于公安法制工作"}, {"letter": "D", "text": "属于治安行政管理工作"}], "answer": "C", "explanation": "'送教下基层执法培训'围绕规范执法内容，针对执法办案中的常见问题进行培训，属于公安法制工作。公安法制工作包括法制宣传教育、执法指导、执法培训等，旨在提高民警的执法水平和规范执法能力。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 221}, {"num": 223, "batch": "专业基础知识", "type": "single", "stem": "宝山县刑警大队在侦办一起诈骗案件时，根据群众提供的线索锁定了犯罪嫌疑人之一辛某的落脚点，由大队长汪某负责抓捕行动的总体指挥工作，副大队长肖某带领队实施。在抓捕过程中汪某突然要求肖某带领队员停止行动，放掉辛某并继续追踪。肖某认为不该错过本次抓捕时机，肖某以下做法正确的是？（）", "options": [{"letter": "A", "text": "执行汪某命令，并向局领导报告"}, {"letter": "B", "text": "执行汪某命令，但可以向汪某提出意见"}, {"letter": "C", "text": "情况紧急，先实施抓捕再向局领导报告"}, {"letter": "D", "text": "情况紧急，先实施抓捕再向王某提出意见"}], "answer": "B", "explanation": "根据《人民警察法》规定，人民警察必须执行上级的决定和命令。如果认为决定和命令有错误的，可以按照规定提出意见，但不得中止或者改变决定和命令的执行。因此肖某应执行汪某命令，但可以提出意见。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 222}, {"num": 224, "batch": "专业基础知识", "type": "single", "stem": "赵某因在酒吧娱乐期间与李某、王某发生口角，被带至胡同殴打，后被周边巡逻民警及时制止。在案件办理过程中，以下说法错误的是（）。", "options": [{"letter": "A", "text": "赵某认为自己的伤情为轻伤，李某、王某对此存有争议，此时公安机关应当对赵某的伤势进行伤情鉴定"}, {"letter": "B", "text": "经鉴定，赵某所受伤害为轻微伤，赵某对此鉴定意见存有异议，可以在收到鉴定意见后3日内提出重新鉴定申请"}, {"letter": "C", "text": "对赵某伤情的重新鉴定最多为1次"}, {"letter": "D", "text": "赵某因不相信公安机关聘请的鉴定人，自行前往其他地点进行伤情鉴定，所产生的鉴定费用应当由公安机关承担"}], "answer": "D", "explanation": "根据相关规定，当事人对鉴定意见有异议可以申请重新鉴定，但自行委托其他机构进行的鉴定，其费用应由当事人自行承担，不应由公安机关承担。公安机关聘请鉴定人进行鉴定的费用才由公安机关承担。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 223}, {"num": 225, "batch": "专业基础知识", "type": "single", "stem": "民警小陈对下列违法行为人当场收缴罚款，根据《公安机关办理行政案件程序规定》，其中当场收缴措施适用不当的是（）。", "options": [{"letter": "A", "text": "行人李某闯红灯，对其处以20元罚款，李某无异议"}, {"letter": "B", "text": "张某在高铁上吸烟被处以2000元罚款，张某向指定银行缴纳罚款确有困难"}, {"letter": "C", "text": "方某为甲市人，来乙市旅游期间公然侮辱他人被处以100元罚款"}, {"letter": "D", "text": "丁某在演唱会上展示侮辱性标语被处以30元罚款，丁某无异议"}], "answer": "B", "explanation": "根据《公安机关办理行政案件程序规定》，当场收缴罚款适用于罚款数额在100元以下的情形，或者被处罚人在当地没有固定住所不当场收缴事后难以执行的。张某被处2000元罚款，数额较大，不符合当场收缴的适用条件，即使缴纳有困难也不应当场收缴。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 224}, {"num": 226, "batch": "专业基础知识", "type": "single", "stem": "临江县公安局在办理周X抢夺案件时，还查实了周X的另一起盗窃行为。针对周X的两起违法事实，临江县公安局依法对周X的抢夺违法行为作出十五日行政拘留的处罚决定，对周X的盗窃违法行为作出十三日行政拘留的处罚决定。根据相关法律法规，下列关于对周X合并执行的决定正确的是（）。", "options": [{"letter": "A", "text": "行政拘留十三日"}, {"letter": "B", "text": "行政拘留十五日"}, {"letter": "C", "text": "行政拘留二十日"}, {"letter": "D", "text": "行政拘留二十八日"}], "answer": "C", "explanation": "根据《治安管理处罚法》第十六条规定，有两种以上违反治安管理行为的，分别决定，合并执行。行政拘留处罚合并执行的，最长不超过二十日。周某的抢夺行为拘留15日、盗窃行为拘留13日，合并执行应在20日以内，即行政拘留二十日。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 225}, {"num": 227, "batch": "专业基础知识", "type": "single", "stem": "张某在小区内散养烈性大型犬，经常无故扑袭、恐吓其他居民，经派出所警告后仍拒不悔改，对此河南派出所受理张某饲养动物干扰他人生活案。在案件办理过程中以下做法错误的是（）。", "options": [{"letter": "A", "text": "对违法嫌疑人张某进行询问最长时间不得超过8小时"}, {"letter": "B", "text": "公安机关应当在首次询问张某时问明其是否为各级人民代表大会代表"}, {"letter": "C", "text": "民警在对小区居民赵某（17岁，曾受该大型犬惊吓）进行询问时，必须要求其父母或监护人到场"}, {"letter": "D", "text": "民警在小区居民孙某（聋哑人）进行询问时，应当有通晓手语的人帮助翻译"}], "answer": "C", "explanation": "根据《治安管理处罚法》规定，询问不满十八周岁的违反治安管理行为人，'应当'通知其父母或者其他监护人到场。选项C表述为'必须要求父母或监护人到场'看似正确，但根据新修订的治安法相关规定，对于已满十六周岁不满十八周岁的未成年人，初次违反治安管理的，可以不通知监护人到场，故C的表述过于绝对。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 226}, {"num": 228, "batch": "专业基础知识", "type": "single", "stem": "王某因土地纠纷问题将李某打伤，李某向辖区派出所报案，公安机关的下列做法错误的是（）。", "options": [{"letter": "A", "text": "若李某要求作伤情鉴定，公安机关应当进行伤情鉴定"}, {"letter": "B", "text": "若李某无故未在公安机关确定的时间内作伤情鉴定，视为拒绝鉴定"}, {"letter": "C", "text": "若李某对鉴定意见有异议申请了重新鉴定，最终总的鉴定次数最多为2次"}, {"letter": "D", "text": "若李某自行进行鉴定，所产生的费用由公安机关承担"}], "answer": "D", "explanation": "当事人自行委托其他机构进行鉴定的，所产生的费用应由当事人自行承担，不应由公安机关承担。公安机关只承担其依法委托鉴定人进行鉴定所产生的费用。选项D表述错误。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 227}, {"num": 229, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）民警梁某在执法过程中，对女司机郑某驾驶的汽车进行检查时，发现该车使用违规套牌，民警梁某依法要求其出示驾驶证时，遭到郑某拒绝，随后，情绪激动的郑某坐在车里公然对梁某进行侮辱。据此情形，郑某应受到的处罚是（）", "options": [{"letter": "A", "text": "治安管理处罚"}, {"letter": "B", "text": "刑事处罚"}, {"letter": "C", "text": "行政处罚"}, {"letter": "D", "text": "口头批评"}], "answer": "C", "explanation": "根据新修订的《治安管理处罚法》，公然侮辱正在执行职务的人民警察，尚不够刑事处罚的，应给予行政处罚（治安管理处罚属于行政处罚的一种）。本题中郑某拒绝出示驾驶证并公然侮辱民警，构成违反治安管理行为，应受行政处罚。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 228}, {"num": 230, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）何某是聋哑人，2020年5月31日抢夺他人价值一千元的手机时被巡逻民警当场抓获，何某交待其在2019年11月28日盗窃价值四百元的自行车一辆，对何某违反治安管理行为的处理，下列说法正确的是（）。", "options": [{"letter": "A", "text": "由于其盗窃行为已过追究时效，对其盗窃行为不再处罚"}, {"letter": "B", "text": "应对其盗窃和抢夺行为分别决定治安处罚，合并执行"}, {"letter": "C", "text": "由于其是聋哑人，应当从轻、减轻处罚或者不予处罚"}, {"letter": "D", "text": "由于其有两种违法行为，应当从重处罚"}], "answer": "A", "explanation": "根据《治安管理处罚法》第二十二条规定，违反治安管理行为在六个月内没有被公安机关发现的，不再处罚。何某的盗窃行为发生在2019年11月28日，至2020年5月31日被抓获时已超过六个月追究时效，故对其盗窃行为不再处罚。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 229}, {"num": 231, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）某年8月6日13时许，东南沿海某小岛内，某“渔家乐”报警称有人在店里闹事，民警赶到现场得知，因“台风”过境造成食品价格上涨，某旅游团的成员方某对该“渔家乐”的鱼价提出质疑，与店员发生口角，方某随手毁坏了身边的餐具。民警进行处理时正确的做法是：（）", "options": [{"letter": "A", "text": "要求店家适当打折"}, {"letter": "B", "text": "责令方某赔偿店家损失"}, {"letter": "C", "text": "对损坏的餐具进行估价"}, {"letter": "D", "text": "通知旅游团的导游参与调解"}], "answer": "D", "explanation": "本案因台风导致食品价格上涨引发消费纠纷，属于民间纠纷。民警到场后应首先了解情况，通知旅游团导游参与调解，借助导游的力量协助化解纠纷。直接要求店家打折或责令赔偿均超出了民警的职权范围。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 230}, {"num": 232, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）刘某在居住的小区内看到一辆小轿车的后车门没有关严，随即进入车中，想法接通点火电线启动汽车，并绕环城公路驾驶一圈后将汽车停在原处。车的主人发现车被人挪动后报警，民警根据小区的监控录像将刘某抓获。下列说法正确的是（）。", "options": [{"letter": "A", "text": "按照《治安管理处罚法》，以偷开他人机动车的规定处罚"}, {"letter": "B", "text": "按照《治安管理处罚法》，以寻衅滋事的规定处罚"}, {"letter": "C", "text": "刘某的行为属盗窃中止，应追究刑事责任"}, {"letter": "D", "text": "刘某的行为属盗窃未遂，应追究刑事责任"}], "answer": "A", "explanation": "刘某未经允许擅自启动他人汽车驾驶后归还，没有非法占有目的，属于偷开他人机动车的行为，应按《治安管理处罚法》相关规定予以处罚。其行为不构成盗窃，因为缺乏非法占有的主观故意。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 231}, {"num": 233, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）刘某，1999年8月13日生，2017年1月因散布儿童失踪的网络谣言被县公安局抓获，依法应当给予行政拘留五日的处罚。同时，县公安局警察发现刘某于2015年5月曾被收容教养。对此，公安机关正确的做法是（）", "options": [{"letter": "A", "text": "因刘某未成年，不应当执行拘留处罚"}, {"letter": "B", "text": "因刘某未成年，将拘留处罚改为罚款"}, {"letter": "C", "text": "尽管刘某未成年，仍依法执行行政拘留"}, {"letter": "D", "text": "根据刘某的悔过表现决定是否执行拘留处罚"}], "answer": "C", "explanation": "根据《治安管理处罚法》规定，已满十六周岁不满十八周岁的人初次违反治安管理的，不执行行政拘留处罚。但刘某曾被收容教养，说明其并非'初次'，且2017年1月时刘某已满17周岁，依法应当执行行政拘留。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 232}, {"num": 234, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）某用餐人在饭店就餐时吃出异物，拒不结账。饭店报警，民警到达现场后，经现场了解，饭店确实存在过错。民警现场告知用餐人到食品安全监管部门投诉举报，但该用餐人仍拒绝付款，双方没有发生打架斗殴。民警以下做法正确的是（）。", "options": [{"letter": "A", "text": "建议饭店收费打折"}, {"letter": "B", "text": "对用餐人予以警告"}, {"letter": "C", "text": "通知食品安全监管部门到场处理"}, {"letter": "D", "text": "告知当事人向人民法院或者人民调解组织申请处理"}], "answer": "D", "explanation": "用餐人与饭店之间的纠纷属于民事纠纷，不涉及治安违法行为。民警现场已告知用餐人向食品安全监管部门投诉举报，用餐人仍拒绝付款的，民警应告知当事人向人民法院或人民调解组织申请处理，不宜直接介入民事纠纷。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 233}, {"num": 235, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）某小区业主甲因邻居乙在家唱卡拉OK影响其休息而多次报警。10月20日，甲、乙2人为此又发生相互殴打，均造成轻微伤害。派出所民警赵某、张某对这起纠纷进行了处理。以下说法错误的是（）。", "options": [{"letter": "A", "text": "赵某、张某对此案可以调解处理"}, {"letter": "B", "text": "产生社会生活噪声干扰他人正常生活的，经有关部门制止仍不改的，处五日以下拘留或者一千元以下罚款"}, {"letter": "C", "text": "产生社会生活噪声干扰他人正常生活的，情节严重的，处五日以上十日以下拘留"}, {"letter": "D", "text": "产生社会生活噪声干扰他人正常生活的，情节严重的，应处一千元以下罚款"}], "answer": "D", "explanation": "根据新修订的《治安管理处罚法》，产生社会生活噪声干扰他人正常生活，经有关部门制止仍不改正的，处五日以下拘留或者一千元以下罚款；情节严重的，处五日以上十日以下拘留。选项D称'情节严重的应处一千元以下罚款'与法律规定不符，应为拘留。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 234}, {"num": 236, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）民警在派出所办案区询问行政违法嫌疑甲，甲要求喝水，民警用纸杯给其接水，甲接过纸杯喝完水后直接脱裤子小便在水杯里，民警上前制止，甲将水杯里的尿液泼在民警身上。下列选项中对甲的行为定性最合适的是（）。", "options": [{"letter": "A", "text": "公然侮辱"}, {"letter": "B", "text": "故意伤害"}, {"letter": "C", "text": "阻碍执法"}, {"letter": "D", "text": "扰乱单位秩序"}], "answer": "C", "explanation": "甲在派出所办案区向正在执行职务的民警泼洒尿液，属于以暴力方法阻碍国家机关工作人员依法执行职务的行为，应定性为阻碍执行职务（阻碍执法）。其行为并非单纯的公然侮辱或故意伤害。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 235}, {"num": 237, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）杨某将房屋出租给刘某（女）居住，没有按规定登记刘某的姓名、身份证件种类和号码。刘某在租住的房屋内卖淫被公安机关查获，对于刘某的卖淫行为杨某并不知情。关于杨某的行为，下列说法正确的是（）", "options": [{"letter": "A", "text": "杨某没有违法行为"}, {"letter": "B", "text": "杨某构成容留卖淫的违反治安管理行为"}, {"letter": "C", "text": "杨某构成不按规定登记承租人信息的违反治安管理行为"}, {"letter": "D", "text": "杨某构成容留卖淫和不按规定登记承租人信息两种违反治安管理行为"}], "answer": "C", "explanation": "杨某未按规定登记承租人刘某的姓名和身份证件信息，构成不按规定登记承租人信息的违反治安管理行为。杨某对刘某的卖淫行为并不知情，缺乏容留卖淫的主观故意，不构成容留卖淫行为。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 236}, {"num": 238, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）2023年2月，白某在观看篮球比赛，因扰乱比赛秩序被处以治安拘留处罚，并被公安机关责令12个月内不得进体育场馆观看篮球比赛。同年9月，白某为观看篮球比赛违反规定进入篮球场馆。公安机关应当对其（）。", "options": [{"letter": "A", "text": "予以警告"}, {"letter": "B", "text": "当场罚款"}, {"letter": "C", "text": "治安拘留"}, {"letter": "D", "text": "强行带离现场"}], "answer": "D", "explanation": "根据《治安管理处罚法》规定，因扰乱大型活动秩序被责令十二个月内不得进入体育场馆观看同类比赛的，违反规定进入体育场馆的，公安机关可以强行带离现场。选项D符合法律规定。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 237}, {"num": 239, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）居民王某报警称，昨晚停放在小区的汽车被划伤，并怀疑是住其楼下的岳某所为，派出所经询问了解和调取监控录像，证实确系岳某所为，同时进一步了解到双方因噪声问题素有矛盾。对此案的处理，公安机关最正确的做法是（）。", "options": [{"letter": "A", "text": "对岳某直接作出行政处罚"}, {"letter": "B", "text": "告知王某到当地人民法院申请处理"}, {"letter": "C", "text": "经征询双方当事人同意，可以进行治安调解"}, {"letter": "D", "text": "为化解邻里矛盾，必须进行治安调解"}], "answer": "C", "explanation": "本案系邻里纠纷引起的故意损毁财物行为，属于因民间纠纷引起的治安案件。根据《治安管理处罚法》第九条规定，对于因民间纠纷引起的违反治安管理行为，情节较轻的，公安机关可以调解处理，但须征得双方当事人同意。调解不是必须的。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 238}, {"num": 240, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）男子张某因不满政府拆迁政策，在火车站广场大吵大闹，扰乱现场秩序，被公安机关处以罚款，但因为某些现实原因无法当场向张某宣告治安管理处罚决定书，按照法律规定，应当在（）日内向其送达治安管理处罚决定书。", "options": [{"letter": "A", "text": "一日"}, {"letter": "B", "text": "二日"}, {"letter": "C", "text": "三日"}, {"letter": "D", "text": "四日"}], "answer": "B", "explanation": "根据《治安管理处罚法》第九十七条规定，公安机关应当向被处罚人宣告治安管理处罚决定书，并当场交付被处罚人；无法当场向被处罚人宣告的，应当在二日内送达被处罚人。因此应当在二日内送达。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 239}, {"num": 241, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）某日晚十时许，在校大学生漆某在校园酒吧举行20岁生日聚会，喝醉酒后殴打同学刘某，致其头皮血肿、左膝皮肤擦伤，构成轻微伤害。刘某报警，民警赶到现场后，漆某仍不停手，并拉扯、辱骂民警。针对本案，下列表述正确的是（）", "options": [{"letter": "A", "text": "本案案情简单、事实清楚，民警可以对漆某进行当场处罚"}, {"letter": "B", "text": "民警可以对漆某适用继续盘问措施"}, {"letter": "C", "text": "民警应当将漆某约束至酒醒"}, {"letter": "D", "text": "民警可以对漆某适用拘传"}], "answer": "C", "explanation": "根据《治安管理处罚法》第十五条规定，醉酒的人在醉酒状态中，对本人有危险或者对他人的人身、财产或者公共安全有威胁的，应当对其采取保护性约束措施约束至酒醒。漆某醉酒殴打他人且拉扯辱骂民警，应当约束至酒醒。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 240}, {"num": 242, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）下列行政案件不适用简易程序，但事实清楚，违法嫌疑人自愿认错认罚，且对违法事实和法律适用没有异议，公安机关可以通过简化取证方式和审核审批手续等措施快速办理的是（）", "options": [{"letter": "A", "text": "赵某（15周岁）在超市偷窃"}, {"letter": "B", "text": "黄某（19周岁，聋哑人）殴打他人"}, {"letter": "C", "text": "李某（18周岁）扰乱单位秩序，情节较轻"}, {"letter": "D", "text": "林某（20周岁）殴打一75岁退休教师"}], "answer": "C", "explanation": "根据《公安机关办理行政案件程序规定》，快速办理不适用于涉及未成年人、聋哑人、精神病人等特殊主体的案件。选项A段某15周岁为未成年人，选项B黄某为聋哑人，选项D涉及殴打75岁以上老人，均不适用快速办理。选项C李某18周岁且情节较轻，可以适用快速办理。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 241}, {"num": 243, "batch": "专业基础知识", "type": "single", "stem": "善泰县为建设医药产业园，征收司楠坊村15公顷土地。按程序完成选址、环境影响评价后，建设项目获得主管部门批准。施工中，几十位村民对土地补偿不满，同时担心医药产业园排出的废水污染环境，在本村老人协会会长林x和妇女委员会主任郑x的带领下集体阻止施工，导致项目停工20余小时。民警赶到现场后，仍有部分村民起哄，大声叫嚷：“不管怎样，只要这个项目进行施工就会阻止！”民警劝导说：“项目合法合规，再阻止施工将涉嫌违法。”有村民追问：“怎么违法了？”民警应依法告知涉嫌的违法行为名称是（）。", "options": [{"letter": "A", "text": "阻碍执行职务"}, {"letter": "B", "text": "扰乱单位秩序"}, {"letter": "C", "text": "故意损毁财物"}, {"letter": "D", "text": "寻衅滋事"}], "answer": "B", "explanation": "村民集体阻止合法合规的施工导致项目停工，属于扰乱企业事业单位秩序的行为。民警应依法告知其行为涉嫌扰乱单位秩序的违法行为。阻碍执行职务是指阻碍国家机关工作人员依法执行职务，不符合本案情形。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 242}, {"num": 244, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）某市实验中学刘老师正给学生上网课，甲和乙通过其他网站获取会议号后进入课堂并在课堂上随意刷屏、播放音乐，严重扰乱了正常的网络课堂秩序，刘老师最终无奈终止了网课。则甲和乙构成（）。", "options": [{"letter": "A", "text": "扰乱单位秩序违法行为"}, {"letter": "B", "text": "扰乱公共场所秩序违法行为"}, {"letter": "C", "text": "寻衅滋事违法行为"}, {"letter": "D", "text": "侮辱违法行为"}], "answer": "A", "explanation": "甲和乙进入网课课堂刷屏、播放音乐，严重扰乱了学校正常的网络教学秩序，导致网课被迫终止。该行为属于扰乱单位（学校）秩序的违法行为，应按《治安管理处罚法》相关规定予以处罚。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 243}, {"num": 245, "batch": "专业基础知识", "type": "single", "stem": "罗某、李某因相互劝酒发生口角后，罗某打了李某背部一拳，致李某滑倒在地扭伤脚踝。随后，李某拨打110报警。罗某酒醒后表示很后悔，称愿意赔礼道歉、赔偿李某损失，希望公安机关调解处理。李某接受道歉，同意调解。后在民警主持下，双方达成调解协议。假如罗某不履行协议，李某不满找到公安民警，民警正确的处理方式是：（）。", "options": [{"letter": "A", "text": "对罗某进行强制执行"}, {"letter": "B", "text": "对罗某进行治安处罚"}, {"letter": "C", "text": "告知李某提起行政诉讼"}, {"letter": "D", "text": "重新主持治安调解"}], "answer": "B", "explanation": "根据《治安管理处罚法》第九条规定，经公安机关调解，当事人达成协议的，不予处罚。经调解未达成协议或者达成协议后不履行的，公安机关应当依法对违反治安管理行为人给予处罚。因此罗某不履行协议，公安机关应对罗某进行治安处罚。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 244}, {"num": 246, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）李某和邻居张某打架，造成张某轻微伤。在民警的主持下，双方自愿达成了调解协议，张某拿到了李某赔偿的医药费500元。事后，张某觉得吃亏了，又到派出所要求重新处理，对此办案民警应该（）。", "options": [{"letter": "A", "text": "再次调解"}, {"letter": "B", "text": "告知张某只能对李某提起民事诉讼"}, {"letter": "C", "text": "不能对李某做出治安处罚"}, {"letter": "D", "text": "告知张某可申请行政复议或提起行政诉讼"}], "answer": "C", "explanation": "根据《治安管理处罚法》第九条规定，经公安机关调解当事人达成协议并已履行的，不再对违法行为人给予治安处罚。张某事后觉得吃亏要求重新处理，公安机关不能因此再对李某作出治安处罚。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 245}, {"num": 247, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）某日张某家的小狗闯入邻居刘某屋中，将一个瓷瓶撞落摔碎，刘某持棍将小狗赶出房间，张某冲进刘某屋中与其激烈争吵，并互相拉扯，张某受轻微伤，派出所民警接警赶到现场后，下列处置措施恰当的是（）", "options": [{"letter": "A", "text": "责令张某赔偿刘某的花瓶"}, {"letter": "B", "text": "告知刘某应当去法院起诉张某"}, {"letter": "C", "text": "在双方同意基础上进行治安调解"}, {"letter": "D", "text": "告知刘某与张某应自行协商解决"}], "answer": "C", "explanation": "本案系邻里之间因小狗闯入引发纠纷导致的轻微伤害案件，属于因民间纠纷引起的治安案件。根据法律规定，对于因民间纠纷引起的打架斗殴等情节较轻的治安案件，公安机关可以在双方同意的基础上进行治安调解。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 246}, {"num": 248, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）治安案件是扰乱公共秩序，妨害公共安全，侵犯人身权利、财产权利，妨害社会管理，具有社会危害性，尚不够刑事处罚，由公安机关依法给予治安管理处罚的案件。下列属于治安案件的是（）。", "options": [{"letter": "A", "text": "宫某（女，14周岁）从父母日常放钱处偷拿走500元钱"}, {"letter": "B", "text": "薛某在家偶尔吸食毒品"}, {"letter": "C", "text": "黄某喜欢有夫之妇连某并对其表白爱慕之意"}, {"letter": "D", "text": "钱某因对主管领导不满，写信给单位领导发泄不满情绪"}], "answer": "B", "explanation": "吸食毒品属于违反治安管理的行为，构成治安案件。宫某偷拿父母500元属于家庭内部行为，一般不作为治安案件处理；表白爱慕不构成违法行为；写信发泄不满未造成危害后果，不构成治安案件。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 247}, {"num": 249, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）甲酒后驾车轻微擦碰到骑摩托车的乙后要求私了，乙根据损失提出甲须赔偿1000元，否则报警。甲不同意并强行离开，乙将甲打成轻微伤，强迫甲抱头蹲在地上，引发围观。乙违法行为的性质是（）。", "options": [{"letter": "A", "text": "殴打他人、侮辱"}, {"letter": "B", "text": "敲诈勒索、寻衅滋事"}, {"letter": "C", "text": "敲诈勒索、殴打他人"}, {"letter": "D", "text": "殴打他人、非法限制人身自由"}], "answer": "A", "explanation": "乙将甲打成轻微伤，构成殴打他人的违法行为；乙强迫甲抱头蹲在地上，引发围观，具有贬损甲人格的故意，构成侮辱行为。乙提出1000元赔偿要求属于合理的民事索赔，不构成敲诈勒索。因此乙的违法行为性质为殴打他人和侮辱。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 248}, {"num": 250, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）李某与周某因债务发生纠纷，李某心生怨气，发送短信对周某进行辱骂。起初周某未予理睬，但李某继续向周某发送数十条辱骂信息，周某不堪其扰而报警。对李某的行为，公安机关处理正确的是（）。", "options": [{"letter": "A", "text": "以侮辱对李某予以治安管理处罚"}, {"letter": "B", "text": "以诽谤对李某予以治安管理处罚"}, {"letter": "C", "text": "以侵犯隐私对李某予以治安管理处罚"}, {"letter": "D", "text": "以发送信息干扰正常生活对李某予以治安管理处罚"}], "answer": "D", "explanation": "根据新修订的《治安管理处罚法》，多次发送侮辱、恐吓或者其他信息，干扰他人正常生活的，构成发送信息干扰正常生活的违法行为。李某持续向周某发送数十条辱骂信息，符合该行为的构成要件，应以发送信息干扰正常生活予以治安处罚。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 249}, {"num": 251, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）某日22时许，胡X与同事在火锅店聚餐，醉酒后与人发生争执。民警小刘、小张到场处置，胡X辱骂民警，并用头撞墙，小刘、小张依法对其采取保护性约束措施。胡X拼命反抗，导致其右臂脱臼。对此，下列表述正确的是（）。", "options": [{"letter": "A", "text": "公安机关对胡X的损害承担赔偿责任"}, {"letter": "B", "text": "小刘、小张对胡X的损害承担补偿责任"}, {"letter": "C", "text": "火锅店经营者对胡的损害承担补充责任"}, {"letter": "D", "text": "不能因胡X醉酒免除其治安违法责任"}], "answer": "D", "explanation": "根据《治安管理处罚法》第十五条规定，醉酒的人违反治安管理的，应当给予处罚。胡X虽处于醉酒状态，但不能免除其治安违法责任。胡X的损害系其自身拼命反抗所致，民警依法采取保护性约束措施并无不当，公安机关不承担赔偿责任。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 250}, {"num": 252, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）执勤民警老李正在执行出城车辆盘查任务，按照当地防疫规定，驾驶人张某的核酸检测报告已过期不可出城，老李对其进行劝返。张某称有急事，向民警说情。老李现场处置恰当的是（）。", "options": [{"letter": "A", "text": "考虑实情让张某通过"}, {"letter": "B", "text": "将张某强行带离现场"}, {"letter": "C", "text": "建议张某去核酸检测"}, {"letter": "D", "text": "当场对张某给予警告"}], "answer": "C", "explanation": "张某核酸检测报告过期不可出城，但其称有急事。民警应当坚持防疫规定，同时建议张某去做核酸检测后再出城，既严格执行规定又体现人性化执法。直接放行违反规定，强行带离和当场警告则处置过度。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 251}, {"num": 253, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）某日晚10时许，H派出所接到群众报警称：G小区公用广场有很多人在跳广场舞，噪音很大，严重影响了小区居民的正常休息。接警后，该派出所处警民警正确的做法是（）", "options": [{"letter": "A", "text": "告知报警群众：该警情不属于公安机关管辖，不予理会"}, {"letter": "B", "text": "到达现场后，直接扣押音响设备，驱散现场跳舞者"}, {"letter": "C", "text": "到达现场后，劝告跳舞者立即降低音量，不要扰民"}, {"letter": "D", "text": "到达现场后，直接将带头跳舞者带至派出所"}], "answer": "C", "explanation": "广场舞噪音扰民属于公安机关管辖的治安问题。民警到场后应先劝告跳舞者降低音量、不要扰民，以教育劝导为主。直接扣押设备、驱散跳舞者或将带头者带离派出所均属于处置过度。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 252}, {"num": 254, "batch": "专业基础知识", "type": "single", "stem": "甲县公安局在夏季治安整治行动中，接群众举报，称某度假区“丰和山庄”内有人赌博。2022年7月10日，甲县公安局城东派出所民警根据前期获得的线索，将正在“丰和山庄”房间内赌博的黄某、杨某、陈某、罗某四人一举抓获，现场查获麻将一副及现金4000余元。经询问，四人均承认用现场查获的赌具麻将进行赌博，目的是为了“想赢点钱用用”，麻将系由罗某从家中带来。经鉴定，麻将价值5万元。根据法律的规定，办案民警对涉案赌具的处理正确的是（）。", "options": [{"letter": "A", "text": "经甲县公安局局长批准，予以收缴"}, {"letter": "B", "text": "经甲县公安局局长批准，予以追缴"}, {"letter": "C", "text": "经城东派出所所长批准，予以没收"}, {"letter": "D", "text": "经城东派出所所长批准，予以销毁"}], "answer": "A", "explanation": "根据《治安管理处罚法》第十一条规定，办理治安案件所查获的毒品、淫秽物品等违禁品，赌具、赌资以及直接用于实施违法行为的工具，应当收缴。赌具麻将属于直接用于赌博的工具，经县级以上公安机关负责人（县公安局局长）批准，予以收缴。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 253}, {"num": 255, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）某交警中队在查处酒驾时，一名驾驶皮卡车的男子拒不服从民警的指挥，强行冲卡。车辆被截停后，该男子又推搡、殴打、撕咬执法交警。对该男子的行为及处理，下列说法正确的是（）", "options": [{"letter": "A", "text": "构成扰乱公共秩序的治安违法"}, {"letter": "B", "text": "构成妨害公务罪"}, {"letter": "C", "text": "构成危险驾驶罪"}, {"letter": "D", "text": "构成袭警罪"}], "answer": "D", "explanation": "根据《刑法》第二百七十七条第五款规定，暴力袭击正在依法执行职务的人民警察的，构成袭警罪。该男子推搡、殴打、撕咬执法交警，属于以暴力方法袭击正在执行职务的人民警察，构成袭警罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 254}, {"num": 256, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）赵某（15周岁）和同学王某在学校发生纠纷。赵某回家后恰好看到王某从其家门口经过，便驱使自家养的狗扑咬王某，致王某轻微伤。下列选项中错误的是（）", "options": [{"letter": "A", "text": "赵某构成故意伤害他人的违反治安管理行为"}, {"letter": "B", "text": "公安机关询问赵某时没有通知其父母或其他监护人到场"}, {"letter": "C", "text": "公安机关可以对此案进行调解处理"}, {"letter": "D", "text": "公安机关对赵某应当从轻或减轻处罚"}], "answer": "B", "explanation": "根据《治安管理处罚法》规定，询问不满十八周岁的违反治安管理行为人，应当通知其父母或者其他监护人到场。赵某15周岁，公安机关询问时应当通知其父母或监护人到场，选项B称'没有通知'的做法是错误的，但题目问的是错误选项，B本身就是错误做法的描述，因此选B。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 255}, {"num": 257, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）某县公安局治安大队办理一起赌博案件时，在调查结束后，办案民警书面告知违法行为人贾某公安机关对其拘留10日并处罚款4000元。此时，贾某依法可以提出的是（）。", "options": [{"letter": "A", "text": "要求听证"}, {"letter": "B", "text": "要求复议"}, {"letter": "C", "text": "提起行政诉讼"}, {"letter": "D", "text": "向信访部门申诉"}], "answer": "A", "explanation": "根据《治安管理处罚法》第九十八条规定，公安机关作出吊销许可证以及处二千元以上罚款的治安管理处罚决定前，应当告知违反治安管理行为人有要求举行听证的权利。拘留10日并处罚款4000元，罚款数额超过2000元，贾某有权要求听证。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 256}, {"num": 258, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）周某是某市在读大三学生，涉嫌在火车站寻衅滋事，致使安检员黄某手臂轻微割伤，公安机关经调查拟对其作出700元罚款的治安处罚。关于此处罚决定，下列做法恰当的是（）", "options": [{"letter": "A", "text": "由车站公安派出所作出"}, {"letter": "B", "text": "应将副本抄送安检员黄某"}, {"letter": "C", "text": "应当依当场处罚程序作出"}, {"letter": "D", "text": "可以当场收缴罚款"}], "answer": "A", "explanation": "根据相关规定，火车站区域的治安处罚可由车站公安派出所作出。对周某处以700元罚款，不属于当场处罚的适用范围（当场处罚限于警告或500元以下罚款），应由车站派出所按一般程序作出。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 257}, {"num": 259, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）某日，赵某驾驶无牌超标电动车途经中山路口时因闯红灯被交警查处。民警依法对其处罚时，赵某极度不满，大声谩骂民警长达十几分钟，引发众人围观。赵某的行为构成（）。", "options": [{"letter": "A", "text": "袭警罪"}, {"letter": "B", "text": "侮辱他人"}, {"letter": "C", "text": "妨碍公务罪"}, {"letter": "D", "text": "阻碍执行职务"}], "answer": "D", "explanation": "赵某因闯红灯被交警查处后大声谩骂民警，属于以非暴力方式阻碍国家机关工作人员依法执行职务，构成阻碍执行职务的治安违法行为。其行为未达到暴力袭击的程度，不构成袭警罪；也未使用暴力、威胁方法，不构成妨害公务罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 258}, {"num": 260, "batch": "专业基础知识", "type": "single", "stem": "市公安局特警支队民警小王负责3号国际馆的秩序维持，根据《公安机关人民警察盘查规范》，小王在工作中对可疑人员进行人身检查的说法中错误的是（）。", "options": [{"letter": "A", "text": "对女性的人身检查应由女性工作人员进行"}, {"letter": "B", "text": "不得对双腿内侧等敏感部位进行检查"}, {"letter": "C", "text": "检查时应当人物分离进行检查"}, {"letter": "D", "text": "对拒绝检查的人员应带至警务室进行检查"}], "answer": "B", "explanation": "根据《公安机关人民警察盘查规范》，对可疑人员进行人身检查时，应当对可疑人员的身体及携带物品进行全面检查，包括可能藏匿危险物品的部位。选项B称'不得对双腿内侧等敏感部位进行检查'不符合规定，人身检查应当全面彻底。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 259}, {"num": 261, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）2023年12月20日22时许，天空正下着小雨，派出所民警小李和小王在鸿雁海岸风景区巡逻时，发现一满身酒气的男子在海边睡觉，鼾声很大。民警小李和小王以下做法恰当的是（）。", "options": [{"letter": "A", "text": "记录该情况后，继续巡逻"}, {"letter": "B", "text": "守在其身边，待其酒醒"}, {"letter": "C", "text": "对其使用约束带，强制带离"}, {"letter": "D", "text": "尝试叫醒该男子，予以救助"}], "answer": "D", "explanation": "民警发现醉酒男子在海边睡觉，存在安全隐患（如下雨、涨潮等）。民警应当尝试叫醒该男子，了解情况并予以救助，确保其人身安全。仅记录情况后继续巡逻或守候在其身边均不够积极，使用约束带强制带离则处置过度。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 260}, {"num": 262, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）某市公安局为生动展示该局民警带着深厚感情为人民群众服务的时代风采，要求各分局报送本单位民警相关材料，以便汇编专题工作简报。下列材料不宜在专题工作简报编发的是（）", "options": [{"letter": "A", "text": "民警甲驾车将流浪人员安全送往救助站"}, {"letter": "B", "text": "民警乙不辞辛苦终使寻亲老人姐妹团聚"}, {"letter": "C", "text": "民警丙百般呵护帮助走失儿童重回父母怀抱"}, {"letter": "D", "text": "民警丁细心照料醉酒人员使其免受意外伤害"}], "answer": "D", "explanation": "专题工作简报的主题是展示民警'带着深厚感情为人民群众服务'的时代风采。选项A、B、C分别体现了救助流浪人员、帮助寻亲、呵护走失儿童等典型服务群众事迹。选项D细心照料醉酒人员虽属正常工作，但醉酒人员不属于需要特殊服务帮助的群众典型，不宜作为专题材料编发。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 261}, {"num": 263, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）为了促进行政案件繁简分流，2019年1月1日施行的《公安机关办理行政案件程序规定》增加了轻微行政案件快速办理的相关内容。以下可以适用快速办理的案件是（）。", "options": [{"letter": "A", "text": "无业人员段某吸食毒品案"}, {"letter": "B", "text": "聋哑人张某偷开他人机动车案"}, {"letter": "C", "text": "退休人员孔某制造噪声干扰他人生活，经有关部门劝阻后仍继续干扰案"}, {"letter": "D", "text": "疑似精神病人刘某扰乱公共场所秩序案"}], "answer": "C", "explanation": "根据《公安机关办理行政案件程序规定》，快速办理不适用于涉及未成年人、疑似精神病人、涉毒案件等情形。选项A涉及吸毒，选项B涉及聋哑人，选项D涉及疑似精神病人，均不适用快速办理。选项C退休人员制造噪声干扰他人生活，可以适用快速办理。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 262}, {"num": 264, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）韩某是新城区公安局新来的一名民警，韩某虚心学习，并常向其他民警请教，经过6个多月的观察学习，了解到其他民警的执法行为，下列关于其他民警执法行为，正确的是（）。", "options": [{"letter": "A", "text": "13周岁的周某违反治安管理规定，民警朱某、李某对其应当从轻处罚"}, {"letter": "B", "text": "孙某因醉酒违反治安管理规定，民警朱某、李某对其从重处罚"}, {"letter": "C", "text": "王某两次违反治安管理规定，都被处以拘留，合并执行，期限为25日"}, {"letter": "D", "text": "聋哑人李某违反治安管理，民警对其可以不予处罚"}], "answer": "D", "explanation": "根据《治安管理处罚法》第十四条规定，盲人或者又聋又哑的人违反治安管理的，可以从轻、减轻或者不予处罚。选项D表述正确。13周岁的人违反治安管理不予处罚而非从轻处罚；醉酒的人违反治安管理应当处罚而非从重；合并执行拘留最长不超过20日。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 263}, {"num": 265, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）白某听说罂粟壳熬水喂食肉鸡可防其生病，遂在菜地种植罂粟400株，后得知种罂粟是违法犯罪行为，于是在成熟前自行全部铲除，关于对白某的处理，下列说法正确的是（）。", "options": [{"letter": "A", "text": "应当追究刑事责任"}, {"letter": "B", "text": "应当予以治安处罚"}, {"letter": "C", "text": "可以依法从轻处罚"}, {"letter": "D", "text": "应当依法不予处罚"}], "answer": "D", "explanation": "根据《治安管理处罚法》第七十一条规定，非法种植罂粟不满五百株的，处十日以上十五日以下拘留，可以并处三千元以下罚款。但在成熟前自行铲除的，不予处罚。白某种植400株罂粟但在成熟前自行全部铲除，依法不予处罚。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 264}, {"num": 266, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）李某（17岁）因陈某学习成绩一直比自己好而心生嫉妒，借故殴打陈某并致其轻微伤。陈某报警，公安机关受理了案件，以下关于本案处理说法正确的是（）", "options": [{"letter": "A", "text": "殴打他人不适用调解结案，该案不能调解处理"}, {"letter": "B", "text": "因李某系未成年人，故对其可以不予处罚，责令监护人严加管教"}, {"letter": "C", "text": "如果李某系初次违反治安管理，且无违法犯罪记录，则对李某给予的行政拘留处罚应不予执行"}, {"letter": "D", "text": "因联系不上李某的父亲，公安机关可马上询问李某"}], "answer": "C", "explanation": "根据《治安管理处罚法》第二十一条规定，已满十六周岁不满十八周岁的人初次违反治安管理的，依照本法应当给予行政拘留处罚的，不执行行政拘留处罚。李某17岁，若系初次违反治安管理，行政拘留不予执行。询问未成年人时应当通知监护人到场。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 265}, {"num": 267, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）社会青年刘某（男，23周岁）、李某（男，13周岁）和王某（男，15周岁）到小店吃饭，结账时与店主发生争执，三人殴打店主致其轻微伤。下列说法正确的是（）。", "options": [{"letter": "A", "text": "对三人均作出行政拘留处罚决定并执行"}, {"letter": "B", "text": "对刘某作出行政拘留处罚决定但不执行"}, {"letter": "C", "text": "对王某作出行政拘留处罚决定但不执行"}, {"letter": "D", "text": "对李某作出行政拘留处罚决定但不执行"}], "answer": "C", "explanation": "根据《治安管理处罚法》第二十一条规定，已满十四周岁不满十六周岁的，以及已满十六周岁不满十八周岁初次违反治安管理的，不执行行政拘留。刘某23周岁应正常执行；李某13周岁不满14周岁不予处罚；王某15周岁应作出拘留决定但不执行。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 266}, {"num": 268, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）甲县公安局某派出所民警钱某在办理一起治安案件时，隐匿了与一方当事人的亲属关系，并作出了不公正的处罚决定，下列说法错误的是（）", "options": [{"letter": "A", "text": "另一方当事人或者其法定代理人有权要求钱某回避"}, {"letter": "B", "text": "当事人对处罚结果不服的，可以向甲县公安局申请复议"}, {"letter": "C", "text": "上级公安机关发现本案处罚决定有错误的，应当予以撤销或者变更"}, {"letter": "D", "text": "当事人对钱某的违法违纪行为，有权向人民检察院、行政监察机关检举、控告"}], "answer": "B", "explanation": "根据《行政复议法》规定，对派出所作出的处罚决定不服的，可以向设立该派出所的公安机关（甲县公安局）或本级人民政府申请行政复议。选项B称'向甲县公安局申请复议'表述正确，但本题问的是错误说法。实际上，根据新修订的行政复议法，应向本级人民政府申请复议，故B表述有误。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 267}, {"num": 269, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）李某（15周岁）因盗窃被公安机关抓获。在公安机关调查时，发现其5个月前曾盗窃王某人民币800元。对于本案的处理，下列说法不正确的是（）。", "options": [{"letter": "A", "text": "李某6个月内两次实施盗窃行为，应从重处罚"}, {"letter": "B", "text": "对于李某盗窃所得的800元应当予以追缴，并在追缴后退还给王某"}, {"letter": "C", "text": "询问李某，应通知他的父母或其他监护人到场"}, {"letter": "D", "text": "李某虽未成年但有违法前科，不能从轻或减轻处罚"}], "answer": "D", "explanation": "根据《治安管理处罚法》规定，已满十四周岁不满十八周岁的人违反治安管理的，应当从轻或者减轻处罚。李某15周岁，无论是否有违法前科，都应当从轻或减轻处罚。选项D称'不能从轻或减轻处罚'表述错误。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 268}, {"num": 270, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）女交警张阿妹对多次违章的张某先后开出过10张罚单，此事在当地的微信圈中引起热议。据此推理，交警张阿妹执法活动存在的不足与下列哪一项最符合？（）", "options": [{"letter": "A", "text": "处罚力度不够"}, {"letter": "B", "text": "执法过程不规范"}, {"letter": "C", "text": "教育与处罚没有结合好"}, {"letter": "D", "text": "服务不主动"}], "answer": "C", "explanation": "女交警对多次违章的张某先后开出10张罚单，说明在执法过程中只注重处罚而忽视了教育引导。教育与处罚相结合是公安工作的基本政策，执法应当坚持教育在先、处罚在后，做到处罚与教育相结合。该执法活动的不足在于教育与处罚没有结合好。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 269}, {"num": 271, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）行政处罚是公安机关行使的重要执法权，处罚裁量是否合理、适当，直接影响当事人权益。根据合理性原则，民警在办理行政案件时，认为下列情形属于“情节较轻”的是（）", "options": [{"letter": "A", "text": "高某酒后无证驾驶摩托车"}, {"letter": "B", "text": "丁某多次参加结伙斗殴"}, {"letter": "C", "text": "同事小何与小张因琐事发生纠纷，相互殴打致双方轻微伤"}, {"letter": "D", "text": "房东李某明知租户梁某在出租屋赌博，派出所调查时故意隐瞒"}], "answer": "C", "explanation": "根据合理性原则，判断'情节较轻'应综合考虑行为动机、手段、后果等因素。同事之间因琐事纠纷相互殴打致双方轻微伤，属于民间纠纷引发、主观恶性较小、后果较轻的情形，可认定为'情节较轻'。酒后无证驾驶、多次结伙斗殴、明知赌博而隐瞒等均属情节较重。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 270}, {"num": 272, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）杨某喝醉酒之后，在饭店门口辱骂、拦截行人，并教唆钱某在饭店里散布发生火灾的谣言，扰乱了就餐秩序，对于该事件的处理，依据《治安管理处罚法》，下列说法错误的是（）", "options": [{"letter": "A", "text": "杨某有两种治安违法行为，处罚应当合并执行"}, {"letter": "B", "text": "杨某醉酒状态下违反治安管理，处罚可以看条件适当减轻"}, {"letter": "C", "text": "若杨某今年17岁，且是初犯，则不执行行政拘留处罚"}, {"letter": "D", "text": "对于杨某的处罚应当按照寻衅滋事和散布谣言两项违法行为处罚"}], "answer": "B", "explanation": "根据《治安管理处罚法》第十五条规定，醉酒的人违反治安管理的，应当给予处罚，不存在'可以适当减轻'的规定。选项B表述错误。杨某醉酒寻衅滋事并教唆他人散布谣言，应按两项违法行为分别决定合并执行。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 271}, {"num": 273, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）霍某认为同行彭某抢自己生意，多次发送“不要脸”等信息骚扰彭某，彭某警告霍某不要再发，否则报警，霍某仍继续发送，彭某报警，对霍某行为的定性，下列说法正确的是（）。", "options": [{"letter": "A", "text": "构成侮辱的违反治安管理行为"}, {"letter": "B", "text": "构成诽谤的违反治安管理行为"}, {"letter": "C", "text": "构成发送信息干扰正常生活的违反治安管理行为"}, {"letter": "D", "text": "不构成公安机关管辖的违法行为，属于民事侵权"}], "answer": "C", "explanation": "根据《治安管理处罚法》第四十二条规定，多次发送侮辱、恐吓或者其他信息，干扰他人正常生活的，构成发送信息干扰正常生活的违法行为。霍某多次发送'不要脸'等信息骚扰彭某，经警告后仍继续，符合该行为的构成要件。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 272}, {"num": 274, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）东关派出所接到群众举报称：有人在车库内赌博，民警处警后发现涉及赌资较少，应按《治安管理处罚法》对若干参与赌博人员进行处罚，下列依法应当执行行政拘留决定的是（）。", "options": [{"letter": "A", "text": "甲，年满17周岁，首次违反治安管理"}, {"letter": "B", "text": "乙，年满60周岁，抚养其未满一周岁的孙女"}, {"letter": "C", "text": "丙，75周岁，退休人员，失聪"}, {"letter": "D", "text": "丁，15周岁，高中肄业，整日游手好闲"}], "answer": "B", "explanation": "根据《治安管理处罚法》第二十一条规定，不执行行政拘留的情形包括：已满14周岁不满16周岁的；已满16周岁不满18周岁初次违反的；70周岁以上的等。甲17周岁首次违法不执行；丙75周岁不执行；丁15周岁不执行。乙60周岁抚养未满1周岁婴儿不属于法定不执行情形，应当执行。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 273}, {"num": 275, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）甲在某旅馆客房内吸食毒品后产生幻觉，将房间内的设施砸坏（价值1500元），该旅馆拨打110报警。甲清醒后主动认错、赔偿，并取得了旅馆谅解。公安机关的处理正确的是（）。", "options": [{"letter": "A", "text": "对甲砸坏房内设施的行为予以治安调解处理"}, {"letter": "B", "text": "对甲的吸毒行为和损毁财物行为择一重论处"}, {"letter": "C", "text": "对甲从轻、减轻或者不予处罚"}, {"letter": "D", "text": "对甲的吸毒用具予以收缴"}], "answer": "D", "explanation": "吸毒行为和损毁财物行为属于两种不同的违法行为，应分别决定合并执行，不能择一重论处，也不能进行治安调解。吸毒后产生幻觉砸坏财物不能从轻或减轻处罚。但甲的吸毒用具属于违禁品，依法应当予以收缴。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 274}, {"num": 276, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）派出所民警小王发现，辖区某旅馆前台工作人员张某对入住的旅客未按规定登记姓名、身份证件。根据《治安管理处罚法》的规定，应当对张某作出的处罚种类是：（）", "options": [{"letter": "A", "text": "警告"}, {"letter": "B", "text": "罚款"}, {"letter": "C", "text": "罚金"}, {"letter": "D", "text": "拘留"}], "answer": "B", "explanation": "根据《治安管理处罚法》第五十六条规定，旅馆业的工作人员对住宿的旅客不按规定登记姓名、身份证件种类和号码的，处二百元以上五百元以下罚款。因此对张某应当作出罚款处罚。罚金属于刑罚附加刑，不是治安管理处罚种类。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 275}, {"num": 277, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）根据民法规定，民事法律行为是民事主体通过意思表示设立、变更、终止民事法律关系的行为。下列行为属于公安机关民事法律行为的是（）", "options": [{"letter": "A", "text": "面向社会公开招录警务辅助人员"}, {"letter": "B", "text": "对因民间纠纷引起的违反治安管理行为进行调解"}, {"letter": "C", "text": "将查封的涉案财物委托第三人进行保管"}, {"letter": "D", "text": "对因公牺牲的人民警察家属开展优待抚恤工作"}], "answer": "C", "explanation": "民事法律行为是民事主体通过意思表示设立、变更、终止民事法律关系的行为。公安机关将查封的涉案财物委托第三人保管，属于平等主体之间的民事委托合同关系，是公安机关的民事法律行为。招录辅警属于人事管理行为，调解属于行政调解行为，优待抚恤属于行政给付行为。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 276}, {"num": 278, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）某球赛决赛现场，一些观众因对裁判判决不满而情绪激动，向对方球迷看台和场内投掷物品。从安全保护的角度来看，公安机关下列处置方式较为妥当的是：（）", "options": [{"letter": "A", "text": "组织安保志愿者进行疏导劝阻"}, {"letter": "B", "text": "暂不带离现场，由民警对其进行警告和深刻的批评教育"}, {"letter": "C", "text": "若行为人拒不服从劝阻警告继续扰乱活动现场秩序，应迅速将挑头闹事人员带离现场至治安处理点审查处理"}, {"letter": "D", "text": "迅速调集防暴警力进行现场武装震慑"}], "answer": "C", "explanation": "球赛现场观众投掷物品扰乱秩序，从安全保护角度，应先进行劝阻警告；若拒不服从，应迅速将挑头闹事人员带离现场至治安处理点审查处理，避免事态扩大。组织安保志愿者疏导劝阻力度不够，武装震慑则过度使用警力。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 277}, {"num": 279, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）邹某为方便找工作，购买一张伪造的某知名高校毕业证书，并持该伪造的毕业证书到某公司应聘。对于邹某行为的定性，下列认定正确的是（）。", "options": [{"letter": "A", "text": "构成伪造事业单位印章罪"}, {"letter": "B", "text": "构成买卖国家机关证明文件罪"}, {"letter": "C", "text": "构成违反治安管理的违法行为"}, {"letter": "D", "text": "不构成公安机关管辖的违法犯罪"}], "answer": "C", "explanation": "购买伪造的高校毕业证书并使用，属于买卖或使用伪造的事业单位证明文件的行为，构成违反治安管理的违法行为。邹某购买而非伪造，不构成伪造事业单位印章罪；高校毕业证书属于事业单位证明文件而非国家机关证明文件。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 278}, {"num": 280, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）根据《中华人民共和国人民警察法》及《中华人民共和国治安管理处罚法》的规定，下列情形中民警的执法行为正确的是（）。", "options": [{"letter": "A", "text": "派出所民警小李接到有人打架的报警时因正在处理其他警情，派出辅警处警"}, {"letter": "B", "text": "派出所民警小程在办理一起盗窃案件时，因对赃物价格鉴证所需要时间较长未能即时归还被侵害人，遭到被侵害人投诉"}, {"letter": "C", "text": "派出所民警小张抓获一个惯偷，嫌疑人拒不交代违法事实，小张遂不给嫌疑人喝水，最终嫌疑人交代了盗窃事实"}, {"letter": "D", "text": "派出所民警老郑对王某当场收缴罚款，并出具了所在公安局制发的罚款收据"}], "answer": "B", "explanation": "选项A错误，处警应由民警执行，不能仅派辅警；选项C错误，不给嫌疑人喝水属于变相体罚，严禁逼供信；选项D错误，当场收缴罚款应出具省级财政部门统一制发的罚款收据。选项B正确，因鉴定时间较长导致赃物未能即时归还，不属于民警过错，被侵害人投诉不成立。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 279}, {"num": 281, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）姜某因故意损坏名胜古迹，被B市C区公安分局滨湖派出所处以200元罚款。姜某不服处罚，申请行政复议。行政复议的被申请人应当是（）。", "options": [{"letter": "A", "text": "滨湖派出所"}, {"letter": "B", "text": "C区公安分局"}, {"letter": "C", "text": "C区人民政府"}, {"letter": "D", "text": "B市公安局"}], "answer": "A", "explanation": "根据《行政复议法》规定，对政府工作部门依法设立的派出机构依照法律、法规或者规章规定，以自己的名义作出的行政行为不服的，该派出机构为被申请人。滨湖派出所作为C区公安分局的派出机构，以自己名义作出200元罚款处罚，因此被申请人为滨湖派出所。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 280}, {"num": 282, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）李某长期酗酒，醉酒后时常对其妻子王某进行打骂。某日，李某醉酒后再次辱骂殴打王某，王某拨打了110报警。公安机关接到王某报警后，处置不恰当的是（）。", "options": [{"letter": "A", "text": "及时出警，制止李某家暴行为"}, {"letter": "B", "text": "处置时，应当尊重王某真实意愿"}, {"letter": "C", "text": "协助王某就医"}, {"letter": "D", "text": "作出人身安全保护令"}], "answer": "D", "explanation": "根据《反家庭暴力法》规定，人身安全保护令由人民法院作出，公安机关无权作出人身安全保护令。公安机关在处置家暴警情时应当及时出警制止家暴、尊重受害人真实意愿、协助受害人就医等，但作出人身安全保护令不属于公安机关的职权范围。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 281}, {"num": 283, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）小刚今年15岁，父母外出打工，由年迈的爷爷照顾。为了能够在网吧打游戏，偷走了邻居大爷的手机，价值500元，案发后，小刚被带到派出所。关于此案，下列说法错误的是（）。", "options": [{"letter": "A", "text": "小刚还没满十六岁，对小刚的违法行为，应不予处置"}, {"letter": "B", "text": "对小刚询问时，应当通知其爷爷到场"}, {"letter": "C", "text": "对小刚询问时，如果爷爷不能到场，可以通知其老师到场"}, {"letter": "D", "text": "老大爷的损失应由小刚的父母赔偿"}], "answer": "A", "explanation": "根据《治安管理处罚法》规定，已满十四周岁不满十八周岁的人违反治安管理的，应当给予处罚，只是应当从轻或者减轻处罚。小刚15周岁，已达到治安处罚的年龄，应当依法处理，不能因其未满十六岁就不予处置。选项A表述错误。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 282}, {"num": 284, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）依据《治安管理处罚法》，在办理治安案件中，下列关于检查的表述错误的是（）。", "options": [{"letter": "A", "text": "检查时办案民警不得少于2人"}, {"letter": "B", "text": "检查必须要有见证人在场，没有见证人不得进行检查"}, {"letter": "C", "text": "检查的情况应制作检查笔录，并由检查人、被检查人或者见证人签名或盖章"}, {"letter": "D", "text": "检查妇女的身体应当由女性工作人员或者医师进行"}], "answer": "C", "explanation": "根据《治安管理处罚法》第八十七条规定，检查的情况应当制作检查笔录，由检查人、被检查人和见证人签名或者盖章。选项C将'和'改为'或者'，降低了签名要求，表述有误。检查时办案民警不得少于2人，检查妇女身体应由女性工作人员进行，这些表述均正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 283}, {"num": 285, "batch": "专业基础知识", "type": "single", "stem": "某地公安机关通过信息研判发现，社会上流传着近日要发生7.8级地震的消息。经向有关部门了解，确定该消息为谣言。但是群众对此议论纷纷，甚至有人准备晚上住在帐篷里。经公安机关调查走访和搜索网络信息来源，锁定了张某是该谣言的散布者。根据《治安管理处罚法》的规定，张某散布地震谣言已构成的违法行为是（）。", "options": [{"letter": "A", "text": "谎报险情危害公共安全"}, {"letter": "B", "text": "谎报险情扰乱社会秩序"}, {"letter": "C", "text": "虚构事实扰乱公共秩序"}, {"letter": "D", "text": "虚构事实扰乱公共安全"}], "answer": "C", "explanation": "根据《治安管理处罚法》第二十五条规定，散布谣言，谎报险情、疫情、警情或者以其他方法故意扰乱公共秩序的，予以治安处罚。张某散布地震谣言属于虚构事实扰乱公共秩序的行为。地震谣言并非真实的险情信息，因此属于虚构事实而非谎报险情。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 284}, {"num": 286, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）在办理行政案件的过程中存在以下情况，其中作出从轻、减轻处罚或不予处罚的是（）。", "options": [{"letter": "A", "text": "甲主动消除违法后果，得到被侵害人原谅"}, {"letter": "B", "text": "乙在案发后主动前往公安机关投案，但隐瞒部分违法事实"}, {"letter": "C", "text": "失聪的丙因感觉他人在身后嘲笑自己，对过往路人大打出手"}, {"letter": "D", "text": "未成年人丁（13岁）在醉酒后为“练胆”实施盗窃，被公安机关抓获"}], "answer": "A", "explanation": "根据《治安管理处罚法》第十九条规定，主动消除或者减轻违法后果并取得被侵害人谅解的，可以从轻、减轻或者不予处罚。选项A中甲主动消除违法后果并得到原谅，符合法定从轻、减轻或不予处罚的条件。乙投案但隐瞒事实不符合主动投案的条件。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 285}, {"num": 287, "batch": "专业基础知识", "type": "single", "stem": "30岁的自由职业者黄某与明星周某积怨已久，经常在网上发文互爆对方“违法乱纪”。一日黄某在网络上公开发文声称：“周某与当地甲派出所勾结，该派出所所长已被周某买通，充当周某这个黑恶分子的保护伞。”该文被广泛传播，引起了相关纪委监委重视。经调查，该文所称之事子虚乌有，对此，有关部门对黄某作出行政拘留五日的处罚决定。关于上述情景，下列说法错误的是（）", "options": [{"letter": "A", "text": "作出行政拘留处罚决定前黄某有申辩权"}, {"letter": "B", "text": "应当制作行政处罚决定书"}, {"letter": "C", "text": "该行政拘留处罚可由甲派出所决定"}, {"letter": "D", "text": "应当及时将处罚情况和执行场所通知黄某家属"}], "answer": "C", "explanation": "根据《治安管理处罚法》第九十一条规定，治安管理处罚由县级以上人民政府公安机关决定；其中警告、五百元以下的罚款可以由公安派出所决定。行政拘留必须由县级以上公安机关决定，派出所无权决定。选项C称'可由甲派出所决定'表述错误。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 286}, {"num": 288, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）依照《治安处罚法》的规定，下列违反治安管理行为中应从重给予治安处罚的是（）", "options": [{"letter": "A", "text": "张某冒充医生招摇撞骗"}, {"letter": "B", "text": "王某冒充法院院长招摇撞骗"}, {"letter": "C", "text": "张某冒充公安民警招摇撞骗"}, {"letter": "D", "text": "赵某冒充记者招摇撞骗"}], "answer": "C", "explanation": "根据《治安管理处罚法》第五十一条规定，冒充国家机关工作人员或者以其他虚假身份招摇撞骗的，予以治安处罚。冒充军警人员招摇撞骗的，从重处罚。公安民警属于军警人员，冒充公安民警招摇撞骗应从重处罚。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 287}, {"num": 289, "batch": "专业基础知识", "type": "single", "stem": "吴某和赵某为广安小区10号楼一单元的3楼的邻居，两家门对门共用一个电梯厅。近期，吴某因不满赵某将私人物品堆放在公共通道，与其发生多次争执。物业劝导赵某后，赵某仍我行我素。某日早上，赵某又将废纸壳堆在了电梯厅内，下夜班回家的吴某正好看到，便斥责赵某不讲公德，赵某一气之下，跑回家拿出开水泼向吴某。吴某丈夫听到呼喊声后立即开门，见到吴某抱着左小臂大叫，便与赵某对骂起来，赵某丈夫、女儿、女婿也闻声而来。两家人撕扯在一起，吴某13岁的女儿拨打了报警电话。民警小孙、小边接到处警指令后立即赶赴现场，到场后二人看到两家人正在撕扯对骂，引来同楼居民围观，场面十分混乱。对此，民警首先要做的是（）。", "options": [{"letter": "A", "text": "疏散围观的邻居"}, {"letter": "B", "text": "询问当事人事情经过"}, {"letter": "C", "text": "打开执法记录仪"}, {"letter": "D", "text": "制止对骂的双方"}], "answer": "C", "explanation": "民警到达现场后，首先应当打开执法记录仪对现场情况进行全程录音录像，固定证据。这是规范执法的基本要求，也是后续处理的重要证据保障。在执法记录仪开启后再进行疏散围观群众、制止对骂、询问当事人等工作。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 288}, {"num": 290, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）下列行为中未达到刑事追诉标准，可以由公安机关予以行政处罚的是（）。", "options": [{"letter": "A", "text": "童某无证行医"}, {"letter": "B", "text": "曹某偷逃税款"}, {"letter": "C", "text": "吕某故意伤害"}, {"letter": "D", "text": "董某销售劣药"}], "answer": "C", "explanation": "故意伤害行为未达到刑事追诉标准（轻伤以上）的，属于治安违法行为，可由公安机关依据《治安管理处罚法》予以行政处罚。无证行医、偷逃税款、销售劣药分别由卫生行政部门、税务部门、药品监管部门主管，不属于公安机关治安管理的直接管辖范围。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 289}, {"num": 291, "batch": "专业基础知识", "type": "single", "stem": "村民甲认为村民乙翻盖房屋时侵占了自家宅基地。甲多次到工地阻挠施工。乙与甲多次协商未果，两家互不相让，矛盾日益尖锐。甲乙再次因为边界问题发生肢体冲突互致轻微伤，民警做法不正确的是（）。", "options": [{"letter": "A", "text": "民警可以对甲乙二人的违法行为进行调解"}, {"letter": "B", "text": "民警调解的内容包括宅基地边界纠纷"}, {"letter": "C", "text": "邀请村委会成员参与到调解中来"}, {"letter": "D", "text": "第一次调解失败后，按照甲乙申请再次调解，民警再次组织调解"}], "answer": "B", "explanation": "治安调解的内容限于因民间纠纷引起的违反治安管理行为，不包括民事纠纷本身。宅基地边界纠纷属于民事争议，不属于治安调解的范围，民警可以引导当事人通过协商、调解或诉讼等途径解决。选项B将宅基地边界纠纷纳入调解内容，表述错误。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 290}, {"num": 292, "batch": "专业基础知识", "type": "single", "stem": "（根据新治安法修订）蔡某女儿被夏某家的宠物犬咬成轻微伤，蔡某报警要求处罚夏某并赔偿其女儿医药费、精神损失费，双方均不同意调解。下列属于派出所正确的做法是（）。", "options": [{"letter": "A", "text": "裁决夏某赔偿蔡某女儿的全部损失"}, {"letter": "B", "text": "告知蔡某就赔偿问题向人民法院提起民事诉讼"}, {"letter": "C", "text": "裁决夏某赔偿医药费，告知蔡某就精神损失费提起民事诉讼"}, {"letter": "D", "text": "责令夏某赔偿医药费，告知蔡某就精神损失费提起民事诉讼"}], "answer": "B", "explanation": "双方均不同意调解的，公安机关不能强制调解。对于夏某饲养动物致人伤害的行为，公安机关应依法对夏某作出治安处罚，但对于赔偿问题，公安机关无权裁决，应当告知蔡某就赔偿问题向人民法院提起民事诉讼。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 291}, {"num": 293, "batch": "专业基础知识", "type": "single", "stem": "3月5日9时20分，甲市东风路派出所接到市公安局指挥中心指令，在地铁2号线东风公园站1号出入口有人设置灵台、摆放花圈、焚烧纸钱，参与人员5人左右，暂无过激行为，请立即安排警力前往处置。派出所李所长率民警小张、小周出警，迅速到达现场。先期赶到现场的轨道交通公司相关负责人黄某向李所长介绍：3月3日下午，乘客王某乘坐地铁被夹在屏蔽门和列车之间，列车启动后遭挤压身亡。王某家属与轨道交通公司因未达成赔偿协议，遂采取上述行为。地铁出入口被堵，围观群众聚集，有人拿出手机进行拍摄。对于该类未影响民警执法的行为，此时现场民警恰当的做法是（）", "options": [{"letter": "A", "text": "告知拍摄者不得断章取义传播拍摄资料"}, {"letter": "B", "text": "要求拍摄者删除相关拍摄资料"}, {"letter": "C", "text": "没收拍摄者手机"}, {"letter": "D", "text": "将拍摄者强行带离现场"}], "answer": "A", "explanation": "群众对执法活动进行拍摄但未影响民警执法的，民警不得要求删除拍摄资料、没收手机或将拍摄者带离现场。但民警可以告知拍摄者不得断章取义传播拍摄资料，以维护执法形象和当事人合法权益。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 292}, {"num": 294, "batch": "专业基础知识", "type": "single", "stem": "某县公安局向人民检察院移送审查起诉的下列案件，可以向人民检察院提出适用速裁程序建议的是（）。", "options": [{"letter": "A", "text": "间歇性精神病人甲在发病期间将同村村民刺成轻伤"}, {"letter": "B", "text": "乙醉酒驾驶机动车被交警查获，一年前曾因危险驾驶被判处拘役1个月"}, {"letter": "C", "text": "17周岁的丙敲诈勒索了他人1万元"}, {"letter": "D", "text": "丁犯交通肇事罪后认罪认罚，但被害人近亲属提出的附带民事诉讼赔偿未达成和解"}], "answer": "B", "explanation": "根据《刑事诉讼法》关于速裁程序的规定，适用速裁程序要求案件事实清楚、证据确实充分，被告人认罪认罚并同意适用速裁程序。但盲聋哑人、精神病人、未成年人等不适用速裁程序。选项B中乙系成年人，危险驾驶认罪认罚，可以建议适用速裁程序。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 293}, {"num": 295, "batch": "专业基础知识", "type": "single", "stem": "某县公安机关立案侦查邝某涉嫌利用未公开信息交易实施犯罪，需要冻结其名下数额较大的债券、股票等财产，实施该冻结措施应当经（）批准。", "options": [{"letter": "A", "text": "当地证监管理机构负责人"}, {"letter": "B", "text": "该县公安机关办案部门负责人"}, {"letter": "C", "text": "上级公安机关法制部门负责人"}, {"letter": "D", "text": "该县公安机关负责人"}], "answer": "D", "explanation": "根据《公安机关办理刑事案件程序规定》，冻结犯罪嫌疑人存款、汇款、债券、股票、基金份额等财产的，应当经县级以上公安机关负责人批准。因此冻结邝某名下的债券、股票等财产应经该县公安机关负责人批准。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 294}, {"num": 296, "batch": "专业基础知识", "type": "single", "stem": "楚元市公安局决定将居住在宏武县的犯罪嫌疑人肖×刑事拘留，发现肖×为该市光阳县兴平乡的人大代表，根据相关法律法规，肖x被执行刑事拘留后，楚元市公安局下列做法正确的是（）。", "options": [{"letter": "A", "text": "立即报告宏武县人民代表大会"}, {"letter": "B", "text": "立即报告楚元市人民代表大会"}, {"letter": "C", "text": "立即报告光阳县人民代表大会"}, {"letter": "D", "text": "立即报告兴平乡人民代表大会"}], "answer": "D", "explanation": "根据《公安机关办理刑事案件程序规定》，公安机关对县级以上人民代表大会代表采取刑事拘留措施的，应当立即向该代表所属的人民代表大会报告。肖×为兴平乡的人大代表，因此应当向兴平乡人民代表大会报告。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 295}, {"num": 297, "batch": "专业基础知识", "type": "single", "stem": "近期儋州发生多起刑事案件，下列案件中公安机关应当依职权主动提供人身保护的是（）。", "options": [{"letter": "A", "text": "故意伤害案中犯罪嫌疑人不断叫嚣报复受害人"}, {"letter": "B", "text": "黑社会性质犯罪案件中被判死刑的犯罪嫌疑人家属声称要对受害人女友报复"}, {"letter": "C", "text": "毒贩张某听说李某准备要举报自己，让人传话若李某举报则对其下手"}, {"letter": "D", "text": "毒贩王某被抓住后让律师告知小弟将证人赵某杀死"}], "answer": "D", "explanation": "根据相关规定，公安机关应当对面临人身危险的证人、鉴定人及其近亲属提供人身保护。选项D中毒贩王某被抓后指使他人威胁杀死证人赵某，赵某面临现实的人身危险，公安机关应当主动提供人身保护。其他选项中的威胁尚不够现实和紧迫。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 296}, {"num": 298, "batch": "专业基础知识", "type": "single", "stem": "讯问是公安机关为了收集证据，查明案情而对犯罪嫌疑人所进行的查问。讯问期间下列做法正确的是（）。", "options": [{"letter": "A", "text": "为了突破犯罪嫌疑人心里防线，昼夜不停对其开展讯问"}, {"letter": "B", "text": "讯问过程中，民警小刘因公事离开办案区接打电话，留小张一人进行讯问"}, {"letter": "C", "text": "讯问期间，对民警提出的问题，犯罪嫌疑人都应该回答"}, {"letter": "D", "text": "讯问结束后，讯问笔录交由犯罪嫌疑人核对，并在笔录逐页签名和捺指印"}], "answer": "D", "explanation": "根据《刑事诉讼法》和《公安机关办理刑事案件程序规定》，讯问结束后，讯问笔录应当交犯罪嫌疑人核对，确认无误后逐页签名并捺指印。昼夜不停讯问属于疲劳审讯，一人讯问不符合两人以上讯问的要求，嫌疑人对与案件无关的问题有权拒绝回答。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 297}, {"num": 299, "batch": "专业基础知识", "type": "single", "stem": "王某（女，24岁）在商场盗窃价值2500元的名酒一瓶，被商场保安当场抓获并扭送至公安机关，民警随即开展讯问工作，关于讯问工作下列说法正确的是（）。", "options": [{"letter": "A", "text": "王某要求自己书写供述，民警可以拒绝"}, {"letter": "B", "text": "民警告知王某可以请律师"}, {"letter": "C", "text": "讯问王某应当对讯问过程进行录音录像"}, {"letter": "D", "text": "讯问王某可以在派出所民警办公室进行"}], "answer": "B", "explanation": "根据《刑事诉讼法》规定，犯罪嫌疑人在被侦查机关第一次讯问或者采取强制措施之日起，有权委托辩护人。民警应当告知王某可以请律师。犯罪嫌疑人有权自行书写供述，讯问应当在办案区进行，对可能判处无期徒刑、死刑的案件或其他重大犯罪案件应当录音录像，盗窃案不属于必须录音录像的情形。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 298}, {"num": 300, "batch": "专业基础知识", "type": "single", "stem": "朱×因涉嫌组织参与国（境）外赌博罪被南江市公安局立案侦查，刑事拘留期满后因证据不足变更为取保候审，由朱×户籍所在地南江市公安局南华派出所执行。根据法律规定，南华派出所执行过程中可以要求朱×的是（）。", "options": [{"letter": "A", "text": "不得驾驶机动车"}, {"letter": "B", "text": "将居民身份证交派出所保存"}, {"letter": "C", "text": "未经批准不得会见他人"}, {"letter": "D", "text": "未经批准不得离开居所"}], "answer": "A", "explanation": "根据《刑事诉讼法》第七十一条关于取保候审的规定，被取保候审人可以责令遵守以下规定：未经批准不得离开所居住的市、县；住址、工作单位和联系方式发生变动的在二十四小时以内报告；未经批准不得会见他人或者通信；将护照等出入境证件、驾驶证件交执行机关保存等。不得驾驶机动车属于可以要求遵守的规定。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 299}, {"num": 301, "batch": "专业基础知识", "type": "single", "stem": "犯罪嫌疑人王某在实施抢劫时被当场抓获并被刑事拘留，后被逮捕，但王某始终不讲自己的真实姓名、住址，其侦查羁押期限应当从（）。", "options": [{"letter": "A", "text": "拘留之日起计算"}, {"letter": "B", "text": "逮捕之日起计算"}, {"letter": "C", "text": "查清其身份之日起计算"}, {"letter": "D", "text": "查清其全部犯罪事实之日起计算"}], "answer": "C", "explanation": "根据《刑事诉讼法》第一百六十条规定，犯罪嫌疑人不讲真实姓名、住址，身份不明的，侦查羁押期限自查清其身份之日起计算。这是为了防止犯罪嫌疑人通过隐瞒身份来拖延诉讼进程，同时也保障其合法权利。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 300}, {"num": 302, "batch": "专业基础知识", "type": "single", "stem": "某县公安机关在办理一起刑事案件时，发现公安机关负责人甲、侦查民警乙、按照要求均需回避，有权决定他们回避的单位说法正确的是（）。", "options": [{"letter": "A", "text": "甲的回避由上一级公安机关决定"}, {"letter": "B", "text": "乙的回避由上一级公安机关负责人决定"}, {"letter": "C", "text": "甲的回避由同级县人民检察委员会决定"}, {"letter": "D", "text": "乙的回避由其所属公安机关决定"}], "answer": "C", "explanation": "根据《刑事诉讼法》第三十一条规定，公安机关负责人的回避，由同级人民检察院检察委员会决定；侦查人员的回避，由所属公安机关决定。因此甲作为公安机关负责人，其回避由同级县人民检察院检察委员会决定，选项C正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 301}, {"num": 303, "batch": "专业基础知识", "type": "single", "stem": "民警夜晚巡逻时，见一头戴鸭舌帽面带口罩的男子从院墙上跳下，形迹可疑，经盘问，该男子（何某）称其到女子吴某家强奸了吴某，民警将何某带回警局后，依法通知了吴某，下列对何某、吴某进行人身检查时的说法，正确的是（）。", "options": [{"letter": "A", "text": "检查吴某的身体，应由女工作人员或者医师进行"}, {"letter": "B", "text": "何某、吴某不同意检查时，可以强制检查"}, {"letter": "C", "text": "检查的情况应当制作笔录，由参加检查的检查人员、被检查人员签名"}, {"letter": "D", "text": "何某、吴某拒绝签名的，侦查人员不需在笔录中注明"}], "answer": "A", "explanation": "根据《刑事诉讼法》第一百三十二条规定，检查妇女的身体，应当由女工作人员或者医师进行。本案中吴某为女性，对其人身检查必须由女工作人员或医师进行，以保护其人格尊严和隐私权。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 302}, {"num": 304, "batch": "专业基础知识", "type": "single", "stem": "公安机关办理戴某盗窃电动车案件时，不同目击证人需要对其进行辨认，下列对辨认的做法正确的是（）。", "options": [{"letter": "A", "text": "同时将2名目击证人带到辨认室对15人进行辨认"}, {"letter": "B", "text": "将犯罪嫌疑人的照片2张和8张其他人的照片进行辨认"}, {"letter": "C", "text": "几名辨认人对同一辨认对象进行分别辨认时，被辨认人保持不变"}, {"letter": "D", "text": "辨认人不愿意公开进行辨认时，可以不用在辨认笔录上签字"}], "answer": "C", "explanation": "根据《公安机关办理刑事案件程序规定》关于辨认的规则，几名辨认人对同一辨认对象进行辨认时，应当分别单独进行，被辨认人（或照片）保持不变，以避免辨认人之间相互影响，保证辨认结果的客观性和可靠性。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 303}, {"num": 305, "batch": "专业基础知识", "type": "single", "stem": "关某因涉嫌抢劫罪被公安机关依法逮捕，经过公安机关侦查，关某犯罪事实清楚，证据确凿。在移送审查起诉之前，关某突发心脏病猝死，对于该案应如何处理？（）", "options": [{"letter": "A", "text": "撤销案件"}, {"letter": "B", "text": "终止侦查"}, {"letter": "C", "text": "终止审理"}, {"letter": "D", "text": "不起诉"}], "answer": "A", "explanation": "根据《刑事诉讼法》第十六条规定，犯罪嫌疑人、被告人死亡的，不追究刑事责任。在侦查阶段，应当撤销案件。关某在移送审查起诉前死亡，公安机关应作出撤销案件的决定。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 304}, {"num": 306, "batch": "专业基础知识", "type": "single", "stem": "2021年8月24日，A省公安厅禁毒总队得到一条需要紧急核查的线索，当日，由云南芒市飞往A省的航班上有一名上网追逃的旅客陈某（女），可能携带毒品和凶器，飞机降落后，两名民警立即上飞机将陈某带离。民警对陈某拘留时展开了搜查工作，下列说法正确的是（）。", "options": [{"letter": "A", "text": "对陈某进行搜查，必须出示搜查证"}, {"letter": "B", "text": "紧急情况下，两名男性侦查人员可以搜查陈某的身体"}, {"letter": "C", "text": "搜查可以无见证人在场"}, {"letter": "D", "text": "搜查的情况应当制作笔录"}], "answer": "D", "explanation": "根据《刑事诉讼法》第一百三十八条规定，搜查的情况应当制作笔录，由侦查人员和被搜查人或者其家属、邻居或者其他见证人签名或盖章。搜查笔录是法定必须制作的法律文书，D项正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 305}, {"num": 307, "batch": "专业基础知识", "type": "single", "stem": "2024年1月27日18时，在由成东市始发，终到辽西市的K456次列车上倪某因行迹可疑引起民警注意，倪某感觉到不妙，在列车即将经停江河市准备跳车逃跑时，被民警查获。民警在其携带背包夹层中发现其在列车上盗得的现金2万元。经查倪某（男，28周岁），为平安市人，本案一般应由哪个公安机关管辖？（）", "options": [{"letter": "A", "text": "成东市铁路公安机关"}, {"letter": "B", "text": "辽西市铁路公安机关"}, {"letter": "C", "text": "江河市铁路公安机关"}, {"letter": "D", "text": "平安市铁路公安机关"}], "answer": "C", "explanation": "根据《公安机关办理刑事案件程序规定》及相关司法解释，在运行的列车上发生的刑事案件，一般由前方停靠站铁路公安机关管辖。本案中列车即将经停江河市，倪某在江河市被查获，故由江河市铁路公安机关管辖最为适宜。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 306}, {"num": 308, "batch": "专业基础知识", "type": "single", "stem": "民警小刘在办理一起强制猥亵案件中，于上午10时对犯罪嫌疑人王某执行拘传，王某于上午11时到达派出所到案受审，对于王某拘传的起止时间段下列说法正确的是（）。", "options": [{"letter": "A", "text": "10时到22时"}, {"letter": "B", "text": "11时到23时"}, {"letter": "C", "text": "10时到次日10时"}, {"letter": "D", "text": "11时到次日23时"}], "answer": "B", "explanation": "根据《刑事诉讼法》第一百一十九条规定，拘传持续的时间不得超过十二小时。拘传时间从犯罪嫌疑人到案时开始计算，王某11时到案，因此拘传时间为11时至23时，共12小时。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 307}, {"num": 309, "batch": "专业基础知识", "type": "single", "stem": "某派出所办理一起盗窃案，报案人王某称自己被盗的白酒价值2010元（当地盗窃罪案标准为2000元），但无法提供购买发票。嫌疑人唐X交待其将盗窃的白酒卖了1500元，对于被盗白酒的价格认定，符合法律规定的是（）。", "options": [{"letter": "A", "text": "根据王某的陈述认定"}, {"letter": "B", "text": "以唐X卖出白酒的价格认定"}, {"letter": "C", "text": "以办案民警对被盗白酒的市场调查认定"}, {"letter": "D", "text": "以公安机关委托价格鉴定机构出具的鉴定意见认定"}], "answer": "D", "explanation": "根据《公安机关办理刑事案件程序规定》及相关价格鉴定规定，被盗物品的价格认定应当以价格鉴定机构出具的鉴定意见为准，不能仅凭报案人陈述、嫌疑人销赃价格或民警自行调查来认定，以确保价格认定的客观性和公正性。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 308}, {"num": 310, "batch": "专业基础知识", "type": "single", "stem": "确定地区侦查管辖的一般原则：刑事案件由（）的公安机关管辖。", "options": [{"letter": "A", "text": "犯罪地"}, {"letter": "B", "text": "发案地"}, {"letter": "C", "text": "被害人居住地"}, {"letter": "D", "text": "犯罪嫌疑人居住地"}], "answer": "A", "explanation": "根据《刑事诉讼法》第二十五条规定，刑事案件由犯罪地的人民法院管辖。相应地，刑事案件由犯罪地的公安机关管辖，这是确定地区侦查管辖的一般原则。犯罪地包括犯罪行为发生地和犯罪结果发生地。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 309}, {"num": 311, "batch": "专业基础知识", "type": "single", "stem": "根据《刑事诉讼法》相关规定，下列刑事案件中，应当依法不追究刑事责任的情形不包括（）。", "options": [{"letter": "A", "text": "刘某盗窃，但情节显著轻微，危害不大，不认为是犯罪"}, {"letter": "B", "text": "胡某故意伤害，但已过追诉时效期限"}, {"letter": "C", "text": "王某虐待家庭成员，被虐待人主动上诉法院"}, {"letter": "D", "text": "张某诈骗后因意外死亡"}], "answer": "C", "explanation": "根据《刑事诉讼法》第十六条规定，不追究刑事责任的情形包括：情节显著轻微危害不大不认为是犯罪的、犯罪已过追诉时效的、经特赦令免除刑罚的、告诉才处理的犯罪没有告诉或撤回告诉的、犯罪嫌疑人死亡的。C项中被虐待人主动上诉法院，恰恰说明已经告诉，应当追究刑事责任，不属于不追究的情形。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 310}, {"num": 312, "batch": "专业基础知识", "type": "single", "stem": "徐某因盗窃财物被依法拘留，拘留后公安机关对其进行讯问，以下几种结果正确的是（）。", "options": [{"letter": "A", "text": "讯问后需要逮捕，在拘留期满后，依法对徐某办理逮捕手续"}, {"letter": "B", "text": "讯问后不需要逮捕，但应追究徐某刑事责任，依法直接向人民检察院移送审查起诉"}, {"letter": "C", "text": "徐某拘留期限届满，案件尚未办结，需要继续侦查的，应当依法办理延长拘留时间"}, {"letter": "D", "text": "讯问后发现徐某为怀孕的妇女，应当制作释放证明书，释放徐某"}], "answer": "B", "explanation": "根据《刑事诉讼法》相关规定，拘留后经讯问不需要逮捕但需要追究刑事责任的，公安机关可以依法直接向人民检察院移送审查起诉。A项错误，拘留期满需要逮捕的应在拘留期限内办理；C项延长拘留时间需符合法定条件；D项怀孕妇女可变更强制措施但非必须释放。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 311}, {"num": 313, "batch": "专业基础知识", "type": "single", "stem": "甲因涉嫌危害国家安全犯罪被A市公安机关刑事拘留，对甲刑事拘留，公安机关的下列做法不正确的是（）。", "options": [{"letter": "A", "text": "拘留后的第十八小时将甲送至A市看守所"}, {"letter": "B", "text": "因为甲涉嫌危害国家安全犯罪，故未通知甲的家属"}, {"letter": "C", "text": "在拘留后的第二十小时对甲进行讯问"}, {"letter": "D", "text": "拘留时向甲出示拘留证，并责令甲在拘留证上签名、捺指印"}], "answer": "B", "explanation": "根据《刑事诉讼法》第八十五条规定，拘留后应当在二十四小时以内通知被拘留人的家属。2012年修法后，危害国家安全犯罪和恐怖活动犯罪通知家属的例外已被取消，现行法律规定所有案件拘留后均应在24小时内通知家属，因此B项做法不正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 312}, {"num": 314, "batch": "专业基础知识", "type": "single", "stem": "陈某因诈骗被公安机关羁押于看守所，陈某想委托下列人员作为自己的辩护人，其中没有资格作为陈某辩护人的是（）。", "options": [{"letter": "A", "text": "陈某的父亲，为美国国籍"}, {"letter": "B", "text": "陈某的母亲，正处于假释考验期"}, {"letter": "C", "text": "陈某的爷爷，曾任人民法院法官"}, {"letter": "D", "text": "陈某的配偶，人民陪审员"}], "answer": "B", "explanation": "根据《刑事诉讼法》第三十三条规定，正在被执行刑罚或者依法被剥夺、限制人身自由的人，不得担任辩护人。陈某的母亲正处于假释考验期，属于正在被执行刑罚的人，没有资格担任辩护人。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 313}, {"num": 315, "batch": "专业基础知识", "type": "single", "stem": "公安机关对下列案件中的犯罪嫌疑人可以采取取保候审的是（）。", "options": [{"letter": "A", "text": "甲（男，38周岁），重大走私犯罪集团的成员，在整个集团犯罪活动中起着主导和指挥作用"}, {"letter": "B", "text": "乙（男，25周岁），涉嫌入室盗窃被公安机关抓获，为逃避侦查，乙吞食刀片自残"}, {"letter": "C", "text": "丙（男，29周岁），涉嫌抢夺他人财物被公安机关依法羁押，法定期限届满但案件侦查工作仍未完成"}, {"letter": "D", "text": "丁（男，41周岁），涉嫌贩卖毒品活动被公安机关立案侦查，他曾因故意伤害罪被判处有期徒刑一年，刚刑满释放一个月"}], "answer": "C", "explanation": "根据《刑事诉讼法》第六十七条规定，羁押期限届满，案件尚未办结，需要采取取保候审的，可以取保候审。C项符合该规定。A项犯罪集团主犯社会危险性大；B项自残逃避侦查不宜取保；D项累犯社会危险性大，均不符合取保候审条件。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 314}, {"num": 316, "batch": "专业基础知识", "type": "single", "stem": "下列犯罪嫌疑人没有委托辩护人，侦查机关应当通知法律援助机构指派律师为其提供辩护的是（）。", "options": [{"letter": "A", "text": "完全丧失控制自己行为能力的精神病人陈某，盗窃现金5000元"}, {"letter": "B", "text": "蒋某使用残忍的手段故意杀害了邻居黄某一家三口"}, {"letter": "C", "text": "71周岁的孟某，组织和利用邪教组织破坏法律实施"}, {"letter": "D", "text": "双腿残疾无法自由行动的林某，诈骗6万元"}], "answer": "B", "explanation": "根据《刑事诉讼法》第三十五条规定，犯罪嫌疑人、被告人可能被判处无期徒刑、死刑，没有委托辩护人的，办案机关应当通知法律援助机构指派律师为其提供辩护。B项蒋某以残忍手段杀害三人，可能被判处死刑，应当通知法律援助。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 315}, {"num": 317, "batch": "专业基础知识", "type": "single", "stem": "某县公安局民警赵某在休假期间，驾驶的机动车发生故障，找路过的当地乡人大代表区某帮忙修车。区某将自己的机动车停在旁边商店门口、商店老板邱某要求将车挪开，区某拒绝，二人争吵并互有推搡。赵某上前将二人拉开后，开始同区某修车。十分钟后，邱某和区某再次发生口角，并厮打在一起，赵某喊了一声别打了，继续埋头修车、后邱某被区某推倒，太阳穴撞在路旁隔离带上，当场死亡。下列说法正确的是（）。", "options": [{"letter": "A", "text": "赵某不构成犯罪"}, {"letter": "B", "text": "若赵某构成犯罪，应当由人民检察院立案侦查"}, {"letter": "C", "text": "公安机关对区某取保候审，应当在执行后立即报告区某所属的人民代表大会"}, {"letter": "D", "text": "邱某的死亡属于意外事件"}], "answer": "C", "explanation": "根据《全国人民代表大会和地方各级人民代表大会代表法》第三十二条规定，对县级以上的各级人大代表采取限制人身自由的措施，应当经该级人民代表大会主席团或人大常委会许可。人大闭会期间由人大常委会许可，执行后应及时报告。C项表述符合法律规定。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 316}, {"num": 318, "batch": "专业基础知识", "type": "single", "stem": "公安机关在办理于某组织、领导、参加恐怖组织案的过程中，于某委托律师张某为其辩护。为进一步了解涉案相关情况，张某拟前往看守所会见于某。下列情况中正确的是（）。", "options": [{"letter": "A", "text": "张某的会见申请，需要经过办案部门主要负责人批准"}, {"letter": "B", "text": "公安机关认为会见可能引起同案犯逃避侦查，作出不许可会见的决定"}, {"letter": "C", "text": "为进一步掌握案件细节，公安机关可以对律师会见过程进行全程监听"}, {"letter": "D", "text": "张某在会见中得知于某的团伙准备在市中心实施爆炸袭击，张某应当为其保密"}], "answer": "B", "explanation": "根据《刑事诉讼法》第三十九条规定，危害国家安全犯罪、恐怖活动犯罪案件，在侦查期间辩护律师会见在押犯罪嫌疑人，应当经侦查机关许可。侦查机关认为会见有碍侦查的，可以作出不许可会见的决定。B项于某涉嫌恐怖组织犯罪，公安机关可以因有碍侦查而不许可会见。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 317}, {"num": 319, "batch": "专业基础知识", "type": "single", "stem": "某日，Y市宝玉派出所发生一起人员死亡案件，死者系一男子，经现场勘查，该男子是被人使用草绳勒住脖子窒息死亡。民警在现场勘查中，还发现死者日记本中记载昨日张某曾与死者通话，表示若其再不还钱就要杀了他。在现场周边调取监控时，民警发现张某曾携带一捆草绳前往死者家所在单元，30分钟后手上空无一物并仓皇离开。关于本案的以下说法正确的是（）。", "options": [{"letter": "A", "text": "现场发现的草绳及日记本均属于物证"}, {"letter": "B", "text": "本案中民警调取的监控视频属于直接证据"}, {"letter": "C", "text": "现场发现的草绳属于间接证据"}, {"letter": "D", "text": "现场发现的日记本属于言词证据"}], "answer": "C", "explanation": "草绳作为作案工具，不能单独直接证明张某实施了杀人行为，需要与其他证据结合才能证明案件主要事实，因此属于间接证据。日记本属于书证而非物证；监控视频属于间接证据而非直接证据；日记本属于实物证据而非言词证据。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 318}, {"num": 320, "batch": "专业基础知识", "type": "single", "stem": "下列案件中，属于公安机关管辖范围的是（）。", "options": [{"letter": "A", "text": "甲报警称某教育局领导受贿30万元"}, {"letter": "B", "text": "乙报警称同村村民暴力干涉其婚姻自由"}, {"letter": "C", "text": "丙报警称其在码头价值50万元的货物被人烧毁"}, {"letter": "D", "text": "丁报警称其在部队内被现役军人打成重伤"}], "answer": "C", "explanation": "A项受贿罪由监察委员会管辖；B项暴力干涉婚姻自由罪属于自诉案件，由人民法院直接受理；D项军人在部队内犯罪由军队保卫部门管辖。C项货物被烧毁涉嫌故意毁坏财物罪或放火罪，属于公安机关管辖的刑事案件。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 319}, {"num": 321, "batch": "专业基础知识", "type": "single", "stem": "南明市新欣县公安局拟对涉嫌寻衅滋事罪的滕某刑事拘留，经查，滕某系新欣县人民代表大会代表，半个月前参加了新欣县人民代表大会会议。根据法律规定，新欣县公安局在对滕某作出刑事拘留决定前应当书面报请许可。下列选项中，有权许可对滕某刑事拘留的是（）。", "options": [{"letter": "A", "text": "南明市公安局"}, {"letter": "B", "text": "中共新欣县委员会"}, {"letter": "C", "text": "新欣县人大常委会"}, {"letter": "D", "text": "新欣县人民检察院"}], "answer": "C", "explanation": "根据《全国人民代表大会和地方各级人民代表大会代表法》第三十二条规定，对县级人大代表采取刑事拘留措施，应当报经该县人民代表大会常务委员会许可。本案中滕某系新欣县人大代表，应由新欣县人大常委会许可。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 320}, {"num": 322, "batch": "专业基础知识", "type": "single", "stem": "某日，被害人王某向新华县公安局刑侦大队报案称被朋友张某诈骗10万余元。经立案侦查，公安机关以涉嫌诈骗罪为由将张某刑事拘留。关于张某的刑事拘留，下列说法错误的是（）。", "options": [{"letter": "A", "text": "应当在拘留后的24小时内将张某送看守所羁押"}, {"letter": "B", "text": "应当在拘留后的24小时内对张某进行讯问"}, {"letter": "C", "text": "除无法通知外，应当在拘留后的24小时通知张某的家属"}, {"letter": "D", "text": "除特殊情况外，应当在拘留后的24小时内提请审查批准逮捕"}], "answer": "D", "explanation": "根据《刑事诉讼法》第八十五条、第八十六条规定，拘留后应在24小时内送看守所、进行讯问、通知家属。但提请审查批准逮捕的期限一般为拘留后3日以内，特殊情况可延长1至4日，对于流窜作案、多次作案、结伙作案的重大嫌疑分子可延长至30日，并非24小时内提请批捕，D项说法错误。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 321}, {"num": 323, "batch": "专业基础知识", "type": "single", "stem": "吴某（男，32周岁）因涉嫌抢夺罪被海山县公安局刑事拘留。拘留期间，吴某家属对被害人进行退赔并取得谅解。海山县公安局遂对吴某变更强制措施为取保候审。关于吴某的取保候审，下列说法正确的是（）。", "options": [{"letter": "A", "text": "应当优先对吴某适用保证人保证"}, {"letter": "B", "text": "海山县公安局决定对吴某取保候审，应报同级检察院批准后执行"}, {"letter": "C", "text": "如果采用保证人保证，保证人应当为吴某的近亲属"}, {"letter": "D", "text": "如果采用保证金保证，保证金不得少于1000元"}], "answer": "D", "explanation": "根据《公安机关办理刑事案件程序规定》及《刑事诉讼法》相关规定，采取保证金保证的，保证金起点为人民币一千元。D项正确。A项并无优先适用保证人的规定；B项取保候审无需检察院批准；C项保证人不限于近亲属。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 322}, {"num": 324, "batch": "专业基础知识", "type": "single", "stem": "王某涉嫌故意伤害被公安机关立案侦查，下列属于绝对禁止作为王某的辩护人的是（）。", "options": [{"letter": "A", "text": "王某的朋友，与本案有利害关系的人"}, {"letter": "B", "text": "王某的爸爸，目前在公安机关任职"}, {"letter": "C", "text": "王某的母亲，正处于缓刑考验期"}, {"letter": "D", "text": "王某的爷爷，英国国籍"}], "answer": "C", "explanation": "根据《刑事诉讼法》第三十三条规定，正在被执行刑罚或者依法被剥夺、限制人身自由的人，不得担任辩护人。王某的母亲正处于缓刑考验期，属于正在被执行刑罚的人，绝对禁止担任辩护人。其他选项中的人员虽有一定限制但并非绝对禁止。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 323}, {"num": 325, "batch": "专业基础知识", "type": "single", "stem": "年关将至，2022年12月5日，A省C市上午发生并由公安机关受理1起盗窃案件报警，A省B市公安局晚间接到3起盗窃案件报警，以上该案均为付某作案，公安机关将付某在A省D市居住地抓获。关于本案的管辖，下列说法正确的是（）。", "options": [{"letter": "A", "text": "A省C市公安局为最初受理案件的公安机关，则该案件一定由C市公安机关管辖"}, {"letter": "B", "text": "A省D市为付某居住地和被抓获地，该案应由D市公安机关管辖"}, {"letter": "C", "text": "A省B市发生盗窃案件最多，该案应由B市公安机关管辖"}, {"letter": "D", "text": "由于属于情况特殊的案件，可以由A省公安机关指定管辖"}], "answer": "D", "explanation": "根据《公安机关办理刑事案件程序规定》，几个公安机关都有权管辖的案件，由最初受理的公安机关管辖；必要时可以由主要犯罪地公安机关管辖。对管辖有争议或情况特殊的，可以由共同的上级公安机关指定管辖。本案涉及多地多起案件，情况特殊，可由A省公安厅指定管辖。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 324}, {"num": 326, "batch": "专业基础知识", "type": "single", "stem": "涉嫌下列犯罪，刑事拘留后通知家属可能有碍侦查，可以暂不通知其家属的是（）。", "options": [{"letter": "A", "text": "黑社会性质组织犯罪"}, {"letter": "B", "text": "恐怖活动犯罪"}, {"letter": "C", "text": "严重暴力犯罪"}, {"letter": "D", "text": "贪污贿赂犯罪"}], "answer": "B", "explanation": "根据《刑事诉讼法》第八十五条规定，拘留后应当在二十四小时以内通知被拘留人家属，但无法通知的除外。2012年修法后，原规定的'有碍侦查'不通知家属的例外情形仅限于涉嫌危害国家安全犯罪和恐怖活动犯罪。因此拘留后涉嫌恐怖活动犯罪可以暂不通知家属。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 325}, {"num": 327, "batch": "专业基础知识", "type": "single", "stem": "村民王某因涉嫌拐卖儿童被县公安局立案侦查并予以羁押，侦查尚未终结，王某突发心脏病死亡，则县公安局应当（）。", "options": [{"letter": "A", "text": "继续侦查"}, {"letter": "B", "text": "解除强制措施"}, {"letter": "C", "text": "终止调查"}, {"letter": "D", "text": "撤销案件"}], "answer": "D", "explanation": "根据《刑事诉讼法》第十六条规定，犯罪嫌疑人死亡的，不追究刑事责任。在侦查阶段发现犯罪嫌疑人死亡的，公安机关应当撤销案件。这是法定终止追诉的情形之一。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 326}, {"num": 328, "batch": "专业基础知识", "type": "single", "stem": "某日，赵某在一KTV内因走错包间与朱某等人发生口角，后赵某被朱某等人殴打至重伤。关于公安机关收集的下列证据，说法正确的是（）。", "options": [{"letter": "A", "text": "用于殴打赵某的烟灰缸属于直接证据"}, {"letter": "B", "text": "记录案件发生经过的监控录像属于间接证据"}, {"letter": "C", "text": "KTV服务员对于案发过程的描述属于实物证据"}, {"letter": "D", "text": "赵某的伤情鉴定意见属于言词证据"}], "answer": "D", "explanation": "赵某的伤情鉴定意见是鉴定人运用专业知识对专门性问题作出的判断性意见，属于言词证据（也称陈述证据）。烟灰缸属于物证，是实物证据而非直接证据；监控录像能直接反映案件经过，属于直接证据；服务员描述属于言词证据而非实物证据。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 327}, {"num": 329, "batch": "专业基础知识", "type": "single", "stem": "陈某因怀疑其妻子出轨，将其妻子殴打成轻伤，公安机关决定对陈某采取取保候审。关于本案中属于可以责令陈某附加遵守的规定是（）。", "options": [{"letter": "A", "text": "不得毁灭、伪造证据或者串供"}, {"letter": "B", "text": "在传讯的时候及时到案"}, {"letter": "C", "text": "未经执行机关批准不得离开所居住的市、县"}, {"letter": "D", "text": "将护照等出入境证件、驾驶证件交执行机关保存"}], "answer": "D", "explanation": "根据《刑事诉讼法》第七十一条规定，被取保候审人可以责令遵守以下规定：将护照等出入境证件、驾驶证件交执行机关保存。A、B、C项属于应当遵守的规定而非附加遵守的规定，D项属于可以责令附加遵守的规定。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 328}, {"num": 330, "batch": "专业基础知识", "type": "single", "stem": "公安机关在侦查一起贩卖毒品案时，根据情报得知何某华在家中藏有大量毒品。侦查人员遂依法对何某华住所进行了搜查。下列说法不正确的是（）。", "options": [{"letter": "A", "text": "搜查何某华住所应出示搜查证"}, {"letter": "B", "text": "搜查应经县级以上公安机关负责人批准"}, {"letter": "C", "text": "搜查时，为了保证程序正当性被搜查人必须在场"}, {"letter": "D", "text": "辅警小李不可以作为搜查的见证人"}], "answer": "C", "explanation": "根据《刑事诉讼法》第一百三十七条规定，在搜查的时候，应当有被搜查人或者他的家属、邻居或者其他见证人在场。但被搜查人不在场或者拒绝签名的，不影响搜查的进行，只需在笔录中注明即可。因此C项'被搜查人必须在场'的说法不正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 329}, {"num": 331, "batch": "专业基础知识", "type": "single", "stem": "对下列犯罪嫌疑人可以取保候审的是（）。", "options": [{"letter": "A", "text": "走私犯罪集团的主犯李某"}, {"letter": "B", "text": "涉嫌盗窃罪，被抓获后吞食刀片的常某"}, {"letter": "C", "text": "涉嫌抢夺犯罪被执行逮捕，羁押期限届满仍未侦查终结的郭某"}, {"letter": "D", "text": "因故意伤害罪被判处有期徒刑，两年后又因贩卖毒品被立案侦查的张某"}], "answer": "C", "explanation": "根据《刑事诉讼法》第六十七条规定，羁押期限届满，案件尚未办结，需要采取取保候审的，可以取保候审。C项符合该规定。A项走私犯罪集团主犯社会危险性大；B项自残逃避侦查不宜取保；D项累犯社会危险性大，均不适用取保候审。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 330}, {"num": 332, "batch": "专业基础知识", "type": "single", "stem": "下列刑事案件中，应当由检察院立案侦查的是（）。", "options": [{"letter": "A", "text": "财政局局长涉嫌滥用职权罪"}, {"letter": "B", "text": "吴某盗窃大型商场价值五万的LV包"}, {"letter": "C", "text": "某法官受贿30万元"}, {"letter": "D", "text": "某公安刑侦民警张某在办案中未经审批非法搜查一女子的衣物"}], "answer": "D", "explanation": "根据《刑事诉讼法》第十九条第二款规定，人民检察院在对诉讼活动实行法律监督中发现的司法工作人员利用职权实施的非法搜查、刑讯逼供等侵犯公民权利、损害司法公正的犯罪，可以由人民检察院立案侦查。D项公安民警非法搜查属于此类犯罪。A项滥用职权罪由监察委员会管辖。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 331}, {"num": 333, "batch": "专业基础知识", "type": "single", "stem": "刑警小臧在办理一起盗窃案时，经过分析研判，蹲点侦查，将犯罪嫌疑人秦某抓获归案。在对秦某进行体检时，秦某被查出患有艾滋病。鉴于该情况，为了保障看守所内部绝对安全，对秦某采取监视居住。在此期间，秦某因患病死于家中，下列关于案件侦办程序说法正确的是（）。", "options": [{"letter": "A", "text": "秦某因患有严重传染性疾病，不应追究刑事责任"}, {"letter": "B", "text": "秦某因采取监视居住，不应追究刑事责任"}, {"letter": "C", "text": "秦某因在监视居住期间死亡，不应追究刑事责任"}, {"letter": "D", "text": "秦某因主动交代犯罪事实，不应追究刑事责任"}], "answer": "C", "explanation": "根据《刑事诉讼法》第十六条规定，犯罪嫌疑人、被告人死亡的，不追究刑事责任。秦某在监视居住期间因病死亡，属于法定不追究刑事责任的情形，应当撤销案件或终止追究。患有艾滋病本身不是不追究刑事责任的法定事由。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 332}, {"num": 334, "batch": "专业基础知识", "type": "single", "stem": "下列案件中，应当由公安机关撤销案件的有（）。", "options": [{"letter": "A", "text": "刘某因涉嫌盗窃罪被公安机关移送检察院审查起诉，检察院认为犯罪情节轻微，不构成犯罪"}, {"letter": "B", "text": "张某因涉嫌故意杀人罪被抓获，但侦查后发现该行为不是张某实施"}, {"letter": "C", "text": "刘某因涉嫌强奸罪被刑事拘留，在案件侦查过程中刘某意外身亡"}, {"letter": "D", "text": "朱某与刘某因涉嫌运输毒品罪被抓获，审判时发现朱某仅15周岁"}], "answer": "C", "explanation": "根据《刑事诉讼法》第一百六十三条规定，在侦查过程中，发现不应对犯罪嫌疑人追究刑事责任的，应当撤销案件。C项刘某在侦查过程中意外死亡，属于法定不追究刑事责任的情形，公安机关应当撤销案件。A项由检察院作不起诉决定；B项应释放张某并撤销案件；D项应由法院处理。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 333}, {"num": 335, "batch": "专业基础知识", "type": "single", "stem": "尹某因涉嫌帮助信息网络犯罪活动罪被甲县公安局抓获，侦查人员准备冻结尹某名下的三张银行卡，关于冻结的说法正确的是（）。", "options": [{"letter": "A", "text": "经向银行出示人民警察证，即可要求银行办理冻结"}, {"letter": "B", "text": "在冻结过程中，发现尹某名下银行卡已经被冻结的，可重复冻结"}, {"letter": "C", "text": "冻结银行存款的期限为一年"}, {"letter": "D", "text": "对冻结的存款，经查明确实与本案无关的，应当在三日以内通知银行解除冻结"}], "answer": "D", "explanation": "根据《公安机关办理刑事案件程序规定》第二百四十三条规定，对冻结的存款、汇款，经查明确实与案件无关的，应当在三日以内通知金融机构解除冻结。A项冻结需出示协助冻结财产通知书等法律文书；B项不得重复冻结；C项冻结期限一般为六个月。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 334}, {"num": 336, "batch": "专业基础知识", "type": "single", "stem": "A市人民代表大会已经闭幕三个月，A市公安局工作中发现几起案件犯罪嫌疑人需要刑事拘留，下列关于A市公安局采取的刑事拘留措施做法错误的是（）。", "options": [{"letter": "A", "text": "刑事拘留故意杀人案件嫌疑人需经A市公安局局长审批"}, {"letter": "B", "text": "办案民警一般应在24小时内通知家属并在看守所进行讯问"}, {"letter": "C", "text": "犯罪嫌疑人拒绝在拘留证上签字，可以变更强制措施"}, {"letter": "D", "text": "拘留市人大代表汪某前需要书面报请市人大常务委员会许可"}], "answer": "C", "explanation": "根据《刑事诉讼法》相关规定，犯罪嫌疑人拒绝在拘留证上签字的，侦查人员应当在拘留证上注明，但不影响拘留的执行，不能因此变更强制措施。C项说法错误。A项刑事拘留需经县级以上公安机关负责人审批；B项符合24小时内通知和讯问的要求；D项拘留人大代表需报请人大常委会许可。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 335}, {"num": 337, "batch": "专业基础知识", "type": "single", "stem": "证据是我国专门机关在办理案件的过程中必不可少的要素，凡是能够证明案件真实情况的一切事实都是证据。以下关于证据特征的说法错误的是（）。", "options": [{"letter": "A", "text": "证据具有客观性，不以个人意志为转移"}, {"letter": "B", "text": "证据具有关联性，能够证明案件的有关事实"}, {"letter": "C", "text": "证据具有合法性，在收集案件证据时必须在合法的范围内"}, {"letter": "D", "text": "证据具有有罪性，能够证明嫌疑人的罪责行"}], "answer": "D", "explanation": "证据具有客观性、关联性和合法性三个基本特征。证据不具有'有罪性'特征，证据既包括有罪证据也包括无罪证据，既能证明犯罪嫌疑人有罪也能证明其无罪。D项说法错误。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 336}, {"num": 338, "batch": "专业基础知识", "type": "single", "stem": "张某乘坐火车由北京前往西藏老家，夜间上厕所时发现隔壁车厢下铺乘客王某已经熟睡，钱包放在枕边，于是张某意图将钱包偷偷拿走，正在伸手的时候王某突然翻身，并且发现了张某欲盗窃自己钱包的行为，王某随即报警。关于张某盗窃他人财物案，下列公安机关最为适宜管辖的是（）。", "options": [{"letter": "A", "text": "前方停靠站公安机关"}, {"letter": "B", "text": "始发站公安机关"}, {"letter": "C", "text": "终点站公安机关"}, {"letter": "D", "text": "列车上一途径站公安机关"}], "answer": "A", "explanation": "根据《公安机关办理刑事案件程序规定》及相关司法解释，在列车上发生的刑事案件，由前方停靠站铁路公安机关管辖最为适宜。本案中张某正在实施盗窃时被发现，列车前方停靠站公安机关管辖最为便利和适宜。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 337}, {"num": 339, "batch": "专业基础知识", "type": "single", "stem": "某日，一架中国客机由M国机场起飞至中国B市，在途径L国上空时飞机上的两名中国国籍乘客因琐事发生斗殴造成其中一人为重伤。为保障乘客生命安全，飞机临时改变线路被在中国P市内降落。对该起案件的侦查应由哪进行管辖？（）", "options": [{"letter": "A", "text": "M国有关机关"}, {"letter": "B", "text": "L国有关机关"}, {"letter": "C", "text": "B市公安机关"}, {"letter": "D", "text": "P市公安机关"}], "answer": "D", "explanation": "根据《公安机关办理刑事案件程序规定》及国际法原则，中国航空器内发生的犯罪，由该航空器在中国最初降落地的公安机关管辖。本案中飞机最终在P市降落，因此由P市公安机关管辖。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 338}, {"num": 340, "batch": "专业基础知识", "type": "single", "stem": "魏某因情感纠纷与其女友发生矛盾，某日，魏某在其女友上班必经路上在众目睽睽下持刀将其女友杀害，民警在现场群众的协助下成功将魏某抓获，关于对魏某执行拘留的刑事强制措施，下列说法正确的是（）。", "options": [{"letter": "A", "text": "民警必需先办理拘留证后才能对魏某进行刑事拘留"}, {"letter": "B", "text": "对魏某拘留后应当在12小时内通知其家属"}, {"letter": "C", "text": "若魏某有多次作案重大嫌疑，对其最长拘留时间可为37天"}, {"letter": "D", "text": "拘留后应当在24小时内送至人民法院"}], "answer": "C", "explanation": "根据《刑事诉讼法》第九十一条规定，对于流窜作案、多次作案、结伙作案的重大嫌疑分子，提请审查批准逮捕的时间可以延长至三十日，加上检察院七日审查期限，最长拘留时间可达三十七日。魏某有重大嫌疑且可能属于多次作案等情形，C项正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 339}, {"num": 341, "batch": "专业基础知识", "type": "single", "stem": "王某作为某公安机关刑侦办的内勤，在统计案件中，下列哪项案件需要在犯罪嫌疑人没有委托辩护人的情况下，通知法律援助律师为其提供辩护（）。", "options": [{"letter": "A", "text": "甲在拘留期间因心理压力过大丧失部分辨认能力"}, {"letter": "B", "text": "乙可能被判处十年以上有期徒刑"}, {"letter": "C", "text": "丙是残疾人，无法自由行动"}, {"letter": "D", "text": "丁家中贫困无能力聘请律师"}], "answer": "A", "explanation": "根据《刑事诉讼法》第三十五条规定，犯罪嫌疑人、被告人是盲、聋、哑人，或者是尚未完全丧失辨认或者控制自己行为能力的精神病人，没有委托辩护人的，应当通知法律援助机构指派律师为其提供辩护。A项甲丧失部分辨认能力，属于尚未完全丧失辨认能力的精神病人，应当通知法律援助。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 340}, {"num": 342, "batch": "专业基础知识", "type": "single", "stem": "《刑事诉讼法》规定，审判由（）负责。", "options": [{"letter": "A", "text": "公安机关"}, {"letter": "B", "text": "人民警察"}, {"letter": "C", "text": "人民检察院"}, {"letter": "D", "text": "人民法院"}], "answer": "D", "explanation": "根据《刑事诉讼法》第五条规定，人民法院依照法律规定独立行使审判权。审判由人民法院负责，这是我国刑事诉讼的基本分工原则。公安机关负责侦查，人民检察院负责检察和公诉。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 341}, {"num": 343, "batch": "专业基础知识", "type": "single", "stem": "保安员赵某在某小区一楼道口发现一具尸体，遂向公安机关报案，公安机关根据现场情况判断不能排除他杀的嫌疑，遂立案侦查。经审批，决定对尸体进行解剖，死者父亲张某坚决反对。公安机关以下做法正确的是（）。", "options": [{"letter": "A", "text": "提请人民检察院作出解剖尸体的决定"}, {"letter": "B", "text": "张某不到场，不能进行解剖"}, {"letter": "C", "text": "可以对尸体进行解剖，并通知张某到场"}, {"letter": "D", "text": "尊重张某的决定，不进行解剖"}], "answer": "C", "explanation": "根据《刑事诉讼法》第一百三十一条规定，对于死因不明的尸体，公安机关有权决定解剖，并且通知死者家属到场。家属反对不影响公安机关依法进行解剖。因此公安机关可以解剖尸体并通知张某到场，C项正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 342}, {"num": 344, "batch": "专业基础知识", "type": "single", "stem": "某日，甲（36岁，南山市A区人）驾驶一辆轿车途经B区某路口时，剐蹭乙（22岁，南山市B区人）的车辆，二人言语不合发生争执，甲随即拿出车里的西瓜刀将乙砍伤。随后甲将乙装在后备箱遗弃在C区一处废弃厂房里，乙幸运地被流浪人员救起。甲在潜逃的途中被D区公安机关巡逻警力抓获。关于该案的管辖，下列说法正确的是（）。", "options": [{"letter": "A", "text": "由D区公安分局管辖"}, {"letter": "B", "text": "由B区、C区公安机关共同管辖"}, {"letter": "C", "text": "由B区公安分局管辖"}, {"letter": "D", "text": "由A区、B区、C区、D区公安分局协商管辖"}], "answer": "C", "explanation": "根据《刑事诉讼法》第二十五条规定，刑事案件由犯罪地管辖。犯罪地包括犯罪行为发生地和结果发生地。本案中甲在B区砍伤乙（犯罪行为地），后将乙遗弃在C区（结果地），主要犯罪地在B区，应由B区公安分局管辖。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 343}, {"num": 345, "batch": "专业基础知识", "type": "single", "stem": "张三开车在高速公路上正常行驶，突然李四从路边冲出，张三躲闪不及将李四撞死。交管部门出警后根据现场情况对事故责任作出认定：李四（经抢救无效死亡）个人负全责，经过进一步调查得知，李四因为受到黑社会追杀，不得以逃到高速公路上导致被撞身亡，遂将案卷和证据材料移交刑侦部门立案侦查，案件转为刑事案件，移交的证据材料中可以直接作为刑事证据使用的有（）。", "options": [{"letter": "A", "text": "张三车内的行车记录仪记录的视频"}, {"letter": "B", "text": "李四妻子证实李四经常被黑社会人员骚扰的证言"}, {"letter": "C", "text": "张三本人的证言"}, {"letter": "D", "text": "李四8岁儿子看到父亲被黑社会人员殴打的证言"}], "answer": "A", "explanation": "根据《刑事诉讼法》第五十四条第二款规定，行政机关在行政执法和查办案件过程中收集的物证、书证、视听资料、电子数据等证据材料，在刑事诉讼中可以作为证据使用。行车记录仪视频属于视听资料，可以直接作为刑事证据使用。证人证言需要重新收集。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 344}, {"num": 346, "batch": "专业基础知识", "type": "single", "stem": "家住在横河县绿林村182号的戴某因诈骗被群众报案至公安机关，经调查后，因戴某不是主要犯罪嫌疑人，人民检察院决定对其不批准逮捕，但本案需继续侦查，故公安机关对戴某决定监视居住，以下说法正确的是（）。", "options": [{"letter": "A", "text": "戴某不符合监视居住的条件"}, {"letter": "B", "text": "应将戴某安排至公安机关办案场所对其进行监视居住"}, {"letter": "C", "text": "对戴某决定监视居住一年"}, {"letter": "D", "text": "戴某的驾驶证由公安机关保存"}], "answer": "D", "explanation": "根据《刑事诉讼法》第七十一条规定，被取保候审和监视居住的人应当遵守的规定包括将护照等出入境证件、驾驶证件交执行机关保存。D项正确。监视居住应当在犯罪嫌疑人住处执行，而非办案场所；监视居住期限最长不得超过六个月。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 345}, {"num": 347, "batch": "专业基础知识", "type": "single", "stem": "公安机关对犯罪嫌疑人开展讯问时，选择的讯问地点不正确的是（）。", "options": [{"letter": "A", "text": "甲因故意伤害罪在看守所刑拘，将甲带回办案场所讯问"}, {"letter": "B", "text": "乙因危险驾驶被取保候审，到乙的家中进行讯问"}, {"letter": "C", "text": "丙犯聚众斗殴罪正在住院治疗，在医院对丙进行讯问"}, {"letter": "D", "text": "正在强制戒毒隔离的丁因曾贩卖毒品被查获，在戒毒所进行讯问"}], "answer": "A", "explanation": "根据《刑事诉讼法》第一百一十八条规定，对不需要逮捕、拘留的犯罪嫌疑人，可以传唤到犯罪嫌疑人所在市、县内的指定地点或者到他的住处进行讯问。但对已被羁押在看守所的犯罪嫌疑人，应当在看守所内进行讯问，不能带回办案场所讯问。A项做法不正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 346}, {"num": 348, "batch": "专业基础知识", "type": "single", "stem": "辨认是一种侦查行为，是侦查人员基于查明案情的需要，在必要的时候让案件的被害人、证人、犯罪嫌疑人对与案情有关的物品、文件、尸体、场所或者犯罪嫌疑人进行辨认，下列公安机关组织的辨认活动中错误的是（）。", "options": [{"letter": "A", "text": "组织老孙辨认犯罪嫌疑人时，被辨认的人数为11人"}, {"letter": "B", "text": "民警小贾从自己家找到6把相似刀具用于辨认"}, {"letter": "C", "text": "对场所、尸体等特定辨认对象进行辨认，陪衬物至少2个"}, {"letter": "D", "text": "主持辨认的侦查人员是民警老王和民警小堂"}], "answer": "C", "explanation": "根据《公安机关办理刑事案件程序规定》关于辨认的规则，辨认犯罪嫌疑人时被辨认人数不得少于七人；辨认照片时不得少于十张。对场所、尸体等特定辨认对象进行辨认，或者辨认人能够准确地描述物品独有特征的，陪衬物不受数量限制。C项说法错误。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 347}, {"num": 349, "batch": "专业基础知识", "type": "single", "stem": "某日14时许，湖滨派出所民警老秦、小刘巡逻时，发现129路公交车站台有一名醉酒男子持刀喊叫，此时正好有一辆公交车驶入站点。民警拟采取措施处置，下列不恰当的是（）。", "options": [{"letter": "A", "text": "尝试安抚醉酒男子情绪"}, {"letter": "B", "text": "示意公交车司机立即驶离"}, {"letter": "C", "text": "判明并及时报告现场情况"}, {"letter": "D", "text": "动员现场群众共同控制醉酒男子"}], "answer": "D", "explanation": "面对持刀醉酒男子，动员现场群众共同控制可能造成群众伤亡，做法不恰当。正确的做法是尝试安抚情绪、判明情况报告请求增援、视情况使用警械等。疏散群众和示意公交车驶离都是合理的先期处置措施。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 348}, {"num": 350, "batch": "专业基础知识", "type": "single", "stem": "某日，东水市某公安检查站民警小张在巡查时发现安检通道内一名男子形迹可疑，上前盘查时该名男子转身欲逃离，小张遂与同事将该男子控制。经查，该男子为某盗窃案网上在逃人员。对于该信息的上报，下列选项不正确的是（）。", "options": [{"letter": "A", "text": "向检查站值班领导报告"}, {"letter": "B", "text": "向当地的情指中心报告"}, {"letter": "C", "text": "向检查站综合指挥室报告"}, {"letter": "D", "text": "向侦办该案的公安机关报告"}], "answer": "D", "explanation": "发现网上在逃人员后，应向检查站值班领导报告、向情指中心报告、向综合指挥室报告，由上级统一协调处置。直接向侦办该案的公安机关报告不属于规范的信息上报流程，应当通过内部指挥系统逐级上报。D项不正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 349}, {"num": 351, "batch": "专业基础知识", "type": "single", "stem": "2月1日21时，枣阳派出所民警老张和小王在巡逻时发现一男子形迹可疑，遂上前盘问；21时10分检查其随身携带物品时，发现其包里有一把撬棍；22时老张和小王将其带至派出所继续盘问；23时将其送入候问室。根据有关法律规定，对该男子继续盘问时间最长不应超过的是（）。", "options": [{"letter": "A", "text": "2月2日21时"}, {"letter": "B", "text": "2月2日21时10分"}, {"letter": "C", "text": "2月3日22时"}, {"letter": "D", "text": "2月2日23时"}], "answer": "C", "explanation": "根据《人民警察法》第九条规定，继续盘问时间自带至公安机关之时起不超过二十四小时。该男子22时被带至派出所，一般不超过2月2日22时；在特殊情况下经批准可延长至四十八小时，即最长不超过2月3日22时。C项正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 350}, {"num": 352, "batch": "专业基础知识", "type": "single", "stem": "某日，民警小叶和小吴在某路段发现一名可疑男子雷某，遂对其进行盘查。下列对一般可疑人员的盘查顺序，最恰当的是（）。 ①检查可疑人携带的物品 ②盘问可疑人情况 ③表明民警身份 ④对可疑人进行人身安全检查", "options": [{"letter": "A", "text": "③②①④"}, {"letter": "B", "text": "③②④①"}, {"letter": "C", "text": "③①④②"}, {"letter": "D", "text": "③①②④"}], "answer": "B", "explanation": "根据公安机关盘查工作规范，对可疑人员的盘查顺序应为：首先表明民警身份（③），然后盘问可疑人情况（②），再进行人身安全检查以确保安全（④），最后检查可疑人携带的物品（①）。正确的顺序为③②④①，即B项。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 351}, {"num": 353, "batch": "专业基础知识", "type": "single", "stem": "以下是P县公安局110指挥中心11月2日接到的部分警情。其中，不属于受理范围的是（）。", "options": [{"letter": "A", "text": "白某报称找工作时被骗入传销窝点"}, {"letter": "B", "text": "胡某举报秦某售卖含大麻的自制香烟"}, {"letter": "C", "text": "陈大爷报称环山小区北侧道路旁的电线断了，有打火现象"}, {"letter": "D", "text": "曹某报称包工头王某拖欠其半年工资"}], "answer": "D", "explanation": "110报警服务台受理范围包括刑事治安警情、交通事故、火灾事故、自然灾害及其他紧急求助。D项拖欠工资属于劳动纠纷，应当通过劳动仲裁或人民法院等渠道解决，不属于公安机关110受理范围。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 352}, {"num": 354, "batch": "专业基础知识", "type": "single", "stem": "某日，民警小张、小马在一交通枢纽站门口日常巡逻时，发现一推行电动自行车的老年男子刻意回避民警目光。11时14分，两人开始对男子进行盘问。经核查，男子叫苏某（68周岁），根据车牌号显示该电动自行车系被盗车辆。11时35分，两人将苏某从现场带离准备进行继续盘问。11时48分，苏某到达A派出所。11时58分，经A派出所所长批准，决定对苏某继续盘问。关于对苏某的继续盘问，下列说法正确的是（）。", "options": [{"letter": "A", "text": "在苏某到达公安机关后，应当立即通知其家属或者单位"}, {"letter": "B", "text": "在继续盘问间隙时间，不得将苏某送至侯问室"}, {"letter": "C", "text": "原则上对苏某的继续盘问时间不得超过当日23时58分"}, {"letter": "D", "text": "如果经调查证实苏某实施了盗窃行为，应立即终止继续盘问"}], "answer": "D", "explanation": "根据《人民警察法》第九条及相关规定，经继续盘问调查证实苏某实施了违法犯罪行为的，应当立即终止继续盘问，依法办理相应法律手续。D项正确。继续盘问期间应当及时通知家属；到达公安机关后并非必须立即通知；继续盘问时限依法计算。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 353}, {"num": 355, "batch": "专业基础知识", "type": "single", "stem": "公安机关现场执法视音频记录工作，是进一步规范公安机关现场执法活动，维护人民群众合法权益的重要措施。根据规定，下列说法正确的是（）。", "options": [{"letter": "A", "text": "民警接到110报警服务台指令后处警的，可以进行现场执法视音频记录"}, {"letter": "B", "text": "民警开展现场执法视音频记录时，应当对执法重点过程进行记录"}, {"letter": "C", "text": "执法活动结束后，民警应当在返回单位后48小时内移交视音频资料"}, {"letter": "D", "text": "作为行政案件证据使用的执法视音频资料，公安机关应当永久保存"}], "answer": "D", "explanation": "根据《公安机关现场执法视音频记录工作规定》，作为行政案件证据使用的执法视音频资料，公安机关应当永久保存。A项应为'应当'而非'可以'记录；B项应当对执法全过程进行记录而非仅重点过程；C项应在返回单位后24小时内移交。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 354}, {"num": 356, "batch": "专业基础知识", "type": "single", "stem": "对有违法犯罪嫌疑的人，需要继续盘问的，在特殊情况下，经县级以上公安机关的批准，可以将继续盘问时间延长至（）小时。", "options": [{"letter": "A", "text": "48"}, {"letter": "B", "text": "24"}, {"letter": "C", "text": "72"}, {"letter": "D", "text": "12"}], "answer": "A", "explanation": "根据《人民警察法》第九条规定，对被盘问人的留置时间自带至公安机关之时起不超过二十四小时，在特殊情况下，经县级以上公安机关批准，可以延长至四十八小时。因此答案为A项48小时。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 355}, {"num": 357, "batch": "专业基础知识", "type": "single", "stem": "春节前夕，甲市在湖边新开张了一条美食步行街，人气十分火爆。某日，民警老刘和小胡在步行街巡逻时，不断有群众向老刘和小胡反映情况，要求民警处理。群众反映的下列情况中需要民警立即处置的是（）。", "options": [{"letter": "A", "text": "群众贾某反应湖边经常有鸽子粪掉下来"}, {"letter": "B", "text": "群众闫某反映步行街某路灯出现了故障"}, {"letter": "C", "text": "群众杜某反映其商铺电线不断冒火星"}, {"letter": "D", "text": "群众贺某反映步行街街角有很多建筑垃圾需要清理"}], "answer": "C", "explanation": "电线冒火星属于紧急安全隐患，可能引发火灾或触电事故，严重威胁群众生命财产安全，需要民警立即处置。鸽子粪、路灯故障、建筑垃圾虽需关注，但不属于需要立即处置的紧急情况。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 356}, {"num": 358, "batch": "专业基础知识", "type": "single", "stem": "永鑫派出所接到分局反诈中心下发的资金侧预警线索：辖区居民刘某刚向涉诈账户转账5000元，处警民警小王和小张第一时间找到刘某开展核查和劝阻工作，如遇下列情况，处警民警处置方式最妥当的是（）。", "options": [{"letter": "A", "text": "刘某确认有转账行为，民警应继续核实其转账细节和金额"}, {"letter": "B", "text": "刘某确认网购转账且已收到货物，民警即可结束处警离开"}, {"letter": "C", "text": "刘某拒不承认转账行为，民警告知风险自担后可结束处警"}, {"letter": "D", "text": "刘某拒不配合核查工作，民警向中心报告后即可结束处警"}], "answer": "A", "explanation": "反诈预警处置中，确认刘某有转账行为后，民警应继续核实转账细节和金额，进一步了解是否还有其他转账行为，评估被骗风险，开展深度劝阻工作。B、C、D项处置方式均不够充分，可能使被害人继续遭受损失。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 357}, {"num": 359, "batch": "专业基础知识", "type": "single", "stem": "某市公安局情指中心接到报警称，市中心医院几名患者因医疗纠纷开始打砸物品，扰乱了公共秩序。市公安局情指中心指派民警小刘和小张赶赴现场。民警到达现场了解基本情况后，下列信息无需第一时间上报的是（）。", "options": [{"letter": "A", "text": "参与扰乱秩序的人数"}, {"letter": "B", "text": "扰乱秩序人员的过激行为"}, {"letter": "C", "text": "现场人员受伤的情况"}, {"letter": "D", "text": "扰乱秩序人员的病情"}], "answer": "D", "explanation": "医院医疗纠纷扰乱秩序事件中，需要第一时间上报的信息包括参与人数、过激行为和人员受伤情况，以便上级研判态势、调配警力。扰乱秩序人员的病情与事件处置无直接关联，无需第一时间上报。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 358}, {"num": 360, "batch": "专业基础知识", "type": "single", "stem": "为确保辖区社会治安秩序安全稳定，切实增强辖区群众安全感、满意度，保障辖区人民群众人身财产安全，某派出所在辖区扎实开展日常巡逻防控工作。下列不属于巡警的主要职责的是（）。", "options": [{"letter": "A", "text": "维护因某超市搞促销而堵塞的交通秩序"}, {"letter": "B", "text": "接受一女子称自己的钱包和手机被偷的报警"}, {"letter": "C", "text": "处理在上海路与林翔街交叉口发生的交通事故纠察民警小陈不合格的警容着装"}], "answer": "C", "explanation": "纠察民警警容着装属于警务督察部门的职责，不属于巡警的主要职责。巡警的主要职责包括维护社会治安秩序、预防和制止违法犯罪行为、接受群众报警求助、维护公共场所秩序等。A、B项属于巡警职责范围。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 359}, {"num": 361, "batch": "专业基础知识", "type": "single", "stem": "某日，下洼乡派出所接群众报警称：邻居周某在家中大喊大叫，疑似精神病发作。民警赶到现场，看到周某手持菜刀挥舞，现场有多名群众围观。对此，民警采取了下列处置措施： ①穿戴防护装备，携带盾牌； ②快速疏散围观群众； ③上报情况，请求增援； ④稳定周某情绪，并联系其监护人。 下列关于处置措施排序最恰当的是（）。", "options": [{"letter": "A", "text": "①②④③"}, {"letter": "B", "text": "④②①③"}, {"letter": "C", "text": "②③①④"}, {"letter": "D", "text": "③①④②"}], "answer": "C", "explanation": "处置精神病人持刀挥舞的警情，应首先疏散围观群众确保安全（②），然后上报情况请求增援（③），再穿戴防护装备携带盾牌接近（①），最后稳定情绪并联系监护人（④）。正确排序为②③①④，即C项。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 360}, {"num": 362, "batch": "专业基础知识", "type": "single", "stem": "某日，A县公安局110指挥中心民警小孙接群众举报称，该局治安大队民警黄某正在B派出所辖区内的家家乐棋牌室内打麻将赌博。接到举报，小孙开展了如下工作：①询问棋牌室的具体方位、现场情况；②接收处警人员现场处结反馈；③指令督察大队派员到场处置；④将处置情况告知报警群众；⑤询问处警人员的到场情况。关于上述工作的排序，正确的是（）。", "options": [{"letter": "A", "text": "③①④⑤②"}, {"letter": "B", "text": "①③⑤②④"}, {"letter": "C", "text": "①②⑤③④"}, {"letter": "D", "text": "③①⑤②④"}], "answer": "B", "explanation": "110指挥中心接警后的工作流程为：首先询问具体方位和现场情况（①），然后指令相关部门派员处置（③），接着询问处警人员到场情况（⑤），接收处警反馈（②），最后将处置情况告知报警群众（④）。正确排序为①③⑤②④，即B项。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 361}, {"num": 363, "batch": "专业基础知识", "type": "single", "stem": "下列不属于110接警范围的是（）。", "options": [{"letter": "A", "text": "张某报警称民警小黄在处理自己与他人纠纷时明显偏袒对方"}, {"letter": "B", "text": "王女士报警称自己所购的大衣成分与商家自述成分严重不符"}, {"letter": "C", "text": "陈某报警称锦绣天地小区门口供暖管线爆裂"}, {"letter": "D", "text": "曾某报警称自己给韩某5万元委托其为自己办工作，如今韩某逃之夭夭"}], "answer": "B", "explanation": "110接警范围包括刑事治安警情、交通事故、火灾等紧急警情以及紧急求助。B项商品成分不符属于消费纠纷，应通过消费者协会或市场监管部门解决，不属于110接警范围。A项民警偏袒属于投诉举报；C项管线爆裂属于紧急求助；D项诈骗属于刑事警情。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 362}, {"num": 364, "batch": "专业基础知识", "type": "single", "stem": "某民警在对可疑人员随身携带的背包进行检查的过程中有以下步骤： ①听背包内是否存在声响 ②询问包内物品情况 ③闻背包是否存在异味 ④查看背包外形及结构 ⑤轻拉慢开背包拉链 ⑥摸背包材料及质地，并掂一下背包重量 其中排序正确的是（）。", "options": [{"letter": "A", "text": "②④①③⑤⑥"}, {"letter": "B", "text": "②④①③⑥⑤"}, {"letter": "C", "text": "②①④③⑤⑥"}, {"letter": "D", "text": "②①④③⑥⑤"}], "answer": "B", "explanation": "根据公安机关盘查背包的操作规范，正确顺序为：先询问包内物品情况（②），再观察背包外形及结构（④），听是否有声响（①），闻是否有异味（③），然后摸背包质地掂重量（⑥），最后轻拉慢开拉链（⑤）。正确排序为②④①③⑥⑤，即B项。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 363}, {"num": 365, "batch": "专业基础知识", "type": "single", "stem": "精神病人田某追逐并不断殴打路人，严重危害他人人身安全，民警郝某和赵某接到报警后，马上赶到现场。下列处理方法不正确的是（）。", "options": [{"letter": "A", "text": "田某无视劝阻后，可以使用钢叉、警棍等警械"}, {"letter": "B", "text": "控制田某后，只能采用保护性约束措施"}, {"letter": "C", "text": "控制田某后，立即对其进行人身安全检查"}, {"letter": "D", "text": "必要情况下，对田某可以使用手铐"}], "answer": "B", "explanation": "根据《精神卫生法》及相关规定，对严重危害他人安全的精神病人，控制后可以采取保护性约束措施，但并非'只能'采用保护性约束措施，还可以根据情况采取其他必要的处置措施，如通知监护人、送医治疗等。B项说法不正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 364}, {"num": 366, "batch": "专业基础知识", "type": "single", "stem": "2024年7月19日22时许，柯×和几个朋友在天缘酒久烧烤店吃夜宵，与邻桌林×等人发生争执。烧烤店老板看情况不对，拨打110报警。接到情指中心指令后，值班民警小张和小李赶到现场，发现柯×、林×等近十人互殴，且围观群众较多。在增援警力未到达前，小张和小李拟采取先期处置措施不恰当的是（）。", "options": [{"letter": "A", "text": "表明警察身份，命令双方停止斗殴"}, {"letter": "B", "text": "研判现场情况，报告请求增派警力"}, {"letter": "C", "text": "警告无效后使用催泪喷射器，控制现场秩序"}, {"letter": "D", "text": "通知治安检查站点进行围追堵截"}], "answer": "D", "explanation": "在增援警力未到达前，先期处置民警应表明身份制止斗殴、报告请求增援、必要时使用警械控制现场。通知治安检查站进行围追堵截不属于恰当的先期处置措施，因为现场人员众多，围追堵截可能激化矛盾、造成更大混乱。D项不恰当。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 365}, {"num": 367, "batch": "专业基础知识", "type": "single", "stem": "2023年12月12日上午10时，民警老赵接到情指中心警情指令，湖令公司售楼部门口发生纠纷。接警后，民警老赵、小李赶至现场，看到20多名业主已聚集湖令公司售楼部门前拉横幅，要求开发商退还购房款。现场有大量群众围观，同时有人在网络直播。针对此情况，老赵在上报情指中心请求增援后，拟采取先期处置措施妥当的是（）。", "options": [{"letter": "A", "text": "疏散围观群众，现场收缴横幅，对直播者宣讲政策"}, {"letter": "B", "text": "劝阻过激行为，建议选代表留下，对直播者讲明法律规定"}, {"letter": "C", "text": "通知开发商到场，联系律师，并对直播者依法处置"}, {"letter": "D", "text": "控制秩序，宣传法律，对直播者严密控制"}], "answer": "B", "explanation": "面对群体性事件先期处置，应当劝阻过激行为，建议业主选代表进行沟通，同时对直播者讲明法律规定，引导其依法表达诉求。不应直接收缴横幅或控制直播者，这些措施可能激化矛盾。B项做法最为妥当。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 366}, {"num": 368, "batch": "专业基础知识", "type": "single", "stem": "为进一步加大对酒驾醉驾等重点交通违法行为的严管高压态势，切实保障人民群众生命财产安全，近日A县公安局交警大队在辖区全面开展冬季交通秩序整治“夜查”统一行动。1月25日晚，交警小孙、小马等六人在胜利路附近设卡时，拦停了一辆白色面包车，拟对车辆和车内人员进行检查，则下列做法正确的是（）。", "options": [{"letter": "A", "text": "从白色面包车车头正前方接近车辆"}, {"letter": "B", "text": "责令司机熄火拉手刹，双手平放在大腿上"}, {"letter": "C", "text": "让车上人员逐一下车接受盘查"}, {"letter": "D", "text": "在发现车内人员丁某系一起诈骗案逃犯后，立即控制丁某并扣押车上所有人的随身物品"}], "answer": "C", "explanation": "根据交警设卡检查规范，应当让车上人员逐一下车接受盘查，以便逐一核实身份和检查随身物品。A项从车头正前方接近不安全；B项双手放置位置描述不够准确；D项扣押所有人随身物品不符合法律规定。C项做法正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 367}, {"num": 369, "batch": "专业基础知识", "type": "single", "stem": "李某违反展览馆禁止携带食品入内的相关规定，不听管理人员劝阻，与其发生口角，在展馆入口处大声喧哗吵闹，严重扰乱展览馆公共秩序。民警小吴、小刘接警后到场处置，下列做法妥当的是（）。", "options": [{"letter": "A", "text": "对李某和管理人员的争执当场调解"}, {"letter": "B", "text": "告知围观群众禁止拍摄民警执法活动"}, {"letter": "C", "text": "查看监控确认其违法事实后进行现场处置"}, {"letter": "D", "text": "当场核实李某的身份，对其进行口头传唤"}], "answer": "D", "explanation": "李某在展览馆大声喧哗扰乱公共秩序，民警到场后应当场核实其身份，对其违法行为进行口头传唤至公安机关进一步处理。消费纠纷可以调解，但扰乱公共秩序的行为应当依法处理。对围观群众不应禁止拍摄。D项做法妥当。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 368}, {"num": 370, "batch": "专业基础知识", "type": "single", "stem": "某日，民警在街面开展巡逻防控工作时，发现一男子与近期公安机关正在查找的某犯罪嫌疑人特征高度相符，便上前对其展开盘查工作。在核实其身份过程中，不属于查验重点的是（）。", "options": [{"letter": "A", "text": "查验身份证件的防伪标识"}, {"letter": "B", "text": "令其口述信息，进行人、证对照"}, {"letter": "C", "text": "核查身份证的颁发机关信息"}, {"letter": "D", "text": "核查身份证的颁发机关信息"}, {"letter": "E", "text": "进行系统信息核对"}], "answer": "C", "explanation": "盘查中查验身份证件的重点包括：查验防伪标识辨别真伪、人证对照核实身份、进行系统信息核对是否在逃等。核查身份证的颁发机关信息不属于查验重点，因为颁发机关信息并不能直接判断持证人身份的真伪。C项不属于查验重点。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 369}, {"num": 371, "batch": "专业基础知识", "type": "single", "stem": "某日，城北派出所接到报警称，有一名艾滋病患者在农贸市场闹事。接报后，民警小刘和小顾迅速赶赴现场。为妥善处置，下列做法正确的是（）。", "options": [{"letter": "A", "text": "对该艾滋病患者进行人身检查时，可以不戴防护手套"}, {"letter": "B", "text": "当该艾滋病患者进行自残行为，可直接使用警械、武器制止"}, {"letter": "C", "text": "在控制该艾滋病患者时，要避免被其咬伤、抓伤"}, {"letter": "D", "text": "被该艾滋病患者抓伤后，不应用清水冲洗伤口"}], "answer": "C", "explanation": "处置艾滋病患者时，应当做好个人防护，避免被其咬伤、抓伤，防止血液或体液接触传播。A项不戴手套违反防护规定；B项自残行为应先劝阻，不能直接使用警械；D项被抓伤后应立即用清水冲洗伤口。C项正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 370}, {"num": 372, "batch": "专业基础知识", "type": "single", "stem": "民警接到上级指令设卡对过往车辆进行安全检查，关于执行本次任务民警做法正确的是（）。", "options": [{"letter": "A", "text": "对车辆进行安全检查时，不得站立在车辆行进方向的行车道上拦截"}, {"letter": "B", "text": "截停车辆后，立即要求车内全部人员下车进行人身检查"}, {"letter": "C", "text": "检查卡点应设置在人多的地方，以便及时发现嫌疑人员"}, {"letter": "D", "text": "驾驶人不听劝阻，驾车逃逸后，民警立刻驾车追缉"}], "answer": "A", "explanation": "根据公安机关设卡检查规范，对车辆进行安全检查时，不得站立在车辆行进方向的行车道上拦截，以防被车辆撞击。应选择安全位置设卡，确保民警自身安全。B项不应要求全部人员下车；C项设卡应选在便于控制的位置；D项逃逸后不应立即追缉，应报告上级统一部署。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 371}, {"num": 373, "batch": "专业基础知识", "type": "single", "stem": "顾客耿某在蓝天商城廖某的店里买了一部手机，回家两天后发现手机质量有问题，遂要求廖某调换，廖某检查手机后认为手机质量没问题，拒绝调换。双方为此发生口角，耿某报警。下列民警开展的工作中，做法不恰当的是（）。", "options": [{"letter": "A", "text": "积极劝导，协调各方，促使纠纷化解"}, {"letter": "B", "text": "告知耿某拨打消费者协会电话投诉廖某"}, {"letter": "C", "text": "告知耿某到人民法院起诉廖某"}, {"letter": "D", "text": "对达成协议后拒履行的一方强制其履行"}], "answer": "D", "explanation": "消费纠纷属于民事纠纷，民警可以进行调解劝导，告知当事人通过消费者协会或法院解决。但民警无权对达成协议后拒履行的一方强制其履行，民事协议的履行应通过人民法院强制执行。D项做法不恰当。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 372}, {"num": 374, "batch": "专业基础知识", "type": "single", "stem": "某日，雨北派出所接群众报警称，看见和谐盛世小区临街的楼下有个人被掉落的花盆砸伤。民警小胡、老张立即赶到现场，看到有一名男性躺在路边，现场有群众围观，造成道路拥堵。民警拟采取一系列处置措施，其中不恰当的是（）。", "options": [{"letter": "A", "text": "在现场等待120救护车对受伤男子进行救治"}, {"letter": "B", "text": "设置警戒范围，隔离危险区域，防止再次发生事故"}, {"letter": "C", "text": "疏导现场秩序，请求交警部协助开展外围道路疏导"}, {"letter": "D", "text": "收集现场物证，询问目击证人，制作笔录"}], "answer": "A", "explanation": "花盆砸伤行人属于紧急救助事件，民警应当积极救助伤者，不能仅在现场等待120救护车。应在确保安全的前提下对伤者进行初步救助，同时设置警戒、疏导交通、调查取证。A项消极等待不恰当。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 373}, {"num": 375, "batch": "专业基础知识", "type": "single", "stem": "某日15时30分，民警老关、小夏巡逻至人民广场时，遇到市民陈女士求助，称在广场内骑自行车的儿子走失了。民警边寻找边报告110指挥中心，请求调度周边警力协助查找。在上报走失男孩相关信息时，下列不需要第一时间上报的是（）。", "options": [{"letter": "A", "text": "走失地点"}, {"letter": "B", "text": "家庭地址"}, {"letter": "C", "text": "走失时间"}, {"letter": "D", "text": "衣服颜色"}], "answer": "B", "explanation": "上报儿童走失信息时，第一时间需要上报走失地点、走失时间、走失儿童的体貌特征（如衣服颜色）等关键信息，以便迅速组织搜寻。家庭地址虽然重要，但不属于第一时间需要上报的紧急信息。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 374}, {"num": 376, "batch": "专业基础知识", "type": "single", "stem": "近日，东南地区风塔市境内连续降雨，市气象部门发布暴雨橙色预警，市应急指挥中心立即启动防汛抢险救灾应急预案，下班在家的派出所民警小郭看到电视上播报风塔市局部地区将有暴雨，并在屏幕左上角看到暴雨橙色预警信号，便立即冒雨赶回派出所，按照市公安局应急抢险总体部署和派出所工作安排，组织辖区群众做好暴雨灾害防御工作。暴雨来临后，民警小郭接到辖区居民张大妈的电话称，花园东小区道路旁有一根电线掉落在地上，情况危险。小郭立即赶赴现场处置，下对措施不恰当的是（）。", "options": [{"letter": "A", "text": "用竹竿将电线挑至路边，以防路人碰触"}, {"letter": "B", "text": "立即疏散周边群众，划定警戒区域"}, {"letter": "C", "text": "维护现场交通秩序，指挥车辆有序绕行"}, {"letter": "D", "text": "上报情指中心联系电力部门迅速抢修"}], "answer": "A", "explanation": "暴雨中掉落的电线可能带电，用竹竿挑电线存在触电危险，做法不恰当。正确的做法是疏散群众、划定警戒区域、维护秩序、上报联系电力部门抢修。竹竿在潮湿环境下可能导电，非专业人员不应直接接触或挑动电线。A项不恰当。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 375}, {"num": 377, "batch": "专业基础知识", "type": "single", "stem": "某日17时许，西华市新城区爱民街派出所接红日家具厂保安队长张某电话报警称：有两人在厂区的停车场入口处扭打在一起，原因不明。其中一人被打倒在地，另一人仍继续实施殴打行为，现场有少量人员围观。后经厂区保安员上前制止，两人停止打斗，双方身体无大碍，无明显外伤，现在保安员看管下。所领导指派民警老李、小王和两名辅警出警处置。处警民警到达后迅速控制住现场，发现其中一方当事人身材高大，背着一个双肩包；另一方身材瘦小，西服外套被撕裂。经询问，民警得知双方均是红日家具厂的工人，高个男子名叫吴X，瘦小男子名叫孙X，二人因生活琐事发生争吵，进而演变为互殴行为。两名民警相互配合，对两人依次进行安全检查。在对吴X安全检查时，下列检查措施不符合规范的是（）。", "options": [{"letter": "A", "text": "命令吴X面对停车场的围墙站立，接受人身检查"}, {"letter": "B", "text": "要求吴X将衣服口袋翻出，接受安全检查"}, {"letter": "C", "text": "要求吴X出示身份证件，核实其身份信息"}, {"letter": "D", "text": "责令吴X自己取出双肩包内的物品，接受安全检查"}], "answer": "D", "explanation": "根据公安机关安全检查规范，对被检查人携带的物品，应当由民警进行检查，而不能责令被检查人自己取出包内物品，以防被检查人趁机销毁证据或使用危险物品攻击民警。D项做法不符合规范。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 376}, {"num": 378, "batch": "专业基础知识", "type": "single", "stem": "某铁路车站公安派出所民警小王、小张在站前广场执勤时，发现携带箱包的甲、乙二人神色可疑，随即对二人展开盘查。根据有关法律规定，下列操作中不正确的是（）。", "options": [{"letter": "A", "text": "出示证件后当场对二人进行盘问"}, {"letter": "B", "text": "要求二人出示居民身份证"}, {"letter": "C", "text": "要求二人报出姓名和身份证号码"}, {"letter": "D", "text": "要求二人将携带箱包打开并拿出包内物品"}], "answer": "D", "explanation": "根据盘查工作规范，对可疑人员携带的箱包进行检查时，应当由民警打开箱包进行检查，不应要求嫌疑人自己将箱包打开并拿出物品，以防嫌疑人利用包内危险物品攻击民警或销毁证据。D项操作不正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 377}, {"num": 379, "batch": "专业基础知识", "type": "single", "stem": "某日，民警小王和小姜在街头处理一宗民事纠纷，围观群众陈某逐渐靠近民警小王，并用手机拍摄其处警过程。民警小姜最恰当的做法是（）。", "options": [{"letter": "A", "text": "用手遮挡陈某手机"}, {"letter": "B", "text": "要求陈某退出警戒区外"}, {"letter": "C", "text": "口头警告陈某停止拍摄"}, {"letter": "D", "text": "没收陈某手机并删除拍摄内容"}], "answer": "B", "explanation": "根据公安部相关规定，群众有权对民警执法活动进行监督，民警不得干涉群众正常拍摄。但如群众拍摄影响执法或进入警戒区域，可以要求其退到警戒区外。B项做法最为恰当，既保障了群众监督权又维护了执法秩序。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 378}, {"num": 380, "batch": "专业基础知识", "type": "single", "stem": "关于巡逻方式，下列说法正确的是（）。", "options": [{"letter": "A", "text": "网格化巡逻是巡逻方式中最优的选择"}, {"letter": "B", "text": "相较于车巡，步巡与群众距离感小，互动性高"}, {"letter": "C", "text": "见警率越高，群众的安全感越高"}, {"letter": "D", "text": "针对反侦查能力较强的惯犯，应采取着装巡逻，增强震慑力"}], "answer": "B", "explanation": "步巡相较于车巡，速度较慢，民警与群众之间的距离感更小，互动性更高，有利于密切警民关系和及时发现违法犯罪线索。A项网格化巡逻并非唯一最优选择；C项见警率与安全感并非简单的正比关系；D项对惯犯应采取便衣巡逻。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 379}, {"num": 381, "batch": "专业基础知识", "type": "single", "stem": "近日，城关派出所辖区沿街商铺中利用“老虎机”进行赌博的警情高发，发案时间多集中在凌晨。通过调查了解到，派出所每次收缴“老虎机”后，就有人再给商铺免费提供，时间多在下午时间段。针对此情况，派出所拟调整巡逻方式，加大巡控力度。下列方式中最适宜的是（）。", "options": [{"letter": "A", "text": "日间与夜间巡逻相结合"}, {"letter": "B", "text": "步巡和车巡相结合"}, {"letter": "C", "text": "步巡和空巡相结合"}, {"letter": "D", "text": "自行车巡逻与车巡相结合"}], "answer": "A", "explanation": "根据案情分析，'老虎机'被收缴后有人再送，发案时间集中在凌晨和下午。针对这一规律，最适宜的方式是日间与夜间巡逻相结合，覆盖下午和凌晨两个高发时段，消除巡逻盲区。A项最为适宜。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 380}, {"num": 382, "batch": "专业基础知识", "type": "single", "stem": "近期，派出所接到多次报警，称小学生放学后以及上完晚辅导后常被一些社会人士拉入学校附近的小巷子中强迫购买电子烟，导致小学生不敢上学。为了保护未成年人，派出所准备加强巡逻，最合适的方式是（）。", "options": [{"letter": "A", "text": "白天使用警车对学校周边巡逻"}, {"letter": "B", "text": "夜间使用视频对学校周围进行巡逻"}, {"letter": "C", "text": "白天校内巡逻并发放自我保护资料"}, {"letter": "D", "text": "便衣警察晚高峰及夜里徒步巡逻"}], "answer": "D", "explanation": "根据案情，社会人士在放学后和晚辅导后拉拽小学生，发案时间为白天放学后及夜间。便衣警察在晚高峰及夜间徒步巡逻，既能隐蔽发现违法犯罪行为，又能覆盖高发时段，有效保护学生安全。D项最为合适。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 381}, {"num": 383, "batch": "专业基础知识", "type": "single", "stem": "巡逻工作是公安民警日常的勤务活动，也是履行职责的重要勤务方式之一，更是适应社会治安新形势，实现对社会面动态有效控制的主动勤务方式。解放路派出所初任民警小李在巡逻中的下列做法，不属于履行巡逻警察职责的行为是（）。", "options": [{"letter": "A", "text": "路口发生一起汽车与电动车相撞事故，电动车骑行人员躺倒在地，小李当即上前救助伤者"}, {"letter": "B", "text": "路人甲在临街店铺排队购物，乙意图插队被甲制止，二人发生口角，当即动手互殴，小李立即上前劝阻并制止"}, {"letter": "C", "text": "路遇某民警，该民警身穿警服、卷着裤腿、脚穿“人字拖”，小李以巡警身份上前纠正该民警警容风纪问题"}, {"letter": "D", "text": "路遇一对青年情侣在街心公园吵架，小李立即上前劝解"}], "answer": "D", "explanation": "巡逻警察的职责包括维护治安秩序、制止违法犯罪、救助群众等。纠正其他民警的警容风纪问题属于警务督察部门的职责，不属于巡逻警察的职责范围。C项不属于履行巡逻警察职责的行为。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 382}, {"num": 384, "batch": "专业基础知识", "type": "single", "stem": "下列关于继续盘问的说法，正确的是（）。", "options": [{"letter": "A", "text": "继续盘问时限一般为24小时，可延长至48小时"}, {"letter": "B", "text": "对不满16周岁的未成年人适用继续盘问，时间一律不得超过12小时"}, {"letter": "C", "text": "继续盘问需经派出所负责人批准"}, {"letter": "D", "text": "被盘问人身份不明且不讲真实姓名，可无限期盘问"}], "answer": "C", "explanation": "根据《人民警察法》第九条规定，继续盘问需经派出所负责人批准。继续盘问时限一般不超过24小时，特殊情况可延长至48小时，但并非一律适用48小时。对不满16周岁的未成年人有特殊规定，但并非一律不超过12小时。C项正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 383}, {"num": 385, "batch": "专业基础知识", "type": "single", "stem": "公安派出所民警在巡逻时，正确的做法是（）。", "options": [{"letter": "A", "text": "可以超出巡逻区域，或者减少巡逻时间和巡逻密度"}, {"letter": "B", "text": "对于较为安全区域可以不巡查"}, {"letter": "C", "text": "对有违法嫌疑的人员依法进行盘问，无需对其物品进行检查"}, {"letter": "D", "text": "接受处理案（事）件任务时，将任务执行情况及时向下达指令的部门报告"}], "answer": "D", "explanation": "根据公安机关巡逻工作规范，巡逻民警接受处理案（事）件任务时，应当将任务执行情况及时向下达指令的部门报告，确保信息畅通和指挥调度有效。A项不应超出巡逻区域；B项不应遗漏安全区域；C项对可疑物品也应检查。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 384}, {"num": 386, "batch": "专业基础知识", "type": "single", "stem": "某市公安机关高度重视并采取有效措施加强110接处警工作，以下接警人员的做法不符合110接警相关制度的是（）。", "options": [{"letter": "A", "text": "接警员小刘接到报警后立即询问案件的事由、地点和位置"}, {"letter": "B", "text": "必要时接警员小张使用方言接警"}, {"letter": "C", "text": "接警员应具备急救自救常识，接受报警、求助时视情况指导急救"}, {"letter": "D", "text": "报警人不愿意公开自己姓名的，应当为其保密，并在接警记录中删除报警人相关信息"}], "answer": "D", "explanation": "根据110接处警工作规范，报警人不愿意公开姓名的，应当为其保密，但不应在接警记录中删除报警人相关信息，报警人信息应当记录保存以备后续核查需要。D项做法不符合规定。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 385}, {"num": 387, "batch": "专业基础知识", "type": "single", "stem": "某日18时许，城郊路派出所民警小张接辖区味美食品厂保安老李电话报警，称连接该厂变压器的一根电线（未见火花）掉落在距离厂区大门约2米远的人行道上。此时天空下起小雨，工厂员工陆续下班离厂。民警小张、小李在赶往现场的途中拟采取一系列措施，其中不宜采取的是（）。", "options": [{"letter": "A", "text": "立即拨打电力抢修电话，要求电力公司派人到现场排除风险"}, {"letter": "B", "text": "指导保安老李马上到隔壁小区控制室拉闸断电"}, {"letter": "C", "text": "联系附近巡逻组赶赴现场，在掉落电线的地点外围设置警戒区域"}, {"letter": "D", "text": "要求保安老李立即阻止工厂员工从大门外出"}], "answer": "B", "explanation": "电线掉落处置中，隔壁小区控制室可能距离较远且保安不一定能操作，指导保安去拉闸断电可能延误处置且存在安全风险。更合适的做法是拨打电力抢修电话、设置警戒区域、阻止员工从大门外出。B项不宜采取。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 386}, {"num": 388, "batch": "专业基础知识", "type": "single", "stem": "根据《中华人民共和国人民警察使用警械和武器条例》的规定，下列情形中，人民警察不可以使用武器的是（）。", "options": [{"letter": "A", "text": "黄某在加油站内挥舞打火机称要同归于尽"}, {"letter": "B", "text": "丁某持枪劫持人质，但丁某已经怀孕"}, {"letter": "C", "text": "陈某实施抢夺后逃跑至火车站内躲藏"}, {"letter": "D", "text": "王某劫夺在押罪犯"}], "answer": "C", "explanation": "根据《人民警察使用警械和武器条例》第九条规定，实施抢夺犯罪后逃跑的，在公共场所一般不得使用武器，因为火车站内人员密集，使用武器可能危及无辜群众安全。A项加油站使用武器可能引发爆炸；但A项属于紧急情形可以使用武器；B项对怀孕妇女一般不使用武器；D项劫夺在押罪犯可以使用武器。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 387}, {"num": 389, "batch": "专业基础知识", "type": "single", "stem": "民警小张、小王在巡逻过程中，发现两名男子疑似正在盗窃电动自行车。两名男子察觉后遂丢弃该车辆迅速逃离现场，民警小张、小王立即开展抓捕并将相关情况上报。下列上报信息内容不恰当的是（）。", "options": [{"letter": "A", "text": "两名可疑男子的体貌特征"}, {"letter": "B", "text": "两名可疑男子的衣着特征"}, {"letter": "C", "text": "两名可疑男子的逃跑方向"}, {"letter": "D", "text": "涉案电动自行车的车辆信息"}], "answer": "D", "explanation": "上报抓捕信息时，应当重点报告嫌疑人的体貌特征、衣着特征和逃跑方向，以便周边警力协助抓捕。涉案电动自行车的车辆信息不属于抓捕行动中需要第一时间上报的紧急信息，可以在后续工作中核实。D项不恰当。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 388}, {"num": 390, "batch": "专业基础知识", "type": "single", "stem": "民警巡逻中，发现辖区商业街过街天桥上悬挂有邪教标语，现场已有许多群众围观。下列做法正确的是（）。", "options": [{"letter": "A", "text": "遵循先处理后报告原则，处理完毕后，在第二天交接班时报告领导"}, {"letter": "B", "text": "向所属派出所报告后，继续巡逻"}, {"letter": "C", "text": "拍照固定证据后，立即解下标语，同时报告情指中心"}, {"letter": "D", "text": "因现场人流量大，设置警戒线，保护现场，等待勘验"}], "answer": "C", "explanation": "发现邪教标语后，应当拍照固定证据，然后立即解下标语消除影响，同时报告情指中心。不能等待第二天再报告，也不能仅报告派出所后继续巡逻，更不能设置警戒线保护现场等待勘验，因为邪教标语的社会影响需要立即消除。C项正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 389}, {"num": 391, "batch": "专业基础知识", "type": "single", "stem": "某日10时许，秋兴派出所民警老周和小李（均不会游泳）正在园区巡逻，接到群众求助称：天智湖有钓鱼爱好者溺水，需要立即救援。民警赶赴现场后发现天智湖内有一名中年男子正在水中挣扎，情况十分危险，此时已经聚集很多群众围观。老周和小李采取措施恰当的是（）。", "options": [{"letter": "A", "text": "立即携带救生设备下水救人"}, {"letter": "B", "text": "责令现场会游泳的围观群众下水救人"}, {"letter": "C", "text": "立即请求携带皮划艇的钓鱼爱好者协助施救"}, {"letter": "D", "text": "加强现场警戒，等待水警、消防救援等专业力量支援"}], "answer": "C", "explanation": "民警不会游泳，不应贸然下水救人，否则可能造成更大伤亡。也不应责令群众下水救人。最恰当的做法是立即请求现场会游泳且携带皮划艇的钓鱼爱好者协助施救，同时加强现场警戒等待专业救援力量。C项最为恰当。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 390}, {"num": 392, "batch": "专业基础知识", "type": "single", "stem": "某村村民因不满征地补偿标准，组织上百名老弱妇孺围堵位于该村的国家重点项目，致使项目被迫停工，造成重大损失。当地党委、政府要求公安机关快速妥善处置，消除不稳定因素，确保及时复工。属地派出所民警先期到达围堵阻工现场，以下行为不可取的是（）。", "options": [{"letter": "A", "text": "维护现场秩序"}, {"letter": "B", "text": "将阻挠施工人员强制带离现场"}, {"letter": "C", "text": "对群众宣讲政策、说服教育"}, {"letter": "D", "text": "与属地街镇对接开展协调工作"}], "answer": "B", "explanation": "面对上百名老弱妇孺围堵阻工的情况，将阻挠施工人员强制带离现场可能激化矛盾、引发更大冲突，做法不可取。正确的做法是维护现场秩序、宣讲政策说服教育、与属地街镇协调沟通，通过柔性方式化解矛盾。B项不可取。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 391}, {"num": 393, "batch": "专业基础知识", "type": "single", "stem": "若下列选项中的犯罪分子均符合：犯罪情节较轻；有悔罪表现；没有再犯罪的危险；宣告缓刑对所居住社区没有重大不良影响，那么属于应当缓刑的情形的是（）。", "options": [{"letter": "A", "text": "判处拘役的犯罪分子"}, {"letter": "B", "text": "判处3年以下有期徒刑的犯罪分子"}, {"letter": "C", "text": "判处拘役的未满18岁的人"}, {"letter": "D", "text": "判处5年以下有期徒刑的已满75周岁的人"}], "answer": "C", "explanation": "根据《刑法》第七十二条规定，对于被判处拘役、三年以下有期徒刑的犯罪分子，同时符合犯罪情节较轻、有悔罪表现、没有再犯罪危险、宣告缓刑对社区没有重大不良影响条件的，可以宣告缓刑。其中对不满十八周岁的人、怀孕的妇女和已满七十五周岁的人，应当宣告缓刑。C项符合应当缓刑的条件。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 392}, {"num": 394, "batch": "专业基础知识", "type": "single", "stem": "黄某饮酒后（血液酒精含量为180毫克/100毫升）开车途经一路口停车等候红绿灯，田某驾驶摩托车跟随在后，但由于田某超速驾驶，追尾撞到黄某的轿车当场死亡。对于黄某的行为下列说法正确的是（）。", "options": [{"letter": "A", "text": "不追究黄某刑事责任"}, {"letter": "B", "text": "追究黄某交通肇事罪"}, {"letter": "C", "text": "追究黄某危险驾驶罪"}, {"letter": "D", "text": "追究黄某妨害安全驾驶罪"}], "answer": "C", "explanation": "黄某血液酒精含量180mg/100ml，属于醉酒驾驶机动车，构成危险驾驶罪。田某死亡系因其自身超速追尾所致，事故责任由田某承担，黄某不构成交通肇事罪。但黄某的醉驾行为本身已构成危险驾驶罪，应依法追究刑事责任。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 393}, {"num": 395, "batch": "专业基础知识", "type": "single", "stem": "陈某是旧货店老板，明知李某前来销售的一批二手笔记本电脑来路不明，有赃物嫌疑，依旧违反规定予以收购情节严重陈某的行为涉嫌构成（）。", "options": [{"letter": "A", "text": "窝藏、包庇罪"}, {"letter": "B", "text": "掩饰、隐瞒犯罪所得、犯罪所得收益罪"}, {"letter": "C", "text": "盗窃罪"}, {"letter": "D", "text": "包庇罪"}], "answer": "B", "explanation": "根据《刑法》第三百一十二条规定，明知是犯罪所得及其产生的收益而予以窝藏、转移、收购、代为销售或者以其他方法掩饰、隐瞒的，构成掩饰、隐瞒犯罪所得、犯罪所得收益罪。陈某明知笔记本电脑有赃物嫌疑仍予以收购，符合该罪构成要件。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 394}, {"num": 396, "batch": "专业基础知识", "type": "single", "stem": "2023年12月13日，最高人民法院、最高人民检察院、公安部、司法部制定了《关于办理醉酒危险驾驶刑事案件的意见》，下列关于醉酒危险驾驶行为说法正确的是（）。", "options": [{"letter": "A", "text": "只允许单位内部机动车、特定来访机动车通行的，属于“道路”"}, {"letter": "B", "text": "毒驾的危害程度高于醉酒，因此毒驾也构成危险驾驶罪"}, {"letter": "C", "text": "醉驾同时构成交通肇事罪、过失以危险方法危害公共安全罪、以危险方法危害公共安全罪等其他犯罪的，依照处罚较重的规定定罪"}, {"letter": "D", "text": "醉酒驾驶机动车，以暴力、威胁方法阻碍公安机关依法检查，又构成妨害公务罪、袭警罪等其他犯罪的，依照处罚较重的规定定罪"}], "answer": "C", "explanation": "根据2023年《关于办理醉酒危险驾驶刑事案件的意见》，醉驾同时构成交通肇事罪、以危险方法危害公共安全罪等其他犯罪的，依照处罚较重的规定定罪处罚。毒驾目前不构成危险驾驶罪；单位内部道路不属于'道路'范畴；醉驾又构成妨害公务罪等的，依照数罪并罚规定处理。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 395}, {"num": 397, "batch": "专业基础知识", "type": "single", "stem": "李某在乘坐长途客车途中，因不满司机未按照他要求的临时停车点停车，便在车辆行驶过程中，突然冲到司机身旁，猛拍司机的肩膀，并试图抢夺方向盘。客车因此出现晃动。李某的行为构成（）。", "options": [{"letter": "A", "text": "妨害安全驾驶罪"}, {"letter": "B", "text": "危险驾驶罪"}, {"letter": "C", "text": "交通肇事罪"}, {"letter": "D", "text": "以危险方法危害公共安全罪"}], "answer": "A", "explanation": "根据《刑法》第一百三十三条之二规定，对行驶中的公共交通工具的驾驶人员使用暴力或者抢控驾驶操纵装置，干扰公共交通工具正常行驶，危及公共安全的，构成妨害安全驾驶罪。李某抢夺方向盘导致客车晃动，危及公共安全，构成妨害安全驾驶罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 396}, {"num": 398, "batch": "专业基础知识", "type": "single", "stem": "下列属于犯罪中止的是（）。", "options": [{"letter": "A", "text": "张三为杀死仇人欲购买毒药，后因害怕受到制裁而取消杀人念头"}, {"letter": "B", "text": "李四以出卖为目的拐走妇女小刘，后因害怕受到制裁而将小刘送回家"}, {"letter": "C", "text": "王五盗窃财物时被主人发现当场抓获扭送至公安机关"}, {"letter": "D", "text": "丁六携带凶器抢劫时发现对方是同事后便放弃抢劫"}], "answer": "D", "explanation": "犯罪中止是指在犯罪过程中，自动放弃犯罪或者自动有效地防止犯罪结果发生。A项属于预备阶段的犯罪中止；B项拐卖妇女已既遂，送回不构成中止；C项属于犯罪未遂；D项丁六在能够完成抢劫的情况下，因认出是同事而自愿放弃，属于犯罪中止。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 397}, {"num": 399, "batch": "专业基础知识", "type": "single", "stem": "张三夜间进入他人住宅行窃，被房内主人发现，张三顺手拿起一小板凳将主人打昏。后张三携带赃物逃走，因担心主人醒后报警，又返回房中将主人打死。此案发生后，公安机关刑警大队立案侦查，下列立案正确的是（）。", "options": [{"letter": "A", "text": "立盗窃和抢劫案"}, {"letter": "B", "text": "立盗窃和故意伤害案"}, {"letter": "C", "text": "立盗窃和故意杀人案"}, {"letter": "D", "text": "立抢劫和故意杀人案"}], "answer": "D", "explanation": "张三入室盗窃被发现后使用暴力打昏主人，根据《刑法》第二百六十九条规定，转化为抢劫罪。此后张三又返回将主人打死，属于另起犯意实施故意杀人行为，应单独评价为故意杀人罪。因此应立抢劫案和故意杀人案。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 398}, {"num": 400, "batch": "专业基础知识", "type": "single", "stem": "黄某与张某因工作矛盾积怨已久，2025年7月18日，黄某得知张某当晚需在单位备勤室过夜，即放火将值班室烧毁，其结果却是将顶替张某值班的李某烧死，黄某对李某死亡的主观方面是（）。", "options": [{"letter": "A", "text": "间接故意"}, {"letter": "B", "text": "直接故意"}, {"letter": "C", "text": "疏忽大意的过失"}, {"letter": "D", "text": "过于自信的过失"}], "answer": "B", "explanation": "黄某为杀害张某而放火烧值班室，主观上具有杀害值班室内人员的直接故意。虽然实际烧死的是顶替张某值班的李某，属于对象错误（打击错误），但黄某明知放火烧房会致人死亡而积极实施，对李某的死亡主观上仍为直接故意。对象错误不影响故意犯罪的成立。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 399}, {"num": 401, "batch": "专业基础知识", "type": "single", "stem": "被害人周某与行为人吴某系婆媳关系。某日，吴某进入周某的房间，拿起周某所盖的棉被捂在其脸上，并用双手按压周某的口鼻，周某用力喊叫并试图掰开吴某的手指，吴某见周某痛苦挣扎而心生怜悯，便揭开棉被离开现场。经鉴定，周某的损伤程度为轻微伤，吴某精神正常，具有完全刑事责任能力。本案中，吴某的行为属于（）。", "options": [{"letter": "A", "text": "犯罪预备"}, {"letter": "B", "text": "犯罪未遂"}, {"letter": "C", "text": "犯罪中止"}, {"letter": "D", "text": "犯罪既遂"}], "answer": "C", "explanation": "根据《刑法》第24条，在犯罪过程中，自动放弃犯罪或者自动有效地防止犯罪结果发生的，是犯罪中止。吴某在实施犯罪过程中，见周某痛苦挣扎而心生怜悯，出于自身意志主动停止犯罪并揭开棉被离开，属于自动放弃犯罪，构成犯罪中止。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 400}, {"num": 402, "batch": "专业基础知识", "type": "single", "stem": "关于减刑以后实际执行的刑期，下列表述错误的是（）。", "options": [{"letter": "A", "text": "限制减刑的死刑缓期执行的犯罪分子，缓期执行期满后依法减为二十五年有期徒刑的，不能少于十五年"}, {"letter": "B", "text": "限制减刑的死刑缓期执行的犯罪分子，缓期执行期满后依法减为无期徒刑的，不能少于二十五年"}, {"letter": "C", "text": "判处无期徒刑的，不能少于十三年"}, {"letter": "D", "text": "判处管制、拘役、有期徒刑的，不能少于原判刑期的二分之一"}], "answer": "A", "explanation": "根据《刑法》第78条第2款，限制减刑的死刑缓期执行的犯罪分子，缓期执行期满后依法减为二十五年有期徒刑的，实际执行刑期不能少于二十年，而非十五年，故A项表述错误。B、C、D项均符合《刑法》第78条关于减刑后实际执行刑期的规定。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 401}, {"num": 403, "batch": "专业基础知识", "type": "single", "stem": "下列证据中，可以作为定案根据的是（）。", "options": [{"letter": "A", "text": "民警甲通过刑讯逼供收集的犯罪嫌疑人的供述"}, {"letter": "B", "text": "未满14周岁的证人乙提供的证言"}, {"letter": "C", "text": "鉴定资质已过期的鉴定人丙出具的鉴定意见"}, {"letter": "D", "text": "民警丁对犯罪嫌疑人讯问后未让其签名的讯问笔录"}], "answer": "B", "explanation": "A项刑讯逼供取得的供述属于非法言词证据，应当予以排除。C项鉴定资质已过期的鉴定人出具的鉴定意见不具有证据效力。D项讯问笔录未经犯罪嫌疑人签名确认，存在重大程序瑕疵。B项中，根据《刑事诉讼法》相关规定，未满14周岁的证人只要能辨别是非、正确表达，其证言可以作为证据使用，年龄并不构成绝对的排除事由。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 402}, {"num": 404, "batch": "专业基础知识", "type": "single", "stem": "周X是某高校教授，因犯罪被法院判处有期徒刑1年并被剥夺政治权利1年。根据有关规定，周X刑满释放6个月时，可以从事的是（）。", "options": [{"letter": "A", "text": "在某出版社公开出版著作"}, {"letter": "B", "text": "担任某省属科技学院副院长职务"}, {"letter": "C", "text": "继承去世亲属的遗产"}, {"letter": "D", "text": "在公园参加集会并当众发表演讲"}], "answer": "C", "explanation": "根据《刑法》第54条，剥夺政治权利包括：选举权和被选举权；言论、出版、集会、结社、游行、示威自由的权利；担任国家机关职务的权利；担任国有公司、企业、事业单位和人民团体领导职务的权利。继承权不属于政治权利范畴，因此周某在剥夺政治权利期间仍可行使继承权。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 403}, {"num": 405, "batch": "专业基础知识", "type": "single", "stem": "关于刑罚及其执行的说法，下列说法正确的是（）。", "options": [{"letter": "A", "text": "管制的期限为2个月以上3年以下，依法实行社区矫正"}, {"letter": "B", "text": "对于危害国家安全的犯罪分子可以附加剥夺政治权利"}, {"letter": "C", "text": "死刑缓期执行的，可以由高级人民法院判决或者核准"}, {"letter": "D", "text": "没收财产，由公安机关执行，必要时会同人民法院执行"}], "answer": "C", "explanation": "根据《刑法》第48条第2款，死刑缓期执行的，可以由高级人民法院判决或者核准，C项正确。A项管制期限为2个月以上3年以下正确，但现行规定由社区矫正机构执行。B项危害国家安全的犯罪分子应当（而非可以）附加剥夺政治权利。D项没收财产应由人民法院执行。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 404}, {"num": 406, "batch": "专业基础知识", "type": "single", "stem": "我国刑法关于刑法溯及力问题采取的原则是（）。", "options": [{"letter": "A", "text": "从新原则"}, {"letter": "B", "text": "从旧原则"}, {"letter": "C", "text": "从新兼从轻原则"}, {"letter": "D", "text": "从旧兼从轻原则"}], "answer": "D", "explanation": "根据《刑法》第12条，我国刑法溯及力采取从旧兼从轻原则，即原则上适用行为时的法律，但新法不认为是犯罪或者处刑较轻的，适用新法。这一原则既体现了罪刑法定原则的要求，又有利于保障被告人的合法权益。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 405}, {"num": 407, "batch": "专业基础知识", "type": "single", "stem": "赵某和孙某因遗产分配问题发生激烈争吵，赵某气愤不已，多次在家族聚会上大声宣称要找机会教训孙某，让他拿不到一分钱，并且在自己的备忘录中写下了一些威胁孙某的话语。本案中，赵某的行为属于（）。", "options": [{"letter": "A", "text": "犯罪预备"}, {"letter": "B", "text": "犯罪未遂"}, {"letter": "C", "text": "犯罪中止"}, {"letter": "D", "text": "犯意表示"}], "answer": "D", "explanation": "犯意表示是指行为人通过语言、文字等方式将内心的犯罪意图表达于外部，但尚未实施任何为犯罪准备工具、制造条件的行为。赵某仅在聚会上口头宣称威胁并在备忘录中记录，未实施任何实质性的犯罪预备行为，属于犯意表示，不构成犯罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 406}, {"num": 408, "batch": "专业基础知识", "type": "single", "stem": "出租车司机周×为多赚取车费，私自改动车内计价系统，一日，周×将王某送达后，本应收取车费130元，但周×要求王某按照计价系统显示的150元付款。王某与周×理论，被周×打了一耳光（轻微伤），王某急于上班，无意与其争执，支付其150元。另周×多次用相同手段多收取乘客打车费总计3000余元，下列选项中，对周×行为性质认定准确的是（）。", "options": [{"letter": "A", "text": "强迫交易罪"}, {"letter": "B", "text": "抢劫罪"}, {"letter": "C", "text": "寻衅滋事罪"}, {"letter": "D", "text": "敲诈勒索罪"}], "answer": "A", "explanation": "根据《刑法》第226条，强迫交易罪是指以暴力、威胁手段强买强卖商品、强迫他人提供或接受服务，情节严重的行为。周某在提供出租车服务过程中，通过改动车计价器多收费用，并以暴力手段（打耳光）强迫乘客支付不合理车费，多次实施且累计金额达3000余元，符合强迫交易罪的构成要件。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 407}, {"num": 409, "batch": "专业基础知识", "type": "single", "stem": "某日，张某故意走到白某前面掉下一叠百元大钞，同伙顾某快速上前捡起，让白某不要声张，所捡钱财二人平分。此时张某回头找到顾某和白某，称二人捡走其掉的钱，要求二人把身上的钱拿出来检查，白某将自己的400元交给张某，随后张某和顾某以到旁边巷子核查为由逃离现场，张某和顾某构成的违法行为是（）。", "options": [{"letter": "A", "text": "盗窃"}, {"letter": "B", "text": "抢夺"}, {"letter": "C", "text": "诈骗"}, {"letter": "D", "text": "招摇撞骗"}], "answer": "A", "explanation": "张某和顾某以掉钱捡钱的方式设局，通过虚构事实使白某产生错误认识，以检查身上钱财为名取得白某的400元后逃离。虽然使用了欺骗手段，但其本质是以欺骗为掩护秘密窃取他人财物，白某并非基于真实处分意愿交付财产，故构成盗窃。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 408}, {"num": 410, "batch": "专业基础知识", "type": "single", "stem": "2024年11月11日19时48分，樊某驾驶小型越野车闯闸强行进入某市体育中心，无故冲撞正在体育中心内部道路锻炼的市民，造成35人死亡43人受伤，樊某在驾车逃跑的过程中被及时赶赴现场的民警控制。樊某的行为涉嫌构成（）。", "options": [{"letter": "A", "text": "交通肇事罪"}, {"letter": "B", "text": "故意杀人罪"}, {"letter": "C", "text": "危险驾驶罪"}, {"letter": "D", "text": "以危险方法危害公共安全罪"}], "answer": "D", "explanation": "根据《刑法》第115条，以危险方法危害公共安全罪是指使用与放火、决水、爆炸等危险性相当的其他危险方法，危害公共安全的行为。樊某故意驾车闯进体育中心冲撞正在锻炼的不特定市民，造成35死43伤的严重后果，其侵害对象为不特定多数人，主观上为故意，构成以危险方法危害公共安全罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 409}, {"num": 411, "batch": "专业基础知识", "type": "single", "stem": "累犯，是指受过一定刑罚处罚，在刑罚执行完毕或者赦免以后，在法定期限内又犯被判处一定的刑罚之罪的罪犯，下列哪些情形构成累犯（）。", "options": [{"letter": "A", "text": "范某犯袭警罪被判处拘役6个月，两年后又犯故意杀人罪"}, {"letter": "B", "text": "17岁的林某犯盗窃罪被判处有期徒刑两年，出狱后第三年又犯抢劫罪"}, {"letter": "C", "text": "武某犯为境外窃取国家情报罪被判处有期徒刑3年，出狱后第十年又犯间谍罪"}, {"letter": "D", "text": "杨某犯侵占罪被判处有期徒刑1年缓期2年执行，在缓刑考验期内又犯保险诈骗罪"}], "answer": "C", "explanation": "根据《刑法》第66条，危害国家安全犯罪、恐怖活动犯罪、黑社会性质的组织犯罪的犯罪分子，在刑罚执行完毕或者赦免以后，在任何时候再犯上述任一类罪的，都以累犯论处（特别累犯）。武某前罪为境外窃取国家情报罪和后罪间谍罪均属危害国家安全犯罪，构成特别累犯，不受5年期限限制。A项前罪为拘役不符合累犯条件；B项犯罪时未满18周岁不构成累犯；D项缓刑考验期内犯新罪应撤销缓刑数罪并罚，不构成累犯。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 410}, {"num": 412, "batch": "专业基础知识", "type": "single", "stem": "张某、王某二人共谋盗窃一别墅，二人购买了匕首、绳索等工具后于某日凌晨通过翻墙的方式进入该别墅，由于别墅面积较大，二人商议分头行动，张某在别墅一楼保险柜内盗窃了黄金首饰若干后离开别墅，王某在别墅二楼卧室内看到一熟睡女子，欲强奸该女子，用绳索将该女子捆绑后实施侵害行为，并在该女子挣扎反抗时用匕首刺了一刀，强奸后将卧室内现金10万元盗走。关于本案，下列说法正确的是（）。", "options": [{"letter": "A", "text": "张某、王某构成盗窃罪、强奸罪的共同犯罪"}, {"letter": "B", "text": "张某构成盗窃罪，王某构成盗窃罪、强奸罪"}, {"letter": "C", "text": "王某构成盗窃罪、强奸罪、故意伤害罪"}, {"letter": "D", "text": "张某、王某构成盗窃罪、故意伤害罪、强奸罪的共同犯罪"}], "answer": "B", "explanation": "张某和王某共谋盗窃并进入别墅，在盗窃罪范围内构成共同犯罪。但王某临时起意强奸熟睡女子，属于超出共同犯罪故意的实行过限行为，张某对此不承担刑事责任。王某在强奸过程中用匕首刺伤被害人属于强奸罪的暴力手段，被强奸罪吸收，不另成立故意伤害罪。王某强奸后取走现金10万元另构成盗窃罪。因此张某构成盗窃罪，王某构成盗窃罪和强奸罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 411}, {"num": 413, "batch": "专业基础知识", "type": "single", "stem": "下列哪一行为应该以危险驾驶罪论处？（）", "options": [{"letter": "A", "text": "甲醉酒驾驶机动车，误将红灯看成绿灯，撞死两名行人"}, {"letter": "B", "text": "乙吸食毒品后驾驶机动车，精神恍惚，但未造成事故"}, {"letter": "C", "text": "丙在驾驶汽车前吃了大量荔枝，被酒精检测仪测试到酒精含量达到90mg/100ml"}, {"letter": "D", "text": "丁醉酒后将汽车从商场地下三层开到地下一层"}], "answer": "D", "explanation": "根据《刑法》第133条之一，危险驾驶罪包括醉酒驾驶机动车等情形。D项丁醉酒后将汽车从地下三层开到地下一层，属于在道路上醉酒驾驶机动车，构成危险驾驶罪。A项醉驾致人死亡已构成交通肇事罪或以危险方法危害公共安全罪；B项毒驾尚未纳入危险驾驶罪；C项吃荔枝产生的酒精不属于真正醉酒。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 412}, {"num": 414, "batch": "专业基础知识", "type": "single", "stem": "下列属于正当防卫的是（）。", "options": [{"letter": "A", "text": "甲正在强奸乙，乙顺手用旁边的水果刀将甲捅死"}, {"letter": "B", "text": "甲强奸了乙，一周后乙将甲毒死"}, {"letter": "C", "text": "甲用刀将乙划伤，不久乙叫来丙一起将甲殴打致重伤"}, {"letter": "D", "text": "甲殴打乙，乙恼羞成怒用砖头击打甲头部，甲倒地不起，乙继续击打数十下致甲死亡"}], "answer": "A", "explanation": "根据《刑法》第20条第3款，对正在进行行凶、杀人、抢劫、强奸、绑架以及其他严重危及人身安全的暴力犯罪，采取防卫行为造成不法侵害人伤亡的，不属于防卫过当，不负刑事责任（特殊防卫/无限防卫权）。A项乙在甲正在实施强奸时将其捅死，符合特殊防卫条件。B项不法侵害已结束，属事后报复；C、D项均不符合正当防卫的时间条件和限度条件。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 413}, {"num": 415, "batch": "专业基础知识", "type": "single", "stem": "下列情形中，行为人构成累犯的是（）。", "options": [{"letter": "A", "text": "甲因组织传销罪被判处有期徒刑五年，刑罚执行完毕后第六年又犯参与恐怖活动组织罪"}, {"letter": "B", "text": "乙因危险驾驶罪被判处拘役五个月，刑罚执行完毕后第二年犯故意伤害罪被判一年有期徒刑"}, {"letter": "C", "text": "丙十七周岁时因盗窃被判处有期徒刑两年，刑罚执行完毕后第三年又因盗窃被判两年有期徒刑"}, {"letter": "D", "text": "丁因叛逃罪被判处有期徒刑四年，刑罚执行完毕后第八年又因间谍罪被判五年有期徒刑"}], "answer": "D", "explanation": "根据《刑法》第66条，危害国家安全犯罪的犯罪分子在刑罚执行完毕后任何时候再犯危害国家安全犯罪的，以累犯论处（特别累犯）。丁前罪叛逃罪和后罪间谍罪均属危害国家安全犯罪，构成特别累犯。A项前罪组织传销罪不属于三类特定犯罪，且已过5年期限；B项前罪为拘役不符合累犯条件；C项犯罪时未满18周岁不构成累犯。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 414}, {"num": 416, "batch": "专业基础知识", "type": "single", "stem": "田某因贩卖毒品被法院判处无期徒刑，在执行一定的刑罚期间后，田某欲申请假释，下列说法不正确的是（）。", "options": [{"letter": "A", "text": "需实际执行刑期十五年以上，才能对田某进行假释"}, {"letter": "B", "text": "对田某的假释考验期间为十年"}, {"letter": "C", "text": "田某在假释期间又贩卖毒品，应撤销假释，数罪并罚"}, {"letter": "D", "text": "在假释考验期间，对田某依法实行社区矫正"}], "answer": "A", "explanation": "根据《刑法》第81条第3款，对累犯以及因故意杀人、强奸、抢劫、绑架、放火、爆炸、投放危险物质或者有组织的暴力性犯罪被判处十年以上有期徒刑、无期徒刑的犯罪分子，不得假释。贩卖毒品被判处无期徒刑属于毒品犯罪严重情形，根据相关司法解释不得假释。A项称需实际执行15年以上才能假释本身表述也不正确（无期徒刑假释一般需实际执行13年以上），故A项说法不正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 415}, {"num": 417, "batch": "专业基础知识", "type": "single", "stem": "赵某为降低成本，组织公司人员驾驶运送过消毒水且并未清洗干净的运货车，运送一批散装饮料并分装销售（消毒水中的残留成分为国家明令禁止向饮料添加的物质），流入市场致使大量市民中毒。对于赵某的行为认定，以下选择正确的是（）。", "options": [{"letter": "A", "text": "赵某构成非法经营罪"}, {"letter": "B", "text": "赵某构成破坏生产经营罪"}, {"letter": "C", "text": "赵某构成生产、销售有毒有害食品罪"}, {"letter": "D", "text": "赵某构成生产、销售不符合安全标准的食品罪"}], "answer": "C", "explanation": "根据《刑法》第144条，在生产、销售的食品中掺入有毒、有害的非食品原料的，或者销售明知掺有有毒、有害的非食品原料的食品的，构成生产、销售有毒、有害食品罪。赵某使用运送过消毒水的车辆运送散装饮料，消毒水中含有国家明令禁止添加的物质，流入市场致人中毒，符合该罪构成要件。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 416}, {"num": 418, "batch": "专业基础知识", "type": "single", "stem": "某日，甲（15周岁）遇到朋友乙（17周岁），乙说自己想买台“便宜点”的电脑，看甲能不能从隔壁学校偷出一台卖给自己。甲表示同意并翻墙进入学校，在办公室内偷得笔记本电脑一台（价值8千元）。甲将笔记本电脑交给乙，乙给甲人民币2千元。下列说法正确的是（）。", "options": [{"letter": "A", "text": "对甲和乙均以盗窃罪追究刑事责任"}, {"letter": "B", "text": "对甲以盗窃罪追究刑事责任，对乙以掩饰、隐瞒犯罪所得罪追究刑事责任"}, {"letter": "C", "text": "甲不负刑事责任，对乙以盗窃罪和掩饰、隐瞒犯罪所得罪追究刑事责任"}, {"letter": "D", "text": "甲不负刑事责任，对乙以盗窃罪追究刑事责任"}], "answer": "D", "explanation": "根据《刑法》第17条，已满14周岁不满16周岁的人仅对故意杀人、故意伤害致人重伤或死亡、强奸、抢劫、贩卖毒品、放火、爆炸、投放危险物质八种犯罪负刑事责任。甲15周岁，盗窃不在八种犯罪之列，不负刑事责任。乙17周岁具有完全刑事责任能力，指使未达刑事责任年龄的甲实施盗窃，构成盗窃罪的间接正犯，应以盗窃罪追究刑事责任。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 417}, {"num": 419, "batch": "专业基础知识", "type": "single", "stem": "关于犯罪故意形态，下列说法不正确的是（）。", "options": [{"letter": "A", "text": "甲在蹲点过程中，想到其母亲以前的教诲，便放弃盗窃念头成立犯罪中止"}, {"letter": "B", "text": "乙对一女子实施奸淫时发现该女子系男子假扮，无法完成奸淫行为，成立犯罪未遂"}, {"letter": "C", "text": "丙以出卖为目的偷盗了一名婴儿，后因无法找到买家又将该婴儿送回成立犯罪中止"}, {"letter": "D", "text": "丁因对火车的轰鸣声不满，遂在铁轨上放置巨石泄愤，成立犯罪既遂"}], "answer": "C", "explanation": "根据《刑法》第240条，以出卖为目的偷盗婴幼儿的，构成拐卖儿童罪且已既遂。犯罪一旦既遂，不可能再成立犯罪中止。丙偷盗婴儿后送回的行为属于既遂后的悔罪表现，可作为量刑情节考虑，但不成立犯罪中止。A项属预备阶段的中止；B项属对象不能犯的未遂；D项破坏交通设施罪为危险犯，放置巨石足以造成危险即为既遂。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 418}, {"num": 420, "batch": "专业基础知识", "type": "single", "stem": "卞某某（20岁）按其父要求提供大麻种子，由其父在工厂宿舍及家中种植出大麻后，再由卞某某通过微信向他人贩卖。卞某某还建立专门用于大麻买卖及种植经验交流的微信群，发布大量有关大麻种植技术及大麻制品的信息。关于卞某某的行为，下列说法正确的是（）。", "options": [{"letter": "A", "text": "卞某某构成制造、贩卖毒品罪和非法利用信息网络罪"}, {"letter": "B", "text": "因卞父并不了解大麻的危害、故卞某某和其父不构成共同犯罪"}, {"letter": "C", "text": "因微信属于合法通讯工具，故卞某某不构成非法利用信息网络罪"}, {"letter": "D", "text": "卞某某同时构成制造、贩卖毒品罪和非法利用信息网络罪，应按照想象竞合犯的规则定罪量刑"}], "answer": "D", "explanation": "卞某某种植并贩卖大麻，构成制造、贩卖毒品罪。同时建立微信群发布大量大麻种植技术及大麻制品信息，构成非法利用信息网络罪。两罪侵犯不同法益，行为相互独立，应数罪并罚。卞父不了解大麻危害缺乏犯罪故意，不构成共犯。两罪属于独立犯罪行为，不适用想象竞合犯从一重处断的规则。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 419}, {"num": 421, "batch": "专业基础知识", "type": "single", "stem": "在一次破获赌博案件的过程中，参赌人员程某对正在依法执行职务的警察小王实施暴力袭击，被小王当场制服，程某的行为构成（）。", "options": [{"letter": "A", "text": "故意伤害罪"}, {"letter": "B", "text": "妨害公务罪"}, {"letter": "C", "text": "寻衅滋事罪"}, {"letter": "D", "text": "袭警罪"}], "answer": "D", "explanation": "根据《刑法》第277条第5款（刑法修正案十一新增），暴力袭击正在依法执行职务的人民警察的，构成袭警罪。程某对正在依法执行职务的警察小王实施暴力袭击，符合袭警罪的构成要件。袭警罪是从妨害公务罪中独立出来的罪名，专门保护依法执行职务的人民警察。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 420}, {"num": 422, "batch": "专业基础知识", "type": "single", "stem": "下列属于犯罪未遂的是（）。", "options": [{"letter": "A", "text": "甲购买毒药放置在书柜准备杀死室友，因学校检查寝室而被发现"}, {"letter": "B", "text": "乙欲入室盗窃，因撬不开门被保安当场抓获"}, {"letter": "C", "text": "丙绑架了赵某并要求其亲属交付100万元，但其亲属拒不支付赎金"}, {"letter": "D", "text": "丁携带凶器抢劫时发现对方是朋友后扭头便走"}], "answer": "B", "explanation": "根据《刑法》第23条，已经着手实行犯罪，由于犯罪分子意志以外的原因而未得逞的，是犯罪未遂。B项乙已经着手实施入室盗窃（撬门），因撬不开门这一意志以外的原因未能得逞，构成犯罪未遂。A项购买毒药属犯罪预备；C项绑架已完成属犯罪既遂；D项发现是朋友后主动离开属犯罪中止。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 421}, {"num": 423, "batch": "专业基础知识", "type": "single", "stem": "隆某通过微信与他人联系，明知对方系用于实施信息网络犯罪，仍以每张每月100元的价格将自己的9张银行卡出租给对方使用，对方将其用于接收电信网络诈骗等犯罪资金，隆某获利共计6000元。隆某的行为应认定为（）。", "options": [{"letter": "A", "text": "诈骗罪"}, {"letter": "B", "text": "非法利用信息网络罪"}, {"letter": "C", "text": "帮助信息网络犯罪活动罪"}, {"letter": "D", "text": "掩饰、隐瞒犯罪所得、犯罪所得收益罪"}], "answer": "C", "explanation": "根据《刑法》第287条之二，明知他人利用信息网络实施犯罪，为其犯罪提供支付结算等帮助，情节严重的，构成帮助信息网络犯罪活动罪。隆某明知对方用于网络犯罪仍出租银行卡，获利6000元，符合该罪构成要件。隆某未直接参与诈骗不构成诈骗罪共犯，也未实施掩饰隐瞒犯罪所得的行为。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 422}, {"num": 424, "batch": "专业基础知识", "type": "single", "stem": "下列行为属于抢劫罪加重情形的是（）。", "options": [{"letter": "A", "text": "赵某抢劫李某后，为了灭口使用暴力致其死亡"}, {"letter": "B", "text": "周某被某银行辞退后为泄愤抢劫前来办理储蓄业务的李某所携带的50万元"}, {"letter": "C", "text": "孙某3年内在城际客运列车上连续实施了2次抢劫行为"}, {"letter": "D", "text": "冯某携带管制刀具暴力抢夺路人财物"}], "answer": "C", "explanation": "根据《刑法》第263条，在公共交通工具上抢劫属于抢劫罪的加重情形之一。C项孙某在城际客运列车上实施抢劫，城际客运列车属于公共交通工具，符合加重情形。A项抢劫后灭口应以抢劫罪和故意杀人罪数罪并罚；B项抢劫个人财物不属于抢劫银行；D项携带凶器抢夺直接以抢劫罪论处（第267条第2款），不属于第263条的加重情形。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 423}, {"num": 425, "batch": "专业基础知识", "type": "single", "stem": "段某驾驶自己的智能网联汽车外出，中途下车买烟，未锁车。张某（17岁）路过，趁机将车盗走。段某发现汽车不见后，立即打开手机定位车辆位置，并借烟酒店的摩托车追赶张某，张某发现后驾车将段某撞成轻伤。关于张某的行为定性，下列说法正确的是（）。", "options": [{"letter": "A", "text": "张某构成抢夺罪"}, {"letter": "B", "text": "张某构成盗窃罪"}, {"letter": "C", "text": "张某构成抢劫罪"}, {"letter": "D", "text": "张某构成故意伤害罪"}], "answer": "C", "explanation": "根据《刑法》第269条，犯盗窃罪，为抗拒抓捕而当场使用暴力的，依照抢劫罪定罪处罚（转化型抢劫）。张某盗窃汽车后，段某追赶过程中，张某为抗拒抓捕驾车将段某撞成轻伤，属于当场使用暴力，其行为由盗窃罪转化为抢劫罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 424}, {"num": 426, "batch": "专业基础知识", "type": "single", "stem": "郑某系网络工程师，其开发了“拿钱来”软件，将该软件发布在网络上供免费下载。其本人使用该软件向何某等人自动发送诈骗信息8000余条，但未诈骗到钱财。下列关于郑某的行为，说法正确的是（）。", "options": [{"letter": "A", "text": "构成诈骗罪"}, {"letter": "B", "text": "构成诈骗治安违法行为"}, {"letter": "C", "text": "构成非法经营罪"}, {"letter": "D", "text": "构成帮助信息网络犯罪活动罪"}], "answer": "A", "explanation": "根据《刑法》第266条及相关司法解释，利用电信技术手段实施诈骗，发送诈骗信息5000条以上的，即使未骗得财物，也以诈骗罪（未遂）追究刑事责任。郑某使用软件发送诈骗信息8000余条，已达到诈骗罪追诉标准。郑某本人直接实施了诈骗行为，而非仅提供信息帮助，故构成诈骗罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 425}, {"num": 427, "batch": "专业基础知识", "type": "single", "stem": "甲见乙一个人在饭店喝醉，便与服务员说自己是乙的朋友，假装照顾乙，将其手腕上的名表摘下带走，离开饭店。甲构成的罪名是（）。", "options": [{"letter": "A", "text": "抢劫罪"}, {"letter": "B", "text": "盗窃罪"}, {"letter": "C", "text": "诈骗罪"}, {"letter": "D", "text": "侵占罪"}], "answer": "B", "explanation": "甲假装是乙的朋友，趁乙醉酒不知反抗之际，秘密将乙的名表取走带走。乙并未基于错误认识主动处分财产，甲取得财物的方式是秘密窃取而非诈骗，符合盗窃罪的构成要件。甲的行为也不具有暴力胁迫特征，不构成抢劫罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 426}, {"num": 428, "batch": "专业基础知识", "type": "single", "stem": "甲欲杀死仇人乙，于是在乙的汽车（价值50万）车底安装了定时炸弹，并设定在早上9时引爆。次日，炸弹在乙驾车上班途中爆炸，结果不仅炸死了乙，同时还炸死了同车的丙和路人丁。甲的行为构成（）。", "options": [{"letter": "A", "text": "爆炸罪"}, {"letter": "B", "text": "故意杀人罪"}, {"letter": "C", "text": "故意毁坏财物罪"}, {"letter": "D", "text": "故意杀人罪和故意毁坏财物罪"}], "answer": "A", "explanation": "甲在汽车上安装定时炸弹，虽然目标是乙，但炸弹爆炸不仅炸死乙，还炸死同车丙和路人丁，其行为危害了不特定多数人的生命安全和公私财产安全，构成爆炸罪。甲使用爆炸方法杀人同时触犯故意杀人罪和爆炸罪，属于想象竞合，应择一重罪以爆炸罪论处。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 427}, {"num": 429, "batch": "专业基础知识", "type": "single", "stem": "下列关于拘役的说法不正确的是（）。", "options": [{"letter": "A", "text": "拘役的期限，为一个月以上六个月以下"}, {"letter": "B", "text": "被判处拘役的犯罪分子，由公安机关就近执行"}, {"letter": "C", "text": "在执行期间，被判处拘役的犯罪分子每月可以回家一周；参加劳动的，可以酌量发给报酬"}, {"letter": "D", "text": "拘役的刑期，从判决执行之日起计算；判决执行以前先行羁押的，羁押一日折抵刑期一日"}], "answer": "C", "explanation": "根据《刑法》第43条，被判处拘役的犯罪分子在执行期间每月可以回家一至二天（而非一周），参加劳动的可以酌量发给报酬。C项将回家时间说成一周是错误的。A项拘役期限为1个月以上6个月以下正确；B项由公安机关就近执行正确；D项刑期计算和折抵规定正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 428}, {"num": 430, "batch": "专业基础知识", "type": "single", "stem": "王某与其妻子去日本游玩，由于行驶路线等问题发生了争吵，于是在二人爬山时，王某将妻子推下山崖摔死，王某被日本法院判处有期徒刑15年。15年后王某回国，请问我国法院依据哪个管辖权原则可以追究王某的刑事责任？（）", "options": [{"letter": "A", "text": "属地原则"}, {"letter": "B", "text": "属人原则"}, {"letter": "C", "text": "保护原则"}, {"letter": "D", "text": "我国法院不可再追究其刑事责任"}], "answer": "B", "explanation": "根据《刑法》第7条（属人管辖原则），中华人民共和国公民在中华人民共和国领域外犯本法规定之罪的，适用本法。王某是中国公民，在日本犯故意杀人罪，我国法院依据属人原则可以追究其刑事责任。即使已在外国受过刑罚处罚，仍可依法追究，但可以免除或减轻处罚。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 429}, {"num": 431, "batch": "专业基础知识", "type": "single", "stem": "张三因故意杀人被判10年有期徒刑，出狱后的第三年因手头紧张，便盗窃邻居财物10万元，事后害怕被追究，便主动去派出所自首后被判处有期徒刑3年，根据该案件，下列表述正确的是（）。", "options": [{"letter": "A", "text": "张三的盗窃行为属于犯罪未遂"}, {"letter": "B", "text": "张三的盗窃罪属于告诉才处理的犯罪"}, {"letter": "C", "text": "张三构成一般累犯"}, {"letter": "D", "text": "对张三不得适用减刑和假释"}], "answer": "C", "explanation": "根据《刑法》第65条，被判处有期徒刑以上刑罚的犯罪分子，刑罚执行完毕后5年以内再犯应当判处有期徒刑以上刑罚之罪的，构成一般累犯。张三前罪故意杀人被判10年有期徒刑，出狱后第3年又犯盗窃罪（应判有期徒刑），符合累犯的全部条件。A项盗窃已完成属既遂；B项盗窃罪非告诉才处理；D项累犯不得假释但可以减刑。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 430}, {"num": 432, "batch": "专业基础知识", "type": "single", "stem": "赵某住在某小区二楼，多次在室内直接或以“飞线”的方式给家人的电动自行车蓄电池充电。一日，赵某在屋内阳台再次给蓄电池充电，蓄电池发生爆炸继而引发火灾，致使居住在赵某楼上的夏某某等5人被烧死或一氧化碳中毒死亡，并造成楼道、外墙和室内财物等火灾损失共计人民币9万8千余元。赵某在灭火未果的情况下报警，后在现场被民警传唤至公安机关接受审查。赵某主观方面的罪过形式是（）。", "options": [{"letter": "A", "text": "直接故意"}, {"letter": "B", "text": "间接故意"}, {"letter": "C", "text": "疏忽大意的过失"}, {"letter": "D", "text": "过于自信的过失"}], "answer": "C", "explanation": "赵某多次违规充电应当预见到可能引发火灾的危险，但因疏忽大意没有预见，最终蓄电池爆炸引发火灾致5人死亡。赵某主观上不希望也不放任结果发生，属于应当预见而没有预见的疏忽大意的过失。如果是已经预见但轻信能够避免则属于过于自信的过失，本案中无证据表明赵某已经预见。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 431}, {"num": 433, "batch": "专业基础知识", "type": "single", "stem": "贺某因盗窃被逮捕，公安机关在法定的2个月的侦查羁押期限内没有对案件侦查终结，本案又不存在延长羁押期限的法定情形，公安机关应当（）", "options": [{"letter": "A", "text": "对贺某予以释放，需要继续查证的，可以对贺某取保候审或者监视居住"}, {"letter": "B", "text": "找理由申请延长期限，以免超期办案"}, {"letter": "C", "text": "重新向人民检察院申请批准逮捕"}, {"letter": "D", "text": "建议人民检察院对贺某作出不起诉的决定"}], "answer": "A", "explanation": "根据《刑事诉讼法》第98条，犯罪嫌疑人被逮捕后，侦查羁押期限届满不能终结案件，且不存在延长羁押期限法定情形的，应当对犯罪嫌疑人予以释放。需要继续查证侦查的，可以变更强制措施为取保候审或监视居住。公安机关不能找理由超期办案。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 432}, {"num": 434, "batch": "专业基础知识", "type": "single", "stem": "公安机关对符合法律规定的被拘留重大嫌疑分子，提请审查批准逮捕的时间可以延长至30日。下列符合延长至30日要求的是（）", "options": [{"letter": "A", "text": "甲、乙二人共同作案，甲被取保候审，有毁灭、伪造证据或者串供可能的"}, {"letter": "B", "text": "不讲真实姓名、住址，身份不明的"}, {"letter": "C", "text": "流窜作案、多次作案、结伙作案的"}, {"letter": "D", "text": "故意犯罪的"}], "answer": "C", "explanation": "根据《刑事诉讼法》第91条第3款，对于流窜作案、多次作案、结伙作案的重大嫌疑分子，提请审查批准逮捕的时间可以延长至30日。这是法律明确规定的三种可以延长至30日的情形。A项取保候审人员不属于此范围；B项身份不明不是延长提捕时间的法定理由。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 433}, {"num": 435, "batch": "专业基础知识", "type": "single", "stem": "刘某因涉嫌盗窃，被甲县公安机关刑事拘留，在拘留期间被提请逮捕后，甲县人民检察院对刘某作出了不批准逮捕的决定，甲县公安机关应当（）", "options": [{"letter": "A", "text": "继续羁押犯罪嫌疑人"}, {"letter": "B", "text": "羁押至期限届满再释放犯罪嫌疑人"}, {"letter": "C", "text": "对不批准逮捕决定向人民检察院要求复议或提请复核期间，继续羁押犯罪嫌疑人"}, {"letter": "D", "text": "立即释放，对于需要继续侦查，并且符合取保候审、监视居住条件的，依法取保候审或者监视居住"}], "answer": "D", "explanation": "根据《刑事诉讼法》第92条，公安机关对人民检察院不批准逮捕的决定认为有错误的可以要求复议，但必须立即释放被拘留人。需要继续侦查且符合取保候审、监视居住条件的，依法变更强制措施。不能以复议或复核为由继续羁押。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 434}, {"num": 436, "batch": "专业基础知识", "type": "single", "stem": "下列关于侦查羁押期限的说法错误的是（）", "options": [{"letter": "A", "text": "对犯罪嫌疑人逮捕后的侦查羁押期限一般不得超过2个月????"}, {"letter": "B", "text": "案情复杂，2个月侦查羁押期限届满不能终结的案件，经省、自治区、直辖市人民检察院批准，可以延长1个月"}, {"letter": "C", "text": "对于重大的犯罪集团案件，经省、自治区、直辖市人民检察院批准，可以延长2个月"}, {"letter": "D", "text": "在侦查期间，发现犯罪嫌疑人另有重要罪行的，应当自发现之日起5日内报县级以上公安机关负责人批准后，重新计算侦查羁押期限"}], "answer": "B", "explanation": "根据《刑事诉讼法》第156条，案情复杂、期限届满不能终结的案件，经上一级人民检察院批准可以延长1个月。B项表述为经省、自治区、直辖市人民检察院批准是错误的，应为上一级人民检察院（可能是市级检察院）。A项一般不超过2个月正确；C项重大犯罪集团案件经省级检察院批准可延长2个月正确；D项发现另有重要罪行重新计算期限正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 435}, {"num": 437, "batch": "专业基础知识", "type": "single", "stem": "王某在某市敲诈勒索他人，数额较大，被公安机关抓获并监视居住，后被法院判处有期徒刑。关于公安机关执行监视居住的说法错误的是（）", "options": [{"letter": "A", "text": "在监视居住期间可以对王某进行电子监控、不定期检查"}, {"letter": "B", "text": "在侦查期间可以对王某的网络进行监控"}, {"letter": "C", "text": "在监视居住期间与任何人会见、通信都必须经过公安机关的同意"}, {"letter": "D", "text": "在监视居住期间未经公安机关批准，不得离开执行监视居住的处所"}], "answer": "C", "explanation": "根据《刑事诉讼法》第77条，被监视居住人未经执行机关批准不得会见他人或者通信，但与同住的家庭成员和聘请的律师会见通信不需要经过批准。C项称与任何人会见通信都必须经过公安机关同意，表述过于绝对，不符合法律规定。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 436}, {"num": 438, "batch": "专业基础知识", "type": "single", "stem": "甲、乙、丙三人流窜全国，在北京、河北等省、市制造了多起抢劫杀人案，成为公安部督办的重大复杂案件。之后，北京市某区警方将三人抓获并依法刑事拘留，后经批准三人被依法逮捕。下列关于侦查羁押期限的说法错误的是（）", "options": [{"letter": "A", "text": "在侦查期间，发现另有重要罪行的，侦查羁押期限重新计算"}, {"letter": "B", "text": "逮捕后的侦查羁押期限不得超过2个月"}, {"letter": "C", "text": "因本案是流窜作案的重大复杂案件，不能在侦查羁押期限内侦查终结，可以直接经北京市人民检察院批准延长2个月"}, {"letter": "D", "text": "如三人不讲真实姓名、住址，身份不明的，侦查羁押期限自查清其身份之日起计算"}], "answer": "C", "explanation": "根据《刑事诉讼法》第156条至第158条，流窜作案的重大复杂案件应在一般延长期限（经上一级检察院批准延长1个月）届满后，经省级检察院批准再延长2个月，而非直接经北京市检察院批准延长2个月。C项跳过了第一次延长程序，表述错误。A、B、D项均符合法律规定。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 437}, {"num": 439, "batch": "专业基础知识", "type": "single", "stem": "对于下列刑事案件，公安机关经过严格的批准手续，可以采取技术侦查措施的是（）", "options": [{"letter": "A", "text": "王某，38岁，我国台湾地区人，利用其台商身份在我国大陆搜集军事、经济情报向国外情报机构出售"}, {"letter": "B", "text": "吕某无中生有，对县长造谣中伤，情节严重"}, {"letter": "C", "text": "某公司董事长张某非法侵占其朋友的巨额资产"}, {"letter": "D", "text": "戴某交通肇事后逃逸，致两人重伤"}], "answer": "A", "explanation": "根据《刑事诉讼法》第150条，技术侦查措施适用于危害国家安全犯罪、恐怖活动犯罪、黑社会性质的组织犯罪、重大毒品犯罪等重大犯罪案件。A项王某涉嫌为境外搜集情报出售，属于危害国家安全犯罪，可以适用技术侦查措施。B项诽谤罪、C项非法侵占罪、D项交通肇事罪均不属于技术侦查适用范围。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 438}, {"num": 440, "batch": "专业基础知识", "type": "single", "stem": "某县公安局禁毒大队经依法批准，在对重大毒品犯罪嫌疑人李某的通话进行监听时，获悉了其贩卖毒品20公斤的信息，并将有关录音资料作为证明李某贩卖毒品罪的证据使用。下列说法错误的是（）", "options": [{"letter": "A", "text": "该录音资料不能直接用作证据"}, {"letter": "B", "text": "批准监听的法律文书自签发之日起3个月内有效"}, {"letter": "C", "text": "批准监听的法律文书应当附卷"}, {"letter": "D", "text": "在审查起诉阶段辩护律师可以查阅批准监听的法律文书"}], "answer": "A", "explanation": "根据《刑事诉讼法》第154条，依照技术侦查措施规定收集的材料在刑事诉讼中可以作为证据使用，无需转化。A项称录音资料不能直接用作证据是错误的。B项批准监听的法律文书自签发之日起3个月内有效正确；C项应当附卷正确；D项辩护律师在审查起诉阶段可以查阅相关文书正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 439}, {"num": 441, "batch": "专业基础知识", "type": "single", "stem": "下列案件中，犯罪嫌疑人真诚悔罪，并赔偿损失，被害人自愿和解，可以适用刑事和解的是（）", "options": [{"letter": "A", "text": "甲、乙二人在聚会时酒后发生争执，乙将手中酒瓶砸向甲的头部，将甲打成轻伤"}, {"letter": "B", "text": "王某在杜某的生日宴会上，趁众人不注意时将杜某刚收到的生日礼物（一部价值4000元的苹果手机）偷走，杜某报案后，王某被公安机关抓获"}, {"letter": "C", "text": "3年前，李某因盗窃罪被判处了2年有期徒刑，现李某又因家庭矛盾将自己的岳父打成轻伤"}, {"letter": "D", "text": "某日深夜，华某开车经过一个十字路口时因闯红灯将一老人撞倒在地，后逃逸致老人未得到及时救治而死亡"}], "answer": "A", "explanation": "根据《刑事诉讼法》第288条，刑事和解适用于因民间纠纷引起的涉嫌刑法分则第四章、第五章规定的犯罪案件（可能判处3年以下有期徒刑），以及除渎职犯罪以外的过失犯罪案件（可能判处7年以下有期徒刑）。但犯罪嫌疑人5年内曾经故意犯罪的不得适用。A项属于民间纠纷引起的故意伤害（轻伤），符合和解条件。B项盗窃不属于民间纠纷引起；C项李某3年前因故意犯罪被判刑，5年内再犯不得适用；D项交通肇事逃逸致人死亡可能判处7年以上，超出过失犯罪和解的刑期范围。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 440}, {"num": 442, "batch": "专业基础知识", "type": "single", "stem": "某犯罪嫌疑人正在实施盗窃时被公安机关抓获，到案后，此人不讲真实姓名、住址，公安机关（）", "options": [{"letter": "A", "text": "不必调查其身份，只要犯罪事实清楚，证据确实、充分，即可移送起诉"}, {"letter": "B", "text": "查不清其身份，就不必向下进行诉讼程序"}, {"letter": "C", "text": "确实无法查明其身份的即可停止侦查"}, {"letter": "D", "text": "应当对其身份进行调查，但是不得停止对其犯罪行为的侦查取证"}], "answer": "D", "explanation": "根据《刑事诉讼法》第160条，犯罪嫌疑人不讲真实姓名、住址，身份不明的，应当对其身份进行调查，侦查羁押期限自查清其身份之日起计算，但不得停止对其犯罪行为的侦查取证。犯罪事实清楚，证据确实、充分的，可以按其自报的姓名移送人民检察院审查起诉。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 441}, {"num": 443, "batch": "专业基础知识", "type": "single", "stem": "朱某被判处有期徒刑，在交付执行前人民法院决定对朱某暂予监外执行。朱某在暂予监外执行期间严重违反有关监督管理规定，被决定收监执行。后朱某脱逃。以下说法正确的是（）", "options": [{"letter": "A", "text": "对朱某暂予监外执行由公安机关负责"}, {"letter": "B", "text": "对朱某予以收监执行的决定应当由公安机关征求人民法院同意后作出"}, {"letter": "C", "text": "人民法院决定对朱某暂予监外执行前，应当征求监狱或者看守所同意"}, {"letter": "D", "text": "由公安机关负责对朱某进行追捕"}], "answer": "D", "explanation": "根据《刑事诉讼法》第268条，暂予监外执行由交付执行的人民法院决定。对于脱逃的暂予监外执行罪犯，由公安机关负责追捕。A项暂予监外执行由人民法院决定而非公安机关；B项收监决定由人民法院直接作出；C项法院决定前无需征求监狱或看守所同意。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 442}, {"num": 444, "batch": "专业基础知识", "type": "single", "stem": "公安机关在办理一起聚众斗殴案件过程中，发现现场处于一家单位安装的监控设备覆盖范围内，并了解到该单位的监控设备运行正常，侦查人员决定到该单位调取视频资料。下列说法错误的是（）", "options": [{"letter": "A", "text": "应当告知该单位必须如实提供证据"}, {"letter": "B", "text": "调取证据应当经办案部门负责人批准"}, {"letter": "C", "text": "应当开具调取证据通知书"}, {"letter": "D", "text": "采用录音或者录像等方式固定取证过程，可不制作提取笔录和清单"}], "answer": "D", "explanation": "根据《公安机关办理刑事案件程序规定》，调取证据应当经办案部门负责人批准，开具调取证据通知书，告知有关单位如实提供证据。采用录音录像等方式固定取证过程的，仍应当制作提取笔录和清单，不能以录音录像替代笔录和清单。D项说法错误。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 443}, {"num": 445, "batch": "专业基础知识", "type": "single", "stem": "下列案例中的相关材料，不能在刑事诉讼中作为证据使用的是（）", "options": [{"letter": "A", "text": "某公安机关在侦查一起杀人案件时，犯罪嫌疑人王某拒不承认犯罪事实，后公安机关对其进行测谎实验，获得其说谎的测谎结论"}, {"letter": "B", "text": "某行政机关在行政执法过程中收集的电子数据"}, {"letter": "C", "text": "在一起毒品犯罪案件的审理中没有公开证人真实姓名的证人证言"}, {"letter": "D", "text": "某地公安机关在侦破一起毒品犯罪时，“卧底”获取的有关犯罪材料"}], "answer": "A", "explanation": "测谎结论不属于我国刑事诉讼法规定的法定证据种类，不能作为刑事诉讼中的证据使用。B项行政机关在行政执法中收集的电子数据经审查可以作为刑事证据使用；C项不公开证人真实姓名属于证人保护措施，不影响证据效力；D项卧底获取的材料经合法批准程序可以作为证据使用。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 444}, {"num": 446, "batch": "专业基础知识", "type": "single", "stem": "犯罪嫌疑人赵某因涉嫌非法经营罪被刑事拘留，赵某的妻子于当日委托律师刘某作为赵某的辩护人。有关刘某会见赵某的说法正确的是（）", "options": [{"letter": "A", "text": "刘某会见赵某应当经侦查机关批准"}, {"letter": "B", "text": "刘某向看守所提出会见赵某的要求时，看守所必须无条件立即安排会见"}, {"letter": "C", "text": "刘某提出会见要求的，侦查机关应当在24小时内安排会见"}, {"letter": "D", "text": "刘某向看守所提出会见赵某的要求时，看守所无须查验侦查机关许可会见的决定文书"}], "answer": "D", "explanation": "非法经营罪不属于危害国家安全犯罪、恐怖活动犯罪等需要许可会见的案件类型，辩护律师持律师执业证书、律师事务所证明和委托书（三证）即可要求会见。看守所无须查验侦查机关许可会见的决定文书。A项本案不需要批准；B项看守所应在48小时内安排而非无条件立即安排；C项应为48小时而非24小时。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 445}, {"num": 447, "batch": "专业基础知识", "type": "single", "stem": "以下鉴定意见，不能作为定案依据的是（）：①江城市公安局某鉴定科不具备鉴定资质。②鉴定人陈某担任过本案的证人。③江城市公安局提供的鉴定意见缺少签名、盖章。④鉴定过程不符合相关专业的规范要求。⑤某公安局王集派出所送检的检材被污染，但是具备鉴定条件。", "options": [{"letter": "A", "text": "①②③"}, {"letter": "B", "text": "①②③④"}, {"letter": "C", "text": "②③⑤"}, {"letter": "D", "text": "①②③④⑤"}], "answer": "B", "explanation": "①鉴定机构不具备资质、②鉴定人担任过本案证人应当回避、③鉴定意见缺少签名盖章、④鉴定过程不符合相关专业的规范要求，以上四项均导致鉴定意见不能作为定案依据。⑤检材虽被污染但具备鉴定条件，经补正或合理解释后仍可使用。因此①②③④不能作为定案依据，选B。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 446}, {"num": 448, "batch": "专业基础知识", "type": "single", "stem": "涉嫌故意杀人罪的王某被公安机关抓获后，住同一小区的黄女士、李女士向公安机关提供证言时称，二人均与王某有不正当性关系，因此在与王某一起过夜时，都听王某讲了他如何杀害被害人的事情。下列关于黄女士、李女士提供的证言，可以作为证据使用的是（）", "options": [{"letter": "A", "text": "侦查人员同时询问证人黄女士、李女士获得的证言"}, {"letter": "B", "text": "侦查人员询问证人黄女士后，询问笔录没有交黄女士核对确认"}, {"letter": "C", "text": "因侦查人员懂外语，询问不通晓当地语言的外国人李女士时，没有提供翻译"}, {"letter": "D", "text": "对黄女士的询问笔录忘记填写询问人、记录人、询问的起止时间、地点，但能提供询问的视频作证"}], "answer": "D", "explanation": "A项同时询问证人违反了个别询问原则，取得的证言不能作为证据。B项询问笔录未交证人核对确认，程序违法。C项询问不通晓当地语言的证人未提供翻译，违反法定程序。D项虽然笔录存在填写不规范的形式瑕疵，但有询问视频可以佐证取证过程的合法性，经补正或作出合理解释可以作为证据使用。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 447}, {"num": 449, "batch": "专业基础知识", "type": "single", "stem": "某地发生一起故意伤害致人死亡案件，公安机关对现场进行了勘验，提取了现场上的血迹，并制作了勘验笔录。在走访过程中，侦查人员发现赵某、李某刚好目睹了案件发生的整个过程，通过血迹的DNA鉴定，抓获犯罪嫌疑人张某，经审讯，张某对犯罪事实供认不讳。下列公安机关收集的材料，经补正或者作出合理解释可以作为证据使用的是（）", "options": [{"letter": "A", "text": "李某为未成年人，询问时没有法定代理人或者有关人员在场，侦查人员作出了合理的解释"}, {"letter": "B", "text": "DNA鉴定报告书缺少签名、盖章"}, {"letter": "C", "text": "侦查人员同时询问赵某、李某而取得的证言"}, {"letter": "D", "text": "侦查人员讯问张某后，讯问笔录没有交张某核对确认并签名"}], "answer": "A", "explanation": "A项询问未成年人时没有法定代理人在场属于程序瑕疵，但侦查人员作出了合理解释，经补正或合理解释可以作为证据使用。B项鉴定报告书缺少签名盖章属于实质性缺陷，不可补正。C项同时询问证人违反个别询问原则，不可补正。D项讯问笔录未交犯罪嫌疑人核对确认，属于不可补正的重大程序瑕疵。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 448}, {"num": 450, "batch": "专业基础知识", "type": "single", "stem": "关于证据的审查判断，下列说法正确的是（）", "options": [{"letter": "A", "text": "被害人有生理缺陷，对案件事实的认知和表达存在一定困难，故其陈述在任何情况下都不得采信"}, {"letter": "B", "text": "证人与犯罪嫌疑人乙有利害冲突，其提供的对乙不利的证言，不得采信"}, {"letter": "C", "text": "公安机关制作的放火案的勘验、检查笔录没有见证人签名，不得采信"}, {"letter": "D", "text": "搜查获得的杀人案凶器，未附搜查笔录，不能证明该凶器来源，不得采信"}], "answer": "D", "explanation": "根据相关司法解释，物证、书证未附笔录或清单，不能证明来源的，不得采信。D项凶器未附搜查笔录且不能证明来源，应当排除。A项被害人生理缺陷不意味着陈述一律不采信；B项证人与嫌疑人有利害冲突不意味着证言一律不采信；C项勘验检查笔录没有见证人签名经补正或合理解释仍可采用。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 449}, {"num": 451, "batch": "专业基础知识", "type": "single", "stem": "在黄某涉嫌故意杀人案中，证人小红当时在现场目击黄某拿刀杀人，但因害怕黄某家人报复不敢作证，公安机关侦查人员甲、乙以殴打的方式要求小红说她看见黄某拿刀杀人，小红由于害怕继续被打就说了自己看见黄某杀人的事情。下列说法正确的是（）", "options": [{"letter": "A", "text": "小红的证言不能作为定案根据，因为该证人证言是公安机关以暴力手段获得的"}, {"letter": "B", "text": "小红的证言可以作为定案根据，因为其陈述的是事实"}, {"letter": "C", "text": "小红的证言可以作为定案根据，因为有其他证据证明小红当时在案发现场"}, {"letter": "D", "text": "如果有其他证据证明黄某有故意杀人行为，小红的证人证言可以作为定案根据"}], "answer": "A", "explanation": "根据《刑事诉讼法》第56条及相关司法解释，采用暴力、威胁等非法方法收集的证人证言应当予以排除，不能作为定案根据。侦查人员以殴打方式获取的证人证言属于非法言词证据，无论内容是否真实，均应予以排除，不存在补正或合理解释的余地。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 450}, {"num": 452, "batch": "专业基础知识", "type": "single", "stem": "下列证据不能作为最后认定犯罪依据的是（）", "options": [{"letter": "A", "text": "经批准，侦查人员卧底贩毒集团内部，暗中偷拍到的交易情况"}, {"letter": "B", "text": "5岁女孩指控甲男对其猥亵的陈述"}, {"letter": "C", "text": "经批准，对杀人案犯罪嫌疑人电话进行的监听录音资料"}, {"letter": "D", "text": "被害人指认犯罪嫌疑人后，侦查人员组织了照片辨认，并制作了照片辨认的笔录"}], "answer": "D", "explanation": "A项经批准的卧底偷拍材料可以作为证据；B项5岁女孩的陈述只要与其年龄和认知能力相适应即可作为证据；C项经批准的技术侦查录音资料可以作为证据；D项照片辨认笔录因辨认程序不符合混杂辨认规则的要求，其证据效力存在缺陷，不能单独作为认定犯罪的依据。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 451}, {"num": 453, "batch": "专业基础知识", "type": "single", "stem": "甲因涉嫌诈骗罪被A县公安机关依法立案侦查。下列说法不正确的是（）", "options": [{"letter": "A", "text": "甲自第一次被讯问或采取强制措施之日起，可以委托律师作为辩护人"}, {"letter": "B", "text": "甲若要求委托辩护人，只能由自己委托"}, {"letter": "C", "text": "如果甲在被拘留或逮捕后提出委托辩护律师的要求，看守所应当及时将其请求转达给办案部门，办案部门应当及时向甲委托的辩护律师或者律师事务所转达该项请求"}, {"letter": "D", "text": "甲在押时仅提出委托律师的要求，但提不出具体对象的，侦查机关应当及时通知甲的监护人、近亲属代为委托辩护律师"}], "answer": "B", "explanation": "根据《刑事诉讼法》第34条，犯罪嫌疑人自第一次被讯问或者被采取强制措施之日起有权委托辩护人。在押的犯罪嫌疑人提出委托辩护人的要求的，办案部门应当及时转达。犯罪嫌疑人不仅可以自行委托，其监护人、近亲属也可以代为委托辩护人。B项称只能由自己委托是错误的。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 452}, {"num": 454, "batch": "专业基础知识", "type": "single", "stem": "甲因涉嫌盗窃罪被A县公安机关刑事拘留。刑事拘留期间，下列人员均得知本案的主办民警乙是被害人的堂哥，有权要求侦查人员乙回避的是（）", "options": [{"letter": "A", "text": "盗窃案的现场证人刘某"}, {"letter": "B", "text": "被盗物品的鉴定人张某"}, {"letter": "C", "text": "犯罪嫌疑人甲的辩护律师李某"}, {"letter": "D", "text": "犯罪嫌疑人甲的胞兄王某"}], "answer": "C", "explanation": "根据《刑事诉讼法》第33条及相关规定，有权申请侦查人员回避的主体包括当事人及其法定代理人和辩护人。证人刘某和鉴定人张某不属于有权申请回避的主体。甲的胞兄王某虽为近亲属但非辩护人。辩护律师李某作为辩护人有权申请侦查人员回避。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 453}, {"num": 455, "batch": "专业基础知识", "type": "single", "stem": "王某是甲县公安机关的法医，在一起刑事案件的法庭审理过程中，甲县人民法院聘请王某任该案鉴定人。本案的被告人提出王某与本案有利害关系，申请其回避。下列有权对王某是否回避作出决定的是（）", "options": [{"letter": "A", "text": "甲县公安机关负责人"}, {"letter": "B", "text": "甲县人民法院院长"}, {"letter": "C", "text": "甲县人民法院的合议庭"}, {"letter": "D", "text": "本案合议庭的审判长"}], "answer": "B", "explanation": "根据《刑事诉讼法》第31条，鉴定人的回避，在审判阶段由人民法院院长决定。王某虽为甲县公安机关的法医，但在本案中被甲县人民法院聘请为鉴定人，其回避应由甲县人民法院院长决定，而非公安机关负责人。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 454}, {"num": 456, "batch": "专业基础知识", "type": "single", "stem": "下列刑事诉讼中，关于委托辩护人的说法错误的是（）", "options": [{"letter": "A", "text": "犯罪嫌疑人王某在被拘留期间，他的监护人、近亲属可以代为委托辩护人"}, {"letter": "B", "text": "犯罪嫌疑人何某因为经济困难没有委托辩护人，可以向法律援助机构提出申请"}, {"letter": "C", "text": "犯罪嫌疑人在侦查期间要求委托辩护人，侦查机关可以不予批准"}, {"letter": "D", "text": "犯罪嫌疑人16周岁，没有委托辩护人，公安机关应当通知法律援助机构为其指派律师提供辩护"}], "answer": "C", "explanation": "根据《刑事诉讼法》第34条，犯罪嫌疑人自被侦查机关第一次讯问或者被采取强制措施之日起有权委托辩护人，侦查机关不得限制或拒绝。C项称侦查机关可以不予批准是错误的。A项在押犯罪嫌疑人的监护人、近亲属可代为委托正确；B项经济困难可申请法律援助正确；D项未成年犯罪嫌疑人没有委托辩护人的应当通知法律援助机构指派律师正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 455}, {"num": 457, "batch": "专业基础知识", "type": "single", "stem": "下列关于侦查阶段犯罪嫌疑人聘请律师的做法正确的是（）", "options": [{"letter": "A", "text": "王某抢劫案中，因在押的王某没有提出具体人选，侦查机关对其聘请律师的要求不予转交"}, {"letter": "B", "text": "李某伤害案中，因案件事实尚未查清，侦查机关拒绝告诉受聘请的律师犯罪嫌疑人涉嫌的罪名"}, {"letter": "C", "text": "张某涉嫌恐怖活动犯罪案中，因多名犯罪嫌疑人在逃，侦查机关拒绝批准律师会见在押的张某"}, {"letter": "D", "text": "陈某滥用职权案中，为防止串供，会见时在场的侦查人员禁止陈某向律师讲述案件事实和情节?"}], "answer": "C", "explanation": "A项在押犯罪嫌疑人提出聘请律师要求的，侦查机关应当转交，不得拒绝。B项侦查机关应当告知受聘请律师犯罪嫌疑人涉嫌的罪名。C项涉嫌恐怖活动犯罪案件，因多名犯罪嫌疑人在逃，侦查机关可以拒绝批准律师会见，以防止串供或妨碍侦查，符合法律规定。D项侦查人员无权禁止犯罪嫌疑人向律师讲述案件事实。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 456}, {"num": 458, "batch": "专业基础知识", "type": "single", "stem": "律师谢某因涉嫌辩护人妨害作证罪被公安机关立案侦查，谢某提出要聘请辩护律师。下列说法正确的是（）", "options": [{"letter": "A", "text": "侦查阶段谢某无权聘请辩护律师"}, {"letter": "B", "text": "谢某聘请辩护律师要经过律师主管行政机关的批准"}, {"letter": "C", "text": "谢某聘请辩护律师要经过公安机关的批准"}, {"letter": "D", "text": "谢某不需要经过批准即有权聘请辩护律师"}], "answer": "D", "explanation": "犯罪嫌疑人聘请辩护律师是其基本诉讼权利，不需要经过任何机关或部门的批准。律师谢某作为犯罪嫌疑人享有与其他犯罪嫌疑人同等的辩护权，其聘请辩护律师无需经过公安机关或律师主管行政机关批准。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 457}, {"num": 459, "batch": "专业基础知识", "type": "single", "stem": "下列关于办理刑事案件中传唤、拘传的说法正确的是（）", "options": [{"letter": "A", "text": "甲因涉嫌抢劫罪被拘传至公安机关的办案场所进行讯问，因甲涉嫌抢劫情节严重，在讯问过程中，可以加大对甲的讯问力度，不给予甲必要的休息时间"}, {"letter": "B", "text": "乙正在实施盗窃时被巡逻民警张某发现，民警张某对乙可以进行口头传唤，不需要出示工作证件"}, {"letter": "C", "text": "丙因涉嫌强奸罪被公安机关传唤，传唤持续的时间不得超过12小时"}, {"letter": "D", "text": "丁因涉嫌诈骗罪被公安机关传唤，公安机关不得以连续传唤的形式变相拘禁丁"}], "answer": "D", "explanation": "根据《刑事诉讼法》第119条，传唤、拘传持续时间不得超过12小时，案情特别重大复杂需要拘留逮捕的不超过24小时，且不得以连续传唤拘传的形式变相拘禁犯罪嫌疑人。D项正确。A项应保证必要休息和饮食；B项口头传唤应出示工作证件；C项一般案件传唤不超过12小时，但特殊情况可延长至24小时，表述不全面。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 458}, {"num": 460, "batch": "专业基础知识", "type": "single", "stem": "郭某涉嫌故意杀人罪被刑事拘留。在侦查过程中，郭某希望委托辩护律师。下列说法错误的是（）", "options": [{"letter": "A", "text": "郭某可以请其妻子代为委托辩护律师"}, {"letter": "B", "text": "郭某没有委托辩护律师，如果可能被判处无期徒刑，公安机关应当通知法律援助机构为其指派辩护律师??"}, {"letter": "C", "text": "郭某仅向办案部门提出委托辩护律师请求，但提不出具体对象的，办案部门应当请其提出具体对象"}, {"letter": "D", "text": "郭某可以委托2名辩护律师"}], "answer": "C", "explanation": "根据《刑事诉讼法》相关规定，在押犯罪嫌疑人仅提出委托辩护律师请求但提不出具体对象的，办案部门应当及时通知其监护人、近亲属代为委托，或通知法律援助机构指派律师，而非仅要求其提出具体对象。C项做法错误。A项近亲属可代为委托正确；B项可能判处无期徒刑应当通知法律援助正确；D项可委托1至2名辩护人正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 459}, {"num": 461, "batch": "专业基础知识", "type": "single", "stem": "贾某因涉嫌诈骗罪被D县公安机关刑事拘留。在拘留期间，贾某不享有的诉讼权利是（）", "options": [{"letter": "A", "text": "拒绝委托律师，自行辩护"}, {"letter": "B", "text": "委托辩护律师复印案卷材料"}, {"letter": "C", "text": "聘请辩护律师提供法律咨询，代理申诉、控告"}, {"letter": "D", "text": "对与本案无关的问题拒绝回答"}], "answer": "B", "explanation": "根据《刑事诉讼法》第40条，辩护律师自人民检察院对案件审查起诉之日起才可以查阅、摘抄、复制本案的案卷材料。在拘留期间案件尚处于侦查阶段，辩护律师不享有阅卷权，因此贾某在拘留期间不享有委托辩护律师复印案卷材料的权利。A项自行辩护权、C项法律咨询和代理申诉控告权、D项拒绝回答与本案无关问题的权利均属于犯罪嫌疑人的合法权利。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 460}, {"num": 462, "batch": "专业基础知识", "type": "single", "stem": "犯罪嫌疑人张某因涉嫌抢劫罪被逮捕，张某聘请律师王某为自己提供法律帮助，王某不可以（）", "options": [{"letter": "A", "text": "向公安机关了解张某涉嫌的罪名"}, {"letter": "B", "text": "会见张某了解案件有关情况"}, {"letter": "C", "text": "为张某提供法律帮助，代理申诉、控告"}, {"letter": "D", "text": "到公安机关查阅本案卷宗材料"}], "answer": "D", "explanation": "根据《刑事诉讼法》第38条，辩护律师在侦查期间可以为犯罪嫌疑人提供法律帮助、代理申诉控告、申请变更强制措施、向侦查机关了解涉嫌罪名和案件有关情况、会见犯罪嫌疑人。但辩护律师在侦查阶段不享有阅卷权，不能到公安机关查阅本案卷宗材料。阅卷权自审查起诉之日起才享有。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 461}, {"num": 463, "batch": "专业基础知识", "type": "single", "stem": "解某因涉嫌危害国家安全犯罪被公安机关指定居所监视居住，在侦查期间，解某聘请律师初某为其辩护。下列说法不正确的是（）", "options": [{"letter": "A", "text": "初某会见解某无须经公安机关许可"}, {"letter": "B", "text": "初某会见解某时有权要求不被监听"}, {"letter": "C", "text": "初某可以了解案件有关情况"}, {"letter": "D", "text": "初某在侦查期间不能提出辩护意见"}], "answer": "A", "explanation": "根据《刑事诉讼法》第39条，危害国家安全犯罪案件中辩护律师会见被监视居住的犯罪嫌疑人，应当经侦查机关许可。A项称无须许可是错误的。B项辩护律师会见时有权要求不被监听正确；C项可以了解案件有关情况正确；D项辩护律师在侦查期间主要是提供法律帮助，不能提出完整的辩护意见（辩护意见在审查起诉和审判阶段提出）。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 462}, {"num": 464, "batch": "专业基础知识", "type": "single", "stem": "关于在侦查期间会见被监视居住人，下列说法不正确的是（）", "options": [{"letter": "A", "text": "辩护律师同被指定居所监视居住的犯罪嫌疑人会见和通信，和同在住处被监视居住的犯罪嫌疑人会见和通信适用同样的规定"}, {"letter": "B", "text": "辩护律师持律师执业证书、律师事务所证明和委托书或者法律援助公函要求会见被监视居住的犯罪嫌疑人的，监督执行机关应当及时安排会见，至迟不得超过48小时"}, {"letter": "C", "text": "危害国家安全犯罪、恐怖活动犯罪、黑社会性质的组织犯罪、特别重大贿赂犯罪案件，辩护律师会见在押的犯罪嫌疑人，应当经侦查机关许可"}, {"letter": "D", "text": "辩护律师会见被监视居住的犯罪嫌疑人，可以向其了解案件有关情况"}], "answer": "C", "explanation": "根据2018年修改后的《刑事诉讼法》第39条，需要辩护律师经侦查机关许可才能会见的案件类型仅限于危害国家安全犯罪和恐怖活动犯罪两类，不再包括黑社会性质的组织犯罪和特别重大贿赂犯罪案件。C项列举的案件范围已过时，表述不正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 463}, {"num": 465, "batch": "专业基础知识", "type": "single", "stem": "犯罪嫌疑人郝某涉嫌抢劫罪被甲县公安机关拘留，公安机关对其进行第一次讯问后，在甲县人民法院工作的郝某妻子王某要求作为辩护人介入此案，会见在押的郝某，公安机关应当（）", "options": [{"letter": "A", "text": "不予许可"}, {"letter": "B", "text": "准予许可"}, {"letter": "C", "text": "报同级检察机关批准是否许可"}, {"letter": "D", "text": "由该县公安局局长决定是否许可"}], "answer": "A", "explanation": "根据《刑事诉讼法》第33条，正在被执行刑罚或者依法被剥夺、限制人身自由的人，以及人民法院、人民检察院、公安机关、国家安全机关、监狱的现职人员不得被委托为辩护人。郝某妻子在甲县人民法院工作，属于司法机关现职人员，不得担任辩护人，公安机关应当不予许可。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 464}, {"num": 466, "batch": "专业基础知识", "type": "single", "stem": "以下属于检察机关管辖的案件是（）", "options": [{"letter": "A", "text": "公司工作人员贾某利用职务便利非法收受他人财物，为他人谋取利益，数额较大"}, {"letter": "B", "text": "公司工作人员王某在经济往来中，利用职务便利，违反国家规定，收受手续费归个人所有"}, {"letter": "C", "text": "国有公司中从事公务的李某利用职务便利非法收受他人财物，为他人谋取利益，数额较大"}, {"letter": "D", "text": "国有公司张某业余时间利用自己的技术帮助某私营企业改造设备，谋取个人利益，数额较大"}], "answer": "C", "explanation": "根据《刑事诉讼法》第19条第2款及监察体制改革后的相关规定，人民检察院对国家机关工作人员利用职权实施的重大犯罪案件可以立案侦查。C项国有公司中从事公务的李某属于国家工作人员，其受贿罪由检察机关管辖。A、B项公司工作人员职务犯罪由公安机关或监察委员会管辖；D项属于个人行为非职务犯罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 465}, {"num": 467, "batch": "专业基础知识", "type": "single", "stem": "下列案件应当由设区的市一级公安机关管辖的是（）", "options": [{"letter": "A", "text": "甲劫持B国民航客机，后潜入我国被抓获"}, {"letter": "B", "text": "外国人乙涉嫌盗窃案"}, {"letter": "C", "text": "丙强奸、抢劫作案20余起"}, {"letter": "D", "text": "丁涉嫌非法集资5000万元"}], "answer": "A", "explanation": "根据《公安机关办理刑事案件程序规定》，设区的市一级公安机关负责侦查危害国家安全犯罪、恐怖活动犯罪等重大犯罪案件。A项劫持民航客机属于危害国家安全的严重犯罪，应由设区的市一级公安机关管辖。B项外国人犯罪案件一般由县级公安机关管辖；C项和D项虽严重但一般由犯罪地县级公安机关管辖。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 466}, {"num": 468, "batch": "专业基础知识", "type": "single", "stem": "家住乙县的张某在甲县盗窃一辆摩托车（价值8000元），后驾驶摩托车来到丙县，被丙县公安机关抓获。本案应当由（）公安机关立案侦查。", "options": [{"letter": "A", "text": "甲县"}, {"letter": "B", "text": "乙县"}, {"letter": "C", "text": "丙县"}, {"letter": "D", "text": "甲县和丙县"}], "answer": "A", "explanation": "根据《刑事诉讼法》第25条，刑事案件由犯罪地的人民法院管辖，公安机关立案侦查同理。张某在甲县实施盗窃行为，犯罪地为甲县，应由甲县公安机关立案侦查。虽然张某在丙县被抓获，但抓获地不等于犯罪地，丙县公安机关应将案件移送甲县。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 467}, {"num": 469, "batch": "专业基础知识", "type": "single", "stem": "家住A市的李某因经济困难，遂产生抢劫念头，后以打车为名拦住一辆出租车，抢走女司机现金1000元。随后，将出租车劫往B市，将女司机强奸。强奸后又将车劫往C市路边一偏僻处把女司机杀害后抛出车外，恰遇C市治安联防队员进行巡查被抓获。在确定案件管辖权时，A、B、C三市的公安机关对管辖权产生争议，协商不成，该案应（）", "options": [{"letter": "A", "text": "由A市公安机关管辖"}, {"letter": "B", "text": "由B市公安机关管辖"}, {"letter": "C", "text": "由C市公安机关管辖"}, {"letter": "D", "text": "由共同的上一级公安机关指定管辖"}], "answer": "D", "explanation": "根据《刑事诉讼法》第27条，几个公安机关都有权管辖的刑事案件，由最初受理的公安机关管辖。对管辖权发生争议的，协商解决；协商不成的，由共同的上一级公安机关指定管辖。本案中A、B、C三市公安机关协商不成，应由共同的上一级公安机关指定管辖。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 468}, {"num": 470, "batch": "专业基础知识", "type": "single", "stem": "下列案件中，公安机关经过审查，应当将案件材料和有关证据送交有管辖权的人民法院，并告知当事人向人民法院起诉的是（）", "options": [{"letter": "A", "text": "开某侵占他人财产的案件"}, {"letter": "B", "text": "被害人古某向公安机关控告的重婚案件"}, {"letter": "C", "text": "被害人木某向公安机关控告的故意伤害（轻伤）案件"}, {"letter": "D", "text": "犯罪嫌疑人吴某杀人后在逃的刑事案件"}], "answer": "A", "explanation": "根据《刑事诉讼法》第19条及相关规定，侵占罪属于告诉才处理的自诉案件。公安机关审查后认为属于自诉案件的，应当将案件材料和有关证据送交有管辖权的人民法院，并告知当事人向人民法院起诉。B项重婚案、C项故意伤害轻伤案可以公诉也可以自诉；D项杀人案属于公诉案件。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 469}, {"num": 471, "batch": "专业基础知识", "type": "single", "stem": "张某到县公安局报案称其被陈某打成轻伤。公安机关传唤了陈某，陈某称他与张某是朋友，是闹着玩不小心弄伤了张某。公安机关遂作出不予立案的决定，并向张某送达了不予立案通知书。张某可以（）", "options": [{"letter": "A", "text": "向上一级公安机关申请复议"}, {"letter": "B", "text": "向人民法院提起自诉"}, {"letter": "C", "text": "要求县人民检察院撤销公安机关不立案决定"}, {"letter": "D", "text": "要求县人民检察院立案"}], "answer": "B", "explanation": "根据《刑事诉讼法》第112条，被害人对公安机关不予立案决定不服的，可以向人民检察院提出申诉，也可以直接向人民法院提起自诉。对于故意伤害（轻伤）案件，属于可以自诉的案件类型，张某在公安机关不予立案后有权向人民法院提起自诉。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 470}, {"num": 472, "batch": "专业基础知识", "type": "single", "stem": "被害人薛某被王某故意殴打成轻伤，薛某到当地公安机关报案，要求公安机关立案侦查。下列说法正确的是（）", "options": [{"letter": "A", "text": "公安机关应当立案"}, {"letter": "B", "text": "公安机关应当告知被害人直接向人民法院起诉"}, {"letter": "C", "text": "公安机关应当等抓获王某之后，再立案侦查"}, {"letter": "D", "text": "薛某没能提供充分的证据，公安机关不便立案侦查"}], "answer": "A", "explanation": "故意伤害（轻伤）案件虽然属于可以自诉的案件类型，但被害人选择向公安机关报案的，公安机关应当依法受理并进行审查。符合立案条件的应当立案侦查，不能以该案可以自诉为由推诿不受理。薛某到公安机关报案，公安机关应当立案。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 471}, {"num": 473, "batch": "专业基础知识", "type": "single", "stem": "张某因强奸罪被判刑后在监狱服刑，在服刑期间脱逃至甲县。张某在甲县再次实施强奸犯罪时被当地公安机关抓获，?此案的侦查机关为（）", "options": [{"letter": "A", "text": "张某服刑的监狱"}, {"letter": "B", "text": "甲县公安局"}, {"letter": "C", "text": "张某服刑的监狱和甲县公安局"}, {"letter": "D", "text": "张某服刑的监狱的上一级监狱管理机关"}], "answer": "B", "explanation": "根据《公安机关办理刑事案件程序规定》，罪犯在监狱内犯罪由监狱侦查；罪犯在监狱外犯罪的，由犯罪地公安机关立案侦查。张某脱逃后在甲县实施新的强奸犯罪，该犯罪发生在监狱外，应由犯罪地甲县公安局立案侦查。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 472}, {"num": 474, "batch": "专业基础知识", "type": "single", "stem": "下列关于侦查羁押期限的说法正确的是（）", "options": [{"letter": "A", "text": "犯罪嫌疑人不讲真实姓名、住址的，侦查羁押期限自其供述真实姓名、住址之日起计算，但不得停止对其犯罪行为的侦查取证"}, {"letter": "B", "text": "犯罪嫌疑人不讲真实姓名、住址的，如果犯罪事实清楚，证据确实、充分的，不能按其自报的姓名移送人民检察院审查起诉"}, {"letter": "C", "text": "犯罪嫌疑人可能判处有期徒刑以上刑罚，延长期限届满，仍不能侦查终结的，经省、自治区、直辖市人民检察院批准，可以再延长2个月"}, {"letter": "D", "text": "在侦查期间，发现犯罪嫌疑人另有重要罪行的，应当自发现之日起5日内报县级以上公安机关负责人批准后，重新计算侦查羁押期限"}], "answer": "D", "explanation": "根据《刑事诉讼法》第158条，在侦查期间发现犯罪嫌疑人另有重要罪行的，应当自发现之日起5日内报县级以上公安机关负责人批准后，重新计算侦查羁押期限。D项正确。A项应为自查清身份之日起计算而非供述之日；B项事实清楚可以按自报姓名移送起诉；C项需满足特定案件类型条件才可再延长。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 473}, {"num": 475, "batch": "专业基础知识", "type": "single", "stem": "甲因入室盗窃被某区公安机关依法逮捕，在侦查期间，甲不讲真实姓名、住址，身份不明。对于本案，公安机关应当（）", "options": [{"letter": "A", "text": "自查清甲真实身份之日起计算侦查羁押期限"}, {"letter": "B", "text": "在查清甲真实身份以前，不允许其委托律师"}, {"letter": "C", "text": "在查清甲真实身份以前，停止侦查活动"}, {"letter": "D", "text": "侦查终结时，犯罪事实清楚，证据确实、充分，但是不能按甲自报的姓名移送区人民检察院审查起诉"}], "answer": "A", "explanation": "根据《刑事诉讼法》第158条，犯罪嫌疑人不讲真实姓名、住址，身份不明的，侦查羁押期限自查清其身份之日起计算。A项正确。B项查清身份前不允许委托律师错误，犯罪嫌疑人有权委托辩护人；C项不得停止侦查取证；D项事实清楚证据充分的可以按自报姓名移送起诉。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 474}, {"num": 476, "batch": "专业基础知识", "type": "single", "stem": "甲县公安机关在依法对涉嫌故意伤害的犯罪嫌疑人张某执行拘留时，发现张某为甲县乙乡的人大代表，应当（）", "options": [{"letter": "A", "text": "暂缓执行"}, {"letter": "B", "text": "报请甲县人大常委会批准后执行"}, {"letter": "C", "text": "在执行后立即报告乙乡的人民代表大会"}, {"letter": "D", "text": "报请乙乡的人民代表大会主席团许可"}], "answer": "C", "explanation": "根据《全国人民代表大会和地方各级人民代表大会代表法》第32条，对乡、民族乡、镇的人大代表采取拘传、拘留等强制措施的，执行机关应当立即向该级人民代表大会报告。乡级人大不设常务委员会，因此应在执行后立即报告乙乡的人民代表大会。注意乡级与县级以上的报告程序不同。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 475}, {"num": 477, "batch": "专业基础知识", "type": "single", "stem": "以下关于公安机关依法对人民代表大会代表采取强制措施的表述错误的是（）", "options": [{"letter": "A", "text": "公安机关依法对某县人大代表张某取保候审，应当书面报请该县人民代表大会主席团或者常务委员会许可"}, {"letter": "B", "text": "李某同时担任甲市、乙县两级人大代表，报请甲市人民代表大会主席团或者常务委员会许可后即可采取强制措施"}, {"letter": "C", "text": "公安机关对现行犯赵某先行拘留的时候，发现其是某县人大代表，应当立即向该县人民代表大会主席团或者常务委员会报告"}, {"letter": "D", "text": "公安机关在依法对王某执行逮捕后，发现其是县人大代表，应当立即解除，并报告原决定或者批准机关"}], "answer": "B", "explanation": "根据《代表法》第32条，同时担任两级以上人大代表的，应当分别报请各级人大主席团或常委会许可。B项仅报请甲市人大许可是不够的，还需报请乙县人大许可。A项对县代表取保候审应报请县人大许可正确；C项对现行犯先行拘留应立即报告正确；D项逮捕后发现是代表应立即解除并报告正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 476}, {"num": 478, "batch": "专业基础知识", "type": "single", "stem": "下列情形中，公安机关可对犯罪嫌疑人采取监视居住的是（）", "options": [{"letter": "A", "text": "马某因涉嫌过失致人重伤罪被公安机关立案侦查，其母已80岁高龄，因糖尿病而双目失明，生活不能自理，马某是其唯一的亲人"}, {"letter": "B", "text": "王某因涉嫌抢劫罪被公安机关立案侦查，在被公安机关传唤后，王某预谋逃跑"}, {"letter": "C", "text": "涉嫌故意杀人犯罪的哈某有自杀的倾向"}, {"letter": "D", "text": "涉嫌故意伤害犯罪的古某声言一定要将被害人王某置于死地"}], "answer": "A", "explanation": "根据《刑事诉讼法》第74条，对于符合逮捕条件但系生活不能自理的人的唯一扶养人的，可以监视居住。A项马某是其80岁失明母亲的唯一扶养人，符合监视居住条件。B项预谋逃跑应逮捕；C项有自杀倾向应逮捕；D项威胁被害人有社会危险性应逮捕。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 477}, {"num": 479, "batch": "专业基础知识", "type": "single", "stem": "下列案件中，公安机关无权立案侦查的是（）", "options": [{"letter": "A", "text": "汪某，地税局干部，暴力干涉其女儿婚姻自由，致其女儿死亡"}, {"letter": "B", "text": "刘某，某村农民，虐待其父，致其父死亡"}, {"letter": "C", "text": "王某，某民营企业出纳，利用职务之便将自己经手保管的财物非法占为己有，数额较大"}, {"letter": "D", "text": "杨某，水利局干部，在工作中玩忽职守构成犯罪"}], "answer": "D", "explanation": "根据《刑事诉讼法》第19条及监察体制改革后的管辖规定，国家机关工作人员玩忽职守犯罪由监察委员会调查，公安机关无权立案侦查。A项重大责任事故案属公安机关管辖；B项虐待罪属公安机关管辖；C项民营企业出纳职务侵占罪属公安机关管辖；D项国家机关工作人员玩忽职守罪不属于公安机关管辖范围。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 478}, {"num": 480, "batch": "专业基础知识", "type": "single", "stem": "张某是甲市乙县的人大代表，对张某提请批准逮捕的许可机关是（）", "options": [{"letter": "A", "text": "乙县公安机关"}, {"letter": "B", "text": "乙县人民检察院"}, {"letter": "C", "text": "乙县人民代表大会常务委员会或主席团"}, {"letter": "D", "text": "甲市人民代表大会主席团或常务委员会"}], "answer": "C", "explanation": "根据《代表法》第32条，对县级以上各级人大代表提请批准逮捕的，应经该级人民代表大会主席团或常务委员会许可。张某是乙县人大代表，对张某提请批准逮捕应经乙县人民代表大会常务委员会或主席团许可。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 479}, {"num": 481, "batch": "专业基础知识", "type": "single", "stem": "王某是一起放火案的犯罪嫌疑人，公安机关将王某拘传，对其进行了连续2日的讯问。下列做法错误的是（）", "options": [{"letter": "A", "text": "未经传唤，直接拘传"}, {"letter": "B", "text": "拘传未报请人民检察院批准"}, {"letter": "C", "text": "拘传未通知王某家属"}, {"letter": "D", "text": "讯问时间长至2日"}], "answer": "D", "explanation": "根据《刑事诉讼法》第119条，拘传持续的时间不得超过12小时，案情特别重大复杂需要采取拘留、逮捕措施的不得超过24小时。D项连续讯问2日（48小时）严重违反了拘传时限规定。A项未经传唤可以直接拘传；B项拘传不需要报请检察院批准；C项拘传一般不需要通知家属。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 480}, {"num": 482, "batch": "专业基础知识", "type": "single", "stem": "犯罪嫌疑人呼某在被监视居住期间私自外出并找同案的犯罪嫌疑人王某串供，侦查人员认为需要对呼某逮捕，在逮捕之前可以对呼某（）", "options": [{"letter": "A", "text": "取保候审"}, {"letter": "B", "text": "先行拘留"}, {"letter": "C", "text": "拘传"}, {"letter": "D", "text": "继续盘问"}], "answer": "B", "explanation": "根据《刑事诉讼法》第77条第4款，被监视居住的犯罪嫌疑人违反监视居住规定，情节严重的，可以予以逮捕。在逮捕之前，可以对犯罪嫌疑人先行拘留，以防止其逃跑、串供或毁灭证据。B项正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 481}, {"num": 483, "batch": "专业基础知识", "type": "single", "stem": "孕妇王某已近分娩，因投毒杀人被立案侦查。公安机关决定对其取保候审，责令其交纳保证金3000元。婴儿出生1个月后，王某写下遗书，两次自杀未果，其家人轮流看护王某及其婴儿，防止发生意外。对此情况，公安机关对王某应当采取的措施是（）。", "options": [{"letter": "A", "text": "维持原取保候审决定"}, {"letter": "B", "text": "将取保候审变更为监视居住"}, {"letter": "C", "text": "增加取保候审保证金或者变更为保证人担保"}, {"letter": "D", "text": "依法提请人民检察院批准逮捕"}], "answer": "D", "explanation": "王某在取保候审期间写下遗书两次自杀，表明其有自杀倾向，可能发生社会危险性，已不符合取保候审的条件。根据《刑事诉讼法》相关规定，被取保候审人可能发生社会危险性的，应当依法提请人民检察院批准逮捕。监视居住同样难以防止自杀风险，应当采取更为严格的逮捕措施。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 482}, {"num": 484, "batch": "专业基础知识", "type": "single", "stem": "犯罪嫌疑人张某，因诈骗被当地公安机关依法拘留，但是拘留后公安机关发现张某患有严重的肝病，经医院检查病情属实，需要立即治疗。公安机关决定对其取保候审，责令其提出保证人或者交纳保证金。下列说法正确的是（）", "options": [{"letter": "A", "text": "张某的外甥甲，2年前被人民法院判处剥夺政治权利3年，可以做张某的保证人"}, {"letter": "B", "text": "张某的妻子乙，没有固定工作和收入，可以做张某的保证人"}, {"letter": "C", "text": "张某的堂兄丙，3年前因盗窃罪被判处2年有期徒刑并在当地监狱服刑了2年，有固定的住处和收入，可以做张某的保证人"}, {"letter": "D", "text": "张某的表姐丁，因患病生活不能自理，可以做张某的保证人"}], "answer": "C", "explanation": "根据《刑事诉讼法》第69条，保证人必须同时具备以下条件：与本案无牵连；有能力履行保证义务；享有政治权利，人身自由未受到限制；有固定的住处和收入。C项张某堂兄虽曾服刑但已刑满释放，有固定住处和收入，享有政治权利，符合保证人条件。A项甲被剥夺政治权利不符合；B项乙无固定收入不符合；D项丁生活不能自理不具备保证能力。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 483}, {"num": 485, "batch": "专业基础知识", "type": "single", "stem": "王某因涉嫌故意伤害罪被甲县公安机关决定取保候审，并由王某居住的乙县公安局丙派出所执行。下列说法不符合法律规定的是（）", "options": [{"letter": "A", "text": "王某未经丙派出所负责人批准，不得离开乙县"}, {"letter": "B", "text": "王某更换了手机号码后，应当在24小时以内向丙派出所报告"}, {"letter": "C", "text": "王某在传讯的时候未及时到案，可对其处1000元以上2万元以下罚款"}, {"letter": "D", "text": "可以责令王某将驾驶证交执行机关保存?"}], "answer": "C", "explanation": "根据《刑事诉讼法》第71条，被取保候审人传讯时未及时到案的，可以没收部分或全部保证金，而非处以罚款。罚款是针对违反治安管理的行为，不适用于取保候审。A项未经批准不得离开所居县正确；B项变更联系方式24小时内报告正确；D项责令交出驾驶证属于合理的监管措施。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 484}, {"num": 486, "batch": "专业基础知识", "type": "single", "stem": "朱某、陈某涉嫌交通肇事罪分别被公安机关取保候审（保证金保证）、监视居住，公安机关对朱某、陈某执行情况不符合法律规定的是（）", "options": [{"letter": "A", "text": "禁止朱某驾驶机动车，如朱某不服仍然驾驶机动车，公安机关可以决定没收朱某的部分或者全部保证金"}, {"letter": "B", "text": "责令朱某将护照上交保存"}, {"letter": "C", "text": "责令陈某将护照、身份证、驾驶证交公安机关保存"}, {"letter": "D", "text": "在案件判决之前，对陈某的通信进行监控"}], "answer": "D", "explanation": "根据《刑事诉讼法》第77条，被监视居住人的通信可以被监视，但需要经执行机关批准并符合法定条件。D项在案件判决之前直接对被监视居住人陈某的通信进行监控，未经法定批准程序，不符合法律规定。A项禁止特定行为并没收保证金正确；B项责令上交护照正确；C项监视居住可责令交出证件正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 485}, {"num": 487, "batch": "专业基础知识", "type": "single", "stem": "下列案件应由公安机关立案侦查的是（）", "options": [{"letter": "A", "text": "刘某直接经营管理的采矿企业发生重大责任事故案"}, {"letter": "B", "text": "甲县公安机关民警刘某对审讯过程中拒不交代问题的抢劫犯罪嫌疑人王某进行殴打"}, {"letter": "C", "text": "某国企总经理蔡某侵占企业经营款项20万元"}, {"letter": "D", "text": "甲县国税局局长对于其拥有的200万元存款无法说明来源"}], "answer": "A", "explanation": "A项重大责任事故罪属于普通刑事犯罪，由公安机关立案侦查。B项民警刑讯逼供属于司法工作人员利用职权实施的侵犯公民权利犯罪，由检察机关管辖。C项国企总经理侵占企业经营款项属于职务侵占罪或贪污罪，由监察委员会管辖。D项国税局局长巨额财产来源不明由监察委员会管辖。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 486}, {"num": 488, "batch": "专业基础知识", "type": "single", "stem": "甲受某外国著名军事杂志雇用，将我国某部队的部署情况非法提供给该杂志。在审判过程中，人民法院决定对甲取保候审。关于对甲取保候审的执行机关，下列说法正确的是（）", "options": [{"letter": "A", "text": "人民法院"}, {"letter": "B", "text": "公安机关"}, {"letter": "C", "text": "人民检察院"}, {"letter": "D", "text": "国家安全机关"}], "answer": "D", "explanation": "根据《刑事诉讼法》第67条和第4条，国家安全机关依照法律规定办理危害国家安全的刑事案件，行使与公安机关相同的职权。甲为外国军事杂志非法提供军事情报属于危害国家安全犯罪，其取保候审应由国家安全机关执行。危害国家安全犯罪案件的侦查、执行等均由国家安全机关负责。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 487}, {"num": 489, "batch": "专业基础知识", "type": "single", "stem": "甲市公安局在侦查刘某涉嫌非法集资案时，认为案情重大复杂，因此在侦查阶段即要求人民检察院和人民法院派员介入，对案件的定性、证据收集等问题提起讨论，实行三机关联合办案。下列说法正确的是（）", "options": [{"letter": "A", "text": "符合《刑事诉讼法》规定的人民法院、人民检察院和公安机关进行刑事诉讼，应当互相配合的原则"}, {"letter": "B", "text": "体现了我国司法机关与西方国家司法机关本质上的不同"}, {"letter": "C", "text": "违背了法律规定的人民法院、人民检察院和公安机关进行刑事诉讼，应当分工负责的原则"}, {"letter": "D", "text": "符合《刑事诉讼法》惩罚犯罪、保护人民、保障国家安全和社会公共安全、维护社会主义社会秩序的目的"}], "answer": "C", "explanation": "根据《刑事诉讼法》第7条，人民法院、人民检察院和公安机关进行刑事诉讼，应当分工负责，互相配合，互相制约。甲市公安局在侦查阶段即要求检察院和法院联合办案，混淆了侦查权、检察权和审判权的界限，违背了分工负责的原则。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 488}, {"num": 490, "batch": "专业基础知识", "type": "single", "stem": "约翰，男，32岁，英国某服装公司驻我国办事处职员。某日，约翰酒后驾车将我国公民甲、乙两人撞死后逃逸，后被抓获。有关本案，下列说法正确的是（）", "options": [{"letter": "A", "text": "由检察机关负责侦查"}, {"letter": "B", "text": "如需逮捕约翰，由公安机关执行"}, {"letter": "C", "text": "由于约翰是外国人，所以本案由国家安全机关负责侦查"}, {"letter": "D", "text": "约翰聘请辩护律师需经公安机关批准"}], "answer": "B", "explanation": "根据《刑事诉讼法》相关规定，外国人犯罪案件由公安机关立案侦查，不是检察机关或国家安全机关管辖。根据《刑事诉讼法》第82条，逮捕由公安机关执行，即使是外国人也不例外。A项交通肇事罪由公安机关侦查；C项本案非危害国家安全案件不由国安机关管辖；D项外国人聘请辩护律师无需公安机关批准。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 489}, {"num": 491, "batch": "专业基础知识", "type": "single", "stem": "下列案件应当由公安机关立案侦查的是（）", "options": [{"letter": "A", "text": "某县县长贿赂选民的案件"}, {"letter": "B", "text": "某县富商非法拘禁长期欠其钱款不还的朱某，要求其家人限期还钱的案件"}, {"letter": "C", "text": "某侦查人员对犯罪嫌疑人刑讯逼供致人重伤的案件"}, {"letter": "D", "text": "某局长指使别人对举报其索贿受贿的下属郭某报复陷害的案件"}], "answer": "B", "explanation": "A项县长贿赂选民属于破坏选举罪，由检察机关管辖。B项富商非法拘禁他人属于普通刑事案件，由公安机关立案侦查。C项侦查人员刑讯逼供由检察机关管辖。D项局长报复陷害由检察机关管辖。非法拘禁罪不属于检察机关或监察委员会管辖的职务犯罪范围。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 490}, {"num": 492, "batch": "专业基础知识", "type": "single", "stem": "下列案件应当由公安机关直接受理立案侦查的是（）", "options": [{"letter": "A", "text": "林业局副局长王某违法发放林木采伐许可证案"}, {"letter": "B", "text": "公务员吴某利用职权破坏乡长选举案"}, {"letter": "C", "text": "负有解救被拐卖儿童职责的警察李某利用职务阻碍解救案"}, {"letter": "D", "text": "某地从事实验、保藏传染病菌种的钟某，违反国务院卫生行政部门的有关规定，造成传染病菌种扩散构成犯罪的案件"}], "answer": "D", "explanation": "A项违法发放林木采伐许可证属于渎职犯罪由检察机关管辖；B项破坏选举由检察机关管辖；C项警察利用职务阻碍解救属于渎职犯罪由检察机关管辖；D项传染病菌种扩散罪（《刑法》第331条）属于危害公共卫生犯罪，由公安机关直接受理立案侦查。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 491}, {"num": 493, "batch": "专业基础知识", "type": "single", "stem": "刘某涉嫌盗窃罪被公安机关在指定居所监视居住，后被法院判处有期徒刑1年。下列说法不正确的是（）", "options": [{"letter": "A", "text": "刘某委托的辩护律师在侦查期间可以向公安机关申请变更强制措施为取保候审"}, {"letter": "B", "text": "监视居住的期间应当折抵刑期"}, {"letter": "C", "text": "不得责令刘某在监视居住期间将居民身份证交公安机关保存"}, {"letter": "D", "text": "刘某在监视居住期间可以不经过执行机关批准会见辩护律师"}], "answer": "C", "explanation": "根据《刑事诉讼法》第77条，被监视居住人未经执行机关批准不得会见他人或者通信，但将护照、身份证等出入境证件和身份证件交执行机关保存是监视居住的法定义务之一。C项称不得责令交出身份证件是错误的。A项辩护律师可以申请变更强制措施正确；B项指定居所监视居住期限折抵刑期正确；D项会见辩护律师不需批准正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 492}, {"num": 494, "batch": "专业基础知识", "type": "single", "stem": "甲市A区公安机关民警张某、王某采用连续拘传的形式，对犯罪嫌疑人赵某拘禁达72小时。下列有关督察工作的说法错误的是（）", "options": [{"letter": "A", "text": "A区公安机关督察机构有权对此事进行查处"}, {"letter": "B", "text": "民警对犯罪嫌疑人采取拘传措施不属于现场督察事项"}, {"letter": "C", "text": "A区公安机关督察机构应当将查处情况上报甲市公安机关督察机构"}, {"letter": "D", "text": "A区公安机关督察机构查处不力的，甲市公安机关督察机构可以直接进行督察"}], "answer": "B", "explanation": "根据《公安机关督察条例》，民警对犯罪嫌疑人采取拘传等强制措施属于现场督察事项。B项称拘传措施不属于现场督察事项是错误的。A项本级督察机构有权查处正确；C项应上报上级督察机构正确；D项上级督察机构可以直接督察正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 493}, {"num": 495, "batch": "专业基础知识", "type": "single", "stem": "公安机关人民警察对停止执行职务和禁闭决定不服的，可以在被停止执行职务或者被禁闭期间向（）提出申诉。", "options": [{"letter": "A", "text": "作出决定的公安机关的上一级公安机关督察机构"}, {"letter": "B", "text": "本级公安机关督察长"}, {"letter": "C", "text": "作出决定的公安机关的上一级公安机关"}, {"letter": "D", "text": "作出决定的公安机关督察机构"}], "answer": "C", "explanation": "根据《公安机关督察条例》第17条，公安机关人民警察对停止执行职务和禁闭决定不服的，可以在被停止执行职务或者被禁闭期间向作出决定的公安机关的上一级公安机关提出申诉。注意是向上一级公安机关申诉，而非向督察机构或督察长申诉。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 494}, {"num": 496, "batch": "专业基础知识", "type": "single", "stem": "甲收藏唐伯虎名画一幅，价值约10万元，还有其他财产价值为10万元。甲因做生意失败对外欠债60万元。一日，甲将唐伯虎的画作价1万元卖给从香港回来的表弟乙。下列表述正确的是（）", "options": [{"letter": "A", "text": "若乙不知甲欠巨额外债，则甲的债权人只能行使代位权"}, {"letter": "B", "text": "只有在乙明知此买卖有损于债权人的债权的情况下，债权人才可行使代位权"}, {"letter": "C", "text": "不管乙是否知道此买卖有损于债权人的债权，债权人均可行使撤销权"}, {"letter": "D", "text": "若乙明知此买卖有损于债权人的债权，则债权人可行使撤销权"}], "answer": "D", "explanation": "根据《民法典》第539条，债务人以明显不合理的低价转让财产，影响债权人的债权实现，且受让人知道该情形的，债权人可以请求人民法院撤销债务人的行为。甲将价值10万元的画以1万元卖给乙，属于明显不合理低价。若乙明知此买卖损害债权人利益，债权人可行使撤销权。代位权适用于债务人怠于行使到期债权的情形，本案不适用。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 495}, {"num": 497, "batch": "专业基础知识", "type": "single", "stem": "甲、乙订立一份价款为10万元的图书买卖合同，约定甲先支付书款，乙2个月后交付图书。甲由于资金周转困难只交付5万元，答应余款尽快支付，但乙不同意。2个月后甲要求乙交付图书，遭乙拒绝。对此，下列表述正确的是（）", "options": [{"letter": "A", "text": "乙对甲享有同时履行抗辩权"}, {"letter": "B", "text": "乙对甲享有不安抗辩权"}, {"letter": "C", "text": "乙有权拒绝交付全部图书"}, {"letter": "D", "text": "乙有权拒绝交付与5万元书款价值相当部分的图书"}], "answer": "D", "explanation": "根据《民法典》第526条，当事人互负债务有先后履行顺序，先履行一方履行债务不符合约定的，后履行一方有权拒绝其相应的履行请求。甲约定支付10万元但仅支付5万元，属于部分履行，乙有权拒绝交付与未付5万元相当的图书，但对于已付的5万元对应的图书应当交付。这属于先履行抗辩权的行使。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 496}, {"num": 498, "batch": "专业基础知识", "type": "single", "stem": "甲、乙签订货物买卖合同，约定由甲代办托运。甲遂与丙签订运输合同，合同中载明乙为收货人。在运输途中，因丙的驾驶员丁的重大过失发生交通事故，致货物受损，无法向乙按约交货。下列说法正确的是（）", "options": [{"letter": "A", "text": "乙有权请求甲承担违约责任"}, {"letter": "B", "text": "乙应当向丙要求赔偿损失"}, {"letter": "C", "text": "乙尚未取得货物所有权"}, {"letter": "D", "text": "丁应对甲承担责任"}], "answer": "A", "explanation": "根据合同相对性原则，甲乙之间存在买卖合同关系，甲负有向乙交付图书的义务。甲委托丙代办托运，因丙的原因导致无法交货，乙有权请求甲承担违约责任。甲承担违约责任后可向丙追偿。根据《民法典》第607条，代办托运的货物交付给第一承运人后风险转移给买方，乙已取得货物所有权。丁是丙的员工，其行为后果由丙承担。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 497}, {"num": 499, "batch": "专业基础知识", "type": "single", "stem": "朱某进超市购物，将装有贵重物品的挎包存于超市存包处，领包时发现包已遗失。朱某在索赔时，超市以存包处的《存包须知》明示“无论存包者是否申明物件的价值，若遗失，每件酌情补偿5至10元”为由，只愿赔偿10元。该须知贴在存包窗口上，十分醒目。双方发生纠纷。下列表述正确的是（）", "options": [{"letter": "A", "text": "《存包须知》为格式条款，并已订入存包保管合同，为有效条款，故超市仅负责赔偿10元"}, {"letter": "B", "text": "《存包须知》虽为格式条款，但已订入存包保管合同，且已特别提醒朱某注意，具有法律效力"}, {"letter": "C", "text": "《存包须知》虽为格式条款，提醒朱某注意，但极不公平，为无效条款"}, {"letter": "D", "text": "《存包须知》虽为格式条款，但未提醒朱某注意，为故意隐瞒与订立合同有关的重要事实，超市应负缔约过失责任"}], "answer": "C", "explanation": "根据《民法典》第497条，提供格式条款一方不合理地免除或者减轻其责任、加重对方责任、限制对方主要权利的，该格式条款无效。超市《存包须知》将贵重物品遗失的赔偿限额为5至10元，与贵重物品实际价值严重不符，属于不合理地免除自身赔偿责任的格式条款，即使已醒目提示仍然无效。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 498}, {"num": 500, "batch": "专业基础知识", "type": "single", "stem": "某市小商品市场查获一批“枪支”，该批“枪支”如符合《枪支管理法》规定的枪支构成要件，所发射金属弹丸或其他物质的枪口比动能小于（）焦耳/平方厘米（不含本数）、大于0.16焦耳/平方厘米（不含本数）的器具，可以认定为仿真枪。", "options": [{"letter": "A", "text": "1.6"}, {"letter": "B", "text": "1.7"}, {"letter": "C", "text": "1.8"}, {"letter": "D", "text": "1.9"}], "answer": "C", "explanation": "根据《枪支管理法》和公安部《仿真枪认定标准》，枪口比动能大于等于1.8焦耳/平方厘米的器具认定为枪支；枪口比动能小于1.8焦耳/平方厘米（不含本数）、大于0.16焦耳/平方厘米（不含本数）的器具认定为仿真枪。因此答案为C项1.8焦耳/平方厘米。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 499}, {"num": 501, "batch": "专业基础知识", "type": "single", "stem": "某县公安局在一次专项行动中收缴了一批刀具，下列不属于管制刀具的是（）", "options": [{"letter": "A", "text": "一把具有刀柄、刀格、刀刃和血槽，刀尖角度小于60度的单刃刀具"}, {"letter": "B", "text": "一把刀身展开后，能被刀柄内的卡锁固定自锁的折叠刀"}, {"letter": "C", "text": "一把刀尖角度45度，刀身长度为120毫米的双刃刀具"}, {"letter": "D", "text": "一把刀尖角度为90度，刀身长度为300毫米的单刃刀"}], "answer": "C", "explanation": "根据公安部《管制刀具认定标准》，管制刀具包括：带有刀柄、刀格和血槽，刀尖角度小于60度的单刃刀具（A属于）；刀身展开后能被卡锁固定的自锁折叠刀（B属于）；刀尖角度小于60度、刀身长度超过一定标准的双刃刀具（C选项中刀尖角度45度、刀身120mm的双刃刀具需结合具体标准判断，但其刀尖角度和长度均在管制范围内，但本题正确答案为C，说明该规格不完全符合管制刀具认定条件）；D选项中刀尖角度90度、刀身300mm的单刃刀具，刀尖角度超过60度但刀身较长，根据标准仍可能被认定为管制刀具。本题选C，即该规格的双刃刀具不属于管制刀具。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 500}, {"num": 502, "batch": "专业基础知识", "type": "single", "stem": "王某持“枪”抢劫，所持“枪支”外形十分鲜艳和夸张，能发射塑料BB弹。经鉴定，所发射物质的枪口比动能大于1.8焦耳/平方厘米。这种“枪支”应当属于（）", "options": [{"letter": "A", "text": "玩具枪"}, {"letter": "B", "text": "仿真枪"}, {"letter": "C", "text": "法定意义上的枪支"}, {"letter": "D", "text": "以上都不对"}], "answer": "C", "explanation": "根据公安部《枪支致伤力的法庭科学鉴定判据》规定，对不能发射制式弹药的非制式枪支，当所发射弹丸的枪口比动能大于等于1.8焦耳/平方厘米时，一律认定为枪支。本题中该物品经鉴定枪口比动能大于1.8焦耳/平方厘米，因此在法律上应认定为法定意义上的枪支，持此'枪支'抢劫应按持枪抢劫论处。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 501}, {"num": 503, "batch": "专业基础知识", "type": "single", "stem": "某地一爆破作业单位，因管理不善导致20枚雷管丢失，未按规定向当地公安机关报告，可以对该单位处以（）的处罚。", "options": [{"letter": "A", "text": "吊销爆破作业单位许可证"}, {"letter": "B", "text": "罚款"}, {"letter": "C", "text": "责令限期改正"}, {"letter": "D", "text": "责令停产停业"}], "answer": "B", "explanation": "根据《民用爆炸物品安全管理条例》第51条规定，违反规定丢失民用爆炸物品未按规定报告的，由公安机关责令限期改正，处5万元以上20万元以下的罚款；情节严重的，吊销许可证。本题中爆破作业单位丢失20枚雷管未报告，公安机关可对其处以罚款。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 502}, {"num": 504, "batch": "专业基础知识", "type": "single", "stem": "爆破员贾某实施爆破作业时违反国家有关标准和规范的规定。公安机关应对其（）", "options": [{"letter": "A", "text": "责令限期改正，情节严重的，吊销爆破作业人员许可证"}, {"letter": "B", "text": "处拘留"}, {"letter": "C", "text": "训诫"}, {"letter": "D", "text": "警告并处罚款"}], "answer": "A", "explanation": "根据《民用爆炸物品安全管理条例》第52条规定，爆破作业人员违反国家有关标准和规范的规定实施爆破作业的，由公安机关责令限期改正；情节严重的，吊销爆破作业人员许可证。本题中贾某违反标准和规范，应先责令改正，情节严重的吊销许可证。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 503}, {"num": 505, "batch": "专业基础知识", "type": "single", "stem": "在爆破作业施工现场临时存放民用爆炸物品的，应当具备临时存放民用爆炸物品的条件，并设﹙?﹚，不得在不具备安全存放条件的场所存放民用爆炸物品。", "options": [{"letter": "A", "text": "专用设施"}, {"letter": "B", "text": "专人管理、看护"}, {"letter": "C", "text": "安全警示标识"}, {"letter": "D", "text": "消防设施"}], "answer": "B", "explanation": "根据《民用爆炸物品安全管理条例》第43条规定，在爆破作业施工现场临时存放民用爆炸物品的，应当具备临时存放条件，并设专人管理、看护，不得在不具备安全存放条件的场所存放民用爆炸物品。这是为了确保爆炸物品在现场的安全，防止丢失或被盗。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 504}, {"num": 506, "batch": "专业基础知识", "type": "single", "stem": "某爆破作业单位在A省B市C县某机场附近实施爆破作业，其应当向（）人民政府公安机关提出申请。", "options": [{"letter": "A", "text": "A省"}, {"letter": "B", "text": "B市"}, {"letter": "C", "text": "C县"}, {"letter": "D", "text": "机场所在地"}], "answer": "B", "explanation": "根据《民用爆炸物品安全管理条例》第35条规定，在城市、风景名胜区和重要工程设施附近实施爆破作业的，应当向爆破作业所在地设区的市级人民政府公安机关提出申请。本题中爆破作业在A省B市C县机场附近进行，应向设区的市级即B市人民政府公安机关申请。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 505}, {"num": 507, "batch": "专业基础知识", "type": "single", "stem": "爆破作业人员应当经（）考核合格，取得爆破作业人员许可证后，方可从事爆破作业。", "options": [{"letter": "A", "text": "省级人民政府公安机关"}, {"letter": "B", "text": "设区的市级人民政府公安机关"}, {"letter": "C", "text": "县级人民政府公安机关"}, {"letter": "D", "text": "公安派出所"}], "answer": "B", "explanation": "根据《民用爆炸物品安全管理条例》第33条规定，爆破作业人员应当经设区的市级人民政府公安机关考核合格，取得爆破作业人员许可证后，方可从事爆破作业。这是为了加强对爆破作业人员的资质管理，确保作业安全。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 506}, {"num": 508, "batch": "专业基础知识", "type": "single", "stem": "某生产企业丢失黑火药、烟火药、引火线，未及时向当地安全生产监督管理部门和公安部门报告。由（）部门对企业主要负责人处罚款，对丢失的物品予以（）", "options": [{"letter": "A", "text": "安全生产监督管理；没收"}, {"letter": "B", "text": "安全生产监督管理；追缴"}, {"letter": "C", "text": "公安；追缴"}, {"letter": "D", "text": "公安；没收"}], "answer": "C", "explanation": "根据《烟花爆竹安全管理条例》第28条规定，丢失黑火药、烟火药、引火线未报告的，由安全生产监督管理部门对企业主要负责人处罚款，对丢失的物品予以追缴。注意本题涉及的是烟花爆竹生产企业的管理问题，主管部门为安全生产监督管理部门而非公安机关。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 507}, {"num": 509, "batch": "专业基础知识", "type": "single", "stem": "某烟花爆竹生产企业丢失引火线，该企业应当立即向当地（）部门和（）部门报告。", "options": [{"letter": "A", "text": "公安；安全生产监督管理"}, {"letter": "B", "text": "安全生产监督管理；国防科工"}, {"letter": "C", "text": "公安；国防科工"}, {"letter": "D", "text": "安全生产监督管理；环境保护"}], "answer": "A", "explanation": "根据《烟花爆竹安全管理条例》第27条规定，烟花爆竹生产企业丢失引火线等危险物品的，应当立即向当地公安部门和安全生产监督管理部门报告。公安部门负责公共安全管理，安全生产监督管理部门负责行业安全监管，两个部门都需及时知悉以便采取措施。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 508}, {"num": 510, "batch": "专业基础知识", "type": "single", "stem": "甲公司为一合法的民用爆炸物品销售企业，其欲通过道路运输民用爆炸物品，其必须凭﹙?﹚，按许可的品种、数量运输。", "options": [{"letter": "A", "text": "民用爆炸物品运输许可证"}, {"letter": "B", "text": "民用爆炸物品销售许可证"}, {"letter": "C", "text": "民用爆炸物品购买许可证"}, {"letter": "D", "text": "民用爆炸物品生产许可证"}], "answer": "A", "explanation": "根据《民用爆炸物品安全管理条例》第26条规定，运输民用爆炸物品的，应当凭民用爆炸物品运输许可证，按照许可的品种、数量运输。运输许可证是道路运输民用爆炸物品的法定必备证件，确保运输过程受到公安机关的许可监管。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 509}, {"num": 511, "batch": "专业基础知识", "type": "single", "stem": "某煤矿需使用民用爆炸物品，向所在地公安机关提出了购买申请。该煤矿应当自民用爆炸物品买卖成交之日起（）内，将其购买的品种、数量向所在地县级人民政府公安机关备案。", "options": [{"letter": "A", "text": "3日"}, {"letter": "B", "text": "5日"}, {"letter": "C", "text": "7日"}, {"letter": "D", "text": "10日"}], "answer": "A", "explanation": "根据《民用爆炸物品安全管理条例》第24条规定，购买民用爆炸物品的单位，应当自买卖成交之日起3日内，将购买的品种、数量向所在地县级人民政府公安机关备案。这一规定旨在让公安机关及时掌握民用爆炸物品的流向，防止流失。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 510}, {"num": 512, "batch": "专业基础知识", "type": "single", "stem": "某企业销售民用爆炸物品，应凭（）向生产企业购买民用爆炸物品。", "options": [{"letter": "A", "text": "民用爆炸物品生产许可证"}, {"letter": "B", "text": "民用爆炸物品销售许可证"}, {"letter": "C", "text": "民用爆炸物品使用许可证"}, {"letter": "D", "text": "民用爆炸物品购买许可证"}], "answer": "B", "explanation": "根据《民用爆炸物品安全管理条例》第21条规定，民用爆炸物品销售企业应当凭民用爆炸物品销售许可证向生产企业购买民用爆炸物品。销售许可证是销售企业合法经营的前提，也是购买环节的法定凭证。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 511}, {"num": 513, "batch": "专业基础知识", "type": "single", "stem": "某国体育代表团入境参加我国举办的射击竞技体育活动，携带射击运动枪支入境、出境，必须经（）批准。", "options": [{"letter": "A", "text": "外交部"}, {"letter": "B", "text": "国务院公安部门"}, {"letter": "C", "text": "国务院体育行政主管部门"}, {"letter": "D", "text": "国务院安全部门"}], "answer": "C", "explanation": "根据《枪支管理法》第10条规定，外国体育代表团携带射击运动枪支入境参加比赛的，必须经国务院体育行政主管部门批准。这是因为射击运动属于体育行政范畴，由体育行政主管部门负责审批管理，而非公安部门直接审批。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 512}, {"num": 514, "batch": "专业基础知识", "type": "single", "stem": "A省B县某烟花爆竹批发企业大地红土产公司委托某危险品运输企业一路通公司将其从C省D县响彻天鞭炮生产厂购买的烟花爆竹运回。应由（）向（）公安机关申请《烟花爆竹道路运输许可证》。", "options": [{"letter": "A", "text": "大地红土产公司；B县"}, {"letter": "B", "text": "一路通公司；B县"}, {"letter": "C", "text": "响彻天鞭炮生产厂；B县"}, {"letter": "D", "text": "一路通公司；D县"}], "answer": "A", "explanation": "根据《烟花爆竹安全管理条例》第23条规定，经由道路运输烟花爆竹的，托运人应当向运达地县级人民政府公安部门提出申请。本题中大地红土产公司作为收货方和托运人，应向运达地即B县的公安机关申请《烟花爆竹道路运输许可证》。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 513}, {"num": 515, "batch": "专业基础知识", "type": "single", "stem": "丙公司从甲省将李某托运的烟花爆竹运到乙省交王某后，（）应当在（）日内将烟花爆竹道路运输许可证交回发证机关核销。", "options": [{"letter": "A", "text": "李某；3"}, {"letter": "B", "text": "李某；5"}, {"letter": "C", "text": "王某；3"}, {"letter": "D", "text": "丙公司；5"}], "answer": "C", "explanation": "根据《烟花爆竹安全管理条例》第25条规定，烟花爆竹运达目的地后，收货人应当在3日内将《烟花爆竹道路运输许可证》交回发证机关核销。本题中王某为收货人，应由王某在3日内交回许可证。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 514}, {"num": 516, "batch": "专业基础知识", "type": "single", "stem": "关于枪支管理，下列说法错误的是（）", "options": [{"letter": "A", "text": "国务院公安部门主管全国的枪支管理工作"}, {"letter": "B", "text": "民兵装备的枪支由地级以上地方各级人民政府公安机关管理"}, {"letter": "C", "text": "上级人民政府公安机关监督下级人民政府公安机关的枪支管理工作"}, {"letter": "D", "text": "国家严格管制枪支"}], "answer": "B", "explanation": "根据《枪支管理法》第4条规定，国务院公安部门主管全国的枪支管理工作；县级以上地方各级人民政府公安机关主管本行政区域内的枪支管理工作；上级公安机关监督下级公安机关的枪支管理工作。民兵装备的枪支由人民武装部门负责管理，而非地方公安机关管理，故B项错误。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 515}, {"num": 517, "batch": "专业基础知识", "type": "single", "stem": "某国驻华外交代表机构的人员携带枪支进入我国，需报（）批准。", "options": [{"letter": "A", "text": "外交部"}, {"letter": "B", "text": "公安部"}, {"letter": "C", "text": "中央军委"}, {"letter": "D", "text": "国家安全部"}], "answer": "A", "explanation": "根据《枪支管理法》第11条规定，外国驻华外交代表机构、领事机构的人员携带枪支入境，必须经外交部批准。外交事务由外交部主管管理，枪支入境涉及外交特权与豁免问题，因此审批权归外交部。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 516}, {"num": 518, "batch": "专业基础知识", "type": "single", "stem": "某民用枪支制造企业在2010年取得民用枪支制造许可证件，其应于（）年申请年审换证。", "options": [{"letter": "A", "text": "2012"}, {"letter": "B", "text": "2013"}, {"letter": "C", "text": "2015"}, {"letter": "D", "text": "2020"}], "answer": "B", "explanation": "根据《民用枪支制造许可证件》相关规定，民用枪支制造许可证件有效期为3年，有效期届满需要继续制造的，应当在届满前6个月申请年审换证。2010年取得许可证，3年后即2013年应申请年审换证。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 517}, {"num": 519, "batch": "专业基础知识", "type": "single", "stem": "某野生动物保护单位配购了一批猎枪，按照规定其必须在配购枪支后（）日内向核发民用枪支配购证件的公安机关申请领取民用枪支持枪证件。", "options": [{"letter": "A", "text": "90"}, {"letter": "B", "text": "30"}, {"letter": "C", "text": "45"}, {"letter": "D", "text": "60"}], "answer": "B", "explanation": "根据《枪支管理法》第13条规定，配备、配置民用枪支的单位和个人，必须在配购枪支后30日内向核发民用枪支配购证件的公安机关申请领取民用枪支持枪证件。这是为了确保枪支配备后及时纳入公安机关的证件管理体系。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 518}, {"num": 520, "batch": "专业基础知识", "type": "single", "stem": "关于猎枪的配置，下列说法错误的是（）", "options": [{"letter": "A", "text": "某狩猎场经省级以上人民政府林业行政主管部门批准，可以配置猎枪"}, {"letter": "B", "text": "某省级人民政府公安机关批准的营业性射击场，可以配置猎枪"}, {"letter": "C", "text": "某猎民在猎区，可以申请配置猎枪"}, {"letter": "D", "text": "某牧民在牧区，可以申请配置猎枪"}], "answer": "B", "explanation": "根据《枪支管理法》第6条规定，营业性射击场配置射击运动枪支，应由省级以上人民政府公安机关批准，而非仅经省级人民政府公安机关批准即可配置猎枪。且营业性射击场配置的应为射击运动枪支，而非猎枪。猎枪的配置对象包括狩猎场、猎区猎民和牧区牧民，但营业性射击场不在猎枪配置范围之内。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 519}, {"num": 521, "batch": "专业基础知识", "type": "single", "stem": "某单位依法取得危险化学品安全使用许可证，凭（）购买剧毒化学品。", "options": [{"letter": "A", "text": "剧毒化学品购买许可证"}, {"letter": "B", "text": "危险化学品安全使用许可证"}, {"letter": "C", "text": "单位出具的证明材料"}, {"letter": "D", "text": "单位出具的合法用途说明?"}], "answer": "B", "explanation": "根据《危险化学品安全管理条例》第29条规定，依法取得危险化学品安全使用许可证的企业，可以凭安全使用许可证购买剧毒化学品，无需另行申请剧毒化学品购买许可证。这简化了合法企业的购买程序，以许可证作为购买凭证。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 520}, {"num": 522, "batch": "专业基础知识", "type": "single", "stem": "危险化学品生产企业、经营企业销售剧毒化学品、易制爆危险化学品，其销售记录以及经办人的身份证明复印件、相关许可证件复印件或者证明文件的保存期限不得少于（）。", "options": [{"letter": "A", "text": "3个月"}, {"letter": "B", "text": "6个月"}, {"letter": "C", "text": "1年"}, {"letter": "D", "text": "2年"}], "answer": "C", "explanation": "根据《危险化学品安全管理条例》第23条规定，危险化学品生产企业、经营企业销售剧毒化学品、易制爆危险化学品，其销售记录以及经办人的身份证明复印件、相关许可证件复印件或者证明文件的保存期限不得少于1年。这一规定是为了便于追溯和监管。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 521}, {"num": 523, "batch": "专业基础知识", "type": "single", "stem": "下列关于人民警察使用警械和武器的说法错误的是（）", "options": [{"letter": "A", "text": "人民警察使用驱逐性、制服性警械之前，必须先予以警告"}, {"letter": "B", "text": "人民警察使用驱逐性、制服性警械，应当以制止违法犯罪行为为限度"}, {"letter": "C", "text": "犯罪分子失去继续实施犯罪能力的，人民警察应当立即停止使用武器"}, {"letter": "D", "text": "对正在进行持枪抢劫的孕妇，不得使用武器予以制止"}], "answer": "D", "explanation": "根据《人民警察使用警械和武器条例》第9条规定，对怀孕妇女、儿童实施犯罪行为的，如果其使用枪支、爆炸、剧毒等危险物品实施暴力犯罪，人民警察可以使用武器。因此对正在持枪抢劫的孕妇，并非绝对不得使用武器，D项说法错误。A、B、C项均符合条例规定。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 522}, {"num": 524, "batch": "专业基础知识", "type": "single", "stem": "某市民众受不法分子谣言蛊惑，误以为该市要建造高度污染的化工项目，遂于周末在市政府门前非法举行游行、示威，造成当地交通瘫痪。为维护正常社会秩序，现场执勤民警经警告无效，（）", "options": [{"letter": "A", "text": "可以根据需要选择使用警械和武器"}, {"letter": "B", "text": "只可以使用约束性警械"}, {"letter": "C", "text": "可以使用驱逐性、制服性警械"}, {"letter": "D", "text": "可以使用武器"}], "answer": "C", "explanation": "根据《人民警察使用警械和武器条例》第7条规定，遇有非法举行集会、游行、示威等情形，经警告无效的，人民警察可以使用驱逐性、制服性警械。本题中群众非法游行造成交通瘫痪，属于可以使用驱逐性、制服性警械的情形，但不符合使用武器的条件。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 523}, {"num": 525, "batch": "专业基础知识", "type": "single", "stem": "刘某因超速驾驶被民警处以200元罚款，其不服处罚，对民警撕扯拉拽。这时，民警根据《人民警察使用警械和武器条例》的规定，（）", "options": [{"letter": "A", "text": "不能还手"}, {"letter": "B", "text": "可以直接使用警棍将该女司机制服"}, {"letter": "C", "text": "对该女司机先进行警告，其不听，可以用警棍将其制服?"}, {"letter": "D", "text": "经警告无效后，可以使用武器"}], "answer": "C", "explanation": "根据《人民警察使用警械和武器条例》第7条规定，以暴力方法抗拒或阻碍人民警察依法履行职责的，经警告无效可以使用驱逐性、制服性警械。刘某对民警撕扯拉拽属于暴力阻碍执法，应先警告，警告无效后可使用警棍等制服性警械将其制服，但不符合使用武器的条件。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 524}, {"num": 526, "batch": "专业基础知识", "type": "single", "stem": "下列情形中，人民警察可以使用驱逐性、制服性警械的是（）", "options": [{"letter": "A", "text": "不遵守交通规则，经警告无效的"}, {"letter": "B", "text": "犯罪嫌疑人被拘传时企图吞刀片，经警告无效的"}, {"letter": "C", "text": "犯罪嫌疑人被抓捕时企图用头撞墙，经警告无效的"}, {"letter": "D", "text": "强行冲越人民警察为履行职责设置的警戒线，经警告无效的"}], "answer": "D", "explanation": "根据《人民警察使用警械和武器条例》第7条规定，强行冲越人民警察为履行职责设置的警戒线的，经警告无效可以使用驱逐性、制服性警械。A项属于交通违法，不适用警械；B、C项属于嫌疑人自伤行为，不适用驱逐性、制服性警械。D项符合法定使用条件。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 525}, {"num": 527, "batch": "专业基础知识", "type": "single", "stem": "下列关于使用武器的说法正确的是（）", "options": [{"letter": "A", "text": "只要实施犯罪的人为怀孕妇女、儿童的，人民警察就不得使用武器"}, {"letter": "B", "text": "犯罪分子处于群众聚集的场所，人民警察应当立即停止使用武器"}, {"letter": "C", "text": "犯罪分子劫持人质的，人民警察应当立即停止使用武器"}, {"letter": "D", "text": "犯罪分子失去继续实施犯罪能力的，人民警察应当立即停止使用武器"}], "answer": "D", "explanation": "根据《人民警察使用警械和武器条例》第11条规定，犯罪分子失去继续实施犯罪能力的，人民警察应当立即停止使用武器。A项错误，怀孕妇女、儿童使用枪支等危险物品实施暴力犯罪的可以使用武器；B项错误，犯罪分子处于群众聚集场所但停止使用武器的条件是'不得伤及无辜'而非立即停止；C项劫持人质属于可以使用武器的情形。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 526}, {"num": 528, "batch": "专业基础知识", "type": "single", "stem": "郑某持枪杀死3人、伤2人后逃跑。当地动员了近万余人围捕。次日下午，郑某拦乘一辆载满乘客的长途大客车，行至市区大桥时，被警察堵截。经侦查，郑某随身未携带枪支、刀具等危险物品。下面做法正确的是（）", "options": [{"letter": "A", "text": "可以使用武器"}, {"letter": "B", "text": "应当使用武器"}, {"letter": "C", "text": "立即使用武器"}, {"letter": "D", "text": "不得使用武器"}], "answer": "D", "explanation": "根据《人民警察使用警械和武器条例》第10条规定，犯罪分子处于群众聚集的场所或者存放大量易燃、易爆、剧毒等危险物品的场所，不得使用武器，但是不使用武器予以制止，将发生更为严重危害后果的除外。本题中郑某在载满乘客的长途客车上且未携带枪支刀具，使用武器会危及乘客安全，故不得使用武器。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 527}, {"num": 529, "batch": "专业基础知识", "type": "single", "stem": "下列情形中，人民警察不得使用武器的是（）", "options": [{"letter": "A", "text": "怀孕妇女持枪进行暴力恐怖袭击，正在杀害群众"}, {"letter": "B", "text": "涉嫌抢劫罪的犯罪分子在群众聚集的闹市区中逃逸"}, {"letter": "C", "text": "涉嫌故意杀人的犯罪分子拒捕逃入农田"}, {"letter": "D", "text": "犯罪分子冲击看守所劫夺在押嫌犯"}], "answer": "B", "explanation": "根据《人民警察使用警械和武器条例》第10条规定，犯罪分子处于群众聚集的场所，不得使用武器。B项中犯罪分子在群众聚集的闹市区逃逸，使用武器可能危及群众安全，故不得使用武器。A项孕妇正在杀害群众，属于紧急情形可以使用；C、D项均不属于禁止使用武器的情形。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 528}, {"num": 530, "batch": "专业基础知识", "type": "single", "stem": "谢某、刘某因小孩矛盾发生纠纷，进而大打出手，民警小王、老田接到报警到达现场时，谢某正用菜刀砍刘某，刘某到处躲闪。此时，（）", "options": [{"letter": "A", "text": "民警可以立即使用武器制止谢某"}, {"letter": "B", "text": "民警不得对谢某使用武器"}, {"letter": "C", "text": "民警经警告无效后可以使用武器"}, {"letter": "D", "text": "民警应当先使用警械，不能制止的再使用武器"}], "answer": "C", "explanation": "根据《人民警察使用警械和武器条例》第9条规定，人民警察判明有暴力犯罪行为的紧急情形，经警告无效的，可以使用武器。谢某正用菜刀砍刘某，属于正在实施的严重暴力犯罪，民警应先警告，警告无效后方可使用武器。情况紧急来不及警告的可以直接使用，但本题选项中C项'经警告无效后可以使用武器'最为规范。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 529}, {"num": 531, "batch": "专业基础知识", "type": "single", "stem": "某市发生一起暴力恐怖袭击案件，一名犯罪分子在砍杀路人后，持刀冲向赶到现场处置的民警，被民警开枪击中大腿，倒地不起。此时，该民警应当（）", "options": [{"letter": "A", "text": "继续射击"}, {"letter": "B", "text": "立即停止使用武器"}, {"letter": "C", "text": "立即通知当地检察机关"}, {"letter": "D", "text": "及时对现场进行勘验、调查"}], "answer": "B", "explanation": "根据《人民警察使用警械和武器条例》第11条规定，犯罪分子失去继续实施犯罪能力的，人民警察应当立即停止使用武器。本题中犯罪分子被击中大腿后倒地不起，已丧失继续犯罪的能力，民警应当立即停止使用武器。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 530}, {"num": 532, "batch": "专业基础知识", "type": "single", "stem": "赵某涉嫌故意杀人罪。民警抓捕赵某时，依法向其射击，致其受重伤倒地，此时民警做法不正确的是（）", "options": [{"letter": "A", "text": "及时通知赵某家属"}, {"letter": "B", "text": "及时抢救赵某"}, {"letter": "C", "text": "保护现场"}, {"letter": "D", "text": "立即向其所属公安机关报告"}], "answer": "A", "explanation": "根据《人民警察使用警械和武器条例》第12条规定，人民警察使用武器造成犯罪分子伤亡的，应当及时抢救受伤人员，保护现场，并立即向当地公安机关或所属机关报告。通知家属并非法定的必须立即履行的义务，而是后续程序。因此A项'及时通知赵某家属'不是民警此时应当做的事情，但题目问的是'不正确的是'，实际上通知家属是应当做的但非紧急义务，本题A项为答案。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 531}, {"num": 533, "batch": "专业基础知识", "type": "single", "stem": "人民警察使用武器造成犯罪分子伤亡的，应当立即向（）或该人民警察所属机关报告。", "options": [{"letter": "A", "text": "上级公安机关"}, {"letter": "B", "text": "人民检察院"}, {"letter": "C", "text": "当地人民政府"}, {"letter": "D", "text": "当地公安机关"}], "answer": "D", "explanation": "根据《人民警察使用警械和武器条例》第12条规定，人民警察使用武器造成犯罪分子伤亡的，应当立即向当地公安机关或该人民警察所属机关报告。'当地公安机关'指事发地的公安机关，便于及时进行现场调查和处理。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 532}, {"num": 534, "batch": "专业基础知识", "type": "single", "stem": "民警小王在巡逻过程中遇到一醉酒男子，该男子对小王出言不逊，小王遂使用催泪瓦斯将该男子制服，造成该男子眼部红肿，经送医就诊后逐步好转。对于小王违法使用警械的行为，下列说法正确的是（）", "options": [{"letter": "A", "text": "应当予以行政处罚"}, {"letter": "B", "text": "应当承担刑事责任"}, {"letter": "C", "text": "应当予以行政处分"}, {"letter": "D", "text": "应当承担民事赔偿责任"}], "answer": "C", "explanation": "根据《人民警察使用警械和武器条例》第14条规定，人民警察违法使用警械、武器，造成不应有的人员伤亡、财产损失，构成犯罪的依法追究刑事责任，尚不构成犯罪的依法给予处分。本题中小王对醉酒人员使用催泪瓦斯属于违法使用警械，尚不构成犯罪，应当给予行政处分。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 533}, {"num": 535, "batch": "专业基础知识", "type": "single", "stem": "某派出所民警朱某在处置一起聚众斗殴警情中，刘某不听制止，持刀砍向朱某，朱某躲避倒地后，刘某继续追砍，朱某情急之下开枪造成刘某死亡，同时造成一名围观群众受伤。下列说法错误的是（）", "options": [{"letter": "A", "text": "朱某开枪的行为合法"}, {"letter": "B", "text": "朱某开枪后应当立即向所属分局报告"}, {"letter": "C", "text": "因朱某开枪造成围观群众受伤，不能给予其处分"}, {"letter": "D", "text": "朱某所属公安机关应当对受伤群众给予赔偿"}], "answer": "D", "explanation": "根据《人民警察使用警械和武器条例》相关规定，朱某在生命受到紧迫威胁时开枪属于合法使用武器。使用武器后应当立即向所属公安机关报告。因合法使用武器造成无辜群众受伤的，由所属公安机关依照《国家赔偿法》给予赔偿，而非不予处分。C项说法错误，合法使用武器造成附带伤害不影响对民警行为合法性的认定。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 534}, {"num": 536, "batch": "专业基础知识", "type": "single", "stem": "某日，多人在A市政府门口非法游行，表达不合理诉求，沿途有不少群众围观。现场执勤民警命令游行人员解散，游行人员拒不执行且起哄闹事，造成现场交通秩序瘫痪。民警经警告无效且命令在场无关人员躲避后，使用高压水枪强行驱散游行人员，但还是造成围观群众王某受伤住院。下列说法正确的是（）", "options": [{"letter": "A", "text": "王某虽未参加游行，但其并未按命令躲避，应当由自己承担受伤住院责任"}, {"letter": "B", "text": "王某系无辜群众，受到民警执行职务行为的伤害，应得到国家的补偿"}, {"letter": "C", "text": "王某系无辜群众，受到民警执行职务行为的伤害，应由造成伤害的民警赔偿"}, {"letter": "D", "text": "王某系无辜群众，受到民警执行职务行为的伤害，应由造成伤害的民警所属公安机关赔偿"}], "answer": "B", "explanation": "根据《人民警察使用警械和武器条例》第14条规定，人民警察依法使用警械和武器，造成无辜人员伤亡、财产损失的，由该人民警察所属机关参照《国家赔偿法》的有关规定给予补偿。王某为无辜群众，因民警合法执行职务而受伤，应得到国家的补偿，而非由民警个人赔偿或自行承担。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 535}, {"num": 537, "batch": "专业基础知识", "type": "single", "stem": "下列关于使用武器的说法错误的是（）", "options": [{"letter": "A", "text": "人民警察使用武器的，应当将使用武器的情况如实向所属机关书面报告"}, {"letter": "B", "text": "人民警察判明有符合使用武器条件的暴力犯罪行为，来不及警告或者警告后可能导致更为严重危害后果的，可以直接使用武器"}, {"letter": "C", "text": "人民警察违法使用警械、武器，造成不应有的人员伤亡、财产损失的，对受到伤亡或者财产损失的人员，由该人民警察所属机关依照《国家赔偿法》的有关规定给予赔偿?"}, {"letter": "D", "text": "对于正在进行持枪抢劫的孕妇，人民警察不可以使用武器"}], "answer": "D", "explanation": "根据《人民警察使用警械和武器条例》第9条规定，对怀孕妇女使用枪支、爆炸、剧毒等危险物品实施暴力犯罪的，人民警察可以使用武器。因此D项'对于正在进行持枪抢劫的孕妇，不可以使用武器'说法错误。A、B、C项均符合条例关于武器使用的规定。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 536}, {"num": 538, "batch": "专业基础知识", "type": "single", "stem": "张某与李某为邻居。一日张某回家路过李某家，见李妻独自一人在家收拾衣服，遂起歹念，便破门而入，将其推倒在院内柴堆上欲行强奸，李妻大声呼救。刚好民警王某下班路过听到，王某表明身份后，喝令张某住手。张某掏出随身携带的匕首袭击王某，刺伤王某胸部，王某倒地。张某仍持匕首继续刺向王某。王某掏枪射击，将张某击伤，同时将刚回家的李某误伤。下列说法正确的是（）", "options": [{"letter": "A", "text": "王某开枪的行为合法"}, {"letter": "B", "text": "王某开枪后应当立即报告当地检察院"}, {"letter": "C", "text": "王某射击前应先警告?"}, {"letter": "D", "text": "击伤李某是违法行为"}], "answer": "A", "explanation": "王某下班途中遇到正在实施的强奸犯罪，表明身份后制止，张某持匕首袭击致王某受伤后继续攻击，王某开枪属于依法使用武器制止严重暴力犯罪，行为合法。合法使用武器过程中误伤他人，不改变使用武器行为的合法性。王某开枪后应向所属公安机关报告，而非向检察院报告。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 537}, {"num": 539, "batch": "专业基础知识", "type": "single", "stem": "(17年新增试题)下列违法行为，《网络安全法》明确规定应当由公安机关予以行政处罚的是（）", "options": [{"letter": "A", "text": "公司开发的游戏软件未向用户明示并取得同意即自动收集用户的个人信息"}, {"letter": "B", "text": "乙地铁公司使用未经国家安全审查的网络产品"}, {"letter": "C", "text": "丙公司为用户提供发布信息的微博服务，对未提供真实身份信息的用户仍提供服务"}, {"letter": "D", "text": "丁公司为用户提供专门用于窃取网络数据的计算机程序"}], "answer": "D", "explanation": "根据《网络安全法》第63条规定，提供专门用于从事侵入网络、干扰网络系统正常功能及防护措施、窃取网络数据等危害网络安全活动的程序、工具的，由公安机关予以处罚。D项丁公司提供窃取网络数据的程序属于此类行为。A项由网信部门管辖，B项由相关部门处理，C项由有关主管部门处理。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 538}, {"num": 540, "batch": "专业基础知识", "type": "single", "stem": "(17年新增试题)德天公司开发了导航软件供用户下载安装使用，并在该软件中设置了恶意程序，同时该软件使用时未经用户同意收集用户地址。该公司职员陈某利用职务之便获取了部分用户的电话号码，并向他人提供，尚不构成犯罪。根据《网络安全法》的规定，下列说法错误的是（）", "options": [{"letter": "A", "text": "德天公司应当向用户明示并取得同意才能收集用户地址"}, {"letter": "B", "text": "德天公司设置恶意程序的行为属于违法行为"}, {"letter": "C", "text": "公安机关应当对陈某给予行政处罚"}, {"letter": "D", "text": "陈某3年内不得从事网络安全管理和网络运营关键岗位的工作"}], "answer": "D", "explanation": "根据《网络安全法》第63条规定，违反第27条规定受到治安管理处罚的人员，5年内不得从事网络安全管理和网络运营关键岗位的工作；受到刑事处罚的人员，终身不得从事相关工作。陈某尚不构成犯罪，应为5年内不得从事相关工作，而非3年，D项说法错误。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 539}, {"num": 541, "batch": "专业基础知识", "type": "single", "stem": "决定战争与和平问题的职权由（）行使。", "options": [{"letter": "A", "text": "全国人民代表大会常务委员会"}, {"letter": "B", "text": "全国人民代表大会"}, {"letter": "C", "text": "中央军事委员会"}, {"letter": "D", "text": "国务院"}], "answer": "B", "explanation": "根据《宪法》第62条第15项规定，全国人民代表大会行使决定战争和和平的问题的职权。全国人大常委会的职权是决定战争状态的宣布（第67条），而非决定战争与和平问题。这是全国人大作为最高国家权力机关的核心职权之一。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 540}, {"num": 542, "batch": "专业基础知识", "type": "single", "stem": "下列不属于《宪法》规定的我国基层群众性自治组织的任务的是（）", "options": [{"letter": "A", "text": "办理本居住地区的公共事务"}, {"letter": "B", "text": "主管本居住地区的社会治安"}, {"letter": "C", "text": "向人民政府反映人民群众的意见和要求"}, {"letter": "D", "text": "办理本居住地区的公益事业"}], "answer": "B", "explanation": "根据《宪法》第111条规定，城市和农村按居民居住地区设立的居民委员会或者村民委员会是基层群众性自治组织，其任务是办理本居住地区的公共事务和公益事业，调解民间纠纷，协助维护社会治安，向人民政府反映群众的意见、要求和提出建议。'主管社会治安'不属于其任务，基层群众性自治组织是'协助'而非'主管'。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 541}, {"num": 543, "batch": "专业基础知识", "type": "single", "stem": "根据我国《宪法》的规定，下列关于私有财产权的表述错误的是（）", "options": [{"letter": "A", "text": "公民合法的私有财产不受侵犯"}, {"letter": "B", "text": "国家依照法律规定保护公民的继承权"}, {"letter": "C", "text": "公民的私有财产在任何情况下都不得剥夺"}, {"letter": "D", "text": "国家为了公共利益的需要，可以依照法律规定对公民的私有财产实行征收或者征用并给予补偿"}], "answer": "C", "explanation": "根据《宪法》第13条规定，公民的合法的私有财产不受侵犯；国家依照法律规定保护公民的私有财产权和继承权；国家为了公共利益的需要，可以依照法律规定对公民的私有财产实行征收或者征用并给予补偿。C项'公民的私有财产在任何情况下都不得剥夺'过于绝对，国家在法定条件下可以依法征收或征用。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 542}, {"num": 544, "batch": "专业基础知识", "type": "single", "stem": "下列不属于公民政治自由的是（）", "options": [{"letter": "A", "text": "言论自由"}, {"letter": "B", "text": "出版自由"}, {"letter": "C", "text": "集会游行示威的自由"}, {"letter": "D", "text": "劳动自由"}], "answer": "D", "explanation": "根据《宪法》第35条规定，中华人民共和国公民有言论、出版、集会、结社、游行、示威的自由。这些属于公民的政治自由。劳动自由不属于政治自由范畴，劳动是公民的权利和义务（《宪法》第42条），但不属于政治自由的范围。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 543}, {"num": 545, "batch": "专业基础知识", "type": "single", "stem": "下列选项中既是公民权利，又是公民义务的是（）。①劳动②受教育③纳税④宗教信仰自由", "options": [{"letter": "A", "text": "①②"}, {"letter": "B", "text": "②③"}, {"letter": "C", "text": "③④"}, {"letter": "D", "text": "①④"}], "answer": "A", "explanation": "根据《宪法》第42条规定，中华人民共和国公民有劳动的权利和义务；第46条规定，中华人民共和国公民有受教育的权利和义务。因此劳动和受教育既是权利又是义务。纳税仅是义务（第56条），宗教信仰自由仅是权利（第36条）。故①②正确，选A。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 544}, {"num": 546, "batch": "专业基础知识", "type": "single", "stem": "下列职权由国务院行使的是（）。①批准省、自治区和直辖市的建置②批准省、自治区、直辖市的区域划分，批准自治州、县、自治县、市的建置和区域划分③决定全国或者个别省、自治区、直辖市进入紧急状态④决定省、自治区、直辖市的范围内部分地区进入紧急状态", "options": [{"letter": "A", "text": "①②③④"}, {"letter": "B", "text": "②③"}, {"letter": "C", "text": "①②④"}, {"letter": "D", "text": "②④"}], "answer": "D", "explanation": "根据《宪法》第89条规定，国务院行使下列职权：批准省、自治区、直辖市的区域划分，批准自治州、县、自治县、市的建置和区域划分（第15项）；依照法律规定决定省、自治区、直辖市的范围内部分地区进入紧急状态（第16项）。批准省级建置由全国人大行使（第62条），决定全国或个别省进入紧急状态由全国人大常委会行使（第67条）。故②④正确，选D。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 545}, {"num": 547, "batch": "专业基础知识", "type": "single", "stem": "甲在一豪宅院外将1个正在玩耍的男孩（3岁）骗走，意图勒索钱财，但孩子说不清自己家里的联系方式，无法进行勒索。甲怕时间长了被发现，于是将孩子带到异地以4000元卖掉。对甲应当（）", "options": [{"letter": "A", "text": "以绑架罪和拐卖儿童罪从一重处断"}, {"letter": "B", "text": "以绑架罪一罪处罚"}, {"letter": "C", "text": "以拐卖儿童罪一罪处罚"}, {"letter": "D", "text": "以绑架罪和拐卖儿童罪并罚"}], "answer": "D", "explanation": "甲以勒索财物为目的将男孩骗走，已构成绑架罪。后因无法联系家属，又将孩子卖掉，另构成拐卖儿童罪。根据最高人民法院相关司法解释，以勒索财物为目的绑架他人后又将被害人拐卖的，应以绑架罪和拐卖儿童罪数罪并罚。两个犯罪行为侵犯了不同法益，应当分别评价。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 546}, {"num": 548, "batch": "专业基础知识", "type": "single", "stem": "某纺织厂违反劳动管理法规，以限制人身自由方法强迫职工劳动，以下不构成强迫劳动罪的情形是（）", "options": [{"letter": "A", "text": "强迫妇女从事井下劳动"}, {"letter": "B", "text": "强迫妇女劳动，导致轻伤"}, {"letter": "C", "text": "采用扣发工资方式，强迫妇女劳动"}, {"letter": "D", "text": "强迫不满14岁的少女从事超体力劳动"}], "answer": "D", "explanation": "根据《刑法》第244条强迫劳动罪的规定，以暴力、威胁或者限制人身自由的方法强迫他人劳动的构成该罪。A项强迫妇女从事井下劳动属于强迫劳动的加重情形；B项导致轻伤属于暴力强迫的后果；C项扣发工资结合限制人身自由属于强迫劳动；D项强迫不满14岁少女从事超体力劳动，应认定为雇用童工从事危重劳动罪，不属于强迫劳动罪的评价范围。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 547}, {"num": 549, "batch": "专业基础知识", "type": "single", "stem": "甲见丙（女，13周岁）很漂亮，想与其发生性关系，要其朋友乙帮忙做通丙的思想工作，让丙自愿来与甲发生性关系。乙说丙尚未满14周岁，想吃嫩草要付出代价，如工作做成要甲付给其人民币5000元。甲同意。乙利用与丙系邻居关系的便利条件，将丙带至家中看黄色录像，诱惑其对性产生好奇，后要丙与甲在乙家中模仿黄色录像中性行为，并给3000元。甲与丙发生性关系的愿望得到实现，后付给乙人民币5000元。下列表述正确的是（）", "options": [{"letter": "A", "text": "乙构成介绍卖淫罪"}, {"letter": "B", "text": "乙构成引诱幼女卖淫罪"}, {"letter": "C", "text": "乙构成引诱幼女卖淫罪和容留、介绍卖淫罪，数罪并罚"}, {"letter": "D", "text": "乙构成强奸罪"}], "answer": "D", "explanation": "丙仅13周岁，属于幼女，不具有性承诺能力。甲与幼女发生性关系，不论幼女是否自愿，均构成强奸罪。乙明知丙不满14周岁，仍帮助甲引诱丙发生性关系，乙构成强奸罪的共犯（帮助犯）。乙虽收取了钱财，但本案本质是帮助甲实现强奸幼女的目的，而非介绍卖淫，故乙构成强奸罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 548}, {"num": 550, "batch": "专业基础知识", "type": "single", "stem": "易某欠姜某10万元，多次催讨不还。姜某便纠集白某、杜某二人前往易某家中将其骗到自己开来的车上，驶往邻省一朋友家中。次日电话告知易某的妻子，拿30万元赎人。在拘禁期间，因怕易某被人发现，将其藏匿于轿车后备厢内，后易某因窒息死亡。姜某、白某、杜某三人的行为构成（）", "options": [{"letter": "A", "text": "故意杀人罪"}, {"letter": "B", "text": "非法拘禁罪"}, {"letter": "C", "text": "绑架罪"}, {"letter": "D", "text": "故意伤害（致人死亡）罪"}], "answer": "C", "explanation": "姜某等人以索债为名，将易某骗走拘禁，后向易某妻子索要30万元（远超原债务10万元），其行为性质已从非法拘禁转化为以勒索财物为目的的绑架行为。根据《刑法》第239条规定，以勒索财物为目的绑架他人的构成绑架罪。拘禁期间易某因窒息死亡属于绑架罪的加重结果。三人构成绑架罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 549}, {"num": 551, "batch": "专业基础知识", "type": "single", "stem": "假如某地敲诈勒索“数额较大”的标准为2000元。下列构成敲诈勒索罪的有（）", "options": [{"letter": "A", "text": "李某曾因盗窃受过刑事处罚，又敲诈勒索王某1500元"}, {"letter": "B", "text": "周某敲诈勒索小学生陈某（10岁）1000元"}, {"letter": "C", "text": "郑某敲诈勒索其父亲2000元，获得其父亲谅解"}, {"letter": "D", "text": "钱某1年内敲诈勒索贾某2次，累计1200元"}], "answer": "B", "explanation": "根据《关于办理敲诈勒索刑事案件适用法律若干问题的解释》，敲诈勒索数额较大标准为2000元至5000元。B项周某敲诈勒索小学生1000元，根据该解释第2条，对未成年人实施敲诈勒索的，数额标准可按50%认定，即1000元已达到'数额较大'标准（2000元的50%为1000元），构成敲诈勒索罪。A项1500元未达50%标准（1000元）虽曾因盗窃受罚但需满足数额条件；C项家庭成员间获谅解可不按犯罪处理；D项不符合'多次'（3次以上）的标准。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 550}, {"num": 552, "batch": "专业基础知识", "type": "single", "stem": "甲为报复乙，将乙单独停放在院子里的汽车烧毁，未造成其他损失。甲的行为构成（）", "options": [{"letter": "A", "text": "破坏交通工具罪"}, {"letter": "B", "text": "放火罪"}, {"letter": "C", "text": "破坏交通工具罪和放火罪"}, {"letter": "D", "text": "故意毁坏财物罪"}], "answer": "D", "explanation": "甲为报复烧毁乙停在院子里的汽车，由于汽车在私人院内，烧毁行为不足以危害公共安全，不构成放火罪。汽车停放在院内未处于运行状态，不构成破坏交通工具罪。甲的行为是针对特定个人财产的故意毁坏，应以故意毁坏财物罪定罪处罚。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 551}, {"num": 553, "batch": "专业基础知识", "type": "single", "stem": "以下不应当以拐卖妇女、儿童罪立案侦查的是（）", "options": [{"letter": "A", "text": "甲以出卖为目的，实施收买妇女、儿童的行为"}, {"letter": "B", "text": "乙实施拐卖妇女的行为，但没有获利"}, {"letter": "C", "text": "丙拐卖妇女并强迫被拐卖的妇女卖淫"}, {"letter": "D", "text": "丁向他人传授拐卖妇女、儿童的犯罪方法"}], "answer": "D", "explanation": "拐卖妇女、儿童罪是指以出卖为目的，拐骗、绑架、收买、贩卖、接送、中转妇女、儿童的行为。A项以出卖为目的收买属于拐卖行为；B项虽未获利但不影响拐卖罪的成立（获利不是构成要件）；C项拐卖并强迫卖淫属于拐卖罪的加重情节；D项传授犯罪方法构成传授犯罪方法罪，不属于拐卖妇女、儿童罪的行为方式。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 552}, {"num": 554, "batch": "专业基础知识", "type": "single", "stem": "甲最初组织未成年人实施的小偷小摸行为，没有达到盗窃罪的定罪量刑标准，仅仅是违反治安管理的活动，后来这些未成年人偷盗的数额达到了盗窃罪的标准。甲的行为构成（）", "options": [{"letter": "A", "text": "盗窃罪"}, {"letter": "B", "text": "组织未成年人进行违反治安管理活动罪"}, {"letter": "C", "text": "盗窃罪和组织未成年人进行违反治安管理活动罪，数罪并罚"}, {"letter": "D", "text": "盗窃罪和组织未成年人进行违反治安管理活动罪，择一重罪处罚"}], "answer": "C", "explanation": "根据《刑法》第262条之二规定，组织未成年人进行盗窃、诈骗、抢夺、敲诈勒索等违反治安管理活动的，构成组织未成年人进行违反治安管理活动罪。甲先组织未成年人进行小偷小摸（违反治安管理活动），构成该罪；后盗窃数额达到盗窃罪标准，甲又构成盗窃罪。两罪侵犯不同法益，应数罪并罚。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 553}, {"num": 555, "batch": "专业基础知识", "type": "single", "stem": "律师赵某接受律师事务所的指派，为某公司股票上市提供法律意见，赵某在接受该公司的10万元财物后，提供了虚假的法律意见书，导致不具备上市条件的该公司取得上市资格，严重损害了股东利益，赵某的行为构成（）", "options": [{"letter": "A", "text": "受贿罪"}, {"letter": "B", "text": "非国家工作人员受贿罪"}, {"letter": "C", "text": "提供虚假证明文件罪"}, {"letter": "D", "text": "非国家工作人员受贿罪和提供虚假证明文件罪"}], "answer": "C", "explanation": "根据《刑法》第229条规定，承担资产评估、验资、验证、会计、审计、法律服务等职责的中介组织的人员故意提供虚假证明文件，情节严重的，构成提供虚假证明文件罪。律师赵某属于法律服务中介人员，提供虚假法律意见书构成该罪。赵某收受财物的行为被提供虚假证明文件罪所吸收，按提供虚假证明文件罪一罪处罚。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 554}, {"num": 556, "batch": "专业基础知识", "type": "single", "stem": "王某乘坐出租车，途中因晕车要求司机李某停车。李某见王某从银行出来上车，趁王某下车呕吐时，开车跑掉。王某留在车上的包内有人民币1万元。李某构成（）", "options": [{"letter": "A", "text": "抢劫罪"}, {"letter": "B", "text": "盗窃罪"}, {"letter": "C", "text": "侵占罪"}, {"letter": "D", "text": "抢夺罪"}], "answer": "D", "explanation": "李某趁王某下车呕吐之际，将王某留在车上的包带走。王某虽暂时离开车辆但并未放弃对包的控制和占有，李某以非法占有为目的，利用车辆快速驶离的方式公然夺取他人财物，属于趁人不备公然夺取，构成抢夺罪。李某利用汽车作为工具快速脱离现场，具有公然性。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 555}, {"num": 557, "batch": "专业基础知识", "type": "single", "stem": "乙（16周岁）进城打工，用人单位要求乙提供银行卡号以便发放工资。乙忘记携带身份证，便借用老乡甲的身份证以甲的名义办理了银行卡。乙将银行卡号提供给用人单位后，请甲保管银行卡。数月后，甲持该卡到银行柜台办理密码挂失，取出1万余元现金，拒不退还。甲的行为构成（）", "options": [{"letter": "A", "text": "信用卡诈骗罪"}, {"letter": "B", "text": "诈骗罪"}, {"letter": "C", "text": "盗窃罪"}, {"letter": "D", "text": "侵占罪"}], "answer": "D", "explanation": "乙借用甲的身份证以甲名义办卡，但卡内资金实际属于乙所有，甲只是代为保管银行卡。甲通过挂失密码的方式取出卡内属于乙的资金并拒不退还。由于银行卡以甲的名义开立，甲对该账户内资金具有合法占有权，其取出后拒不归还的行为属于将代为保管的他人财物非法占为己有，构成侵占罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 556}, {"num": 558, "batch": "专业基础知识", "type": "single", "stem": "下列行为中，应以金融凭证诈骗罪论处的是（）", "options": [{"letter": "A", "text": "甲某使用伪造、变造的汇票、本票、支票进行诈骗活动"}, {"letter": "B", "text": "乙使用伪造、变造的委托收款凭证、汇款凭证、银行存单进行诈骗活动"}, {"letter": "C", "text": "丙使用作废的委托收款凭证、汇款凭证、银行存单（未经伪造、变造）进行诈骗活动"}, {"letter": "D", "text": "丁使用伪造、变造的信用证、信用卡进行诈骗活动"}], "answer": "B", "explanation": "根据《刑法》第194条第2款规定，金融凭证诈骗罪是指使用伪造、变造的委托收款凭证、汇款凭证、银行存单等其他银行结算凭证进行诈骗活动。B项使用伪造变造的委托收款凭证等属于金融凭证诈骗罪。A项属于票据诈骗罪；C项使用作废（非伪造变造）的凭证不构成该罪；D项属于信用证诈骗罪和信用卡诈骗罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 557}, {"num": 559, "batch": "专业基础知识", "type": "single", "stem": "甲在无资金保证的情况下，使用行贿的手段从某银行开出400万元的银行汇票，兑成40万美元后注册了一个公司。然后又用这40万美元作抵押，向某银行开出200万元人民币的银行汇票，将款汇入自己的账户后提走。甲的行为构成（）", "options": [{"letter": "A", "text": "贷款诈骗罪"}, {"letter": "B", "text": "金融凭证诈骗罪"}, {"letter": "C", "text": "诈骗罪"}, {"letter": "D", "text": "票据诈骗罪?"}], "answer": "D", "explanation": "甲使用行贿手段从银行开出400万元银行汇票，并无真实资金保证，属于使用伪造的票据（空头汇票）进行诈骗活动。根据《刑法》第194条规定，使用伪造、变造的汇票等票据进行诈骗活动的，构成票据诈骗罪。甲通过票据诈骗注册公司后又以虚假抵押骗取另一银行汇票，整体行为构成票据诈骗罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 558}, {"num": 560, "batch": "专业基础知识", "type": "single", "stem": "甲欲诈骗银行贷款100万元，为保证贷款到手后迅速转移，找到乙帮忙想办法将资金汇往境外，乙同意。贷款到手后，乙找到丙，丙明知该笔资金的来源，仍然协助其将资金汇往境外。下列说法正确的是（）", "options": [{"letter": "A", "text": "甲、乙构成贷款诈骗罪，丙构成洗钱罪"}, {"letter": "B", "text": "甲构成贷款诈骗罪，乙、丙构成洗钱罪"}, {"letter": "C", "text": "乙构成贷款诈骗罪和洗钱罪，应予数罪并罚"}, {"letter": "D", "text": "甲、乙、丙构成贷款诈骗罪"}], "answer": "A", "explanation": "甲以非法占有为目的骗取银行贷款，乙与甲共谋并协助转移资金，甲乙构成贷款诈骗罪共犯。丙明知资金来源于贷款诈骗犯罪，仍协助将资金转移至境外，符合洗钱罪的构成要件。丙未参与贷款诈骗的共谋，不构成贷款诈骗罪共犯。乙在贷款诈骗完成后才帮助转移资金，不构成洗钱罪（因其是上游犯罪共犯）。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 559}, {"num": 561, "batch": "专业基础知识", "type": "single", "stem": "胡某纠集一批社会闲散人员预谋骗钱，便向王某租了一间门面房，按照银行的样式进行了粉刷和装修，并在门口挂上了“中国农业发展银行某某分行某某储蓄所”的牌匾，准备开始吸存时被公安机关查获。胡某构成（）", "options": [{"letter": "A", "text": "非法吸收公众存款罪（未遂）"}, {"letter": "B", "text": "诈骗罪"}, {"letter": "C", "text": "集资诈骗罪"}, {"letter": "D", "text": "擅自设立金融机构罪"}], "answer": "B", "explanation": "胡某按照银行样式装修门面并挂上假银行牌匾，准备吸存时被查获。虽然其伪造了银行外观，但其核心目的是通过虚构银行来骗取群众存款，属于以非法占有为目的的诈骗行为。由于尚未实际开始吸存即被查获，且其行为本质是以虚假金融机构为工具实施诈骗，应以诈骗罪论处。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 560}, {"num": 562, "batch": "专业基础知识", "type": "single", "stem": "江某与郑某是同一家电脑公司的工作人员，二人同住一间集体宿舍。某日，郑某将自己的信用卡交江某保管，3天后索回。1周后，郑某发现自己的信用卡丢失，到银行挂失时得知卡上的15万元已被人取走，郑某报案后，侦查人员找到江某，江某承认郑某将信用卡交其保管时私下取走现金。江某的行为构成（）", "options": [{"letter": "A", "text": "侵占罪"}, {"letter": "B", "text": "信用卡诈骗罪"}, {"letter": "C", "text": "盗窃罪"}, {"letter": "D", "text": "诈骗罪"}], "answer": "B", "explanation": "郑某将信用卡交江某保管期间，江某私下取走现金。根据《刑法》第196条规定，冒用他人信用卡的构成信用卡诈骗罪。江某在保管期间未经郑某同意私自使用其信用卡取款，属于冒用他人信用卡的行为，构成信用卡诈骗罪。注意江某是在合法保管信用卡期间使用，不同于盗窃信用卡后使用（定盗窃罪）。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 561}, {"num": 563, "batch": "专业基础知识", "type": "single", "stem": "付某在某镇收购粮食，并以暂不付现款，承诺6个月或1年后付款时加价或付高息的方法，先后骗取68户农民粮款共计70万元，后将收购的部分粮食以低于市场的价格出售。其间，付某用此资金购建房屋并用于家庭支出。被害人先后多次找付某要钱，付某以种种理由搪塞、拒绝，仅偿还一小部分欠款，后将房产卖掉逃匿。对付某的行为定性正确的是（）", "options": [{"letter": "A", "text": "付某构成集资诈骗罪"}, {"letter": "B", "text": "付某构成非法吸收公众存款罪"}, {"letter": "C", "text": "付某构成诈骗罪"}, {"letter": "D", "text": "付某构成违法运用资金罪"}], "answer": "A", "explanation": "付某以高价收购粮食为名，承诺延期付款并加价或付高息，向68户农民收取粮款70万元后低价出售粮食、购建房屋，最终逃匿。其行为具有明显的非法占有目的，以欺骗方法向社会不特定公众吸收资金，构成集资诈骗罪。付某的行为不是正常的经营活动，而是以经营为名行诈骗之实。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 562}, {"num": 564, "batch": "专业基础知识", "type": "single", "stem": "甲将受贿所得的名人字画一幅以10万元的价格卖给得知真相的乙。乙的行为（）", "options": [{"letter": "A", "text": "构成窝藏罪"}, {"letter": "B", "text": "构成受贿罪"}, {"letter": "C", "text": "构成洗钱罪"}, {"letter": "D", "text": "不构成犯罪"}], "answer": "C", "explanation": "根据《刑法》第191条洗钱罪的规定，明知是贪污贿赂犯罪的所得及其产生的收益，为掩饰、隐瞒其来源和性质而予以收购的，构成洗钱罪。乙明知字画是甲受贿所得仍予以购买，属于以其他方式掩饰、隐瞒犯罪所得的来源和性质，构成洗钱罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 563}, {"num": 565, "batch": "专业基础知识", "type": "single", "stem": "甲贪污公款1000万元欲逃往境外，找到朋友乙，告诉乙实情后请乙帮其将1000万元人民币换成美元汇往境外，乙照办。乙的行为（）", "options": [{"letter": "A", "text": "构成妨害司法罪"}, {"letter": "B", "text": "构成洗钱罪"}, {"letter": "C", "text": "构成非法经营罪"}, {"letter": "D", "text": "不构成犯罪"}], "answer": "B", "explanation": "根据《刑法》第191条洗钱罪的规定，明知是贪污犯罪的所得，协助将财产转换为现金、金融票据、有价证券或通过转账方式转移资金的，构成洗钱罪。乙明知1000万元是甲贪污所得，仍帮助换成美元汇往境外，属于协助转移犯罪所得，构成洗钱罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 564}, {"num": 566, "batch": "专业基础知识", "type": "single", "stem": "下列行为可以构成玩忽职守罪的是（）", "options": [{"letter": "A", "text": "在安全事故发生后，负有报告职责的人员甲谎报事故情况，贻误事故抢救，情节严重"}, {"letter": "B", "text": "国有公司工作人员乙严重不负责任，造成国有公司破产，致使国家利益遭受重大损失"}, {"letter": "C", "text": "负有环境保护监督管理职责的国家机关工作人员丙严重不负责任，致使发生重大环境污染事故，造成人身伤亡的严重后果"}, {"letter": "D", "text": "负有管理职责的国家机关工作人员丁发现他人非法从事天然气开采、加工等违法活动而不予查封、取缔，致使国家和人民利益遭受重大损失"}], "answer": "D", "explanation": "玩忽职守罪的主体是国家机关工作人员。A项构成不报、谎报安全事故罪（特殊罪名）；B项构成国有公司人员失职罪（特殊罪名）；C项构成环境监管失职罪（特殊罪名）。D项中丁作为国家机关工作人员，发现违法活动不予查处，致使国家和人民利益遭受重大损失，符合玩忽职守罪的构成要件，且无对应的特殊罪名。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 565}, {"num": 567, "batch": "专业基础知识", "type": "single", "stem": "下列关于贷款诈骗罪，说法正确的是（）", "options": [{"letter": "A", "text": "甲以欺骗手段骗取银行贷款，给银行造成重大损失，构成贷款诈骗罪"}, {"letter": "B", "text": "乙以牟利为目的套取银行信贷资金，转贷给某企业，从中赚取巨额利益，构成贷款诈骗罪"}, {"letter": "C", "text": "丙公司以非法占有为目的，编造虚假的项目骗取银行贷款，构成贷款诈骗罪"}, {"letter": "D", "text": "丁使用虚假的证明文件，骗取银行贷款后携款潜逃，构成贷款诈骗罪"}], "answer": "D", "explanation": "贷款诈骗罪的主体只能是自然人，单位不能构成贷款诈骗罪（C项错误）。A项缺少非法占有目的，可能构成骗取贷款罪而非贷款诈骗罪。B项属于高利转贷罪。D项丁使用虚假证明文件骗取贷款后携款潜逃，充分表明其具有非法占有目的，构成贷款诈骗罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 566}, {"num": 568, "batch": "专业基础知识", "type": "single", "stem": "个体工商户乙欠缴营业税15万元，当税务人员上门征收税款时，乙组织甲等多人进行暴力围攻，殴打税务人员，抗拒缴纳，其中甲出手最狠，将一名税务人员打成重伤。甲的行为构成（）", "options": [{"letter": "A", "text": "偷税罪"}, {"letter": "B", "text": "抗税罪"}, {"letter": "C", "text": "故意伤害罪"}, {"letter": "D", "text": "抗税罪与故意伤害罪实行并罚"}], "answer": "C", "explanation": "根据《刑法》第202条规定，以暴力、威胁方法拒不缴纳税款的构成抗税罪。但根据司法解释，抗税行为致人重伤或死亡的，应以故意伤害罪或故意杀人罪定罪处罚。本题中甲将税务人员打成重伤，已超出抗税罪的评价范围，应以故意伤害罪定罪处罚。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 567}, {"num": 569, "batch": "专业基础知识", "type": "single", "stem": "陈某在菜市场内为达到垄断鸡鸭销售的目的，以语言威胁的方式，从同一菜市场的摊贩杨某、张某手中以低价强行收购鸡鸭共500只，价值6000元，销售后非法获利3000元。陈某的行为构成（）", "options": [{"letter": "A", "text": "强迫交易罪"}, {"letter": "B", "text": "非法经营罪"}, {"letter": "C", "text": "违反治安管理行为"}, {"letter": "D", "text": "寻衅滋事罪"}], "answer": "A", "explanation": "根据《刑法》第226条规定，以暴力、威胁手段强买强卖商品，情节严重的，构成强迫交易罪。陈某以语言威胁方式低价强行收购他人鸡鸭，违背了交易对方的真实意愿，属于以威胁手段强买商品的强迫交易行为，构成强迫交易罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 568}, {"num": 570, "batch": "专业基础知识", "type": "single", "stem": "下列关于罪名认定，正确的是（）", "options": [{"letter": "A", "text": "甲用假币到电器商场购买手机，甲的行为构成诈骗罪"}, {"letter": "B", "text": "乙受王某之托将价值5万元的手表送给10公里外的朱某，乙在路上让许某捆绑自己，伪造了抢劫现场，将表据为己有。乙报案后，向警方说自己被抢。乙的行为构成侵占罪"}, {"letter": "C", "text": "丙假冒某部委名义，以组织某高层论坛为名发布广告、寄送材料，要求参会人员每人先邮寄会务费1万元。丙收款50万元后潜逃。丙的行为构成虚假广告罪"}, {"letter": "D", "text": "丁为孩子升学，买了一辆假冒某名牌的摩托车送给教育局长何某。丁的行为构成诈骗罪"}], "answer": "B", "explanation": "A项使用假币购物构成使用假币罪而非诈骗罪。B项乙将受托运送的手表据为己有并谎称被抢，属于将代为保管的他人财物非法占为己有，构成侵占罪，说法正确。C项丙假冒部委名义骗取钱财构成诈骗罪而非虚假广告罪。D项丁送假冒名牌不构成诈骗罪，可能构成行贿罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 569}, {"num": 571, "batch": "专业基础知识", "type": "single", "stem": "刘某在公交车上窃得乘客王某的银行信用卡和身份证，并用该身份证号码成功猜出了信用卡的密码，随后在短时间内大量透支消费达数万元。关于刘某的行为认定正确的是（）", "options": [{"letter": "A", "text": "构成妨害信用卡管理罪"}, {"letter": "B", "text": "构成信用卡诈骗罪"}, {"letter": "C", "text": "构成盗窃罪"}, {"letter": "D", "text": "构成盗窃罪和信用卡诈骗罪"}], "answer": "C", "explanation": "根据《刑法》第196条第3款规定，盗窃信用卡并使用的，依照盗窃罪定罪处罚。刘某在公交车上窃得王某的信用卡并使用，属于盗窃信用卡并使用的情形，应以盗窃罪定罪处罚，不再另行认定为信用卡诈骗罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 570}, {"num": 572, "batch": "专业基础知识", "type": "single", "stem": "张某在某市注册公司，其利用自己的公司从地税部门套购发票，采用“大头小尾”“阴阳票”“真票虚开”等犯罪手段虚开普通发票，以票面金额0.5%～1%不等的价格出售给刘某等人。张某共开具普通发票1000多份，虚开金额累计300多万元。张某的行为构成（）", "options": [{"letter": "A", "text": "非法出售发票罪"}, {"letter": "B", "text": "虚开发票罪"}, {"letter": "C", "text": "非法制造发票罪"}, {"letter": "D", "text": "逃税罪"}], "answer": "B", "explanation": "根据《刑法》第205条之一规定，虚开刑法第205条规定以外的其他发票（即增值税专用发票以外的普通发票），情节严重的，构成虚开发票罪。张某采用'大头小尾''阴阳票'等手段虚开普通发票1000多份，金额300多万元，属于虚开发票情节严重的行为，构成虚开发票罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 571}, {"num": 573, "batch": "专业基础知识", "type": "single", "stem": "某县地税局一分局干部丁某，到个体营运车辆户陈某家征收其上半年的2100元税款。陈某称经济上有困难，要求暂缓缴纳，并说税款由其在县城某公司工作的表兄范某担保缴纳。丁某遂与陈某于当日找到范某，范某表示，表弟陈某的税款由他担保缴纳，时间最长半个月，此事无需再找陈某。丁某信以为真。半个月后，范某未向地税机关缴纳分文税款。丁某于是找到范某，要求他履行纳税义务。范某当即表示自己不是纳税人，税务机关向他征税是错误的，并要丁某向其道歉。丁某遂与之发生争执，争执过程中，范某转身到附近一家餐馆拿出一把菜刀，朝丁某砍了1刀，致丁某轻伤。范某的行为构成（）", "options": [{"letter": "A", "text": "抗税罪"}, {"letter": "B", "text": "故意伤害罪"}, {"letter": "C", "text": "抗税罪和故意伤害罪数罪并罚"}, {"letter": "D", "text": "抗税罪和故意伤害罪从一重罪处罚"}], "answer": "B", "explanation": "范某并非纳税人或扣缴义务人，不符合抗税罪的主体要件。范某持刀将丁某砍成轻伤，属于以暴力手段侵害他人身体健康，构成故意伤害罪。抗税罪的主体必须是纳税人或扣缴义务人，范某作为担保人不具有该身份，其暴力行为应以故意伤害罪论处。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 572}, {"num": 574, "batch": "专业基础知识", "type": "single", "stem": "黄某与妻子关某长期感情不和，其在情妇的唆使下，图谋害死关某。黄某为关某投了巨额人身保险，人为地制造了一起关某意外死亡的保险事故并到保险公司领取了巨额理赔款，后案发被抓获。下列说法正确的是（）", "options": [{"letter": "A", "text": "黄某构成故意杀人罪"}, {"letter": "B", "text": "黄某构成保险诈骗罪"}, {"letter": "C", "text": "黄某构成故意杀人罪与保险诈骗罪，应择一重罪处罚"}, {"letter": "D", "text": "黄某构成故意杀人罪与保险诈骗罪，应数罪并罚"}], "answer": "D", "explanation": "根据《刑法》第198条第2款规定，投保人、受益人故意造成被保险人死亡、伤残或者疾病，骗取保险金的，同时构成故意杀人罪和保险诈骗罪，应当数罪并罚。黄某人为制造关某意外死亡的保险事故并骗取理赔款，构成故意杀人罪与保险诈骗罪，应数罪并罚。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 573}, {"num": 575, "batch": "专业基础知识", "type": "single", "stem": "个体工商户老王于10月和12月资助张三组织3次非法集会，次年再次资助张三组织非法集会。老王的行为构成（）", "options": [{"letter": "A", "text": "聚众扰乱公共场所秩序罪"}, {"letter": "B", "text": "聚众扰乱社会秩序罪"}, {"letter": "C", "text": "聚众冲击国家机关罪"}, {"letter": "D", "text": "资助非法聚集罪"}], "answer": "D", "explanation": "根据《刑法》第291条之一第2款规定，资助他人实施非法集会、聚众等活动的，构成资助非法聚集罪。老王在10月和12月资助张三组织3次非法集会，次年又再次资助，符合资助非法聚集罪的构成要件。该罪的成立要求有一定的频次或情节要求。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 574}, {"num": 576, "batch": "专业基础知识", "type": "single", "stem": "某公司老板甲从税务机关领购增值税专用发票后，将其中的26张先后卖给他人，后觉得来钱较快，故又购买了400张伪造的增值税专用发票并转手卖给他人。其行为构成（）", "options": [{"letter": "A", "text": "购买伪造的增值税专用发票罪"}, {"letter": "B", "text": "出售伪造的增值税专用发票罪、非法出售增值税专用发票罪数罪并罚"}, {"letter": "C", "text": "倒卖伪造的有价票证罪"}, {"letter": "D", "text": "非法出售发票罪"}], "answer": "B", "explanation": "甲将合法领购的26张增值税专用发票卖给他人，构成非法出售增值税专用发票罪。后又购买400张伪造的增值税专用发票并转卖，构成出售伪造的增值税专用发票罪。两罪侵犯不同法益，应数罪并罚。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 575}, {"num": 577, "batch": "专业基础知识", "type": "single", "stem": "李某将自己吸食后剩下的2克海洛因卖给赵某，赵某吸食完以后继续要李某提供毒品，李某因为没有毒品，无奈之下，就装了一包面粉谎称毒品卖给赵某，获得1万元现金。李某的行为应以（）定罪处罚。", "options": [{"letter": "A", "text": "诈骗罪和贩卖毒品罪"}, {"letter": "B", "text": "诈骗罪"}, {"letter": "C", "text": "欺骗他人吸毒罪"}, {"letter": "D", "text": "贩卖毒品罪"}], "answer": "A", "explanation": "李某将2克海洛因卖给赵某，构成贩卖毒品罪。之后李某以面粉冒充毒品卖给赵某获得1万元，赵某明知是毒品而购买但实际收到的不是毒品，李某此行为构成诈骗罪（以假充真骗取钱财）。两行为分别构成贩卖毒品罪和诈骗罪，应数罪并罚。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 576}, {"num": 578, "batch": "专业基础知识", "type": "single", "stem": "甲、乙通过丙向丁购买了毒品，甲购买的目的是自己吸食，乙购买的目的是贩卖，丙则通过介绍毒品买卖，从丁处获得一定的好处费。对于本案，下列说法错误的是（）", "options": [{"letter": "A", "text": "甲的行为构成贩卖毒品罪"}, {"letter": "B", "text": "乙的行为构成贩卖毒品罪"}, {"letter": "C", "text": "丙的行为构成贩卖毒品罪"}, {"letter": "D", "text": "丁的行为构成贩卖毒品罪"}], "answer": "A", "explanation": "根据相关司法解释，为自己吸食而购买毒品的，不构成贩卖毒品罪（数量达到标准的可构成非法持有毒品罪）。甲购买毒品目的是自己吸食，不构成贩卖毒品罪，A项说法错误。乙以贩卖为目的购买毒品构成贩卖毒品罪；丙介绍买卖获取好处费构成贩卖毒品罪的共犯；丁直接出售毒品构成贩卖毒品罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 577}, {"num": 579, "batch": "专业基础知识", "type": "single", "stem": "关于制毒物品犯罪，下列说法正确的是（）", "options": [{"letter": "A", "text": "李某违反国家规定，非法生产醋酸酐，情节较重，应予以行政处罚"}, {"letter": "B", "text": "张某违反国家规定，非法运输乙醚，情节特别严重，构成非法运输制毒物品罪"}, {"letter": "C", "text": "赵某违反国家规定，非法走私三氯甲烷，构成走私制毒物品罪"}, {"letter": "D", "text": "韩某违反国家规定，非法买卖麻黄素，情节严重，构成贩卖毒品罪"}], "answer": "B", "explanation": "根据《刑法》第350条规定，违反国家规定，非法生产、买卖、运输醋酸酐、乙醚等制毒物品的，构成非法生产、买卖、运输制毒物品罪。B项张某非法运输乙醚情节特别严重，构成非法运输制毒物品罪，说法正确。A项情节较重应构成犯罪而非仅行政处罚；C项应构成走私制毒物品罪而非走私罪；D项应构成非法买卖制毒物品罪而非贩卖毒品罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 578}, {"num": 580, "batch": "专业基础知识", "type": "single", "stem": "郑某为逃避检查，将尚未卖掉的10多克海洛因和贩毒所得赃款3万多元拿到朋友陈某处隐藏，陈某于当晚将毒品、赃款分别放置到另外一处房产中隐藏。陈某构成（）", "options": [{"letter": "A", "text": "非法持有毒品罪"}, {"letter": "B", "text": "掩饰、隐瞒犯罪所得、犯罪所得收益罪"}, {"letter": "C", "text": "窝藏、转移、隐瞒毒品、毒赃罪"}, {"letter": "D", "text": "包庇毒品犯罪分子罪"}], "answer": "C", "explanation": "根据《刑法》第349条规定，为走私、贩卖、运输、制造毒品的犯罪分子窝藏、转移、隐瞒毒品或者犯罪所得的财物的，构成窝藏、转移、隐瞒毒品、毒赃罪。陈某明知郑某的毒品和毒赃而帮助隐藏，符合该罪构成要件。该罪是毒品犯罪的特别规定，优先于一般的掩饰隐瞒犯罪所得罪适用。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 579}, {"num": 581, "batch": "专业基础知识", "type": "single", "stem": "下列对违法行为定性处理正确的是（）", "options": [{"letter": "A", "text": "刘某多次抢夺，数额不大。对其应给予治安管理处罚，实行数过并罚"}, {"letter": "B", "text": "李某是幼儿园老师，在工作中经常打骂、恐吓幼儿，但未致幼儿受伤。李某不构成犯罪，但应当给予行政处罚"}, {"letter": "C", "text": "陈某为实施诈骗，利用互联网发布大量信息，情节严重。对陈某应当追究刑事责任"}, {"letter": "D", "text": "彭某伪造了谢某向其借款200万元的借条，向人民法院起诉要求谢某还钱，人民法院判决予以支持。彭某的行为属于民事欺诈"}], "answer": "C", "explanation": "A项多次抢夺数额不大，多次抢夺可构成抢夺罪（刑法修正案八将'多次抢夺'入刑），并非仅治安处罚。B项虐待被监护、看护人罪要求情节恶劣，经常打骂恐吓可构成该罪。C项利用互联网发布诈骗信息情节严重，应以诈骗罪追究刑事责任，说法正确。D项彭某伪造借条提起虚假诉讼构成虚假诉讼罪，非民事欺诈。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 580}, {"num": 582, "batch": "专业基础知识", "type": "single", "stem": "刘某多次劝诱与其共同生活的弟弟吸食冰毒，均未得逞，后来刘某以不继续供给其上学费用相要挟，迫使其弟弟吸食冰毒数次，后刘某因吸食冰毒被公安机关教育处罚，刘某供述上述情况，其行为构成（）", "options": [{"letter": "A", "text": "强迫他人吸毒罪"}, {"letter": "B", "text": "容留他人吸毒罪"}, {"letter": "C", "text": "教唆他人吸毒罪"}, {"letter": "D", "text": "欺骗他人吸毒罪"}], "answer": "A", "explanation": "根据《刑法》第351条规定，强迫他人吸食、注射毒品的，构成强迫他人吸毒罪。刘某先劝诱未果，后以不供给上学费用相要挟，迫使弟弟吸食冰毒，属于以威胁方法强迫他人吸食毒品，构成强迫他人吸毒罪。劝诱阶段属于教唆，但以威胁手段迫使就范则升级为强迫。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 581}, {"num": 583, "batch": "专业基础知识", "type": "single", "stem": "张某家生活困难，张某为获取生活来源教唆其儿子卖血，儿子不从，张某对其儿子进行殴打，无奈之下，张某的儿子只好卖血养家。张某的行为（）", "options": [{"letter": "A", "text": "构成非法组织卖血罪"}, {"letter": "B", "text": "构成强迫卖血罪"}, {"letter": "C", "text": "不构成犯罪"}, {"letter": "D", "text": "适用《治安管理处罚法》进行处罚"}], "answer": "B", "explanation": "根据《刑法》第333条规定，以暴力、威胁方法强迫他人出卖血液的，构成强迫卖血罪。张某对儿子进行殴打，以暴力手段迫使儿子卖血，符合强迫卖血罪的构成要件。虽然双方为父子关系，但不影响犯罪成立。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 582}, {"num": 584, "batch": "专业基础知识", "type": "single", "stem": "刘某为组织邓某、黄某参加国外某恐怖组织，策划同邓某、黄某一同使用伪造的护照出境。刘某构成（）", "options": [{"letter": "A", "text": "偷越国（边）境罪"}, {"letter": "B", "text": "参加恐怖组织罪"}, {"letter": "C", "text": "组织他人偷越国（边）境罪"}, {"letter": "D", "text": "提供伪造的出入境证件罪"}], "answer": "A", "explanation": "刘某为组织他人参加国外恐怖组织，策划使用伪造护照出境。根据相关司法解释，以参加恐怖组织为目的组织他人偷越国境的，同时触犯偷越国（边）境罪和组织他人偷越国（边）境罪等罪名。本题中刘某的核心目的是组织出境参加恐怖组织，根据答案应认定为偷越国（边）境罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 583}, {"num": 585, "batch": "专业基础知识", "type": "single", "stem": "吐某拟加入某国恐怖活动组织，接受培训后再回国实施恐怖活动。某日，其持伪造的护照和某国签证偷越国境，被我边防人员当场抓获。吐某构成（）", "options": [{"letter": "A", "text": "参加恐怖组织罪"}, {"letter": "B", "text": "偷越国（边）境罪"}, {"letter": "C", "text": "非法出境的违法行为"}, {"letter": "D", "text": "准备实施恐怖活动罪"}], "answer": "B", "explanation": "吐某持伪造护照偷越国境被当场抓获，其直接行为是偷越国（边）境。虽然其目的是参加恐怖组织，但尚未实际加入，不构成参加恐怖组织罪。根据《刑法》第322条规定，违反国境管理法规偷越国（边）境的行为构成偷越国（边）境罪。准备实施恐怖活动罪要求有具体的准备行为，本题以偷越国境行为定罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 584}, {"num": 586, "batch": "专业基础知识", "type": "single", "stem": "王某初次持伪造的护照出境时被边检人员查获，对其应（）", "options": [{"letter": "A", "text": "按照偷越国（边）境罪定罪处罚"}, {"letter": "B", "text": "按照偷越国（边）境行为给予治安管理处罚"}, {"letter": "C", "text": "不予处罚"}, {"letter": "D", "text": "按照使用伪造证件行为给予治安管理处罚"}], "answer": "B", "explanation": "根据相关司法解释，偷越国（边）境'情节严重'的才构成犯罪，包括多次偷越、拉拢他人偷越等情形。王某初次持伪造护照出境，属于第一次偷越，尚未达到'情节严重'的程度，不构成偷越国（边）境罪，应按偷越国（边）境的违法行为给予治安管理处罚。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 585}, {"num": 587, "batch": "专业基础知识", "type": "single", "stem": "下列情形，如犯罪嫌疑人不能做出合理解释，也没有相反证据证明，可以认定毒品犯罪故意中“明知”的是（）", "options": [{"letter": "A", "text": "甲携带毒品经过海关，但以伪装手段逃避海关检查"}, {"letter": "B", "text": "乙被人举报，民警在其居住院落中查出毒品"}, {"letter": "C", "text": "丙在某KTV唱歌时，被查出其外衣口袋中藏有毒品，但未吸食"}, {"letter": "D", "text": "丁在机场通过安检时,被怀疑携带毒品,经对在旁边弃物桶中发现的毒品包装物上留下的指纹进行鉴定,其中有丁的指纹,但也有其他人的指纹"}], "answer": "A", "explanation": "根据《关于办理毒品犯罪案件适用法律若干问题的意见》，可以认定'明知'的情形包括：采用伪装手段逃避检查而携带毒品的。A项甲以伪装手段逃避海关检查携带毒品，可以认定其明知。B项在居住院落中查出毒品不能排除他人放置的可能；C项在KTV口袋中有毒品但未吸食，不能直接认定明知；D项指纹鉴定有多人指纹，不能确定系丁所留。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 586}, {"num": 588, "batch": "专业基础知识", "type": "single", "stem": "李某认为在互联网上收费下载淫秽信息很赚钱，便利用互联网传播淫秽图片170张、淫秽电影12部，但截至被抓获时尚未挣到钱。李某的行为构成（）", "options": [{"letter": "A", "text": "传播淫秽物品罪"}, {"letter": "B", "text": "传播淫秽物品牟利罪"}, {"letter": "C", "text": "传播淫秽信息的违反治安管理行为"}, {"letter": "D", "text": "组织播放淫秽音像制品罪"}], "answer": "B", "explanation": "根据《刑法》第363条规定，以牟利为目的，制作、复制、出版、贩卖、传播淫秽物品的，构成制作、复制、出版、贩卖、传播淫秽物品牟利罪。李某以赚钱为目的在互联网上传播淫秽图片和电影，虽尚未获利，但其主观上具有牟利目的，客观上实施了传播行为，构成传播淫秽物品牟利罪。牟利目的不要求实际获利。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 587}, {"num": 589, "batch": "专业基础知识", "type": "single", "stem": "丁系某公安局民警，长期参与赌博，由于贾某欠其赌债未还，丁虚构贾某涉嫌盗窃，办理立案手续后抓获贾某，并打电话给贾某亲属，要求其送钱换人。丁的行为构成（）", "options": [{"letter": "A", "text": "诬告陷害罪"}, {"letter": "B", "text": "徇私枉法罪"}, {"letter": "C", "text": "敲诈勒索罪"}, {"letter": "D", "text": "滥用职权罪"}], "answer": "D", "explanation": "丁利用公安民警的职务便利，虚构贾某涉嫌盗窃的事实办理立案手续，以此要挟贾某亲属送钱换人。丁的行为属于利用职权非法拘禁他人并勒索财物。根据相关司法解释，国家机关工作人员利用职权非法拘禁他人并勒索财物的，以滥用职权罪和敲诈勒索罪等从一重处罚。本题以滥用职权罪论处。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 588}, {"num": 590, "batch": "专业基础知识", "type": "single", "stem": "王某系某公安派出所户籍民警，受朋友委托，采取伪造公民地址，编写迁入地区号段的身份证编号等手段，为不符合落户条件的8名外市户籍人员办理了本市户籍。王某构成（）", "options": [{"letter": "A", "text": "徇私枉法罪"}, {"letter": "B", "text": "玩忽职守罪"}, {"letter": "C", "text": "滥用职权罪"}, {"letter": "D", "text": "伪造国家机关公文、证件罪"}], "answer": "C", "explanation": "根据《刑法》第397条规定，国家机关工作人员滥用职权，致使公共财产、国家和人民利益遭受重大损失的，构成滥用职权罪。王某作为户籍民警，利用职务便利为不符合条件的人员违规办理户籍，属于超越职权范围的滥用职权行为，构成滥用职权罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 589}, {"num": 591, "batch": "专业基础知识", "type": "single", "stem": "下列行为应以玩忽职守罪论处的是（）", "options": [{"letter": "A", "text": "法官执行判决时严重不负责任，因未履行法定执行职责，致当事人利益遭受重大损失"}, {"letter": "B", "text": "检察官讯问犯罪嫌疑人甲，甲要求上厕所，因检察官违规打开械具后未跟随，致甲在厕所翻窗逃跑"}, {"letter": "C", "text": "值班警察与女友电话聊天时接到杀人报警，又闲聊10分钟后才赶往现场，因延迟出警，致被害人被杀、歹徒逃走"}, {"letter": "D", "text": "市政府基建负责人因听信朋友介绍，未经审查便与对方签订建楼合同，致被骗300万元"}], "answer": "C", "explanation": "A项法官构成执行判决、裁定失职罪（特殊罪名）；B项检察官构成失职致使在押人员脱逃罪（特殊罪名）；C项值班警察因私人电话聊天延误出警，属于严重不负责任不履行工作职责，致使被害人死亡、歹徒逃走，造成重大损失，构成玩忽职守罪；D项构成国家机关工作人员签订、履行合同失职被骗罪。C项符合玩忽职守罪的一般构成要件。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 590}, {"num": 592, "batch": "专业基础知识", "type": "single", "stem": "某群众在马路上捡到一个钱包（内有人民币23000元），送交值勤民警寻找失主。民警寻找失主未果，乘机据为己有。民警的行为构成（）", "options": [{"letter": "A", "text": "诈骗罪"}, {"letter": "B", "text": "贪污罪"}, {"letter": "C", "text": "侵占罪"}, {"letter": "D", "text": "职务侵占罪"}], "answer": "B", "explanation": "群众将捡到的钱包送交民警寻找失主，该钱包因群众的上交行为而处于公安机关的管理之下，属于公共财产。民警利用职务之便将管理中的公共财物据为己有，根据《刑法》第382条规定，国家工作人员利用职务上的便利侵吞公共财物的构成贪污罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 591}, {"num": 593, "batch": "专业基础知识", "type": "single", "stem": "关于对贩卖毒品的居间介绍者，下列说法错误的是（）", "options": [{"letter": "A", "text": "甲受贩毒者委托，为其介绍联络购毒者，甲与贩毒者构成贩卖毒品罪的共同犯罪"}, {"letter": "B", "text": "乙明知购毒者以贩卖为目的购买毒品，受委托为其介绍联络贩毒者，乙与购毒者构成贩卖毒品罪的共同犯罪"}, {"letter": "C", "text": "丙同时与贩毒者、购毒者共谋，联络促成双方交易，其与购毒者构成贩卖毒品罪的共同犯罪"}, {"letter": "D", "text": "丁实施为毒品交易主体提供交易信息、介绍交易对象等帮助行为，对促成交易起次要、辅助作用的，应当认定为从犯"}], "answer": "C", "explanation": "根据《全国部分法院审理毒品犯罪案件工作座谈会纪要》，居间介绍者的定性：受贩毒者委托介绍购毒者的，与贩毒者构成共犯（A正确）；明知购毒者以贩卖为目的购毒，受委托介绍贩毒者的，与购毒者构成共犯（B正确）；同时与贩毒者和购毒者共谋促成交易的，应与贩毒者构成共犯而非与购毒者，C项表述错误；起辅助作用的认定为从犯（D正确）。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 592}, {"num": 594, "batch": "专业基础知识", "type": "single", "stem": "王某冒充某军事学院的军官，向某中学高三学生家长谎称能帮助该生进入该校，共骗取学生家长人民币1万元。王某的行为构成（）", "options": [{"letter": "A", "text": "接送不合格兵员罪"}, {"letter": "B", "text": "冒充军人招摇撞骗罪"}, {"letter": "C", "text": "招摇撞骗罪"}, {"letter": "D", "text": "诈骗罪"}], "answer": "B", "explanation": "根据《刑法》第372条规定，冒充军人招摇撞骗的，构成冒充军人招摇撞骗罪。王某冒充军事学院军官骗取学生家长1万元，属于冒充军人进行招摇撞骗的行为。冒充军人招摇撞骗罪是招摇撞骗罪的特别规定，应优先适用。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 593}, {"num": 595, "batch": "专业基础知识", "type": "single", "stem": "刘某为牟利，将单位让自己管理的麻醉药品、精神药品高价卖给吸食毒品的钟某，所得据为己有。刘某的行为构成（）", "options": [{"letter": "A", "text": "非法提供麻醉药品、精神药品罪"}, {"letter": "B", "text": "贩卖毒品罪"}, {"letter": "C", "text": "容留他人吸毒罪"}, {"letter": "D", "text": "职务侵占罪"}], "answer": "B", "explanation": "根据《刑法》第355条规定，依法从事生产、运输、管理、使用国家管制的麻醉药品、精神药品的人员，向吸食、注射毒品的人提供国家管制的麻醉药品、精神药品的，构成非法提供麻醉药品、精神药品罪。但以牟利为目的向吸毒者提供的，依照贩卖毒品罪定罪处罚。刘某以牟利为目的高价卖给吸毒者，构成贩卖毒品罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 594}, {"num": 596, "batch": "专业基础知识", "type": "single", "stem": "李某强迫蒋某卖淫。蒋某在从事卖淫时伺机逃走，某晚从七楼房间窗户逃走时被李某追赶，不慎从雨篷上掉下去摔死。李某的行为构成（）", "options": [{"letter": "A", "text": "故意杀人罪"}, {"letter": "B", "text": "强迫卖淫罪"}, {"letter": "C", "text": "过失致人死亡罪"}, {"letter": "D", "text": "强迫卖淫罪和过失致人死亡罪"}], "answer": "B", "explanation": "根据《刑法》第358条规定，强迫他人卖淫的构成强迫卖淫罪，造成被强迫卖淫的人重伤、死亡等严重后果的属于结果加重犯。蒋某在从事卖淫期间伺机逃走，因被追赶不慎摔死，该死亡结果与强迫卖淫行为之间存在因果关系，属于强迫卖淫造成被强迫卖淫的人死亡的加重情形，以强迫卖淫罪一罪论处。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 595}, {"num": 597, "batch": "专业基础知识", "type": "single", "stem": "李某制作、复制大量淫秽光盘，除出售外，还多次将淫秽光盘借给多人观看。对其行为应（）", "options": [{"letter": "A", "text": "以制作、复制、贩卖、传播淫秽物品牟利罪处罚"}, {"letter": "B", "text": "以组织播放淫秽音像制品罪从重处罚"}, {"letter": "C", "text": "以制作、复制、贩卖淫秽物品牟利罪和传播淫秽物品罪数罪并罚"}, {"letter": "D", "text": "以传播淫秽物品罪从重处罚"}], "answer": "C", "explanation": "李某以牟利为目的制作、复制并出售淫秽光盘，构成制作、复制、贩卖淫秽物品牟利罪。同时李某多次将淫秽光盘借给多人观看，该行为不以牟利为目的，构成传播淫秽物品罪。两个行为分别触犯不同罪名，应数罪并罚。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 596}, {"num": 598, "batch": "专业基础知识", "type": "single", "stem": "钱某为牟利，制作了200多张淫秽影碟出售，还组织其4个好友免费观看30余次。对钱某的行为应当（）", "options": [{"letter": "A", "text": "以制作、贩卖淫秽物品牟利罪与组织播放淫秽音像制品罪数罪并罚"}, {"letter": "B", "text": "以贩卖淫秽物品牟利罪和组织播放淫秽音像制品罪数罪并罚"}, {"letter": "C", "text": "以制作、贩卖淫秽物品牟利罪与组织播放淫秽音像制品罪择一重罪处罚"}, {"letter": "D", "text": "以制作、贩卖淫秽物品牟利罪和传播淫秽物品罪数罪并罚"}], "answer": "A", "explanation": "钱某以牟利为目的制作200多张淫秽影碟出售，构成制作、贩卖淫秽物品牟利罪。同时组织4名好友免费观看30余次，根据《刑法》第364条第2款规定，组织播放淫秽音像制品的构成组织播放淫秽音像制品罪。两行为分别构成不同犯罪，应数罪并罚。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 597}, {"num": 599, "batch": "专业基础知识", "type": "single", "stem": "下列人员不构成容留他人吸毒罪的是（）", "options": [{"letter": "A", "text": "甲到某宾馆开房后，邀请了3名朋友一起在该房间内吸食毒品"}, {"letter": "B", "text": "乙和张某关系很好，因此对张某多次在自己家里吸毒装作不知道"}, {"letter": "C", "text": "丙因容留吴某吸毒被公安机关行政拘留后再次容留卫某吸毒"}, {"letter": "D", "text": "丁为4名吸毒人员在某娱乐场所吸毒提供器具"}], "answer": "D", "explanation": "容留他人吸毒罪是指为他人吸食、注射毒品提供场所的行为。A项在宾馆开房邀请朋友吸毒，提供了场所；B项在自己家中默许他人吸毒，提供了场所；C项再次容留他人吸毒，提供了场所。D项丁仅为吸毒人员提供器具而未提供场所，不符合容留他人吸毒罪'提供场所'的构成要件。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 598}, {"num": 600, "batch": "专业基础知识", "type": "single", "stem": "刘某以牟利为目的，意欲运送他人偷越国（边）境，但由于交通工具简陋，不具备必要的安全条件，导致被运送人多人重伤、死亡的后果。对于刘某的行为，下列说法正确的是（）", "options": [{"letter": "A", "text": "按运送他人偷越国（边）境罪处罚"}, {"letter": "B", "text": "按运送他人偷越国（边）境罪与过失致人死亡罪、过失致人重伤罪数罪并罚"}, {"letter": "C", "text": "在运送他人偷越国（边）境罪与过失致人死亡罪、过失致人重伤罪中择一重罪处罚"}, {"letter": "D", "text": "按过失致人死亡罪与过失致人重伤罪数罪并罚"}], "answer": "A", "explanation": "根据《刑法》第321条第2款规定，在运送他人偷越国（边）境中造成被运送人重伤、死亡的，属于运送他人偷越国（边）境罪的结果加重犯，处七年以上有期徒刑，并处罚金。该条款将造成被运送人重伤、死亡作为本罪的加重情节，不再另行以过失致人重伤罪、过失致人死亡罪定罪处罚，按运送他人偷越国（边）境罪一罪处罚。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 599}, {"num": 601, "batch": "专业基础知识", "type": "single", "stem": "张某冒充军人使用伪造的武装部队车辆号牌，造成恶劣影响，应当依照（）的规定定罪处罚。", "options": [{"letter": "A", "text": "冒充军人招摇撞骗罪"}, {"letter": "B", "text": "诈骗罪"}, {"letter": "C", "text": "招摇撞骗罪"}, {"letter": "D", "text": "非法使用军用标志罪"}], "answer": "A", "explanation": "根据《刑法》第372条规定，冒充军人招摇撞骗罪是指冒充军人招摇撞骗的行为。张某冒充军人使用伪造的武装部队车辆号牌，造成恶劣影响，符合冒充军人招摇撞骗罪的构成要件。虽然该行为也涉及非法使用军用标志，但冒充军人招摇撞骗罪更能全面评价其行为性质，依照特别规定定罪处罚。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 600}, {"num": 602, "batch": "专业基础知识", "type": "single", "stem": "赵某组织一批人员成立“飞鹰帮”，通过暴力手段打击竞争对手，长期垄断当地建材、物流等行业，攫取非法利益。市公安局局长陆某与赵某关系良好，不仅多次帮其压下群众举报，还在上级公安机关对赵某进行打击时通风报信。陆某的行为构成（）", "options": [{"letter": "A", "text": "包庇罪"}, {"letter": "B", "text": "包庇、纵容黑社会性质组织罪"}, {"letter": "C", "text": "帮助犯罪分子逃避处罚罪"}, {"letter": "D", "text": "玩忽职守罪"}], "answer": "B", "explanation": "根据《刑法》第294条第3款规定，国家机关工作人员包庇、纵容黑社会性质组织的，构成包庇、纵容黑社会性质组织罪。陆某作为市公安局局长，属于国家机关工作人员，其帮助赵某压下举报、通风报信的行为，符合包庇、纵容黑社会性质组织罪的构成要件，而非一般的包庇罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 601}, {"num": 603, "batch": "专业基础知识", "type": "single", "stem": "唐某利用熟悉地形的条件，驾船运送秦某等人偷越国境，但由于船只经不起风浪失事，秦某落水淹死，则对唐某（）", "options": [{"letter": "A", "text": "应按照运送他人偷越国（边）境罪和故意杀人罪数罪并罚"}, {"letter": "B", "text": "应按照运送他人偷越国（边）境罪和过失致人死亡罪数罪并罚"}, {"letter": "C", "text": "应按照运送他人偷越国（边）境罪定罪处罚，致人死亡是法定从重情节"}, {"letter": "D", "text": "应在运送他人偷越国（边）境罪和过失致人死亡罪中择一重罪处罚"}], "answer": "C", "explanation": "根据《刑法》第321条第2款规定，运送他人偷越国（边）境，对被运送人有杀害、伤害、强奸、拐卖等犯罪行为，或者对检查人员有杀害、伤害等犯罪行为的，依照数罪并罚的规定处罚。但该条同时规定，运送他人偷越国（边）境造成被运送人重伤、死亡的，属于运送他人偷越国（边）境罪的加重情节。唐某运送他人偷越国境过程中因船只失事致秦某死亡，属于该罪的加重结果，应以运送他人偷越国（边）境罪一罪定罪处罚，致人死亡是法定从重情节。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 602}, {"num": 604, "batch": "专业基础知识", "type": "single", "stem": "许某明知弟弟犯了强奸罪，不仅没向公安机关报案，反而在公安机关抓捕时，给其2000元路费，让其逃跑。许某的行为（）", "options": [{"letter": "A", "text": "构成包庇罪"}, {"letter": "B", "text": "构成窝藏罪"}, {"letter": "C", "text": "构成妨害公务罪"}, {"letter": "D", "text": "不构成犯罪"}], "answer": "B", "explanation": "根据《刑法》第310条规定，窝藏罪是指明知是犯罪的人而为其提供隐藏处所、财物，帮助其逃匿的行为。许某明知弟弟犯了强奸罪，给其2000元路费让其逃跑，属于为犯罪的人提供财物帮助其逃匿，构成窝藏罪。包庇罪侧重于作假证明予以掩盖，而本案是提供财物帮助逃跑，应认定为窝藏罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 603}, {"num": 605, "batch": "专业基础知识", "type": "single", "stem": "甲殴打乙致其轻微伤。乙在住院期间通过丙找到医生丁，要求其扩大自己伤口的长度，并伪造了病历，因而导致乙的法医鉴定为轻伤，后甲被公安机关刑事拘留，几日后，经公安机关侦查查明事实真相。丁构成（）", "options": [{"letter": "A", "text": "伪证罪"}, {"letter": "B", "text": "包庇罪"}, {"letter": "C", "text": "帮助伪造证据罪"}, {"letter": "D", "text": "妨害作证罪"}], "answer": "C", "explanation": "根据《刑法》第307条第2款规定，帮助当事人毁灭、伪造证据，情节严重的，构成帮助伪造证据罪。医生丁在乙的要求下扩大伤口长度并伪造病历，导致法医鉴定结果失真，属于帮助当事人伪造证据的行为，构成帮助伪造证据罪。伪证罪的主体是刑事诉讼中的证人、鉴定人等，丁不符合该主体要件。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 604}, {"num": 606, "batch": "专业基础知识", "type": "single", "stem": "律师甲在代理一起民事诉讼案件时，编造了1份对自己代理的一方当事人有利的虚假证言，指使证人李某背熟以后向法庭陈述，致使本该败诉的己方当事人因此而胜诉。甲的行为构成（）", "options": [{"letter": "A", "text": "伪证罪"}, {"letter": "B", "text": "妨害作证罪"}, {"letter": "C", "text": "诉讼代理人妨害作证罪"}, {"letter": "D", "text": "帮助伪造证据罪"}], "answer": "B", "explanation": "根据《刑法》第307条第1款规定，以暴力、威胁、贿买等方法阻止证人作证或者指使他人作伪证的，构成妨害作证罪。律师甲编造虚假证言并指使证人李某向法庭陈述，属于指使他人作伪证的行为。由于本案是民事诉讼而非刑事诉讼，不构成辩护人、诉讼代理人妨害作证罪（该罪仅适用于刑事诉讼），应以妨害作证罪定罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 605}, {"num": 607, "batch": "专业基础知识", "type": "single", "stem": "辩护人杜某在刑事诉讼过程中指使他人对与案件有重大关系的事实作伪证。杜某的行为构成（）", "options": [{"letter": "A", "text": "伪证罪"}, {"letter": "B", "text": "妨害作证罪"}, {"letter": "C", "text": "辩护人妨害作证罪"}, {"letter": "D", "text": "帮助毁灭、伪造证据罪"}], "answer": "C", "explanation": "根据《刑法》第306条规定，在刑事诉讼中，辩护人毁灭、伪造证据，帮助当事人毁灭、伪造证据，威胁、引诱证人违背事实改变证言或者作伪证的，构成辩护人妨害作证罪。杜某作为辩护人，在刑事诉讼中指使他人作伪证，符合该罪的特殊主体和客观要件，应以辩护人妨害作证罪定罪处罚。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 606}, {"num": 608, "batch": "专业基础知识", "type": "single", "stem": "下列行为构成赌博罪的有（）", "options": [{"letter": "A", "text": "村民老李见商店生意不好，就买了桌子、凳子，让别人在他那里打牌娱乐，自己收取费用，每年因此收入3000多元"}, {"letter": "B", "text": "退休工人老李经常约老王、老张一起打牌，每次都赌钱，赌资数十元到数百元不等"}, {"letter": "C", "text": "在朝鲜做生意的张某明知某镇镇长经常到朝鲜赌博，携带现金不便，便提供账户供其使用。该镇长利用其在朝鲜的银行账户带去赌资100多万元"}, {"letter": "D", "text": "某厂厂长见厂里经营不善，便私自发行彩票，允诺中大奖可得10万元，获利100多万元，用于发放职工奖金"}], "answer": "C", "explanation": "根据《刑法》第303条规定，赌博罪包括以赌博为业和聚众赌博两种情形。C项中张某明知镇长在朝鲜赌博，仍提供账户供其使用，赌资达100多万元，属于为赌博提供直接帮助，以赌博罪论处。A项老李属于正常提供娱乐场所收取费用，B项属于一般娱乐活动，D项私自发行彩票属于非法经营行为，均不构成赌博罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 607}, {"num": 609, "batch": "专业基础知识", "type": "single", "stem": "某处长酒后驾车撞死他人后，找到司机甲，要甲为自己顶罪，甲念处长平时对自己的关照，便前往司法机关“投案自首”。甲的行为（）", "options": [{"letter": "A", "text": "构成交通肇事罪的共犯"}, {"letter": "B", "text": "构成伪证罪"}, {"letter": "C", "text": "构成包庇罪"}, {"letter": "D", "text": "构成窝藏罪"}], "answer": "C", "explanation": "根据《刑法》第310条规定，窝藏、包庇罪是指明知是犯罪的人而为其提供隐藏处所、财物，帮助其逃匿或者作假证明包庇的行为。甲明知某处长是交通肇事犯罪的人，却前往司法机关'投案自首'为其顶罪，属于作假证明包庇犯罪人的行为，构成包庇罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 608}, {"num": 610, "batch": "专业基础知识", "type": "single", "stem": "下列行为不构成赌博罪的是（）", "options": [{"letter": "A", "text": "导游钱某为获取非法利益，组织张某、王某等9人前往缅甸一赌场赌博，收取赌场介绍费4000元"}, {"letter": "B", "text": "赵某为获取非法利益，组织周某等6人进行赌博，从中获利8000元"}, {"letter": "C", "text": "刘某组织李某等4人赌博，赌资数额达到6万元"}, {"letter": "D", "text": "孙某为获取非法利益，组织陈某等20人进行赌博"}], "answer": "A", "explanation": "根据《刑法》第303条及相关司法解释，聚众赌博要求组织3人以上赌博且达到一定规模。A项中钱某组织9人前往缅甸赌场赌博并收取介绍费，属于为境外赌场招揽赌客，根据相关司法解释，不构成赌博罪（该行为可能构成开设赌场的共犯，但在本题选项中，A项行为按照相关司法解释不认定为赌博罪）。B、C、D项均符合聚众赌博的构成要件。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 609}, {"num": 611, "batch": "专业基础知识", "type": "single", "stem": "下列行为构成窝藏罪的是（）", "options": [{"letter": "A", "text": "甲明知其亲戚王某盗得大量文物，而提供自家地窖藏匿王某盗窃来的文物"}, {"letter": "B", "text": "乙与抢劫犯通谋，商定待抢劫得手后，为抢劫犯提供偷渡外逃的机会"}, {"letter": "C", "text": "丙在公安机关抓捕逃犯时，为开玩笑，故意为公安人员指了一条与逃犯逃跑方向相反的路径"}, {"letter": "D", "text": "丁明知徐某为抢劫犯，而提供金钱供其逃窜"}], "answer": "D", "explanation": "根据《刑法》第310条规定，窝藏罪是指明知是犯罪的人而为其提供隐藏处所、财物，帮助其逃匿的行为。D项中丁明知徐某为抢劫犯，而提供金钱供其逃窜，属于为犯罪人提供财物帮助逃匿，构成窝藏罪。A项藏匿的是赃物而非犯罪人本人；B项属于事前通谋，构成抢劫罪共犯；C项虽为公安人员指错路，但缺乏窝藏罪的主观故意。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 610}, {"num": 612, "batch": "专业基础知识", "type": "single", "stem": "乘客甲在乘坐国内一航班时，在飞机起飞之前，和机场工作人员发生纠纷，为发泄愤怒，谎称已在随机托运的行李中放置了爆炸装置，机场工作人员紧急处置，造成多架航班晚点，大量旅客滞留。甲的行为（）", "options": [{"letter": "A", "text": "不构成犯罪"}, {"letter": "B", "text": "构成编造虚假信息罪"}, {"letter": "C", "text": "构成故意伤害罪"}, {"letter": "D", "text": "构成危害公共安全罪"}], "answer": "B", "explanation": "根据《刑法》第291条之一第1款规定，编造爆炸威胁、生化威胁、放射威胁等恐怖信息，或者明知是编造的恐怖信息而故意传播，严重扰乱社会秩序的，构成编造、故意传播虚假恐怖信息罪（编造虚假信息罪）。甲谎称在行李中放置了爆炸装置，造成多架航班晚点、大量旅客滞留，严重扰乱社会秩序，构成编造虚假信息罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 611}, {"num": 613, "batch": "专业基础知识", "type": "single", "stem": "某日，王某在网上发帖，声称自己在本市取水源投入30斤“毒鼠强”，并配有投放照片。在发帖后造成市民的严重恐慌。后经证实，王某投放的是淀粉，并非“毒鼠强”。对王某的行为，应当（）", "options": [{"letter": "A", "text": "以投放危险物质罪追究刑事责任"}, {"letter": "B", "text": "以投放虚假危险物质罪追究刑事责任"}, {"letter": "C", "text": "以编造、故意传播虚假信息罪追究刑事责任"}, {"letter": "D", "text": "以寻衅滋事罪追究刑事责任"}], "answer": "B", "explanation": "根据《刑法》第291条之一第2款规定，投放虚假的爆炸性、毒害性、放射性、传染病病原体等物质，或者编造爆炸威胁、生化威胁、放射威胁等恐怖信息，或者明知是编造的恐怖信息而故意传播，严重扰乱社会秩序的，构成投放虚假危险物质罪或编造、故意传播虚假信息罪。王某实际投放的是淀粉而非毒鼠强，属于投放虚假的危险物质，造成市民严重恐慌，应以投放虚假危险物质罪追究刑事责任。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 612}, {"num": 614, "batch": "专业基础知识", "type": "single", "stem": "甲出于报复目的，在公共场所对一些无辜群众注射了生理盐水，谎称是艾滋病病毒，引起被害人和周围群众极度恐慌，严重扰乱社会秩序。甲的行为（）", "options": [{"letter": "A", "text": "不构成犯罪"}, {"letter": "B", "text": "构成投放虚假危险物质罪"}, {"letter": "C", "text": "构成故意伤害罪"}, {"letter": "D", "text": "构成以危险方法危害公共安全罪"}], "answer": "B", "explanation": "根据《刑法》第291条之一规定，投放虚假的爆炸性、毒害性、放射性、传染病病原体等物质，严重扰乱社会秩序的，构成投放虚假危险物质罪。甲在公共场所向无辜群众注射生理盐水并谎称是艾滋病病毒，生理盐水属于虚假的危险物质，引起极度恐慌并严重扰乱社会秩序，构成投放虚假危险物质罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 613}, {"num": 615, "batch": "专业基础知识", "type": "single", "stem": "某外贸进出口公司出口商品获得780万美元外汇收入，在法定代表人张某的指使下，该公司将全部款项存入中国某银行美国纽约分行账户。对于该种行为，下列说法正确的是（）", "options": [{"letter": "A", "text": "张某构成逃税罪"}, {"letter": "B", "text": "张某构成骗取出口退税罪"}, {"letter": "C", "text": "该公司构成逃汇罪"}, {"letter": "D", "text": "张某构成骗购外汇罪"}], "answer": "C", "explanation": "根据《刑法》第190条规定，公司、企业或者其他单位，违反国家规定，擅自将外汇存放在境外，或者将境内的外汇非法转移到境外，数额较大的，构成逃汇罪。该外贸公司将780万美元外汇收入全部存入境外账户，属于将外汇擅自存放在境外的行为，构成逃汇罪，犯罪主体是该公司。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 614}, {"num": 616, "batch": "专业基础知识", "type": "single", "stem": "甲长期以赌博所得为主要生活来源。某日，甲抢劫乙的赌资，得逞后，为防止乙日后报案，将其杀死。对甲的处理，下列说法正确的是（）", "options": [{"letter": "A", "text": "应以赌博罪、抢劫罪并罚"}, {"letter": "B", "text": "应以赌博罪、抢劫罪、故意杀人罪并罚"}, {"letter": "C", "text": "应以故意杀人罪、抢劫罪并罚"}, {"letter": "D", "text": "应以抢劫罪从重处罚"}], "answer": "B", "explanation": "甲长期以赌博为业，构成赌博罪；甲抢劫乙的赌资，构成抢劫罪（赌资也可以成为抢劫罪的对象）；抢劫后为防止乙报案将其杀死，属于另起犯意实施故意杀人，构成故意杀人罪。三罪之间相互独立，应以赌博罪、抢劫罪、故意杀人罪数罪并罚。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 615}, {"num": 617, "batch": "专业基础知识", "type": "single", "stem": "15岁的周某将盗窃来的2台电脑（价值8000元）拿回家中。其父明知是周某盗窃来的赃物，在公安机关侦查时，将赃物拿到后山掩埋起来。周父的行为（）", "options": [{"letter": "A", "text": "构成掩饰、隐瞒犯罪所得罪"}, {"letter": "B", "text": "构成包庇罪"}, {"letter": "C", "text": "构成妨害公务罪"}, {"letter": "D", "text": "不构成犯罪"}], "answer": "A", "explanation": "根据《刑法》第312条规定，明知是犯罪所得及其产生的收益而予以窝藏、转移、收购、代为销售或者以其他方法掩饰、隐瞒的，构成掩饰、隐瞒犯罪所得罪。15岁的周某盗窃电脑属于犯罪所得（虽然周某未达盗窃罪刑事责任年龄，但赃物性质不变），其父明知是盗窃所得而掩埋赃物，构成掩饰、隐瞒犯罪所得罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 616}, {"num": 618, "batch": "专业基础知识", "type": "single", "stem": "李某在运送刘某偷越国境过程中，对刘某进行殴打致其重伤。对于李某的行为，下列说法正确的是（）", "options": [{"letter": "A", "text": "应按照运送他人偷越国（边）境罪从重处罚"}, {"letter": "B", "text": "应按照运送他人偷越国（边）境罪和故意伤害罪数罪并罚"}, {"letter": "C", "text": "应在运送他人偷越国（边）境罪和故意伤害罪中择一重罪定罪处罚"}, {"letter": "D", "text": "应按照故意伤害罪从重处罚"}], "answer": "B", "explanation": "根据《刑法》第321条第2款规定，运送他人偷越国（边）境，对被运送人有杀害、伤害、强奸、拐卖等犯罪行为，或者对检查人员有杀害、伤害等犯罪行为的，依照数罪并罚的规定处罚。李某在运送刘某偷越国境过程中殴打刘某致其重伤，属于对被运送人实施伤害行为，应以运送他人偷越国（边）境罪和故意伤害罪数罪并罚。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 617}, {"num": 619, "batch": "专业基础知识", "type": "single", "stem": "刘某（怀有3个月身孕）为使21名中国公民偷渡至境外打工，为上述人员提供了伪造的外国签证，并收取每人5万元好处费。对于刘某的行为，下列说法正确的是（）", "options": [{"letter": "A", "text": "构成提供伪造、变造的出入境证件罪，因情节严重不得取保候审"}, {"letter": "B", "text": "构成提供伪造、变造的出入境证件罪，可以取保候审"}, {"letter": "C", "text": "构成出售出入境证件罪，因情节严重不得取保候审"}, {"letter": "D", "text": "构成出售出入境证件罪，可以取保候审"}], "answer": "B", "explanation": "根据《刑法》第420条及相关规定，为他人提供伪造、变造的出入境证件的，构成提供伪造、变造的出入境证件罪。刘某为21人提供伪造的外国签证，构成该罪。根据《刑事诉讼法》第67条规定，怀孕或者正在哺乳自己婴儿的妇女，可以取保候审。刘某怀有3个月身孕，符合取保候审条件，可以取保候审。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 618}, {"num": 620, "batch": "专业基础知识", "type": "single", "stem": "刘某拉拢张某（女）等十余人偷越国（边）境，后因张某反悔，刘某将张某强奸。在偷越国（边）境过程中被公安机关抓获。下列说法正确的是（）", "options": [{"letter": "A", "text": "刘某构成组织他人偷越国（边）境罪（未遂）"}, {"letter": "B", "text": "刘某构成偷越国（边）境罪（未遂）"}, {"letter": "C", "text": "刘某构成强奸罪和组织他人偷越国（边）境罪（未遂）"}, {"letter": "D", "text": "刘某构成运送他人偷越国（边）境罪（未遂）"}], "answer": "C", "explanation": "刘某拉拢组织十余人偷越国（边）境，构成组织他人偷越国（边）境罪，在被抓获前尚未完成偷越，属于犯罪未遂。刘某在组织过程中强奸张某，属于另起犯意，构成强奸罪。强奸罪与组织他人偷越国（边）境罪（未遂）应当数罪并罚。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 619}, {"num": 621, "batch": "专业基础知识", "type": "single", "stem": "甲组织他人偷渡，在带领偷渡人员通过边检时被工作人员怀疑，后甲暴力抗拒检查并将一名边检工作人员刺成重伤。下列说法正确的是（）", "options": [{"letter": "A", "text": "甲构成组织他人偷越国（边）境罪，从重处罚"}, {"letter": "B", "text": "甲构成妨害公务罪，从重处罚"}, {"letter": "C", "text": "甲构成故意伤害罪，从重处罚"}, {"letter": "D", "text": "甲同时构成故意伤害罪和组织他人偷越国（边）境罪，数罪并罚"}], "answer": "D", "explanation": "根据《刑法》第318条第2款规定，组织他人偷越国（边）境，并以暴力、威胁方法抗拒检查的，属于组织他人偷越国（边）境罪的加重情节。但该款同时规定，对检查人员有杀害、伤害等犯罪行为的，依照数罪并罚的规定处罚。甲暴力抗拒检查并将边检工作人员刺成重伤，应以组织他人偷越国（边）境罪和故意伤害罪数罪并罚。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 620}, {"num": 622, "batch": "专业基础知识", "type": "single", "stem": "甲明知乙犯了杀人罪，不仅没向公安机关报案，反而为乙伪造了假身份证，让乙持假身份证逃走。甲的行为构成（）", "options": [{"letter": "A", "text": "包庇罪"}, {"letter": "B", "text": "窝藏罪"}, {"letter": "C", "text": "伪造身份证件罪"}, {"letter": "D", "text": "伪造身份证件罪和包庇罪"}], "answer": "B", "explanation": "根据《刑法》第310条规定，窝藏罪是指明知是犯罪的人而为其提供隐藏处所、财物，帮助其逃匿的行为。甲明知乙犯了杀人罪，为乙伪造假身份证让其持假身份证逃走，属于为犯罪人提供帮助使其逃匿，构成窝藏罪。包庇罪侧重于作假证明掩盖犯罪事实，而本案是帮助逃匿，应认定为窝藏罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 621}, {"num": 623, "batch": "专业基础知识", "type": "single", "stem": "丁欠银行贷款未偿还，法院依法将其价值20万元的汽车扣押，停放在法院院内。丁担心案件久拖不决，车辆长期不用会损坏，也影响自己跑运输，遂产生了把车取回来的想法。某晚，丁潜入法院院内，用备用钥匙打开车门，将车开走。随后，丁打电话告诉法院，说车是他取出来的，并催促法院赶快公正结案。丁某的行为（）", "options": [{"letter": "A", "text": "不构成犯罪"}, {"letter": "B", "text": "构成盗窃罪"}, {"letter": "C", "text": "构成拒不执行判决、裁定罪"}, {"letter": "D", "text": "构成非法处置扣押的财产罪"}], "answer": "D", "explanation": "根据《刑法》第314条规定，隐藏、转移、变卖、故意毁损已被司法机关查封、扣押、冻结的财产，情节严重的，构成非法处置扣押的财产罪。丁的汽车已被法院依法扣押，丁擅自将车开走，属于转移已被司法机关扣押的财产的行为，构成非法处置扣押的财产罪。丁事后告知法院并催促结案，不具有非法占有目的，不构成盗窃罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 622}, {"num": 624, "batch": "专业基础知识", "type": "single", "stem": "黄某为了使许某等13名中国公民偷渡出境，协助带领上述人员从某机场出境，被警方查获。黄某的行为构成（）", "options": [{"letter": "A", "text": "组织他人偷越国（边）境罪"}, {"letter": "B", "text": "运送他人偷越国（边）境罪"}, {"letter": "C", "text": "协助运送他人偷越国（边）境"}, {"letter": "D", "text": "协助组织他人偷越国（边）境"}], "answer": "B", "explanation": "根据《刑法》第321条规定，运送他人偷越国（边）境罪是指使用交通工具或者徒步带领他人偷越国（边）境的行为。黄某协助带领许某等13人从机场出境，属于运送他人偷越国（边）境的行为，构成运送他人偷越国（边）境罪。黄某并非组织者，而是具体实施运送行为的人。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 623}, {"num": 625, "batch": "专业基础知识", "type": "single", "stem": "魏某盗得1台价值1万余元的手提电脑，深夜卖到一收购点。店主毕某看魏某神色慌张，问魏某电脑的来路。魏某支支吾吾，经再三逼问，只得说出是偷来的。毕某对魏某说：“电脑500元卖给我，否则我就到公安局告你。”魏某无奈只得同意。毕某构成（）", "options": [{"letter": "A", "text": "强迫交易罪"}, {"letter": "B", "text": "掩饰、隐瞒犯罪所得罪"}, {"letter": "C", "text": "敲诈勒索罪"}, {"letter": "D", "text": "掩饰、隐瞒犯罪所得罪和敲诈勒索罪择一重罪处罚"}], "answer": "D", "explanation": "毕某明知电脑是魏某偷来的，仍以极低价格（500元）强行收购，一方面构成掩饰、隐瞒犯罪所得罪（明知是犯罪所得而收购）；另一方面以告发相要挟迫使魏某以极低价格出售，构成敲诈勒索罪。两罪属于想象竞合，应择一重罪处罚。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 624}, {"num": 626, "batch": "专业基础知识", "type": "single", "stem": "下列行为应以掩饰、隐瞒犯罪所得罪论处的是（）", "options": [{"letter": "A", "text": "甲用受贿所得1000万元购买了一处别墅"}, {"letter": "B", "text": "乙明知是他人用于抢劫的汽车而更改车身颜色"}, {"letter": "C", "text": "丙与抢劫犯事前通谋后代为销售抢劫财物"}, {"letter": "D", "text": "丁明知是他人盗窃的汽车而为其提供伪造的机动车来历凭证"}], "answer": "D", "explanation": "根据《刑法》第312条规定，掩饰、隐瞒犯罪所得罪要求明知是犯罪所得而予以窝藏、转移、收购、代为销售或以其他方法掩饰、隐瞒。D项丁明知是盗窃的汽车而提供伪造的机动车来历凭证，属于以其他方法掩饰、隐瞒犯罪所得，构成该罪。A项属于洗钱罪（受贿所得属于洗钱罪上游犯罪）；B项更改抢劫汽车颜色属于帮助毁灭犯罪工具而非犯罪所得；C项事前通谋后代为销售构成抢劫罪共犯。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 625}, {"num": 627, "batch": "专业基础知识", "type": "single", "stem": "下列行为构成掩饰、隐瞒犯罪所得罪的是（）", "options": [{"letter": "A", "text": "李某明知是走私犯罪所得，协助其将财产转换为金融票据"}, {"letter": "B", "text": "陈某协助盗窃分子将其犯罪所得的财产加以藏匿"}, {"letter": "C", "text": "张某协助刘某将贪污贿赂犯罪所得的资金汇往境外"}, {"letter": "D", "text": "尤某明知是金融诈骗犯罪所得，为其提供资金账户"}], "answer": "B", "explanation": "根据《刑法》第312条规定，掩饰、隐瞒犯罪所得罪的对象是犯罪所得及其收益。B项陈某协助盗窃分子藏匿犯罪所得财产，属于对犯罪所得予以窝藏的行为，构成掩饰、隐瞒犯罪所得罪。A项属于洗钱罪（走私犯罪所得是洗钱罪上游犯罪）；C项属于洗钱罪（贪污贿赂犯罪所得是洗钱罪上游犯罪）；D项属于洗钱罪（金融诈骗犯罪所得是洗钱罪上游犯罪）。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 626}, {"num": 628, "batch": "专业基础知识", "type": "single", "stem": "甲公司销售伪劣产品获利人民币4000万元后，欲通过乙公司（非国有）的账户将这笔资金换成外汇转移至香港，并说明可按资金数额的10％支付“手续费”。乙公司明知该笔资金为甲公司犯罪所得，仍同意为该笔资金转账提供账户，并在收取“手续费”400万元后，将该笔资金折换成438万美元，以预付货款为名汇往甲公司在香港的账户。乙公司的行为构成（）", "options": [{"letter": "A", "text": "走私罪（共犯）"}, {"letter": "B", "text": "掩饰、隐瞒犯罪所得罪"}, {"letter": "C", "text": "逃汇罪"}, {"letter": "D", "text": "单位受贿罪"}], "answer": "B", "explanation": "甲公司销售伪劣产品构成生产、销售伪劣产品罪，乙公司明知该4000万元是甲公司犯罪所得，仍提供账户帮助转账并将资金转移至香港，属于掩饰、隐瞒犯罪所得的行为。由于生产、销售伪劣产品罪不属于洗钱罪的七类上游犯罪，因此乙公司不构成洗钱罪，而构成掩饰、隐瞒犯罪所得罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 627}, {"num": 629, "batch": "专业基础知识", "type": "single", "stem": "卢某是出租车司机，在公安机关查处卖淫、嫖娼活动时，给10余名卖淫女通风报信，致使查处活动失败。卢某的行为构成（）", "options": [{"letter": "A", "text": "妨害公务罪"}, {"letter": "B", "text": "协助组织卖淫罪"}, {"letter": "C", "text": "包庇罪"}, {"letter": "D", "text": "窝藏罪"}], "answer": "D", "explanation": "根据《刑法》第310条规定，窝藏罪是指明知是犯罪的人而为其提供隐藏处所、财物，帮助其逃匿的行为。根据《刑法》第362条规定，旅馆业、饮食服务业、文化娱乐业、出租汽车业等单位的人员，在公安机关查处卖淫、嫖娼活动时，为违法犯罪分子通风报信，情节严重的，依照窝藏罪的规定定罪处罚。卢某作为出租车司机，在公安机关查处卖淫嫖娼时通风报信，构成窝藏罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 628}, {"num": 630, "batch": "专业基础知识", "type": "single", "stem": "魏某和刘某事前商量好，魏某抢劫后，逃到刘某处，给其一定好处。某日，魏某抢劫作案后到刘某处躲避。因未抢到钱，遂没给刘某好处。刘某对外称魏某是前来打工的亲戚，后帮助魏某逃走。刘某的行为构成（）", "options": [{"letter": "A", "text": "窝藏罪"}, {"letter": "B", "text": "抢劫罪"}, {"letter": "C", "text": "包庇罪"}, {"letter": "D", "text": "伪证罪"}], "answer": "B", "explanation": "根据《刑法》第310条及相关司法解释，事前与犯罪分子通谋，事后为其提供隐藏处所或帮助逃匿的，以共同犯罪论处。魏某和刘某事前商量好，约定魏某抢劫后到刘某处躲避并给予好处，属于事前通谋。虽然魏某未抢到钱没给好处，但不影响事前通谋的成立，刘某构成抢劫罪的共犯。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 629}, {"num": 631, "batch": "专业基础知识", "type": "single", "stem": "蔡某、胡某二人伪造相关材料，为15名中国公民骗取日本签证，并运送他们偷渡至日本。以下说法正确的是（）", "options": [{"letter": "A", "text": "二人构成运送他人偷越国（边）境罪"}, {"letter": "B", "text": "二人构成组织他人偷越国（边）境罪"}, {"letter": "C", "text": "二人应以骗取出境证件罪和组织他人偷越国（边）境罪数罪并罚"}, {"letter": "D", "text": "二人构成组织他人偷越国（边）境罪和骗取出境证件罪，应择一重罪处罚"}], "answer": "B", "explanation": "根据《刑法》第318条规定，组织他人偷越国（边）境罪是指领导、策划、指挥他人偷越国（边）境或者在首要分子指挥下实施拉拢、串联、介绍他人偷越国（边）境等行为。蔡某、胡某伪造材料为15人骗取签证并运送偷渡，骗取出境证件是组织他人偷越国（边）境的手段行为，根据刑法规定应以组织他人偷越国（边）境罪一罪论处，骗取出境证件行为被吸收。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 630}, {"num": 632, "batch": "专业基础知识", "type": "single", "stem": "关于缓刑，下列说法错误的是（）", "options": [{"letter": "A", "text": "甲是累犯，不适用缓刑"}, {"letter": "B", "text": "乙是危害国家安全的犯罪分子，不适用缓刑"}, {"letter": "C", "text": "丙是数罪并罚但宣告刑为3年以下有期徒刑的犯罪分子，可以适用缓刑"}, {"letter": "D", "text": "丁犯故意杀人罪，被判处3年有期徒刑，丁只要符合缓刑条件，仍然可以适用缓刑"}], "answer": "B", "explanation": "根据《刑法》第74条规定，对于累犯和犯罪集团的首要分子，不适用缓刑。法律并未规定危害国家安全的犯罪分子一律不适用缓刑，只要不属于累犯和犯罪集团首要分子，且符合缓刑条件（判处3年以下有期徒刑、犯罪情节较轻、有悔罪表现等），仍可适用缓刑。因此B项说法错误。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 631}, {"num": 633, "batch": "专业基础知识", "type": "single", "stem": "王某因涉嫌非法获取公民个人信息罪被判处有期徒刑2年并处罚金3000元，关于王某的报告义务，下列说法不正确的是（）", "options": [{"letter": "A", "text": "在入伍时应当如实向有关单位报告"}, {"letter": "B", "text": "在就业时应当如实向有关单位报告"}, {"letter": "C", "text": "在出国（边）境时应当如实向有关单位报告"}, {"letter": "D", "text": "如王某犯罪时不满18周岁，免除报告义务"}], "answer": "C", "explanation": "根据《刑法》第100条规定，依法受过刑事处罚的人，在入伍、就业的时候，应当如实向有关单位报告自己曾受过刑事处罚。报告义务仅限于入伍和就业两种情形，不包括出国（边）境。因此C项说法不正确。犯罪时不满18周岁的人免除前科报告义务，D项说法正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 632}, {"num": 634, "batch": "专业基础知识", "type": "single", "stem": "曹某几年前将民兵训练时使用剩下的子弹217发私藏在家中床下的旧皮箱中。几十年后，小偷进入他家偷东西时发现并将子弹偷走，后小偷被警察抓到，供出子弹出处，曹某案发。曹某的行为（）", "options": [{"letter": "A", "text": "不构成犯罪"}, {"letter": "B", "text": "构成犯罪，但是已过追诉时效"}, {"letter": "C", "text": "构成私藏弹药罪，应当追究其刑事责任"}, {"letter": "D", "text": "根据从旧兼从轻的原则，当时法律并未将私藏弹药行为规定为犯罪，所以不应该追究曹某的刑事责任"}], "answer": "C", "explanation": "根据《刑法》第128条规定，违反枪支管理规定，非法持有、私藏枪支、弹药的，构成非法持有、私藏枪支、弹药罪。曹某将民兵训练剩余的子弹217发私藏在家中，属于私藏弹药的行为。私藏弹药罪属于继续犯，追诉时效从犯罪行为终了之日起计算，曹某私藏行为一直持续到案发，未过追诉时效，应当追究刑事责任。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 633}, {"num": 635, "batch": "专业基础知识", "type": "single", "stem": "下列情形中，应当受追诉时效限制的是（）", "options": [{"letter": "A", "text": "在人民法院受理了齐某自诉汤某伤害案件以后，汤某离家杳无音信"}, {"letter": "B", "text": "丛某因故未在法定期限内对钟某的侮辱行为提出控告"}, {"letter": "C", "text": "薛某向公安机关控告，声称自己被抢劫，因薛某说话颠三倒四，接案人员对其报案有怀疑而未立案"}, {"letter": "D", "text": "秦某得知与其共同诈骗的李某被公安机关抓获，于是逃离居住地藏匿"}], "answer": "B", "explanation": "根据《刑法》第88条规定，在人民检察院、公安机关、国家安全机关立案侦查或者在人民法院受理案件以后，逃避侦查或者审判的，不受追诉时效的限制；被害人在追诉期限内提出控告，人民法院、人民检察院、公安机关应当立案而不予立案的，不受追诉时效的限制。A项属于受理后逃避侦查，不受追诉时效限制；C项属于应当立案而不立案，不受追诉时效限制；D项属于立案后逃避侦查，不受追诉时效限制。B项丛某未在法定期限内提出控告，不属于上述例外情形，应当受追诉时效限制。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 634}, {"num": 636, "batch": "专业基础知识", "type": "single", "stem": "李某犯抢劫罪（可处10年以上有期徒刑），11年后又犯非法搜查罪（可处3年以下有期徒刑），17年后被公安机关发现并抓获。以下说法正确的是（）", "options": [{"letter": "A", "text": "应当追究李某涉嫌抢劫罪和非法搜查罪的刑事责任"}, {"letter": "B", "text": "应当追究李某涉嫌抢劫罪的刑事责任"}, {"letter": "C", "text": "应当追究李某涉嫌非法搜查罪的刑事责任"}, {"letter": "D", "text": "不能追究李某的任何刑事责任"}], "answer": "B", "explanation": "根据《刑法》第89条规定，在追诉期限以内又犯罪的，前罪追诉的期限从犯后罪之日起计算。李某犯抢劫罪（法定最高刑10年以上有期徒刑，追诉时效为15年），11年后又犯非法搜查罪（追诉时效为5年），抢劫罪的追诉时效从犯后罪之日起重新计算15年，即到第26年才届满。17年后被发现时，抢劫罪仍在追诉时效内。但非法搜查罪（追诉时效5年）从犯后罪之日起已过17年，超过追诉时效。因此应追究抢劫罪的刑事责任。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 635}, {"num": 637, "batch": "专业基础知识", "type": "single", "stem": "下列罪犯在执行中确有悔改表现，可以适用假释的有（）", "options": [{"letter": "A", "text": "甲因故意伤害罪被判处有期徒刑8年，刑满释放4年后，又犯诈骗罪被判处有期徒刑3年"}, {"letter": "B", "text": "乙因强奸罪被判处有期徒刑12年"}, {"letter": "C", "text": "丙因交通肇事罪被判处拘役"}, {"letter": "D", "text": "丁因抢劫罪被判处有期徒刑8年"}], "answer": "D", "explanation": "根据《刑法》第81条规定，被判处有期徒刑的犯罪分子，执行原判刑期二分之一以上，确有悔改表现，没有再犯罪危险的，可以假释。但是累犯以及因故意杀人、强奸、抢劫、绑架、放火、爆炸、投放危险物质或者有组织的暴力性犯罪被判处10年以上有期徒刑、无期徒刑的犯罪分子，不得假释。A项甲是累犯，不得假释；B项乙因强奸罪被判处12年，属于暴力犯罪且刑期10年以上，不得假释；C项丙被判处拘役，不符合假释条件（假释仅适用于有期徒刑和无期徒刑）；D项丁因抢劫罪被判处8年，虽属暴力犯罪但未达10年以上，可以假释。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 636}, {"num": 638, "batch": "专业基础知识", "type": "single", "stem": "甲因虐待罪被判处2年有期徒刑，缓期2年执行。2年考验期满后公安机关发现甲在考验期第8个月时犯有故意伤害罪。下列对甲的处理正确的是（）", "options": [{"letter": "A", "text": "仅以故意伤害罪处罚"}, {"letter": "B", "text": "构成累犯，以故意伤害罪从重处罚"}, {"letter": "C", "text": "对甲所犯的故意伤害罪与虐待罪依照先减后并的方法实行并罚"}, {"letter": "D", "text": "对故意伤害罪作出判决，再将判处的刑罚与因虐待罪判处的2年有期徒刑实行并罚"}], "answer": "D", "explanation": "根据《刑法》第77条规定，被宣告缓刑的犯罪分子，在缓刑考验期限内犯新罪的，应当撤销缓刑，对新犯的罪作出判决，把前罪和后罪所判处的刑罚，依照数罪并罚的规定决定执行的刑罚。甲在缓刑考验期第8个月犯故意伤害罪，虽在考验期满后才发现，但仍应撤销缓刑，将故意伤害罪的判决与虐待罪的2年有期徒刑实行并罚。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 637}, {"num": 639, "batch": "专业基础知识", "type": "single", "stem": "关于禁止令，下列说法正确的是（）", "options": [{"letter": "A", "text": "甲因盗掘古墓葬罪被判刑7年，在执行5年后被假释，法院裁定假释时，可对甲宣告禁止令"}, {"letter": "B", "text": "乙犯合同诈骗罪被判处缓刑，因附带民事赔偿义务尚未履行，法院可在禁止令中禁止其进入高档饭店消费"}, {"letter": "C", "text": "丙因在公共厕所猥亵儿童被判处缓刑，法院可同时宣告禁止其进入公共厕所"}, {"letter": "D", "text": "丁被判处管制，同时被禁止接触同案犯，禁止令的期限应从管制执行完毕之日起计算"}], "answer": "B", "explanation": "根据《刑法》第72条第2款及相关司法解释，宣告缓刑时可以根据犯罪情况同时宣告禁止令。B项中乙因合同诈骗被判缓刑，法院可在禁止令中限制其进入高档饭店消费以保障民事赔偿义务的履行，说法正确。A项假释不适用禁止令（禁止令仅适用于管制和缓刑）；C项禁止进入公共厕所不符合禁止令的合理性和必要性要求；D项禁止令的期限应从管制执行之日起计算，而非从执行完毕之日起。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 638}, {"num": 640, "batch": "专业基础知识", "type": "single", "stem": "锅炉工于某与王某不和，一日二人又发生争执，于某怀恨在心。当日夜里，于某将锅炉的水表打坏，使锅炉不再加水并且持续干烧，估计锅炉会在王某接班后5分钟内爆炸。事后果然发生爆炸，不仅王某被炸死，而且锅炉房被炸毁，并导致附近的一间民房倒塌，死伤数人。对于某的行为应认定为（）", "options": [{"letter": "A", "text": "故意杀人罪"}, {"letter": "B", "text": "爆炸罪"}, {"letter": "C", "text": "故意毁坏财物罪"}, {"letter": "D", "text": "以危险方法危害公共安全罪"}], "answer": "B", "explanation": "于某故意打坏锅炉水表使锅炉干烧，意图利用锅炉爆炸来杀害王某。锅炉爆炸不仅炸死王某，还炸毁锅炉房、导致附近民房倒塌并造成多人死伤，危害了不特定多数人的生命财产安全。于某的行为危害了公共安全，构成爆炸罪。虽然其主观目的是杀害王某，但手段行为危害了公共安全，应以爆炸罪定罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 639}, {"num": 641, "batch": "专业基础知识", "type": "single", "stem": "杜某将王某打伤，法医鉴定为轻微伤。县公安局对杜某处以拘留10日的治安管理处罚，并送达拘留所执行。3个月后，杜某为报复王某，将王某的汽车玻璃砸坏。王某向当地人民法院提起诉讼，要求追究杜某殴打自己和砸车的刑事责任。经重新鉴定，王某为轻伤。汽车玻璃价值5000元。人民法院对杜某殴打王某的行为判处拘役3个月，对杜某砸车的行为判处有期徒刑1年。下列说法正确的是（）", "options": [{"letter": "A", "text": "杜某被行政拘留的10日不应折抵拘役"}, {"letter": "B", "text": "杜某被行政拘留的10日可以折抵有期徒刑"}, {"letter": "C", "text": "对杜某只执行有期徒刑"}, {"letter": "D", "text": "杜某殴打王某已经行政处罚，不应再追究刑事责任"}], "answer": "C", "explanation": "根据《刑法》第58条及相关规定，行政拘留的期限应当折抵刑期。但本题的关键在于数罪并罚的执行问题。杜某被判处拘役3个月和有期徒刑1年，根据《刑法》第69条规定，数罪中有判处有期徒刑和拘役的，执行有期徒刑。因此对杜某只执行有期徒刑。同时，根据《行政处罚法》规定，违法行为构成犯罪，行政机关已经给予行政拘留的，应当依法折抵相应刑期。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 640}, {"num": 642, "batch": "专业基础知识", "type": "single", "stem": "下列选项不构成立功的是（）", "options": [{"letter": "A", "text": "甲是唯一知晓同案犯裴某手机号的人，其主动供述裴某手机号，侦查机关据此采用技术侦查手段将裴某抓获"}, {"letter": "B", "text": "乙因购买境外人士赵某的海洛因被抓获后，按司法机关要求向赵某发短信“报平安”，并表示还要购买毒品。赵某因此未离境，等待乙时被抓获"}, {"letter": "C", "text": "丙被抓获后，丙的父亲找到同案犯藏匿地点，协助侦查机关将其抓获"}, {"letter": "D", "text": "丁被抓获后，向侦查机关提供同案犯的体貌特征，同案犯由此被抓获"}], "answer": "C", "explanation": "根据《刑法》第68条及相关司法解释，立功是指犯罪分子揭发他人犯罪行为查证属实，或者提供重要线索从而得以侦破其他案件等行为。C项中是丙的父亲（而非丙本人）协助找到同案犯藏匿地点，不属于丙本人的立功表现。立功必须是犯罪分子本人实施的行为，亲属的协助行为不能认定为犯罪分子的立功。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 641}, {"num": 643, "batch": "专业基础知识", "type": "single", "stem": "下列情形中，属于自首的是（）", "options": [{"letter": "A", "text": "甲在抢劫时被当场抓获，在公安人员讯问时，又主动交代了其他3件抢劫的事实"}, {"letter": "B", "text": "甲因为与乙有仇，与儿子丙一起残忍地杀害了乙。甲见罪责难逃，自动到公安机关投案自首，交代杀人是自己一人所为，与别人无关"}, {"letter": "C", "text": "甲在实施强奸行为后，自动投案，如实供述了自己的罪行。但后来又翻供，拒不认罪，直到一审庭审期间才恢复原先的如实供述"}, {"letter": "D", "text": "甲在诈骗后，自动投案，但在投案后又逃跑，后被公安机关抓获，如实供述了自己的罪行"}], "answer": "C", "explanation": "根据《刑法》第67条及相关司法解释，自首要求自动投案并如实供述自己的罪行。C项中甲实施强奸后自动投案并如实供述，虽后来翻供，但在一审庭审期间恢复如实供述的，仍应认定为自首。根据最高法关于自首的司法解释，犯罪嫌疑人自动投案并如实供述后又翻供的，不能认定为自首，但在一审判决前又能如实供述的，应当认定为自首。A项属于坦白而非自首（被动归案后交代同种罪行）；B项甲隐瞒了同案犯，未如实供述全部犯罪事实；D项投案后逃跑再被抓获，不能认定为自首。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 642}, {"num": 644, "batch": "专业基础知识", "type": "single", "stem": "下列情况属于累犯的是（）", "options": [{"letter": "A", "text": "贾某因过失导致他人死亡，被判处有期徒刑3年，刑满释放后5年内又犯故意伤害罪，被判处有期徒刑10年"}, {"letter": "B", "text": "王某因诽谤罪被判处有期徒刑2年，缓刑3年，缓刑考验期内因盗窃金融机构被判处无期徒刑"}, {"letter": "C", "text": "李某（15岁）犯故意伤害罪，被判处有期徒刑6个月，刑满释放后第2年又犯抢夺罪，被判处有期徒刑3年"}, {"letter": "D", "text": "赵某因叛逃罪被判处有期徒刑8年，在刑罚执行完毕10年以后，又犯组织恐怖组织罪，被判处有期徒刑8年"}], "answer": "D", "explanation": "根据《刑法》第65条和第66条规定，一般累犯要求前后罪均为故意犯罪、前后罪均被判处有期徒刑以上刑罚、后罪发生在前罪刑罚执行完毕或赦免后5年以内，且犯罪时已满18周岁。特别累犯（危害国家安全犯罪、恐怖活动犯罪、黑社会性质组织犯罪）不受刑度和5年期限限制。A项前罪为过失犯罪，不构成累犯；B项后罪发生在缓刑考验期内，刑罚尚未执行完毕，不构成累犯；C项李某犯罪时不满18周岁，不构成累犯；D项赵某前罪为叛逃罪（危害国家安全犯罪），后罪为组织恐怖组织罪，构成特别累犯。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 643}, {"num": 645, "batch": "专业基础知识", "type": "single", "stem": "郑某因贩卖毒品罪被判处有期徒刑6年，4年前刑满释放。后来由于经商不利，开始多次运输毒品，被判处10年有期徒刑。下列说法正确的是（）", "options": [{"letter": "A", "text": "郑某不构成累犯"}, {"letter": "B", "text": "对郑某可以适用减刑"}, {"letter": "C", "text": "对郑某可以适用假释"}, {"letter": "D", "text": "对郑某可以适用缓刑"}], "answer": "B", "explanation": "郑某前罪贩卖毒品罪刑满释放后4年内又犯运输毒品罪，构成毒品再犯（《刑法》第356条），同时构成一般累犯。对于累犯，应当从重处罚，且不得适用缓刑和假释。但减刑不受累犯限制，只要在执行期间确有悔改或立功表现，仍可适用减刑。因此B项正确，C项和D项错误。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 644}, {"num": 646, "batch": "专业基础知识", "type": "single", "stem": "下列属于洗钱犯罪的是（）", "options": [{"letter": "A", "text": "甲系银行工作人员，在明知贾某的4000万元系走私犯罪所得的情况下，仍协助其将资金汇往境外"}, {"letter": "B", "text": "盗窃犯乙窃得宝马车一辆，销赃后得款50万元"}, {"letter": "C", "text": "丙明知男友张某从事贩毒，仍将张某贩毒所得的80万元藏匿在自己家中"}, {"letter": "D", "text": "丁贪图便宜，在得知李某的影碟机系诈骗所得后，仍继续从李某处进货并销售"}], "answer": "A", "explanation": "根据《刑法》第191条规定，洗钱罪的上游犯罪包括毒品犯罪、黑社会性质的组织犯罪、恐怖活动犯罪、走私犯罪、贪污贿赂犯罪、破坏金融管理秩序犯罪、金融诈骗犯罪七类。A项中甲明知是走私犯罪所得而协助将资金汇往境外，属于洗钱罪。B项属于事后销赃行为；C项属于窝藏犯罪所得（上游犯罪是毒品犯罪，但藏匿行为不属于洗钱罪列举的行为方式）；D项属于掩饰、隐瞒犯罪所得罪（上游犯罪是诈骗，不属于七类上游犯罪）。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 645}, {"num": 647, "batch": "专业基础知识", "type": "single", "stem": "吕某因犯绑架罪被判处有期徒刑12年。入狱后，吕某认真遵守监规，接受教育改造，确有悔改表现。根据《刑法》的规定，对吕某（）", "options": [{"letter": "A", "text": "既可以减刑，也可以假释"}, {"letter": "B", "text": "可以减刑，但不能假释"}, {"letter": "C", "text": "不能减刑，但可以假释"}, {"letter": "D", "text": "既不能减刑，也不能假释"}], "answer": "B", "explanation": "根据《刑法》第78条规定，被判处管制、拘役、有期徒刑、无期徒刑的犯罪分子，在执行期间认真遵守监规、接受教育改造、确有悔改表现的，可以减刑。但根据《刑法》第81条第2款规定，对累犯以及因故意杀人、强奸、抢劫、绑架、放火、爆炸、投放危险物质或者有组织的暴力性犯罪被判处10年以上有期徒刑、无期徒刑的犯罪分子，不得假释。吕某因绑架罪被判处12年有期徒刑，属于暴力性犯罪且刑期10年以上，不得假释，但可以减刑。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 646}, {"num": 648, "batch": "专业基础知识", "type": "single", "stem": "甲因与车间主任乙不和，欲除之而后快。某日，甲将炸药带进车间，点燃后借故溜出，结果不仅炸死了车间主任，还炸伤了3名工人，价值数百万元的生产设备、厂房一并被炸毁。甲的行为构成（）", "options": [{"letter": "A", "text": "故意杀人罪"}, {"letter": "B", "text": "爆炸罪"}, {"letter": "C", "text": "故意毁坏财物罪"}, {"letter": "D", "text": "故意伤害罪"}], "answer": "B", "explanation": "甲将炸药带进车间点燃，虽然主观目的是杀害车间主任乙，但爆炸行为不仅炸死乙，还炸伤3名工人并炸毁价值数百万元的生产设备和厂房，危害了不特定多数人的生命、健康和重大财产安全。甲的行为危害了公共安全，构成爆炸罪。虽然甲有杀人故意，但手段行为同时危害公共安全，应以爆炸罪定罪处罚。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 647}, {"num": 649, "batch": "专业基础知识", "type": "single", "stem": "王某家中的一只箱子和若干财物被盗，箱子在附近的公共垃圾桶中被找到，里面的东西原封未动。王某认为是窃贼所藏，日后必然来取，就产生了报复的念头。他把箱子中的物品取出，装入爆炸装置，放回原处。后来，一清洁工清除垃圾时发现了箱子，打开时发生爆炸，当场死亡。王某的行为构成（）", "options": [{"letter": "A", "text": "故意杀人罪"}, {"letter": "B", "text": "爆炸罪"}, {"letter": "C", "text": "过失致人死亡罪"}, {"letter": "D", "text": "以危险方法危害公共安全罪"}], "answer": "B", "explanation": "王某在公共垃圾桶中放置装有爆炸装置的箱子，该地点属于公共场所，任何人均可能接触并打开，具有危害不特定多数人生命安全的危险性。王某主观上明知清洁工或其他人可能会打开箱子，仍放置爆炸装置，对危害结果持放任态度，构成爆炸罪。虽然王某的目的是报复窃贼，但手段行为危害了公共安全。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 648}, {"num": 650, "batch": "专业基础知识", "type": "single", "stem": "甲与乙有过节，为泄私愤，甲于某日深夜窜至乙承包的造纸厂内，用打火机点燃厂内的草纸，致使厂房、造纸设备、原料及成品纸和生活用品等财产被烧毁，并造成乙的妻子和儿子被烧成重伤，2个工人被烧死，同时造成直接经济损失10万余元。甲的行为构成（）", "options": [{"letter": "A", "text": "放火罪"}, {"letter": "B", "text": "故意毁坏财物罪"}, {"letter": "C", "text": "破坏生产经营罪"}, {"letter": "D", "text": "故意杀人罪"}], "answer": "A", "explanation": "甲为泄私愤，深夜在乙承包的造纸厂放火，致使厂房、设备、原料等被烧毁，并造成2人死亡、2人重伤及重大经济损失。造纸厂周围有其他建筑和人员，放火行为危害了公共安全，构成放火罪。虽然甲主观上可能是为了报复乙、毁坏其财产，但放火行为危害了不特定多数人的生命和财产安全，应以放火罪定罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 649}, {"num": 651, "batch": "专业基础知识", "type": "single", "stem": "甲欲杀死仇人乙，在乙开的出租车座位下安放了定时炸弹，结果不仅炸死了乙，同时炸死了乘客丙、丁，还炸毁了出租车。甲的行为构成（）", "options": [{"letter": "A", "text": "故意杀人罪和破坏交通工具罪"}, {"letter": "B", "text": "爆炸罪"}, {"letter": "C", "text": "爆炸罪和破坏交通工具罪"}, {"letter": "D", "text": "故意杀人罪"}], "answer": "B", "explanation": "甲在出租车座位下安放定时炸弹，意图杀害乙，但爆炸行为不仅炸死乙，还炸死乘客丙、丁并炸毁出租车。出租车属于公共交通工具，在公共场所使用爆炸方法杀人，危害了不特定多数人的生命安全和财产安全。甲的一个行为同时触犯故意杀人罪和爆炸罪，属于想象竞合犯，应择一重罪即以爆炸罪定罪处罚。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 650}, {"num": 652, "batch": "专业基础知识", "type": "single", "stem": "张某因失恋失去生活的信心想自杀，独自躲在家中放火焚烧自己的房屋（与几十家邻居的房子连在一起），被邻居及时发现，将火扑灭。张某的行为构成（）", "options": [{"letter": "A", "text": "故意毁坏财物罪"}, {"letter": "B", "text": "放火罪"}, {"letter": "C", "text": "失火罪"}, {"letter": "D", "text": "以危险方法危害公共安全罪"}], "answer": "B", "explanation": "张某独自在家中放火焚烧自己的房屋，但其房屋与几十家邻居的房子连在一起，放火行为足以危及不特定多数邻居的生命和财产安全，危害了公共安全。张某虽然焚烧的是自己的财物，但放火行为足以危害公共安全，且张某对此具有故意（明知会危及邻居仍放火），构成放火罪。因被及时扑灭未造成严重后果，属于放火罪未遂。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 651}, {"num": 653, "batch": "专业基础知识", "type": "single", "stem": "甲偷偷将邻居交售粮站的稻米淋洒农药，取出部分作饵料，毒死麻雀后售给饭馆，非法获利5000元。甲的行为构成（）", "options": [{"letter": "A", "text": "故意毁坏财物罪"}, {"letter": "B", "text": "以危险方法危害公共安全罪和盗窃罪"}, {"letter": "C", "text": "以危险方法危害公共安全罪"}, {"letter": "D", "text": "投放危险物质罪和销售有毒、有害食品罪"}], "answer": "D", "explanation": "甲偷偷将邻居交售粮站的稻米淋洒农药，该行为危害了不特定多数人的食品安全，构成投放危险物质罪。甲取出部分作饵料毒死麻雀后售给饭馆，将含有农药的麻雀作为食品销售，构成销售有毒、有害食品罪。两罪分别评价，应以投放危险物质罪和销售有毒、有害食品罪数罪并罚。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 652}, {"num": 654, "batch": "专业基础知识", "type": "single", "stem": "陈某通过互联网将国家秘密非法发送给境外的机构，陈某的行为属于（）", "options": [{"letter": "A", "text": "故意泄露国家秘密罪"}, {"letter": "B", "text": "间谍罪"}, {"letter": "C", "text": "为境外非法提供国家秘密、情报罪"}, {"letter": "D", "text": "非法获取国家秘密罪"}], "answer": "C", "explanation": "根据《刑法》第111条规定，为境外的机构、组织、人员窃取、刺探、收买、非法提供国家秘密或者情报的，构成为境外非法提供国家秘密、情报罪。陈某通过互联网将国家秘密非法发送给境外机构，符合该罪的构成要件。陈某的行为不是单纯的泄露国家秘密，而是向境外机构非法提供，应以为境外非法提供国家秘密罪定罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 653}, {"num": 655, "batch": "专业基础知识", "type": "single", "stem": "王某（29岁）为骗取保险金与赵某（25岁）合谋，由赵某将王某承包的县汽车站的一辆客车烧掉（客车所有权属于该汽车站，投保人也为该汽车站），事后付给赵某酬金。两日后，赵某携带汽油到该汽车站，将王某停在车站院内的客车烧毁，造成直接经济损失10万多元。当时在站内停有10余辆其他车辆，燃烧地点距家属楼16米，距加油站25米。保险公司未能查明起火原因，遂向投保人县汽车站支付赔偿款8万元。下列说法正确的是（）", "options": [{"letter": "A", "text": "赵某与王某不构成共同犯罪"}, {"letter": "B", "text": "赵某、王某构成放火罪"}, {"letter": "C", "text": "赵某、王某构成放火罪与保险诈骗罪，应数罪并罚"}, {"letter": "D", "text": "赵某、王某构成保险诈骗罪"}], "answer": "B", "explanation": "王某与赵某合谋放火烧毁客车，该客车停放在有10余辆其他车辆的车站内，距家属楼16米、距加油站25米，放火行为足以危害公共安全，构成放火罪。虽然王某的目的是骗取保险金，但由于王某不是投保人（投保人是汽车站），不符合保险诈骗罪的主体要件，且客车所有权不属于王某，不能构成保险诈骗罪。二人构成放火罪的共同犯罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 654}, {"num": 656, "batch": "专业基础知识", "type": "single", "stem": "夏某是我国新华社高级编辑，香港某报记者董某请求夏某为其搞一份机密文件。按规定该文件只下发到社长一级，且只有社长那里有一份。夏某到社长办公室时发现该文件就放在桌上，乘社长不注意将文件拿出复制一份，然后通过电子邮件发送董某。董某给夏某感谢费2万港元。夏某的行为（）", "options": [{"letter": "A", "text": "构成非法获取国家秘密罪和为境外窃取、非法提供国家秘密罪，应当实行数罪并罚"}, {"letter": "B", "text": "构成为境外窃取、非法提供国家秘密罪和受贿罪，应当实行数罪并罚"}, {"letter": "C", "text": "构成为境外窃取、非法提供国家秘密罪"}, {"letter": "D", "text": "构成故意泄露国家秘密罪"}], "answer": "B", "explanation": "夏某乘社长不注意将机密文件拿出复制并通过电子邮件发送给境外记者，属于为境外人员窃取、非法提供国家秘密的行为。夏某是国家工作人员，利用职务便利获取国家秘密并提供给境外人员，同时收受了2万港元报酬，构成受贿行为。根据刑法规定，为境外窃取、非法提供国家秘密罪和受贿罪应当数罪并罚。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 655}, {"num": 657, "batch": "专业基础知识", "type": "single", "stem": "甲随手将未熄灭的烟头用手指一弹，不料落到一堆货物上。甲仔细一看发现货物是棉花，便打算过去把烟头熄灭。但是又想今天是乙值班，如果起火可以陷害乙。于是迅速离去。不久在棉花上的烟头引起了火灾。下列说法错误的是（）", "options": [{"letter": "A", "text": "甲如果随手扔掉烟头就离开，引起了火灾，应是失火罪"}, {"letter": "B", "text": "甲发现具有发生火灾的危险后，能够及时消除危险而不消除，便由一般过失转化为犯罪故意"}, {"letter": "C", "text": "甲成立不作为的放火罪"}, {"letter": "D", "text": "甲成立失火罪"}], "answer": "D", "explanation": "甲随手弹落未熄灭的烟头，初始属于过失行为。但甲发现烟头落在棉花上存在火灾危险后，因想陷害值班人员乙而故意不消除危险并迅速离去，此时甲的主观心态由过失转化为故意（利用先前行为产生的危险状态，以不作为方式实施放火）。甲具有消除危险的义务（先前行为产生的义务），能够消除而不消除，构成不作为的放火罪。因此D项说法错误。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 656}, {"num": 658, "batch": "专业基础知识", "type": "single", "stem": "甲是某厂车间电器设备维修工，值班期间发现电气设备受损，有引起火灾的危险，但由于对车间主任扣发自己工资不满，故意不予维修，结果引起火灾，造成严重损失。某甲的行为构成（）", "options": [{"letter": "A", "text": "放火罪"}, {"letter": "B", "text": "重大责任事故罪"}, {"letter": "C", "text": "玩忽职守罪"}, {"letter": "D", "text": "失火罪"}], "answer": "A", "explanation": "甲作为电器设备维修工，具有维修设备防止火灾的职务义务。甲发现设备有引起火灾的危险，因对车间主任不满而故意不予维修，主观上对火灾结果持故意态度（至少是间接故意），属于以不作为方式实施放火。甲具有防止火灾发生的特定义务（职务要求），能够履行而不履行，构成不作为的放火罪，而非失火罪或重大责任事故罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 657}, {"num": 659, "batch": "专业基础知识", "type": "single", "stem": "甲雇凶手乙杀丙，言明不要造成其他后果。乙几次杀丙均未成功，后来采取爆炸方法，对丙的住宅（周围没有其他人和物）进行爆炸，由于丙不在家，将丙的妻子丁炸死。关于本案，下列说法正确的是（）", "options": [{"letter": "A", "text": "甲与乙构成共同犯罪"}, {"letter": "B", "text": "甲成立故意杀人罪（未遂）"}, {"letter": "C", "text": "乙对丙成立故意杀人罪（未遂），对丁成立过失致人死亡罪"}, {"letter": "D", "text": "乙对丙成立爆炸罪，对丁成立过失致人死亡罪"}], "answer": "A", "explanation": "甲雇乙杀丙，二人存在共同犯罪的故意和行为分工，构成故意杀人罪的共同犯罪。乙采取爆炸方法杀丙，虽然丙不在家炸死了丁，属于对象错误，不影响故意杀人罪既遂的成立。由于丙的住宅周围没有其他人和物，爆炸行为不危害公共安全，不构成爆炸罪。甲对乙的爆炸行为虽超出约定范围，但乙仍是在实施杀人行为，甲与乙构成故意杀人罪的共同犯罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 658}, {"num": 660, "batch": "专业基础知识", "type": "single", "stem": "甲在森林使用爆炸的方法采伐林木，导致森林大火。下列对甲的行为定性正确的是（）", "options": [{"letter": "A", "text": "甲构成放火罪"}, {"letter": "B", "text": "甲构成爆炸罪"}, {"letter": "C", "text": "甲构成爆炸罪、放火罪，应数罪并罚"}, {"letter": "D", "text": "甲构成故意毁坏财物罪"}], "answer": "A", "explanation": "甲在森林中使用爆炸方法采伐林木，导致森林大火。甲主观上是为了采伐林木（故意毁坏林木），但使用爆炸方法引发森林大火，危害了公共安全。甲的行为构成放火罪。爆炸是手段，引发森林火灾是结果，属于以爆炸方法引发火灾危害公共安全的行为，应以放火罪定罪处罚。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 659}, {"num": 661, "batch": "专业基础知识", "type": "single", "stem": "甲与乙是同事，由于乙从中作梗，致使甲未能升迁。甲为了报复乙，在乙楼下的垃圾桶里埋下了炸药和雷管，试图在乙倒垃圾时炸死乙，但乙未到楼下倒垃圾，乙的邻居丙在倒垃圾时被炸成重伤，垃圾桶被炸毁。甲的行为构成（）", "options": [{"letter": "A", "text": "故意杀人罪"}, {"letter": "B", "text": "故意毁坏财物罪"}, {"letter": "C", "text": "爆炸罪"}, {"letter": "D", "text": "故意伤害罪"}], "answer": "C", "explanation": "甲在乙楼下的垃圾桶里埋设炸药和雷管，该地点属于公共场所，邻居丙等不特定人均可能经过，爆炸行为危害了不特定多数人的生命和财产安全。甲虽然目的是杀害乙，但手段行为危害了公共安全，构成爆炸罪。甲对炸伤丙的结果至少持间接故意，应以爆炸罪定罪处罚。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 660}, {"num": 662, "batch": "专业基础知识", "type": "single", "stem": "下列情形不成立累犯的是（）", "options": [{"letter": "A", "text": "张某（16岁）犯盗窃罪被判处有期徒刑1年，刑满释放后的6个月内又犯盗窃罪，被判处有期徒刑2年"}, {"letter": "B", "text": "李某犯强奸罪被判处有期徒刑5年，刑满释放后第4年又犯妨害公务罪，被判处有期徒刑6个月"}, {"letter": "C", "text": "王某犯抢夺罪被判处有期徒刑4年，执行3年后被假释，于假释期满后5年内又犯故意杀人罪被判处无期徒刑"}, {"letter": "D", "text": "田某犯叛逃罪被判处管制2年，管制期满后20年又犯为境外刺探国家秘密罪，被判处拘役6个月"}], "answer": "A", "explanation": "根据《刑法》第65条规定，一般累犯要求犯罪时已满18周岁。A项张某犯前罪时16岁，不满18周岁，不构成累犯。B项李某前后罪均为故意犯罪，均被判处有期徒刑以上刑罚，后罪发生在前罪刑满释放后4年内（5年以内），且犯罪时已满18周岁，构成累犯。C项王某假释考验期满视为刑罚执行完毕，此后5年内再犯故意犯罪，构成累犯。D项田某前罪为叛逃罪（危害国家安全犯罪），后罪为境外刺探国家秘密罪，构成特别累犯。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 661}, {"num": 663, "batch": "专业基础知识", "type": "single", "stem": "张某为了破坏某商场生意，将无引爆装置的炸弹放置于商场内，并散布某商场有炸弹的消息，后案发。张某的行为构成（）", "options": [{"letter": "A", "text": "投放危险物质罪"}, {"letter": "B", "text": "爆炸罪"}, {"letter": "C", "text": "寻衅滋事罪"}, {"letter": "D", "text": "投放虚假危险物质罪"}], "answer": "D", "explanation": "张某将无引爆装置的炸弹放置于商场内，该炸弹不具有实际引爆功能，属于虚假的危险物质。张某同时散布商场有炸弹的消息，造成社会恐慌，属于投放虚假危险物质的行为，构成投放虚假危险物质罪。由于炸弹无引爆装置，不具有实际爆炸危险，不构成爆炸罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 662}, {"num": 664, "batch": "专业基础知识", "type": "single", "stem": "下列人员可以适用死刑的是（）", "options": [{"letter": "A", "text": "甲在73周岁时与他人因口角发生斗殴，击打对方头部而过失致对方死亡，由于案件一直处于侦查、审查起诉等司法程序，审判该案件时甲已经76周岁"}, {"letter": "B", "text": "乙在17周岁时实施了轮奸行为，该案件审判时乙刚好过了18周岁的生日"}, {"letter": "C", "text": "丙妇女涉嫌爆炸罪，在羁押期间与看守人员自愿发生性关系，案件审判时丙已怀孕"}, {"letter": "D", "text": "丁在75周岁生日的次日将一流浪汉捆绑肢解，现已进入审判程序"}], "answer": "D", "explanation": "根据《刑法》第49条规定，犯罪时不满18周岁的人和审判时怀孕的妇女不适用死刑。审判时已满75周岁的人，不适用死刑，但以特别残忍手段致人死亡的除外。A项甲犯罪时73岁，审判时76岁，且为过失致人死亡，不适用死刑；B项乙犯罪时17岁，不适用死刑；C项丙审判时已怀孕，不适用死刑；D项丁犯罪时75周岁生日的次日，即已满75周岁，且不是以特别残忍手段致人死亡（捆绑肢解属于特别残忍手段），因此可以适用死刑。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 663}, {"num": 665, "batch": "专业基础知识", "type": "single", "stem": "甲意图杀害身材高大的乙，打算先用安眠药使乙昏迷，然后勒乙脖子，致乙窒息死亡。由于甲放的安眠药过多，乙吞食过量安眠药后死亡。对此，下列说法正确的是（）", "options": [{"letter": "A", "text": "甲的预备行为导致了乙的死亡，仅成立故意杀人预备"}, {"letter": "B", "text": "甲虽已着手实行杀人行为但所预定的实行行为（勒乙脖子）并未实施完毕，故只能认定为未实行终了（未遂）"}, {"letter": "C", "text": "甲已着手实行杀人行为，应认定为故意杀人既遂"}, {"letter": "D", "text": "甲的行为是故意杀人预备与过失致人死亡罪的想象竞合犯，应从一重罪论处"}], "answer": "C", "explanation": "甲意图杀害乙，已经着手实施杀人行为（投放安眠药属于杀人行为的实行阶段），虽然甲预定的杀人计划还包括勒乙脖子的步骤，但实际上乙因吞食过量安眠药而死亡。甲的实行行为与乙的死亡结果之间存在因果关系，甲主观上具有杀人故意，应认定为故意杀人罪既遂。犯罪人实际因果发展过程与预想不一致，但不影响既遂的成立。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 664}, {"num": 666, "batch": "专业基础知识", "type": "single", "stem": "甲欲杀害乙，自感力不从心，就极力要求朋友丙一起去。丙则劝阻甲不要杀害乙，甲不听劝阻。丙遂打电话报案，公安民警火速赶到，将正在赶赴乙家途中的甲抓获。甲的行为属于（）", "options": [{"letter": "A", "text": "犯罪预备"}, {"letter": "B", "text": "犯罪中止"}, {"letter": "C", "text": "犯罪未遂"}, {"letter": "D", "text": "犯罪既遂"}], "answer": "A", "explanation": "甲极力要求丙一起去杀害乙，在赶赴乙家途中被抓获。甲已经为实施犯罪准备了工具、制造了条件（纠集同伙、前往犯罪地点），但尚未着手实行犯罪（还未到达乙家开始实施杀人行为），属于犯罪预备。甲被抓获是意志以外的原因导致未能着手，不属于犯罪中止。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 665}, {"num": 667, "batch": "专业基础知识", "type": "single", "stem": "王某蓄意杀害孙某。某天，王某看到孙某正在熬药就偷偷在药中投毒，但孙某是熬药给牛治病，病牛吃药后中毒而死。王某的行为属于（）犯罪形态。", "options": [{"letter": "A", "text": "犯罪预备"}, {"letter": "B", "text": "犯罪中止"}, {"letter": "C", "text": "犯罪既遂"}, {"letter": "D", "text": "犯罪未遂"}], "answer": "D", "explanation": "王某已经着手实施故意杀人行为（在药中投毒），但由于孙某是熬药给牛治病而非自己服用，导致杀人行为未能得逞。这是由于王某意志以外的原因（对犯罪对象情况的认识错误）导致犯罪未得逞，属于犯罪未遂。王某已经着手实行犯罪，不是犯罪预备；犯罪结果未发生不是王某主动放弃，不是犯罪中止。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 666}, {"num": 668, "batch": "专业基础知识", "type": "single", "stem": "下列行为，不构成犯罪的是（）", "options": [{"letter": "A", "text": "甲伪造社会保障卡"}, {"letter": "B", "text": "乙代替他人参加国家司法考试"}, {"letter": "C", "text": "丙利用极端主义胁迫当地村民不让子女参加九年义务教育"}, {"letter": "D", "text": "丁路遇持刀抢劫，在反抗中用捡拾的石块将嫌疑人打成轻伤"}], "answer": "D", "explanation": "A项甲伪造社会保障卡，构成伪造身份证件罪；B项乙代替他人参加国家司法考试，构成代替考试罪；C项丙利用极端主义胁迫村民不让子女参加义务教育，构成利用极端主义破坏法律实施罪；D项丁路遇持刀抢劫，在反抗中将嫌疑人打成轻伤，属于正当防卫。根据《刑法》第20条规定，对正在进行行凶、杀人、抢劫等严重危及人身安全的暴力犯罪采取防卫行为，造成不法侵害人伤亡的，不属于防卫过当，不负刑事责任。丁的行为属于正当防卫，不构成犯罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 667}, {"num": 669, "batch": "专业基础知识", "type": "single", "stem": "甲、乙二人绑架丙，丙家人交付20万元赎金。甲为灭口执意要杀掉丙，乙认为丙家人已交赎金，杀之不义，坚决反对。在甲动手杀丙时，乙与丙联手将甲杀死。乙、丙杀死甲的行为性质属于（）", "options": [{"letter": "A", "text": "正当防卫"}, {"letter": "B", "text": "防卫过当"}, {"letter": "C", "text": "故意杀人罪"}, {"letter": "D", "text": "紧急避险?"}], "answer": "A", "explanation": "甲在绑架丙后执意要杀害丙灭口，此时甲的杀人行为正在进行，严重危及丙的生命安全。乙与丙联手将甲杀死，属于对正在进行的不法侵害（故意杀人行为）进行防卫。根据《刑法》第20条第3款规定，对正在进行行凶、杀人、抢劫、强奸、绑架等严重危及人身安全的暴力犯罪，采取防卫行为造成不法侵害人伤亡的，不属于防卫过当，不负刑事责任。乙、丙的行为属于正当防卫（特殊防卫）。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 668}, {"num": 670, "batch": "专业基础知识", "type": "single", "stem": "关于假释，下列说法正确的是（）", "options": [{"letter": "A", "text": "甲被假释，未经执行机关批准，不得行使言论、出版、结社、游行、示威自由的权利"}, {"letter": "B", "text": "乙因犯故意杀人罪，被判处9年有期徒刑，不得适用假释"}, {"letter": "C", "text": "丙是累犯，因盗窃被判处6年有期徒刑，可以适用假释"}, {"letter": "D", "text": "丁是被假释的犯罪分子，在假释考验期间再犯新罪，不构成累犯"}], "answer": "D", "explanation": "A项错误，被假释的犯罪分子在假释考验期内并不当然被剥夺政治权利，只有被判处附加剥夺政治权利的才受此限制。B项错误，故意杀人罪被判处9年（未达10年以上），可以适用假释。C项错误，累犯不得假释。D项正确，被假释的犯罪分子在假释考验期间再犯新罪，因前罪刑罚尚未执行完毕，不符合累犯'刑罚执行完毕或赦免后'的条件，不构成累犯。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 669}, {"num": 671, "batch": "专业基础知识", "type": "single", "stem": "甲73周岁时因琐事将乙一刀刺死。两年后，某市人民法院对甲故意杀人一案进行审理。关于本案，下列说法正确的是（）", "options": [{"letter": "A", "text": "由于甲在审判的时候已满75周岁，所以可以对甲从轻或者减轻处罚"}, {"letter": "B", "text": "由于甲在犯罪的时候不满75周岁，所以可以对甲适用死刑"}, {"letter": "C", "text": "由于甲犯的是故意杀人罪，所以对甲可以适用死刑"}, {"letter": "D", "text": "甲在审判的时候已满75周岁，杀人手段不是特别残忍，所以对甲不能适用死刑"}], "answer": "D", "explanation": "根据《刑法》第49条第2款规定，审判的时候已满75周岁的人，不适用死刑，但以特别残忍手段致人死亡的除外。这里的'审判的时候已满75周岁'以审判时为准。甲73周岁时杀人，审判时已满75周岁（73+2=75岁），且一刀刺死不属于特别残忍手段致人死亡，因此对甲不能适用死刑。同时根据该条规定，审判时已满75周岁的人可以从轻或减轻处罚。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 670}, {"num": 672, "batch": "专业基础知识", "type": "single", "stem": "甲预谋拍摄乙与卖淫女的裸照，迫使乙交付财物。一日，甲请乙吃饭，叫卖淫女丙相陪。饭后，甲将乙、丙送上车。乙、丙刚到乙宅，乙便被老板电话叫走，丙亦离开。半小时后，甲持相机闯入乙宅发现无人，遂拿走了乙的3万元现金。关于甲的行为性质，下列说法正确的是（）", "options": [{"letter": "A", "text": "构成抢劫未遂与盗窃既遂"}, {"letter": "B", "text": "构成抢劫既遂与盗窃既遂的想象竞合"}, {"letter": "C", "text": "构成敲诈勒索预备与盗窃既遂"}, {"letter": "D", "text": "构成敲诈勒索未遂与盗窃既遂的想象竞合"}], "answer": "C", "explanation": "甲预谋拍摄裸照迫使乙交付财物，属于敲诈勒索的预备行为（尚未着手实行敲诈勒索），因乙、丙离开而未进入实行阶段，构成敲诈勒索预备。甲闯入乙宅拿走3万元现金，属于以秘密手段窃取他人财物，构成盗窃既遂。敲诈勒索处于预备阶段，盗窃已既遂，应以敲诈勒索预备与盗窃既遂论处。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 671}, {"num": 673, "batch": "专业基础知识", "type": "single", "stem": "关于未成年人犯罪，下列说法正确的是（）", "options": [{"letter": "A", "text": "甲（15岁）在诈骗过程中被发现，为抗拒抓捕，当场使用暴力致使被害人重伤、死亡。甲构成抢劫罪"}, {"letter": "B", "text": "乙（15岁）某日深夜潜入一家商场意图窃取财物，但因听到警报声而仓皇逃走。乙构成盗窃罪，但应减轻处罚"}, {"letter": "C", "text": "丙（15岁）将某女强奸后迫使其卖淫。丙的行为不构成犯罪"}, {"letter": "D", "text": "丁（17岁，在校学生）多次强行索要其他学生随身携带的钱财、学习用品，扰乱了学校的秩序，情节严重。丁构成寻衅滋事罪"}], "answer": "D", "explanation": "根据《刑法》第17条规定，已满14周岁不满16周岁的人，犯故意杀人、故意伤害致人重伤或死亡、强奸、抢劫、贩卖毒品、放火、爆炸、投放危险物质罪的，应当负刑事责任。A项15岁甲在诈骗中为抗拒抓捕当场使用暴力致人重伤死亡，根据司法解释应转化为抢劫罪，但未成年人不适用转化型抢劫的规定，应以故意伤害罪或故意杀人罪追究刑事责任。B项15岁乙不构成盗窃罪（盗窃罪不在8种犯罪之列）。C项15岁丙强奸后迫使卖淫，强奸罪在8种犯罪之列，应负刑事责任。D项17岁丁多次强行索要他人财物，情节严重，构成寻衅滋事罪，说法正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 672}, {"num": 674, "batch": "专业基础知识", "type": "single", "stem": "路某（15岁）先后唆使张某（15岁）盗窃他人的财物折价1万余元；唆使李某（19岁）绑架他人勒索财物共计2000余元；唆使王某（15岁）抢劫他人财物共计1500元。路某的行为构成（）", "options": [{"letter": "A", "text": "盗窃罪"}, {"letter": "B", "text": "抢劫罪"}, {"letter": "C", "text": "绑架罪"}, {"letter": "D", "text": "抢劫罪、绑架罪"}], "answer": "B", "explanation": "根据《刑法》第17条规定，已满14周岁不满16周岁的人，只对故意杀人、故意伤害致人重伤或死亡、强奸、抢劫、贩卖毒品、放火、爆炸、投放危险物质罪负刑事责任。路某15岁，其教唆的盗窃行为和绑架行为不在上述8种犯罪之列，不负刑事责任。但其教唆王某抢劫，抢劫罪在8种犯罪之列，路某作为教唆犯应以抢劫罪追究刑事责任。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 673}, {"num": 675, "batch": "专业基础知识", "type": "single", "stem": "下列有关刑罚的说法正确的是（）", "options": [{"letter": "A", "text": "甲（17周岁）因故意伤害罪被判处4年有期徒刑，若甲符合缓刑的条件，则对甲可以适用缓刑"}, {"letter": "B", "text": "乙（76周岁）犯失火罪，对乙可以减轻或者免除处罚"}, {"letter": "C", "text": "丙犯贪污罪，宣判当日是其75周岁生日，可以根据其犯罪情节对其适用死刑"}, {"letter": "D", "text": "丁（78周岁）长年虐待自己的女儿，并用针头、铁钳等工具对其施加暴力，造成其重伤，丁的残忍手段引起公愤，对丁可以适用死刑?"}], "answer": "C", "explanation": "根据《刑法》第49条规定，审判的时候已满75周岁的人，不适用死刑，但以特别残忍手段致人死亡的除外。C项中丙宣判当日是其75周岁生日，根据刑法中年龄计算的通行理解，生日当天视为已满该周岁。但本题标准答案认为C项正确，即认为可以适用死刑，其逻辑在于将宣判当日视为尚未'已满75周岁'（即从生日次日起算已满）。A项正确，未成年人符合缓刑条件的可以适用缓刑；B项错误，已满75周岁过失犯罪应从轻或减轻处罚而非'可以减轻或免除'；D项错误，丁78周岁且虐待致重伤不属于'以特别残忍手段致人死亡'，不适用死刑。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 674}, {"num": 676, "batch": "专业基础知识", "type": "single", "stem": "甲（15周岁）在与他人共同实施拐卖妇女、儿童犯罪中，对被拐卖的幼女实施了奸淫行为。对于甲的行为，下列说法错误的是（）", "options": [{"letter": "A", "text": "应当以强奸罪定罪处罚"}, {"letter": "B", "text": "应当从轻或减轻处罚"}, {"letter": "C", "text": "最高刑只能判处死刑缓期2年执行"}, {"letter": "D", "text": "一般不判处无期徒刑和附加剥夺政治权利"}], "answer": "C", "explanation": "根据《刑法》第17条规定，已满14周岁不满16周岁的人犯强奸罪应负刑事责任。甲15周岁在拐卖儿童过程中奸淫幼女，根据《刑法》第240条规定，拐卖妇女、儿童过程中奸淫被拐卖妇女的，属于拐卖妇女、儿童罪的加重情节。但由于甲不满16周岁，对拐卖妇女、儿童罪不负刑事责任，而对其中的强奸行为应以强奸罪定罪处罚。根据《刑法》第17条和第49条，犯罪时不满18周岁的人不适用死刑（包括死刑立即执行和死缓），因此C项'最高刑只能判处死刑缓期2年执行'说法错误。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 675}, {"num": 677, "batch": "专业基础知识", "type": "single", "stem": "下列关于刑事责任年龄和责任能力的说法，不正确的是（）", "options": [{"letter": "A", "text": "甲，15周岁，抢劫公务人员张某配备的枪支，应当负刑事责任"}, {"letter": "B", "text": "乙，15周岁，实施绑架行为并杀死人质，应当以故意杀人罪追究其刑事责任"}, {"letter": "C", "text": "丙，间歇性精神病人，在精神正常的时候实施故意杀人犯罪行为，应当负刑事责任"}, {"letter": "D", "text": "丁，在实施抢劫犯罪行为时精神正常，但犯罪后患了间歇性精神病，对其不应再追究刑事责任"}], "answer": "D", "explanation": "A项正确，15周岁的人抢劫枪支属于抢劫行为，应负刑事责任。B项正确，15周岁的人实施绑架并杀死人质，应以故意杀人罪追究刑事责任。C项正确，间歇性精神病人在精神正常时犯罪应负刑事责任。D项错误，根据《刑法》第18条规定，精神病人在不能辨认或不能控制自己行为时造成危害结果，经法定程序鉴定确认的，不负刑事责任。但犯罪后患精神病不影响对其犯罪行为的追诉，只是可能中止诉讼程序待其恢复后再行追诉。犯罪时精神正常即应负刑事责任。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 676}, {"num": 678, "batch": "专业基础知识", "type": "single", "stem": "甲趁黑夜持刀抢劫乙价值3000多元的手机，次日听家人说邻居被抢劫手机，遂将手机归还乙，并声称自己是开玩笑。从犯罪构成的观点来看，甲的行为（）", "options": [{"letter": "A", "text": "属于犯罪未遂"}, {"letter": "B", "text": "属于犯罪中止"}, {"letter": "C", "text": "属于犯罪既遂"}, {"letter": "D", "text": "可以不认为是犯罪"}], "answer": "C", "explanation": "甲趁黑夜持刀抢劫乙的手机，已经以暴力手段劫取财物，犯罪已经既遂。抢劫罪以行为人取得财物为既遂标准。甲次日将手机归还并声称是开玩笑，属于犯罪既遂后的退赃行为，不影响犯罪既遂的成立。犯罪形态一旦确定就不会再发生变化，既遂后不可能再转化为中止或未遂。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 677}, {"num": 679, "batch": "专业基础知识", "type": "single", "stem": "下列选项中，可以适用死刑的是（）", "options": [{"letter": "A", "text": "甲18岁生日当天杀死与其同居的女友后逃跑，23岁被抓获审判"}, {"letter": "B", "text": "乙18岁生日第二天与刘某发生口角后将刘某杀死"}, {"letter": "C", "text": "丙（女）因涉嫌故意杀人罪被羁押，为逃避被判处死刑，羁押期间与律师通谋，在律师会见时发生性关系而怀孕"}, {"letter": "D", "text": "丁因涉嫌故意杀人罪被提起公诉，审判期间自然流产"}], "answer": "B", "explanation": "根据《刑法》第49条规定，犯罪时不满18周岁的人和审判时怀孕的妇女不适用死刑。A项甲18岁生日当天犯罪，按法律规定'不满18周岁'不包括18周岁生日当天（生日当天视为已满），但司法实践中18岁生日当天仍视为不满18周岁，不适用死刑。B项乙18岁生日第二天犯罪，已满18周岁，可以适用死刑。C项丙羁押期间怀孕，审判时怀孕的妇女不适用死刑（无论怀孕原因如何）。D项丁审判期间自然流产，根据司法解释，审判时怀孕的妇女包括在羁押期间流产的情形，不适用死刑。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 678}, {"num": 680, "batch": "专业基础知识", "type": "single", "stem": "下列关于教唆犯的说法正确的是（）", "options": [{"letter": "A", "text": "甲教唆乙实施杀害丙的行为，结果乙口头允诺，但实际只是去丙家盗窃了一台彩电，则甲不构成教唆犯"}, {"letter": "B", "text": "甲、乙共同约定实施盗窃行为，在盗窃得逞之后，甲临时起意，向乙使了个眼色，乙心领神会放了把火毁灭现场，致使大量财物被烧毁，则甲构成放火罪的教唆犯"}, {"letter": "C", "text": "甲已经打算实施杀人行为，但是还在犹豫之中，乙见状给甲打气，鼓励甲实施，结果甲实施了故意杀人行为，则乙构成教唆犯"}, {"letter": "D", "text": "甲对乙说：“你去犯罪吧！”结果乙实施了抢劫行为，则甲构成教唆"}], "answer": "B", "explanation": "A项错误，甲教唆乙杀人，乙实施了盗窃，甲在盗窃范围内与乙成立共同犯罪，甲仍构成教唆犯（在盗窃罪范围内）。B项正确，甲临时起意向乙使眼色，乙心领神会放火，甲以默示方式教唆乙实施放火行为，构成放火罪的教唆犯。C项错误，甲已有犯罪意图，乙只是强化其犯意，属于帮助犯（精神帮助）而非教唆犯（教唆犯要求使本无犯意的人产生犯意）。D项错误，甲的话过于笼统，没有指向具体犯罪，不构成教唆犯。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 679}, {"num": 681, "batch": "专业基础知识", "type": "single", "stem": "甲依法配置猎枪，某日乙向甲借枪，甲问干什么用，乙说因与丙有仇，又打不过丙，所以借枪杀丙，甲碍于情面，将猎枪借与乙，乙持猎枪将丙杀死。关于本案，下列说法正确的是（）", "options": [{"letter": "A", "text": "甲构成非法出借枪支罪"}, {"letter": "B", "text": "甲、乙构成故意杀人罪的共犯"}, {"letter": "C", "text": "甲构成过失致人死亡罪"}, {"letter": "D", "text": "甲无杀死丙的故意，所以不负刑事责任"}], "answer": "B", "explanation": "甲明知乙借枪是为了杀丙，仍碍于情面将猎枪借给乙，甲主观上对乙杀丙持放任态度（间接故意），客观上为乙的杀人行为提供了工具帮助。甲、乙构成故意杀人罪的共同犯罪，甲为帮助犯。虽然甲没有直接杀人的目的，但明知乙要杀人仍提供枪支，具有帮助杀人的故意，应以故意杀人罪共犯论处。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 680}, {"num": 682, "batch": "专业基础知识", "type": "single", "stem": "甲有外遇，欲杀其妻乙。某日，甲将毒药拌入菜中意图杀乙。因久等乙未归且又惧怕法律制裁，甲遂打消杀人恶念，将菜倒掉。甲的行为属于（）", "options": [{"letter": "A", "text": "犯罪预备"}, {"letter": "B", "text": "犯罪预备阶段的犯罪中止"}, {"letter": "C", "text": "犯罪未遂"}, {"letter": "D", "text": "犯罪实行阶段的犯罪中止"}], "answer": "B", "explanation": "甲将毒药拌入菜中，已经为实施杀人做了准备，但乙尚未回来，甲尚未着手实行杀人行为（投毒行为尚未到达被害人可以接触的程度）。甲因惧怕法律制裁而主动打消杀人恶念，将菜倒掉，属于在犯罪预备阶段自动放弃犯罪，构成犯罪预备阶段的犯罪中止。关键在于甲是自动放弃而非被迫放弃。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 681}, {"num": 683, "batch": "专业基础知识", "type": "single", "stem": "甲给乙5万元让乙“教训”一下丁。乙收钱后，给丙2万元让丙“教训”一下丁。后甲又后悔便告诉乙取消行动。乙说知道了，但未告诉丙。丙仍按照原计划将丁打成重伤。甲的行为属于（）", "options": [{"letter": "A", "text": "犯罪预备"}, {"letter": "B", "text": "犯罪中止"}, {"letter": "C", "text": "犯罪既遂"}, {"letter": "D", "text": "犯罪未遂"}], "answer": "C", "explanation": "甲给乙5万元让乙'教训'丁，乙又转托丙。甲虽然后悔并告诉乙取消行动，但乙未告知丙，丙仍将丁打成重伤。在共同犯罪中，共犯要成立犯罪中止，不仅需要自己放弃犯罪，还必须有效阻止其他共犯继续实施犯罪或消除自己先前行为对犯罪的作用。甲虽然向乙表示取消，但未有效阻止丙的犯罪行为，犯罪结果仍然发生，甲的行为构成犯罪既遂。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 682}, {"num": 684, "batch": "专业基础知识", "type": "single", "stem": "药店营业员李某与王某有仇。某日王某之妻到药店买药为王某治病，李某将一包砒霜混在药中交给王某妻子。李某于第二天到王某家欲取回砒霜，而王某谎称药已服完。李某见王某没有什么异常，就没有将真相告诉王某。几天后，王某因服用李某提供的混有砒霜的药而死亡。李某的行为属于（）", "options": [{"letter": "A", "text": "犯罪中止"}, {"letter": "B", "text": "犯罪既遂"}, {"letter": "C", "text": "犯罪未遂"}, {"letter": "D", "text": "犯罪预备"}], "answer": "B", "explanation": "李某将砒霜混入药中交给王某妻子，已经实施了投毒行为，犯罪已经着手。李某次日想要取回砒霜，说明其有中止犯罪的意思，但当王某谎称药已服完时，李某见王某没有异常就未将真相告知王某，未能有效阻止犯罪结果的发生。根据《刑法》第24条规定，犯罪中止要求自动放弃犯罪或自动有效地防止犯罪结果发生。李某未能有效防止结果发生，王某最终死亡，李某的行为构成犯罪既遂。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 683}, {"num": 685, "batch": "专业基础知识", "type": "single", "stem": "李某与王某共谋盗窃汽车，李某将盗车所需的钥匙交给王某。但李某后来向王某表明放弃犯罪之意，让王某归还钥匙。王某对李某说“你等几分钟，我用你的钥匙配制一把后再还给你”，之后李某要回了自己原来提供的钥匙。事后王某利用自己配制的钥匙盗窃了汽车（价值6万元）。关于本案，下列说法正确的是（）", "options": [{"letter": "A", "text": "李某的行为属于盗窃中止"}, {"letter": "B", "text": "李某的行为属于盗窃预备"}, {"letter": "C", "text": "李某的行为属于盗窃未遂"}, {"letter": "D", "text": "李某与王某构成盗窃罪（既遂）的共犯"}], "answer": "D", "explanation": "在共同犯罪中，共犯要成立犯罪中止，必须自动放弃犯罪并有效消除自己先前行为对共同犯罪的作用。李某虽然向王某表明放弃犯罪并要回钥匙，但王某在归还前已用该钥匙配制了一把，李某的钥匙实质上已被复制，李某未能有效消除自己提供钥匙对盗窃行为的帮助作用。最终王某利用配制的钥匙完成了盗窃，李某的先前帮助行为与犯罪结果之间仍有因果关系，因此李某不能成立中止，应与王某一起构成盗窃罪既遂的共犯。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 684}, {"num": 686, "batch": "专业基础知识", "type": "single", "stem": "陈某教唆张某编造、故意传播虚假恐怖信息，后陈某感到害怕，劝说张某取消该行为。张某不听，继续实施该行为，在社会上造成极大恐慌。陈某的行为（）", "options": [{"letter": "A", "text": "构成编造、故意传播虚假信息罪（既遂）"}, {"letter": "B", "text": "构成编造、故意传播虚假信息罪（未遂）"}, {"letter": "C", "text": "构成传授犯罪方法罪"}, {"letter": "D", "text": "不构成犯罪??"}], "answer": "A", "explanation": "陈某教唆张某编造、故意传播虚假恐怖信息，张某实施了该行为并造成极大恐慌。根据共同犯罪理论，教唆犯的犯罪形态取决于被教唆者是否实施了犯罪以及实施的结果。张某已经完成了编造、故意传播虚假恐怖信息的行为并造成严重后果（既遂），陈某作为教唆犯也应认定为既遂。陈某虽然事后劝说张某取消，但未能阻止犯罪结果的发生，不成立中止。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 685}, {"num": 687, "batch": "专业基础知识", "type": "single", "stem": "甲欲杀乙，将乙打倒在地，掐住乙的脖子致乙深度昏迷。30分钟后，甲发现乙未死，便举刀刺乙，第一刀刺中乙的腹部，第二刀扎在乙的皮带上，刺第三刀时刀柄折断。甲长叹“你命太大，整不死你，我服气了”，遂将乙送医，乙得以保命。经查，第一刀已致乙重伤。关于甲犯罪形态的认定，下列说法正确的是（）", "options": [{"letter": "A", "text": "构成故意杀人罪（未遂）"}, {"letter": "B", "text": "构成故意杀人罪（中止）"}, {"letter": "C", "text": "构成故意伤害罪（既遂）"}, {"letter": "D", "text": "构成故意杀人罪（不能犯）"}], "answer": "A", "explanation": "甲将乙打倒掐脖子致乙深度昏迷，又举刀刺乙，因刀柄折断而未能刺死乙。甲最终放弃是因为刀柄折断这一意志以外的原因（客观上无法继续实施），而非自动放弃犯罪。甲虽然将乙送医，但这是在犯罪行为已经无法继续之后的行为，不属于自动放弃。甲已经着手实施故意杀人行为，因意志以外原因未得逞，构成故意杀人罪未遂。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 686}, {"num": 688, "batch": "专业基础知识", "type": "single", "stem": "甲开办一间小汽车修理店，因修理一进口轿车缺零配件，便于晚间在一停车场将同一型号小轿车的1个备用轮胎（价值1200元）和发动机（价值5万元）拆下盗走。甲的行为（）", "options": [{"letter": "A", "text": "构成盗窃罪和破坏交通工具罪，数罪并罚"}, {"letter": "B", "text": "构成盗窃罪和破坏交通工具罪，从一重罪即破坏交通工具罪定罪处罚"}, {"letter": "C", "text": "只构成破坏交通工具罪"}, {"letter": "D", "text": "只构成盗窃罪"}], "answer": "D", "explanation": "破坏交通工具罪要求破坏行为足以使交通工具发生倾覆、毁坏危险，危害公共安全。甲盗走的是停放在停车场的同一型号小轿车的备用轮胎和发动机，该车辆并非正在使用中的交通工具，且拆走轮胎和发动机不会使该交通工具在运行中发生倾覆危险（因为车辆根本不会启动运行），不危害公共安全，不构成破坏交通工具罪。甲以非法占有为目的秘密窃取他人财物，构成盗窃罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 687}, {"num": 689, "batch": "专业基础知识", "type": "single", "stem": "下列行为成立犯罪中止的是（）", "options": [{"letter": "A", "text": "甲放火之后，喊了一声“救火啊”，随后立即离开了现场，大火被群众扑灭"}, {"letter": "B", "text": "乙对仇人王某猛砍10刀后离开现场。1小时后，乙为寻找、销毁犯罪工具回到现场，见王某仍然没有死亡，但极其可怜，即将其送到医院治疗，后王某因伤势过重死亡"}, {"letter": "C", "text": "丙为了发泄对社会的不满，将一块巨石搬上铁轨，在火车即将到来之前，因被铁路工人发现而及时将石头搬开"}, {"letter": "D", "text": "丁一直想杀害胡某，某日向胡某的食物里投放了毒药，胡某食用之后痛苦万分，丁见状顿生悔意，立即拨打急救电话，将被害人送往医院，在医生的救治下，胡某没有死亡，但终生残疾"}], "answer": "D", "explanation": "A项甲放火后喊'救火啊'但随即离开现场，未积极有效参与灭火，不能认定为有效防止结果发生，不构成中止。B项乙砍完王某后离开，1小时后返回将王某送医，但王某最终因伤势过重死亡，未能有效防止结果发生，不构成中止。C项丙搬巨石上铁轨，在火车到来前被铁路工人发现搬开，丙并非自动放弃，而是被他人发现制止，不构成中止。D项丁投放毒药后见胡某痛苦，顿生悔意，立即拨打急救电话并送医，胡某未死亡，丁自动有效地防止了死亡结果发生，构成犯罪中止。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 688}, {"num": 690, "batch": "专业基础知识", "type": "single", "stem": "某国有公司总经理甲将本公司盈利的业务交由其妹妹乙经营，乙从中获利100万元。甲的行为（）", "options": [{"letter": "A", "text": "构成非法经营同类营业罪"}, {"letter": "B", "text": "构成为亲友非法牟利罪"}, {"letter": "C", "text": "构成职务侵占罪"}, {"letter": "D", "text": "构成贪污罪"}], "answer": "B", "explanation": "根据《刑法》第166条规定，国有公司、企业、事业单位的工作人员，利用职务便利，将本单位的盈利业务交由自己的亲友进行经营，使国家利益遭受重大损失的，构成为亲友非法牟利罪。甲作为国有公司总经理，将公司盈利业务交由妹妹乙经营，乙获利100万元，使国家利益遭受重大损失，符合为亲友非法牟利罪的构成要件。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 689}, {"num": 691, "batch": "专业基础知识", "type": "single", "stem": "甲欠乙1800元人民币，经乙多次催讨，甲提议用其购得的（无法查证）假人民币8000元偿还，乙表示同意并收下。下列说法正确的是（）", "options": [{"letter": "A", "text": "甲、乙的行为均构成持有、使用假币罪"}, {"letter": "B", "text": "甲的行为构成使用假币罪，乙的行为构成持有假币罪"}, {"letter": "C", "text": "甲的行为构成出售假币罪，乙的行为构成购买假币罪"}, {"letter": "D", "text": "甲的行为构成非法经营罪，乙的行为构成掩饰、隐瞒犯罪所得罪"}], "answer": "C", "explanation": "甲以假币8000元偿还1800元债务，实质是以假币换取真币（免除债务），属于出售假币的行为。乙明知是假币而同意以8000元假币抵偿1800元真币债务，相当于以1800元的价格购买8000元假币，构成购买假币罪。甲的行为构成出售假币罪，乙的行为构成购买假币罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 690}, {"num": 692, "batch": "专业基础知识", "type": "single", "stem": "甲将5万元假币从A地带往B地，刚到B地便发现有民警盘查，随即点火烧毁携带的假币。甲的行为（）", "options": [{"letter": "A", "text": "构成运输假币罪（中止）"}, {"letter": "B", "text": "构成运输假币罪（未遂）"}, {"letter": "C", "text": "构成运输假币罪（既遂）"}, {"letter": "D", "text": "不构成犯罪"}], "answer": "C", "explanation": "甲将5万元假币从A地带往B地，在运输过程中已经完成了假币的空间位移，运输假币罪已经既遂。到达B地后发现民警盘查而烧毁假币，属于既遂后的处分行为，不影响既遂的成立。犯罪形态一旦确定就不会再发生变化，既遂后不可能转化为中止或未遂。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 691}, {"num": 693, "batch": "专业基础知识", "type": "single", "stem": "曹某是某鞋业股份有限公司(已上市)的副总经理，其舅舅石某因白手起家做生意缺乏资金，要向某银行贷款，但由于没有适当的担保，也明显没有清偿能力，银行拒绝放贷，于是曹某操纵其所在公司为石某提供了价值150万元的贷款担保。最后因为石某经商破产，该公司遭受重大损失。曹某的行为（）", "options": [{"letter": "A", "text": "构成国有公司、企业、事业单位人员滥用职权罪"}, {"letter": "B", "text": "构成背信损害上市公司利益罪"}, {"letter": "C", "text": "构成违法运用资金罪"}, {"letter": "D", "text": "不构成犯罪"}], "answer": "B", "explanation": "根据《刑法》第169条之一规定，上市公司的董事、监事、高级管理人员违背对公司的忠实义务，利用职务便利，操纵上市公司无偿或以明显不合理条件为他人提供担保，致使上市公司利益遭受重大损失的，构成背信损害上市公司利益罪。曹某作为上市公司副总经理，操纵公司为明显无清偿能力的舅舅提供担保，致使公司遭受重大损失，构成背信损害上市公司利益罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 692}, {"num": 694, "batch": "专业基础知识", "type": "single", "stem": "某国有大型企业财务总监张某利用职务之便，擅自使用该国有公司印章并以该国有公司名义为其朋友王某作担保，帮王某向某银行贷款200万美元，后王某无法偿还贷款，银行向法院起诉，最终法院判决该国有企业代为偿还贷款，致使该国有企业损失200多万美元。张某的行为构成（）", "options": [{"letter": "A", "text": "国有公司、企业、事业单位人员失职罪"}, {"letter": "B", "text": "为亲友非法牟利罪"}, {"letter": "C", "text": "贷款诈骗罪"}, {"letter": "D", "text": "国有公司、企业、事业单位人员滥用职权罪"}], "answer": "D", "explanation": "根据《刑法》第168条规定，国有公司、企业的工作人员，滥用职权，造成国有公司、企业破产或严重损失，致使国家利益遭受重大损失的，构成国有公司、企业、事业单位人员滥用职权罪。张某作为国有大型企业财务总监，利用职务便利擅自使用公司印章为他人担保，致使企业损失200多万美元，属于滥用职权行为，构成国有公司、企业、事业单位人员滥用职权罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 693}, {"num": 695, "batch": "专业基础知识", "type": "single", "stem": "某粉条厂的粉条经常被偷。该厂负责人与雇工商量后将“1605”农药洒在粉条上，当晚，8名村民前去盗窃，食用洒有农药的粉条后中毒，其中2人死亡。该厂负责人及雇工的行为构成（）", "options": [{"letter": "A", "text": "过失投放危险物质罪"}, {"letter": "B", "text": "投放危险物质罪"}, {"letter": "C", "text": "故意伤害罪"}, {"letter": "D", "text": "过失致人死亡罪"}], "answer": "B", "explanation": "粉条厂负责人与雇工将农药洒在粉条上，明知村民会来盗窃并食用，对村民中毒的结果持放任态度（间接故意）。农药洒在粉条上，村民食用后中毒，该行为危害了不特定多数人的生命健康安全（来偷粉条的人数不确定），构成投放危险物质罪。虽然目的是防止粉条被偷，但手段行为危害了公共安全。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 694}, {"num": 696, "batch": "专业基础知识", "type": "single", "stem": "某国有企业经理甲以明显低于市场的价格向其妹妹乙经营的公司销售畅销白酒一批，乙从而获利100万元。对于甲的行为，下列说法正确的是（）", "options": [{"letter": "A", "text": "构成非法经营同类营业罪"}, {"letter": "B", "text": "构成为亲友非法牟利罪"}, {"letter": "C", "text": "构成职务侵占罪"}, {"letter": "D", "text": "构成滥用职权罪"}], "answer": "B", "explanation": "根据《刑法》第166条规定，国有公司、企业的工作人员，利用职务便利，以明显高于市场的价格向自己的亲友经营管理的单位采购商品或以明显低于市场的价格向自己的亲友经营管理的单位销售商品，使国家利益遭受重大损失的，构成为亲友非法牟利罪。甲以明显低于市场的价格向妹妹乙的公司销售白酒，使国家利益遭受重大损失，构成为亲友非法牟利罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 695}, {"num": 697, "batch": "专业基础知识", "type": "single", "stem": "甲将盗窃来的5万元假币用于支付殴打他人（轻微伤）后的赔偿金。甲的行为（）", "options": [{"letter": "A", "text": "构成持有假币罪"}, {"letter": "B", "text": "构成盗窃罪"}, {"letter": "C", "text": "构成使用假币罪"}, {"letter": "D", "text": "构成盗窃罪和使用假币罪"}], "answer": "D", "explanation": "甲盗窃假币5万元，构成盗窃罪（假币作为违禁品也可以成为盗窃罪的对象，其具有黑市价值）。甲将盗窃来的假币用于支付赔偿金，属于将假币作为支付手段投入流通，构成使用假币罪。盗窃罪和使用假币罪是两个独立的犯罪行为，应以盗窃罪和使用假币罪数罪并罚。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 696}, {"num": 698, "batch": "专业基础知识", "type": "single", "stem": "甲是某国政府派到我国进行设备采购的公职人员，甲告诉国内某公司老板乙说：“你给我好处，我们所需的设备就都买你的。”乙遂给甲5000元人民币，甲使该国政府从乙处购买设备花费100万元，乙获利10万元。下列选项正确的是（）", "options": [{"letter": "A", "text": "甲构成受贿罪"}, {"letter": "B", "text": "甲构成非国家工作人员受贿罪"}, {"letter": "C", "text": "乙构成对外国公职人员行贿罪"}, {"letter": "D", "text": "乙不构成犯罪"}], "answer": "D", "explanation": "甲是外国政府公职人员，不属于我国刑法中受贿罪的主体（受贿罪主体为国家工作人员）。乙给甲5000元好处费，使该国政府从乙处购买设备。根据我国《刑法》第164条之一规定，为谋取不正当商业利益，给予外国公职人员以财物的，构成对外国公职人员行贿罪。但该罪要求'为谋取不正当商业利益'，本题中乙只是获得了正常交易机会，获利10万元是否属于不正当利益存疑。根据答案，乙不构成犯罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 697}, {"num": 699, "batch": "专业基础知识", "type": "single", "stem": "飞达公司推销员甲为了让腾飞公司购买飞达公司生产的汽车，送给腾飞公司负责采购的乙购物卡价值2万元，后乙使腾飞公司采购飞达公司的汽车2辆。甲的行为（）", "options": [{"letter": "A", "text": "构成行贿罪"}, {"letter": "B", "text": "不构成犯罪"}, {"letter": "C", "text": "构成对非国家工作人员行贿罪"}, {"letter": "D", "text": "构成不正当竞争罪"}], "answer": "C", "explanation": "根据《刑法》第164条规定，为谋取不正当利益，给予公司、企业或者其他单位的工作人员以财物，数额较大的，构成对非国家工作人员行贿罪。飞达公司推销员甲为使腾飞公司购买其产品，向腾飞公司负责采购的乙（非国家工作人员）送价值2万元购物卡，属于对非国家工作人员行贿，构成对非国家工作人员行贿罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 698}, {"num": 700, "batch": "专业基础知识", "type": "single", "stem": "某医药公司负责采购的职员甲在药品采购过程中，药品生产商乙为了让甲采购其生产的药品而为甲的房产进行了装修，为此乙花费6万元，甲便采购了乙生产的药品。对于甲的行为定性正确的是（）", "options": [{"letter": "A", "text": "构成受贿罪"}, {"letter": "B", "text": "不构成犯罪"}, {"letter": "C", "text": "构成非国家工作人员受贿罪"}, {"letter": "D", "text": "构成不正当竞争罪"}], "answer": "C", "explanation": "根据《刑法》第163条规定，公司、企业或者其他单位的工作人员利用职务上的便利，索取他人财物或者非法收受他人财物，为他人谋取利益，数额较大的，构成非国家工作人员受贿罪。医药公司采购职员甲（非国家工作人员）在药品采购过程中，非法收受药品生产商乙为其房产装修花费6万元，为乙谋取利益（采购其药品），构成非国家工作人员受贿罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 699}, {"num": 701, "batch": "专业基础知识", "type": "single", "stem": "甲是某学校负责采购教材的后勤人员，新学期开始前甲告诉某书店的老板乙说：“你给我5万元好处费，我们学校的教材就都买你的。”乙遂给甲5万元，甲使该学校从乙处购买教材花费100万元，乙获利30万元。甲的行为（）", "options": [{"letter": "A", "text": "构成受贿罪"}, {"letter": "B", "text": "构成非国家工作人员受贿罪"}, {"letter": "C", "text": "构成贪污罪"}, {"letter": "D", "text": "不构成犯罪"}], "answer": "B", "explanation": "根据《刑法》第163条，非国家工作人员利用职务上的便利，索取他人财物或者非法收受他人财物，为他人谋取利益，数额较大的，构成非国家工作人员受贿罪。甲作为学校（非国家机关）的采购人员，不属于国家工作人员，其利用采购教材的职务便利向书店索取5万元好处费，符合非国家工作人员受贿罪的构成要件。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 700}, {"num": 702, "batch": "专业基础知识", "type": "single", "stem": "某邮局工作人员王某为了得到李某赠送的淫秽光碟，明知李某长期从境外将大量淫秽物品夹在行李中托运入境销售而提供帮助。王某的行为构成（）", "options": [{"letter": "A", "text": "传播淫秽物品罪"}, {"letter": "B", "text": "走私淫秽物品罪"}, {"letter": "C", "text": "渎职罪"}, {"letter": "D", "text": "走私普通货物罪"}], "answer": "B", "explanation": "根据《刑法》第152条及相关司法解释，明知他人走私淫秽物品而为其提供帮助的，以走私淫秽物品罪的共犯论处。王某明知李某长期从境外走私淫秽物品入境销售，仍为其提供帮助，主观上具有走私淫秽物品的故意，客观上实施了帮助行为，构成走私淫秽物品罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 701}, {"num": 703, "batch": "专业基础知识", "type": "single", "stem": "王某走私淫秽物品到深圳后，向李某贩卖淫秽光碟80张用于播放经营。王某的行为构成（）", "options": [{"letter": "A", "text": "传播淫秽物品罪"}, {"letter": "B", "text": "走私淫秽物品罪"}, {"letter": "C", "text": "组织播放淫秽音像制品罪"}, {"letter": "D", "text": "贩卖淫秽物品牟利罪"}], "answer": "B", "explanation": "根据刑法理论，走私淫秽物品后又进行贩卖的，属于牵连犯，前行为（走私）与后行为（贩卖）之间存在手段与目的的牵连关系，应从一重罪处断。由于走私淫秽物品罪的法定刑重于贩卖淫秽物品牟利罪，故以走私淫秽物品罪论处。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 702}, {"num": 704, "batch": "专业基础知识", "type": "single", "stem": "下列行为中，构成签订、履行合同失职被骗罪的是（）", "options": [{"letter": "A", "text": "某国有公司直接负责的主管人员在不了解对方资信的情况下，为其提供经济担保，致使国家利益遭受重大损失"}, {"letter": "B", "text": "某民营企业负责人未经调查，盲目同无资金来源的另一方进行购销活动而被诈骗，单位损失严重"}, {"letter": "C", "text": "某事业单位工作人员对供方提供的质次价高的产品，未经检查而自行同意接受货物，给国家带来重大损失"}, {"letter": "D", "text": "某国家机关工作人员与对方签订购销合同，但由于意外事件的发生，致使合同目的不能实现，国家利益遭受重大损失"}], "answer": "A", "explanation": "根据《刑法》第167条，签订、履行合同失职被骗罪的主体为国有公司、企业、事业单位直接负责的主管人员。A项中某国有公司直接负责的主管人员在不了解对方资信的情况下提供担保，致使国家利益遭受重大损失，符合该罪的主体和客观要件。B项主体为民营企业负责人，不符合主体要求；C项主体为事业单位工作人员而非直接负责的主管人员；D项系意外事件，不存在失职行为。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 703}, {"num": 705, "batch": "专业基础知识", "type": "single", "stem": "甲为中国银行工作人员，工作期间利用职务上的便利窃取了大量信用卡信息，并以1万元的价格将其出卖给乙。甲的行为（）", "options": [{"letter": "A", "text": "构成窃取信用卡信息罪与非法提供信用卡信息罪，应数罪并罚"}, {"letter": "B", "text": "构成窃取、非法提供信用卡信息罪"}, {"letter": "C", "text": "不构成犯罪"}, {"letter": "D", "text": "构成窃取信用卡信息罪与非法提供信用卡信息罪，择一重罪处罚"}], "answer": "B", "explanation": "根据《刑法》第177条之一，银行工作人员利用职务便利窃取信用卡信息后又非法提供的，窃取行为与提供行为属于同一犯罪过程中的不可分割的行为，刑法将其规定为选择性罪名——窃取、非法提供信用卡信息罪，不实行数罪并罚，直接以一罪定罪处罚。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 704}, {"num": 706, "batch": "专业基础知识", "type": "single", "stem": "客户王某找到银行行长张某，称其向一家房地产公司借款1000万元，需要银行作担保。张某想利用这笔巨款在他所在的银行流转的机会，提升业务量，于是便为王某和房地产公司之间的借款办理了银行担保函。结果，王某获得巨款后携款潜逃。张某构成（）", "options": [{"letter": "A", "text": "滥用职权罪"}, {"letter": "B", "text": "违法发放贷款罪"}, {"letter": "C", "text": "违规出具金融票证罪"}, {"letter": "D", "text": "违法运用资金罪"}], "answer": "C", "explanation": "根据《刑法》第188条，银行或者其他金融机构的工作人员违反规定，为他人出具信用证或者其他保函、票据、存单、资信证明，造成较大损失的，构成违规出具金融票证罪。张某作为银行行长，违反规定为王某办理银行担保函，属于违规出具金融票证的行为，最终导致巨额损失，构成违规出具金融票证罪。该罪与违法发放贷款罪的区别在于，担保函不属于贷款行为。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 705}, {"num": 707, "batch": "专业基础知识", "type": "single", "stem": "某市国税分局副局长王某因投资房地产开发需要资金，便找到该市某银行某营业所主任邹某，要求贷款5000万元。邹某告知王某只有质押贷款他才有权放贷，王某遂提出用该国税分局在该营业所的存款账户作质押。邹某明知公款账户不能作为个人贷款的质押，仍表示同意并叫信贷员填写了借款借据，在借款借据上注明“以国税局存款为质押”。当日王某即在营业所得到贷款5000万元。邹某构成（）", "options": [{"letter": "A", "text": "违法发放贷款罪"}, {"letter": "B", "text": "挪用公款罪"}, {"letter": "C", "text": "挪用资金罪"}, {"letter": "D", "text": "违法运用资金罪?"}], "answer": "A", "explanation": "根据《刑法》第186条，银行工作人员违反国家规定发放贷款，数额巨大或者造成重大损失的，构成违法发放贷款罪。邹某作为银行营业所主任，明知公款账户不能作为个人贷款的质押，仍违反规定向王某发放5000万元贷款，属于违法发放贷款的行为，构成违法发放贷款罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 706}, {"num": 708, "batch": "专业基础知识", "type": "single", "stem": "刘某是某证券交易所从业人员，为了获利，其利用自己的特殊身份，故意将某上市公司所谓的“重大利好消息”告知了并不知情的张某，并怂恿张某进行传播。在所谓的“重大利好消息”的刺激下该上市公司股票价格出现了连续上涨。下列说法正确的是（）", "options": [{"letter": "A", "text": "刘某虽然编造了虚假信息，但并未进行传播，因此不构成犯罪"}, {"letter": "B", "text": "刘某无传播的行为，但其怂恿他人传播，其可构成编造并传播证券交易虚假信息罪"}, {"letter": "C", "text": "刘某编造虚假信息后故意要他人传播，应认定其编造且加以传播，但因其身份特殊，按照特别法优于普通法的原则，构成诱骗投资者买卖证券罪"}, {"letter": "D", "text": "张某事实上从事了传播虚假信息的活动，但该信息不是其本人编造的，因此，不构成编造并传播证券交易虚假信息罪，但应构成诱骗投资者买卖证券罪"}], "answer": "C", "explanation": "根据《刑法》第181条，证券交易所从业人员故意编造并传播虚假证券交易信息，诱骗投资者买卖证券的，构成诱骗投资者买卖证券罪。刘某作为证券交易所从业人员，虽然自己未直接传播，但怂恿不知情的张某代为传播，属于利用他人实施传播行为，应认定其编造且加以传播。因其身份为证券交易所从业人员，属于特殊主体，按照特别法优于普通法的原则，应认定为诱骗投资者买卖证券罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 707}, {"num": 709, "batch": "专业基础知识", "type": "single", "stem": "甲听说某上市公司主营业务即将发生重大改变，公司盈利能力将大幅增强，正好甲持有该公司股票，于是甲通过互联网大肆宣扬，致使该公司股票大幅上涨，甲及时抛出所持股票，获利颇丰，后该公司对该消息予以了否认。对甲的行为认定正确的是（）", "options": [{"letter": "A", "text": "甲传播的信息属于内幕信息，构成内幕交易罪"}, {"letter": "B", "text": "甲的行为事实上导致了众多投资者购买该股票，构成诱骗投资者买卖证券罪"}, {"letter": "C", "text": "甲的行为导致了该股票价格出现重大波动，构成操纵证券市场罪"}, {"letter": "D", "text": "甲传播道听途说的消息，该消息并不是其自己编造的，因此不构成编造并传播证券交易虚假信息罪"}], "answer": "D", "explanation": "编造并传播证券交易虚假信息罪要求行为人自己编造虚假信息并加以传播。甲传播的消息系道听途说所得，并非其本人编造，不符合该罪的构成要件。同时，甲不属于内幕信息的知情人员，其传播的内容也不属于法定内幕信息，不构成内幕交易罪。甲的行为虽然客观上导致股票价格波动，但不构成操纵证券市场罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 708}, {"num": 710, "batch": "专业基础知识", "type": "single", "stem": "甲是某律师事务所打字员，在打印某上市公司的法律意见书时，获知该公司的股票将大幅上扬，于是赶紧购买了数万股，获利400万元。甲的行为（）", "options": [{"letter": "A", "text": "不构成犯罪"}, {"letter": "B", "text": "构成内幕交易罪"}, {"letter": "C", "text": "构成侵犯商业秘密罪"}, {"letter": "D", "text": "构成利用未公开信息交易罪"}], "answer": "B", "explanation": "根据《刑法》第180条，证券、期货交易内幕信息的知情人员在涉及证券的发行、交易或者其他对证券的价格有重大影响的信息尚未公开前，买入或者卖出该证券，情节严重的，构成内幕交易罪。甲作为律师事务所打字员，在打印法律意见书过程中获知了尚未公开的重大信息，属于非法获取内幕信息的人员，据此进行交易获利400万元，构成内幕交易罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 709}, {"num": 711, "batch": "专业基础知识", "type": "single", "stem": "某公司发给员工每人400元的某商场购物代金券作为过节福利。职工甲觉得太少，于是私刻商场的公章又伪造了面额400元的代金券100余张，留一半准备自己使用，其余送给亲戚和朋友使用。甲的行为构成（）", "options": [{"letter": "A", "text": "伪造公司债券罪"}, {"letter": "B", "text": "伪造金融票证罪"}, {"letter": "C", "text": "诈骗罪"}, {"letter": "D", "text": "伪造公司印章罪"}], "answer": "D", "explanation": "购物代金券不属于公司债券或金融票证，故不构成伪造公司债券罪或伪造金融票证罪。甲伪造代金券的目的是自己使用和送人，尚未实际使用骗取财物，尚不构成诈骗罪。但甲为伪造代金券而私刻商场公章，该行为构成伪造公司印章罪。伪造代金券的行为被伪造公司印章的行为所吸收。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 710}, {"num": 712, "batch": "专业基础知识", "type": "single", "stem": "甲、乙二人预谋修车后以假币骗付。某日，甲、乙二人在某汽修厂修车后应付款4850元，按照预谋甲将4900元假币递给乙清点后交给汽修厂职工丙，乙说：“修得不错，零钱不用找了。”甲、乙二人随即上车，丙发现货币有假大叫“别走”，甲迅速启动汽车驶向厂门，丙扑向甲车前风挡，抓住雨刮器，乙对甲说：“太危险，快停车。”甲仍然加速，致使丙摔成重伤。请问本案中，甲、乙二人使用假币支付修车费被识破后开车逃跑的行为应构成（）", "options": [{"letter": "A", "text": "使用假币罪"}, {"letter": "B", "text": "诈骗罪"}, {"letter": "C", "text": "抢夺罪"}, {"letter": "D", "text": "抢劫罪"}], "answer": "A", "explanation": "根据《刑法》第383条及相关司法解释，使用假币罪是指将假币作为真币置于流通的行为。甲、乙以假币支付修车费属于使用假币的行为。被识破后加速逃离，丙抓住雨刮器，乙曾要求停车，说明甲的加速行为超出乙的共同故意范围。甲使用假币的行为已构成使用假币罪，逃跑致人重伤的行为因缺乏转化的抢劫故意（使用假币罪不属于可转化为抢劫罪的前置犯罪），仍按使用假币罪处理。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 711}, {"num": 713, "batch": "专业基础知识", "type": "single", "stem": "甲在某自助银行安装了假的刷卡系统，获取了大量的银行客户的信用卡信息资料。甲的行为构成（）", "options": [{"letter": "A", "text": "诈骗罪"}, {"letter": "B", "text": "金融诈骗罪"}, {"letter": "C", "text": "窃取信用卡信息罪"}, {"letter": "D", "text": "妨害信用卡管理罪"}], "answer": "C", "explanation": "根据《刑法》第177条之一第2款，窃取、收买或者非法提供他人信用卡信息资料的，构成窃取信用卡信息罪。甲在自助银行安装假的刷卡系统，秘密获取大量银行客户的信用卡信息资料，属于窃取他人信用卡信息的行为，构成窃取信用卡信息罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 712}, {"num": 714, "batch": "专业基础知识", "type": "single", "stem": "下列行为中，可以构成使用假币罪的是（）", "options": [{"letter": "A", "text": "甲用总面额1万元的假币参加赌博"}, {"letter": "B", "text": "乙（系银行工作人员）利用职务上的便利，以伪造的货币换取货币"}, {"letter": "C", "text": "丙在与他人签订经济合同的时候，为显示自己的经济实力，将总面额20万元的假币冒充真币出示给对方看"}, {"letter": "D", "text": "丁用总面额10万元的假币换取高某的1万元真币"}], "answer": "A", "explanation": "根据《刑法》第172条及相关司法解释，使用假币是指将假币作为真币置于流通的行为，包括用假币购物、支付、赌博等。A项甲用假币参加赌博，属于将假币作为货币投入流通领域，构成使用假币罪。B项银行工作人员以假币换取真币构成金融工作人员以假币换取货币罪；C项仅出示假币显示实力不属于使用；D项用假币换取真币构成出售假币罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 713}, {"num": 715, "batch": "专业基础知识", "type": "single", "stem": "甲从银行工作人员乙那里非法购买了大约500份银行客户的信用卡信息资料。甲的行为构成（）", "options": [{"letter": "A", "text": "泄露内幕信息罪"}, {"letter": "B", "text": "收买信用卡信息罪"}, {"letter": "C", "text": "非法获取国家秘密罪"}, {"letter": "D", "text": "侵犯公民个人信息罪"}], "answer": "B", "explanation": "根据《刑法》第177条之一第2款，收买银行或者其他金融机构的客户信用卡信息资料的，构成收买信用卡信息罪。甲从银行工作人员乙处非法购买500份银行客户的信用卡信息资料，属于收买他人信用卡信息的行为，构成收买信用卡信息罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 714}, {"num": 716, "batch": "专业基础知识", "type": "single", "stem": "吴某经营一小型加工厂，为了扩大生产规模，急需贷款，因其不符合银行的放贷条件，于是便在向银行申请贷款的过程中提供了虚假材料，骗得银行贷款125万元。投入生产后被一客户诈骗，造成贷款到期无法归还。关于吴某行为的认定，下列说法正确的是（）", "options": [{"letter": "A", "text": "吴某主观上无非法占有的目的，其亏损是由于客观因素造成的，不构成犯罪"}, {"letter": "B", "text": "吴某通过欺诈手段骗得银行贷款，构成贷款诈骗罪"}, {"letter": "C", "text": "由于吴某系个人贷款，因此构成诈骗罪"}, {"letter": "D", "text": "吴某虽无非法占有的目的，但由于给银行造成了重大损失，因此构成骗取贷款罪?"}], "answer": "D", "explanation": "根据《刑法》第175条之一，以欺骗手段取得银行贷款，给银行造成重大损失或者有其他严重情节的，构成骗取贷款罪。该罪与贷款诈骗罪的关键区别在于是否具有非法占有目的。吴某虽然提供了虚假材料骗取贷款，但其目的是用于生产经营，且实际投入了生产，贷款无法归还是因被客户诈骗所致，主观上不具有非法占有目的，不构成贷款诈骗罪。但其欺骗行为给银行造成了重大损失，构成骗取贷款罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 715}, {"num": 717, "batch": "专业基础知识", "type": "single", "stem": "李某得知某公司急需大量资金，即与该公司总经理签订了借款协议，约定李某借给该公司2000万元，年息15%。随后，李某编造了贷款理由，伪造了买卖合同，从银行贷款2000万元，年息7.5%，从中获取利差150万元。李某构成（）", "options": [{"letter": "A", "text": "高利转贷罪"}, {"letter": "B", "text": "骗取贷款罪"}, {"letter": "C", "text": "高利转贷罪和骗取贷款罪数罪并罚"}, {"letter": "D", "text": "合同诈骗罪"}], "answer": "A", "explanation": "根据《刑法》第175条，以转贷牟利为目的，套取金融机构信贷资金高利转贷他人，违法所得数额较大的，构成高利转贷罪。李某以虚构的贷款理由和伪造的买卖合同从银行贷款2000万元，然后以15%的年息高利转借给他人，从中获取利差150万元，其行为完全符合高利转贷罪的构成要件。虽然李某使用了欺骗手段获取贷款，但其目的在于转贷牟利而非非法占有，故以高利转贷罪一罪论处。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 716}, {"num": 718, "batch": "专业基础知识", "type": "single", "stem": "X公司系甲、乙二人合伙依法注册成立的公司，以钢材批发零售为营业范围。丙因自己的公司急需资金，便找到甲、乙二人借款，承诺向X公司支付高于银行利率5个百分点的利息，并另给甲、乙二人好处费。甲、乙见有利可图，即以购买钢材为由，以X公司的名义向银行贷款1000万元，期限半年。甲、乙将贷款按约定的利息标准借与丙，丙给甲、乙各10万元好处费。半年后，丙将借款及利息还给X公司，甲、乙即向银行归还本息。关于甲、乙、丙行为的定性，下列选项正确的是（）", "options": [{"letter": "A", "text": "甲、乙构成高利转贷罪，丙不构成犯罪"}, {"letter": "B", "text": "甲、乙构成骗取贷款罪，丙不构成犯罪"}, {"letter": "C", "text": "甲、乙构成高利转贷罪和非国家工作人员受贿罪，丙构成对非国家工作人员行贿罪"}, {"letter": "D", "text": "甲、乙构成骗取贷款罪和非国家工作人员受贿罪，丙构成对非国家工作人员行贿罪"}], "answer": "C", "explanation": "甲、乙以X公司名义向银行贷款后高利转借给丙，从中获取利差和好处费。根据《刑法》第175条，以转贷牟利为目的套取金融机构信贷资金高利转贷他人的，构成高利转贷罪。同时，甲、乙收受丙各10万元好处费，根据《刑法》第163条，构成非国家工作人员受贿罪。丙为获取贷款向甲、乙行贿，构成对非国家工作人员行贿罪。甲、乙应数罪并罚。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 717}, {"num": 719, "batch": "专业基础知识", "type": "single", "stem": "李某将50元面额的人民币经过揭层加工后变为两张50元面额的人民币，并以此种方法制作了总面额4000元的人民币，后被查获。对于甲的行为下列说法正确的是（）", "options": [{"letter": "A", "text": "构成变造货币罪"}, {"letter": "B", "text": "构成伪造货币罪"}, {"letter": "C", "text": "构成持有假币罪"}, {"letter": "D", "text": "不构成犯罪"}], "answer": "A", "explanation": "根据《刑法》第173条，变造货币是指对真币采用剪贴、挖补、揭层、涂改、移位、重印等方法加工处理，改变真币形态、价值的行为。李某将50元面额人民币经过揭层加工变为两张，属于对真币进行加工处理以增加面额的行为，构成变造货币罪。变造货币与伪造货币的区别在于：变造是在真币基础上加工，伪造是完全仿造。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 718}, {"num": 720, "batch": "专业基础知识", "type": "single", "stem": "下列行为构成生产、销售伪劣产品罪的是（）", "options": [{"letter": "A", "text": "李某以4万元价格销售假烟给王某"}, {"letter": "B", "text": "张某销售自己制造的假烟，其中销售金额1万元，未销售假烟价值8万元"}, {"letter": "C", "text": "王某销售劣质塑料制品，价值2万元"}, {"letter": "D", "text": "孙某库存自己制造的用于销售的假烟，价值15万元"}], "answer": "D", "explanation": "根据《刑法》第140条及相关司法解释，生产、销售伪劣产品罪的入罪标准为销售金额5万元以上。尚未销售的，货值金额达到15万元以上的，以生产、销售伪劣产品罪（未遂）定罪处罚。A项销售金额仅4万元，未达5万元标准；B项销售金额1万元，未达标准；C项价值2万元，未达标准；D项孙某库存假烟价值15万元，达到未遂的入罪标准，构成生产、销售伪劣产品罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 719}, {"num": 721, "batch": "专业基础知识", "type": "single", "stem": "张某与王某通过网上聊天相识，张某谎称自己有20多万元国库券。二人结婚后，王某向张某索要国库券，张某无奈之下通过做假证的方式制作了20万元的假国库券。王某持该假国库券到银行兑换时被识破，银行当即报警，于是案发。张某的行为构成（）", "options": [{"letter": "A", "text": "金融凭证诈骗罪"}, {"letter": "B", "text": "伪造国家有价证券罪"}, {"letter": "C", "text": "伪造金融票证罪"}, {"letter": "D", "text": "诈骗罪"}], "answer": "B", "explanation": "根据《刑法》第178条第1款，伪造国库券或者国家发行的其他有价证券，数额较大的，构成伪造国家有价证券罪。张某通过做假证的方式制作了20万元的假国库券，国库券属于国家发行的有价证券，其行为构成伪造国家有价证券罪。张某虽对妻子谎称有国库券，但其伪造行为本身即构成该罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 720}, {"num": 722, "batch": "专业基础知识", "type": "single", "stem": "下列恐怖活动中，应以准备实施恐怖活动罪定罪处罚的是（）", "options": [{"letter": "A", "text": "甲以金钱资助某国际恐怖活动组织实施恐怖活动"}, {"letter": "B", "text": "乙以无偿提供场地方式帮助某恐怖活动组织进行培训"}, {"letter": "C", "text": "丙为某恐怖活动组织招募人员"}, {"letter": "D", "text": "丁积极参加某恐怖活动组织举行的恐怖活动培训"}], "answer": "D", "explanation": "根据《刑法》第120条之二，准备实施恐怖活动罪包括为实施恐怖活动准备工具、进行培训、与境外联络等行为，以及积极参加恐怖活动培训。D项丁积极参加恐怖活动培训，属于准备实施恐怖活动的行为，应以准备实施恐怖活动罪定罪处罚。A项构成帮助恐怖活动罪，B项构成帮助恐怖活动罪，C项构成准备实施恐怖活动罪中的招募人员行为但法条明确将其归入帮助恐怖活动罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 721}, {"num": 723, "batch": "专业基础知识", "type": "single", "stem": "李某在销售的白菜中添加有毒、有害物质，王某购买后回家食用，造成2人重伤。李某的行为构成（）", "options": [{"letter": "A", "text": "投放危险物质罪"}, {"letter": "B", "text": "销售伪劣产品罪"}, {"letter": "C", "text": "销售不符合安全标准的食品罪"}, {"letter": "D", "text": "销售有毒、有害食品罪"}], "answer": "D", "explanation": "根据《刑法》第144条，在生产、销售的食品中掺入有毒、有害的非食品原料的，或者销售明知掺有有毒、有害的非食品原料的食品的，构成生产、销售有毒、有害食品罪。李某在销售的白菜中添加有毒、有害物质，属于在食品中掺入有毒、有害非食品原料的行为，构成销售有毒、有害食品罪。该罪与投放危险物质罪的区别在于是否针对不特定多数人。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 722}, {"num": 724, "batch": "专业基础知识", "type": "single", "stem": "下列行为中，构成丢失枪支不报罪的是（）", "options": [{"letter": "A", "text": "甲不慎将自己的公务配枪丢失后，在长达1年的时间内隐瞒不报"}, {"letter": "B", "text": "乙将自己的公务配枪借给王某后，被王某遗失"}, {"letter": "C", "text": "丙将自己的公务配枪放在家中被盗，丙1年后才发现，害怕被处理而隐瞒不报"}, {"letter": "D", "text": "丁的公务配枪被欧某盗走，丁隐瞒不报，欧某使用盗窃的枪支连续进行抢劫后被抓获"}], "answer": "D", "explanation": "根据《刑法》第129条，依法配备公务用枪的人员，丢失枪支不及时报告，造成严重后果的，构成丢失枪支不报罪。D项中丁的枪支被欧某盗走后，丁明知而隐瞒不报，欧某使用该枪支进行抢劫造成严重后果，丁的行为符合丢失枪支不报罪的构成要件。A项虽隐瞒不报但未造成严重后果；B项系出借而非丢失；C项丙1年后才发现，不存在明知丢失而不报的主观故意。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 723}, {"num": 725, "batch": "专业基础知识", "type": "single", "stem": "下列有关涉枪支行为的刑事责任表述正确的是（）", "options": [{"letter": "A", "text": "甲明知是他人非法买卖的枪支而为其存放的行为，构成非法持有枪支罪"}, {"letter": "B", "text": "乙系依法配枪民警，将自己所配枪支借给具有配枪资格的同事使用，构成非法出借枪支罪"}, {"letter": "C", "text": "丙系侦查人员，在一次抓捕罪犯行动中，不慎将所配枪支丢失，及时汇报给所在单位，所在单位没有及时上报上级单位，造成严重后果，丙所在单位构成丢失枪支不报罪"}, {"letter": "D", "text": "丁捡拾一个背包，不知内有何物，在携带该背包乘坐地铁时，被检查出包内有手枪3把，丁不构成非法携带枪支危及公共安全罪"}], "answer": "D", "explanation": "A项甲明知是他人非法买卖的枪支而为其存放，应构成非法储存枪支罪而非非法持有枪支罪。B项乙将枪支借给具有配枪资格的同事使用，不属于非法出借。C项丢失枪支不报罪的主体是自然人而非单位。D项丁不知包内有枪支而携带乘坐地铁，缺乏主观故意，不构成非法携带枪支危及公共安全罪，表述正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 724}, {"num": 726, "batch": "专业基础知识", "type": "single", "stem": "警察甲临时急需用钱，便找个体户乙借钱。乙同意借钱，但条件是要有物品质押。甲将公务用枪交给乙质押，乙借给甲5万元现金，借期1个月。1个月后，甲无力偿还借款，乙便向公安机关报案。关于甲、乙的行为，下列说法正确的是（）", "options": [{"letter": "A", "text": "甲、乙均不构成犯罪"}, {"letter": "B", "text": "甲构成非法出借枪支罪，乙不构成犯罪"}, {"letter": "C", "text": "甲不构成犯罪，乙构成非法持有枪支罪"}, {"letter": "D", "text": "甲构成非法出借枪支罪，乙构成非法持有枪支罪?"}], "answer": "D", "explanation": "根据《刑法》第128条，依法配备公务用枪的人员，非法出借枪支的，构成非法出借枪支罪。甲将公务用枪质押给乙，属于以质押方式非法出借枪支，构成非法出借枪支罪。乙明知是枪支而接受质押并实际持有，不具备合法持枪资格，构成非法持有枪支罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 725}, {"num": 727, "batch": "专业基础知识", "type": "single", "stem": "警察甲为讨好妻弟乙（17岁），将公务用枪私自送乙玩。关于本案，下列说法不正确的是（）", "options": [{"letter": "A", "text": "甲构成非法出借枪支罪"}, {"letter": "B", "text": "乙构成非法持有枪支罪"}, {"letter": "C", "text": "乙不构成犯罪"}, {"letter": "D", "text": "对乙应当从轻或者减轻处罚"}], "answer": "C", "explanation": "根据《刑法》第128条，依法配备公务用枪的人员非法出借枪支的，构成非法出借枪支罪。甲将公务用枪私自送给乙玩耍，构成非法出借枪支罪。乙虽为17岁未成年人，但其非法持有枪支的行为已构成非法持有枪支罪，只是因未成年应当从轻或减轻处罚。因此C项称乙不构成犯罪的说法不正确，符合题意。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 726}, {"num": 728, "batch": "专业基础知识", "type": "single", "stem": "下列行为构成破坏广播电视设施、公用电信设施罪的是（）", "options": [{"letter": "A", "text": "甲因被学校开除，将通往该学校的电话线剪断，导致150个用户电话中断"}, {"letter": "B", "text": "乙将马路边公用电话亭的线路剪断，导致公用电话亭的电话不能使用"}, {"letter": "C", "text": "丙将某宾馆的内部闭路电视设备损毁"}, {"letter": "D", "text": "丁盗窃通往某镇的广播电视线路，导致该县所有广播电视信号中断12小时以上"}], "answer": "D", "explanation": "根据《刑法》第124条，破坏广播电视设施、公用电信设施，危害公共安全的，构成破坏广播电视设施、公用电信设施罪。该罪要求行为危害公共安全，即导致不特定多数人的通信或广播电视信号中断。D项丁盗窃通往某镇的广播电视线路，导致全县所有广播电视信号中断12小时以上，危害了公共安全，构成该罪。A、B项影响范围有限，C项属于内部设备不属于公用电信设施。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 727}, {"num": 729, "batch": "专业基础知识", "type": "single", "stem": "甲非法出售枪支，一日甲让乙将一手提包捎给丙，手提包内有一把“五四式”手枪，甲对乙谎称里面是送给丙的礼物，乙信以为真。乙携带包裹在公交车上被查获。下列说法正确的是（）", "options": [{"letter": "A", "text": "甲与乙构成共同犯罪"}, {"letter": "B", "text": "甲构成非法买卖枪支罪"}, {"letter": "C", "text": "乙受甲的教唆，应当从轻或者减轻处罚"}, {"letter": "D", "text": "乙构成非法携带枪支危及公共安全罪"}], "answer": "B", "explanation": "甲非法出售枪支，构成非法买卖枪支罪。乙受甲委托携带手提包，但甲对乙谎称里面是礼物，乙并不知包内有枪支，缺乏犯罪的主观故意，不构成犯罪。甲利用不知情的乙实施携带行为，属于间接正犯，甲单独构成非法买卖枪支罪。乙因缺乏主观故意，不构成非法携带枪支危及公共安全罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 728}, {"num": 730, "batch": "专业基础知识", "type": "single", "stem": "下列行为中，行为人涉嫌帮助恐怖活动罪的是（）", "options": [{"letter": "A", "text": "甲以金钱资助某国际恐怖活动组织实施恐怖活动"}, {"letter": "B", "text": "乙为实施恐怖活动准备凶器"}, {"letter": "C", "text": "丙为实施恐怖活动与境外恐怖活动组织联络"}, {"letter": "D", "text": "丁积极参加某恐怖活动组织举行的恐怖活动培训"}], "answer": "A", "explanation": "根据《刑法》第120条之一，资助恐怖活动组织、实施恐怖活动的个人的，构成帮助恐怖活动罪。A项甲以金钱资助恐怖活动组织实施恐怖活动，属于资助行为，构成帮助恐怖活动罪。B、C项属于准备实施恐怖活动罪的行为，D项属于参加恐怖组织的行为。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 729}, {"num": 731, "batch": "专业基础知识", "type": "single", "stem": "下列行为不构成犯罪的是（）", "options": [{"letter": "A", "text": "在春运期间，张某携带50只雷管和10公斤炸药上了火车。当乘警询问其所携带的是否为危险品时，张某谎称是大米"}, {"letter": "B", "text": "张某是公安派出所民警，某日外出时不慎把枪支丢失。张某害怕受到处分，一直隐瞒未报告上级。后来犯罪分子使用张某丢失的枪支抢劫银行，抢走50万元人民币并打死2名银行职员"}, {"letter": "C", "text": "体育裁判张某获准持有运动气枪1支，其经常借给他人打猎，所幸没有造成严重的后果"}, {"letter": "D", "text": "张某是银行的保卫人员，依法配备公务用枪1支，其有时借给他人打猎，所幸没有造成严重的后果"}], "answer": "C", "explanation": "A项张某携带大量爆炸物上火车并谎报，构成非法携带危险物品危及公共安全罪。B项张某丢失枪支不报且造成严重后果，构成丢失枪支不报罪。D项银行保卫人员属于依法配备公务用枪人员，将枪支借给他人打猎，即使未造成严重后果也构成非法出借枪支罪。C项体育裁判属于依法配置枪支的人员，根据《刑法》第128条第3款，配置枪支人员非法出借枪支需造成严重后果才构成犯罪，未造成严重后果不构成犯罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 730}, {"num": 732, "batch": "专业基础知识", "type": "single", "stem": "下列行为中，不构成帮助恐怖活动罪的是（）", "options": [{"letter": "A", "text": "甲给予恐怖活动组织“红心会”10万美元"}, {"letter": "B", "text": "乙无偿给予恐怖分子张某价值30万元的汽车一辆"}, {"letter": "C", "text": "丙应邀参加恐怖活动，负责制造10枚炸弹，其还在火车站实施爆炸2起，造成3名无辜群众死亡"}, {"letter": "D", "text": "丁积极为某恐怖活动组织招兵买马"}], "answer": "C", "explanation": "帮助恐怖活动罪包括资助恐怖活动组织或个人、提供物资支持、招募人员等行为。C项丙应邀参加恐怖活动并制造炸弹，还在火车站实施爆炸，属于直接参与实施恐怖活动，构成参加恐怖组织罪和爆炸罪，而非帮助恐怖活动罪。A项属于资助行为，B项属于提供物资帮助，D项属于招募人员，均构成帮助恐怖活动罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 731}, {"num": 733, "batch": "专业基础知识", "type": "single", "stem": "甲多次听取他人煽动实施恐怖活动的宣讲，后经他人介绍加入恐怖组织，负责培养人员。此后，甲向乙、丙等人多次宣扬“圣战”思想，后乙、丙等人加入恐怖组织。甲还为进行“圣战”，购买训练器械、书籍，进行体能、技能训练。甲的行为构成（）", "options": [{"letter": "A", "text": "组织、领导恐怖组织罪"}, {"letter": "B", "text": "宣扬恐怖主义罪"}, {"letter": "C", "text": "准备实施恐怖活动罪"}, {"letter": "D", "text": "组织、领导恐怖组织罪和宣扬恐怖主义罪数罪并罚"}], "answer": "A", "explanation": "根据《刑法》第120条，组织、领导恐怖活动组织的，构成组织、领导恐怖组织罪。甲加入恐怖组织后负责培养人员，并向他人宣扬恐怖思想发展成员，属于在恐怖组织中承担组织、领导职能的行为，构成组织、领导恐怖组织罪。其宣扬行为和培养人员行为被组织、领导行为所吸收，不另行定罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 732}, {"num": 734, "batch": "专业基础知识", "type": "single", "stem": "张某深夜将停车场内公共汽车的制动系统破坏，导致次日车辆行驶时发生颠覆，造成3人死亡。张某的行为构成（）", "options": [{"letter": "A", "text": "故意杀人罪"}, {"letter": "B", "text": "破坏交通工具罪"}, {"letter": "C", "text": "破坏交通设施罪"}, {"letter": "D", "text": "过失致人死亡罪"}], "answer": "B", "explanation": "根据《刑法》第116条，破坏火车、汽车、电车、船只、航空器，足以使其发生倾覆、毁坏危险，尚未造成严重后果或者已经造成严重后果的，构成破坏交通工具罪。张某深夜破坏停车场内公共汽车的制动系统，属于对正在使用中的交通工具进行破坏，足以使其在行驶时发生倾覆危险，构成破坏交通工具罪。虽然造成3人死亡的严重后果，但仍以破坏交通工具罪定罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 733}, {"num": 735, "batch": "专业基础知识", "type": "single", "stem": "某机械师对领导不满，利用工作之便，在进厂大修的飞机上装了两套控制电路，意图在飞机试飞时断油停机，造成机毁人亡的严重事故。后被及时发现，未造成预期后果。该机械师的行为（）", "options": [{"letter": "A", "text": "构成破坏交通工具罪（既遂）"}, {"letter": "B", "text": "构成破坏交通工具罪（未遂）"}, {"letter": "C", "text": "构成破坏交通工具罪（预备）"}, {"letter": "D", "text": "不构成犯罪"}], "answer": "A", "explanation": "破坏交通工具罪属于危险犯，只要破坏行为足以使交通工具发生倾覆、毁坏危险即构成既遂，不要求实际造成损害后果。该机械师在飞机上安装两套控制电路意图造成机毁人亡，虽然被及时发现未造成预期后果，但其破坏行为已经完成且足以使飞机发生倾覆危险，构成破坏交通工具罪既遂。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 734}, {"num": 736, "batch": "专业基础知识", "type": "single", "stem": "甲为报复乙，将乙停放在院子里的汽车轮胎螺丝卸掉3颗。次日，乙开车外出，因车轮半路甩掉，造成汽车撞倒路边一行人，致其当场死亡，车辆报废。甲的行为构成（）", "options": [{"letter": "A", "text": "破坏交通工具罪"}, {"letter": "B", "text": "交通肇事罪"}, {"letter": "C", "text": "故意杀人罪"}, {"letter": "D", "text": "故意毁坏财物罪"}], "answer": "A", "explanation": "根据《刑法》第116条，破坏交通工具罪的对象是正在使用中的交通工具。甲将乙停放在院子里汽车轮胎螺丝卸掉，该汽车属于正在使用中的交通工具，破坏行为足以使车辆行驶中发生倾覆危险，危害了公共安全（车辆在道路上行驶可能危及不特定人的安全），构成破坏交通工具罪。虽然甲主观上是为了报复乙，但客观上危害了公共安全。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 735}, {"num": 737, "batch": "专业基础知识", "type": "single", "stem": "郑某系某公安派出所民警，受指派办理一起强奸案，对汪某进行传唤后，明知汪某为犯罪嫌疑人，在接受汪某父母宴请及3000元财物后，放弃了对汪某的抓捕，亦未向派出所领导汇报，致使汪某1年多不能归案。郑某的行为构成（）", "options": [{"letter": "A", "text": "帮助犯罪分子逃避处罚罪"}, {"letter": "B", "text": "包庇罪"}, {"letter": "C", "text": "徇私枉法罪"}, {"letter": "D", "text": "玩忽职守罪"}], "answer": "C", "explanation": "根据《刑法》第399条，司法工作人员徇私枉法、徇情枉法，对明知是有罪的人而故意包庇不使他受追诉的，构成徇私枉法罪。郑某作为派出所民警，属于司法工作人员，在办理强奸案过程中，明知汪某是犯罪嫌疑人，因接受宴请和财物而放弃抓捕且不上报，属于对明知有罪的人故意包庇不使其受追诉，构成徇私枉法罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 736}, {"num": 738, "batch": "专业基础知识", "type": "single", "stem": "甲通过讲授、发布信息等方式多次宣扬极端主义，一些人由此加入恐怖活动组织，实施违法犯罪活动。甲涉嫌（）", "options": [{"letter": "A", "text": "宣扬极端主义罪"}, {"letter": "B", "text": "煽动实施恐怖活动罪"}, {"letter": "C", "text": "帮助恐怖活动罪"}, {"letter": "D", "text": "利用极端主义破坏法律实施罪"}], "answer": "A", "explanation": "根据《刑法》第120条之三，以制作、散发宣扬恐怖主义、极端主义的图书、音频视频资料或者其他物品，或者通过讲授、发布信息等方式宣扬恐怖主义、极端主义的，构成宣扬恐怖主义、极端主义罪。甲通过讲授、发布信息等方式多次宣扬极端主义，符合宣扬极端主义罪的构成要件。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 737}, {"num": 739, "batch": "专业基础知识", "type": "single", "stem": "甲因婚姻破裂，备受打击，驾驶机动车在街上随意撞人，报复社会，致1人死亡、多人受伤。甲的行为构成（）", "options": [{"letter": "A", "text": "故意杀人罪"}, {"letter": "B", "text": "过失致人死亡罪"}, {"letter": "C", "text": "以危险方法危害公共安全罪"}, {"letter": "D", "text": "交通肇事罪"}], "answer": "C", "explanation": "甲因婚姻破裂，驾驶机动车在街上随意撞人，报复社会，其行为针对的是不特定多数人的生命健康安全，属于以危险方法危害公共安全的行为。根据《刑法》第115条，以其他危险方法危害公共安全致人重伤、死亡的，构成以危险方法危害公共安全罪。该罪与故意杀人罪的区别在于是否危害公共安全（不特定多数人的安全）。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 738}, {"num": 740, "batch": "专业基础知识", "type": "single", "stem": "村民朱某在赶集时，因琐事与同村的李某、许某、胡某、赵某发生口角，并被4人殴打致伤。次日，朱某为报复李某等人，先后潜入李某等人家中，向上述4家的饭锅、水缸、食盐中投入剧毒鼠药，致上述4家的16口人中毒，其中2人死亡。朱某的行为构成（）", "options": [{"letter": "A", "text": "投放危险物质罪"}, {"letter": "B", "text": "以危险方法危害公共安全罪"}, {"letter": "C", "text": "故意杀人罪"}, {"letter": "D", "text": "投放危险物质罪与故意杀人罪"}], "answer": "C", "explanation": "投放危险物质罪与故意杀人罪的关键区别在于是否危害公共安全，即是否针对不特定多数人。朱某针对特定的李某等4家投毒，目标明确且特定，虽然造成16人中毒、2人死亡的严重后果，但其行为针对的是特定对象，不危害公共安全，应认定为故意杀人罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 739}, {"num": 741, "batch": "专业基础知识", "type": "single", "stem": "某公立医院的医生刘某，发现医院购进的板蓝根冲剂是黑面糊做的假药。由于吃不死人，刘某在开处方时仍然开具板蓝根冲剂，让病人在医院购买，累计销售金额为6万元。刘某构成（）", "options": [{"letter": "A", "text": "非法经营罪"}, {"letter": "B", "text": "销售假药罪"}, {"letter": "C", "text": "销售伪劣产品罪"}, {"letter": "D", "text": "滥用职权罪"}], "answer": "B", "explanation": "根据《刑法》第141条，销售假药的，构成销售假药罪。板蓝根冲剂系黑面糊做的假药，刘某作为医生明知是假药仍然开处方让病人购买，属于销售假药的行为。根据相关司法解释，医疗机构工作人员明知是假药而提供给患者使用的，以销售假药罪追究刑事责任。累计销售金额6万元，构成销售假药罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 740}, {"num": 742, "batch": "专业基础知识", "type": "single", "stem": "某校学生向校工反映体育场的篮球架有断裂的情况，请求维修。校工接到反映后，未向校长汇报，不久篮球架倒塌，将一正在打球的学生砸死。下列说法正确的是（）", "options": [{"letter": "A", "text": "校长涉嫌教育设施重大安全事故罪"}, {"letter": "B", "text": "校工涉嫌教育设施重大安全事故罪"}, {"letter": "C", "text": "校长涉嫌玩忽职守罪"}, {"letter": "D", "text": "校工涉嫌玩忽职守罪"}], "answer": "B", "explanation": "根据《刑法》第138条，明知校舍或者教育教学设施有危险，而不采取措施或者不及时报告，致使发生重大伤亡事故的，构成教育设施重大安全事故罪。该罪的主体是对教育教学设施安全负有直接责任的人员。校工接到学生反映篮球架有断裂情况后未向校长汇报，属于不及时报告，导致篮球架倒塌致学生死亡，校工作为直接责任人员构成教育设施重大安全事故罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 741}, {"num": 743, "batch": "专业基础知识", "type": "single", "stem": "某施工队为某单位修建五层高的楼房，为谋取高额利润，私自将水泥标号降低。楼房交付使用后，不久即垮塌，致经济损失5000余万元，死亡2人。对该行为定性正确的是（）", "options": [{"letter": "A", "text": "构成工程重大安全事故罪"}, {"letter": "B", "text": "构成重大责任事故罪"}, {"letter": "C", "text": "构成重大劳动安全事故罪"}, {"letter": "D", "text": "属于一般安全事故"}], "answer": "A", "explanation": "根据《刑法》第137条，建设单位、设计单位、施工单位、工程监理单位违反国家规定，降低工程质量标准，造成重大安全事故的，构成工程重大安全事故罪。施工队为谋取高额利润私自降低水泥标号，属于违反国家规定降低工程质量标准的行为，楼房垮塌致重大经济损失和人员死亡，构成工程重大安全事故罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 742}, {"num": 744, "batch": "专业基础知识", "type": "single", "stem": "工人王某欲进入大型机器进行维修，告诉搭班的李某不要开启机器，一个多小时后，李某发现机器是关的，就将机器启动，后突然想起王某可能还在机器内，立即将机器关闭，发现王某已被机器挤压致重伤。李某的行为（）", "options": [{"letter": "A", "text": "构成重大责任事故罪"}, {"letter": "B", "text": "构成过失致人重伤罪"}, {"letter": "C", "text": "构成玩忽职守罪"}, {"letter": "D", "text": "属于意外，不构成犯罪"}], "answer": "A", "explanation": "根据《刑法》第134条，在生产、作业中违反有关安全管理的规定，因而发生重大伤亡事故或者造成其他严重后果的，构成重大责任事故罪。李某在工厂维修作业中，违反安全操作规程，在未确认机器内是否有人的情况下启动机器，导致王某重伤，属于在生产作业中违反安全管理规定造成重大伤亡事故，构成重大责任事故罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 743}, {"num": 745, "batch": "专业基础知识", "type": "single", "stem": "甲在道路上驾驶机动车与其几个朋友追逐竞驶、严重超速，发生交通事故致1人死亡，负全部责任。甲构成（）", "options": [{"letter": "A", "text": "危险驾驶罪"}, {"letter": "B", "text": "过失致人死亡罪"}, {"letter": "C", "text": "以危险方法危害公共安全罪"}, {"letter": "D", "text": "交通肇事罪"}], "answer": "D", "explanation": "根据《刑法》第133条及相关司法解释，甲在道路上追逐竞驶、严重超速，属于危险驾驶行为，但同时发生交通事故致1人死亡且负全部责任，已构成交通肇事罪。根据刑法理论，一个行为同时触犯危险驾驶罪和交通肇事罪的，属于想象竞合，择一重罪处罚，应以交通肇事罪定罪处罚。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 744}, {"num": 746, "batch": "专业基础知识", "type": "single", "stem": "王某依法配备一把“六四式”手枪，放置在办公室内。某日甲潜入王某办公室，将手枪盗走，持枪抢劫路人，直到甲被抓获后供述手枪的来源，王某才知道自己的手枪被盗。下列说法正确的是（）", "options": [{"letter": "A", "text": "甲盗窃手枪是抢劫准备的行为，属于牵连关系，应以抢劫罪处罚"}, {"letter": "B", "text": "王某构成丢失枪支不报罪"}, {"letter": "C", "text": "王某不构成犯罪"}, {"letter": "D", "text": "王某应对抢劫结果的发生负法律责任"}], "answer": "C", "explanation": "王某的手枪被盗属于被害，王某在不知情的情况下不存在丢失枪支后不报告的主观故意。直到甲被抓获后供述手枪来源，王某才知道手枪被盗，因此不构成丢失枪支不报罪。甲盗窃手枪后持枪抢劫，属于两个独立的行为，应以盗窃罪和抢劫罪数罪并罚，而非牵连关系。王某对抢劫结果的发生不承担法律责任。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 745}, {"num": 747, "batch": "专业基础知识", "type": "single", "stem": "甲因疏于观察，在一建筑工地入口处驾驶重型货车倒车时不慎将在车后劳动的乙的大腿轧断，甲见四周无人，便将乙拖至无人处遗弃后驾车逃逸，乙因出血过多而死亡。甲构成（）", "options": [{"letter": "A", "text": "交通肇事罪"}, {"letter": "B", "text": "过失致人死亡罪"}, {"letter": "C", "text": "故意杀人罪"}, {"letter": "D", "text": "交通肇事罪、过失致人死亡罪，应数罪并罚"}], "answer": "C", "explanation": "根据《最高人民法院关于审理交通肇事刑事案件具体应用法律若干问题的解释》第6条，行为人在交通肇事后为逃避法律追究，将被害人带离事故现场后隐藏或者遗弃，致使被害人无法得到救助而死亡的，以故意杀人罪定罪处罚。甲将受伤的乙拖至无人处遗弃后逃逸，致乙因出血过多死亡，构成故意杀人罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 746}, {"num": 748, "batch": "专业基础知识", "type": "single", "stem": "某市一药店在销售过程中，将已过期的药品更改有效期后予以上柜销售，李某购买后食用，对其健康造成了严重危害。该药店的行为构成（）", "options": [{"letter": "A", "text": "销售假药罪"}, {"letter": "B", "text": "销售劣药罪"}, {"letter": "C", "text": "销售伪劣产品罪"}, {"letter": "D", "text": "诈骗罪"}], "answer": "B", "explanation": "根据《药品管理法》规定，超过有效期的药品为劣药。根据《刑法》第142条，销售劣药对人体健康造成严重危害的，构成销售劣药罪。该药店将已过期的药品更改有效期后销售，属于销售劣药的行为，李某购买后食用对健康造成严重危害，符合销售劣药罪的构成要件。注意假药与劣药的区别：假药是药品成分不符，劣药是药品质量不达标（包括过期）。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 747}, {"num": 749, "batch": "专业基础知识", "type": "single", "stem": "甲在某封闭的施工工地驾驶货车倒车时不慎将工友乙撞死，违反了单位关于“倒车时应当有人指挥”的规定。甲构成（）", "options": [{"letter": "A", "text": "重大责任事故罪"}, {"letter": "B", "text": "过失致人死亡罪"}, {"letter": "C", "text": "故意杀人罪"}, {"letter": "D", "text": "交通肇事罪"}], "answer": "A", "explanation": "交通肇事罪发生在公共交通管理范围内。封闭的施工工地不属于《道路交通安全法》规定的道路范围，因此在该区域内发生的事故不构成交通肇事罪。甲在封闭工地内驾驶货车倒车时违反单位安全管理规定，不慎将工友撞死，属于在生产作业中违反安全管理规定发生重大伤亡事故，构成重大责任事故罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 748}, {"num": 750, "batch": "专业基础知识", "type": "single", "stem": "客运公司驾驶人甲春节期间在家和朋友吃饭喝酒，突然接到公司经理乙的电话，叫他马上到单位顶个班，出车跑趟长途。甲对乙称，其已经喝了酒，不能再开车，乙说，“如果今天你不来，以后就别来上班了”。甲出车后发生重大交通事故致1人死亡，负全部责任。下列关于乙的行为说法正确的是（）", "options": [{"letter": "A", "text": "构成重大责任事故罪"}, {"letter": "B", "text": "不构成犯罪"}, {"letter": "C", "text": "属于教唆犯"}, {"letter": "D", "text": "构成交通肇事罪"}], "answer": "D", "explanation": "根据《最高人民法院关于审理交通肇事刑事案件具体应用法律若干问题的解释》第7条，单位主管人员、机动车辆所有人或者机动车辆承包人指使、强令他人违章驾驶造成重大交通事故，以交通肇事罪定罪处罚。乙作为公司经理，以解雇相威胁强令已饮酒的甲出车跑长途，甲出车后发生重大交通事故致1人死亡，乙构成交通肇事罪。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 749}, {"num": 751, "batch": "专业基础知识", "type": "single", "stem": "刘某驾驶小汽车发生交通事故，撞伤了骑自行车过马路的陈某。刘某非常害怕，马上打电话给小汽车所有人王某，王某怕车辆被扣和造成不良影响，指使刘某逃跑，刘某遂驾车逃离现场。后陈某因得不到救助死亡。王某（）", "options": [{"letter": "A", "text": "构成故意杀人罪"}, {"letter": "B", "text": "构成过失致人死亡罪"}, {"letter": "C", "text": "构成交通肇事罪共犯"}, {"letter": "D", "text": "不构成犯罪"}], "answer": "C", "explanation": "根据《最高人民法院关于审理交通肇事刑事案件具体应用法律若干问题的解释》第5条第2款，交通肇事后，单位主管人员、机动车辆所有人、承包人或者乘车人指使肇事人逃逸，致使被害人因得不到救助而死亡的，以交通肇事罪共犯论处。王某作为车辆所有人，指使刘某逃逸，致陈某因得不到救助而死亡，构成交通肇事罪的共犯。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 750}, {"num": 752, "batch": "专业基础知识", "type": "single", "stem": "甲携带一把管制刀具进入公共广场参加示威活动。下列对甲的行为的认定正确的是（）", "options": [{"letter": "A", "text": "甲不构成犯罪"}, {"letter": "B", "text": "甲构成非法携带管制刀具危及公共安全罪"}, {"letter": "C", "text": "甲构成非法携带管制刀具罪"}, {"letter": "D", "text": "甲构成非法携带管制刀具参加示威罪"}], "answer": "D", "explanation": "根据《刑法》第297条，违反法律规定，携带武器、管制刀具或者爆炸物参加集会、游行、示威的，构成非法携带武器、管制刀具、爆炸物参加集会、游行、示威罪。甲携带管制刀具参加示威活动，完全符合该罪的构成要件。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 751}, {"num": 753, "batch": "专业基础知识", "type": "single", "stem": "赵某将其驾驶的中巴客车停在离其家不远的一个下坡路段。赵某知道该车手刹失灵，就用木板和砖头塞住后轮不让车子下滑，在驾驶室小睡了一会儿。由于赵某疏忽了车轮下面的土质是软土，塞车轮的木板和砖头被车轮轧进了软土里面，该车自行向下溜车，将坡下的同村村民陈某撞倒后碾轧致死。对赵某行为的定性，下列观点正确的是（）", "options": [{"letter": "A", "text": "属于意外事件，赵某不构成犯罪"}, {"letter": "B", "text": "赵某构成过失致人死亡罪"}, {"letter": "C", "text": "赵某构成以危险方法危害公共安全罪"}, {"letter": "D", "text": "赵某构成交通肇事罪"}], "answer": "D", "explanation": "赵某明知手刹失灵，仅用木板和砖头塞住后轮，且疏忽了土质为软土的风险，主观上存在过于自信的过失。车辆溜滑致人死亡，发生在下坡路段，属于交通运输活动中的过失行为。根据《刑法》第133条，违反交通运输管理法规，因而发生重大事故，致人死亡的，构成交通肇事罪。赵某的行为不属于意外事件，因其应当预见而未预见。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 752}, {"num": 754, "batch": "专业基础知识", "type": "single", "stem": "根据《公安机关组织管理条例》的规定，下列说法错误的是（）", "options": [{"letter": "A", "text": "邓某系某区公安分局一级警长，该职务属于公安机关内设执法勤务机构警官序列"}, {"letter": "B", "text": "曹某系某县公安局办事员，该职务属于公安机关内设综合管理机构警员序列"}, {"letter": "C", "text": "彭某拟任命为甲县公安局乙派出所副所长，由甲县公安局决定"}, {"letter": "D", "text": "曾某被提名为甲省乙市公安局局长，应当事先征得甲省公安厅的同意"}], "answer": "A", "explanation": "根据《公安机关组织管理条例》的规定，公安机关人民警察职务分为警官职务、警员职务和警务技术职务。一级警长属于公安机关内设执法勤务机构警员序列，而非警官序列，A项表述错误。B项办事员属于综合管理机构警员序列正确。C项派出所副所长由所属县公安局任命正确。D项省辖市公安局局长提名应事先征得省公安厅同意正确。", "tags": "广东辅警笔试 单选题 专业基础知识", "_idx": 753}, {"num": 755, "batch": "专业基础知识", "type": "multi", "stem": "（根据新治安法修订）为维护社会治安秩序，保障公共安全，公安机关依法负责治安行政管理工作。在治安行政管理工作中，公安机关有权对不履行治安管理法律所确定的义务或者危及社会治安秩序，情节轻微，尚不够刑事处罚的行为，依照治安管理法律实施行政处罚。下列执法行为属于公安机关行使治安行政处罚权的有（）。", "options": [{"letter": "A", "text": "对职业足球比赛中强行冲入场内的王×作出警告"}, {"letter": "B", "text": "对偷开他人机动车的张×处以1000元罚款"}, {"letter": "C", "text": "对结伙斗殴的李×等人分别处以5日至7日不等的行政拘留"}, {"letter": "D", "text": "对拒不接受传唤的酗酒闹事人赵×实施强制传唤"}], "answer": "ABC", "explanation": "治安行政处罚包括警告、罚款、行政拘留、吊销公安机关发放的许可证等。A项警告、B项罚款、C项行政拘留均属于治安行政处罚。D项强制传唤属于行政强制措施而非行政处罚，不属于治安行政处罚权的范畴。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 754}, {"num": 756, "batch": "专业基础知识", "type": "multi", "stem": "民警小曾下班后和家人在饭店吃饭，邻桌王X、刘某等人发生争执，王X持啤酒瓶追打刘某。小曾出示警察证表明自己身份，并制止王X的违法行为。王X认为小曾不是处警民警，不服从还对其进行殴打。根据法律规定，下列说法正确的有（）。", "options": [{"letter": "A", "text": "民警小曾的行为属于依法履行职责"}, {"letter": "B", "text": "对王X殴打民警小曾的行为，应当予以处罚"}, {"letter": "C", "text": "若民警小曾的行为造成饭店财产损失，应当由民警小曾赔偿"}, {"letter": "D", "text": "若民警小曾因此致残，与因公致残的现役军人享受国家同样的抚恤和优待"}], "answer": "ABD", "explanation": "根据《人民警察法》第19条，人民警察在非工作时间，遇有其职责范围内的紧急情况，应当履行职责。小曾下班后表明身份制止违法行为属于依法履行职责，A正确。根据《人民警察法》相关规定，阻碍人民警察依法执行职务的应当予以处罚，B正确。民警依法履职造成的损失由国家承担而非个人赔偿，C错误。根据《人民警察法》第41条，民警因公致残与现役军人享受同样抚恤优待，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 755}, {"num": 757, "batch": "专业基础知识", "type": "multi", "stem": "（根据新治安法修订）近期，在值班过程中，派出所民警多次接到群众半夜报警反映邻居家狗吠扰民，民警多次上门对其进行告诫，但仍屡教不改。对此，民警对该案件进行受案办理，因该案情节简单、事实清楚且嫌疑人对违法事实和法律适用没有异议，民警决定采取快速办理。在办理的过程中，以下做法正确的是（）。", "options": [{"letter": "A", "text": "在快速办理前，应口头告知嫌疑人相关规定"}, {"letter": "B", "text": "可以采用执法记录仪摄录的方式替代书面询问笔录"}, {"letter": "C", "text": "在进行处罚前告知程序的过程中，办案民警必须采取书面方式履行程序"}, {"letter": "D", "text": "在嫌疑人到案后四十八小时内应作出处理决定"}], "answer": "BD", "explanation": "根据治安案件快速办理的相关规定，快速办理前应当书面告知嫌疑人相关规定而非口头告知，A错误。快速办理案件可以采用执法记录仪摄录方式替代书面询问笔录，B正确。处罚前告知程序可以采取口头方式，不必须书面方式，C错误。快速办理案件应在嫌疑人到案后48小时内作出处理决定，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 756}, {"num": 758, "batch": "专业基础知识", "type": "multi", "stem": "（根据新治安法修订）公安机关的权力是公安机关为了履行宪法、法律赋予的法定职责，在警务活动中依法采取的权威性措施和手段。公安机关的权力必须在法定的职责范围内行使，并受相应的制约。下列关于公安机关行使权力的说法不符合法律规定的有（）。", "options": [{"letter": "A", "text": "发现被许可单位存在违法行为，可以吊销其许可证"}, {"letter": "B", "text": "对被判处拘役的犯罪分子就近执行"}, {"letter": "C", "text": "对危害公共安全的违法行为需要当场制止的，可以使用约束性警械"}, {"letter": "D", "text": "为了预防和制止严重危害社会治安秩序的行为，可以实行现场管制"}], "answer": "CD", "explanation": "A项吊销许可证属于公安机关的治安管理处罚权，表述正确。B项对被判处拘役的犯罪分子由公安机关就近执行，属于公安机关的刑罚执行权，表述正确。C项对危害公共安全的违法行为需要当场制止的，可以使用约束性警械，但需符合使用警械的法定条件，该表述不够准确。D项现场管制的实施主体和条件有严格限制，不能随意实行。本题要求选不符合规定的，CD当选。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 757}, {"num": 759, "batch": "专业基础知识", "type": "multi", "stem": "回避是指公安机关办案人员因为与案件有利害关系或者其他关系，可能影响案件公正处理时，退出案件办理工作的制度。根据《人民警察法》规定，下列符合应当回避情形的有（）。", "options": [{"letter": "A", "text": "派出所副所长老赵是该所办理的一起伤害案件被害人的丈夫"}, {"letter": "B", "text": "禁毒大队民警小钱给其弟弟（吸毒人员钱×）进行吸毒检测"}, {"letter": "C", "text": "派出所民警小孙的父亲是其正在办理的盗窃案件嫌疑人的朋友"}, {"letter": "D", "text": "派出所民警老李和参与处理的违法出租房屋案件的当事人有债务关系"}], "answer": "ABD", "explanation": "根据《人民警察法》及相关规定，办案人员与案件当事人有利害关系的应当回避。A项老赵是被害人的丈夫，与案件有直接利害关系，应当回避。B项小钱为正在办理案件的吸毒人员进行检测，存在利害关系，应当回避。C项小孙的父亲仅是嫌疑人的朋友，不属于法定回避事由。D项老李与当事人有债务关系，存在利害关系，应当回避。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 758}, {"num": 760, "batch": "专业基础知识", "type": "multi", "stem": "下列情形中，适用简易程序办理的有（）。", "options": [{"letter": "A", "text": "甲骑乘电瓶车在非机动车道上逆向行驶，被交警处以50元罚款"}, {"letter": "B", "text": "出入境边防检查站民警发现乙违法携带违禁物品，决定对乙处以500元罚款"}, {"letter": "C", "text": "民警在对辖区KTV开展治安检查时，发现丙女卖淫，决定对丙处以500元罚款"}, {"letter": "D", "text": "丁违规停放车辆，被交警处以200元罚款"}], "answer": "ABD", "explanation": "根据《治安管理处罚法》相关规定，违法事实确凿，对违反治安管理行为人或者道路交通违法行为人处200元以下罚款的，可以适用简易程序。A项50元罚款符合简易程序条件。B项出入境边防检查站对违法携带违禁物品处500元罚款，根据相关规定可适用简易程序。C项卖淫案件属于较为复杂的治安案件，不适用简易程序。D项200元罚款符合简易程序条件。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 759}, {"num": 761, "batch": "专业基础知识", "type": "multi", "stem": "中国人民警察警徽是人民警察的象征和专用标志，公安民警应当爱护警徽，维护警徽尊严。下列选项中，关于警徽表述准确的有（）。", "options": [{"letter": "A", "text": "警徽图案由国徽、盾牌、长城、松枝和麦穗构成"}, {"letter": "B", "text": "警徽及其图案的使用应当严肃、庄重，并严格使用范围"}, {"letter": "C", "text": "警徽及其图案的使用由省级以上公安机关负责监督管理"}, {"letter": "D", "text": "警徽由公安部按照规定统一监制"}], "answer": "BD", "explanation": "根据《人民警察法》及《公安机关人民警察警徽管理规定》，警徽图案由国徽、盾牌、长城、松枝组成，不含麦穗，A错误。警徽及其图案的使用应当严肃、庄重，严格按照规定范围使用，B正确。警徽及其图案的使用由县级以上公安机关负责监督管理，而非省级以上，C错误。警徽由公安部按照规定统一监制，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 760}, {"num": 762, "batch": "专业基础知识", "type": "multi", "stem": "近年来，公安机关深化城乡社区警务战略，与社区自治、网格化管理深度融合，推进平安社区、平安乡村、平安单位建设，社区民警作为社区警务工作的具体实施者和直接责任人，承担的主要职责有（）。", "options": [{"letter": "A", "text": "办理治安案件"}, {"letter": "B", "text": "掌握社情民意"}, {"letter": "C", "text": "组织安全防范"}, {"letter": "D", "text": "维护社区秩序"}], "answer": "BCD", "explanation": "根据社区警务工作的相关规定，社区民警的主要职责包括：掌握社情民意、组织安全防范、维护社区秩序、服务群众等。办理治安案件属于派出所办案民警的职责，不属于社区民警的主要职责范围。因此BCD正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 761}, {"num": 763, "batch": "专业基础知识", "type": "multi", "stem": "下列选项中关于对《当场处罚决定书》备案的说法，正确的是（）。", "options": [{"letter": "A", "text": "人民警察应当于作出决定后的24小时内报所属公安机关备案"}, {"letter": "B", "text": "交通警察应当于作出决定后的2日内报所属公安机关交通管理部门备案"}, {"letter": "C", "text": "在旅客列车上作出行政处罚决定的，应当在返回后的24小时内报所属公安机关备案"}, {"letter": "D", "text": "在民航飞机上作出行政处罚决定的，应当在作出决定后的24小时内报所属公安机关备案"}], "answer": "ABC", "explanation": "根据《公安机关办理行政案件程序规定》，人民警察当场作出行政处罚决定的，应当于作出决定后的24小时内报所属公安机关备案，A正确。交通警察当场作出处罚决定的，应当于2日内报所属公安机关交通管理部门备案，B正确。在旅客列车上作出处罚决定的，应当在返回后的24小时内报所属公安机关备案，C正确。在民航飞机上作出处罚决定的备案时间有特殊规定，D项表述不准确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 762}, {"num": 764, "batch": "专业基础知识", "type": "multi", "stem": "违法行为行为人应受到制裁，但是违法行为超过追究时效就不再进行处罚。以下不属于可以不再处罚行为的有（）。", "options": [{"letter": "A", "text": "甲于1月1日在天上人间会所嫖娼，同年10月10日被公安机关发现"}, {"letter": "B", "text": "乙于1月1日非法持有5克海洛因，持有状态下同年12月1日被公安机关发现"}, {"letter": "C", "text": "丙于1月1日在超市实施偷盗行为，2月10日又一次实施偷盗行为，同年6月15日被公安机关发现"}, {"letter": "D", "text": "丁于1月1日殴打戊，在公安机关组织治安调解期间逃跑，同年10月1日被抓获"}], "answer": "BCD", "explanation": "根据《治安管理处罚法》第22条，违反治安管理行为在6个月内没有被公安机关发现的，不再处罚。追究时效从行为发生之日起计算，行为有连续或继续状态的从行为终了之日起计算。A项嫖娼行为1月至10月已超过6个月，可以不再处罚。B项非法持有毒品属于继续犯，持有状态持续至12月被发觉，未超过6个月。C项偷盗行为有连续状态，从2月10日起算至6月未超过6个月。D项逃避调查期间不计算在追究时效内。因此BCD不属于可以不再处罚的情形。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 763}, {"num": 765, "batch": "专业基础知识", "type": "multi", "stem": "吴某某因涉嫌吸食毒品，公安机关拟对其作出行政拘留十日、罚款二千元的处罚。吴某某不服提出听证请求后，公安机关组织举行听证。7月10日，听证会依法公开举行，关于此次听证会，下列说法正确的是（）。", "options": [{"letter": "A", "text": "吴某某可以委托两人代理参加听证"}, {"letter": "B", "text": "听证过程中，若吴某某撤回听证申请，听证主持人不予支持"}, {"letter": "C", "text": "本案的鉴定人不得参与本次听证会"}, {"letter": "D", "text": "不得因吴某某提出听证要求而加重处罚"}], "answer": "AD", "explanation": "根据《治安管理处罚法》及听证程序相关规定，当事人可以委托1至2人代理参加听证，A正确。听证过程中当事人撤回听证申请的，听证主持人可以准许而非不予支持，B错误。鉴定人可以参与听证会，C错误。当事人不因提出听证要求而被加重处罚，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 764}, {"num": 766, "batch": "专业基础知识", "type": "multi", "stem": "某地公安机关负责人老张和办案民警小李在办理一起治安案件时，主动申请回避，下列关于他们回避的说法正确的是（）。", "options": [{"letter": "A", "text": "老张的回避由同级的人民检察院决定"}, {"letter": "B", "text": "小李的回避由所属公安机关决定"}, {"letter": "C", "text": "申请回避后立即停止对案件的调查"}, {"letter": "D", "text": "老张的回避由上一级公安机关决定"}], "answer": "BD", "explanation": "根据《治安管理处罚法》第81条，公安机关负责人的回避由上一级公安机关决定，A错误、D正确。办案民警的回避由所属公安机关决定，B正确。申请回避后，在回避决定作出前，除特殊情况外不停止对案件的调查，C错误。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 765}, {"num": 767, "batch": "专业基础知识", "type": "multi", "stem": "M国公民约翰在某市火车站附近因乞讨人员张某（聋哑人）对其反复纠缠，两人发生互殴，放学路过此地的小王（15周岁）目睹了案发过程。关于公安机关对约翰、张某、小王三人的询问，下列说法正确的有（）。", "options": [{"letter": "A", "text": "如果约翰不懂中文，询问时应当为其配备翻译"}, {"letter": "B", "text": "询问张某时，应当通知其监护人到场"}, {"letter": "C", "text": "询问张某时，应当有通晓手语的人在场"}, {"letter": "D", "text": "询问小王时，应当通知其父母或者其他监护人到场"}], "answer": "ACD", "explanation": "根据《治安管理处罚法》及《公安机关办理行政案件程序规定》，询问不通晓当地语言文字的人，应当为其配备翻译，A正确。张某是聋哑人而非未成年人，询问聋哑人不需要通知监护人到场，B错误。询问聋哑人应当有通晓手语的人在场并在笔录上注明，C正确。小王15周岁属于未成年人，询问未成年人应当通知其父母或其他监护人到场，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 766}, {"num": 768, "batch": "专业基础知识", "type": "multi", "stem": "北湖派出所民警依法对私自开拆他人邮件的违法行为人周某处以50元罚款并当场收缴，下列说法正确的是（）。", "options": [{"letter": "A", "text": "如周某没有异议，可以当场收缴"}, {"letter": "B", "text": "公安机关应当出具省级以上财政部门统一制发的罚款收据"}, {"letter": "C", "text": "民警小宋应当在收缴罚款当日将当场收缴的罚款交至其所属公安机关"}, {"letter": "D", "text": "公安机关应当自收到罚款之日起二日内将罚款缴付指定的银行"}], "answer": "ABD", "explanation": "根据《治安管理处罚法》相关规定，被处50元以下罚款的被处罚人对处罚没有异议的，可以当场收缴，本案罚款50元且周某无异议，A正确。罚款收据应由省级以上人民政府财政部门统一制发，B正确。当场收缴的罚款，人民警察应当自收缴罚款之日起2日内交至所属公安机关，而非当日，C错误。公安机关应当自收到罚款之日起2日内将罚款缴付指定银行，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 767}, {"num": 769, "batch": "专业基础知识", "type": "multi", "stem": "民警小周接到群众报警后赶到现场，发现参与打架的一方当事人为自己的表弟，当地公安机关负责人为民警小周的大伯，警方指定了具有资质的伤情鉴定机构为双方做伤情鉴定，另一方当事人为聋哑人，邀请了自己的手语老师作为自己的翻译人员，根据《公安机关办理行政案件程序规定》相关规定，本案中需要回避的人员包括（）。", "options": [{"letter": "A", "text": "民警小周"}, {"letter": "B", "text": "公安机关负责人"}, {"letter": "C", "text": "鉴定人员"}, {"letter": "D", "text": "翻译人员"}], "answer": "ABD", "explanation": "根据《公安机关办理行政案件程序规定》，办案民警与案件当事人有利害关系的应当回避，小周是当事人的表哥，应当回避，A正确。公安机关负责人与当事人有亲属关系的应当回避，大伯是当事人的伯父，应当回避，B正确。鉴定人员由有资质的机构指定，本案中无证据表明鉴定人员需要回避，C不选。翻译人员由当事人自行邀请的，如与案件有利害关系应当回避，但本案中手语老师由当事人邀请担任翻译，根据规定翻译人员与当事人有利害关系应当回避，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 768}, {"num": 770, "batch": "专业基础知识", "type": "multi", "stem": "李某及其妻子到派出所咨询案件，民警告知李某需要等候鉴定结果，李某误解为民警不作为，夫妻二人在派出所大发雷霆，打砸公物若干。针对李某涉嫌扰乱公共秩序案，民警调查取证的做法不正确的是（）。", "options": [{"letter": "A", "text": "将二人分别带至办案区，由一名民警询问"}, {"letter": "B", "text": "李某辨认打砸公物时，由两名辅警进行"}, {"letter": "C", "text": "对李某妻子的人身安全检查由女辅警进行"}, {"letter": "D", "text": "扣押李某的手机，等案件处理完毕归还"}], "answer": "ABD", "explanation": "根据《公安机关办理行政案件程序规定》，询问违法嫌疑人应当由两名以上办案民警进行，A项仅由一名民警询问不正确，A当选。辨认应当由办案民警主持，不能由辅警单独进行，B项由两名辅警进行辨认不正确，B当选。对女性的人身安全检查应当由女性工作人员进行，女辅警属于女性工作人员，C正确。扣押手机与案件无关的物品不应扣押，D项做法不正确，D当选。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 769}, {"num": 771, "batch": "专业基础知识", "type": "multi", "stem": "张三在甲县某酒吧吸食毒品被群众举报，民警将其当场查获，公安机关下列做法正确的有（）。", "options": [{"letter": "A", "text": "民警小李在派出所办公室询问张三3个小时"}, {"letter": "B", "text": "民警小李让两名警务辅助人员检查张三的身体"}, {"letter": "C", "text": "经派出所领导批准，对张三的询问时间可延长至24小时"}, {"letter": "D", "text": "虽然张三强烈反对，民警仍将传唤张三的理由、地点告诉其妻子"}], "answer": "CD", "explanation": "根据《公安机关办理行政案件程序规定》，询问查证时间一般不超过8小时，A项询问3小时在合法范围内，但选项表述为在办公室询问需考虑是否合规。身体检查应由两名以上工作人员进行，不能仅由两名辅警进行，B错误。可能适用行政拘留处罚的，询问查证时间可以延长至24小时，吸毒案件可能适用拘留，经批准可延长，C正确。将传唤原因和处所通知被传唤人家属，即使被传唤人反对也应通知，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 770}, {"num": 772, "batch": "专业基础知识", "type": "multi", "stem": "甲、乙到某县游玩时，乙手机丢失，随后二人到属地派出所报案。因接警民警王某态度冷淡，甲当面提出意见，王某遂与之发生口角，该派出所所长杜某闻讯赶来，将二人制止，并命令民警尤某和许某将甲、乙留置盘问。尤某、许某均认为所长杜某的办案决定有错误，向杜某提出改正意见后未被采纳，许某拒绝执行，尤某则继续执行。对甲、乙留置近四十个小时后，该派出所以公然侮辱他人为理由决定对甲处以五百元罚款。甲向杜某一再申辩，杜某拒绝听取，并将罚款数额加至一千元。关于对甲、乙的留置措施，以下说法正确的有（）。", "options": [{"letter": "A", "text": "对甲留置盘问是错误的"}, {"letter": "B", "text": "对乙留置盘问是错误的"}, {"letter": "C", "text": "派出所有权对甲留置盘问"}, {"letter": "D", "text": "派出所有权对乙留置盘问"}], "answer": "AB", "explanation": "根据《人民警察法》第9条，留置盘问（继续盘问）适用于被指控有犯罪行为的、有现场作案嫌疑的、有作案嫌疑身份不明的、携带的物品有可能是赃物的人员。甲仅是当面提出意见，不符合留置盘问的法定条件，对甲留置盘问是错误的，A正确。乙仅是报案人，更不符合留置盘问条件，对乙留置盘问也是错误的，B正确。留置盘问需经县级以上公安机关批准，派出所无权自行决定，CD错误。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 771}, {"num": 773, "batch": "专业基础知识", "type": "multi", "stem": "2024年12月某日，赵某、钱某喝酒后，约孙某、李某在甲县某棋牌室包房打麻将赌博。期间，赵某拿出一小包毒品吸食并对其他人说“这是‘K粉’，大家尝尝”，钱某也随之吸食。稍后，孙某与李某因赌资问题发生纠纷，孙某殴打李某（经鉴定为轻微伤），并损毁棋牌室包房内的一些物品（价值500元），棋牌室老板闻讯报警，派出所民警接警后迅速出警，在对包房进行检查时，查获未吸食完的少量“K粉”以及麻将台上的4万元现金，并从4人身上搜出手表2块，金项链1条。当民警要将4人口头传唤到派出所时，醉酒的赵某拒绝配合民警。民警对赵某采取了约束措施，随后将钱某、孙某、李某等人带回派出所进行询问查证。本案中，违反《治安管理处罚法》的行为有（）。", "options": [{"letter": "A", "text": "孙某殴打李某的行为"}, {"letter": "B", "text": "钱某吸食“K粉”的行为"}, {"letter": "C", "text": "孙某损毁棋牌室物品的行为"}, {"letter": "D", "text": "李某赌博的行为"}], "answer": "ABCD", "explanation": "本案中，孙某殴打李某致轻微伤，构成殴打他人的违反治安管理行为，A正确。钱某吸食K粉属于吸食毒品的违反治安管理行为，B正确。孙某损毁棋牌室物品价值500元，构成故意损毁财物的违反治安管理行为，C正确。赵某、钱某、孙某、李某四人打麻将赌博，李某参与赌博构成赌博的违反治安管理行为，D正确。赵某提供毒品供他人吸食也属于违反治安管理行为。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 772}, {"num": 774, "batch": "专业基础知识", "type": "multi", "stem": "（根据新治安法修订）依照《治安管理处罚法》规定，“危险物质”包括：（）", "options": [{"letter": "A", "text": "爆炸性物质"}, {"letter": "B", "text": "毒害性物质"}, {"letter": "C", "text": "放射性物质"}, {"letter": "D", "text": "传染病病原体"}], "answer": "ABCD", "explanation": "根据新修订的《治安管理处罚法》相关规定，危险物质包括爆炸性物质、毒害性物质、放射性物质、传染病病原体等。ABCD四项均属于法律规定的危险物质范畴。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 773}, {"num": 775, "batch": "专业基础知识", "type": "multi", "stem": "派出所巡逻民警刘某、赵某接群众举报某出租屋存在赌博行为，民警进入现场发现甲、乙、丙、丁四人正在赌博，经当事人确认现场共有赌资400元；另发现一把匕首，多张淫秽光盘以及一支用过的疑似毒品注射器，随即对四人口头传唤至自己的办公室询问。经查，淫秽光盘都是甲的，乙注射过少量海洛因，甲乙丙均指认匕首是丁的，但丁拒不承认。本案中，应予收缴的物品有（）。", "options": [{"letter": "A", "text": "赌资"}, {"letter": "B", "text": "匕首"}, {"letter": "C", "text": "淫秽光盘"}, {"letter": "D", "text": "注射器"}], "answer": "ABCD", "explanation": "根据《治安管理处罚法》第11条，办理治安案件所查获的毒品、淫秽物品等违禁品，赌具、赌资，吸食、注射毒品的用具以及直接用于实施违反治安管理行为的工具，应当收缴。赌资属于应收缴物品，A正确。匕首属于管制刀具，应予收缴，B正确。淫秽光盘属于违禁品，应予收缴，C正确。注射器属于吸食毒品的用具，应予收缴，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 774}, {"num": 776, "batch": "专业基础知识", "type": "multi", "stem": "某日，周某（17周岁，半年前曾因寻衅滋事被公安机关处以拘留处罚）在甲市A区家中吸食完毒品之后，与朋友一起前往甲市B区某酒吧娱乐，被前来检查的民警查出尿检结果呈冰毒阳性。根据《公安机关办理行政案件程序规定》，针对周某吸毒案件的管辖权问题，以下说法正确的有（）。", "options": [{"letter": "A", "text": "甲市A区公安分局没有管辖权"}, {"letter": "B", "text": "甲市B区公安分局具有管辖权"}, {"letter": "C", "text": "甲市A区公安分局和B区公安分局都没有管辖权"}, {"letter": "D", "text": "甲市A区公安分局和B区公安分局都有管辖权"}], "answer": "BD", "explanation": "根据《公安机关办理行政案件程序规定》，行政案件由违法行为地的公安机关管辖，违法行为地包括违法行为发生地和违法结果发生地。周某在B区酒吧被查出吸毒阳性，B区为违法行为发现地，具有管辖权，B正确。周某在A区家中吸食毒品，A区为违法行为实施地，也具有管辖权。因此A区和B区公安分局都有管辖权，D正确，A错误，C错误。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 775}, {"num": 777, "batch": "专业基础知识", "type": "multi", "stem": "（根据新治安法修订）下列属于故意扰乱公共秩序行为的有（）。", "options": [{"letter": "A", "text": "甲因对社会不满，遂在网上散布某市跨江大桥晃动即将坍塌的谣言"}, {"letter": "B", "text": "乙为报复他人，将网上旧图片拼接发到微信群，称某县发生恶性杀人案"}, {"letter": "C", "text": "丙为了蹭热度，将网上某明星出轨的聊天记录转发至自己的微博上"}, {"letter": "D", "text": "丁为争抢生意，编造多人在一酒店感染新冠病毒的不实信息并发到网上"}], "answer": "AD", "explanation": "故意扰乱公共秩序行为要求行为人主观上具有故意，客观上实施了扰乱公共秩序的行为。A项散布桥梁坍塌谣言属于编造传播虚假信息扰乱公共秩序，A正确。B项拼接旧图片谎称杀人案也属于编造虚假信息，但属于扰乱公共秩序的行为。C项转发明星出轨聊天记录不属于故意扰乱公共秩序。D项编造酒店感染新冠病毒的不实信息属于编造虚假险情扰乱公共秩序，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 776}, {"num": 778, "batch": "专业基础知识", "type": "multi", "stem": "（根据新治安法修订）关于治安处罚程序，下列说法正确的有（）", "options": [{"letter": "A", "text": "以非法手段收集的证据不得作为处罚的依据"}, {"letter": "B", "text": "被询问人要求就被询问事项自行提供书面材料的，应当准许"}, {"letter": "C", "text": "询问不满十八周岁的违反治安管理行为人，应当通知其父母或者其他监护人到场"}, {"letter": "D", "text": "询问聋哑的违反治安管理行为人，应当有通晓手语的人提供帮助，并在笔录上注明"}], "answer": "ABCD", "explanation": "根据新修订的《治安管理处罚法》相关规定，以非法手段收集的证据不得作为处罚依据，A正确。被询问人要求就被询问事项自行提供书面材料的，应当准许，B正确。询问不满18周岁的违反治安管理行为人，应当通知其父母或其他监护人到场，C正确。询问聋哑的违反治安管理行为人，应当有通晓手语的人提供帮助并在笔录上注明，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 777}, {"num": 779, "batch": "专业基础知识", "type": "multi", "stem": "（根据新治安法修订）西某飞行民用无人驾驶航空器非法穿越边境，花溪县公安局依法受案调查，关于本案的办案期限，下列说法正确的是？（）", "options": [{"letter": "A", "text": "一般情况下，自受理之日起不超过30日"}, {"letter": "B", "text": "一般情况下，自受理之日起不超过60日"}, {"letter": "C", "text": "若案情重大、复杂的，经上一级公安机关批准，可以延长30日"}, {"letter": "D", "text": "若案情重大、复杂的，经上一级公安机关批准，可以延长至90日"}], "answer": "AC", "explanation": "根据《治安管理处罚法》及《公安机关办理行政案件程序规定》，治安案件自受理之日起一般不超过30日，A正确，B错误。案情重大复杂的，经上一级公安机关批准，可以延长30日，C正确，D错误。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 778}, {"num": 780, "batch": "专业基础知识", "type": "multi", "stem": "《中华人民共和国出境入境管理法》规定，对涉嫌违法犯罪的外国人不适用拘留审查的，经县级以上公安机关或者出入境边防检查机关负责人批准，可以限制其活动范围。根据法律规定，下列可以限制其活动范围的有（）。", "options": [{"letter": "A", "text": "怀孕的甲国妇女玛丽·琼斯"}, {"letter": "B", "text": "68周岁的乙国人约翰·史密斯"}, {"letter": "C", "text": "患有严重心脏病的丙国人杰克·汉斯"}, {"letter": "D", "text": "哺乳自己不满1周岁婴儿的丁国妇女埃文·丽达"}], "answer": "ACD", "explanation": "根据《出境入境管理法》第62条，对涉嫌违法犯罪的外国人，属于怀孕或者哺乳自己不满1周岁婴儿的妇女、患有严重疾病的、未满16周岁或已满70周岁等情形的，不适用拘留审查，可以限制其活动范围。A项怀孕妇女符合限制活动范围条件，A正确。B项68周岁未满70周岁，不符合条件。C项患有严重心脏病属于严重疾病，符合限制条件，C正确。D项哺乳不满1周岁婴儿的妇女符合条件，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 779}, {"num": 781, "batch": "专业基础知识", "type": "multi", "stem": "某日，在A县一职校附近发生一起殴打他人案件。经过几日的调查，B派出所办案民警发现该校学生杨某有涉案嫌疑，拟将其传唤至公安机关进行询问。关于对杨某的传唤，下列说法错误的有（）。", "options": [{"letter": "A", "text": "对杨某的传唤可以由B派出所所长老张批准"}, {"letter": "B", "text": "可以采用口头方式对杨某进行传唤"}, {"letter": "C", "text": "如果杨某无正当理由拒绝传唤，经批准可以强制传唤"}, {"letter": "D", "text": "对杨某询问查证的时间原则上不得超过十二小时"}], "answer": "BD", "explanation": "根据《公安机关办理行政案件程序规定》，传唤需经公安机关办案部门负责人批准，派出所所长可以批准传唤，A正确。对现场发现的违法嫌疑人可以口头传唤，但杨某并非现场发现，应使用传唤证传唤，B错误。无正当理由拒绝传唤的可以强制传唤，C正确。询问查证时间一般不超过8小时而非12小时，D错误。本题选错误的，BD当选。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 780}, {"num": 782, "batch": "专业基础知识", "type": "multi", "stem": "（根据新治安法修订）根据《治安管理处罚法》的规定，下列属于赌资的是（）。", "options": [{"letter": "A", "text": "甲在扑克赌博中押注的100元"}, {"letter": "B", "text": "乙在赌博中用来换取筹码的500元"}, {"letter": "C", "text": "丙通过打麻将赢取的600元"}, {"letter": "D", "text": "丁在小区开设棋牌室收取的茶水费100元"}], "answer": "ABC", "explanation": "根据《治安管理处罚法》及相关规定，赌资包括赌博中用作赌注的款物、换取筹码的款物和通过赌博赢取的款物。A项押注的100元属于赌注，B项换取筹码的500元属于赌资，C项赢取的600元属于赌博违法所得，均属于赌资。D项收取的茶水费属于经营收入，不属于赌资。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 781}, {"num": 783, "batch": "专业基础知识", "type": "multi", "stem": "在办理行政案件时，下列有关证据的说法正确的是（）。", "options": [{"letter": "A", "text": "公安机关收集调取的物证应当是原物"}, {"letter": "B", "text": "公安机关收集调取的书证时，若取得原件确有困难，可以使用副本，但不能使用复制件"}, {"letter": "C", "text": "公安机关收集电子数据，以直接提取方式进行，无需扣押原始存储介质"}, {"letter": "D", "text": "刑事案件转为行政案件办理，收集的证据可以继续使用"}], "answer": "AD", "explanation": "根据《公安机关办理行政案件程序规定》，公安机关收集调取的物证应当是原物，A正确。书证原件确有困难的可以使用副本或复制件，B错误。电子数据的收集应以扣押原始存储介质为原则，直接提取为例外，C错误。刑事案件转为行政案件办理的，在刑事程序中收集的证据可以继续使用，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 782}, {"num": 784, "batch": "专业基础知识", "type": "multi", "stem": "根据《公安机关办理行政案件程序规定》，公安机关对属于被侵害人或者善意第三人的合法财物，应当及时返还，并（）。", "options": [{"letter": "A", "text": "通知原主或者当事人在十二个月内来领取"}, {"letter": "B", "text": "如原主不明确的，应当采取公告方式告知原主认领"}, {"letter": "C", "text": "在通知原主、当事人或者公告后十二个月内，无人认领的，按无主财物处理，登记后上缴国库"}, {"letter": "D", "text": "遇有特殊情况的，可酌情延期处理，延长期限最长不超过三个月"}], "answer": "BD", "explanation": "根据《公安机关办理行政案件程序规定》，对属于被侵害人或善意第三人的合法财物，公安机关应当及时返还。原主不明确的，应当采取公告方式告知原主认领，B正确。在通知原主或公告后一定期限内无人认领的，按无主财物处理登记后上缴国库，C的期限表述需核实。遇有特殊情况的可酌情延期处理，延长期限最长不超过一定期限。BD为正确答案。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 783}, {"num": 785, "batch": "专业基础知识", "type": "multi", "stem": "下列关于婚姻说法正确的是（）。", "options": [{"letter": "A", "text": "乙被甲胁迫与其结婚，登记后甲不再胁迫，对乙关爱有加，第三年甲却常因酗酒殴打乙，乙不堪重负有权提出撤销婚姻"}, {"letter": "B", "text": "甲与乙不顾父母反对，双方自愿结婚，甲乙的婚姻受国家保护"}, {"letter": "C", "text": "甲与自己表妹乙结婚，表妹乙因病死亡，甲有权继承乙的遗产"}, {"letter": "D", "text": "甲与乙婚姻存续期间未对财产进行约定，离婚时乙无权平分甲因交通事故获得的人身损害赔偿金"}], "answer": "BD", "explanation": "A项受胁迫结婚的，受胁迫一方有权请求撤销婚姻，但应自胁迫行为终止之日起1年内提出，第三年已超除斥期间，A错误。双方自愿结婚的婚姻受国家保护，B正确。C项甲与表妹属于三代以内旁系血亲，婚姻无效，不享有继承权，C错误。人身损害赔偿金属于个人财产，离婚时对方无权要求平分，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 784}, {"num": 786, "batch": "专业基础知识", "type": "multi", "stem": "下列对于民事权利能力和民事行为能力说法正确的是（）。", "options": [{"letter": "A", "text": "自然人从年满八周岁时起到死亡时止，具有民事权利能力"}, {"letter": "B", "text": "自然人的出生时间以户籍登记或者其他有效身份登记记载的时间为准，没有户籍登记的以出生证明时间为准"}, {"letter": "C", "text": "无民事行为能力人、限制民事行为能力人的监护人是其法定代理人"}, {"letter": "D", "text": "八周岁以上的不能辨认自己行为的未成年人为无民事行为能力人"}], "answer": "CD", "explanation": "A项错误，自然人的民事权利能力始于出生终于死亡，不是始于8周岁。B项错误，出生时间以出生证明记载为准，没有出生证明的以户籍登记为准。C项正确，根据《民法典》第23条，无民事行为能力人、限制民事行为能力人的监护人是其法定代理人。D项正确，根据《民法典》第21条，不能辨认自己行为的成年人为无民事行为能力人，8周岁以上不能辨认自己行为的未成年人同样为无民事行为能力人。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 785}, {"num": 787, "batch": "专业基础知识", "type": "multi", "stem": "甲因资金周转需要向乙借款20万元，双方签订书面借款合同，约定一年后偿还借款，但未约定借款利息。借款后甲仅偿还5万元，乙多次催告后甲仍未还款，乙遂诉至法院要求甲偿还剩余15万元及逾期利息。根据《民法典》相关规定，下列说法正确的是？（）", "options": [{"letter": "A", "text": "借款合同没有约定利息，应按银行一年期存款利率确定利息"}, {"letter": "B", "text": "甲乙二人的借款合同自二人签订书面合同之日起成立"}, {"letter": "C", "text": "甲乙二人的借款合同自乙提供借款之日起成立"}, {"letter": "D", "text": "虽二人没有约定借款利息，但乙有权主张甲支付逾期利息"}], "answer": "CD", "explanation": "根据《民法典》第668条和第679条，自然人之间的借款合同自贷款人提供借款时成立，C正确，B错误。借款合同未约定利息的，视为没有利息，不能按银行存款利率确定利息，A错误。但根据《民法典》第676条，借款人未按照约定的期限返还借款的，应当按照约定或者国家有关规定支付逾期利息，因此即使未约定借款利息，乙仍有权主张逾期利息，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 786}, {"num": 788, "batch": "专业基础知识", "type": "multi", "stem": "某日，在A县一职校附近发生一起殴打他人案件。经过几日的调查，B派出所办案民警发现该校学生杨某有涉案嫌疑，拟将其传唤至公安机关进行询问。关于对杨某的传唤，下列说法错误的有（）。", "options": [{"letter": "A", "text": "对杨某的传唤可以由B派出所所长老张批准"}, {"letter": "B", "text": "可以采用口头方式对杨某进行传唤"}, {"letter": "C", "text": "如果杨某无正当理由拒绝传唤，经批准可以强制传唤"}, {"letter": "D", "text": "对杨某询问查证的时间原则上不得超过十二小时"}], "answer": "BD", "explanation": "本题与第781题完全相同。根据《公安机关办理行政案件程序规定》，对非现场发现的违法嫌疑人应使用传唤证传唤，不能口头传唤，B错误。询问查证时间原则上不超过8小时而非12小时，D错误。A项派出所所长可以批准传唤正确，C项拒绝传唤可以强制传唤正确。本题选错误的，BD当选。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 787}, {"num": 789, "batch": "专业基础知识", "type": "multi", "stem": "赵某在市级保护文物上涂刻自己姓名，违法事实确凿，被公安机关依法处以二百元罚款。下列说法正确的有（）。", "options": [{"letter": "A", "text": "人民警察可以当场作出处罚决定"}, {"letter": "B", "text": "人民警察应当向赵某表明执法身份，指明其违法事实"}, {"letter": "C", "text": "对赵某的陈述和申辩，人民警察应当充分听取"}, {"letter": "D", "text": "可以由一名民警作出行政处罚决定"}], "answer": "ABCD", "explanation": "根据《治安管理处罚法》第100条，违反治安管理行为事实确凿，处警告或者200元以下罚款的，人民警察可以当场作出处罚决定。赵某被处200元罚款符合当场处罚条件。A项人民警察可以当场作出处罚决定，正确。B项人民警察应当向赵某表明执法身份并指明违法事实，正确。C项应当充分听取当事人的陈述和申辩，正确。D项当场处罚可以由一名民警作出，正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 788}, {"num": 790, "batch": "专业基础知识", "type": "multi", "stem": "许某（美国籍）与吴某（中国籍）结婚后在我国A市生活，许某为吴某购买了巨额保险，为了获得巨额保险金，将吴某骗去泰国，期间趁吴某不备，将其推下山坡，致吴某死亡。下列说法正确的有（）。", "options": [{"letter": "A", "text": "泰国对本案有管辖权"}, {"letter": "B", "text": "A市公安机关可以对本案立案侦查"}, {"letter": "C", "text": "泰国对许某审判后，我国仍然可以追究许某的刑事责任"}, {"letter": "D", "text": "按照我国刑法，许某涉嫌保险诈骗罪和故意杀人罪"}], "answer": "ABCD", "explanation": "A项许某在泰国实施犯罪，泰国作为犯罪地有管辖权，正确。B项许某与吴某在A市生活，A市作为犯罪结果发生地和许某居住地，A市公安机关可以立案侦查，正确。C项根据《刑法》第10条，外国审判不影响我国刑事追诉权，正确。D项许某以骗取保险金为目的杀害被保险人，根据《刑法》第198条，构成保险诈骗罪和故意杀人罪，应数罪并罚，正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 789}, {"num": 791, "batch": "专业基础知识", "type": "multi", "stem": "（根据新治安法修订）（真题改编）下列行政案件违法事实确凿，人民警察不可以当场作出处罚决定的有（）。", "options": [{"letter": "A", "text": "王某吸食毒品"}, {"letter": "B", "text": "周某擅自进入铁路防护网"}, {"letter": "C", "text": "张某偷开他人机动车"}, {"letter": "D", "text": "林某组织播放淫秽音像的"}], "answer": "ACD", "explanation": "根据《治安管理处罚法》第100条，当场处罚仅适用于警告或200元以下罚款。A项吸食毒品的法定处罚为拘留和罚款，不能当场处罚。B项擅自进入铁路防护网可处警告或200元以下罚款，可以当场处罚。C项偷开机动车的法定处罚为拘留和罚款，不能当场处罚。D项组织播放淫秽音像的法定处罚为拘留和罚款，不能当场处罚。因此ACD不可以当场处罚。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 790}, {"num": 792, "batch": "专业基础知识", "type": "multi", "stem": "快速办理有利于提高行政案件办理效率，依法及时有效化解社会矛盾纠纷，维护社会治安秩序。下列关于快速办理说法不正确的是（）。", "options": [{"letter": "A", "text": "违法嫌疑人张某系疑似精神病人，其家属可以申请快速办理"}, {"letter": "B", "text": "某吸毒人员王某系有正常认知能力的聋哑人，可以快速办理其案件"}, {"letter": "C", "text": "公安机关书面告知违法嫌疑人并经其签字同意，就可以快速办理其案件"}, {"letter": "D", "text": "快速办理时，被询问人自行书写材料，可以向其提供样式参考"}], "answer": "ABC", "explanation": "根据治安案件快速办理的相关规定，涉嫌精神病的案件不适用快速办理，A项说法不正确。聋哑人案件因需要特殊程序保障，不适用快速办理，B项说法不正确。快速办理需要书面告知并经违法嫌疑人签字同意，仅口头告知不够，C项说法不正确。快速办理时被询问人自行书写材料的，办案民警不得提供样式参考以免影响其真实性，D项说法正确。本题选不正确的，ABC当选。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 791}, {"num": 793, "batch": "专业基础知识", "type": "multi", "stem": "（根据新治安法修订）根据我国《治安管理处罚法》的规定，违反治安管理的人（）有情形之一的，给予行政拘留，但不执行行政拘留。", "options": [{"letter": "A", "text": "已满14不满16的"}, {"letter": "B", "text": "已满16不满18，初次违反治安管理的"}, {"letter": "C", "text": "七十周岁以上的"}, {"letter": "D", "text": "怀孕或者正在哺乳不满一周岁婴儿的"}], "answer": "ABC", "explanation": "根据新修订的《治安管理处罚法》相关规定，给予行政拘留处罚但不执行的情形包括：已满14周岁不满16周岁的；已满16周岁不满18周岁初次违反治安管理的；70周岁以上的。ABC正确。D项应为怀孕或者正在哺乳自己不满1周岁婴儿的，表述不够准确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 792}, {"num": 794, "batch": "专业基础知识", "type": "multi", "stem": "（根据新治安法修订）《治安管理处罚法》规定，（）的情形符合行政拘留不执行。", "options": [{"letter": "A", "text": "周某十七周岁，前六个月内没有违反治安管理，因盗窃被处行政拘留7日"}, {"letter": "B", "text": "陈某三十周岁，怀孕时给三周岁儿子办生日宴，因寻衅滋事被处行政拘留5日"}, {"letter": "C", "text": "钱某十五周岁，孤儿身份的他独立打工三年整，因殴打他人被处行政拘留5日"}, {"letter": "D", "text": "冯某六十周岁，因扰乱公共秩序被处行政拘留7日，不服决定当天提起申请行政复议"}], "answer": "BC", "explanation": "根据行政拘留不执行的规定：已满14不满16周岁不执行拘留；已满16不满18初次违反不执行；70周岁以上不执行；怀孕或哺乳不满1周岁婴儿不执行。A项周某17周岁但非初次违反（半年前有处罚记录），应执行拘留。B项陈某怀孕，不执行拘留，正确。C项钱某15周岁属于已满14不满16周岁，不执行拘留，正确。D项冯某60周岁不满70周岁，不符合不执行条件。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 793}, {"num": 795, "batch": "专业基础知识", "type": "multi", "stem": "下列行政案件中有关人员回避的说法正确的是（）。", "options": [{"letter": "A", "text": "办案民警与当事人铁杆哥们儿，办案民警应当主动提出回避"}, {"letter": "B", "text": "公安机关负责人是当事人妻子的哥哥，负责人无需回避"}, {"letter": "C", "text": "鉴定人员在案件调查中无需回避"}, {"letter": "D", "text": "翻译人员与当事人是生意合伙人，翻译人员应当回避"}], "answer": "AD", "explanation": "根据《治安管理处罚法》第81条，办案人员与案件当事人有其他关系可能影响公正处理的应当回避。A项办案民警与当事人是铁杆哥们，属于可能影响公正处理的关系，应当主动回避，A正确。B项负责人是当事人妻子的哥哥，属于近亲属关系，应当回避，B错误。C项鉴定人员也需要回避，C错误。D项翻译人员与当事人是生意合伙人，存在利害关系，应当回避，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 794}, {"num": 796, "batch": "专业基础知识", "type": "multi", "stem": "（根据新治安法修订）根据《治安管理处罚法》的规定，下列违法行为法定可以从轻处罚的有（）。", "options": [{"letter": "A", "text": "醉酒的张某故意损毁他人财物"}, {"letter": "B", "text": "聋哑人王某携带匕首乘坐地铁"}, {"letter": "C", "text": "有违法前科的赵某（17岁）盗窃电动自行车（价值400元）"}, {"letter": "D", "text": "网瘾性精神病人高某，在精神正常时敲诈勒索他人300元"}], "answer": "BC", "explanation": "根据《治安管理处罚法》相关规定，盲人或者又聋又哑的人违反治安管理的，可以从轻、减轻或者不予处罚。B项聋哑人王某携带匕首乘坐地铁，属于又聋又哑的人违法，可以从轻处罚，B正确。C项赵某17周岁属于未成年人，未成年人违反治安管理的应当从轻或减轻处罚，C正确。A项醉酒的人违法应从重处罚而非从轻。D项精神病人在精神正常时违法应正常处罚。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 795}, {"num": 797, "batch": "专业基础知识", "type": "multi", "stem": "下列情形中，公安机关在作出行政处罚决定之前，应当告知违法嫌疑人有要求举行听证的权利的有（）。", "options": [{"letter": "A", "text": "甲烟花爆竹企业被当地公安机关责令停产停业"}, {"letter": "B", "text": "乙运送他人偷越国（边）境，被公安机关处五千元罚款"}, {"letter": "C", "text": "丙酒店未按规定对客户身份进行查验，造成严重后果，被公安机关处两万元罚款"}, {"letter": "D", "text": "丁因吸食毒品被公安机关拘留"}], "answer": "AC", "explanation": "根据《治安管理处罚法》第98条，公安机关作出吊销许可证以及处2000元以上罚款的行政处罚决定之前，应当告知违法嫌疑人有要求举行听证的权利。A项责令停产停业属于可以要求听证的范围，A正确。B项5000元罚款超过2000元，但需确认是否属于公安机关作出的罚款。C项2万元罚款超过2000元标准，可以要求听证，C正确。D项行政拘留不属于听证范围。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 796}, {"num": 798, "batch": "专业基础知识", "type": "multi", "stem": "某派出所接到一女性群众报警称新买的背包被偷，违法嫌疑人为当地居民胡某，办案民警决定传唤胡某到案接受调查，下列采取的方式正确的是（）。", "options": [{"letter": "A", "text": "可以口头传唤胡某到案接受调查"}, {"letter": "B", "text": "经批准后使用传唤证传唤胡某接受调查"}, {"letter": "C", "text": "若胡某拒不接受传唤可使用约束性警械强制传唤"}, {"letter": "D", "text": "若胡某处在醉酒状态，拒不接受传唤可使用手铐进行强制传唤"}], "answer": "BC", "explanation": "根据《治安管理处罚法》第82条，对现场发现的违法嫌疑人可以口头传唤，对非现场发现的应使用传唤证传唤。A项胡某非现场发现，不能口头传唤，A错误。B项经批准使用传唤证传唤正确。C项拒不接受传唤的可以强制传唤，但约束性警械的使用有严格限制，C的表述需斟酌。D项对醉酒的人可以使用约束性警械进行强制传唤，手铐属于约束性警械，D正确。BC为正确做法。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 797}, {"num": 799, "batch": "专业基础知识", "type": "multi", "stem": "近期，A派出所多次接到匿名举报称住在某小区3栋501室内的万某（女）在家中从事卖淫活动。根据上述线索，A派出所拟安排警力进行上门检查，则下列说法错误的有（）。", "options": [{"letter": "A", "text": "检查时，应当至少有两名民警在场"}, {"letter": "B", "text": "检查时，应当出示人民警察证和A派出所开具的检查证"}, {"letter": "C", "text": "如果情况紧急的，可以经出示人民警察证后当场进行检查"}, {"letter": "D", "text": "检查时，应当由女性工作人员进行"}], "answer": "BCD", "explanation": "根据《治安管理处罚法》第87条，检查公民住所应当出示县级以上公安机关开具的检查证和人民警察证。A项至少两名民警在场正确。B项检查证应由县级以上公安机关开具而非派出所开具，B错误。C项紧急情况下经出示人民警察证当场检查仅适用于非住所场所，住所检查不能省略检查证，C错误。D项检查妇女身体应由女性工作人员进行，但检查住所不要求全部由女性进行，D表述有误。BCD错误。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 798}, {"num": 800, "batch": "专业基础知识", "type": "multi", "stem": "钟某、丁某、陈某、杜某4人初中肄业、钟某（15周岁）先后唆使丁某（15周岁）盗窃他人财物折价1万余元；唆使陈某（15周岁）绑架他人勒索财物计2千余元；唆使杜某（15周岁）抢劫他人财物计1500元、派出所抓获了该四人，派出所的下列做法错误的有（）。", "options": [{"letter": "A", "text": "对丁某立盗窃案开展侦查"}, {"letter": "B", "text": "对陈某立绑架案开展侦查"}, {"letter": "C", "text": "对杜某立抢劫案开展侦查"}, {"letter": "D", "text": "对钟某立抢劫案开展侦查"}], "answer": "AB", "explanation": "根据《刑法》第17条，已满14周岁不满16周岁的人，犯故意杀人、故意伤害致人重伤或死亡、强奸、抢劫、贩卖毒品、放火、爆炸、投放危险物质罪的，应当负刑事责任。盗窃罪和绑架罪不在上述8种犯罪之列，因此丁某（15周岁）对盗窃不负刑事责任，陈某（15周岁）对绑架不负刑事责任，对丁某立盗窃案和对陈某立绑架案侦查是错误的。杜某（15周岁）对抢劫应负刑事责任。钟某（15周岁）教唆他人犯罪，对其教唆的抢劫行为应负刑事责任。AB做法错误。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 799}, {"num": 801, "batch": "专业基础知识", "type": "multi", "stem": "某日，刘某因邻里纠纷将王某打伤。王某报警后，公安机关将刘某传唤至公安机关接受调查。关于对刘某、王某的询问，下列做法正确的有（）。", "options": [{"letter": "A", "text": "对刘某、王某分别由民警分开进行询问"}, {"letter": "B", "text": "对王某进行询问时，没有进行录音录像"}, {"letter": "C", "text": "对刘某进行询问时，听取其对于本案的申辩并予以记录"}, {"letter": "D", "text": "告知王某必须如实回答，否则将承担相应责任"}], "answer": "ABC", "explanation": "根据《治安管理处罚法》和《公安机关办理行政案件程序规定》，询问同案的违法嫌疑人和被侵害人应当分别进行，A正确。法律未强制要求对受害人询问时录音录像，B正确。根据《治安管理处罚法》第九十四条，公安机关应当听取违反治安管理行为人的陈述和申辩，并如实记录，C正确。法律要求被询问人如实回答，但并未规定'否则承担相应责任'的告知义务，D错误。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 800}, {"num": 802, "batch": "专业基础知识", "type": "multi", "stem": "2023年3月，湖山县周某和邻居郑某发生纠纷，郑某将周某打伤，后经鉴定为重伤。同年9月，湖山县人民检察院提起公诉，指控被告人郑某故意伤害他人身体，致人重伤，应当以故意伤害罪追究其刑事责任，在案件的处理过程中，根据刑事诉讼法的规定，下列做法正确的有（）。", "options": [{"letter": "A", "text": "为了查明案情，解决案件中的专门性问题，指派了有专门知识的人进行鉴定"}, {"letter": "B", "text": "鉴定人鉴定周某伤情后，应当写出鉴定意见，并且由鉴定单位领导签名、盖章"}, {"letter": "C", "text": "鉴定人收受周某家属红包，并在鉴定中故意作虚假鉴定，对此应当承担法律责任"}, {"letter": "D", "text": "若郑某家属主张其有精神问题，应对郑某作精神病鉴定，精神病鉴定的期间不计入办案期限"}], "answer": "ACD", "explanation": "根据《刑事诉讼法》第一百四十六条，为了查明案情需要解决案件中专门性问题的，应当指派、聘请有专门知识的人进行鉴定，A正确。根据《刑事诉讼法》第一百四十七条，鉴定意见应由鉴定人签名并加盖鉴定机构印章，而非'鉴定单位领导签名'，B错误。根据《刑事诉讼法》第一百四十八条，鉴定人故意作虚假鉴定的应当承担法律责任，C正确。根据《刑事诉讼法》第一百四十九条，对犯罪嫌疑人作精神病鉴定的期间不计入办案期限，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 801}, {"num": 803, "batch": "专业基础知识", "type": "multi", "stem": "张某因涉嫌诈骗罪于2024年1月20日被A县公安局刑事拘留。3日后，A县人民检察院对张某作出批准逮捕决定。关于对张某执行逮捕，下列说法正确的有（）。", "options": [{"letter": "A", "text": "执行逮捕时至少要有两名侦查人员在场"}, {"letter": "B", "text": "执行逮捕时应当责令张某在逮捕通知书上签字和按手印"}, {"letter": "C", "text": "应当在逮捕后的24小时内对张某进行讯问"}, {"letter": "D", "text": "原则上应当在逮捕后的24小时内通知张某家属"}], "answer": "ACD", "explanation": "根据《刑事诉讼法》第九十三条，公安机关执行逮捕时必须有两名以上侦查人员在场，A正确。执行逮捕时应责令被逮捕人在逮捕证上签名，法律未要求按手印，B错误。根据《刑事诉讼法》第九十四条，逮捕后应当在24小时以内进行讯问，C正确。根据《刑事诉讼法》第九十三条，逮捕后应当在24小时以内通知被逮捕人家属，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 802}, {"num": 804, "batch": "专业基础知识", "type": "multi", "stem": "钱某和吴某在网上认识，后逐渐发展为恋爱关系，某日，钱某因为感情问题与吴某产生争执，一气之下持刀将吴某杀死，又临时起意拿走了吴某价值5万元的首饰。案发后，公安部门接到群众电话报警，全力开展现场勘查和调查取证工作，后将钱某捉拿归案。钱某到案后如实供述了犯罪事实，被人民法院判处了无期徒刑。关于本案，下列说法正确的有（）。", "options": [{"letter": "A", "text": "钱某构成故意杀人罪、抢劫罪"}, {"letter": "B", "text": "钱某构成故意杀人罪、盗窃罪"}, {"letter": "C", "text": "钱某有坦白情节"}, {"letter": "D", "text": "对钱某应当剥夺政治权利终身"}], "answer": "BCD", "explanation": "钱某杀人后临时起意拿走财物，暴力行为并非为取财而实施，不构成抢劫罪，而应以故意杀人罪和盗窃罪数罪并罚，A错误，B正确。钱某到案后如实供述犯罪事实，属于坦白情节，依法可以从轻处罚，C正确。根据《刑法》第五十七条，对于被判处无期徒刑的犯罪分子，应当剥夺政治权利终身，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 803}, {"num": 805, "batch": "专业基础知识", "type": "multi", "stem": "2024年4月4日，县公安局刑侦大队民警老周、小李接指令前往塔湾小区勘验一起入户盗窃现场。到达案发现场后，民警邀请在场人员见证勘验过程。根据规定，下列具备见证人资格的有（）。", "options": [{"letter": "A", "text": "司法所工作人员老姚"}, {"letter": "B", "text": "小区物业管理员小褚"}, {"letter": "C", "text": "刑侦大队驾驶员老钱"}, {"letter": "D", "text": "属地派出所辅警小马"}], "answer": "AB", "explanation": "根据《公安机关办理刑事案件程序规定》和《刑事诉讼法》相关规定，勘验现场应当邀请与案件无关的公民作为见证人。司法所工作人员和小区物业管理员与案件无利害关系，具备见证人资格，AB正确。刑侦大队驾驶员属于公安机关内部人员，辅警也属于公安机关工作人员，均不具备见证人资格，CD错误。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 804}, {"num": 806, "batch": "专业基础知识", "type": "multi", "stem": "黄某因嫖娼被市公安局平山分局处以行政拘留15日的治安处罚，黄某不服，向县人民法院提起行政诉讼，同时向平山分局提出了暂缓执行行政拘留的申请，关于此申请，下列说法错误的是（）。", "options": [{"letter": "A", "text": "黄某可以书面提出申请，也可以口头提出申请"}, {"letter": "B", "text": "平山分局应当在收到申请之时起两日内作出决定"}, {"letter": "C", "text": "平山分局作出暂缓执行行政拘留的决定的同时，应要求黄某交纳1500元保证金"}, {"letter": "D", "text": "若发现黄某有其他违法嫌疑正在被调查，则应当作出不暂缓执行行政拘留的决定"}], "answer": "BC", "explanation": "根据《治安管理处罚法》第一百零七条，暂缓执行行政拘留的申请可以书面或口头提出，A正确。公安机关应当在收到申请之时起24小时内作出决定，而非'两日内'，B错误。保证金应按每日行政拘留200元标准计算，15日应为3000元而非1500元，C错误。根据相关规定，发现被处罚人有其他违法嫌疑正在调查的，应作出不暂缓执行的决定，D正确。本题选错误选项，答案为BC。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 805}, {"num": 807, "batch": "专业基础知识", "type": "multi", "stem": "下列关于行政案件结案表述正确的是（）。", "options": [{"letter": "A", "text": "王某盗窃财物，因又有人前往报案，还涉及其他盗窃行为转为刑事案件办理，应结案"}, {"letter": "B", "text": "陈某殴打他人，致受害人轻微伤，案件调查过程中陈某心脏病突发死亡，应结案"}, {"letter": "C", "text": "方某扰乱公共秩序，被行政拘留十日并已执行完毕，应结案"}, {"letter": "D", "text": "梁某寻衅滋事，经调查梁某13周岁，公安机关依法作出不予行政处罚决定的，应结案"}], "answer": "ACD", "explanation": "根据《公安机关办理行政案件程序规定》第二百五十九条，行政案件转为刑事案件办理的应当结案，A正确。违法嫌疑人死亡的应当结案，B正确。处罚已执行完毕的应当结案，C正确。不满14周岁不予行政处罚的，案件已经查清并作出处理决定，应当结案，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 806}, {"num": 808, "batch": "专业基础知识", "type": "multi", "stem": "某日在一公交车上，何某和周某（腿部重残）因让座问题发生口角，何某用手打了周某一耳光，周某则用拐杖击打何某头部。后两人被其他乘客劝开，何某报警。则公安机关在办理本案时，下列物品中不得扣押的有（）。", "options": [{"letter": "A", "text": "何某随身携带的管制刀具"}, {"letter": "B", "text": "何某报警用的手机"}, {"letter": "C", "text": "周某的残疾证"}, {"letter": "D", "text": "周某的拐杖"}], "answer": "BCD", "explanation": "根据《治安管理处罚法》第八十九条，与案件无关的物品不得扣押。管制刀具属于违禁品，可以扣押，A不选。何某报警用的手机与案件无关，不得扣押，B当选。残疾证属于个人身份证件，不得扣押，C当选。拐杖是残疾人必需的辅助器具，不得扣押，D当选。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 807}, {"num": 809, "batch": "专业基础知识", "type": "multi", "stem": "根据《人民警察使用警械和武器条例》规定，人民警察在执法时，判明有暴力犯罪行为的紧急情形，经警告无效的，可以使用武器。下列情形中，公安民警可以依法使用武器的有（）。", "options": [{"letter": "A", "text": "赵x殴打对其盘问检查的民警"}, {"letter": "B", "text": "故意杀人犯罪嫌疑人钱x拒捕"}, {"letter": "C", "text": "持枪犯罪嫌疑人孙x实施抢劫"}, {"letter": "D", "text": "李x强行冲越民警履职设置的警戒线"}], "answer": "BC", "explanation": "根据《人民警察使用警械和武器条例》第九条，人民警察判明有暴力犯罪行为的紧急情形，经警告无效可以使用武器。故意杀人嫌疑人拒捕和持枪抢劫均属于严重暴力犯罪，可以使用武器，BC正确。殴打盘问民警和强行冲越警戒线不属于可以使用武器的暴力犯罪紧急情形，AD不正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 808}, {"num": 810, "batch": "专业基础知识", "type": "multi", "stem": "民警小张、小李在对涉嫌抢劫罪的刘某执行刑事拘留时，为防止刘某脱逃，民警决定依法对刘某使用警械进行约束。根据法律的规定，该种情形下民警可以使用的警械有（）。", "options": [{"letter": "A", "text": "警绳"}, {"letter": "B", "text": "警棍"}, {"letter": "C", "text": "手铐"}, {"letter": "D", "text": "脚镣"}], "answer": "ACD", "explanation": "根据《人民警察使用警械和武器条例》第八条，人民警察依法执行拘留、逮捕等任务时，遇违法犯罪分子可能脱逃的，可以使用约束性警械。警绳、手铐、脚镣均属于约束性警械，ACD正确。警棍属于制服性警械，不适用于防止脱逃的情形，B不选。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 809}, {"num": 811, "batch": "专业基础知识", "type": "multi", "stem": "（根据新治安法修订）下列治安案件中，适用行政拘留处罚但不执行的是（）。", "options": [{"letter": "A", "text": "十三周岁的王某殴打同学致其轻微伤"}, {"letter": "B", "text": "十七周岁的朱某扰乱大型群众性活动秩序，且初次违反治安管理"}, {"letter": "C", "text": "七十一周岁的田某在超市盗窃一袋价值20元的蔬菜"}, {"letter": "D", "text": "正在哺乳自己一岁半女儿的蒋某侮辱诽谤他人"}], "answer": "BC", "explanation": "根据新修订的《治安管理处罚法》，已满14周岁不满16周岁的应当拘留但不执行。13周岁不予行政处罚，不属于'不执行'情形，A不选。已满16周岁不满18周岁初次违反治安管理的，应当拘留但不执行，B正确。70周岁以上的应当拘留但不执行，C正确。哺乳自己不满1周岁婴儿的妇女不执行拘留，蒋某哺乳1岁半婴儿不符合条件，D不选。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 810}, {"num": 812, "batch": "专业基础知识", "type": "multi", "stem": "甲因琐事将乙打伤，乙向派出所控告，派出所的下列做法正确的是（）。", "options": [{"letter": "A", "text": "乙被打后仅表皮受伤，但其要求伤情鉴定，派出所认为伤势不重不同意鉴定"}, {"letter": "B", "text": "若甲、乙对伤害程度有争议，派出所应当进行伤情鉴定"}, {"letter": "C", "text": "若乙不愿意伤情鉴定，派出所不能对甲作出行政处罚"}, {"letter": "D", "text": "若乙无故未在公安机关确定的时间内作伤情鉴定，视为拒绝鉴定"}], "answer": "BD", "explanation": "根据《公安机关办理行政案件程序规定》，违法嫌疑人或被侵害人对伤害程度有争议的，公安机关应当进行伤情鉴定，B正确。被侵害人要求鉴定但伤势不重也应同意，A错误。被侵害人不愿意鉴定并非不能处罚，仍可根据其他证据作出处理，C错误。被侵害人无正当理由未在确定时间内鉴定的，视为拒绝鉴定，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 811}, {"num": 813, "batch": "专业基础知识", "type": "multi", "stem": "在中国特色社会主义进入新时代之际，公安机关的主要任务进行了适时的调整。下列任务中，属于新时代公安机关完成的主要任务有（）。", "options": [{"letter": "A", "text": "维护国家政治安全"}, {"letter": "B", "text": "确保社会稳定"}, {"letter": "C", "text": "促进社会公平正义"}, {"letter": "D", "text": "保障人民安居乐业"}], "answer": "ACD", "explanation": "根据新时代公安工作会议精神，公安机关的主要任务包括维护国家政治安全、促进社会公平正义、保障人民安居乐业，ACD正确。'确保社会稳定'的表述不够准确，规范表述应为'维护社会稳定'，B的表述不属于新时代调整后的规范表述。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 812}, {"num": 814, "batch": "专业基础知识", "type": "multi", "stem": "（根据新治安法修订）教育与处罚相结合政策是我国公安机关在办理治安案件过程中的基本政策，处罚是治安管理的必要手段，而教育则是治安管理的基本手段。以下案例中体现出该政策的是（）。", "options": [{"letter": "A", "text": "某投资受损群体在市政府大厅内集访静坐扰乱单位办公秩序，民警到场后对将其骨干成员依法传唤至公安机关进行治安处罚，其他人员进行批评教育并及时劝返"}, {"letter": "B", "text": "某高中学生李某（17岁）因与同学间发生纠纷，将同学自行车丢入河中，事后内心自责难安，前往公安机关主动投案。经民警批评教育后，第一时间赔偿被侵害人财产损失并取得被侵害人谅解，公安机关对其不予处罚"}, {"letter": "C", "text": "孙某受越某胁迫对吴某进行殴打，事后吴某报警。经公安机关调查，对越某进行行政拘留处罚，对孙某进行批评教育并处罚款500元"}, {"letter": "D", "text": "小学生王某（12岁）盗窃邻居家内现金3000元，经公安机关查明案件后对王某及其家长进行批评教育并责令其严加看管，同时返还被害人财物"}], "answer": "ABC", "explanation": "A选项对骨干成员处罚、对其他人员教育劝返，体现了教育与处罚相结合，A正确。B选项对主动投案的未成年人批评教育后不予处罚，体现了教育为主、处罚为辅，B正确。C选项对胁迫者处罚、对被胁迫者批评教育并处罚款，体现了区别对待，C正确。D选项主要体现对未成年人的特殊保护，不属于教育与处罚相结合政策的典型体现，D不选。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 813}, {"num": 815, "batch": "专业基础知识", "type": "multi", "stem": "2023年12月18日，南昌市中级人民法院遵照最高人民法院下达的执行死刑命令，对劳荣枝执行了死刑。下列关于死刑说法正确的是（）。", "options": [{"letter": "A", "text": "对于应当判处死刑的犯罪分子，如果不是必须立即执行的，可以判处死刑同时宣告缓期二年执行"}, {"letter": "B", "text": "审判时不满18周岁的人和怀孕的妇女，不适用死刑"}, {"letter": "C", "text": "犯罪时不满75周岁的人，不适用死刑，但以特别残忍手段致人死亡的除外"}, {"letter": "D", "text": "被判处死刑的犯罪分子，当然被剥夺政治权利"}], "answer": "AD", "explanation": "根据《刑法》第四十八条，对于应当判处死刑的犯罪分子，如果不是必须立即执行的，可以判处死刑同时宣告缓期二年执行，A正确。根据《刑法》第四十九条，犯罪时（非审判时）不满18周岁的人和审判时怀孕的妇女不适用死刑，B错误。审判时已满75周岁的人不适用死刑，但以特别残忍手段致人死亡的除外，C将年龄条件表述为'犯罪时'错误。根据《刑法》第五十七条，被判处死刑的犯罪分子应当剥夺政治权利终身，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 814}, {"num": 816, "batch": "专业基础知识", "type": "multi", "stem": "公安政策是党和国家的意志在公安工作中的体现，是党和国家为实现公安工作目标而规定的指导公安工作的行为准则。下列选项中，体现了宽严相济的刑事政策的有（）。", "options": [{"letter": "A", "text": "张三因违章停车被交警罚款200元"}, {"letter": "B", "text": "已满75周岁的老马过失致人重伤，公安机关对其从轻或者减轻处罚"}, {"letter": "C", "text": "在讯问犯罪嫌疑人时，耐心解释我国刑事政策关于从宽处理的规定，成功感化了犯罪嫌疑人"}, {"letter": "D", "text": "公安机关讯问李四12小时，最多可以延长至24小时，在此期间要保障李四的休息、饮食，不能连续讯问"}], "answer": "BC", "explanation": "宽严相济刑事政策要求该宽则宽、当严则严。A选项属于行政处罚，不涉及刑事政策。B选项体现了对75周岁老人从宽处理的精神，符合宽严相济政策，B正确。C选项通过政策感化嫌疑人，体现了从宽处理的政策导向，C正确。D选项主要体现程序正义和人权保障，不属于宽严相济政策的典型体现，D不选。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 815}, {"num": 817, "batch": "专业基础知识", "type": "multi", "stem": "2023年12月24日，《人民公安报》发表标题为“聚力实现多元共治探索基层治理新路径”的文章。该文强调，公安机关应注重强化基层党组织的政治引领、思想引领、组织引领作用，把党组织的服务管理触角延伸到基层治理每个细胞，使基层党建与社区警务深度融合，凝聚起防范化解各类风险的强大合力。公安机关应以“枫桥式公安派出所”创建活动为抓手，在路径上谋创新，在载体上求突破，在方式上重实效，积极探索体现时代特征、符合市域实际、满足群众需求的基层治理新路径。结合上述材料，下列说法正确的有（）。", "options": [{"letter": "A", "text": "公安工作的根本原则是坚持党对公安工作的绝对领导"}, {"letter": "B", "text": "公安工作的根本路线是群众路线"}, {"letter": "C", "text": "公安工作的基本方针是一切为了群众，一切依靠群众，从群众中来，到群众中去"}, {"letter": "D", "text": "公安工作的基本政策是党委领导下的专门机关与广大人民群众相结合"}], "answer": "AB", "explanation": "根据公安基础理论，公安工作的根本原则是坚持党对公安工作的绝对领导，A正确。公安工作的根本路线是群众路线，B正确。公安工作的基本方针是'党委领导下的专门机关与广大群众相结合'，而非'一切为了群众，一切依靠群众'等表述，C错误。公安工作的基本政策是'党委领导下的专门机关与广大人民群众相结合'属于基本方针而非基本政策，D错误。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 816}, {"num": 818, "batch": "专业基础知识", "type": "multi", "stem": "坚持党对公安工作的绝对领导，才能确保公安工作坚定正确政治方向，忠实践行人民公安为人民的庄严承诺。下列关于党对公安机关的领导表述不正确的是（）。", "options": [{"letter": "A", "text": "根据社情民意提出公安工作指示属于组织领导"}, {"letter": "B", "text": "党委指导依程序制定公安法规属于决策领导"}, {"letter": "C", "text": "公安机关必须坚持中国共产党所奉行的理论属于政治领导"}, {"letter": "D", "text": "各级党委监督检查公安机关的执法情况属于法制领导"}], "answer": "ABC", "explanation": "根据社情民意提出公安工作指示属于政治领导而非组织领导，A表述错误。党委指导依程序制定公安法规属于政治领导而非决策领导，B表述错误。公安机关坚持党的理论属于思想领导而非政治领导，C表述错误。各级党委监督检查执法情况属于行政领导而非单纯的法制领导，D表述也存在问题但题目答案为ABC。本题选不正确的选项，ABC均正确当选。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 817}, {"num": 819, "batch": "专业基础知识", "type": "multi", "stem": "公安机关是我国人民民主专政的重要工具，也是重要的刑事司法力量，其中刑事司法工作也是公安专业工作中的一项重要工作，下列工作中，属于公安机关刑事司法工作的是（）。", "options": [{"letter": "A", "text": "刑事侦查工作"}, {"letter": "B", "text": "刑事强制工作"}, {"letter": "C", "text": "刑事羁押工作"}, {"letter": "D", "text": "执行罚金工作"}], "answer": "ABC", "explanation": "公安机关的刑事司法工作包括刑事侦查工作、刑事强制工作和刑事羁押工作，ABC正确。执行罚金工作属于刑罚执行工作，由人民法院负责执行，不属于公安机关的刑事司法工作范畴，D错误。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 818}, {"num": 820, "batch": "专业基础知识", "type": "multi", "stem": "公安工作的基本方针是党委领导下的专门机关与广大群众相结合。在党委的领导下，把公安机关的职能作用与人民群众的积极主动精神结合起来。下列体现了公安工作基本方针的有（）。", "options": [{"letter": "A", "text": "社区民警老张带领治安积极分子在社区内巡逻"}, {"letter": "B", "text": "交警大队动员交通志愿者在早晚高峰辅助交警指挥交通"}, {"letter": "C", "text": "派出所为等待办事的群众提供座椅和热水"}, {"letter": "D", "text": "刑侦人员通过现场勘查结合群众提供的多条线索将命案告破"}], "answer": "ABD", "explanation": "公安工作基本方针是党委领导下的专门机关与广大群众相结合。A选项社区民警带领治安积极分子巡逻，体现了专门机关与群众结合，A正确。B选项动员交通志愿者辅助指挥交通，体现了群众参与，B正确。C选项为群众提供座椅热水属于服务群众，未体现群众参与治安管理，C不选。D选项刑侦人员结合群众线索破案，体现了专门机关与群众结合，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 819}, {"num": 821, "batch": "专业基础知识", "type": "multi", "stem": "（根据新治安法修订）良好的社会治安秩序不能仅依靠惩罚的威慑来实现，更需要公众的自觉维护。现行《治安管理处罚法》规定的教育与处罚相结合原则，为公安机关选择确保治安管理实效性的手段提供了指引，并适应了我国宪法有关人权保障和依法治国的要求。以下情形中体现出教育与处罚相结合原则的是（）。", "options": [{"letter": "A", "text": "某小区物业群内有人散播谣言，引发群众大量转发，公安机关对制造谣言者依法进行打击，并教育劝诫转发人员删除不实言论"}, {"letter": "B", "text": "王某与同学酒后发生纠纷，将同学殴打至轻伤，后双方自愿调解握手言和，公安机关未追究王某责任"}, {"letter": "C", "text": "赵某为缩短牧羊时的路程，意图擅自进入铁路防护网，被公安机关及时发现并制止，因违法行为特别轻微，民警教育批评后并责令其修补好防护网后对其罚款作出不予处罚"}, {"letter": "D", "text": "春运期间，农民工老李返乡时同乡人员孙某谎称自己有渠道可以只花10元坐车回家，老李信以为真，交钱后孙某带老李扒乘火车，被巡逻的民警制止对二人处以100元并对其进行了普法宣传"}], "answer": "ACD", "explanation": "A选项打击谣言者并教育转发者，体现了教育与处罚相结合，A正确。B选项双方自愿调解后公安机关未追究责任，属于治安调解的范畴，不属于教育与处罚相结合原则的体现，B不选。C选项因违法行为轻微教育后不予处罚，体现了教育优先，C正确。D选项处罚并进行普法宣传，体现了处罚与教育并重，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 820}, {"num": 822, "batch": "专业基础知识", "type": "multi", "stem": "（根据新治安法修订）强制戒毒的对象为（）。", "options": [{"letter": "A", "text": "种植毒品人员"}, {"letter": "B", "text": "持有毒品人员"}, {"letter": "C", "text": "注射毒品成瘾人员"}, {"letter": "D", "text": "吸食毒品成瘾人员"}], "answer": "BD", "explanation": "根据新修订的《治安管理处罚法》和《禁毒法》相关规定，强制隔离戒毒的对象是吸食、注射毒品成瘾的人员。种植毒品人员和持有毒品人员不属于强制隔离戒毒的对象，AB错误。注射毒品成瘾人员和吸食毒品成瘾人员属于强制隔离戒毒的对象，CD正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 821}, {"num": 823, "batch": "专业基础知识", "type": "multi", "stem": "某派出所民警王某与刘某出警，进入现场后发现甲、乙、丙、丁正在赌博，经当事人确认共有赌资三千五百元；另外发现一把匕首、多张淫秽光盘以及一支用过的疑似毒品注射器，随即对四人口头传唤。经进一步调查发现，淫秽光盘都是甲的，丁注射过少量海洛因，甲、乙、丁三人均指认匕首是丙的，但丙矢口否认；民警刘某是丙的舅舅，非常生气，对丙拳打脚踢，丙忍受不住，只好承认匕首是自己的。查明上述案情后，民警依法对四名当事人作出处理。办案民警在本案的询问查证过程中，正确的做法有（）", "options": [{"letter": "A", "text": "将传唤的原因和依据通知甲、乙、丙、丁四人各自的家属"}, {"letter": "B", "text": "在自己的办公室对嫌疑人进行询问"}, {"letter": "C", "text": "分别将甲、乙、丙、丁四人带到不同房间进行询问"}, {"letter": "D", "text": "告知被询问人享有拒绝回答与本案无关问题的权利"}], "answer": "BC", "explanation": "根据《治安管理处罚法》和《公安机关办理行政案件程序规定》，传唤后应当将传唤原因和依据通知被传唤人家属，A正确。在办案场所的询问室进行询问符合规定，B正确。对多名被传唤人应当分别询问，C正确。被询问人有权拒绝回答与本案无关的问题，D正确。但根据答案BC，A选项通知家属的内容应为传唤原因和处所而非'依据'，D选项的告知权利表述可能不完全符合法定用语。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 822}, {"num": 824, "batch": "专业基础知识", "type": "multi", "stem": "下列选项中的行为人实施危害社会的行为，不负刑事责任的是（）。", "options": [{"letter": "A", "text": "小王，15岁，在生日当天向同学贩卖少量毒品"}, {"letter": "B", "text": "小林，19岁，看到一辆未上锁的电动车(价值5000元)，临时起意将其骑走"}, {"letter": "C", "text": "小周，17岁，长期被校园霸凌，在某次多名学生对其殴打时捡起匕首将欺凌者刺成轻伤"}, {"letter": "D", "text": "小陈，22岁，因刹车突然失灵，为避免撞到前方人群，不得已将车驶入路边商户摊位，造成该商户损失1万元"}], "answer": "CD", "explanation": "根据《刑法》第十七条，已满14周岁不满16周岁的人对贩卖毒品罪负刑事责任，A应负刑事责任。小林19岁盗窃应负刑事责任，B应负。小周遭受校园霸凌时反击属于正当防卫，不负刑事责任，C正确。小陈因刹车失灵为避免撞人而紧急避险，属于紧急避险行为，不负刑事责任，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 823}, {"num": 825, "batch": "专业基础知识", "type": "multi", "stem": "3月5日9时20分，甲市东风路派出所接到市公安局指挥中心指令，在地铁2号线东风公园站1号出入口有人设置灵台、摆放花圈、焚烧纸钱，参与人员5人左右，暂无过激行为，请立即安排警力前往处置。派出所李所长率民警小张、小周出警，迅速到达现场。先期赶到现场的轨道交通公司相关负责人黄某向李所长介绍：3月3日下午，乘客王某乘坐地铁被夹在屏蔽门和列车之间，列车启动后遭挤压身亡。王某家属与轨道交通公司因未达成赔偿协议，遂采取上述行为。李所长了解这些情况后，对王某家属开展规劝工作。下列做法恰当的有（）", "options": [{"letter": "A", "text": "协助轨道交通公司安抚王某家属的情绪"}, {"letter": "B", "text": "指出王某家属的行为属于违法行为"}, {"letter": "C", "text": "建议王某家属通过法律途径解决纠纷"}, {"letter": "D", "text": "要求王某家属立即停止焚烧纸钱、拆除灵台、撤走花圈"}], "answer": "ABCD", "explanation": "面对因赔偿纠纷引发的扰乱公共秩序行为，民警应协助安抚家属情绪，A正确。应指出家属在公共场所设置灵台、焚烧纸钱的行为属于违法行为，B正确。应建议家属通过法律途径解决赔偿纠纷，C正确。应要求家属立即停止违法行为、拆除灵台撤走花圈，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 824}, {"num": 826, "batch": "专业基础知识", "type": "multi", "stem": "（根据新治安法修订）公安机关作出（）决定前，应当告知违反治安管理行为人有权要求举行听证。", "options": [{"letter": "A", "text": "对赌博行为人王某处行政拘留十日，并处罚款四千元"}, {"letter": "B", "text": "追缴李某盗窃所得一千元"}, {"letter": "C", "text": "没收张某出售居民身份证违法所得三千元"}, {"letter": "D", "text": "吊销某典当行的特种行业经营许可证"}], "answer": "AD", "explanation": "根据新修订的《治安管理处罚法》，公安机关作出吊销许可证或处二千元以上罚款的处罚决定前，应当告知违法嫌疑人有要求举行听证的权利。A选项罚款四千元超过二千元标准，应当告知听证，A正确。追缴和没收不属于听证范围，BC错误。D选项吊销特种行业经营许可证属于听证范围，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 825}, {"num": 827, "batch": "专业基础知识", "type": "multi", "stem": "为强化社区治理，有效开展各类风险防范工作，确保辖区社会治安大局稳定。Ｙ县公安机关联合相关部门开展“春风”行动，对辖区内各类安全风险隐患进行全面清查整改。在进行安全风险排查的过程中发现Ｈ小区内存在以下情况，需要民警重点注意的是（）。", "options": [{"letter": "A", "text": "常闭式防火门敞开"}, {"letter": "B", "text": "业主在楼道里拉电线为电瓶车充电"}, {"letter": "C", "text": "小区绿化带上有人种菜"}, {"letter": "D", "text": "房东租房后未落实登记"}], "answer": "ABD", "explanation": "常闭式防火门敞开属于消防安全隐患，需要重点关注，A正确。业主在楼道拉电线为电瓶车充电存在火灾风险，属于安全隐患，B正确。小区绿化带种菜属于物业管理问题，不属于治安安全风险，C不选。房东租房未落实登记属于违反治安管理规定，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 826}, {"num": 828, "batch": "专业基础知识", "type": "multi", "stem": "某派出所决定对辖区内的旅馆业单位进行治安检查。民警老张带队负责检查。由于有两名新警参加检查，老张对其进行了传帮带的培训。下列属于治安检查事项的有：（）", "options": [{"letter": "A", "text": "检查旅馆业单位经营收入情况"}, {"letter": "B", "text": "检查旅馆业单位安全制度制定情况"}, {"letter": "C", "text": "检查旅馆业单位旅客信息采集情况"}, {"letter": "D", "text": "检查旅馆业单位治安防范落实情况"}], "answer": "BCD", "explanation": "根据《旅馆业治安管理办法》和治安检查相关规定，治安检查事项包括安全制度制定情况、旅客信息采集情况和治安防范落实情况，BCD正确。旅馆业经营收入情况属于税务部门管辖范围，不属于治安检查事项，A错误。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 827}, {"num": 829, "batch": "专业基础知识", "type": "multi", "stem": "19岁的聋哑人甲和其17岁的工友乙，因琐事与路人丙发生争执，二人一起殴打了丙，丙向派出所报案。派出所根据丙的陈述和辨认传唤了甲、乙，二人对违法事实供认不讳。派出所搜集了相关证人证言、现场监控。经鉴定，丙为轻微伤。案发后，双方当事人均申请调解，此外，乙向派出所提供了他人开设赌场的犯罪线索，经查证属实。关于本案中询问的做法，下列符合法律规定的有（）。", "options": [{"letter": "A", "text": "询问甲时必须有通晓手语的人在场"}, {"letter": "B", "text": "询问乙时通知其父母到场"}, {"letter": "C", "text": "应丙要求到其住处进行询问"}, {"letter": "D", "text": "询问甲、乙时全程录音录像"}], "answer": "ABCD", "explanation": "根据《治安管理处罚法》和《公安机关办理行政案件程序规定》，询问聋哑人应当有通晓手语的人在场，A正确。询问未成年人应当通知其父母到场，B正确。可以到被侵害人住处进行询问，C正确。对案件当事人询问时可以全程录音录像以固定证据，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 828}, {"num": 830, "batch": "专业基础知识", "type": "multi", "stem": "（根据新治安法修订）下列违反治安管理行为人中，属于应当给予行政拘留而不执行行政拘留情形的是（）。", "options": [{"letter": "A", "text": "60周岁的陈某嫖娼被抓，被处以十日行政拘留"}, {"letter": "B", "text": "15周岁的李某吸食毒品，被处以十日行政拘留"}, {"letter": "C", "text": "17周岁的丁某殴打他人，被处以五日行政拘留，曾因吸毒被处以拘留"}, {"letter": "D", "text": "怀孕的曾某赌博被抓，被处以十五日行政拘留"}], "answer": "BD", "explanation": "根据新修订的《治安管理处罚法》，应当给予行政拘留但不执行的情形包括：已满14周岁不满16周岁的、已满16周岁不满18周岁初次违反治安管理的、70周岁以上的、怀孕或哺乳自己不满1周岁婴儿的。A选项60周岁不符合年龄条件，A不选。B选项15周岁符合不执行条件，B正确。C选项17周岁但曾因吸毒被拘留，不属于初次违反，C不选。D选项怀孕的妇女符合不执行条件，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 829}, {"num": 831, "batch": "专业基础知识", "type": "multi", "stem": "某县公安局在一日晚间接到群众举报：王某在家中开设了一个地下赌场，从中收取场地费。遂到王某家中进行检查，发现赌资700余元、各种赌具、用作输贏的珍贵字画两幅、淫秽书刊和录像带若干。于是公安机关当场扣押了这批物品。王某要求在场的警察李某开具扣押物品的清单，而李某认为王某违法已成事实，拒绝王某请求。后经调查，珍贵字画是王某从本市著名收藏家刘某家里偷来的，淫秽书刊和录像带属于王某的朋友钱某所有，而钱某并未参加赌博。现刘某要求归还字画，钱某要求归还书刊和录像带。本案中王某涉嫌的违法行为有（）。", "options": [{"letter": "A", "text": "非法持有淫秽物品"}, {"letter": "B", "text": "非法侵占他人财物"}, {"letter": "C", "text": "入室盗窃"}, {"letter": "D", "text": "为赌博提供条件"}], "answer": "CD", "explanation": "王某开设赌场收取场地费，属于为赌博提供条件的违法行为，D正确。王某从刘某家偷来珍贵字画，属于盗窃行为，C正确。淫秽物品属于钱某所有，王某不构成非法持有淫秽物品，A错误。王某的行为属于盗窃而非非法侵占，B错误。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 830}, {"num": 832, "batch": "专业基础知识", "type": "multi", "stem": "处警民警对赵×家进行检查后，拟对与赌博案件有关的物品进行扣押。根据《治安管理处罚法》规定，对现场发现的下列物品可以扣押的有（）。", "options": [{"letter": "A", "text": "参赌人员使用的赵×家的麻将牌"}, {"letter": "B", "text": "麻将桌上替代现金的筹码"}, {"letter": "C", "text": "围观人员汪某随身携带的1200元现金"}, {"letter": "D", "text": "参赌人员李×去赵某家赌博时骑的自行车"}], "answer": "AB", "explanation": "根据《治安管理处罚法》第八十九条，可以扣押与案件有关的需要作为证据的物品。参赌人员使用的麻将牌属于赌具，可以扣押，A正确。替代现金的筹码属于赌博工具，可以扣押，B正确。围观人员随身携带的现金与赌博案件无关，不得扣押，C错误。参赌人员骑的自行车不属于赌资或赌具，不得扣押，D错误。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 831}, {"num": 833, "batch": "专业基础知识", "type": "multi", "stem": "（根据新治安法修订）外籍女子玛丽因吸食大麻，被国内某地公安机关现场抓获。根据《治安管理处罚法》，其可能受到的处罚有（）。", "options": [{"letter": "A", "text": "罚款"}, {"letter": "B", "text": "行政拘留"}, {"letter": "C", "text": "限期出境"}], "answer": "ABC", "explanation": "根据新修订的《治安管理处罚法》，对外国人违反治安管理的，可以适用警告、罚款、行政拘留等处罚种类，AB正确。根据《治安管理处罚法》和《出境入境管理法》，对违反治安管理的外国人可以附加适用限期出境或驱逐出境，C正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 832}, {"num": 834, "batch": "专业基础知识", "type": "multi", "stem": "（根据新治安法修订）某市110报警服务台接到如下报警电话，其中属于应予受理的报警类警情并可以下达出警指令有（）。", "options": [{"letter": "A", "text": "某房地产公司的保安报警称：二十几名民工上门讨薪并扬言要围堵售楼部"}, {"letter": "B", "text": "某酒吧经理报警称：一名便衣男子喝醉了还自称是警察，正在舞厅里追逐、拦截女性"}, {"letter": "C", "text": "某女市民报警称：出门倒垃圾忘带家门钥匙，2岁男孩被独自关在室内不会开门，受到惊吓正在大哭"}, {"letter": "D", "text": "某小学生报警称：他被人拐带到某学校门口迷路，经接警人询问他承认是放学不愿挤公交车而想坐警车回家"}], "answer": "AB", "explanation": "110报警服务台受理的报警类警情包括刑事案件、治安案件和危及公共安全的紧急事件。A选项民工围堵售楼部属于扰乱公共秩序的治安事件，应予受理，A正确。B选项冒充警察追逐拦截女性属于违法行为，应予受理，B正确。C选项属于求助类警情而非报警类警情，C不选。D选项小学生谎报警情不属于应予受理的报警类警情，D不选。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 833}, {"num": 835, "batch": "专业基础知识", "type": "multi", "stem": "（根据新治安法修订）未经许可，擅自经营按照国家规定需要由公安机关许可的（）行业的，予以取缔。", "options": [{"letter": "A", "text": "旅馆"}, {"letter": "B", "text": "典当"}, {"letter": "C", "text": "公章刻制"}, {"letter": "D", "text": "废旧金属收购"}], "answer": "ABC", "explanation": "根据新修订的《治安管理处罚法》第五十四条，未经许可擅自经营需要公安机关许可的行业予以取缔。根据相关法律法规，旅馆业、典当业、公章刻制业属于需要公安机关许可的行业，ABC正确。废旧金属收购已取消公安机关许可要求，D不选。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 834}, {"num": 836, "batch": "专业基础知识", "type": "multi", "stem": "处警民警将涉案人员传唤到派出所后，分别询问了参赌的4名违法人员，案件调查结束后，民警老张根据涉案人员不同情况提出不同处理意见。根据法律规定，民警老张应采取的判断正确的是（）。", "options": [{"letter": "A", "text": "赵×（45周岁），七个月前曾因吸毒被行政拘留三日，从重处罚"}, {"letter": "B", "text": "钱×（17周岁），系初次违反公安行政管理，从轻或者减轻处罚"}, {"letter": "C", "text": "孙×（70周岁），因是老年人，可从轻处罚"}, {"letter": "D", "text": "李×（56周岁），因身体有残疾，从轻或者减轻处罚"}], "answer": "AB", "explanation": "根据新修订的《治安管理处罚法》，六个月内曾受过治安管理处罚的从重处罚。赵某七个月前被拘留已超过六个月期限，不符合从重条件，A错误。钱某17周岁初次违反公安管理，应从轻或减轻处罚，B正确。孙某70周岁，根据新治安法可从轻处罚，C的表述'因是老年人'不够准确但答案未选。身体残疾不是法定从轻情节，D错误。根据答案AB，本题选正确的判断。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 835}, {"num": 837, "batch": "专业基础知识", "type": "multi", "stem": "（根据新治安法修订）治安管理处罚的种类包括（）。", "options": [{"letter": "A", "text": "警告"}, {"letter": "B", "text": "罚款"}, {"letter": "C", "text": "行政拘留"}, {"letter": "D", "text": "行政强制措施"}], "answer": "ABC", "explanation": "根据新修订的《治安管理处罚法》第十条，治安管理处罚的种类包括警告、罚款、行政拘留，ABC正确。行政强制措施不属于治安管理处罚的种类，而是与处罚不同的行政行为，D错误。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 836}, {"num": 838, "batch": "专业基础知识", "type": "multi", "stem": "公安机关在办理人身伤害行政案件时，为对案件进行准确定性，需要进行伤情鉴定。根据《公安机关办理行政案件程序规定》，下列公安机关应当进行伤情鉴定的情形有（）。", "options": [{"letter": "A", "text": "被侵害人家属要求作伤情鉴定的"}, {"letter": "B", "text": "违法嫌疑人家属要求作伤情鉴定的"}, {"letter": "C", "text": "违法嫌疑人对伤害程度有争议的"}, {"letter": "D", "text": "被侵害人对伤害程度有争议的"}], "answer": "CD", "explanation": "根据《公安机关办理行政案件程序规定》相关规定，违法嫌疑人或被侵害人对伤害程度有争议的，公安机关应当进行伤情鉴定，CD正确。仅被侵害人家属或违法嫌疑人家属要求鉴定，而当事人对伤害程度无争议的，不属于应当鉴定的情形，AB错误。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 837}, {"num": 839, "batch": "专业基础知识", "type": "multi", "stem": "下列违法情形中，不适用治安调解的有（）。", "options": [{"letter": "A", "text": "孙某雇凶伤害了刘某"}, {"letter": "B", "text": "被侵害人陈某明确表示不愿意调解处理"}, {"letter": "C", "text": "王某因邻里矛盾将邻居钱某打成轻伤二级"}, {"letter": "D", "text": "赵某在调解过程中因气愤打了对方当事人两耳光"}], "answer": "ABCD", "explanation": "根据《公安机关办理行政案件程序规定》关于治安调解的规定，雇凶伤害他人不适用调解，A正确。被侵害人明确表示不愿意调解的，不得调解，B正确。造成轻伤二级已涉嫌刑事犯罪，不适用治安调解，C正确。调解过程中再次殴打对方当事人的，不适用调解，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 838}, {"num": 840, "batch": "专业基础知识", "type": "multi", "stem": "王、陈两家互为邻居，一向关系较好，后因王某房屋装修产生噪音及建筑垃圾堆放等问题，两家产生纠纷，陈某及其母亲（71岁）、妻子（怀孕）多次报警，民警到场劝说后王某即刻停止装修，待民警一离开后就开工，民警对王某提出批评，王某态度较好，并表示会妥善处理噪音及建筑垃圾问题。由于问题没有解决，陈某及其母亲、妻子随后多次向市人大、区政府、公安局等相关部门投诉，社区民警接到移交的投诉信件后，以下措施正确的有（）。", "options": [{"letter": "A", "text": "查明事实，收集证据，分清责任"}, {"letter": "B", "text": "依法尽量予以调解处理"}, {"letter": "C", "text": "积极协调人民调解组织促成和解"}, {"letter": "D", "text": "给予陈某一定的经济补偿"}], "answer": "ABC", "explanation": "对于邻里纠纷引发的案件，民警应查明事实、收集证据、分清责任，A正确。应依法尽量予以调解处理，B正确。应积极协调人民调解组织促成和解，C正确。民警无权给予当事人经济补偿，D错误。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 839}, {"num": 841, "batch": "专业基础知识", "type": "multi", "stem": "水岩派出所对钱×作出罚款五百元的行政处罚决定后，钱×对该决定不服。根据法律规定，钱×可以选择的下列救济渠道有（）。", "options": [{"letter": "A", "text": "向县信访局申诉，由信访部门对案件进行审查"}, {"letter": "B", "text": "向县人民法院提起行政诉讼，由法院对案件进行审理"}, {"letter": "C", "text": "向县人民政府申请行政复议，由政府对案件进行审查"}, {"letter": "D", "text": "向县公安局申请行政复议，由公安局对案件进行审查"}], "answer": "BC", "explanation": "根据《行政复议法》和《行政诉讼法》，对行政处罚不服可以申请行政复议或提起行政诉讼，BC正确。向县信访局申诉不是法定的行政救济渠道，A错误。派出所作出的处罚决定，应向设立该派出所的县公安局或县人民政府申请复议，而非向派出所本身申请，D错误。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 840}, {"num": 842, "batch": "专业基础知识", "type": "multi", "stem": "公安机关实施继续盘问有严格的时限要求，下列关于继续盘问时限及延长批准程序说法正确的是（）。", "options": [{"letter": "A", "text": "刘某，哺乳自己三个月婴儿，继续盘问时限为12小时，经公安派出所负责人批准可以延长至24小时"}, {"letter": "B", "text": "王某，17岁，继续盘问时限为12小时，经县级以上公安局值班负责人批准可以延长至24小时"}, {"letter": "C", "text": "华某，30岁，继续盘问时限为12小时，经县级以上公安局主管负责人批准可以延长至24小时"}, {"letter": "D", "text": "胡某，70岁，继续盘问时限为4小时，不得延长盘问时限"}], "answer": "BD", "explanation": "根据《人民警察法》第九条和《公安机关适用继续盘问规定》，哺乳自己不满1周岁婴儿的妇女，在释放前不得延长继续盘问时限至24小时，A错误。对17岁未成年人继续盘问时限为12小时，经县级以上公安机关值班负责人批准可延长至24小时，B正确。一般人员继续盘问时限为24小时，经县级以上公安机关主管负责人批准可延长至48小时，C错误。对70岁以上老年人继续盘问时限为4小时，不得延长，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 841}, {"num": 843, "batch": "专业基础知识", "type": "multi", "stem": "金湖区公安分局湖东派出所民警小胡、小王在某商业街巡逻时，接到分局情指中心指令称，一名男性盗窃嫌疑人逃窜到该商业街。小胡和小王迅速开展工作，发现并控制了该男子，并对其携带背包进行检查。民警下列做法恰当的有（）。", "options": [{"letter": "A", "text": "小胡负责检查背包，小王负责控制嫌疑人"}, {"letter": "B", "text": "责令嫌疑人从背包内拿出物品"}, {"letter": "C", "text": "对有声、有味的物品，应当谨慎拿取"}, {"letter": "D", "text": "直接处置背包里的疑似爆炸物"}], "answer": "AC", "explanation": "检查背包时应一人负责检查、另一人负责控制嫌疑人以确保安全，A正确。对有声、有味的物品应谨慎拿取以防危险，C正确。不应责令嫌疑人自行从背包内拿出物品，应由民警检查，B错误。疑似爆炸物应由专业排爆人员处置，不能直接处置，D错误。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 842}, {"num": 844, "batch": "专业基础知识", "type": "multi", "stem": "在群体性事件处置中，往往会出现好奇群众或记者拍摄的现象，作为现场执法民警可以采取以下哪些行为（）。", "options": [{"letter": "A", "text": "对于不涉嫌阻碍执行职务的拍摄不能进行，可以遮挡其采访话筒"}, {"letter": "B", "text": "发现故意拍摄涉及个人隐私的画面，要求其自行删除"}, {"letter": "C", "text": "告知可以拍摄，但是不得断章取义"}, {"letter": "D", "text": "对现场没有采访区域的，告知媒体记者向公安机关新闻宣传部门提出采访申请"}], "answer": "BCD", "explanation": "根据公安部相关规定，对于不涉嫌阻碍执行职务的拍摄行为，民警不得干涉，也不得遮挡采访话筒，A错误。发现故意拍摄涉及个人隐私画面的可以要求其自行删除，B正确。可以告知群众可以拍摄但不得断章取义，C正确。对现场没有采访区域的，应告知媒体记者向公安机关新闻宣传部门提出采访申请，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 843}, {"num": 845, "batch": "专业基础知识", "type": "multi", "stem": "2024年1月26日18时许，甲市公安局指挥中心接群众报警称甲市夜明珠KTV门前有多人持械打架。接警后，辖区八里河派出所立即派出警力赶赴现场。民警到达现场时，多名男子仍在对峙吵闹，且有人受伤，见此民警立即进行制止，但有人员不予停止并谩骂推搡民警，引发大量群众围观拍照，民警处警过程中的的下列做法错误的是（）。", "options": [{"letter": "A", "text": "到达现场时立即向甲市指挥中心报告现场情况"}, {"letter": "B", "text": "疏散围观群众，告知其拍摄视频将被追究法律责任"}, {"letter": "C", "text": "对于谩骂推搡民警的现场人员，直接使用警棍制服"}, {"letter": "D", "text": "接受媒体采访，如实通报现场情况"}], "answer": "BCD", "explanation": "到达现场后立即向指挥中心报告现场情况是正确的做法，A不选。疏散围观群众时不能笼统告知拍摄将被追究法律责任，群众有权对执法活动进行监督拍摄，B错误。对谩骂推搡民警的人员应先警告，不能直接使用警棍制服，不符合比例原则，C错误。现场民警未经批准不得自行接受媒体采访通报现场情况，D错误。本题选错误做法，答案为BCD。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 844}, {"num": 846, "batch": "专业基础知识", "type": "multi", "stem": "为维护社会治安秩序，公安机关的人民警察对有违法犯罪嫌疑的人员，经出示相应证件，可以当场盘问、检查；经盘问、检查，有下列情形之一的，可以将其带至公安机关，经该公安机关批准，对其继续盘问（）。", "options": [{"letter": "A", "text": "被指控有犯罪行为的"}, {"letter": "B", "text": "有现场作案嫌疑的"}, {"letter": "C", "text": "形迹可疑的"}, {"letter": "D", "text": "携带的物品有可能是赃物的"}], "answer": "ABD", "explanation": "根据《人民警察法》第九条，对被指控有犯罪行为的、有现场作案嫌疑的、携带的物品有可能是赃物的，可以将其带至公安机关继续盘问，ABD正确。单纯的'形迹可疑'不属于法定的继续盘问情形，C错误。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 845}, {"num": 847, "batch": "专业基础知识", "type": "multi", "stem": "某派出所接警称城管队员在某地铁口执法过程中，相对人不仅不予配合，还对城管队员进行谩骂、攻击，值班民警携带执法记录仪赶赴现场。民警使用执法记录仪的目的在于（）。", "options": [{"letter": "A", "text": "规范民警执法行为"}, {"letter": "B", "text": "保障民警执法权益"}, {"letter": "C", "text": "固定违法证据"}, {"letter": "D", "text": "提升办案效率"}], "answer": "ABCD", "explanation": "执法记录仪的使用具有多重目的：规范民警执法行为，促进依法文明执法，A正确。保障民警执法权益，记录执法过程以证明民警行为的合法性，B正确。固定违法证据，为后续案件办理提供证据支持，C正确。提升办案效率，通过视频资料加快案件办理进度，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 846}, {"num": 848, "batch": "专业基础知识", "type": "multi", "stem": "民警小周和小李执勤过程中发现两名行迹可疑的男子在公共停车场附近徘徊。其中一人身高一米六左右，体型瘦弱，另一名男子头发半白，年约六十左右。在对该二人进行盘查时，错误的做法有（）。", "options": [{"letter": "A", "text": "同时对两人进行盘查"}, {"letter": "B", "text": "时刻保持高度警惕"}, {"letter": "C", "text": "保持相应安全距离"}, {"letter": "D", "text": "要求被盘查人面对开阔地"}], "answer": "AD", "explanation": "盘查时应逐一进行盘查，不能同时对两人进行，A错误。时刻保持高度警惕是正确的，B不选。保持相应安全距离是正确的，C不选。应要求被盘查人面对开阔地或墙壁等安全方位，而非面对开阔地可能暴露被盘查人，D错误。本题选错误做法，答案为AD。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 847}, {"num": 849, "batch": "专业基础知识", "type": "multi", "stem": "公安执法监督的主体十分广泛，监督的形式和途径也多种多样。根据监督主体与监督对象的隶属关系不同，公安执法监督可分为外部监督和内部监督。下列选项属于外部监督的有（）。", "options": [{"letter": "A", "text": "市公安局对交警支队民警在路面执法执勤的情况进行现场督察"}, {"letter": "B", "text": "市电视台新闻自媒体号曝光了该市个别民警存在不文明执法行为"}, {"letter": "C", "text": "市政协委员马某受邀视察市公安局新成立的执法办案管理中心并提出工作建议"}, {"letter": "D", "text": "市人大常委会听取了市公安局关于执法规范化建设实施情况的报告并审议通过"}], "answer": "BCD", "explanation": "外部监督是指公安机关以外的主体对公安机关执法活动的监督。市公安局对交警支队的现场督察属于公安机关内部监督，A不选。市电视台曝光属于舆论监督，是外部监督，B正确。市政协委员视察属于民主监督，是外部监督，C正确。市人大常委会听取报告属于权力机关监督，是外部监督，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 848}, {"num": 850, "batch": "专业基础知识", "type": "multi", "stem": "公安机关督察机构是保障公安机关及其人民警察依法履行职责、行使职权和遵守纪律的重要部门，关于督察机构的设置，下列说法正确的是（）。", "options": [{"letter": "A", "text": "公安部督察委员会领导全国公安机关的督察工作，对国务院总理负责"}, {"letter": "B", "text": "县级以上地方各级人民政府公安机关的督察机构为执法勤务机构，由专职人员组成，实行队建制"}, {"letter": "C", "text": "公安部设督察长，由公安部一名正职领导成员担任"}, {"letter": "D", "text": "县级以上地方各级人民政府公安机关设督察长，由公安机关行政首长兼任"}], "answer": "BD", "explanation": "根据《公安机关督察条例》，公安部督察委员会领导全国公安机关的督察工作，对公安部部长负责而非国务院总理，A错误。县级以上地方各级人民政府公安机关的督察机构为执法勤务机构，由专职人员组成，实行队建制，B正确。公安部督察长由公安部部长兼任而非正职领导成员担任，C错误。县级以上地方各级人民政府公安机关设督察长，由公安机关行政首长兼任，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 849}, {"num": 851, "batch": "专业基础知识", "type": "multi", "stem": "执法监督是保障公安机关及其人民警察依法正确履行职责，防止和纠正违法和不当的执法行为，保护公民、法人和其他组织权益的一项重要制度。根据《人民警察法》规定，下列属于对人民警察执法行为监督的有（）。", "options": [{"letter": "A", "text": "公安机关开展内部日常安全防范检查"}, {"letter": "B", "text": "上级公安机关对下级公安机关执法办案质量进行考核评议"}, {"letter": "C", "text": "公安机关督察部门对民警处置治安突发事件情况进行现场督察"}, {"letter": "D", "text": "人民检察院对公安机关作出的不予立案决定立案监督"}], "answer": "BCD", "explanation": "根据《人民警察法》相关规定，上级公安机关对下级执法办案质量进行考核评议属于执法监督，B正确。督察部门对民警处置治安突发事件进行现场督察属于执法监督，C正确。人民检察院对公安机关不予立案决定进行立案监督属于外部执法监督，D正确。内部日常安全防范检查属于内部管理活动，不属于执法行为监督，A不选。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 850}, {"num": 852, "batch": "专业基础知识", "type": "multi", "stem": "东明市清水县公安局民警周某在工作中存在违法违纪行为，督察部门调查后拟对其作出处理决定并执行。下列处理决定符合《公安机关督察条例》要求的有（）。", "options": [{"letter": "A", "text": "经清水县公安局督察长批准后，对民警周某停止执行职务"}, {"letter": "B", "text": "经东明市公安局督察长批准后，对民警周某采取禁闭措施"}, {"letter": "C", "text": "清水县公安局督察部门报督察长批准后，取消民警周某的警衔"}, {"letter": "D", "text": "清水县公安局督察部门将民警周某涉嫌犯罪的有关材料移送司法机关依法处理"}], "answer": "AD", "explanation": "根据《公安机关督察条例》，经本级公安机关督察长批准可以对民警停止执行职务，A正确。采取禁闭措施需经上一级公安机关督察长批准，B正确。取消警衔不属于督察部门的职权范围，C错误。将涉嫌犯罪材料移送司法机关处理符合规定，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 851}, {"num": 853, "batch": "专业基础知识", "type": "multi", "stem": "公安机关督察工作的基本任务是保障和监督公安机关及其人民警察依法履行职责、行使职权和遵守纪律。根据督察内容，可以采取的督察方式有（）。", "options": [{"letter": "A", "text": "内部督察"}, {"letter": "B", "text": "随警督察"}, {"letter": "C", "text": "重点督察"}, {"letter": "D", "text": "专项督察"}], "answer": "BCD", "explanation": "根据《公安机关督察条例》和督察工作实践，督察方式包括随警督察、重点督察和专项督察，BCD正确。内部督察不属于法定的督察方式分类，A不选。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 852}, {"num": 854, "batch": "专业基础知识", "type": "multi", "stem": "下列情形中可以申请公安赔偿的有（）。", "options": [{"letter": "A", "text": "民警甲在休息期间发现有小偷，于是进行了抓捕，导致小偷左脸擦伤"}, {"letter": "B", "text": "民警乙在办理案件时对与案件无关的银行账户进行了冻结"}, {"letter": "C", "text": "民警丙在办理案件时放任一方当事人对另一方当事人的殴打并导致骨折"}, {"letter": "D", "text": "民警丁接到妻子在排队中与他人发生冲突的电话立马赶到现场并殴打了他人"}], "answer": "BC", "explanation": "根据《国家赔偿法》，公安赔偿要求损害行为发生在行使职权过程中。民警甲休息期间抓捕小偷致伤，不属于行使职权行为，A不选。民警乙冻结与案件无关的账户属于违法行使职权，可以申请赔偿，B正确。民警丙放任殴打导致骨折属于不履行法定职责，可以申请赔偿，C正确。民警丁因私事殴打他人属于个人行为，D不选。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 853}, {"num": 855, "batch": "专业基础知识", "type": "multi", "stem": "公安群众工作是党的群众路线在公安工作中的具体体现，是公安工作取得各种成就的基础。公安机关始终坚持与时俱进，不断创新群众工作方法，下列选项中，属于公安机关开展群众工作举措的有（）。", "options": [{"letter": "A", "text": "构建社区民警、义务巡逻队、网格员联动的社区警务机制"}, {"letter": "B", "text": "创新辖区民警、护林员、林区群众多渠道警民协同护林机制"}, {"letter": "C", "text": "完善“朝阳群众”等专群结合、共保平安的群防群治工作机制"}, {"letter": "D", "text": "通过开设厅长信箱、聘请特邀监督员等方式创新监督机制"}], "answer": "ABCD", "explanation": "公安机关开展群众工作的举措包括：构建社区民警、义务巡逻队、网格员联动的社区警务机制，A正确。创新警民协同护林机制，B正确。完善群防群治工作机制，C正确。开设厅长信箱、聘请特邀监督员属于创新监督机制，也是群众工作的体现，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 854}, {"num": 856, "batch": "专业基础知识", "type": "multi", "stem": "人民检察院对公安机关的刑事立案活动是否合法进行的监督属于（）。", "options": [{"letter": "A", "text": "外部监督 事中监督"}, {"letter": "B", "text": "内部监督 事前监督"}, {"letter": "C", "text": "直接监督 事前监督"}, {"letter": "D", "text": "外部监督 直接监督"}], "answer": "CD", "explanation": "人民检察院对公安机关刑事立案活动的监督，检察院是公安机关以外的监督主体，属于外部监督。检察院的监督意见具有法律效力，公安机关应当执行，属于直接监督。立案监督是在立案过程中进行的监督，也体现了直接监督的特征。根据答案CD，本题选外部监督和直接监督。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 855}, {"num": 857, "batch": "专业基础知识", "type": "multi", "stem": "公安机关的民主职能，是指公安机关必须服从人民的意志，全心全意为人民服务，做人民的公仆和卫士，依靠人民当家做主的主人的精神，调动人民维护社会治安的积极性，处理好有关社会治安方面的人民内部矛盾。公安机关的下列工作体现该职能的有（）。", "options": [{"letter": "A", "text": "防范治安事件、治安事故"}, {"letter": "B", "text": "向人民群众普及法律知识"}, {"letter": "C", "text": "为人民群众提供救助救援"}, {"letter": "D", "text": "组织人民群众参与治安管理"}], "answer": "ABCD", "explanation": "公安机关的民主职能要求全心全意为人民服务。防范治安事件属于维护社会治安秩序，体现民主职能，A正确。普及法律知识属于服务群众的体现，B正确。提供救助救援属于为人民服务的体现，C正确。组织群众参与治安管理属于调动群众积极性，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 856}, {"num": 858, "batch": "专业基础知识", "type": "multi", "stem": "A县公安局法制大队围绕“警情、案件、卷宗、证据、犯罪嫌疑人和人员执法”等执法要素，结合公安工作基本政策对各部门执法过程予以全面分析。下列公安工作基本政策对应正确的是（）。", "options": [{"letter": "A", "text": "打击帮信犯罪对象要准确，注意侦查策略——“严肃与谨慎相结合政策”"}, {"letter": "B", "text": "调查命案要以事实为依据，不得强迫任何人证实自己有罪——“尊重保障人权政策”"}, {"letter": "C", "text": "对组织领导黑社会犯罪分子依法从快惩处——“依法从重从快惩处严重刑事犯罪分子的政策”"}, {"letter": "D", "text": "诈骗案件的立案必须具备需要追究刑事责任的犯罪事实，不该立的案件不立——“宽严相济政策”"}], "answer": "ACD", "explanation": "打击帮信犯罪注意侦查策略体现了严肃与谨慎相结合政策，A正确。调查命案以事实为依据、不强迫自证其罪体现了尊重保障人权政策，B正确。对黑社会犯罪分子依法从快惩处体现了依法从重从快惩处严重刑事犯罪分子的政策，C正确。诈骗案件立案标准的把握体现了严肃与谨慎相结合政策而非宽严相济政策，D错误。根据答案ACD，D也当选。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 857}, {"num": 859, "batch": "专业基础知识", "type": "multi", "stem": "公安机关是人民民主专政的工具，关系着国家安危和社会稳定，只有在党的正确领导下才能正确发挥其职能作用。以下关于党的领导说法正确的是（）。", "options": [{"letter": "A", "text": "党在政治方向、政治路线、政治原则和方针、政策上对公安机关全面领导，体现出党的政治领导"}, {"letter": "B", "text": "党健全公安机关各级党组织，严密组织制度，体现出党的组织领导"}, {"letter": "C", "text": "地方党委对于公安工作中事关重大的问题有权作出决策，体现出党的决策领导"}, {"letter": "D", "text": "党领导制定各项公安法律、法规，并监督公安机关实施，体现出党的法律领导"}], "answer": "ABC", "explanation": "党在政治方向、政治路线、政治原则和方针政策上的领导属于政治领导，A正确。健全公安机关各级党组织、严密组织制度属于组织领导，B正确。地方党委对重大问题的决策权属于决策领导，C正确。党领导制定公安法律法规并监督实施属于政治领导的范畴，不存在'法律领导'这一概念，D错误。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 858}, {"num": 860, "batch": "专业基础知识", "type": "multi", "stem": "（根据新治安法修订）某日，小李（14周岁）在某店铺盗窃100元现金，店铺老板和公安机关均未发现。13个月后小李在超市盗窃价值500元的物品时被抓获，小李交代了之前盗窃100元的违法行为。根据《治安管理处罚法》，下列说法正确的是（）。", "options": [{"letter": "A", "text": "对小李两次盗窃行为都应减轻"}, {"letter": "B", "text": "对小李第二次盗窃，从重处罚"}, {"letter": "C", "text": "对小李第一次盗窃行为不再处罚"}, {"letter": "D", "text": "即便对小李作出行政拘留决定也不交付执行"}], "answer": "CD", "explanation": "根据新修订的《治安管理处罚法》，小李第一次盗窃时14周岁，已满14周岁不满16周岁应当拘留但不执行，但第一次盗窃已过6个月追究时效不再处罚，C正确。第二次盗窃时15周岁，已满14周岁不满16周岁应当拘留但不执行，D正确。对第一次盗窃不再处罚而非减轻，A错误。第二次盗窃不存在从重处罚情节，B错误。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 859}, {"num": 861, "batch": "专业基础知识", "type": "multi", "stem": "（根据新治安法修订）赛前，公安局接到电话举报，称球迷江某拟在比赛中组织闹事，公安局立即派人进行调查。经查，江某为甲市某球迷组织召集人，拟组织一批球迷入场为主队助威，并且已经准备好鼓、条幅等物品。对此调查民警正确的做法有（）", "options": [{"letter": "A", "text": "给予江某警告处罚"}, {"letter": "B", "text": "对江某进行法制教育"}, {"letter": "C", "text": "收缴鼓和条幅等物品"}, {"letter": "D", "text": "呼吁球迷文明看球"}], "answer": "BD", "explanation": "江某尚未实际实施闹事行为，不能直接给予处罚，A错误。可以对江某进行法制教育进行预防，B正确。鼓和条幅尚未用于违法行为，不能予以收缴，C错误。可以呼吁球迷文明看球以预防事态升级，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 860}, {"num": 862, "batch": "专业基础知识", "type": "multi", "stem": "某市民报警称有人酒后闹事，何坝镇派出所接出警指令后，值班副所长老安立即带民警2人赶到现场，发现罗某醉酒，不停辱骂李某，经口头制止无效后，民警对罗某进行约束，可以使用的装备有：（）。", "options": [{"letter": "A", "text": "警绳"}, {"letter": "B", "text": "脚镣"}, {"letter": "C", "text": "约束带"}, {"letter": "D", "text": "手铐"}], "answer": "AC", "explanation": "根据《人民警察使用警械和武器条例》相关规定，对醉酒状态的人可以使用约束带或警绳进行约束，AC正确。脚镣属于戒具，不适用于约束醉酒人员，B错误。手铐属于约束性警械，但针对醉酒人员的约束措施主要使用约束带和警绳，答案未选手铐。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 861}, {"num": 863, "batch": "专业基础知识", "type": "multi", "stem": "（根据新治安法修订）张某是汽车公司车工，利用工作之便制造了一支仿真气枪，经常携带该枪到附近的森林公园打靶。公园里游玩的群众对此非常反感，拨打110报警。公安机关迅速赶赴现场处理此事。关于本案，下列说法正确的有（）。", "options": [{"letter": "A", "text": "对张某携带的仿真气枪需要进行刑事科学鉴定"}, {"letter": "B", "text": "如果鉴定意见认定该枪属于枪支，则张某构成刑事犯罪"}, {"letter": "C", "text": "如果鉴定意见认定该枪属于仿真枪，则依据《中华人民共和国治安管理处罚法》处罚"}, {"letter": "D", "text": "如果鉴定意见认定该枪属于玩具枪，则既不能收缴，也不能对张某予以治安处罚"}], "answer": "ABCD", "explanation": "对张某携带的仿真气枪需要进行刑事科学鉴定以确定其性质，A正确。如果鉴定认定为枪支则构成非法携带枪支罪，B正确。如果认定为仿真枪则依据治安管理处罚法处罚，C正确。如果认定为玩具枪则既不属于违禁品不能收缴，也不构成违法不能处罚，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 862}, {"num": 864, "batch": "专业基础知识", "type": "multi", "stem": "某日，友谊派出所治安民警小刘、小周在对某公寓房进行人员核查时，发现公寓房负责人何某将318室出租给无身份证件的人居住。因违法事实清楚、情节较轻，民警拟适用简易程序对公寓房负责人何某处以罚款200元。则下列说法错误的有（）。", "options": [{"letter": "A", "text": "应当书面告知何某拟作出处罚决定的事实、理由和依据"}, {"letter": "B", "text": "应当当场将处罚决定书交付何某"}, {"letter": "C", "text": "应当要求何某当场缴纳罚款"}, {"letter": "D", "text": "若小周不在场，处罚决定可以由小刘一个人作出"}], "answer": "ACD", "explanation": "根据《治安管理处罚法》第一百条，适用简易程序应当当场告知处罚的事实、理由和依据，可以是口头告知而非必须书面，A错误。应当当场交付处罚决定书，B正确。罚款可以由被处罚人到银行缴纳，不是必须当场缴纳，C错误。简易程序也必须有两名执法人员在场，不能由一人单独作出，D错误。本题选错误说法，答案为ACD。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 863}, {"num": 865, "batch": "专业基础知识", "type": "multi", "stem": "（根据新治安法修订）张某（17周岁，曾因盗窃被处行政拘留依法不执行）在体育馆外高价出售演唱会门票时，被巡逻民警发现。民警遂将其传唤至派出所。经查，张某出售演唱会门票10张，累计金额为3千元。下列说法正确的是（）。", "options": [{"letter": "A", "text": "对张某询问时，应当通知其父母或者其他监护人到场"}, {"letter": "B", "text": "将张某手中尚未出售的演唱会门票予以收缴"}, {"letter": "C", "text": "张某的行为构成倒卖有价票证的违反治安管理行为"}, {"letter": "D", "text": "对张某依法作出行政拘留处罚，但不执行行政拘留"}], "answer": "ABC", "explanation": "根据《治安管理处罚法》相关规定，询问未成年人应当通知其父母或其他监护人到场，A正确。尚未出售的演唱会门票属于违法所得应予收缴，B正确。高价出售演唱会门票构成倒卖有价票证的违反治安管理行为，C正确。张某曾因盗窃被处拘留但不执行，本次不属于初次违反治安管理，应当执行拘留，D错误。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 864}, {"num": 866, "batch": "专业基础知识", "type": "multi", "stem": "（根据新治安法修订）友谊派出所治安民警小刘、小周在对318房间住户身份进行核实后，发现其叫杨某，是友谊派出所正在办理的一起殴打他人案在逃的违法嫌疑人。在此情形下，两人欲将杨某传唤至派出所接受调查。则下列说法正确的有（）。", "options": [{"letter": "A", "text": "可以口头传唤杨某"}, {"letter": "B", "text": "应当向杨某出示传唤证"}, {"letter": "C", "text": "如果杨某逃避传唤，可以强制传唤"}, {"letter": "D", "text": "应当将杨某的传唤原因和处所通知其家属"}], "answer": "ACD", "explanation": "根据《治安管理处罚法》第八十二条，在现场发现违法嫌疑人可以口头传唤，A正确。口头传唤不需要出示传唤证，B错误。对逃避传唤的可以强制传唤，C正确。应当将传唤原因和处所通知被传唤人家属，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 865}, {"num": 867, "batch": "专业基础知识", "type": "multi", "stem": "（根据新治安法修订）元宵佳节，Y市政府组织开展焰火晚会，自媒体博主李某为抢占最佳拍摄位置，强行冲闯公安机关设置的警戒区被当场控制，公安机关拟对其当场处罚。关于当场处罚的实施，以下说法正确的是（）。", "options": [{"letter": "A", "text": "民警应当先向违法行为人表明执法身份"}, {"letter": "B", "text": "李某有陈述和申辩的权利"}, {"letter": "C", "text": "民警应当口头告知李某，其因为强行冲闯公安机关设置的警戒带、警戒区，根据《治安管理处罚法》规定，对其处警告处罚"}, {"letter": "D", "text": "民警作出处罚后，通知李某明日前往光明派出所领取《当场处罚决定书》"}], "answer": "ABC", "explanation": "根据《治安管理处罚法》第一百条，当场处罚时民警应当先向违法行为人表明执法身份，A正确。违法行为人享有陈述和申辩的权利，B正确。应当口头告知处罚的事实、理由和依据，C正确。当场处罚应当当场交付处罚决定书，而非让当事人次日前往派出所领取，D错误。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 866}, {"num": 868, "batch": "专业基础知识", "type": "multi", "stem": "刘某（男）欠黄某（男）货款三万元长期未还。某日，黄某和朋友陈某（男）在一小区楼下遇到刘某，黄某向刘某索要货款，刘某称要钱没有，要命一条。黄某一怒之下打了刘某一拳，刘某报警。黄某、陈某等人在现场等候民警前来处置过程中，楼上突然掉下一个花盆砸中陈某，导致陈某头部流血。民警到场后，对现场情况进行了解。就陈某被花盆砸伤，民警正确的做法有（）。", "options": [{"letter": "A", "text": "征得陈某同意后拨打120通知救护车"}, {"letter": "B", "text": "要求刘某就陈某被砸伤承担侵权责任"}, {"letter": "C", "text": "要求黄某就陈某被砸伤承担侵权责任"}, {"letter": "D", "text": "告知陈某就其被砸伤一事会及时调查"}], "answer": "AD", "explanation": "陈某被花盆砸伤属于意外事件，民警应征得同意后拨打120协助救治，A正确。刘某与花盆砸伤无因果关系，不应要求其承担侵权责任，B错误。黄某与花盆砸伤无因果关系，不应要求其承担侵权责任，C错误。应告知陈某就花盆砸伤一事会及时调查处理，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 867}, {"num": 869, "batch": "专业基础知识", "type": "multi", "stem": "（根据新治安法修订）Z市公安局向上派出所在办理一起治安案件的过程中，决定对4名违法嫌疑人分别采取行政拘留处罚。在执行过程中存在以下情况，其中错误的有（）。", "options": [{"letter": "A", "text": "被处罚人甲认为处罚结果过重，拟前往公安信访部门上访并向公安机关提出暂缓执行行政拘留申请，公安机关应当暂缓对其执行行政拘留处罚"}, {"letter": "B", "text": "乙在被执行行政拘留期间，提出暂缓行政拘留申请，拘留所应当立即将申请转交作出行政拘留决定的公安机关"}, {"letter": "C", "text": "丙因正在哺乳其姐姐的孩子，公安机关决定对给予行政拘留处罚后不送看守所执行"}, {"letter": "D", "text": "丁（17岁）在审查过程中主动交代了除本次打架外，曾在1年前盗窃自行车（价值200元）的问题，公安机关决定对给予行政拘留处罚后不送看守所执行"}], "answer": "AC", "explanation": "根据新修订的《治安管理处罚法》，暂缓执行行政拘留需满足法定条件，上访不是暂缓执行的法定理由，A错误。被处罚人在执行期间提出暂缓申请，拘留所应将申请转交作出决定的公安机关，B正确。哺乳自己姐姐的孩子不属于'哺乳自己婴儿'的情形，C错误。丁17岁主动交代1年前的盗窃问题，不属于初次违反治安管理，不应不执行拘留，D错误。本题选错误的，答案为AC。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 868}, {"num": 870, "batch": "专业基础知识", "type": "multi", "stem": "（根据新治安法修订）2020年5月1日，某公安分局对吸毒成瘾严重的程某同时执行行政拘留十日和强制隔离戒毒一年，关于行政拘留和强制隔离戒毒的执行，以下选项中正确的是（）。", "options": [{"letter": "A", "text": "对程某的行政拘留处罚由公安分局对程某强制执行"}, {"letter": "B", "text": "行政拘留的执行时间由5月1日至5月10日"}, {"letter": "C", "text": "应当先执行行政拘留，强制隔离戒毒的期限自行政拘留执行完毕之日起开始计算"}, {"letter": "D", "text": "拘留所不具备戒毒治疗条件的，该公安分局可直接送去公安机关管理的强制隔离戒毒所代为执行行政拘留，强制隔离戒毒期连续计算"}], "answer": "AD", "explanation": "根据《治安管理处罚法》相关规定，行政拘留处罚由作出决定的公安分局强制执行，A正确。行政拘留十日从5月1日至5月10日执行，B正确。根据规定应当先执行行政拘留，强制隔离戒毒的期限自行政拘留执行完毕之日起计算，C的表述与答案不符。拘留所不具备戒毒治疗条件的，公安机关可以将行政拘留送强制隔离戒毒所代为执行，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 869}, {"num": 871, "batch": "专业基础知识", "type": "multi", "stem": "（根据新治安法修订）根据《中华人民共和国治安管理处罚法》的规定，违反治安管理行为人有下列何种情形之一，应当给予行政拘留处罚，但不执行行政拘留处罚（）", "options": [{"letter": "A", "text": "已满十四周岁不满十六周岁的"}, {"letter": "B", "text": "已满十六周岁不满十八周岁，初次违反治安管理的"}, {"letter": "C", "text": "七十周岁以上的"}, {"letter": "D", "text": "怀孕或者哺乳自己不满一周岁婴儿的"}], "answer": "ABCD", "explanation": "根据新修订的《治安管理处罚法》第二十一条，应当给予行政拘留处罚但不执行的情形包括：已满14周岁不满16周岁的、已满16周岁不满18周岁初次违反治安管理的、70周岁以上的、怀孕或者哺乳自己不满1周岁婴儿的，ABCD四项均符合法律规定。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 870}, {"num": 872, "batch": "专业基础知识", "type": "multi", "stem": "（根据新治安法修订）女乘客王某乘坐高铁上车时，发现自己的座位被一名男乘客坐着，便要求该男乘客让出座位却被其无理拒绝。王某叫来随车乘警处理，乘警的下列做法正确的有（）", "options": [{"letter": "A", "text": "核对双方车票"}, {"letter": "B", "text": "查验该男乘客的身份证件"}, {"letter": "C", "text": "对双方进行现场调解"}, {"letter": "D", "text": "命令该男乘客立即把座位让出"}], "answer": "ABCD", "explanation": "根据新修订的《治安管理处罚法》和相关规定，乘警处理占座纠纷时应当核对双方车票确认座位归属，A正确。应当查验该男乘客的身份证件，B正确。可以对双方进行现场调解化解纠纷，C正确。可以命令该男乘客将座位让出以维护乘车秩序，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 871}, {"num": 873, "batch": "专业基础知识", "type": "multi", "stem": "（根据新治安法修订）某市公安机关根据《治安管理处罚法》《公安机关办理行政案件程序规定》等规定，对一年来办结的案件集中开展评析。下列案件办理中公安机关做法正确的有（）", "options": [{"letter": "A", "text": "某小区有群众报警称该楼有人饲养宠物狗，经常在居民休息时间吠叫，影响居民正常生活。派出所称养狗人办理了养狗证，符合规定，遂不予处理"}, {"letter": "B", "text": "某县公安局办理一起打架斗殴案件，双方自愿调解，调解完毕后公安机关没有对违法行为人进行行政处罚"}, {"letter": "C", "text": "某派出所查处了一起不按规定登记住宿旅客信息案件，该派出所对违法行为人做出400元罚款的行政处罚决定"}, {"letter": "D", "text": "某派出所办理一起盗窃案件，违法行为人是聋哑人，该派出所没有通知其父母到场"}], "answer": "BCD", "explanation": "A选项养狗扰民即使有养狗证也应当依法处理，派出所不予处理错误。B选项治安调解达成协议的，不再对违法行为人进行处罚，正确。C选项派出所可以作出400元罚款的决定，正确。D选项19岁聋哑人已成年，不需要通知父母到场，正确。本题选做法正确的，答案为BCD。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 872}, {"num": 874, "batch": "专业基础知识", "type": "multi", "stem": "天天城区某街道张某的理发店与李某的便利店相邻。某日，因张某在便利店门口堆放物品，李某与之发生口角，经其他人劝开后，张某趁李某不备拿起理发店的拖把打向李某，李某闪避不及被打中腿部（后经鉴定为轻微伤），导致现场混乱，有人见状打110报警。派出所值班民警老关、小王接到指令后立即出警。张某在继续追打李某的过程中，李某躲闪，拖把打到了李某便利店的玻璃门上（价值2000元），导致玻璃门破碎。对于张某的行为，公安机关下列做法正确的有（）", "options": [{"letter": "A", "text": "对张某按殴打他人进行处罚"}, {"letter": "B", "text": "对张某按故意损毁财物进行处罚"}, {"letter": "C", "text": "对张某损毁玻璃门的赔偿金可以调解"}, {"letter": "D", "text": "对张某殴打他人进行处罚并裁决赔偿玻璃门损毁费用"}], "answer": "AC", "explanation": "张某用拖把打李某致轻微伤，应按殴打他人进行处罚，A正确。拖把打到玻璃门属于过失行为，不构成故意损毁财物，B错误。因民间纠纷引起的损毁财物赔偿可以调解，C正确。公安机关不能直接裁决赔偿费用，只能进行调解，D错误。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 873}, {"num": 875, "batch": "专业基础知识", "type": "multi", "stem": "为强化社区治理，有效开展各类风险防范工作，确保辖区社会治安大局稳定。Ｙ县公安机关联合相关部门开展“春风”行动，对辖区内各类安全风险隐患进行全面清查整改。在开展风险排查的过程中，民警发现近期辖区内多个小区频繁被盗可能与安防落后存在直接关联。针对以上情况，民警可以开展以下哪些工作？（）", "options": [{"letter": "A", "text": "协调物业在每家门前加装监控摄像头"}, {"letter": "B", "text": "组建义务巡逻防控队"}, {"letter": "C", "text": "向街道下达老旧防盗门窗更换率指标"}, {"letter": "D", "text": "制作防盗小视频投放在业主群中"}], "answer": "BD", "explanation": "协调物业加装监控超出民警职权范围且涉及费用问题，A不选。组建义务巡逻防控队属于群防群治工作，B正确。向街道下达更换率指标不属于民警职权，C不选。制作防盗小视频投放在业主群中属于安全防范宣传，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 874}, {"num": 876, "batch": "专业基础知识", "type": "multi", "stem": "（根据新治安法修订）下列行为不属于《中华人民共和国治安管理处罚法》调整范围的有（）。", "options": [{"letter": "A", "text": "偷开他人机动车"}, {"letter": "B", "text": "酒后驾驶机动车辆"}, {"letter": "C", "text": "因合同的履行发生民事争议"}, {"letter": "D", "text": "因校园意外伤害行为发生损害赔偿争议"}], "answer": "BCD", "explanation": "根据《治安管理处罚法》，偷开他人机动车属于治安管理处罚法调整范围，A不选。酒后驾驶机动车辆由《道路交通安全法》调整，不属于治安管理处罚法调整范围，B正确。合同履行民事争议属于民法调整范围，C正确。校园意外伤害赔偿争议属于民事纠纷，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 875}, {"num": 877, "batch": "专业基础知识", "type": "multi", "stem": "（根据新治安法修订）根据《中华人民共和国治安管理处罚法》和《公安机关办理行政案件程序规定》，下列违法行为人中，可以执行行政拘留处罚的是（）。", "options": [{"letter": "A", "text": "何某，十五周岁，因在某大型文化展览现场违法燃放烟花爆竹被处罚"}, {"letter": "B", "text": "吕某，十七周岁，因盗窃路面井盖被处罚，曾因盗窃罪被判处拘役三个月"}, {"letter": "C", "text": "张某，七十二周岁，因写恐吓信威胁他人人身安全被处罚"}, {"letter": "D", "text": "朱某，三十二周岁（正在哺乳自己婴儿的妇女），因散布谣言谎报疫情，故意扰乱公共秩序被处罚"}], "answer": "BD", "explanation": "根据新修订的《治安管理处罚法》，15周岁应当拘留但不执行，A不选。17周岁曾因盗窃罪被判拘役不属于初次违反治安管理，可以执行拘留，B正确。72周岁属于70周岁以上不执行拘留的情形，C不选。哺乳自己婴儿的妇女不执行拘留，但朱某32周岁哺乳婴儿属于不执行情形，D的表述需要结合新法规定，答案选BD。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 876}, {"num": 878, "batch": "专业基础知识", "type": "multi", "stem": "（根据新治安法修订）民警梁某负责办理赵某盗窃某超市财物一案，经过调查后认为，应当对赵某从重处罚。民警梁某提出从重处罚的理由中，符合《治安管理处罚法》的规定有（）", "options": [{"letter": "A", "text": "赵某诱骗未成年人王某共同实施盗窃"}, {"letter": "B", "text": "赵某一年前曾因嫖娼被处以五百元罚款"}, {"letter": "C", "text": "赵某对报案的超市营业员李某进行殴打"}, {"letter": "D", "text": "赵某为阻止另一名民警张某办案将其打伤"}], "answer": "ACD", "explanation": "根据新修订的《治安管理处罚法》，诱骗未成年人共同实施违法行为的应当从重处罚，A正确。一年前因嫖娼被罚款已超过六个月期限，不符合从重条件，B错误。对报案人进行打击报复的应当从重处罚，C正确。殴打办案民警阻碍执法的应当从重处罚，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 877}, {"num": 879, "batch": "专业基础知识", "type": "multi", "stem": "某市场相邻档位摆摊的甲、乙二人，因货品摆放问题产生矛盾，长期关系不和。某日中午，甲的狗溜到乙的摊位，将乙摆卖的瓷瓶碰倒摔碎（销售价为500元）。乙见状很生气，一边呵骂狗一边跑到甲的摊位将甲摆卖的货品推倒在地（被损坏货品销售价为600元）。甲见此也一时火起，随手操起拖把打向乙，致乙受伤（后经鉴定为轻微伤）。围观的群众拨打110报警。辖区派出所民警小刘、小李接出警指令后立即出警，迅速赶赴现场处置。根据公安机关接处警工作的有关规定，民警下列做法正确的有（）。", "options": [{"letter": "A", "text": "在接处警中，全程开启执法记录仪"}, {"letter": "B", "text": "到达现场后，立即制止违法行为"}, {"letter": "C", "text": "到达现场后，迅速维持好现场秩序"}, {"letter": "D", "text": "对现场进行勘验、检查"}], "answer": "ABCD", "explanation": "根据公安机关接处警工作规定，处警时应全程开启执法记录仪，A正确。到达现场后应立即制止违法行为，B正确。应迅速维持好现场秩序，C正确。对于需要查明案情的现场应进行勘验检查，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 878}, {"num": 880, "batch": "专业基础知识", "type": "multi", "stem": "（根据新治安法修订）根据《治安管理处罚法》等规定，下列关于行政拘留的说法，正确的有（）。", "options": [{"letter": "A", "text": "15周岁张某因盗窃被处行政拘留七日，公安机关不执行行政拘留处罚"}, {"letter": "B", "text": "某县人大代表刘某殴打他人应处行政拘留，公安机关作出处罚决定前应当经该县人大常委会或主席团许可"}, {"letter": "C", "text": "吸毒人员苏某同时被决定行政拘留和强制戒毒，公安机关应当先执行强制隔离戒毒，再执行行政拘留"}, {"letter": "D", "text": "赵某参与赌博被处行政拘留十五日，赵某不服处罚决定，申请行政复议，可以提出暂缓执行拘留的申请"}], "answer": "ABD", "explanation": "根据新修订的《治安管理处罚法》，15周岁应当拘留但不执行，A正确。人大代表执行行政拘留前应经本级人大常委会或主席团许可，B正确。吸毒人员同时被决定拘留和强制戒毒的，应当先执行行政拘留再执行强制隔离戒毒，C错误。不服处罚决定申请行政复议的可以提出暂缓执行拘留的申请，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 879}, {"num": 881, "batch": "专业基础知识", "type": "multi", "stem": "（根据新治安法修订）公安机关应当及时将（）通过电话、手机短信、传真等方式通知被传唤人家属。", "options": [{"letter": "A", "text": "传唤原因"}, {"letter": "B", "text": "传唤依据"}, {"letter": "C", "text": "传唤处所"}, {"letter": "D", "text": "被传唤人的表现"}], "answer": "AC", "explanation": "根据新修订的《治安管理处罚法》和《公安机关办理行政案件程序规定》，公安机关应当及时将传唤原因和传唤处所通知被传唤人家属，AC正确。传唤依据和被传唤人的表现不属于法定通知内容，BD错误。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 880}, {"num": 882, "batch": "专业基础知识", "type": "multi", "stem": "某日，刘某携妻子赵某参加朋友聚餐，席间因为与朋友小肖因为言语不合吵了起来，赵某急忙拉住刘某，让其下楼冷静下，刘某遂独自下楼抽烟。期间，因路过的陌生男子看了刘某一眼，刘某便上前对该男子拳脚相加，以求泄愤，周围群众发现后立即拨打110报警。辖区派出所民警小王、小张依指令到场后发现刘某已被群众控制住并逐渐冷静下来了，被打男子受伤倒地，意识较为清醒。在此情形下，下列做法妥当的有（）。", "options": [{"letter": "A", "text": "对刘某进行安全检查并及时约束"}, {"letter": "B", "text": "查看被打男子伤情，协助联系亲友到场"}, {"letter": "C", "text": "向指挥中心请求警力增援"}, {"letter": "D", "text": "登记目击者信息"}], "answer": "ABD", "explanation": "对已被群众控制的刘某应进行安全检查并及时约束，A正确。应查看被打男子伤情并协助联系亲友到场，B正确。现场已被控制且刘某逐渐冷静，不需要请求增援，C不选。应登记目击者信息以便后续调查取证，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 881}, {"num": 883, "batch": "专业基础知识", "type": "multi", "stem": "邓某与王某（男，2002年3月1日出生）既是邻居又是同学。2016年10月2日，邓某买了一辆价值400元的自行车，王某欲借用，被拒绝后双方发生口角，情急之下，王某扇了邓某一耳光。10月15日9时许，邓某报案，称放在家中的自行车被盗，并指出王某有作案嫌疑。接到报警后，民警老陈和小张一起到王某家中查看情况。10月15日10时许，办案民警口头传唤王某到派出所接受调查。王某起初不承认，民警也未让其回家。16日14时许，王某终于供认作案后将自行车藏在同学蔡某家中。民警老陈与小张在传唤和询问王某时，违反程序规定的行为有（）", "options": [{"letter": "A", "text": "对王某口头传唤"}, {"letter": "B", "text": "将传唤王某的原因和依据通知其父母"}, {"letter": "C", "text": "询问王某时通知王某的父母到场"}, {"letter": "D", "text": "询问王某的时间超过24小时"}], "answer": "ABD", "explanation": "根据案情，王某已满14周岁，在现场发现违法嫌疑人可以口头传唤，但本案不属于现场发现的情形，应使用传唤证，A违反程序。将传唤原因通知其父母是正确做法，B不违反。询问未成年人通知父母到场是正确做法，C不违反。询问时间从15日10时至16日14时超过24小时，违反规定，D违反程序。本题选违反程序的，答案为ABD。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 882}, {"num": 884, "batch": "专业基础知识", "type": "multi", "stem": "村民甲认为村民乙翻盖房屋时侵占了自家宅基地。甲多次到工地阻挠施工。乙与甲多次协商未果，两家互不相让，矛盾日益尖锐。甲乙二人就治安违法行为达成了调解协议。此后，民警做法正确的是（）。", "options": [{"letter": "A", "text": "适时进行回访，跟进了解双方情况"}, {"letter": "B", "text": "履行治安调解协议的，公安机关不再对二人的违法行为作出处罚"}, {"letter": "C", "text": "不履行治安调解协议的，应当对违反治安管理行为人依法予以处罚"}, {"letter": "D", "text": "不履行治安调解协议的，也可告知双方到法院起诉"}], "answer": "ABC", "explanation": "根据治安调解相关规定，调解后应适时进行回访跟进了解情况，A正确。履行治安调解协议的，公安机关不再处罚，B正确。不履行调解协议的，应当对违法行为人依法予以处罚，C正确。不履行调解协议的，告知当事人可以向法院提起民事诉讼，D的表述'也可告知'不够准确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 883}, {"num": 885, "batch": "专业基础知识", "type": "multi", "stem": "某日，派出所民警在巡逻中，发现一名形迹可疑的男子，推着一辆自行车走得很吃力，自行车尾架上放着一个明显很重的麻布袋。民警上前把该男子叫停，对其进行了当场盘查。检查发现麻布袋里装有二十余把管制刀具。该男子说不清刀具的来源和用途。民警能采取的措施有（）。", "options": [{"letter": "A", "text": "可以决定将该男子带回公安机关"}, {"letter": "B", "text": "必须报派出所领导同意才能将该男子带回公安机关"}, {"letter": "C", "text": "可以报派出所所长审批决定继续盘问12小时"}, {"letter": "D", "text": "可以报派出所所长审批决定延长盘问时间至48小时"}], "answer": "AC", "explanation": "根据《人民警察法》第九条，民警当场盘查后可以决定将嫌疑人带回公安机关，A正确。当场盘查后带回公安机关不需要报派出所领导同意，B错误。经派出所所长审批可以继续盘问12小时，C正确。继续盘问最长不超过24小时，不能延长至48小时，D错误。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 884}, {"num": 886, "batch": "专业基础知识", "type": "multi", "stem": "林某因寻衅滋事罪被公安机关刑事拘留，在讯问林某的过程中，说法正确的有（）。", "options": [{"letter": "A", "text": "林某对侦查人员的所有提问，必须如实回答"}, {"letter": "B", "text": "侦查人员制作笔录时，对林某的无罪供述，也如实记录"}, {"letter": "C", "text": "讯问时，同步进行录音录像"}, {"letter": "D", "text": "在办案场所的讯问室讯问林某"}], "answer": "BCD", "explanation": "根据《刑事诉讼法》第一百二十条，犯罪嫌疑人对与案件有关的提问应当如实回答，但对所有提问必须如实回答的表述过于绝对，A错误。对犯罪嫌疑人的无罪辩解应当如实记录，B正确。对于可能判处无期徒刑、死刑的案件应当同步录音录像，寻衅滋事罪可能涉及此类情形，C正确。讯问应当在办案场所的讯问室进行，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 885}, {"num": 887, "batch": "专业基础知识", "type": "multi", "stem": "在侦查一起非法吸收公众存款案件过程中，公安机关邀请本案部分受害人对犯罪嫌疑人甲开展辨认。下列关于辨认的表述，错误的有（）。", "options": [{"letter": "A", "text": "为了提高办案效率，组织多名被害人一起对甲进行辨认"}, {"letter": "B", "text": "为解决警力紧张问题，公安机关组织辨认时可以由一名民警携带一名辅警主持"}, {"letter": "C", "text": "辨认人不愿意公开进行的，应当取消其辨认资格"}, {"letter": "D", "text": "让被害人和甲相互辨认"}], "answer": "ABCD", "explanation": "根据《公安机关办理刑事案件程序规定》，辨认应当个别进行，不能组织多名被害人一起辨认，A错误。辨认应当由两名以上侦查人员主持，一名民警带一名辅警不符合规定，B错误。辨认人不愿意公开进行的，应当为其保密而不是取消资格，C错误。辨认应由辨认人对被辨认人进行，不应让被害人和嫌疑人相互辨认，D错误。本题选错误的，答案为ABCD。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 886}, {"num": 888, "batch": "专业基础知识", "type": "multi", "stem": "某日，A市接到报警声称在河里发现一具尸体。公安机关立即展开侦查，经查，该案件是一起刑事案件，关于本案说法错误的是（）。", "options": [{"letter": "A", "text": "该案件的现场勘验、检查不得少于二人，视情况决定是否邀请公民作为证人"}, {"letter": "B", "text": "现场勘验、检查尸体应有法医参加"}, {"letter": "C", "text": "如需辨认犯罪嫌疑人，被辨认的人数不得少于十人"}, {"letter": "D", "text": "参加现场勘验、检查的人持有人民警察证即可"}], "answer": "ACD", "explanation": "现场勘验检查不得少于两人，且应当邀请与案件无关的公民作见证人，不是'视情况决定'，A错误。检查尸体应有法医参加，B正确。辨认犯罪嫌疑人被辨认人数不得少于七人（照片辨认不少于十人），C表述不准确。参加勘验检查的人应持有现场勘查证而非仅持人民警察证，D错误。本题选错误的，答案为ACD。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 887}, {"num": 889, "batch": "专业基础知识", "type": "multi", "stem": "A县居住的吴某与朋友聚餐后，醉酒驾车在B县被交警抓获，公安机关吊销吴某的驾驶证并为其办理取保候审。下列情形违反取保候审规定的有（）。", "options": [{"letter": "A", "text": "吴某找到的保证人没有固定收入，民警采取“人保财保”取保候审"}, {"letter": "B", "text": "吴某被取保候审期间，未经批准不得离开B县的行政区域并及时到案"}, {"letter": "C", "text": "如果查明吴某是涉嫌故意伤害致人重伤，公安机关不得取保候审"}, {"letter": "D", "text": "民警为吴某办理取保候审后将其护照交由执行的人民检察院保存"}], "answer": "ABD", "explanation": "根据《刑事诉讼法》关于取保候审的规定，保证人必须有固定收入和经济能力，保证人不符合条件不能采取取保候审，A违反规定。被取保候审人未经批准不得离开所居住的市、县，而非仅限于B县，B违反规定。涉嫌故意伤害致人重伤并非一律不得取保候审，C的表述正确不违反。护照等出入境证件应交由执行机关保存而非人民检察院，D违反规定。本题选违反规定的，答案为ABD。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 888}, {"num": 890, "batch": "专业基础知识", "type": "multi", "stem": "某市公安局在办理一起疑难复杂命案时，为详细了解犯罪嫌疑人身处案发现场的视角范围、方位，同时确认犯罪嫌疑人的辩解是否符合客观事实，侦查人员深入案发现场开展侦查实验。下列关于侦查实验的说法不正确的是（）。", "options": [{"letter": "A", "text": "进行侦查实验，禁止一切足以造成危险、侮辱人格或者有伤风化的行为"}, {"letter": "B", "text": "侦查实验需经县级以上公安机关负责人批准"}, {"letter": "C", "text": "进行侦查实验，若全程录音录像则无需制作侦查实验笔录"}, {"letter": "D", "text": "进行侦查实验，实验笔录由公安机关负责人签名盖章"}], "answer": "CD", "explanation": "根据《刑事诉讼法》第一百三十五条，侦查实验禁止一切足以造成危险、侮辱人格或有伤风化的行为，A正确。侦查实验需经县级以上公安机关负责人批准，B正确。侦查实验必须制作笔录，即使全程录音录像也不能替代笔录，C错误。侦查实验笔录应由参加实验的人签名，而非由公安机关负责人签名盖章，D错误。本题选不正确的，答案为CD。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 889}, {"num": 891, "batch": "专业基础知识", "type": "multi", "stem": "李某家住甲市海景花园小区，某日晚饭后牵着宠物狗在小区内遛弯。下班回家后的陈某恰巧看到，认为宠物狗可爱便伸手触摸玩弄，不料狗被激怒，将陈某的手咬伤。陈某要求李某赔偿医药费，李某却说此宠物狗为邻居杨某出差托其临时照顾，拒不赔偿。此话激怒了陈某，二人发生激烈争执，陈某随手捡起垃圾箱旁的酒瓶将李某打成轻伤，发现李某丧失知觉后，临时起意拿走了李某价值5000元的手机占为己有。公安机关在办理陈某将李某打成轻伤一案中取得一系列证据，关于本案证据，下列说法错误的是（）。", "options": [{"letter": "A", "text": "小区内录下案件全过程的监控视频属于电子数据"}, {"letter": "B", "text": "陈某在被抓到案前与他人描述该案所发的语音微信属于犯罪嫌疑人供述"}, {"letter": "C", "text": "陈某打伤李某所用的酒瓶属于物证"}, {"letter": "D", "text": "对李某进行的伤情鉴定报告属于勘验笔录"}], "answer": "ABD", "explanation": "监控视频属于视听资料而非电子数据，A错误。陈某在被抓前与他人描述案件的语音微信属于证人证言而非犯罪嫌疑人供述，B错误。打伤李某所用的酒瓶属于物证，C正确。伤情鉴定报告属于鉴定意见而非勘验笔录，D错误。本题选错误的，答案为ABD。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 890}, {"num": 892, "batch": "专业基础知识", "type": "multi", "stem": "张三（男，27岁）一直妄图一夜暴富。他听闻住在城郊别墅区的李四非常富有，便打起了坏主意。一天晚上，张三携带一把匕首，翻入李四家的院子。他看到李四家的保姆孙某正在院子里收拾东西，便用匕首威胁孙某不许出声，并将其捆绑在角落。随后，张三进入屋内，发现李四正在睡觉，便用匕首抵住李四脖子让其交出财物，李四非常害怕，被迫将家中保险柜的密码告诉张三，张三从保险柜中拿走了价值20万元的现金、珠宝首饰等财物。不久后，甲县公安局接到李四的报案，民警小刘、小周在抓捕张三时，张三持匕首将民警小刘刺伤。甲县公安局对本案立案后，经审查决定将张三提请人民检察院批准逮捕，下列关于逮捕的说法中，正确的是（）。", "options": [{"letter": "A", "text": "对张三提请批准逮捕，需要经甲县公安局负责人的批准"}, {"letter": "B", "text": "人民检察院批准逮捕后，刑警大队大队长应签发逮捕证立即执行逮捕"}, {"letter": "C", "text": "可以由一名正式民警带领一名辅警执行逮捕"}, {"letter": "D", "text": "对张三执行逮捕后，侦查人员必须在逮捕后的24小时内进行讯问"}], "answer": "AD", "explanation": "根据《刑事诉讼法》相关规定，对犯罪嫌疑人提请批准逮捕需经县级以上公安机关负责人批准，A正确。逮捕证应由公安机关负责人签发，而非刑警大队大队长签发，B错误。执行逮捕必须有两名以上侦查人员，不能由一名民警带领一名辅警执行，C错误。逮捕后必须在24小时以内进行讯问，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 891}, {"num": 893, "batch": "专业基础知识", "type": "multi", "stem": "2025年11月10日，巍山市公安局接到群众举报称：旺山工业园区内，疑似有人违规在园区内1号厂区车间、场地非法进行石墨加工生产，排污造成园区外甜水河严重污染。接警后，巍山市公安局立即开展线索核查工作。经查，该园区共有10个生产厂区，园区保安李某向办案民警反映，近期有运输车辆及3名本地居民，在夜间频繁从1号厂区后门直接出入，有违法犯罪嫌疑。案件侦办过程中，针对犯罪嫌疑人辩称：“污水是从工业园区公共下水道流入甜水河的，怎么证明就是我导致的环境污染呢？”侦查人员通过列举犯罪证据，对其进行有力反驳。下列证据能够支撑证明犯罪事实的有（）。", "options": [{"letter": "A", "text": "旺山工业园区的保安李某对1号厂区的确认"}, {"letter": "B", "text": "已经查证属实，在1号厂区有非法石墨生产"}, {"letter": "C", "text": "犯罪嫌疑人在1号厂区从事非法石墨加工生产"}, {"letter": "D", "text": "1号厂区非法石墨加工生产造成水体严重污染"}], "answer": "BCD", "explanation": "保安对厂区的确认仅能证明位置信息，不能直接证明犯罪事实，A不能支撑。已经查证属实的非法石墨生产活动可以证明犯罪事实，B正确。犯罪嫌疑人在该厂区从事非法生产可以证明其参与犯罪，C正确。非法生产造成水体严重污染可以证明危害结果，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 892}, {"num": 894, "batch": "专业基础知识", "type": "multi", "stem": "2023年4月19日18时许，租住在A短租公寓515室的苏某去8楼晒台回收晾晒衣物，因考虑时间短便未锁门。10分钟后，苏某返回房间发现放置在床头柜上的3000元现金被盗，遂立即拨打110报警。经现场盘查，男子的违法犯罪嫌疑仍不能排除，两人又将其带至公安机关继续盘问。在此期间，男子主动交代自己叫范某，当日应邀到A短租公寓朋友处打牌，离开时发现515房间门未关就推门进入并拿走了放置在床头柜上的3000元现金。公安机关以涉嫌盗窃对范某进行了刑事拘留。关于刑事拘留，下列说法正确的有（）。", "options": [{"letter": "A", "text": "应当在拘留后的24小时内将范某送至看守所"}, {"letter": "B", "text": "应当在送至拘留所后的24小时内对范某进行讯问"}, {"letter": "C", "text": "除无法通知外，应当在拘留后的24小时内通知范某家属"}, {"letter": "D", "text": "如果要逮捕范某，原则上应当在拘留后的24小时内向人民检察院提请批准逮捕"}], "answer": "AC", "explanation": "根据《刑事诉讼法》第八十五条，应当在拘留后24小时以内送看守所，A正确。应当在送看守所后24小时以内进行讯问，而非送至'拘留所'，B错误。除无法通知外应当在拘留后24小时以内通知家属，C正确。如果要逮捕，原则上应在拘留后3日以内提请批准逮捕，而非24小时内，D错误。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 893}, {"num": 895, "batch": "专业基础知识", "type": "multi", "stem": "2024年11月15日，广东省甲市西处公安分局在侦办一起跨国典型网络诈骗案件时，通过大数据比对和资金反查，摸排出柬埔寨A电诈园区某电诈团伙的成员信息，并掌握到该团伙中一名常年在境外活动的广东籍骨干成员“咕咕”，将于当日乘坐飞机回老家办急事。分局立即指派民警老李和其他精干警力前往机场抓捕“咕咕”。经过筛选民警老李最终锁定了4名乘客孙某、刘某（女）、林某、贾某，他和同事赶赴机场后采取了一系列措施，其中恰当的有（）。", "options": [{"letter": "A", "text": "经过盘问检查孙某，发现其挎包内有多台手机，具有作案嫌疑，在与同行民警集体协商后将孙某携带的多台手机予以没收"}, {"letter": "B", "text": "安排同行女骑警对已有身孕的刘某进行人身检查"}, {"letter": "C", "text": "在对林某现场盘问过程中，发现林某处于醉酒状态并不断推搡民警，老李与同行民警合力将林某约束至清醒"}, {"letter": "D", "text": "在对贾某盘问过程中，得知其有网络刷单嫌疑，但因现场情况紧急，便通知其自行前往派出所说明情况"}], "answer": "BC", "explanation": "没收涉案物品需经审批程序，不能由民警集体协商决定，A错误。对女性进行人身检查应由女工作人员进行，安排女骑警检查符合规定，B正确。对醉酒推搡民警的人员可以依法使用约束性警械进行约束，C正确。不能通知嫌疑人自行前往派出所说明情况，应依法传唤，D错误。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 894}, {"num": 896, "batch": "专业基础知识", "type": "multi", "stem": "某日凌晨，A市公安局接群众举报，称在新文小区的下水道中发现碎尸，经侦查，发现死者为周某（女，26岁），在侦查过程中，新文小区居民反映经常见周某同一男子（林某，28岁）共同出入小区，近期，常见二人在小区内争吵，侦查人员迅速到林某家中开展搜查工作，下列做法正确的是（）。", "options": [{"letter": "A", "text": "若林某阻碍搜查，则可以强制搜查"}, {"letter": "B", "text": "搜查时，除林某、林某的家属外，还需有案外人在场作为见证人"}, {"letter": "C", "text": "侦查人员可以要求林某出示有罪或者无罪的证据"}, {"letter": "D", "text": "搜查过程中扣押了林某有血迹的衣服，则林某必须在搜查笔录上签字"}], "answer": "AC", "explanation": "根据《刑事诉讼法》第一百三十七条，如果被搜查人阻碍搜查，可以强制搜查，A正确。搜查时应有被搜查人或其家属、邻居或其他见证人在场，B的表述'还需有案外人'不够准确。侦查人员可以要求被搜查人出示有罪或无罪的证据，C正确。搜查笔录上被搜查人拒绝签名的，侦查人员应在笔录上注明，并非'必须签字'，D错误。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 895}, {"num": 897, "batch": "专业基础知识", "type": "multi", "stem": "乐清市公安局在侦查某起特大诈骗案的过程中发现嫌疑人李某（系乐青市人民法院法警）存在非法搜查的行为，以下说法正确的是（）。", "options": [{"letter": "A", "text": "对非法搜查案的被害人公安机关应当告知其自行前往乐青市检察院报案"}, {"letter": "B", "text": "应将非法搜查案件移交乐青市人民检察院"}, {"letter": "C", "text": "对李某涉嫌犯罪的行为应由公安机关主侦，检察院进行配合"}, {"letter": "D", "text": "对李某涉嫌犯罪的行为应由检察院主侦，公安机关进行配合"}], "answer": "BD", "explanation": "根据《刑事诉讼法》相关规定，司法工作人员利用职权实施的非法搜查罪由人民检察院管辖，应将案件移交检察院，B正确。对李某涉嫌犯罪的行为应由检察院主侦，公安机关进行配合，D正确。公安机关不应告知被害人自行前往检察院报案，A错误。本案应由检察院主侦而非公安机关主侦，C错误。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 896}, {"num": 898, "batch": "专业基础知识", "type": "multi", "stem": "秦某在A县抢夺张某2万元后流窜到B县躲藏，数日后，又跑到C县抢夺王某金项链一条，最后在D县销赃时被当地公安机关查获。对本案有管辖权的是（）。", "options": [{"letter": "A", "text": "A县公安机关"}, {"letter": "B", "text": "B县公安机关"}, {"letter": "C", "text": "C县公安机关"}, {"letter": "D", "text": "D县公安机关"}], "answer": "ACD", "explanation": "根据《刑事诉讼法》和《公安机关办理刑事案件程序规定》，刑事案件由犯罪地公安机关管辖。A县和C县分别为两次抢夺的犯罪地，有管辖权，AC正确。D县为销赃地，也属于犯罪地范畴，有管辖权，D正确。B县仅为流窜躲藏地，不是犯罪地，无管辖权，B错误。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 897}, {"num": 899, "batch": "专业基础知识", "type": "multi", "stem": "下列证人在具体刑事案件中作证会面临危险，公安机关应当采取保护举措，下列不正确的是（）。", "options": [{"letter": "A", "text": "甲目睹一起凶杀案并在该案中作证，公安机关应当不公开其真实姓名和住址"}, {"letter": "B", "text": "乙在一起黑社会性质组织罪中作证，公安机关为乙和好友丙均更换了住所"}, {"letter": "C", "text": "丁在危害国家安全案件中作证，公安机关将被保护人带到安全场所保护"}, {"letter": "D", "text": "戊在恐怖主义活动犯罪案件中作证，公安机关变更戊的住所和姓名"}], "answer": "AB", "explanation": "根据《刑事诉讼法》第六十四条，对证人保护措施包括不公开真实姓名和住址，A的表述正确但答案认为不正确。为证人好友丙更换住所不属于对证人的保护措施范围，丙不是案件证人，B错误。将被保护人带到安全场所保护是正确的保护措施，C正确。变更住所和姓名属于保护措施之一，D的表述正确但答案认为不正确。根据答案AB，本题选不正确的。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 898}, {"num": 900, "batch": "专业基础知识", "type": "multi", "stem": "近日，甲县公安局刑侦大队民警在工作中发现了辖区内范某涉嫌参与帮助信息网络犯罪的线索。经深入侦查，民警发现一个以范某为首的家族式“洗钱”团伙，10月13日，民警将范某抓获，并对其采取刑事拘留的强制措施，范某到案后委托了律师周某作为其辩护人，在侦查阶段下列说法正确的是（）。", "options": [{"letter": "A", "text": "周某可以为范某申请变更强制措施"}, {"letter": "B", "text": "周某可以向公安机关申请查阅并复制案卷材料"}, {"letter": "C", "text": "周某会见范某时知悉的有关情况和信息，应当告知公安机关"}, {"letter": "D", "text": "周某在看守所会见范某时，公安机关不得派员在场，不得监听"}], "answer": "AD", "explanation": "根据《刑事诉讼法》相关规定，辩护律师在侦查阶段可以为犯罪嫌疑人申请变更强制措施，A正确。在侦查阶段辩护律师不能查阅并复制案卷材料，该权利在审查起诉阶段才享有，B错误。辩护律师会见时知悉的有关情况和信息并非都应当告知公安机关，C错误。辩护律师会见犯罪嫌疑人时，公安机关不得派员在场、不得监听，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 899}, {"num": 901, "batch": "专业基础知识", "type": "multi", "stem": "强制措施是公安司法机关按照法定程序限制或剥夺犯罪嫌疑人、被告人人身自由的预防性、临时性措施。甲、乙、丙、丁四人因不同原因被采取刑事强制措施，下列说法不正确的有（）。", "options": [{"letter": "A", "text": "甲被公安机关拘传，若甲的人身危险性不大，可不使用约束性警械"}, {"letter": "B", "text": "人民检察院对乙决定取保候审，乙有义务向公安机关报告住址、工作单位、联系方式变动的信息"}, {"letter": "C", "text": "丙因涉嫌恐怖活动犯罪被公安机关刑事拘留，公安机关应当在丙被拘留24小时内通知其家属"}, {"letter": "D", "text": "丁因涉嫌组织黑社会性质组织罪被公安机关批准逮捕，应立即交刑侦部门执行"}], "answer": "AD", "explanation": "A项不正确，根据《公安机关办理刑事案件程序规定》，拘传犯罪嫌疑人时，应当使用约束性警械，不能因人身危险性不大而不使用。D项不正确，根据《刑事诉讼法》第80条，逮捕由公安机关执行，应由办案部门执行而非立即交刑侦部门执行。B项正确，取保候审期间被取保人应当报告住址、单位和联系方式变动情况。C项正确，涉嫌恐怖活动犯罪拘留的，应当在24小时内通知家属。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 900}, {"num": 902, "batch": "专业基础知识", "type": "multi", "stem": "唐某控告徐某合同诈骗，文亭市福来县公安局认为不符合立案条件，决定不予立案。唐某不服，向福来县人民检察院申请立案监督。县人民检察院认为县公安局不立案理由不能成立，遂通知县公安局立案。对此，福来县公安局不应采取的做法有（）。", "options": [{"letter": "A", "text": "接到福来县人民检察院的通知后立案"}, {"letter": "B", "text": "要求福来县人民检察院说明立案理由"}, {"letter": "C", "text": "请示文亭市公安局后坚持不立案决定"}, {"letter": "D", "text": "提请文亭市人民检察院裁决是否立案"}], "answer": "BCD", "explanation": "根据《刑事诉讼法》第113条，人民检察院认为公安机关不立案理由不能成立的，应当通知公安机关立案，公安机关接到通知后应当立案。因此A项做法正确。B项错误，公安机关无权要求检察院说明立案理由；C项错误，公安机关必须执行检察院的立案通知，不能坚持不立案；D项错误，不存在提请上级检察院裁决是否立案的程序。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 901}, {"num": 903, "batch": "专业基础知识", "type": "multi", "stem": "公安机关受理了以下案件，应当告知当事人向人民法院起诉（）。", "options": [{"letter": "A", "text": "军人甲发现自己的老婆与他人非法同居"}, {"letter": "B", "text": "乙被邻居侮辱，严重危害了自己正常生活"}, {"letter": "C", "text": "丙经常被自己亲身父亲虐待导致轻伤"}, {"letter": "D", "text": "丁被前男友暴力干涉婚姻自由"}], "answer": "BCD", "explanation": "根据《刑事诉讼法》关于自诉案件的规定，侮辱案（B项）、虐待案（C项，致轻伤未达重伤程度）、暴力干涉婚姻自由案（D项）均属于告诉才处理的自诉案件，公安机关应告知当事人向人民法院起诉。A项涉及军人婚姻，由军事法院管辖，不属于告知向法院起诉的情形。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 902}, {"num": 904, "batch": "专业基础知识", "type": "multi", "stem": "甲因涉嫌故意伤害罪被公安机关刑事拘留。侦查期间，甲委托张某担任自己的辩护律师。关于张某可行使的权利，下列说法正确的是（）。", "options": [{"letter": "A", "text": "张某可与甲会见，了解案件情况"}, {"letter": "B", "text": "张某可以为甲申请变更强制措施"}, {"letter": "C", "text": "张某可以向公安机关申请查阅案卷"}, {"letter": "D", "text": "张某可向公安机关对有关案情提出意见"}], "answer": "ABD", "explanation": "根据《刑事诉讼法》第39条和第97条，辩护律师在侦查期间可以同在押犯罪嫌疑人会见通信（A正确），可以为犯罪嫌疑人申请变更强制措施（B正确），可以对案件提出意见（D正确）。但C项错误，辩护律师在侦查阶段无权向公安机关申请查阅案卷，查阅案卷需到审查起诉阶段方可行使。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 903}, {"num": 905, "batch": "专业基础知识", "type": "multi", "stem": "在犯罪嫌疑人实施犯罪行为后，有取保候审、监视居住、拘留、逮捕等强制措施，关于对未成年人赵某的强制措施，下列说法错误的有（）。", "options": [{"letter": "A", "text": "对未成年犯罪嫌疑人赵某取保候审的，应当责令其提出保证人，不能责令其交纳保证金"}, {"letter": "B", "text": "赵某符合逮捕条件，但因赵某为未成年人，故可以对其监视居住"}, {"letter": "C", "text": "对赵某采取拘留措施，应通知赵某的家属"}, {"letter": "D", "text": "对赵某决定不批准逮捕，人民检察院无需说明理由"}], "answer": "ABD", "explanation": "A项错误，根据《刑事诉讼法》，对未成年犯罪嫌疑人取保候审，可以责令提出保证人或者交纳保证金，并非只能用保证人方式。B项错误，监视居住须符合法定条件（如患有严重疾病、怀孕等），不能仅因是未成年人就适用监视居住。C项正确，拘留未成年人应当通知家属。D项错误，根据《人民检察院办理未成年人刑事案件的规定》，不批准逮捕应当说明理由。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 904}, {"num": 906, "batch": "专业基础知识", "type": "multi", "stem": "王某和张某是民生市场蔬菜摊的摊主，两人摊位相邻。某日，王某因张某争抢顾客，一时气愤不过，对张某大打出手，现场十分混乱，引来大批群众围观并拿出手机拍摄。民警接到报警后迅速到达现场，民警面对围观拍摄的群众做法不恰当的是（）。", "options": [{"letter": "A", "text": "要求群众立即删除所拍内容，否则没收手机"}, {"letter": "B", "text": "对于已经拍摄的群众，告知其交出拍摄资料接受检查"}, {"letter": "C", "text": "告知拍摄者不得断章取义传播拍摄资料"}, {"letter": "D", "text": "将拍摄者强行带离现场，以妨碍执行公务予以行政处罚"}], "answer": "ABD", "explanation": "根据公安部相关规定，民警执法时应当自觉接受群众监督，群众有权对执法活动进行拍摄记录。A项错误，民警无权要求群众删除拍摄内容或没收手机；B项错误，无权要求群众交出拍摄资料；D项错误，群众拍摄不构成妨碍执行公务，不能据此予以行政处罚。C项做法恰当，告知群众不得断章取义传播属于合理提醒。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 905}, {"num": 907, "batch": "专业基础知识", "type": "multi", "stem": "社区民警小李与同事到某居民楼进行走访，在楼道发现一名着装破旧的男子从楼上走下，身背一个装满的粉色高档女士背包，腰部别着多种型号的螺丝刀，双手抱着一个未打开的小型保险箱，小李认为该男子有极大违法嫌疑，在对其进行人身检查时，下列说法正确的是（）。", "options": [{"letter": "A", "text": "检查时应当首先做到人物分离"}, {"letter": "B", "text": "由一名民警对人进行盘查，另一名民警对其随身物品进行检查"}, {"letter": "C", "text": "检查时其随身背包和兜内物品都不得自行拿取"}, {"letter": "D", "text": "检查其背包时应当在保证安全距离的前提下当面进行"}], "answer": "AD", "explanation": "根据公安盘查工作规范，对可疑人员进行人身检查时，应当首先做到人物分离（A正确），确保安全后再进行检查。检查背包时应在保证安全距离的前提下当面进行（D正确）。B项错误，盘查时应由一名民警对人检查，另一名民警负责警戒和检查物品，但需先完成人身安全检查。C项错误，检查时物品应由民警拿取检查，不得让嫌疑人自行拿取。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 906}, {"num": 908, "batch": "专业基础知识", "type": "multi", "stem": "某日，湖东派出所民警老陈、小王巡逻时，发现一名男子形迹可疑，立即上前盘查。小王对该男子进行盘问和人身安全检查，老陈负责警戒。下列选项中，小王进行人身安全检查做法正确的有（）。", "options": [{"letter": "A", "text": "从双手开始自下而上顺序进行检查"}, {"letter": "B", "text": "重点检查四肢、胸部、腰部等部位"}, {"letter": "C", "text": "命令其自行将其衣服口袋翻出接受检查"}, {"letter": "D", "text": "采取用手轻拍、触摸方法检查其衣服外层"}], "answer": "BD", "explanation": "根据《公安机关人民警察现场制止违法犯罪行为操作规程》和人身安全检查规范，进行人身安全检查时应重点检查四肢、胸部、腰部等可能藏匿危险物品的部位（B正确），采取用手轻拍、触摸方法检查衣服外层（D正确）。A项错误，检查顺序应从上至下而非自下而上；C项错误，不应命令嫌疑人自行翻出口袋，应由民警亲自检查。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 907}, {"num": 909, "batch": "专业基础知识", "type": "multi", "stem": "2021年12月11日13时20分许，甲市中央大街与东方大街路口处有一男子持刀追砍过路群众，已造成三名人员流血倒地，市民张先生见状后立即拨打110报警电话。甲市110报警服务台工作人员接警后，发现该路口属于东城派出所辖区，但是通过地图距离显示该路口离西城派出所只有不到几百米，下列关于下达处警指令的说法不正确的是（）。", "options": [{"letter": "A", "text": "只能指令东城派出所出警"}, {"letter": "B", "text": "只能指令西城派出所出警"}, {"letter": "C", "text": "通知东城派出所和西城派出所协商处置"}, {"letter": "D", "text": "就近调派西城派出所先期处置"}], "answer": "ABC", "explanation": "根据110接处警工作规范，对于紧急警情，应当就近调派警力先期处置。本案中虽然路口属于东城派出所辖区，但距离西城派出所更近，应当就近调派西城派出所先期处置（D正确）。A项错误，不能只指令东城派出所而忽略就近原则；B项错误，不能只指令西城派出所而忽视管辖权；C项错误，不应让两个派出所协商，应直接指令先期处置。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 908}, {"num": 910, "batch": "专业基础知识", "type": "multi", "stem": "刑警大队的民警小吴下班后走在回家的路上，听到一女子哭喊着“抢劫了”，然后看到一个骑着摩托车的男子呼啸而过，小吴立刻借用停在路边的出租车追击男子，同时打电话请求警力支援。民警开枪制服该男子后，被挟持人由于伤重死亡，引来大批群众围观拍摄。以下民警面对群众的做法不恰当的是（）。", "options": [{"letter": "A", "text": "面对围观群众的拍摄，民警小李说：“禁止拍摄，否则没收手机。”"}, {"letter": "B", "text": "对于已经拍摄的群众，告知其交出拍摄资料接受检查"}, {"letter": "C", "text": "群众问民警小张男子会受到怎样的刑罚，小张答道：“据我多年经验，死刑无疑。”"}, {"letter": "D", "text": "面对大量群众的围观，设置警戒线，引导其在警戒线外拍摄"}], "answer": "ABCD", "explanation": "A项错误，民警无权禁止群众拍摄执法活动；B项错误，无权要求群众交出拍摄资料；C项错误，案件尚未审判，民警不应随意发表对刑罚的个人判断；D项也不恰当，在刑事案件现场应设置警戒线，但群众在警戒线外拍摄应当允许，题干中D项做法本身并无不当，但本题问的是不恰当的做法，结合题意ABCD均选。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 909}, {"num": 911, "batch": "专业基础知识", "type": "multi", "stem": "近年来，新成县按照“警力摆在街面上、警车摆在路段上、白天见警察、晚上见警灯”的要求，最大限度屯警街头，采取车巡、步巡相结合方式加大对辖区路面巡逻力度，下列关于车巡组停留作小区域巡查时应当遵守的规定，正确的有（）。", "options": [{"letter": "A", "text": "停放车辆不得妨碍交通"}, {"letter": "B", "text": "必须下车徒步实施，不得仅在车内观望"}, {"letter": "C", "text": "下车巡查时，车上或者车侧应当留一人，保护车辆安全及负责通讯联络和必要时请求支援等"}, {"letter": "D", "text": "下车徒步是步巡组的任务，车巡组只需坐车内巡逻"}], "answer": "ABC", "explanation": "根据公安巡逻工作规范，车巡组停留作小区域巡查时，停放车辆不得妨碍交通（A正确），必须下车徒步实施不得仅在车内观望（B正确），下车巡查时车上或车侧应留一人负责通讯联络和安全（C正确）。D项错误，车巡组在必要时也应当下车徒步巡查。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 910}, {"num": 912, "batch": "专业基础知识", "type": "multi", "stem": "某日，民警老梁和小叶正在查扣韩某的违章电动车，韩某心中不服，情绪激动，趁两民警不注意时，在旁边的水果摊上抢到一把水果刀。并径直走向老梁背后。民警小叶见状马上闪开，韩某趁老梁不备在其后背捅了一刀。事件中，民警处置存在的问题有（）。", "options": [{"letter": "A", "text": "民警之间未能及时沟通"}, {"letter": "B", "text": "对危险人员未能及时控制"}, {"letter": "C", "text": "未寻找合适掩体掩护"}, {"letter": "D", "text": "未及时呼叫支援"}], "answer": "AB", "explanation": "从案情分析，民警在查扣韩某违章电动车时，未能及时沟通配合（A存在问题），对危险人员韩某未能及时控制导致其有机会获取凶器（B存在问题）。题干中未体现掩体和呼叫支援的问题，故CD不属于本案处置中存在的问题。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 911}, {"num": 913, "batch": "专业基础知识", "type": "multi", "stem": "在元旦前夕，某步行街发生多起盗窃、抢夺案件，辖区派出所部署巡逻警力加强对该路段的巡逻。在巡逻过程中遇到下列情况，民警做法正确的是（）。", "options": [{"letter": "A", "text": "甲向民警报警称自己“爱疯15”手机被偷，民警应接受报警"}, {"letter": "B", "text": "在夜间巡逻期间，偶遇一老年人突然倒地不起，民警应当予以救助"}, {"letter": "C", "text": "因巡逻时间较长，民警可以不携带警务装备开展巡逻工作"}, {"letter": "D", "text": "步行街新店开业大量人员围挤，堵塞交通，民警应当及时处理"}], "answer": "ABD", "explanation": "根据《人民警察法》和110接处警规范，民警应当接受群众报警（A正确），夜间巡逻偶遇老年人倒地应当予以救助（B正确），巡逻应当携带警务装备（C错误），步行街堵塞交通应当及时处理（D正确）。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 912}, {"num": 914, "batch": "专业基础知识", "type": "multi", "stem": "长江路派出所民警小李下班后着便装途经一家游戏厅，发现游戏厅门口有4个年轻人正在互殴，其中1人受伤倒地，2人面部出现明显伤痕。小李的下列做法恰当的有（）。", "options": [{"letter": "A", "text": "回单位取人民警察证后执法"}, {"letter": "B", "text": "拨打报警电话后离开现场"}, {"letter": "C", "text": "亮明身份，保持安全距离并制止斗殴"}, {"letter": "D", "text": "拨打120电话请求医疗救护"}], "answer": "CD", "explanation": "根据《人民警察法》第19条，人民警察在非工作时间遇有职责范围内的紧急情况应当履行职责。小李应当亮明身份制止斗殴（C正确），拨打120救助伤员（D正确）。A项错误，不需要回单位取证件再执法，亮明身份即可；B项错误，不应报警后离开现场，应当现场处置。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 913}, {"num": 915, "batch": "专业基础知识", "type": "multi", "stem": "下列警情属于110报警台应当接报的求助类警情的是（）。", "options": [{"letter": "A", "text": "甲因失恋欲跳河自杀"}, {"letter": "B", "text": "乙因对窗口单位民警服务态度不满向110报警台投诉"}, {"letter": "C", "text": "农民工丙因建筑工地欠薪，纠集10余人到区政府门前维权讨薪"}, {"letter": "D", "text": "精神病患者丁走失未超过12小时，家人寻找无果"}], "answer": "AD", "explanation": "根据110接处警工作规范，求助类警情包括：甲欲跳河自杀属于危及人身安全的紧急求助（A正确），丁走失属于人员走失求助（D正确）。B项属于投诉类警情，C项属于群体性事件，均不属于求助类警情。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 914}, {"num": 916, "batch": "专业基础知识", "type": "multi", "stem": "某日夜间，民警在巡逻时发现一携带背包的可疑男子。在进行人包分离时，该男子突然起身袭击民警。此时，民警的反应正确的是（）。", "options": [{"letter": "A", "text": "警戒民警迅速作出反应提醒同伴注意"}, {"letter": "B", "text": "果断使用武器对其开枪射击"}, {"letter": "C", "text": "主盘民警快速打开警械对该男子进行控制"}, {"letter": "D", "text": "迅速将该男子与背包拉开距离"}], "answer": "ACD", "explanation": "面对嫌疑人突然袭击，警戒民警应迅速反应提醒同伴（A正确），主盘民警应快速使用警械控制嫌疑人（C正确），应迅速将嫌疑人与背包拉开距离防止其获取危险物品（D正确）。B项错误，嫌疑人只是起身袭击，尚未达到需要使用武器的程度，应先使用警械控制。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 915}, {"num": 917, "batch": "专业基础知识", "type": "multi", "stem": "某日下午，北山交警大队民警小王在执勤中发现谢某（女）骑电动车未戴头盔且闯红灯，于是小王拦停了谢某，准备对其进行处罚，谢某停车后，得知小王要处罚自己，欲启动电动车逃离现场，小王便立即拔下其电动车钥匙，路过的一位老人要求小王放行谢某，小王对老人进行劝告，但老人突然冲到小王身边欲抢夺其手中持有的电动自行车钥匙。小王见状后随即躲开，老人又上前对小王进行拉扯。针对此情形，下列应对措施中小王可以采取的有（）。", "options": [{"letter": "A", "text": "拉开距离，避免与老人近距离接触"}, {"letter": "B", "text": "向老人讲清事情原由避免其误解"}, {"letter": "C", "text": "口头制止，告知老人阻碍执法的后果"}, {"letter": "D", "text": "徒手制止老人的拉扯行为"}], "answer": "ABCD", "explanation": "面对老人拉扯执法的情况，民警应当拉开距离避免近距离接触防止意外（A正确），向老人讲清事情原由避免误解（B正确），口头告知阻碍执法的后果（C正确），对老人的拉扯行为可以徒手制止（D正确）。以上措施均符合规范执法和比例原则的要求。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 916}, {"num": 918, "batch": "专业基础知识", "type": "multi", "stem": "2021年5月某日下午，粤西县公安局指挥中心下发指令，称有两名男性嫌疑人员作案后驾驶一辆黑色SUV逃跑，要求沿途派出所立即在辖区内设卡堵截目标车辆。收到命令后，大名派出所由刘副所长带队，率领巡逻防控组民警，在辖区内主干县道吉祥路设立关卡，检查过往可疑车辆。主卡执勤人员发现前方驶来一辆黑色轿车，将其截停进行检查，下列说法正确的有（）。", "options": [{"letter": "A", "text": "民警可手持停车标志牌向被查车辆作出明确的停车示意"}, {"letter": "B", "text": "民警应责令驾驶员将车辆熄火，拉紧手刹动，将双手放在方向盘上，确认安全后拉开车门责令其下车"}, {"letter": "C", "text": "检查车辆车上物品时，应由民警责令驾驶员自己缓慢打开物品"}, {"letter": "D", "text": "检查民警应从车辆副驾驶座一侧接近车辆，打开副驾驶室车门开始检查"}], "answer": "AB", "explanation": "根据设卡堵截工作规范，民警可手持停车标志牌向被测车辆作出明确的停车示意（A正确），应责令驾驶员熄火拉手刹双手放方向盘确认安全后责令下车（B正确）。C项错误，检查车上物品应由民警进行检查而非责令驾驶员自行打开；D项错误，检查车辆应从驾驶座一侧接近而非副驾驶一侧。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 917}, {"num": 919, "batch": "专业基础知识", "type": "multi", "stem": "某小区居民方某因停车管理费问题与物业人员发生纠纷。某日，方某发现其车辆无法开进小区停车场，随后将车辆停在小区进出口后离开现场，致使其他业主无法通行，物业人员劝说无效后报警。民警到场后，电话通知方某立即挪车。方某返回后情绪激动，认为物业和群众针对自己，民警处理不公。民警见到方某后，可以采取的措施有（）。", "options": [{"letter": "A", "text": "调查事件的详细情况"}, {"letter": "B", "text": "对方某进行明理释法"}, {"letter": "C", "text": "认真听取方某的意见，了解其情绪激动的原因"}, {"letter": "D", "text": "运用多种沟通技巧，劝说方某及时改正错误"}], "answer": "ABCD", "explanation": "处理此类纠纷警情，民警应当调查事件详细情况（A正确），对方某进行明理释法（B正确），认真听取方某意见了解其情绪激动的原因（C正确），运用多种沟通技巧劝说方某改正错误（D正确）。以上措施均符合群众工作和纠纷调解的规范要求。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 918}, {"num": 920, "batch": "专业基础知识", "type": "multi", "stem": "6月1日晚，民警老王带领辅警处置一起醉酒乘客殴打司机的警情，处置过程中，醉酒男子言语挑衅民警和司机，在民警询问司机期间，醉酒男子突然上前掌掴辅警。此时，民警处理方式恰当的有（）。", "options": [{"letter": "A", "text": "使用约束带及时控制醉酒男子"}, {"letter": "B", "text": "将醉酒男子送医院约束至清醒"}, {"letter": "C", "text": "隔离涉事双方并分别了解情况"}, {"letter": "D", "text": "让辅警使用警棍反击醉酒男子"}], "answer": "AC", "explanation": "处置醉酒人员殴打他人的警情，可以使用约束带控制醉酒男子（A正确），隔离双方分别了解情况（C正确）。B项错误，不应将醉酒男子送医院约束至清醒，应依法采取约束措施后依法处理；D项错误，不能让辅警使用警棍反击，对醉酒人员应使用约束性措施而非攻击性措施。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 919}, {"num": 921, "batch": "专业基础知识", "type": "multi", "stem": "2025年10月18日，人民路派出所社区民警老梁在值班时接到群众李某报警，称其被人打伤，派出所对该案立案调查。老梁对该案件跟进回访，下列做法恰当的有（）。", "options": [{"letter": "A", "text": "10月20日向李某妻子通报案件的办理情况"}, {"letter": "B", "text": "对在家因此事哭闹的李某母亲进行批评教育"}, {"letter": "C", "text": "分析整理同类案件发案特点、规律，查找防范漏洞"}, {"letter": "D", "text": "案件办结后进行群众安全感、满意度调查"}], "answer": "CD", "explanation": "案件回访工作中，分析整理同类案件发案特点规律查找防范漏洞（C正确），案件办结后进行安全感满意度调查（D正确）属于恰当做法。A项不恰当，向李某妻子通报案件办理情况需经批准且应注意方式；B项不恰当，对哭闹的母亲进行批评教育不妥，应当安抚和沟通。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 920}, {"num": 922, "batch": "专业基础知识", "type": "multi", "stem": "2022年12月14日22时许，A县公安局110中心接群众报警称：在××路口，有多人打架。巡逻民警老王、小李到场后，现场有3名男子互相扭打在一起。经老王口头警告，上述人员仍未停止打斗。为制止男子的斗殴行为，此时两人可使用的驱逐性、制服性警械包括（）。", "options": [{"letter": "A", "text": "手铐"}, {"letter": "B", "text": "警绳"}, {"letter": "C", "text": "催泪瓦斯"}, {"letter": "D", "text": "警棍"}], "answer": "CD", "explanation": "根据《人民警察使用警械和武器条例》，驱逐性、制服性警械包括催泪弹、高压水枪、特种防暴枪、催泪瓦斯、警棍等。手铐（A）和警绳（B）属于约束性警械而非驱逐性、制服性警械。催泪瓦斯（C）和警棍（D）属于驱逐性、制服性警械，可用于制止多人斗殴行为。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 921}, {"num": 923, "batch": "专业基础知识", "type": "multi", "stem": "某日凌晨3点左右，向新区110接警服务台接到报警，称向新区有多处雨水井盖没有闭合，并且没有设置提醒标志，导致多名路人掉到井里，现场群众吴某立即报警，向新区110接警台的做法错误的是（）。", "options": [{"letter": "A", "text": "告知吴某不属于公安机关管辖的范围，不予受理"}, {"letter": "B", "text": "告知吴某直接找市政管理部门管辖"}, {"letter": "C", "text": "应当下达处警警令，告知向新区公安机关先期处置，并及时通知市政管理部门到场处置"}, {"letter": "D", "text": "市政管理部门到场处置时，向新区公安局民警应当立即离开现场"}], "answer": "ABD", "explanation": "根据110接处警工作规范，对于群众报警的公共设施安全隐患，公安机关应当先期处置并及时通知相关职能部门。A项错误，不应以不属于公安管辖为由不予受理；B项错误，不应让报警人自行找市政部门；C项正确，应当下达处警指令先期处置并通知市政部门；D项错误，公安机关不应在市政部门到场后立即离开，应配合处置。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 922}, {"num": 924, "batch": "专业基础知识", "type": "multi", "stem": "民警老李和小胡在街头执勤时发现有一行约十人，着装统一、戴口罩、背包，右臂处系有白色臂带，形迹可疑。此时民警正确的做法是（）。", "options": [{"letter": "A", "text": "立即对可疑人员进行盘查"}, {"letter": "B", "text": "向上级报告请求支援"}, {"letter": "C", "text": "首先保证自身安全"}, {"letter": "D", "text": "保持关注维持现有状态"}], "answer": "BCD", "explanation": "面对着装统一、形迹可疑的一群人，民警不应立即上前盘查以免发生危险（A不正确），而应当首先保证自身安全（C正确），向上级报告请求支援（B正确），保持关注维持现有状态继续观察（D正确），待支援到位后再行处置。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 923}, {"num": 925, "batch": "专业基础知识", "type": "multi", "stem": "公民李某在逛街时遭受抢劫，抢劫犯将其贵重的包抢走，李某立即报警，接警员的下列做法正确的是（）。", "options": [{"letter": "A", "text": "公民李某生活在广东，使用粤语沟通，接警员让李某必须说普通话沟通"}, {"letter": "B", "text": "接警员接听电话后收到女朋友的短信，对李某说：“你简单点说，我这边还有别的事呢”"}, {"letter": "C", "text": "公民李某逛街被抢地区属于东海区域，因此指派东海区公安局管辖"}, {"letter": "D", "text": "如李某逛街被抢区域在东海区和南海区交界线内，110应指定相应人员处置，明确管辖后再交给有管辖权的部门"}], "answer": "CD", "explanation": "根据110接处警规范，接警员应当使用当地方言或普通话与报警人沟通，不能强制要求报警人必须说普通话（A错误），应当认真接听不能催促（B错误）。C项正确，应当指派有管辖权的公安局处置；D项正确，管辖区域交界线内应指定处置并明确管辖后移交。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 924}, {"num": 926, "batch": "专业基础知识", "type": "multi", "stem": "关于公安派出所民警驾车巡逻时的要求，下列说法正确的有（）。", "options": [{"letter": "A", "text": "作小区域巡查时，必须下车徒步实施"}, {"letter": "B", "text": "下车巡查时，车上或者车侧应当留一人"}, {"letter": "C", "text": "应按照指定路线巡逻，不得无故超出巡逻区域"}, {"letter": "D", "text": "到达巡逻重点地区时，应当停留作小区域巡查"}], "answer": "ABCD", "explanation": "根据《公安派出所巡逻工作规范》，派出所驾车巡逻时，作小区域巡查必须下车徒步实施（A正确），下车巡查时车上或车侧应留一人（B正确），应按照指定路线巡逻不得无故超出区域（C正确），到达重点地区应停留作小区域巡查（D正确）。四项均符合巡逻工作要求。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 925}, {"num": 927, "batch": "专业基础知识", "type": "multi", "stem": "某日中午，A派出所接110报警台指令称：在人民广场西北角，一名疑似精神病人持棍将路人打伤。接到指令民警小王、小陈前往处置。接到指令后，小王、小陈的下列做法妥当的有（）。", "options": [{"letter": "A", "text": "检查并确认人民警察证、执法记录仪携带情况"}, {"letter": "B", "text": "联系报警人，确认具体地点和目前情况"}, {"letter": "C", "text": "携带手铐、警棍、钢叉等警械"}, {"letter": "D", "text": "通知指挥中心增派警力到场处置"}], "answer": "ABC", "explanation": "处置疑似精神病人持棍伤人的警情，应当检查确认警察证和执法记录仪携带情况（A正确），联系报警人确认具体地点和情况（B正确），携带手铐、警棍、钢叉等警械以应对可能的危险（C正确）。D项不选，应先到场处置后再根据需要请求增援，而非接到指令就通知增派。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 926}, {"num": 928, "batch": "专业基础知识", "type": "multi", "stem": "2022年11月，世界杯足球赛在卡塔尔举办，引发世界各国球迷的瞩目关注。在这股足球浪潮的引领下，金球体育传媒有限公司拟于2023年1月23日（农历大年初一）在A省B市C区工人体育场举办一场贺岁足球表演赛。D派出所民警小周、小马作为增援警力，参与本次赛事的外围安保工作。在外场巡逻期间，两人发现一中年男子手提小包行为鬼祟，不断与球迷装扮的群众进行搭话。针对这一情况，两人遂上前对该男子开展盘查。下列做法中，妥当的有（）。", "options": [{"letter": "A", "text": "由小周一人进行主要提问，小马负责戒备"}, {"letter": "B", "text": "让该男子面朝墙壁接受检查"}, {"letter": "C", "text": "将男子用手铐进行控制后再进行人身检查"}, {"letter": "D", "text": "责令男子自己将包内物品按从上至下顺序取出放置在指定区域"}], "answer": "AB", "explanation": "大型活动安保盘查工作中，应由一人主要提问另一人负责戒备（A正确），让被盘查人面朝墙壁接受检查以确保安全（B正确）。C项不妥，应先进行人身检查确认安全后再决定是否使用手铐控制；D项不妥，应由民警检查包内物品而非责令嫌疑人自行取出。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 927}, {"num": 929, "batch": "专业基础知识", "type": "multi", "stem": "2022年12月初，李某婷涉嫌寻衅滋事罪被立案侦查，期间公安机关依法对其进行了取保候审。12月18日，李某婷突然出现在中山路城市绿地南侧，将自己的裤子全部脱光，并对着过往的行人大吼大叫，导致大量群众围观，持续近30分钟。接到群众报警后，巡逻民警小孙、小李立即赶到事发地点。两人的下列做法中，欠妥的有（）。", "options": [{"letter": "A", "text": "使用随车携带的救火棉毯将李某婷的下体予以遮掩"}, {"letter": "B", "text": "为保护李某婷的个人隐私将执法记录仪暂时予以关闭"}, {"letter": "C", "text": "以李某婷违反取保候审期间相关规定为由对其予以先行拘留"}, {"letter": "D", "text": "联系李某婷的家属到场进行劝说并将其领回家进行照看"}], "answer": "BCD", "explanation": "处置李某在公共场所裸露身体的警情，使用救火棉毯遮掩虽出于好意但方式欠妥（A欠妥），关闭执法记录仪违反执法全过程记录要求（B欠妥），以违反取保候审规定为由先行拘留缺乏法律依据（C欠妥），联系家属领回对于正在实施违法行为的情形不够妥当（D欠妥）。正确做法应是依法制止违法行为并固定证据。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 928}, {"num": 930, "batch": "专业基础知识", "type": "multi", "stem": "某日，两名民警在对一名可疑人员的随身背包进行检查的过程中，操作正确的是（）。", "options": [{"letter": "A", "text": "责令嫌疑人将物品放下并后退至安全距离"}, {"letter": "B", "text": "为加快检查速度，两名民警同时上前进行检查"}, {"letter": "C", "text": "将包中物品自上而下进行拿取"}, {"letter": "D", "text": "对发现的违禁物品可依法进行扣押或收缴"}], "answer": "ACD", "explanation": "检查可疑背包时，应责令嫌疑人将物品放下并后退至安全距离（A正确），两名民警不应同时上前检查以免都暴露于危险中（B错误），应将包中物品自上而下依次拿取检查（C正确），发现违禁品可依法扣押或收缴（D正确）。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 929}, {"num": 931, "batch": "专业基础知识", "type": "multi", "stem": "某市东江街道派出所接到医院报警，称有患者家属组织大批亲属朋友到医院闹事。派出所两名值班民警立即赶到现场，发现有30余人在医院住院部1号楼扯横幅、摆花圈、设灵堂、烧纸，导致医院120车辆、急诊医务人员无法进出，严重影响了正常医疗秩序。因烧纸还导致整个楼道烟雾弥漫。针对上述情况，两名现场民警处置正确的是（）。", "options": [{"letter": "A", "text": "因警力不够，无法制止现场发生的违法行为，应撤回派出所寻求增援"}, {"letter": "B", "text": "直接拆除闹事者设置的横幅、花圈、灵堂等，恢复院区的交通秩序"}, {"letter": "C", "text": "疏散围观人员，指令医院利用视频监控设备记录现场情况"}, {"letter": "D", "text": "劝说患者家属与医院的代表进行对话沟通，要求闹事者停止烧纸行为、驱散楼栋烟雾"}], "answer": "CD", "explanation": "面对大量人员闹事但警力不足的情况，不应撤回派出所（A错误），也不应直接拆除横幅花圈以免激化矛盾（B错误）。正确做法是疏散围观人员并利用视频监控记录现场（C正确），劝说家属与医院代表沟通并要求停止烧纸驱散烟雾（D正确），同时应及时请求增援。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 930}, {"num": 932, "batch": "专业基础知识", "type": "multi", "stem": "10月2日晚甲省乙市洪峰派出所接到报警称，在新华大街某商场门口，一名男性乘客拒绝支付搭车费用，引发纠纷。乘客表示出租车司机故意绕路“宰客”，而司机表示这名乘客上车后多次改变目的地，直到来到该商场才要求下车。洪峰派出所民警接到报警后迅速赶往现场，发现出租车司机和乘客互相辱骂推搡、情绪极其激动，为了制止当前纠纷民警做法不正确的是（）。", "options": [{"letter": "A", "text": "使用手铐制止"}, {"letter": "B", "text": "口头警告制止"}, {"letter": "C", "text": "武器制止"}, {"letter": "D", "text": "徒手制止"}], "answer": "AC", "explanation": "对于互相辱骂推搡的纠纷双方，可以使用口头警告制止（B正确）和徒手制止（D正确）。A项不恰当，使用手铐属于使用约束性警械，对于一般纠纷推搡不宜直接使用手铐；C项不恰当，武器制止适用于严重暴力犯罪，本案情形远未达到使用武器的条件。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 931}, {"num": 933, "batch": "专业基础知识", "type": "multi", "stem": "巡逻民警小陈接情指中心指令，刚出现在某商场的一女子与涉毒人员张X高度相似，立即上前稽查，小陈与同事迅速赶赴现场，在商场门口发现一女子与指令核查对象的外貌特征较吻合，对此，民警适宜采取的做法有（）。", "options": [{"letter": "A", "text": "在民警视线范围内继续观察"}, {"letter": "B", "text": "拦截该女子并将其带回派出所继续盘问"}, {"letter": "C", "text": "出示人民警察证后查验该女子身份证"}, {"letter": "D", "text": "立即控制该女子并开展人身检查"}], "answer": "AC", "explanation": "发现与涉毒人员高度相似的女子，民警应在视线范围内继续观察确认（A正确），出示人民警察证后查验身份证（C正确）。B项不妥，仅凭外貌相似不能直接拦截带回；D项不妥，不能立即控制和人身检查，应先核实身份。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 932}, {"num": 934, "batch": "专业基础知识", "type": "multi", "stem": "民警开展夜间巡逻工作的过程中发现一男子神情紧张且衣着尺码与自身不符，便上前对其进行盘查工作。在询问中其自称为王刚，是附近某所大学的在校学生，但是身份证件因放在寝室中未曾携带，民警可以要求其出示以下哪些证件以证明身份（）。", "options": [{"letter": "A", "text": "居住证"}, {"letter": "B", "text": "护照"}, {"letter": "C", "text": "校园卡"}, {"letter": "D", "text": "驾驶证"}], "answer": "ABD", "explanation": "根据盘查工作规范，民警可以要求被盘查人出示有效身份证件证明身份。居住证（A）、护照（B）、驾驶证（D）均属于法定有效身份证件。校园卡（C）不属于法定身份证件，不能用于证明身份。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 933}, {"num": 935, "batch": "专业基础知识", "type": "multi", "stem": "甲市A县蓝山大桥在施工过程中，村民因炮损补偿纠纷与施工方发生矛盾，村民周某、陈某等人到兰山大桥项目部找经理温某讨要说法，温某见状召集工人与村民对峙，并唆使工人对村民进行殴打，双方发生激烈的械斗。居住在项目部周围的群众见状拨打110报警。A县公安局110报警服务台接到群众报警时，第一时间应当问明的情况有（）。", "options": [{"letter": "A", "text": "案件的发生地点"}, {"letter": "B", "text": "在场人员的数量"}, {"letter": "C", "text": "有无人员受伤"}, {"letter": "D", "text": "工程的施工情况"}], "answer": "ABC", "explanation": "根据110接处警工作规范，接到群众报警时，接警员应首先问明案事件发生地点（A）、在场人员数量（B）、有无人员受伤（C）等关键信息，以便快速判断警情性质和调派适当警力。工程施工情况（D）不是首要问明的情况。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 934}, {"num": 936, "batch": "专业基础知识", "type": "multi", "stem": "张某长期酗酒，醉酒后时常对其妻孙某及其女儿张某某进行打骂。某日，张某醉酒后再次辱骂其女儿，并打了其妻孙某两记耳光，其女儿害怕偷偷拨打了110报警。公安机关接到张某某报警后，应当（）。", "options": [{"letter": "A", "text": "及时出警"}, {"letter": "B", "text": "制止张某家暴行为"}, {"letter": "C", "text": "协助孙某就医、鉴定伤情"}, {"letter": "D", "text": "作出人身安全保护令"}], "answer": "ABC", "explanation": "根据《反家庭暴力法》第15条，公安机关接到家暴报警后应当及时出警（A正确），制止家庭暴力行为（B正确），协助受害人就医和鉴定伤情（C正确）。D项错误，人身安全保护令由人民法院作出，公安机关无权作出。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 935}, {"num": 937, "batch": "专业基础知识", "type": "multi", "stem": "根据《刑法》的规定，下列说法错误的有（）。", "options": [{"letter": "A", "text": "许某虚构开设养老院的事实，非法集资人民币1亿元，款项大部分被挥霍一空，许某构成非法吸收公众存款罪"}, {"letter": "B", "text": "李某使用虚假的证明文件，骗取数额较大的银行贷款后携款潜逃，李某构成贷款诈骗罪"}, {"letter": "C", "text": "保险公司工作人员吴某编造保险事故，骗取朋友的财产，吴某构成保险诈骗罪"}, {"letter": "D", "text": "张某在商场购物时使用已经作废的信用卡结账，数额较大，张某构成诈骗罪"}], "answer": "ACD", "explanation": "A项错误，许某非法集资1亿元大部分挥霍，具有非法占有目的，应构成集资诈骗罪而非非法吸收公众存款罪。B项正确，李某使用虚假证明文件骗贷后携款潜逃，具有非法占有目的，构成贷款诈骗罪。C项错误，保险公司工作人员不属于保险诈骗罪的主体（投保人、被保险人或受益人），应构成职务侵占罪或贪污罪。D项错误，使用作废信用卡构成信用卡诈骗罪而非诈骗罪。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 936}, {"num": 938, "batch": "专业基础知识", "type": "multi", "stem": "根据《中华人民共和国刑法》及相关司法解释，关于抢劫犯罪，下列说法正确的有（）。", "options": [{"letter": "A", "text": "犯侵占罪，为窝藏赃物而当场使用暴力的，以抢劫罪定罪处罚"}, {"letter": "B", "text": "携带凶器抢夺的，依照抢劫罪的规定定罪处罚"}, {"letter": "C", "text": "在小型出租车上抢劫的，不属于在公共交通工具上抢劫"}, {"letter": "D", "text": "实施抢劫后，为灭口而故意杀人的，以抢劫罪和故意杀人罪数罪并罚"}], "answer": "BCD", "explanation": "A项错误，犯侵占罪为窝藏赃物当场使用暴力不构成转化型抢劫，转化型抢劫的前提是犯盗窃、诈骗、抢夺罪（《刑法》第269条）。B项正确，根据《刑法》第267条第2款，携带凶器抢夺的依照抢劫罪定罪处罚。C项正确，小型出租车不属于公共交通工具。D项正确，实施抢劫后为灭口故意杀人的，以抢劫罪和故意杀人罪数罪并罚。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 937}, {"num": 939, "batch": "专业基础知识", "type": "multi", "stem": "下列行为应当以盗窃罪立案的有（）。", "options": [{"letter": "A", "text": "甲在火车站扒窃他人钱包，但钱包里只有几十元"}, {"letter": "B", "text": "乙潜入张某家见张某在睡觉，顺手拿了桌上的手表就走了"}, {"letter": "C", "text": "丙带了一把防身匕首进入工地盗窃时被发现"}, {"letter": "D", "text": "丁在地铁盗窃他人手机被人发现，其供称一年来还偷过3次手机"}], "answer": "ABCD", "explanation": "A项正确，扒窃不论金额多少均构成盗窃罪。B项正确，入户盗窃不论金额均构成盗窃罪。C项正确，携带凶器盗窃不论金额均构成盗窃罪。D项正确，多次盗窃（一年内盗窃三次以上）构成盗窃罪。因此四项均应以盗窃罪立案。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 938}, {"num": 940, "batch": "专业基础知识", "type": "multi", "stem": "下列不属于自首的是（）。", "options": [{"letter": "A", "text": "甲杀害乙后，主动到派出所说明犯罪经过"}, {"letter": "B", "text": "甲杀害乙后，向其好友说明犯罪经过，在好友带领下到公安机关自首"}, {"letter": "C", "text": "在监狱服刑的甲主动向狱警说明公安机关并不掌握的其好友的犯罪事实"}, {"letter": "D", "text": "甲殴打乙至其轻伤，畏罪潜逃后被当地派出所抓获，甲据实供述犯罪事实"}], "answer": "CD", "explanation": "A项构成自首，主动投案并如实供述。B项构成自首，经亲友规劝带领投案也视为自动投案。C项不构成自首，在监狱服刑的犯人主动交代公安机关不掌握的他人犯罪事实属于立功而非自首。D项不构成自首，被抓获后如实供述属于坦白，不是自动投案。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 939}, {"num": 941, "batch": "专业基础知识", "type": "multi", "stem": "下列情况，构成危险驾驶罪的有（）。", "options": [{"letter": "A", "text": "甲驾车与乙车在城市道路上追逐竞驶，造成交通混乱"}, {"letter": "B", "text": "丙喝酒后驾驶车辆在道路上行驶，后证实丙达到醉酒标准"}, {"letter": "C", "text": "丁驾驶校车，严重超过额定乘员载客，但未发生交通事故"}, {"letter": "D", "text": "戊吸食毒品后驾车在城市道路上行驶，但未发生交通事故"}], "answer": "ABC", "explanation": "根据《刑法》第133条之一，危险驾驶罪包括以下情形：追逐竞驶情节恶劣的（A正确）、醉酒驾驶的（B正确）、从事校车业务严重超载的（C正确）。D项毒驾尚未被纳入危险驾驶罪的法定情形，刑法未将吸毒后驾车规定为危险驾驶罪。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 940}, {"num": 942, "batch": "专业基础知识", "type": "multi", "stem": "赵某（男）在酒吧遇到了钱某（女），两个人见面之后不久，去酒店开了房间。赵某喝了钱某递给的饮料就昏睡不醒。次日中午，赵某醒过来见钱某已走，同时发现随身的贵重物品不见了，于是报警。如果赵某在与钱某喝酒的过程中，由于自己贪杯大量饮酒而昏睡，钱某乘机拿走赵某手机、钱包等价值一万元的财物。关于钱某的行为，下列选项错误的有（）。", "options": [{"letter": "A", "text": "钱某构成盗窃罪"}, {"letter": "B", "text": "钱某构成诈骗罪"}, {"letter": "C", "text": "钱某构成侵占罪"}, {"letter": "D", "text": "钱某不构成犯罪"}], "answer": "BCD", "explanation": "赵某因自身贪杯大量饮酒而昏睡，并非钱某灌醉，钱某乘机拿走财物属于秘密窃取他人财物，构成盗窃罪（A正确）。因此B项诈骗罪、C项侵占罪、D项不构成犯罪的说法均错误。本题问的是错误的选项，故选BCD。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 941}, {"num": 943, "batch": "专业基础知识", "type": "multi", "stem": "李某是一海鲜批发店的员工，未取得机动车驾驶证，但为了方便给客户送货，经常抱着侥幸心理短途驾驶机动车，老板谢某对此知情，但是为了工作方便未予以制止。2025年7月20日，李某在送货途中发生交通事故，致一名路人死亡，对事故的发生负全部责任，案发后，李某在现场报警并接受交警部门的调查处理，对自己无证驾驶致人死亡的行为亦供认不讳。根据《刑法》关于共同犯罪的规定，下列说法错误的有（）。", "options": [{"letter": "A", "text": "李某与谢某不是共同犯罪"}, {"letter": "B", "text": "李某与谢某是共同犯罪"}, {"letter": "C", "text": "李某是主犯，谢某是从犯"}, {"letter": "D", "text": "谢某是主犯，李某是从犯"}], "answer": "BCD", "explanation": "根据《最高人民法院关于审理交通肇事刑事案件具体应用法律若干问题的解释》第7条，单位主管人员明知他人无驾驶执照驾驶机动车，指使或强令他人驾驶的，以交通肇事罪的共犯论处。本案中谢某知情不制止，与李某构成交通肇事罪共犯（A错误，B正确）。李某是直接驾驶人为主犯，谢某为从犯（C正确，D错误）。本题问错误的说法，故选BCD。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 942}, {"num": 944, "batch": "专业基础知识", "type": "multi", "stem": "余某购买了50克冰毒，2025年8月1日，林某到余某家做客，余某告诉林某这种冰块很提神，且能强身健体，并免费提供给林某吸食。余某的行为构成（）。", "options": [{"letter": "A", "text": "引诱、教唆、欺骗他人吸毒罪"}, {"letter": "B", "text": "容留他人吸毒罪"}, {"letter": "C", "text": "非法持有毒品罪"}, {"letter": "D", "text": "贩卖毒品罪"}], "answer": "ABC", "explanation": "余某告诉林某冰毒能提神强身并提供吸食，构成引诱、教唆、欺骗他人吸毒罪（A正确）。在自己家中提供场所供他人吸食，构成容留他人吸毒罪（B正确）。购买50克冰毒，根据《刑法》第348条，非法持有冰毒50克以上构成非法持有毒品罪（C正确）。余某免费提供而非贩卖，不构成贩卖毒品罪（D不选）。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 943}, {"num": 945, "batch": "专业基础知识", "type": "multi", "stem": "下列关于剥夺政治权利的说法正确的是（）。", "options": [{"letter": "A", "text": "对于危害国家安全的犯罪分子应当附加剥夺政治权利"}, {"letter": "B", "text": "对于故意杀人、强奸、放火、爆炸、投毒、抢劫等严重破坏社会秩序的犯罪分子，应当附加剥夺政治权利"}, {"letter": "C", "text": "对于被判处死刑、无期徒刑的犯罪分子，可以剥夺政治权利终身"}, {"letter": "D", "text": "在死刑缓期执行减为有期徒刑或者无期徒刑减为有期徒刑的时候，应当把附加剥夺政治权利的期限改为三年以上十年以下"}], "answer": "AD", "explanation": "根据《刑法》第56条，对于危害国家安全的犯罪分子应当附加剥夺政治权利（A正确）。对于故意杀人等严重破坏社会秩序的犯罪分子，可以附加剥夺政治权利而非应当（B错误）。根据《刑法》第57条，被判处死刑、无期徒刑的应当剥夺政治权利终身而非可以（C错误）。根据《刑法》第57条第2款，死缓减为有期或无期减为有期时，剥夺政治权利期限改为三年以上十年以下（D正确）。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 944}, {"num": 946, "batch": "专业基础知识", "type": "multi", "stem": "定居美国的中国公民李某短期回国申请换发普通护照的，应当向其暂住地县级以上地方人民政府公安机关出入境管理机构提出，并提交（）", "options": [{"letter": "A", "text": "原普通护照及复印件"}, {"letter": "B", "text": "定居国外的证明及复印件"}, {"letter": "C", "text": "暂住地公安机关出具的暂住证明及复印件"}, {"letter": "D", "text": "身份证及复印件"}], "answer": "ABC", "explanation": "根据《护照法》和公安部相关规定，定居国外的中国公民短期回国申请换发普通护照，应当提交原普通护照及复印件（A正确）、定居国外的证明及复印件（B正确）、暂住地公安机关出具的暂住证明及复印件（C正确）。身份证（D）不是定居国外的中国公民换发护照必须提交的材料。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 945}, {"num": 947, "batch": "专业基础知识", "type": "multi", "stem": "杜某高价倒卖演出门票3张，被执勤民警当场查获，同时从杜某身上查获5张尚未卖出的演出门票。杜某对违法行为供认不讳。公安机关办理此案的下列做法正确的是（）", "options": [{"letter": "A", "text": "口头传唤杜某至公安派出所进行询问"}, {"letter": "B", "text": "对杜某身上尚未卖出的演出门票予以收缴"}, {"letter": "C", "text": "对杜某可以当场作出行政处罚决定"}, {"letter": "D", "text": "对杜某的违法所得予以追缴"}], "answer": "ABD", "explanation": "根据《治安管理处罚法》第82条，对当场发现的违法嫌疑人可以口头传唤（A正确）。尚未卖出的演出门票属于违法工具应予以收缴（B正确）。杜某违法行为事实清楚、证据确凿且本人供认，可以当场作出处罚决定（C不选，但C表述正确，注意本题选ABD）。违法所得应予以追缴（D正确）。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 946}, {"num": 948, "batch": "专业基础知识", "type": "multi", "stem": "对被决定行政拘留的人，由作出决定的公安机关送达拘留所执行。对抗拒执行的，可以使用（）", "options": [{"letter": "A", "text": "手铐"}, {"letter": "B", "text": "麻醉枪"}, {"letter": "C", "text": "警绳"}, {"letter": "D", "text": "警棍"}], "answer": "AC", "explanation": "根据《治安管理处罚法》和《公安机关办理行政案件程序规定》，对抗拒执行行政拘留的，可以使用约束性警械。手铐（A）和警绳（C）属于约束性警械，可以使用。麻醉枪（B）和警棍（D）不属于约束性警械，不适用于抗拒执行行政拘留的情形。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 947}, {"num": 949, "batch": "专业基础知识", "type": "multi", "stem": "对不构成违反治安管理行为的民间纠纷，应当告知当事人向（）申请处理。", "options": [{"letter": "A", "text": "人民法院"}, {"letter": "B", "text": "人民检察院"}, {"letter": "C", "text": "人民调解组织"}, {"letter": "D", "text": "仲裁委员会"}], "answer": "AC", "explanation": "根据《治安管理处罚法》第9条和《公安机关办理行政案件程序规定》，对不构成违反治安管理行为的民间纠纷，应当告知当事人向人民法院（A正确）或人民调解组织（C正确）申请处理。人民检察院（B）和仲裁委员会（D）不是处理民间纠纷的法定告知对象。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 948}, {"num": 950, "batch": "专业基础知识", "type": "multi", "stem": "对公安机关收缴和追缴的财物，作以下哪些处理是正确的？（）", "options": [{"letter": "A", "text": "属于被侵害人或者善意第三人的合法财物，应当及时返还"}, {"letter": "B", "text": "没有被侵害人的，登记造册，按照规定上缴国库或者依法变卖或者拍卖后，将所得款项上缴国库"}, {"letter": "C", "text": "违禁品、没有价值的物品，或者价值轻微无法变卖、拍卖的物品，统一登记造册后予以销毁"}, {"letter": "D", "text": "对无法变卖或者拍卖的危险物品，由县级以上公安机关办案部门组织销毁或者交有关厂家回收"}], "answer": "ABC", "explanation": "根据《公安机关办理行政案件程序规定》第196条，属于被侵害人或善意第三人的合法财物应及时返还（A正确），没有被侵害人的登记造册上缴国库（B正确），违禁品和没有价值的物品予以销毁（C正确）。D项错误，无法变卖或拍卖的危险物品应由县级以上公安机关统一组织销毁，而非由办案部门组织。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 949}, {"num": 951, "batch": "专业基础知识", "type": "multi", "stem": "对行政案件进行审核、审批时，除了应当审查违法嫌疑人的基本情况和案件事实是否清楚，证据是否确实充分外，还应当审查下列（）内容。", "options": [{"letter": "A", "text": "案件定性是否准确"}, {"letter": "B", "text": "适用法律、法规和规章是否正确"}, {"letter": "C", "text": "办案程序是否合法"}, {"letter": "D", "text": "拟作出的处理决定是否适当"}], "answer": "ABCD", "explanation": "根据《公安机关办理行政案件程序规定》，对行政案件进行审核审批时，除审查嫌疑人基本情况和案件事实证据外，还应当审查案件定性是否准确（A）、适用法律法规规章是否正确（B）、办案程序是否合法（C）、拟作出的处理决定是否适当（D）。四项均为审核审批的必审内容。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 950}, {"num": 952, "batch": "专业基础知识", "type": "multi", "stem": "对行政许可申请人隐瞒情况或提供虚假情况申请行政许可的，可能作出的处理有（）", "options": [{"letter": "A", "text": "不予受理"}, {"letter": "B", "text": "不予许可"}, {"letter": "C", "text": "撤销许可"}, {"letter": "D", "text": "给予警告"}], "answer": "ABCD", "explanation": "根据《行政许可法》第78条和第69条，申请人隐瞒情况或提供虚假材料申请行政许可的，行政机关可以不予受理（A正确）、不予许可（B正确）；已取得许可的可以撤销许可（C正确）；并可给予警告（D正确）。四种处理方式均有可能。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 951}, {"num": 953, "batch": "专业基础知识", "type": "multi", "stem": "对精神病的鉴定，由（）进行。", "options": [{"letter": "A", "text": "县级以上医院"}, {"letter": "B", "text": "省级人民政府指定的医院"}, {"letter": "C", "text": "公安机关的安康医院"}, {"letter": "D", "text": "有鉴定资格的精神病医院"}], "answer": "BCD", "explanation": "根据《公安机关办理行政案件程序规定》和相关法律规定，对精神病的鉴定由省级人民政府指定的医院（B正确）、公安机关的安康医院（C正确）、有鉴定资格的精神病医院（D正确）进行。县级以上医院（A）不具有法定的精神病鉴定资质。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 952}, {"num": 954, "batch": "专业基础知识", "type": "multi", "stem": "对适用当场处罚的案件，有（）的，可以当场收缴。", "options": [{"letter": "A", "text": "毒品"}, {"letter": "B", "text": "赌具和赌资"}, {"letter": "C", "text": "淫秽物品"}, {"letter": "D", "text": "吸食、注射毒品的器具"}], "answer": "AC", "explanation": "根据《公安机关办理行政案件程序规定》，对适用当场处罚的案件，有淫秽物品（C正确）和毒品（A正确）的，可以当场收缴。赌具和赌资（B）以及吸食注射毒品的器具（D）不属于当场收缴的范围，应依法另行处理。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 953}, {"num": 955, "batch": "专业基础知识", "type": "multi", "stem": "对违法嫌疑人强制传唤时，可以依法使用（）等警械。", "options": [{"letter": "A", "text": "手铐"}, {"letter": "B", "text": "约束带"}, {"letter": "C", "text": "警绳"}, {"letter": "D", "text": "警棍"}], "answer": "ABC", "explanation": "根据《治安管理处罚法》第82条和《公安机关办理行政案件程序规定》，对违法嫌疑人强制传唤时，可以依法使用手铐（A正确）、约束带（B正确）、警绳（C正确）等约束性警械。警棍（D）属于驱逐性、制服性警械，不适用于强制传唤。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 954}, {"num": 956, "batch": "专业基础知识", "type": "multi", "stem": "对违反治安管理行为人处50元以下罚款和对违反交通管理的（）处罚款，被处罚人没有异议的，公安机关及其办案人民警察可以当场收缴罚款。", "options": [{"letter": "A", "text": "行人"}, {"letter": "B", "text": "乘车人"}, {"letter": "C", "text": "非机动车驾驶人"}, {"letter": "D", "text": "机动车驾驶人"}], "answer": "ABC", "explanation": "根据《治安管理处罚法》第104条，对违反治安管理行为人处50元以下罚款和对违反交通管理的行人（A正确）、乘车人（B正确）和非机动车驾驶人（C正确）处罚款，被处罚人没有异议的，可以当场收缴。机动车驾驶人（D）不包括在内。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 955}, {"num": 957, "batch": "专业基础知识", "type": "multi", "stem": "对下列可以当场收缴罚款的情形，办案人民警察应当要求被处罚人签名确认的是（）", "options": [{"letter": "A", "text": "对违反治安管理行为人处50元以下罚款和对违反交通管理的行人、乘车人和非机动车驾驶人处罚款，被处罚人没有异议的"}, {"letter": "B", "text": "对违反治安管理、交通管理以外的违法行为人当场处20元以下罚款的"}, {"letter": "C", "text": "在边远、水上、交通不便地区以及旅客列车上，被处罚人向指定银行缴纳罚款确有困难，经被处罚人提出的"}, {"letter": "D", "text": "被处罚人在当地没有固定住所，不当场收缴事后难以执行的"}], "answer": "AC", "explanation": "根据《治安管理处罚法》第104条和《公安机关办理行政案件程序规定》，需要被处罚人签名确认的当场收缴罚款情形包括：处50元以下罚款和对交通管理行人等处罚款被处罚人没有异议的（A正确），以及在边远水上交通不便地区缴纳确有困难经被处罚人提出的（C正确）。B项和D项虽然也可以当场收缴，但法条规定的情形以AC为准。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 956}, {"num": 958, "batch": "专业基础知识", "type": "multi", "stem": "对下列物品，公安派出所可以决定收缴的是（）", "options": [{"letter": "A", "text": "淫秽物品"}, {"letter": "B", "text": "被侵害人的iphone4手机"}, {"letter": "C", "text": "吸食、注射毒品的器具"}, {"letter": "D", "text": "当事人对价值无异议的非法财物"}], "answer": "AC", "explanation": "根据《公安机关办理行政案件程序规定》，公安派出所可以决定收缴的物品包括淫秽物品（A正确）和吸食注射毒品的器具（C正确）。被侵害人的手机（B）属于合法财产应当返还而非收缴，当事人对价值无异议的非法财物（D）需由县级以上公安机关决定收缴。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 957}, {"num": 959, "batch": "专业基础知识", "type": "multi", "stem": "对下列物品不得扣押的是（）", "options": [{"letter": "A", "text": "被侵害人合法占有的财产"}, {"letter": "B", "text": "善意第三人合法占有的财产"}, {"letter": "C", "text": "与案件无关的物品"}, {"letter": "D", "text": "容易腐烂变质及其他不易保管的物品"}], "answer": "ABC", "explanation": "根据《治安管理处罚法》第89条和《公安机关办理行政案件程序规定》，不得扣押的物品包括：被侵害人合法占有的财产（A正确）、善意第三人合法占有的财产（B正确）、与案件无关的物品（C正确）。容易腐烂变质的物品可以依法先行变卖或拍卖，但并非不得扣押。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 958}, {"num": 960, "batch": "专业基础知识", "type": "multi", "stem": "对需进行伤情鉴定的案件，（），公安机关应当将有关情况记录在案，并可以根据已认定的事实作出处理决定。", "options": [{"letter": "A", "text": "被侵害人拒绝提供诊断证明的"}, {"letter": "B", "text": "被侵害人拒绝进行伤情鉴定的"}, {"letter": "C", "text": "被侵害人无法提供诊断证明的"}, {"letter": "D", "text": "经公安机关通知，被侵害人无正当理由逾期不作伤情鉴定的"}], "answer": "ABD", "explanation": "根据《公安机关办理行政案件程序规定》第98条，被侵害人拒绝提供诊断证明的（A正确）、拒绝进行伤情鉴定的（B正确）、经通知无正当理由逾期不作伤情鉴定的（D正确），公安机关应当将情况记录在案，可根据已认定的事实作出处理决定。C项无法提供诊断证明不属于上述法定情形。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 959}, {"num": 961, "batch": "专业基础知识", "type": "multi", "stem": "对于公安机关不得因违法嫌疑人提出听证要求而加重处罚的理解正确的有（）", "options": [{"letter": "A", "text": "这是行政处罚法中行政机关不得因当事人申辩而加重处罚这一原则在听证中的体现"}, {"letter": "B", "text": "这里的加重不等同于刑法意义上的加重处罚"}, {"letter": "C", "text": "根据法律的精神，我们虽不能加重处罚，但可以通过减轻或者从轻处罚来规避听证"}, {"letter": "D", "text": "听证后，发现新的违法事实、证据的，对新的违法行为作出新的处罚即使比原处罚重，也不属于加重处罚"}], "answer": "ABD", "explanation": "不得因违法嫌疑人提出听证要求而加重处罚，这是行政处罚法中不得因申辩加重处罚原则在听证程序中的体现（A正确），这里的加重不等同于刑法意义上的加重处罚（B正确），发现新事实新证据作出新处罚即使更重也不属于加重处罚（D正确）。C项错误，不能通过减轻或从轻处罚来规避听证程序。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 960}, {"num": 962, "batch": "专业基础知识", "type": "multi", "stem": "对于下列案件的定性处理，说法正确的是（）", "options": [{"letter": "A", "text": "甲伙同他人强行把中学生黄某（男，13岁）拦截至树林里，对黄某实施鸡奸，甲构成强制猥亵罪"}, {"letter": "B", "text": "乙以散布陈某（男，15岁）的裸照为由，逼迫陈某为其口淫，乙构成强制猥亵罪"}, {"letter": "C", "text": "丙以辅导学习为由，在办公室抚摸刘某（女，12岁）的阴部和乳房，刘某害怕，不敢拒绝也不敢声张，丙构成猥亵儿童罪"}, {"letter": "D", "text": "丁以金钱为诱饵，对中学生陈某（男，16岁）实施鸡奸，丁构成强制猥亵罪"}], "answer": "BC", "explanation": "A项错误，对13岁黄某实施鸡奸，因被害人不满14周岁，应构成猥亵儿童罪而非强制猥亵罪。B项正确，以散布裸照威胁15岁陈某口淫，构成强制猥亵罪。C项正确，对12岁刘某实施猥亵行为，构成猥亵儿童罪。D项错误，以金钱为诱饵对16岁陈某实施鸡奸，构成强制猥亵罪，但本题要求选正确的，故选BC。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 961}, {"num": 963, "batch": "专业基础知识", "type": "multi", "stem": "对于下列案件的定性处理错误的是（）", "options": [{"letter": "A", "text": "陈某在甲的店里挑选商品，对一个瓷碗还价后不想买了，甲及员工上前推打陈某，陈某无奈，出2000元买下一个赝品瓷碗（价值仅20元），甲构成强迫交易罪"}, {"letter": "B", "text": "乙绑架刘某后，对刘某实施殴打，抢走其身上的金项链一条，对乙以绑架罪和抢劫罪数罪并罚"}, {"letter": "C", "text": "丙（17岁）在某中学附近拦截学生华某（15岁），打了华某几巴掌后，让华某交出身上的10元零钱，丙构成抢劫罪"}, {"letter": "D", "text": "丁数次向陈某讨回欠自己的1万元钱，在路上拦截陈某，用刀刺伤陈某（经鉴定为轻伤）后，抢走包里的5000元现金，丁构成抢劫罪"}], "answer": "ABCD", "explanation": "A项说法正确，甲的行为构成强迫交易罪，但本题问的是错误的说法。B项错误，乙绑架后抢走项链，属于在绑架过程中另起犯意抢劫，应以绑架罪和抢劫罪数罪并罚，说法本身正确但本题选错误的。C项错误，17岁丙拦截15岁学生打巴掌抢10元，根据司法解释可不以抢劫罪论处。D项错误，丁讨回合法债务缺乏非法占有目的，不构成抢劫罪，应构成故意伤害罪。本题问错误的说法，故选ABCD。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 962}, {"num": 964, "batch": "专业基础知识", "type": "multi", "stem": "对于下列案件定性处理正确的是（）", "options": [{"letter": "A", "text": "甲在大街上看见一妇女张某独自行走，尾随一段路后，拽走张某的挎包，张某追赶甲，甲回头把张某踹倒在地后逃离，经鉴定，张某受轻微伤。甲构成抢夺罪"}, {"letter": "B", "text": "乙因抢夺一路人被当场抓获，在他身上搜出一把匕首。乙构成抢劫罪"}, {"letter": "C", "text": "丙伙同他人骑一辆摩托车在巷子里把妇女刘某逼挤到墙角后，把挎包抢走。丙构成抢夺罪"}, {"letter": "D", "text": "丁看见前路上一个小孩（4岁）独自玩耍，上前猛力拽下其脖子上的银项链，孩子被吓得哇哇大哭。丁构成抢劫罪"}], "answer": "BD", "explanation": "A项错误，甲抢夺后为抗拒抓捕当场使用暴力（踹倒张某），转化为抢劫罪而非抢夺罪。B项正确，乙携带凶器（匕首）抢夺，根据《刑法》第267条第2款，以抢劫罪定罪处罚。C项错误，丙骑车逼挤被害人属于胁迫方法抢劫，构成抢劫罪而非抢夺罪。D项正确，丁对4岁幼儿猛力拽下项链，属于对人身使用暴力，构成抢劫罪。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 963}, {"num": 965, "batch": "专业基础知识", "type": "multi", "stem": "对于因民间纠纷引起的（）等情节较轻的治安案件，公安机关可以调解处理。", "options": [{"letter": "A", "text": "故意伤害"}, {"letter": "B", "text": "诬告陷害"}, {"letter": "C", "text": "盗窃"}, {"letter": "D", "text": "阻碍执行职务"}], "answer": "AB", "explanation": "根据《治安管理处罚法》第9条和《公安机关办理行政案件程序规定》，因民间纠纷引起的故意伤害（A正确）、诬告陷害（B正确）等情节较轻的治安案件，公安机关可以调解处理。盗窃（C）和阻碍执行职务（D）不属于可以调解处理的治安案件范围。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 964}, {"num": 966, "batch": "专业基础知识", "type": "multi", "stem": "简易程序是为了及时有效处理治安违法行为而当场进行处罚的程序。下列关于公安民警实施简易程序排序正确的是（）。 ①告知违法行为人享有的陈述权和申辩权 ②听取违法行为人的陈述和申辩 ③告知拟作出行政处罚决定的事实、理由和依据 ④填写当场处罚决定书并交付被处罚人 ⑤表明身份 ⑥收集证据", "options": [{"letter": "A", "text": "⑤⑥③①②④"}, {"letter": "B", "text": "⑤⑥③①④②"}, {"letter": "C", "text": "⑥⑤③①④②"}, {"letter": "D", "text": "⑥⑤③①②④"}], "answer": "A", "explanation": "根据《公安机关办理行政案件程序规定》，简易程序（当场处罚）的正确顺序为：首先表明身份（⑤），然后收集证据（⑥），告知拟作出处罚的事实、理由和依据（③），告知享有的陈述权和申辩权（①），听取陈述和申辩（②），最后填写当场处罚决定书并交付（④）。因此正确顺序为⑤⑥③①②④，选A。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 965}, {"num": 967, "batch": "专业基础知识", "type": "multi", "stem": "甲醉酒驾车将行人乙撞死，将尸体运到X地掩埋。10天后，甲得知某单位要在X地施工，因担心乙的尸体被发现，便将乙的尸体从X地转移到Y地。在转移尸体时，甲无意间发现了乙的身份证和信用卡。此后，甲持乙的身份证和信用卡，从银行柜台将乙的信用卡中的5万元转入自己的信用卡，并以乙的身份证办理了入网手续并使用移动电话，造成电信资费损失8000元。甲的行为构成（）", "options": [{"letter": "A", "text": "交通肇事罪"}, {"letter": "B", "text": "盗窃罪"}, {"letter": "C", "text": "信用卡诈骗罪"}, {"letter": "D", "text": "诈骗罪"}], "answer": "ACD", "explanation": "甲醉酒驾车撞死人构成交通肇事罪（A正确）。甲转移尸体时拿走并使用乙的信用卡，根据《刑法》第196条第3款，盗窃信用卡并使用的以盗窃罪论处，但本案中甲是拾得他人信用卡后使用，构成信用卡诈骗罪（C正确）。甲用乙的身份证办理手机造成电信资费损失8000元，构成诈骗罪（D正确）。甲的行为不构成盗窃罪（B不选）。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 966}, {"num": 968, "batch": "专业基础知识", "type": "multi", "stem": "甲作为某会计师事务所的法定代表人、注册会计师，在为乙公司增资事宜进行审验的过程中，没有亲自前往也未指派会计师事务所工作人员到银行对乙公司股东增缴出资是否到位进行审验，就出具了内容虚假的验资报告，报告中表述结论为：乙公司原注册资本为90万元，股东申请增加注册资本9910万元，将注册资本变更为1亿元，由于资金不足，本次新增注册资本1910万元，该1910万元已缴纳到乙公司在中国银行某支行的账户内。之后，乙公司以此验资报告在工商部门办理了变更登记。经查，乙公司账号从开户至销户从未发生过1910万元的业务。下列说法错误的是（）", "options": [{"letter": "A", "text": "甲构成出具证明文件重大失实罪"}, {"letter": "B", "text": "会计师事务所构成出具证明文件重大失实罪"}, {"letter": "C", "text": "甲与会计师事务所是出具证明文件重大失实罪的共犯关系"}, {"letter": "D", "text": "甲构成提供虚假证明文件罪"}], "answer": "ABC", "explanation": "根据《刑法》第229条，甲作为注册会计师故意出具虚假验资报告，构成提供虚假证明文件罪（D正确），而非出具证明文件重大失实罪（该罪为过失犯罪）。会计师事务所作为单位可以构成本罪主体。A项错误，甲是故意而非过失；B项错误，事务所构成的是提供虚假证明文件罪而非重大失实罪；C项错误，甲是事务所的直接责任人员，不存在共犯关系。本题问错误的说法，故选ABC。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 967}, {"num": 969, "batch": "专业基础知识", "type": "multi", "stem": "贾某在闹市区开了一家酒店，并为酒店财产投了20万元保险，后因经营不善，决定放火烧毁酒店，以获取保险赔偿金。贾某放火后到保险公司理赔时被公安机关抓获归案。下列关于本案的说法正确的是（）", "options": [{"letter": "A", "text": "贾某的行为触犯放火罪和保险诈骗罪两个罪名"}, {"letter": "B", "text": "贾某的行为应按放火罪与保险诈骗罪（未遂）数罪并罚"}, {"letter": "C", "text": "贾某的行为只按放火罪定罪处罚"}, {"letter": "D", "text": "贾某的行为只按保险诈骗罪（未遂）定罪处罚"}], "answer": "AB", "explanation": "根据《刑法》第198条，贾某放火烧酒店骗取保险金，同时触犯放火罪和保险诈骗罪（A正确）。由于在理赔时被抓获，保险诈骗未能得逞，属于保险诈骗罪未遂，应以放火罪和保险诈骗罪（未遂）数罪并罚（B正确）。不能仅以一罪论处（CD错误）。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 968}, {"num": 970, "batch": "专业基础知识", "type": "multi", "stem": "检查公民住所必须持有县级以上公安机关开具的检查证。但是，有证据证明或者有群众报警公民住所内（），不立即检查可能对公共安全或者公民人身、财产安全造成重大危害的，人民警察经出示工作证件，可以立即检查。", "options": [{"letter": "A", "text": "正在发生危害公民人身安全的案（事）件"}, {"letter": "B", "text": "正在发生危害妨害社会管理的案（事）件"}, {"letter": "C", "text": "违法存放危险物质"}, {"letter": "D", "text": "正在发生危害公共安全的案（事）件"}], "answer": "ACD", "explanation": "根据《治安管理处罚法》第87条和《公安机关办理行政案件程序规定》，检查公民住所需持有检查证，但有证据证明或有群众报警住所内正在发生危害公民人身安全的案事件（A正确）、违法存放危险物质（C正确）、正在发生危害公共安全的案事件（D正确），经出示工作证件可以立即检查。妨害社会管理的案事件（B）不属于紧急检查的情形。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 969}, {"num": 971, "batch": "专业基础知识", "type": "multi", "stem": "鉴定具有下列哪些情形的，公安机关应当进行重新鉴定？（）", "options": [{"letter": "A", "text": "鉴定人应当回避而没有回避的"}, {"letter": "B", "text": "鉴定意见明显依据不足的"}, {"letter": "C", "text": "鉴定程序违法，但不影响鉴定意见的正确性"}, {"letter": "D", "text": "鉴定人不具备鉴定所需专门知识的"}], "answer": "ABD", "explanation": "根据《公安机关办理行政案件程序规定》第99条，鉴定人应当回避而没有回避的（A正确）、鉴定意见明显依据不足的（B正确）、鉴定人不具备所需专门知识的（D正确），公安机关应当进行重新鉴定。C项鉴定程序违法但不影响鉴定意见正确性的，不需要重新鉴定。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 970}, {"num": 972, "batch": "专业基础知识", "type": "multi", "stem": "江某（女）在医院门口出售伪造的医院出生证明时，被正在巡逻的公安民警抓获。民警将江某带回公安派出所进行询问，江某对出售伪造的医院出生证明的行为供认不讳，称此举是为给自己仅5个月大的儿子买奶粉。此外，江某还向公安机关提供了其邻居杨某生产伪劣产品的情况。经公安机关调查，江某出售伪造的医院出生证明3份，所述事实均属实，并根据江某提供的线索成功侦破了杨某生产伪劣产品案。下列说法正确的有（）", "options": [{"letter": "A", "text": "江某构成买卖伪造的证明文件的违反治安管理行为"}, {"letter": "B", "text": "江某为公安机关破获杨某生产伪劣产品一案提供重要线索，属于立功行为，依法应减轻或者不予处罚"}, {"letter": "C", "text": "江某有5个月大的婴儿需要哺乳，依法给予行政拘留处罚的，不执行行政拘留处罚"}, {"letter": "D", "text": "江某伪造的医院出生证明应当予以追缴"}], "answer": "ABC", "explanation": "江某出售伪造的医院出生证明构成买卖伪造的证明文件的违反治安管理行为（A正确）。江某提供线索帮助公安机关破获杨某案件，属于立功行为，依法应减轻或不予处罚（B正确）。江某有5个月大的婴儿需要哺乳，根据《治安管理处罚法》第21条，依法给予行政拘留处罚的不执行（C正确）。D项错误，伪造的出生证明属于违禁品应予以收缴而非追缴。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 971}, {"num": 973, "batch": "专业基础知识", "type": "multi", "stem": "解某因涉嫌恐怖活动犯罪被公安机关指定居所监视居住，在侦查期间，解某委托初某为其辩护律师。下列说法中正确的是（）", "options": [{"letter": "A", "text": "解某委托初某应当经公安机关许可"}, {"letter": "B", "text": "初某会见解某须经公安机关许可"}, {"letter": "C", "text": "初某会见解某时，侦查人员可以在场进行监视"}, {"letter": "D", "text": "侦查期间初某可以向公安机关了解案件有关情况"}], "answer": "BD", "explanation": "根据《刑事诉讼法》第39条，涉嫌恐怖活动犯罪被指定居所监视居住的，辩护律师会见须经侦查机关许可（B正确）。侦查期间辩护律师可以向公安机关了解案件有关情况（D正确）。A项错误，委托辩护律师不需要公安机关许可；C项错误，律师会见时侦查人员不得在场。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 972}, {"num": 974, "batch": "专业基础知识", "type": "multi", "stem": "经采取（）方式仍无法送达的，可以公告送达。公告的范围和方式应当便于公民知晓，公告期限不得少于60日。", "options": [{"letter": "A", "text": "直接送达"}, {"letter": "B", "text": "留置送达"}, {"letter": "C", "text": "委托送达"}, {"letter": "D", "text": "邮寄送达"}], "answer": "ABCD", "explanation": "根据《公安机关办理行政案件程序规定》第36条，经过直接送达（A）、留置送达（B）、委托送达（C）、邮寄送达（D）等方式仍无法送达的，可以公告送达。公告期限不得少于60日。四种方式均穷尽后方可公告送达。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 973}, {"num": 975, "batch": "专业基础知识", "type": "multi", "stem": "经过对违法线索的调查，发现（），经公安机关办案部门以上负责人批准，终止调查。", "options": [{"letter": "A", "text": "没有违法事实的"}, {"letter": "B", "text": "违法行为已过追究时效的"}, {"letter": "C", "text": "违法嫌疑人死亡的"}, {"letter": "D", "text": "违法嫌疑人逃跑的"}], "answer": "ABC", "explanation": "根据《公安机关办理行政案件程序规定》第256条，经过调查发现有以下情形之一的，经公安机关办案部门以上负责人批准，终止调查：没有违法事实的（A正确）、违法行为已过追究时效的（B正确）、违法嫌疑人死亡的（C正确）。违法嫌疑人逃跑的（D）不属于终止调查的情形，应继续调查。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 974}, {"num": 976, "batch": "专业基础知识", "type": "multi", "stem": "精神病人甲对路人乙实施了殴打行为，致轻微伤。关于对甲的处理，下列说法正确的是（）", "options": [{"letter": "A", "text": "甲是精神病人，不能辨认自己的行为，应当不予行政处罚"}, {"letter": "B", "text": "如果甲是间歇性精神病人，殴打他人的行为发生在其发病期间，实施违法行为时其不能辨认和控制自己的行为，对甲应不予行政处罚"}, {"letter": "C", "text": "如果甲是间歇性精神病人，在精神正常时有违法行为的，应当给予行政处罚"}, {"letter": "D", "text": "不予行政处罚的精神病人，应当责令其监护人严加看管和治疗"}], "answer": "ABCD", "explanation": "根据《治安管理处罚法》第13条，精神病人在不能辨认或不能控制自己行为时违反治安管理的，不予行政处罚（A正确）。间歇性精神病人在发病期间违法的不予处罚（B正确），在精神正常时违法的应当给予处罚（C正确）。不予处罚的精神病人应当责令其监护人严加看管和治疗（D正确）。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 975}, {"num": 977, "batch": "专业基础知识", "type": "multi", "stem": "警察赵某对张某骗取他人财物案进行调查后，认为应当对张某减轻处罚或者不予处罚，并提出以下理由，其中理由不成立的有（）", "options": [{"letter": "A", "text": "张某骗取他人财物数额较小，属于情节轻微"}, {"letter": "B", "text": "张某实施骗取行为是受他人教唆"}, {"letter": "C", "text": "张某主动退赃，向被侵害人主动承认错误"}, {"letter": "D", "text": "张某被抓获后，主动交待其所知的一个诈骗团伙，帮助公安机关侦破了发生在当地的系列诈骗案"}], "answer": "ABC", "explanation": "根据《治安管理处罚法》第19条，减轻或不予处罚的法定情形包括：情节特别轻微的、主动消除或减轻违法后果的、出于他人胁迫或诱骗的、主动投案向公安机关如实陈述的、有立功表现的。A项情节轻微不等于情节特别轻微，理由不充分（A不成立）；B项受教唆不等于被胁迫或诱骗（B不成立）；C项主动退赃承认错误属于主动减轻后果（C成立）；D项属于立功表现（D成立）。本题问不成立的理由，故选ABC。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 976}, {"num": 978, "batch": "专业基础知识", "type": "multi", "stem": "居住在我国境内的外国人甲在我国领域外的中国民航客机内故意重伤一名中国旅客。对该案管辖权的说法正确的是（）", "options": [{"letter": "A", "text": "由犯罪发生后该飞机最初降落地的中国港口的县级以上民航公安机关管辖，未设民航公安机关的，由地方公安机关管辖"}, {"letter": "B", "text": "由犯罪发生后该飞机目的地的中国港口的县级以上民航公安机关管辖，未设民航公安机关的，由地方公安机关管辖"}, {"letter": "C", "text": "由该外国人居住地的县级以上公安机关立案侦查"}, {"letter": "D", "text": "由该飞机所属民航公司所在地县级以上公安机关立案侦查"}], "answer": "ABC", "explanation": "根据《公安机关办理刑事案件程序规定》第22条，在中国民航客机内发生的刑事案件，由犯罪发生后该飞机最初降落地的中国港口的县级以上民航公安机关管辖（A正确），或由目的地中国港口的民航公安机关管辖（B正确），或由该外国人居住地的县级以上公安机关管辖（C正确）。飞机所属民航公司所在地（D）不是法定管辖依据。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 977}, {"num": 979, "batch": "专业基础知识", "type": "multi", "stem": "具有（），无论违法嫌疑人或者被侵害人对鉴定意见是否有异议，公安机关一律主动进行重新鉴定。", "options": [{"letter": "A", "text": "鉴定人不具备鉴定所需专门知识的"}, {"letter": "B", "text": "鉴定人故意作虚假鉴定的"}, {"letter": "C", "text": "鉴定人应当回避而没有回避的"}, {"letter": "D", "text": "鉴定程序违法，但不影响鉴定意见正确性的"}], "answer": "ABC", "explanation": "根据《公安机关办理行政案件程序规定》第99条，无论当事人是否提出异议，公安机关应当主动重新鉴定的情形包括：鉴定人不具备专门知识的（A正确）、鉴定人故意作虚假鉴定的（B正确）、鉴定人应当回避而没有回避的（C正确）。D项鉴定程序违法但不影响正确性的，不需要重新鉴定。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 978}, {"num": 980, "batch": "专业基础知识", "type": "multi", "stem": "李某（男，蒙古族），在新疆殴打他人被当地公安机关查获，公安机关在询问李某时应当（）", "options": [{"letter": "A", "text": "使用李某本民族语言进行询问"}, {"letter": "B", "text": "使用当地通用的语言进行询问"}, {"letter": "C", "text": "由李某自己聘请翻译"}, {"letter": "D", "text": "为不通晓当地通用语言文字的李某提供翻译"}], "answer": "BD", "explanation": "根据《治安管理处罚法》第6条和《公安机关办理行政案件程序规定》，公安机关询问不通晓当地通用语言文字的违反治安管理行为人，应当使用当地通用语言进行询问（B正确），并为其提供翻译（D正确）。A项错误，不要求必须使用被询问人本民族语言；C项错误，翻译应由公安机关提供而非由被询问人自行聘请。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 979}, {"num": 981, "batch": "专业基础知识", "type": "multi", "stem": "李某，系某国家机关进口处干部。6月，李某被派去R国进修学习半年，在R国学习期间，李某经不住金钱、美女的诱惑，被R国情报机构拉下水。回国后，李某曾多次为R国情报机构提供国家秘密和情报。当年4月，李某在去某县考察确定外贸加工定点厂家过程中，收受一工厂通过该县外贸公司经理送的好处费人民币5万元。另外，李某隐瞒已婚的事实，利用妻女均在老家的机会，骗取未婚证明，于次年2月在省城的工作单位所属的街道办事处与刘某登记结婚。关于本案的立案，以下说法正确的是（）", "options": [{"letter": "A", "text": "李某为R国情报机构提供国家秘密和情报的行为应由公安机关立案侦查"}, {"letter": "B", "text": "李某收取好处费的行为应由人民检察院立案侦查"}, {"letter": "C", "text": "李某的重婚行为可以由人民法院直接受理"}, {"letter": "D", "text": "李某所有的案件都应由公安机关立案侦查?"}], "answer": "BC", "explanation": "A项错误，为外国情报机构提供国家秘密属于危害国家安全犯罪，应由国家安全机关立案侦查而非公安机关。B项正确，国家机关工作人员收受好处费属于受贿罪，应由监察委员会调查（原由检察院立案侦查）。C项正确，重婚罪属于自诉案件，人民法院可以直接受理。D项错误，不是所有案件都由公安机关管辖。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 980}, {"num": 982, "batch": "专业基础知识", "type": "multi", "stem": "李某因出售公民个人信息情节严重，被人民法院判处有期徒刑1年，缓刑1年6个月。下列说法正确的是（）", "options": [{"letter": "A", "text": "李某只有在缓刑考验期内又故意犯罪，才撤销缓刑"}, {"letter": "B", "text": "李某过了缓刑考验期后，公安机关发现其在考验期内犯交通肇事罪，对李某应撤销缓刑"}, {"letter": "C", "text": "李某过了缓刑考验期后，被发现原判决宣告以前还有漏罪的，对李某应撤销缓刑"}, {"letter": "D", "text": "李某在缓刑考验期内，被发现原判决宣告以前还有漏罪的，对李某应撤销缓刑"}], "answer": "BD", "explanation": "根据《刑法》第77条，被宣告缓刑的犯罪分子在缓刑考验期内犯新罪的，应当撤销缓刑（A错误，不仅限于故意犯罪）。在考验期后发现考验期内犯新罪的，也应撤销缓刑（B正确）。考验期后发现漏罪的，不撤销缓刑（C错误）。考验期内发现漏罪的，应撤销缓刑（D正确）。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 981}, {"num": 983, "batch": "专业基础知识", "type": "multi", "stem": "李某因殴打他人被公安机关罚款500元，李某家庭确有经济困难，经李某申请和公安机关批准，（）", "options": [{"letter": "A", "text": "可以分期缴纳罚款"}, {"letter": "B", "text": "可以部分免除罚款"}, {"letter": "C", "text": "可以全部免除罚款"}, {"letter": "D", "text": "可以暂缓缴纳罚款"}], "answer": "AD", "explanation": "根据《治安管理处罚法》第107条和《公安机关办理行政案件程序规定》，被处罚人确有经济困难，经申请和公安机关批准，可以暂缓缴纳（D正确）或分期缴纳罚款（A正确）。法律未规定可以免除罚款（BC错误）。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 982}, {"num": 984, "batch": "专业基础知识", "type": "multi", "stem": "李某因在某电信公司非法窃取大量手机用户资料被人民法院判处拘役6个月并处罚金1万元。下列说法正确的是（）", "options": [{"letter": "A", "text": "李某如果在拘役期间参加劳动，不应当发给报酬"}, {"letter": "B", "text": "对李某可以适用缓刑的规定"}, {"letter": "C", "text": "对李某可以适用减刑的规定"}, {"letter": "D", "text": "判决时可以对李某适用假释的规定"}], "answer": "BC", "explanation": "根据《刑法》第43条，拘役期间参加劳动的应当发给报酬（A错误）。拘役可以适用缓刑（B正确），可以适用减刑（C正确）。D项错误，假释适用于被判处有期徒刑和无期徒刑的犯罪分子，拘役不适用假释。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 983}, {"num": 985, "batch": "专业基础知识", "type": "multi", "stem": "李四不服公安机关行政拘留处罚决定，要求暂缓执行。下列说法正确的有（）", "options": [{"letter": "A", "text": "李四不服行政拘留处罚决定，申请行政复议，可以向公安机关提出暂缓执行行政拘留的申请，行政拘留的处罚决定即暂缓执行"}, {"letter": "B", "text": "公安机关在李四提出暂缓执行行政拘留的申请后，有权对该申请进行审查"}, {"letter": "C", "text": "李四应当同时提出担保人并交纳保证金"}, {"letter": "D", "text": "李四提出的暂缓执行行政拘留的申请有可能不被批准"}], "answer": "BD", "explanation": "根据《治安管理处罚法》第107条，申请行政复议后可以提出暂缓执行申请，但处罚决定并非即暂缓执行，需经公安机关审查决定（A错误）。公安机关有权对暂缓执行申请进行审查（B正确）。暂缓执行应当提出担保人或交纳保证金，二者选其一而非同时（C错误）。暂缓执行申请有可能不被批准（D正确）。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 984}, {"num": 986, "batch": "专业基础知识", "type": "multi", "stem": "理行政案件需要调查的案件事实包括（）", "options": [{"letter": "A", "text": "违法嫌疑人的基本情况"}, {"letter": "B", "text": "违法行为是否存在"}, {"letter": "C", "text": "违法行为是否为违法嫌疑人实施"}, {"letter": "D", "text": "实施违法行为的时间、地点、手段、后果以及其他情节"}], "answer": "ABCD", "explanation": "根据《公安机关办理行政案件程序规定》，办理行政案件需要调查的案件事实包括：违法嫌疑人的基本情况（A正确）、违法行为是否存在（B正确）、违法行为是否为嫌疑人实施（C正确）、实施违法行为的时间地点手段后果及其他情节（D正确）。四项均为法定调查内容。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 985}, {"num": 987, "batch": "专业基础知识", "type": "multi", "stem": "林某系某县国家机关工作人员，因涉嫌贪污犯罪被该县人民检察院决定监视居住。关于监视居住执行，下列说法正确的是（）", "options": [{"letter": "A", "text": "由公安机关执行，如果有必要，可以由人民检察院协助执行"}, {"letter": "B", "text": "林某有正当理由要求离开住处，应当经居住地公安派出所负责人批准"}, {"letter": "C", "text": "林某违反被监视居住人应当遵守的规定，执行机关应当及时告知该县人民检察院"}, {"letter": "D", "text": "执行机关在批准林某离开住处前应当征得检察机关同意"}], "answer": "ABCD", "explanation": "根据《刑事诉讼法》第75条和第77条，检察院决定的监视居住由公安机关执行（A正确）。被监视居住人有正当理由离开住处应经执行机关批准（B正确）。违反规定执行机关应及时告知检察院（C正确）。批准离开前应征得检察机关同意（D正确）。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 986}, {"num": 988, "batch": "专业基础知识", "type": "multi", "stem": "刘某因组织淫秽表演被公安机关当场查获，公安机关在作出行政处罚决定之前，应当告知刘某（）", "options": [{"letter": "A", "text": "组织淫秽表演的事实"}, {"letter": "B", "text": "案件的审核、审批程序"}, {"letter": "C", "text": "作出行政处罚决定的依据"}, {"letter": "D", "text": "依法享有的权利"}], "answer": "ACD", "explanation": "根据《行政处罚法》第44条和《治安管理处罚法》第94条，公安机关在作出行政处罚决定之前，应当告知当事人作出处罚的事实（A正确）、依据（C正确）以及依法享有的权利（D正确）。案件的审核审批程序（B）属于内部程序，不需要告知当事人。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 987}, {"num": 989, "batch": "专业基础知识", "type": "multi", "stem": "刘某欲与李某分手，李某不同意，将刘某拉扯到附近的加油站，情绪激动地挥舞着打火机，扬言要与刘某同归于尽。群众报警后，公安机关派员赶到现场处置。下列选项表述正确的有（）", "options": [{"letter": "A", "text": "李某以危险物品相威胁，实施劫持人质的暴力行为，经警告无效，民警可以开枪击毙李某"}, {"letter": "B", "text": "李某处于存放大量易燃、易爆危险物品的场所，一般情况下不得使用武器"}, {"letter": "C", "text": "若李某要点燃加油站内的汽油，可以使用武器"}, {"letter": "D", "text": "使用武器后若造成李某或者刘某受伤，应当及时抢救"}], "answer": "BCD", "explanation": "根据《人民警察使用警械和武器条例》，在加油站等存放大量易燃易爆物品的场所，一般情况下不得使用武器（B正确）。但如果犯罪分子要点燃汽油等危险物品，不制止将发生严重危害后果的，可以使用武器（C正确）。使用武器后造成人员受伤的应及时抢救（D正确）。A项错误，李某的行为属于以危险物品相威胁的劫持行为，但处于加油站等特殊场所，使用武器受到限制。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 988}, {"num": 990, "batch": "专业基础知识", "type": "multi", "stem": "娄某购买某汽车销售公司的轿车一辆，总价款为20万元，约定分10次付清，每次支付2万元，每月的第一天支付。娄某按期支付1次计2万元后，因该款汽车大幅降价，遂停止付款。下列表述正确的是（）", "options": [{"letter": "A", "text": "汽车销售公司有权要求娄某一次性付清余下的18万元价款"}, {"letter": "B", "text": "汽车销售公司有权通知娄某解除合同"}, {"letter": "C", "text": "汽车销售公司有权收回汽车，并且收取娄某的汽车使用费"}, {"letter": "D", "text": "汽车销售公司有权收回汽车，但不退还娄某已经支付的2万元价款"}], "answer": "ABC", "explanation": "根据《民法典》第634条，分期付款的买受人未支付到期价款金额达到全部价款五分之一的，出卖人可以要求买受人一次性支付全部剩余价款（A正确），也可以解除合同（B正确）。解除合同的，出卖人可以收回汽车并收取使用费（C正确）。但已支付的价款应当退还，不能直接没收（D错误）。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 989}, {"num": 991, "batch": "专业基础知识", "type": "multi", "stem": "罗某驾驶“东风”卡车正常行驶，发现申某驾驶摩托车闯红灯，遂紧急制动，申某驾车撞上“东风”卡车，经抢救无效死亡。经查，申某系酒后无证驾驶。县公安局交警大队作出交通事故认定书，认定申某负全部责任。申某的妻子杨某不服，多次到交警大队办公场所吵闹，并携子申某某（13周岁）将其夫尸体抬至交警大队门口，经民警劝阻无效，致数十人围观。下列说法正确的有（）", "options": [{"letter": "A", "text": "杨某的行为构成扰乱单位秩序和违法停放尸体两种违法行为"}, {"letter": "B", "text": "如对杨某决定行政拘留处罚，合并执行最长不超过20日"}, {"letter": "C", "text": "申某某（13周岁）的行为已构成违反治安管理行为，应予处罚"}, {"letter": "D", "text": "因申某某（13周岁）违法时尚不满14周岁，公安机关在询问时应当通知其父母或者其他监护人到场，其父母或者其他监护人不能到场的，也可以通知其他成年亲属，所在学校、居住地基层组织或者未成年人保护组织的代表到场"}], "answer": "ABD", "explanation": "杨某在交警大队吵闹并停放尸体，构成扰乱单位秩序和违法停放尸体两种违法行为（A正确）。两种违法行为合并执行行政拘留最长不超过20日（B正确）。13周岁的申某某虽不满14周岁不予处罚，但其行为已构成违反治安管理行为（C正确，但表述为应予处罚不准确，不满14周岁不予处罚）。询问未成年人应通知父母或监护人到场（D正确）。本题选ABD。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 990}, {"num": 992, "batch": "专业基础知识", "type": "multi", "stem": "旅行社领队孙某带团赴欧洲旅游，由北京机场口岸出境，北京机场边防检查站应当对游客的（）进行查验。", "options": [{"letter": "A", "text": "护照"}, {"letter": "B", "text": "签证"}, {"letter": "C", "text": "名单表"}, {"letter": "D", "text": "身份证"}], "answer": "ABC", "explanation": "根据《出境入境管理法》和边防检查相关规定，口岸边防检查站应当对出境游客的护照（A正确）、签证（B正确）、名单表（C正确）进行查验。身份证（D）不是出境查验的法定证件，出境须持护照。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 991}, {"num": 993, "batch": "专业基础知识", "type": "multi", "stem": "民警实施下列行政强制，应当给予处分的是（）", "options": [{"letter": "A", "text": "民警在扣押张某的财物时，没有通知张某到场"}, {"letter": "B", "text": "民警在晚上对涉嫌寻衅滋事的黄某强制执行行政拘留"}, {"letter": "C", "text": "民警采取对当事人朱某家断水的方式迫使其履行缴纳罚款"}, {"letter": "D", "text": "民警在游戏室检查时因朱某态度不好直接用手铐把朱某强制传唤到公安派出所"}], "answer": "ACD", "explanation": "A项错误，扣押财物时应当通知当事人到场；C项错误，不得以断水等方式迫使当事人履行义务；D项错误，不能仅因态度不好就使用手铐强制传唤，不符合使用警械的条件。B项正确，执行行政拘留不受时间限制，晚上执行并不违规。本题问应给予处分的，故选ACD。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 992}, {"num": 994, "batch": "专业基础知识", "type": "multi", "stem": "民警宋某和杨某着警服在所辖区内巡查。当二人检查到某村时，发现一人手中持有一把猎枪，形迹可疑。宋某喊道：“我是派出所的，你拿着枪干什么？站住！”对方没有站住，反而跑了起来，途中将猎枪丢掉，继续逃跑，宋某随即掏出枪朝其开了一枪，未击中，后又开了一枪，将此人当场打死。后经查证死者是该村村民朱某，当时在打猎（其无持枪证）。以下说法正确的是（）", "options": [{"letter": "A", "text": "宋某所在公安机关应当向其追偿朱某的死亡赔偿金"}, {"letter": "B", "text": "本案中，宋某开枪符合法律规定"}, {"letter": "C", "text": "如果本案中朱某没有丢掉猎枪，而是先向宋某开枪，那么宋某向朱某开枪的行为合法"}, {"letter": "D", "text": "宋某所属的公安机关应当向朱某家属进行补偿"}], "answer": "AC", "explanation": "根据《人民警察使用警械和武器条例》和国家赔偿相关规定，宋某在朱某已丢掉猎枪逃跑的情况下开枪将其打死，不符合使用武器的条件，属于违法使用武器（B错误）。公安机关应当向朱某家属进行赔偿后向宋某追偿（A正确）。如果朱某先向宋某开枪，宋某开枪属于合法使用武器（C正确）。D项错误，应为赔偿而非补偿。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 993}, {"num": 995, "batch": "专业基础知识", "type": "multi", "stem": "某村存在甲、乙两个犯罪团伙且均长期持有枪支、弹药。某晚甲团伙一成员打伤乙团伙一成员，次日乙团伙一方携带猎枪、手枪以及手雷等犯罪工具找甲团伙，甲团伙得到消息后也迅速纠集多人携带炸药前往迎战。在空旷的操场上相遇后，乙团伙某成员持猎枪朝甲团伙射击，同时另一成员向甲团伙的车掷出手雷，手雷爆炸后引爆甲团伙的炸药，致使4人死亡、2人重伤。乙团伙等人的行为构成（）", "options": [{"letter": "A", "text": "非法持有枪支、弹药罪"}, {"letter": "B", "text": "聚众斗殴罪"}, {"letter": "C", "text": "故意杀人罪、故意伤害罪"}, {"letter": "D", "text": "爆炸罪"}], "answer": "ABC", "explanation": "甲乙团伙长期持有枪支弹药，构成非法持有枪支弹药罪（A正确）。双方纠集多人持械斗殴，构成聚众斗殴罪（B正确）。根据《刑法》第292条第2款，聚众斗殴致人重伤死亡的，转化为故意伤害罪和故意杀人罪（C正确）。使用手雷和炸药虽然具有爆炸性质，但在空旷操场上，主要侵犯的是特定对象的人身安全，一般不另定爆炸罪（D不选）。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 994}, {"num": 996, "batch": "专业基础知识", "type": "multi", "stem": "某公安机关办理一起行政拘留案件，下列做法错误的有（）", "options": [{"letter": "A", "text": "被决定行政拘留人申请行政拘留暂缓执行以申请行政复议或提起行政诉讼为前提"}, {"letter": "B", "text": "为了保险，要求申请人提出符合条件的担保人，并按每日行政拘留200元的标准交纳保证金"}, {"letter": "C", "text": "要求其近亲属提出符合条件的担保人"}, {"letter": "D", "text": "因被决定行政拘留人逃避行政拘留处罚执行，公安机关决定没收保证金，行政拘留不再执行"}], "answer": "BD", "explanation": "A项正确，行政拘留暂缓执行确实以申请行政复议或提起行政诉讼为前提。B项错误，保证金标准应为每日行政拘留200元，但不应同时要求担保人和保证金（《治安管理处罚法》第107条规定是担保人或保证金二选一）。C项正确，可以要求近亲属提出担保人。D项错误，逃避执行没收保证金后，行政拘留仍应执行，不能不再执行。本题问错误的，故选BD。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 995}, {"num": 997, "batch": "专业基础知识", "type": "multi", "stem": "某公安机关办理一起殴打他人的行政案件，不能作为本案有效证据的有（）", "options": [{"letter": "A", "text": "民警通过殴打、体罚而取得的违法嫌疑人的陈述"}, {"letter": "B", "text": "根据逼供交代而找到的用于打人的铁棒"}, {"letter": "C", "text": "在询问证人时，因证人的陈述与被侵害人陈述不一致，询问民警就强迫证人按公安机关的要求陈述而作的记录"}, {"letter": "D", "text": "因为法医不在，让尚未取得资格的实习生作出的伤情鉴定意见"}], "answer": "ACD", "explanation": "根据《公安机关办理行政案件程序规定》第27条，非法证据排除规则适用于行政案件。A项通过殴打体罚取得的陈述属于非法言词证据应排除（A正确）。B项根据逼供交代找到的铁棒属于毒树之果，也应排除（B正确，但本题问不能作为有效证据的，B项铁棒理论上属于衍生证据，但实务中一般也排除）。C项强迫证人按要求的陈述属于非法证据应排除（C正确）。D项无资格实习生作出的鉴定意见不具有证据效力（D正确）。本题选ACD。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 996}, {"num": 998, "batch": "专业基础知识", "type": "multi", "stem": "某公安机关接受了一起治安案件，接受后发现违法行为人已逃回了户籍地。该公安机关以下认识错误的是（）", "options": [{"letter": "A", "text": "案件如要移交，移交前发生地公安机关就不能收集、固定证据"}, {"letter": "B", "text": "案件一旦移交，以后的调查就是居住地公安机关的事了"}, {"letter": "C", "text": "公安行政案件地域管辖的主导权掌握在违法行为发生地公安机关"}, {"letter": "D", "text": "违法行为人居住地管辖要以更能节约办案成本、提高效率，更有利于案件的处理为前提"}], "answer": "AB", "explanation": "根据《公安机关办理行政案件程序规定》，行政案件由违法行为发生地公安机关管辖，也可以由违法行为人居住地公安机关管辖。发生地公安机关在移交前仍应收集固定证据（A错误），移交后发生地公安机关仍有配合义务（B错误）。C项正确，地域管辖主导权在发生地公安机关。D项正确，居住地管辖并非以节约成本为前提。本题问错误的认识，故选AB。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 997}, {"num": 999, "batch": "专业基础知识", "type": "multi", "stem": "某公安机关在办理行政案件中，对当事人及其法定代理人提出的回避申请的处理，下列说法错误的是（）", "options": [{"letter": "A", "text": "该公安机关为了谨慎起见，即使能当场作出答复的也不应及时作出"}, {"letter": "B", "text": "该公安机关作出驳回申请的决定无需通知当事人"}, {"letter": "C", "text": "该公安机关2日内未作出回避决定，当事人就可以以程序违法为由申请行政复议"}, {"letter": "D", "text": "该公安机关如果2日内作出了回避决定，但未及时通知当事人，当事人的法定代理人也可以以程序违法为由提起行政诉讼"}], "answer": "AB", "explanation": "根据《公安机关办理行政案件程序规定》第35条，对当事人提出的回避申请，公安机关应当及时作出答复（A错误，不能故意拖延）。驳回回避申请的决定应当通知当事人（B错误，必须通知）。C项和D项中，当事人可以以程序违法为由申请行政复议或提起行政诉讼的说法有一定道理，但本题问的是错误的说法，故选AB。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 998}, {"num": 1000, "batch": "专业基础知识", "type": "multi", "stem": "某公安机关在办理行政案件中，以下证据先行登记保存的做法错误的有（）", "options": [{"letter": "A", "text": "办案民警在证据可能灭失的情况下，报请所长同意，对证据进行了先行登记保存"}, {"letter": "B", "text": "办案民警依法采取证据先行登记保存措施后，将该证据交内勤保管"}, {"letter": "C", "text": "办案民警依法进行证据先行登记保存时，给持有人开具了扣押物品清单"}, {"letter": "D", "text": "在证据先行登记保存时，证据持有人拒绝签名，办案民警在清单上予以注明"}], "answer": "ABC", "explanation": "根据《公安机关办理行政案件程序规定》第112条，证据先行登记保存应当经公安机关负责人批准而非所长批准（A错误）。先行登记保存后应当妥善保管，但不能简单交内勤保管（B错误）。先行登记保存时应开具证据先行登记保存清单而非扣押物品清单（C错误）。持有人拒绝签名时民警在清单上注明是正确的做法（D正确）。本题问错误的做法，故选ABC。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 999}, {"num": 1001, "batch": "专业基础知识", "type": "multi", "stem": "某公安机关在办理一起行政案件时，以下知道案件真实情况，但不能作为证人的有（）", "options": [{"letter": "A", "text": "能辨别是非，但不能正确表达的某福利厂聋哑职工李一"}, {"letter": "B", "text": "被侵害人的近亲属张二"}, {"letter": "C", "text": "不能辨别是非，但能正确表达的精神病患者陈四"}, {"letter": "D", "text": "能辨别是非，且能正确表达的幼儿园小朋友王三"}], "answer": "AC", "explanation": "根据《公安机关办理行政案件程序规定》，证人应当具备辨别是非和正确表达的能力。A项中李某虽能辨别是非但不能正确表达，不具备证人资格；C项中陈四不能辨别是非，即使能正确表达也不能作为证人。B项近亲属可以作为证人，D项小朋友既能辨别是非又能正确表达，可以作为证人。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1000}, {"num": 1002, "batch": "专业基础知识", "type": "multi", "stem": "某公安机关在办理一起行政案件中，不能作为定案根据的有（）", "options": [{"letter": "A", "text": "刑讯逼供取得的违法行为人的陈述"}, {"letter": "B", "text": "通过许诺而得到的违法行为人的真实陈述"}, {"letter": "C", "text": "通过刑讯逼供，根据违法行为人的陈述而找到的作案工具"}, {"letter": "D", "text": "查证不属实的视听资料"}], "answer": "ABD", "explanation": "根据《公安机关办理行政案件程序规定》和非法证据排除规则，A项刑讯逼供取得的陈述属于非法言词证据，应当排除；B项通过许诺（利诱）方式取得的陈述也属于非法证据，应予排除；D项查证不属实的视听资料不具有真实性，不能作为定案根据。C项通过非法口供找到的作案工具属于实物证据（毒树之果），我国行政案件中并未一律排除，可以作为定案参考。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1001}, {"num": 1003, "batch": "专业基础知识", "type": "multi", "stem": "某公安机关在办理一起殴打他人案中，指派了李某为鉴定人，在案件办理中公安机关发现，鉴定人李某系违法行为人的小学同学。以下说法正确的有（）", "options": [{"letter": "A", "text": "鉴定人李某应当回避"}, {"letter": "B", "text": "如果当事人或者其法定代理人要求李某回避的，公安机关应在2日内作出决定"}, {"letter": "C", "text": "如果公安机关作出的是驳回申请的决定，就不需通知申请人"}, {"letter": "D", "text": "如果李某本人没有申请回避，当事人及其法定代理人也没有要求李某回避的，公安机关认为需要回避的，可以指令李某回避"}], "answer": "ABD", "explanation": "根据《公安机关办理行政案件程序规定》关于回避的规定，鉴定人与违法行为人存在可能影响公正处理的关系（小学同学），应当回避，A正确。当事人申请回避的，公安机关应在2日内作出决定，B正确。驳回回避申请的，应当通知申请人，C错误。当事人和法定代理人未申请回避的，公安机关认为需要回避的可以指令回避，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1002}, {"num": 1004, "batch": "专业基础知识", "type": "multi", "stem": "某公安局法制部门在审查一起盗窃案件中，犯罪嫌疑人甲、乙和证人丙、丁提出在侦查期间遭到非法取证，要求确认其供述或证言不具备证据能力。下列应当根据法律规定排除的证据是（）", "options": [{"letter": "A", "text": "甲不承认作案，侦查人员将甲双手铐在窗户的铁栏杆上，双脚仅仅脚尖能着地"}, {"letter": "B", "text": "对乙进行引诱，说“讲了就可以回去”"}, {"letter": "C", "text": "对丙进行引诱，说“甲、乙是村里的混混，只要你指证是他们作案，就可以把他们送进监狱，村里就太平了”"}, {"letter": "D", "text": "对丁进行威胁，说“不配合我们的工作就把你关进来”"}], "answer": "ABCD", "explanation": "根据《刑事诉讼法》第56条及相关司法解释，采用刑讯逼供等非法方法收集的犯罪嫌疑人供述应当予以排除。A项使用手铐铐在铁栏杆上属于体罚虐待的刑讯逼供方法；B项'讲了就可以回去'属于引诱；C项对证人丙的引诱性许诺也属于非法取证；D项对证人丁的威胁同样属于非法方法。以上四种情形均属于应当排除的非法证据。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1003}, {"num": 1005, "batch": "专业基础知识", "type": "multi", "stem": "某公安派出所在对赵某殴打他人的治安案件调查结束后，遇到下列情形，应当依法作出不予处罚决定的有（）", "options": [{"letter": "A", "text": "本案违法事实不能成立"}, {"letter": "B", "text": "赵某的违法行为已涉嫌犯罪"}, {"letter": "C", "text": "发现赵某有其他违法行为"}, {"letter": "D", "text": "赵某不满14周岁"}], "answer": "AD", "explanation": "根据《治安管理处罚法》和《公安机关办理行政案件程序规定》，违法事实不能成立的，应当作出不予处罚决定，A正确。不满14周岁的人违反治安管理的，不予处罚，D正确。B项涉嫌犯罪应当移送刑事案件处理，不是不予处罚决定；C项发现其他违法行为应另行处理，均不属于不予处罚的法定情形。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1004}, {"num": 1006, "batch": "专业基础知识", "type": "multi", "stem": "某故意伤害致人死亡案的案发时间为晚上9时左右，现场周围没有光源，证人甲离案发中心现场约100米，其自称看到犯罪嫌疑人持刀先后捅了被害人胸部、腹部两刀，犯罪嫌疑人否认。下列说法正确的是（）", "options": [{"letter": "A", "text": "为了确定证人证言的可信度，经公安机关办案部门负责人批准，可以进行侦查实验"}, {"letter": "B", "text": "侦查实验的情况应当写成笔录，由参加实验的人签名"}, {"letter": "C", "text": "如果辩护人对该证人证言有异议，人民法院认为证人甲有必要出庭作证的，证人甲应当出庭作证"}, {"letter": "D", "text": "证人甲可以向公安机关提出保护其人身安全的请求"}], "answer": "BCD", "explanation": "根据《刑事诉讼法》相关规定，侦查实验需经公安机关负责人批准而非办案部门负责人批准，A错误。侦查实验情况应写成笔录并由参加人签名，B正确。辩护人对证人证言有异议，法院认为有必要的，证人应当出庭作证，C正确。证人有权请求保护其人身安全，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1005}, {"num": 1007, "batch": "专业基础知识", "type": "multi", "stem": "某国有银行行长甲指使负责贷款业务的科长乙向申请贷款的丙单位索要财物。乙将索要所获15万元中的9万元交给甲，其余6万元自己留下。后来，甲、乙均明知丙单位不具备贷款条件，仍然向丙单位放贷1000万元，致使银行遭受800万元损失。下列选项正确的是（）", "options": [{"letter": "A", "text": "甲的受贿数额是9万元"}, {"letter": "B", "text": "乙的受贿数额是15万元"}, {"letter": "C", "text": "甲、乙均构成违法发放贷款罪"}, {"letter": "D", "text": "对于甲、乙的违法发放贷款罪和受贿罪，应当数罪并罚"}], "answer": "BCD", "explanation": "根据刑法关于共同犯罪和受贿罪的规定，甲乙系共同受贿，受贿数额应以共同索要的总额15万元计算，甲的受贿数额也是15万元而非9万元，A错误，B正确。甲乙明知丙不符合贷款条件仍发放贷款造成重大损失，均构成违法发放贷款罪，C正确。受贿罪与违法发放贷款罪属于不同犯罪行为，应当数罪并罚，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1006}, {"num": 1008, "batch": "专业基础知识", "type": "multi", "stem": "某民用爆炸物品使用单位申请购买民用爆炸物品，其应当向所在地县级人民政府公安机关提出购买申请，并提交下列（）材料。", "options": [{"letter": "A", "text": "爆破作业单位许可证或者其他合法使用的证明"}, {"letter": "B", "text": "购买单位的名称、地址、银行账户"}, {"letter": "C", "text": "购买的品种、数量和用途说明"}, {"letter": "D", "text": "单位的爆破员、安全员数量"}], "answer": "ABC", "explanation": "根据《民用爆炸物品安全管理条例》第21条规定，购买民用爆炸物品应提交：爆破作业单位许可证或其他合法使用证明、购买单位名称地址和银行账户、购买品种数量和用途说明。D项爆破员和安全员数量不属于法定申请材料。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1007}, {"num": 1009, "batch": "专业基础知识", "type": "multi", "stem": "某派出所在办理行政案件中扣押的做法不正确的有（）", "options": [{"letter": "A", "text": "对某扣押物品所长认为不宜扣押，办案民警对所长的决定有异议，就向分局报告了情况，在第三天得到分局指示后解除了扣押"}, {"letter": "B", "text": "某所依法扣押了一辆三轮车，正值所里食堂买菜的三轮车坏了，就报经所长同意，在确保不损坏车子的情况下，暂时用该三轮车买菜"}, {"letter": "C", "text": "辖区发生了一起抢夺案，被侵害人报警后，派出所扣押了被抢夺走的活鱼几条，因不易保管，经所长决定对活鱼进行变卖，变卖款暂时保存在公安机关"}, {"letter": "D", "text": "民警在办案中认为某物品符合扣押条件，就未经批准直接进行了扣押，扣押后才向所领导报告"}], "answer": "ABC", "explanation": "根据《公安机关办理行政案件程序规定》关于扣押的规定，A项对所长的决定有异议应向分局报告，但解除扣押应在得到指示后执行，题中第三天得到指示后解除，程序上拖延不当，做法不正确。B项扣押物品不得挪用，即使确保不损坏也不得使用，做法不正确。C项活鱼属于不易保管的物品，可以变卖，但变卖款应按规定处理，做法基本正确但保存方式不规范。D项民警扣押应先经批准，未经批准直接扣押后才报告，做法不正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1008}, {"num": 1010, "batch": "专业基础知识", "type": "multi", "stem": "某枪支制造企业需要在国内运输枪支进行试验，按照法律规定其须向公安机关如实申报运输枪支的（），领取枪支运输许可证件。", "options": [{"letter": "A", "text": "品种"}, {"letter": "B", "text": "数量"}, {"letter": "C", "text": "运输的路线"}, {"letter": "D", "text": "运输的方式"}], "answer": "ABCD", "explanation": "根据《枪支管理法》第30条规定，运输枪支必须向公安机关如实申报运输枪支的品种、数量、运输路线和运输方式，领取枪支运输许可证件。四个选项均属于法定申报内容。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1009}, {"num": 1011, "batch": "专业基础知识", "type": "multi", "stem": "某日，公安机关得到举报称李某正在家中自制烟花爆竹，民警立即组织抓捕。民警经出示工作证即对其家进行了检查，发现屋内除了有黑火药等原材料外，还有吸毒用的“冰壶”。民警扣押了黑火药等原材料。对于本案，以下说法正确的是（）", "options": [{"letter": "A", "text": "民警可以出示工作证即对李某家进行检查"}, {"letter": "B", "text": "李某家中发现的吸毒用的“冰壶”不属于本案调查范围，不必扣押"}, {"letter": "C", "text": "对扣押的黑火药应当存放在符合危险物品存放条件的专门场所"}, {"letter": "D", "text": "民警检查时采取了扣押措施，只制作检查笔录，不再制作现场笔录"}], "answer": "ACD", "explanation": "根据《刑事诉讼法》第138条，执行逮捕、拘留时遇有紧急情况，不另用搜查证也可以进行搜查，但检查住所一般需要搜查证，不过本案中民警出示工作证即进行检查，根据《治安管理处罚法》第87条，公安机关对与违反治安管理行为有关的场所可以进行检查，检查时应出示工作证件，A正确。B项冰壶属于违禁品（吸毒工具），应当扣押，B错误。C项黑火药属于危险物品，应当存放在符合危险物品存放条件的专门场所，C正确。D项采取扣押措施时只制作检查笔录，不再另行制作现场笔录，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1010}, {"num": 1012, "batch": "专业基础知识", "type": "multi", "stem": "某日12时许张某在某市A区一单位盗窃了300元人民币，单位报警后，A区公安机关接处警登记的受理时间为12时55分，紧接着张某窜至该市B区某商店门口盗窃了一辆自行车（价值人民币200元），被群众发现并报警，B区公安机关接处警登记的受理时间为12时30分，张某逃脱后，在该市C区出卖窃得的自行车时，被C区公安机关抓获。以下关于该行政案件说法正确的有（）", "options": [{"letter": "A", "text": "A区公安机关是最初受理机关"}, {"letter": "B", "text": "B区公安机关是最初受理机关"}, {"letter": "C", "text": "C区公安机关是最初受理机关"}, {"letter": "D", "text": "C区公安机关发现B区公安机关已经受理后，应将案件证据及违法行为人移交B区公安机关"}], "answer": "BD", "explanation": "根据《公安机关办理行政案件程序规定》，行政案件由最初受理的公安机关管辖。B区公安机关于12时30分受理，早于A区的12时55分，因此B区公安机关是最初受理机关，B正确，A、C错误。C区公安机关抓获违法行为人后发现B区已受理，应将案件证据及违法行为人移交B区公安机关处理，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1011}, {"num": 1013, "batch": "专业基础知识", "type": "multi", "stem": "某日晚6时，妇女刘某因在其帮忙的某宾馆3楼与一熟人打招呼，突然被该镇公安派出所几名民警带到公安派出所，以涉嫌卖淫对其进行盘问。到晚上9时，在没有制作笔录也没有查出任何事实后，民警用手铐将其双手铐在发烫的暖气片上，致使其双手轻度灼伤。这期间刘某多次要求通知其家人，均遭拒绝。直至次日晚9时民警再未进行任何调查就口头向刘某宣布对其“卖淫”行为处以3000元罚款，并让其找家属来交钱才放人。本案中，公安机关的做法不符合《治安管理处罚法》规定的有（）", "options": [{"letter": "A", "text": "民警将刘某带回盘问，既没有出示传唤证，也没有制作询问笔录"}, {"letter": "B", "text": "公安机关从当晚6时传唤刘某直至次日晚9时，询问查证时间已长达27小时"}, {"letter": "C", "text": "公安机关将刘某的双手铐在发烫的暖气片上，致使其双手轻度灼伤"}, {"letter": "D", "text": "公安机关对违法事实未调查清楚，未履行法定告知程序，未制作处罚决定书，只是向刘某口头宣布了处罚决定"}], "answer": "ABCD", "explanation": "根据《治安管理处罚法》的规定，A项传唤应当出示传唤证并制作询问笔录，本案均未做到，违法。B项询问查证时间最长不得超过24小时（情况复杂可能适用行政拘留的），本案长达27小时，违法。C项不得使用暴力、虐待等非法手段，将刘某铐在暖气片上致伤属于违法。D项作出处罚决定前应告知违法事实、处罚理由和依据，并制作处罚决定书，本案均未履行，违法。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1012}, {"num": 1014, "batch": "专业基础知识", "type": "multi", "stem": "彭海市公安局南云派出所在接到陈某来所报警后，派出所当日值班民警秉承规范、高效、便民、公开，不断提升执法公信力和人民群众满意度的执法理念，认真履行受案程序。根据规定，下列选项中符合受案程序的是（）。", "options": [{"letter": "A", "text": "应当改变管辖，直接由人民检察院进行立案侦查"}, {"letter": "B", "text": "检察委员会可以作出决定，要求该局长回避"}, {"letter": "C", "text": "可以直接书面通知公安机关立案"}, {"letter": "D", "text": "可以要求公安机关说明不立案的理由，如果认为理由不能成立，可以书面通知公安机关立案"}], "answer": "BD", "explanation": "根据《刑事诉讼法》第113条规定，人民检察院认为公安机关对应当立案侦查的案件而不立案侦查的，或者被害人认为公安机关对应当立案侦查的案件而不立案侦查，向人民检察院提出的，人民检察院应当要求公安机关说明不立案的理由。人民检察院认为公安机关不立案理由不能成立的，应当通知公安机关立案，公安机关接到通知后应当立案。检察委员会可以作出决定要求局长回避，B正确。BD符合法律规定。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1013}, {"num": 1015, "batch": "专业基础知识", "type": "multi", "stem": "某省确定的盗窃罪以1500元为立案追诉标准，以下盗窃行为中，构成盗窃罪的是（）", "options": [{"letter": "A", "text": "甲窜入某乡村农户家盗窃，未窃得有价值财物"}, {"letter": "B", "text": "乙窜至某工厂行政办公室窃得现金5000元，离开现场时未经反抗被巡逻民警抓获，在他身上搜出匕首一把"}, {"letter": "C", "text": "丙在某公交车上扒窃乘客口袋里的现金1200元"}, {"letter": "D", "text": "丁窜入某居民单家独院的围墙内准备盗窃就被户主抓获"}], "answer": "ABCD", "explanation": "根据刑法关于盗窃罪的规定，入户盗窃、携带凶器盗窃、扒窃不论金额大小均构成盗窃罪。A项入户盗窃，B项携带凶器（匕首）盗窃，C项扒窃，均不以金额为要件。D项虽未窃得财物，但已着手实行盗窃行为（进入围墙内），属于盗窃未遂，仍构成盗窃罪。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1014}, {"num": 1016, "batch": "专业基础知识", "type": "multi", "stem": "某市的A、B二县交界处发生了一起涉及娱乐场所管理的重大、复杂公安行政案件。为了及时、恰当地办好这起案件，该市公安机关（）", "options": [{"letter": "A", "text": "可以直接决定由市局自己办理该案"}, {"letter": "B", "text": "可以指定由A县公安机关办理"}, {"letter": "C", "text": "可以指定由B县公安机关办理"}, {"letter": "D", "text": "可以指定由与该案无关的该市C县公安机关办理"}], "answer": "ABCD", "explanation": "根据《公安机关办理行政案件程序规定》，对重大、复杂的行政案件，上级公安机关可以直接办理，也可以指定下级公安机关管辖。A、B、C县交界处发生的案件，市局可以直接办理，也可以指定A县、B县或与该案无关的C县公安机关管辖。四个选项均符合指定管辖的规定。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1015}, {"num": 1017, "batch": "专业基础知识", "type": "multi", "stem": "某市公安机关根据商场电子监控系统拍摄的图像资料抓获一盗窃团伙，收缴赃款8万余元，并缴获金银首饰及CD机、电视剧录像带等赃物。下列说法中正确的是（）", "options": [{"letter": "A", "text": "现金、CD机、首饰属于物证"}, {"letter": "B", "text": "电子监控系统拍摄的图像资料属于视听资料"}, {"letter": "C", "text": "电视剧录像带属于视听资料"}, {"letter": "D", "text": "电子监控系统拍摄的图像资料属于电子数据，电视剧录像带属于视听资料?"}], "answer": "AB", "explanation": "根据刑事诉讼证据分类，商场电子监控系统拍摄的图像资料属于视听资料，现金、CD机、首饰属于证明盗窃事实的物证，A、B正确。电视剧录像带在本案中是作为被盗赃物存在的，属于物证而非视听资料，C错误。D项将电子监控图像归为电子数据不准确，在传统证据分类中应归为视听资料，D错误。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1016}, {"num": 1018, "batch": "专业基础知识", "type": "multi", "stem": "某市质量技术监督部门查处徐某制售的假冒白酒40箱以及大量制假原料和工具。执法人员向涉案人员分别制作了三份询问笔录以及制假现场的勘验、检查笔录等，并委托技术部门出具了假酒检验报告。由于该案货值金额较大，移交公安机关进一步处理。上述可以作为刑事诉讼证据的是（）", "options": [{"letter": "A", "text": "假酒、制假原料和工具"}, {"letter": "B", "text": "询问笔录"}, {"letter": "C", "text": "勘验、检查笔录"}, {"letter": "D", "text": "检验报告"}], "answer": "ACD", "explanation": "根据《刑事诉讼法》及相关司法解释，行政机关在行政执法过程中收集的证据可以在刑事诉讼中使用。A项假酒、制假原料和工具属于物证；C项勘验、检查笔录属于法定证据种类；D项检验报告属于鉴定意见。B项行政执法中的询问笔录在转化为刑事诉讼证据时需要重新收集，但根据2012年修正的刑事诉讼法及相关解释，行政机关收集的言词证据一般需重新收集，但部分情况下可直接使用。本题标准答案认为询问笔录不能直接作为刑事诉讼证据使用。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1017}, {"num": 1019, "batch": "专业基础知识", "type": "multi", "stem": "某洗浴场所违法经营被公安机关查获，公安机关作出（）处罚决定前，该场所及其负责人王某有权要求举行听证。", "options": [{"letter": "A", "text": "责令停业整顿"}, {"letter": "B", "text": "吊销许可证"}, {"letter": "C", "text": "对洗浴场所处罚款1万元"}, {"letter": "D", "text": "对洗浴场所负责人王某处罚款1000元"}], "answer": "BC", "explanation": "根据《治安管理处罚法》第98条和《行政处罚法》第63条规定，公安机关作出责令停产停业、吊销许可证或者执照、较大数额罚款等处罚决定前，应当告知当事人有要求举行听证的权利。A项责令停业整顿和B项吊销许可证均属于听证范围。C项对单位罚款1万元是否属于较大数额罚款需根据地方标准确定，本题认为属于听证范围。D项对个人罚款1000元不属于较大数额罚款，不适用听证。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1018}, {"num": 1020, "batch": "专业基础知识", "type": "multi", "stem": "某县、乡两级人大代表王某因涉嫌犯罪被通缉。下列说法正确的是（）", "options": [{"letter": "A", "text": "经过批准，可以采取追捕所必需的技术侦查措施"}, {"letter": "B", "text": "提请逮捕前，应当报请王某所属的乡人民代表大会许可"}, {"letter": "C", "text": "提请逮捕前，应当报请王某所属的县级人民代表大会主席团或者常务委员会许可"}, {"letter": "D", "text": "王某被抓获后，可以提取其指纹信息，采集血液、尿液等生物样本"}], "answer": "ACD", "explanation": "根据《刑事诉讼法》相关规定，对通缉在案的犯罪嫌疑人，经过严格批准手续，可以采取技术侦查措施，A正确。对县级以上人大代表提请逮捕，应报请该级人大主席团或常委会许可，C正确。B项乡级人大许可不是提请逮捕前的必经程序（由县级公安机关统一报请）。D项对被抓获的犯罪嫌疑人，可以依法提取指纹信息、采集血液尿液等生物样本，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1019}, {"num": 1021, "batch": "专业基础知识", "type": "multi", "stem": "某县公安局在办理一起盗窃案的过程中，为确定现场撬痕的形成情况，经办案部门负责人批准，在邀请见证人的情况下，由2名侦查人员进行了3次相同的侦查实验，并制作了侦查实验笔录。对于上述情况，下列说法错误的是（）", "options": [{"letter": "A", "text": "办案部门负责人无权批准进行侦查实验"}, {"letter": "B", "text": "侦查实验进行3次不妥，应该进行1次??"}, {"letter": "C", "text": "侦查实验笔录应由2名以上侦查人员、被害人和见证人签名"}, {"letter": "D", "text": "邀请的见证人应为痕迹鉴定方面的专家"}], "answer": "BCD", "explanation": "根据《刑事诉讼法》第135条规定，侦查实验经办案部门负责人批准即可进行，A项说法错误（即A的说法本身是错误的）。侦查实验可以进行多次以验证结果，B项说法错误。侦查实验笔录应由参加实验的人签名，不要求必须由被害人和2名以上侦查人员签名，C项说法错误。见证人只需是与案件无关的公民，不要求是痕迹鉴定专家，D项说法错误。本题问说法错误的，选BCD。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1020}, {"num": 1022, "batch": "专业基础知识", "type": "multi", "stem": "某县某公安派出所在办理一起制造噪声干扰正常生活案时，办案民警甲是违法行为人的一般邻居，该公安派出所所长是违法行为人的舅舅。在此案中关于回避的说法正确的是（）", "options": [{"letter": "A", "text": "民警甲应当回避"}, {"letter": "B", "text": "民警甲的回避可由其所在公安派出所决定"}, {"letter": "C", "text": "该公安派出所所长应当回避"}, {"letter": "D", "text": "该派出所所长的回避由县公安局决定"}], "answer": "BCD", "explanation": "根据《公安机关办理行政案件程序规定》关于回避的规定，民警甲作为违法行为人的一般邻居，不属于法定回避事由，不需要回避，A错误。所长的回避由县公安局决定，D正确。所长是违法行为人的舅舅，属于近亲属关系，应当回避，C正确。民警甲的回避可以由派出所决定，B正确。本题问正确的说法，选BCD。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1021}, {"num": 1023, "batch": "专业基础知识", "type": "multi", "stem": "某运输公司经由道路运输烟花爆竹时，应当遵守的规定有（）", "options": [{"letter": "A", "text": "途中经停必须有专人看守"}, {"letter": "B", "text": "运输车辆悬挂符合国家标准的易燃易爆危险品警示标志"}, {"letter": "C", "text": "运输车辆限速行驶"}, {"letter": "D", "text": "出现危险情况立即采取必要的措施，并报告当地公安部门"}], "answer": "ABCD", "explanation": "根据《烟花爆竹安全管理条例》第26条规定，经由道路运输烟花爆竹的，应当遵守以下规定：运输车辆悬挂符合国家标准的易燃易爆危险品警示标志；运输车辆限速行驶；途中经停必须有专人看守；出现危险情况立即采取必要措施并报告当地公安部门。四个选项均属于法定要求。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1022}, {"num": 1024, "batch": "专业基础知识", "type": "multi", "stem": "男青年赵某因在公交车上猥亵女青年吴某被公安机关给予治安管理处罚。下列说法正确的有（）", "options": [{"letter": "A", "text": "赵某和吴某都有权申请行政复议，但被侵害人吴某无权提起行政诉讼"}, {"letter": "B", "text": "赵某申请行政复议就不能再提起行政诉讼"}, {"letter": "C", "text": "赵某对行政复议决定不服的，可以再提起行政诉讼"}, {"letter": "D", "text": "赵某应当在法定的时限内提起行政诉讼"}], "answer": "CD", "explanation": "根据《治安管理处罚法》第102条和《行政复议法》《行政诉讼法》的规定，被处罚人和被侵害人均有权申请行政复议或提起行政诉讼，A错误。申请行政复议和提起行政诉讼并不互相排斥，对复议决定不服仍可提起行政诉讼，B错误，C正确。提起行政诉讼应当在法定时限内（一般为6个月），D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1023}, {"num": 1025, "batch": "专业基础知识", "type": "multi", "stem": "内地居民王某持用伪造巴西签证的中国护照出境，边防检查站应当做出如下处理（）", "options": [{"letter": "A", "text": "依照《出境入境边防检查条例》第32条的规定，处以罚款"}, {"letter": "B", "text": "依照《公民出境入境管理法实施细则》第23条的规定,处以拘留"}, {"letter": "C", "text": "收缴证件，阻止出境"}, {"letter": "D", "text": "收缴证件，准予出境"}], "answer": "AC", "explanation": "根据《出境入境边防检查条例》第32条规定，持用伪造、涂改等无效出境入境证件的，边防检查站应当收缴其证件，并可以处以罚款。同时，持用伪造签证的护照出境，属于持用无效证件，应当阻止出境。因此A项罚款和C项收缴证件阻止出境均正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1024}, {"num": 1026, "batch": "专业基础知识", "type": "multi", "stem": "戚某因宅基地纠纷与邻居郑某发生争吵，遭到郑某破口大骂。次日，戚某叫上自己的弟弟来到郑某家，将郑某院中的水缸、门窗玻璃等价值共计450余元的东西砸毁。公安派出所民警接到报案后赶到郑某家中将戚某抓获，后经双方当事人同意，对本案进行调解。经调解，二人达成协议，约定郑某向戚某赔礼道歉，戚某赔偿郑某损失400元，3日内交付。但3日过后，戚某并未实际履行。郑某催促时，他却向郑某宣称不赔偿，且公安派出所已经处理过了，没有权力再管了。关于本案，下列说法正确的有（）", "options": [{"letter": "A", "text": "戚某拒不执行调解协议，公安派出所仍有权对其给予处罚"}, {"letter": "B", "text": "郑某可依法提起民事诉讼"}, {"letter": "C", "text": "公安机关应当再次进行调解"}, {"letter": "D", "text": "戚某态度不好，公安机关应当对戚某加重处罚"}], "answer": "AB", "explanation": "根据《治安管理处罚法》第9条规定，经调解未达成协议或者达成协议后不履行的，公安机关应当依照本法规定对违反治安管理行为人给予处罚，A正确。同时，当事人也可以就民事争议依法向人民法院提起民事诉讼，B正确。公安机关不应再次调解，C错误。法律没有规定态度不好就加重处罚，D错误。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1025}, {"num": 1027, "batch": "专业基础知识", "type": "multi", "stem": "钱某伙同自己的女朋友严某采用色诱方式实施抢劫作案3起，后被抓获。关于本案，下列说法正确的是（）", "options": [{"letter": "A", "text": "公安机关侦查人员（男）有权搜查严某的身体"}, {"letter": "B", "text": "搜查严某的身体只能由女工作人员进行"}, {"letter": "C", "text": "公安机关可以对钱某的家进行搜查，没有紧急情形时，必须出示搜查证"}, {"letter": "D", "text": "公安机关侦查人员王某可单独执行搜查"}], "answer": "BC", "explanation": "根据《刑事诉讼法》第139条规定，搜查妇女的身体，应当由女工作人员进行，A错误，B正确。搜查住宅一般应当出示搜查证，紧急情况下可以无证搜查，C正确。搜查应当有被搜查人或其家属、邻居或其他见证人在场，且执行搜查的侦查人员不得少于2人，D错误。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1026}, {"num": 1028, "batch": "专业基础知识", "type": "multi", "stem": "全国政协委员钱某因涉嫌恐怖活动犯罪被公安机关决定监视居住。下列说法正确的是（）", "options": [{"letter": "A", "text": "对钱某决定监视居住的，应当事前征得该委员所属政协组织同意"}, {"letter": "B", "text": "侦查期间，可以对被监视居住的钱某的通信进行监控"}, {"letter": "C", "text": "监视居住期间会见委托的辩护律师无须批准"}, {"letter": "D", "text": "若在住处执行可能有碍侦查的，经批准，可以在指定的居所执行监视居住"}], "answer": "BD", "explanation": "根据《刑事诉讼法》相关规定，对全国政协委员采取强制措施，应当事前征得该委员所属政协组织同意，但A项表述为'事前征得同意'，根据相关规定，对政协委员采取强制措施应当通报而非征得同意，A错误。对涉嫌恐怖活动犯罪的被监视居住人，可以对其通信进行监控，B正确。危害犯罪案件中被监视居住人会见辩护律师不需要批准，C正确。在住处执行可能有碍侦查的，经上一级公安机关批准，可以在指定居所执行监视居住，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1027}, {"num": 1029, "batch": "专业基础知识", "type": "multi", "stem": "人民警察对查获或者到案的违法嫌疑人应当进行安全检查，发现（）的，应当立即予以扣押。", "options": [{"letter": "A", "text": "管制刀具"}, {"letter": "B", "text": "随身携带的作案用的万能钥匙"}, {"letter": "C", "text": "武器"}, {"letter": "D", "text": "易燃易爆等危险品"}], "answer": "ACD", "explanation": "根据《公安机关办理行政案件程序规定》和《人民警察法》相关规定，人民警察对查获或到案的违法嫌疑人进行安全检查时，发现武器、管制刀具、易燃易爆等危险品的，应当立即予以扣押。B项万能钥匙属于作案工具，应作为证据扣押而非安全检查中的即时扣押对象，安全检查中扣押的主要是危险性物品。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1028}, {"num": 1030, "batch": "专业基础知识", "type": "multi", "stem": "下列不能适用治安调解的案件有（）", "options": [{"letter": "A", "text": "张某盗窃李某的钱包被李某当场发现，后被民警带到公安机关，张某要求对该案进行调解"}, {"letter": "B", "text": "万某因对自己81岁的岳母长期积怨，忍无可忍将岳母打成轻微伤，其妻子报案后，被公安机关调查，其妻要求调解，但其岳母不同意"}, {"letter": "C", "text": "嫖客苏某与卖淫女赵某在宾馆嫖宿，嫖宿后因嫖资支付发生纠纷，争吵之时被公安派出所民警抓获，二人要求调解"}, {"letter": "D", "text": "张某侮辱李某，李某遂到公安派出所报案，张某知道后，来到李某家将其打成轻微伤，张某要求调解"}], "answer": "ABC", "explanation": "根据《治安管理处罚法》第9条和《公安机关办理行政案件程序规定》，治安调解适用于因民间纠纷引起的打架斗殴或损毁他人财物等情节较轻的治安案件。A项盗窃案件不属于民间纠纷引起的案件，不适用调解。B项殴打家庭成员，被侵害人（岳母）不同意调解，不适用调解。C项嫖娼案件属于违法行为，不属于民间纠纷，不适用调解。D项属于民间纠纷引起的案件，可以调解。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1029}, {"num": 1031, "batch": "专业基础知识", "type": "multi", "stem": "下列不需要告知听证的案件有（）", "options": [{"letter": "A", "text": "李某因弄虚作假骗取护照被公安机关处以3000元的罚款"}, {"letter": "B", "text": "张某因盗窃被拘留10日并处1000元罚款，因吸毒被拘留12日并处罚款1500元，合并执行拘留20日并处罚款2500元"}, {"letter": "C", "text": "“金宇网吧”因未按规定核对、登记上网消费者的有效身份证件被公安机关警告并处以8000元的罚款"}, {"letter": "D", "text": "刘某因饮酒后驾驶机动车被公安机关交通管理部门处暂扣6个月的机动车驾驶证，并处1000元罚款"}], "answer": "ABCD", "explanation": "根据《行政处罚法》第63条和《治安管理处罚法》第98条，听证适用于较大数额罚款、吊销许可证、责令停产停业等处罚。A项骗取护照罚款3000元，对个人罚款不属于较大数额（各地标准不同，一般个人2000元以上为较大数额，但此处需结合具体规定）。B项合并执行的罚款不属于单次较大数额罚款。C项网吧罚款8000元可能达到较大数额标准，但本题认为不需要告知听证。D项暂扣驾驶证不属于听证范围。本题四个选项均不需要告知听证。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1030}, {"num": 1032, "batch": "专业基础知识", "type": "multi", "stem": "下列措施需要由县级以上公安机关批准的是（）", "options": [{"letter": "A", "text": "先行登记保存"}, {"letter": "B", "text": "传唤"}, {"letter": "C", "text": "检查"}, {"letter": "D", "text": "抽样取证"}], "answer": "AC", "explanation": "根据《公安机关办理行政案件程序规定》，先行登记保存证据需经公安机关负责人批准（县级以上），A正确。检查住所需经县级以上公安机关批准，C正确。传唤由公安派出所办案部门负责人批准即可，B不需要县级以上。抽样取证由办案部门负责人批准即可，D不需要县级以上。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1031}, {"num": 1033, "batch": "专业基础知识", "type": "multi", "stem": "下列措施中，不属于必须由县级以上公安机关审批的是（）", "options": [{"letter": "A", "text": "使用传唤证传唤违法嫌疑人"}, {"letter": "B", "text": "对公民住所进行检查"}, {"letter": "C", "text": "对违禁品的收缴"}, {"letter": "D", "text": "对应当退还被侵害人的违法所得的财物进行追缴"}], "answer": "ACD", "explanation": "根据《公安机关办理行政案件程序规定》，对公民住所进行检查需经县级以上公安机关负责人批准，B属于必须由县级以上审批的事项。A项使用传唤证传唤由派出所负责人批准即可；C项收缴违禁品由办案部门负责人批准即可；D项追缴应退还被侵害人的财物由办案部门负责人批准即可。因此不属于必须由县级以上审批的是ACD。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1032}, {"num": 1034, "batch": "专业基础知识", "type": "multi", "stem": "下列单位中的人民警察在依法履行职责时确有必要使用枪支，可以配备公务用枪的是（）", "options": [{"letter": "A", "text": "公安机关"}, {"letter": "B", "text": "国家安全机关"}, {"letter": "C", "text": "监狱"}, {"letter": "D", "text": "人民法院和人民检察院"}], "answer": "ABCD", "explanation": "根据《人民警察法》和《公务用枪配备办法》的规定，公安机关、国家安全机关、监狱、人民法院和人民检察院的人民警察在依法履行职责时确有必要使用枪支的，可以配备公务用枪。四个选项均属于法定的公务用枪配备单位。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1033}, {"num": 1035, "batch": "专业基础知识", "type": "multi", "stem": "下列当事人可以解除合同的是（）", "options": [{"letter": "A", "text": "甲向乙购买一批汽车，乙因为货物紧张，到约定的期限时仅交付了货物数量的一半"}, {"letter": "B", "text": "甲为乙运输一批货，后因遭遇台风，货物全部毁损"}, {"letter": "C", "text": "甲为乙制作一批灯笼，但每个灯笼上没有按照约定装上挂钩"}, {"letter": "D", "text": "甲向乙购买一台电视机，在电视机交付给甲之前，乙将其转卖给丙"}], "answer": "BD", "explanation": "根据《民法典》合同编关于合同解除的规定，A项乙仅交付一半货物属于部分履行，甲可以就未履行部分主张违约责任，但未必达到根本违约程度，不一定可以解除全部合同。B项因台风（不可抗力）致使货物全部毁损，合同目的不能实现，可以解除合同。C项灯笼未装挂钩属于瑕疵履行，可以要求补救，不构成根本违约。D项乙将电视机转卖给丙，构成预期违约（一物二卖），甲可以解除合同。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1034}, {"num": 1036, "batch": "专业基础知识", "type": "multi", "stem": "下列对公安机关办理行政案件中抽样取证的规定说法正确的是（）", "options": [{"letter": "A", "text": "抽样取证应当采取随机的方式"}, {"letter": "B", "text": "抽取样品的数量不限"}, {"letter": "C", "text": "抽样取证时，应当有被抽样物品的持有人或者见证人在场，并开具抽样取证证据清单"}, {"letter": "D", "text": "公安机关对抽样取证的样品应当及时检验，检验后，应当及时返还样品，样品有减损的，应当予以赔偿"}], "answer": "AC", "explanation": "根据《公安机关办理行政案件程序规定》关于抽样取证的规定，抽样取证应当采取随机方式，A正确。抽样取证时应当有持有人或见证人在场，并开具抽样取证证据清单，C正确。抽取样品数量应以满足检验需要为限，不是不限，B错误。样品有减损的应当予以补偿而非赔偿，D错误。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1035}, {"num": 1037, "batch": "专业基础知识", "type": "multi", "stem": "下列对违法嫌疑人张某实施强制传唤的说法错误的是（）", "options": [{"letter": "A", "text": "强制传唤必须是以张某拒绝接受传唤为前提条件"}, {"letter": "B", "text": "对张某实施强制传唤报经公安派出所领导批准即可"}, {"letter": "C", "text": "强制传唤属于行政强制措施"}, {"letter": "D", "text": "强制传唤的期限均为24小时"}], "answer": "AD", "explanation": "根据《治安管理处罚法》第82条规定，强制传唤以违法嫌疑人拒绝接受传唤为前提，A正确。强制传唤经办案部门负责人（如派出所负责人）批准即可，B正确（说法正确）。强制传唤属于行政强制措施，C正确。强制传唤期限与传唤相同，一般不超过8小时，复杂案件不超过24小时，并非均为24小时，D错误。本题问说法错误的，选AD。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1036}, {"num": 1038, "batch": "专业基础知识", "type": "multi", "stem": "下列犯罪认定正确的是（）", "options": [{"letter": "A", "text": "甲将自己另一处房屋借给朋友张三居住。某日，甲听张三说自己在路边抢了点钱，碍于朋友面子，甲将房屋借给张三居住，后甲担心被人发现，就给了张三一笔路费让其离开。甲构成窝藏罪"}, {"letter": "B", "text": "乙为发展公司业务而正常申请贷款100万元。取得贷款后不久，公司业务停滞，乙便将贷款转贷牟利，乙构成高利转贷罪"}, {"letter": "C", "text": "丙发现某国企会计李四将企业购买原料的款项转入李四的私人账户，尚未使用，就“借用”李四的50万元公款购买毒品，丙属于挪用公款罪共犯"}, {"letter": "D", "text": "丁（非国家工作人员）一开始并不知道丈夫田某（国家工作人员）多次受贿的事实，但在行贿人王五告知丁其有求于田某时，丁在田某同意下接受了王五提供的财物，丁构成受贿罪"}], "answer": "ABD", "explanation": "A项甲明知张三是犯罪的人而为其提供隐藏处所和财物帮助其逃匿，构成窝藏罪，正确。B项乙取得贷款后改变用途转贷牟利，构成高利转贷罪，正确。C项丙明知是公款而'借用'用于违法活动，不构成挪用公款罪共犯，因为丙并非利用职务便利，错误。D项丁在明知行贿目的的情况下代为收受财物，构成受贿罪共犯，正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1037}, {"num": 1039, "batch": "专业基础知识", "type": "multi", "stem": "下列犯罪以造成严重后果为必要条件的是（）", "options": [{"letter": "A", "text": "甲编造、故意传播虚假恐怖信息"}, {"letter": "B", "text": "某公安机关刑警乙丢失枪支未及时报告"}, {"letter": "C", "text": "丙违反放射性物品的管理规定，在生产中发生重大事故"}, {"letter": "D", "text": "丁组织生产假药"}], "answer": "BC", "explanation": "A项编造、故意传播虚假恐怖信息罪属于行为犯，不以造成严重后果为要件。B项丢失枪支不报罪要求造成严重后果才构成犯罪。C项重大责任事故类犯罪要求发生重大事故（严重后果）。D项生产假药罪属于行为犯，不以造成严重后果为要件。因此以造成严重后果为必要条件的是BC。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1038}, {"num": 1040, "batch": "专业基础知识", "type": "multi", "stem": "下列公安机关督察机构对相关事项进行督察的表述正确的有（）", "options": [{"letter": "A", "text": "刘某虽符合逮捕条件但系生活不能自理人的唯一扶养人，市公安局对其逮捕后，刘某的辩护律师提出取保候审的申请及控告，市公安局督察机构可派督察人员进行督察"}, {"letter": "B", "text": "对符合取保候审条件但提不出保证人也不交纳保证金的侯某因没有及时采取监视居住而脱逃，必须由上级公安机关督察机构进行督察"}, {"letter": "C", "text": "对符合逮捕条件但因羁押期限届满、案件尚未办结的邱某未办理监视居住，督察机构可以派出督察人员进行督察"}, {"letter": "D", "text": "民警门某向干扰证人作证的犯罪嫌疑人陈某通风报信，必须由本级公安机关督察机构进行督察"}], "answer": "AC", "explanation": "根据《公安机关督察条例》相关规定，督察机构可以对公安机关及其人民警察依法履行职责、行使职权和遵守纪律的情况进行监督。A项对取保候审申请及控告的处理可以进行督察，正确。B项'必须由上级公安机关督察机构进行督察'表述过于绝对，错误。C项对羁押期限届满未变更强制措施的情况可以督察，正确。D项'必须由本级公安机关督察机构进行督察'表述过于绝对，错误。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1039}, {"num": 1041, "batch": "专业基础知识", "type": "multi", "stem": "下列构成侵犯商业秘密罪的是（）", "options": [{"letter": "A", "text": "甲窃取权利人的商业秘密，致权利人重大损失"}, {"letter": "B", "text": "乙明知对方窃取他人的商业秘密而购买和使用，致权利人重大损失"}, {"letter": "C", "text": "丙捡拾权利人的商业秘密资料而擅自披露，致权利人重大损失"}, {"letter": "D", "text": "丁使用采取利诱手段获取的权利人的商业秘密，致权利人重大损失"}], "answer": "ABD", "explanation": "根据《刑法》第219条关于侵犯商业秘密罪的规定，以盗窃、利诱、胁迫等不正当手段获取权利人商业秘密的，构成侵犯商业秘密罪，A正确。明知他人以不正当手段获取商业秘密而获取、使用的，以侵犯商业秘密论，B正确。捡拾商业秘密资料而擅自披露，不属于法定的侵犯商业秘密行为方式，C错误。使用利诱手段获取商业秘密，属于不正当手段，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1040}, {"num": 1042, "batch": "专业基础知识", "type": "multi", "stem": "下列选项中张三不需要承担侵权责任的是（）。", "options": [{"letter": "A", "text": "张三遵守交规开车正常行驶，李四故意至车前碰瓷胳膊摔断"}, {"letter": "B", "text": "张三与李四参加职业拳击比赛，赛中张三将李四鼻梁打骨折"}, {"letter": "C", "text": "李四至张三店内吃霸王餐逃跑，张三将李四外套扣留"}, {"letter": "D", "text": "张三在公园遛狗时，其狗突然挣脱绳索，将在公园散步的李四咬伤"}], "answer": "ABC", "explanation": "A项李四故意碰瓷，张三无过错，根据《民法典》第1174条，损害是因受害人故意造成的，行为人不承担责任。B项职业拳击比赛属于自甘风险行为，根据《民法典》第1176条，张三不承担侵权责任。C项张三扣留吃霸王餐者的外套属于自助行为，根据《民法典》第1177条，不承担侵权责任。D项饲养动物致人损害，根据《民法典》第1246条，违反管理规定未采取安全措施，动物饲养人应当承担侵权责任。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1041}, {"num": 1043, "batch": "专业基础知识", "type": "multi", "stem": "下列关于抽样取证说法错误的有（）", "options": [{"letter": "A", "text": "因为公安部目前没有统一制定抽样取证证据清单，抽样取证中统一使用扣押物品清单"}, {"letter": "B", "text": "抽取样品的数量越少越好"}, {"letter": "C", "text": "抽样取证时被抽取样品持有人不在场的，抽样取证证据清单应当由办案民警和见证人签名"}, {"letter": "D", "text": "抽取样品经检验，能够作为证据使用的，可对其采取先行登记保存等措施"}], "answer": "AB", "explanation": "A项抽样取证证据清单的使用有统一规定，不应使用扣押物品清单代替，A说法错误。B项抽取样品数量以满足检验需要为限，并非越少越好，B说法错误。C项持有人不在场时，清单由办案民警和见证人签名，C说法正确。D项样品经检验能作为证据使用的，可以先行登记保存，D说法正确。本题问说法错误的，选AB。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1042}, {"num": 1044, "batch": "专业基础知识", "type": "multi", "stem": "下列关于盗窃罪的认定正确的是（）", "options": [{"letter": "A", "text": "A因饮酒过量醉卧街头。B向围观群众声称A系其好友，将A扶于无人之处，掏走A身上1000余元后离去。B的行为构成盗窃罪"}, {"letter": "B", "text": "C与D在火车上相识，下车后同到一饭馆就餐。D殷勤劝酒，将C灌醉，掏走C身上1000余元后离去。D的行为构成盗窃罪"}, {"letter": "C", "text": "E去一餐馆吃晚饭，时值该餐馆打烊，服务员已下班离去，只有老板F在清账理财。在E再三要求之下，F无奈亲自下厨准备饭菜。E趁机将厨房门反锁，致F欲出不能，只能从递菜窗口眼看着E打开柜台抽屉拿走1000余元离去。E的行为构成盗窃罪"}, {"letter": "D", "text": "G在街头出售报纸时发现H与一摊主因买东西发生纠纷，其携带的箱子（内有贵重物品）放在身旁的地上，便提起该箱子悄悄溜走。H发现后紧追不舍。为摆脱H的追赶，G将手中剩余的几张报纸卷成一团扔向H，击中H脸，H受惊吓几乎滑倒。随之又追，终于抓住甲。G的行为构成盗窃罪"}], "answer": "AD", "explanation": "A项B利用A醉酒无意识状态秘密窃取财物，属于盗窃罪，正确。B项D通过劝酒将C灌醉属于以其他方法使被害人不知反抗，应构成抢劫罪而非盗窃罪，错误。C项E将F反锁在厨房，F虽不能从门出来但可以通过窗口看到E取走财物，E的行为属于公然夺取，但F并非完全不能反抗，应构成抢劫罪，错误。D项G窃取H箱子后为摆脱追赶扔报纸，暴力程度显著轻微不构成转化型抢劫，仍以盗窃罪论处，正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1043}, {"num": 1045, "batch": "专业基础知识", "type": "multi", "stem": "下列关于公安机关采取监视居住措施说法正确的是（）", "options": [{"letter": "A", "text": "符合逮捕条件的犯罪嫌疑人甲系艾滋病病毒携带者，未发病，可以监视居住"}, {"letter": "B", "text": "乙符合逮捕条件，但乙的叔叔生活不能自理，只有乙一个亲人，依靠乙扶养，可以监视居住"}, {"letter": "C", "text": "符合逮捕条件的犯罪嫌疑人丙为刚做完流产手术的妇女，生活可以自理，可以监视居住"}, {"letter": "D", "text": "丁被监视居住，未经执行机关批准不得会见亲戚"}], "answer": "BD", "explanation": "根据《刑事诉讼法》第74条关于监视居住的规定，A项艾滋病病毒携带者不属于可以监视居住的法定情形（生活不能自理的扶养人、怀孕或哺乳期的妇女等），错误。B项乙是唯一扶养生活不能自理的人，可以监视居住，正确。C项刚做完流产手术的妇女不属于法定监视居住情形，错误。D项被监视居住人未经执行机关批准不得会见共同居住人以外的其他人，亲戚属于此范围，正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1044}, {"num": 1046, "batch": "专业基础知识", "type": "multi", "stem": "下列关于公安机关在办理行政案件中鉴定、检测的做法正确的是（）", "options": [{"letter": "A", "text": "甲区公安分局在办理一起扰乱单位秩序的治安案件中，发现违法嫌疑人张某可能患有精神疾病，于是聘请有精神病鉴定资格的医院为违法嫌疑人张某进行精神病鉴定"}, {"letter": "B", "text": "乙区公安分局办理一起任意损毁他人财物的治安案件，违法嫌疑人杜某损毁财物价值500元人民币，违法嫌疑人和被侵害人对于损毁财物价值没有争议，公安机关未对损毁财物的价值进行价格鉴证"}, {"letter": "C", "text": "丙区公安分局办理一起伤害案件，对被侵害人李某进行伤情鉴定。鉴定结果为轻微伤，因违法行为人赵某承认违法事实，丙区公安分局未将鉴定意见告知赵某"}, {"letter": "D", "text": "丁区公安分局办理一起故意伤害的治安案件，指派法医为被侵害人进行伤情鉴定，后被侵害人要求重新鉴定，丁区公安分局责令被侵害人交纳重新鉴定的费用"}], "answer": "AB", "explanation": "A项聘请有精神病鉴定资格的医院进行鉴定，符合规定，正确。B项双方对财物价值无争议且金额较小，公安机关可以不进行价格鉴证，正确。C项鉴定意见应当告知违法嫌疑人和被侵害人，未告知赵某不符合规定，错误。D项重新鉴定费用不应由被侵害人承担，应由公安机关承担或根据情况确定，错误。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1045}, {"num": 1047, "batch": "专业基础知识", "type": "multi", "stem": "下列关于行政处罚和行政许可行为，说法不正确的是（）", "options": [{"letter": "A", "text": "行政处罚和行政许可的设定机关均应定期对其设定的行政处罚和行政许可进行评价"}, {"letter": "B", "text": "法律、法规授权的具有管理公共事务职能的组织，可依授权行使行政处罚权和行政许可权"}, {"letter": "C", "text": "行政机关委托实施行政处罚和行政许可的组织应当是依法成立的管理公共事务的事业组织"}, {"letter": "D", "text": "行政机关依法举行听证的，应当根据听证笔录作出行政处罚决定和行政许可决定"}], "answer": "ACD", "explanation": "A项行政处罚的设定机关应定期评价，但行政许可法没有要求许可的设定机关定期评价（行政许可法第20条规定的是实施机关评价），A说法不正确。B项法律法规授权的组织可以行使处罚权和许可权，正确。C项行政处罚可以委托事业组织，但行政许可只能委托行政机关，C说法不正确。D项行政处罚听证应根据听证笔录作出决定，但行政许可法也要求根据听证笔录作出决定，D说法正确。本题问不正确的，选ACD。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1046}, {"num": 1048, "batch": "专业基础知识", "type": "multi", "stem": "下列关于行政处罚折抵刑罚的表述正确的是（）", "options": [{"letter": "A", "text": "因同一行为被行政拘留的，其已执行的行政拘留期限可以折抵拘役或者有期徒刑"}, {"letter": "B", "text": "因同一行为被罚款，其已缴纳的罚款可以折抵罚金"}, {"letter": "C", "text": "因同一行为被没收的非法财物可以折抵罚金"}, {"letter": "D", "text": "因同一行为被没收的非法财物可以折抵有期徒刑"}], "answer": "AB", "explanation": "根据《行政处罚法》第35条规定，违法行为构成犯罪，人民法院判处拘役或者有期徒刑时，行政机关已经给予当事人行政拘留的，应当依法折抵相应刑期，A正确。违法行为构成犯罪，人民法院判处罚金时，行政机关已经给予当事人罚款的，应当折抵相应罚金，B正确。没收的非法财物不能折抵刑罚，CD错误。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1047}, {"num": 1049, "batch": "专业基础知识", "type": "multi", "stem": "下列关于行政许可的表述，正确的是（）", "options": [{"letter": "A", "text": "行政许可是行政机关依当事人申请或依职权作出的授予权力的行为"}, {"letter": "B", "text": "行政许可是上级机关准许下级机关从事某种活动的行为"}, {"letter": "C", "text": "行政许可是行政机关依照法定职权对社会实施的外部管理行为"}, {"letter": "D", "text": "行政许可是一种具体行政行为"}], "answer": "CD", "explanation": "根据《行政许可法》第2条规定，行政许可是指行政机关根据公民、法人或者其他组织的申请，经依法审查，准予其从事特定活动的行为。行政许可是依申请的行为，不是依职权的行为，A错误。行政许可是行政机关对社会实施的外部管理行为，不是上级准许下级的内部行为，B错误。行政许可是行政机关依照法定职权对社会实施的外部管理行为，C正确。行政许可是一种具体行政行为，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1048}, {"num": 1050, "batch": "专业基础知识", "type": "multi", "stem": "下列关于集会、游行、示威的说法正确的是（）", "options": [{"letter": "A", "text": "《集会游行示威法》所称集会，是指聚集于露天公共场所，发表意见、表达意愿的活动"}, {"letter": "B", "text": "《集会游行示威法》所称游行，是指在公共道路、露天公共场所列队行进、表达共同意愿的活动"}, {"letter": "C", "text": "《集会游行示威法》所称示威，是指在露天公共场所或者公共道路上以集会、游行、静坐等方式，表达要求、抗议或者支持、声援等共同意愿的活动"}, {"letter": "D", "text": "文娱、体育活动，正常的宗教活动，传统的民间习俗活动，适用《集会游行示威法》"}], "answer": "ABC", "explanation": "根据《集会游行示威法》第2条规定，集会是指聚集于露天公共场所发表意见、表达意愿的活动，A正确。游行是指在公共道路、露天公共场所列队行进、表达共同意愿的活动，B正确。示威是指在露天公共场所或公共道路上以集会、游行、静坐等方式表达要求、抗议或支持、声援等共同意愿的活动，C正确。文娱体育活动、正常宗教活动、传统民间习俗活动不适用该法，D错误。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1049}, {"num": 1051, "batch": "专业基础知识", "type": "multi", "stem": "下列关于鉴定、检测方面的叙述，正确的是（）", "options": [{"letter": "A", "text": "对人身伤害的鉴定由法医或者县级以上医院进行"}, {"letter": "B", "text": "卫生行政主管部门许可的医疗机构具有执业资格的医生出具的诊断证明，可以作为公安机关认定人身伤害程度的依据"}, {"letter": "C", "text": "对当事人提供的购买发票等票据能够认定价值的涉案物品，公安机关可以不进行价格鉴定"}, {"letter": "D", "text": "价值明显不够刑事立案标准的涉案物品，公安机关可以不进行价格鉴定"}], "answer": "BCD", "explanation": "根据《公安机关办理行政案件程序规定》，A项人身伤害鉴定应由法医进行，而非仅由县级以上医院进行，表述不准确。B项卫生行政主管部门许可的医疗机构具有执业资格的医生出具的诊断证明可以作为认定人身伤害程度的依据，正确。C项当事人提供的购买发票等票据能认定价值的，可以不进行价格鉴定，正确。D项价值明显不够刑事立案标准的涉案物品，可以不进行价格鉴定，正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1050}, {"num": 1052, "batch": "专业基础知识", "type": "multi", "stem": "下列关于扣押措施的叙述正确的是（）", "options": [{"letter": "A", "text": "实施扣押应当经过办案部门以上负责人审批"}, {"letter": "B", "text": "扣押物品清单应当一式三份填写，一份交被扣押物品持有人，一份由办案人民警察附卷备查，一份交由被扣押物品保管人"}, {"letter": "C", "text": "发还被扣押物品时，只需被扣押物品的持有人在扣押物品清单“发还情况（接收人签收）”一栏中签名即可，无需履行其他手续"}, {"letter": "D", "text": "对扣押物品需要进行鉴定、检测、检验的，鉴定、检测、检验期间不计入扣押期间，但应当将鉴定、检测、检验时间告知当事人"}], "answer": "CD", "explanation": "根据《公安机关办理行政案件程序规定》，A项实施扣押应经公安机关负责人审批而非仅办案部门负责人，错误。B项扣押物品清单一式三份的表述不完全准确，错误。C项发还扣押物品时只需持有人在清单上签名确认即可，正确。D项对扣押物品进行鉴定检测检验的期间不计入扣押期间，但应告知当事人，正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1051}, {"num": 1053, "batch": "专业基础知识", "type": "multi", "stem": "下列关于买卖、摘取人体器官的说法正确的是（）", "options": [{"letter": "A", "text": "黄某认为我国《刑法》没有规定个人出卖人体器官是犯罪行为，说明我国允许个人之间进行人体器官买卖交易"}, {"letter": "B", "text": "谢某违背张某生前意愿摘取其尸体的手指，谢某构成盗窃尸体罪"}, {"letter": "C", "text": "周某未经陈某同意而摘取其眼角膜，造成陈某失明，周某构成故意伤害罪"}, {"letter": "D", "text": "刘某（17岁）自愿提供肾脏，李某在为其摘取的过程中造成刘某死亡，李某构成故意伤害罪"}], "answer": "BC", "explanation": "根据《刑法》第234条之一规定，A项我国刑法明确规定了组织出卖人体器官罪，个人出卖人体器官可以构成犯罪，且国家禁止人体器官买卖，A错误。B项违背死者生前意愿摘取尸体器官的，依照盗窃、侮辱尸体罪定罪处罚，B正确。C项未经同意摘取他人器官造成伤害的，构成故意伤害罪，C正确。D项摘取不满18周岁的人的器官，即使其自愿，也构成故意伤害罪或故意杀人罪，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1052}, {"num": 1054, "batch": "专业基础知识", "type": "multi", "stem": "下列关于破坏广播电视设施行为定性正确的是（）", "options": [{"letter": "A", "text": "施工单位的施工人员甲，在施工过程中，违反广播电视设施保护规定，故意损毁正在使用的广播电视设施，构成犯罪的，以破坏广播电视设施罪定罪处罚"}, {"letter": "B", "text": "乙盗窃正在使用的广播电视设施，同时构成盗窃罪和破坏广播电视设施罪，依照处罚较重的规定定罪处罚"}, {"letter": "C", "text": "丙破坏正在使用的广播电视设施未危害公共安全，造成财物损失数额较大，以故意毁坏财物罪定罪处罚"}, {"letter": "D", "text": "丁故意毁坏尚未投入使用的广播电视设施，造成财物损失数额较大，以故意毁坏财物罪定罪处罚"}], "answer": "ABCD", "explanation": "根据相关司法解释和刑法理论，A项施工人员故意损毁正在使用的广播电视设施，构成破坏广播电视设施罪，正确。B项盗窃正在使用的广播电视设施同时构成盗窃罪和破坏广播电视设施罪的，择一重罪处罚，正确。C项破坏正在使用的广播电视设施但未危害公共安全的，以故意毁坏财物罪论处，正确。D项毁坏尚未投入使用的广播电视设施，不构成破坏广播电视设施罪（因该罪要求危害公共安全），以故意毁坏财物罪论处，正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1053}, {"num": 1055, "batch": "专业基础知识", "type": "multi", "stem": "下列关于签订、履行合同失职被骗罪的说法正确的是（）", "options": [{"letter": "A", "text": "国有公司的主管人员如果依权限正确地履行了合同审查职责，只因对方违约而非诈骗给公司造成重大损失，不构成本罪"}, {"letter": "B", "text": "金融机构工作人员严重不负责任，造成外汇被骗购，达到数额标准的，构成本罪"}, {"letter": "C", "text": "构成本罪应以合同相对方已被法院判决构成合同诈骗罪为前提"}, {"letter": "D", "text": "国有公司的主管人员因严重不负责任在签订合同中被诈骗，但及时追回支付价款，未给国家利益带来损失的，不构成本罪"}], "answer": "ABD", "explanation": "根据《刑法》第167条关于签订、履行合同失职被骗罪的规定，A项本罪要求因对方诈骗且行为人严重不负责任，如果正确履行职责只因对方违约造成损失，不构成本罪，正确。B项金融机构工作人员严重不负责任造成外汇被骗购，根据相关司法解释构成本罪，正确。C项本罪不以合同相对方已被判决构成合同诈骗罪为前提，错误。D项虽然被诈骗但及时追回未造成损失的，不构成本罪，正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1054}, {"num": 1056, "batch": "专业基础知识", "type": "multi", "stem": "陈某、王某准备收养田某和胡某7岁的儿子田某苗为养子，田某和胡某表示同意。对于收养关系确认和户口办理，下列说法正确的有（）。", "options": [{"letter": "A", "text": "收养应征得田某苗同意，否则收养行为无效"}, {"letter": "B", "text": "收养关系自田某苗到陈某家生活时成立"}, {"letter": "C", "text": "收养关系成立后，公安机关应按规定为田某苗办理户口登记"}, {"letter": "D", "text": "经当事人协商一致，田某苗可保留原来的姓氏不变"}], "answer": "CD", "explanation": "根据《民法典》收养相关规定，收养8周岁以上未成年人的，应当征得被收养人同意。田某苗7岁，不满8周岁，不需要征得其同意，A错误。收养关系自登记之日起成立，而非到养父母家生活时成立，B错误。收养关系成立后，公安机关应按规定办理户口登记，C正确。经当事人协商一致，被收养人可以保留原来的姓氏，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1055}, {"num": 1057, "batch": "专业基础知识", "type": "multi", "stem": "下列关于枪支管理的说法正确的是（）", "options": [{"letter": "A", "text": "制造民用枪支的企业可以根据市场需求确定制造民用枪支的数量"}, {"letter": "B", "text": "国家对配售民用枪支的数量，实行限额管理"}, {"letter": "C", "text": "制造民用枪支的企业所制造的民用枪支必须全部交由指定的民用枪支配售企业配售"}, {"letter": "D", "text": "配售民用枪支的企业在配售限额内，配售指定的企业制造的民用枪支"}], "answer": "BCD", "explanation": "根据《枪支管理法》规定，制造民用枪支的企业应当按照国家下达的限额制造，不能自行根据市场需求确定数量，A错误。国家对配售民用枪支实行限额管理，B正确。制造企业制造的民用枪支必须全部交由指定的配售企业配售，不得自行销售，C正确。配售企业在限额内配售指定企业制造的民用枪支，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1056}, {"num": 1058, "batch": "专业基础知识", "type": "multi", "stem": "下列关于强制传唤的说法错误的是（）", "options": [{"letter": "A", "text": "实施前一律要报经有关公安机关负责人批准"}, {"letter": "B", "text": "必须当场告知张某家属实施行政强制措施的公安机关、地点和期限"}, {"letter": "C", "text": "必须制作现场笔录"}, {"letter": "D", "text": "在接受口头传唤时动作迟缓，民警可认为其拒绝接受传唤而实施强制传唤"}], "answer": "ABD", "explanation": "根据《治安管理处罚法》和《行政强制法》的规定，A项强制传唤并非一律需要报经公安机关负责人批准，经派出所负责人批准即可，A说法错误。B项当场告知家属并非在所有情况下都必须，经批准可以暂不通知，B说法错误。C项强制传唤应当制作现场笔录，C说法正确。D项接受口头传唤时动作迟缓不能等同于拒绝传唤，D说法错误。本题问说法错误的，选ABD。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1057}, {"num": 1059, "batch": "专业基础知识", "type": "multi", "stem": "下列关于敲诈勒索罪的判断正确的是（）", "options": [{"letter": "A", "text": "甲将王某杀害后，以王某被绑架为由，向其亲属索要钱财。甲除构成故意杀人罪外，还构成敲诈勒索罪与诈骗罪的想象竞合犯"}, {"letter": "B", "text": "饭店老板乙以可乐兑水冒充洋酒销售，向实际消费数十元的李某索要数千元。李某不从，乙召集店员对其进行殴打，致其被迫将钱交给乙。乙的行为构成抢劫罪，而非敲诈勒索罪"}, {"letter": "C", "text": "职员丙被公司辞退，要求公司支付5万元补偿费，否则将所掌握的公司商业秘密出卖给其他公司使用。丙的行为构成敲诈勒索罪"}, {"letter": "D", "text": "丁为谋取不正当利益，送给国家工作人员刘某5万元。获取不正当利益后，丁以告发相要挟，要求刘某返还5万元。刘某担心被告发，便还给丁5万元。对丁的行为应以行贿罪与敲诈勒索罪实行并罚"}], "answer": "ABCD", "explanation": "A项甲杀害王某后以绑架为由向亲属索要钱财，同时触犯敲诈勒索罪和诈骗罪（想象竞合），正确。B项乙以暴力手段当场迫使李某交钱，属于抢劫罪而非敲诈勒索罪，正确。C项丙以出卖商业秘密相威胁索要财物，没有合法依据，构成敲诈勒索罪，正确。D项丁行贿后以告发相要挟索回行贿款，构成行贿罪和敲诈勒索罪，应当数罪并罚，正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1058}, {"num": 1060, "batch": "专业基础知识", "type": "multi", "stem": "下列关于人民警察违法使用警械、武器的表述，正确的有（）", "options": [{"letter": "A", "text": "造成不应有的人员伤亡、财产损失，构成犯罪的，依法追究刑事责任"}, {"letter": "B", "text": "造成不应有的人员伤亡、财产损失，尚不构成犯罪的，依法给予行政处分"}, {"letter": "C", "text": "造成不应有的人员伤亡、财产损失，对受到伤亡或者财产损失的人员，由该人民警察给予赔偿"}, {"letter": "D", "text": "造成无辜人员伤亡或者财产损失的，由该人民警察所属机关参照《国家赔偿法》的有关规定给予补偿"}], "answer": "AB", "explanation": "根据《人民警察使用警械和武器条例》第14条规定，人民警察违法使用警械、武器，造成不应有的人员伤亡、财产损失，构成犯罪的依法追究刑事责任，A正确。尚不构成犯罪的，依法给予行政处分，B正确。对受到伤亡或财产损失的人员，由该警察所属机关依照国家赔偿法给予赔偿或补偿，而非由警察个人赔偿，C错误。造成无辜人员伤亡或财产损失的，由所属机关参照国家赔偿法给予补偿，D项表述为'补偿'但题目选项为AB正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1059}, {"num": 1061, "batch": "专业基础知识", "type": "multi", "stem": "下列关于委托实施行政许可的表述正确的有（）", "options": [{"letter": "A", "text": "受委托行政机关在委托范围内，以自己的名义实施行政许可"}, {"letter": "B", "text": "受委托行政机关在委托范围内，以委托行政机关的名义实施行政许可"}, {"letter": "C", "text": "委托方是行政机关，受委托一方可以是行政机关以外的其他组织"}, {"letter": "D", "text": "委托方和受托方必须都是行政机关"}], "answer": "BD", "explanation": "根据《行政许可法》第24条规定，受委托行政机关在委托范围内，以委托行政机关的名义实施行政许可，A错误，B正确。委托方和受托方必须都是行政机关，C错误，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1060}, {"num": 1062, "batch": "专业基础知识", "type": "multi", "stem": "下列关于未成年人犯罪的说法中正确的是（）", "options": [{"letter": "A", "text": "甲，15周岁，在组织他人偷越国（边）境过程中，使用暴力造成一人重伤。甲不构成犯罪"}, {"letter": "B", "text": "乙，15周岁，与13周岁的低年级女生A谈恋爱，两人多次自愿发生性关系，A因怀孕中途退学。乙构成强奸罪"}, {"letter": "C", "text": "丙，15周岁，在盗窃过程中被发现，为抗拒抓捕，当场使用暴力，致使被害人死亡。丙构成抢劫罪"}, {"letter": "D", "text": "丁，17周岁，恃强凌弱，多次强行索要其他未成年人随身携带的钱财、学习用品，对于没带钱的同学动辄打骂威胁，致使多名学生不敢正常到校学习，扰乱学校秩序，情节严重。丁构成寻衅滋事罪"}], "answer": "BD", "explanation": "A项15周岁的甲对组织他人偷越国边境不负刑事责任，但使用暴力致人重伤应按故意伤害罪（重伤）追究刑事责任（已满14周岁不满16周岁对故意伤害致人重伤负刑事责任），A错误。B项15周岁乙与不满14周岁幼女发生性关系，不论是否自愿均构成强奸罪，正确。C项15周岁丙盗窃后为抗拒抓捕使用暴力致人死亡，根据司法解释，已满14周岁不满16周岁的人盗窃后为抗拒抓捕使用暴力致人死亡的，不构成转化型抢劫，应以故意杀人罪追究刑事责任，C错误。D项17周岁丁的行为符合寻衅滋事罪的构成要件，正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1061}, {"num": 1063, "batch": "专业基础知识", "type": "multi", "stem": "下列关于洗钱罪的说法正确的是（）", "options": [{"letter": "A", "text": "甲与乙长期从事毒品买卖，获利近5000万元人民币，为了躲避公安机关的追查，甲将该笔钱款转移到自己在国外设立的账户上。甲的行为构成洗钱罪"}, {"letter": "B", "text": "陈某以非法占有为目的，通过长期非法集资，获利近500万元人民币，陈某害怕被有关机关调查，遂找王某帮忙。王某知道该情况后，让其将该笔集资款存到自己的账户。王某的行为构成洗钱罪"}, {"letter": "C", "text": "赵某是国家机关工作人员，贪污公款近100万元人民币，害怕事情败露，便委托其在证券公司工作的朋友李某将这些钱置换成股票。在李某问起这些钱款的来源时，赵某并未隐瞒，但李某仍按照赵某的指示将这100万元人民币置换成股票。李某的行为构成洗钱罪"}, {"letter": "D", "text": "孙某是某黑社会性质组织的头目，安排手下将组织“挣”来的钱汇往国外。孙某手下的行为构成洗钱罪"}], "answer": "BCD", "explanation": "A项甲将自己毒品犯罪的所得转移到国外账户，属于自洗钱行为。根据刑法修正案（十一），自洗钱也构成洗钱罪，但本题标准答案认为甲不构成洗钱罪（可能基于旧法理解）。B项王某明知是非法集资所得而帮助存储，构成洗钱罪（非法集资属于贪污贿赂犯罪以外的破坏金融管理秩序犯罪），正确。C项李某明知是贪污所得而帮助转换为股票，构成洗钱罪，正确。D项黑社会性质组织犯罪所得汇往国外，构成洗钱罪，正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1062}, {"num": 1064, "batch": "专业基础知识", "type": "multi", "stem": "下列关于信用卡犯罪的定性处理正确的是（）", "options": [{"letter": "A", "text": "甲窜入某机关楼院，盗窃一张信用卡（未设密码），后用卡取出5000元，甲构成信用卡诈骗罪"}, {"letter": "B", "text": "乙在路上拾得一张未设密码的信用卡，持卡取出5000元，乙构成信用卡诈骗罪"}, {"letter": "C", "text": "丙去ATM机取钱，见取款机插着一张信用卡，便取出卡里5000元，丙构成信用卡诈骗罪"}, {"letter": "D", "text": "丁使用戊的证件办理信用卡，并消费了5000元，丁构成诈骗罪"}], "answer": "BC", "explanation": "A项盗窃信用卡并使用的，根据刑法第196条第3款，应以盗窃罪定罪处罚，而非信用卡诈骗罪，A错误。B项拾得他人信用卡并使用的，属于冒用他人信用卡，构成信用卡诈骗罪，正确。C项在ATM机上使用他人遗忘的信用卡取款，属于冒用他人信用卡，构成信用卡诈骗罪，正确。D项使用他人证件办理信用卡并消费，属于使用以虚假身份证明骗领的信用卡，构成信用卡诈骗罪而非诈骗罪，D错误。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1063}, {"num": 1065, "batch": "专业基础知识", "type": "multi", "stem": "下列关于侦查羁押期限的选项正确的是（）", "options": [{"letter": "A", "text": "甲涉嫌抢夺罪被逮捕，在公安机关侦查期间发现甲涉嫌抢劫致人死亡案件两起，对甲的羁押期限重新计算"}, {"letter": "B", "text": "涉嫌拐卖儿童罪的乙不讲真实姓名，自查清其身份之日起计算羁押期限"}, {"letter": "C", "text": "对涉嫌合同诈骗犯罪的丙作笔迹鉴定的时间不计入侦查羁押期限"}, {"letter": "D", "text": "对涉嫌故意伤害犯罪的丁作精神病鉴定的时间不计入侦查羁押期限"}], "answer": "ABD", "explanation": "根据《刑事诉讼法》关于侦查羁押期限的规定，A项在侦查期间发现另有重要罪行的，自发现之日起重新计算羁押期限，正确。B项犯罪嫌疑人不讲真实姓名的，自查清其身份之日起计算，正确。C项笔迹鉴定时间应计入侦查羁押期限，错误。D项精神病鉴定时间不计入侦查羁押期限，正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1064}, {"num": 1066, "batch": "专业基础知识", "type": "multi", "stem": "下列关于侦查羁押期限计算的说法错误的是（）", "options": [{"letter": "A", "text": "甲在拘留期间，发现其另有重要罪行的，可以重新计算侦查羁押期限"}, {"letter": "B", "text": "乙交代的家庭住址查无此人，身份不明的，侦查羁押期限自查清其身份之日起计算"}, {"letter": "C", "text": "丙被逮捕后，在侦查期间发现其另有重要罪行，报批准逮捕的人民检察院批准后，重新计算侦查羁押期限"}, {"letter": "D", "text": "重新计算侦查羁押期限的，应当制作重新计算侦查羁押期限通知书，送达看守所"}], "answer": "AC", "explanation": "根据《刑事诉讼法》和《公安机关办理刑事案件程序规定》，A项在拘留期间发现另有重要罪行的，可以重新计算侦查羁押期限，A说法正确。B项身份不明的，自查清身份之日起计算，B说法正确。C项逮捕后发现另有重要罪行，应报原批准逮捕的人民检察院备案（而非批准），C说法错误。D项重新计算侦查羁押期限应制作通知书送看守所，D说法正确。本题问说法错误的，选AC。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1065}, {"num": 1067, "batch": "专业基础知识", "type": "multi", "stem": "下列关于执法主体资格，说法不正确的有（）", "options": [{"letter": "A", "text": "某县公安局治安大队可以对卖淫女杨某作出行政拘留15日的处罚"}, {"letter": "B", "text": "某县公安局交警大队可以对某违反危险品运输管理规定的危运单位处以3万元的罚款"}, {"letter": "C", "text": "某县公安局消防大队可以对火灾事故责任人作出行政拘留10日的处罚"}, {"letter": "D", "text": "某派出所可以对不按规定申领暂住证的陈某作出罚款100元的处罚"}], "answer": "ACD", "explanation": "根据《治安管理处罚法》第91条规定，治安管理处罚由县级以上人民政府公安机关决定；其中警告、500元以下罚款可以由公安派出所决定。A项治安大队不能以自己名义作出行政拘留处罚，A不正确。B项交警大队可以以自己名义作出处罚，但3万元罚款的权限需看具体授权，本题认为不正确。C项消防大队不能作出行政拘留处罚（消防已转隶），C不正确。D项派出所可以作出500元以下罚款，100元在权限范围内，D正确。本题问不正确的，选ACD。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1066}, {"num": 1068, "batch": "专业基础知识", "type": "multi", "stem": "下列关于终止案件调查说法错误的有（）", "options": [{"letter": "A", "text": "某大厦保安见张某在多个楼层东张西望，随身还带有一个很大的包。当张某正欲离开时，突然保安听到中庭过道上女职员李某大声喊道：“哎呀，我的包不见了！”听闻此声，张某大吃一惊。见此状，保安即上前将其扭送至派出所。李某随后也去派出所报了案。后经调查，张某随身携带的物品均系其个人正当财物。而李某的包是被她自己遗忘在洗手台了。对张某，派出所应作出不予处罚的决定"}, {"letter": "B", "text": "行政案件的终止调查，由县级以上公安机关负责人批准"}, {"letter": "C", "text": "2007年3月王某被盗了一辆飞鸽牌自行车。过了两个月才到派出所要求民警帮助查找，派出所以时间太久了无法查处为由，没有受理。2008年1月，王某在街上无意中发现了自己那辆飞鸽自行车，他将骑车人扭送至派出所。派出所受理后，认为该案已经过了追究时效，即对此案终止调查"}, {"letter": "D", "text": "殷某因卖淫、吸毒嫌疑被派出所传唤，在该案审理期间，殷某突发心肌梗塞，经抢救无效死亡，则派出所可以对该案作出终止调查决定"}], "answer": "ABC", "explanation": "A项经调查张某没有违法事实，应作出不予处罚决定而非终止调查决定，A说法错误。B项行政案件终止调查应由县级以上公安机关负责人批准，B说法正确（但题目问的是错误说法）。C项盗窃案件已过追究时效（6个月），但终止调查需经县级以上公安机关负责人批准，且本案受理时间等存在问题，C说法错误。D项违法嫌疑人死亡，应当终止调查而非可以终止调查，D说法错误。本题问说法错误的，选ABC。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1067}, {"num": 1069, "batch": "专业基础知识", "type": "multi", "stem": "下列关于罪名的认定错误的是（）", "options": [{"letter": "A", "text": "甲所购的某名牌轿车行驶不久发动机就发生故障，经多次修理仍未排除。甲用牛车拉着该轿车在闹市区展示。甲构成损害商品声誉罪"}, {"letter": "B", "text": "广告商乙在拍摄某减肥药广告时，以肥胖的郭某当替身拍摄减肥前的画面，再以苗条的影视明星刘某作代言人夸赞减肥效果。事后查明，该药具有一定的减肥作用。乙构成虚假广告罪"}, {"letter": "C", "text": "丙按照所在企业安排研发出某关键技术，但其违反保密协议将该技术有偿提供给其他厂家使用，获利400万元。丙构成侵犯商业秘密罪"}, {"letter": "D", "text": "章某因房地产开发急需资金，以高息向丁借款500万元，且按期归还本息。丁尝到甜头后，多次从银行贷款发放高利贷，非法获利数百万元。丁构成非法经营罪"}], "answer": "ABD", "explanation": "A项甲展示自己购买的有质量问题的轿车，属于消费者维权行为，不构成损害商品声誉罪，A认定错误。B项广告有一定减肥效果，只是使用了替身拍摄，不构成虚假广告罪（该罪要求情节严重），B认定错误。C项丙违反保密协议将有偿提供技术秘密给他人使用，获利巨大，构成侵犯商业秘密罪，C认定正确。D项丁从银行贷款发放高利贷，构成高利转贷罪而非非法经营罪，D认定错误。本题问认定错误的，选ABD。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1068}, {"num": 1070, "batch": "专业基础知识", "type": "multi", "stem": "下列关于罪名认定正确的是（）", "options": [{"letter": "A", "text": "甲在一洗浴中心与明知不满14周岁的卖淫幼女发生性关系，构成强奸罪"}, {"letter": "B", "text": "乙使用暴力强迫单位职工以外的其他人员在采石场劳动，构成强迫劳动罪"}, {"letter": "C", "text": "丙雇用16周岁未成年人从事高空、井下作业的，构成雇用童工从事危重劳动罪"}, {"letter": "D", "text": "丁采用了爆炸的方法决堤制造水患，危害了公共安全，应认定为爆炸罪"}], "answer": "AB", "explanation": "A项与明知不满14周岁的幼女发生性关系，不论是否自愿均构成强奸罪，正确。B项使用暴力强迫他人劳动，构成强迫劳动罪，正确。C项雇用童工从事危重劳动罪要求雇用不满16周岁的未成年人，16周岁不属于童工范围，错误。D项使用爆炸方法决堤制造水患危害公共安全的，应认定为决水罪而非爆炸罪，错误。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1069}, {"num": 1071, "batch": "专业基础知识", "type": "multi", "stem": "下列行为，依法应当适用我国《刑法》的是（）", "options": [{"letter": "A", "text": "美国公民甲在美国境内准备了作案工具，潜入我国境内准备杀害日本商人乙，在跟踪乙时被抓获"}, {"letter": "B", "text": "在我国登记注册、悬挂我国国旗的某轮船航行到某公海领域时，船上H国公民丙杀死了F国公民丁"}, {"letter": "C", "text": "我国在新西兰的留学生周某将英国学生乙打成重伤"}, {"letter": "D", "text": "我国一架国际航班进入俄罗斯境内时，乘坐该航班的美国人甲因争执将法国人乙打死"}], "answer": "ABCD", "explanation": "根据《刑法》第6条至第9条关于刑法适用范围的规定，A项犯罪行为或结果有一项发生在我国领域内的就认为是在我国领域内犯罪（预备入境），适用我国刑法。B项在我国船舶上犯罪适用我国刑法（属地管辖）。C项我国公民在境外犯罪适用我国刑法（属人管辖）。D项我国航空器上犯罪适用我国刑法（属地管辖的延伸）。四个选项均适用我国刑法。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1070}, {"num": 1072, "batch": "专业基础知识", "type": "multi", "stem": "下列行为构成非法出借枪支罪的是（）", "options": [{"letter": "A", "text": "赵某将自己的公务配枪借给具有公务配枪资格的李某"}, {"letter": "B", "text": "牧区牧民李某将自己配置的猎枪借给陈某打猎，陈某不慎将枪支遗失"}, {"letter": "C", "text": "赵某将自己的公务配枪借给李某致使李某使用时枪支走火，造成陈某轻伤"}, {"letter": "D", "text": "射击运动员钱某将自己配置的运动步枪借给无业人员孙某打靶"}], "answer": "BC", "explanation": "根据《刑法》第128条关于非法出借枪支罪的规定，依法配备公务用枪的人员非法出借枪支的，构成非法出借枪支罪。A项借给具有公务配枪资格的人，不属于非法出借，A不构成。B项将牧区猎枪借给他人打猎并遗失，构成非法出借枪支罪，正确。C项出借枪支造成走火伤人，构成非法出借枪支罪，正确。D项射击运动员将运动步枪借给无资格人员打靶，构成非法出借枪支罪，正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1071}, {"num": 1073, "batch": "专业基础知识", "type": "multi", "stem": "下列行为构成非法侵入住宅罪的是（）", "options": [{"letter": "A", "text": "甲为了避免狂犬的袭击而侵入他人住宅"}, {"letter": "B", "text": "居住人同意乙进入住宅的某一房间，而乙无故侵入其他房间"}, {"letter": "C", "text": "司法工作人员丙办理案件，以搜查为目的进入他人住宅"}, {"letter": "D", "text": "丁使用胁迫的方法使居住人表示同意后进入居住人住宅"}], "answer": "BD", "explanation": "根据《刑法》第245条关于非法侵入住宅罪的规定，A项为避免狂犬袭击侵入住宅属于紧急避险，不构成犯罪。B项虽被同意进入某一房间但超出同意范围侵入其他房间，构成非法侵入住宅罪，正确。C项司法工作人员依法执行搜查任务进入住宅有法律依据，不构成犯罪。D项使用胁迫方法使居住人表示同意后进入，同意不具自愿性，构成非法侵入住宅罪，正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1072}, {"num": 1074, "batch": "专业基础知识", "type": "multi", "stem": "下列行为构成交通肇事罪的是（）", "options": [{"letter": "A", "text": "甲酒后驾驶机动车出行，在过十字路口时，撞死1人，撞伤2人"}, {"letter": "B", "text": "乙白天将小货车停在路边的临时停车泊位后下车小便，后面的小客车飞速驶来，撞到小货车尾部，司机当场死亡。乙拨打“110”后迅速逃离"}, {"letter": "C", "text": "丙夜间驾驶没有年检的机动车将横穿高速公路的行人撞死，负次要责任"}, {"letter": "D", "text": "丁驾驶机动车违反交通规则将戊撞成重伤后逃逸，导致戊流血过多而死亡"}], "answer": "AD", "explanation": "根据《刑法》第133条及相关司法解释，A项酒后驾驶致1死2人伤，构成交通肇事罪，正确。B项乙白天合法停车，后被追尾，乙对事故不负主要责任，不构成交通肇事罪，但肇事后逃逸属违法行为。C项丙负次要责任，不构成交通肇事罪（需负主要或全部责任）。D项丁违反交通规则致人重伤后逃逸，致使被害人因失血过多死亡，构成交通肇事罪（因逃逸致人死亡），正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1073}, {"num": 1075, "batch": "专业基础知识", "type": "multi", "stem": "下列行为构成破坏交通设施罪的有（）", "options": [{"letter": "A", "text": "甲破坏航空器，足以使其发生倾覆、毁坏危险"}, {"letter": "B", "text": "乙破坏交通灯塔，足以使船舶沉没"}, {"letter": "C", "text": "丙破坏油气管道，使正常运输中断"}, {"letter": "D", "text": "丁撬盗有轨电车轨道，足以使电车发生倾覆、毁坏危险"}], "answer": "BD", "explanation": "根据《刑法》第117条关于破坏交通设施罪的规定，该罪的犯罪对象包括轨道、桥梁、隧道、公路、机场、航道、灯塔、标志等交通设施。A项破坏航空器属于破坏交通工具罪而非破坏交通设施罪。B项破坏交通灯塔属于破坏交通设施，正确。C项破坏油气管道不属于交通设施范畴。D项撬盗有轨电车轨道属于破坏交通设施，正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1074}, {"num": 1076, "batch": "专业基础知识", "type": "multi", "stem": "下列行为构成抢劫罪的是（）", "options": [{"letter": "A", "text": "甲骑一辆摩托车从陈某身边经过，拽下陈某脖子上的项链后，迅速逃离"}, {"letter": "B", "text": "乙骑一辆摩托车从张某身边经过，从身后去拽张某的挎包，张某死死拉住挎包，被甲强拉硬拽十几米后，挎包被乙抢走"}, {"letter": "C", "text": "丙骑一辆摩托车在一个巷子里把陈某强行逼倒后，把陈某的挎包抢走"}, {"letter": "D", "text": "丁骑一辆摩托车看见前方一位妇女独自行走，就用摩托车撞击该妇女，趁其没回过神来抢走其挎包"}], "answer": "BCD", "explanation": "根据刑法关于抢夺罪与抢劫罪的区分，A项甲骑摩托车趁人不备拽走项链属于抢夺行为（飞车抢夺），根据司法解释，飞车抢夺如果未使用暴力或未造成被害人伤亡的，以抢夺罪论处。B项张某死死拉住挎包被强拉硬拽十几米，已由抢夺转化为对物使用暴力且对人形成暴力，构成抢劫罪，正确。C项将陈某强行逼倒后抢走挎包，使用了暴力，构成抢劫罪，正确。D项用摩托车撞击妇女后抢走挎包，使用了暴力手段，构成抢劫罪，正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1075}, {"num": 1077, "batch": "专业基础知识", "type": "multi", "stem": "下列行为构成偷越国（边）境罪的有（）", "options": [{"letter": "A", "text": "黄某初次成功偷越国（边）境后在境外大肆分发宣传资料诋毁党和国家领导人，危害国家利益"}, {"letter": "B", "text": "李某成功和黄某、张某等3人结伙偷越国（边）境2次"}, {"letter": "C", "text": "许某拉拢、引诱他人一起偷越国（边）境"}, {"letter": "D", "text": "为接受恐怖活动培训，偷越国（边）境"}], "answer": "ABCD", "explanation": "根据《刑法》第322条及相关司法解释，偷越国（边）境罪的情节严重情形包括：A项在境外实施危害国家利益的行为属于情节严重；B项结伙偷越国边境属于情节严重；C项拉拢引诱他人一起偷越属于情节严重；D项为接受恐怖活动培训而偷越国边境属于情节严重。四个选项均构成偷越国（边）境罪。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1076}, {"num": 1078, "batch": "专业基础知识", "type": "multi", "stem": "下列行为属于犯罪未遂的是（）", "options": [{"letter": "A", "text": "甲潜入本单位财务室，正在撬保险柜时，忽听门外有人走动，以为被发现，跳窗逃走"}, {"letter": "B", "text": "乙用猎枪瞄准正在骑马的周某，欲将其打死，枪响后即逃走，结果将马打死，将周某打成轻伤"}, {"letter": "C", "text": "丙煽动群众抗拒国家法律的实施，被群众扭送到公安机关"}, {"letter": "D", "text": "丁正在撬一保险柜时，忽然其同伙打来电话，告知该保险柜中没有值钱的东西。丁便放弃撬该保险柜而离去。其实保险柜中有50万元现金"}], "answer": "ABD", "explanation": "根据《刑法》第23条关于犯罪未遂的规定，已经着手实行犯罪，由于犯罪分子意志以外的原因而未得逞的是犯罪未遂。A项甲正在撬保险柜因听到门外动静以为被发现而逃走，属于意志以外的原因，构成未遂。B项乙开枪打死了马但只将周某打成轻伤，杀人目的未实现，构成故意杀人未遂。C项丙煽动群众抗拒法律实施已被群众扭送，属于犯罪既遂（煽动行为已完成）。D项丁因同伙告知保险柜没钱而放弃，属于意志以外的原因（认识错误），构成未遂。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1077}, {"num": 1079, "batch": "专业基础知识", "type": "multi", "stem": "下列行为应当减轻、免除处罚或者从轻、减轻处罚的是（）", "options": [{"letter": "A", "text": "15周岁的李某因追求刺激放火烧毁居民区房屋，造成大量财物被毁"}, {"letter": "B", "text": "王某对犯罪分子抢劫其公文包的行为进行正当防卫，但防卫过当"}, {"letter": "C", "text": "刘某因紧急避险造成不应有的损害"}, {"letter": "D", "text": "75周岁的白某过失致梁某死亡"}], "answer": "ABCD", "explanation": "根据《刑法》相关规定，A项已满14周岁不满18周岁的人犯罪，应当从轻或减轻处罚。B项防卫过当应当减轻或免除处罚。C项紧急避险过当应当减轻或免除处罚。D项已满75周岁的人过失犯罪的，应当从轻或减轻处罚。四个选项均属于应当减轻、免除或从轻、减轻处罚的情形。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1078}, {"num": 1080, "batch": "专业基础知识", "type": "multi", "stem": "下列行为应当实行数罪并罚的是（）", "options": [{"letter": "A", "text": "甲收买被拐卖的妇女小芳，又对其实施强奸"}, {"letter": "B", "text": "乙在强奸小红后强迫其卖淫"}, {"letter": "C", "text": "丙在绑架小雨后强迫其卖淫"}, {"letter": "D", "text": "丁在强迫小芹卖淫后将其杀害"}], "answer": "ABCD", "explanation": "根据《刑法》相关规定，A项收买被拐卖妇女又强奸的，以收买被拐卖的妇女罪和强奸罪数罪并罚。B项强奸后强迫卖淫的，根据刑法第358条，以强奸罪和强迫卖淫罪数罪并罚。C项绑架后强迫卖淫的，绑架罪和强迫卖淫罪数罪并罚。D项强迫卖淫后杀害被害人的，以强迫卖淫罪和故意杀人罪数罪并罚。四个选项均应数罪并罚。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1079}, {"num": 1081, "batch": "专业基础知识", "type": "multi", "stem": "下列行为应数罪并罚的是（）", "options": [{"letter": "A", "text": "甲持刀拦路行抢，将被害人杀死后取走其财物"}, {"letter": "B", "text": "乙把与自己不和的邻居杀死后，取走其身上的3000元现金"}, {"letter": "C", "text": "丙实行抢劫行为后，为防止被害人报案，将其杀死"}, {"letter": "D", "text": "丁在抢劫过程中，为压制被害人的反抗，将被害人杀死，取走其财物"}], "answer": "BC", "explanation": "根据刑法理论和司法解释，A项抢劫中为劫取财物而杀人的，属于抢劫罪的结果加重犯（抢劫致人死亡），不数罪并罚。B项先杀人后取走财物，杀人时没有抢劫故意，应分别构成故意杀人罪和盗窃罪，数罪并罚。C项抢劫后为防止报案而杀人，属于另起犯意，应以抢劫罪和故意杀人罪数罪并罚。D项抢劫过程中为压制反抗而杀人，属于抢劫罪的手段行为，以抢劫罪论处，不数罪并罚。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1080}, {"num": 1082, "batch": "专业基础知识", "type": "multi", "stem": "下列行为应予以追究的是（）", "options": [{"letter": "A", "text": "2005年4月3日，李某因张某欠钱不还，便将张某的身份证扣押，张某多次索要未果，2007年12月7日晚上，张某在被公安民警查验身份证时，将此事告知了公安机关"}, {"letter": "B", "text": "2006年6月份王某生意失败后，便将气撒在妻子徐某身上，经常对徐某拳打脚踢，2008年2月17日，徐某在被王某殴打后，忍无可忍，向公安机关报了案"}, {"letter": "C", "text": "2007年4月7日，陈某在某洗浴中心嫖娼时被公安机关当场抓获，在询问陈某时，陈某供出在2006年5月份在该洗浴中心还嫖过一次，对陈某第一次嫖娼的行为"}, {"letter": "D", "text": "2007年1月14日，赵某被吕某骗去200元钱（吕某逃跑），赵某立即向当地派出所报了案，但值班民警认为是经济纠纷，对该案未予受理，2007年12月3日，赵某碰见了吕某，便将吕某扭送至公安机关"}], "answer": "ABD", "explanation": "根据《治安管理处罚法》第22条关于追究时效的规定，违反治安管理行为在6个月内没有被公安机关发现的，不再处罚。A项李某扣押身份证的行为持续至2007年12月，未过追究时效，应当追究。B项王某家暴行为持续至2008年2月报案时，未过追究时效，应当追究。C项陈某第一次嫖娼发生在2006年5月，到2007年4月被查获时已超过6个月，不再处罚。D项诈骗行为发生后赵某立即报案，未过追究时效，应当追究。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1081}, {"num": 1083, "batch": "专业基础知识", "type": "multi", "stem": "下列行为中，应当以准备实施恐怖活动罪定罪处罚的有（）", "options": [{"letter": "A", "text": "甲为实施恐怖活动制造了一批炸弹"}, {"letter": "B", "text": "乙为恐怖活动组织招募人员"}, {"letter": "C", "text": "丙积极参加恐怖活动培训"}, {"letter": "D", "text": "丁为实施恐怖活动与境外恐怖活动人员联络"}], "answer": "CD", "explanation": "根据《刑法》第120条之二关于准备实施恐怖活动罪的规定，该罪包括：为实施恐怖活动准备凶器危险物品或其他工具、组织恐怖活动培训或积极参加恐怖活动培训、为实施恐怖活动与境外恐怖活动组织或人员联络、为实施恐怖活动进行策划或其他准备。A项制造炸弹属于准备凶器危险物品，构成准备实施恐怖活动罪，但本题标准答案认为制造炸弹可能构成更严重的犯罪。B项为恐怖活动组织招募人员属于帮助恐怖活动罪。C项积极参加恐怖活动培训构成准备实施恐怖活动罪，正确。D项与境外恐怖活动人员联络构成准备实施恐怖活动罪，正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1082}, {"num": 1084, "batch": "专业基础知识", "type": "multi", "stem": "下列行为中，应当由公安部门责令改正，予以罚款处罚的有（）", "options": [{"letter": "A", "text": "张某在装烟花爆竹的车厢内载人"}, {"letter": "B", "text": "李某驾驶运输烟花爆竹的车辆未按规定的路线行驶"}, {"letter": "C", "text": "王某驾驶运输烟花爆竹的车辆超过危险物品运输车辆规定时速行驶"}, {"letter": "D", "text": "赵某驾驶运输烟花爆竹车辆中途停靠，没有专人看守"}], "answer": "ABCD", "explanation": "根据《烟花爆竹安全管理条例》第40条规定，经由道路运输烟花爆竹违反规定的，由公安部门责令改正，处以罚款。具体违规行为包括：装载不符合要求（车厢载人）、未按规定路线行驶、超过规定时速行驶、途中停靠无专人看守等。四个选项均属于违反道路运输管理规定的行为。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1083}, {"num": 1085, "batch": "专业基础知识", "type": "multi", "stem": "下列行为中违反《烟花爆竹安全管理条例》关于烟花爆竹道路运输管理规定的有（）", "options": [{"letter": "A", "text": "为了赶时间，运输烟花爆竹的司机张某在高速路上超速行驶"}, {"letter": "B", "text": "李某用装载烟花爆竹的车厢载人"}, {"letter": "C", "text": "张某用于运送烟花爆竹的车辆在路途中出现故障，张某临时雇用了一辆具有特种运输资格的车辆转运"}, {"letter": "D", "text": "押运员张某在出发前有急事需要回家，私下让另一个有资质的押运员顶替"}], "answer": "ABCD", "explanation": "根据《烟花爆竹安全管理条例》关于道路运输烟花爆竹的规定，A项超速行驶违反了限速规定。B项用装载烟花爆竹的车厢载人违反了禁止性规定。C项临时雇用车辆转运需办理相关手续，私自雇用不符合规定。D项押运员私自让他人顶替不符合押运人员管理规定。四个选项均违反规定。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1084}, {"num": 1086, "batch": "专业基础知识", "type": "multi", "stem": "下列行为中违反《烟花爆竹安全管理条例》规定的有（）", "options": [{"letter": "A", "text": "张某家在山区，常年在外地打工，春节不能回家，为了给儿子送礼物，特地买了城里孩子玩的烟花放入纸箱通过邮局邮寄回家"}, {"letter": "B", "text": "李某赶集办年货买了些鞭炮，搭乘小巴车回家"}, {"letter": "C", "text": "徐某将一箱冷光烟花通过火车托运给另一个城市的客户"}, {"letter": "D", "text": "托运人张某给邻县的客户送货，认为距离较近，未办理烟花爆竹道路运输许可证"}], "answer": "ABCD", "explanation": "根据《烟花爆竹安全管理条例》规定，禁止邮寄烟花爆竹（A违法），禁止携带烟花爆竹搭乘公共交通工具（B违法），托运烟花爆竹需办理相关手续（C中未说明是否办理手续，但通过火车托运烟花爆竹需符合特殊规定，违法），道路运输烟花爆竹需办理道路运输许可证（D未办理许可证违法）。四个选项均违反规定。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1085}, {"num": 1087, "batch": "专业基础知识", "type": "multi", "stem": "下列行政案件中，对被传唤的违法嫌疑人询问查证的时间可以超过8小时的有（）", "options": [{"letter": "A", "text": "甲阻碍执行职务案，案情简单，情节轻微，尚不够刑事处罚的"}, {"letter": "B", "text": "乙不按规定登记住宿旅客信息案，案情复杂的"}, {"letter": "C", "text": "丙殴打残疾人案，案情复杂，尚不够刑事处罚的"}, {"letter": "D", "text": "丁倒卖有价票证案，案情复杂，尚不够刑事处罚的"}], "answer": "CD", "explanation": "根据《治安管理处罚法》第83条规定，对违反治安管理行为人询问查证的时间一般不超过8小时；情况复杂，依照本法规定可能适用行政拘留处罚的，询问查证时间不超过24小时。A项案情简单情节轻微，不超过8小时。B项不按规定登记住宿旅客信息一般不适用行政拘留。C项殴打残疾人案情复杂且可能适用拘留，可以超过8小时。D项倒卖有价票证案情复杂且可能适用拘留，可以超过8小时。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1086}, {"num": 1088, "batch": "专业基础知识", "type": "multi", "stem": "下列行政案件中，适用简易程序的有（）", "options": [{"letter": "A", "text": "村民张某冲闯公安机关设置的警戒带，事实清楚、证据确凿，情节比较轻，对其处警告"}, {"letter": "B", "text": "王某冒充国家工作人员进行招摇撞骗，给当事人造成了损害，事实清楚，证据确凿"}, {"letter": "C", "text": "孔某违反了《道路交通安全法》被公安交管部门罚款200元"}, {"letter": "D", "text": "16岁的中学生高某在校园内强迫其同班同学购买其销售的米老鼠玩具，公安机关拟对其处150元的罚款"}], "answer": "ACD", "explanation": "根据《治安管理处罚法》第100条规定，违反治安管理行为事实清楚，证据确凿，处警告或者200元以下罚款的，可以当场作出治安管理处罚决定（简易程序）。A项事实清楚处警告，适用简易程序。B项招摇撞骗造成损害，一般不适用简易程序。C项罚款200元，适用简易程序。D项16岁中学生罚款150元，适用简易程序。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1087}, {"num": 1089, "batch": "专业基础知识", "type": "multi", "stem": "下列交通肇事者的行为均致一人重伤，并且负事故全部责任，可以交通肇事罪定罪的是（）", "options": [{"letter": "A", "text": "甲饮酒后驾驶机动车辆"}, {"letter": "B", "text": "乙严重疲劳驾驶"}, {"letter": "C", "text": "丙无驾驶资格驾驶机动车辆"}, {"letter": "D", "text": "丁明知其驾驶的货车未按规定安装侧后防撞栏而继续驾驶"}], "answer": "ACD", "explanation": "根据最高人民法院《关于审理交通肇事刑事案件具体应用法律若干问题的解释》第2条第2款，交通肇事致1人以上重伤，负事故全部或主要责任，并具有以下情形之一的，以交通肇事罪定罪处罚：酒后驾驶、无驾驶资格驾驶、明知安全装置不全或机件不符合技术标准而驾驶、明知无牌证或已报废而驾驶、严重超载等。A项饮酒后驾驶符合。B项疲劳驾驶不属于该条款列举的情形。C项无驾驶资格符合。D项明知货车未按规定安装防撞栏而驾驶属于明知安全装置不全，符合。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1088}, {"num": 1090, "batch": "专业基础知识", "type": "multi", "stem": "下列可以适用治安调解的案件有（）", "options": [{"letter": "A", "text": "刘某胁迫未成年人赵某实施盗窃"}, {"letter": "B", "text": "张某无故谩骂李某的母亲，李某将张某价值200元的手机摔坏"}, {"letter": "C", "text": "吴某纠集3人与张某等4人斗殴"}, {"letter": "D", "text": "王某与同学侯某因争抢座位厮打在一起，导致侯某轻微伤"}], "answer": "BD", "explanation": "根据《治安管理处罚法》第9条和《公安机关办理行政案件程序规定》，治安调解适用于因民间纠纷引起的打架斗殴或损毁他人财物等情节较轻的案件。A项胁迫未成年人盗窃不属于民间纠纷，不适用调解。B项张某谩骂李某母亲，李某摔坏手机，属于民间纠纷引起的案件，可以调解。C项多人斗殴不属于情节较轻的民间纠纷，不适用调解。D项同学间因争抢座位厮打致轻微伤，属于民间纠纷引起的情节较轻案件，可以调解。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1089}, {"num": 1091, "batch": "专业基础知识", "type": "multi", "stem": "下列可以依法撤销行政许可的情形有（）", "options": [{"letter": "A", "text": "超越法定职权作出准予行政许可决定的"}, {"letter": "B", "text": "行政许可所依据的法律、法规、规章修改或者废止"}, {"letter": "C", "text": "违反法定程序作出准予行政许可决定的"}, {"letter": "D", "text": "准予行政许可所依据的客观情况发生重大变化的"}], "answer": "AC", "explanation": "根据《行政许可法》第69条规定，可以撤销行政许可的情形包括：行政机关工作人员滥用职权、玩忽职守作出准予许可决定的；超越法定职权作出准予许可决定的；违反法定程序作出准予许可决定的等。A项超越法定职权可以撤销，正确。B项许可依据的法律法规修改或废止属于变更或撤回许可的情形，不是撤销。C项违反法定程序可以撤销，正确。D项客观情况重大变化属于变更或撤回许可的情形，不是撤销。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1090}, {"num": 1092, "batch": "专业基础知识", "type": "multi", "stem": "下列可以作为证人的是（）", "options": [{"letter": "A", "text": "王某，11周岁，一日在放学回家的路上，看见邻居家的自行车被人撬开后骑走"}, {"letter": "B", "text": "张某，30周岁，聋哑人，一日在回家的途中，正碰上本村村民赵某辱骂另一村民陈某"}, {"letter": "C", "text": "刘某，19周岁，刘某家与其邻居因宅基地产生矛盾，一日，刘某回家时，见自己的母亲徐某正在往邻居家中扔砖头，并听见了玻璃破碎的声音"}, {"letter": "D", "text": "吕某，45周岁，间歇性精神病人。一日，在去医院检查时，正碰上一病人家属在病房内殴打医生陆某，吕某上前将病人家属拉开"}], "answer": "ACD", "explanation": "根据《刑事诉讼法》第62条规定，凡是知道案件情况的人都有作证的义务。生理上、精神上有缺陷或者年幼，不能辨别是非、不能正确表达的人，不能作证人。A项11岁王某能辨别是非并正确表达关于自行车被盗的见闻，可以作证。B项聋哑人张某可以通过手语等方式正确表达，可以作证。但本题标准答案未选B。C项19岁刘某能辨别是非并正确表达，可以作证。D项间歇性精神病人在精神正常时（去医院检查时）可以作证。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1091}, {"num": 1093, "batch": "专业基础知识", "type": "multi", "stem": "下列哪些物品可以收缴？（）", "options": [{"letter": "A", "text": "淫秽物品"}, {"letter": "B", "text": "为赌博而租用的麻将牌"}, {"letter": "C", "text": "已经支付给卖淫女的嫖资"}, {"letter": "D", "text": "为诈骗而借用的他人变造的印章"}], "answer": "AD", "explanation": "根据《治安管理处罚法》第11条规定，办理治安案件所查获的毒品、淫秽物品等违禁品，赌具、赌资，吸食、注射毒品的用具以及直接用于实施违法行为的本人所有的工具，应当予以收缴。A项淫秽物品属于违禁品，可以收缴。B项租用的麻将牌不属于本人所有，不能收缴。C项已支付给卖淫女的嫖资属于赌资或违法所得性质，但已经支付的不属于行为人持有的财物，不能收缴。D项为诈骗而借用的变造印章属于违禁品（变造的证件印章），可以收缴。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1092}, {"num": 1094, "batch": "专业基础知识", "type": "multi", "stem": "下列情形，可以由公安派出所作出治安管理处罚决定的是（）", "options": [{"letter": "A", "text": "甲为旅店前台登记人员，对住宿的旅客乙不按规定登记姓名、身份证件种类和号码"}, {"letter": "B", "text": "甲经常纵容其饲养的宠物狗到处乱窜，严重干扰了他人的正常生活"}, {"letter": "C", "text": "甲将房屋出租给无身份证件的乙居住"}, {"letter": "D", "text": "甲诈骗乙现金100元"}], "answer": "ABC", "explanation": "根据《治安管理处罚法》第91条规定，公安派出所可以作出警告、500元以下罚款的处罚决定。A项不按规定登记住宿旅客信息，属于警告或200元以下罚款的处罚范围，派出所可以决定。B项纵容宠物干扰他人生活，属于警告或200元以下罚款范围，派出所可以决定。C项将房屋出租给无身份证件的人居住，属于200元以上500元以下罚款范围，派出所可以决定。D项诈骗100元，处罚可能在500元以下罚款范围内，但诈骗属于较严重的违法行为，本题认为派出所可以决定。标准答案选ABC。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1093}, {"num": 1095, "batch": "专业基础知识", "type": "multi", "stem": "下列情形中，不构成过失致人死亡罪的是（）", "options": [{"letter": "A", "text": "甲驾车闯红灯致1死2伤"}, {"letter": "B", "text": "乙在一开放的、用于社会车辆和行人通行的居民小区不慎将一小孩撞死"}, {"letter": "C", "text": "丙驾驶拖拉机在自家耕地不慎将人撞死"}, {"letter": "D", "text": "丁在公共停车场倒车时不慎将一妇女撞死"}], "answer": "ABD", "explanation": "根据《刑法》第233条及相关司法解释，过失致人死亡罪与交通肇事罪存在法条竞合关系，在公共交通管理范围内因交通事故致人死亡的应以交通肇事罪论处。A项在道路上驾车闯红灯致人死亡，应定交通肇事罪而非过失致人死亡罪。B项在开放的小区道路上撞死人，属于公共交通管理范围，应定交通肇事罪。C项在自家耕地驾驶拖拉机撞死人，不属于公共交通管理范围，应定过失致人死亡罪。D项在公共停车场倒车致人死亡，属于公共交通管理范围，应定交通肇事罪。本题问不构成过失致人死亡罪的，选ABD。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1094}, {"num": 1096, "batch": "专业基础知识", "type": "multi", "stem": "下列情形中，符合《公安机关办理行政案件程序规定》对担保人规定的有（）", "options": [{"letter": "A", "text": "担保人履行了担保义务，但被担保人仍逃避行政拘留处罚执行的，对担保人可以从轻或者不予处罚"}, {"letter": "B", "text": "担保人履行了担保义务，但被担保人仍逃避行政拘留处罚执行的，对担保人应当从轻或者不予处罚"}, {"letter": "C", "text": "被处罚人逃跑后，担保人积极帮助公安机关抓获被处罚人的，应当从轻或者不予处罚"}, {"letter": "D", "text": "被处罚人逃跑后，担保人积极帮助公安机关抓获被处罚人的，可以从轻或者不予处罚"}], "answer": "AD", "explanation": "根据《治安管理处罚法》第109条和《公安机关办理行政案件程序规定》关于担保人的规定，担保人履行了担保义务但被担保人仍逃避执行的，对担保人可以从轻或不予处罚，A正确（'可以'而非'应当'）。被处罚人逃跑后担保人积极帮助抓获的，可以从轻或不予处罚，D正确（'可以'而非'应当'）。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1095}, {"num": 1097, "batch": "专业基础知识", "type": "multi", "stem": "下列情形中，公安机关可以对游行队伍负责人和直接责任人员处以警告或者拘留处罚的情形有（）", "options": [{"letter": "A", "text": "未依照《集会游行示威法》规定申请或者申请未获许可的"}, {"letter": "B", "text": "未按照公安机关许可的目的、方式、标语、口号、起止时间、地点、路线进行，不听制止的"}, {"letter": "C", "text": "游行人员携带武器、管制刀具或者爆炸物的"}, {"letter": "D", "text": "游行人员包围、冲击国家机关，致使国家机关的公务活动或者国事活动不能正常进行的"}], "answer": "AB", "explanation": "根据《集会游行示威法》第28条规定，未依照法律规定申请或申请未获许可而举行游行，或者未按照许可的目的、方式、标语、口号、起止时间、地点、路线进行且不听制止的，公安机关可以对游行队伍负责人和直接责任人员处以警告或15日以下拘留。A、B项符合上述规定。C项携带武器管制刀具或爆炸物的，依法追究刑事责任，不是警告或拘留。D项冲击国家机关的，依法追究刑事责任。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1096}, {"num": 1098, "batch": "专业基础知识", "type": "multi", "stem": "下列情形中，公安机关应当按规定填写受案登记表的是（）", "options": [{"letter": "A", "text": "李某因家中一辆旧自行车被盗到公安机关报案，公安机关准备调查"}, {"letter": "B", "text": "陈某殴打他人后到公安机关投案，公安机关准备调解处理"}, {"letter": "C", "text": "赵某举报不属公安机关管辖的漏税案件，公安机关告知其向税务部门举报"}, {"letter": "D", "text": "张某控告邻县齐某，在齐某家中受齐殴打，公安机关准备移交邻县公安机关"}], "answer": "ABCD", "explanation": "根据《公安机关办理行政案件程序规定》，公安机关对于报案、控告、举报、投案等，都应当按规定填写受案登记表。A项报案准备调查应填写受案登记表。B项投案准备调解也应填写。C项举报不属于公安管辖的案件，告知向其他部门举报的同时也应填写受案登记表。D项准备移交其他公安机关的案件也应填写受案登记表。四个选项均应填写。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1097}, {"num": 1099, "batch": "专业基础知识", "type": "multi", "stem": "下列情形中，公安机关作出治安管理处罚决定前，应当告知违反治安管理行为人有权要求举行听证的是（）", "options": [{"letter": "A", "text": "刘某因卖淫拟决定行政拘留15日并处5000元罚款"}, {"letter": "B", "text": "王某因赌博拟决定行政拘留15日并处3000元罚款"}, {"letter": "C", "text": "张某因殴打他人拟决定行政拘留10日并处1000元罚款"}, {"letter": "D", "text": "某典当行违反了典当治安管理的相关规定，公安机关拟决定吊销其许可证"}], "answer": "ABD", "explanation": "根据《治安管理处罚法》第98条规定，公安机关作出吊销许可证以及处2000元以上罚款的处罚决定前，应当告知违法行为人有权要求举行听证。A项罚款5000元超过2000元，应当告知听证。B项赌博罚款3000元超过2000元，应当告知听证。C项殴打他人罚款1000元未超过2000元，不需要告知听证。D项吊销许可证应当告知听证。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1098}, {"num": 1100, "batch": "专业基础知识", "type": "multi", "stem": "下列情形中，可能对游行队伍负责人和直接责任人员依照《刑法》有关规定追究刑事责任的有（）", "options": [{"letter": "A", "text": "未依照《集会游行示威法》规定申请或者申请未获许可，或者未按照公安机关许可的起止时间、地点、路线进行，又拒不服从解散命令，严重破坏社会秩序的"}, {"letter": "B", "text": "包围、冲击国家机关，致使国家机关的公务活动或者国事活动不能正常进行的"}, {"letter": "C", "text": "占领公共场所、拦截车辆行人或者聚众堵塞交通，严重破坏公共场所秩序、交通秩序的"}, {"letter": "D", "text": "未按照公安机关许可的目的、方式、标语、口号、起止时间、地点、路线进行，不听制止的"}], "answer": "ABC", "explanation": "根据《集会游行示威法》第29条规定，未依法申请或申请未获许可，或者未按照许可事项进行，又拒不服从解散命令，严重破坏社会秩序的，依法追究刑事责任，A正确。包围冲击国家机关致使公务活动不能正常进行的，依法追究刑事责任，B正确。占领公共场所、拦截车辆或聚众堵塞交通严重破坏秩序的，依法追究刑事责任，C正确。D项不听制止但未达到严重破坏社会秩序程度的，处以警告或拘留，不追究刑事责任。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1099}, {"num": 1101, "batch": "专业基础知识", "type": "multi", "stem": "下列情形中，可以不使用传唤证在公安机关内对违法嫌疑人进行询问查证的有（）", "options": [{"letter": "A", "text": "投案自首的违法嫌疑人"}, {"letter": "B", "text": "被侵害人控告的违法嫌疑人"}, {"letter": "C", "text": "群众扭送的违法嫌疑人"}, {"letter": "D", "text": "现场发现的违法嫌疑人"}], "answer": "ACD", "explanation": "根据《公安机关办理行政案件程序规定》，对于投案自首、群众扭送、现场发现的违法嫌疑人，公安机关可以直接在公安机关内进行询问查证，无需使用传唤证。被侵害人控告的违法嫌疑人不属于可以省略传唤证的情形，因其并非由公安机关当场发现或被动到案。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1100}, {"num": 1102, "batch": "专业基础知识", "type": "multi", "stem": "下列情形中，可以适用口头传唤的有（）", "options": [{"letter": "A", "text": "民警在执勤时发现李某正在殴打他人"}, {"letter": "B", "text": "民警巡逻途中发现盗窃后正在逃离现场的违法嫌疑人张某"}, {"letter": "C", "text": "公安机关接到举报，在逃的违法嫌疑人陈某已回到单位"}, {"letter": "D", "text": "民警下责任区时，发现在逃的违法嫌疑人赵某正好在家中"}], "answer": "ABD", "explanation": "根据《治安管理处罚法》第82条，对现场发现的违法嫌疑人可以口头传唤。A项民警执勤时发现正在殴打他人、B项巡逻时发现正在逃离的嫌疑人、D项在辖区发现正好在家的在逃嫌疑人，均属'现场发现'，可口头传唤。C项系接到举报后专门前往查找在逃人员，不属于现场发现，应使用传唤证。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1101}, {"num": 1103, "batch": "专业基础知识", "type": "multi", "stem": "下列情形中，体现了行政许可信赖保护原则的有（）", "options": [{"letter": "A", "text": "在“非典”期间，为了防止野生动物传播“非典”病毒，野生动物管理部门收回了已经颁发的野生动物经营许可证，并对由此对被许可人造成的财产损失进行了补偿"}, {"letter": "B", "text": "某直辖市的三轮摩托车客运业务影响了环境和交通秩序，市政府决定收回三轮摩托车许可证，同时对当事人给予了补偿"}, {"letter": "C", "text": "作出行政许可决定的行政机关撤销了行政机关工作人员滥用职权、玩忽职守作出的准予行政许可的决定，并对被许可人受到的损害给予赔偿"}, {"letter": "D", "text": "《矿产资源法》规定，国务院批准开办的矿山企业矿区范围内已有的集体矿山企业应当关闭或者到指定的其他地点开采，由此造成的损失，由矿山建设单位给予合理的补偿"}], "answer": "ABD", "explanation": "信赖保护原则是指行政相对人对行政权力的正当合理信赖应受保护，行政机关不得擅自变更已生效的行政许可；因国家利益、公共利益需要变更或撤回的，应补偿相对人的财产损失。A、B、D三项均体现了因公共利益需要撤回或限制许可并给予补偿。C项属于行政机关违法行政的撤销赔偿，不属于信赖保护原则的范畴。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1102}, {"num": 1104, "batch": "专业基础知识", "type": "multi", "stem": "下列情形中，以拐卖妇女、儿童罪或收买被拐卖的妇女、儿童的共犯论处的有（）", "options": [{"letter": "A", "text": "甲明知他人拐卖儿童，仍然向其提供被拐卖儿童的出生证明"}, {"letter": "B", "text": "乙明知他人收买被拐卖的儿童，仍然向其提供被收买儿童的户籍证明"}, {"letter": "C", "text": "丙明知他人系拐卖儿童的“人贩子”，仍然利用从事福利救助工作的便利居间介绍"}, {"letter": "D", "text": "丁明知他人系拐卖儿童的“人贩子”，仍然利用从事诊疗工作的便利居间介绍"}], "answer": "ABCD", "explanation": "根据最高人民法院、最高人民检察院、公安部、司法部《关于依法惩治拐卖妇女儿童犯罪的意见》，明知他人拐卖儿童而提供出生证明等证明文件的，明知他人收买被拐卖儿童而提供户籍证明等文件的，以及利用从事福利救助、诊疗等工作便利居间介绍的，均以拐卖儿童罪或收买被拐卖的儿童的共犯论处。ABCD四项均符合共犯的认定条件。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1103}, {"num": 1105, "batch": "专业基础知识", "type": "multi", "stem": "下列情形中，以掩饰、隐瞒犯罪所得、犯罪所得收益罪定罪处罚的是有（）", "options": [{"letter": "A", "text": "甲掩饰、隐瞒犯罪所得价值2000元"}, {"letter": "B", "text": "乙一年内曾因掩饰、隐瞒犯罪所得及其产生的收益行为受过行政处罚，又实施掩饰、隐瞒犯罪所得行为"}, {"letter": "C", "text": "丙掩饰、隐瞒的犯罪所得系电力设备"}, {"letter": "D", "text": "丁掩饰、隐瞒行为致使上游犯罪无法及时查处，并造成公私财物损失无法挽回"}], "answer": "BCD", "explanation": "根据《关于办理掩饰、隐瞒犯罪所得及其收益刑事案件适用法律若干问题的解释》，掩饰隐瞒犯罪所得价值达3000元以上方达到一般入罪标准，A项2000元未达标准。但B项一年内曾因同类行为受过行政处罚又实施的、C项犯罪所得系电力设备的、D项致使上游犯罪无法及时查处并造成损失无法挽回的，均属司法解释规定的特殊入罪情形，应以掩饰、隐瞒犯罪所得罪定罪处罚。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1104}, {"num": 1106, "batch": "专业基础知识", "type": "multi", "stem": "下列情形中，应当对违反治安管理行为人减轻或不予处罚的是（）", "options": [{"letter": "A", "text": "盲人张某嫖娼被当场抓获"}, {"letter": "B", "text": "李某酒后在饭店寻衅滋事"}, {"letter": "C", "text": "李某被赵某胁迫参与盗窃放风并分得现金50元"}, {"letter": "D", "text": "王某盗窃被抓后在询问过程中揭露了同案的曹某，并带领民警将其抓获"}], "answer": "CD", "explanation": "根据《治安管理处罚法》相关规定，被胁迫参与违法活动的（C项李某被胁迫放风），应当减轻处罚或不予处罚；有立功表现的（D项王某揭露同案犯并协助抓获），也应当减轻或不予处罚。A项盲人违反治安管理的，是可以从轻、减轻或不予处罚，而非应当。B项酒后滋事无法定减轻情节。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1105}, {"num": 1107, "batch": "专业基础知识", "type": "multi", "stem": "下列情形中，应当以非法持有、私藏枪支、弹药罪定罪处罚的是（）", "options": [{"letter": "A", "text": "甲私藏军用枪支2支以上"}, {"letter": "B", "text": "乙非法持有气枪2支"}, {"letter": "C", "text": "丙私藏军用子弹30发"}, {"letter": "D", "text": "丁私藏手榴弹2枚"}], "answer": "ABCD", "explanation": "根据《关于审理非法制造、买卖、运输枪支、弹药、爆炸物等刑事案件具体应用法律若干问题的解释》，私藏军用枪支2支以上的（A项）、非法持有气枪2支以上的（B项）、私藏军用子弹30发以上的（C项）、私藏手榴弹2枚以上的（D项），均达到非法持有、私藏枪支弹药罪的定罪标准，应依法追究刑事责任。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1106}, {"num": 1108, "batch": "专业基础知识", "type": "multi", "stem": "下列情形中，有关取保候审的措施适用不当的是（）", "options": [{"letter": "A", "text": "甲县公安局决定对涉嫌盗窃罪的赵某取保候审，责令赵某交纳保证金5000元，同时由赵某的父亲作为保证人"}, {"letter": "B", "text": "按摩女钱某在美容院一包厢内向嫖客王某卖淫时被乙县公安局民警当场查获，经审查，钱某供认还向10余名嫖客卖淫。因全案一时难以查清，乙县公安局决定对钱某取保候审"}, {"letter": "C", "text": "孙某因涉嫌危险驾驶罪被公安机关决定取保候审并责令其在取保候审期间不得驾驶机动车，交纳保证金1万元，后其继续违规驾驶机动车，公安机关决定没收孙某的保证金1万元"}, {"letter": "D", "text": "李某因涉嫌非法拘禁罪于3月8日被丁县公安局决定取保候审。经侦查，丁县公安局认为李某的非法拘禁行为情节轻微，不构成犯罪，于4月1日撤销案件，4月16日解除对李某的取保候审"}], "answer": "ABD", "explanation": "A项不当：根据《刑事诉讼法》规定，取保候审不得同时使用保证金和保证人两种方式。B项不当：全案一时难以查清的，不应适用取保候审，应依法继续调查或变更强制措施。C项正确：被取保候审人违反规定，公安机关可以没收保证金。D项不当：案件撤销后应及时解除取保候审，丁县公安局4月1日撤案却4月16日才解除取保，超期15天，属适用不当。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1107}, {"num": 1109, "batch": "专业基础知识", "type": "multi", "stem": "下列情形中犯罪既遂的是（）", "options": [{"letter": "A", "text": "甲以出卖为目的，偷盗婴儿后，惧怕承担刑事责任，又将婴儿送回原处"}, {"letter": "B", "text": "乙收买1名儿童打算日后卖出。次日，看到拐卖儿童犯罪分子被判处死刑的新闻，偷偷将儿童送回家"}, {"letter": "C", "text": "丙以出卖为目的绑架妇女后，被害人反复向丙求情，丙释放了被害人"}, {"letter": "D", "text": "丁以拐骗手段劫持1名儿童欲出卖，在关押期间被害人逃跑"}], "answer": "ABCD", "explanation": "拐卖妇女儿童罪以行为人实际控制被害人作为既遂标准，不要求实际卖出。A项偷盗婴儿已控制即既遂，送回不影响；B项收买儿童已控制即既遂，送回不影响；C项绑架妇女已控制即既遂，释放不影响；D项拐骗儿童已控制即既遂，被害人逃跑不影响既遂成立。故ABCD四项均为犯罪既遂。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1108}, {"num": 1110, "batch": "专业基础知识", "type": "multi", "stem": "下列情形中构成挪用公款罪的是（）", "options": [{"letter": "A", "text": "村委会主任谭某用伪造的发票将集体公款5万元据为己有"}, {"letter": "B", "text": "国有医院采购科科长唐某在药品采购过程中收受两家制药企业的手续费3万元"}, {"letter": "C", "text": "国有公司经理张某以个人名义将公款50万元借给亲属开的公司使用，未谋取个人利益"}, {"letter": "D", "text": "民政局局长冯某将20万元公款以自己名义借给朋友开的公司使用，未谋取个人利益"}], "answer": "CD", "explanation": "根据《刑法》第384条及相关司法解释，国家工作人员利用职务便利，以个人名义将公款借给其他单位使用的，属于挪用公款归个人使用。C项国有公司经理以个人名义将公款借给亲属公司、D项民政局局长以个人名义将公款借给朋友公司，均构成挪用公款罪。A项村委会主任将公款据为己有构成贪污罪；B项采购科长收受手续费构成受贿罪。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1109}, {"num": 1111, "batch": "专业基础知识", "type": "multi", "stem": "下列人员中，不能作为证人的是（）", "options": [{"letter": "A", "text": "生理上有缺陷，不能辨别是非、不能正确表达的人"}, {"letter": "B", "text": "年幼，不能辨别是非、不能正确表达的人"}, {"letter": "C", "text": "精神上有缺陷，不能辨别是非、不能正确表达的人"}, {"letter": "D", "text": "一方当事人的近亲属"}], "answer": "ABC", "explanation": "根据《刑事诉讼法》第62条及《公安机关办理行政案件程序规定》，生理上有缺陷不能辨别是非和正确表达的人（A项）、年幼不能辨别是非和正确表达的人（B项）、精神上有缺陷不能辨别是非和正确表达的人（C项），均不能作为证人。D项一方当事人的近亲属并不因身份关系而丧失证人资格，可以作证。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1110}, {"num": 1112, "batch": "专业基础知识", "type": "multi", "stem": "下列人员中，可以适用取保候审的是（）", "options": [{"letter": "A", "text": "王某涉嫌危险驾驶罪，可能判处拘役"}, {"letter": "B", "text": "李某涉嫌交通肇事罪，可能判处有期徒刑以上刑罚，采取取保候审不致发生社会危险性"}, {"letter": "C", "text": "犯罪嫌疑人田某患有严重疾病，生活不能自理，采取取保候审不致发生社会危险性"}, {"letter": "D", "text": "犯罪嫌疑人吕某正在怀孕，采取取保候审不致发生社会危险性"}], "answer": "ABCD", "explanation": "根据《刑事诉讼法》第67条，可以适用取保候审的情形包括：可能判处管制、拘役或者独立适用附加刑的（A项）；可能判处有期徒刑以上刑罚，采取取保候审不致发生社会危险性的（B项）；患有严重疾病、生活不能自理，采取取保候审不致发生社会危险性的（C项）；怀孕或者正在哺乳自己婴儿的妇女，采取取保候审不致发生社会危险性的（D项）。ABCD均符合法定条件。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1111}, {"num": 1113, "batch": "专业基础知识", "type": "multi", "stem": "下列人员中，属于《公安机关办理行政案件程序规定》中所称的“聋哑人”的是（）", "options": [{"letter": "A", "text": "又聋又哑的张某"}, {"letter": "B", "text": "哑巴李某"}, {"letter": "C", "text": "左耳失聪的陈某"}, {"letter": "D", "text": "只聋不哑的赵某"}], "answer": "ABD", "explanation": "根据《公安机关办理行政案件程序规定》，'聋哑人'包括又聋又哑的人（A项）、哑巴（B项）以及只聋不哑的人（D项）。C项左耳失聪仅为一侧听力障碍，不属于该规定所称的'聋哑人'范畴，因为其主要听力功能仍然存在。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1112}, {"num": 1114, "batch": "专业基础知识", "type": "multi", "stem": "下列属于《行政许可法》调整范围的是（）", "options": [{"letter": "A", "text": "进出口食品检疫机关，经鉴定后，给某公司的出口食品贴上了检疫标签"}, {"letter": "B", "text": "老周下岗后自谋出路，想自己开一个小饭馆，于是向工商局提出申请，工商局经审查，发给了老王营业执照"}, {"letter": "C", "text": "行政机关根据某化肥厂的申请，发给其生产许可证"}, {"letter": "D", "text": "北京市某大学希望上级教育主管部门拨款，对学校进行扩建，上级教育主管部门对其申请予以审批"}], "answer": "ABC", "explanation": "《行政许可法》调整的是行政机关根据公民、法人或其他组织的申请，经依法审查准予其从事特定活动的行为。A项检疫贴标属于行政许可中的认可行为；B项发营业执照属于许可；C项发生产许可证属于许可。D项上级对下级拨款的审批属于行政机关内部审批行为，不属于行政许可法的调整范围。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1113}, {"num": 1115, "batch": "专业基础知识", "type": "multi", "stem": "下列属于公安机关可以依法撤销行政许可的情形是（）", "options": [{"letter": "A", "text": "违反法定程序作出准予行政许可决定的"}, {"letter": "B", "text": "对不具备申请资格或者不符合法定条件的申请人准予行政许可的"}, {"letter": "C", "text": "滥用职权、玩忽职守作出准予行政许可决定的"}, {"letter": "D", "text": "超越法定职权作出准予行政许可决定的"}], "answer": "ABCD", "explanation": "根据《行政许可法》第69条，行政机关可以撤销行政许可的情形包括：违反法定程序作出准予许可决定的（A项）、对不具备申请资格或不符合法定条件的申请人准予许可的（B项）、滥用职权或玩忽职守作出准予许可决定的（C项）、超越法定职权作出准予许可决定的（D项）。ABCD四项均属于法定可撤销情形。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1114}, {"num": 1116, "batch": "专业基础知识", "type": "multi", "stem": "下列说法错误的是（）", "options": [{"letter": "A", "text": "公安机关在办理行政案件中对有关专门性技术问题均应鉴定"}, {"letter": "B", "text": "为了体现鉴定结论的独立性，鉴定只能聘请非公安机关的专业人员进行"}, {"letter": "C", "text": "具体承担鉴定任务的必然是自然人。鉴定的结果一般以书面形式表现，对于一些特别简单的问题也可以口头作出"}, {"letter": "D", "text": "公安机关不能要求鉴定人回答有关案件处理方面的其他问题"}], "answer": "ABC", "explanation": "A项错误：并非所有专门性技术问题均需鉴定，只有需要鉴定时才进行。B项错误：公安机关可以聘请本机关具有鉴定资格的专业人员进行鉴定，并非只能聘请外部人员。C项错误：鉴定结果必须以书面形式作出，不能口头作出鉴定意见。D项说法正确：公安机关确实不能要求鉴定人回答案件处理方面的其他问题，鉴定人仅就专门性技术问题提供意见。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1115}, {"num": 1117, "batch": "专业基础知识", "type": "multi", "stem": "下列听证申请公安机关可以不予受理的有（）", "options": [{"letter": "A", "text": "公安机关于2008年3月10日上午告知违法嫌疑人听证权，当时违法嫌疑人放弃听证，11日公安机关作出处罚决定，而12日违法嫌疑人提出听证要求"}, {"letter": "B", "text": "公安机关于2008年3月10日上午告知违法嫌疑人听证权，当时违法嫌疑人放弃听证，而12日违法嫌疑人提出听证要求，当时公安机关未作出处罚决定"}, {"letter": "C", "text": "公安机关于2008年3月10日上午告知违法嫌疑人听证权，当时违法嫌疑人要求听证，11日又撤回听证，15日又提出听证要求，而当时公安机关未作出处罚决定"}, {"letter": "D", "text": "公安机关于2008年3月10日上午告知违法嫌疑人听证权，当时违法嫌疑人要求听证，10日下午撤回听证，11日公安机关作出处理决定，12日违法嫌疑人要求听证"}], "answer": "ACD", "explanation": "根据《公安机关办理行政案件程序规定》关于听证的规定，A项违法嫌疑人已放弃听证且处罚决定已作出，不能再提出听证申请；C项撤回听证后不得再次提出；D项处罚决定已作出后再提出听证要求，不予受理。B项虽然嫌疑人曾放弃听证，但公安机关尚未作出处罚决定，此时提出听证要求应当受理。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1116}, {"num": 1118, "batch": "专业基础知识", "type": "multi", "stem": "下列违法行为人，不执行行政拘留处罚的是（）", "options": [{"letter": "A", "text": "甲某未满70周岁殴打他人，被公安机关处以行政拘留，作出行政拘留处罚时已满70周岁"}, {"letter": "B", "text": "已满16周岁不满18周岁，曾犯罪但被不予起诉的张某"}, {"letter": "C", "text": "孕妇陈某"}, {"letter": "D", "text": "哺乳自己的刚满1周岁婴儿的妇女李某"}], "answer": "AC", "explanation": "根据《治安管理处罚法》第21条，不执行行政拘留的情形包括：作出处罚决定时已满70周岁的（A项作出处罚时已满70周岁，符合）；怀孕或者哺乳自己不满1周岁婴儿的（C项孕妇符合）。B项已满16不满18周岁但曾犯罪被不起诉，不属于'初次违反治安管理'，不符合不执行条件。D项婴儿已满1周岁，不属于哺乳不满1周岁婴儿的情形。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1117}, {"num": 1119, "batch": "专业基础知识", "type": "multi", "stem": "下列违法情形，应当从重处罚的有（）", "options": [{"letter": "A", "text": "缓刑考验结束六个月内，违反治安管理的"}, {"letter": "B", "text": "刑事处罚执行完毕后，违反治安管理的"}, {"letter": "C", "text": "一年内因同类违法行为受到两次以上公安行政处罚的"}, {"letter": "D", "text": "劳动教养解除后六个月内违反治安管理的"}], "answer": "CD", "explanation": "根据《公安机关执行〈中华人民共和国治安管理处罚法〉有关问题的解释》及相关规定，应当从重处罚的情形包括：一年内因同类违法行为受到两次以上公安行政处罚的（C项）；劳动教养解除后六个月内违反治安管理的（D项）。A项缓刑考验结束和B项刑事处罚执行完毕后违反治安管理的，法律未明确规定为应当从重处罚的情形。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1118}, {"num": 1120, "batch": "专业基础知识", "type": "multi", "stem": "下列违反《人民警察使用警械和武器条例》规定的情形是（）", "options": [{"letter": "A", "text": "几十个下岗工人在市中心区非法举行游行、示威，民警要求解散，经警告无效，鸣枪示警"}, {"letter": "B", "text": "民警张某在街上巡逻时受到几名青年的言语谩骂，警告不听，于是用警棍将他们制服"}, {"letter": "C", "text": "一伙人聚众扰乱车站，影响恶劣，经劝阻不听，民警用高压水枪将他们驱逐"}, {"letter": "D", "text": "民警在讯问犯罪嫌疑人吴某时，吴某欲自杀，民警用警绳将其捆绑"}], "answer": "AB", "explanation": "A项违反规定：对非法游行示威的群众，不得使用武器，鸣枪示警违反了武器使用条件。B项违反规定：言语谩骂不属于可以使用警械的情形，使用警棍制服属过度使用。C项合法：高压水枪属于驱逐性警械，用于驱散聚众扰乱行为符合规定。D项合法：用警绳约束欲自杀的犯罪嫌疑人属于合法的约束措施。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1119}, {"num": 1121, "batch": "专业基础知识", "type": "multi", "stem": "下列违反民用爆炸物品管理规定的行为，由公安机关依法查处的有（）", "options": [{"letter": "A", "text": "民用爆炸物品销售企业超出购买许可的品种、数量销售民用爆炸物品"}, {"letter": "B", "text": "某民用爆炸物生产企业未按照规定对生产的雷管编码打号"}, {"letter": "C", "text": "某民用爆炸物品生产企业生产的民用爆炸物品的质量不符合相关标准"}, {"letter": "D", "text": "某民用爆炸物品销售企业未按照规定建立民用爆炸物品登记制度，未如实将本单位销售的民用爆炸物品的品种、数量和流向信息输入计算机系统"}], "answer": "BD", "explanation": "根据《民用爆炸物品安全管理条例》，B项生产企业未按规定对雷管编码打号、D项销售企业未按规定建立登记制度，由公安机关依法查处。A项超出许可品种销售由国防科技工业主管部门查处；C项产品质量不符合标准由质量监督部门查处，均不属于公安机关查处范围。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1120}, {"num": 1122, "batch": "专业基础知识", "type": "multi", "stem": "下列违反烟花爆竹安全管理规定的行为，由公安机关依法查处的有（）", "options": [{"letter": "A", "text": "某烟花爆竹生产企业超出安全生产许可证核定的产品种类进行生产"}, {"letter": "B", "text": "某从事烟花爆竹批发的企业向某从事烟花爆竹零售的经营者供应非法生产、经营的烟花爆竹"}, {"letter": "C", "text": "某生产黑火药、烟火药、引火线的企业，丢失1000米引火线未及时向当地安全生产监督管理部门和公安部门报告"}, {"letter": "D", "text": "李某运输烟花爆竹，未随车携带《烟花爆竹道路运输许可证》"}], "answer": "CD", "explanation": "根据《烟花爆竹安全管理条例》，C项丢失引火线未向公安部门报告的，由公安机关查处；D项运输烟花爆竹未随车携带道路运输许可证的，由公安机关查处。A项超出许可种类生产由安全生产监督管理部门查处；B项批发企业供应非法烟花爆竹由安全生产监督管理部门查处。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1121}, {"num": 1123, "batch": "专业基础知识", "type": "multi", "stem": "下列违反治安管理行为的人中，依法应当给予行政拘留处罚，但不执行行政拘留处罚的有（）", "options": [{"letter": "A", "text": "赵某，15岁，因多次拦截、追逐同班女同学苏某被公安机关发现"}, {"letter": "B", "text": "钱某，55岁，左腿残疾，某日与邻居争吵时，公然侮辱他人，情节严重"}, {"letter": "C", "text": "孙某，71岁，阻碍公安机关解救其儿子“买来”的媳妇"}, {"letter": "D", "text": "周某，女，35岁，因非法储存少量罂粟壳被公安机关抓获。家中有11个月大的女儿需要哺乳"}], "answer": "ACD", "explanation": "根据《治安管理处罚法》第21条，应当给予行政拘留但不执行的情形包括：已满14周岁不满16周岁的（A项赵某15岁符合）；70周岁以上的（C项孙某71岁符合）；哺乳自己不满1周岁婴儿的（D项周某哺乳11个月婴儿符合）。B项55岁残疾人不属于法定不执行行政拘留的情形。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1122}, {"num": 1124, "batch": "专业基础知识", "type": "multi", "stem": "下列物证、书证的收集程序、方式虽有一定瑕疵，但经补正或者作出合理解释，可以采用的是（）", "options": [{"letter": "A", "text": "某盗窃案的一份搜查笔录上没有物品持有人签名，侦查人员到庭说明当时物品持有人在场但拒绝签名的情况，且有见证人证明"}, {"letter": "B", "text": "某汽车盗窃案中的赃物汽车已经发还给被害人，但发还之前对该汽车所拍摄的一组照片上未注明与原物核对无异字样，后经被害人到庭说明，确认该照片即为被盗车辆的照片"}, {"letter": "C", "text": "在某放火案现场提取的点火用的打火机已丢失，侦查人员提供同种打火机作为证据，并到庭说明了情况"}, {"letter": "D", "text": "在某杀人案的现场勘验中提取了一枚嫌疑人的右手食指指纹，但在勘验笔录中没有记录，侦查人员到庭说明当时由于疏忽，忘记在笔录中注明"}], "answer": "AB", "explanation": "根据《关于办理刑事案件严格排除非法证据若干问题的规定》及相关司法解释，证据瑕疵经补正或合理解释可以采用的包括：A项搜查笔录缺少签名但有侦查人员说明和见证人证明，可以补正；B项照片未注明核对但经被害人确认可补正。C项原物丢失用同类物品替代，违反原物原则，无法补正。D项勘验笔录遗漏记录指纹，但指纹本身客观存在，属于重大瑕疵无法简单补正。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1123}, {"num": 1125, "batch": "专业基础知识", "type": "multi", "stem": "下列叙述正确的是（）", "options": [{"letter": "A", "text": "公安机关在实施行政处罚时，人民警察不得少于两人"}, {"letter": "B", "text": "人民警察对查获或者到案的违法嫌疑人应当进行安全检查，安全检查不需要开具检查证"}, {"letter": "C", "text": "公安机关在调查取证时，应当向被调查取证人员表明执法身份"}, {"letter": "D", "text": "对行为举止失控的醉酒人，可以使用警械进行约束"}], "answer": "BC", "explanation": "A项错误：公安机关实施行政处罚时警察不少于两人是针对一般程序，当场处罚可以一人实施。B项正确：安全检查是例行检查，不需要开具检查证。C项正确：调查取证时应当向被调查人员表明执法身份。D项错误：对行为举止失控的醉酒人可以使用约束性措施，但不得使用警械进行约束。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1124}, {"num": 1126, "batch": "专业基础知识", "type": "multi", "stem": "下列选项中，表述正确的有（）", "options": [{"letter": "A", "text": "人民警察使用武器造成犯罪分子或者无辜人员伤亡的，应当及时抢救受伤人员，保护现场，并立即向当地公安机关或者该人民警察所属机关报告"}, {"letter": "B", "text": "当地公安机关或者该人民警察所属机关接到报告后，应当及时进行勘验、调查，并及时通知当地人民法院"}, {"letter": "C", "text": "当地公安机关或者该人民警察所属机关应当将犯罪分子或者无辜人员的伤亡情况，及时通知其家属或者其所在单位"}, {"letter": "D", "text": "人民警察使用武器的，应当将使用武器的情况如实向人民检察院书面报告"}], "answer": "AC", "explanation": "根据《人民警察使用警械和武器条例》第12条，A项正确：使用武器造成伤亡的应及时抢救受伤人员、保护现场并立即报告。C项正确：应及时通知伤亡者家属或其所在单位。B项错误：应通知当地公安机关而非人民法院。D项错误：应向所属机关报告，而非向人民检察院书面报告。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1125}, {"num": 1127, "batch": "专业基础知识", "type": "multi", "stem": "下列选项中，错误的是（）", "options": [{"letter": "A", "text": "当场处罚可由办案民警一人实施"}, {"letter": "B", "text": "因为是当场处罚，民警没有听取违法行为人申辩"}, {"letter": "C", "text": "当场处罚后，民警第二天向违法行为人送达了当场处罚决定书"}, {"letter": "D", "text": "当场处罚并当场收缴了违禁品"}], "answer": "BC", "explanation": "A项正确：当场处罚可以由一名办案民警实施。B项错误：根据《行政处罚法》规定，行政机关及其执法人员在作出处罚决定前，必须听取当事人的陈述和申辩，即使是当场处罚也不例外。C项错误：当场处罚决定书应当当场交付当事人，不能第二天送达。D项正确：当场处罚可以当场收缴违禁品。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1126}, {"num": 1128, "batch": "专业基础知识", "type": "multi", "stem": "下列选项中，属于不可诉的国家行为的是（）", "options": [{"letter": "A", "text": "边检机关在认为是伪造的护照上加盖“无效”字样"}, {"letter": "B", "text": "国务院宣布某省某市进入紧急状态"}, {"letter": "C", "text": "中国政府驱逐某国使领馆人员出境"}, {"letter": "D", "text": "中华人民共和国主席宣布国家进入紧急状态"}], "answer": "BCD", "explanation": "根据《行政诉讼法》第13条，人民法院不受理对国防、外交等国家行为提起的诉讼。B项国务院宣布紧急状态、C项驱逐外国使领馆人员出境、D项国家主席宣布紧急状态均属于国家行为，不可诉。A项边检机关在护照上加盖'无效'字样属于具体行政行为，可以提起行政诉讼。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1127}, {"num": 1129, "batch": "专业基础知识", "type": "multi", "stem": "下列选项中符合辨认规定的是（）", "options": [{"letter": "A", "text": "多名辨认人对同一辨认对象进行辨认时，应当分别进行"}, {"letter": "B", "text": "辨认违法嫌疑人时，被辨认的人数不得少于10人"}, {"letter": "C", "text": "对违法嫌疑人照片进行辨认的，不得少于12人的照片"}, {"letter": "D", "text": "辨认经过和结果，应当制作辨认笔录，由办案人民警察和辨认人签名或者捺指印"}], "answer": "AD", "explanation": "根据《公安机关办理行政案件程序规定》关于辨认的规定，A项正确：多名辨认人对同一对象辨认时应分别进行，避免相互影响。D项正确：辨认经过和结果应制作辨认笔录，由办案民警和辨认人签名或捺指印。B项错误：辨认违法嫌疑人时被辨认人数不得少于7人而非10人。C项错误：对照片进行辨认不得少于10张照片而非12张。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1128}, {"num": 1130, "batch": "专业基础知识", "type": "multi", "stem": "下列选项中属于《公安机关办理行政案件程序规定》确定的原则是（）", "options": [{"letter": "A", "text": "以事实为根据，以法律为准绳"}, {"letter": "B", "text": "合法、公正、公开、及时"}, {"letter": "C", "text": "公、检、法三机关分工负责、互相配合、互相制约"}, {"letter": "D", "text": "教育与处罚相结合"}], "answer": "ABD", "explanation": "根据《公安机关办理行政案件程序规定》第3条至第5条，该规定确定的原则包括：以事实为根据、以法律为准绳（A项）；合法、公正、公开、及时（B项）；教育与处罚相结合（D项）。C项'公检法三机关分工负责、互相配合、互相制约'是《刑事诉讼法》的原则，不属于办理行政案件程序规定的原则。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1129}, {"num": 1131, "batch": "专业基础知识", "type": "multi", "stem": "下列选项中叙述错误的是（）", "options": [{"letter": "A", "text": "重新鉴定以两次为限"}, {"letter": "B", "text": "初次鉴定、检测费用由公安机关承担"}, {"letter": "C", "text": "重新鉴定费用由申请人承担"}, {"letter": "D", "text": "重新鉴定，如果鉴定结论有改变的，鉴定费用由公安机关承担"}], "answer": "ACD", "explanation": "根据《公安机关办理行政案件程序规定》，A项错误：重新鉴定以两次为限的说法没有法律依据。B项正确：初次鉴定、检测费用由公安机关承担。C项错误：重新鉴定费用不一定由申请人承担，如果鉴定结论有改变，应由公安机关承担。D项错误：重新鉴定结论改变的，费用由公安机关承担，而非申请人承担。题目问错误的选项，答案为ACD。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1130}, {"num": 1132, "batch": "专业基础知识", "type": "multi", "stem": "下列选项中正确的是（）", "options": [{"letter": "A", "text": "周某（男，1992年11月23日出生）自幼父母双亡，监护人为其外祖父，2007年8月20日，周某在一超市内盗窃物品被超市保安扭送到公安派出所，在对其询问时，几经周折，没有联系到其外祖父，派出所办案民警在询问笔录中将情况予以注明"}, {"letter": "B", "text": "王某（男，1991年9月23日出生），2007年5月6日，王某在学校内将同学赵某打伤，派出所民警将其传唤到所内询问，并通知其教师张某到场"}, {"letter": "C", "text": "陈某（女，1992年8月10日出生，高一学生），2008年1月6日陈某在一超市内购买物品时与他人发生争执，用购物篮将人砸伤，公安派出所将其传唤到所内进行询问，因其父母均出差未归，办案民警便通知其老师到场"}, {"letter": "D", "text": "徐某（男，1991年7月6日出生），2007年8月7日，徐某与其邻居发生纠纷，将其邻居家门口停放的一辆自行车砸坏，后被传唤到派出所进行询问"}], "answer": "ACD", "explanation": "A项正确：周某14岁为未成年人，联系不到监护人在笔录中注明情况符合规定。B项错误：王某15岁为未成年人，应通知监护人到场，通知教师不符合规定。C项正确：陈某15岁为未成年人，父母出差通知老师到场属于合理变通。D项正确：徐某已满16周岁（1991年7月出生，2007年8月时已满16周岁），不属于需要通知监护人的未成年人范围。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1131}, {"num": 1133, "batch": "专业基础知识", "type": "multi", "stem": "下列应当按照强奸罪追究刑事责任的是（）", "options": [{"letter": "A", "text": "甲奸淫13岁的幼女"}, {"letter": "B", "text": "乙强奸20岁的妇女致其死亡"}, {"letter": "C", "text": "丙明知对方是精神病患者，而与之发生性关系"}, {"letter": "D", "text": "乙嫖宿12岁的幼女"}], "answer": "ABCD", "explanation": "A项奸淫不满14周岁幼女，以强奸罪从重处罚。B项强奸妇女致其死亡，属于强奸罪的结果加重犯。C项明知对方是精神病患者而与之发生性关系，因精神病患者无法作出有效同意，以强奸罪论处。D项根据《刑法修正案（九）》，嫖宿幼女罪已被废除，嫖宿幼女一律以强奸罪论处。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1132}, {"num": 1134, "batch": "专业基础知识", "type": "multi", "stem": "下列应当按照强迫交易罪追究刑事责任的是（）", "options": [{"letter": "A", "text": "张某以支付10万元为代价，收购李某公司股份"}, {"letter": "B", "text": "王某在殴打李某后，以10万元收购李某公司股份，价值30万元"}, {"letter": "C", "text": "张某以伤害蒋某儿子为要挟，让蒋某购买其价值5万元产品"}, {"letter": "D", "text": "王某威胁企业，不让其车队运输企业产品，就带人阻挠企业工作，后企业被迫决定产品由王某车队运输"}], "answer": "CD", "explanation": "根据《刑法》第226条，强迫交易罪是指以暴力、威胁手段强买强卖商品、强迫提供或接受服务，情节严重的行为。C项以伤害要挟强迫购买产品、D项威胁强迫企业接受运输服务，均符合强迫交易罪的构成要件。A项属于正常交易行为。B项暴力程度严重且交易对价悬殊，可能构成抢劫罪而非强迫交易罪。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1133}, {"num": 1135, "batch": "专业基础知识", "type": "multi", "stem": "下列应当不予处罚的是（）", "options": [{"letter": "A", "text": "间歇性精神病人张某在发病期殴打了邻居李某"}, {"letter": "B", "text": "盲人违反治安管理的"}, {"letter": "C", "text": "朱某涉嫌偷窥他人隐私，在公安机关的主持下已与被侵害人达成调解协议并履行"}, {"letter": "D", "text": "黄某携带工具镊子准备到菜市场行窃，在途中被查获"}], "answer": "ACD", "explanation": "A项间歇性精神病人在发病期不能辨认或控制自己行为，根据《治安管理处罚法》第13条，不予处罚。C项根据《治安管理处罚法》第9条，经调解达成协议并履行的，不予处罚。D项黄某携带工具途中被查获属于犯罪预备，尚未着手实施，不构成治安违法行为，不予处罚。B项盲人违反治安管理的，是可以从轻、减轻或不予处罚，而非应当不予处罚。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1134}, {"num": 1136, "batch": "专业基础知识", "type": "multi", "stem": "下列应当以拐卖妇女、儿童罪立案侦查的行为有（）", "options": [{"letter": "A", "text": "甲以出卖为目的，收买妇女、儿童"}, {"letter": "B", "text": "乙拐卖儿童1名，但未获利"}, {"letter": "C", "text": "丙拐卖妇女，又强迫被拐卖的妇女卖淫"}, {"letter": "D", "text": "丁向他人传授拐卖妇女、儿童的犯罪方法"}], "answer": "ABC", "explanation": "根据《刑法》第240条，拐卖妇女儿童罪包括以出卖为目的的收买、拐骗、绑架、接送、中转等行为。A项以出卖为目的收买妇女儿童、B项拐卖儿童即使未获利、C项拐卖妇女又强迫卖淫（属加重情节），均应以拐卖罪立案侦查。D项传授犯罪方法构成独立的传授犯罪方法罪，不以拐卖罪立案。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1135}, {"num": 1137, "batch": "专业基础知识", "type": "multi", "stem": "下列应定性为拐卖妇女、儿童罪的行为有（）", "options": [{"letter": "A", "text": "甲承担接送被拐卖妇女、儿童任务"}, {"letter": "B", "text": "乙在拐卖妇女过程中，强奸被拐卖的妇女"}, {"letter": "C", "text": "丙以收养为目的，偷盗婴儿"}, {"letter": "D", "text": "丁以出卖为目的，在绑架儿童过程中致使儿童死亡"}], "answer": "ABD", "explanation": "A项承担接送被拐卖妇女儿童任务属于拐卖罪的共同犯罪行为。B项在拐卖过程中强奸被拐卖妇女，属于拐卖罪的加重情节，仍以拐卖罪定罪。D项以出卖为目的绑架儿童致死亡，属于拐卖罪的加重情节。C项以收养为目的偷盗婴儿，因不具有出卖目的，构成拐骗儿童罪而非拐卖儿童罪。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1136}, {"num": 1138, "batch": "专业基础知识", "type": "multi", "stem": "下列有关办案民警当场收缴罚款的说法正确的是（）", "options": [{"letter": "A", "text": "应当自收缴罚款之日起2日内，将当场收缴的罚款交至其所属公安机关"}, {"letter": "B", "text": "在水上当场收缴的罚款，应当自抵岸之日起2日内将当场收缴的罚款交至其所属公安机关"}, {"letter": "C", "text": "在旅客列车上当场收缴的罚款，应当自返回之日起2日内将当场收缴的罚款交至其所属公安机关"}, {"letter": "D", "text": "公安机关应当自收到罚款之日起7日内将罚款缴付指定的银行"}], "answer": "ABC", "explanation": "根据《治安管理处罚法》第105条，办案民警当场收缴罚款的，应当自收缴之日起2日内交至所属公安机关（A项正确）；在水上当场收缴的，自抵岸之日起2日内交至所属公安机关（B项正确）；在旅客列车上当场收缴的，自返回之日起2日内交至所属公安机关（C项正确）。D项错误：公安机关应当自收到罚款之日起2日内缴付指定银行，而非7日。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1137}, {"num": 1139, "batch": "专业基础知识", "type": "multi", "stem": "下列有关办理行政案件的说法正确的有（）", "options": [{"letter": "A", "text": "日常检查不需开具检查证，办案中检查一般要开具检查证"}, {"letter": "B", "text": "日常检查和办案中检查没有区别"}, {"letter": "C", "text": "日常检查的内容较为宽泛，办案中检查的内容则主要是与违法行为有关的证据"}, {"letter": "D", "text": "日常检查属于日常工作，办案中检查是临时的，是以调查违法行为为前提的"}], "answer": "ACD", "explanation": "A项正确：日常检查（如场所治安检查）不需要开具检查证，办案中的检查需要开具检查证。C项正确：日常检查内容较为宽泛，办案中的检查主要针对与违法行为有关的证据。D项正确：日常检查属于日常治安管理工作，办案中的检查是以调查违法行为为前提的临时性行为。B项错误：日常检查和办案中的检查在目的、程序、法律依据等方面存在明显区别。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1138}, {"num": 1140, "batch": "专业基础知识", "type": "multi", "stem": "下列有关丢失枪支不报罪的叙述正确的是（）", "options": [{"letter": "A", "text": "甲是公安局的刑警，丢枪后及时上报，但仍发生严重后果，不负刑事责任"}, {"letter": "B", "text": "甲是公安局的刑警，不知丢枪而没报告，造成严重后果，应定罪处罚"}, {"letter": "C", "text": "甲是狱警，丢枪后及时上报，但仍发生严重后果，应负刑事责任"}, {"letter": "D", "text": "甲是狱警，丢枪后不上报，因落入犯罪分子手中成为了犯罪工具，应负刑事责任"}], "answer": "AD", "explanation": "根据《刑法》第129条，丢失枪支不报罪是指依法配备公务用枪的人员丢失枪支不及时报告，造成严重后果的行为。A项甲及时上报，不符合'不及时报告'的构成要件，不负刑事责任。D项甲不上报且造成严重后果，符合犯罪构成。B项不知丢枪缺乏主观故意，不构成犯罪。C项狱警及时上报后仍发生严重后果，因已履行报告义务，不负刑事责任。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1139}, {"num": 1141, "batch": "专业基础知识", "type": "multi", "stem": "下列有关对身份不明的犯罪嫌疑人的处理说法正确的是（）", "options": [{"letter": "A", "text": "犯罪嫌疑人甲不讲真实姓名、住址，身份不明的，应当对其身份进行调查"}, {"letter": "B", "text": "对于涉嫌盗窃犯罪的乙，因其身份不明，侦查羁押期限自查清其身份之日起计算"}, {"letter": "C", "text": "对于涉嫌抢夺罪但身份不明的丙，侦查取证从查清其身份之日起进行"}, {"letter": "D", "text": "对于涉嫌强奸罪的丁，犯罪事实清楚，证据确实、充分，确实无法查清其身份的，也可以按其自报的姓名起诉、审判"}], "answer": "ABD", "explanation": "根据《刑事诉讼法》第160条，对身份不明的犯罪嫌疑人，应当对其身份进行调查（A项正确）；身份不明的，侦查羁押期限自查清其身份之日起计算（B项正确）；犯罪事实清楚、证据确实充分但确实无法查清身份的，可以按其自报的姓名起诉、审判（D项正确）。C项错误：侦查取证不应当等到查清身份才开始，应继续进行。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1140}, {"num": 1142, "batch": "专业基础知识", "type": "multi", "stem": "下列有关公安机关作出行政拘留处罚决定后，通知家属的做法正确的是（）", "options": [{"letter": "A", "text": "公安机关对李某作出行政拘留处罚决定后，李某拒不提供家属联系方式，公安机关可以不予通知其家属，但应当在附卷的决定书中注明"}, {"letter": "B", "text": "公安机关对王某作出行政拘留处罚决定后，王某没有任何家属，公安机关可以不予通知，但应当在附卷的决定书中注明"}, {"letter": "C", "text": "公安机关对赵某作出行政拘留1日的处罚决定后，因拘留时间较短，公安机关可以不予通知家属，并在决定书中注明"}, {"letter": "D", "text": "不予执行的，可以不通知家属"}], "answer": "AB", "explanation": "根据《治安管理处罚法》第97条和《公安机关办理行政案件程序规定》，A项正确：被处罚人拒不提供家属联系方式的，可以不予通知但应在附卷决定书中注明。B项正确：没有任何家属的，可以不予通知但应在附卷决定书中注明。C项错误：拘留时间较短也不能免除通知家属的义务。D项错误：不予执行也应当通知家属。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1141}, {"num": 1143, "batch": "专业基础知识", "type": "multi", "stem": "下列有关行政案件询问查证的表述正确的是（）", "options": [{"letter": "A", "text": "询问违法嫌疑人的询问查证时间一般是24小时"}, {"letter": "B", "text": "询问同案的违法嫌疑人,应当个别进行"}, {"letter": "C", "text": "询问违法嫌疑人时,应当告知其必须如实回答办案人员的所有提问"}, {"letter": "D", "text": "询问未满16周岁的违法嫌疑人时,应当通知其父母或者其他监护人到场"}], "answer": "BD", "explanation": "A项错误：询问查证时间一般不超过8小时，情况复杂可能适用行政拘留的不超过24小时，而非一般为24小时。B项正确：询问同案违法嫌疑人应当个别进行，防止串供。C项错误：应当告知如实回答的义务，但不能要求回答'所有'提问，嫌疑人有权对与案件无关的问题拒绝回答。D项正确：询问未满16周岁的违法嫌疑人应当通知父母或其他监护人到场。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1142}, {"num": 1144, "batch": "专业基础知识", "type": "multi", "stem": "下列有关恐怖主义、极端主义的犯罪行为，认定正确的有（）", "options": [{"letter": "A", "text": "甲以暴力、胁迫等方式强制他人在公共场所穿着宣扬极端主义服饰，且情节较重，构成寻衅滋事罪"}, {"letter": "B", "text": "乙将一册宣扬恐怖主义的图书藏在家中阅读，构成非法持有宣扬恐怖主义物品罪"}, {"letter": "C", "text": "丙利用极端主义煽动群众实行一夫多妻制，且情节较重，构成利用极端主义破坏法律实施罪"}, {"letter": "D", "text": "丁组织恐怖活动培训，构成准备实施恐怖活动罪"}], "answer": "CD", "explanation": "A项错误：强制他人在公共场所穿着极端主义服饰，构成强制穿戴极端主义服饰罪（《刑法》第120条之四），而非寻衅滋事罪。B项错误：单纯将一册恐怖主义图书藏在家中阅读，情节尚未达到严重程度，不一定构成非法持有宣扬恐怖主义物品罪。C项正确：利用极端主义煽动实行一夫多妻制且情节较重，构成利用极端主义破坏法律实施罪。D项正确：组织恐怖活动培训构成准备实施恐怖活动罪。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1143}, {"num": 1145, "batch": "专业基础知识", "type": "multi", "stem": "下列有关询问违法嫌疑人的做法正确的是（）", "options": [{"letter": "A", "text": "A县公安局将家住在邻县到A县出差的违法嫌疑人甲传唤到公安局询问"}, {"letter": "B", "text": "某县公安局将在B县的违法嫌疑人乙传唤到B县其居住的街道办事处询问"}, {"letter": "C", "text": "某县公安局未办传唤手续就到邻县的违法嫌疑人丙家中对丙询问"}, {"letter": "D", "text": "A县公安局到家住在邻县在A县工作的违法嫌疑人丁的单位询问丁"}], "answer": "ABCD", "explanation": "根据《治安管理处罚法》第82条和《公安机关办理行政案件程序规定》，询问违法嫌疑人可以在其所在市、县内的指定地点或其住处、单位进行。A项将出差的嫌疑人传唤到公安局、B项到嫌疑人居住街道办事处询问、C项到嫌疑人家中询问、D项到嫌疑人工作单位询问，均属于合法的询问地点。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1144}, {"num": 1146, "batch": "专业基础知识", "type": "multi", "stem": "下列有关一事不再罚的做法错误的是（）", "options": [{"letter": "A", "text": "甲因燃放烟花爆竹被所属地县级公安机关罚款，市级公安机关的治安总队在查处烟花爆竹燃放过程中又将甲的同一次燃放行为查处，并进行了罚款"}, {"letter": "B", "text": "甲驾驶货车在某省的路段上行驶，因超载分别被交通运输部门和公安机关给予罚款"}, {"letter": "C", "text": "某歌厅因噪音问题被城管部门罚款，之后公安部门又因同一次噪音问题对其实施了罚款"}, {"letter": "D", "text": "甲因无证经营典当业被市工商局处罚款，同时市公安局对其作出行政拘留的处罚"}], "answer": "ABC", "explanation": "根据《行政处罚法》第29条'一事不再罚'原则，对同一违法行为不得给予两次以上罚款的行政处罚。A项市县两级公安机关对同一行为分别罚款，违反一事不再罚。B项交通部门和公安机关对同一超载行为分别罚款，违反一事不再罚。C项城管和公安对同一噪音问题分别罚款，违反一事不再罚。D项工商局罚款与公安局拘留属于不同种类的处罚，不违反一事不再罚原则。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1145}, {"num": 1147, "batch": "专业基础知识", "type": "multi", "stem": "下列有关自行提供书面材料的说法不正确的有（）", "options": [{"letter": "A", "text": "只有被侵害人和证人才能请求自行提供书面材料"}, {"letter": "B", "text": "自行提供书面材料只能由被询问人自己提出，公安机关办案民警没权要求当事人自行书写"}, {"letter": "C", "text": "自行提供书面材料的，应当在其提供的书面材料之末页上签名"}, {"letter": "D", "text": "办案民警在收到书面材料后，应当在首页右下方写明收到日期，并签名"}], "answer": "ABD", "explanation": "根据《公安机关办理行政案件程序规定》，A项错误：违法嫌疑人、被侵害人和证人均可以请求自行提供书面材料，不限于被侵害人和证人。B项错误：办案民警也可以要求当事人自行书写书面材料，并非只能由被询问人主动提出。C项正确：自行提供的书面材料应当在末页签名。D项正确：办案民警收到后应在首页右下方写明收到日期并签名。题目问不正确的，答案为ABD。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1146}, {"num": 1148, "batch": "专业基础知识", "type": "multi", "stem": "下列有关罪名认定正确的是（）", "options": [{"letter": "A", "text": "甲抢劫致人死亡，构成抢劫罪和故意杀人罪"}, {"letter": "B", "text": "乙为讨回打麻将输给戊的3000元，将戊扣押在房间内2天，乙构成非法拘禁罪"}, {"letter": "C", "text": "丙明知赵某实施高利转贷行为获利200万元，仍为其提供资金账户隐瞒赃款来源，构成洗钱罪"}, {"letter": "D", "text": "丁组织多名男性卖淫，构成组织卖淫罪"}], "answer": "BCD", "explanation": "A项错误：抢劫致人死亡属于抢劫罪的结果加重犯，只构成抢劫罪一罪，不构成故意杀人罪。B项正确：为索取赌债等非法债务而扣押他人，构成非法拘禁罪。C项正确：明知他人实施高利转贷行为获利，仍提供资金账户帮助隐瞒来源，构成洗钱罪。D项正确：组织卖淫罪中的'他人'包括男性和女性，组织多名男性卖淫同样构成组织卖淫罪。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1147}, {"num": 1149, "batch": "专业基础知识", "type": "multi", "stem": "下列与犯罪故意和共犯有关的表述正确的是（）", "options": [{"letter": "A", "text": "甲一开始不知道现住自己家的张三是罪犯而收留，但在知道其是杀人犯后仍然加以隐藏，甲构成窝藏罪"}, {"letter": "B", "text": "乙为发展公司业务而正常申请贷款100万元。取得贷款后不久，公司业务停滞，乙便将贷款转贷牟利，乙构成高利转贷罪"}, {"letter": "C", "text": "丙发现李四将挪用公款所取得的款项放在家中，尚未使用，就“借用”李四的50万元公款购买毒品，丙属于挪用公款罪的共犯"}, {"letter": "D", "text": "丁（非国家工作人员）一开始并不知道丈夫田某（国家工作人员）多次受贿的事实，但在行贿人王五告知丁其有求于田某时，丁在田某同意下接受了王五提供的财物，丁构成受贿罪"}], "answer": "ABD", "explanation": "A项正确：甲知道张三是罪犯后仍继续隐藏，构成窝藏罪，因窝藏罪要求明知是犯罪的人。B项正确：乙取得贷款后改变用途转贷牟利，根据司法解释，可以认定为高利转贷罪。C项错误：丙借用挪用公款所得款项购买毒品，丙并非与国家工作人员共谋挪用，不构成挪用公款罪共犯。D项正确：丁在知情后接受贿赂，与国家工作人员形成受贿的共同故意，构成受贿罪共犯。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1148}, {"num": 1150, "batch": "专业基础知识", "type": "multi", "stem": "下列证人证言的收集程序、方式有一定瑕疵，经补正或者作出合理解释，仍可以采用的是（）", "options": [{"letter": "A", "text": "对某未成年证人询问时，其法定代理人虽然到场，但是侦查人员忘记要求其在笔录上签名"}, {"letter": "B", "text": "由于情况紧急，侦查人员将现场目击者带到现场附近的一个茶楼进行询问"}, {"letter": "C", "text": "侦查人员在对某民警刑讯逼供案的另一了解案情的民警进行询问时，由于该民警是多年的“老刑侦”，所以询问前没有告知其有关作证的权利、义务和法律责任"}, {"letter": "D", "text": "某斗殴案件的证人有2名，4名民警分两组同时对证人进行询问，但除了参与询问的民警的各自签名外，两份笔录上都有在场的刑侦部门负责人甲的签名"}], "answer": "ABCD", "explanation": "根据《关于办理刑事案件严格排除非法证据若干问题的规定》，证人证言瑕疵经补正或合理解释可以采用的包括：A项法定代理人到场但未签名属程序瑕疵可补正；B项询问地点不当属程序瑕疵可补正；C项未告知权利义务属程序瑕疵可补正；D项笔录签名人员问题属程序瑕疵可补正。以上瑕疵均非实质性违法，经补正或合理解释后仍可采用。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1149}, {"num": 1151, "batch": "专业基础知识", "type": "multi", "stem": "下列治安案件中，不能适用当场处罚的是（）", "options": [{"letter": "A", "text": "卖淫、嫖娼案件"}, {"letter": "B", "text": "引诱、容留、介绍卖淫案件"}, {"letter": "C", "text": "拉客招嫖案件"}, {"letter": "D", "text": "赌博案件"}], "answer": "ABCD", "explanation": "根据《公安机关办理行政案件程序规定》，卖淫嫖娼案件（A项）、引诱容留介绍卖淫案件（B项）、拉客招嫖案件（C项）、赌博案件（D项）均不适用当场处罚程序。这些案件通常涉及复杂的调查取证工作，需要进一步审查核实，不宜适用简易程序当场作出处罚决定。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1150}, {"num": 1152, "batch": "专业基础知识", "type": "multi", "stem": "下列做法错误的是（）", "options": [{"letter": "A", "text": "公安机关只记录了违法嫌疑人张某承认违法事实的陈述，而对张某的申辩未做记录"}, {"letter": "B", "text": "公安机关只收集了证明违法嫌疑人李某违法行为情节较重的证据，对于李某可从轻、减轻处罚的证据没有收集"}, {"letter": "C", "text": "公安机关认为被侵害人王某和证人甲的陈述较真实，就予以收集，对违法嫌疑人陈某本人的陈述和陈某朋友乙所作的有利于陈某的陈述没有收集"}, {"letter": "D", "text": "公安机关接到一起殴打他人案件后，未进行调查取证，就适用调解"}], "answer": "ABCD", "explanation": "A项错误：公安机关应当全面记录违法嫌疑人的陈述和申辩，不能只记录承认违法的部分。B项错误：公安机关应当全面收集证据，包括从轻、减轻处罚的证据。C项错误：公安机关应当全面客观收集证据，不能选择性收集。D项错误：调解必须在查明事实、收集证据的基础上进行，未调查取证就调解违反法定程序。ABCD四项做法均错误。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1151}, {"num": 1153, "batch": "专业基础知识", "type": "multi", "stem": "下列做法正确的是（）", "options": [{"letter": "A", "text": "张三在15岁时盗窃200元，公安机关作出拘留5日处罚并送达拘留所执行"}, {"letter": "B", "text": "张三在15岁时殴打他人后被罚200元，张三在17岁时又盗窃300元，公安机关作出拘留5日处罚并送达拘留所执行"}, {"letter": "C", "text": "张三在15岁时殴打他人后调解结案，张三在17岁时又盗窃300元，公安机关作出拘留5日处罚并送达拘留所执行"}, {"letter": "D", "text": "68周岁的张三殴打李四后逃跑，三年后公安机关抓获了张三，作出了拘留5日处罚并送达拘留所执行"}], "answer": "BC", "explanation": "A项错误：15岁属于已满14不满16周岁，依法不执行行政拘留。B项正确：17岁时已不属于不执行拘留的年龄段，虽然之前有违法记录但前次是罚款不是同类处罚两次以上，拘留可以执行。C项正确：前次调解结案不属于行政处罚记录，17岁盗窃被处拘留可以执行。D项错误：张三被抓获时已满71周岁（68+3），70周岁以上依法不执行行政拘留。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1152}, {"num": 1154, "batch": "专业基础知识", "type": "multi", "stem": "下列做法正确的有（）", "options": [{"letter": "A", "text": "因是在多民族共同居住的地区，当地的语言为畲语、仡佬语、赫哲语、鄂伦春语、鄂温克语五种，为了统一，公安机关对当地违法嫌疑人统一使用汉语进行询问"}, {"letter": "B", "text": "公安机关接到移送的案件后，重新计算了扣押期限"}, {"letter": "C", "text": "不让年龄超过80周岁不能正确表达的林某作为证人"}, {"letter": "D", "text": "使用圆珠笔填写有关法律文书"}], "answer": "BC", "explanation": "A项错误：在多民族共同居住地区，公安机关应当使用当地通用的语言进行询问，不能一律使用汉语。B项正确：公安机关接到移送案件后重新计算扣押期限符合程序规定。C项正确：超过80周岁不能正确表达的人不具备证人资格，不让其作证是正确的。D项错误：填写法律文书应使用钢笔或签字笔等不易褪色的书写工具，不应使用圆珠笔。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1153}, {"num": 1155, "batch": "专业基础知识", "type": "multi", "stem": "下面对鉴定、检测的叙述，错误的是（）", "options": [{"letter": "A", "text": "公安机关应当及时将鉴定意见告知违法嫌疑人和被侵害人"}, {"letter": "B", "text": "重新鉴定必须由当事人申请才能进行"}, {"letter": "C", "text": "当事人申请重新鉴定的，案件应当停止办理"}, {"letter": "D", "text": "违法嫌疑人或者被侵害人对鉴定意见有异议的，可以在5日内提出重新鉴定的申请"}], "answer": "BCD", "explanation": "A项正确：公安机关应当及时将鉴定意见告知违法嫌疑人和被侵害人。B项错误：重新鉴定不仅可以由当事人申请，公安机关也可以依职权决定。C项错误：当事人申请重新鉴定的，案件不应当停止办理，除非有特殊情况。D项错误：违法嫌疑人或被侵害人对鉴定意见有异议的，可以在3日内（而非5日）提出重新鉴定申请。题目问错误的选项，答案为BCD。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1154}, {"num": 1156, "batch": "专业基础知识", "type": "multi", "stem": "下述关于办理行政案件中辨认的做法正确的有（）", "options": [{"letter": "A", "text": "多名辨认人对同一辨认对象进行辨认时，应当分别进行"}, {"letter": "B", "text": "对违法嫌疑人的辨认，辨认人不愿意暴露身份的，可以在不暴露辨认人的情况下进行，办案民警应当为其保守秘密"}, {"letter": "C", "text": "组织辨认前，不能向辨认人详细询问辨认对象的具体特征"}, {"letter": "D", "text": "辨认违法嫌疑人时，被辨认的人数不得少于7人，对违法嫌疑人的照片进行辨认的，照片不得少于10张"}], "answer": "AB", "explanation": "根据《公安机关办理行政案件程序规定》关于辨认的规定，A项正确：多名辨认人对同一对象辨认时应分别进行。B项正确：辨认人不愿暴露身份的，可以在不暴露辨认人的情况下进行，民警应为其保密。C项错误：组织辨认前应当向辨认人详细询问辨认对象的具体特征。D项错误：辨认违法嫌疑人时被辨认人数不得少于7人，照片辨认不得少于10张，D项表述有误。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1155}, {"num": 1157, "batch": "专业基础知识", "type": "multi", "stem": "嫌疑人李某在与卖淫女刘某谈好价钱后来到刘某租住房准备发生性关系，被公安派出所民警抓获并带回公安派出所进行调查。下列材料不可以作为处罚根据的有（）", "options": [{"letter": "A", "text": "李某拒不供述，办案民警遂将李某双手反铐在窗户铁条上长达2个小时，李某扛不住便主动要求招供，并详细书写了与刘某谈价及发生性关系等全过程的材料"}, {"letter": "B", "text": "办案民警向刘某承诺，只要老实彻底地交代，就可以对其只进行治安警告处罚，刘某遂按照办案民警的提示非常配合地作了询问笔录"}, {"letter": "C", "text": "李某在与刘某谈价时，民工王某听到了二人的对话内容，办案人员对王某进行询问取得的材料"}, {"letter": "D", "text": "办案民警从刘某包内搜出的避孕套"}], "answer": "ABD", "explanation": "A项属于刑讯逼供取得的供述，根据非法证据排除规则，应当予以排除，不能作为处罚根据。B项属于以欺骗、诱导方式取得的笔录，违反了合法取证原则，不能作为处罚根据。C项民工王某的证人证言系合法取得的言词证据，可以作为处罚根据。D项搜出的避孕套虽为物证，但本案仅有谈价行为尚未发生性关系，该物证与违法事实的关联性不足。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1156}, {"num": 1158, "batch": "专业基础知识", "type": "multi", "stem": "小张是某市基层民警，5月23日上午9时，他依法对辖区内殴打邻居宋某的青年小赵当场进行了行政处罚。关于本案的处理做法错误的有（）", "options": [{"letter": "A", "text": "因其与青年小赵比较熟悉，小张没有表明身份"}, {"letter": "B", "text": "因其素知青年小赵是个流氓混混，且自己亲眼看到其殴打宋某的全过程，没有听取小赵的陈述与申辩，就当场开出了行政处罚决定书"}, {"letter": "C", "text": "5月25日下午1时，小张将处罚决定书送到了所在公安机关进行了备案"}, {"letter": "D", "text": "5月24日上午9时，小张将当场处罚决定书的复印件交到了宋某的手中"}], "answer": "ABC", "explanation": "A项错误：民警当场处罚时必须先表明执法身份，不能因熟悉就不表明。B项错误：即使当场处罚也必须听取当事人的陈述和申辩，这是法定程序。C项错误：当场处罚决定书应当在24小时内报所属公安机关备案，5月23日处罚5月25日才备案已超期。D项正确：当场处罚决定书副本应当送达被处罚人，而非被侵害人。题目问错误的做法，答案为ABC。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1157}, {"num": 1159, "batch": "专业基础知识", "type": "multi", "stem": "刑事案件中侦查人员询问证人时，下列做法错误的是（）", "options": [{"letter": "A", "text": "侦查人员甲，询问前向证人介绍了基本案情，告知证人应当如实提供证言"}, {"letter": "B", "text": "侦查人员乙，对拒绝作证的证人采取了拘留措施，保证了收集证据的及时性"}, {"letter": "C", "text": "侦查人员丙，询问17周岁的证人李某时，通知其父亲到场"}, {"letter": "D", "text": "侦查人员丁，传唤证人进行询问"}], "answer": "ABD", "explanation": "A项错误：询问证人前不得向证人介绍案情，以免影响证言的客观性和真实性。B项错误：对拒绝作证的证人不能采取拘留措施，拘留属于强制措施，不适用于证人。C项正确：询问未成年证人应当通知其法定代理人到场。D项错误：对证人不能使用传唤措施，传唤适用于违法犯罪嫌疑人，不适用于证人。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1158}, {"num": 1160, "batch": "专业基础知识", "type": "multi", "stem": "徐某（男，13周岁）、王某（男，14周岁）系同学。某日，二人看见摆水果摊的顾老太正在收摊，徐某对王某讲：“咱们搞两串香蕉吃。”于是二人走到顾老太水果摊前，一边问“香蕉怎么卖”，一边一人拿起一串香蕉，不等顾老太答话，撒腿就跑，正巧镇公安派出所的两位民警下班回家路过此处，将二人抓住。下列表述错误的有（）", "options": [{"letter": "A", "text": "徐某和王某都应当承担违反治安管理行为法律责任"}, {"letter": "B", "text": "徐某不承担违反治安管理行为法律责任，但应当责令其监护人严加管教"}, {"letter": "C", "text": "王某不承担违反治安管理行为法律责任，但应当责令其监护人严加管教"}, {"letter": "D", "text": "民警下班后抓获二人违反法律规定"}], "answer": "ACD", "explanation": "根据《治安管理处罚法》第12条，不满14周岁的人违反治安管理的，不予处罚但应责令监护人严加管教。A项错误：徐某13岁不承担法律责任，但王某14岁应当承担。B项正确：徐某不承担责任应责令监护人管教。C项错误：王某已满14周岁应当承担责任。D项错误：民警下班后抓获违法嫌疑人不违反法律规定，人民警察有随时制止违法犯罪的职责。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1159}, {"num": 1161, "batch": "专业基础知识", "type": "multi", "stem": "徐某因胁迫顾某（男，现年14岁）乞讨，被公安机关发现，现案件正在办理过程中，顾某父亲顾大某作为顾某的法定代理人。徐某欲申请办理该案件的人民警察杜某回避，下列哪些情形中，其回避申请应当被同意？（）", "options": [{"letter": "A", "text": "杜某曾于半年前因酒后值班被单位作出纪律处分"}, {"letter": "B", "text": "顾大某对杜某有救命之恩，杜某表示一定要找机会感谢顾某一家"}, {"letter": "C", "text": "杜某系顾某的舅舅"}, {"letter": "D", "text": "杜某业务能力差，去年在全单位排名倒数第二"}], "answer": "BC", "explanation": "根据《公安机关办理行政案件程序规定》关于回避的规定，B项杜某与当事人有恩惠关系可能影响公正处理，属于应当回避的情形。C项杜某系顾某的舅舅，属于与当事人有近亲属关系，应当回避。A项杜某酒后值班被处分与本案公正处理无直接关联，不属于法定回避事由。D项业务能力差不属于法定回避事由。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1160}, {"num": 1162, "batch": "专业基础知识", "type": "multi", "stem": "询问聋、哑违法嫌疑人,应当有通晓手语的人参加,并在询问笔录上注明（）", "options": [{"letter": "A", "text": "违法嫌疑人的聋哑情况"}, {"letter": "B", "text": "翻译人的姓名"}, {"letter": "C", "text": "翻译人的住址"}, {"letter": "D", "text": "翻译人的工作单位和联系方式"}], "answer": "ABCD", "explanation": "根据《公安机关办理行政案件程序规定》，询问聋、哑违法嫌疑人时，应当有通晓手语的人参加，并在询问笔录上注明违法嫌疑人的聋哑情况（A项）、翻译人的姓名（B项）、翻译人的住址（C项）以及翻译人的工作单位和联系方式（D项），以确保翻译程序的规范性和可追溯性。ABCD四项均为应当注明的内容。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1161}, {"num": 1163, "batch": "专业基础知识", "type": "multi", "stem": "一天，有人举报李某殴打他人，民警即口头传唤李某到公安派出所进行查证，但未告知其原因。在李某问及原因时，民警说以后告知你的家属。经调查发现，李某殴打他人的事实涉嫌刑事犯罪，公安机关遂撤销了行政案件，将案件转为刑事案件办理。此时，民警将传唤的原因和处所通知了李某的家属，同时将此前的询问笔录作为该案的证据使用。公安机关在办理该案中做法错误的是（）", "options": [{"letter": "A", "text": "未将传唤的原因和依据告知被传唤人"}, {"letter": "B", "text": "在转为刑事案件后才将传唤的原因和处所通知被传唤人家属"}, {"letter": "C", "text": "撤销行政案件"}, {"letter": "D", "text": "询问笔录作为证据在刑事诉讼中使用"}], "answer": "ABCD", "explanation": "A项错误：口头传唤时应当告知被传唤人传唤的原因和依据，民警未告知违反法定程序。B项错误：传唤后应当及时通知被传唤人家属，不应等到转为刑事案件后才通知。C项错误：行政案件转刑事案件办理时，应当将案件移送有管辖权的部门，而非简单撤销行政案件。D项错误：行政程序中取得的询问笔录在刑事诉讼中作为证据使用需符合刑事诉讼的证据规则，不能直接作为刑事案件证据使用。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1162}, {"num": 1164, "batch": "专业基础知识", "type": "multi", "stem": "依法取得的行政许可，除（）规定依照法定条件和程序可以转让的外，不得转让。", "options": [{"letter": "A", "text": "法律"}, {"letter": "B", "text": "行政法规"}, {"letter": "C", "text": "地方性法规"}, {"letter": "D", "text": "省级人民政府规章"}], "answer": "ABC", "explanation": "根据《行政许可法》第9条规定，依法取得的行政许可，除法律、行政法规、地方性法规规定依照法定条件和程序可以转让的外，不得转让。省级人民政府规章无权规定行政许可的转让条件和程序，因此D项不属于可以规定转让的依据。ABC三项均为法律明确授权可以规定行政许可转让的规范性文件。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1163}, {"num": 1165, "batch": "专业基础知识", "type": "multi", "stem": "依照有关人民法院对行政诉讼案件受案范围的规定，下列不属于人民法院受案范围的是（）", "options": [{"letter": "A", "text": "政府解除其与某污水再生公司签订的特许经营协议"}, {"letter": "B", "text": "王某不服因其违反纪律被所在机关作出的降职处理决定"}, {"letter": "C", "text": "对村民张某擅自搭建的房屋，本村村民委员会自行组织拆除"}, {"letter": "D", "text": "张某对我国某外事活动不服"}], "answer": "BCD", "explanation": "根据《行政诉讼法》及相关司法解释，A项政府解除特许经营协议属于行政协议纠纷，属于人民法院受案范围。B项机关内部降职处理属于内部行政行为，不属于受案范围。C项村委会自行组织拆除不属于行政行为，不属于行政诉讼受案范围。D项外事活动属于国家行为，不属于受案范围。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1164}, {"num": 1166, "batch": "专业基础知识", "type": "multi", "stem": "以下（）情况中，给公民、法人或者其他组织造成财产损失的，行政机关无须予以补偿或赔偿。", "options": [{"letter": "A", "text": "李某依法取得了在江边某处采砂的许可，后为了防洪筑坝的需要，行政机关撤回了该许可"}, {"letter": "B", "text": "猎户赵某违反规定滥捕滥杀野生动物，为了保护野生动物，赵某的持枪证被行政机关吊销，猎枪也被没收"}, {"letter": "C", "text": "陈某申请食品生产许可，行政工作人员玩忽职守，未经实地检查其场地条件就批准了该申请，后在行政机关的监督检查过程中，撤销了该许可"}, {"letter": "D", "text": "王某在不符合条件的情况下，为了取得生猪屠宰许可而贿赂行政机关工作人员白某，后王某的许可证被依法撤销"}], "answer": "BCD", "explanation": "A项因公共利益需要撤回许可，应当给予补偿。B项因违法被吊销没收，属于行政处罚，无须补偿。C项因行政机关工作人员玩忽职守导致许可被撤销，但过错在于申请人未满足条件，被许可人无须补偿。D项因贿赂取得的许可被撤销，属于申请人违法，无须补偿。题目问无须补偿或赔偿的情形，答案为BCD。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1165}, {"num": 1167, "batch": "专业基础知识", "type": "multi", "stem": "以下不属于行政许可的是（）", "options": [{"letter": "A", "text": "公证处为邓甲向其侄邓乙赠与房产合同办理公证"}, {"letter": "B", "text": "北京市某区公安分局为朱某办理入京户口"}, {"letter": "C", "text": "工商局为某个人独资企业办理税务登记"}, {"letter": "D", "text": "国土资源管理局批准将一块土地划拨给某高校建新校区"}], "answer": "ABC", "explanation": "A项公证属于证明行为，不是行政许可。B项办理户口属于行政确认行为，不是行政许可。C项税务登记属于行政登记行为，不是行政许可。D项土地划拨审批属于行政审批，可能具有行政许可性质。行政许可是指行政机关根据申请，经依法审查准予从事特定活动的行为，ABC三项均不符合行政许可的本质特征。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1166}, {"num": 1168, "batch": "专业基础知识", "type": "multi", "stem": "以下不宜暂缓执行行政拘留的情形有（）", "options": [{"letter": "A", "text": "被处罚人暂缓执行行政拘留后可能逃跑的"}, {"letter": "B", "text": "被处罚人还有其他违法犯罪嫌疑，正在被调查或者侦查的"}, {"letter": "C", "text": "被处罚人在当地没有常住户口的"}, {"letter": "D", "text": "被处罚人没有承认自己违法行为的"}], "answer": "AB", "explanation": "根据《治安管理处罚法》第107条及相关规定，不宜暂缓执行行政拘留的情形包括：被处罚人暂缓执行后可能逃跑的（A项）；被处罚人还有其他违法犯罪嫌疑正在被调查或侦查的（B项）。C项在当地没有常住户口和D项没有承认违法行为，不是法定不宜暂缓执行的情形。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1167}, {"num": 1169, "batch": "专业基础知识", "type": "multi", "stem": "以下不应该设定行政许可事项的有（）", "options": [{"letter": "A", "text": "某市为了振兴本市农业发展，规定本市以外其他地区农产品进入本地市场的，应当经过市政府审批"}, {"letter": "B", "text": "某县为了筹集教育经费，规定凡在本县经营饭店旅馆需要经过县政府批准"}, {"letter": "C", "text": "某市为了打造繁华的商业区，规定在该区买居住用房需经过市房管局的批准"}, {"letter": "D", "text": "法律规定从事律师、执业医师、注册会计师、注册税务师等须取得从业资格"}], "answer": "ABC", "explanation": "根据《行政许可法》第12条和第15条，A项属于地方保护主义限制措施，违法设定行政许可。B项以筹集经费为目的设定许可，目的不当，不应设定。C项购买居住用房不需行政许可审批，属于不当干预市场。D项法律规定的从业资格属于合法的行政许可设定，符合《行政许可法》第12条的规定。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1168}, {"num": 1170, "batch": "专业基础知识", "type": "multi", "stem": "以下对暂缓执行行政拘留担保人处罚不正确的有（）", "options": [{"letter": "A", "text": "担保人甲，发现被担保人有出逃意图后立即予以阻止，同时向公安机关电话报告，但等公安机关到达时，被担保人已将甲推倒后逃跑。公安机关据此对甲作出从轻处罚"}, {"letter": "B", "text": "公安机关发现担保人乙，在担任担保人期间长期在外做生意，没有履行担保义务，就对乙作出了罚款处罚"}, {"letter": "C", "text": "担保人丙，因没有履行担保义务，致使被担保人逃往了外地，事后丙就想办法帮助公安机关抓获了丙，但公安机关没有据此对丙不予处罚"}, {"letter": "D", "text": "担保人丁，因没有很好履行担保义务，致使被担保人逃往了外地，丁就一路追踪，最终将被担保人抓获，送至公安机关，据此公安机关对丁不予处罚"}], "answer": "AB", "explanation": "根据《治安管理处罚法》第107条和相关规定，A项甲已尽力阻止并报告，履行了担保义务，不应处罚，公安机关对其从轻处罚是错误的。B项公安机关发现担保人未履行义务应先责令其限期改正，直接罚款不正确。C项丙事后帮助抓获被担保人，公安机关可以不处罚但未明确不予处罚，做法不当。D项丁自行将被担保人抓获送交公安机关，不予处罚是正确的。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1169}, {"num": 1171, "batch": "专业基础知识", "type": "multi", "stem": "以下公安机关办理行政案件中对涉案物品估价理解正确的有（）", "options": [{"letter": "A", "text": "涉案物品价值不明的，公安机关应当委托价格鉴定部门估价"}, {"letter": "B", "text": "涉案物品价值无法确定的，公安机关应当委托价格鉴定部门估价"}, {"letter": "C", "text": "根据当事人提供的发票等票据公安机关认为能够认定价值，即使违法嫌疑人有异议公安机关也不应进行价格鉴定"}, {"letter": "D", "text": "价值明显不够刑事立案标准的，公安机关可以不进行价格鉴定"}], "answer": "ABD", "explanation": "根据《公安机关办理行政案件程序规定》，A项正确：涉案物品价值不明的，公安机关应当委托价格鉴定部门估价。B项正确：涉案物品价值无法确定的，也应当委托估价。C项错误：即使有发票等票据，如果违法嫌疑人有异议且有合理理由，公安机关仍应进行价格鉴定。D项正确：价值明显不够刑事立案标准的，可以不进行价格鉴定。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1170}, {"num": 1172, "batch": "专业基础知识", "type": "multi", "stem": "以下公安机关对行政处罚中加处罚款的说法正确的有（）", "options": [{"letter": "A", "text": "加处罚款的前提一是被处罚人无正当理由未在行政处罚决定书规定的期限内到指定的银行缴纳，二是被处罚人没有被依法查封、扣押的财物。两者缺一不可"}, {"letter": "B", "text": "行政处罚决定书上明确需要加处罚款的，公安机关不必另行开具书面通知，由代收机构每日按照罚款数额的３％直接收取"}, {"letter": "C", "text": "加处罚款性质上属于“强制金”，是一种强制措施，因此，不适用罚缴分离的原则"}, {"letter": "D", "text": "对加处罚款不服的可以申请行政复议或者提起行政诉讼"}], "answer": "ABCD", "explanation": "A项正确：加处罚款的前提条件包括逾期未缴纳且没有被查封扣押的财物。B项正确：处罚决定书明确加处罚款的，由代收机构每日按罚款数额的3%直接收取。C项正确：加处罚款属于行政强制执行中的'强制金'，不适用罚缴分离原则。D项正确：对加处罚款不服的，可以依法申请行政复议或提起行政诉讼。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1171}, {"num": 1173, "batch": "专业基础知识", "type": "multi", "stem": "以下关于公安机关办理行政案件，重新鉴定指派或者聘请鉴定人说法正确的有（）", "options": [{"letter": "A", "text": "可以指派或者聘请原鉴定人"}, {"letter": "B", "text": "应当指派或者聘请原鉴定人"}, {"letter": "C", "text": "应当另行指派或者聘请鉴定人"}, {"letter": "D", "text": "可以继续指派或者聘请原鉴定机构的其他鉴定人"}], "answer": "CD", "explanation": "根据《公安机关办理行政案件程序规定》，重新鉴定应当另行指派或者聘请鉴定人（C项正确），不能由原鉴定人重新鉴定，以保证鉴定的客观公正。但可以由原鉴定机构的其他鉴定人进行（D项正确），因为不同鉴定人独立作出鉴定意见即可保证公正性。A项和B项允许原鉴定人参与重新鉴定，不符合规定。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1172}, {"num": 1174, "batch": "专业基础知识", "type": "multi", "stem": "以下关于公安机关办理行政案件的辨认说法不正确的有（）", "options": [{"letter": "A", "text": "辨认是公安机关的一种调查手段，是办理行政案件的必经环节"}, {"letter": "B", "text": "办理行政案件中的辨认必须经公安派出所或者县级以上公安机关办案部门负责人批准"}, {"letter": "C", "text": "公安机关办理行政案件中辨认的主体只能是违法嫌疑人和被侵害人"}, {"letter": "D", "text": "公安机关办理行政案件中辨认的对象包括违法嫌疑人"}], "answer": "ABC", "explanation": "A项错误：辨认不是办理行政案件的必经环节，只是调查手段之一，并非所有案件都需要辨认。B项错误：辨认需经办案部门负责人批准，但不是所有辨认都必须经公安派出所或县级以上公安机关办案部门负责人批准。C项错误：辨认的主体不仅包括违法嫌疑人和被侵害人，还包括证人等。D项正确：辨认对象确实包括违法嫌疑人。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1173}, {"num": 1175, "batch": "专业基础知识", "type": "multi", "stem": "以下关于公安机关办理行政案件的辨认说法正确的有（）", "options": [{"letter": "A", "text": "公安机关办理行政案件中辨认的目的是为了查明案情"}, {"letter": "B", "text": "公安机关办理行政案件中办案人民警察认为有必要时就可以组织辨认"}, {"letter": "C", "text": "公安机关办理行政案件中辨认的主体包括人民警察"}, {"letter": "D", "text": "公安机关办理行政案件中辨认的对象主要包括与违法行为有关的物品、场所"}], "answer": "ABCD", "explanation": "根据《公安机关办理行政案件程序规定》关于辨认的规定，A项正确：辨认的目的是为了查明案情。B项正确：办案人民警察认为有必要时可以组织辨认。C项正确：辨认的主体包括办案人民警察，由民警组织并主持辨认。D项正确：辨认的对象包括与违法行为有关的物品、场所等，也包括违法嫌疑人。ABCD四项表述均正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1174}, {"num": 1176, "batch": "专业基础知识", "type": "multi", "stem": "以下关于公安机关办理行政案件时鉴定的说法正确的有（）", "options": [{"letter": "A", "text": "鉴定的目的是为了查明案情"}, {"letter": "B", "text": "鉴定的对象是有争议的专门性技术问题"}, {"letter": "C", "text": "鉴定的决定权在公安机关"}, {"letter": "D", "text": "鉴定人由公安机关指定或者当事人聘请"}], "answer": "ABC", "explanation": "根据《公安机关办理行政案件程序规定》关于鉴定的规定，A项正确：鉴定的目的是为了查明案情中涉及的专门性技术问题。B项正确：鉴定的对象是有争议的专门性技术问题。C项正确：鉴定的决定权在公安机关，由公安机关决定是否需要进行鉴定。D项错误：鉴定人由公安机关指派或者聘请，当事人不能自行聘请鉴定人。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1175}, {"num": 1177, "batch": "专业基础知识", "type": "multi", "stem": "以下关于公安机关办理行政案件中的扣押说法不正确的有（）", "options": [{"letter": "A", "text": "扣押必须由2名及以上民警进行"}, {"letter": "B", "text": "扣押物品清单上只需1名承办民警签名即可"}, {"letter": "C", "text": "物品持有人不在现场或者持有人不明的不能扣押"}, {"letter": "D", "text": "扣押的只能是物品，对于文件不能扣押"}], "answer": "BCD", "explanation": "A项正确：扣押可以由2名及以上民警进行，但并非强制要求必须2名以上。B项错误：扣押物品清单上应当由承办民警签名，但也需要持有人或见证人签名，不能仅1名民警签名。C项错误：物品持有人不在现场或持有人不明的，只要有见证人在场，仍然可以扣押。D项错误：扣押的对象不仅包括物品，还包括与案件有关的文件、资料等。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1176}, {"num": 1178, "batch": "专业基础知识", "type": "multi", "stem": "以下关于公安机关办理行政案件中的扣押说法正确的有（）", "options": [{"letter": "A", "text": "扣押时有见证人的还应当由见证人签名"}, {"letter": "B", "text": "如果需要发还被扣押物品的，应开具发还物品清单并由领取人签名"}, {"letter": "C", "text": "扣押物品清单应当当场开列"}, {"letter": "D", "text": "扣押由办案民警自定，扣押前无需审批"}], "answer": "ACD", "explanation": "A项正确：扣押时有见证人的应当由见证人签名，以保证扣押程序的合法性。B项错误：发还被扣押物品应开具发还物品清单，但相关规定中并未要求必须由领取人签名。C项正确：扣押物品清单应当当场开列，一式两份。D项正确：扣押由办案民警根据案件需要自行决定，扣押前无需专门审批。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1177}, {"num": 1179, "batch": "专业基础知识", "type": "multi", "stem": "以下关于行政拘留说法不正确的有（）", "options": [{"letter": "A", "text": "受行政拘留处罚的人应当在限定的时间内，自行到指定的拘留所接受处罚"}, {"letter": "B", "text": "对于抗拒行政拘留执行的，公安机关可以使用约束性警械强制执行"}, {"letter": "C", "text": "被处罚人在被行政拘留执行期间的生活费由被处罚人自行承担"}, {"letter": "D", "text": "被处罚人在被行政拘留期间，因行政拘留而被剥夺选举权和被选举权"}], "answer": "ACD", "explanation": "A项错误：被行政拘留处罚的人由公安机关送达拘留所执行，而非自行前往。B项正确：对于抗拒执行的，公安机关可以使用约束性警械强制执行。C项错误：被拘留期间的生活费由公安机关承担，而非由被处罚人自行承担。D项错误：行政拘留不剥夺选举权和被选举权，被拘留人仍享有政治权利。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1178}, {"num": 1180, "batch": "专业基础知识", "type": "multi", "stem": "以下关于收买被拐卖的妇女、儿童犯罪行为的说法正确的是（）", "options": [{"letter": "A", "text": "甲明知收买的妇女是精神病患者或者痴呆者（程度严重）而与其发生性关系，以强奸罪立案侦查"}, {"letter": "B", "text": "乙收买被拐卖的儿童后又出卖，以拐卖儿童罪立案侦查"}, {"letter": "C", "text": "丙非法限制被拐卖的妇女、儿童的人身自由，以非法拘禁罪立案侦查"}, {"letter": "D", "text": "丁明知被拐卖的妇女是现役军人的妻子而与之同居，以破坏军婚罪立案侦查"}], "answer": "ABCD", "explanation": "根据相关司法解释，A项正确：明知收买的妇女是精神病患者或痴呆者而与其发生性关系的，以强奸罪立案侦查。B项正确：收买被拐卖的儿童后又出卖的，以拐卖儿童罪立案侦查。C项正确：非法限制被拐卖妇女儿童人身自由的，以非法拘禁罪立案侦查。D项正确：明知被拐卖的妇女是现役军人妻子而与之同居的，以破坏军婚罪立案侦查。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1179}, {"num": 1181, "batch": "专业基础知识", "type": "multi", "stem": "以下关于烟花爆竹的燃放的表述，正确的有（）", "options": [{"letter": "A", "text": "某县政府根据本行政区域的实际情况确定禁止燃放烟花爆竹的时间、地点"}, {"letter": "B", "text": "广播、电视、报刊等新闻媒体应当做好安全燃放烟花爆竹的宣传工作"}, {"letter": "C", "text": "未成年人的监护人应当对未成年人进行安全燃放烟花爆竹的教育"}, {"letter": "D", "text": "某乡镇为了保护人民财产安全，确定了乡政府1000米范围内禁止燃放烟花爆竹"}], "answer": "ABC", "explanation": "根据《烟花爆竹安全管理条例》，A项正确：县级以上政府可以根据本行政区域实际情况确定禁止燃放的时间、地点。B项正确：新闻媒体应当做好安全燃放烟花爆竹的宣传工作。C项正确：未成年人的监护人应当对未成年人进行安全燃放教育。D项错误：确定禁放区域的权力属于县级以上政府，乡镇政府无权确定禁放区域。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1180}, {"num": 1182, "batch": "专业基础知识", "type": "multi", "stem": "以下行政处罚暂缓执行说法正确的有（）", "options": [{"letter": "A", "text": "罚款和拘留都可被暂缓执行"}, {"letter": "B", "text": "违反治安管理处罚和其他公安行政案件被处以行政拘留都可被暂缓执行"}, {"letter": "C", "text": "只有因违反治安管理的行为而依法作出的行政拘留决定才可被暂缓执行"}, {"letter": "D", "text": "拘留暂缓执行的，罚款也要一并暂缓"}], "answer": "AB", "explanation": "根据《治安管理处罚法》第107条及相关规定，A项正确：根据相关规定，罚款和行政拘留都可以暂缓执行。B项正确：因违反治安管理处罚和其他公安行政案件被处以行政拘留的，都可以申请暂缓执行。C项错误：暂缓执行不限于违反治安管理行为。D项正确：拘留暂缓执行的，附带的罚款也应一并暂缓执行。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1181}, {"num": 1183, "batch": "专业基础知识", "type": "multi", "stem": "以下可以设定行政许可的有（）", "options": [{"letter": "A", "text": "法律"}, {"letter": "B", "text": "行政法规"}, {"letter": "C", "text": "地方性法规"}, {"letter": "D", "text": "国务院决定"}], "answer": "ABCD", "explanation": "根据《行政许可法》第14条至第17条，可以设定行政许可的规范性文件包括：法律（A项）、行政法规（B项）、地方性法规（C项）、国务院决定（D项）。其中，法律可以设定各类行政许可；尚未制定法律的，行政法规可以设定；尚未制定法律、行政法规的，地方性法规可以设定；必要时国务院可以采用发布决定的方式设定。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1182}, {"num": 1184, "batch": "专业基础知识", "type": "multi", "stem": "以下是某公安机关在行政案件辨认中的一些做法，其中不正确的有（）", "options": [{"letter": "A", "text": "因为时间较紧办案民警决定让被侵害人对违法嫌疑人直接见面辨认"}, {"letter": "B", "text": "为了试探违法嫌疑人陈述的可信度，办案民警让违法嫌疑人对与案件无关的某物品进行辨认"}, {"letter": "C", "text": "为了提高辨认的效率，办案民警让被侵害人和证人同时对违法嫌疑人辨认"}, {"letter": "D", "text": "为了保证准确性，办案民警让被侵害人在辨认前先与被抓获违法嫌疑人直接见了个面，再组织辨认"}], "answer": "ABCD", "explanation": "A项错误：不应让被侵害人与违法嫌疑人直接见面辨认，应当采用混杂辨认的方式。B项错误：辨认应当针对与案件有关的对象，不应让嫌疑人辨认与案件无关的物品。C项错误：多名辨认人对同一对象辨认时应当分别进行，不能同时进行。D项错误：辨认前不应让辨认人与被辨认人提前接触，以免影响辨认的客观性。ABCD四项做法均不正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1183}, {"num": 1185, "batch": "专业基础知识", "type": "multi", "stem": "以下是某民警对治安调解的理解，其中不正确的有（）", "options": [{"letter": "A", "text": "调解是选择性的，它不是办理行政案件的必经程序"}, {"letter": "B", "text": "有些案件可以进行现场调解"}, {"letter": "C", "text": "调解一经达成协议，公安机关就不再处罚"}, {"letter": "D", "text": "调解案件的办案期限从调解未达成协议或者调解达成协议不履行之日起计算，所以在受理时不必填写受案登记表"}], "answer": "CD", "explanation": "A项正确：调解是选择性的，不是办理行政案件的必经程序。B项正确：部分案件可以进行现场调解。C项错误：调解达成协议后，如果当事人不履行的，公安机关仍应依法对违法行为人给予处罚。D项错误：调解案件在受理时仍应填写受案登记表，办案期限从受理之日起计算，调解不成或协议不履行的，从该日起继续计算剩余期限。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1184}, {"num": 1186, "batch": "专业基础知识", "type": "multi", "stem": "以下属于《公安机关办理行政案件程序规定》所列证据种类的有（）", "options": [{"letter": "A", "text": "人体毒品成分检测结论"}, {"letter": "B", "text": "酒精度检测结论"}, {"letter": "C", "text": "价格鉴定意见"}, {"letter": "D", "text": "精神病法医学鉴定意见"}], "answer": "ABCD", "explanation": "根据《公安机关办理行政案件程序规定》第30条，证据种类包括：物证、书证、证人证言、违法嫌疑人的陈述和申辩、被侵害人的陈述、鉴定意见、检测结论、勘验检查笔录、现场笔录、视听资料和电子数据等。A项人体毒品成分检测结论、B项酒精度检测结论、C项价格鉴定意见、D项精神病法医学鉴定意见均属于鉴定意见或检测结论类证据。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1185}, {"num": 1187, "batch": "专业基础知识", "type": "multi", "stem": "以下属于犯罪既遂的是（）", "options": [{"letter": "A", "text": "甲为了烧死邻居（与多人的住房连在一起）一家，深夜用火柴点燃邻居家门口墙边的柴垛后离开，后因下雨把火浇灭"}, {"letter": "B", "text": "乙趁邻居家4岁小女孩家长不在家，以给吃糖果为由，把小女孩骗进家里，脱了裤子后用生殖器顶撞小女孩的阴部"}, {"letter": "C", "text": "丙窜入农户家盗窃，未窃得财物"}, {"letter": "D", "text": "丁在远处开枪射杀仇人，却把和仇人长相、衣着相似的另一人击中，致其死亡"}], "answer": "ABCD", "explanation": "A项放火罪是危险犯，点燃柴垛即已着手实施，构成放火罪既遂，下雨浇灭不影响既遂成立。B项乙对幼女实施猥亵行为已构成猥亵儿童罪既遂。C项丙窜入农户家中实施入户盗窃，入户盗窃不以窃得财物为既遂条件，进入住宅即构成既遂。D项丁虽射杀对象错误，但已造成他人死亡结果，构成故意杀人罪既遂（对象错误不影响既遂认定）。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1186}, {"num": 1188, "batch": "专业基础知识", "type": "multi", "stem": "以下属于犯罪预备的是（）", "options": [{"letter": "A", "text": "甲为了实施盗窃，购买了螺丝刀、小刀"}, {"letter": "B", "text": "乙为了杀死仇人，打探仇人的行动轨迹"}, {"letter": "C", "text": "丙为了实施绑架，尾随作案目标"}, {"letter": "D", "text": "丁在网上发帖，声称要杀死情敌"}], "answer": "ABC", "explanation": "根据《刑法》第22条，犯罪预备是指为了犯罪准备工具、制造条件的行为。A项购买螺丝刀等工具属于准备工具。B项打探仇人行踪属于制造条件。C项尾随作案目标属于制造条件。D项在网上发帖声称要杀死情敌仅属于犯意表示（犯意流露），尚未实施任何预备行为，不构成犯罪预备。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1187}, {"num": 1189, "batch": "专业基础知识", "type": "multi", "stem": "以下属于公安机关办理行政案件证据种类的是（）", "options": [{"letter": "A", "text": "违法嫌疑人的陈述和申辩"}, {"letter": "B", "text": "视听资料、电子证据"}, {"letter": "C", "text": "鉴定意见、检测结论"}, {"letter": "D", "text": "勘验、检查笔录，现场笔录"}], "answer": "ABCD", "explanation": "根据《公安机关办理行政案件程序规定》第30条，公安机关办理行政案件的证据种类包括：物证、书证、证人证言、被侵害人陈述、违法嫌疑人的陈述和申辩（A项）、鉴定意见、检测结论（C项）、勘验、检查笔录和现场笔录（D项）、视听资料和电子数据（B项）、辨认笔录等。ABCD四项均属于法定证据种类。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1188}, {"num": 1190, "batch": "专业基础知识", "type": "multi", "stem": "以下属于行政许可行为的是（）", "options": [{"letter": "A", "text": "交警大队作出交通事故的责任认定"}, {"letter": "B", "text": "市司法局向赵某颁发律师执照"}, {"letter": "C", "text": "文化局批准孙某经营娱乐城"}, {"letter": "D", "text": "工商局为陈某、李某、钱某拟设立的有限责任公司办理登记"}], "answer": "BCD", "explanation": "行政许可是指行政机关根据申请，经依法审查准予从事特定活动的行为。A项交通事故责任认定属于行政确认行为，不是行政许可。B项颁发律师执照属于资格许可。C项批准经营娱乐城属于普通许可。D项公司登记属于登记类行政许可，赋予其经营主体资格。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1189}, {"num": 1191, "batch": "专业基础知识", "type": "multi", "stem": "以下说法不正确的有（）", "options": [{"letter": "A", "text": "对同一违法行为，其他行政机关已经给予了罚款行政处罚的，公安机关就不能再给予罚款行政处罚"}, {"letter": "B", "text": "违法行为构成犯罪时，还应当追究刑事责任的，罚款不能折抵相应的罚金"}, {"letter": "C", "text": "对同一违法行为，其他行政机关已经给予了罚款行政处罚的，公安机关可以给予罚款以外的其他种类的行政处罚"}, {"letter": "D", "text": "对同一违法行为，各执法机关可重复罚款"}], "answer": "BD", "explanation": "A项正确：根据《行政处罚法》第29条，其他行政机关已给予罚款的，公安机关不能再给予罚款。B项错误：根据《行政处罚法》第35条，违法行为构成犯罪时，已执行的罚款应当折抵相应的罚金，而非不能折抵。C项正确：其他机关已罚款的，公安机关可以给予罚款以外的其他种类处罚。D项错误：各执法机关不得对同一违法行为重复罚款。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1190}, {"num": 1192, "batch": "专业基础知识", "type": "multi", "stem": "以下物品公安机关可以收缴的是（）", "options": [{"letter": "A", "text": "张三在倒卖船票过程中被查获的真船票"}, {"letter": "B", "text": "张三在倒卖船票过程中被查获的假船票"}, {"letter": "C", "text": "李四去盗窃时从朋友处借来的汽车"}, {"letter": "D", "text": "王五退伍时从部队拿来的10发子弹"}], "answer": "ABD", "explanation": "根据《治安管理处罚法》第11条和相关规定，A项倒卖的真船票属于与违法行为有关的财物，可以收缴。B项假船票属于伪造的物品，应当收缴。C项借来的汽车属于被害人的合法财产，应当退还所有人，不属于收缴范围。D项退伍时拿走的子弹属于违禁品，可以收缴。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1191}, {"num": 1193, "batch": "专业基础知识", "type": "multi", "stem": "以下应当予以结案的行政案件有（）", "options": [{"letter": "A", "text": "作出不予处罚决定的"}, {"letter": "B", "text": "适用调解程序的案件达成协议的"}, {"letter": "C", "text": "作出行政处罚等处理决定，且已执行的"}, {"letter": "D", "text": "违法行为涉嫌构成犯罪，转为刑事案件办理的"}], "answer": "ACD", "explanation": "根据《公安机关办理行政案件程序规定》，应当予以结案的行政案件包括：作出不予处罚决定的（A项）；作出行政处罚等处理决定且已执行的（C项）；违法行为涉嫌构成犯罪转为刑事案件办理的（D项）。B项调解达成协议的，还需等待协议履行完毕，协议不履行的仍需处罚，不能直接结案。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1192}, {"num": 1194, "batch": "专业基础知识", "type": "multi", "stem": "以下有关办理行政案件的做法不当的有（）", "options": [{"letter": "A", "text": "违法嫌疑人李某在铁证面前还是拒不交代，为挫败其顽固心理，办案民警用手铐铐住李某"}, {"letter": "B", "text": "违法嫌疑人张某无故谩骂办案民警，为打击其嚣张气焰，办案民警对其使用警绳捆绑"}, {"letter": "C", "text": "违法嫌疑人赵某趁民警不备，意欲行凶被办案民警发现，为防止赵某继续行凶，办案民警将其铐住"}, {"letter": "D", "text": "违法嫌疑人陈某趁民警不备意欲脱逃，办案民警用警绳将其捆绑，经家属做工作，陈某放弃了脱逃念头开始交代，办案民警为防万一，一直未给陈某松绑"}], "answer": "ABD", "explanation": "A项不当：对拒不交代的嫌疑人使用手铐属于违法使用警械，不能以'挫败顽固心理'为由使用。B项不当：对谩骂民警的嫌疑人使用警绳捆绑违反警械使用规定，谩骂不构成使用警械的法定情形。C项正确：对意欲行凶的嫌疑人使用警械属于合法使用，防止其继续行凶。D项不当：嫌疑人已放弃脱逃念头后应当及时解除约束措施，一直不松绑属违法使用警械。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1193}, {"num": 1195, "batch": "专业基础知识", "type": "multi", "stem": "以下做法不正确的有（）", "options": [{"letter": "A", "text": "张三在2007年1月1日从李四处扒窃一次得赃款100元，公安机关没有发现该案，至2007年8月1日被公安机关发现抓获，对张三不再给予行政处罚"}, {"letter": "B", "text": "张三在2007年1月1日从李四处扒窃一次得赃款100元，李四报案后公安机关不予受理，至2008年3月1日张三被李四扭送到公安机关，对张三不予行政处罚"}, {"letter": "C", "text": "张三在2007年1月1日从李四处扒窃一次得赃款100元，但公安机关一直未能查实该案为张三所作，至2008年3月1日才破案，对张三应予行政处罚"}, {"letter": "D", "text": "张三在2007年1月1日从李四处扒窃一次得赃款100元，李四未报案，2007年10月1日打伤王五被公安机关抓获后交待出扒窃一案。对张三的扒窃一案应予行政处罚"}], "answer": "BD", "explanation": "根据《治安管理处罚法》第22条，违反治安管理行为在6个月内没有被公安机关发现的，不再处罚。A项正确：1月到8月已过6个月，不再处罚。B项错误：李四已报案，说明公安机关已经受理，不受6个月期限限制，应当处罚。C项正确：公安已经受理案件，不受期限限制，破案后应予处罚。D项错误：1月到10月已过9个月超过6个月期限，虽然主动交待但已过追诉时效，不应处罚。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1194}, {"num": 1196, "batch": "专业基础知识", "type": "multi", "stem": "因经营不善，王某负责的因私出入境中介机构破产，需要履行的后续手续包括（）", "options": [{"letter": "A", "text": "以书面形式向中介机构所在地的地、市级公安机关提出终止中介活动申请，包括处理善后事宜的措施、期限和留守人员名单"}, {"letter": "B", "text": "缴还经营许可证"}, {"letter": "C", "text": "向原登记注册的工商行政管理机关办理注销登记"}, {"letter": "D", "text": "凭委托监管的公安机关开具的证明，到开户行领取其备用金及利息"}], "answer": "ABC", "explanation": "根据因私出入境中介服务机构管理的相关规定，中介机构终止经营需要：以书面形式向地市级公安机关提出终止申请（A项）；缴还经营许可证（B项）；向工商行政管理机关办理注销登记（C项）。D项领取备用金及利息不属于终止手续的内容，且备用金的处理应按照相关规定另行办理。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1195}, {"num": 1197, "batch": "专业基础知识", "type": "multi", "stem": "英国人托尼在中国因殴打他人被县级公安机关处以拘留并处罚款和附加适用驱逐出境的治安管理处罚。下列说法正确的是（）", "options": [{"letter": "A", "text": "承办案件的公安机关可以直接决定对托尼的驱逐出境处罚"}, {"letter": "B", "text": "承办案件的公安机关应逐级上报，由公安部或者公安部授权的省级人民政府公安机关决定对托尼的驱逐出境处罚"}, {"letter": "C", "text": "只要其按照规定缴纳了罚款并执行了行政拘留，可不再适用驱逐出境"}, {"letter": "D", "text": "应在其缴纳罚款并执行完拘留处罚后再适用驱逐出境"}], "answer": "BD", "explanation": "根据《治安管理处罚法》第10条和相关规定，A项错误：承办案件的公安机关无权直接决定驱逐出境，应逐级上报。B项正确：驱逐出境应由公安部或公安部授权的省级公安机关决定。C项错误：驱逐出境是附加处罚，不因缴纳罚款和执行拘留而免除。D项正确：应当在主处罚（拘留和罚款）执行完毕后再适用驱逐出境。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1196}, {"num": 1198, "batch": "专业基础知识", "type": "multi", "stem": "有一商住合一的店房，一楼为营业门面，二楼用于住人。现公安机关对其进行检查，以下说法正确的有（）", "options": [{"letter": "A", "text": "不需要开具检查证"}, {"letter": "B", "text": "必须开具检查证"}, {"letter": "C", "text": "检查一楼依照检查场所的有关规定执行"}, {"letter": "D", "text": "检查二楼应依照检查公民住所的有关规定执行"}], "answer": "CD", "explanation": "对于商住合一的店房，应当区分营业区域和生活区域分别处理。一楼为营业门面，属于公共场所，检查一楼依照检查场所的有关规定执行（C项正确）。二楼用于住人，属于公民住所，检查二楼应依照检查公民住所的有关规定执行（D项正确），即必须开具检查证。A项和B项笼统地说需要或不需要检查证均不准确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1197}, {"num": 1199, "batch": "专业基础知识", "type": "multi", "stem": "遇有下列哪些情形，公安机关及其人民警察可以当场收缴罚款？（）", "options": [{"letter": "A", "text": "张某骑自行车在道路上逆行，被交通民警当场罚款50元，张某不服，认为自己没有违法行为"}, {"letter": "B", "text": "李某在火车卧铺车厢内殴打邻铺的赵某，被当场罚款200元，李某说自己下车后要转车，无法缴纳罚款，要求当场缴纳罚款"}, {"letter": "C", "text": "陈某A县人，系长途货运司机，在经过B县时，因闯红灯被交通民警当场罚款200元"}, {"letter": "D", "text": "王某驾驶自己的私家车违反道路通行规定，被交通民警当场罚款100元，王某对此无异议"}], "answer": "BC", "explanation": "根据《治安管理处罚法》第104条，可以当场收缴罚款的情形包括：被处罚人在当地没有固定住所，不当场收缴事后难以执行的。A项张某不服罚款，不符合当场收缴条件。B项李某在火车上被罚款，下车后无法缴纳，符合当场收缴条件。C项陈某为外地货运司机，在B县无固定住所，符合当场收缴条件。D项王某无异议且在当地有固定住所，不符合当场收缴条件。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1198}, {"num": 1200, "batch": "专业基础知识", "type": "multi", "stem": "员甲和演出公司乙签订了一份演出合同，约定甲在乙主办的一场演出中出演一个节目，由乙预先支付给甲演出劳务费5万元。后来，在合同约定支付劳务费的期限到来之前，甲因一场车祸而受伤住院。乙通过向医生询问甲的伤势得知，在演出日之前，甲的身体有康复的可能，但也不排除甲的伤情会恶化，以至于不能参加原定的演出。下列说法正确的是（）", "options": [{"letter": "A", "text": "乙可暂不支付合同中所约定的5万元劳务费"}, {"letter": "B", "text": "乙可行使不安抗辩权"}, {"letter": "C", "text": "若甲在合理期限内身体康复，乙应按合同支付5万元劳务费"}, {"letter": "D", "text": "若甲在合理期限内伤情恶化不能参加原定的演出，乙可解除演出合同"}], "answer": "ABCD", "explanation": "根据《民法典》关于不安抗辩权的规定（原《合同法》第68条），应当先履行债务的当事人有确切证据证明对方丧失或可能丧失履行能力的，可以中止履行。A项正确：乙有合理理由担心甲无法履约，可暂不支付劳务费。B项正确：乙行使的是不安抗辩权。C项正确：若甲康复能履行合同，乙应当按约支付。D项正确：若甲伤情恶化不能参加演出，合同目的无法实现，乙可解除合同。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1199}, {"num": 1201, "batch": "专业基础知识", "type": "multi", "stem": "袁某受人指使，以每人1500美元好处费的条件引带中国公民林某（女，12岁）、李某（女，15岁）持伪造的玻利维亚护照准备从首都机场出境前往法国。在通过边防检查站时，三人以母女相称，企图蒙混过关，但被检查人员发现并阻留审查。以下说法正确的是（）", "options": [{"letter": "A", "text": "袁某涉嫌运送他人偷越国（边）境"}, {"letter": "B", "text": "袁某涉嫌组织他人偷越国（边）境"}, {"letter": "C", "text": "林某、李某二人不构成犯罪"}, {"letter": "D", "text": "对李某可予以治安管理处罚"}], "answer": "ACD", "explanation": "袁某受人指使引带他人偷越国境，属于运送行为，构成运送他人偷越国（边）境罪（刑法第321条），而非组织者，故A正确、B错误。林某12岁、李某15岁，均未达偷越国（边）境罪的刑事责任年龄（16周岁），不构成犯罪，C正确。李某虽不构成犯罪，但其违法行为可依据治安管理处罚法予以处罚，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1200}, {"num": 1202, "batch": "专业基础知识", "type": "multi", "stem": "在（），被处罚人向指定银行缴纳罚款确有困难，经被处罚人提出，公安机关及其办案人民警察可以当场收缴罚款，法律另有规定的，从其规定。", "options": [{"letter": "A", "text": "边远"}, {"letter": "B", "text": "水上"}, {"letter": "C", "text": "交通不便地区"}, {"letter": "D", "text": "旅客列车上"}], "answer": "ABCD", "explanation": "根据《治安管理处罚法》第104条规定，在边远、水上、交通不便地区、旅客列车上、民航飞机上，被处罚人向指定银行缴纳罚款确有困难的，经被处罚人提出，公安机关及其办案人民警察可以当场收缴罚款。四个选项均符合法律规定。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1201}, {"num": 1203, "batch": "专业基础知识", "type": "multi", "stem": "在故意伤害案件中，犯罪嫌疑人钱某委托律师甲为其辩护人，被害人沈某委托律师乙为其诉讼代理人。下列说法中正确的是（）", "options": [{"letter": "A", "text": "律师甲在犯罪嫌疑人钱某被侦查机关第一次讯问或采取强制措施之日起，有权接受委托担任其辩护人"}, {"letter": "B", "text": "律师乙在犯罪嫌疑人钱某被侦查机关第一次讯问或采取强制措施之日起,有权接受沈某的委托担任其诉讼代理人"}, {"letter": "C", "text": "律师乙在侦查阶段有权要求查阅案卷"}, {"letter": "D", "text": "律师甲在侦查阶段有权同在押的犯罪嫌疑人钱某会见和通信"}], "answer": "AD", "explanation": "根据《刑事诉讼法》第34条，犯罪嫌疑人自被侦查机关第一次讯问或者采取强制措施之日起，有权委托辩护人，A正确。诉讼代理人的委托时间不同于辩护人，被害人委托诉讼代理人的时间规定有特别要求，B错误。侦查阶段诉讼代理人无权查阅案卷，C错误。辩护律师在侦查阶段有权同在押的犯罪嫌疑人会见和通信，D正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1202}, {"num": 1204, "batch": "专业基础知识", "type": "multi", "stem": "在审核有同案犯的盗窃违法案件中，下列情况必须核实的是（）", "options": [{"letter": "A", "text": "证明违法嫌疑人身份的户籍信息"}, {"letter": "B", "text": "违法嫌疑人有共同的故意"}, {"letter": "C", "text": "案件的共同违法行为人是否都实施了盗窃行为"}, {"letter": "D", "text": "案件发生的时间"}], "answer": "ABCD", "explanation": "审核有同案犯的盗窃案件时，需要全面核实：违法嫌疑人身份信息（A）、共同故意（B）、各共同违法行为人是否都实施了盗窃行为（C）、案件发生的时间（D）等基本事实，以确保案件事实清楚、证据确实充分。以上四项均为必须核实的内容。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1203}, {"num": 1205, "batch": "专业基础知识", "type": "multi", "stem": "在下列情形中，可以对涉及的物品予以扣押的是（）", "options": [{"letter": "A", "text": "网球拍：甲与乙为同事，一日甲在乙家中吃饭，双方发生争执，甲拿起乙挂在墙上的网球拍将乙打伤"}, {"letter": "B", "text": "麻将牌：甲、乙、丙、丁四人在甲家中赌博，后甲的侄女来串门，对甲说自己的父母也喜欢打麻将，甲便说：“我们玩完后你就把这副麻将带走吧，算是我送给你父母的。”后甲的侄女将麻将带走"}, {"letter": "C", "text": "手机：甲欲嫖宿乙，乙看到甲的手机挺漂亮，就跟甲说不要甲的钱了，把手机送给她就行，甲觉得自己的手机便宜，就答应了，在发生性关系时，被巡逻警察抓获"}, {"letter": "D", "text": "旧刻录机：甲经常下载一些淫秽影片，用自己的刻录机制成VCD后送给自己的朋友，为了购买一新刻录机，甲在旧货市场上将该旧刻录机卖掉，后被乙买走"}], "answer": "BC", "explanation": "A项网球拍属于乙合法所有，不能因甲的违法行为而扣押他人合法财产。B项麻将牌属于赌具，依据《治安管理处罚法》第11条应当收缴，可以扣押。C项手机在嫖娼案件中实质上作为嫖资使用，属于违法相关财物，可以扣押。D项旧刻录机已被合法卖出，乙善意取得所有权，不再属于可扣押范围。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1204}, {"num": 1206, "batch": "专业基础知识", "type": "multi", "stem": "在一起聚众斗殴致人死亡案件中，有甲、乙、丙、丁4名犯罪嫌疑人，他们对于犯罪事实都供认不讳，都是主犯，但对于年龄都提出了异议，按照户籍证明四人都年满18周岁。下列说法正确的是（）", "options": [{"letter": "A", "text": "甲的父母提出甲作案时为17周岁，提出的出生证明文件也被查证属实，且有邻居等证言证实，可以认定甲作案时未满18周岁"}, {"letter": "B", "text": "乙的父母提出乙作案时为17周岁，没有出生证明文件提供，但有人口普查登记、邻居等证言证实乙为17周岁，可以认定乙作案时未满18周岁"}, {"letter": "C", "text": "丙的父母提出丙作案时为17周岁，提供了学籍卡、防疫证明等书证证明丙为17周岁，且有邻居等证言印证，可以认定丙作案时未满18周岁"}, {"letter": "D", "text": "丁的父母提出丁作案时为17周岁，但经查，没有相关书证印证，只有邻居、接生婆等证言证明丁作案时为17周岁，骨龄鉴定为作案时未满18周岁，因骨龄鉴定仅作为参考，可以根据户籍证明认定丁作案时为18周岁"}], "answer": "ABC", "explanation": "根据最高法《关于审理未成年人刑事案件具体应用法律若干问题的解释》，认定年龄应以户籍证明为准，但户籍证明与出生证明等书证矛盾的，以书证为准。A项有出生证明佐证，可以认定未满18周岁。B项虽无出生证明，但有普查登记等书证印证，可以认定。C项有学籍卡、防疫证明等书证印证，可以认定。D项仅有证言和骨龄鉴定，骨龄鉴定仅作参考，无书证印证，仍以户籍证明为准认定18周岁。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1205}, {"num": 1207, "batch": "专业基础知识", "type": "multi", "stem": "在一起殴打他人的案件中，甲因殴打乙而被行政拘留。若乙对行政拘留不满而提起行政诉讼，下列说法正确的是（）", "options": [{"letter": "A", "text": "若乙无诉讼行为能力，应由法定代理人代为诉讼"}, {"letter": "B", "text": "乙可以委托其朋友李某作为诉讼代理人代为诉讼"}, {"letter": "C", "text": "乙所在的社区可以推荐公民作为诉讼代理人代为诉讼"}, {"letter": "D", "text": "若乙无诉讼行为能力，乙的法定代理人又互相推诿代理责任，人民法院待确定法定代理人后方能审理本案"}], "answer": "AC", "explanation": "根据《行政诉讼法》规定，无诉讼行为能力的公民由其法定代理人代为诉讼，A正确。可以被委托为诉讼代理人的包括律师、基层法律服务工作者、近亲属、所在社区推荐的公民等，朋友不在法定范围内，B错误。社区可以推荐公民作为诉讼代理人，C正确。法定代理人互相推诿的，由人民法院指定其中一人代为诉讼，法院无需等待确定后才审理，D错误。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1206}, {"num": 1208, "batch": "专业基础知识", "type": "multi", "stem": "在一起伤害案中，公安机关指派鉴定人王某对被害人宫某的伤情出具了一份鉴定意见。被告人徐某及其辩护人对这一鉴定意见有异议，人民法院认为鉴定人王某有必要出庭，遂通知王某出庭。下列说法错误的是（）", "options": [{"letter": "A", "text": "鉴定人王某拒绝出庭作证，不会影响鉴定意见的证据效力"}, {"letter": "B", "text": "鉴定人王某应当出庭作证"}, {"letter": "C", "text": "王某系受公安机关指派出具鉴定意见，人民法院无权通知王某出庭"}, {"letter": "D", "text": "是否出庭作证由鉴定人王某自行决定"}], "answer": "ACD", "explanation": "根据《刑事诉讼法》第192条，公诉人、当事人或辩护人对鉴定意见有异议，法院认为有必要的，鉴定人应当出庭作证。鉴定人拒不出庭的，鉴定意见不得作为定案根据。因此，A项称不影响证据效力错误；B项正确；C项称法院无权通知鉴定人出庭错误，法院有权通知；D项称由鉴定人自行决定错误。本题选错误选项，故ACD当选。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1207}, {"num": 1209, "batch": "专业基础知识", "type": "multi", "stem": "在暂缓执行规定中，下列的叙述错误的是（）", "options": [{"letter": "A", "text": "暂缓执行的保证金不同于罚款，可以由公安机关代收"}, {"letter": "B", "text": "在行政处罚中，罚款不能暂缓缴纳"}, {"letter": "C", "text": "公安机关没收保证金的决定不是一种行政处罚，所以被处罚人不能申请行政复议或提起行政诉讼"}, {"letter": "D", "text": "被处罚人逃避行政拘留处罚执行的，公安机关没收其保证金后，可以决定让其重新交纳保证金或提交担保人，也可以恢复执行行政拘留"}], "answer": "ABCD", "explanation": "A错误，暂缓执行的保证金应由银行代收，公安机关不得代收。B错误，根据《治安管理处罚法》第107条，被处罚人确有困难的，经申请可以暂缓或分期缴纳罚款。C错误，没收保证金的决定属于具体行政行为，可以申请行政复议或提起行政诉讼。D错误，被处罚人逃避执行的，没收保证金后应恢复执行行政拘留，不能重新交纳保证金或提交担保人。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1208}, {"num": 1210, "batch": "专业基础知识", "type": "multi", "stem": "在暂缓执行行政拘留期间，被处罚人的下列哪些行为违反了《公安机关办理行政案件程序规定》中关于暂缓执行的规定？（）", "options": [{"letter": "A", "text": "被处罚人甲因生意问题，未告知所在地的公安机关，离开居住地A县到B县"}, {"letter": "B", "text": "被处罚人乙到证人赵某家中，给赵某5000元钱，让赵某改变证词"}, {"letter": "C", "text": "被处罚人丙到纪委、监察机关控告办理该案的民警张某有徇私枉法的行为"}, {"letter": "D", "text": "为了使案件在复议、诉讼中不出现问题，该公安机关通知被处罚人丁到当地的派出所继续接受询问，丁未按时到达公安机关"}], "answer": "AB", "explanation": "根据《公安机关办理行政案件程序规定》，暂缓执行期间被处罚人应遵守的规定包括：未经批准不得离开居住地所在县（A违反）、不得干扰证人作证（B违反）。C项丙向纪委控告属于合法行使举报权利，不构成违反规定。D项丁未按时到达系公安机关通知而非其主动违反暂缓执行规定，不属于违反暂缓执行规定的行为。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1209}, {"num": 1211, "batch": "专业基础知识", "type": "multi", "stem": "张某（15岁）和刘某（17岁）在共同抢夺过程中使用暴力将被害人华某打成重伤。对张某和刘某的处理，下列说法正确的是（）", "options": [{"letter": "A", "text": "对张某以故意伤害罪定罪处罚"}, {"letter": "B", "text": "对张某和刘某以抢劫罪（结果加重犯）定罪处罚"}, {"letter": "C", "text": "对刘某以抢劫罪（结果加重犯）定罪处罚"}, {"letter": "D", "text": "对张某和刘某以故意伤害罪定罪处罚"}], "answer": "AC", "explanation": "根据《刑法》第17条，已满14周岁不满16周岁的人仅对故意杀人、故意伤害致人重伤或死亡等八种严重犯罪负刑事责任。张某15岁，在抢夺过程中使用暴力致人重伤，因不满16周岁不对抢夺罪负责，但应以故意伤害罪定罪处罚，A正确。刘某17岁，抢夺后使用暴力转化为抢劫罪（刑法第269条），且致人重伤属结果加重犯，C正确。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1210}, {"num": 1212, "batch": "专业基础知识", "type": "multi", "stem": "张某，男，美国籍，于2007年6月来华就业，一直担任北京某外资企业副总经理，?4年内在中国居留累计不少于3年且纳税记录良好，身体健康，无违法犯罪记录，张某若以任职类申请中国的永久居留，需在下列（）中任职才可以。", "options": [{"letter": "A", "text": "高新技术企业"}, {"letter": "B", "text": "鼓励类外商投资企业"}, {"letter": "C", "text": "外商投资先进技术企业"}, {"letter": "D", "text": "外商投资产品出口企业"}], "answer": "ABCD", "explanation": "根据《外国人在中国永久居留审批管理办法》，以任职类申请永久居留的外国人，需在高新技术企业、鼓励类外商投资企业、外商投资先进技术企业或外商投资产品出口企业中任职。四个选项均符合规定。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1211}, {"num": 1213, "batch": "专业基础知识", "type": "multi", "stem": "张某出国定居后将原有上海市居民户口注销。后回国暂住北京期间，他想参加旅行团出国旅游，但护照有效期不足3个月，他应该提交（）申请换发护照。", "options": [{"letter": "A", "text": "定居国外的证明及复印件"}, {"letter": "B", "text": "原普通护照及复印件"}, {"letter": "C", "text": "在京暂住地公安机关出具的暂住证明及复印件"}, {"letter": "D", "text": "上海原户籍地出具的户籍证明"}], "answer": "ABC", "explanation": "根据《护照法》及有关规定，已注销户口的定居国外的中国公民回国后申请换发护照，需提交定居国外的证明及复印件（A）、原普通护照及复印件（B）、在京暂住地公安机关出具的暂住证明及复印件（C）。由于户籍已注销，无需上海原户籍地出具的户籍证明。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1212}, {"num": 1214, "batch": "专业基础知识", "type": "multi", "stem": "张某从甲地购得面值1万元的假币，然后携带假币乘坐火车到乙地。张某在车上与几个朋友赌博时被乘警发现，乘警按规定对张某处以罚款，张某欺骗乘警，以假币交纳罚款，被乘警发现。张某的行为构成（）", "options": [{"letter": "A", "text": "持有、使用假币罪"}, {"letter": "B", "text": "诈骗罪"}, {"letter": "C", "text": "赌博罪"}, {"letter": "D", "text": "购买、运输假币罪"}], "answer": "AD", "explanation": "张某购买假币并携带乘坐火车到异地，构成购买、运输假币罪（刑法第171条），D正确。张某以假币交纳罚款，属于使用假币的行为。根据相关司法解释，购买假币后又使用的，以购买假币罪和使用假币罪并罚，故同时构成持有、使用假币罪（刑法第172条），A正确。赌博行为尚不构成赌博罪，不构成诈骗罪。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1213}, {"num": 1215, "batch": "专业基础知识", "type": "multi", "stem": "张某经营某煤矿，为了降低采矿成本，提高开采量，便动员当地矿工和村民将子女带到矿井上班，并许诺给他们的子女以高工资。矿工和村民纷纷将他们的子女带到矿井上班，从事井下采矿作业，其中有十余人为10～16周岁的未成年人。后因张某所承诺的高工资未兑现，十余名童工表示不想再干，要求离开矿井。张某不同意，并在矿井周围布上电铁丝网，雇用数十名守卫，禁止所有的矿工包括这十余名童工离开矿井，强制他们为其采矿，其中一名年约12岁的童工因体质瘦弱而累死在井下。张某的行为构成（）", "options": [{"letter": "A", "text": "强迫劳动罪"}, {"letter": "B", "text": "雇用童工从事危重劳动罪"}, {"letter": "C", "text": "重大责任事故罪"}, {"letter": "D", "text": "非法拘禁罪"}], "answer": "AB", "explanation": "张某雇用10余名10至16周岁未成年人从事井下采矿，构成雇用童工从事危重劳动罪（刑法第244条之一），B正确。张某在矿井周围布设电网、雇守卫禁止人员离开，以限制人身自由的方法强迫劳动，构成强迫劳动罪（刑法第244条），A正确。非法拘禁行为被强迫劳动罪吸收，不另定罪。童工累死属于强迫劳动的加重结果，不构成重大责任事故罪。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1214}, {"num": 1216, "batch": "专业基础知识", "type": "multi", "stem": "张某居住在A县，因涉嫌受贿罪被检察机关决定取保候审。在取保候审期间，张某应当遵守的规定有（）", "options": [{"letter": "A", "text": "未经A县公安机关批准不得离开A县"}, {"letter": "B", "text": "未经A县检察机关批准不得离开住处"}, {"letter": "C", "text": "在传讯的时候及时到案"}, {"letter": "D", "text": "未经A县公安机关批准不得会见他人"}], "answer": "AC", "explanation": "根据《刑事诉讼法》第71条，被取保候审人应遵守：未经执行机关（公安机关）批准不得离开所居住的市、县（A正确）；传讯时及时到案（C正确）。不得离开住处是监视居住的规定，B错误。未经批准不得会见他人也是监视居住的要求，D错误。取保候审由公安机关执行。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1215}, {"num": 1217, "batch": "专业基础知识", "type": "multi", "stem": "张某扰乱公共秩序，被民警李某当场查获，并依据《治安管理处罚法》对张某当场作出行政处罚决定。李某应当（）", "options": [{"letter": "A", "text": "向当事人出示执法身份证件"}, {"letter": "B", "text": "当场制作行政处罚决定书"}, {"letter": "C", "text": "将行政处罚决定书当场交付当事人"}, {"letter": "D", "text": "无法当场交付的，予以说明，不再交付"}], "answer": "ABC", "explanation": "根据《治安管理处罚法》第101条规定，当场作出行政处罚决定的，人民警察应当向当事人出示工作证件（A），当场填写处罚决定书（B），并当场交付当事人（C）。不存在无法当场交付就不交付的情形，D错误。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1216}, {"num": 1218, "batch": "专业基础知识", "type": "multi", "stem": "张某申请在北京设立因私出入境中介机构，需递交的材料包括（）", "options": [{"letter": "A", "text": "5名主要工作人员的简历、身份证明及相关的专业资格证明"}, {"letter": "B", "text": "具有法定资格的验资机构出具的验资证明"}, {"letter": "C", "text": "与外国出入境服务机构直接签署的有效的合作意向书或者协议（中、外文本），以及经我国驻外使、领馆认证的外国签约方的合法资格证明"}, {"letter": "D", "text": "住所和经营场所使用证明"}], "answer": "ABCD", "explanation": "根据因私出入境中介活动管理相关规定，申请设立因私出入境中介机构需提交：主要工作人员的简历、身份证明及专业资格证明（A）；验资证明（B）；与外国出入境服务机构的合作协议及认证文件（C）；住所和经营场所使用证明（D）。四项均为必需材料。", "tags": "广东辅警笔试 多选题 专业基础知识", "_idx": 1217}, {"num": 1219, "batch": "专业基础知识", "type": "bool", "stem": "（根据新治安法修订）招摇撞骗属于侵犯财产权利行为。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据新修订的《治安管理处罚法》，招摇撞骗是指冒充国家机关工作人员或其他虚假身份进行欺骗的行为，其侵犯的客体主要是国家机关的威信及其正常活动，属于妨害社会管理秩序的行为，而非侵犯财产权利行为。因此该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1218}, {"num": 1220, "batch": "专业基础知识", "type": "bool", "stem": "证人、鉴定人、翻译人员属于听证参加人的范围。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《公安机关办理行政案件程序规定》，听证参加人包括当事人及其代理人、案件的办案人民警察、证人、鉴定人、翻译人员等。因此，证人、鉴定人、翻译人员属于听证参加人的范围，该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1219}, {"num": 1221, "batch": "专业基础知识", "type": "bool", "stem": "对县级以上的各级人民代表大会代表予以行政拘留的，作出处罚决定前应当经该级人民代表大会主席团或者人民代表大会常务委员会许可。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《治安管理处罚法》及《全国人民代表大会和地方各级人民代表大会代表法》的规定，对县级以上各级人民代表大会代表予以行政拘留的，作出处罚决定前应当经该级人民代表大会主席团或者人民代表大会常务委员会许可。该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1220}, {"num": 1222, "batch": "专业基础知识", "type": "bool", "stem": "办理刑事案件中取得的证据，不得作为行政处罚或者其他行政处理的根据。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《公安机关办理行政案件程序规定》，在办理刑事案件中取得的证据，可以作为行政处罚或者其他行政处理的根据。刑事案件与行政案件之间证据可以转化使用，并非不得作为行政处罚的根据。因此该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1221}, {"num": 1223, "batch": "专业基础知识", "type": "bool", "stem": "对于因民间纠纷引起的殴打他人、故意伤害、侮辱、诽谤、诬告陷害、故意损毁财物、干扰他人正常生活、侵犯隐私等情节较轻的治安案件，公安机关应当调解处理。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《治安管理处罚法》第9条，对于因民间纠纷引起的殴打他人等情节较轻的治安案件，公安机关可以调解处理，而非应当调解处理。'可以'表示有裁量权，'应当'表示必须调解，两者含义不同。此外，调解还需双方当事人同意。因此该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1222}, {"num": 1224, "batch": "专业基础知识", "type": "bool", "stem": "根据《公安机关办理行政案件程序规定》的规定，对适合调解处理的案件，公安机关应当先予调解。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《公安机关办理行政案件程序规定》，对适合调解处理的案件，公安机关可以调解处理，而非应当先予调解。调解的前提是双方当事人自愿同意，公安机关不能强制先行调解。因此该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1223}, {"num": 1225, "batch": "专业基础知识", "type": "bool", "stem": "对雇凶伤害他人的案件，不适用调解处理。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《公安机关办理行政案件程序规定》，雇凶伤害他人的案件不适用调解处理。此外，寻衅滋事、结伙斗殴等案件也不适用调解。该规定旨在防止以调解代替处罚、放纵严重违法行为。因此该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1224}, {"num": 1226, "batch": "专业基础知识", "type": "bool", "stem": "确有违法行为，但有依法不予行政处罚情形的，作出不予行政处罚决定；有违法所得和非法财物的，应当予以退还。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《治安管理处罚法》及相关规定，确有违法行为但有依法不予行政处罚情形的，作出不予行政处罚决定。对于违法所得和非法财物，应当依法予以收缴或追缴，而非退还。退还仅适用于被侵害人的合法财物。因此该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1225}, {"num": 1227, "batch": "专业基础知识", "type": "bool", "stem": "对因邻里纠纷引起的治安案件进行调解时，应当邀请当事人居住地的居（村）民委员会的人员或者双方当事人熟悉的人员参加帮助调解。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《公安机关办理行政案件程序规定》，对因邻里纠纷引起的治安案件进行调解时，可以邀请当事人居住地的居（村）民委员会的人员或者双方当事人熟悉的人员参加帮助调解。法律规定的是'可以'而非'应当'，题目表述过于绝对。因此该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1226}, {"num": 1228, "batch": "专业基础知识", "type": "bool", "stem": "违法行为涉嫌构成犯罪的，转为刑事案件办理或者移送有权处理的主管机关、部门办理，公安机关应当撤销行政案件。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《公安机关办理行政案件程序规定》，违法行为涉嫌构成犯罪的，转为刑事案件办理或者移送有权处理的主管机关、部门办理，无需撤销行政案件。行政案件转为刑事案件办理后，原行政案件的相关材料可以作为刑事案件的证据使用。因此该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1227}, {"num": 1229, "batch": "专业基础知识", "type": "bool", "stem": "对调解未达成协议或者达成协议后不履行的，公安机关应当对违反治安管理行为人依法予以处罚；对违法行为造成的损害赔偿纠纷，应当告知当事人向人民法院提起民事诉讼。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《治安管理处罚法》第9条规定，对于调解未达成协议或者达成协议后不履行的，公安机关应当对违反治安管理行为人依法予以处罚；对违法行为造成的损害赔偿纠纷，公安机关不再处理，应当告知当事人向人民法院提起民事诉讼。该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1228}, {"num": 1230, "batch": "专业基础知识", "type": "bool", "stem": "公安机关在作出行政处罚决定时，对涉案财物应当先行作出处理。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《公安机关办理行政案件程序规定》，公安机关在作出行政处罚决定时，应当同时对涉案财物作出处理决定，而非先行处理。涉案财物的处理与行政处罚决定应一并作出。因此该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1229}, {"num": 1231, "batch": "专业基础知识", "type": "bool", "stem": "公安机关在办理行政案件中查获的直接用于实施违法行为的工具应当依法予以收缴。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《治安管理处罚法》第11条和《公安机关办理行政案件程序规定》，直接用于实施违法行为的工具，如果属于本人所有的，应当予以收缴。但如果有证据表明属于他人合法所有的，不应收缴。题目表述过于绝对，缺少'属于本人所有'的前提条件。因此该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1230}, {"num": 1232, "batch": "专业基础知识", "type": "bool", "stem": "直接用于实施违法行为的工具，除非有证据表明属于他人合法所有，可以直接认定为违法行为人本人所有。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《公安机关办理行政案件程序规定》，直接用于实施违法行为的工具，除非有证据表明属于他人合法所有，可以直接认定为违法行为人本人所有，依法予以收缴。该规定简化了执法中的认定程序。因此该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1231}, {"num": 1233, "batch": "专业基础知识", "type": "bool", "stem": "公安机关在办理行政案件中查获的毒品、淫秽物品等违禁品应当予以收缴或者没收。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《治安管理处罚法》第11条和《公安机关办理行政案件程序规定》，公安机关在办理行政案件中查获的毒品、淫秽物品等违禁品应当予以收缴。'收缴'与'没收'是不同的法律概念，在行政案件中适用'收缴'，不能表述为'收缴或者没收'。因此该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1232}, {"num": 1234, "batch": "专业基础知识", "type": "bool", "stem": "鉴定程序违法，公安机关应当进行重新鉴定。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《公安机关办理行政案件程序规定》，鉴定程序违法或鉴定意见有误的，可以进行补充鉴定或重新鉴定，并非一律应当重新鉴定。具体处理方式视情况而定，程序违法不一定都需要重新鉴定，也可能通过补充鉴定等方式纠正。因此该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1233}, {"num": 1235, "batch": "专业基础知识", "type": "bool", "stem": "对结伙斗殴或者其他寻衅滋事的案件，如被侵害人愿意调解处理的，可以适用调解处理。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《公安机关办理行政案件程序规定》，对结伙斗殴或者其他寻衅滋事的案件，不适用调解处理。这类案件侵犯的是社会公共秩序，不同于民间纠纷引起的治安案件，即使被侵害人愿意调解，也不能适用调解处理。因此该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1234}, {"num": 1236, "batch": "专业基础知识", "type": "bool", "stem": "两个以上违法嫌疑人分别对同一行政案件提出听证要求的，可以合并举行。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《公安机关办理行政案件程序规定》，两个以上违法嫌疑人分别对同一行政案件提出听证要求的，可以合并举行。这样可以提高行政效率，避免对同一案件重复举行听证。因此该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1235}, {"num": 1237, "batch": "专业基础知识", "type": "bool", "stem": "多名违法行为人共同实施违法行为，违法所得或者非法财物无法分清所有人的，作为共同违法所得或者非法财物予以处理。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《公安机关办理行政案件程序规定》，多名违法行为人共同实施违法行为，违法所得或者非法财物无法分清所有人的，作为共同违法所得或者非法财物予以处理。这有利于解决共同违法中财物归属不明的处理问题。因此该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1236}, {"num": 1238, "batch": "专业基础知识", "type": "bool", "stem": "听证是否公开举行及听证的延期、中止或者终止由听证主持人确定。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《公安机关办理行政案件程序规定》，听证是否公开举行由公安机关负责人决定，而非听证主持人确定。但听证的延期、中止或者终止由听证主持人确定。题目将听证是否公开举行的决定权也归于听证主持人，表述不准确。但根据规定，听证公开举行及延期、中止、终止确实由听证主持人确定，该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1237}, {"num": 1239, "batch": "专业基础知识", "type": "bool", "stem": "与听证案件处理结果有直接利害关系的其他公民、法人或者其他组织，作为第三人申请参加听证的，可以允许，也可以不允许。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《公安机关办理行政案件程序规定》，与听证案件处理结果有直接利害关系的其他公民、法人或者其他组织，作为第三人申请参加听证的，应当允许。法律规定的是'应当允许'而非'可以允许也可以不允许'，第三人参加听证是其法定权利。因此该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1238}, {"num": 1240, "batch": "专业基础知识", "type": "bool", "stem": "违法嫌疑人要求听证的，应当在公安机关告知后3日内提出申请。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《公安机关办理行政案件程序规定》和《治安管理处罚法》相关规定，违法嫌疑人要求听证的，应当在公安机关告知后3日内提出申请。超过3日未提出的，视为放弃听证权利。因此该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1239}, {"num": 1241, "batch": "专业基础知识", "type": "bool", "stem": "违法嫌疑人放弃听证或者撤回听证要求后，处罚决定作出前，又提出听证要求的，应当允许。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《公安机关办理行政案件程序规定》，违法嫌疑人放弃听证或者撤回听证要求后，处罚决定作出前，又提出听证要求的，如果在听证申请期限内（告知后3日内），不应一律允许。只有在法定申请期限内的，才应当允许。题目表述过于绝对。因此该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1240}, {"num": 1242, "batch": "专业基础知识", "type": "bool", "stem": "公安机关收到听证申请后，应当在2日内决定是否受理。逾期不通知听证申请人的，视为受理。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《公安机关办理行政案件程序规定》，公安机关收到听证申请后，应当在2日内决定是否受理。逾期不通知听证申请人的，视为受理。该规定保障了违法嫌疑人的听证权利，防止公安机关消极对待听证申请。因此该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1241}, {"num": 1243, "batch": "专业基础知识", "type": "bool", "stem": "治安案件有被侵害人的，公安机关应当将决定书原件送达被侵害人。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《公安机关办理行政案件程序规定》，治安案件有被侵害人的，公安机关应当将决定书副本送达被侵害人，而非原件。原件应由被处罚人持有或存档。因此该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1242}, {"num": 1244, "batch": "专业基础知识", "type": "bool", "stem": "行政案件的听证一律公开举行。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《公安机关办理行政案件程序规定》，行政案件的听证原则上公开举行，但涉及国家秘密、商业秘密、个人隐私的，不公开举行。因此'一律公开举行'的表述过于绝对。该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1243}, {"num": 1245, "batch": "专业基础知识", "type": "bool", "stem": "举行听证的时间、地点由听证主持人确定。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《公安机关办理行政案件程序规定》，举行听证的时间、地点由听证主持人确定。听证主持人负责组织和主持听证活动，有权确定具体的时间和地点安排。因此该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1244}, {"num": 1246, "batch": "专业基础知识", "type": "bool", "stem": "公安机关办理治安案件的期限，自受理之日起不得超过30日；案情重大、复杂的，经本级公安机关负责人批准，可以延长30日。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《治安管理处罚法》第99条，公安机关办理治安案件的期限，自受理之日起不得超过30日；案情重大、复杂的，经上一级公安机关批准，可以延长30日。题目中称'经本级公安机关负责人批准'，应为'上一级公安机关'，审批权限表述错误。因此该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1245}, {"num": 1247, "batch": "专业基础知识", "type": "bool", "stem": "为了查明案情进行鉴定、检测的期间，不计入办案期限。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《公安机关办理行政案件程序规定》，为了查明案情进行鉴定、检测的期间，不计入办案期限。这是因为鉴定、检测所需时间不属于公安机关办案本身的时间，扣除后有利于保障办案质量。因此该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1246}, {"num": 1248, "batch": "专业基础知识", "type": "bool", "stem": "违法嫌疑人不讲真实姓名、住址，身份不明，但只要违法事实清楚，证据确实充分的，可以按其自报的姓名、贴附照片作出处罚决定，并在相关法律文书中注明。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《公安机关办理行政案件程序规定》，违法嫌疑人不讲真实姓名、住址，身份不明，但只要违法事实清楚，证据确实充分的，可以按其自报的姓名、贴附照片作出处罚决定，并在相关法律文书中注明。这确保了违法行为不因身份不明而逃避处罚。因此该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1247}, {"num": 1249, "batch": "专业基础知识", "type": "bool", "stem": "公安机关适用一般程序作出行政处罚决定的，应当采用口头或者书面形式告知违法嫌疑人拟作出行政处罚决定的事实、理由、依据及违法嫌疑人依法享有陈述权和申辩权。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《治安管理处罚法》和《公安机关办理行政案件程序规定》，公安机关适用一般程序作出行政处罚决定的，应当采用书面形式告知违法嫌疑人拟作出行政处罚决定的事实、理由、依据及依法享有的陈述权和申辩权。法律规定必须书面告知，不允许口头告知。因此该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1248}, {"num": 1250, "batch": "专业基础知识", "type": "bool", "stem": "对违法行为事实清楚，证据确实充分，依法应当予以行政处罚，因违法行为人逃跑等原因无法履行告知义务的，公安机关可以采取公告方式予以告知。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《公安机关办理行政案件程序规定》，对违法行为事实清楚，证据确实充分，依法应当予以行政处罚，因违法行为人逃跑等原因无法履行告知义务的，公安机关可以采取公告方式予以告知。公告告知是保障程序正义的补充方式。因此该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1249}, {"num": 1251, "batch": "专业基础知识", "type": "bool", "stem": "公安机关采取公告方式履行告知义务的，公告期为10日。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《公安机关办理行政案件程序规定》，公安机关采取公告方式履行告知义务的，公告期为7日，而非10日。题目中公告期限表述错误。因此该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1250}, {"num": 1252, "batch": "专业基础知识", "type": "bool", "stem": "听证应当在公安机关收到听证申请之日起10日内举行。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《公安机关办理行政案件程序规定》，听证应当在公安机关收到听证申请之日起10日内举行。该期限规定旨在保障听证及时举行，维护当事人合法权益。因此该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1251}, {"num": 1253, "batch": "专业基础知识", "type": "bool", "stem": "甲公司向乙公司发出欲出售一批钢材的要约，要求乙公司月底前承诺。甲公司的该要约可以在乙公司承诺之前撤销。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《民法典》第476条规定，要约人确定了承诺期限的，要约不得撤销。题目中甲公司要求乙公司月底前承诺，即确定了承诺期限，因此该要约不可撤销。题目称可以撤销，违反了要约不可撤销的法律规定。因此该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1252}, {"num": 1254, "batch": "专业基础知识", "type": "bool", "stem": "《集会游行示威法》所称示威，是指在公共道路、露天公共场所列队行进、表达共同意愿的活动。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《集会游行示威法》第2条规定，游行是指在公共道路、露天公共场所列队行进、表达共同意愿的活动；示威是指在露天公共场所或公共道路上以集会、游行、静坐等方式表达共同意愿的活动。题目将'游行'的定义错误地用于'示威'，混淆了两个概念。因此该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1253}, {"num": 1255, "batch": "专业基础知识", "type": "bool", "stem": "为了保障依法举行的游行的行进，负责维持交通秩序的人民警察在征得游行负责人同意后，可以临时变通执行交通规则的有关规定。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《集会游行示威法》第23条规定，为了保障依法举行的游行的行进，负责维持交通秩序的人民警察可以临时变通执行交通规则的有关规定，无需征得游行负责人同意。题目增加了'征得游行负责人同意'这一条件，不符合法律规定。因此该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1254}, {"num": 1256, "batch": "专业基础知识", "type": "bool", "stem": "李某是A市B区的居民，其被推举为游行负责人，计划组织队伍从B区游行至A市C区，其应当向B区和C区公安机关提交游行申请。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《集会游行示威法》第6条规定，游行路线跨越两个以上区、县的，由共同的上級公安机关主管，即向上一级公安机关（A市公安局）提出申请，而非分别向B区和C区公安机关提交申请。因此该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1255}, {"num": 1257, "batch": "专业基础知识", "type": "bool", "stem": "依照《集会游行示威法》的规定，需要申请的集会、游行、示威，其负责人必须在举行日期的3日前向公安机关递交书面申请。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《集会游行示威法》第8条规定，需要申请的集会、游行、示威，其负责人必须在举行日期的5日前向公安机关递交书面申请，而非3日前。题目中的申请期限表述错误。因此该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1256}, {"num": 1258, "batch": "专业基础知识", "type": "bool", "stem": "(17年新增试题)公安机关抓获涉嫌准备实施恐怖活动犯罪的犯罪嫌疑人屈某，经侦查发现某境外非政府组织曾资助并帮助屈某实施该活动。立案后，经县级以上公安机关负责人批准，可以冻结该境外非政府组织的银行账户资金。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《反恐怖主义法》相关规定，公安机关抓获涉嫌准备实施恐怖活动犯罪的犯罪嫌疑人，经侦查发现境外非政府组织曾资助并帮助其实施该活动的，立案后经县级以上公安机关负责人批准，可以冻结该境外非政府组织的银行账户资金。因此该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1257}, {"num": 1259, "batch": "专业基础知识", "type": "bool", "stem": "(17年新增试题)某境外非政府组织涉嫌在中国境内资助某营利性活动。经设区的市级以上公安机关负责人批准，可以提请人民法院冻结其银行账户资金。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《境外非政府组织境内活动管理法》第47条规定，境外非政府组织涉嫌在中国境内资助营利性活动等违法行为的，经设区的市级以上公安机关负责人批准，可以提请人民法院冻结其银行账户资金。因此该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1258}, {"num": 1260, "batch": "专业基础知识", "type": "bool", "stem": "(17年新增试题)境外非政府组织在中国境内开展临时活动，应当通过中方合作单位的银行账户管理用于中国境内的资金，实行单独记账，专款专用。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《境外非政府组织境内活动管理法》第22条规定，境外非政府组织在中国境内开展临时活动，应当通过中方合作单位的银行账户管理用于中国境内的资金，实行单独记账，专款专用。该规定旨在加强资金监管，确保资金合法使用。因此该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1259}, {"num": 1261, "batch": "专业基础知识", "type": "bool", "stem": "某派出所民警在辖区巡逻时发现路人李某随身携带一把刀具，经测量该刀具长170厘米，刀尖角度70度，当地县级公安机关认定该刀具属于管制刀具，该县公安局据此对李某作出治安处罚。该县公安机关的做法正确。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《管制刀具认定标准》，管制刀具的认定需综合考虑刀具类型、刀身长度、刀尖角度、是否具有自锁装置等多个因素。仅凭刀身长度和刀尖角度不能直接认定为管制刀具，还需由县级以上公安机关依据标准综合判定。题目中刀具参数需进一步比对标准，不能简单认定。因此该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1260}, {"num": 1262, "batch": "专业基础知识", "type": "bool", "stem": "国家对烟花爆竹的生产、经营、运输和举办焰火晚会以及其他大型焰火燃放活动，实行许可证制度。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《烟花爆竹安全管理条例》第3条规定，国家对烟花爆竹的生产、经营、运输和举办焰火晚会以及其他大型焰火燃放活动，实行许可证制度。未经许可，任何单位或者个人不得从事上述活动。因此该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1261}, {"num": 1263, "batch": "专业基础知识", "type": "bool", "stem": "外形、颜色与制式枪支相同或者近似，并且外形长度尺寸介于相应制式枪支全枪长度尺寸的1/2与1倍之间，不能发射任何物质，或者所发射物质的枪口比动能小于1.8焦耳/平方厘米的，可以认定为仿真枪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据公安部《枪支致伤力的法庭科学鉴定判据》及相关规定，仿真枪的认定标准为：外形、颜色与制式枪支相同或近似，外形长度介于制式枪支全枪长度的1/2与1倍之间，不能发射任何物质或发射物质的枪口比动能小于1.8焦耳/平方厘米。题目表述符合仿真枪认定标准。因此该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1262}, {"num": 1264, "batch": "专业基础知识", "type": "bool", "stem": "D县公安局查获一批“枪支”，该“枪支”符合《枪支管理法》规定的枪支构成要件，但外形、颜色十分鲜艳和夸张，所发射物质的枪口比动能为1.2焦耳/平方厘米，应当属于玩具枪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据相关规定，符合《枪支管理法》规定的枪支构成要件的，应认定为枪支。枪口比动能1.2焦耳/平方厘米虽低于1.8焦耳/平方厘米的标准，但题目明确该物品符合枪支构成要件，且外形颜色鲜艳夸张不能作为认定为玩具枪的依据。只要符合枪支标准，即使外观夸张仍应认定为枪支。因此该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1263}, {"num": 1265, "batch": "专业基础知识", "type": "bool", "stem": "为了维护社会治安秩序的特殊需要，经省级公安机关批准，某县级公安机关决定对该县合法配备、配置的枪支采取集中保管。该省级和县级公安机关的做法正确。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《枪支管理法》第23条规定，为了维护社会治安秩序的特殊需要，经国务院公安部门批准，县级以上各级人民政府公安机关可以对合法配备、配置的枪支采取集中保管的措施。题目中称经'省级公安机关'批准，审批权限应为国务院公安部门（公安部），而非省级公安机关。因此该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1264}, {"num": 1266, "batch": "专业基础知识", "type": "bool", "stem": "甲、乙两家煤矿的领导系朋友关系，在经单位领导同意并履行手续后，两家煤矿经常相互借用、转让使用民用爆炸物品。该两煤矿的做法符合法律有关规定。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《民用爆炸物品安全管理条例》规定，民用爆炸物品严禁转让、倒卖、出借。即使经单位领导同意并履行手续，两家煤矿相互借用、转让民用爆炸物品也违反了法律禁止性规定。因此该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1265}, {"num": 1267, "batch": "专业基础知识", "type": "bool", "stem": "某雷管生产厂职工孙某，下班时私自夹带成品雷管2枚，送给朋友李某用于收藏。孙某的行为不构成违法。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《民用爆炸物品安全管理条例》规定，雷管属于民用爆炸物品，严禁个人私自携带、赠送。孙某私自夹带成品雷管送人的行为违反了民用爆炸物品管理规定，构成违法行为，应依法予以处罚。因此该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1266}, {"num": 1268, "batch": "专业基础知识", "type": "bool", "stem": "王某私自帮某企业购买了5吨非法生产的炸药，并为其保管。王某的行为构成非法买卖、储存爆炸物罪，应当依法追究刑事责任。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《刑法》第125条规定，非法制造、买卖、运输、储存枪支、弹药、爆炸物的，构成非法买卖、储存枪支、弹药、爆炸物罪。王某帮企业购买非法生产的炸药并为其保管，同时构成非法买卖和储存爆炸物罪，应依法追究刑事责任。因此该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1267}, {"num": 1269, "batch": "专业基础知识", "type": "bool", "stem": "危险化学品生产单位应当按规定如实记录其生产、储存的剧毒化学品的数量、流向，并采取必要的安全防范措施，防止剧毒化学品丢失或者被盗。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《危险化学品安全管理条例》第24条规定，危险化学品生产单位应当如实记录其生产、储存的剧毒化学品的数量、流向，并采取必要的安全防范措施，防止剧毒化学品丢失或者被盗。该规定是保障剧毒化学品安全管理的法定义务。因此该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1268}, {"num": 1270, "batch": "专业基础知识", "type": "bool", "stem": "张某为某地农民，1996年之前他合法持有猎枪两支（都依法办理《猎枪证》）。1996年贯彻《枪支管理法》之后，当地未划定猎区和牧区，张某谎称枪支被盗，将枪支一直隐匿未交。接群众举报，2013年公安机关在其家中查获这两支猎枪，但都锈蚀严重，不能击发。张某的行为涉嫌非法持有枪支。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据最高法《关于审理非法制造、买卖、运输枪支、弹药、爆炸物等刑事案件具体应用法律若干问题的解释》，非法持有枪支罪的成立要求持有的物品经鉴定属于枪支。张某的猎枪锈蚀严重不能击发，经鉴定不具有杀伤力的，不属于枪支，不构成非法持有枪支罪。因此该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1269}, {"num": 1271, "batch": "专业基础知识", "type": "bool", "stem": "东方兽药厂储存剧毒化学品的专用仓库未按照国家有关规定设置相应的技术防范设施，应由安全生产监督管理部门予以处罚。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《危险化学品安全管理条例》相关规定，储存剧毒化学品的专用仓库未按照国家有关规定设置相应的技术防范设施的，应由公安机关责令改正并处罚款，而非由安全生产监督管理部门处罚。题目中的处罚主体表述错误。因此该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1270}, {"num": 1272, "batch": "专业基础知识", "type": "bool", "stem": "甲公司生产剧毒化学品，在生产过程中未如实记录生产、储存、使用的剧毒化学品的数量、流向，应由公安机关予以查处。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《危险化学品安全管理条例》规定，生产、储存、使用剧毒化学品的单位未如实记录剧毒化学品的数量、流向的，由公安机关责令改正，可以处以罚款；情节严重的，责令停产停业整顿。因此该行为应由公安机关查处，该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1271}, {"num": 1273, "batch": "专业基础知识", "type": "bool", "stem": "销售、购买民用爆炸物品，应当通过银行账户进行交易，不得使用现金或者实物进行交易。某民用爆炸物品生产企业违反上述规定使用现金交易销售其生产的炸药，该违法行为由国防科技工业主管部门查处。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《民用爆炸物品安全管理条例》规定，销售、购买民用爆炸物品应通过银行账户进行交易，不得使用现金或实物。违反该规定的，由公安机关责令限期改正并处罚款，而非由国防科技工业主管部门查处。题目中的查处主体表述错误。因此该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1272}, {"num": 1274, "batch": "专业基础知识", "type": "bool", "stem": "甲单位是生产危险化学品的单位，由于转产，制定了处置危险化学品生产装置、储存设施以及库存的危险化学品的方案。处置方案应向当地环境保护主管部门、工业和信息化主管部门备案。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《危险化学品安全管理条例》第27条规定，处置方案应当报所在地县级人民政府安全生产监督管理部门、环境保护主管部门和工业和信息化主管部门备案。题目中遗漏了安全生产监督管理部门，备案机关不完整。因此该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1273}, {"num": 1275, "batch": "专业基础知识", "type": "bool", "stem": "某企业从本省A地级市向B地级市运送枪支，该企业应向B市级人民政府公安机关申请领取枪支运输许可证件。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《枪支管理法》第30条规定，运输枪支必须向运往地的设区的市级人民政府公安机关申请领取枪支运输许可证件。从甲地运往乙地，应向乙地（运往地）市级公安机关申请。因此该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1274}, {"num": 1276, "batch": "专业基础知识", "type": "bool", "stem": "甲县一家爆破作业单位到乙县购买民用爆炸物品时，必须持有甲县公安机关开具的购买许可证。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《民用爆炸物品安全管理条例》第21条规定，购买民用爆炸物品的单位，应当向所在地县级人民政府公安机关申请取得购买许可证。甲县的爆破作业单位应持有甲县公安机关开具的购买许可证。因此该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1275}, {"num": 1277, "batch": "专业基础知识", "type": "bool", "stem": "某爆破公司欲将用于采矿的炸药由A县运往B县，其应到B县公安机关申请办理《民用爆炸物品运输许可证》。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《民用爆炸物品安全管理条例》第26条规定，运输民用爆炸物品的单位，应当向运达地县级人民政府公安机关申请领取运输许可证。从A县运往B县，应向B县（运达地）公安机关申请。因此该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1276}, {"num": 1278, "batch": "专业基础知识", "type": "bool", "stem": "甲企业是一家生产黑火药、烟火药、引火线的企业，其可以向任何单位销售黑火药、烟火药和引火线，但不得向个人销售。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《民用爆炸物品安全管理条例》规定，黑火药、烟火药、引火线的销售对象有严格限制，只能销售给依法取得生产许可的相关企业，不能向任何单位销售。题目中称'可以向任何单位销售'违反了法律对黑火药等危险物品的严格管控规定。因此该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1277}, {"num": 1279, "batch": "专业基础知识", "type": "bool", "stem": "爆破作业单位甲不再使用民用爆炸物品时，经向公安机关备案后，可以将剩余的民用爆炸物品转卖给乙煤矿。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《民用爆炸物品安全管理条例》第43条规定，爆破作业单位不再使用民用爆炸物品时，应当将剩余的民用爆炸物品登记造册并报所在地县级公安机关组织销毁，或监督退回生产企业，不得转让、转卖给其他单位。因此该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1278}, {"num": 1280, "batch": "专业基础知识", "type": "bool", "stem": "甲省某市一爆破作业单位在乙省某地承接一爆破施工项目，该单位事先没有将爆破作业项目的有关情况向乙省某地县级人民政府公安机关报告，被公安机关查处。公安机关可以责令其停止违法行为，处以罚款。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《民用爆炸物品安全管理条例》第50条规定，爆破作业单位跨省、自治区、直辖市行政区域从事爆破作业的，应当事先向作业所在地县级人民政府公安机关报告。未报告的，由公安机关责令停止违法行为，处以罚款。因此该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1279}, {"num": 1281, "batch": "专业基础知识", "type": "bool", "stem": "某烟花爆竹经营公司通过道路将一车烟花爆竹从A地运输到B地，应当向B地县级人民政府公安部门提出申请。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《烟花爆竹安全管理条例》第23条规定，经由道路运输烟花爆竹的，应当向运达地县级人民政府公安部门提出申请。从A地运到B地，应向B地（运达地）县级公安部门申请。因此该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1280}, {"num": 1282, "batch": "专业基础知识", "type": "bool", "stem": "某县公安局在核发烟花爆竹道路运输许可证时，应当在许可证上载明托运人、承运人、许可证使用次数、起始地点、烟花爆竹的种类、规格和数量。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《烟花爆竹安全管理条例》第24条规定，道路运输许可证应载明托运人、承运人、一次性运输有效期限、起始地点、烟花爆竹的种类、规格和数量等。题目中称载明'许可证使用次数'不准确，应为'一次性运输有效期限'。因此该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1281}, {"num": 1283, "batch": "专业基础知识", "type": "bool", "stem": "某烟花爆竹经营公司在烟花爆竹运达目的地后，应当在烟花爆竹道路运输许可证上签注到达情况，并在7日内将运输许可证交回原发证的公安部门核销。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《烟花爆竹安全管理条例》第26条规定，烟花爆竹运达目的地后，收货人应当在3日内将运输许可证交回原发证的公安部门核销，而非7日内。题目中的签注和核销期限表述错误。因此该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1282}, {"num": 1284, "batch": "专业基础知识", "type": "bool", "stem": "某派出所在检查中发现一辆运输烟花爆竹的车辆除没有按照规定安装符合国家标准的易燃易爆危险物品警示标志外，其他手续齐全，可以对其给予没收烟花爆竹产品和罚款的处罚。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《烟花爆竹安全管理条例》规定，运输车辆未按照规定安装警示标志的，由公安机关责令改正，处以罚款，但不包括没收烟花爆竹产品。没收产品适用于非法运输等情形，本题中运输手续齐全，仅缺少警示标志，不应没收。因此该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1283}, {"num": 1285, "batch": "专业基础知识", "type": "bool", "stem": "某烟花爆竹生产厂在申请通过道路运输黑火药时，应当提交驾驶员、押运员从事危险货物运输的资格证明。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《烟花爆竹安全管理条例》第24条规定，经由道路运输黑火药、烟火药、引火线的，应当提交驾驶员、押运员从事危险货物运输的资格证明。这是确保运输安全的重要条件。因此该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1284}, {"num": 1286, "batch": "专业基础知识", "type": "bool", "stem": "2011年10月1日由某区政府主办的大型焰火晚会，在燃放过程中，承办单位及其作业人员未按照焰火晚会燃放安全规程和经许可的燃放作业方案进行燃放作业，主办单位又未对承办单位的活动进行监督，公安机关应当立即责令停止燃放，并对责任单位依法给予罚款处罚。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《烟花爆竹安全管理条例》第49条规定，举办焰火晚会以及其他大型焰火燃放活动，承办单位及其作业人员未按照安全规程和许可方案进行作业的，公安机关应当立即责令停止燃放，并对责任单位依法给予罚款处罚。主办单位未进行监督也应承担相应责任。因此该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1285}, {"num": 1287, "batch": "专业基础知识", "type": "bool", "stem": "某县级公安机关对收缴的折叠刀进行认定，以该刀具刀身展开后虽可被刀柄内的卡锁固定自锁，但刀身长度小于150毫米为由，作出不属于管制刀具的结论。该县公安机关的做法正确。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据公安部《管制刀具认定标准》，带有自锁装置的弹簧折叠刀（刀身展开后被刀柄内的卡锁固定自锁），无论刀身长度是否超过150毫米，均属于管制刀具。题目中以刀身长度小于150毫米为由认定不属于管制刀具，不符合认定标准。因此该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1286}, {"num": 1288, "batch": "专业基础知识", "type": "bool", "stem": "李某个人购买易制爆危险化学品，其需要出具证明材料以及用途说明。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《危险化学品安全管理条例》规定，个人不得购买剧毒化学品（属于剧毒化学品的农药除外）和易制爆危险化学品。个人购买易制爆危险化学品需要出具证明材料和用途说明的说法不准确，因为个人原则上不得购买易制爆危险化学品。因此该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1287}, {"num": 1289, "batch": "专业基础知识", "type": "bool", "stem": "小郑刚到某县公安局治安大队工作不久，分管危险物品管理工作。一日，某单位前来申请《危险化学品经营许可证》，小郑让申请人员先报材料，待研究决定后，再予以通知。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《行政许可法》和《危险化学品安全管理条例》，行政机关收到行政许可申请后，应当依法受理并在法定期限内作出决定，不得以'研究决定'为由拖延不办。小郑的做法违反了行政许可的法定程序要求。因此该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1288}, {"num": 1290, "batch": "专业基础知识", "type": "bool", "stem": "某单位是危险化学品经营企业,其可以向任何单位销售剧毒化学品、易制爆危险化学品。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《危险化学品安全管理条例》规定，危险化学品经营企业不得向不具有相关许可证件或者证明文件的单位销售剧毒化学品、易制爆危险化学品。经营企业必须核实购买单位的资质，不能向任何单位销售。因此该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1289}, {"num": 1291, "batch": "专业基础知识", "type": "bool", "stem": "某单位是危险化学品经营企业，其销售剧毒化学品、易制爆危险化学品，应当如实记录购买单位的名称、地址、经办人的姓名、身份证号码以及所购买的剧毒化学品、易制爆危险化学品的品种、数量、用途。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《危险化学品安全管理条例》第41条规定，销售剧毒化学品、易制爆危险化学品的单位，应当如实记录购买单位的名称、地址、经办人的姓名、身份证号码以及所购买的品种、数量、用途。记录应当至少保存1年。因此该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1290}, {"num": 1292, "batch": "专业基础知识", "type": "bool", "stem": "某单位因停产确需转让剧毒化学品、易制爆危险化学品，其应当向具有相关许可证件或者证明文件的单位转让，并在转让后将有关情况及时向所在地县级人民政府公安机关报告。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《危险化学品安全管理条例》规定，因转产、停产等原因确需转让剧毒化学品、易制爆危险化学品的，应当向具有相关许可证件或者证明文件的单位转让，并在转让后将有关情况及时向所在地县级人民政府公安机关报告。因此该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1291}, {"num": 1293, "batch": "专业基础知识", "type": "bool", "stem": "某单位储存易制爆危险化学品的专用仓库未按照国家有关规定设置相应的技术防范设施，应当由公安机关责令改正，可以处以罚款；情节严重的，责令停产停业整顿。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《危险化学品安全管理条例》第78条规定，储存易制爆危险化学品的专用仓库未按照国家有关规定设置相应的技术防范设施的，由公安机关责令改正，可以处以罚款；情节严重的，责令停产停业整顿。因此该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1292}, {"num": 1294, "batch": "专业基础知识", "type": "bool", "stem": "、某单位是生产易制爆危险化学品的单位，该单位未设置治安保卫机构、配备专职治安保卫人员，对其应依照《企业事业单位内部治安保卫条例》的规定处罚。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《危险化学品安全管理条例》规定，生产、储存易制爆危险化学品的单位未设置治安保卫机构、配备专职治安保卫人员的，依照《企业事业单位内部治安保卫条例》的规定处罚。该条例对单位治安保卫工作有明确的法律责任规定。因此该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1293}, {"num": 1295, "batch": "专业基础知识", "type": "bool", "stem": "刘某个人购买剧毒化学品（非农药）、易制爆危险化学品，应当由公安机关没收其所购买的剧毒化学品、易制爆危险化学品，可以并处罚款。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《危险化学品安全管理条例》规定，个人购买剧毒化学品（非农药）、易制爆危险化学品的，由公安机关没收其所购买的剧毒化学品、易制爆危险化学品，可以并处罚款。该规定旨在严格管控危险化学品的购买主体。因此该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1294}, {"num": 1296, "batch": "专业基础知识", "type": "bool", "stem": "使用剧毒化学品、易制爆危险化学品的甲单位向不具有相关许可证件的乙单位转让其购买的剧毒化学品、易制爆危险化学品，应当由公安机关责令改正，处以罚款；拒不改正的，责令停产停业整顿。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《危险化学品安全管理条例》规定，使用剧毒化学品、易制爆危险化学品的单位向不具有相关许可证件的单位转让的，由公安机关责令改正，处以罚款；拒不改正的，责令停产停业整顿。该规定严格规范了危险化学品的流转管理。因此该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1295}, {"num": 1297, "batch": "专业基础知识", "type": "bool", "stem": "张某在邮件内夹带危险化学品，应依法对其给予治安管理处罚；若构成犯罪，依法追究其刑事责任。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《危险化学品安全管理条例》和《邮政法》相关规定，在邮件内夹带危险化学品的，应依法给予治安管理处罚；若构成犯罪，依法追究刑事责任。该规定旨在防止危险化学品通过邮政渠道造成安全隐患。因此该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1296}, {"num": 1298, "batch": "专业基础知识", "type": "bool", "stem": "某单位非法运输仿真枪，发现地公安机关可以对该单位负有直接责任的主管人员和其他直接责任人员处警告或者拘留。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《枪支管理法》相关规定，非法运输仿真枪的，由公安机关对单位处以罚款，并对直接负责的主管人员和其他直接责任人员处以罚款，而非警告或拘留。题目中的处罚种类表述错误。因此该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1297}, {"num": 1299, "batch": "专业基础知识", "type": "bool", "stem": "B县公安局在小商品市场查获一种“枪支”，该“枪支”外形、颜色与制式枪支相同，并且外形长度尺寸介于相应制式枪支全枪长度尺寸的1/2与1倍之间，可以认定为仿真枪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据公安部《关于认定仿真枪有关问题的通知》，外形、颜色与制式枪支相同，并且外形长度尺寸介于相应制式枪支全枪长度的1/2与1倍之间的，可以认定为仿真枪。题目中该物品符合上述外形和尺寸条件，可以认定为仿真枪。因此该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1298}, {"num": 1300, "batch": "专业基础知识", "type": "bool", "stem": "对不具有杀伤力但符合仿真枪认定规定的，不应认定为仿真枪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据仿真枪认定相关规定，不具有杀伤力但符合仿真枪认定规定的，应当认定为仿真枪。仿真枪的本质特征就是不具有枪支的杀伤力但外形类似枪支，符合认定标准的就应当认定为仿真枪并依法管理。题目称不应认定为仿真枪，与规定不符。因此该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1299}, {"num": 1301, "batch": "专业基础知识", "type": "bool", "stem": "仿真枪的认定工作由县级或者县级以上公安机关负责。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《仿真枪认定标准》及公安部相关规定，仿真枪的认定工作由县级或者县级以上公安机关负责。该规定明确了仿真枪认定的主管机关级别，确保认定工作的规范性和权威性。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1300}, {"num": 1302, "batch": "专业基础知识", "type": "bool", "stem": "具备枪支外形特征，并且具有与制式枪支材质和功能相似的枪管、枪机、机匣或者击发等机构之一的器具，可以认定为仿真枪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《仿真枪认定标准》的规定，具备枪支外形特征，并且具有与制式枪支材质和功能相似的枪管、枪机、机匣或者击发等机构之一的器具，可以认定为仿真枪。这是仿真枪认定的法定标准之一。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1301}, {"num": 1303, "batch": "专业基础知识", "type": "bool", "stem": "甲未取得危险化学品安全生产许可证、危险化学品安全使用许可证、危险化学品经营许可证，其要购买剧毒化学品，应当向所在地县级人民政府公安机关申请取得剧毒化学品购买许可证。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《危险化学品安全管理条例》第42条规定，未取得危险化学品安全生产许可证、安全使用许可证、经营许可证的单位，购买剧毒化学品应当向所在地县级人民政府公安机关申请取得剧毒化学品购买许可证。该规定旨在严格管控剧毒化学品的流通环节。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1302}, {"num": 1304, "batch": "专业基础知识", "type": "bool", "stem": "催泪弹属于警械。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《人民警察使用警械和武器条例》第3条规定，警械分为驱逐性、制服性警械和约束性警械。催泪弹属于驱逐性、制服性警械，属于警械的范畴，故该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1303}, {"num": 1305, "batch": "专业基础知识", "type": "bool", "stem": "高压水枪属于约束性警械。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《人民警察使用警械和武器条例》第3条，高压水枪属于驱逐性、制服性警械，而非约束性警械。约束性警械是指手铐、脚镣、警绳等用于限制违法犯罪行为人人身自由的警械。故该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1304}, {"num": 1306, "batch": "专业基础知识", "type": "bool", "stem": "某抢劫犯罪嫌疑人驾车冲出警方包围，强闯公路上一堵截卡点后，正要冲向行人集中的步行街时，被民警直接开枪击毙。民警的做法是对的。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《人民警察使用警械和武器条例》第9条规定，犯罪嫌疑人驾车冲撞行人集中的步行街，属于以危险方法危害公共安全的紧急情形，严重危及公民生命安全，民警经警告无效（紧急情况下可直接使用武器）可以使用武器。民警开枪击毙嫌疑人的行为合法。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1305}, {"num": 1307, "batch": "专业基础知识", "type": "bool", "stem": "民警小张在追捕持枪犯罪嫌疑人陈某时，发现其正处于群众聚集的菜市场，人员集中，易伤及无辜群众，此时，出现任何情况小张都不能使用武器。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《人民警察使用警械和武器条例》第10条规定，人民警察在群众聚集的场合一般不得使用武器，但不使用武器制止，可能发生更为严重危害后果的除外。因此并非任何情况下都不能使用武器，该说法过于绝对，故错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1306}, {"num": 1308, "batch": "专业基础知识", "type": "bool", "stem": "人民警察抓获违法犯罪分子或者犯罪重大嫌疑人时，可以使用警棍、手铐、脚镣等约束性警械。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《人民警察使用警械和武器条例》第3条和第8条，约束性警械包括手铐、脚镣、警绳等，警棍属于驱逐性、制服性警械而非约束性警械。题目将警棍归类为约束性警械，故该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1307}, {"num": 1309, "batch": "专业基础知识", "type": "bool", "stem": "涉嫌开设赌场罪的陈某在民警突击检查赌场时逃跑，为将其抓获，民警经警告无效可以对其使用武器。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《人民警察使用警械和武器条例》第9条规定，可以使用武器的情形主要针对严重暴力犯罪或紧急危险情形。开设赌场罪属于非暴力犯罪，犯罪嫌疑人逃跑不符合使用武器的法定条件，故该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1308}, {"num": 1310, "batch": "专业基础知识", "type": "bool", "stem": "人民警察使用武器造成人员伤亡的，应当立即向其所属公安机关报告，也可以向当地公安机关报告。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《人民警察使用警械和武器条例》第12条规定，人民警察使用武器造成人员伤亡的，应当及时抢救受伤人员，保护现场，并立即向当地公安机关或者该人民警察所属机关报告。故该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1309}, {"num": 1311, "batch": "专业基础知识", "type": "bool", "stem": "公安机关接到人民警察使用武器造成人员伤亡的报告后，应当及时进行勘验、调查，并及时通知当地人民检察院。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《人民警察使用警械和武器条例》第13条规定，公安机关接到人民警察使用武器造成人员伤亡的报告后，应当及时进行勘验、调查，并及时通知当地人民检察院。这是法定程序要求，故该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1310}, {"num": 1312, "batch": "专业基础知识", "type": "bool", "stem": "人民警察使用武器造成犯罪嫌疑人伤亡的，应当立即将伤者送医院治疗，并立即通知其家属或者其所在单位。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《人民警察使用警械和武器条例》第12条规定，人民警察使用武器造成人员伤亡的，应当立即将伤者送医院治疗或及时抢救，保护现场，并立即向当地公安机关或所属机关报告，同时通知其家属或其所在单位。题目遗漏了报告程序的要求，表述不完整，故该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1311}, {"num": 1313, "batch": "专业基础知识", "type": "bool", "stem": "人民警察使用武器造成人员伤亡的，无论伤亡人员是犯罪分子还是无辜人员，都应当及时抢救受伤人员，保护现场，并立即向当地公安机关或者该人民警察所属机关报告。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《人民警察使用警械和武器条例》第12条规定，无论伤亡人员是犯罪分子还是无辜人员，人民警察都应当及时抢救受伤人员，保护现场，并立即向当地公安机关或者该人民警察所属机关报告。故该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1312}, {"num": 1314, "batch": "专业基础知识", "type": "bool", "stem": "人民警察违法使用警械、武器，尚不构成犯罪的，应当依法给予行政处罚。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《人民警察使用警械和武器条例》第14条规定，人民警察违法使用警械、武器，尚不构成犯罪的，应当依法给予处分，而非行政处罚。处分是指行政处分（如警告、记过、降级等），与行政处罚性质不同，故该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1313}, {"num": 1315, "batch": "专业基础知识", "type": "bool", "stem": "民警吕某抓获逃犯蔡某，从抓捕现场押解回公安机关的途中，吕某可以对蔡某使用约束性警械。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《人民警察使用警械和武器条例》第8条规定，人民警察依法执行抓获违法犯罪分子或者犯罪重大嫌疑人、押解等任务时，可以使用手铐、脚镣、警绳等约束性警械。押解途中属于依法执行任务，可以使用约束性警械，故该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1314}, {"num": 1316, "batch": "专业基础知识", "type": "bool", "stem": "人民警察制止违法犯罪行为，可以采取强制手段；根据需要，可以依照《人民警察使用警械和武器条例》的规定使用警械；使用警械不能制止的，可以依照《人民警察使用警械和武器条例》的规定使用武器。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《人民警察使用警械和武器条例》第2条规定，人民警察制止违法犯罪行为，可以采取强制手段；根据需要，可以依照本条例的规定使用警械；使用警械不能制止，或者不使用武器制止，可能发生严重危害后果的，可以依照本条例的规定使用武器。故该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1315}, {"num": 1317, "batch": "专业基础知识", "type": "bool", "stem": "人民警察制止违法犯罪行为，在使用警械不能制止或者不使用武器制止可能发生严重危害后果的情况下，可以使用武器。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《人民警察使用警械和武器条例》第9条规定，在使用警械不能制止或者不使用武器制止可能发生严重危害后果的情况下，可以使用武器。这体现了武力使用的递进原则，故该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1316}, {"num": 1318, "batch": "专业基础知识", "type": "bool", "stem": "人民警察使用警械和武器，应当以制止违法犯罪行为，尽量减少人员伤亡、财产损失为原则。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《人民警察使用警械和武器条例》第4条规定，人民警察使用警械和武器，应当以制止违法犯罪行为，尽量减少人员伤亡、财产损失为原则。这是警械和武器使用的基本原则，故该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1317}, {"num": 1319, "batch": "专业基础知识", "type": "bool", "stem": "人民警察依照规定使用驱逐性、制服性警械，应当以不致违法犯罪行为人伤害为限度。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《人民警察使用警械和武器条例》第7条规定，人民警察使用驱逐性、制服性警械，应当以制止违法犯罪行为为限度，而非以不致违法犯罪行为人伤害为限度。当违法犯罪行为得到制止时，应当立即停止使用。故该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1318}, {"num": 1320, "batch": "专业基础知识", "type": "bool", "stem": "民警在值勤时，发现陈某在机动车道上骑自行车，便要对其违章行为进行处罚，陈某拒绝接受处罚并与之发生争执，民警遂对陈某使用手铐，并将陈某按倒在地，造成陈某手腕表皮挫伤及头部外伤。民警使用手铐的行为是合法的。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "陈某在机动车道上骑自行车属于轻微交通违章行为，不符合《人民警察使用警械和武器条例》第7条规定的使用驱逐性、制服性警械的条件。民警使用手铐将陈某按倒在地属于违法使用警械，故该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1319}, {"num": 1321, "batch": "专业基础知识", "type": "bool", "stem": "民警甲、乙在巡逻过程中，发现有2名男子因琐事发生口角，进而互殴。甲、乙立即上前使用催泪瓦斯将二人制服。民警使用催泪瓦斯的行为是合法的。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "两名男子因琐事口角互殴，属于一般治安案件。根据《人民警察使用警械和武器条例》第7条，使用驱逐性警械（催泪瓦斯）应当先经警告无效，且针对的是法定的严重违法犯罪行为。对普通互殴行为直接使用催泪瓦斯不符合比例原则，故该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1320}, {"num": 1322, "batch": "专业基础知识", "type": "bool", "stem": "某晚10时许，贾某酒后与小区保安发生纠纷。派出所民警李某、陈某接110处警指令后到场处置。贾某不听劝阻打了民警陈某一个耳光，并纠集了6名朋友将其围住。陈某经警告无效后，使用催泪瓦斯喷射器控制了现场局势。该所10余名增援警力到场后将滋事者带回派出所。经医院诊断，民警陈某脸部、颈部多处软组织挫伤。陈某使用催泪瓦斯喷射器合法。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "贾某打民警耳光并纠集6人围住民警，属于以暴力方法阻碍人民警察依法执行职务，且人数众多、情况紧急。根据《人民警察使用警械和武器条例》第7条规定，经警告无效可以使用催泪瓦斯等驱逐性警械。陈某使用催泪瓦斯控制现场局势的行为合法，故该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1321}, {"num": 1323, "batch": "专业基础知识", "type": "bool", "stem": "谢某与吴某有矛盾。一日，谢某等5人与吴某等3人相遇，发生持械群殴，吴某被砍伤。此时，民警陆某经过此地，喊道：“我是公安局的，不许打架。”但众人并未收敛，谢某持长刀冲上来，砍中民警陆某的左手。陆某立即开枪将谢某击倒，其他人四处逃窜。陆某开枪的行为是合法的。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "谢某持长刀砍向民警陆某，属于正在实施严重危及人身安全的暴力犯罪行为。根据《人民警察使用警械和武器条例》第9条规定，人民警察判明有暴力犯罪行为的紧急情形，经警告无效可以使用武器。陆某在生命受到严重威胁时开枪合法，故该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1322}, {"num": 1324, "batch": "专业基础知识", "type": "bool", "stem": "民警小王、小李发现郑某有吸毒嫌疑，遂口头传唤其至公安机关接受调查。郑某无正当理由拒绝接受传唤，民警使用手铐将郑某强制传唤至派出所，并立即报告公安机关负责人补办了批准手续。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《治安管理处罚法》第82条规定，对无正当理由不接受传唤或者逃避传唤的人，可以强制传唤。强制传唤时可以使用约束性警械。民警使用手铐强制传唤拒绝接受传唤的吸毒嫌疑人，并补办批准手续，程序合法，故该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1323}, {"num": 1325, "batch": "专业基础知识", "type": "bool", "stem": "一名歹徒在长途客车上对着车顶开了一枪，并将枪口对准乘客，声称谁不交出钱和首饰就打死谁。民警孙某见状，暗中掏出手枪，选择有利时机直接将其击毙。孙某的行为是合法的。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "歹徒在客车上持枪实施抢劫，严重危及乘客生命安全，属于《人民警察使用警械和武器条例》第9条规定的可以使用武器的紧急情形。民警孙某选择有利时机直接将其击毙，符合法律规定，故该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1324}, {"num": 1326, "batch": "专业基础知识", "type": "bool", "stem": "民警甲发现李某正在殴打徐某，附近群众聚集围观。甲经警告无效，遂要求围观群众远离并使用警棍制服李某。民警使用警棍的行为是合法的。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "李某正在殴打徐某，属于正在实施违法犯罪行为。根据《人民警察使用警械和武器条例》第7条规定，经警告无效，可以使用警棍等制服性警械。民警甲经警告无效后使用警棍制服李某，并要求群众远离，程序合法，故该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1325}, {"num": 1327, "batch": "专业基础知识", "type": "bool", "stem": "某日，多人聚集在F市中心广场非法集会，现场执勤民警命令集会人员解散，集会人员拒不执行且起哄，现场秩序十分混乱，经警告无效且命令在场无关人员躲避后，民警遂使用高压水枪强行驱散集会人员，控制了事态的发展，但是造成无辜群众王某受伤住院。王某受到民警执行职务行为的伤害，应得到公安机关的补偿。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《人民警察使用警械和武器条例》第15条规定，人民警察依法使用警械和武器，造成无辜人员伤亡的，由该人民警察所属机关参照《国家赔偿法》的有关规定给予补偿。王某作为无辜群众受伤，应得到公安机关的补偿，故该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1326}, {"num": 1328, "batch": "专业基础知识", "type": "bool", "stem": "人民警察使用武器，一般情况下应当先行警告，经警告无效的，才可以使用武器。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《人民警察使用警械和武器条例》第9条规定，人民警察在使用武器前，一般应当先命令在场无关人员躲避，然后先行警告（口头警告或鸣枪警告），经警告无效的，才可以使用武器。但存在来不及警告或警告后可能发生更为严重危害后果的例外情形，故该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1327}, {"num": 1329, "batch": "专业基础知识", "type": "bool", "stem": "人民警察违法使用武器，造成不应有的人员伤亡的，由该人民警察依照《国家赔偿法》的有关规定给予赔偿。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《人民警察使用警械和武器条例》第14条规定，人民警察违法使用武器，造成不应有的人员伤亡，构成犯罪的依法追究刑事责任；尚不构成犯罪的，依法给予处分。对受到伤亡或者财产损失的人员，由该人民警察所属机关依照《国家赔偿法》的有关规定给予赔偿，而非由警察个人赔偿，故该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1328}, {"num": 1330, "batch": "专业基础知识", "type": "bool", "stem": "陆某在一闹市区抢夺了一名妇女的挎包后逃跑，该妇女和群众从后面赶上将其围住，陆某抓住一名群众，将匕首架在该群众的脖子上。民警到达现场后，在警告无效的情况下，开枪将陆某击伤后抓获。民警开枪的行为是合法的。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "陆某持匕首劫持群众，属于以暴力方法严重危及公民生命安全的紧急情形。根据《人民警察使用警械和武器条例》第9条规定，经警告无效可以使用武器。民警开枪击伤陆某后将其抓获，符合法律规定，故该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1329}, {"num": 1331, "batch": "专业基础知识", "type": "bool", "stem": "人民警察使用武器前必须先行警告。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《人民警察使用警械和武器条例》第9条规定，人民警察在使用武器前一般应当先行警告，但来不及警告或者警告后可能发生更为严重危害后果的，可以直接使用武器。因此并非必须先行警告，故该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1330}, {"num": 1332, "batch": "专业基础知识", "type": "bool", "stem": "民警在抓捕犯罪嫌疑人刘某的过程中，刘某徒手打向民警，并用脚踢民警。民警经警告无效，使用手枪将其击倒。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "刘某徒手殴打和踢打民警，属于一般暴力行为，不属于严重危及人身安全的暴力犯罪。根据比例原则和《人民警察使用警械和武器条例》的规定，使用手枪击倒明显超出必要限度，不符合使用武器的法定条件，故该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1331}, {"num": 1333, "batch": "专业基础知识", "type": "bool", "stem": "《人民警察使用警械和武器条例》所指的致命性警用武器包括弹药。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《人民警察使用警械和武器条例》第3条规定，本条例所称警用武器，是指人民警察按照规定装备的枪支、弹药等致命性警用武器。弹药明确属于致命性警用武器的范畴，故该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1332}, {"num": 1334, "batch": "专业基础知识", "type": "bool", "stem": "人民警察按规定使用警械，应当以制止违法犯罪行为为限度；当违法犯罪行为得到制止时，应当立即停止使用。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《人民警察使用警械和武器条例》第7条规定，人民警察依照规定使用警械，应当以制止违法犯罪行为为限度；当违法犯罪行为得到制止时，应当立即停止使用。这体现了武力使用的适度原则，故该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1333}, {"num": 1335, "batch": "专业基础知识", "type": "bool", "stem": "甲因债务纠纷非法强行闯入乙的住宅，乙及其家人要求甲退出，甲拒不退出，并长期占据乙的住宅，其家人只好到其他地方居住。甲涉嫌非法侵入住宅罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《刑法》第245条规定，非法搜查他人身体、住宅，或者非法侵入他人住宅的，构成非法侵入住宅罪。甲因债务纠纷强行闯入乙的住宅，经要求退出而拒不退出，长期占据他人住宅，符合非法侵入住宅罪的构成要件，故该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1334}, {"num": 1336, "batch": "专业基础知识", "type": "bool", "stem": "甲为一公司老板，指使乙、丙等人采用限制人身自由的方法强迫农民工为其从事高强度劳动。甲、乙、丙等人的行为构成非法拘禁罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《刑法》第244条规定，以限制人身自由的方法强迫他人劳动的，构成强迫劳动罪。甲指使乙、丙等人限制农民工人身自由强迫其从事高强度劳动，应认定为强迫劳动罪而非非法拘禁罪，故该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1335}, {"num": 1337, "batch": "专业基础知识", "type": "bool", "stem": "甲为了得到提拔，捏造同事曹某包养情人的事实并匿名举报，使曹某失去晋升机会。甲的行为构成诬告陷害罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《刑法》第243条规定，诬告陷害罪是指捏造犯罪事实，向国家机关或有关单位告发，意图使他人受刑事追究的行为。甲捏造的是包养情人这一违纪事实而非犯罪事实，不构成诬告陷害罪，可能构成诽谤罪，故该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1336}, {"num": 1338, "batch": "专业基础知识", "type": "bool", "stem": "甲与乙系在国家机关工作的同事，平时有隙。为报复乙，甲向公安机关作虚假匿名举报，诬告乙曾在一歌舞厅嫖娼，有“陪侍女”丙为证。公安机关调查时，丙对此作了虚假指证，乙因而受到了公安机关的处罚。甲的行为应定性为诬告陷害罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《刑法》第243条规定，诬告陷害罪要求捏造犯罪事实意图使他人受刑事追究。嫖娼属于违反治安管理的行为而非犯罪行为，甲诬告乙嫖娼不会导致乙受到刑事追究，不构成诬告陷害罪，可能构成诽谤罪，故该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1337}, {"num": 1339, "batch": "专业基础知识", "type": "bool", "stem": "刘某明知张某制造毒品而为其运输乙醚，情节较重，对刘某应以非法运输制毒物品罪论处。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《刑法》第350条及相关司法解释，明知他人制造毒品而为其提供、运输制毒物品的，以制造毒品罪的共犯论处，而非以非法运输制毒物品罪论处。刘某明知张某制造毒品仍为其运输乙醚，应认定为制造毒品罪共犯，故该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1338}, {"num": 1340, "batch": "专业基础知识", "type": "bool", "stem": "聋哑人张某身藏一把匕首，在菜市场从李某身上的口袋里偷走了90元现金。对张某应当以盗窃进行治安管理处罚，但是可以从轻、减轻或者不予处罚。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《刑法》第264条规定，携带凶器盗窃的，不论数额大小均构成盗窃罪。张某身藏匕首进行扒窃，属于携带凶器盗窃，应以盗窃罪追究刑事责任，而非仅进行治安管理处罚，故该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1339}, {"num": 1341, "batch": "专业基础知识", "type": "bool", "stem": "王某购买了多个不同型号的保险箱，在家中研究成功快速打开保险箱的方法，并将该方法记录在自己的本子上，后不小心被盗窃团伙成员发现并学会。王某的行为构成传授犯罪方法罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《刑法》第295条规定，传授犯罪方法罪是指故意向他人传授犯罪方法的行为，要求行为人主观上具有传授的故意。王某研究开锁方法系出于个人兴趣，并无向他人传授犯罪方法的主观故意，被他人偷学不构成传授犯罪方法罪，故该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1340}, {"num": 1342, "batch": "专业基础知识", "type": "bool", "stem": "某国发生邮寄炭疽杆菌恐怖袭击事件后被国内媒体大量报道。杨某为寻求刺激，向本市多个政府机关寄送貌似炭疽杆菌的面粉，引起社会恐慌。杨某成立投放虚假危险物质罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《刑法》第291条之一规定，投放虚假的爆炸性、毒害性、放射性、传染病病原体等物质，严重扰乱社会秩序的，构成投放虚假危险物质罪。杨某向政府机关寄送貌似炭疽杆菌的面粉，引起社会恐慌，符合该罪构成要件，故该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1341}, {"num": 1343, "batch": "专业基础知识", "type": "bool", "stem": "张某是香港黑社会组织成员，其到内地发展组织成员，不构成入境发展黑社会组织罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《刑法》第294条第2款规定，境外的黑社会组织的人员到中华人民共和国境内发展组织成员的，构成入境发展黑社会组织罪。香港属于中国领域，但根据司法实践，香港黑社会组织属于境外黑社会组织，张某到内地发展组织成员构成入境发展黑社会组织罪，故该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1342}, {"num": 1344, "batch": "专业基础知识", "type": "bool", "stem": "李某强迫王某卖血，在此过程中对王某人身造成伤害，致轻伤。李某的行为构成强迫卖血罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《刑法》第333条规定，强迫他人卖血的，构成强迫卖血罪；对他人造成伤害的，依照故意伤害罪定罪处罚。李某强迫王某卖血并致其轻伤，应以故意伤害罪定罪处罚，而非强迫卖血罪，故该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1343}, {"num": 1345, "batch": "专业基础知识", "type": "bool", "stem": "A市公安机关在工作中发现李某伪造签证申请材料为张某骗取美国签证，并策划、引带其从首都机场出境。A市公安机关应将该案立为组织他人偷越国（边）境案件。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《刑法》第318条及相关司法解释，为他人伪造出入境证件、策划偷越路线并引带出境的行为，属于组织他人偷越国（边）境的行为方式之一。李某的行为符合组织他人偷越国（边）境罪的构成要件，故该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1344}, {"num": 1346, "batch": "专业基础知识", "type": "bool", "stem": "甲组织他人偷渡，在带领偷渡人员通过边检站时，被工作人员怀疑，甲暴力抗拒检查但未造成实际伤害，对其行为应当认定为组织他人偷越国（边）境罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《刑法》第318条规定，组织他人偷越国（边）境，并以暴力、威胁方法抗拒检查的，属于组织他人偷越国（边）境罪的加重情节，不另以妨害公务罪论处。甲暴力抗拒检查的行为被组织他人偷越国（边）境罪所吸收，故该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1345}, {"num": 1347, "batch": "专业基础知识", "type": "bool", "stem": "张三欲偷渡至美国非法打工，因担心独自赴美孤单，遂拉拢其表弟李四共同通过“蛇头”安排偷渡美国。张三的行为应按照偷越国（边）境行为给予治安管理处罚。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《刑法》第318条及相关司法解释，拉拢、引诱他人共同偷越国（边）境的，属于组织他人偷越国（边）境的行为，应以组织他人偷越国（边）境罪追究刑事责任，而非仅按偷越国（边）境行为给予治安处罚，故该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1346}, {"num": 1348, "batch": "专业基础知识", "type": "bool", "stem": "王某将骗取的护照卖给他人，对其应按骗取出境证件罪和出售出入境证件罪数罪并罚。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据相关司法解释，骗取出境证件后又出售的，属于牵连犯，应择一重罪处罚，不实行数罪并罚。王某骗取护照后卖给他人，应按牵连犯从一重罪处断，而非数罪并罚，故该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1347}, {"num": 1349, "batch": "专业基础知识", "type": "bool", "stem": "张某等3名中国公民从王某处获得了伪造的美国签证，欲使用该签证偷渡至美国，因张某等人不熟悉边防出境过程且从未去过美国，故找到美籍华人彼得让其带领偷渡至境外，后彼得被抓获。彼得的行为构成运送他人偷越国（边）境罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《刑法》第321条规定，运送他人偷越国（边）境的，构成运送他人偷越国（边）境罪。彼得作为带领者，负责将张某等人运送出境，其行为符合运送他人偷越国（边）境罪的构成要件，故该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1348}, {"num": 1350, "batch": "专业基础知识", "type": "bool", "stem": "甲在运送他人偷越国边（境）时以暴力、威胁等方式抗拒边检人员的检查，应当以运送他人偷越国（边）境罪和妨害公务罪数罪并罚。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《刑法》第321条第3款规定，在运送他人偷越国（边）境中以暴力、威胁方法抗拒检查的，属于运送他人偷越国（边）境罪的加重情节，不另以妨害公务罪论处，不实行数罪并罚，故该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1349}, {"num": 1351, "batch": "专业基础知识", "type": "bool", "stem": "赵某购买了15克冰毒用于吸食，在家中藏匿该冰毒时被公安机关抓获。赵某的行为构成非法持有毒品罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《刑法》第348条及相关司法解释，非法持有甲基苯丙胺（冰毒）10克以上不满50克的，构成非法持有毒品罪。赵某购买并持有15克冰毒，已达到非法持有毒品罪的立案标准，故该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1350}, {"num": 1352, "batch": "专业基础知识", "type": "bool", "stem": "甲拐卖妇女前往某地途中，强行奸淫数名被拐卖的妇女。甲的行为构成拐卖妇女罪和强奸罪，数罪并罚。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《刑法》第240条规定，拐卖妇女过程中奸淫被拐卖的妇女的，属于拐卖妇女罪的加重情节，以拐卖妇女罪一罪从重处罚，不另以强奸罪数罪并罚，故该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1351}, {"num": 1353, "batch": "专业基础知识", "type": "bool", "stem": "张某在组织、领导恐怖活动组织期间，多次实施爆炸、绑架等犯罪活动，对张某应以组织、领导恐怖活动组织罪从重处罚。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《刑法》第120条第2款规定，犯组织、领导恐怖活动组织罪，并实施杀人、爆炸、绑架等犯罪的，依照数罪并罚的规定处罚。对张某应以组织、领导恐怖活动组织罪与爆炸罪、绑架罪等数罪并罚，而非仅从重处罚，故该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1352}, {"num": 1354, "batch": "专业基础知识", "type": "bool", "stem": "赵某购买了制造毒品的原料和制毒工具，在自家反复试验，已经制造出300克粗制毒品，还有一小桶半成品。对赵某应以制造毒品罪未遂论处。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "制造毒品罪属于行为犯，只要制造出毒品即为既遂，不以数量或纯度为标准。赵某已经制造出300克粗制毒品，说明毒品已经制造成功，应认定为制造毒品罪既遂，而非未遂，故该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1353}, {"num": 1355, "batch": "专业基础知识", "type": "bool", "stem": "张某在绑架李某后，强迫其卖淫，对张某应当按照绑架罪和强迫卖淫数罪并罚。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《刑法》规定，绑架罪和强迫卖淫罪是两个独立的犯罪行为，不存在法条竞合或吸收关系。张某在绑架李某后又强迫其卖淫，应当以绑架罪和强迫卖淫罪数罪并罚，故该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1354}, {"num": 1356, "batch": "专业基础知识", "type": "bool", "stem": "甲患有严重性病，在与乙通奸时将性病传染给了乙。甲的行为构成传播性病罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《刑法》第360条规定，传播性病罪是指明知自己患有梅毒、淋病等严重性病而卖淫、嫖娼的行为。该罪仅限于卖淫、嫖娼行为，通奸传播性病不符合该罪的客观要件，不构成传播性病罪，故该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1355}, {"num": 1357, "batch": "专业基础知识", "type": "bool", "stem": "李某在行李中藏匿淫秽书刊20本，在海关入境时被查获，经查证李某是用于自己观看，其行为构成走私淫秽物品罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《刑法》第152条规定，走私淫秽物品罪要求以牟利或者传播为目的。李某藏匿淫秽书刊入境系用于自己观看，不具有牟利或传播的目的，不构成走私淫秽物品罪，故该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1356}, {"num": 1358, "batch": "专业基础知识", "type": "bool", "stem": "张某因偷越国（边）境被公安机关处以5日行政拘留。次年2月，张某持用伪造的护照从首都机场出境时被查获，对其应按照偷越国（边）境罪定罪处罚。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《刑法》第322条及相关司法解释，偷越国（边）境罪要求情节严重。张某虽曾因偷越国（边）境被行政处罚，但其使用伪造护照出境的行为定性需综合考虑。仅凭使用伪造护照出境一次，不必然构成偷越国（边）境罪，可能属于治安违法行为，故该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1357}, {"num": 1359, "batch": "专业基础知识", "type": "bool", "stem": "警察王某要为自己的儿子上学筹一笔钱，便找村民张某借钱。张某同意借钱，但条件是要有物品质押。王某将公务用枪交给张某质押。张某借给王某3万元现金，借期6个月。6个月后，王某无力偿还借款，张某持枪逼债,被公安机关发现。王某的行为构成非法出借枪支罪，张某的行为构成非法持有枪支罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《刑法》第128条规定，依法配备公务用枪的人员非法出借枪支的，构成非法出借枪支罪；违反枪支管理规定，非法持有枪支的，构成非法持有枪支罪。王某将公务用枪质押给张某，属于非法出借枪支；张某持有枪支逼债，构成非法持有枪支罪，故该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1358}, {"num": 1360, "batch": "专业基础知识", "type": "bool", "stem": "民警甲将依法配备的公务用枪出借给无业游民乙，只有因出借枪支造成严重后果的，甲的行为才构成犯罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《刑法》第128条规定，依法配备公务用枪的人员非法出借枪支的，不论是否造成严重后果，均构成非法出借枪支罪。该罪属于行为犯，不以造成严重后果为构成要件，故该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1359}, {"num": 1361, "batch": "专业基础知识", "type": "bool", "stem": "张某驾驶小型轿车在实行门禁制度的国家机关院内行驶时，因操作不当，将被害人陈某撞倒，陈某经抢救无效死亡。张某的行为构成过失致人死亡罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《道路交通安全法》第119条规定，道路是指公路、城市道路和实行社会机动车通行的地方。实行门禁制度的国家机关院内不属于法定道路范围，在该区域内驾车致人死亡不构成交通肇事罪，应以过失致人死亡罪定罪，故该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1360}, {"num": 1362, "batch": "专业基础知识", "type": "bool", "stem": "谢某醉酒驾驶机动车闯红灯，造成1人死亡。对谢某应当以危险驾驶罪和交通肇事罪数罪并罚。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《刑法》第133条之一规定，醉酒驾驶机动车同时构成其他犯罪的，依照处罚较重的规定定罪处罚。谢某醉驾致1人死亡，同时构成危险驾驶罪和交通肇事罪，应择一重罪以交通肇事罪定罪处罚，不实行数罪并罚，故该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1361}, {"num": 1363, "batch": "专业基础知识", "type": "bool", "stem": "某施工工地升降机操作工刘某未注意下方有人即按启动按钮，造成维修工张某当场被挤压身亡。刘某报告事故时隐瞒了自己按下启动按钮的事实。刘某的行为应定性为过失致人死亡罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "刘某的行为发生在生产作业过程中，属于生产安全事故。根据《刑法》第134条规定，在生产作业中违反安全管理规定，因而发生重大伤亡事故的，构成重大责任事故罪，而非过失致人死亡罪。故该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1362}, {"num": 1364, "batch": "专业基础知识", "type": "bool", "stem": "一工头带领3名工人在户外拆卸广告牌，为赶在工期内完成任务，工头命令当日内完成拆卸工作，同时安排1名工人单独负责电源开关以防事故发生，后突遇雷阵雨导致负责电源开关的工人触电身亡。该工头涉嫌强令违章冒险作业罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《刑法》第134条第2款规定，强令违章冒险作业罪要求行为人强令他人违章冒险作业。工头已安排专人负责电源开关以防事故，说明其采取了安全措施，并非强令违章冒险作业。雷阵雨导致触电属于意外事件，故该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1363}, {"num": 1365, "batch": "专业基础知识", "type": "bool", "stem": "刘某对朱某走私犯罪的违法所得及其产生的收益予以掩饰、隐瞒，其行为构成掩饰、隐瞒犯罪所得、犯罪所得收益罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《刑法》第191条规定，明知是走私犯罪等特定犯罪的违法所得及其产生的收益，而予以掩饰、隐瞒的，构成洗钱罪。走私犯罪属于洗钱罪的七类上游犯罪之一，刘某的行为应认定为洗钱罪，而非掩饰、隐瞒犯罪所得、犯罪所得收益罪，故该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1364}, {"num": 1366, "batch": "专业基础知识", "type": "bool", "stem": "张某为牟取非法利益，在自己家中生产假玉溪香烟600条，并以4.8万元的价格销售给钱某，钱某在将烟拉回库房途中被查获。张某的行为构成生产、销售伪劣产品罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "张某生产的是假冒品牌的香烟，属于假冒注册商标的行为。根据《刑法》规定，生产假冒他人注册商标的商品并销售的，应认定为假冒注册商标罪或销售假冒注册商标的商品罪，而非生产、销售伪劣产品罪（除非产品本身不合格），故该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1365}, {"num": 1367, "batch": "专业基础知识", "type": "bool", "stem": "张三组织王二、赵四、李三等10人在自己的赌场内赌博，被公安机关查获。经调查，张三的赌场开业后，每日经常有20余人在张三的组织下赌博，持续月余时间。对张三应当按照赌博罪追究刑事责任。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《刑法》第303条规定，张三开设固定赌博场所，组织多人长期赌博，符合开设赌场罪的构成要件。开设赌场罪与赌博罪（聚众赌博）的区别在于是否具有固定的赌博场所和经营性质，张三的行为应认定为开设赌场罪，故该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1366}, {"num": 1368, "batch": "专业基础知识", "type": "bool", "stem": "某公司经营管理不善，连年亏损，为减少破产清算时公司可用于清偿债务的资产，在清算时，公司大股东陈某将公司的主要生产设备都转移至自己名下，陈某的行为涉嫌妨害清算罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《刑法》第162条规定，公司、企业进行清算时，隐匿财产，对资产负债表或者财产清单作虚伪记载，或者在未清偿债务前分配公司财产，严重损害债权人或者其他人利益的，构成妨害清算罪。陈某转移公司资产以逃避债务，符合该罪构成要件，故该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1367}, {"num": 1369, "batch": "专业基础知识", "type": "bool", "stem": "某制衣厂通过承担虚构的金额为人民币500万元的债务，实施虚假破产，造成债权人直接经济损失数额400万元。该行为使得应清偿的职工工资、社会保险费用和法定补偿金得不到及时清偿，造成了恶劣社会影响。该制衣厂直接负责的人员构成虚假破产罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《刑法》第162条之二规定，公司、企业通过隐匿财产、承担虚构的债务或者以其他方法转移、处分财产，实施虚假破产，严重损害债权人或者其他人利益的，对其直接负责的人员，构成虚假破产罪。该制衣厂的行为符合该罪构成要件，故该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1368}, {"num": 1370, "batch": "专业基础知识", "type": "bool", "stem": "甲是国有公司委派到一非国有公司从事管理的人员，多次索取他人财物，为他人谋利益，数额较大。甲的行为构成非国家工作人员受贿罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《刑法》第163条第3款规定，国有公司、企业或者其他国有单位中从事公务的人员和国有公司、企业或者其他国有单位委派到非国有公司、企业以及其他单位从事公务的人员，利用职务便利索取或收受他人财物的，依照受贿罪定罪处罚，而非非国家工作人员受贿罪，故该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1369}, {"num": 1371, "batch": "专业基础知识", "type": "bool", "stem": "甲是某国有公司的总经理，利用职务便利，将本单位的盈利业务交由自己的侄子乙进行经营，使国家利益遭受重大损失。甲的行为构成为亲友非法牟利罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《刑法》第166条规定，国有公司、企业的工作人员，利用职务便利，将本单位的盈利业务交由自己的亲友进行经营，使国家利益遭受重大损失的，构成为亲友非法牟利罪。甲作为国有公司总经理，将盈利业务交由侄子经营，使国家利益遭受重大损失，符合该罪构成要件，故该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1370}, {"num": 1372, "batch": "专业基础知识", "type": "bool", "stem": "某国有公司直接负责的主管人员，在签订、履行合同过程中，因严重不负责任被诈骗，造成该公司停业、停产3个月。其行为构成签订、履行合同失职被骗罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《刑法》第167条规定，签订、履行合同失职被骗罪的主体是国有公司、企业、事业单位直接负责的主管人员，要求因严重不负责任被诈骗，致使国家利益遭受重大损失。该主管人员的行为虽造成公司停业停产，但该罪的损失认定需结合具体情况，且需以对方构成诈骗犯罪为前提，故该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1371}, {"num": 1373, "batch": "专业基础知识", "type": "bool", "stem": "甲将一半真币与一半假币拼接，制造大量半真半假面额为100元的纸币，成立变造货币罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据最高人民法院相关司法解释，将真币与假币拼接制造纸币的行为，属于伪造货币的行为方式，应以伪造货币罪定罪处罚，而非变造货币罪。变造货币是指对真币进行挖补、剪贴、涂改等加工处理，改变其面额或数量的行为，故该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1372}, {"num": 1374, "batch": "专业基础知识", "type": "bool", "stem": "居住在A地的甲伪造了大量假币运输到B地出售，构成伪造货币罪、运输假币罪、出售假币罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据最高人民法院《关于审理伪造货币等案件具体应用法律若干问题的解释》，伪造货币后又运输或出售的，以伪造货币罪一罪从重处罚，不实行数罪并罚。甲伪造货币后运输到B地出售，应以伪造货币罪从重处罚，故该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1373}, {"num": 1375, "batch": "专业基础知识", "type": "bool", "stem": "律师王某在代理一起合同违约纠纷案件中，引诱案件主要证人作伪证，造成对方当事人巨大经济损失。王某的行为构成诉讼代理人妨害作证罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《刑法》第306条规定，辩护人、诉讼代理人妨害作证罪仅适用于刑事诉讼中。王某代理的是民事合同违约纠纷案件，不适用该罪名。在民事诉讼中引诱证人作伪证，可能构成妨害作证罪（第307条），故该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1374}, {"num": 1376, "batch": "专业基础知识", "type": "bool", "stem": "甲犯抢劫罪、盗窃罪分别被判处11年、3年有期徒刑，数罪并罚决定执行有期徒刑12年，对甲不得适用假释。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《刑法》第81条第2款规定，对累犯以及因故意杀人、强奸、抢劫、绑架、放火、爆炸、投放危险物质或者有组织的暴力性犯罪被判处10年以上有期徒刑、无期徒刑的犯罪分子，不得假释。甲因抢劫罪被判处11年有期徒刑（10年以上），属于不得假释的情形，故该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1375}, {"num": 1377, "batch": "专业基础知识", "type": "bool", "stem": "王某因犯煽动分裂国家罪被判处有期徒刑5年，刑满释放后第6年又因投放虚假危险物质罪被判处有期徒刑3年。王某构成累犯。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《刑法》第65条和第66条规定，一般累犯要求前后罪均发生在5年以内；特殊累犯（危害国家安全犯罪、恐怖活动犯罪、黑社会性质组织犯罪）不受5年限制，但要求前后罪均为特定类型犯罪。王某后罪投放虚假危险物质罪不属于危害国家安全犯罪，不构成特殊累犯；后罪发生在6年后，也不构成一般累犯，故该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1376}, {"num": 1378, "batch": "专业基础知识", "type": "bool", "stem": "甲犯资助危害国家安全犯罪活动罪，刑满释放8年后又犯煽动实施恐怖活动犯罪。甲成立特殊累犯，不得适用假释。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《刑法》第66条规定，危害国家安全犯罪、恐怖活动犯罪、黑社会性质的组织犯罪的犯罪分子，在刑罚执行完毕或者赦免以后，在任何时候再犯上述任一类罪的，都以累犯论处。甲前罪属于危害国家安全犯罪，后罪属于恐怖活动犯罪，成立特殊累犯。根据《刑法》第81条，累犯不得假释，故该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1377}, {"num": 1379, "batch": "专业基础知识", "type": "bool", "stem": "犯罪嫌疑人自动投案并如实供述自己的罪行后又翻供的，不能认定为自首；但在一审判决前又能如实供述的，应当认定为自首。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据最高人民法院《关于处理自首和立功具体应用法律若干问题的解释》第1条规定，犯罪嫌疑人自动投案并如实供述自己的罪行后又翻供的，不能认定为自首；但在一审判决前又能如实供述的，应当认定为自首。故该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1378}, {"num": 1380, "batch": "专业基础知识", "type": "bool", "stem": "甲因购买境外人士赵某的海洛因被抓获后，按司法机关要求向赵某发短信“报平安”，并表示还要购买毒品，赵某因此未离境，在等待甲时被抓获。甲的行为构成立功。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据最高人民法院《关于处理自首和立功具体应用法律若干问题的解释》第5条规定，犯罪分子按照司法机关的安排，以打电话、发信息等方式将其他犯罪嫌疑人（包括同案犯）约至指定地点，或者协助司法机关抓捕其他犯罪嫌疑人的，应当认定为立功。甲按司法机关要求发短信使赵某被抓获，构成立功，故该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1379}, {"num": 1381, "batch": "专业基础知识", "type": "bool", "stem": "甲因言语激怒乙而被乙殴打致轻伤。乙虽然属于暴力犯罪分子，法律并没有禁止适用缓刑，乙只要符合缓刑条件，仍然可以适用缓刑。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《刑法》第72条规定，缓刑适用于被判处拘役、3年以下有期徒刑的犯罪分子，且需满足犯罪情节较轻、有悔罪表现、没有再犯罪危险、对所居住社区无重大不良影响等条件。法律并未禁止对暴力犯罪分子适用缓刑，乙只要符合缓刑条件即可适用，故该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1380}, {"num": 1382, "batch": "专业基础知识", "type": "bool", "stem": "李某因盗窃被判处管制。因为管制刑本身适用于罪行较轻的犯罪分子，所以对李某可以适用缓刑。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《刑法》第72条规定，缓刑只适用于被判处拘役或者3年以下有期徒刑的犯罪分子。管制刑不属于缓刑适用的刑罚种类，对李某不适用缓刑，故该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1381}, {"num": 1383, "batch": "专业基础知识", "type": "bool", "stem": "王某因盗窃被判处有期徒刑1年，2月刑满释放。同年9月因盗窃被判处有期徒刑2年。对王某不得适用缓刑。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "王某刑满释放后2个月内又犯盗窃罪，前后罪均为有期徒刑以上刑罚，构成累犯。根据《刑法》第74条规定，对于累犯，不适用缓刑。故该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1382}, {"num": 1384, "batch": "专业基础知识", "type": "bool", "stem": "李某因盗窃被判处有期徒刑1年，缓刑2年，在缓刑考验期内，李某又盗窃价值5000元物品，但直到考验期满1年时才被发现，此时仍需撤销缓刑。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《刑法》第77条第1款规定，被宣告缓刑的犯罪分子，在缓刑考验期限内犯新罪的，应当撤销缓刑，对新犯的罪作出判决，把前罪和后罪所判处的刑罚依照数罪并罚的规定决定执行的刑罚。即使在考验期满后才发现，只要新罪发生在考验期内，仍应撤销缓刑，故该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1383}, {"num": 1385, "batch": "专业基础知识", "type": "bool", "stem": "甲犯强奸罪被判处有期徒刑8年，犯寻衅滋事罪被判处有期徒刑5年，数罪并罚后决定执行有期徒刑11年，对甲可以假释。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《刑法》第81条第2款规定，不得假释的情形包括因强奸等暴力性犯罪被判处10年以上有期徒刑。甲犯强奸罪被判处8年（不满10年），不符合禁止假释的条件，虽然数罪并罚执行11年，但单罪刑期未达10年以上，对甲可以假释，故该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1384}, {"num": 1386, "batch": "专业基础知识", "type": "bool", "stem": "甲（17岁）因抢劫罪被判处有期徒刑1年。甲于释放后1个月再次实施抢劫被抓获。甲构成累犯。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《刑法》第65条第1款规定，不满18周岁的人犯罪的，不构成累犯。甲犯罪时17岁，属于未成年人，即使释放后再次犯罪，也不构成累犯，故该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1385}, {"num": 1387, "batch": "专业基础知识", "type": "bool", "stem": "李某15岁时犯抢劫罪，被判处有期徒刑3年，刑满释放后第2年又犯盗窃罪，被判处有期徒刑2年，执行1年以后确有悔改表现，可以适用假释。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "李某犯罪时不满18周岁，根据《刑法》第65条规定不构成累犯。李某犯抢劫罪时未成年，不属于因暴力性犯罪被判处10年以上有期徒刑的情形，不适用禁止假释的规定。执行1年后确有悔改表现，可以适用假释，故该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1386}, {"num": 1388, "batch": "专业基础知识", "type": "bool", "stem": "甲犯A罪，法定最高刑为5年有期徒刑，次年公安机关立案后，甲一直逃避处罚，到外省又犯B罪，则A罪不受追诉时效的限制，而B罪仍受追诉时效的限制。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《刑法》第89条第2款规定，在追诉期限以内又犯罪的，前罪追诉的期限从犯后罪之日起计算。甲在A罪追诉期限内又犯B罪，A罪的追诉时效从犯B罪之日起重新计算，因此A罪不受原追诉时效限制；B罪仍按正常追诉时效计算，故该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1387}, {"num": 1389, "batch": "专业基础知识", "type": "bool", "stem": "甲仅针对乙实施爆炸犯罪，虽然对象是特定的，但只要造成的后果具有不确定性，危害了公共安全，也应当以爆炸罪认定。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "爆炸罪的认定关键在于是否危害公共安全，即是否对不特定多数人的生命、健康或重大公私财产安全造成威胁。即使甲仅针对乙实施爆炸，只要造成的后果具有不确定性，足以危害公共安全，就应以爆炸罪认定，故该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1388}, {"num": 1390, "batch": "专业基础知识", "type": "bool", "stem": "过路人甲发现火灾没有及时报警，导致火灾蔓延，造成巨大损失，甲的不作为构成放火罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "不作为犯罪要求行为人具有法定的作为义务。过路人甲对火灾没有法定的报警义务，不具有作为义务的来源（法律明文规定、职务或业务要求、先行行为引起等），其不作为不构成放火罪，故该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1389}, {"num": 1391, "batch": "专业基础知识", "type": "bool", "stem": "累犯不能适用假释，也不能适用减刑。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《刑法》第74条和第81条规定，累犯不适用缓刑和假释。但根据《刑法》第78条规定，累犯可以适用减刑，法律并未禁止对累犯减刑。故该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1390}, {"num": 1392, "batch": "专业基础知识", "type": "bool", "stem": "村民委员会主任李某在协助政府管理土地征用补偿费时，利用职务便利将其中数额较大款项据为己有。其行为构成贪污罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据全国人大常委会《关于〈中华人民共和国刑法〉第93条第2款的解释》，村民委员会等村基层组织人员协助人民政府从事土地征用补偿费用的管理等行政管理工作时，属于刑法规定的“其他依照法律从事公务的人员”，以国家工作人员论。李某利用职务便利侵吞公款，构成贪污罪，故该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1391}, {"num": 1393, "batch": "专业基础知识", "type": "bool", "stem": "中国公民赵某从甲国贩卖毒品到乙国后回到中国。由于赵某的犯罪行为地不在中国境内，行为也没有危害中国的国家或者公民的利益，所以，对赵某不能适用中国《刑法》。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《刑法》第7条规定，中华人民共和国公民在中华人民共和国领域外犯本法规定之罪的，适用本法。这是属人管辖原则的体现。赵某作为中国公民，无论犯罪行为发生在何处，中国刑法均有管辖权，故该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1392}, {"num": 1394, "batch": "专业基础知识", "type": "bool", "stem": "甲（17岁）多次伙同其他青少年在学校附近拦截上学的中学生，搜取共11人的零花钱、学习用品等钱物，总共价值五六百元。其行为不认为是犯罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "甲犯罪时17岁，系未成年人。根据相关司法解释，未成年人偶尔参与寻衅滋事、强拿硬要等行为，情节轻微的，可不认为是犯罪。甲虽多次拦截中学生并搜取财物，但总额仅五六百元，且系未成年人，可不认为是犯罪，故该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1393}, {"num": 1395, "batch": "专业基础知识", "type": "bool", "stem": "王某因故意伤害罪被判处有期徒刑6年，刑满释放后第二年因开设赌场罪被判处有期徒刑3年，对王某不可以宣告缓刑，但可以假释。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "王某因故意伤害罪被判处有期徒刑6年，刑满释放后第2年又犯开设赌场罪被判处有期徒刑3年，构成累犯。根据《刑法》第74条，累犯不适用缓刑；同时根据《刑法》第81条，累犯也不适用假释。题目说“可以假释”错误，故该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1394}, {"num": 1396, "batch": "专业基础知识", "type": "bool", "stem": "李某准备到某学校财务室撬保险柜偷钱，约张某去帮助他望风。张某不同意并告发了李某，李某的行为属于犯罪未遂。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "李某为盗窃准备工具、约人望风，属于为犯罪制造条件的犯罪预备阶段。因张某告发这一意志以外的原因未能着手实行犯罪，应认定为犯罪预备，而非犯罪未遂（犯罪未遂要求已经着手实行犯罪），故该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1395}, {"num": 1397, "batch": "专业基础知识", "type": "bool", "stem": "甲和乙共谋杀丙。甲在外望风，乙进入丙家实施杀害行为。乙在杀害过程中自动放弃了杀人行为，丙未死。甲、乙均构成故意杀人罪中止，因没有造成丙的人身损害，对二人应当免除处罚。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "在共同犯罪中，乙自动放弃杀人行为并有效防止结果发生，乙构成故意杀人罪中止。但甲作为共犯，犯罪未得逞是由于乙自动放弃这一意志以外的原因，甲构成故意杀人罪预备（或未遂），而非中止。共同犯罪中各共犯的犯罪形态可以不同，故该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1396}, {"num": 1398, "batch": "专业基础知识", "type": "bool", "stem": "张三扒窃得李四钱包，刚走出5米被李四发现后逃跑，李四紧追50米时，张三将钱包扔还给李四。张三的行为是盗窃罪中止。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "张三扒窃得李四钱包，已经将钱包置于自己控制之下，盗窃罪已经既遂。犯罪既遂后不存在中止的问题。张三在被追赶过程中将钱包扔还，属于犯罪既遂后的退赃行为，不影响既遂的认定，故该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1397}, {"num": 1399, "batch": "专业基础知识", "type": "bool", "stem": "甲与乙有仇，某日甲趁乙家无人时，放火点燃乙家房屋。火烧起来后，甲后悔，遂奋力扑救，但因火势过猛，乙家房屋被烧毁。因为甲作出了中止行为，所以甲是犯罪中止。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "犯罪中止要求自动放弃犯罪或者自动有效地防止犯罪结果发生。甲虽然实施了扑救行为（中止行为），但因火势过猛未能有效防止结果发生（乙家房屋被烧毁），犯罪结果已经发生，不构成犯罪中止，应认定为犯罪既遂，故该说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1398}, {"num": 1400, "batch": "专业基础知识", "type": "bool", "stem": "公司、企业中不具有国家工作人员身份的人与国家工作人员勾结，分别利用各自的职务便利，共同将本单位财物非法占为己有的，按照主犯的犯罪性质定罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据最高人民法院《关于审理贪污、职务侵占案件如何认定共同犯罪几个问题的解释》第3条规定，公司、企业中不具有国家工作人员身份的人与国家工作人员勾结，分别利用各自的职务便利，共同将本单位财物非法占为己有的，按照主犯的犯罪性质定罪。故该说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1399}, {"num": 1401, "batch": "专业基础知识", "type": "bool", "stem": "个人为进行违法犯罪活动而设立的公司、企业、事业单位实施犯罪的，或者公司、企业、事业单位设立后，以实施犯罪为主要活动的，不以单位犯罪论处。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《最高人民法院关于审理单位犯罪案件具体应用法律有关问题的解释》第2条规定，个人为进行违法犯罪活动而设立的公司、企业、事业单位实施犯罪的，或者公司、企业、事业单位设立后，以实施犯罪为主要活动的，不以单位犯罪论处，应以自然人犯罪追究刑事责任。本题表述与司法解释一致，说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1400}, {"num": 1402, "batch": "专业基础知识", "type": "bool", "stem": "黄某系某公司财务会计，因职务侵占罪被判处有期徒刑4年，人民法院可以禁止其终身不得从事财务会计的相关工作。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《刑法》第37条之一规定，因利用职业便利实施犯罪的，人民法院可以决定禁止其自刑罚执行完毕之日或者假释之日起从事相关职业，期限为三年至五年。禁止令有期限限制，不能终身禁止。本题称'终身不得从事财务会计相关工作'，说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1401}, {"num": 1403, "batch": "专业基础知识", "type": "bool", "stem": "李某被判处死刑缓期执行期间故意犯罪，虽然情节较轻，但仍应当报请最高人民法院核准后对其执行死刑。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《刑法》第50条规定，判处死刑缓期执行的，在死刑缓期执行期间，如果故意犯罪，情节恶劣的，报请最高人民法院核准后执行死刑。题目中'虽然情节较轻'，不符合'情节恶劣'的条件，不应报请核准执行死刑。本题表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1402}, {"num": 1404, "batch": "专业基础知识", "type": "bool", "stem": "甲因涉嫌抢夺被判处7年有期徒刑，附加剥夺政治权利2年。其在主刑执行4年时被假释，假释期限为3年，对甲剥夺政治权利的刑期应从假释期满之日起算。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《刑法》第58条规定，附加剥夺政治权利的刑期，从徒刑、拘役执行完毕之日或者从假释之日起计算。因此，对甲剥夺政治权利的刑期应从假释之日起算，而非从假释期满之日起算。本题表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1403}, {"num": 1405, "batch": "专业基础知识", "type": "bool", "stem": "李某与王某有仇，遂伺机报复。一日，李某得知王某一人在家，便携带匕首向王某家走去，刚到王某家门口突然腹痛难忍，只得返回家中，李某的行为属于犯罪未遂，可以比照既遂犯从轻或者减轻处罚。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《刑法》第22条和第23条的规定，犯罪预备是在准备阶段因意志以外原因未能着手实行犯罪；犯罪未遂是已经着手实行犯罪后由于意志以外原因未得逞。李某刚到王某家门口，尚未着手实行杀人行为，属于犯罪预备而非犯罪未遂。本题表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1404}, {"num": 1406, "batch": "专业基础知识", "type": "bool", "stem": "李某购买伪造的增值税专用发票后又出售,对其应按出售伪造的增值税专用发票罪定罪处罚。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据最高人民法院相关司法解释，购买伪造的增值税专用发票后又出售的，应以出售伪造的增值税专用发票罪一罪定罪处罚，不实行数罪并罚。购买行为被出售行为所吸收，本题表述正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1405}, {"num": 1407, "batch": "专业基础知识", "type": "bool", "stem": "李某伪造了面额5000元的国库券，其行为构成伪造有价票证罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《刑法》第178条规定，伪造国库券或者国家发行的其他有价证券的，构成伪造有价证券罪。国库券属于有价证券而非有价票证，有价票证是指车票、船票、邮票等。因此李某的行为应构成伪造有价证券罪，而非伪造有价票证罪。本题表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1406}, {"num": 1408, "batch": "专业基础知识", "type": "bool", "stem": "李某用147万余元买入S股票5万股。不久，S股价连续下跌，李某为挽回损失，以内部传真的形式，向某报的编辑部等发出传真稿，谎称“B公司”已收购S股票。某报原文刊登了李某编造的虚假信息。第二天，S股票价格异常波动，李某在S股票上涨后，抛售S股票，营利200万余元。对李某应当以涉嫌编造并传播证券交易虚假信息罪立案追诉。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《刑法》第181条第1款规定，编造并且传播影响证券交易的虚假信息，扰乱证券交易市场，造成严重后果的，构成编造并传播证券交易虚假信息罪。李某编造虚假收购信息并通过媒体传播，导致股价异常波动并获利200万余元，符合该罪构成要件。本题表述正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1407}, {"num": 1409, "batch": "专业基础知识", "type": "bool", "stem": "王某是某证券公司的工作人员，持有某上市科技公司的大量股票。为了达到获利目的，王某利用其证券从业人员的身份，在网上发帖，将该上市公司开发的被专家估值100万美元的网络应用程序，故意错写为100亿美元，造成该公司股票交易价格和交易量异常波动，给股民造成巨大损失。王某构成编造并传播证券交易虚假信息罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《刑法》第181条第1款规定，编造并传播影响证券交易的虚假信息，扰乱证券交易市场，造成严重后果的，构成编造并传播证券交易虚假信息罪。王某故意将软件估值夸大1000倍并在网上发帖传播，造成股票交易异常波动和股民巨大损失，符合该罪构成要件。本题表述正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1408}, {"num": 1410, "batch": "专业基础知识", "type": "bool", "stem": "朱某、张某与殷某密谋后，由殷某以交通银行某分行的名义为朱某、张某属下企业开出14份虚假的《信托（委托）存款合同》，共计100万元，殷某从中收取手续费，后朱某、张某用该14份《信托（委托）存款合同》作质押，到某开发区城市信用社申请贷款100万元。因企业经营不善，贷款到期后不能收回，给金融机构造成了巨大的经济损失。对三人的行为应当以违规出具金融票证罪立案追诉。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《刑法》第188条规定，银行或者其他金融机构的工作人员违反规定，为他人出具信用证或者其他保函、票据、存单、资信证明，造成较大损失的，构成违规出具金融票证罪。殷某以银行名义开具虚假存款合同，朱某、张某利用该虚假合同质押贷款造成重大损失，应以违规出具金融票证罪追诉。本题表述正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1409}, {"num": 1411, "batch": "专业基础知识", "type": "bool", "stem": "甲对外宣传获得市政府重点工程的承包权需要资金进行施工，向社会公众募集资金1000万元，集资后甲即携款潜逃。甲的行为构成诈骗罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "甲以非法占有为目的，虚构承包工程的事实向社会公众募集资金后携款潜逃，其行为本质是以集资为名骗取财物。根据《刑法》第192条及相关司法解释，以非法占有为目的使用诈骗方法非法集资的，构成集资诈骗罪，而非普通诈骗罪。本题表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1410}, {"num": 1412, "batch": "专业基础知识", "type": "bool", "stem": "某省彩票管理中心主任李某在担任财信总公司法人代表、总经理期间，采取签订虚假进口货物合同及内销合同等方法，在省工行开出不可撤销的信用证18单，骗取省工行信用证款共计5300多万美元，造成省工行实际损失4100多万美元，折合人民币3.4亿多元。李某的行为构成信用证诈骗罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《刑法》第195条规定，有下列情形之一进行信用证诈骗活动的，构成信用证诈骗罪，其中包括骗取信用证的。李某采取签订虚假合同的方式骗取银行开出信用证，造成巨额损失，符合信用证诈骗罪的构成要件。本题表述正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1411}, {"num": 1413, "batch": "专业基础知识", "type": "bool", "stem": "任某（本市某大型商场工作人员，负责该商场发行的购物券销售工作）伙同其丈夫郝某、其弟任某某（二人均系无业人员），经预谋后由任某某联系印刷厂印制了3000张该商场假购物券（每张可以在该商场购买100元的商品），然后由任某将该商场公章偷盖在假购物券上对外进行销售，其中一部分交给郝某、任某某在商场购物。后商场收银中心发现有顾客使用假购物券购物，遂案发。此时任某已出售和使用假购物券获利14万余元。任某的行为构成有价证券诈骗罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "商场购物券不属于《刑法》规定的有价证券范畴，有价证券是指国库券、公司债券、股票等国家或企业发行的有价证券。任某伪造并使用商场购物券获利的行为，应构成诈骗罪而非有价证券诈骗罪。本题表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1412}, {"num": 1414, "batch": "专业基础知识", "type": "bool", "stem": "甲与乙有过节。一日，甲趁乙家中无人，用一自制的爆炸装置将乙停放在自家院中的轿车炸毁。乙的房屋周边没有其他人与物。甲的行为构成爆炸罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "爆炸罪属于危害公共安全罪，要求行为危害或足以危害不特定多数人的生命、健康或重大公私财产安全。甲炸毁乙的轿车，且乙的房屋周边没有其他人与物，不危害公共安全，应构成故意毁坏财物罪而非爆炸罪。本题表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1413}, {"num": 1415, "batch": "专业基础知识", "type": "bool", "stem": "王某非法购买增值税专用发票又虚开的，对其应按虚开增值税专用发票罪定罪处罚。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据最高人民法院相关司法解释，非法购买增值税专用发票又虚开的，应以虚开增值税专用发票罪一罪定罪处罚。购买行为被虚开行为所吸收，不实行数罪并罚。本题表述正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1414}, {"num": 1416, "batch": "专业基础知识", "type": "bool", "stem": "甲公司拥有某项独家技术，每年为公司带来数百万元利润，故对该技术严加保密。乙公司经理丙为获得该技术，带人将甲公司技术员丁强行拦截并推入丙的汽车，对丁说如果他提供该技术资料就给他2万元，如果不提供就将他嫖娼之事公之于众。丁同意配合。次日丁向丙提供了该技术资料，并获得2万元报酬。丙的行为构成强迫交易罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "丙以揭发隐私相威胁，强行获取甲公司的独家技术（商业秘密），其行为应构成侵犯商业秘密罪，即以胁迫手段获取权利人的商业秘密。强迫交易罪是指在商品交易中强迫他人买卖商品或接受服务，本案不属于商品交易行为。本题表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1415}, {"num": 1417, "batch": "专业基础知识", "type": "bool", "stem": "张某到甲的加盟店欲批发1万元调味品，见甲态度不好就表示不买了。甲对张某拳打脚踢，并说：“涨价2000元，不付款休想走。”张某无奈付款1.2万元买下调味品。甲的行为构成强迫交易罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《刑法》第226条规定，以暴力、威胁手段强买强卖商品，强迫他人提供服务或者强迫他人接受服务，情节严重的，构成强迫交易罪。甲对张某拳打脚踢，以暴力手段强迫张某以涨价后的价格购买调味品，符合强迫交易罪的构成要件。本题表述正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1416}, {"num": 1418, "batch": "专业基础知识", "type": "bool", "stem": "甲承担资产评估职责，非法收受他人财物后，故意提供虚假证明文件。甲的行为构成非国家工作人员受贿罪与提供虚假证明文件罪，应实行数罪并罚。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《刑法》第229条第2款规定，承担资产评估等职责的中介组织人员，索取他人财物或者非法收受他人财物，故意提供虚假证明文件的，依照处罚较重的规定定罪处罚，即从一重罪处罚，不实行数罪并罚。本题称应数罪并罚，表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1417}, {"num": 1419, "batch": "专业基础知识", "type": "bool", "stem": "因乙移情别恋，甲将硫酸倒入水杯带到学校欲报复乙。课间，甲、乙激烈争吵，甲欲以硫酸泼乙，但情急之下未能拧开杯盖，后甲因追乙离开教室。丙到教室，误将甲的水杯当作自己的杯子，拧开杯盖时硫酸淋洒一身，灼成重伤。对丙的重伤，甲构成过失致人重伤罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "甲将硫酸带入学校，应当预见到可能被他人误拿使用，但未妥善保管也未设置警示标志，对丙的重伤存在疏忽大意的过失。甲主观上对乙有故意但未能实施，对丙则属于应当预见而未预见的过失，构成过失致人重伤罪。本题表述正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1418}, {"num": 1420, "batch": "专业基础知识", "type": "bool", "stem": "甲抢夺乙的财物，尚未构成抢夺罪，但为抗拒抓捕造成乙重伤，对甲以抢劫罪定罪处罚。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《刑法》第269条规定，犯盗窃、诈骗、抢夺罪，为窝藏赃物、抗拒抓捕或者毁灭罪证而当场使用暴力或者以暴力相威胁的，依照抢劫罪定罪处罚。根据司法解释，虽然抢夺行为尚未达到数额较大标准不构成抢夺罪，但为抗拒抓捕使用暴力致人重伤的，可以转化为抢劫罪。本题表述正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1419}, {"num": 1421, "batch": "专业基础知识", "type": "bool", "stem": "行为人明知其驾驶车辆强行夺取他人财物的手段会造成他人伤亡的后果，仍然驾驶车辆强行夺取并放任造成财物持有人重伤的后果，依照抢夺罪、过失致人重伤罪数罪并罚。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据最高人民法院《关于审理抢夺刑事案件具体应用法律若干问题的解释》，驾驶车辆强行夺取他人财物，明知会造成他人伤亡后果而放任的，应以抢劫罪定罪处罚，而非以抢夺罪和过失致人重伤罪数罪并罚。本题表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1420}, {"num": 1422, "batch": "专业基础知识", "type": "bool", "stem": "甲为勒索财物绑架并杀害被害人乙，应当以绑架罪和故意杀人罪数罪并罚。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《刑法》第239条规定，以勒索财物为目的绑架他人的，杀害被绑架人的，处死刑，并处没收财产。即绑架并杀害被害人的，以绑架罪一罪论处，属于绑架罪的加重情节，不实行数罪并罚。本题表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1421}, {"num": 1423, "batch": "专业基础知识", "type": "bool", "stem": "吴某家保姆甲在将吴某之子（3岁）从幼儿园接出后带到外地藏匿，向吴某打电话索要赎金50万元，在双方约定的交易地点交易时被埋伏的警察当场抓获。甲未拿到赎金，其行为构成绑架罪的未遂。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "绑架罪以实际控制被害人作为既遂标准，而非以取得赎金为标准。甲已将吴某之子从幼儿园接出并带到外地藏匿，已实际控制了被害人，构成绑架罪既遂。未拿到赎金不影响既遂的成立。本题表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1422}, {"num": 1424, "batch": "专业基础知识", "type": "bool", "stem": "甲婚后无子，遂偷盗一婴儿养在家里。甲的行为构成绑架罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "绑架罪要求以勒索财物或满足其他不法要求为目的。甲偷盗婴儿的目的是自己抚养，不具有勒索财物或提出其他不法要求的目的，不构成绑架罪。甲的行为应构成拐骗儿童罪。本题表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1423}, {"num": 1425, "batch": "专业基础知识", "type": "bool", "stem": "某机床厂欠缴应纳税款，其采取转移或者隐匿财产的手段，致使税务机关无法追缴欠缴的税款，对其应以抗税罪定罪处罚。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《刑法》第203条规定，纳税人欠缴应纳税款，采取转移或者隐匿财产的手段，致使税务机关无法追缴欠缴的税款的，构成逃避追缴欠税罪。抗税罪是指以暴力、威胁方法拒不缴纳税款的行为。本题中机床厂未使用暴力、威胁方法，应构成逃避追缴欠税罪而非抗税罪。本题表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1424}, {"num": 1426, "batch": "专业基础知识", "type": "bool", "stem": "刘某出于好玩，多次在公共场所穿着宣扬极端主义的服饰，根据《刑法》的规定，刘某的行为涉嫌犯罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《刑法》第120条之五规定，强制他人在公共场所穿戴宣扬恐怖主义、极端主义的服饰、标志的，构成犯罪。刘某系自己穿着，并非'强制他人'穿戴，不符合该罪构成要件。同时，单纯穿着行为也不属于宣扬行为，不构成宣扬恐怖主义、极端主义罪。本题表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1425}, {"num": 1427, "batch": "专业基础知识", "type": "bool", "stem": "甲以出卖为目的收买生活贫困的妇女乙后，经乙同意，将其卖给一个富裕人家为妻。甲的行为构成拐卖妇女罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《刑法》第240条规定，以出卖为目的，拐骗、绑架、收买、贩卖、接送、中转妇女的，构成拐卖妇女罪。甲以出卖为目的收买妇女后卖出，即使经乙同意，被害人的同意不影响犯罪成立。本题表述正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1426}, {"num": 1428, "batch": "专业基础知识", "type": "bool", "stem": "王某与李某有仇。一日，王某趁李某不注意，将一包砒霜投入李某的水杯中，李某饮后死亡。王某的行为构成投放危险物质罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "投放危险物质罪要求危害公共安全，即针对不特定多数人的生命健康安全。王某仅针对特定个人李某投毒，不危害公共安全，应构成故意杀人罪而非投放危险物质罪。本题表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1427}, {"num": 1429, "batch": "专业基础知识", "type": "bool", "stem": "马某欲将郭某毒死，便将自家的一瓶1000毫升的“除草剂”放入郭某与乡邻共用的水井中，因“除草剂”失效，郭某与乡邻饮用水后，并无大碍。马某构成故意杀人罪未遂。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "马某向郭某与乡邻共用的水井中投毒，其行为针对的是不特定多数人的生命健康安全，应构成投放危险物质罪（未遂），而非故意杀人罪未遂。虽然因'除草剂'失效未造成后果，但行为性质已危及公共安全。本题表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1428}, {"num": 1430, "batch": "专业基础知识", "type": "bool", "stem": "甲、乙都是做卖早点生意的个体户，甲见乙家的生意比自家红火，就产生报复念头，于是买来“毒鼠强”并偷偷投入乙家的面粉袋里，造成多名顾客在食用乙家出售的早点后死亡。甲的行为构成投放危险物质罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "甲在乙家早点店的面粉中投毒，该早点面向不特定多数顾客，甲的行为危害了不特定多数人的生命健康安全，构成投放危险物质罪。虽然甲主观上可能仅想报复乙，但客观上危及了公共安全。本题表述正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1429}, {"num": 1431, "batch": "专业基础知识", "type": "bool", "stem": "甲是电气设备维修工，负有维修车间电气设备的责任。在其当班期间发现电气设备受损，有引起火灾的危险。但由于对领导不满，故意不予维修，以致引起爆炸起火，损失重大。对甲应以过失爆炸罪论处。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "甲作为电气设备维修工，负有维修义务，其明知有火灾危险而故意不予维修，主观上是故意而非过失。甲以不作为方式实施了危害公共安全的故意犯罪，应构成爆炸罪而非过失爆炸罪。本题表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1430}, {"num": 1432, "batch": "专业基础知识", "type": "bool", "stem": "张某为了搞点名堂使自己出名，向采石场老板索要炸药、雷管遭到拒绝，便持刀威胁，强行从工棚抢走炸药1包、雷管12只及一段导火索，并将以上爆炸物制成定时引爆装置带入某高校食堂，安装在桌椅下引爆，导致师生数人受伤，并造成数万元经济损失。张某的行为构成抢夺爆炸物罪和故意毁坏财物罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "张某持刀威胁强行抢走炸药、雷管，以暴力胁迫手段劫取爆炸物，应构成抢劫爆炸物罪而非抢夺爆炸物罪。其将爆炸物带入高校食堂引爆，危害公共安全，还应构成爆炸罪或投放危险物质罪，应数罪并罚。本题表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1431}, {"num": 1433, "batch": "专业基础知识", "type": "bool", "stem": "王某多次为某恐怖活动组织招募人员，对王某应以资助恐怖活动罪处罚。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《刑法》第120条之一规定，资助恐怖活动罪是指资助恐怖活动组织或实施恐怖活动的行为，资助方式主要是提供经费、物资等。王某为恐怖活动组织招募人员，属于帮助恐怖活动的行为，应构成帮助恐怖活动罪，而非资助恐怖活动罪。本题表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1432}, {"num": 1434, "batch": "专业基础知识", "type": "bool", "stem": "刘某为实施恐怖活动与境外恐怖活动组织进行联络，并为实施恐怖活动进行策划，涉嫌准备实施恐怖活动罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《刑法》第120条之二规定，为实施恐怖活动而进行策划或与境外恐怖活动组织联络的，构成准备实施恐怖活动罪。刘某为实施恐怖活动与境外组织联络并进行策划，符合该罪的构成要件。本题表述正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1433}, {"num": 1435, "batch": "专业基础知识", "type": "bool", "stem": "某大学教授张某多次在大学讲座中宣扬恐怖主义、极端主义，造成恶劣影响，张某涉嫌宣扬恐怖主义、极端主义罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《刑法》第120条之三规定，制作、散布宣扬恐怖主义、极端主义的图书、音频视频资料或者其他物品的，构成宣扬恐怖主义、极端主义罪。张某多次在大学讲座中宣扬恐怖主义、极端主义，造成恶劣影响，符合该罪构成要件。本题表述正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1434}, {"num": 1436, "batch": "专业基础知识", "type": "bool", "stem": "甲在某银行存款3万元，在支取29900元后，存折上尚余100元。甲将存折上的存款额涂改为100100元，到银行取款，因被识破而未能得逞。对甲以变造金融票证罪和金融凭证诈骗罪数罪并罚。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "甲涂改存折金额属于变造金融票证行为，利用变造的存折取款属于金融凭证诈骗行为。二者之间存在手段与目的的牵连关系，属于牵连犯，应从一重罪处罚，而非数罪并罚。本题表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1435}, {"num": 1437, "batch": "专业基础知识", "type": "bool", "stem": "刘某伙同他人在闹市采取暴力方式，强制行人佩戴宣扬恐怖主义、极端主义标志，刘某涉嫌宣扬恐怖主义、极端主义罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《刑法》第120条之五规定，强制他人在公共场所穿戴宣扬恐怖主义、极端主义的服饰、标志的，构成强制穿戴宣扬恐怖主义、极端主义服饰、标志罪。刘某以暴力方式强制行人佩戴相关标志，应构成该罪而非宣扬恐怖主义、极端主义罪。本题表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1436}, {"num": 1438, "batch": "专业基础知识", "type": "bool", "stem": "甲向金融机构贷款时，不是出于转贷牟利的目的，而是出于自用生产、经营的需要，但获取贷款后，因其他原因将该款项高利转贷给了他人，不构成高利转贷罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《刑法》第175条规定，高利转贷罪要求行为人在获取贷款时就具有转贷牟利的目的。甲在获取贷款时出于自用生产经营需要，不具有转贷牟利目的，虽然后来将贷款高利转贷给他人，但因获取贷款时缺乏该罪的主观要件，不构成高利转贷罪。本题表述正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1437}, {"num": 1439, "batch": "专业基础知识", "type": "bool", "stem": "王某明知是宣扬恐怖主义、极端主义的图书、音频视频资料而收藏，情节严重，应对其以非法持有宣扬恐怖主义、极端主义物品罪追究刑事责任。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《刑法》第120条之六规定，明知是宣扬恐怖主义、极端主义的图书、音频视频资料而非法持有，情节严重的，构成非法持有宣扬恐怖主义、极端主义物品罪。王某明知而收藏且情节严重，符合该罪构成要件。本题表述正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1438}, {"num": 1440, "batch": "专业基础知识", "type": "bool", "stem": "张某为了报复社会，将本市正在使用的公用通信线路截断，造成医疗急救通信中断1小时，致使一心梗病人因贻误救助死亡。张某的行为构成破坏公用电信设施罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《刑法》第124条规定，破坏广播电视设施、公用电信设施，危害公共安全的，构成破坏公用电信设施罪。张某截断正在使用的公用通信线路，造成医疗急救通信中断并致人死亡，严重危害公共安全，符合该罪构成要件。本题表述正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1439}, {"num": 1441, "batch": "专业基础知识", "type": "bool", "stem": "王某非法生产仿警用手枪3支卖与他人，其行为构成非法生产、买卖警用装备罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "仿警用手枪属于枪支范畴，非法生产、买卖枪支的行为应构成非法制造、买卖枪支罪（《刑法》第125条），而非非法生产、买卖警用装备罪（《刑法》第281条）。非法生产、买卖警用装备罪针对的是警用标志、制服等装备，不包括枪支。本题表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1440}, {"num": 1442, "batch": "专业基础知识", "type": "bool", "stem": "甲用总面额10万元的假币换取乙的1万元真币。甲的行为构成使用假币罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《刑法》第171条第2款规定，银行或者其他金融机构的工作人员购买伪造的货币或者利用职务上的便利以伪造的货币换取真币的，构成金融机构工作人员购买假币、以假币换取真币罪。甲用假币换取乙的真币，应构成出售假币罪，而非使用假币罪。本题表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1441}, {"num": 1443, "batch": "专业基础知识", "type": "bool", "stem": "甲让不知实情的乙从A地代为运输假币20万元到B地。乙的行为构成运输假币罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "运输假币罪要求行为人明知是假币而运输，即要求主观上具有犯罪故意。乙对假币不知情，缺乏犯罪的主观故意，不构成运输假币罪。甲利用不知情的乙运输假币，甲构成运输假币罪的间接正犯。本题表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1442}, {"num": 1444, "batch": "专业基础知识", "type": "bool", "stem": "甲购买假币后使用，构成犯罪的，以购买假币罪从重处罚。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据最高人民法院《关于审理伪造货币等案件具体应用法律若干问题的解释》，购买假币后使用的，以购买假币罪定罪从重处罚。使用行为被购买行为所吸收，不另行定罪。本题表述正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1443}, {"num": 1445, "batch": "专业基础知识", "type": "bool", "stem": "甲因出售假币构成犯罪，同时有使用假币行为的，对甲依法实行数罪并罚。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据最高人民法院相关司法解释，出售假币构成犯罪，同时有使用假币行为的，应当以出售假币罪和使用假币罪实行数罪并罚。因为出售和使用是两种不同的行为，侵犯不同的法益，不属于吸收关系。本题表述正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1444}, {"num": 1446, "batch": "专业基础知识", "type": "bool", "stem": "甲在与他人签订合同时，为显示自己的经济实力，将总面额20万元的假币冒充真币出示给对方看。甲的行为构成使用假币罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "使用假币是指将假币作为真币投入流通领域的行为。甲将假币出示给对方看，仅是展示以显示经济实力，并未将假币投入流通，不属于'使用'假币的行为，不构成使用假币罪。本题表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1445}, {"num": 1447, "batch": "专业基础知识", "type": "bool", "stem": "甲将10万元假币当做合同保证金提供给乙。甲的行为构成诈骗罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "甲将假币作为合同保证金提供给乙，是将假币作为真币投入流通领域使用，应构成使用假币罪而非诈骗罪。使用假币罪本身就包含了一定的欺骗性质，属于特殊法条，应优先适用。本题表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1446}, {"num": 1448, "batch": "专业基础知识", "type": "bool", "stem": "犯罪分子甲潜入某机关大院宿舍楼四楼，在乙家门口放火，意欲烧死乙，乙刚好外出。大火烧起后，被住在本楼的其他人员发现，将火扑灭。甲的放火行为只造成乙家的大门损坏。甲的行为构成故意杀人罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "甲在机关大院宿舍楼放火，宿舍楼属于多人居住的场所，放火行为足以危害不特定多数人的生命和财产安全，应构成放火罪而非故意杀人罪。虽然甲主观目的是烧死乙，但其手段行为危害了公共安全，应以放火罪论处。本题表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1447}, {"num": 1449, "batch": "专业基础知识", "type": "bool", "stem": "王某利用极端主义胁迫多名群众破坏《反恐怖主义法》的实施，王某涉嫌宣扬极端主义、煽动实施恐怖活动罪。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《刑法》第120条之四规定，利用极端主义煽动、胁迫群众破坏国家法律确立的婚姻、司法、教育、社会管理等制度实施的，构成利用极端主义破坏法律实施罪。王某利用极端主义胁迫群众破坏法律实施，应构成该罪而非宣扬极端主义、煽动实施恐怖活动罪。本题表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1448}, {"num": 1450, "batch": "专业基础知识", "type": "bool", "stem": "某县公安局规定刑警大队副大队长的任职条件为高中以上学历。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《人民警察法》第26条规定，担任人民警察领导职务的人员，应当具备大专以上文化程度。县公安局规定刑警大队副大队长任职条件为高中以上学历，低于法定要求，不符合法律规定。本题表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1449}, {"num": 1451, "batch": "专业基础知识", "type": "bool", "stem": "某县出租车司机500多人因经营权纠纷开车聚集在该县主干道上造成大规模拥堵，严重危害社会治安秩序，县公安局经市公安局和县人民政府批准，可以采取现场管制措施。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《人民警察法》第17条规定，县级以上人民政府公安机关，经上级公安机关和同级人民政府批准，对严重危害社会治安秩序的突发事件，可以根据情况实行现场管制。出租车司机聚集造成大规模拥堵，县公安局经市公安局和县人民政府批准，可以采取现场管制措施。本题表述正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1450}, {"num": 1452, "batch": "专业基础知识", "type": "bool", "stem": "甲县公安局民警刘某刑讯逼供，情节严重，经甲县公安局局长批准，可以对其采取停止执行职务的措施。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《公安机关督察条例》第12条规定，公安机关人民警察有刑讯逼供、体罚虐待被监管人等行为，情节严重的，经本级公安机关督察长（即公安局长）批准，可以对其采取停止执行职务的措施。本题表述正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1451}, {"num": 1453, "batch": "专业基础知识", "type": "bool", "stem": "甲县拆迁户围堵县政府,并欲冲进政府大楼，县公安局根据情况可以决定实行现场管制。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《人民警察法》第17条规定，实行现场管制须经上级公安机关和同级人民政府批准。县公安局不能自行决定实行现场管制，必须经上级公安机关和县人民政府批准。本题称'县公安局根据情况可以决定实行现场管制'，缺少审批程序，表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1452}, {"num": 1454, "batch": "专业基础知识", "type": "bool", "stem": "小张驾驶机动车未悬挂机动车号牌，A市交警大队将其车辆扣留。后小张提供了合法证明，A市交警大队直接将车辆退还小张。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《道路交通安全法》第95条规定，未悬挂机动车号牌的，公安机关交通管理部门应当扣留机动车。当事人提供相应的合法证明或者补办相应手续的，应当及时退还机动车。小张提供合法证明后，交警大队直接退还车辆符合法律规定。本题表述正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1453}, {"num": 1455, "batch": "专业基础知识", "type": "bool", "stem": "小张将车辆违法停放在人行道上，A市交警大队将该车辆进行了拖移，但后来发现机动车因拖移损坏，A市交警大队应当依法承担补偿责任。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《道路交通安全法》第93条第3款规定，因采取不正确的方法拖移机动车造成车辆损坏的，公安机关交通管理部门应当依法承担补偿责任。本题表述与法律规定一致，说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1454}, {"num": 1456, "batch": "专业基础知识", "type": "bool", "stem": "张某自驾游期间，因不熟悉道路违法临时停车，但未影响道路通行，执勤交警小温认定该违法行为情节轻微，指出违法行为，给予口头警告后放行。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《道路交通安全法》第87条第2款规定，对于情节轻微、未影响道路通行的违法行为，公安机关交通管理部门及其交通警察应当指出违法行为，给予口头警告后放行。小张因不熟悉道路违法临时停车且未影响通行，执勤交警给予口头警告后放行符合法律规定。本题表述正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1455}, {"num": 1457, "batch": "专业基础知识", "type": "bool", "stem": "达到报废标准的机动车不得上道路行驶。报废的大型客、货车及其他营运车辆应当在公安机关交通管理部门的监督下解体。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《道路交通安全法》第14条规定，达到报废标准的机动车不得上道路行驶。报废的大型客、货车及其他营运车辆应当在公安机关交通管理部门的监督下解体。本题表述与法律规定完全一致，说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1456}, {"num": 1458, "batch": "专业基础知识", "type": "bool", "stem": "根据《道路交通安全法》的规定，机动车进厂大修的，应当到公安机关交通管理部门办理相应登记。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《道路交通安全法》及相关规定，机动车需要办理变更登记的情形包括：改变车身颜色、更换发动机、更换车身或车架等，但不包括进厂大修。机动车进厂大修不需要到公安机关交通管理部门办理登记。本题表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1457}, {"num": 1459, "batch": "专业基础知识", "type": "bool", "stem": "贾某因饮酒后驾驶机动车被处罚，之后再次饮酒后在甲市乙区驾驶机动车被查获。对贾某再次饮酒后驾驶机动车的违法行为，应当由甲市公安机关交通管理部门作出行政拘留、罚款和吊销机动车驾驶证的处罚决定。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《道路交通安全法》第91条和《道路交通安全违法行为处理程序规定》，再次饮酒后驾驶机动车的，处十日以下拘留、并处罚款和吊销驾驶证。处罚应由违法行为发生地的县级以上公安机关交通管理部门作出，即应由甲市乙区公安机关交通管理部门作出，而非笼统由'甲市公安机关交通管理部门'作出。本题表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1458}, {"num": 1460, "batch": "专业基础知识", "type": "bool", "stem": "刘某年满16周岁后，其应当在30日内向常住户口所在地的公安机关申请领取居民身份证。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《居民身份证法》第5条规定，年满十六周岁的公民，应当自年满十六周岁之日起三个月内，向常住户口所在地的公安机关申请领取居民身份证。题目称'30日内'，与法定的'三个月内'不符。本题表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1459}, {"num": 1461, "batch": "专业基础知识", "type": "bool", "stem": "甲市公安局在处置打砸百货公司群体性事件中，为防止违法犯罪嫌疑人脱逃，扣押了百货公司内的所有人员的身份证，待查明人员身份后再甄别返还。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《居民身份证法》第15条第3款规定，任何组织或者个人不得扣押居民身份证，但公安机关依照《刑事诉讼法》执行监视居住强制措施的情形除外。公安局扣押百货公司所有人员身份证的做法没有法律依据，属于违法行为。本题表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1460}, {"num": 1462, "batch": "专业基础知识", "type": "bool", "stem": "小孙到学校图书馆还书，管理员王某发现图书有损坏，要求小孙赔偿，小孙未带现金，王某便扣押了小孙的居民身份证，让其拿赔偿金来换。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《居民身份证法》第15条第3款规定，除公安机关依照法律规定执行特定强制措施外，任何组织或者个人不得扣押居民身份证。图书管理员王某无权扣押小孙的居民身份证，其行为违法。本题表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1461}, {"num": 1463, "batch": "专业基础知识", "type": "bool", "stem": "电信公司工作人员刘某在给公民王某办理业务时留存了王某的居民身份证复印件，后来刘某觉得王某的名字很搞笑，便把王某的居民身份证复印件传到了网上，给王某造成了不良影响。对刘某的行为应当给予处分。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《居民身份证法》第19条规定，有关单位及其工作人员对在履行职责或者提供服务过程中获得的居民身份证记载的公民个人信息，应当予以保密，不得向他人泄露。刘某泄露公民个人信息给王某造成不良影响，应当依法给予处分。但本题说法为'正确'而答案标注为'错误'，可能因为处分的主体和程序表述不够准确，或刘某的行为已涉嫌犯罪应追究刑事责任而非仅给予处分。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1462}, {"num": 1464, "batch": "专业基础知识", "type": "bool", "stem": "民警小张利用职务便利，协助李四制作假居民身份证进行诈骗，李四诈骗获取10万元违法所得，并分给小张1万元。公安机关应依法给予小张行政处罚。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "民警小张利用职务便利协助制作假居民身份证并进行诈骗，其行为已涉嫌伪造居民身份证罪和诈骗罪的共犯，应当依法追究刑事责任，而非仅给予行政处罚。本题称'应依法给予小张行政处罚'，降低了处理层级，表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1463}, {"num": 1465, "batch": "专业基础知识", "type": "bool", "stem": "张某被县人民检察院决定刑事拘留，交由县公安局执行。后经调查证明拘留错误，应以县公安局为赔偿义务机关。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《国家赔偿法》第21条第1款规定，行使侦查、检察、审判职权的机关以及看守所、监狱管理机关及其工作人员在行使职权时侵犯公民合法权益造成损害的，该机关为赔偿义务机关。本案中刑事拘留由县人民检察院决定，赔偿义务机关应为作出拘留决定的县人民检察院，而非执行拘留的县公安局。本题表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1464}, {"num": 1466, "batch": "专业基础知识", "type": "bool", "stem": "赔偿义务机关赔偿损失后，应当责令其工作人员或者受委托的组织或者个人承担部分或者全部赔偿费用。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《国家赔偿法》第16条规定，赔偿义务机关赔偿损失后，应当责令有故意或者重大过失的工作人员或者受委托的组织或者个人承担部分或者全部赔偿费用。即追偿的前提是工作人员存在故意或重大过失，并非所有情况都应当追偿。本题表述过于绝对，缺少'故意或重大过失'的前提条件，说法错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1465}, {"num": 1467, "batch": "专业基础知识", "type": "bool", "stem": "A市B区公安分局对吕某作出行政拘留5日的处罚决定。行政拘留执行完毕后，吕某申请复议。A市公安局维持了处罚决定，吕某向B区人民法院起诉，B区人民法院撤销了处罚决定。B区公安分局未上诉。本案中的赔偿义务机关是A市公安局。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《国家赔偿法》及相关司法解释，经复议机关维持原行政行为的，作出原行政行为的行政机关为赔偿义务机关。本案中，区公安分局作出行政拘留决定，市公安局复议维持，区公安分局未上诉，法院撤销处罚决定后，赔偿义务机关应为作出原决定的B区公安分局，而非A市公安局。本题表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1466}, {"num": 1468, "batch": "专业基础知识", "type": "bool", "stem": "两个以上行政机关共同行使行政职权时，侵犯公民、法人和其他组织的合法权益造成损害的，共同行使行政职权的行政机关为共同赔偿义务机关。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《国家赔偿法》第7条第2款规定，两个以上行政机关共同行使行政职权时侵犯公民、法人和其他组织的合法权益造成损害的，共同行使行政职权的行政机关为共同赔偿义务机关。本题表述与法律规定一致，说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1467}, {"num": 1469, "batch": "专业基础知识", "type": "bool", "stem": "按照A市政府的部署，A市公安局、工商局与文化局三家单位联合对文化市场进行清理整顿。在检查到陈某经营的个体书摊时，发现其正在出售宣扬暴力的影碟，执法人员当场扣押了这些影碟。文化局吊销了陈某的音像制品经营许可证，工商局吊销了陈某的个体营业执照。如吊销音像制品经营许可证的行为对陈某的合法权益造成了损害，陈某可以向市公安局提出赔偿请求。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据国家赔偿法的相关规定，赔偿义务机关应是作出侵权行为的行政机关。本案中吊销音像制品经营许可证的行为由文化局作出，市公安局并未参与该具体行政行为，陈某应向文化局提出赔偿请求，而非向市公安局提出。本题表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1468}, {"num": 1470, "batch": "专业基础知识", "type": "bool", "stem": "涉嫌吸食毒品的郑某为逃避处罚，在被公安机关送往羁押场所的途中，趁民警不备，偷偷将车内遗落在座椅上的一只圆珠笔吞下，造成胃穿孔。公安机关不应当承担国家赔偿责任。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《国家赔偿法》第19条规定，因公民、法人和其他组织自己的行为致使损害发生的，国家不承担赔偿责任。郑某偷偷将圆珠笔吞下造成胃穿孔，属于自身故意行为导致的损害，与公安机关的执法行为无因果关系，公安机关不承担国家赔偿责任。本题表述正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1469}, {"num": 1471, "batch": "专业基础知识", "type": "bool", "stem": "小王吸毒成瘾严重，由于正在怀孕期，对小王不适用强制隔离戒毒，但应依法进行社区戒毒。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《禁毒法》第39条规定，怀孕或者正在哺乳自己婴儿的妇女，不适用强制隔离戒毒。但吸毒成瘾的，应当依法进行社区戒毒。小王正处于怀孕期，不适用强制隔离戒毒，但应依法进行社区戒毒。本题表述正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1470}, {"num": 1472, "batch": "专业基础知识", "type": "bool", "stem": "李某吸毒成瘾，最终无钱购买毒品，自行到具有戒毒治疗资质的医疗机构接受戒毒治疗，后被公安机关发现。公安机关应当对其予以行政处罚。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《禁毒法》第36条规定，吸毒成瘾人员可以自行到具有戒毒治疗资质的医疗机构接受戒毒治疗。对自愿接受戒毒治疗的吸毒人员，公安机关对其原吸毒行为不予处罚。李某自行到医疗机构接受戒毒治疗，公安机关不应予以行政处罚。本题表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1471}, {"num": 1473, "batch": "专业基础知识", "type": "bool", "stem": "组团社应当为旅游团队安排专职领队，领队应当佩戴领队证。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《旅游法》及相关规定，组团社应当为旅游团队安排专职领队，领队应当经考核取得领队证并佩戴领队证从事领队活动。本题表述与法律规定一致，说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1472}, {"num": 1474, "batch": "专业基础知识", "type": "bool", "stem": "在执行边防检查任务时，执法人员登上外国船舶执行公务应当着制服或出示证件。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《出境入境管理法》及相关规定，在执行边防检查任务时，执法人员登上外国船舶执行公务应当着制服并出示证件，二者缺一不可。题目称'着制服或出示证件'，将并列关系变为选择关系，降低了法定要求。本题表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1473}, {"num": 1475, "batch": "专业基础知识", "type": "bool", "stem": "某赴台旅游团成员张某因紧急情况不能随团按期返回大陆，组团社应及时向有关出入境边防检查总站或省级公安边防部门报告。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据赴台旅游相关管理规定，赴台旅游团成员因紧急情况不能随团按期返回大陆的，组团社应及时向有关出入境边防检查总站或省级公安边防部门报告，以便妥善处理后续事宜。本题表述正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1474}, {"num": 1476, "batch": "专业基础知识", "type": "bool", "stem": "“出境、入境的交通运输工具”，是指一切离开、进入或者通过中华人民共和国国（边）境的船舶、航空器、火车和机动车辆、非机动车辆。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《出境入境管理法》的规定，出境、入境的交通运输工具是指离开、进入或者通过中华人民共和国国（边）境的船舶、航空器、火车和机动车辆，不包括非机动车辆。本题将非机动车辆也纳入定义范围，表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1475}, {"num": 1477, "batch": "专业基础知识", "type": "bool", "stem": "抵达中华人民共和国口岸的船舶的外国籍船员及其随行家属和香港、澳门、台湾船员及其随行家属，要求在港口城市登陆、住宿的，由其本人向边防检查站申请办理登陆、住宿手续。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据相关规定，抵达中国口岸的船舶的外国籍船员等要求登陆、住宿的，应由船长或其代理人向边防检查站申请办理登陆、住宿手续，而非由船员本人直接申请。本题表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1476}, {"num": 1478, "batch": "专业基础知识", "type": "bool", "stem": "经批准登陆、住宿的外国籍船员及其随行家属，必须按照规定的时间返回船舶。登陆后有违法行为，尚未构成犯罪的，由当地公安机关给予罚款、拘留等治安处罚。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据相关规定，经批准登陆、住宿的外国籍船员必须按照规定时间返回船舶。登陆后有违法行为尚未构成犯罪的，应由边防检查站或当地公安机关依照出入境管理相关法律法规处理，而非直接适用治安管理处罚法给予治安处罚。本题表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1477}, {"num": 1479, "batch": "专业基础知识", "type": "bool", "stem": "甲系台湾人，持就业类居留许可。其已在某高新技术企业任副总经理职务满5年，可以申请永久居留。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "台湾居民属于中国公民，不适用外国人永久居留制度。台湾居民在大陆就业和居留，适用《中国公民往来台湾地区管理办法》等相关规定，而非外国人永久居留的相关规定。本题表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1478}, {"num": 1480, "batch": "专业基础知识", "type": "bool", "stem": "张某，男，美国籍，3年前任北京大学物理系副教授，且至今纳税记录良好。张某可以申请外国人永久居留证。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《外国人在中国永久居留审批管理办法》规定，申请永久居留的外国人需满足较高职务级别（如教授、研究员等正高级专业技术职务）和一定年限等条件。张某任副教授，未达到正高级职称要求，不符合永久居留申请条件。本题表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1479}, {"num": 1481, "batch": "专业基础知识", "type": "bool", "stem": "美籍华人王某可申请在北京成立因私出入境中介机构，并担任公司法定代表人。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据因私出入境中介活动管理的相关规定，因私出入境中介机构的法定代表人应当是具有完全民事行为能力的中国公民。美籍华人王某属于外国国籍，不能在中国担任因私出入境中介机构的法定代表人。本题表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1480}, {"num": 1482, "batch": "专业基础知识", "type": "bool", "stem": "被处罚人对边防检查站作出的处罚决定不服的，自接到处罚决定书之日起15日内，可以向边防检查站所在地的地市州级公安机关申请复议。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《出境入境管理法》第64条规定，对公安机关出入境管理机构作出的处罚决定不服的，可以依法申请行政复议或者提起行政诉讼。边防检查站的复议机关并非地市级公安机关，本题关于复议机关和期限的表述与法律规定不符。本题表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1481}, {"num": 1483, "batch": "专业基础知识", "type": "bool", "stem": "李某，男，加拿大籍，已连续4年在北京师范大学任教授，4年内在中国居留累计不少于3年且纳税记录良好，他和他19周岁的女儿可以一同申请外国人永久居留证。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《外国人在中国永久居留审批管理办法》规定，外国人申请永久居留时，其未满18周岁的未婚子女可以随同申请。李某的女儿已19周岁，已超过随同申请的年龄限制，不能一同申请永久居留证。本题表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1482}, {"num": 1484, "batch": "专业基础知识", "type": "bool", "stem": "叶某，中国公民，因妨害国境管理受到刑事处罚，于2013年4月30日刑满释放，公安机关出入境管理机构在2018年5月1日之前都不能为其签发普通护照。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《护照法》第14条规定，因妨害国境管理受到刑事处罚的，自刑罚执行完毕之日起六个月以内，不予签发普通护照。聂某2013年4月30日刑满释放，限制期至2013年10月30日止，此后即可申请签发护照。本题称'2018年5月1日之前都不能签发'，远超法定限制期限，表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1483}, {"num": 1485, "batch": "专业基础知识", "type": "bool", "stem": "李某女儿在澳大利亚留学，因车祸在医院抢救，李某可以向其户籍所在地县级以上地方人民政府公安机关出入境管理机构申请加急办理普通护照。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《护照法》第6条规定，公民因紧急情况（如境外亲属病危、需要紧急处理等），可以向户籍所在地县级以上地方人民政府公安机关出入境管理机构申请加急办理普通护照。李某女儿因车祸在医院抢救，属于紧急情况，符合加急办理条件。本题表述正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1484}, {"num": 1486, "batch": "专业基础知识", "type": "bool", "stem": "2013年2月10日，王某发现自己所持普通护照有效期将于2013年9月1日到期，同时还发现自己所持护照签证页即将用完，王某最早也只能在2013年2月28日申请换发护照。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《护照法》第11条规定，护照有效期即将到期或者护照签证页即将使用完毕的，持照人可以按照规定申请换发或者补发。法律并未规定必须在特定时间后才能申请换发，王某可以在护照到期前的合理时间内随时申请。本题称'最早也只能在2月28日'缺乏法律依据，表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1485}, {"num": 1487, "batch": "专业基础知识", "type": "bool", "stem": "张某在公安机关出入境管理机构申请换发普通护照时，该机构发现原普通护照上有前往国有效入境许可，可将护照右上角裁去，退还本人。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《护照法》及《普通护照和出入境通行证签发管理办法》的规定，换发新护照时，原护照应当予以剪角注销后退还申请人。但如果原护照上有前往国有效入境许可，不应简单将护照裁去退还，而应做适当处理以保护有效签证信息。本题表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1486}, {"num": 1488, "batch": "专业基础知识", "type": "bool", "stem": "中国公民聂某，申请在云南边境地区从事边境贸易，公安机关可为其签发1年多次出入境有效的出入境通行证。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《出入境通行证签发管理办法》规定，从事边境贸易的中国公民，公安机关可以为其签发1年多次出入境有效的出入境通行证。聂某申请在云南边境地区从事边境贸易，符合签发条件。本题表述正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1487}, {"num": 1489, "batch": "专业基础知识", "type": "bool", "stem": "一出入境中介机构将申请人甲的加拿大投资移民申请委托给了另一未经批准的中介机构办理，公安机关发现后责令其限期整改并处罚款。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据因私出入境中介活动管理的相关规定，中介机构不得将业务委托给未经批准的中介机构办理。违反规定的，公安机关可以责令其限期整改并处罚款。本题中中介机构将申请委托给未经批准的机构，公安机关的处理措施符合法律规定。本题表述正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1488}, {"num": 1490, "batch": "专业基础知识", "type": "bool", "stem": "大陆居民赴台湾旅游团队，只能向其组团社所在地公安机关出入境管理部门申请办理大陆居民往来台湾通行证及其签注。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据大陆居民赴台旅游的相关管理规定，大陆居民可以向户口所在地或居住地的公安机关出入境管理部门申请办理大陆居民往来台湾通行证及签注，并非只能向组团社所在地的公安机关申请办理。本题表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1489}, {"num": 1491, "batch": "专业基础知识", "type": "bool", "stem": "因私出入境中介活动，是指为中国公民出国定居、探亲、访友、继承财产和其他非公务活动提供信息介绍、法律咨询、沟通联系、境外安排、签证申办及相关服务的活动。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《因私出入境中介活动管理办法》第2条规定，因私出入境中介活动是指为中国公民出国定居、探亲、访友、继承财产和其他非公务活动提供信息介绍、法律咨询、沟通联系、境外安排、签证申办及相关服务的活动。本题表述与规定一致，说法正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1490}, {"num": 1492, "batch": "专业基础知识", "type": "bool", "stem": "天津某中介机构法定代表人张某可以在北京从事因私出入境中介活动。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据因私出入境中介活动管理的相关规定，中介机构应当在其注册地所在的行政区域内开展业务活动。天津的中介机构不能跨行政区域在北京从事因私出入境中介活动。本题表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1491}, {"num": 1493, "batch": "专业基础知识", "type": "bool", "stem": "某中介机构变更法定代表人，无须换领经营许可证。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据因私出入境中介活动管理的相关规定，中介机构变更名称、住所、法定代表人等重要事项的，应当向原审批机关办理变更手续并换领经营许可证。因此变更法定代表人需要换领经营许可证。本题表述错误。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1492}, {"num": 1494, "batch": "专业基础知识", "type": "bool", "stem": "大陆居民赴台个人旅游可自行前往台湾地区，在台湾期间可自行活动。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据大陆居民赴台个人旅游的相关政策规定，取得个人旅游签注的大陆居民可以自行前往台湾地区，在台湾期间可自行安排活动，无需跟团。本题表述正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1493}, {"num": 1495, "batch": "专业基础知识", "type": "bool", "stem": "大陆居民赴台湾个人旅游，须向户口所在地的市、县公安机关出入境管理部门申请办理大陆居民往来台湾通行证及相应签注。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据大陆居民赴台旅游的相关管理规定，大陆居民赴台个人旅游须向户口所在地的市、县公安机关出入境管理部门申请办理大陆居民往来台湾通行证及相应个人旅游签注。本题表述正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1494}, {"num": 1496, "batch": "专业基础知识", "type": "bool", "stem": "张某系从事边境贸易的非边境地区公民，其在办理出入境通行证时提交的营业执照应由边境地区工商行政管理部门核发。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据出入境通行证管理的相关规定，从事边境贸易的人员办理出入境通行证时，提交的营业执照应由边境地区工商行政管理部门核发。本题中张某虽为非边境地区公民，但从事边境贸易，其提交的营业执照应由边境地区工商部门核发。本题表述正确。", "tags": "广东辅警笔试 判断题 专业基础知识", "_idx": 1495}, {"num": 1497, "batch": "公共基础知识", "type": "single", "stem": "“超级满月”是月球位于近地点时刚好出现满月，使月亮看起来又大又亮的现象。其发生需要满足的条件是（）", "options": [{"letter": "A", "text": "农历初一前后，地球运动到太阳与月球之间"}, {"letter": "B", "text": "农历初一前后，月球运动到太阳与地球之间"}, {"letter": "C", "text": "农历十五前后，地球运动到太阳与月球之间"}, {"letter": "D", "text": "农历十五前后，月球运动到太阳与地球之间"}], "answer": "C", "explanation": "超级满月即满月出现在月球近地点附近。满月发生在农历十五前后，此时地球位于太阳与月球之间，三者大致排成一条直线，月球被太阳照亮的一面完全朝向地球。选项C正确描述了这一条件。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1496}, {"num": 1498, "batch": "公共基础知识", "type": "single", "stem": "“科学”流言是一种不负责任、未经证实的传闻或谣言，通常以科学为名，但实际缺乏科学依据和实证支持。以下言论中，具有科学依据、不属于“科学”流言的是（）。", "options": [{"letter": "A", "text": "长期只吃白青菜，肝脏会成“油犀”，纯素饮食易致脂肪性肝炎"}, {"letter": "B", "text": "航天员不能有近视眼，因为在太空中戴眼镜可能会带来意外伤害"}, {"letter": "C", "text": "孕妇应尽量穿防辐射服，以有效保护胎儿免受日常电磁辐射影响"}, {"letter": "D", "text": "中国古代木结构建筑不使用一颗钉子，全靠榫卯结构搭建"}], "answer": "A", "explanation": "选项A有科学依据：长期纯素饮食可能导致蛋白质和某些营养素摄入不足，影响肝脏脂肪代谢，增加脂肪性肝炎的风险。选项B错误，近视眼并非航天员的绝对禁忌；选项C错误，日常电磁辐射对人体无害；选项D错误，古代木建筑也会使用钉子等金属构件。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1497}, {"num": 1499, "batch": "公共基础知识", "type": "single", "stem": "“体重管理年”三年行动旨在引导全社会养成重视体重、科学饮食与锻炼的习惯，科学减重，健康生活。关于肥胖对健康的影响，下列说法错误的是（）", "options": [{"letter": "A", "text": "肥胖容易引发胰岛素抵抗，增加患2型糖尿病风险"}, {"letter": "B", "text": "内脏脂肪组织分泌的炎症因子与动脉粥样硬化发展相关"}, {"letter": "C", "text": "肥胖者的排尿次数多，会导致血尿酸水平远低于正常人"}, {"letter": "D", "text": "肥胖引起的气道狭窄可能诱发阻塞性睡眠呼吸暂停"}], "answer": "C", "explanation": "选项C说法错误：肥胖者由于代谢紊乱，嘌呤代谢异常，血尿酸水平通常高于正常人而非远低于正常人。肥胖与高尿酸血症密切相关。选项A、B、D均正确描述了肥胖对健康的影响。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1498}, {"num": 1500, "batch": "公共基础知识", "type": "single", "stem": "“蛰虫惊而出走”，惊蛰是一个和百虫相关的节气，其特点在于“百虫惊醒”。以下对惊蛰时节百虫复苏现象的解释，最符合科学原理的是（）。", "options": [{"letter": "A", "text": "惊蛰前后气温回升加快，土壤温度升高，地下的虫子被气温“热醒”"}, {"letter": "B", "text": "惊蛰前后农民开始深翻土地，准备耕种，地下的虫子被农民“热醒”"}, {"letter": "C", "text": "惊蛰前后春雷轰鸣，响彻天际，地下的虫子被雷声“吵醒”"}, {"letter": "D", "text": "惊蛰前后春雨骤降，水汽充沛，地下的虫子被雨水“泡醒”"}], "answer": "A", "explanation": "惊蛰时节，气温回升加快，土壤温度升高，冬眠的昆虫因感受到温度变化而结束休眠状态开始活动。这是最符合科学原理的解释。选项C将虫子苏醒归因于雷声不准确，选项B和D也不符合昆虫冬眠复苏的科学机制。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1499}, {"num": 1501, "batch": "公共基础知识", "type": "single", "stem": "《汉书》中记载，宣帝作色曰：“汉家自有制度，本以霸王道杂之。奈何纯任德教，用周政乎！且俗儒不达时宜，好是古非今，使人眩於名实，不知所守，何足委任。”下列与之相关的说法正确的是（）", "options": [{"letter": "A", "text": "“宣帝”是某位皇帝的庙号"}, {"letter": "B", "text": "董仲舒是“霸道”的代表人物"}, {"letter": "C", "text": "“周政”主张“无为而治”"}, {"letter": "D", "text": "“文景之治”是“汉家”盛世"}], "answer": "D", "explanation": "汉宣帝所说的'霸王道杂之'是指王道（儒术）与霸道（法家）并用，是汉朝的基本治国方略。A项'宣帝'是谥号而非庙号；B项董仲舒是儒学代表人物，主张'罢黜百家、独尊儒术'，非霸道代表；C项'周政'指西周礼乐制度，非'无为而治'；D项正确，文景之治是汉初著名盛世，符合'汉家'盛世之说。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1500}, {"num": 1502, "batch": "公共基础知识", "type": "single", "stem": "《加强新时代公安派出所工作三年行动计划（2023-2025年）》是深入贯彻落实公安部党委筑牢公安基层基础决策部署、全力推进今后加强派出所工作的重要文件。实施基本能力提升行动，要加强对派出所警情处置、基础管控、（）工作的支持。", "options": [{"letter": "A", "text": "综合指挥"}, {"letter": "B", "text": "案件办理"}, {"letter": "C", "text": "风险防控"}, {"letter": "D", "text": "纠纷化解"}], "answer": "B", "explanation": "根据《加强新时代公安派出所工作三年行动计划（2023-2025年）》，实施基本能力提升行动，要加强对派出所警情处置、基础管控、案件办理工作的支持。案件办理是派出所核心业务之一，属于基本能力建设的重要内容。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1501}, {"num": 1503, "batch": "公共基础知识", "type": "single", "stem": "2023年是共建“一带一路”倡议提出10周年，10年来，共建“一带一路”成为深受欢迎的国际公共产品和最大规模的国际合作平台。下列“一带一路”项目与其合作国家对应有误的是（）。", "options": [{"letter": "A", "text": "雅万高铁项目——印度尼西亚"}, {"letter": "B", "text": "卡拉奇核电项目——巴基斯坦"}, {"letter": "C", "text": "中老铁路项目——老挝"}, {"letter": "D", "text": "中马友谊大桥项目——马来西亚"}], "answer": "D", "explanation": "中马友谊大桥是中国援建马尔代夫的桥梁工程，连接马累岛与机场岛，并非马来西亚的项目。雅万高铁对应印度尼西亚、卡拉奇核电对应巴基斯坦、中老铁路对应老挝，均正确。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1502}, {"num": 1504, "batch": "公共基础知识", "type": "single", "stem": "2023年完成的第三次全国农业种质资源普查，是中华人民共和国成立以来规模最大、覆盖范围最广、技术要求最高、参与人员最多的一次普查。关于农业种质资源，下列说法不正确的是（）", "options": [{"letter": "A", "text": "农业种质资源工作属于社会公益性事业"}, {"letter": "B", "text": "农业种质资源是现代种业发展的物质基础"}, {"letter": "C", "text": "农业种质资源是培育突破性品种的亲本材料"}, {"letter": "D", "text": "农业种质资源的主权由种植者和育种者拥有"}], "answer": "D", "explanation": "根据《中华人民共和国种子法》等相关规定，农业种质资源属于国家所有，其主权由国家拥有，而非由种植者和育种者个人拥有。农业种质资源是现代种业发展的物质基础，是培育突破性品种的亲本材料，相关工作属于社会公益性事业。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1503}, {"num": 1505, "batch": "公共基础知识", "type": "single", "stem": "2024年，中国科技以奋进姿态奏响创新强音，向着科技强国目标迈出更加坚实的步伐。以下有关2024年中国科技成就的表述有误的是（）。", "options": [{"letter": "A", "text": "深海载人潜水器“梦想”号标志我国深海探测关键技术取得重大突破"}, {"letter": "B", "text": "深中通道联通陆海，为粤港澳大湾区协同发展按下“快捷键”"}, {"letter": "C", "text": "南极秦岭站建成并投入使用，开启新时代极地科考新征程"}, {"letter": "D", "text": "嫦娥六号在人类历史上首次实现了月球背面采样返回"}], "answer": "A", "explanation": "'梦想'号是我国自主设计建造的国际首艘深远海大洋钻探船，并非深海载人潜水器。我国深海载人潜水器包括'蛟龙'号、'深海勇士'号和'奋斗者'号。深中通道、南极秦岭站、嫦娥六号月球背面采样返回的表述均正确。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1504}, {"num": 1506, "batch": "公共基础知识", "type": "single", "stem": "2024年4月，中共中央办公厅印发通知，围绕新修订的《中国共产党纪律处分条例》在全党开展（）", "options": [{"letter": "A", "text": "党纪学习教育"}, {"letter": "B", "text": "违纪案例警示教育"}, {"letter": "C", "text": "党风廉政专项整顿"}, {"letter": "D", "text": "党内法规学习教育"}], "answer": "A", "explanation": "2024年4月，中共中央办公厅印发通知，围绕新修订的《中国共产党纪律处分条例》在全党开展党纪学习教育，旨在引导党员干部学纪、知纪、明纪、守纪，这是加强党的纪律建设的重要举措。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1505}, {"num": 1507, "batch": "公共基础知识", "type": "single", "stem": "2024年7月15日至18日，党的二十届三中全会在北京召开。会议提出，高质量发展是全面建设社会主义现代化国家的首要任务。必须以新发展理念引领改革，立足新发展阶段，深化供给侧结构性改革，完善推动高质量发展激励约束机制。依据全会提出高质量发展思路，下列属于需未来五年改革塑造的是（）。", "options": [{"letter": "A", "text": "改革新路径新方向"}, {"letter": "B", "text": "改革新动能新成效"}, {"letter": "C", "text": "发展新动能新优势"}, {"letter": "D", "text": "发展新质量新成果"}], "answer": "C", "explanation": "党的二十届三中全会提出，高质量发展是全面建设社会主义现代化国家的首要任务，必须以新发展理念引领改革，着力塑造'发展新动能新优势'。这是全会明确提出的未来五年改革目标表述。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1506}, {"num": 1508, "batch": "公共基础知识", "type": "single", "stem": "2024年7月16日出版的第14期《求是》杂志发表中共中央总书记、国家主席、中央军委主席习近平的重要文章《必须坚持自信自立》。文章强调，党的百年奋斗成功道路是党领导人民独立自主探索开辟出来的，马克思主义的中国篇章是中国共产党人依靠自身力量实践出来的，贯穿其中的一个基本点就是（）", "options": [{"letter": "A", "text": "必须坚持把马克思主义基本原理与中华优秀传统文化相结合"}, {"letter": "B", "text": "解决中国的问题必须坚持把国家和民族发展放在自己力量的基点上"}, {"letter": "C", "text": "坚持群众路线，密切联系群众，不可脱离群众"}, {"letter": "D", "text": "必须从中国基本国情出发，中国的问题由中国人自己来解答"}], "answer": "D", "explanation": "《必须坚持自信自立》一文强调，贯穿党的百年奋斗的一个基本点就是'必须从中国基本国情出发，中国的问题由中国人自己来解答'。这体现了独立自主探索道路的核心思想，是自信自立的根本要求。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1507}, {"num": 1509, "batch": "公共基础知识", "type": "single", "stem": "2024年7月27日，联合国教科文组织第46届世界遗产大会通过决议，将“北京中轴线——中国理想都城秩序的杰作”成功列入《世界遗产名录》。关于北京中轴线，下列表述不正确的是（）", "options": [{"letter": "A", "text": "属于文化遗产中的建筑群类型"}, {"letter": "B", "text": "是世界上现存最长的城市中轴线"}, {"letter": "C", "text": "是“以中为尊”文化传统的生动实践"}, {"letter": "D", "text": "包含了宋、元、明、清及近现代城市演变的历史积淀"}], "answer": "D", "explanation": "北京中轴线始建于元代，历经元、明、清及近现代，不包含宋代的城市演变积淀。北京中轴线是世界上现存最长的城市中轴线，属于建筑群类型的文化遗产，体现了'以中为尊'的中国传统都城规划理念。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1508}, {"num": 1510, "batch": "公共基础知识", "type": "single", "stem": "2025年10月20日至23日，中国共产党第二十届中央委员会第四次全体会议在北京举行。全会指出，实现社会主义现代化是一个阶梯式递进、不断发展进步的历史过程，需要不懈努力、接续奋斗，“十五五”时期是基本实现社会主义现代化夯实基础、全面发力的关键时期，在基本实现社会主义现代化进程中具有承前启后重要地位。根据全会提出的“十五五”时期经济社会发展必须遵循的原则，推进中国式现代化的根本保证是（）。", "options": [{"letter": "A", "text": "坚持党的全面领导"}, {"letter": "B", "text": "坚持人民至上"}, {"letter": "C", "text": "坚持高质量发展"}, {"letter": "D", "text": "坚持全面深化改革"}], "answer": "A", "explanation": "党的二十届四中全会指出，推进中国式现代化的根本保证是坚持党的全面领导。党的领导是中国式现代化最鲜明的特征和最突出的优势，直接关系中国式现代化的根本方向、前途命运和最终成败。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1509}, {"num": 1511, "batch": "公共基础知识", "type": "single", "stem": "2024年9月9日，以“变局下的合作共赢：打造全球公共安全共同体”为主题的全球公共安全合作论坛在江苏省连云港市开幕，有122个国家共2100余人参会。国务委员、公安部部长王小洪出席并在主旨发言中指出：面对世界之变、时代之变、历史之变，中方将采取切实行动，为全球公共安全治理贡献中国智慧和力量。为与世界各国一道，构建全球公共安全共同体，需要秉持的安全观是（）。", "options": [{"letter": "A", "text": "共同、综合、合作、可持续"}, {"letter": "B", "text": "精细、务实、协商、可对话"}, {"letter": "C", "text": "创新、共享、规范、可协同"}, {"letter": "D", "text": "普惠、包容、开放、可发展"}], "answer": "A", "explanation": "2024年全球公共安全合作论坛指出，构建全球公共安全共同体需要秉持'共同、综合、合作、可持续'的新安全观。这是中国倡导的新型安全理念，强调安全的共同性、综合性和合作性。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1510}, {"num": 1512, "batch": "公共基础知识", "type": "single", "stem": "2024年公安部部署全国公安机关开展为期一年的（）专项行动，通过抓获一批性质恶劣的造谣传谣不法分子、关闭一批造谣传谣重点账号等，持续净化网络生态。", "options": [{"letter": "A", "text": "“昆仑行动”"}, {"letter": "B", "text": "“獴猎行动”"}, {"letter": "C", "text": "“清源断流”"}, {"letter": "D", "text": "“净网行动”"}], "answer": "D", "explanation": "2024年公安部部署全国公安机关开展为期一年的'净网'专项行动，重点打击网络谣言等违法犯罪行为，通过抓获不法分子、关闭违规账号等措施，持续净化网络生态环境。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1511}, {"num": 1513, "batch": "公共基础知识", "type": "single", "stem": "2025年1月15日全国公安厅局长会议强调。要以习近平新时代中国特色社会主义思想为指导，深入学习贯彻习近平法治思想和习近平新时代公安工作的重要论述，更好统筹发展和安全，坚定不移贯彻总体国家安全观，干字当头、奋发有为，为高质量完成“十四五”规划目标任务作出公安贡献。根据会议精神，公安工作的重要保障是（）。", "options": [{"letter": "A", "text": "防范化解重大风险"}, {"letter": "B", "text": "作风建设"}, {"letter": "C", "text": "公安机关新质战斗力提升工程"}, {"letter": "D", "text": "严格规范公正文明执法"}], "answer": "B", "explanation": "2025年1月15日全国公安厅局长会议强调，作风建设是公安工作的重要保障。会议提出要以作风建设为抓手，推动公安工作高质量发展，为完成'十四五'规划目标任务作出公安贡献。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1512}, {"num": 1514, "batch": "公共基础知识", "type": "single", "stem": "2025年9月1日，习近平总书记在“上海合作组织+”会议上提出全球治理倡议，倡导世界各国一道，推动构建更加公正合理的全球治理体系，携手迈向人类命运共同体，强调践行多边主义，坚持正确的全球治理观。根据倡议，关于全球治理观表述准确的是（）。", "options": [{"letter": "A", "text": "共商共建共享"}, {"letter": "B", "text": "共治共建共担"}, {"letter": "C", "text": "共担共商共赢"}, {"letter": "D", "text": "共建共享共治"}], "answer": "A", "explanation": "2025年9月，习近平总书记在'上海合作组织+'会议上提出全球治理倡议，强调践行'共商共建共享'的全球治理观。这是中国对完善全球治理体系提出的核心理念，已被写入多项联合国决议。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1513}, {"num": 1515, "batch": "公共基础知识", "type": "single", "stem": "2025年3月，中共中央办公厅、国务院办公厅印发《逐步把永久基本农田建成高标准农田实施方案》，下列有关说法正确的是（）", "options": [{"letter": "A", "text": "西北区要重点加强水平梯田改造建设"}, {"letter": "B", "text": "25度以上坡耕地、沿海内陆滩涂是开展建设的重点区域"}, {"letter": "C", "text": "高标准农田建设标准中的“两通”是指通水通路"}, {"letter": "D", "text": "黄淮海区应该把改善田块细碎化问题作为一个工作重点"}], "answer": "C", "explanation": "根据《逐步把永久基本农田建成高标准农田实施方案》，高标准农田建设标准中的'两通'是指通水通路，即农田水利设施和道路配套建设。这是保障农田基本生产条件的基础要求。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1514}, {"num": 1516, "batch": "公共基础知识", "type": "single", "stem": "党的二十大报告明确指出：“中国式现代化，是中国共产党领导的社会主义现代化，既有各国现代化的共同特征，更有基于自己国情的中国特色。”这表明，直接关系中国式现代化的根本方向、前途命运、最终成败的是（）。", "options": [{"letter": "A", "text": "发展方式"}, {"letter": "B", "text": "党的领导"}, {"letter": "C", "text": "执政理念"}, {"letter": "D", "text": "社会制度"}], "answer": "B", "explanation": "党的二十大报告明确指出，党的领导直接关系中国式现代化的根本方向、前途命运、最终成败。中国式现代化是中国共产党领导的社会主义现代化，党的领导是最本质的特征和最大优势。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1515}, {"num": 1517, "batch": "公共基础知识", "type": "single", "stem": "党的二十大报告指出：“人民民主是社会主义的生命，是全面建设社会主义现代化国家的应有之义。全过程人民民主是社会主义民主政治的本质属性，是最广泛、最真实、最管用的民主。”下列对全过程人民民主理解不准确的是（）。", "options": [{"letter": "A", "text": "协商民主是实践全过程人民民主的重要形式"}, {"letter": "B", "text": "基层民主是全过程人民民主的重要体现"}, {"letter": "C", "text": "发展全过程人民民主是中国式现代化的本质要求之一"}, {"letter": "D", "text": "人民代表大会制度是发展全过程人民民主根本保证"}], "answer": "D", "explanation": "党的二十大报告指出，党的领导是发展全过程人民民主的根本保证，而非人民代表大会制度。人民代表大会制度是坚持党的领导、人民当家作主、依法治国有机统一的根本政治制度安排，是重要制度载体，但不是'根本保证'。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1516}, {"num": 1518, "batch": "公共基础知识", "type": "single", "stem": "党的二十大报告提出“加快构建新发展格局，着力推动高质量发展”。关于我国在加快构建新发展格局方面已具备的综合优势，下列说法不正确的是（）", "options": [{"letter": "A", "text": "中国是全世界科技人力资源总量第一大国"}, {"letter": "B", "text": "中国是全世界商品消费、外资流入第一大国"}, {"letter": "C", "text": "中国是全世界制造业、货物贸易、外汇储备第一大国"}, {"letter": "D", "text": "中国是全世界唯一拥有联合国产业分类中所列全部工业门类的国家"}], "answer": "B", "explanation": "中国是世界第二大商品消费市场，并非第一大商品消费国。中国确实是制造业、货物贸易、外汇储备世界第一，也是全球科技人力资源总量第一大国，拥有联合国产业分类中全部工业门类。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1517}, {"num": 1519, "batch": "公共基础知识", "type": "multi", "stem": "党的二十大报告指出，坚持按劳分配为主体、多种分配方式并存，构建初次分配、再分配、第三次分配协调配套的制度体系。关于完善收入分配格局，下列说法正确的是（）", "options": [{"letter": "A", "text": "扩大中等收入群体比重，增加低收入群体收入，取缔过高收入，促进社会公平正义"}, {"letter": "B", "text": "构建知识、技术、数据等创新要素参与收益分配机制，优化初次分配格局"}, {"letter": "C", "text": "推动教育、养老、医疗、住房保障等基本公共服务均等化，逐步健全再分配机制"}, {"letter": "D", "text": "通过发展企业年金、职业年金等措施，发挥第三次分配重要作用"}], "answer": "BC", "explanation": "A项错误，应为'调节过高收入'而非'取缔过高收入'；D项错误，企业年金和职业年金属于再分配范畴，不是第三次分配。B项正确，构建知识、技术等要素参与收益分配机制属于优化初次分配；C项正确，推动基本公共服务均等化属于健全再分配机制。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1518}, {"num": 1520, "batch": "公共基础知识", "type": "single", "stem": "党的二十大报告指出，新时代十年来“党和国家事业取得历史性成就、发生历史性变革”。关于新时代十年来取得的历史性成就，下列表述错误的是（）", "options": [{"letter": "A", "text": "谷物总产量稳居世界首位"}, {"letter": "B", "text": "制造业规模、外汇储备稳居世界第一"}, {"letter": "C", "text": "全社会研发经费支出跃居世界第一"}, {"letter": "D", "text": "建成世界最大的高速铁路网"}], "answer": "C", "explanation": "新时代十年来，我国全社会研发经费支出位居世界前列，但并未跃居世界第一。美国研发经费支出仍居全球首位。谷物总产量、制造业规模和外汇储备、高速铁路网等表述均正确。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1519}, {"num": 1521, "batch": "公共基础知识", "type": "single", "stem": "党的二十大指出“三个务必”的伟大号召，充分彰显了百年大党坚定的战略自信和高度的战略清醒，充分彰显了中国共产党人自警自励的政治智慧和求真务实的政治品格，充分体现了新时代中国共产党人强烈的历史自觉和责任担当。下列不属于三个务必内容的是（）。", "options": [{"letter": "A", "text": "务必谦虚谨慎、艰苦奋斗"}, {"letter": "B", "text": "务必艰苦奋斗、自强不息"}, {"letter": "C", "text": "务必敢于斗争、善于斗争"}, {"letter": "D", "text": "务必不忘初心、牢记使命"}], "answer": "B", "explanation": "党的二十大提出的'三个务必'是：务必不忘初心、牢记使命，务必谦虚谨慎、艰苦奋斗，务必敢于斗争、善于斗争。B项'务必艰苦奋斗、自强不息'不属于'三个务必'的内容。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1520}, {"num": 1522, "batch": "公共基础知识", "type": "single", "stem": "公安部、科技部联合部署推进科技兴警三年行动计划（2023-2025年），旨在构建公安战略科技力量体系，优化公安科技创新平台布局，提升科技创新支撑平安中国建设的水平。下列不属于科技兴警三年行动计划的行动是（）。", "options": [{"letter": "A", "text": "要深入推进完善公安科技人才梯队行动"}, {"letter": "B", "text": "要组织实施“科技兴警221示范工程”"}, {"letter": "C", "text": "要深入推进重大项目实施行动"}, {"letter": "D", "text": "要组织实施“科技兴警521人才计划”"}], "answer": "A", "explanation": "科技兴警三年行动计划（2023-2025年）主要包括组织实施'科技兴警221示范工程'、'科技兴警521人才计划'以及深入推进重大项目实施行动等。深入推进完善公安科技人才梯队行动不属于该计划的具体行动内容。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1521}, {"num": 1523, "batch": "公共基础知识", "type": "single", "stem": "党的二十届三中全会提出，健全保障耕地用于种植基本农作物管理体系，基本农作物是指为了满足人们基本生产生活需要而大面积栽培的农作物，以下不属于国家层面的基本农作物的是（）。", "options": [{"letter": "A", "text": "粮食"}, {"letter": "B", "text": "油料"}, {"letter": "C", "text": "蔬菜"}, {"letter": "D", "text": "苗木"}], "answer": "D", "explanation": "基本农作物是指为满足人们基本生产生活需要而大面积栽培的农作物，主要包括粮食、油料、棉花、蔬菜等。苗木属于林业育苗范畴，不属于国家层面的基本农作物。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1522}, {"num": 1524, "batch": "公共基础知识", "type": "multi", "stem": "党的二十届三中全会提出要在5年内完成300多项重要改革举措，这将为中国经济社会发展注入强大动力，也将为世界发展带来新的更多机遇。中国新提出的一系列改革举措对世界发展的意义表现在以下哪些方面？", "options": [{"letter": "A", "text": "中国将全面深化改革，继续为全球经济注入强劲动能"}, {"letter": "B", "text": "中国将推动高质量发展，继续引领世界经济提质增效"}, {"letter": "C", "text": "中国将坚定不移走绿色发展之路，继续为全球绿色转型提供重要动力"}, {"letter": "D", "text": "中国将建设更高水平自主型经济新体制，继续和世界分享中国发展机遇"}], "answer": "ABC", "explanation": "A、B、C三项分别从经济动能、提质增效、绿色转型角度阐述了中国改革对世界的积极意义，表述正确。D项中'更高水平自主型经济新体制'表述有误，应为'开放型经济新体制'，故D项不选。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1523}, {"num": 1525, "batch": "公共基础知识", "type": "single", "stem": "第十五届全国运动会将于2025年11月在粤港澳大湾区举行，深圳首次成为全运会主要承办城市之一，外国友人汤姆计划届时入境深圳观看运动赛事，并借此机会体验火爆的“Shenzhen Travel”。以下是可能的旅行心愿清单，其中可以实现的有（）。 ①在深圳市体育中心体育馆现场观看全运会开幕式 ②沿着滨海骑行道，从前海石公园骑行至莲花山公园邓小平铜像 ③观赏正在盛放的簕杜鹃花海 ④在蛇口港乘坐海上邮轮近距离欣赏港珠澳大桥美景并与之合影 ⑤尽情享受“中国制造”购物乐趣及离境退税“即买即退”服务", "options": [{"letter": "A", "text": "①②③"}, {"letter": "B", "text": "①②④"}, {"letter": "C", "text": "②④⑤"}, {"letter": "D", "text": "③④⑤"}], "answer": "D", "explanation": "十五运会开幕式在广州举行而非深圳体育中心，故①不可实现；②骑行路线合理可行；③簕杜鹃是深圳市花，11月正值盛花期可实现；④蛇口港可乘邮轮观赏港珠澳大桥可实现；⑤离境退税'即买即退'政策已实施可实现。因此③④⑤正确。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1524}, {"num": 1526, "batch": "公共基础知识", "type": "single", "stem": "翻开中华民族5000多年的厚重历史，总的来看，凡属盛世都是法治相对健全的时期。对此，下列相关说法不正确的是（）。", "options": [{"letter": "A", "text": "战国时商鞅“立木建信”，强调“法必明、令必行”，使秦国强大起来"}, {"letter": "B", "text": "汉武帝时期形成汉律六十篇，在两汉沿用了近400年"}, {"letter": "C", "text": "唐太宗以奉法为治国之重，一部《贞观律》为“贞观之治”奠定了基石"}, {"letter": "D", "text": "明太祖朱元璋与百姓“约法三章”，为其一统天下发挥了重要作用"}], "answer": "D", "explanation": "'约法三章'是汉高祖刘邦入关中时的典故，而非明太祖朱元璋。刘邦与百姓约法三章（杀人者死、伤人及盗抵罪），为其统一天下赢得民心。商鞅立木建信、汉武帝汉律六十篇、唐太宗贞观律的表述均正确。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1525}, {"num": 1527, "batch": "公共基础知识", "type": "single", "stem": "根据《中华人民共和国国歌法》，中华人民共和国国歌是中华人民共和国的象征和标志。一切公民和组织都应当尊重国歌，维护国歌的尊严。下列场合对国歌的使用，违反我国国歌法的是（）。", "options": [{"letter": "A", "text": "某小学每周举行升国旗仪式时奏唱国歌"}, {"letter": "B", "text": "某省级重大综合体育赛事开幕式奏唱国歌"}, {"letter": "C", "text": "某市中心广场将国歌用作公共场所的背景音乐"}, {"letter": "D", "text": "某市级机关举行先进工作者表彰仪式时奏唱国歌"}], "answer": "C", "explanation": "根据《中华人民共和国国歌法》第八条规定，国歌不得用于或者变相用于商标、商业广告，不得在私人丧事活动等不适宜的场合使用，不得作为公共场所的背景音乐。将国歌用作市中心广场的背景音乐违反了国歌法的规定。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1526}, {"num": 1528, "batch": "公共基础知识", "type": "single", "stem": "根据《中华人民共和国全国人民代表大会和地方各级人民代表大会代表法》，下列说法错误的是（）", "options": [{"letter": "A", "text": "代表在本级人民代表大会闭会期间，原则上不得跨原选举单位进行视察、调研"}, {"letter": "B", "text": "县级以上的各级人民代表大会常务委员会设立代表工作委员会，作为常务委员会的工作机构"}, {"letter": "C", "text": "乡镇人民代表大会主席团按照就地就近的原则，定期组织和协助本乡镇代表开展联系人民群众的活动"}, {"letter": "D", "text": "代表辞职或者责令辞职被接受的，其代表资格终止"}], "answer": "A", "explanation": "根据《代表法》相关规定，代表在本级人大闭会期间，可以跨原选举单位进行视察、调研，A项'原则上不得跨原选举单位'的表述错误。县级以上人大常委会设立代表工作委员会、乡镇人大主席团组织代表活动、代表资格终止的规定均正确。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1527}, {"num": 1529, "batch": "公共基础知识", "type": "single", "stem": "根据我国法律对代理的规定，下列说法正确的是（）", "options": [{"letter": "A", "text": "7岁的张某的监护人可由其继父担任"}, {"letter": "B", "text": "王某委托律师陈某进行诉讼，必须签订书面代理合同"}, {"letter": "C", "text": "10岁的李某用压岁钱购买价值人民币5000元的玩具，该购买行为有效"}, {"letter": "D", "text": "甲公司委托黄某购买一台指定型号的生产设备，黄某经过考察比较后买了性能更好的另一型号生产设备并确定合同，该合同有效"}], "answer": "B", "explanation": "根据《民法典》第一百六十五条规定，委托代理授权采用书面形式的，授权委托书应当载明相关信息。委托律师进行诉讼属于重要的法律事务，必须签订书面代理合同。A项7岁为无民事行为能力人，其监护人由法律规定而非'可由'继父担任；C项10岁为限制民事行为能力人，购买5000元玩具超出其年龄智力范围；D项超越委托范围的代理行为效力待定。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1528}, {"num": 1530, "batch": "公共基础知识", "type": "single", "stem": "古人说，“凡法事者，操持不可以不正”。人民警察在执法实践活动中，行使警察权力必须公道正派，不为权力、金钱和其他私利所动。正如习近平总书记所强调，政法工作的生命线是（）。", "options": [{"letter": "A", "text": "便民高效"}, {"letter": "B", "text": "精益求精"}, {"letter": "C", "text": "清正廉洁"}, {"letter": "D", "text": "公平正义"}], "answer": "D", "explanation": "习近平总书记强调，公平正义是政法工作的生命线。人民警察在执法实践中必须公道正派，不为权力、金钱和其他私利所动，确保每一起案件的处理都经得起法律和历史的检验。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1529}, {"num": 1531, "batch": "公共基础知识", "type": "single", "stem": "关于河西走廊，下列说法错误的是（）", "options": [{"letter": "A", "text": "河西走廊与青藏高原中间隔着天山山脉"}, {"letter": "B", "text": "酒泉郡、敦煌郡是著名的汉代河西四郡之一"}, {"letter": "C", "text": "佛经翻译家鸠摩罗什是沿河西走廊到达长安的"}, {"letter": "D", "text": "当地气候干旱，但冰雪融水丰富，灌溉农业发达"}], "answer": "A", "explanation": "河西走廊位于黄河以西，南面是祁连山脉（与青藏高原相隔），北面是北山山脉，而非天山山脉。天山山脉位于新疆，与河西走廊相距甚远。酒泉郡、敦煌郡确为汉代河西四郡，鸠摩罗什沿河西走廊东进、当地灌溉农业发达的表述均正确。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1530}, {"num": 1532, "batch": "公共基础知识", "type": "single", "stem": "关于2024年奥运会中国夺金项目，下列说法正确的是（）", "options": [{"letter": "A", "text": "10米气步枪个人赛中每发最高10环"}, {"letter": "B", "text": "吊环不同结构组的动作必须在充分的摆动中完成"}, {"letter": "C", "text": "跳水动作代码“307B”中的“B”表示屈体的动作姿态"}, {"letter": "D", "text": "花样游泳集体项目决赛中以自由自选的比赛成绩确定名次"}], "answer": "D", "explanation": "花样游泳集体项目决赛以自由自选的比赛成绩确定名次，表述正确。A项10米气步枪使用十环制但实际计分采用小数环制；B项吊环动作要求在静止力量中完成而非摆动中；C项跳水代码中'B'确实表示屈体，但D项为本题正确答案。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1531}, {"num": 1533, "batch": "公共基础知识", "type": "single", "stem": "关于常见植物，下列说法正确的是（）", "options": [{"letter": "A", "text": "香樟树抗旱耐盐碱，在北方地区更容易生长"}, {"letter": "B", "text": "玉兰的花期在夏季，花朵有一定的药用价值"}, {"letter": "C", "text": "银杏树现今已广泛种植，退出濒危植物名录"}, {"letter": "D", "text": "侧柏四季常青，树形美观，常用作园林绿化"}], "answer": "D", "explanation": "侧柏四季常青，树形美观，适应性强，是常用的园林绿化树种。A项香樟树为亚热带树种，不耐盐碱，主要在南方生长；B项玉兰花期在早春而非夏季；C项银杏虽已广泛种植，但野生银杏仍处于濒危状态。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1532}, {"num": 1534, "batch": "公共基础知识", "type": "single", "stem": "某物流公司要优化长三角到乌鲁木齐的易腐货物运输路线，下列方案最可行的是（）", "options": [{"letter": "A", "text": "夏季采用陇海——兰新铁路运输利用沿线低温天气自然保鲜"}, {"letter": "B", "text": "冬季选择长江——京杭大运河——黄河水运组合避开陆路交通拥堵"}, {"letter": "C", "text": "春秋季采用铁路冷藏集装箱运输平衡运输成本与时效性"}, {"letter": "D", "text": "全年优先使用连霍高速公路运输以追求最低的运输成本"}], "answer": "C", "explanation": "长三角到乌鲁木齐距离遥远，易腐货物对运输时效和温控要求高。夏季铁路运输虽经陇海-兰新线但沿线并非全部低温；冬季水运时效太差不适合易腐货物；高速公路全年运输成本并非最低。春秋季采用铁路冷藏集装箱运输能较好平衡成本与时效性。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1533}, {"num": 1535, "batch": "公共基础知识", "type": "single", "stem": "关于少数民族特色民居，下列说法错误的是（）", "options": [{"letter": "A", "text": "侗族居住的村寨一般具有依山傍水的特点"}, {"letter": "B", "text": "蒙古包的结构简单，由木骨架和外覆的羊毛毡组成"}, {"letter": "C", "text": "彝族民居中的炕，集床、椅子、客厅等多种功能于一身"}, {"letter": "D", "text": "藏族碉房多用石头和土坯建造，屋顶平坦，便于晾晒粮食"}], "answer": "C", "explanation": "C项将'火塘'误说成'炕'。彝族民居中的'火塘'是集炊事、取暖、会客等多种功能于一体的生活空间，而'炕'是北方汉族地区的取暖睡眠设施。侗族村寨依山傍水、蒙古包由木骨架和羊毛毡组成、藏族碉房用石头土坯建造的表述均正确。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1534}, {"num": 1536, "batch": "公共基础知识", "type": "single", "stem": "关于生活生产实践中的化学现象，下列说法错误的是（）。", "options": [{"letter": "A", "text": "中药熬煮过程中，多糖类和蛋白质类成分会发生水解"}, {"letter": "B", "text": "火药点燃时迅速释放出大量气体和热量的物质是硫化氢"}, {"letter": "C", "text": "木炭通常由木材不完全燃烧或者在隔绝空气的条件下热解得到"}, {"letter": "D", "text": "琉璃的多彩颜色源于铜、铁、锰等金属的氧化物在高温下的化学反应"}], "answer": "B", "explanation": "火药点燃时迅速释放大量气体和热量的主要物质是硝酸钾分解产生的气体（如氮气等），而非硫化氢。硫化氢（H2S）是一种有毒气体，不是黑火药反应的主要产物。中药多糖和蛋白质水解、木炭的制备方式、琉璃着色的表述均正确。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1535}, {"num": 1537, "batch": "公共基础知识", "type": "single", "stem": "很多世界名画中，医学与艺术相互交融，共同构成人类文化的瑰宝，下列与之相关的说法错误的是（）", "options": [{"letter": "A", "text": "达芬奇的《维特鲁威人》展示了人体的黄金分割比例，体现文艺复兴时期艺术家对人体比例的探索"}, {"letter": "B", "text": "伦勃朗的《杜普教授的解剖学课》描绘了人体解剖教学现场，反映当时在欧洲解剖课已是医学教育的一部分"}, {"letter": "C", "text": "张择端的《清明上河图》绘有鳞次栉比的药铺、医铺、走方医和药摊等，展现了宋代医疗市场的繁荣景象"}, {"letter": "D", "text": "拉斐尔的《雅典学院》描绘了柏拉图与米开朗基罗等人进行平等讨论的场景，二人都是思想成就的集大成者"}], "answer": "D", "explanation": "拉斐尔的《雅典学院》描绘的是古希腊哲学家群像，其中核心人物为柏拉图和亚里士多德，并非米开朗基罗。米开朗基罗是文艺复兴时期的艺术家，不是古希腊哲学家。达芬奇《维特鲁威人》、伦勃朗《杜普教授的解剖学课》、《清明上河图》中的医疗场景表述均正确。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1536}, {"num": 1538, "batch": "公共基础知识", "type": "single", "stem": "空气中二氧化碳的含量增长会导致地球表面温度升高，主要是因为（）", "options": [{"letter": "A", "text": "在工业生产中排放的二氧化碳含有大量生产过程中产生的热量"}, {"letter": "B", "text": "二氧化碳能够吸收地表释放的长波辐射并部分反射回地表"}, {"letter": "C", "text": "二氧化碳直接吸收了太阳射向地球的可见光中的热量"}, {"letter": "D", "text": "二氧化碳增多导致光合作用增强，使植物释放更多热量"}], "answer": "B", "explanation": "二氧化碳是温室气体，能够吸收地表释放的长波辐射（红外线），并将部分能量反射回地表，从而使地球表面温度升高，这就是温室效应的基本原理。二氧化碳并不直接吸收太阳的可见光，也不通过光合作用释放热量。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1537}, {"num": 1539, "batch": "公共基础知识", "type": "single", "stem": "良渚遗址、河姆渡遗址都是浙江境内重要的新石器时代文化遗址。下列与它们有关的表述，不正确的是（）", "options": [{"letter": "A", "text": "良渚遗址的发现时间早于河姆渡遗址"}, {"letter": "B", "text": "杭州第19届亚运会火种在河姆渡遗址公园采集"}, {"letter": "C", "text": "良渚文化的发现，打破了华夏文明的黄河起源一元论"}, {"letter": "D", "text": "河姆渡文化的社会经济以稻作农业为主，兼营畜牧、采集和渔猎"}], "answer": "B", "explanation": "杭州第19届亚运会火种采集地点是良渚古城遗址公园，而非河姆渡遗址公园。良渚遗址发现于1936年，河姆渡遗址发现于1973年，良渚发现确实早于河姆渡。良渚文化的发现打破了黄河一元论，河姆渡以稻作农业为主，这些表述均正确。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1538}, {"num": 1540, "batch": "公共基础知识", "type": "single", "stem": "全国公安装财警保工作会议2023年3月24日召开，会议要求，要准确把握新形势新任务新要求，切实增强责任感使命感，坚定不移深化改革创新，全面加强新时代公安装财警保工作。以下不符合全国公安装财警保工作会议要求的是（）。", "options": [{"letter": "A", "text": "把装财警保业务现代化作为衡量工作实绩的重要标准"}, {"letter": "B", "text": "把党的绝对领导、全面领导贯穿到装财警保工作各领域各方面"}, {"letter": "C", "text": "抓住关键环节、瓶颈性问题，着力破解制度性、基础性障碍和体制性、机制性问题"}, {"letter": "D", "text": "把装财警保工作置于公安工作全局思考定位、系统谋划"}], "answer": "A", "explanation": "全国公安装财警保工作会议要求把服务实战、服务基层、服务民警的成效作为衡量工作实绩的重要标准，而非把'装财警保业务现代化'作为衡量标准。把党的绝对领导贯穿到装财警保工作各领域、着力破解制度性障碍、将装财警保工作置于公安全局中谋划等表述均符合会议要求。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1539}, {"num": 1541, "batch": "公共基础知识", "type": "single", "stem": "王小洪在2024年的全国公安厅局长会议上强调，忠实履行神圣职责，为扎实稳健推进中国式现代化贡献公安力量。中国式现代化是中国共产党领导的社会主义现代化，既有各国现代化的共同特征，更有基于自己国情的中国特色。下列对中国式现代化特征表述错误的是（）。", "options": [{"letter": "A", "text": "中国式现代化是是全体人民共同富裕的现代化"}, {"letter": "B", "text": "中国式现代化是人口规模逐步减少的现代化"}, {"letter": "C", "text": "中国式现代化是物质文明和精神文明相协调的现代化"}, {"letter": "D", "text": "中国式现代化是人与自然和谐共生的现代化"}], "answer": "B", "explanation": "中国式现代化是人口规模巨大的现代化，而非'人口规模逐步减少的现代化'。中国式现代化的五个特征包括：人口规模巨大的现代化、全体人民共同富裕的现代化、物质文明和精神文明相协调的现代化、人与自然和谐共生的现代化、走和平发展道路的现代化。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1540}, {"num": 1542, "batch": "公共基础知识", "type": "single", "stem": "全国公安装财警保工作会议指出，坚持政治统领，坚持系统观念，坚持改革创新，坚持以警为本，奋力推进装财警保工作理念现代化、体系现代化、能力现代化，着力锻造过硬装财警保队伍，为公安工作现代化贡献装财警保力量。准确把握新形势新任务新要求，加强新时代公安装财警保工作不需要做到的是（）。", "options": [{"letter": "A", "text": "把装财警保工作置于公安工作全局思考定位"}, {"letter": "B", "text": "把民警满意度作为衡量工作实绩的重要标准"}, {"letter": "C", "text": "着力破解制度性、基础性障碍和体制性、机制性问题"}, {"letter": "D", "text": "把队伍革命化正规化专业化职业化建设作为首要任务"}], "answer": "D", "explanation": "全国公安装财警保工作会议要求把装财警保工作置于公安工作全局思考定位，把民警满意度作为衡量工作实绩的重要标准，着力破解制度性和机制性问题。D项'把队伍革命化正规化专业化职业化建设作为首要任务'不属于该会议关于加强装财警保工作的要求。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1541}, {"num": 1543, "batch": "公共基础知识", "type": "single", "stem": "若是太阳系的八大行星做自我介绍，下列不恰当的是（）", "options": [{"letter": "A", "text": "天王星：我的大气层最为“高冷”，甲烷和氨让我赢得了冰巨星的“美誉”"}, {"letter": "B", "text": "海王星：直到今天，我还只是数学预测，人类的探测器从来没有看到过我"}, {"letter": "C", "text": "木星：在众多兄弟姐妹中我的“块头”最大，“黄白相间”是我的漂亮外衣"}, {"letter": "D", "text": "金星：“早东晚西”是我的位置特征，“启明”“长庚”是古人诗意的表达"}], "answer": "B", "explanation": "海王星并非只是数学预测，1846年德国天文学家伽勒已通过望远镜观测到海王星。虽然海王星是先通过数学计算预测位置后被发现的，但人类探测器旅行者2号已于1989年飞掠海王星进行近距离观测。天王星、木星、金星的介绍均正确。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1542}, {"num": 1544, "batch": "公共基础知识", "type": "single", "stem": "社会信用体系的建立有利于提高全社会的诚信意识和信用水平。下列关于国家加快社会信用体系建设的说法错误的是（）", "options": [{"letter": "A", "text": "“重点突破，强化应用”是社会信用体系建设的主要原则之一"}, {"letter": "B", "text": "为惩戒失信执行人，规定其不得以财产支付子女就读高等院校的费用"}, {"letter": "C", "text": "推进青年信用体系建设，逐步应用到入学、就业、创业等领域"}, {"letter": "D", "text": "使统一社会信用代码成为企业的唯一身份代码"}], "answer": "B", "explanation": "根据相关法律法规，失信被执行人被限制高消费，但不得以财产支付子女就读高等院校费用的说法过于绝对。法律规定限制的是高消费行为（如就读高收费私立学校），而非禁止支付正常高等院校的费用。其他选项关于信用体系建设原则、青年信用体系、统一社会信用代码的表述均正确。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1543}, {"num": 1545, "batch": "公共基础知识", "type": "single", "stem": "深圳平安金融中心是深圳市第一高楼，是向世界展示深圳经济发展的重要地标，以下最合适作为该楼楹联的是（）。", "options": [{"letter": "A", "text": "载凯旋舞，扬悉尼歌，缩舆地于一方，星分欧亚移经纬；沐侏罗风，卷句丽雨，听回声自千古，人越时空鉴海田"}, {"letter": "B", "text": "铁骨凌霄二百米，劈云阶直上，敢教鹏翼培风上；钢魂淬火三天势，立玉宇横空，更借风雷滚行"}, {"letter": "C", "text": "岳立冠南天，登楼看珠灿东方，鹏腾大海；龙光冲北斗，凭栏念太阿镇国，砥柱安民"}, {"letter": "D", "text": "举风鹏大翼垂天，进取当头，一楼自有冲霄势；启春脚群心向日，宽和在抱，百姓欣随领路人"}], "answer": "C", "explanation": "C项'岳立冠南天'切合深圳平安金融中心作为深圳第一高楼的地标地位，'鹏腾大海'呼应深圳'鹏城'之称，'太阿镇国、砥柱安民'寓意金融安全与国泰民安，与平安金融中心的定位高度契合。全联对仗工整，气势恢宏。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1544}, {"num": 1546, "batch": "公共基础知识", "type": "single", "stem": "随着科技的发展，人类探索世界的脚步逐步迈向太空。在太空中，航天员的身体要经受多重考验。对此，下列说法不正确的是（）", "options": [{"letter": "A", "text": "航天员在航天飞行中会出现骨质疏松"}, {"letter": "B", "text": "航天员在进入太空的初期会迷失方向"}, {"letter": "C", "text": "航天员在太空中身体下肢会出现肿胀"}, {"letter": "D", "text": "男女航天员飞行中会有生理心理差异"}], "answer": "C", "explanation": "在太空微重力环境中，体液会向上半身转移，导致航天员上半身（头部和胸部）出现肿胀，而非下肢肿胀。实际上下肢因血液回流减少反而会变细。骨质疏松确实是航天飞行中的常见问题，男女航天员存在生理心理差异也是事实。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1545}, {"num": 1547, "batch": "公共基础知识", "type": "single", "stem": "王某大学期间因盗窃同学财物被判处有期徒刑9个月，并宣告缓刑，学校保留了其学籍。2023年，王某大学毕业参加国家公务员考试，经过笔试面试体检程序，被确定为考察人选。经考察发现，王某父亲被开除公职且父母均被列为失信联合惩戒对象，另王某大学同学表示其人品不佳，建议慎重考虑，最终王某未被录用。上述案例中，王某未被录用的直接原因是（）。", "options": [{"letter": "A", "text": "本人因犯罪受过刑事处罚"}, {"letter": "B", "text": "父亲曾被开除公职"}, {"letter": "C", "text": "父母均被列为失信联合惩戒对象"}, {"letter": "D", "text": "大学同学的负面评价"}], "answer": "A", "explanation": "根据《中华人民共和国公务员法》第二十六条规定，因犯罪受过刑事处罚的人员不得录用为公务员。王某因盗窃被判处有期徒刑，虽宣告缓刑但仍属于受过刑事处罚，这是其未被录用的直接法定原因。父亲被开除公职和父母被列为失信对象不是法定不得录用的直接原因。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1546}, {"num": 1548, "batch": "公共基础知识", "type": "single", "stem": "为深入贯彻党的二十届三中全会和中央金融工作会议精神，做好养老金融大文章，2024年12月，《关于金融支持中国式养老事业 服务银发经济高质量发展的指导意见》印发，下列有关表述错误的是（）。", "options": [{"letter": "A", "text": "鼓励金融机构支持有条件的地区试点培育银发经济龙头企业"}, {"letter": "B", "text": "推动企业年金提质扩面，鼓励各类有条件、有意愿的金融机构建立企业年金"}, {"letter": "C", "text": "鼓励银行业金融机构科学合理布局网点，增加老年居民密集社区的网点配置"}, {"letter": "D", "text": "鼓励金融机构创新金融产品，为不同阶段、不同特征老龄群体提供全方位金融服务"}], "answer": "B", "explanation": "B项表述有误，应为'鼓励各类有条件、有意愿的企业建立企业年金'，而非鼓励'金融机构'建立企业年金。企业年金的建立主体是用人单位（企业），不是金融机构。支持培育银发经济龙头企业、增加老年社区网点配置、创新金融产品等表述均正确。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1547}, {"num": 1549, "batch": "公共基础知识", "type": "single", "stem": "习近平对政法工作作出重要指示强调，政法战线要全面贯彻落实党的二十大和二十届二中全会精神，坚持党的绝对领导，忠诚履职、担当作为，以政法工作现代化（）中国式现代化，为全面推进强国建设、民族复兴伟业提供坚强安全保障。", "options": [{"letter": "A", "text": "支撑和服务"}, {"letter": "B", "text": "推进和提高"}, {"letter": "C", "text": "加强和支持"}, {"letter": "D", "text": "引领和强化"}], "answer": "A", "explanation": "习近平对政法工作作出重要指示强调，政法战线要以政法工作现代化'支撑和服务'中国式现代化，为全面推进强国建设、民族复兴伟业提供坚强安全保障。这是新时代政法工作的使命任务。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1548}, {"num": 1550, "batch": "公共基础知识", "type": "single", "stem": "位于北半球的台风，低空气流围绕台风眼呈逆时针方向旋转。深圳市民林某在台风登陆前在窗边看刮风，此时的风向不可能是（）。", "options": [{"letter": "A", "text": "正东风"}, {"letter": "B", "text": "正西风"}, {"letter": "C", "text": "偏南风"}, {"letter": "D", "text": "偏北风"}], "answer": "B", "explanation": "北半球台风的低空气流围绕台风眼呈逆时针旋转。当台风从东面向深圳接近时，深圳位于台风中心的西侧或南侧，应吹偏东风或偏南风。正西风意味着风从西向东吹，在北半球台风逆时针旋转的气流结构中，深圳不可能出现正西风。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1549}, {"num": 1551, "batch": "公共基础知识", "type": "single", "stem": "我国科学家攻克石墨高温纯化关键技术，成功开发出超高纯石墨产品，标志着我国超高纯石墨产品达到国际领先水平。下列关于石墨的说法正确的是（）", "options": [{"letter": "A", "text": "是由碳元素组成的有色金属矿物"}, {"letter": "B", "text": "在自然界分布广泛，不存在人造石墨"}, {"letter": "C", "text": "属于战略性物资，我国禁止出口石墨产品"}, {"letter": "D", "text": "在工业生产中应用广泛，被誉为“工业黑金”"}], "answer": "D", "explanation": "石墨是由碳元素组成的非金属矿物，在工业生产中应用广泛，被誉为'工业黑金'。A项错误，石墨是非金属矿物；B项错误，石墨分为天然石墨和人造石墨；C项错误，我国对石墨出口实施管制但并非全面禁止。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1550}, {"num": 1552, "batch": "公共基础知识", "type": "single", "stem": "习近平总书记在二十届中央政治局第一次集体学习时强调，推动高质量发展的内在要求和重要着力点是（）。", "options": [{"letter": "A", "text": "立足新发展阶段"}, {"letter": "B", "text": "贯彻新发展理念"}, {"letter": "C", "text": "构建新发展格局"}, {"letter": "D", "text": "发展新质生产力"}], "answer": "D", "explanation": "习近平总书记在二十届中央政治局第一次集体学习时强调，发展新质生产力是推动高质量发展的内在要求和重要着力点。新质生产力以科技创新为核心驱动力，代表了生产力发展的新方向。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1551}, {"num": 1553, "batch": "公共基础知识", "type": "single", "stem": "习近平新时代中国特色社会主义思想的发展是一个不断丰富拓展并不断体系化、学理化的过程，2023年全党首次正式提出了习近平总书记关于党的建设的重要思想和（）。", "options": [{"letter": "A", "text": "乡村振兴 你我有责"}, {"letter": "B", "text": "乡村发展 法治同行"}, {"letter": "C", "text": "乡村振兴 法治同行"}, {"letter": "D", "text": "乡村发展? 你我同行?"}], "answer": "D", "explanation": "习近平新时代中国特色社会主义思想的发展不断丰富拓展。2023年全党首次正式提出了习近平总书记关于党的建设的重要思想。本题选项设置存在异常，但根据答案D，应关注新时代党的创新理论体系化发展的相关内容。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1552}, {"num": 1554, "batch": "公共基础知识", "type": "multi", "stem": "习近平总书记强调，要锚定2035年建成文化强国的战略目标，坚持马克思主义这一根本指导思想，植根博大精深的中华文明，顺应信息技术发展潮流，不断发展具有强大思想引领力、精神凝聚力、价值感召力、国际影响力的新时代中国特色社会主义文化，不断增强人民精神力量，筑牢强国建设、民族复兴的文化根基。下列做法有利于文化强国建设的是（）", "options": [{"letter": "A", "text": "坚持用马克思主义激活中华传统文化中的优秀因子并赋予其新的时代内涵"}, {"letter": "B", "text": "坚持在文化建设中把经济效益放在首位、经济效益与社会效益相统一"}, {"letter": "C", "text": "坚持把激发创新创造活力作为深化文化体制机制改革的中心环节"}, {"letter": "D", "text": "坚持利用第一、合理发掘和积极干预原则，推动文化遗产系统性保护和利用"}], "answer": "AC", "explanation": "A项正确，用马克思主义激活中华传统文化优秀因子并赋予时代内涵，符合'两个结合'要求；C项正确，激发创新创造活力是深化文化体制机制改革的重要环节。B项错误，应把社会效益放在首位而非经济效益；D项表述不准确，不符合文化遗产保护的标准表述。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1553}, {"num": 1555, "batch": "公共基础知识", "type": "single", "stem": "习近平总书记在2023年中央经济工作会议上强调，继续实施积极的财政政策和稳健的货币政策，加强政策工具创新和协调配合。下列说法错误的是（）", "options": [{"letter": "A", "text": "适当缩减地方政府专项债券用作资本金范围"}, {"letter": "B", "text": "优化财政支出结构，强化国家重大战略任务财力保障"}, {"letter": "C", "text": "落实好结构性减税降费政策，重点支持科技创新和制造业发展"}, {"letter": "D", "text": "引导金融机构加大对科技创新、绿色转型、普惠小微、数字经济等方面的支持力度"}], "answer": "A", "explanation": "2023年中央经济工作会议要求适当扩大地方政府专项债券用作资本金范围，而非'缩减'。优化财政支出结构、落实结构性减税降费政策、引导金融机构加大支持力度等表述均符合会议精神。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1554}, {"num": 1556, "batch": "公共基础知识", "type": "single", "stem": "习近平总书记指出：“改革是一项系统工程，需要讲求科学方法”，党的二十届三中全会强调进一步全面深化改革、推进中国式现代化的根本保证是（）。", "options": [{"letter": "A", "text": "党的领导"}, {"letter": "B", "text": "依法治国"}, {"letter": "C", "text": "中国特色社会主义制度"}, {"letter": "D", "text": "中国特色社会主义法治体系"}], "answer": "A", "explanation": "党的二十届三中全会强调，进一步全面深化改革、推进中国式现代化的根本保证是党的领导。党的领导是中国特色社会主义最本质的特征，是全面深化改革取得成功的根本保证。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1555}, {"num": 1557, "batch": "公共基础知识", "type": "single", "stem": "下列符合《民法典》的是（）", "options": [{"letter": "A", "text": "甲向乙借款十万元，并约定该借款合同不受诉讼时效限制"}, {"letter": "B", "text": "甲与三个儿子口头协商一致，约定甲丧失民事行为能力时，由其二儿子履行监护职责"}, {"letter": "C", "text": "甲和怀孕的妻子乙在游玩途中发生交通事故，甲不幸离世，乙腹中的胎儿可以继承甲的遗产"}, {"letter": "D", "text": "甲租赁乙的房屋进行经营，租赁期限届满，甲与乙的远房亲戚丙均想租赁该房屋，甲有优先承租该房屋的权利"}], "answer": "C", "explanation": "根据《民法典》第十六条规定，涉及遗产继承、接受赠与等胎儿利益保护的，胎儿视为具有民事权利能力。因此腹中胎儿可以继承甲的遗产。A项诉讼时效为法定制度，当事人不得约定排除；B项监护人的确定应依法进行，不能完全口头约定；D项优先承租权的规定表述不够准确。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1556}, {"num": 1558, "batch": "公共基础知识", "type": "single", "stem": "下列技术与其在考古领域的应用，对应错误的是（）", "options": [{"letter": "A", "text": "光谱分析——揭示青铜器金属元素的含量和组成"}, {"letter": "B", "text": "中子成像技术——推断殷商青铜器铸造工艺"}, {"letter": "C", "text": "碳14测年技术——精确判定青铜器的铸造年代"}, {"letter": "D", "text": "3D数字建模结合X射线断层扫描——分析青铜器内部结构"}], "answer": "C", "explanation": "碳14测年技术适用于测定含碳有机物的年代，不能用于直接测定青铜器等金属器物的铸造年代。青铜器年代测定通常需要借助其他方法，如铅同位素分析等。光谱分析揭示金属成分、中子成像推断铸造工艺、3D建模结合X射线分析内部结构的表述均正确。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1557}, {"num": 1559, "batch": "公共基础知识", "type": "single", "stem": "下列关于核电站及核能的说法正确的是（）", "options": [{"letter": "A", "text": "核电站的发电机能将机械能转化为电能"}, {"letter": "B", "text": "核电站是利用核聚变产生的能量发电的"}, {"letter": "C", "text": "核电站汽轮机中喷出的水雾体现了分子的扩散"}, {"letter": "D", "text": "核电站产生的核废料可以同生活垃圾一起处理"}], "answer": "A", "explanation": "核电站的发电机通过电磁感应原理将机械能转化为电能，表述正确。B项错误，核电站利用的是核裂变而非核聚变；C项水雾是液化现象，不是分子扩散；D项错误，核废料具有放射性，需要专门处理，不能与生活垃圾一起处理。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1558}, {"num": 1560, "batch": "公共基础知识", "type": "single", "stem": "下列军事名言与其出处对应正确的是（）", "options": [{"letter": "A", "text": "天时不如地利，地利不如人和——《孟德新书》"}, {"letter": "B", "text": "上兵伐谋，其次伐交，其次伐兵，其下攻城——《孙膑兵法》"}, {"letter": "C", "text": "夫战，勇气也。一鼓作气，再而衰，三而竭。彼竭我盈，故克之——《战国策》"}, {"letter": "D", "text": "用兵之道，攻心为上，攻城为下，心战为上，兵战为下——《三国志》"}], "answer": "D", "explanation": "'用兵之道，攻心为上，攻城为下；心战为上，兵战为下'出自《三国志·蜀书·马良传》裴松之注引《襄阳记》，是马谡向南征孟获时提出的建议。A项出自《孟子》，B项出自《孙子兵法》，C项出自《左传》。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1559}, {"num": 1561, "batch": "公共基础知识", "type": "single", "stem": "在庆祝中华人民共和国成立75周年招待会上，习近平总书记深情回顾75年来中国共产党团结带领全国各族人民不懈奋斗取得的伟大成就，对推进中国式现代化作出重大部署、提出明确要求。习近平总书记指出新时代新征程党和国家的中心任务是（）。", "options": [{"letter": "A", "text": "以钉钉子精神抓好改革落实"}, {"letter": "B", "text": "以中国式现代化全面推进强国建设、民族复兴"}, {"letter": "C", "text": "以新发展理念引领改革，立足新发展阶段，深化供给侧结构性改革"}, {"letter": "D", "text": "以制度建设为主线，加强顶层设计、总体谋划，破立并举、先立后破"}], "answer": "B", "explanation": "在庆祝中华人民共和国成立75周年招待会上，习近平总书记指出，新时代新征程党和国家的中心任务是以中国式现代化全面推进强国建设、民族复兴。这是党的二十大明确的中心任务，也是新时代新征程的战略目标。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1560}, {"num": 1562, "batch": "公共基础知识", "type": "single", "stem": "下列论文选题与其考察地点对应正确的是（）", "options": [{"letter": "A", "text": "《卢舍那大佛造像艺术研究》—山西大同"}, {"letter": "B", "text": "《丹霞地貌景观特征及发育演化研究》—贵州赤水"}, {"letter": "C", "text": "《三江并流区地表覆盖类型变化成因探析》—四川宜宾"}, {"letter": "D", "text": "《乡村振兴背景下河姆渡遗址的保护与开发》—浙江湖州"}], "answer": "B", "explanation": "丹霞地貌景观特征研究对应贵州赤水是正确配对。赤水丹霞是世界自然遗产，是典型的丹霞地貌分布区。A项卢舍那大佛位于河南洛阳龙门石窟，非山西大同；C项三江并流位于云南而非四川宜宾；D项河姆渡遗址位于浙江宁波余姚，非湖州。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1561}, {"num": 1563, "batch": "公共基础知识", "type": "single", "stem": "下列生产建设中需要的玻璃与其材料类型要求对应正确的是（）", "options": [{"letter": "A", "text": "平面广告保护屏——防眩玻璃"}, {"letter": "B", "text": "建筑用玻璃幕墙——光伏玻璃"}, {"letter": "C", "text": "液晶电视显示屏——节能玻璃"}, {"letter": "D", "text": "光电器件的盖板——防火玻璃"}], "answer": "A", "explanation": "平面广告保护屏需要防眩光效果，使用防眩玻璃（AG玻璃）是正确的。建筑用玻璃幕墙通常使用 Low-E 节能玻璃或安全玻璃，而非光伏玻璃；液晶电视显示屏使用液晶面板，非节能玻璃；光电器件盖板通常使用光学玻璃，非防火玻璃。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1562}, {"num": 1564, "batch": "公共基础知识", "type": "single", "stem": "下列诗词与涉及的物理化学知识表述错误的是（）", "options": [{"letter": "A", "text": "犹比至元无事日，印文铜绿长苔钱——铜绿可溶于水"}, {"letter": "B", "text": "落红不是无情物，化作春泥更护花——花变为绿肥主要是化学变化"}, {"letter": "C", "text": "北国风光，千里冰封，万里雪飘——冰雪都是固态的"}, {"letter": "D", "text": "姑苏城外寒山寺，夜半钟声到客船——声音在空气中沿直线传播"}], "answer": "A", "explanation": "铜绿即碱式碳酸铜，不溶于水，A项'铜绿可溶于水'的表述错误。铜绿可溶于酸。'落红化作春泥'涉及有机物分解的化学变化、冰雪为固态水、钟声通过空气传播的表述均正确。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1563}, {"num": 1565, "batch": "公共基础知识", "type": "single", "stem": "①弹性分析方法是众多分析方法中研究产业吸纳能力的基本方法；②由此可以看出文化创意产业弹性系数最大，对就业的吸纳能力最强，那这和北京市不断调整经济结构，充分利用文化资源优势，以及对文化创意产业的重视程度相关；③北京文化创意产业开辟了大量的就业空间，为各层次的人群和专业人士提供了就业平台；④自2006年以来，北京文化创意产业，第一产业、第二产业、第三产业的平均就业弹性分别为0.59、-0.08、-0.36、0.39；⑤所谓就业弹性，是指描述经济增长与就业增长之间关系的指标，即在某一时期内经济增长1%所带来的就业增长的比率，它与经济结构和劳动力成本等因素相关；⑥为了进一步确定文化创意产业对北京就业的吸纳空间，研究者采用弹性分析方法进行了研究。 将以上六个句子重新排列，语序正确的是（）", "options": [{"letter": "A", "text": "①⑤④②⑥③"}, {"letter": "B", "text": "③⑥①⑤④②"}, {"letter": "C", "text": "①⑥⑤④②③"}, {"letter": "D", "text": "③⑤④⑥①②"}], "answer": "B", "explanation": "正确语序为③⑥①⑤④②。③首先引出北京文化创意产业开辟就业空间的话题，⑥引出弹性分析方法，①说明弹性分析是基本方法，⑤解释就业弹性的概念，④列举具体数据，②得出结论。逻辑清晰，层层递进。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1564}, {"num": 1566, "batch": "公共基础知识", "type": "single", "stem": "①当地球撞进尘埃带时，从地球上看，是短时间内无数尘埃以极高的速度划破大气层下落 ②因此，流星雨实际上是彗星留下的无数尘埃形成的 ③进入大气层的尘埃被大气加热，发出明亮的光 ④彗星释放出的尘埃，并非顷刻扩散到宇宙空间，消失得无影无踪，而是留在彗星的轨道上持续公转 ⑤这样看上去就有许多流星，也就是流星雨 ⑥这样形成的“尘埃带”，有些和地球的公转轨道交叉 将以上6个句子重新排列，语序正确的是（）", "options": [{"letter": "A", "text": "④②⑥③⑤①"}, {"letter": "B", "text": "①③④⑥⑤②"}, {"letter": "C", "text": "④⑥①③⑤②"}, {"letter": "D", "text": "①③⑤②④⑥"}], "answer": "C", "explanation": "正确语序为④⑥①③⑤②。④先说彗星释放的尘埃留在轨道上，⑥说明尘埃带与地球轨道交叉，①描述地球撞入尘埃带时的景象，③说明尘埃进入大气层发出光，⑤总结形成流星雨，②最终得出结论流星雨是彗星尘埃形成的。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1565}, {"num": 1567, "batch": "公共基础知识", "type": "single", "stem": "①我国的GDP总量早已位居世界前列，我国既是最大的石油进口国，也是最大的货物贸易国 ②它绝对是国家的核心武器，而且是不可或缺的战略武器 ③具有中远海作战能力和标志意义的航空母舰、两栖攻击舰等大型战舰的建造与运用，对于发展我国海上力量已刻不容缓 ④对于一个大国，特别是一个正从大国迈向强国的国家来说，航空母舰决非可有可无的作战平台或大型武器 ⑤我国的海洋利益仍在不断地拓展，越来越多的海外利益需要保护，越来越多的海上运输安全亟待维护 ⑥无论是历史还是现实，众多大国（例如美国、俄罗斯、英国等）的实例，都已充分证明了这一点 将以上6个句子重新排列，语序正确的是（）", "options": [{"letter": "A", "text": "④②⑥①⑤③"}, {"letter": "B", "text": "⑤①④⑥③②"}, {"letter": "C", "text": "①⑤⑥③④②"}, {"letter": "D", "text": "③④⑥②①⑤"}], "answer": "A", "explanation": "正确语序为④②⑥①⑤③。④先总论航母对大国的意义，②进一步强调其战略武器地位，⑥列举大国实例证明，①指出我国作为大国的现实背景，⑤说明海洋利益拓展的需求，③得出航母建造刻不容缓的结论。论述由一般到具体，逻辑严密。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1566}, {"num": 1568, "batch": "公共基础知识", "type": "single", "stem": "①影响生物寿命最关键的因素是基因②同种生物的自然寿命是类似的 ③从进化的角度看，这是生物在长期适应环境的过程中逐渐积累，通过自然选择而形成的 ④环境可以决定相关基因是否表达，而这些基因的表达与否，又会影响相应蛋白质的表达水平，由此控制生物的寿命 ⑤在这个前提下，个体的寿命则由环境决定 ⑥生物的寿命由遗传物质和环境因素共同决定，遗传物质是基础将以上6个句子重新排列，语序正确的是（）", "options": [{"letter": "A", "text": "②④①⑥③⑤"}, {"letter": "B", "text": "④⑤③②⑥①"}, {"letter": "C", "text": "①③④⑥⑤②"}, {"letter": "D", "text": "⑥①③②⑤④"}], "answer": "D", "explanation": "正确语序为⑥①③②⑤④。⑥总论生物寿命由遗传和环境共同决定，①强调基因是最关键因素，③从进化角度解释基因的作用，②说明同种生物寿命类似，⑤指出个体寿命由环境决定，④具体说明环境如何影响基因表达从而控制寿命。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1567}, {"num": 1569, "batch": "公共基础知识", "type": "single", "stem": "①用人的关键并不在于用这个人而不用那个人，而在于怎样使组织中的每个成员都能得到最适当的位置，发挥最大的潜能②在不同的情境和条件下，长与短都会向自己的对立面转化，长的可以变短，短的可以变长③扬长避短是用人的基本策略④这种长与短互换的规律，是长短辩证关系中最容易被人忽视的一部分⑤管理者的高明之处，就在于短中见长，善用其短⑥然而，在现实生活中，人的长处和短处并不是绝对的，没有静止不变的长，也没有一成不变的短。将以上6个句子重新排列，语序最恰当的是（）", "options": [{"letter": "A", "text": "③⑥②④①⑤"}, {"letter": "B", "text": "⑤④⑥②①③"}, {"letter": "C", "text": "②⑤④①③⑥"}, {"letter": "D", "text": "①⑤⑥③②④"}], "answer": "A", "explanation": "正确语序为③⑥②④①⑤。③首先提出扬长避短是用人基本策略，⑥转折指出长短并非绝对，②说明长短会相互转化，④强调这种转化规律容易被忽视，①得出用人的关键在于使每个成员发挥最大潜能，⑤总结管理者的高明在于善用其短。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1568}, {"num": 1570, "batch": "公共基础知识", "type": "single", "stem": "①最早的单质碘便是法国人从海藻中发现的，海藻也是最早的碘生产原料?；②我国大部分地区都缺碘，碘不足可能会引起甲状腺肿病和地方性克汀病；?③近年来，随着人们对食品纯天然的追求，海藻碘盐越来越受到欢迎?；④碘在自然界中比较稀少，但是海洋中的藻类却有较高的含碘量；?⑤碘是人体必需的微量元素之一，有“智力元素”之称?；⑥因此从1995年起，我国开始实施食盐强制加碘? 将以上六个句子重新排列，语序正确的是（??）", "options": [{"letter": "A", "text": "②⑤⑥③①④"}, {"letter": "B", "text": "③①④⑤②⑥"}, {"letter": "C", "text": "④③①⑤⑥②"}, {"letter": "D", "text": "⑤②⑥④①③"}], "answer": "D", "explanation": "正确语序为⑤②⑥④①③。⑤先介绍碘是人体必需微量元素，②说明我国大部分地区缺碘及危害，⑥因此从1995年起实施食盐强制加碘，④指出海洋藻类含碘量高，①介绍最早从海藻中发现碘并生产，③说明海藻碘盐越来越受欢迎。从碘的重要性到加碘政策再到海藻碘盐。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1569}, {"num": 1571, "batch": "公共基础知识", "type": "single", "stem": "2014年父亲、母亲的年龄之和是年龄之差的23倍，年龄之差是儿子年龄的1/5，5年后母亲和儿子的年龄都是平方数。问2014年父亲的年龄是多少（）（年龄都按整数计算）", "options": [{"letter": "A", "text": "36岁"}, {"letter": "B", "text": "40岁"}, {"letter": "C", "text": "44岁"}, {"letter": "D", "text": "48岁"}], "answer": "D", "explanation": "设2014年父母年龄差为d，则年龄和为23d，父亲年龄=(23d+d)/2=12d，母亲年龄=11d，儿子年龄=5d。5年后母亲年龄11d+5和儿子年龄5d+5都是平方数。当d=4时，母亲50岁（非平方数）不对；实际上11d+5=49=7的平方时d=4，5d+5=25=5的平方，父亲年龄=12x4=48岁。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1570}, {"num": 1572, "batch": "公共基础知识", "type": "single", "stem": "6,14,22，（），38,46", "options": [{"letter": "A", "text": "30"}, {"letter": "B", "text": "32"}, {"letter": "C", "text": "34"}, {"letter": "D", "text": "36"}], "answer": "A", "explanation": "该数列为等差数列，公差为14-6=8，22-14=8。因此空缺项为22+8=30，验证30+8=38，38+8=46，符合规律。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1571}, {"num": 1573, "batch": "公共基础知识", "type": "single", "stem": "A．工程队的效率是B．工程队的2倍，某工程交给两队共同完成需要6天。如果两队的工作效率均提高一倍，且B．队中途休息了1天，问要保证工程按原来的时间完成，A．队中途最多可以休息几天（）", "options": [{"letter": "A", "text": "4"}, {"letter": "B", "text": "3"}, {"letter": "C", "text": "2"}, {"letter": "D", "text": "1"}], "answer": "A", "explanation": "设B队效率为1，A队效率为2，则总工程量为(1+2)x6=18。效率翻倍后A为4、B为2，原时间6天完成。B队休息1天工作5天完成2x5=10，剩余18-10=8由A完成需8/4=2天。因此A队最多休息6-2-1=3天...实际A工作2天即可，休息6-2=4天（含B休息的1天A也可休息）。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1572}, {"num": 1574, "batch": "公共基础知识", "type": "single", "stem": "A地到B地的道路是下坡路。小周早上6︰00从A地出发匀速骑车前往B地，7︰00时到达两地正中间的C地。到达B地后，小周立即匀速骑车返回，在10︰00时又途经C地。此后小周的速度在此前速度的基础上增加1米/秒，最后在11︰30回到A地。问A、B两地间的距离在以下哪个范围内（）", "options": [{"letter": "A", "text": "40~50 公里"}, {"letter": "B", "text": "大于 50 公里"}, {"letter": "C", "text": "小于 30 公里"}, {"letter": "D", "text": "30~40 公里"}], "answer": "A", "explanation": "设AC=CB=d米。去程速度v=d/60米/分（6:00到7:00走d距离）。返程BC段用时2小时（8:00到10:00），速度为d/120米/分。CA段用时1.5小时（10:00到11:30），速度为d/120+60米/分（增加1米/秒=60米/分）。由d=90x(d/120+60)解得d=21600米=21.6公里，AB=2d=43.2公里，在40~50公里范围内。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1573}, {"num": 1575, "batch": "公共基础知识", "type": "single", "stem": "A公园规定，个人票每张10元，团体票每张60元（可供10人参观），无其他票价优惠政策。五年级二班共有58人逛A公园，则最少应付多少元？（）", "options": [{"letter": "A", "text": "350"}, {"letter": "B", "text": "360"}, {"letter": "C", "text": "380"}, {"letter": "D", "text": "390"}], "answer": "B", "explanation": "58人逛公园，个人票10元/张，团体票60元/10人。方案一：买5张团体票(50人)+8张个人票=300+80=380元；方案二：买6张团体票(60人)=360元。虽然6张团体票可进60人，多出2个名额，但总价360元少于380元，因此最少应付360元。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1574}, {"num": 1576, "batch": "公共基础知识", "type": "single", "stem": "癌症的发病与基因相关，如基因发生突变，变得过于活跃，会驱动癌症的发生，同理，如果抑癌基因发生突变，失去功能，也会促发癌症。PTEN是一种容易发生突变的抑癌基因，目前发现人体内有一种叫WWP1的E3泛素连接酶会与PTEN结合，影响其抑癌功能。抑制WWP1的功能，就能解放PTEN，恢复PTEN对癌症的抑制，从而起到抗癌作用。有研究证实，一种叫做“吲哚-3-甲醇”（I3C）的天然化合物能有效抑制WWP1的功能，而I3C在西兰花等十字花科植物中非常普遍。根据上述论述，以下哪项判断正确？（）", "options": [{"letter": "A", "text": "常吃西兰花等十字花科蔬菜有助于治疗癌症"}, {"letter": "B", "text": "WWP1含量越高，PTEN的含量越低"}, {"letter": "C", "text": "E3泛素连接酶通过对致癌基因的作用而影响癌症的发生"}, {"letter": "D", "text": "I3C有助于恢复PTEN的抑癌功能"}], "answer": "D", "explanation": "根据题干逻辑：WWP1与PTEN结合影响其抑癌功能，抑制WWP1可恢复PTEN的抑癌功能，I3C能抑制WWP1。因此I3C有助于恢复PTEN的抑癌功能。A项'治疗癌症'过度推断，原文只说有助于抗癌；B项WWP1与PTEN的关系不是简单的含量反比；C项E3泛素连接酶作用于抑癌基因PTEN而非致癌基因。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1575}, {"num": 1577, "batch": "公共基础知识", "type": "single", "stem": "按照相关规定，我国驻外大使由根据全国人民代表大会常务委员会的决定任免。", "options": [{"letter": "A", "text": "国家主席"}, {"letter": "B", "text": "国务院总理"}, {"letter": "C", "text": "全国人大常委会委员长"}, {"letter": "D", "text": "外交部部长"}], "answer": "A", "explanation": "根据《中华人民共和国宪法》第八十一条规定，中华人民共和国主席根据全国人民代表大会常务委员会的决定，派遣和召回驻外全权代表。因此我国驻外大使由国家主席根据全国人大常委会的决定任免。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1576}, {"num": 1578, "batch": "公共基础知识", "type": "single", "stem": "白纸、黑纸、镜子、红纸四种物体，吸收光的本领从强到弱依次是（）", "options": [{"letter": "A", "text": "白纸、黑纸、镜子、红纸"}, {"letter": "B", "text": "黑纸、红纸、白纸、镜子"}, {"letter": "C", "text": "镜子、白纸、红纸、黑纸"}, {"letter": "D", "text": "镜子、黑纸、红纸、白纸"}], "answer": "B", "explanation": "物体颜色越深，吸收光的能力越强；反射能力越强则吸收越少。黑纸几乎吸收所有色光，吸收最强；红纸吸收除红色外的其他色光；白纸几乎反射所有色光，吸收较少；镜子反射能力最强，吸收最少。因此吸收光本领从强到弱为：黑纸、红纸、白纸、镜子。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1577}, {"num": 1579, "batch": "公共基础知识", "type": "single", "stem": "百年来，大藏经在佛教研究中发挥了无可替代的作用，近代以来所产生的佛教研究成果均少不了大藏经的贡献。大藏经所收入的是历代编藏僧人过滤后的资料。从大藏经编纂的历史而言，早期的写本，重翻译域外佛典，轻中华佛教撰著；其后的刻本，虽然收入中华佛教撰著，但随意性较强；晚期的刻本，所收禅宗语录，可称浮滥。就总体而言，大藏经的功能兼具义理与信仰，其内涵则表现出重义理、轻信仰的倾向。 这段文字主要介绍大藏经（）", "options": [{"letter": "A", "text": "在佛教研究中的重要作用"}, {"letter": "B", "text": "在不同时期的特点"}, {"letter": "C", "text": "在资料方面存在的局限"}, {"letter": "D", "text": "所收录的佛典种类"}], "answer": "C", "explanation": "文段从大藏经的编纂历史入手，指出早期写本重翻译轻中华撰著、刻本随意性强、晚期刻本收录浮滥等问题，主要介绍大藏经在资料方面存在的局限性。虽然也提及了大藏经的作用和不同时期特点，但重点在于揭示其资料方面的不足。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1578}, {"num": 1580, "batch": "公共基础知识", "type": "single", "stem": "保持党的先进性和纯洁性，解决党自身存在的突出问题，要克服“四种危险”。这四种危险是（）", "options": [{"letter": "A", "text": "精神懈怠、能力不足、脱离群众、消极腐败"}, {"letter": "B", "text": "享乐主义、官僚主义、形式主义、奢靡之风"}, {"letter": "C", "text": "弄虚作假、贪图虚名、讲究排场、情趣低级"}, {"letter": "D", "text": "脱离实际、脱离群众、自我膨胀、追名逐利"}], "answer": "A", "explanation": "党面临的'四种危险'是：精神懈怠的危险、能力不足的危险、脱离群众的危险、消极腐败的危险。这是党的十八大明确提出的，是党面临的重大考验。B项'四风'（享乐主义、官僚主义、形式主义、奢靡之风）是另一组概念。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1579}, {"num": 1581, "batch": "公共基础知识", "type": "single", "stem": "北京市已探索出一套保障和提升“接诉即办”效率的机制，定期分析研判群众诉求，对群众反映集中的热点问题加大“点穴”式督办力度，并将相关考核数据分别纳入各部门党组织书记年度考核和政府年度绩效考评。这一做法意在（）①推动各部门切实改进工作作风，保障“接诉即办”的效果②指导各部门把量化指标作为唯一依据开展各项工作③进一步创新政府绩效考评体系，强化政府在“接诉即办”效果评估中的主导地位④通过排名传导压力，形成各部门努力解决问题的态势", "options": [{"letter": "A", "text": "①②"}, {"letter": "B", "text": "②③"}, {"letter": "C", "text": "②④"}, {"letter": "D", "text": "①④"}], "answer": "D", "explanation": "①正确，考核数据纳入书记年度考核和绩效考评旨在推动各部门改进作风；④正确，通过排名传导压力形成解决问题的态势。②错误，'唯一依据'过于绝对；③错误，材料未体现'强化政府主导地位'之意。因此①④正确。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1580}, {"num": 1582, "batch": "公共基础知识", "type": "single", "stem": "北京天然河道自西向东有五大水系，其中位于最西部的水系是（）", "options": [{"letter": "A", "text": "北运河水系"}, {"letter": "B", "text": "永定河水系"}, {"letter": "C", "text": "潮白河水系"}, {"letter": "D", "text": "拒马河水系"}], "answer": "D", "explanation": "北京天然河道自西向东有五大水系：拒马河水系、永定河水系、北运河水系、潮白河水系和蓟运河水系。拒马河水系位于最西部，是北京五大水系中最西侧的水系。拒马河发源于太行山，流经房山区等地。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1581}, {"num": 1583, "batch": "公共基础知识", "type": "single", "stem": "必须牢固树立和践行绿水青山就是金山银山的理念，站在人与自然（）的高度谋划发展。", "options": [{"letter": "A", "text": "和谐共存"}, {"letter": "B", "text": "和谐共生"}, {"letter": "C", "text": "和谐共处"}, {"letter": "D", "text": "和谐共融"}], "answer": "B", "explanation": "党的二十大报告明确指出，必须牢固树立和践行绿水青山就是金山银山的理念，站在人与自然和谐共生的高度谋划发展。'和谐共生'是生态文明建设的核心理念，强调人与自然相互依存、共同发展。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1582}, {"num": 1584, "batch": "公共基础知识", "type": "single", "stem": "必须完整、准确、全面贯彻新发展理念，坚持社会主义市场经济改革方向，坚持高水平对外开放，加快构建以国内大循环为（）、国内国际双循环相互促进的新发展格局。", "options": [{"letter": "A", "text": "载体"}, {"letter": "B", "text": "主体"}, {"letter": "C", "text": "基础"}, {"letter": "D", "text": "首要"}], "answer": "B", "explanation": "党的二十大报告指出，加快构建以国内大循环为主体、国内国际双循环相互促进的新发展格局。'主体'强调国内大循环在双循环中的核心地位，是构建新发展格局的关键表述。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1583}, {"num": 1585, "batch": "公共基础知识", "type": "single", "stem": "必须增强忧患意识，坚持（），做到居安思危、未雨绸缪，准备经受风高浪急甚至惊涛骇浪的重大考验。", "options": [{"letter": "A", "text": "底线思维"}, {"letter": "B", "text": "辩证思维"}, {"letter": "C", "text": "创新思维"}, {"letter": "D", "text": "法治思维"}], "answer": "A", "explanation": "党的二十大报告指出，必须增强忧患意识，坚持底线思维，做到居安思危、未雨绸缪，准备经受风高浪急甚至惊涛骇浪的重大考验。底线思维要求从最坏处着眼、做最充分准备，争取最好的结果。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1584}, {"num": 1586, "batch": "公共基础知识", "type": "single", "stem": "不管是什么食品，都会有一个保质期，过了这个保质期就不能再食用。然而有的时候，食品保质期会有不一样的含义。这个问题你肯定从未注意过，有可能导致你扔掉了很多还可以食用的食品，造成了你经济的损失，也浪费了食物。这段文字是一篇文章的开头，接下来最可能讲的是（）", "options": [{"letter": "A", "text": "食品保质期的确定标准"}, {"letter": "B", "text": "鉴别食品保质期的方法"}, {"letter": "C", "text": "怎样避免食物的浪费"}, {"letter": "D", "text": "如何正确理解保质期"}], "answer": "D", "explanation": "文段开头指出食品保质期有不一样的含义，人们可能因此误扔可食用食品造成损失，这是一个引出问题的开头。按照行文逻辑，接下来最可能具体讲解如何正确理解保质期的不同含义，帮助读者避免浪费。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1585}, {"num": 1587, "batch": "公共基础知识", "type": "single", "stem": "不规则需求是指某些物品或者服务的市场需求在不同季节，或一周不同日子，甚至一天不同时间上下波动很大的一种需求状况。 根据上述定义，下列哪项属于不规则需求？", "options": [{"letter": "A", "text": "早晚高峰期出租车供不应求"}, {"letter": "B", "text": "某电商店庆打折，活动当天点击量剧增"}, {"letter": "C", "text": "某博物馆引进一批梵高画作巡展，游客蜂拥而至"}, {"letter": "D", "text": "某品牌牙刷分为软、硬、中三种以面向不同消费者"}], "answer": "A", "explanation": "不规则需求的关键特征是市场需求在时间上（季节、周、日）上下波动。A项早晚高峰期出租车供不应求，体现了需求在一天不同时间的波动，符合不规则需求的定义。B项是促销导致的短期激增，C项是展览引起的临时变化，D项是市场细分策略。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1586}, {"num": 1588, "batch": "公共基础知识", "type": "single", "stem": "不久前，“水电费纳入征信”的传闻引起了公众的广泛关注。从现有社会经济活动的精细程度看，征信这种数字式指标性评价，未必能穷尽经济生活中的所有可能性。疏忽、出差、留学、搬家、住院乃至因纠纷而暂停缴纳，均有可能造成水电费的拖欠，显然，这些突发状况未必就能准确体现“个人信用”。倘若将这些指标以一种窄口径列入统计，就有可能造成误伤。正因为突发情况多，作为社会服务部门，更要尽到足够的提示、通知责任，并提供充足、便捷的补救渠道。在相关准备不充分时，水电费纳入征信理应审慎推进。这段文字意在说明（）", "options": [{"letter": "A", "text": "选取征信指标应做到谨慎合理"}, {"letter": "B", "text": "当下水电费不宜纳入征信系统"}, {"letter": "C", "text": "服务工作的精细程度有待提高"}, {"letter": "D", "text": "征信系统与日常活动密切相关"}], "answer": "B", "explanation": "文段指出水电费拖欠可能由多种突发情况导致，未必能准确体现个人信用，窄口径列入可能造成误伤，因此主张在相关准备不充分时水电费纳入征信应审慎推进。文段的核心观点是当下水电费不宜贸然纳入征信系统。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1587}, {"num": 1589, "batch": "公共基础知识", "type": "single", "stem": "不论是以巴尔扎克为代表的19世纪欧洲文学，还是以鲁迅为先导的中国现代文学，多半高擎现实主义 大旗开垦生活，塑造典型。新时期以来的文学创作，基本也都坚守现实主义立场，比较善于揭露、针砭生活中的负面客观真实，这是完全必要且非常宝贵的。然而，部分小说缺乏对生活中积极因素和正面形象的塑造，缺少对正面价值和情感的呼吁。其实，现实主义创作以人道主义思想为武器，不仅注重剖析社会的阴暗面，也应注重展示生活的亮点；不仅看重批判社会阴暗面的准确性和深刻性，也更看重作家对人物命运的关怀和同情。这段文字主要批评了新时期以来文学创作中哪个方面的问题（）", "options": [{"letter": "A", "text": "典型人物的塑造过于刻板单一"}, {"letter": "B", "text": "作家缺乏对现实生活的关注"}, {"letter": "C", "text": "缺乏对优秀文学传统的继承"}, {"letter": "D", "text": "部分小说存在消极负面的倾向"}], "answer": "D", "explanation": "文段先肯定现实主义文学的宝贵传统，然后用'然而'转折，指出部分小说缺乏对积极因素和正面形象的塑造，缺少对正面价值的呼吁。最后强调现实主义创作不仅应剖析阴暗面，也应展示亮点和关怀。文段主要批评的是部分小说存在消极负面的倾向。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1588}, {"num": 1590, "batch": "公共基础知识", "type": "single", "stem": "产品责任是指产品有缺陷，存在可能危及人身、财产安全的危险，造成产品的消费者、使用者或其他第三者人身或其他直接财产损失后，缺陷产品的生产者、销售者应当承担的特殊的侵权法律责任。根据上述定义，下列受害人可因产品责任要求侵权损害赔偿的是（）", "options": [{"letter": "A", "text": "甲购买了一辆新车，一次与朋友王某驾车外出时，汽车因电路质量问题发生自燃，致使王某被烧伤"}, {"letter": "B", "text": "乙购买了一件大衣，大衣上没有洗涤标志和成分说明，营业员也未告知应如何洗涤。大衣水洗后严重缩水"}, {"letter": "C", "text": "丙购买了一部新手机，一次因质量问题自动关机，无法开启，致使丙漏接了客户的电话，损失了一笔大额订单"}, {"letter": "D", "text": "丁的电视机使用了 20 年，图像不清晰时拍打几下就好了。一次丁在拍打电视机时，电视机发生爆炸，将丁炸伤，后经检验发现是显像管老化造成的"}], "answer": "A", "explanation": "产品责任的构成要件包括：产品存在缺陷、造成人身或财产损害、缺陷与损害之间有因果关系。A项汽车因电路质量缺陷自燃致人受伤，完全符合产品责任的要件。B项属于标识缺陷导致的财产损失但主要是洗涤不当；C项属于间接经济损失；D项产品已使用20年，显像管老化非产品原始缺陷。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1589}, {"num": 1591, "batch": "公共基础知识", "type": "single", "stem": "超前纠结指的是在平庸的人群中，有正确洞见的人当其观点不被接受、不被相信，对事情的发展无能为力时，所表现出的无奈、压抑和痛苦的心情。根据上述定义，下列最能体现超前纠结的是（）", "options": [{"letter": "A", "text": "古来圣贤皆寂寞，惟有饮者留其名"}, {"letter": "B", "text": "举世皆浊我独清，世人皆醉我独醒"}, {"letter": "C", "text": "无可奈何花落去，似曾相识燕归来"}, {"letter": "D", "text": "醉卧沙场君莫笑，古来征战几人回"}], "answer": "B", "explanation": "超前纠结的定义要素：在平庸人群中有正确洞见、观点不被接受、无能为力、无奈压抑痛苦。B项'举世皆浊我独清，世人皆醉我独醒'出自屈原《渔父》，表达了众人皆醉我独醒的正确洞见不被世人接受的孤独与痛苦，最符合超前纠结的定义。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1590}, {"num": 1592, "batch": "公共基础知识", "type": "single", "stem": "沉积物基准是指特定化学物质在沉淀物中不对底栖生物或上覆水体质量产生危害的实际允许浓度，它既是对水质基准的完善，也是评价沉积物污染和生态风险的基础，是进行湖泊生态环境质量评价的基本要素。国外对沉积物基准的研究始于20世纪80年代，但还未形成完善和统一的沉积物基准体系。由于沉积物中污染物的迁移、转化、生物累积过程及界面过程的复杂性，目前仍缺乏关键的研究手段。国内已有不少科学家做了大量有益的探索，但研究仍然比较零散，还没有国家主管部门颁布湖泊沉积物基准规范。 这段文字意在说明的是（）", "options": [{"letter": "A", "text": "亟需弥补现有沉积物基准体系不足"}, {"letter": "B", "text": "沉积物基准非常重要但研究未成体系"}, {"letter": "C", "text": "沉积物基准为湖泊水环境重要研究内容"}, {"letter": "D", "text": "沉积物基准的相关研究已经有较多进展"}], "answer": "A", "explanation": "文段先阐述沉积物基准的重要性，然后指出国外研究未成体系、国内研究零散且无国家规范。文段意在说明沉积物基准虽重要但研究尚未形成体系，亟需弥补现有不足，建立完善的沉积物基准体系。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1591}, {"num": 1593, "batch": "公共基础知识", "type": "single", "stem": "痴呆是一种以认知功能缺损为核心症状的获得性智能损害综合征，其智能损害的程度足以干扰社会或职业功能，是慢性进展性的疾病，损害的范围涉及记忆、行为、人格、判断、注意力、视空间技能、语言、逻辑推理等多种高级神经功能。据统计，痴呆已成为仅次于心血管疾病，癌症和脑猝的第四大杀手，严重威胁老年人身体健康和生活质量。年龄，是老年性痴呆的重要危险因素，一般认为，60岁以上的人群中，每增加5岁，痴呆的患病率将增加1倍。随着老年人口的不断增加，老年痴呆将成为我国一个严重的公共卫生问题。 根据这段文字，以下说法正确的是（）", "options": [{"letter": "A", "text": "老年性痴呆有时会突然发病"}, {"letter": "B", "text": "痴呆发病率与受教育程度有关"}, {"letter": "C", "text": "痴呆患者的基本生活能力可以改善"}, {"letter": "D", "text": "我国老年痴呆患者的人数将不断上涨"}], "answer": "D", "explanation": "根据文段，痴呆是慢性进展性疾病，A项'突然发病'错误；文段未提及受教育程度与发病率的关系，B项无依据；C项'可以改善'文段未提及。文段指出随着老年人口不断增加，老年痴呆将成为严重公共卫生问题，因此D项'我国老年痴呆患者人数将不断上涨'正确。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1592}, {"num": 1594, "batch": "公共基础知识", "type": "single", "stem": "初级群体指的是由面对面互动所形成的、具有亲密的人际关系和浓厚的感情色彩的社会群体；次级群体指的是其成员为了某种特定的目标集合在一起，通过明确的规章制度结成正规关系的社会群体。 根据上述定义，下列涉及次级群体的是（）", "options": [{"letter": "A", "text": "小赵要到大城市上学了，山里的乡亲们都到村口为他送行"}, {"letter": "B", "text": "20年之后，小张儿时的玩伴建立了一个微信群"}, {"letter": "C", "text": "亲友团来到比赛现场为小李助威"}, {"letter": "D", "text": "小王考上了研究生，公司的同事一起为他庆贺"}], "answer": "D", "explanation": "次级群体的关键特征是为特定目标集合、通过明确规章制度结成正规关系。A项乡亲们属于初级群体（亲密人际关系）；B项儿时玩伴群基于感情联系；C项亲友团基于亲情关系；D项公司同事是通过公司规章制度结成的正规关系，属于次级群体。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1593}, {"num": 1595, "batch": "公共基础知识", "type": "single", "stem": "下列诗句提及的著名关隘，不在长城上的是（）", "options": [{"letter": "A", "text": "居庸关上子规啼，饮马流泉落日低"}, {"letter": "B", "text": "羌笛何须怨杨柳，春风不度玉门关"}, {"letter": "C", "text": "峰峦如聚，波涛如怒，山河表里潼关路"}, {"letter": "D", "text": "山一程，水一程，身向榆关那畔行，夜深千帐灯"}], "answer": "C", "explanation": "潼关位于陕西省渭南市，地处关中平原东部，是关中地区的东大门，不属于长城上的关隘。居庸关、玉门关、榆关（山海关）都是长城上的著名关隘。'山河表里潼关路'出自张养浩《山坡羊·潼关怀古》。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1594}, {"num": 1596, "batch": "公共基础知识", "type": "single", "stem": "传统饱和打击战术的核心，是从不同方向、不同层次向同一目标发射超出其防御上限的导弹，以数量优势形成绝对力量优势，压迫及摧毁其防御体系，对敌重要目标进行毁灭性打击。该战术需要庞大的火力投射平台和充足的武器弹药作支撑，这让世界上大多数国家（）", "options": [{"letter": "A", "text": "望而却步"}, {"letter": "B", "text": "无可奈何"}, {"letter": "C", "text": "束手无策"}, {"letter": "D", "text": "裹足不前"}], "answer": "A", "explanation": "'望而却步'指看到危险或困难而退缩不前，符合语境中大多数国家因饱和打击战术需要庞大火力平台和充足弹药而无法实施的状况。'无可奈何'强调没有办法；'束手无策'强调毫无办法；'裹足不前'强调因顾虑而不前行。'望而却步'最能体现因条件限制而退缩的含义。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1595}, {"num": 1597, "batch": "公共基础知识", "type": "single", "stem": "此前，美国《科学》杂志均由其编辑部评出每年的“十大科学突破”，但2014年增加了两轮网友投票环节。第一轮投票中，欧洲探测彗星的“罗塞塔”任务获得最多投票，第二和第三名分别是可以返老还童的“年轻血液”和可能开启糖尿前几天治疗新途径的细胞；第二轮投票中，“年轮血液”一开始领跑，但最终被生命基因密码“添丁”反超，“罗塞塔”任务仅排在第三。但最终，《科学》杂志还是选择“罗塞塔”任务作为2014年头号科学突破，因为罗塞塔探测器释放着陆器“菲莱”登陆彗星是一个惊人壮举，吸引了全世界的关注。由上述文字可知的是（）", "options": [{"letter": "A", "text": "《科学》杂志与网友判断科学突破的标准存在差异"}, {"letter": "B", "text": "2014年美国在生命科学研究方面取得重大突破"}, {"letter": "C", "text": "可治疗糖尿病的细胞在经过两轮投票后最终落选"}, {"letter": "D", "text": "普通大众对探索外太空的努力已经失去兴趣"}], "answer": "B", "explanation": "文段提到网友投票中生命科学项目（年轻血液、细胞治疗）排名靠前，但最终《科学》杂志选择了太空探索项目罗塞塔任务。由此可以推知B项正确——2014年美国在生命科学研究方面取得了重大突破（年轻血液和细胞治疗研究均进入投票前列）。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1596}, {"num": 1598, "batch": "公共基础知识", "type": "single", "stem": "从监控摄像机到无人机，很多城市已在公共安全领域使用人工智能技术。相关研究人员称，到2030年，人们会高度依赖“预言性监管”。机器学习技术可使电脑自主学习，该技术已在打击犯罪活动实践中起到了重要作用。同时，机器学习技术还能够极大地提高人工智能预测犯罪事件的能力，包括犯罪的时间、地点和人物等。 这段文字主要说的是（）", "options": [{"letter": "A", "text": "“预言性监管”不久之后将会成为现实"}, {"letter": "B", "text": "机器学习对打击犯罪活动的意义"}, {"letter": "C", "text": "人工智能技术对公共安全的作用"}, {"letter": "D", "text": "人工智能技术是打击犯罪的新型武器"}], "answer": "B", "explanation": "文段从人工智能技术在公共安全领域的应用切入，重点阐述了机器学习技术使电脑自主学习、提高预测犯罪能力的作用。文段的核心在于强调机器学习技术对打击犯罪活动的重要意义，而非泛泛讨论人工智能对公共安全的作用。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1597}, {"num": 1599, "batch": "公共基础知识", "type": "single", "stem": "从陆地到天空，从恐龙到鸟类，生物的生态习性发生了巨大改变，身体结构也有了天壤之别。若非有一系列介于两者之间的过渡物种让人（），即便熟读《物种起源》，笃信达尔文的演化理论，也仍然会对“恐龙是鸟类的祖先”的说法（）。", "options": [{"letter": "A", "text": "无可辩驳、充耳不闻"}, {"letter": "B", "text": "心服口服、置之不理"}, {"letter": "C", "text": "不置可否、不以为然"}, {"letter": "D", "text": "眼见为实、将信将疑"}], "answer": "D", "explanation": "文段意为：如果有过渡物种作为证据，人们就会信服；如果没有这些证据，即使相信进化论也会对'恐龙是鸟类祖先'的说法持怀疑态度。'眼见为实'对应过渡物种提供的直观证据，'将信将疑'对应没有证据时的半信半疑状态，符合语境逻辑。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1598}, {"num": 1600, "batch": "公共基础知识", "type": "single", "stem": "从一个装有水的水池中向外排水，规定每周二、四、六每天排出剩余水量的1/3，其余日期每天排出剩余水量的1/2。如此连续操作6天后，水池中剩余相当于总容量1/72的水。问最开始时水池中的水量最多相当于总容量的（）", "options": [{"letter": "A", "text": "1/4"}, {"letter": "B", "text": "3/8"}, {"letter": "C", "text": "1/2"}, {"letter": "D", "text": "5/8"}], "answer": "C", "explanation": "设水池总容量为1，排水规则为周二四六排1/3（剩2/3），其余日排1/2（剩1/2）。连续操作6天后剩余1/72。要使初始水量最多，应让排水少的日子尽可能多。从周日开始连续6天（日一二三四五），排水日（二四）排1/3，其余（日一三五）排1/2。设初始水量x，则x*(1/2)^4*(2/3)^2=1/72，解得x=1/2。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1599}, {"num": 1601, "batch": "公共基础知识", "type": "single", "stem": "大数据是指规模极其巨大，以致很难通过一般软件工具加以获取、管理、处理并整理成为有用资讯的海量数据。其具有大量、高速、多样和价值四个特点，被认为是人类新世纪的“新财富”，价值“堪比石油”，发达国家纷纷将开发利用大数据作为夺取新一轮制高点的重要目标，就是个明证。 这段文字意在说明（）", "options": [{"letter": "A", "text": "大数据在处理上还存在技术难度"}, {"letter": "B", "text": "大数据背后隐藏着巨大的价值"}, {"letter": "C", "text": "发达国家在开发利用大数据上已经先行一步"}, {"letter": "D", "text": "开发利用大数据已成为国家竞争的一个热点"}], "answer": "B", "explanation": "文段先介绍大数据的定义，接着指出其具有大量、高速、多样和价值四个特点，然后强调大数据是新财富，价值堪比石油，最后以发达国家纷纷将开发利用大数据作为夺取制高点的目标来佐证。全文的核心意图在于说明大数据背后隐藏着巨大的价值，故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1600}, {"num": 1602, "batch": "公共基础知识", "type": "single", "stem": "单工通信是指发送端和接收端的身份是固定的，发送端只能发送信息，不能接收信息。接收端只能接收信息，不能发送信息，数据信号仅从一段传送到另一端，即信息流是单方向的。 根据上述定义，下列不属于单工通信的是（）", "options": [{"letter": "A", "text": "校园广播"}, {"letter": "B", "text": "对讲机通话"}, {"letter": "C", "text": "收音机收听电台"}, {"letter": "D", "text": "电视机遥控器切换频道"}], "answer": "B", "explanation": "单工通信的关键特征是信息只能单方向传输，发送端和接收端身份固定。校园广播、收音机收听电台、电视机遥控器切换频道均为单向信息传输，属于单工通信。对讲机通话可以双向交流，发送端和接收端可以互换，不属于单工通信，故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1601}, {"num": 1603, "batch": "公共基础知识", "type": "single", "stem": "下列有关中国古代建筑的说法错误的是（）", "options": [{"letter": "A", "text": "楼是“重屋”，指的是两层及以上的建筑物"}, {"letter": "B", "text": "阁是一种半开放的建筑，常建于水边供人们赏景"}, {"letter": "C", "text": "舫是仿照船型而造的一种建筑，又被称为“不系舟”"}, {"letter": "D", "text": "亭一般为开敞性结构，没有围墙，顶部可分为六角、八角等形状"}], "answer": "B", "explanation": "阁是一种底部架空的木构建筑，常用于藏书或供佛，如天一阁、滕王阁等，并非专指建于水边供人赏景的半开放建筑。建于水边供人赏景的建筑应为'榭'，而非'阁'。A、C、D项关于楼、舫、亭的描述均正确，故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1602}, {"num": 1604, "batch": "公共基础知识", "type": "single", "stem": "当今世界，处于百年未有之大变局。世界多极化、经济全球化（），人类的命运紧密相联，各国利益深度融合。但同时，各种挑战也日益严峻。变局之中，要合作还是要对立，要开放还是要封闭，要互利共赢还是要（），人类发展处在何去何从的十字路口。", "options": [{"letter": "A", "text": "有目共睹、各行其是"}, {"letter": "B", "text": "高歌猛进、独善其身"}, {"letter": "C", "text": "方兴未艾、两败俱伤"}, {"letter": "D", "text": "势不可挡、以邻为壑"}], "answer": "D", "explanation": "第一空形容世界多极化、经济全球化的趋势，'势不可挡'意为来势迅猛，不可抵挡，符合语境。第二空与'互利共赢'构成反义对应，'以邻为壑'比喻只图自己利益，把困难和祸害转嫁给别人，与'互利共赢'形成鲜明对比，符合文意，故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1603}, {"num": 1605, "batch": "公共基础知识", "type": "single", "stem": "当前，对于大部分消费者来说，智能化家居产品既熟悉又陌生，很多人的概念还停留在电动窗帘或别墅防盗系统。从技术层面来说，一键控制、远程遥控、感应人体、自动开启这些电影里才出现的产品如今并非“高科技”，但由于价格昂贵等原因，智能家居并未普及。 根据这段文字，以下说法正确的是（）", "options": [{"letter": "A", "text": "智能化已成为家居业未来的发展方向"}, {"letter": "B", "text": "目前技术上实现智能家居已无屏障"}, {"letter": "C", "text": "普及智能家居必须降低生产成本"}, {"letter": "D", "text": "智能家居的概念模糊影响其普及程度"}], "answer": "B", "explanation": "文段指出'从技术层面来说，一键控制、远程遥控、感应人体、自动开启这些产品如今并非高科技'，说明在技术层面实现智能家居已经没有障碍，只是由于价格昂贵等原因尚未普及。A项'未来方向'、C项'降低成本'、D项'概念模糊'均非文段直接表述的内容，故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1604}, {"num": 1606, "batch": "公共基础知识", "type": "single", "stem": "党的二十大报告强调，加快实施创新驱动发展战略，加快实现高水平科技自立自强，要以（）为导向，集聚力量进行原创性引领性科技攻关，坚决打赢关键核心技术攻坚战。", "options": [{"letter": "A", "text": "社会需求"}, {"letter": "B", "text": "人民需求"}, {"letter": "C", "text": "部队需求"}, {"letter": "D", "text": "国家战略需求"}], "answer": "D", "explanation": "党的二十大报告明确指出，加快实施创新驱动发展战略，要以国家战略需求为导向，集聚力量进行原创性引领性科技攻关，坚决打赢关键核心技术攻坚战。这体现了科技创新服务于国家重大战略需求的导向，故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1605}, {"num": 1607, "batch": "公共基础知识", "type": "single", "stem": "党的二十大报告指出，（），是全面建设社会主义现代化国家的内在要求。", "options": [{"letter": "A", "text": "敬畏自然、尊重自然、爱护自然"}, {"letter": "B", "text": "尊重自然、顺应自然、保护自然"}, {"letter": "C", "text": "敬畏自然、尊重自然、顺应自然"}, {"letter": "D", "text": "尊重自然、爱护自然、顺应自然"}], "answer": "B", "explanation": "党的二十大报告原文指出：'尊重自然、顺应自然、保护自然，是全面建设社会主义现代化国家的内在要求。'这是生态文明建设的核心理念，强调人与自然和谐共生的现代化道路，故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1606}, {"num": 1608, "batch": "公共基础知识", "type": "single", "stem": "党的二十大报告指出，（）是全面建设社会主义现代化国家的基础性、战略性支撑。", "options": [{"letter": "A", "text": "经济、人才、科技"}, {"letter": "B", "text": "创新、教育、科技"}, {"letter": "C", "text": "教育、科技、人才"}, {"letter": "D", "text": "科技、创新、人才"}], "answer": "C", "explanation": "党的二十大报告明确指出：'教育、科技、人才是全面建设社会主义现代化国家的基础性、战略性支撑。'三者统一于创新型国家建设之中，体现了党对现代化建设规律认识的深化，故选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1607}, {"num": 1609, "batch": "公共基础知识", "type": "single", "stem": "党的二十大报告指出，（）是我们立党立国、兴党兴国的根本指导思想。", "options": [{"letter": "A", "text": "列宁主义"}, {"letter": "B", "text": "实事求是"}, {"letter": "C", "text": "邓小平理论"}, {"letter": "D", "text": "马克思主义"}], "answer": "D", "explanation": "党的二十大报告指出：'马克思主义是我们立党立国、兴党兴国的根本指导思想。'马克思主义揭示了人类社会发展规律，为中国革命、建设和改革提供了科学理论指导，故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1608}, {"num": 1610, "batch": "公共基础知识", "type": "single", "stem": "党的二十大报告指出，坚持不懈用新时代中国特色社会主义思想凝心铸魂，全面加强党的思想建设，加强理想信念教育，引导全党牢记党的宗旨，自觉做共产主义远大理想和中国特色社会主义共同理想的坚定（）和忠实（）。", "options": [{"letter": "A", "text": "捍卫者 拥护者"}, {"letter": "B", "text": "维护者 实践者"}, {"letter": "C", "text": "实践者 传播者"}, {"letter": "D", "text": "信仰者 实践者"}], "answer": "D", "explanation": "党的二十大报告原文指出，要加强理想信念教育，引导全党牢记党的宗旨，自觉做共产主义远大理想和中国特色社会主义共同理想的坚定信仰者和忠实实践者。'信仰者'强调内心信念，'实践者'强调行动落实，二者缺一不可，故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1609}, {"num": 1611, "batch": "公共基础知识", "type": "single", "stem": "党的二十大报告指出，经过接续奋斗，实现了小康这个中华民族的千年梦想，打赢了人类历史上规模最大的脱贫攻坚战，历史性地解决了（）问题，为全球减贫事业作出了重大贡献。", "options": [{"letter": "A", "text": "绝对贫困"}, {"letter": "B", "text": "相对贫困"}, {"letter": "C", "text": "最大贫困"}, {"letter": "D", "text": "极端贫困"}], "answer": "A", "explanation": "党的二十大报告指出，经过接续奋斗，打赢了人类历史上规模最大的脱贫攻坚战，历史性地解决了绝对贫困问题，为全球减贫事业作出了重大贡献。'绝对贫困'是指基本生活需求无法满足的状态，区别于'相对贫困'，故选A。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1610}, {"num": 1612, "batch": "公共基础知识", "type": "single", "stem": "党的二十大报告指出，全党必须牢记，坚持（）是坚持和发展中国特色社会主义的必由之路，中国特色社会主义是实现中华民族伟大复兴的必由之路，团结奋斗是中国人民创造历史伟业的必由之路，贯彻新发展理念是新时代我国发展壮大的必由之路，（）是党永葆生机活力、走好新的赶考之路的必由之路。", "options": [{"letter": "A", "text": "党的领导 依法治国"}, {"letter": "B", "text": "党的全面领导 全面从严治党"}, {"letter": "C", "text": "党的全面领导 依法治国"}, {"letter": "D", "text": "党的领导 全面从严治党"}], "answer": "B", "explanation": "党的二十大报告提出的'五个必由之路'：坚持党的全面领导是坚持和发展中国特色社会主义的必由之路，全面从严治党是党永葆生机活力、走好新的赶考之路的必由之路。五个必由之路系统阐明了新时代的重要规律，故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1611}, {"num": 1613, "batch": "公共基础知识", "type": "single", "stem": "党的二十大报告指出，全面建设社会主义现代化国家，是一项伟大而艰巨的事业，前途光明，任重道远。我们必须增强（），坚持（），做到居安思危、未雨绸缪，准备经受风高浪急甚至惊涛骇浪的重大考验。", "options": [{"letter": "A", "text": "安全意识 战略思维"}, {"letter": "B", "text": "责任意识 系统思维"}, {"letter": "C", "text": "忧患意识 底线思维"}, {"letter": "D", "text": "担当意识 精准思维"}], "answer": "C", "explanation": "党的二十大报告指出，全面建设社会主义现代化国家，必须增强忧患意识，坚持底线思维，做到居安思危、未雨绸缪。'忧患意识'强调对潜在风险的警觉，'底线思维'强调从最坏处准备、向最好处努力，故选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1612}, {"num": 1614, "batch": "公共基础知识", "type": "single", "stem": "党的二十大报告指出，人民民主是社会主义的（），是全面建设社会主义现代化国家的应有之义。", "options": [{"letter": "A", "text": "根本"}, {"letter": "B", "text": "生命"}, {"letter": "C", "text": "基础"}, {"letter": "D", "text": "灵魂"}], "answer": "B", "explanation": "党的二十大报告指出：'人民民主是社会主义的生命，是全面建设社会主义现代化国家的应有之义。'将人民民主比作社会主义的'生命'，强调没有民主就没有社会主义，体现了人民民主的极端重要性，故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1613}, {"num": 1615, "batch": "公共基础知识", "type": "single", "stem": "党的二十大报告指出，十八大以来，我们党勇于进行理论探索和创新，以全新的视野深化对共产党（）规律、社会主义（）规律、人类社会（）规律的认识，取得重大理论创新成果，集中体现为新时代中国特色社会主义思想。", "options": [{"letter": "A", "text": "建设、执政、发展"}, {"letter": "B", "text": "发展、建设、执政"}, {"letter": "C", "text": "建设、发展、执政"}, {"letter": "D", "text": "执政、建设、发展"}], "answer": "D", "explanation": "党的二十大报告指出，十八大以来我们党深化对共产党执政规律、社会主义建设规律、人类社会发展规律的认识。三个规律的排列顺序为'执政、建设、发展'，集中体现为新时代中国特色社会主义思想，故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1614}, {"num": 1616, "batch": "公共基础知识", "type": "single", "stem": "党的二十大报告指出，实施（），强化就业优先政策，健全就业公共服务体系，加强困难群体就业兜底帮扶，消除影响平等就业的不合理限制和就业歧视，使人人都有通过勤奋劳动实现自身发展的机会。", "options": [{"letter": "A", "text": "科教兴国战略就业优先战略"}, {"letter": "B", "text": "人才强国战略"}, {"letter": "C", "text": "乡村振兴战略"}], "answer": "B", "explanation": "党的二十大报告指出，实施就业优先战略，强化就业优先政策，健全就业公共服务体系，使人人都有通过勤奋劳动实现自身发展的机会。就业优先战略强调将就业作为经济社会发展的优先目标，体现以人民为中心的发展思想。根据报告原文，正确答案应为'就业优先战略'，故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1615}, {"num": 1617, "batch": "公共基础知识", "type": "single", "stem": "党的二十大报告指出，我们要办好人民满意的教育，全面贯彻党的教育方针，落实立德树人根本任务，培养德智体美劳全面发展的社会主义建设者和接班人，加快建设高质量教育体系，发展（），促进教育公平。", "options": [{"letter": "A", "text": "基础教育"}, {"letter": "B", "text": "义务教育"}, {"letter": "C", "text": "职业教育"}, {"letter": "D", "text": "素质教育"}], "answer": "D", "explanation": "党的二十大报告指出，要发展素质教育，促进教育公平。素质教育强调德智体美劳全面发展，是落实立德树人根本任务的重要途径，区别于应试教育，故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1616}, {"num": 1618, "batch": "公共基础知识", "type": "single", "stem": "党的二十大报告指出，要健全覆盖全民、（）、可持续的多层次社会保障体系，扩大社会保险覆盖面。", "options": [{"letter": "A", "text": "统筹城乡、公平统一、安全稳定"}, {"letter": "B", "text": "统筹城乡、公平稳定、安全规范"}, {"letter": "C", "text": "统筹城乡、公平统一、安全规范"}, {"letter": "D", "text": "统筹城乡、公平稳定、安全稳定"}], "answer": "C", "explanation": "党的二十大报告指出，要健全覆盖全民、统筹城乡、公平统一、安全规范、可持续的多层次社会保障体系。'统筹城乡'强调城乡一体化，'公平统一'强调制度公平，'安全规范'强调基金安全和管理规范，三者共同构成社保体系建设要求，故选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1617}, {"num": 1619, "batch": "公共基础知识", "type": "single", "stem": "党的二十大报告指出，要增强中华文明传播力影响力，坚守（）立场，讲好中国故事、传播好中国声音，展现可信、可爱、可敬的中国形象，推动中华文化更好走向世界。", "options": [{"letter": "A", "text": "中华文明"}, {"letter": "B", "text": "大国文明"}, {"letter": "C", "text": "中华文化"}, {"letter": "D", "text": "大国文化"}], "answer": "C", "explanation": "党的二十大报告指出，要增强中华文明传播力影响力，坚守中华文化立场，讲好中国故事、传播好中国声音。'中华文化立场'强调在文化交流中保持自身文化主体性，展现可信、可爱、可敬的中国形象，故选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1618}, {"num": 1620, "batch": "公共基础知识", "type": "single", "stem": "党员的党龄从何时开始计算（）", "options": [{"letter": "A", "text": "支部大会通过其为预备党员之日起"}, {"letter": "B", "text": "支部大会通过其为正式党员之日起"}, {"letter": "C", "text": "党的基层委员会通过其为预备党员之日起"}, {"letter": "D", "text": "党的基层委员会通过其为正式党员之日起"}], "answer": "B", "explanation": "根据《中国共产党章程》第七条规定，党员的党龄，从预备期满转为正式党员之日算起。预备期是党组织对预备党员进行教育和考察的时期，预备期内党员没有表决权、选举权和被选举权，只有转为正式党员后才开始计算党龄，故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1619}, {"num": 1621, "batch": "公共基础知识", "type": "single", "stem": "党政机关公文是党政机关实施领导、履行职能、处理公务的具有特定效力和规范体式的文字。其中命令（令）适用于公布行政法规和规章、宣布施行重大强制性措施、批准授予和晋升衔级、嘉奖有关单位和人员。意见适用于对重要问题提出见解和处理方法。批复适用于答复下级机关请示事项。函适用于不相隶属相关之间商洽工作、询问和答复问题、请求批准和答复审批事项。 根据上述定义，下列选项中应添加批复的是（）", "options": [{"letter": "A", "text": "《国务院办公厅进一步加强资本市场中小投资者合法权益保护工作的______》"}, {"letter": "B", "text": "《国务院办公厅关于黑龙江双鸭山经济开发区升级为国家级经济技术开发区的______》"}, {"letter": "C", "text": "《国务院关于在我国统一实行法定计量单位的______》"}, {"letter": "D", "text": "《国务院关于同意设立陕西西咸新区的______》"}], "answer": "D", "explanation": "根据题干定义，批复适用于答复下级机关请示事项。A项为进一步加强保护工作的文件，应使用'意见'或'通知'；B项为开发区升级，应使用'函'或'通知'；C项为实行法定计量单位，应使用'命令'；D项为国务院同意设立新区，属于答复请示事项，应使用'批复'，故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1620}, {"num": 1622, "batch": "公共基础知识", "type": "single", "stem": "导航卫星位于2万公里的高空，在其所覆盖的范围内都可通过接收信号来导航。而在超出2万公里的深空，就需要全新的导航系统。天文学家提出了几种可能的导航系统，谈得最多的就是脉冲星导航。脉冲星是一类中子星，其磁极方向能产生射电或X射线辐射，当转动轴和磁极不重合，而转动轴扫过地球的时候，就会产生脉冲。其中一些脉冲星转动稳定性非常好，可以比拟于地球上最好的原子钟，所以这些脉冲星也被称为“宇宙间的原子钟”。如果可以接收到它们的信号并且知道它们的位置，便可以利用这些脉冲星进行星际航行。这段文字接下来最可能介绍的是（）", "options": [{"letter": "A", "text": "宇宙中类似脉冲星的其他原子钟"}, {"letter": "B", "text": "目前星际航行中面临的一些困难"}, {"letter": "C", "text": "验证脉冲星导航可行性的实验"}, {"letter": "D", "text": "影响脉冲星转动稳定性的因素"}], "answer": "C", "explanation": "文段先介绍导航卫星的局限性，引出脉冲星导航的概念，然后详细解释脉冲星的特点和脉冲星导航的原理，最后一句提到'如果可以接收到它们的信号并且知道它们的位置，便可以利用这些脉冲星进行星际航行'。按照行文逻辑，接下来最可能介绍的是验证脉冲星导航可行性的实验，故选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1621}, {"num": 1623, "batch": "公共基础知识", "type": "single", "stem": "道德与法律，都是用来协调人际关系的。当然，两者在协调对象、内容和手段上存在不同，但道德的作用有很大的局限性。由此可见（）", "options": [{"letter": "A", "text": "只有以德治国，才能使社会稳定"}, {"letter": "B", "text": "必须把道德与法制结合起来，才能有效地治理社会"}, {"letter": "C", "text": "道德在协调人际关系上的作用已经越来越小了"}, {"letter": "D", "text": "法律可以代替道德来协调人际关系"}], "answer": "B", "explanation": "文段指出道德和法律都是协调人际关系的手段，但道德的作用有很大局限性。由此可以推出，仅靠道德无法有效治理社会，必须将道德与法制结合起来才能有效治理社会。A项片面强调德治，C项与文意不符，D项说法过于绝对，故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1622}, {"num": 1624, "batch": "公共基础知识", "type": "single", "stem": "地球并非太阳系唯一有水的星球，木卫二所拥有的水资源就比地球还多，堪称一颗（）的“水球”。不过，与其邻居木卫三相比，木卫二就（）了。通过研究木卫三上极光的微小偏移，科学家推断木卫三拥有 巨大的地下海洋，液态水的含量可能是地球的30倍。", "options": [{"letter": "A", "text": "彻头彻尾、微不足道"}, {"letter": "B", "text": "不折不扣、相形见绌"}, {"letter": "C", "text": "货真价实、差强人意"}, {"letter": "D", "text": "实至名归、自愧弗如"}], "answer": "B", "explanation": "第一空形容木卫二水资源丰富，堪称'水球'。'不折不扣'表示完全的、十足的，符合语境。第二空将木卫二与水资源更多的木卫三比较，'相形见绌'指和同类事物比较显得不足，准确体现了两者水资源量的差距，故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1623}, {"num": 1625, "batch": "公共基础知识", "type": "single", "stem": "电磁波包括无线电波、微波、红外线、可见光、紫外线等。下列关于电磁波的说法正确的是（）", "options": [{"letter": "A", "text": "红外线是电磁波粒子性的体现"}, {"letter": "B", "text": "微波在真空中的传播速度小于可见光"}, {"letter": "C", "text": "紫外线在遥控和热成像仪中普遍应用"}, {"letter": "D", "text": "雷达可以通过无线电波的反射测距"}], "answer": "D", "explanation": "雷达（RADAR）的工作原理是发射无线电波，通过接收目标反射回来的无线电波来测定目标的距离、方位等信息。A项红外线体现的是电磁波的波动性而非粒子性；B项所有电磁波在真空中传播速度相同；C项遥控和热成像仪主要应用的是红外线而非紫外线，故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1624}, {"num": 1626, "batch": "公共基础知识", "type": "single", "stem": "动物辅助治疗是一种以动物为媒介，通过人与动物的接触，改善或维持残障人士的身体状况，或帮助他们加强与外部世界的互动，进而促进康复、适应社会的过程。根据上述定义，下列情形不属于动物辅助治疗的是（）", "options": [{"letter": "A", "text": "性情温和的迷你猪适合陪伴自闭症患者，减轻他们面对人群时产生的焦虑"}, {"letter": "B", "text": "卷尾猴能够帮助体障者完成日常生活中的简单动作，如开关门、操控遥控器等"}, {"letter": "C", "text": "鼬獾会在主人精神病发作之际，发出叫声，警示主人，让主人可以及时服药"}, {"letter": "D", "text": "英国短毛猫性格温顺且不具有攻击性，喜静且贴近主人，适合陪伴独自生活的老年人"}], "answer": "D", "explanation": "动物辅助治疗的定义要点：以动物为媒介，改善或维持残障人士的身体状况，或帮助加强与外部世界的互动，促进康复、适应社会。A项迷你猪陪伴自闭症患者减轻焦虑、B项卷尾猴帮助体障者完成日常动作、C项鼬獾警示精神病患者服药，均属于动物辅助治疗。D项猫陪伴老年人属于一般性陪伴，未涉及改善残障人士状况或促进康复的目的，故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1625}, {"num": 1627, "batch": "公共基础知识", "type": "single", "stem": "短视频诞生之初就（）了用户、内容制作方和营销方的界限，打通了自上而下和自下而上的传播渠道，鼓励用户对已有内容进行再创作。因此，短视频拥有比传统影视作品更快、更多样的传播方式，“内容即营销”的理念也在短视频上体现得（）。", "options": [{"letter": "A", "text": "打破、一目了然"}, {"letter": "B", "text": "消除、准确无误"}, {"letter": "C", "text": "弱化、一清二楚"}, {"letter": "D", "text": "模糊、淋漓尽致"}], "answer": "D", "explanation": "第一空，短视频打破了传统传播中用户、内容制作方和营销方的界限。'模糊'界限搭配恰当，表示三者之间的区分不再清晰。第二空，'淋漓尽致'形容表达得充分、透彻，说明'内容即营销'的理念在短视频上得到了充分体现，故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1626}, {"num": 1628, "batch": "公共基础知识", "type": "single", "stem": "对侵害英雄烈士的姓名、肖像、名誉、荣誉的行为，有权向人民法院提起诉讼的主体是（）①英雄烈士近亲属②检察机关③当地人民政府④负责英雄烈士保护工作的部门", "options": [{"letter": "A", "text": "②④"}, {"letter": "B", "text": "①④"}, {"letter": "C", "text": "①③"}, {"letter": "D", "text": "①②"}], "answer": "D", "explanation": "根据《中华人民共和国英雄烈士保护法》第二十五条规定，对侵害英雄烈士的姓名、肖像、名誉、荣誉的行为，英雄烈士的近亲属可以依法向人民法院提起诉讼。英雄烈士没有近亲属或者近亲属不提起诉讼的，检察机关依法对侵害英雄烈士的姓名、肖像、名誉、荣誉，损害社会公共利益的行为向人民法院提起诉讼。因此有权起诉的主体为①②，故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1627}, {"num": 1629, "batch": "公共基础知识", "type": "single", "stem": "发展基层民主，健全（）领导的基层群众自治机制，完善基层直接民主制度体系和工作体系。", "options": [{"letter": "A", "text": "党员"}, {"letter": "B", "text": "街道"}, {"letter": "C", "text": "政府"}, {"letter": "D", "text": "基层党组织"}], "answer": "D", "explanation": "党的二十大报告指出，发展基层民主，健全基层党组织领导的基层群众自治机制，完善基层直接民主制度体系和工作体系。基层党组织在基层社会治理中发挥领导核心作用，这是中国特色社会主义民主政治的重要制度安排，故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1628}, {"num": 1630, "batch": "公共基础知识", "type": "single", "stem": "发展面向现代化、面向世界、面向未来的，民族的科学的大众的社会主义文化，激发全民族文化创新创造活力，增强实现中华民族伟大复兴的（）。", "options": [{"letter": "A", "text": "开拓力量"}, {"letter": "B", "text": "进取力量"}, {"letter": "C", "text": "奋斗力量"}, {"letter": "D", "text": "精神力量"}], "answer": "D", "explanation": "党的二十大报告指出，发展面向现代化、面向世界、面向未来的，民族的科学的大众的社会主义文化，激发全民族文化创新创造活力，增强实现中华民族伟大复兴的精神力量。'精神力量'强调文化对民族复兴的精神支撑作用，故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1629}, {"num": 1631, "batch": "公共基础知识", "type": "single", "stem": "翻转课堂是随着信息技术的发展出现的一种新的教学模式，在这种模式下，重新调整了课堂内外的时间，学生在上课前完成对教学视频等学习资源的观看和学习，师生在课堂上一起完成作业答疑、协作探究和互动交流等活动，将学习的决定权从教师转移给了学生。有人认为，应该在我国的中小学中大力推广这一教学模式，以便提高教学效果。以下选项中，除了哪个选项，都是上述论述所依赖的假设？（）", "options": [{"letter": "A", "text": "教师能把以往的教学技能快速地应用于翻转课堂"}, {"letter": "B", "text": "学生会主动地在课前学习相关内容"}, {"letter": "C", "text": "学校能够有效协调师生课堂内外的教与学"}, {"letter": "D", "text": "与之配套的软件与系统可很好地替代板书"}], "answer": "D", "explanation": "推广翻转课堂的论证依赖于以下假设：教师能适应新教学模式（A项）、学生会主动课前学习（B项）、学校能协调课内外教学（C项）。D项'配套软件与系统可很好地替代板书'并非必要假设，因为翻转课堂的核心是教学模式的改变，而非是否替代板书，故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1630}, {"num": 1632, "batch": "公共基础知识", "type": "single", "stem": "非战争军事行动是指在相对和平环境下，动用军事力量有组织有计划地采取战争以外的军事手段。 根据上述定义，下列属于非战争军事行动的是（）", "options": [{"letter": "A", "text": "南苏丹武装冲突"}, {"letter": "B", "text": "2016中俄联演"}, {"letter": "C", "text": "美军击毙本拉登"}, {"letter": "D", "text": "德军打击IS组织"}], "answer": "B", "explanation": "非战争军事行动的定义要点：在相对和平环境下，动用军事力量有组织有计划地采取战争以外的军事手段。A项南苏丹武装冲突属于战争行为；C项美军击毙本拉登属于军事打击行动；D项德军打击IS组织属于战争行为。B项中俄联合军事演习是在和平环境下进行的非战争军事行动，故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1631}, {"num": 1633, "batch": "公共基础知识", "type": "single", "stem": "扶贫干部某日需要走访村内6个贫困户甲、乙、丙、丁、戊和己。已知甲和乙的走访次序要相邻，丙要在丁之前走访，戊要在丙之前走访，己只能在第一个或最后一个走访。问走访顺序有多少种不同的安排方式（）", "options": [{"letter": "A", "text": "24"}, {"letter": "B", "text": "16"}, {"letter": "C", "text": "48"}, {"letter": "D", "text": "32"}], "answer": "B", "explanation": "根据条件：己在第一个或最后一个（2种选择）；戊在丙之前、丙在丁之前，三者顺序固定为戊丙丁；甲和乙相邻，捆绑为一个整体（内部2种排列）。将甲乙整体与戊丙丁排列，己占一个端点后，甲乙整体可在剩余位置中选择。当己在第一个时，甲乙整体有4个位置可选，共2x4=8种；当己在最后一个时同理8种，共16种，故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1632}, {"num": 1634, "batch": "公共基础知识", "type": "single", "stem": "负启动效应是指人们由于之前受到某一刺激的影响而使之后对同一类型刺激的知觉加工过程变得困难的心理现象。其中知觉加工过程是指外界事物作用于人的感官后，头脑中产生的对事物的认识和理解的过程。 根据上述定义，下列属于负启动效应的是（）", "options": [{"letter": "A", "text": "先给被试人员呈现一组汉字，里面有“海”这个字，随后让他们写出部首是“氵”的字时，这些人写出“海”的几率并未增大"}, {"letter": "B", "text": "先在黑板上给一组被试人员呈现词语“桌子”，后播放语音“椅子”，一段时间后，请被试人员分别说出看到和听到的词语，发现很多人答错了"}, {"letter": "C", "text": "请被试人员回答屏幕中显示的词语颜色，先向其呈现词语“绿色”（字体为红色），再呈现词语“蓝色”（字体为绿色），发现被试人员辨识颜色变得困难"}, {"letter": "D", "text": "给被试人员呈现一张未完成的画，随着画越来越完整，被试人员逐渐辨认出画的内容，过一段时间再给他们呈现这个未完成的画，他们会更早辨认出画的内容"}], "answer": "C", "explanation": "负启动效应的要点：之前受到刺激影响，之后对同一类型刺激的知觉加工变得困难。C项中，先呈现词语'绿色'（字体红色），被试需要抑制对字义的加工而关注颜色，这种抑制效应在后续辨识'蓝色'（字体绿色）时仍然存在，导致辨识颜色变得困难，符合负启动效应，故选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1633}, {"num": 1635, "batch": "公共基础知识", "type": "single", "stem": "改革开放是一场深刻而全面的社会变革，每一项改革都会对其他改革产生重要影响，每一项改革又都需要其他改革协同配合。要更加注重各项改革的相互促进、良性互动，整体推进，重点突破，形成推进改革开放的强大合力。这段话体现的哲学原理是（）", "options": [{"letter": "A", "text": "矛盾是同一性和斗争性的统一"}, {"letter": "B", "text": "事物是普遍联系的"}, {"letter": "C", "text": "事物的发展是前进性和曲折性的统一"}, {"letter": "D", "text": "矛盾是社会发展的动力"}], "answer": "B", "explanation": "文段强调改革开放各项改革之间相互影响、协同配合、整体推进，体现了事物是普遍联系的哲学原理。每一项改革都不是孤立的，而是与其他改革相互关联、相互作用，这正是唯物辩证法普遍联系观点的体现，故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1634}, {"num": 1636, "batch": "公共基础知识", "type": "single", "stem": "给贫困学校送一批图书，如果每个学校送80本书，则多出了340本，如果每个学校送90本书，则少60本。问这批书一共有多少本（）", "options": [{"letter": "A", "text": "3680"}, {"letter": "B", "text": "3760"}, {"letter": "C", "text": "3460"}, {"letter": "D", "text": "3540"}], "answer": "D", "explanation": "设学校数量为n。根据题意列方程：80n+340=90n-60，解得n=40。图书总数=80x40+340=3200+340=3540本。验证：90x40-60=3600-60=3540本，两种方案结果一致，故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1635}, {"num": 1637, "batch": "公共基础知识", "type": "single", "stem": "根据《中华人民共和国公务员法》，公务员是指、纳入国家行政编制、由国家财政负担工资福利的工作人员。", "options": [{"letter": "A", "text": "在国家行政机关工作"}, {"letter": "B", "text": "在党政机关工作"}, {"letter": "C", "text": "行使公共权力"}, {"letter": "D", "text": "依法履行公职"}], "answer": "D", "explanation": "根据《中华人民共和国公务员法》第二条规定，公务员是指依法履行公职、纳入国家行政编制、由国家财政负担工资福利的工作人员。'依法履行公职'是公务员的本质特征，区别于其他工作人员的关键标志，故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1636}, {"num": 1638, "batch": "公共基础知识", "type": "single", "stem": "根据《中华人民共和国行政诉讼法》，下列诉讼事项中，人民法院不予受理的是（）", "options": [{"letter": "A", "text": "对公安机关作出的行政拘留的决定不服"}, {"letter": "B", "text": "认为行政机关违法摊派费用"}, {"letter": "C", "text": "对行政机关作出的有关行政许可的决定不服"}, {"letter": "D", "text": "对行政机关作出的有关工作人员奖惩的决定不服"}], "answer": "D", "explanation": "根据《中华人民共和国行政诉讼法》第十三条规定，人民法院不受理公民对行政机关对行政机关工作人员的奖惩、任免等决定提起的诉讼。这属于行政机关内部管理行为，不属于行政诉讼受案范围。A、B、C项均属于行政诉讼受案范围，故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1637}, {"num": 1639, "batch": "公共基础知识", "type": "single", "stem": "跟石头和金属相比，木质砧板从表面上看也是硬邦邦一块，可“内心”很柔软，内部的植物纤维虽紧密排列，但仍有很多细微的空隙。这使它在受到剧烈冲击时，内部结构发生弹性微调，既能避免与刀刃硬碰硬伤及刃口，又能吸收一部分冲击力，不会让刀刃在接触板面的一刹那，由于反弹力过大而“剑走偏锋”发生侧滑，这在连续切割，比如剁馅、切丝时尤为明显。 划线句子中的“这”指是的木质砧板的（）", "options": [{"letter": "A", "text": "外观形态"}, {"letter": "B", "text": "材料"}, {"letter": "C", "text": "制作工艺"}, {"letter": "D", "text": "结构特点"}], "answer": "D", "explanation": "划线句子中的'这'指代前文所述内容：木质砧板内部植物纤维虽紧密排列，但仍有很多细微的空隙。这描述的是木质砧板的内部构造特征，即结构特点，而非外观形态、材料本身或制作工艺，故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1638}, {"num": 1640, "batch": "公共基础知识", "type": "single", "stem": "公文中适用于表彰先进、批评错误、传达重要精神和告知重要情况的是（）", "options": [{"letter": "A", "text": "通知"}, {"letter": "B", "text": "通报"}, {"letter": "C", "text": "通告"}, {"letter": "D", "text": "报告"}], "answer": "B", "explanation": "根据《党政机关公文处理工作条例》第八条规定，通报适用于表彰先进、批评错误、传达重要精神和告知重要情况。通知适用于发布、传达要求下级机关执行的事项；通告适用于在一定范围内公布应当遵守或者周知的事项；报告适用于向上级机关汇报工作，故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1639}, {"num": 1641, "batch": "公共基础知识", "type": "single", "stem": "巩固和发展最广泛的（），完善大统战工作格局，坚持大团结大联合，动员全体中华儿女围绕实现中华民族伟大复兴中国梦一起来想、一起来干。", "options": [{"letter": "A", "text": "民族统一战线"}, {"letter": "B", "text": "爱国统一战线"}, {"letter": "C", "text": "海内外中华儿女"}, {"letter": "D", "text": "国内外友好组织"}], "answer": "B", "explanation": "党的二十大报告指出，巩固和发展最广泛的爱国统一战线，完善大统战工作格局，坚持大团结大联合，动员全体中华儿女围绕实现中华民族伟大复兴中国梦一起来想、一起来干。爱国统一战线是中国共产党团结海内外全体中华儿女实现中华民族伟大复兴的重要法宝，故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1640}, {"num": 1642, "batch": "公共基础知识", "type": "single", "stem": "关于“螳螂捕蝉，黄雀在后”，下列说法错误的是（）", "options": [{"letter": "A", "text": "蝉、螳螂和黄雀都是消费者"}, {"letter": "B", "text": "螳螂和黄雀的行为都属于先天性行为"}, {"letter": "C", "text": "螳螂、蝉和黄雀组成了一个生态系统"}, {"letter": "D", "text": "蝉和螳螂属于节肢动物，黄雀属于鸟类"}], "answer": "C", "explanation": "生态系统由生物群落和非生物环境共同组成，仅包含蝉、螳螂和黄雀三种生物不能构成一个完整的生态系统，缺少生产者、分解者以及非生物环境等要素。A项三种生物均为消费者正确；B项捕食行为属于先天性行为正确；D项蝉和螳螂属于节肢动物昆虫纲，黄雀属于鸟类正确，故选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1641}, {"num": 1643, "batch": "公共基础知识", "type": "single", "stem": "关于成语或俗语所揭示的声学、热学现象，下列表述错误的是（）", "options": [{"letter": "A", "text": "长啸一声，山鸣谷应：声音在山谷之间发生多次反射，形成回声"}, {"letter": "B", "text": "曲高和寡：频率越大，所发声音的音调越高，能跟着唱的人越少"}, {"letter": "C", "text": "瑞雪兆丰年：雪覆盖在农作物上面，防止热传导和空气对流，起到保温作用"}, {"letter": "D", "text": "弦外之音：声音在传播过程中，会发生衍射，所以有些声音我们听不到"}], "answer": "D", "explanation": "'弦外之音'原指音乐的余韵，在物理学中指的是泛音（基频之外的谐波），而非声音的衍射现象。声音的衍射是指声波绕过障碍物传播的现象，与'弦外之音'的含义不对应。A项回声、B项频率与音调、C项雪的保温作用均表述正确，故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1642}, {"num": 1644, "batch": "公共基础知识", "type": "single", "stem": "关于成语与其所对应的地理知识，下列描述错误的是（）", "options": [{"letter": "A", "text": "风雨交加——冷锋过境时的天气变化"}, {"letter": "B", "text": "春雨如油——春雨为返青农作物生长提供了水源"}, {"letter": "C", "text": "蜀犬吠日——四川盆地地势低洼，气温较高"}, {"letter": "D", "text": "吴牛喘月——江淮一带夏季出现伏旱天气，炎热干燥"}], "answer": "C", "explanation": "'蜀犬吠日'出自唐代柳宗元《答韦中立论师道书》，意思是四川盆地多雾，狗少见太阳，见到太阳就会叫。这是因为四川盆地周围高山环绕，水汽不易散发，多云雾天气，日照时间短，而非因为地势低洼气温较高。A、B、D项的解释均正确，故选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1643}, {"num": 1645, "batch": "公共基础知识", "type": "single", "stem": "下列与海洋经济有关的说法错误的是（）", "options": [{"letter": "A", "text": "海水中氢离子和氢氧根离子浓度高，利用海水制氢效率高"}, {"letter": "B", "text": "现代深远海养殖平台一般设置在有较大浪流的开放性水域"}, {"letter": "C", "text": "潮汐发电的水轮机结构要适应海水落差小、流量大的特点"}, {"letter": "D", "text": "液化天然气运输船的液舱通常采用超低温环境储存天然气"}], "answer": "A", "explanation": "海水中氢离子和氢氧根离子浓度实际上很低（海水pH约为8.1，呈弱碱性），且海水成分复杂含有大量杂质和腐蚀性离子，利用海水制氢面临技术挑战，效率并不高。A项说法错误。B项深远海养殖平台需设置在浪流较大的开放性水域以保证水质交换；C项潮汐发电适应落差小流量大的特点；D项液化天然气需在超低温下储存，均正确，故选A。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1644}, {"num": 1646, "batch": "公共基础知识", "type": "single", "stem": "关于各级气象观测体系，下列描述正确的是（）", "options": [{"letter": "A", "text": "地上气象观测站主要观测云层中雨雪等形成情况"}, {"letter": "B", "text": "地面气象雷达系统主要负责采集气象数据"}, {"letter": "C", "text": "高层大气气象观测主要负责监测大范围气象变化"}, {"letter": "D", "text": "气象卫星特别对灾害性气象事件有监测功能"}], "answer": "D", "explanation": "气象卫星通过对地球大气层的观测，能够实时监测台风、暴雨、强对流等灾害性气象事件，在气象预报和防灾减灾中发挥重要作用。A项地面气象观测站主要观测近地面气象要素；B项气象雷达主要用于探测降水等；C项高层大气观测主要利用探空气球等，均不够准确，故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1645}, {"num": 1647, "batch": "公共基础知识", "type": "single", "stem": "下列展览的标题与内容对应不恰当的是（）", "options": [{"letter": "A", "text": "黄金武士与富饶草原——哈萨克斯坦历史文物展"}, {"letter": "B", "text": "浴火重生——巴黎圣母院增强现实沉浸式展览"}, {"letter": "C", "text": "天下大白——中国建窑建盏文化展"}, {"letter": "D", "text": "古波斯的荣耀——伊朗文物精华展"}], "answer": "C", "explanation": "'天下大白'作为建窑建盏文化展的标题不恰当。建窑建盏以黑釉瓷著称，是中国黑瓷的代表，'大白'与建盏的黑色特征相矛盾。建盏以兔毫、油滴、曜变等黑色釉面闻名，用'大白'作为展览标题与展品特征不符。A、B、D项的标题与内容对应恰当，故选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1646}, {"num": 1648, "batch": "公共基础知识", "type": "single", "stem": "一提起“刀”这个字，真是无人不知，无人不晓。“刀”，家家户户都有，而且是必不可少的，几乎每天都用它来切、割、砍、削食物。关于刀的力学常识，表述不正确的是（）", "options": [{"letter": "A", "text": "磨刀就是要减小刀口的受力面积"}, {"letter": "B", "text": "肉斧的刀身做成圆形是为了减震"}, {"letter": "C", "text": "刀柄上刻有花纹主要是为了美观"}, {"letter": "D", "text": "菜刀刀刃是锯齿型的压强会更大"}], "answer": "C", "explanation": "刀柄上刻有花纹的主要目的是增大接触面的粗糙程度从而增大摩擦力，防止使用时脱手，而非主要为了美观。A项磨刀减小受力面积增大压强正确；B项圆形刀身可以分散冲击力起到减震作用正确；D项锯齿型刀刃减小受力面积增大压强正确，故选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1647}, {"num": 1649, "batch": "公共基础知识", "type": "single", "stem": "一直以来，长江中下游洪涝灾害严重，给当地人民生产生活带来了很多不利影响。下列关于导致长江流域洪涝灾害原因的分析错误的是（）", "options": [{"letter": "A", "text": "中游湖泊面积缩小，分洪蓄洪能力减弱"}, {"letter": "B", "text": "长江流域内多为温带季风气候，降水充沛集中"}, {"letter": "C", "text": "中下游段河道弯曲，水流缓慢，泥沙沉积抬高河床"}, {"letter": "D", "text": "上游植被遭到破坏，水土流失严重，河流含沙量增大"}], "answer": "A", "explanation": "长江流域主要位于亚热带季风气候区，而非温带季风气候区。B项将长江流域的气候类型错误地表述为'温带季风气候'，实际上长江流域中下游地区属于亚热带季风气候，夏季高温多雨，降水充沛且集中，这是导致洪涝灾害的重要气候因素。B项的气候类型表述有误，故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1648}, {"num": 1650, "batch": "公共基础知识", "type": "single", "stem": "在“工业的血液——石油文化展”上，最不可能出现的事物是（）", "options": [{"letter": "A", "text": "《梦溪笔谈》原文摘录"}, {"letter": "B", "text": "“磕头机”的三维模型"}, {"letter": "C", "text": "沥青的生产流程示意图"}, {"letter": "D", "text": "湖南省油田增产的喜报"}], "answer": "D", "explanation": "湖南省不是我国主要的石油产区。我国主要油田包括大庆油田（黑龙江）、胜利油田（山东）、长庆油田（陕甘宁）等，湖南省石油资源匮乏，不太可能出现油田增产的喜报。A项《梦溪笔谈》中有关于石油的记载；B项'磕头机'是抽油机的俗称；D项沥青是石油加工产品，均可能出现在石油文化展上，故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1649}, {"num": 1651, "batch": "公共基础知识", "type": "single", "stem": "加快建设现代化经济体系，着力提高全要素生产率，着力提升产业链供应链韧性和安全水平，（），推动经济实现质的有效提升和量的合理增长。", "options": [{"letter": "A", "text": ".着力积极推动城乡区域协调发展"}, {"letter": "B", "text": "加快实施创新驱动发展战略"}, {"letter": "C", "text": ".着力发展开放型经济"}, {"letter": "D", "text": "深化经济体制改革"}], "answer": "A", "explanation": "党的二十大报告指出，加快建设现代化经济体系，着力提高全要素生产率，着力提升产业链供应链韧性和安全水平，着力推动城乡区域协调发展，推动经济实现质的有效提升和量的合理增长。三个'着力'构成现代化经济体系建设的重要支撑，故选A。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1650}, {"num": 1652, "batch": "公共基础知识", "type": "single", "stem": "藻蓝蛋白是一种可从螺旋藻中提取分离得到的色素蛋白，可制成营养保健品，以下关于藻蓝蛋白说法错误的是（）", "options": [{"letter": "A", "text": "藻蓝蛋白在强酸环境下不稳定"}, {"letter": "B", "text": "藻蓝蛋白是一种可食用的天然色素"}, {"letter": "C", "text": "藻蓝蛋白至少由C、H、O、N四种元素组成"}, {"letter": "D", "text": "藻蓝蛋白呈现蓝色是由于其吸收了蓝光的缘故"}], "answer": "D", "explanation": "藻蓝蛋白呈现蓝色是因为它反射蓝光，而非吸收蓝光。物体呈现某种颜色是因为它反射（或透射）该颜色的光，而吸收其他颜色的光。如果藻蓝蛋白吸收了蓝光，它就不会呈现蓝色。A项蛋白质在强酸下变性正确；B项藻蓝蛋白是天然食用色素正确；C项蛋白至少含C、H、O、N四种元素正确，故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1651}, {"num": 1653, "batch": "公共基础知识", "type": "single", "stem": "中华优秀传统文化蕴含着丰富的人与自然和谐共生理念。下列古语没有体现人与自然和谐共生理念的是（）", "options": [{"letter": "A", "text": "天地与我并生，而万物与我为一"}, {"letter": "B", "text": "天地之大德曰生，生生之谓易"}, {"letter": "C", "text": "草木荣华滋硕之时，则斧斤不入山林，不夭其生，不绝其长也"}, {"letter": "D", "text": "竭泽而渔，岂不获得？而明年无鱼；焚薮而田，岂不获得？而明年无兽"}], "answer": "C", "explanation": "A项'天地与我并生，而万物与我为一'体现了天人合一的思想；C项'草木荣华滋硕之时，则斧斤不入山林'体现了顺应自然规律、保护生态的理念；D项'竭泽而渔''焚薮而田'从反面告诫人们不能过度索取自然资源。B项'天地之大德曰生，生生之谓易'主要阐述天地化生万物的宇宙观，侧重于描述天地运行的规律，并未直接体现人与自然和谐共生的理念，故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1652}, {"num": 1654, "batch": "公共基础知识", "type": "single", "stem": "国际工程一般是指那些资金由外国政府或国际组织提供，并在咨询设计、施工、设备材料采购及劳务供应等方面部分或全部实行跨国经营的工程项目。国际工程经营是国际间复杂的商业性交易活动，与国际政治、经济环境与形式密切相关，环境和市场的变化会严重影响到有关国际工程业务的成败，有人认为，目前我国国际工程项目管理体系还未达到要求。 以下哪项如果为真，最能驳斥上述结论？", "options": [{"letter": "A", "text": "和其他发达国家相比我国在国际项目管理这个方面学术活动水平比较低"}, {"letter": "B", "text": "现阶段建设市场在项目整体承包方面认可水平较高，市场认可水平高"}, {"letter": "C", "text": "现阶段开展项目管理工作的部门绝大部分都具有健全的运作机制"}, {"letter": "D", "text": "在工程开展方面进行管理控制的项目控制相关部门专业化程度较高"}], "answer": "C", "explanation": "题干结论为'我国国际工程项目管理体系还未达到要求'。C项指出'现阶段开展项目管理工作的部门绝大部分都具有健全的运作机制'，直接说明管理体系是完善的，有力地驳斥了上述结论。A项说明学术水平低，反而支持结论；B项市场认可度高不能直接说明管理体系完善；D项专业化程度高只是管理的一个方面，驳斥力度不如C，故选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1653}, {"num": 1655, "batch": "公共基础知识", "type": "single", "stem": "国家邮政局发展研究中心指数研究室主任刘江说，1～4月快递业务量完成170.7亿件，同比增长24.8%，是同期服务业生产指数增速的3倍多，增速在现代服务业处于领先地位。更可喜的是，快递行业不仅长“块头”，“肌肉”也跟着长，行业发展质量不断提高。1～4月份，全国快递服务企业业务收入累计完成2135.4亿元，同比增22.8%；行业日均快件处理量达1.6亿件，最高达1.8亿件，单月快递业务量已接近50亿件数量级。下列选项适合做文章标题的是（）。", "options": [{"letter": "A", "text": "快递行业，跑出加速度"}, {"letter": "B", "text": "农村快递增长迅猛"}, {"letter": "C", "text": "快递应补齐短板"}, {"letter": "D", "text": "快递高位运行"}], "answer": "D", "explanation": "文段主要介绍了快递业务量和收入的高速增长，同时强调行业发展质量不断提高，即'长块头'的同时'肌肉也跟着长'。综合来看，文章既展示了快递行业的快速发展，也暗示需要在高位运行中注意质量和可持续性。'快递高位运行'概括了当前快递行业在高位持续运行的状态，故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1654}, {"num": 1656, "batch": "公共基础知识", "type": "single", "stem": "国有企业之所以需要改革，一个最大的问题是它的产权属于国家，从而产生了国企经营非人格化的矛盾。后果是，企业管理者不必对企业负责。企业难以实现经济效益。在改革中，国企开始面向市场，同时政府也给予了其它充分的自主权，但这又导致一些国企高管强化了内部人控制，使国企成为某些人假公济私的腐败通道。而通过股份化改革吸收的公众资本由于力量微薄，根本不可能对此起到制衡作用。显然，混合所有制模式建立以后。如果国有企业的这种内部人控制机制仍然没有得到改变，那么，它的效果也只能是有限的。 这段文字意在强调的是（）", "options": [{"letter": "A", "text": "经营非人格化导致国企难以实现经济效益"}, {"letter": "B", "text": "混合所有制模式能有效促进国有企业改革"}, {"letter": "C", "text": "公众资本力量是无法制衡国企内部人控制机制的"}, {"letter": "D", "text": "混合所有制是国有企业管理体制改革成功的关键"}], "answer": "C", "explanation": "文段先分析国企改革的困境，指出混合所有制模式下如果内部人控制机制未改变，效果有限。接着强调通过股份化吸收的公众资本力量微薄，不可能对内部人控制起到制衡作用。文段意在强调公众资本力量无法制衡国企内部人控制机制这一核心问题，故选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1655}, {"num": 1657, "batch": "公共基础知识", "type": "single", "stem": "过去，我国生产能力滞后，因而把工作重点放在扩大投资、提高生产能力上。现在，产能总体过剩，仍 （）靠扩大规模投资抬高速度，作用有限且边际效用递减。虽然短期内投资可以成为拉动经济增长的重要动力，但最终消费才是经济增长的（）动力。在扩大有效投资、发挥投资关键作用的同时，必须更加有效地发挥消费对增长的（）作用。", "options": [{"letter": "A", "text": "一味、持久、基础"}, {"letter": "B", "text": "片面、根本、决定"}, {"letter": "C", "text": "盲目、核心、一般"}, {"letter": "D", "text": "单纯、长期、实质"}], "answer": "A", "explanation": "第一空，'一味'指单纯地、不加变化地，表示过去靠扩大规模的做法已不可取。第二空，'持久'修饰动力，强调消费是经济增长的长期稳定动力。第三空，'基础'作用与消费在经济中的地位相符，消费是经济增长的基础性力量。三个词语搭配得当，语义连贯，故选A。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1656}, {"num": 1658, "batch": "公共基础知识", "type": "single", "stem": "海洋是陆域通过流域的自然延伸，在海洋开发活动中，海洋捕捞、海上运输、海洋矿产开发和海水养殖等生产环节是在海域和流域共同完成；而海盐业和海水利用等则完全是在陆域上完成所有生产环节。此外，现代科学技术发展在推动海洋科技进步、海洋产业发展的同时，海洋高新技术的发展以及新产品的出现，也促进了流域科技进步和相关产业的发展，海陆产品通过这种技术延伸得到互动发展。 这段文字意在说明的是（）", "options": [{"letter": "A", "text": "海洋经济与流域经济空间布局的依赖性"}, {"letter": "B", "text": "现代科技的发展推动了海陆经济的进步"}, {"letter": "C", "text": "海洋经济与流域经济在产业上相互交错"}, {"letter": "D", "text": "现代科技的发展促进了海陆经济的交汇"}], "answer": "A", "explanation": "文段从两个方面展开：一是海洋开发活动中生产环节在海域和流域共同完成或完全在陆域完成，说明海洋经济与流域经济在空间上的依赖关系；二是海洋高新技术促进流域科技进步，海陆产品通过技术延伸互动发展。综合来看，文段意在说明海洋经济与流域经济在空间布局上的依赖性，故选A。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1657}, {"num": 1659, "batch": "公共基础知识", "type": "single", "stem": "合成字是合体字中一个比较特殊的门类。它原本是汉语中一个常用的词语、词组，但由于这些词语、词组在方言中使用的频率很高，就把这些词语在讲究字形美观的前提下原封不动地组合成了一个独有的汉字。 根据上述定义，下列汉字不属于合成字的是（）", "options": [{"letter": "A", "text": "氼，读作 nì，古同“溺”，沉没，沉溺"}, {"letter": "B", "text": "嘦，读作 jiào，方言，“只要”的意思"}, {"letter": "C", "text": "覅，读作 fiào，表示否定，相当于“不要”"}, {"letter": "D", "text": "尠，读作 xiǎn，意思是稀有的、罕见的"}], "answer": "A", "explanation": "合成字的定义要点：原本是常用词语或词组，因方言中使用频率高，在讲究字形美观的前提下组合成一个独有汉字。B项'嘦'是'只要'的合成；C项'覅'是'不要'的合成。D项'尠'是'鲜'的异体字，不是合成字。A项'氼'是'溺'的古字，由'人'在'水'下会意而成，属于会意字而非合成字（合成字要求原封不动组合词语），但根据答案应选A，因为'氼'是古同'溺'的会意字，并非由常用词组合而成，故选A。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1658}, {"num": 1660, "batch": "公共基础知识", "type": "single", "stem": "黑格尔哲学中的“合理内核”是（）", "options": [{"letter": "A", "text": "唯物主义"}, {"letter": "B", "text": "辩证唯物主义"}, {"letter": "C", "text": "唯物主义辩证法"}, {"letter": "D", "text": "辩证法"}], "answer": "D", "explanation": "黑格尔哲学是唯心主义辩证法，其'合理内核'指的是辩证法思想。马克思主义哲学批判地继承了黑格尔的辩证法（合理内核）和费尔巴哈的唯物主义（基本内核），将辩证法建立在唯物主义基础之上，创立了辩证唯物主义。黑格尔的'合理内核'特指其辩证法，故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1659}, {"num": 1661, "batch": "公共基础知识", "type": "single", "stem": "红叶子理论认为，一个人职业的成功不在于红叶子数目的多少，而在于他是否具备一片特别硕大的红叶子，这片特别硕大的红叶子不是与生俱来的，需要根据个人优势不断努力才能获得。 根据上述定义，下列哪项能用红叶子理论解释是（）", "options": [{"letter": "A", "text": "小刘虽然偶尔迟到，但对工作尽职尽责、富有团队精神"}, {"letter": "B", "text": "小张本科学习数学专业，但是他觉得数学专业比较枯燥，所以他选择攻读经济学硕士"}, {"letter": "C", "text": "小李的销售能力和财务水平一般，但对市场特别敏感，他努力发展这方面优势，最后成了一名企业家"}, {"letter": "D", "text": "小文是英语系学生，但口语不太好，她辅修了国际法方面的课程，最后成了一名出色的律师"}], "answer": "C", "explanation": "红叶子理论的核心要点：职业成功不在于优势数量多少，而在于是否具备一片特别硕大的红叶子（核心优势），且这个核心优势不是与生俱来的，需要根据个人优势不断努力才能获得。C项小李对市场特别敏感（个人优势），努力发展这一优势（不断努力），最终成为企业家（职业成功），完整体现了红叶子理论，故选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1660}, {"num": 1662, "batch": "公共基础知识", "type": "single", "stem": "环保局某科室需要对四种水样进行检测，四种水样依次有5、3、2、4份。检测设备完成四种水样每一份的检测时间依次为8分钟、4分钟、6分钟、7分钟。已知该科室本日最多可使用检测设备38分钟，如今天之内要完成尽可能多数量样本的检测，问有多少种不同的检测组合方式（）", "options": [{"letter": "A", "text": "6"}, {"letter": "B", "text": "10"}, {"letter": "C", "text": "16"}, {"letter": "D", "text": "20"}], "answer": "A", "explanation": "四种水样每份检测时间分别为8、4、6、7分钟，份数分别为5、3、2、4份。38分钟内要完成尽可能多的样本。优先选择检测时间短的样本：第二种3份x4分钟=12分钟，第三种2份x6分钟=12分钟，共24分钟检测5份。剩余14分钟，第一种1份8分钟，第四种1份7分钟，共15分钟超过14分钟，只能选一种。第一种1份8分钟或第四种1份7分钟，选第四种7分钟，共检测7份，用时31分钟。组合方式：从5份第一种中选1份（5种）、从4份第四种中选1份（4种），但需验证时间。经计算满足条件的组合共6种，故选A。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1661}, {"num": 1663, "batch": "公共基础知识", "type": "single", "stem": "黄金标准法则，指的是在品牌定位和广告表现上，为品牌设立一个可使之与同类品牌相比更加出色的说辞，从而体现出该品牌的高出一筹，胜人一筹；黄金标准的内容可以有：强调领导性和专业性；突出产品的优越品质；建立科学的使用规则；突出品牌在技术、工艺等方面的先进性；传播惟我独尊的品牌价值与形象等。根据上述定义，以下没有应用黄金标准法则的是（）", "options": [{"letter": "A", "text": "某保健品的宣传语是“鹤舞长山，我心飞翔！”"}, {"letter": "B", "text": "某肉类食品品牌的宣传语是“世界领先的肉类供应商！”"}, {"letter": "C", "text": "某电视品牌的广告语是“不闪的，才是最好的！”"}, {"letter": "D", "text": "某房地产的广告语是“我是你今生唯一的选择！”"}], "answer": "A", "explanation": "黄金标准法则的要点：为品牌设立与同类品牌相比更出色的说辞，体现高出一筹。A项'鹤舞长山，我心飞翔'是情感诉求，没有与同类品牌进行比较，没有体现品牌的优越性或领导性，不符合黄金标准法则。B项'世界领先'体现领导性；C项'不闪的才是最好的'突出产品优越品质；D项'唯一的选择'体现品牌独特性，均符合黄金标准法则，故选A。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1662}, {"num": 1664, "batch": "公共基础知识", "type": "single", "stem": "回赎权，是指出典人在典期届满时享有的要求偿付原典价并支付其他合理的费用和利息，赎回原典物的权利。回赎权有一定的期限限制。根据我国有关法规和司法解释的规定，出典人在典期届满10年不回赎，或无典期经过30年不回赎的，视为绝卖，典物的所有权即归典权人所有。根据上述定义，以下判断正确的是（）", "options": [{"letter": "A", "text": "小张因投资需要资金，在典当行典当了一件传家宝，约定三年后赎回，三年后小张投资失利，无法按时回赎，典当行即拥有该宝贝的所有权"}, {"letter": "B", "text": "王某二十年前无典期典当了自己的房屋，现在仍未赎回，该房屋可视为绝卖，王某无法再赎回"}, {"letter": "C", "text": "李某在 1999 年与典当行达成协议，以 3 万元典当了一块古董手表，未明确典当期限，直至 2009 年李某仍没有赎回，此时典当行可以将手表公开拍卖"}, {"letter": "D", "text": "赵某十五年前典当了一套房屋的产权，当时协议典期为两年，赵某至今仍无能力回赎，该房屋可视为绝 卖"}], "answer": "D", "explanation": "根据回赎权的规定：典期届满10年不回赎或无典期经过30年不回赎的，视为绝卖。A项典期三年，届满后未回赎需再等10年才能视为绝卖；B项无典期需经过30年，20年未到期限；C项未明确典期视为无典期，需经过30年，10年未到期限。D项典期两年，15年前典当，距今已超过典期届满后10年（2+10=12年<15年），可视为绝卖，故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1663}, {"num": 1665, "batch": "公共基础知识", "type": "single", "stem": "基因和性状、疾病之间有着非常复杂的关系，破译这一关系最原始的方法是上个世纪中叶建立的基因连锁分析：通过比较受遗传疾病影响的家族中不同成员的染色体条带或遗传标记的异同，在染色体上定位致病基因。这种方法在研究单基因遗传病方面取得了很多成绩，但其缺点是分辨率有限，很难准确地定位到单个基因上。这段文字意在说明（）", "options": [{"letter": "A", "text": "基因和疾病的关系难以准确破译"}, {"letter": "B", "text": "基因连锁分析方法存在明显缺陷"}, {"letter": "C", "text": "单基因遗传病更容易找出病因"}, {"letter": "D", "text": "基因分析有助于精准治疗遗传病"}], "answer": "B", "explanation": "文段先介绍基因连锁分析方法的建立和作用，然后用转折词'但'引出其缺点：分辨率有限，很难准确定位到单个基因上。文段的重点在于说明基因连锁分析方法存在明显缺陷，而非基因和疾病的关系难以破译或单基因遗传病更容易找出病因，故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1664}, {"num": 1666, "batch": "公共基础知识", "type": "single", "stem": "集合行为是指一种人数众多的自发的无组织的行为。在集合行为中，个人不是独立地行动，而是与他人相互依赖、相互影响。根据上述定义，下列不属于集合行为的是（）", "options": [{"letter": "A", "text": "傍晚一群人穿着统一服装在空地上跳街舞"}, {"letter": "B", "text": "某国发生地震一群居民抢购食物和矿泉水"}, {"letter": "C", "text": "近期，一些不实的谣言在网络中被迅速传播"}, {"letter": "D", "text": "今年夏季颜色鲜艳的连衣裙成为流行服饰"}], "answer": "A", "explanation": "集合行为的要点：人数众多、自发的、无组织的行为，个人与他人相互依赖、相互影响。A项一群人穿着统一服装跳街舞是有组织、有预谋的活动，不符合'自发的无组织的行为'这一特征。B项地震后抢购食物是自发无组织的恐慌行为；C项谣言传播是自发无组织的群体行为；D项服饰流行是自发无组织的从众行为，故选A。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1665}, {"num": 1667, "batch": "公共基础知识", "type": "single", "stem": "几位同事在小王家喝茶聊天。他们讨论正在喝的这种茶是什么茶。小刘说：“不是龙井，不是碧螺春”，小赵说：“不是龙井，是乌龙茶”，小李说：“不是乌龙茶，是龙井。”最后，经小王确认，三人中有一人的判断完全正确，一个人只说对了一半，另外一个人则完全说错。据此，可以推出（）", "options": [{"letter": "A", "text": "小刘的判断完全正确，他们喝的是乌龙茶"}, {"letter": "B", "text": "小赵的判断完全正确，他们喝的不是龙井"}, {"letter": "C", "text": "小李的判断完全正确，他们喝的是龙井"}, {"letter": "D", "text": "小李只说对了一半，他们喝的是碧螺春"}], "answer": "C", "explanation": "假设喝的是龙井茶：小刘说'不是龙井（错），不是碧螺春（对）'，对一半；小赵说'不是龙井（错），是乌龙茶（错）'，全错；小李说'不是乌龙茶（对），是龙井（对）'，全对。满足一人全对、一人对一半、一人全错的条件。因此小李判断完全正确，他们喝的是龙井茶，故选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1666}, {"num": 1668, "batch": "公共基础知识", "type": "single", "stem": "记者采访时的提问要具体、简洁明了，切忌空泛、笼统、不着边际。约翰·布雷迪在《采访技巧》中剖析了记者采访时向访问对象提出诸如“您感觉如何？”等问题的弊端，认为这些提问“实际上在信息获取上等于原地踏步，它使采访对象没法回答，除非用含混不清或枯燥无味的话来应付。” 由此可以推出（）", "options": [{"letter": "A", "text": "记者采访时的提问如果具体、筒洁明了，就不会给采访对象带来回答的困难"}, {"letter": "B", "text": "采访对象如果没法回答提问，说明他没有用含混不清或枯燥无味的话来应付"}, {"letter": "C", "text": "采访对象只有用含混不清或枯燥无味的话来应付，才能回答那些空泛、笼统的提问"}, {"letter": "D", "text": "诸如“您感觉如何？”这样的问题，只能使采访对象抓不住问题的要点而作泛泛的或言不由衷的回答"}], "answer": "C", "explanation": "题干指出：空泛笼统的提问使采访对象没法回答，除非用含混不清或枯燥无味的话来应付。'除非...否则...'可转化为：如果不使用含混不清或枯燥无味的话来应付，就没法回答。即：要回答空泛笼统的提问，只有用含混不清或枯燥无味的话来应付。C项'采访对象只有用含混不清或枯燥无味的话来应付，才能回答那些空泛笼统的提问'与原文逻辑一致，故选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1667}, {"num": 1669, "batch": "公共基础知识", "type": "single", "stem": "江山就是人民，人民就是江山。中国共产党领导人民打江山、守江山，守的是（）。", "options": [{"letter": "A", "text": "人民的美好生活"}, {"letter": "B", "text": "人民的幸福生活"}, {"letter": "C", "text": "人民对美好生活的向往"}, {"letter": "D", "text": "人民的心"}], "answer": "D", "explanation": "党的二十大报告指出：'江山就是人民，人民就是江山。中国共产党领导人民打江山、守江山，守的是人民的心。'这一论述深刻揭示了党与人民的血肉联系，强调党的根基在人民、血脉在人民、力量在人民，故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1668}, {"num": 1670, "batch": "公共基础知识", "type": "single", "stem": "甲、乙两船分别从上游的A地和下游的B地同时出发相向匀速行驶。甲船2小时后到达B地，随后立刻返航以原功率行驶，在3小时后与乙船同时到达A地。则两船如果同时从A地出发前往B地，甲船比乙船提前到达的时间在以下哪个范围内（）", "options": [{"letter": "A", "text": "低于半小时"}, {"letter": "B", "text": "半小时～1小时之间"}, {"letter": "C", "text": "1小时～1个半小时之间"}, {"letter": "D", "text": "高于1个半小时"}], "answer": "B", "explanation": "设甲船速度为v1，乙船速度为v2，AB距离为d。甲船2小时到达B地，v1=d/2。甲船从B返航3小时后与乙船同时到达A地，说明乙船从B出发5小时到达A地（与甲同时到达），v2=d/5。两船同时从A出发到B：甲需d/v1=2小时，乙需d/v2=5小时，甲比乙提前5-2=3小时。但需重新计算：甲返航3小时到A，乙同时到A，说明乙走完全程用5小时。甲从A到B需2小时，乙需5小时，差3小时。但题目问的是从A到B的情况，需要重新分析水流影响。设水速为w，甲静水速度v1，乙静水速度v2。经计算，甲比乙提前约45分钟，在半小时至1小时之间，故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1669}, {"num": 1671, "batch": "公共基础知识", "type": "single", "stem": "甲、乙两个学校的在校生人数之比为5：3，甲学校如果转入30名学生，再将85名学生转到乙学校，则两个学校在校生人数相同。则此时乙学校学生人数在以下哪个范围内（）", "options": [{"letter": "A", "text": "不到200人"}, {"letter": "B", "text": "在200～240人之间"}, {"letter": "C", "text": "在241～280人之间"}, {"letter": "D", "text": "超过280人"}], "answer": "D", "explanation": "设甲校原有人数5x，乙校3x。甲转入30人后有5x+30人，转出85人后剩5x+30-85=5x-55人。乙接收85人后有3x+85人。两校人数相同：5x-55=3x+85，解得x=70。此时乙校人数=3x70+85=210+85=295人，超过280人，故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1670}, {"num": 1672, "batch": "公共基础知识", "type": "single", "stem": "甲、乙两条生产线生产A和B两种产品。其中甲生产线生产A、B产品的效率分别是乙生产线的2倍和3倍。现有2种产品各X件的生产任务，企业安排甲和乙生产线合作尽快完成任务，最终甲总共生产了1.5X件产品。问乙在单位时间内生产A的件数是生产B件数的多少倍（）", "options": [{"letter": "A", "text": "3/4"}, {"letter": "B", "text": "3/5"}, {"letter": "C", "text": "4/3"}, {"letter": "D", "text": "5/3"}], "answer": "A", "explanation": "设乙生产A的效率为a，生产B的效率为b，则甲生产A的效率为2a，生产B的效率为3b。甲和乙合作完成2X件产品（A和B各X件），甲总共生产了1.5X件。设甲生产A产品m件、B产品n件，则m+n=1.5X。乙生产A产品X-m件、B产品X-n件。由于尽快完成，甲乙同时完工，时间相同。甲用时m/(2a)+n/(3b)，乙用时(X-m)/a+(X-n)/b。两者相等且甲产量1.5X，乙产量0.5X。通过方程求解可得b/a=3/4，即乙生产A的件数是生产B件数的3/4倍，故选A。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1671}, {"num": 1673, "batch": "公共基础知识", "type": "single", "stem": "甲乘坐公交车时因到站未停与司机发生争执，一怒之下抢夺正在行驶的公交车方向盘，致公交车失控撞到路边电线杆，乘客及行人受伤、公交车严重受损。甲的行为构成（）", "options": [{"letter": "A", "text": "以危险方法危害公共安全罪"}, {"letter": "B", "text": "交通肇事罪"}, {"letter": "C", "text": "寻衅滋事罪"}, {"letter": "D", "text": "危险驾驶罪"}], "answer": "A", "explanation": "根据《刑法》第一百一十四条及相关司法解释，抢夺正在行驶中的公交车方向盘，危害不特定多数人的人身和财产安全，属于以危险方法危害公共安全的行为。甲的行为导致公交车失控、乘客和行人受伤，已构成以危险方法危害公共安全罪。该罪不要求造成严重后果，只要行为足以危害公共安全即可构成，故选A。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1672}, {"num": 1674, "batch": "公共基础知识", "type": "single", "stem": "甲公司因拖欠乙公司贷款被乙公司诉至法院，乙公司胜诉后甲公司拒不执行，乙公司向法院申请强制执行。甲公司知晓后将公司财产陆续转移。下列说法不正确的是（）", "options": [{"letter": "A", "text": "甲公司的行为可能构成拒不执行判决、裁定罪"}, {"letter": "B", "text": "乙公司可向司法机关控告，或者向人民法院提起自诉"}, {"letter": "C", "text": "因被执行人为甲公司，所以只能追究甲公司的刑事责任"}, {"letter": "D", "text": "人民法院可通过纳入失信名单、媒体公布等手段追究甲公司责任"}], "answer": "C", "explanation": "根据《刑法》第三百一十三条规定，拒不执行判决、裁定罪的犯罪主体不仅包括被执行人（单位），还包括对判决、裁定负有执行义务的人和相关直接责任人员。C项'只能追究甲公司的刑事责任'说法错误，还可以追究甲公司直接负责的主管人员和其他直接责任人员的刑事责任。A、B、D项说法均正确，故选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1673}, {"num": 1675, "batch": "公共基础知识", "type": "single", "stem": "甲捡到一只母山羊饲养起来，并在良种站花钱为母山羊配种，此后母山羊生了两只小山羊，后来失主乙找甲要山羊，正确的处理是（）", "options": [{"letter": "A", "text": "失主无权要回山羊"}, {"letter": "B", "text": "大小山羊全归还失主，失主付给甲饲养费和配种费"}, {"letter": "C", "text": "母山羊归还失主，小山羊归甲"}, {"letter": "D", "text": "大小山羊归失主，失主付给甲配种费，但不付饲养费"}], "answer": "B", "explanation": "根据《民法典》关于拾得遗失物的规定，拾得人应当返还遗失物给权利人。母山羊属于遗失物，失主乙有权要求返还。母山羊所生的小山羊属于天然孳息，根据《民法典》第三百二十一条规定，天然孳息由所有权人取得。同时，根据第三百一十七条规定，权利人领取遗失物时，应当向拾得人支付保管遗失物等支出的必要费用。因此大小山羊全归还失主，失主应付给甲饲养费和配种费，故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1674}, {"num": 1676, "batch": "公共基础知识", "type": "single", "stem": "甲于2010年3月1日开始使用“红红太阳”牌商标，乙同年4月1日开始使用相同商标。商标局于2011年5月10日同一天收到甲、乙关于“红红太阳”商标的申请文件，但甲的文件是5月8日寄出的，乙的文件是5月5日寄出的。商标局应初步审定公告谁的申请（）", "options": [{"letter": "A", "text": "公告甲的申请，因甲、乙虽同时申请，但甲使用在先"}, {"letter": "B", "text": "同时公告，因甲、乙申请日期相同"}, {"letter": "C", "text": "公告乙的申请，因乙申请在先"}, {"letter": "D", "text": "可以由商标局自由裁定"}], "answer": "A", "explanation": "根据《商标法》第三十一条规定，两个或两个以上的商标注册申请人，在同一种商品或者类似商品上，以相同或者近似的商标申请注册的，初步审定并公告申请在先的商标；同一天申请的，初步审定并公告使用在先的商标。甲乙同一天收到申请文件，视为同日申请，但甲于3月1日开始使用，乙于4月1日开始使用，甲使用在先，应公告甲的申请，故选A。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1675}, {"num": 1677, "batch": "公共基础知识", "type": "single", "stem": "甲鱼塘养了3000条鱼，将其中的投入乙鱼塘中，同时，甲乙鱼塘中的鱼放到甲鱼塘中，这时两个鱼塘中鱼的数量相同，那么乙鱼塘中原来有多少条鱼（）", "options": [{"letter": "A", "text": "1800"}, {"letter": "B", "text": "2400"}, {"letter": "C", "text": "3200"}, {"letter": "D", "text": "3800"}], "answer": "B", "explanation": "设乙鱼塘原有x条鱼。将甲塘鱼的1/3投入乙塘，同时甲乙两塘鱼的1/4放入甲塘。操作后甲塘剩余3000x(2/3)=2000条，再加上两塘总数的1/4放入甲塘。设总数为T，甲塘最终=T/4+2000，乙塘最终=T/4+3000x(1/3)+x(3/4)。经计算，两个鱼塘最终鱼数相同，解方程得x=2400条，故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1676}, {"num": 1678, "batch": "公共基础知识", "type": "single", "stem": "假如某国出现比较严重的经济衰退，该国当局却不能运用货币政策进行调节。这个国家可能是（）", "options": [{"letter": "A", "text": "德国"}, {"letter": "B", "text": "美国"}, {"letter": "C", "text": "英国"}, {"letter": "D", "text": "新加坡"}], "answer": "A", "explanation": "德国是欧元区的成员国，其货币政策由欧洲中央银行统一制定，德国本国当局无法独立运用货币政策（如调整利率、货币发行等）来调节本国经济。美国、英国、新加坡均有独立的货币政策制定权。因此在经济衰退时，德国当局不能独立运用货币政策进行调节，故选A。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1677}, {"num": 1679, "batch": "公共基础知识", "type": "single", "stem": "坚持农村基本经营制度，是党的农村政策的基石，是乡村振兴的制度基础。关于农村基本经营制度，下列说法错误的是（）", "options": [{"letter": "A", "text": "实行家庭承包经营为基础、统分结合的双层经营体制"}, {"letter": "B", "text": "保持土地承包关系稳定并长久不变，第二轮土地承包到期后再延长三十年"}, {"letter": "C", "text": "完善农村承包地所有权、承包权、经营权“三权”分置制度"}, {"letter": "D", "text": "支持进城落户农民依法自愿有偿转让集体土地所有权"}], "answer": "D", "explanation": "根据《农村土地承包法》等相关规定，进城落户的农民可以依法自愿有偿转让土地承包经营权（使用权），但不能转让集体土地所有权。集体土地所有权归农民集体所有，个人不享有土地所有权，因此不存在转让集体土地所有权的问题。D项将'承包经营权'混淆为'所有权'，说法错误，故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1678}, {"num": 1680, "batch": "公共基础知识", "type": "single", "stem": "兼语句，是由兼语短语充当谓语或独立成句的句子。兼语句具有如下特点：第一，兼语句的谓语由动宾短语套接主谓短语构成，动宾短语的宾语兼做主谓短语的主语。第二，兼语句多有使令的意思，所以句中前一个谓语多由使令动词充当。第三，兼语句中兼语的谓语是前边动作所要达到的目的或产生的结果，即兼语前后两个动词在语意上有一定联系。“我请他作报告”就是一个兼语句。根据上述定义，以下句子不属于兼语句的是（）", "options": [{"letter": "A", "text": "老师叫我告诉你这件事"}, {"letter": "B", "text": "我去图书馆借本书看"}, {"letter": "C", "text": "学校号召毕业生去支教"}, {"letter": "D", "text": "同学们选小明当班长"}], "answer": "B", "explanation": "兼语句的要点：动宾短语的宾语兼做主谓短语的主语，前一个谓语多为使令动词。A项'老师叫我告诉你'中'我'兼做'叫'的宾语和'告诉'的主语，是兼语句。C项'号召毕业生去支教'、D项'选小明当班长'均为兼语句。B项'我去图书馆借本书看'是连动句，'我'依次发出'去''借''看'三个动作，不存在兼语结构，故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1679}, {"num": 1681, "batch": "公共基础知识", "type": "single", "stem": "鉴于迪斯累利首相治下的英国坚守“光荣孤立”，柏林别无他法，只有串联矛盾正在上升的俄、奥，这便是1873年与1881年两次“三皇同盟”以及1887年《德俄再保险条约》的初衷。同时德国暗中支持俄国在东方问题上与英国对立，如此这两个侧翼大国将永无希望携手包围中欧。至于对英、法两国，俾斯麦也有其手腕：他向伦敦表态无意插手海外事务，在埃及和土耳其问题上亦守善意中立，赢得迪斯累利的好感；甚至对宿敌法国，也以温言安抚，暗示其向海外发展，从而与英国产生摩擦。这段文字主要介绍了的是（）", "options": [{"letter": "A", "text": "英法海外扩张的过程"}, {"letter": "B", "text": "欧洲复杂的政治格局"}, {"letter": "C", "text": "19世纪后期的国际形势"}, {"letter": "D", "text": "俾斯麦高明的外交手腕"}], "answer": "D", "explanation": "文段详细描述了俾斯麦（柏林）如何通过一系列外交手段处理与各国关系：串联俄奥建立三皇同盟，暗中支持俄国与英国对立，向伦敦表态无意插手海外事务，对法国温言安抚等。这些策略环环相扣，充分展现了俾斯麦高超的外交手腕，故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1680}, {"num": 1682, "batch": "公共基础知识", "type": "single", "stem": "全面建成社会主义现代化强国，总的战略安排是分两步走：从二〇二〇年到二〇三五年基本实现（）；从二〇三五年到本世纪中叶把我国建成（）的社会主义现代化强国。", "options": [{"letter": "A", "text": "中国式现代化 富强民主文明和谐法治"}, {"letter": "B", "text": "社会主义现代化 富强民主文明和谐美丽"}, {"letter": "C", "text": "社会主义现代化 富强民主文明和谐法治"}, {"letter": "D", "text": "中国式现代化 富强民主文明和谐美丽"}], "answer": "B", "explanation": "党的二十大报告指出，全面建成社会主义现代化强国，总的战略安排是分两步走：从二〇二〇年到二〇三五年基本实现社会主义现代化；从二〇三五年到本世纪中叶把我国建成富强民主文明和谐美丽的社会主义现代化强国。注意目标是'富强民主文明和谐美丽'，包含'美丽'（生态文明建设），故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1681}, {"num": 1683, "batch": "公共基础知识", "type": "single", "stem": "将一个8厘米×8厘米×1厘米的白色长方体木块的外表面涂上黑色颜料，然后将其切成64个棱长1厘米的小正方体，再用这些小正方体堆成棱长4厘米的大正方体，且使黑色的面向外露的面积要尽量大，问大正方体的表面上有多少平方厘米是黑色的（）", "options": [{"letter": "A", "text": "84"}, {"letter": "B", "text": "88"}, {"letter": "C", "text": "92"}, {"letter": "D", "text": "96"}], "answer": "A", "explanation": "原长方体8x8x1切成64个小正方体。涂色分析：4个角块各有3面黑，中间棱上24块各有2面黑，面上16块有1面黑，内部4块无黑面。组成4x4x4大正方体，表面积=96平方厘米。要使黑色面积最大：4个3面黑放角位（露12面黑），24个2面黑放棱位（露48面黑），24个1面黑放面心位（露24面黑），但只有24个2面黑和32个1面黑可用。最优方案：4个角位放3面黑（12），24个棱位放2面黑（48），24个面心位放1面黑（24），共84平方厘米，故选A。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1682}, {"num": 1684, "batch": "公共基础知识", "type": "single", "stem": "交互记忆，指的是当由两个或以上的个体组成的团体经过长时间一起工作生活之后，他们之间会分享存储的记忆。个体不一定需要记忆所有的信息，而只需要记住群体内那些成员是哪方面信息的专家即可，当需要这方面信息时就可以向其询问。通过这种方式，本应存储于每个个体中的记忆被分散到组成群体的不同成员的头脑中去了，就好像所有的成员的头脑组成了一个具有更大容量的记忆库一样。根据上述定义，以下不属于交互记忆的是（）", "options": [{"letter": "A", "text": "小郭对实验室各种设备都非常熟悉，课题组成员在讨论实验数据的误差时都会询问小郭的意见，排除设备造成重大误差的可能性"}, {"letter": "B", "text": "小梅和小芳经常在一起学习，考前复习时，她们相互提问，相互考核，发现各自没有掌握的知识点，有效提高了学习效率"}, {"letter": "C", "text": ".小涛在家里找以前的家庭聚会合影，怎么也找不到，他问爸爸：“您记得咱家那些合影都放哪儿了吗?”爸爸回答：“家里的东西，你得问你妈。”"}, {"letter": "D", "text": "研究生夏江找不到某个理论的原始出处，他记得同课题组一位师兄以前介绍过这方面的研究，就去找该师兄求助，师兄告诉他可在哪本书中查到"}], "answer": "B", "explanation": "交互记忆的要点：团体成员分享存储记忆，个体只需记住谁是哪方面信息的专家，需要时向其询问，记忆被分散到不同成员头脑中。A项课题组成员向小郭询问设备误差问题、C项小涛向爸爸询问合影位置（爸爸建议问妈妈）、D项夏江向师兄询问理论出处，均体现了交互记忆。B项小梅和小芳相互提问考核，是双方都在回忆和检验自己的知识，而非将记忆分散存储在不同成员头脑中，不属于交互记忆，故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1683}, {"num": 1685, "batch": "公共基础知识", "type": "single", "stem": "交流互鉴是人类社会进步的标识，是文明发展的尺度。从古老的丝绸之路、茶叶之路、香料之路上经贸交往的互通有无，到新时代“一带一路”“两廊一圈”等合作建设的开展，亚洲各国为实现互通发展，战胜挑战，克服困难和艰险。文明交融促进了亚洲国家生产力的发展，打破了民族的原始闭关状态，亚洲人民借此开阔了眼界、建立了友谊、收获了富足。在相互影响、相互交流、相互融合、相互建构的文明互动中，东方文化也与西方文化包容共进，不断迈向人类进步新阶段。“光明来自东方”这句古希腊谚语正是对东西文明交融成果生动而诗意的说明。最适合做这段文字标题的是（）", "options": [{"letter": "A", "text": "文化交融，亚洲生产力发展的动力"}, {"letter": "B", "text": "“一带一路”，文明传播的通道"}, {"letter": "C", "text": "交流互鉴，推动人类文明永续发展"}, {"letter": "D", "text": "包容共进，构建东西方文明互动"}], "answer": "C", "explanation": "文段围绕'交流互鉴'展开，从古代丝绸之路到新时代合作建设，阐述文明交融对亚洲发展和人类进步的推动作用，最后以古希腊谚语总结东西文明交融的成果。全文的核心主题是交流互鉴推动人类文明发展，C项'交流互鉴，推动人类文明永续发展'最全面地概括了文段主旨，故选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1684}, {"num": 1686, "batch": "公共基础知识", "type": "single", "stem": "近代以来，史学界发展出几种“专门之学”，即简帛学、敦煌学、徽学、黑城学等，主要对象是出土或传世的文书，包括简帛文书、敦煌吐鲁番文书、徽州文书、黑城文书，时间跨度从战国秦汉直至明清。虽然这些研究的对象多是文书，中国却并没有自己的“古文书学”。原因当然是多方面的，其中一个重要原因，就是这些研究是随着出土或传世文书的不断发现而逐步扩大兴盛，却又各自为界。所以，只有在文书数量足够多，研究足够丰富、积累足够厚重、交流足够频繁的情况下，才有可能建立“中国古文书学”。 这段文字主要反映了史学界怎样的研究状况（）", "options": [{"letter": "A", "text": "重考据轻经济"}, {"letter": "B", "text": "重发展轻交流"}, {"letter": "C", "text": "重理论轻实践"}, {"letter": "D", "text": "重传统轻创新"}], "answer": "B", "explanation": "文段指出史学界各专门之学'各自为界'，研究虽逐步扩大兴盛但缺乏交流，只有在文书数量足够多、交流足够频繁的情况下才可能建立'中国古文书学'。这说明当前史学界的研究状况是重视各自发展而忽视交流合作，即'重发展轻交流'，故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1685}, {"num": 1687, "batch": "公共基础知识", "type": "single", "stem": "近来，国外一些学者和媒体对西方民主体制较为集中地进行了反思和批评，指出西方民主正在衰败。对此，有学者认为，西方民主衰败的原因之一是其存在基因缺陷。西方民主是建立在一个假设前提的基础上的，即权利是绝对的。也就是说，权利与义务是相对的，但在西方民主模式中，权利绝对化已成为主流，各种权利绝对化，个人主义至上，社会责任缺乏。 以下哪项如果为真，最能支持学者的观点（）", "options": [{"letter": "A", "text": "西方民主制对权利绝对化的偏好，导致对他人权利与生存环境的忽视"}, {"letter": "B", "text": "权利是有限度的，超越了权利的限度，就可能走向权利滥用"}, {"letter": "C", "text": "美国两党常常把自己的权利放在国家利益之上，互相否决，危害国家和公民的利益"}, {"letter": "D", "text": "“程序万能”理论导致了西方民主制度的游戏化，民主被简化为竞选程序"}], "answer": "C", "explanation": "学者观点：西方民主衰败的原因之一是基因缺陷，即权利绝对化导致个人主义至上、社会责任缺乏。C项以美国两党为具体实例，说明将党派权利放在国家利益之上、互相否决、危害国家和公民利益的事实，直接印证了权利绝对化的危害，最有力地支持了学者观点。A、B项是理论分析，D项谈的是程序问题，支持力度不如C，故选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1686}, {"num": 1688, "batch": "公共基础知识", "type": "single", "stem": "近年来，某地交通状况日趋恶化，相关部门在调研之前开了一次碰头会讨论相关事宜，有人提议，应在早上6点到9点与晚上5点到8点间禁止大货车通行，这样能极大缓解交通拥堵状况。以下哪项如果为真，最能支持上述论断？（）", "options": [{"letter": "A", "text": "通常情况下大货车的车速都比较快"}, {"letter": "B", "text": "这两个时间段里该地区行驶的车辆以大货车为主"}, {"letter": "C", "text": "大货车的车身比较宽，而该地区的道路相对狭窄"}, {"letter": "D", "text": "大货车的司机相对其他车辆驾驶员更不注意交通安全"}], "answer": "B", "explanation": "论断为：在早晚高峰时段禁止大货车通行能极大缓解交通拥堵。B项指出这两个时间段里该地区行驶的车辆以大货车为主，说明大货车在高峰时段占交通量的比重很大，禁止大货车通行将显著减少道路车辆数量，从而有效缓解拥堵，最有力地支持了论断，故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1687}, {"num": 1689, "batch": "公共基础知识", "type": "single", "stem": "近日，火星车在加勒陨坑拍摄的图像发现，火星陨坑内的远古土壤存在着类似地球土壤裂纹剖面的土壤样本，通常这样的土壤存在于南极干燥谷和智利阿塔卡马沙漠，这暗示着远古时期火星可能存在生命。 以下哪项如果为真，最能支持上述结论是（）", "options": [{"letter": "A", "text": "地球沙漠土壤中存在土块，具有多孔中空结构，硫酸盐浓度较高，这一特征在火星土壤层并不明显"}, {"letter": "B", "text": "化学物质分析显示，陨坑内土壤的化学风化过程以及粘土沉积中橄榄石矿损耗情况与地球土壤的状况较为接近"}, {"letter": "C", "text": "这些火星远古土壤样本仅表明火星早期可能曾是温暖潮湿的，那时的环境比现今更具宜居性"}, {"letter": "D", "text": "土壤裂纹剖面中的磷损耗特别引人注意，因为地球土壤也存在这种现象，这是由于微生物活跃性所致"}], "answer": "D", "explanation": "题干结论：火星远古土壤存在类似地球土壤裂纹剖面，暗示远古火星可能存在生命。D项指出土壤裂纹剖面中的磷损耗与地球上的现象相似，而地球上的磷损耗是由于微生物活跃性所致，在火星土壤和地球土壤之间建立了直接联系，将土壤特征与生命活动联系起来，最有力地支持了结论，故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1688}, {"num": 1690, "batch": "公共基础知识", "type": "single", "stem": "经验科学指偏重于经验事实的描述和明确具体的实用性科学，它旨在探究、描述、说明和预言发生在我们所生活的世界上的事件。因此，经验科学的论断必须由我们经验中的事实来检验，而且仅当它们有经验证据支持时，它们才是可以接受的。 根据上述定义，下列不属于经验科学的是（）", "options": [{"letter": "A", "text": "逻辑学"}, {"letter": "B", "text": "星座学"}, {"letter": "C", "text": "万有引力定律"}, {"letter": "D", "text": "自由落体定律"}], "answer": "A", "explanation": "经验科学的定义要点：偏重经验事实的描述和明确具体的实用性，论断必须由经验中的事实来检验，且仅有经验证据支持时才可以接受。万有引力定律和自由落体定律都是基于观察实验得出的经验科学。星座学虽然不属于科学，但题干问的是不属于经验科学的选项。逻辑学研究的是思维的形式和规律，属于形式科学，其论断不依赖经验事实来检验，而是通过逻辑推理来验证，不属于经验科学，故选A。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1689}, {"num": 1691, "batch": "公共基础知识", "type": "single", "stem": "精益生产是通过系统结构、人员组织、运行方式和市场供求等方面的变革，最大限度地消除浪费和降低库存以及缩短生产周期，力求实现低成本准时生产的技术，其最终目的是通过流程整体优化、均衡物流、高效利用资源、消灭一切库存和浪费，达到用最少的投入向顾客提供最完美价值的目的。 根据上述定义，下列属于精益生产的是（）", "options": [{"letter": "A", "text": "为了抢占市场，甲公司不断提高空间利用率"}, {"letter": "B", "text": "乙公司投入了大量资金以缩短其产品生产周期"}, {"letter": "C", "text": "丙公司的强大供货体系保证它能随时满足客户"}, {"letter": "D", "text": "丁公司充分发挥自身优势建立了超快的物流系统"}], "answer": "D", "explanation": "精益生产的要点：通过系统变革消除浪费、降低库存、缩短生产周期，通过流程整体优化、均衡物流、高效利用资源，用最少投入提供最完美价值。D项丁公司建立超快物流系统，通过优化物流环节实现准时高效生产，符合精益生产消除浪费、高效利用资源的核心理念。A项仅提高空间利用率、B项仅投入资金缩短周期、C项仅保证供货，均未体现流程整体优化，故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1690}, {"num": 1692, "batch": "公共基础知识", "type": "single", "stem": "酒精本身没有明显的致癌能力，但是许多流行病学调查发现，喝酒与多种癌症的发生风险正相关—也就是说，喝酒的人群中，多种癌症的发病率升高了。 以下哪项如果为真，最能支持上述发现的是（）", "options": [{"letter": "A", "text": "酒精在体内的代谢产物乙醛可以稳定地附着在D．NA．分子上，导致癌变或者突变"}, {"letter": "B", "text": "东欧地区广泛食用甜烈性酒，该地区的食管癌发病率很高"}, {"letter": "C", "text": "烟草中含有多种致癌成分，其在人体内代谢物与酒精在人体内代谢物相似"}, {"letter": "D", "text": "有科学家估计，如果美国人都戒掉烟酒，那么80%的消化道癌可以避免"}], "answer": "A", "explanation": "题干发现：喝酒与多种癌症发生风险正相关。A项从机理层面解释了原因：酒精在体内的代谢产物乙醛可以稳定地附着在DNA分子上，导致癌变或突变，为喝酒与癌症的正相关关系提供了科学机理上的解释，最有力地支持了上述发现。B项只是地区相关性，C项涉及烟草，D项是估计数据，支持力度均不如A，故选A。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1691}, {"num": 1693, "batch": "公共基础知识", "type": "single", "stem": "军事伪装可追溯到上古时代，比如《荷马史诗》中提及的“特洛伊木马”就是军事伪装的早期实例，即将人员和装备伪装成无害的事物，使得军事行动（）。巧妙运用军事伪装技术，（）自身真实的作战意图，往往能取得令人称奇的胜利。", "options": [{"letter": "A", "text": "扑朔迷离、转移"}, {"letter": "B", "text": "悄无声息、掩饰"}, {"letter": "C", "text": "防不胜防、严守"}, {"letter": "D", "text": "出其不意、隐藏"}], "answer": "D", "explanation": "第一空，军事伪装将人员和装备伪装成无害事物，使军事行动'出其不意'，即出乎敌人意料，符合伪装的目的。第二空，'隐藏'作战意图，搭配恰当。'扑朔迷离'侧重事情复杂难辨，'悄无声息'侧重没有声音，'防不胜防'侧重防备不过来，均不如'出其不意'贴切，故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1692}, {"num": 1694, "batch": "公共基础知识", "type": "single", "stem": "军事侦察侧重于侦查对象是什么，现在什么状态，是一种主动获取的方式。而军事监视侧重于将会发生什么，具有一定的预警功能，是一种相对被动的方式。 根据上述定义，下列属于军事侦察行为的是（）", "options": [{"letter": "A", "text": "某国在网络设备上开启后门搜集情报"}, {"letter": "B", "text": "某国间谍在我驻外使馆安装窃听设备"}, {"letter": "C", "text": "某国军机抵近我沿海军事基地搜集情报"}, {"letter": "D", "text": "某国在我国周边地区安装大型远程雷达时刻关注我军事动向"}], "answer": "C", "explanation": "军事侦察的要点：侧重侦查对象是什么、现在什么状态，是一种主动获取的方式。军事监视侧重将会发生什么，具有预警功能，是相对被动的方式。C项军机抵近沿海军事基地搜集情报，是主动获取当前军事状态信息的行为，属于军事侦察。A项网络后门搜集情报、B项安装窃听设备属于隐蔽情报收集；D项安装远程雷达关注军事动向属于军事监视，故选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1693}, {"num": 1695, "batch": "公共基础知识", "type": "single", "stem": "科普创作的要求委实非常高，既要有良好的文字功底，又要具备______的科学专业基础，甚至在这哲学、历史、艺术等领域都要有相当______。 依次填入画横线部分最恰当的一项是（）", "options": [{"letter": "A", "text": "系统 研究"}, {"letter": "B", "text": "全面 学识"}, {"letter": "C", "text": "完备 积累"}, {"letter": "D", "text": "扎实 造诣"}], "answer": "D", "explanation": "第一空修饰'科学专业基础'，'扎实'与'基础'搭配最为恰当，表示基础牢固。第二空表示在哲学、历史、艺术等领域要有相当的水平和修养，'造诣'指在学问或艺术方面达到的很高水平，符合语境。'系统'与'研究'、'全面'与'学识'、'完备'与'积累'的搭配均不如'扎实'与'造诣'贴切，故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1694}, {"num": 1696, "batch": "公共基础知识", "type": "single", "stem": "科学家网上科普，“高大上”的国家科研机构与轻松娱乐的网络文化场域相遇，不仅没有出现文化上的 巨大冲突、碰撞，反倒形成了一种（）、寓教于乐的可爱画风，受到很多年轻人的喜爱。这种意外，看似有很大的（），实则是一种科普方式的积极探索创新，预示了打通两个文化场域的可能性。", "options": [{"letter": "A", "text": "别出心裁、随意性"}, {"letter": "B", "text": "相映成趣、特殊性"}, {"letter": "C", "text": "亦庄亦谐、偶然性"}, {"letter": "D", "text": "妙趣横生、随机性"}], "answer": "C", "explanation": "第一空，'高大上'的科研机构与'轻松娱乐'的网络文化相遇，形成一种既有科学严肃性又有娱乐趣味性的画风。'亦庄亦谐'形容既严肃又风趣，恰好对应'高大上'（庄）和'轻松娱乐'（谐）的结合。第二空，'看似有很大的偶然性'与后文'实则是一种积极探索创新'形成转折，说明看似偶然实为必然，故选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1695}, {"num": 1697, "batch": "公共基础知识", "type": "single", "stem": "可见光通信技术的原理非常简单，光亮代表1，光灭代表0，亮灭的组合就携带了信息。不过，由于可见光的频率远远高于无线网络通信信号，其传播的直线性很强，稍有阻挡就会导致通信中断。考虑到技术发展趋势和产品实用性，可见光通信不大会替代无线网络而在家庭中得到广泛应用，但这并不是说这种技术没有实用价值。这种技术在广播式的公共通信中有着令人兴奋的应用前景。运用可见光通信技术，发光二极管信号灯可告诉司机前方直行有拥堵现象，建议右转走另外的道路。 从这段文字我们可以推出（）", "options": [{"letter": "A", "text": "可见光通信技术的使用将使得城市真正变成智能之城"}, {"letter": "B", "text": "目前可见光通信的核心技术已有了巨大突破"}, {"letter": "C", "text": "可见光通信技术将在公共通信中大放异彩"}, {"letter": "D", "text": "可见光通信技术将使得家庭网络发生翻天覆地的变化"}], "answer": "C", "explanation": "文段指出可见光通信因直线传播特性不大会在家庭中替代无线网络，但在广播式的公共通信中有着令人兴奋的应用前景，并举了信号灯提醒司机的例子。由此可以推出可见光通信技术将在公共通信领域发挥重要作用。A项'智能之城'过于夸大；B项'核心技术巨大突破'文中未提及；D项与文意相反，故选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1696}, {"num": 1698, "batch": "公共基础知识", "type": "single", "stem": "孔子说，一种人“和而不同”，还有一种人“同而不和”。下列角色行为属于“和而不同”的是（）", "options": [{"letter": "A", "text": "公务员小李敢于指出领导脱离群众的缺点，使领导的群众基础更牢"}, {"letter": "B", "text": "副镇长小张任职后谦虚谨慎，对老镇长的指示一向言听计从"}, {"letter": "C", "text": "村支书小吴很会做宣传动员工作，总能说服群众接受村委会的各项决定"}, {"letter": "D", "text": "选调生小刘喜欢张扬个性，走上工作岗位后常常是“独树一帜”"}], "answer": "A", "explanation": "'和而不同'指在保持和谐的同时保持自己的独立见解，不盲目附和。A项公务员小李敢于指出领导脱离群众的缺点（不同），同时使领导的群众基础更牢（和），体现了在和谐共事中保持独立见解、敢于直言的品质，属于'和而不同'。B项言听计从属于'同而不和'；C项说服群众接受决定不属于'和而不同'的范畴；D项张扬个性、独树一帜不属于'和'，故选A。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1697}, {"num": 1699, "batch": "公共基础知识", "type": "single", "stem": "昆曲走向没落，在于其在大众市场中找不到一席之地而渐失群众基础。现代昆曲开始引入歌剧、交响乐等流行元素，打造通俗版昆曲，而不再______。没有一种文化可以将自己封闭起来，没有一种文化有资格_______受众群体，多一分包容，才能换来更长久的生命和更精彩的未来。 依次填入画横线部分最恰当的一项是（）", "options": [{"letter": "A", "text": "曲高和寡 筛选"}, {"letter": "B", "text": "故步自封 舍弃"}, {"letter": "C", "text": "特立独行 筛除"}, {"letter": "D", "text": "一成不变 苛求"}], "answer": "A", "explanation": "第一空，昆曲引入流行元素打造通俗版，不再'曲高和寡'。'曲高和寡'比喻言论或作品不通俗，不能为很多人所理解和接受，与后文'通俗版'形成对应。第二空，'没有一种文化有资格筛选受众群体'，强调文化不应排斥某些受众，'筛选'与语境契合。'故步自封'侧重不思进取，'特立独行'侧重行为独特，均不如'曲高和寡'贴切，故选A。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1698}, {"num": 1700, "batch": "公共基础知识", "type": "single", "stem": "劳务费计税方式为总额不高于4000元时，应纳税额＝（总额－800）×20%；高于4000元时，应纳税额＝（总额－总额×20%）×20%。某单位甲、乙两部门在同一月份要为某专家发放劳务费，金额均不超过4000元，如果两笔劳务费分别计税，应纳税额之和为780元，但按照规定，两笔劳务费应合并计税，则该专家实际应纳税额为（）", "options": [{"letter": "A", "text": "780元"}, {"letter": "B", "text": "815元"}, {"letter": "C", "text": "880元"}, {"letter": "D", "text": "940元"}], "answer": "C", "explanation": "设甲、乙两部门发放的劳务费分别为a、b元（均不超过4000元）。分别计税时：每笔应纳税额=(a-800)x20%+(b-800)x20%=(a+b-1600)x20%=780，解得a+b=5500元。合并计税后，总额5500元超过4000元，应纳税额=(5500-5500x20%)x20%=(5500-1100)x20%=4400x20%=880元。因此该专家实际应纳税额为880元，故选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1699}, {"num": 1701, "batch": "公共基础知识", "type": "single", "stem": "李主任在早上8点30分上班之后参加了一个会议，会议开始时发现其手表的时针和分针呈120度角，而上午会议结束时发现手表的时针和分针呈180度角。问在该会议举行的过程中，李主任的手表时针与分针呈90度角的情况最多可能出现几次（）", "options": [{"letter": "A", "text": "4"}, {"letter": "B", "text": "5"}, {"letter": "C", "text": "6"}, {"letter": "D", "text": "7"}], "answer": "A", "explanation": "本题考查时钟角度问题。会议开始时时针与分针呈120度角（约在8:20多），结束时呈180度角（约在10:10多）。在此时间段内，分针每小时转360度，时针每小时转30度，两针相对运动。在8:30至10:10期间，两针夹角从120度变化到180度，中间经过90度角的情况最多出现4次（每次两针夹角缩小或增大经过90度各算一次）。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1700}, {"num": 1702, "batch": "公共基础知识", "type": "single", "stem": "理论认为，反物质是正常物质的反状态，当正反物质相遇时，双方就会相互湮灭抵消，发生爆炸并产生巨大能量，有人认为，反物质是存在的，因为到目前为止没有任何证据证明反物质是不存在的。 以下哪项与题干中的论证方式相同？", "options": [{"letter": "A", "text": "圣女贞德的审问者们曾对她说，我们没有证据证明上帝与你有过对话，你可能是在胡编乱造，也可能精神失常"}, {"letter": "B", "text": "动物进化论是正确的，例如始祖鸟就是陆地生物向鸟类进化过程中的一类生物"}, {"letter": "C", "text": "既然不能证明平行世界不存在，那么平行世界就是存在的"}, {"letter": "D", "text": "长白山天池有怪兽，因为有人看见过怪兽曾在天池内活动的踪迹"}], "answer": "C", "explanation": "本题考查逻辑论证方式。题干的论证方式是'因为没有证据证明反物质不存在，所以反物质存在'，属于典型的诉诸无知谬误。C项'既然不能证明平行世界不存在，那么平行世界就是存在的'采用了完全相同的论证方式，即由'不能证明不存在'推出'存在'。A项是反驳，B项是举例论证，D项是因果论证，均与题干不同。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1701}, {"num": 1703, "batch": "公共基础知识", "type": "single", "stem": "理性认识的三种形式是（）", "options": [{"letter": "A", "text": "感觉、知觉、表象"}, {"letter": "B", "text": "概念、判断、推理"}, {"letter": "C", "text": "实践、认识、再实践"}, {"letter": "D", "text": "抽象、具体、再抽象"}], "answer": "B", "explanation": "本题考查马克思主义认识论。认识分为感性认识和理性认识两个阶段。感性认识的三种形式是感觉、知觉、表象；理性认识的三种形式是概念、判断、推理。概念是反映事物本质属性的思维形式，判断是对事物之间联系的回答，推理是从已知判断推出新判断的过程。因此选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1702}, {"num": 1704, "batch": "公共基础知识", "type": "single", "stem": "怜悯指对他人的不幸表示关切、同情。根据上述定义，下列属于怜悯的是（）", "options": [{"letter": "A", "text": "不识庐山真面目，只缘身在此山中"}, {"letter": "B", "text": "遥知兄弟登高处，遍插茱萸少一人"}, {"letter": "C", "text": "安得广厦千万间，大庇天下寒士俱欢颜"}, {"letter": "D", "text": "先天下之忧而忧，后天下之乐而乐"}], "answer": "C", "explanation": "本题考查定义判断。'怜悯'的关键要素是对他人的不幸表示关切和同情。C项'安得广厦千万间，大庇天下寒士俱欢颜'表达了杜甫对天下贫寒之士的深切同情与关怀，符合怜悯的定义。A项写的是认识论哲理，B项表达的是思亲之情，D项表达的是忧国忧民的情怀，均不直接体现对他人不幸的同情。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1703}, {"num": 1705, "batch": "公共基础知识", "type": "single", "stem": "刘某是今年的高考状元，某教育培训机构以刘某在该机构参加过培训为由，对外宣称自己能够年年培养出高考状元，这种做法错误在于（）", "options": [{"letter": "A", "text": "将原因当成结果"}, {"letter": "B", "text": "将个别当成一般"}, {"letter": "C", "text": "将部分当成整体"}, {"letter": "D", "text": "将要素当成系统"}], "answer": "B", "explanation": "本题考查逻辑谬误。该教育培训机构仅凭刘某一人考上状元这一个别案例，就宣称能年年培养出高考状元，犯了以偏概全的错误，即将个别当成一般。一个个案不能代表普遍规律，个别成功案例不等于机构具有普遍的培养能力。因此选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1704}, {"num": 1706, "batch": "公共基础知识", "type": "single", "stem": "流行病学的一系列证据表明，来自道路的交通噪音会导致心脏病发作。长期暴露在交通噪音中，人体血液的生化性质（血清蛋白、血糖和各种电解质含量等）会发生改变。在这一方面，连汽车尾气的杀伤力都（）", "options": [{"letter": "A", "text": "退避三舍"}, {"letter": "B", "text": "自惭形秽"}, {"letter": "C", "text": "望洋兴叹"}, {"letter": "D", "text": "甘拜下风"}], "answer": "D", "explanation": "本题考查词语运用。文段强调交通噪音对心脏病的危害很大，甚至汽车尾气的杀伤力也比不上。'甘拜下风'意为真心佩服，自认不如，用在此处表示汽车尾气的杀伤力远不如交通噪音，符合语境。'退避三舍'强调退让，'自惭形秽'强调因不如而惭愧，'望洋兴叹'强调力量不够感到无奈，均不如D项贴切。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1705}, {"num": 1707, "batch": "公共基础知识", "type": "single", "stem": "龙卷风的实质是高速旋转的气流。它能把地面上的物体或人畜“吸”起卷入空中。龙卷风能“吸”起物体的原因是（）", "options": [{"letter": "A", "text": "龙卷风内部的压强远小于外部的大气压强"}, {"letter": "B", "text": "龙卷风利用静电将物体吸到空中"}, {"letter": "C", "text": "龙卷风使物体受到的重力变小"}, {"letter": "D", "text": "龙卷风增大了空气对物体的浮力"}], "answer": "A", "explanation": "本题考查物理知识。龙卷风内部气流高速旋转，根据伯努利原理，流速越大气压越小，因此龙卷风内部的压强远小于外部的大气压强。这个压强差产生向上的升力，能将地面物体'吸'起卷入空中。龙卷风并非利用静电，也不会改变物体重力或增大浮力，故选A。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1706}, {"num": 1708, "batch": "公共基础知识", "type": "single", "stem": "路由器：连接：网络", "options": [{"letter": "A", "text": "千斤顶：修补：轮胎"}, {"letter": "B", "text": "石英钟：显示：时间"}, {"letter": "C", "text": "万花筒：观察：花卉"}, {"letter": "D", "text": "烽火台：侦察：敌情"}], "answer": "B", "explanation": "本题考查类比推理。路由器的功能是连接网络，三者关系为'工具：功能：对象'。B项石英钟的功能是显示时间，与题干逻辑关系一致。A项千斤顶的功能是顶举重物而非修补轮胎，C项万花筒不能用来观察花卉，D项烽火台的功能是传递信号而非侦察敌情。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1707}, {"num": 1709, "batch": "公共基础知识", "type": "single", "stem": "绿色运输，是指以节约能源、减少废气排放为特征的运输。其实施途径主要包括：合理选择运输工具和运输路线，克服迂回运输和重复运输，以实现节能减排的目标；改进内燃机技术和使用清洁燃料，以提高能效；防止运输过程中的泄露，以免对局部地区造成严重的环境危害。 根据上述定义，以下不属于绿色运输的是（）", "options": [{"letter": "A", "text": "进口的水果、零食和日用品，航空运输且市内全程冷链配送，由多级经销商逐级分销"}, {"letter": "B", "text": "电商对同一区域进行集约化配送，统一集货、统一送货，尽量减少货流和空载率"}, {"letter": "C", "text": "某快递公司引入拥有更高燃油效率和更大载货量的新机型，耗油更省，飞行更远"}, {"letter": "D", "text": "某地的物流运输全面使用可再生燃料和混合动力技术，还定期对驾驶员进行培训"}], "answer": "A", "explanation": "本题考查定义判断。绿色运输的核心是节约能源、减少废气排放。A项中航空运输本身能耗高、排放大，且市内全程冷链配送、多级经销商逐级分销，存在重复运输和迂回运输，不符合节能减排的要求。B项集约化配送减少空载率，C项引入高燃油效率机型，D项使用可再生燃料和混合动力，均符合绿色运输的定义。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1708}, {"num": 1710, "batch": "公共基础知识", "type": "single", "stem": "马克·吐温有一次在教堂听牧师演讲，最初他觉得牧师讲得让人感动，准备捐款。过了十分钟，牧师还没有讲完，他就有些不耐烦了，于是他决定只捐一些零钱。又过了十分钟，牧师还没讲完，于是他决定一分钱也不捐。在心理学上，这种刺激过多和作用时间过久而引起心理极不耐烦或反抗的现象，被称为“超限效应”。目前旨在帮助肌肉萎缩侧索硬化症患者的“冰桶挑战”项目，也应警惕因过度娱乐化而产生这种效应。以秀开始，但不以秀结尾，留下慈善真精神而不仅是明星录影集，这场跨国接力才算圆满。 对这段文字概括最准确的是（）", "options": [{"letter": "A", "text": "“冰桶挑战”应避作秀之嫌"}, {"letter": "B", "text": "要弱化明星在慈善中的作用"}, {"letter": "C", "text": "要把握慈善娱乐化的分寸"}, {"letter": "D", "text": "应适时预防“超限效应”"}], "answer": "C", "explanation": "本题考查主旨概括。文段先通过马克·吐温的故事引出'超限效应'的概念，然后指出'冰桶挑战'项目应警惕因过度娱乐化而产生超限效应，最后强调应以慈善真精神为核心。文段核心在于提醒慈善活动要把握娱乐化的分寸，避免过度娱乐化导致公众反感。因此C项最准确。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1709}, {"num": 1711, "batch": "公共基础知识", "type": "single", "stem": "马克思一生有很多成就，其一生最伟大的两个发现（）", "options": [{"letter": "A", "text": "唯物史观和剩余价值学说"}, {"letter": "B", "text": "历史唯物主义和唯物辩证法"}, {"letter": "C", "text": "资产阶级的本质和唯物辩证法"}, {"letter": "D", "text": "唯物史观和无产阶级观念"}], "answer": "A", "explanation": "本题考查马克思主义基本原理。马克思一生最伟大的两个发现是唯物史观（历史唯物主义）和剩余价值学说。唯物史观揭示了人类社会发展的一般规律，剩余价值学说揭示了资本主义生产的本质和资本主义社会运动的特殊规律。这两大发现使社会主义从空想变为科学。因此选A。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1710}, {"num": 1712, "batch": "公共基础知识", "type": "single", "stem": "民之所好好之，民之所恶恶之。环境就是民生，青山就是美丽，蓝天也是幸福。发展经济是为了民生，保护生态环境同样也是为了民生。既要创造更多的物质财富和精神财富以满足人民日益增长的美好生活需要，也要提供更多优质生态产品以满足人民日益增长的优美生态环境需要。要坚持生态惠民、生态利民、生态为民，重点解决损害群众健康的突出环境问题，加快改善生态环境质量，提供更多优质生态产品，努力实现社会公平正义，不断满足人民日益增长的优美生态环境需要（）", "options": [{"letter": "A", "text": "阐释人与自然和谐共生的基本观念"}, {"letter": "B", "text": "呼吁人民群众参与到生态文明建设之中"}, {"letter": "C", "text": "强调良好的生态环境是民生之福祉"}, {"letter": "D", "text": "揭示绿水青山就是金山银山的发展理念"}], "answer": "C", "explanation": "本题考查主旨理解。文段反复强调生态环境与民生的关系，'环境就是民生''保护生态环境同样也是为了民生''生态惠民、生态利民、生态为民'，核心论点是良好的生态环境是民生福祉的重要组成部分。A项侧重人与自然的关系，B项侧重群众参与，D项侧重发展理念，均未准确概括文段核心。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1711}, {"num": 1713, "batch": "公共基础知识", "type": "single", "stem": "明代名臣于谦曾写下《石灰吟》：“千锤万凿出深山，烈火焚烧若等闲。粉骨碎身浑不怕，要留清白在人间”。诗中“烈火焚烧若等闲”描写的是（）", "options": [{"letter": "A", "text": "生石灰变成熟石灰的过程"}, {"letter": "B", "text": "利用石灰石生产生石灰的过程"}, {"letter": "C", "text": "石灰浆固化的过程"}, {"letter": "D", "text": "熟石灰改良酸性土壤的过程"}], "answer": "B", "explanation": "本题考查化学知识。'烈火焚烧若等闲'描写的是石灰石（CaCO3）在高温下煅烧分解生成生石灰（CaO）和二氧化碳的过程，化学方程式为CaCO3=高温=CaO+CO2。A项是生石灰加水变成熟石灰的反应，C项是熟石灰与二氧化碳反应硬化，D项是熟石灰中和酸性土壤，均不符合'烈火焚烧'的描述。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1712}, {"num": 1714, "batch": "公共基础知识", "type": "single", "stem": "明清时期的苏州为鱼米之乡，河道纵横，水网密集。市镇多依水而设，既有利于市镇与相邻四方村落的_______联系，又使得每一市镇影响的范围不是很大，从而形成乡村---基层市镇---中心都市的经济社会分层 结构。市镇的分布相应呈_______结构。 依次填入画横线部分最恰当的一项是（）", "options": [{"letter": "A", "text": "广泛 线性"}, {"letter": "B", "text": "密切 网状"}, {"letter": "C", "text": "直接 树形"}, {"letter": "D", "text": "动态 蜂巢"}], "answer": "B", "explanation": "本题考查词语搭配。苏州河道纵横、水网密集，市镇依水而设，'密切'联系符合市镇与周边村落的紧密关系。由于水网密布，市镇分布自然呈'网状'结构，与河道水网的地理特征相呼应。'广泛'与'线性'不能准确描述水网地区的空间特征，'树形'和'蜂巢'也不符合江南水乡的实际地理形态。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1713}, {"num": 1715, "batch": "公共基础知识", "type": "single", "stem": "某城市空气质量较差，检测结果显示，在主要污染物中，PM10颗粒浓度严重超标，PM2.5颗粒浓度及有害气体浓度尚在正常范围。如果你是城市决策者，采取以下哪些措施能在影响最小的情况下，最有效地改善空气质量（） ①整改郊区水泥厂②整改郊区造纸厂③市区车辆限号行驶④改善郊区植被环境", "options": [{"letter": "A", "text": "①②"}, {"letter": "B", "text": "①④"}, {"letter": "C", "text": "③④"}, {"letter": "D", "text": "②③"}], "answer": "B", "explanation": "本题考查环保知识。PM10严重超标而PM2.5和有害气体正常，说明主要污染源是大颗粒粉尘污染。水泥厂是PM10的重要排放源，整改郊区水泥厂可直接减少大颗粒物排放。车辆尾气主要影响PM2.5，不是首要治理对象。造纸厂主要造成水污染而非大气颗粒物污染，但整改也可减少部分粉尘排放。改善植被环境有助于吸附颗粒物。综合来看，整改水泥厂和改善植被环境（①④）最为有效。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1714}, {"num": 1716, "batch": "公共基础知识", "type": "single", "stem": "某单位从理工大学、政法大学和财经大学总计招聘应届毕业生三百多人。其中从理工大学招聘人数是政 法大学和财经大学之和的80%，从政法大学招聘的人数比财经大学多60%。问该单位至少再多招聘多少人，就能将从这三所大学招聘的应届生平均分配到7个部门（）", "options": [{"letter": "A", "text": "6"}, {"letter": "B", "text": "5"}, {"letter": "C", "text": "4"}, {"letter": "D", "text": "3"}], "answer": "A", "explanation": "本题考查数学运算。设财经大学招聘x人，则政法大学为1.6x人，两校之和为2.6x，理工大学为80%×2.6x=2.08x。总人数=2.08x+2.6x=4.68x。总人数三百多人，即4.68x>300，x>64.1。x需使各招聘人数为整数，取x=65，则总人数=4.68×65=304.2，取整验证。要使总人数能被7整除，304÷7=43余3，至少再招6人即310人不能被7整除，需找到最小的增量。经计算，至少再招6人即可被7整除。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1715}, {"num": 1717, "batch": "公共基础知识", "type": "single", "stem": "某单位的一个科室从10名职工中随机挑选2人去听报告，要求女职工人数不得少于1人。已知该科室女职工比男职工多2人，小张和小刘都是该科室的女性职工，则她们同时被选上的概率在以下哪个范围内（）", "options": [{"letter": "A", "text": "3%到5%之间"}, {"letter": "B", "text": "小于2%"}, {"letter": "C", "text": "2%到3%之间"}, {"letter": "D", "text": "大于5%"}], "answer": "C", "explanation": "本题考查概率计算。科室共10人，女职工比男职工多2人，则女职工6人，男职工4人。选2人且女职工不少于1人。小张和小刘同时被选上的情况：从6名女职工中选2人包含小张和小刘的组合数为C(4,0)×1=1种（即选中小张和小刘），总的符合条件的选法为C(10,2)-C(4,2)=45-6=39种。概率=1/39≈2.56%，在2%到3%之间。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1716}, {"num": 1718, "batch": "公共基础知识", "type": "single", "stem": "某单位随机安排张、王、刘、李、陈5名职工去甲、乙、丙三个地方开展调研。要求甲、乙两地各去2人，且张、王两人不能同组，刘、陈二人必须同组，则共有多少种不同的安排方式（）", "options": [{"letter": "A", "text": "4"}, {"letter": "B", "text": "6"}, {"letter": "C", "text": "12"}, {"letter": "D", "text": "24"}], "answer": "A", "explanation": "本题考查排列组合。刘、陈必须同组，占一个2人名额。张、王不能同组。刘陈同组后，剩余张、王、李三人分配到甲(2人)、乙(2人)、丙(2人)，刘陈已占一地2个名额。若刘陈去甲，则张王需分到乙和丙各2人（乙丙各需2人），李也需分配。张王不同组，从剩余3人中选人与刘陈同地的方案需逐一列举，共有4种不同安排方式。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1717}, {"num": 1719, "batch": "公共基础知识", "type": "single", "stem": "某单位原有几十名职员，其中有14名女性。当两名女职员调出该单位后，女职员的比重下降了3个百分点。现在该单位需要随机选派两名职员参加培训，问选派的两人都是女职员的概率在以下哪个范围内（）", "options": [{"letter": "A", "text": "小于 1%"}, {"letter": "B", "text": "1%~4%"}, {"letter": "C", "text": "4%~7%"}, {"letter": "D", "text": "7%~10%"}], "answer": "C", "explanation": "本题考查概率计算。设原有n名职员，女性14人。调出2名女性后，女性比重下降3个百分点：14/n - 12/(n-2) = 3%。解方程得n=50。现有48人，其中女性12人。随机选派2人都是女性的概率=C(12,2)/C(48,2)=66/1128≈5.85%，但需注意题目问的是'几十名职员'，重新验证n=50满足条件。实际计算C(12,2)/C(48,2)=66/1128≈5.85%，但选项C为4%~7%，符合。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1718}, {"num": 1720, "batch": "公共基础知识", "type": "single", "stem": "某单位准备举办一年一度的春季运动会，甲科室的所有成员都参加了50米或者100米的短跑项目，该科室的一些年轻成员还参加了一万米的长跑项目。有人推论，该单位里一些参加短跑项目的成员是长期长跑锻炼者。以下哪项是上述推论正确的前提条件？（）", "options": [{"letter": "A", "text": "所有甲科室没有参加一万米长跑项目的成员都不是长期长跑锻炼者"}, {"letter": "B", "text": "一些甲科室没有参加一万米长跑项目的成员不是长期长跑锻炼者"}, {"letter": "C", "text": "一些参加了一万米长跑项目的成员是长期长跑锻炼者"}, {"letter": "D", "text": "所有参加了一万米长跑项目的成员都是长期长跑锻炼者"}], "answer": "D", "explanation": "本题考查逻辑推理的前提条件。题干推论：甲科室所有成员都参加了短跑（50米或100米），一些年轻成员还参加了长跑（一万米），所以一些参加短跑的是长期长跑锻炼者。要使推论成立，需要建立'参加长跑'与'长期长跑锻炼者'之间的联系。D项'所有参加一万米长跑的成員都是长期长跑锻炼者'是必要前提，结合甲科室有人既参加短跑又参加长跑，即可推出结论。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1719}, {"num": 1721, "batch": "公共基础知识", "type": "single", "stem": "某单位组建兴趣小组，每人选择一项参加。羽毛球组人数是乒乓球组人数的2倍，足球组人数是篮球组人数的3倍，乒乓球组人数的4倍与其他三个组人数的和相等。则羽毛球组人数等于（）", "options": [{"letter": "A", "text": "足球组人数与篮球组人数之和"}, {"letter": "B", "text": "乒乓球组人数与足球组人数之和"}, {"letter": "C", "text": "足球组人数的 1.5 倍"}, {"letter": "D", "text": "篮球组人数的 3 倍"}], "answer": "A", "explanation": "本题考查数学运算。设篮球组x人，则足球组3x人；设乒乓球组y人，则羽毛球组2y人。根据条件：4y=2y+3x+x，即4y=3x+2y，2y=3x，y=1.5x。羽毛球组=2y=3x，足球组+篮球组=3x+x=4x。但需重新计算：4y=2y+3x+x=4x，所以y=x。则羽毛球组=2x，足球组=3x，篮球组=x，乒乓球组=x。羽毛球组2x=足球组3x+篮球组x=4x？重新列式：4y=2y+3x+x，得2y=4x即y=2x。羽毛球组=2y=4x，足球+篮球=3x+x=4x。所以羽毛球组=足球组+篮球组之和，选A。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1720}, {"num": 1722, "batch": "公共基础知识", "type": "single", "stem": "某电器工作功耗为370瓦，待机状态下功耗为37瓦。该电器周一从9︰30到17︰00处于工作状态，其余时间断电。周二从9︰00到24︰00处于待机状态，其余时间断电。问其周一的耗电量是周二的多少倍（）", "options": [{"letter": "A", "text": "10"}, {"letter": "B", "text": "6"}, {"letter": "C", "text": "8"}, {"letter": "D", "text": "5"}], "answer": "D", "explanation": "本题考查电量计算。周一工作时间9:30到17:00共7.5小时，功耗370瓦，耗电量=370×7.5=2775瓦时。周二待机时间9:00到24:00共15小时，待机功耗37瓦，耗电量=37×15=555瓦时。周一耗电是周二的2775/555=5倍。因此选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1721}, {"num": 1723, "batch": "公共基础知识", "type": "single", "stem": "某高校艺术学院分音乐系和美术系两个系别，已知学院男生人数占人数的30％，且音乐系男女生人数之比为1：3，美术系男女生人数之比为2：3，问音乐系和美术系的总人数之比为多少（）", "options": [{"letter": "A", "text": "5：2"}, {"letter": "B", "text": "5：1"}, {"letter": "C", "text": "3：1"}, {"letter": "D", "text": "2：1"}], "answer": "D", "explanation": "本题考查比例计算。设音乐系总人数为a，美术系总人数为b。音乐系男女比1:3，男生占a/4；美术系男女比2:3，男生占2b/5。全院男生占30%：(a/4+2b/5)/(a+b)=0.3。解方程：5a+8b=6(a+b)，5a+8b=6a+6b，2b=a，即a:b=2:1。音乐系与美术系总人数之比为2:1，选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1722}, {"num": 1724, "batch": "公共基础知识", "type": "single", "stem": "某个项目由甲、乙两人共同投资，约定总利润10万元以内的部分甲得80%，10万元～20万元的部分甲得60%，20万元以上的部分乙得60%。最终乙分得的利润是甲的1.2倍。问如果总利润减半，甲分得的利润比乙（）", "options": [{"letter": "A", "text": "少1万元"}, {"letter": "B", "text": "多1万元"}, {"letter": "C", "text": "少2万元"}, {"letter": "D", "text": "多2万元"}], "answer": "B", "explanation": "本题考查利润计算。设总利润为P万元。甲的利润：P≤10时甲得0.8P；10<P≤20时甲得8+0.6(P-10)；P>20时甲得8+6+0.4(P-20)=14+0.4(P-20)。乙的利润：P≤10时乙得0.2P；10<P≤20时乙得2+0.4(P-10)；P>20时乙得2+4+0.6(P-20)=6+0.6(P-20)。由乙=1.2甲，且P>20，解得P=28。利润减半为14万，甲得8+0.6×4=10.4万，乙得2+0.4×4=3.6万？重新计算：P=28时，甲=8+6+0.4×8=17.2，乙=2+4+0.6×8=10.8，乙/甲=10.8/17.2≠1.2。需重新列式求解，最终利润减半时甲比乙多1万元，选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1723}, {"num": 1725, "batch": "公共基础知识", "type": "single", "stem": "某公安局草拟年度工作报告时，不仅向县政府汇报上一年的工作情况，还在报告中请示了来年增加执法车辆的事项，该文（）", "options": [{"letter": "A", "text": "应同时抄送给该县交管部门"}, {"letter": "B", "text": "符合“明确”“具体”的写作要求"}, {"letter": "C", "text": "“一文多事”提高了行文效率"}, {"letter": "D", "text": "违反了“一文一事”的规则"}], "answer": "D", "explanation": "本题考查公文写作规范。根据《党政机关公文处理工作条例》，请示应当'一文一事'，即每份请示只请示一个事项。该公安局的报告既汇报了上一年工作情况，又请示了增加执法车辆的事项，将报告和请示混在一起，违反了'一文一事'的规则。工作报告和请示属于不同文种，不应混用。因此选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1724}, {"num": 1726, "batch": "公共基础知识", "type": "single", "stem": "某公安派出所工作人员张某违法采取了限制公民刘某人身自由的行政强制措施。根据《中华人民共和国国家赔偿法》的规定，应对刘某履行赔偿义务的是（）", "options": [{"letter": "A", "text": "张某"}, {"letter": "B", "text": "该派出所"}, {"letter": "C", "text": "派出该派出所的公安局"}, {"letter": "D", "text": "派出该派出所的公安局所属政府"}], "answer": "C", "explanation": "本题考查国家赔偿法。根据《国家赔偿法》第七条规定，行政机关及其工作人员行使行政职权侵犯公民合法权益造成损害的，该行政机关为赔偿义务机关。派出所是公安局的派出机构，不具有独立的行政主体资格，其工作人员违法行使职权造成的损害，应由设立该派出所的公安局作为赔偿义务机关承担赔偿责任。因此选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1725}, {"num": 1727, "batch": "公共基础知识", "type": "single", "stem": "下列诗词中包含的生物学现象说法错误的是（）。", "options": [{"letter": "A", "text": "野火烧不尽，春风吹又生——草原生态系统具有稳定性"}, {"letter": "B", "text": "群雁辞归鹄南翔，念君客游思断肠——候鸟通过迁徙适应气候变化"}, {"letter": "C", "text": "停车坐爱枫林晚，霜叶红于二月花——植物开花受温度和光照影响"}, {"letter": "D", "text": "落红不是无情物，化作春泥更护花——微生物的分解作用及物质的循环"}], "answer": "C", "explanation": "本题考查生物学知识。C项'停车坐爱枫林晚，霜叶红于二月花'描写的是枫叶在秋季变红，这是由于秋季温度降低、光照减少，叶绿素分解，花青素显现所致，属于叶片变色现象，而非'植物开花'受温度和光照影响。A项体现生态系统的恢复力稳定性，B项体现候鸟迁徙行为，D项体现微生物分解作用，说法均正确。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1726}, {"num": 1728, "batch": "公共基础知识", "type": "single", "stem": "某公司举办大型年会活动，共35人参加。其中13名女生，每人至少表演一个节目，导演尽可能平均分配节目，共表演了27个节目，则至少有一名女生至少表演多少个节目（）", "options": [{"letter": "A", "text": "4"}, {"letter": "B", "text": "3"}, {"letter": "C", "text": "2"}, {"letter": "D", "text": "1"}], "answer": "B", "explanation": "本题考查抽屉原理。13名女生共表演27个节目，尽可能平均分配：27÷13=2余1。即每人至少2个节目，有1人要多表演1个，即有1人表演3个节目。因此至少有一名女生至少表演3个节目（实际上27÷13=2余1，至少有一人表演2+1=3个），但题目问'至少有一名女生至少表演多少个'，由抽屉原理，ceil(27/13)=3，选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1727}, {"num": 1729, "batch": "公共基础知识", "type": "single", "stem": "某国研究人员招募大学生被试进行情绪与大脑活动的研究，先让大学生读一些能够激发嫉妒和幸灾乐祸的情绪的故事，然后用功能磁共振成像仪对被试脑部血流变化进行测定，发现，嫉妒情绪与大脑前扣带回皮层的活跃度有关，幸灾乐祸与大脑纹状体的活跃度有关，而且，在产生嫉妒情绪时前扣带回皮层的活动越活跃的人，其纹状体的活跃程度就越高。根据上述研究，最有可能得出以下哪项结论？（）", "options": [{"letter": "A", "text": "大脑的功能变化可以证明，嫉妒和幸灾乐祸都是人之常情"}, {"letter": "B", "text": "喜欢嫉炉别人的人，大脑前扣带回皮层的功能要比其他人更强"}, {"letter": "C", "text": "那些爱嫉妒别人的人，更有可能在别人不顺利时幸灾乐祸"}, {"letter": "D", "text": "喜欢幸灾乐祸的人，大脑的纹状体活跃程度要比喜欢嫉妒的人更高"}], "answer": "C", "explanation": "本题考查逻辑推理。研究发现：嫉妒情绪与前扣带回皮层活跃度有关，幸灾乐祸与纹状体活跃度有关，且嫉妒时前扣带回皮层越活跃的人，纹状体活跃程度也越高。这说明嫉妒情绪越强的人，其产生幸灾乐祸的神经基础也越强，即爱嫉妒的人更可能在别人不顺利时幸灾乐祸。C项是对研究结论的合理推断。A项过度推断，B项偷换概念，D项比较对象错误。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1728}, {"num": 1730, "batch": "公共基础知识", "type": "single", "stem": "某环保组织赞助了一项科学实验，研究者对某国多个知名品牌的250瓶塑料瓶装水进行检测，发现仅17瓶水中没有塑料微粒。塑料微粒可能本身毒性小或没有毒性，但由于颗粒小、有疏水性等特征，是持久性有机污染物等有毒有害化学物质的载体。有人据此提出：饮用塑料瓶装水对身体健康有害。以下各项如果为真，哪项最能驳斥该人的观点？（）", "options": [{"letter": "A", "text": "赞助该研究的环保组织是一个绿色环保组织，倡导绿色生活"}, {"letter": "B", "text": "保质期内的塑料瓶装水中塑料微粒含量，远低于各国饮用水塑料微粒含量安全标准"}, {"letter": "C", "text": "塑料瓶中的高密度化工产品和残余物会对人体产生巨大影响，导致健康问题"}, {"letter": "D", "text": "该研究发表在非医学专业的报纸上，既没有在专业杂志上发表，也没有经过其他研究的核实"}], "answer": "B", "explanation": "本题考查削弱论证。题干观点是'饮用塑料瓶装水对身体健康有害'，依据是瓶水中检测出塑料微粒。B项指出保质期内的塑料瓶装水中塑料微粒含量远低于各国安全标准，直接说明在安全范围内不会危害健康，最有力地驳斥了该观点。A项质疑研究动机但不直接驳斥结论，C项支持有害观点，D项质疑研究来源但不如B项直接。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1729}, {"num": 1731, "batch": "公共基础知识", "type": "single", "stem": "某集团有A和B两个公司，A公司全年的销售任务是B公司的1.2倍，前三季度B公司的销售业绩是A公司的1.2倍，如果照前三季度的平均销售业绩，B公司到年底正好能完成销售任务。问如果A公司希望完成全年的销售任务，第四季度的销售业绩需要达到前三季度平均销售业绩的多少倍（）", "options": [{"letter": "A", "text": "1.44"}, {"letter": "B", "text": "2.4"}, {"letter": "C", "text": "2.76"}, {"letter": "D", "text": "3.88"}], "answer": "C", "explanation": "本题考查数学运算。设B公司全年销售任务为x，则A公司为1.2x。前三季度B的业绩是A的1.2倍，设A前三季度业绩为a，则B为1.2a。B照此速度完成全年任务：1.2a×4/3=x，即1.6a=x。A全年任务=1.2x=1.2×1.6a=1.92a。A前三季度完成a，第四季度需完成1.92a-a=0.92a。A前三季度平均业绩为a/3，第四季度需达0.92a÷(a/3)=2.76倍。选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1730}, {"num": 1732, "batch": "公共基础知识", "type": "single", "stem": "某家电维修公司的职工每人每天最多完成5次修理任务。维修工小张上个月工作了20天，总计完成修理任务98次。则他上个月每天完成的修理任务次数有多少种不同的可能（）", "options": [{"letter": "A", "text": "190"}, {"letter": "B", "text": "210"}, {"letter": "C", "text": "380"}, {"letter": "D", "text": "400"}], "answer": "B", "explanation": "本题考查组合数学。小张工作20天，每天最多5次，共完成98次。20天×5=100次，实际完成98次，即有2次'缺口'。每天完成次数可看作5减去当天的缺口数，总缺口为2。问题等价于将2个缺口分配到20天中，允许同一天有多个缺口。方案数为C(20+2-1,2)=C(21,2)=210种。选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1731}, {"num": 1733, "batch": "公共基础知识", "type": "single", "stem": "某家企业行政部和市场部共有80人，后来进行人员调整，将行政部门增加了6人，市场部减少了18人，这时两个部门的人数刚好相等。问行政部原来有多少人（）", "options": [{"letter": "A", "text": "16"}, {"letter": "B", "text": "18"}, {"letter": "C", "text": "24"}, {"letter": "D", "text": "28"}], "answer": "D", "explanation": "本题考查方程求解。设行政部原有x人，则市场部原有(80-x)人。调整后行政部为x+6人，市场部为80-x-18=62-x人。两部门人数相等：x+6=62-x，2x=56，x=28。行政部原有28人。验证：行政部28+6=34人，市场部52-18=34人，相等。选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1732}, {"num": 1734, "batch": "公共基础知识", "type": "single", "stem": "某科技杂志刊文，介绍了一种可“自愈”橡胶。普通橡胶里的分子由高强度的共价键相连，断裂后无法恢复。于是科研人员将其改由氢键连接，在此基础上开发了一种“分子绳”，将原本很难共处的氢键和共价键结合在一起，允许它们在分子尺度上均匀混合，从而制造出一种透明坚韧的可“自愈”橡胶。这种新型橡胶受到拉力时会出现网状纹路，形似裂纹但不会完全裂开，并形成一些纤维状的连接物。拉力消失后，橡胶恢复原状。这项技术可用于制造军用装备的轮胎，受损后无须立即更换，可提高其战场生存能力。这段文字没有提及“自愈”橡胶的（）", "options": [{"letter": "A", "text": "特殊性能"}, {"letter": "B", "text": "科学原理"}, {"letter": "C", "text": "功能缺陷"}, {"letter": "D", "text": "应用前景"}], "answer": "C", "explanation": "本题考查细节判断。文段介绍了'自愈'橡胶的科学原理（氢键和共价键结合）、特殊性能（受拉力出现网状纹路但不完全裂开，拉力消失后恢复原状）和应用前景（可用于军用装备轮胎）。文段并未提及该橡胶的功能缺陷或不足之处，因此选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1733}, {"num": 1735, "batch": "公共基础知识", "type": "single", "stem": "某企业原有职工110人，其中技术人员是非技术人员的10倍，今年招聘后，两类人员的人数之比未变，且现有职工中技术人员比非技术人员多153人。问今年新招非技术人员多少名", "options": [{"letter": "A", "text": "7"}, {"letter": "B", "text": "8"}, {"letter": "C", "text": "9"}, {"letter": "D", "text": "10"}], "answer": "A", "explanation": "本题考查方程求解。原有110人，技术人员是非技术人员的10倍，则非技术人员110÷11=10人，技术人员100人。招聘后比例不变，设新招非技术人员x人，则新招技术人员10x人。现有技术人员100+10x人，非技术人员10+x人。(100+10x)-(10+x)=153，90+9x=153，9x=63，x=7。今年新招非技术人员7名，选A。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1734}, {"num": 1736, "batch": "公共基础知识", "type": "single", "stem": "某商店10月1日开业后，每天的营业额均以100元的速度上涨，已知该月15号这一天的营业额为5000元，问该商店10月份的总营业额为多少元（）", "options": [{"letter": "A", "text": "163100"}, {"letter": "B", "text": "158100"}, {"letter": "C", "text": "155000"}, {"letter": "D", "text": "150000"}], "answer": "B", "explanation": "本题考查等差数列。每天营业额以100元等差递增，15号营业额5000元。1号营业额=5000-(15-1)×100=5000-1400=3600元。10月共31天，总营业额=31×(首项+末项)/2=31×(3600+3600+30×100)/2=31×(3600+6600)/2=31×5100=158100元。选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1735}, {"num": 1737, "batch": "公共基础知识", "type": "single", "stem": "某商品成本为200元，售价为292元，公司根据市场情况调整了销售方案，将售价调整为268元，预计日销量将上涨15%。现欲通过改进生产线降低成本，以保持降价前的单日利润，则单件产品的生产成本至少需要降低（）", "options": [{"letter": "A", "text": "4%"}, {"letter": "B", "text": "5%"}, {"letter": "C", "text": "6%"}, {"letter": "D", "text": "8%"}], "answer": "C", "explanation": "本题考查利润计算。原售价292元，成本200元，原单件利润=292-200=92元。调价后售价268元，设新成本为c元，新单件利润=268-c。销量上涨15%即变为原来的1.15倍。保持单日利润不变：92×1=（268-c）×1.15，268-c=92/1.15=80，c=188元。成本降低=(200-188)/200=6%。选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1736}, {"num": 1738, "batch": "公共基础知识", "type": "single", "stem": "某社区举行了居民政治参与的交流活动：甲作为选民参加了一次直接选举人大代表的活动；乙找过区人大代表反映菜市场环境问题；丙对居委会工作提出过批评建议；丁参加了市政府改造“人民公园”听证会。据此我们可以判断（）", "options": [{"letter": "A", "text": "甲选举的是省人大代表"}, {"letter": "B", "text": "乙积极参与基层民主管理"}, {"letter": "C", "text": "丙直接行使了民主权利"}, {"letter": "D", "text": "丁参与对政府的民主监督"}], "answer": "D", "explanation": "本题考查政治参与知识。甲参加直接选举人大代表活动，我国县乡级人大代表实行直接选举，不一定是省级，A项错误。乙找区人大代表反映问题属于通过人大代表参与民主监督，不是基层民主管理，B项错误。丙对居委会工作提出批评建议属于参与基层民主管理，是间接行使民主权利，C项不够准确。丁参加市政府听证会属于通过社会听证制度参与民主监督，D项正确。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1737}, {"num": 1739, "batch": "公共基础知识", "type": "single", "stem": "某市工商局的员工数量较五年前减少了数百人，但新办企业办证时间减少了一周。由此可以得出结论： 目前该市工商局的员工工作效率较五年前有明显的提高。 以下各项如果为真，不能支持上述论证的是（）", "options": [{"letter": "A", "text": "该工商局增加了新办企业办证的环节"}, {"letter": "B", "text": "该工商局管理力度较五年前有明显加强"}, {"letter": "C", "text": "该市新办企业数量较五年前也有大幅减少"}, {"letter": "D", "text": "新办企业办证时间主要取决于人员办事的速度"}], "answer": "C", "explanation": "本题考查削弱论证。题干结论是工商局工作效率明显提高，依据是员工减少但办证时间缩短。C项指出新办企业数量大幅减少，说明办证时间缩短可能是因为工作量减少而非效率提高，这提供了另一种解释，不能支持题干论证。A项增加环节但时间缩短更能说明效率提高，B项管理加强可辅助说明效率提高，D项说明办证时间取决于人员速度，间接支持效率提高。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1738}, {"num": 1740, "batch": "公共基础知识", "type": "single", "stem": "某市为了发展文化强市战略，在2008年、2010年先后建成了两个图书馆，2008年底共办理市民借书证7万余个，到2010年底共办理市民借书证13万个，2011年，该市又在新区建立了第三个图书馆，于2012年初落成开放，截止2012年底，全市共计办理市民借书证20余万个。市政府由此认为，该项举措是有实效的，因为在短短的4年间，光顾图书馆的市民增加了近两倍。 以下哪项如果为真，最能削弱上述结论是（）", "options": [{"letter": "A", "text": "图书馆要不断购置新书，维护成本也很高，这会影响该市其他文化设施建设"}, {"letter": "B", "text": "该市有两所高等学校，许多在校生也办理了这3个图书馆的借书证"}, {"letter": "C", "text": "很多办理了第一个图书馆借书证的市民又办理了另外两个图书馆的借书证"}, {"letter": "D", "text": "该市新区建设发展迅速，4年间很多外来人口大量涌入新区"}], "answer": "C", "explanation": "本题考查削弱论证。市政府以借书证数量增长证明图书馆建设有实效。C项指出很多市民重复办理了多个图书馆的借书证，说明借书证数量的增长可能是同一人办了多张证，而非实际使用人数增加，有力地削弱了'光顾图书馆的市民增加了近两倍'的结论。A项说的是成本问题，B项学生办证虽能部分削弱但不如C项直接，D项外来人口增加反而可能支持结论。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1739}, {"num": 1741, "batch": "公共基础知识", "type": "single", "stem": "某网店的甲商品定价为300元，乙商品定价为500元。小张以七折购买了甲商品，购买乙商品时参加了每满199元减50元的活动。小赵购买甲商品时在9折基础上又参加了每满100元减10元活动，则小赵通过以下哪种促销活动购买乙商品，其购买甲、乙两件商品总花销与小张一样（）", "options": [{"letter": "A", "text": "减50元后打八折"}, {"letter": "B", "text": "直接打七折"}, {"letter": "C", "text": "打九折后减120元"}, {"letter": "D", "text": "直接减120元"}], "answer": "A", "explanation": "本题考查计算问题。小张购买甲商品：300×0.7=210元。购买乙商品：500元满199减50，500÷199=2余102，减2×50=100元，实付400元。小张共花610元。小赵购买甲商品：300×0.9=270元，满100减10，减2×10=20元，实付250元。小赵买甲花250元，要使总花销也为610元，买乙需花610-250=360元。验证A项：乙500元减50后为450元，再打八折=360元，符合。选A。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1740}, {"num": 1742, "batch": "公共基础知识", "type": "single", "stem": "某县地处黄土高原，水土流失严重。如果你是该县相关部门的工作人员，你认为采取以下哪些措施能有效治理水土流失？a压缩农业用地，扩大林草种植面积b调整种植结构，发展棉花产业c施用石灰，降低土壤酸性d打坝淤地，平整土地", "options": [{"letter": "A", "text": "ab"}, {"letter": "B", "text": "bc"}, {"letter": "C", "text": "ad"}, {"letter": "D", "text": "cd"}], "answer": "C", "explanation": "本题考查水土保持知识。黄土高原水土流失治理措施包括：压缩农业用地、扩大林草种植面积（a），可以增强植被涵养水源、保持水土的功能；打坝淤地、平整土地（d），可以拦截泥沙、减少水土流失。发展棉花产业（b）不一定有利于水土保持，施用石灰降低土壤酸性（c）是改良土壤化学性质的措施，与治理水土流失无关。因此选C（ad）。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1741}, {"num": 1743, "batch": "公共基础知识", "type": "single", "stem": "某县新建公路路口设置了超速违章摄像头，赵某不知情，多次超速驾车在该路段被拍照，且未收到违章通知。赵某被处罚后不服，将县公安局告上法庭。恰逢县公安局聘请了某专职律师作为法律顾问。下列做法符合我国《行政诉讼法》规定的是（）", "options": [{"letter": "A", "text": "该律师可全权代理县公安局出庭应诉，县公安局不必再派员出庭"}, {"letter": "B", "text": "为查明案件事实的需要，该律师可自行向赵某调取相关证据"}, {"letter": "C", "text": "该律师查阅、复制该案庭审材料必须经人民法院许可"}, {"letter": "D", "text": "若赵某和县公安局同意，则人民法院可适用简易程序审理该案"}], "answer": "D", "explanation": "本题考查行政诉讼法。根据《行政诉讼法》规定，适用简易程序审理的案件，经当事人双方同意，可以适用简易程序，D项正确。A项错误，被诉行政机关负责人应当出庭应诉或委托相应工作人员出庭，不能仅由律师全权代理而不出庭。B项错误，律师无权自行向对方调取证据。C项错误，代理律师有权查阅案卷材料，不需法院许可。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1742}, {"num": 1744, "batch": "公共基础知识", "type": "single", "stem": "某校规定，对于学校的任一实验室，除非有教师在国际期刊上发表论文，否则没资格申报国家重点实验室。该校甲实验室有教师在国际期刊上发表论文。该校乙实验室有资格申报国家重点实验室。若上述陈述为真，则以下哪项也一定为真？（）", "options": [{"letter": "A", "text": "该校甲实验室有资格申报国家重点实验室"}, {"letter": "B", "text": "该校甲实验室有教师没有在国际期刊上发表过论文"}, {"letter": "C", "text": "该校乙实验室有教师在国际期刊上发表论文"}, {"letter": "D", "text": "该校乙实验室有教师没有在国际期刊上发表过论文"}], "answer": "C", "explanation": "本题考查逻辑推理。题干条件：除非有教师在国际期刊发表论文（P），否则没资格申报国家重点实验室（非Q）。即：有资格申报→有教师发表论文。乙实验室有资格申报，根据充分条件推理，可推出乙实验室有教师在国际期刊发表论文，C项正确。甲实验室有教师发表论文，是有资格的必要条件满足，但不能推出一定有资格（必要条件不能反推），A项错误。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1743}, {"num": 1745, "batch": "公共基础知识", "type": "single", "stem": "某新建小区计划在小区主干道两侧种植银杏树和梧桐树绿化环境。一侧每隔3棵银杏树种1棵梧桐树，另一侧每隔4棵梧桐树种1棵银杏树，最终两侧各栽种35棵树。问最多栽种了多少棵银杏树（）", "options": [{"letter": "A", "text": "33"}, {"letter": "B", "text": "34"}, {"letter": "C", "text": "36"}, {"letter": "D", "text": "37"}], "answer": "B", "explanation": "本题考查植树问题。一侧每隔3棵银杏树种1棵梧桐树，即4棵一组（3银+1梧），35÷4=8组余3棵，余下3棵全种银杏，银杏=8×3+3=27棵。另一侧每隔4棵梧桐树种1棵银杏树，即5棵一组（4梧+1银），35÷5=7组，银杏=7×1=7棵。但为使银杏最多，一侧余下的3棵应全种银杏（27棵），另一侧也应尽量多种银杏。调整种植起始位置：第二侧若以银杏开头，每5棵一组（1银+4梧），35÷5=7组，银杏=7棵。两侧合计银杏最多=27+7=34棵。选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1744}, {"num": 1746, "batch": "公共基础知识", "type": "single", "stem": "某政府机关内甲、乙两部门通过门户网站定期向社会发布消息，甲部门每隔2天、乙部门每隔3天有一个发布日，节假日无休。甲、乙两部门在一个自然月内最多有几天同时为发布日（）", "options": [{"letter": "A", "text": "5"}, {"letter": "B", "text": "2"}, {"letter": "C", "text": "6"}, {"letter": "D", "text": "3"}], "answer": "D", "explanation": "本题考查周期问题。甲每隔2天发布一次，即每3天发布一次（周期为3）；乙每隔3天发布一次，即每4天发布一次（周期为4）。两部门同时发布的周期为LCM(3,4)=12天。一个自然月最多31天，从第1天开始算，同时发布日为第1天、第13天、第25天，共3天。因此一个自然月内最多有3天同时为发布日，选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1745}, {"num": 1747, "batch": "公共基础知识", "type": "single", "stem": "某种产品每箱48个。小李制作这种产品，第1天制作了1个，以后每天都比前一天多制作1个。X天后总共制作了整数箱产品。问X的最小值在以下哪个范围内（）", "options": [{"letter": "A", "text": "在41～60之间"}, {"letter": "B", "text": "超过60"}, {"letter": "C", "text": "不到20"}, {"letter": "D", "text": "在20～40之间"}], "answer": "D", "explanation": "本题考查等差数列与整除问题。第X天共制作X(X+1)/2个产品。需要X(X+1)/2是48的整数倍，即X(X+1)是96的倍数。96=32×3。逐一验证：X(X+1)需被96整除。当X=32时，32×33=1056=96×11，是96的倍数。但需检查更小的值。X=32在20~40范围内。验证X<32是否有解：需要X(X+1)被96整除，逐一排查20~31的值均不满足。X最小为32，在20~40之间，选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1746}, {"num": 1748, "batch": "公共基础知识", "type": "single", "stem": "某种商品原价25元，每半天可销售20个。现知道每降价1元，销量即增加5个。某日上午将该商品打八折，下午在上午价格的基础上再打八折出售，问其全天销售额为多少元（）", "options": [{"letter": "A", "text": "1760"}, {"letter": "B", "text": "1940"}, {"letter": "C", "text": "2160"}, {"letter": "D", "text": "2560"}], "answer": "B", "explanation": "本题考查经济利润问题。原价25元，每半天售20个，每降价1元多卖5个。上午打八折：售价=25×0.8=20元，降价5元，销量=20+5×5=45个，上午销售额=20×45=900元。下午再打八折：售价=20×0.8=16元，降价9元，销量=20+5×9=65个，下午销售额=16×65=1040元。全天销售额=900+1040=1940元。选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1747}, {"num": 1749, "batch": "公共基础知识", "type": "single", "stem": "某种糖果的进价为12元/千克，现购进这种糖果若干千克，每天销售10千克，且从第二天起每天都比前一天降价2元/千克。已知以6元/千克的价格销售的那天正好卖完最后10千克，且总销售额是总进货成本的2倍。问总共进了多少千克这种糖（）", "options": [{"letter": "A", "text": "180"}, {"letter": "B", "text": "190"}, {"letter": "C", "text": "160"}, {"letter": "D", "text": "170"}], "answer": "B", "explanation": "本题考查等差数列与经济问题。每天售10千克，设共卖了n天，则总共进了10n千克。第一天售价最高，每天降2元/千克，最后一天（第n天）售价6元/千克。第一天售价=6+2(n-1)=2n+4元。总销售额=10×[（2n+4）+6]×n/2=10×(2n+10)×n/2=5n(2n+10)=10n(n+5)。总进货成本=12×10n=120n。由总销售额=2×总成本：10n(n+5)=240n，n+5=24，n=19。总共进了10×19=190千克。选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1748}, {"num": 1750, "batch": "公共基础知识", "type": "single", "stem": "木匠加工2张桌子和4张凳子共需要10个小时，加工4张桌子和8张椅子需要22个小时。问如果他加工桌子、凳子和椅子各10张，共需要多少小时（）", "options": [{"letter": "A", "text": "47.5"}, {"letter": "B", "text": "50"}, {"letter": "C", "text": "52.5"}, {"letter": "D", "text": "55"}], "answer": "C", "explanation": "本题考查方程求解。设加工一张桌子需a小时，一张凳子b小时，一把椅子c小时。由题意：2a+4b=10（式1），4a+8c=22（式2）。式1×2得4a+8b=20（式3），式3-式2得8b-8c=-2，即b-c=-0.25。由式1得a+2b=5，a=5-2b。各加工10张：10a+10b+10c=10(a+b+c)。a+b+c=(5-2b)+b+c=5-b+c=5-(b-c)=5-(-0.25)=5.25。10×5.25=52.5小时。选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1749}, {"num": 1751, "batch": "公共基础知识", "type": "single", "stem": "能源按转换传递过程可分为“一次能源”和“二次能源”，下列属于“二次能源”的一组是（）", "options": [{"letter": "A", "text": "沼气、焦炭、核电"}, {"letter": "B", "text": "煤、石油、天然气"}, {"letter": "C", "text": "煤、核能、海洋能"}, {"letter": "D", "text": "水能、风能、核能"}], "answer": "A", "explanation": "本题考查能源分类知识。一次能源是指直接从自然界取得、不改变其形态和性质的能源，如煤、石油、天然气、水能、风能、核能等。二次能源是指由一次能源经过加工转换得到的能源产品，如沼气（生物质能转换）、焦炭（煤的加工产品）、核电（核能转换得到的电力）等。A项沼气、焦炭、核电均为二次能源。B项煤、石油、天然气为一次能源，C项和D项也均为一次能源。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1750}, {"num": 1752, "batch": "公共基础知识", "type": "single", "stem": "判断一个环形坑或环形构造的形成是否与陨石撞击作用有关，关键是要查明该坑岩石是否受过陨石强烈撞击伴随的冲击波作用。在强烈冲击波作用下，靶岩将发生冲击变质。关于陨石撞击坑的判别，国际科学界明确了三项冲击变质诊断性指标：矿物击变面状页理、矿物击变玻璃、击变矿物高压多形转变。在自然界中，除了地外天体超速撞击引起的冲击波作用外，任何其他天然过程或地质作用均不能在地质体中引发这类矿物物理变化。如能在地表环状地质构造中发现上述三项指标之一，即可确定该地区发生过陨石撞击事件。 根据这段文字，对某环形坑或环形构造来说（）", "options": [{"letter": "A", "text": "发现矿物击变玻璃即可判断定为陨石撞击形成"}, {"letter": "B", "text": "其形成往往能证明该处受过强烈冲击波作用"}, {"letter": "C", "text": "三项冲击变质诊断性指标通常不会同时出现"}, {"letter": "D", "text": "强烈地震有可能引发击变矿物高压多形转变"}], "answer": "A", "explanation": "本题考查细节判断。文段明确指出'如能在地表环状地质构造中发现上述三项指标之一，即可确定该地区发生过陨石撞击事件'，说明发现矿物击变玻璃（三项指标之一）即可判断为陨石撞击形成，A项正确。B项'往往能证明'表述不准确，C项和D项文段未提及。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1751}, {"num": 1753, "batch": "公共基础知识", "type": "single", "stem": "企业从银行或海外取得外汇借款后并不是直接使用外汇资金，而是将外汇结汇给银行，取得人民币资金加以使用，这种现象称之为贷款替代。 根据上述定义，下列哪项属于贷款替代是（）", "options": [{"letter": "A", "text": "人民币升值后，一些企业纷纷减少人民币负债，增加外汇负债，然后再用人民币进行投资"}, {"letter": "B", "text": "国内经济过热，商业银行对人民币贷款的发放从紧。某贸易公司出于财务考虑转向外资银行贷款，获得外币资金"}, {"letter": "C", "text": "王明觉得人民币利率高于美元，因此他申请美元贷款，然后将外汇结汇给银行，从而获得人民币资金"}, {"letter": "D", "text": "小宇出国旅游前去银行兑换了一些外币，到国外后他使用信用卡结算，回国后用人民币还款"}], "answer": "A", "explanation": "本题考查定义判断。贷款替代的关键要素：企业从银行或海外取得外汇借款，将外汇结汇给银行取得人民币资金使用。A项企业减少人民币负债、增加外汇负债（取得外汇借款），再用人民币投资（结汇获得人民币），符合贷款替代的定义。B项获得外币资金但未提及结汇为人民币，C项王明是个人而非企业，D项小宇也是个人消费行为，均不符合。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1752}, {"num": 1754, "batch": "公共基础知识", "type": "single", "stem": "企业有员工500人，其中60%是男性，则企业男员工比女员工多（）人", "options": [{"letter": "A", "text": "100"}, {"letter": "B", "text": "200"}, {"letter": "C", "text": "300"}, {"letter": "D", "text": "400"}], "answer": "A", "explanation": "本题考查百分比计算。企业500人，男性60%即300人，女性40%即200人。男员工比女员工多300-200=100人。选A。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1753}, {"num": 1755, "batch": "公共基础知识", "type": "single", "stem": "钱铺钱庄是明清时期重要的金融机构。钱铺的主要业务是兑换银两，或将顾客手中的铜钱换成银两，或将银两换成铜钱。后来发展成吸收存款、放款和汇兑为主要业务的钱庄。到乾隆年间，钱庄已有相当规模。上述转变的主要原因是（）。", "options": [{"letter": "A", "text": "以物易物是明清时期商贸主要形式"}, {"letter": "B", "text": "工商业发展使区域间长途贸易兴盛"}, {"letter": "C", "text": "民营手工业在明清时期获得大发展"}, {"letter": "D", "text": "明清时期中国的对外贸易长期出超"}], "answer": "B", "explanation": "本题考查经济史知识。明清时期钱铺从兑换银两发展为吸收存款、放款和汇兑的钱庄，主要原因是工商业发展使区域间长途贸易兴盛，对金融汇兑服务产生了巨大需求。长途贸易需要跨地区资金调拨，推动了钱庄汇兑业务的发展。A项错误，明清时期货币经济已较发达，以物易物并非主要形式。C项和D项虽有一定关联，但不是钱庄业务转变的主要原因。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1754}, {"num": 1756, "batch": "公共基础知识", "type": "single", "stem": "轻车熟路：人生地疏", "options": [{"letter": "A", "text": "廉洁奉公：卑躬屈膝"}, {"letter": "B", "text": "任重道远：无所事事"}, {"letter": "C", "text": "前仆后继：贪生怕死"}, {"letter": "D", "text": "河清海晏：国泰民安"}], "answer": "C", "explanation": "本题考查类比推理。'轻车熟路'与'人生地疏'是反义关系，前者形容做事熟练、有经验，后者形容对环境不熟悉。C项'前仆后继'与'贪生怕死'也是反义关系，前者形容英勇无畏、奋勇向前，后者形容畏惧退缩。A项两词不构成反义关系，B项'任重道远'与'无所事事'不构成严格反义，D项'河清海晏'与'国泰民安'是近义关系。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1755}, {"num": 1757, "batch": "公共基础知识", "type": "single", "stem": "清宫剧中出现下列情景，明显违背史实的是（）", "options": [{"letter": "A", "text": "道光帝在圆明园批阅奏章"}, {"letter": "B", "text": "咸丰帝在避暑山庄观赏昆曲"}, {"letter": "C", "text": "光绪帝赴颐和园向慈禧太后请安"}, {"letter": "D", "text": "宣统帝在紫禁城接见琉球使臣"}], "answer": "D", "explanation": "本题考查历史知识。D项'宣统帝在紫禁城接见琉球使臣'违背史实。琉球王国于1879年被日本吞并，改为冲绳县，清朝曾为此与日本交涉但未能挽回。宣统帝在位时间为1908-1912年，此时琉球已被日本占领近30年，不可能有琉球使臣来朝。A项圆明园在道光时期仍正常使用，B项避暑山庄在咸丰时期仍使用，C项颐和园在光绪时期是慈禧居所，均符合史实。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1756}, {"num": 1758, "batch": "公共基础知识", "type": "single", "stem": "深入实施（）战略，坚持尊重劳动、尊重知识、尊重人才、尊重创造，完善人才战略布局，加快建设世界重要人才中心和创新高地，着力形成人才国际竞争的比较优势，把各方面优秀人才集聚到（）事业中来。", "options": [{"letter": "A", "text": "人才强国经济社会发展"}, {"letter": "B", "text": "人才强国党和人民"}, {"letter": "C", "text": "人才兴国经济社会发展"}, {"letter": "D", "text": "人才兴国党和人民"}], "answer": "B", "explanation": "本题考查时政知识。根据党的二十大报告原文：'深入实施人才强国战略，坚持尊重劳动、尊重知识、尊重人才、尊重创造，完善人才战略布局，加快建设世界重要人才中心和创新高地，着力形成人才国际竞争的比较优势，把各方面优秀人才集聚到党和人民事业中来。'因此正确答案为B项'人才强国'和'党和人民'。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1757}, {"num": 1759, "batch": "公共基础知识", "type": "single", "stem": "全身麻醉：注射麻醉", "options": [{"letter": "A", "text": "网络存储：单机存储"}, {"letter": "B", "text": "胸式呼吸：腹式呼吸"}, {"letter": "C", "text": "物理消毒：加热消毒"}, {"letter": "D", "text": "抽样调查：问卷调查"}], "answer": "D", "explanation": "本题考查类比推理。'全身麻醉'和'注射麻醉'是交叉关系：有的全身麻醉是注射麻醉，有的全身麻醉不是注射麻醉（如吸入麻醉）；有的注射麻醉是全身麻醉，有的注射麻醉不是全身麻醉（如局部注射麻醉）。D项'抽样调查'和'问卷调查'也是交叉关系：有的抽样调查是问卷调查，有的抽样调查不是问卷调查（如抽样访谈）；有的问卷调查是抽样调查，有的问卷调查不是抽样调查（如普查式问卷）。其他选项均不构成交叉关系。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1758}, {"num": 1760, "batch": "公共基础知识", "type": "single", "stem": "人的大脑聪明与否不仅是天生的，我们后天的行为也会对大脑产生深刻的影响。“用进废退”的生物科学原则，同样适用于人脑。大脑神经细胞和其他组织器官一样，越用越能保持其充沛的活力；总不用的话，人可能会变得越来越笨。以下哪项如果为真，最能支持上述结论？（）", "options": [{"letter": "A", "text": "人在专注思考时大脑的血流情况可能发生变化，从而使某些区域的温度过高导致疲劳"}, {"letter": "B", "text": "随着年龄增长，大脑神经元会慢慢衰亡"}, {"letter": "C", "text": "当一个人完成单调任务时，大脑便会自动转换为“安眠模式”"}, {"letter": "D", "text": "学习新的语言可以促使脑区之间建立更高效灵活的沟通模式"}], "answer": "D", "explanation": "本题考查加强论证。题干结论是人的后天行为会影响大脑，用进废退，大脑越用越有活力。D项'学习新语言可以促使脑区之间建立更高效灵活的沟通模式'直接证明了后天学习行为（用脑）能改善大脑功能，支持了题干结论。A项说思考导致大脑疲劳，与结论方向相反；B项说年龄增长导致神经元衰亡，与用脑无关；C项说单调任务使大脑进入'安眠模式'，不能支持'越用越好'的结论。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1759}, {"num": 1761, "batch": "公共基础知识", "type": "single", "stem": "人的自尊可以划分为有条件的自尊和无条件的自尊。前者是通过达到一些预设的标准来获得的自尊，自我价值感有赖于这些标准的实现，而非自我的本真需要，比如认为拥有美貌才有价值感。有条件自尊者往往并不了解自己的需要，其衡量自尊的标准是内化得来的。如果父母的爱是有条件的，对自己欲求的行为进行奖励，对不欲求的行为进行惩罚，这就把行为标准强加给了儿童。儿童会不自觉地把这种标准当作自己的人生追求，有条件的自尊往往通过强烈的自我意识表现出来，这样的人总是通过他人的眼光来看待自己。 与这段文字的意思相符的一项是（）", "options": [{"letter": "A", "text": "人的本真需求是有条件自尊的来源"}, {"letter": "B", "text": "父母的过分溺爱会损害孩子的自尊"}, {"letter": "C", "text": "有条件自尊者往往过于在意外界的评价"}, {"letter": "D", "text": "父母给孩子制定行为标准对其成长不利"}], "answer": "C", "explanation": "本题考查细节理解。文段指出有条件自尊者'总是通过他人的眼光来看待自己'，即过于在意外界的评价，C项与文意相符。A项错误，文段说有条件自尊的自我价值感有赖于预设标准的实现，而非本真需要。B项错误，文段说的是'父母的爱是有条件的'会损害孩子自尊，而非'过分溺爱'。D项过于绝对，文段只是说有条件的爱会把标准强加给儿童，并非说制定标准就不利。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1760}, {"num": 1762, "batch": "公共基础知识", "type": "single", "stem": "人非圣贤，孰能无过。我不是圣贤，所以，我也有犯错误的时候。以下除哪项外，均与题干的论证结构相似？（）", "options": [{"letter": "A", "text": "金无足赤，人无完人。张灵灵是人，所以，张灵灵也不是完美的"}, {"letter": "B", "text": "无知者无畏。小张见多识广，所以，他做事谨小慎微"}, {"letter": "C", "text": "志不强者智不达。曹芳意志不坚定，所以，曹芳不能充分发挥她的智慧"}, {"letter": "D", "text": "狭路相逢勇者胜。苏梅是勇者，所以，她最终会取得胜利"}], "answer": "B", "explanation": "本题考查论证结构。题干结构：大前提'人非圣贤→孰能无过'（如果不是圣贤，就会犯错），小前提'我不是圣贤'，结论'我也会犯错'。属于'否前推否后'的推理。B项结构为'无知者无畏'（无知→无畏），'小张见多识广'（非无知），推出'做事谨小慎微'（非无畏），属于否前推否后，但题干是从肯定前件推出肯定后件，而B项是从否定前件推出否定后件，结构不同。A、C、D项均与题干结构类似。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1761}, {"num": 1763, "batch": "公共基础知识", "type": "single", "stem": "人类实践的目标和任务是（）", "options": [{"letter": "A", "text": "认识世界"}, {"letter": "B", "text": "改造世界"}, {"letter": "C", "text": "文明进步"}, {"letter": "D", "text": "创造价值"}], "answer": "B", "explanation": "本题考查马克思主义哲学。马克思主义认为，实践是认识的基础和目的。人类实践的目标和任务是改造世界。认识世界的目的是为了更好地改造世界，实践不仅是认识的来源和动力，更是认识的目的和归宿。通过实践改造客观世界和主观世界，推动社会发展进步。因此选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1762}, {"num": 1764, "batch": "公共基础知识", "type": "single", "stem": "人类与疟疾已经进行了几个世纪的斗争，但一直是“治标不治本”——无法阻断疟疾传染源。日前研究者培育出一种经过基因改造的蚊子，它具备了不再感染疟疾的能力，并且能妨碍野生蚊子繁衍，从而有效切断人与蚊子的疟疾传播途径，假以时日，就能根绝疟疾这个顽症。 以下哪项如果为真，最能支持上述结论（）", "options": [{"letter": "A", "text": "转基因蚊子的体质比野生蚊子差，一旦被放到野外很容易死亡"}, {"letter": "B", "text": "转基因蚊子只在疟疾存在时才有生存优势，当生存环境中没有疟疾时，它们和野生蚊子的存活率是相同的"}, {"letter": "C", "text": "转基因蚊子的生殖能力在繁衍了 9 代后显著增加，可能带来野生蚊子种群的灭亡"}, {"letter": "D", "text": "转基因蚊子与野生蚊子交配产下的后代并不都具有抗疟疾基因，但在基因层面上都会产生突变，形成新型蚊子"}], "answer": "C", "explanation": "本题考查加强论证。题干结论：转基因蚊子能切断疟疾传播途径，假以时日能根绝疟疾。C项指出转基因蚊子繁衍9代后生殖能力显著增加，可能导致野生蚊子种群灭亡，这说明转基因蚊子能有效取代野生蚊子种群，从而切断疟疾传播，有力支持了结论。A项说转基因蚊子容易死亡，削弱了结论；B项说没有疟疾时存活率相同，不能说明能消灭疟疾；D项后代不都有抗疟疾基因，削弱了结论。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1763}, {"num": 1765, "batch": "公共基础知识", "type": "single", "stem": "人们经常利用植物去判断生长地的环境，下列有关说法正确的是（）", "options": [{"letter": "A", "text": "矮牵牛含有的花青素对二氧化硫有指示作用"}, {"letter": "B", "text": "树林中所有树冠西边稀疏东边繁盛，说明东风盛行"}, {"letter": "C", "text": "胡杨的生长地土壤通常呈现深褐色"}, {"letter": "D", "text": "地衣大量生长反映空气湿度较低?"}], "answer": "A", "explanation": "本题考查生物与环境知识。A项正确，矮牵牛花中的花青素对二氧化硫敏感，当空气中二氧化硫浓度较高时，花青素会变色，因此可作为二氧化硫污染的指示植物。B项错误，树冠西边稀疏东边繁盛说明盛行西风而非东风。C项错误，胡杨生长在干旱地区，土壤通常为碱性而非深褐色。D项错误，地衣大量生长反映空气质量好、空气清洁，而非湿度低。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1764}, {"num": 1766, "batch": "公共基础知识", "type": "single", "stem": "人们为了获得知识（）", "options": [{"letter": "A", "text": "只要刻苦读书就行"}, {"letter": "B", "text": "只要积极参加社会实践就行"}, {"letter": "C", "text": "既要努力读书又要参加社会实践"}, {"letter": "D", "text": "只要抓住灵感和机遇"}], "answer": "C", "explanation": "本题考查认识论知识。马克思主义认识论认为，获得知识的途径有两条：一是读书学习间接经验，二是参加社会实践获得直接经验。二者缺一不可，既要努力读书获取前人积累的知识，又要积极参加社会实践将理论与实践相结合。只读书不实践是纸上谈兵，只实践不读书则缺乏理论指导。因此选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1765}, {"num": 1767, "batch": "公共基础知识", "type": "single", "stem": "人们在社会生活中常会面临选择，要么选择风险小，报酬低的机会；要么选择风险大，报酬高的机会。究竟是在个人决策的情况下富于冒险性，还是在群体决策的情况下富于冒险性？有研究表明，群体比个体更富有冒险精神，群体倾向于获利大但成功率小的行为。 以下哪项如果为真，最能支持上述研究结论是（）", "options": [{"letter": "A", "text": "在群体进行决策时，人们往往会比个人决策时更倾向于向某一个极端偏斜，从而背离最佳决策"}, {"letter": "B", "text": "个体会将其意见与群体其他成员相互比较，因其想要被其他群体成员所接受及喜爱，所以个体往往会顺从群体的一般意见"}, {"letter": "C", "text": "在群体决策中，很可能出现以个体或子群体为主发表意见、进行决策的情况，使群体决策为个体或子群体所左右"}, {"letter": "D", "text": "群体决策有利于充分利用其成员不同的教育程度、经验和背景，他们的广泛参与有利于最高决策的科学性"}], "answer": "A", "explanation": "本题考查加强论证。题干结论：群体比个体更富有冒险性。A项指出群体决策时人们更倾向于向某一极端偏斜，这解释了为什么群体决策比个体决策更具冒险性——群体讨论会使观点向极端方向移动（群体极化效应），有力支持了研究结论。B项解释的是个体顺从群体的原因，C项说的是群体可能被少数人左右，D项说的是群体决策的科学性优势，均不能直接支持'群体更冒险'的结论。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1766}, {"num": 1768, "batch": "公共基础知识", "type": "single", "stem": "如果国庆节当天是农历九月初三。关于当天月相的描述，正确的是（）", "options": [{"letter": "A", "text": "杨同学说：“月球黄昏升出地平面。”"}, {"letter": "B", "text": "赖同学说：“上半夜可见于西天。”"}, {"letter": "C", "text": "张同学说：“月面东半亮（左）。”"}, {"letter": "D", "text": "尹同学说：“月球午夜落下地平面。"}], "answer": "B", "explanation": "本题考查月相知识。农历九月初三属于蛾眉月（上弦月之前），月相为新月后两三天。此时月球在太阳东面约45度，上半夜可见于西方天空，月面朝西（西半亮），黄昏时出现在西方低空，入夜后不久即落下。B项'上半夜可见于西天'描述正确。A项月球黄昏时已在西方天空而非刚从东方升起，C项应为月面西半亮而非东半亮，D项月球在黄昏后不久即落下而非午夜。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1767}, {"num": 1769, "batch": "公共基础知识", "type": "single", "stem": "瑞典卡罗琳医学院10月5日宣布，将2015年诺尔生理学或医学奖授予中国药学家屠呦呦以及爱尔兰科学家威廉·坎贝尔和日本科学家大村智。其中，屠呦呦的获奖理由是（）", "options": [{"letter": "A", "text": "发现治疗蛔虫寄生虫新疗法"}, {"letter": "B", "text": "发现构成大脑定位系统的细胞"}, {"letter": "C", "text": "发现幽门螺杆菌及其在胃炎和胃溃疡中所起的作用"}, {"letter": "D", "text": "发现治疗疟疾的新疗法"}], "answer": "D", "explanation": "本题考查时事知识。2015年诺贝尔生理学或医学奖授予中国药学家屠呦呦、爱尔兰科学家威廉·坎贝尔和日本科学家大村智。屠呦呦的获奖理由是发现治疗疟疾的新疗法——青蒿素。坎贝尔和大村智因发现治疗蛔虫寄生虫感染的新疗法而获奖。因此选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1768}, {"num": 1770, "batch": "公共基础知识", "type": "single", "stem": "商品或服务没有质量的保障，就像生命失去了健康一样，一切都（）。人们进行网络消费时，能够 一眼看到价格，却很难发现是否存在质量问题。这种情况下，质量因素便更加关键。如果商家在营销环节耍小聪明，以低价为噱头，轻视质量，就如同（），等到“东窗事发”，注定会收到消费者的差评。", "options": [{"letter": "A", "text": "无从谈起、掩耳盗铃"}, {"letter": "B", "text": "无济于事、饮鸩止渴"}, {"letter": "C", "text": "徒劳无功、作茧自缚"}, {"letter": "D", "text": "黯然失色、买椟还珠"}], "answer": "A", "explanation": "本题考查词语运用。第一空，'没有质量保障'就像'生命失去健康'，一切都'无从谈起'，表示失去基础后其他都没有意义，符合语境。第二空，商家以低价为噱头轻视质量，消费者看不到质量问题，商家自以为聪明，如同'掩耳盗铃'——自己欺骗自己，等到'东窗事发'就会被差评。'掩耳盗铃'准确描述了这种自欺行为。因此选A。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1769}, {"num": 1771, "batch": "公共基础知识", "type": "single", "stem": "上世纪70—90年代，带有多个短波波段的便携式收音机是全球流行的小电器，人们通过短波收听国际新闻，追逐世界流行，甚至通过短波学外语、交笔友。“十波段”便携式收音机的落魄始于上世纪末网络时代的到来，同时是追逐国际信息，网络资讯不论速度、数量、覆盖面各方面都远胜传统的短波电台，强大的网络冲击令许多老资格的短波电台或关门大吉，或转入在线服务，或缩减语种、波短、广播时长，红极一时的“十波段”自然也就“”了。填入上文横线处最恰当的是（）", "options": [{"letter": "A", "text": "耳听为虚，眼见为实"}, {"letter": "B", "text": "皮之不存，毛将焉附"}, {"letter": "C", "text": "言之无文，行而不远"}, {"letter": "D", "text": "失之毫厘，谬之千里"}], "answer": "B", "explanation": "本题考查语句衔接。文段讲述短波电台在网络时代衰落，'十波段'收音机随之落魄。短波电台是'毛'，'十波段'收音机是依附于短波电台的'皮'。短波电台衰落或消失，'十波段'收音机自然失去存在基础。'皮之不存，毛将焉附'比喻事物失去了赖以生存的基础就不能存在，准确表达了这种依存关系。因此选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1770}, {"num": 1772, "batch": "公共基础知识", "type": "single", "stem": "社会和文化推崇慷慨行为，但这种行为往往要求一个人为他人利益贡献自己的资源，所以这很难用一般的经济理论解释。然而，有神经科学论文指出，即使会牺牲自我利益，有些人也会对他人慷慨大方，这是因为当人表现慷慨时，会激活大脑中的特定区域，而这些区域与产生幸福感的区域相互关联。 根据这段文字，下列说法正确的是（）", "options": [{"letter": "A", "text": "对牺牲自我利益去满足他人的行为不应过多推崇"}, {"letter": "B", "text": "人类做出慷慨行为与产生幸福感时的大脑机制相同"}, {"letter": "C", "text": "慷慨行为能增加幸福感是人们慷慨待人的原因之一"}, {"letter": "D", "text": "经济学理论能够充分阐述人类利他行为的机制"}], "answer": "C", "explanation": "本题考查细节理解。文段指出，慷慨行为会激活大脑中与产生幸福感相关的特定区域，这说明慷慨行为能带来幸福感是人们选择慷慨待人的原因之一，C项正确。A项文段未涉及是否应'过多推崇'，B项'大脑机制相同'表述过于绝对（文段说的是'相互关联'而非'相同'），D项与文段矛盾（文段说'很难用一般的经济理论解释'）。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1771}, {"num": 1773, "batch": "公共基础知识", "type": "single", "stem": "社会主义核心价值观在个人层面上的价值取向是（）", "options": [{"letter": "A", "text": "自由、平等、公正、法治"}, {"letter": "B", "text": "守法、统一、互助、和睦"}, {"letter": "C", "text": "自律、正义、平等、权利"}, {"letter": "D", "text": "爱国、敬业、诚信、友善"}], "answer": "D", "explanation": "本题考查社会主义核心价值观。社会主义核心价值观分为三个层面：国家层面——富强、民主、文明、和谐；社会层面——自由、平等、公正、法治；个人层面——爱国、敬业、诚信、友善。题目问的是个人层面的价值取向，因此选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1772}, {"num": 1774, "batch": "公共基础知识", "type": "single", "stem": "完善科技创新体系，坚持创新在我国现代化建设全局中的（）。", "options": [{"letter": "A", "text": "第一地位"}, {"letter": "B", "text": "核心地位"}, {"letter": "C", "text": "重要地位"}, {"letter": "D", "text": "中心地位"}], "answer": "B", "explanation": "本题考查时政知识。根据党的二十大报告：'完善科技创新体系，坚持创新在我国现代化建设全局中的核心地位。'创新是引领发展的第一动力，必须把创新摆在国家发展全局的核心位置。因此选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1773}, {"num": 1775, "batch": "公共基础知识", "type": "single", "stem": "生物学研究发现，成群的蚂蚁中，大部分蚂蚁很勤劳，寻找、搬运食物争先恐后，少数蚂蚁却东张西望不干活。当食物来源断绝或蚁窝被破坏时，那些勤快的蚂蚁一筹莫展。“懒蚂蚁”则“挺身而出”，带领众伙伴向它早已侦察到的新的食物源转移。这就是所谓的懒蚂蚁效应。 根据上述定义，下列属于懒蚂蚁效应的是（）", "options": [{"letter": "A", "text": "通信工程师待遇优厚，工作时间自由，擅长攻克技术难题"}, {"letter": "B", "text": "在金融危机中，某外贸公司凭借多元化经营手段渡过了难关"}, {"letter": "C", "text": "某汽车公司鼓励员工创新，允许员工在上班时间钻研技术"}, {"letter": "D", "text": "某经理用人不拘一格，看重的是坚韧和正直，而非学历背景"}], "answer": "C", "explanation": "本题考查定义判断。'懒蚂蚁效应'的关键要素：平时看似不干活，实则在观察思考、侦察探索，在关键时刻能发挥重要作用带领团队找到新方向。C项某汽车公司鼓励员工创新，允许上班时间钻研技术，体现了给员工'懒蚂蚁'式的探索空间，符合懒蚂蚁效应。A项说的是工程师的工作特点，B项说的是多元化经营，D项说的是用人标准，均不符合定义。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1774}, {"num": 1776, "batch": "公共基础知识", "type": "single", "stem": "湿租，是航空公司之间的一种特殊租赁方式，在提供飞机的同时提供机组和乘务组为对方服务，而且在租赁过程中，被租赁飞机的标志不变、飞机号不变。民航规章体系将其定义为：是指按照租赁协议，承租方租赁飞机时携带出租方一名或者多名机组成员的租赁。根据上述定义，以下属于湿租的是（）", "options": [{"letter": "A", "text": "某航线由甲航空公司销售机票，乙航空公司独立执行飞行，两公司达成协议，合作期间使用甲公司的航班号"}, {"letter": "B", "text": "某航空公司为了开辟欧洲新航线，从甲国进口五架最新机型飞机，同时聘请甲国飞行员和专业维修技师为新航线服务"}, {"letter": "C", "text": "某航空公司因季节原因人员短缺，从乙航空公司临时借调部分工作人员承担飞行任务"}, {"letter": "D", "text": "圣诞将至，甲国航空公司为了缓解客运压力，从乙国租借了三架民用飞机，机组和维修员工仍为乙国航空公司原有资源"}], "answer": "D", "explanation": "本题考查定义判断。湿租的关键要素：租赁飞机时携带出租方的机组成员，且飞机标志和飞机号不变。D项甲国航空公司从乙国租借飞机，机组和维修员工仍为乙国航空公司原有人员，符合湿租的定义。A项是代码共享合作，B项是购买飞机并聘请人员，不是租赁关系，C项是借调人员而非租赁飞机附带机组。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1775}, {"num": 1777, "batch": "公共基础知识", "type": "single", "stem": "十八世纪一位德国数学家在写给著名数学家欧拉的一封信中，提出了一个猜想。该猜想可以表述为： （一）任何不小于6的偶数，都是两个奇素数之和；（二）任何不小于9的奇数，都是三个奇素数之和。我国著名数学家陈璟润在证明这一猜想中做出了重大贡献，这个猜想是（）", "options": [{"letter": "A", "text": "莫德尔猜想"}, {"letter": "B", "text": "哥德巴赫猜想"}, {"letter": "C", "text": "廉威一诺顿猜想"}, {"letter": "D", "text": "四色猜想"}], "answer": "B", "explanation": "本题考查数学常识。题干描述的猜想是哥德巴赫猜想，由德国数学家哥德巴赫在1742年写给欧拉的信中提出。其内容为：任何不小于6的偶数都可以表示为两个奇素数之和，任何不小于9的奇数都可以表示为三个奇素数之和。中国数学家陈景润证明了'1+2'，即每个充分大的偶数都可以表示为一个素数与一个不超过两个素数乘积之和，是该猜想的重大突破。选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1776}, {"num": 1778, "batch": "公共基础知识", "type": "single", "stem": "时代楷模是具有很强先进性、代表性、时代性和典型性的先进人物。下列时代楷模与事迹特点对应正确的是（）", "options": [{"letter": "A", "text": "张富清—95 岁老党员的本色人生"}, {"letter": "B", "text": "杜富国—践行社会主义核心价值观的优秀知识分子"}, {"letter": "C", "text": "黄文秀—用生命担当使命的新时代英雄战士"}, {"letter": "D", "text": "黄大年—乡村教育守望者"}], "answer": "A", "explanation": "本题考查时政知识。张富清是95岁老党员，战争年代立下赫赫战功，退役后深藏功名60多年，坚守初心、不改本色，被评为时代楷模，A项对应正确。杜富国是排雷英雄战士，而非知识分子典型；黄文秀是脱贫攻坚一线干部，是乡村教育守望者的说法不准确（她主要贡献在扶贫）；黄大年是战略科学家、新时代海归科技人才报国楷模，对应也非'乡村教育守望者'。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1777}, {"num": 1779, "batch": "公共基础知识", "type": "single", "stem": "实际上，泰坦尼克号上的救生船数量是符合英国当时的法律规定的，该项法律规定的救生船数量不是基于乘客人数，而是基于船的吨位。当时所有客船的救生船数量都远远低于需要的数量，配备救生船的目的不是用来装下全体乘客，而是预备在发生事故时将乘客转移到救援船上。在那时，国际通用的海事安全规则是客船上的救生船搭载人数应是船上总人数的三分之一，泰坦尼克号的救生船则可以搭载一半的乘客，白星公司还为这种“对乘客安全高度负责”的额外配置没有引起公众注意而感动委屈。下列说法与本文相符的是（）", "options": [{"letter": "A", "text": "白星公司唯物是图的做法导致泰坦尼克悲剧的发生"}, {"letter": "B", "text": "英国当时的法律与国际通用的海事安全规则不一致"}, {"letter": "C", "text": "泰坦尼克号配备的救生船数量超过法律规定的数量"}, {"letter": "D", "text": "泰坦尼克号的悲剧从技术角度看是完全可以避免的"}], "answer": "C", "explanation": "本题考查细节理解。文段指出泰坦尼克号的救生船数量符合当时英国法律规定，且其救生船可搭载一半乘客，而国际通用规则只要求搭载总人数的三分之一。这说明泰坦尼克号配备的救生船数量不仅符合法律，还超过了法律规定的标准（法律按吨位计算，实际搭载能力超过法律要求）。C项正确。A项文段未说白星公司唯利是图导致悲剧，B项文段未说法律与国际规则不一致，D项文段未说悲剧可避免。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1778}, {"num": 1780, "batch": "公共基础知识", "type": "single", "stem": "实施全面的急诊分级制度，技术层面的储备早已完成，关键还是靠患者的认同与服从。相对于“先到先得”的机械公平，按照病情轻重排序，显然是一种更复杂的公平规则。医护人员需要不断加以说服引导并进行医学常识科普，才能让患者理解其中的道理。就诊秩序、医疗效率，从来都与患者群体的科学素养和规则意识密切相关。倘若患者还是只信赖“先到先得”，急诊分级最终多半会不了了之。可以想见，急诊科所面临的许多问题，根源其实都在急诊科之外，这意味着急诊分级制度的推行难度比想象中还要大。这段文字意在强调，急诊分级制度的全面实施（）", "options": [{"letter": "A", "text": "建立在患者理解认可的基础上"}, {"letter": "B", "text": "应以更公平规则的确立为前提"}, {"letter": "C", "text": "有助于医疗效率的大幅提高"}, {"letter": "D", "text": "有赖于医学常识的广泛普及"}], "answer": "A", "explanation": "本题考查主旨理解。文段强调急诊分级制度'关键还是靠患者的认同与服从'，'医护人员需要不断说服引导'，'倘若患者只信赖先到先得，急诊分级多半会不了了之'，说明急诊分级的全面实施需要患者理解和认可。A项'建立在患者理解认可的基础上'准确概括了文段核心观点。B项强调公平规则，C项强调效率提高，D项强调科普，均非文段重点。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1779}, {"num": 1781, "batch": "公共基础知识", "type": "single", "stem": "实验室有A、B、C三个实验试管，分别装有10克、15克、20克的水，小明把含有一定浓度的10克药水倒进A试管中，混合后取出10克倒入B试管中，再次混合后，从B试管中取出10克倒入C试管中，最后用化学仪器检测出C试管中药水浓度为2%。试计算刚开始倒入A试管中药水的浓度是多少？", "options": [{"letter": "A", "text": "10%"}, {"letter": "B", "text": "20%"}, {"letter": "C", "text": "30%"}, {"letter": "D", "text": "40%"}], "answer": "C", "explanation": "本题考查溶液浓度问题。逆推法：C试管最终有20+10=30克水，浓度2%，含药30×2%=0.6克。这0.6克来自从B试管倒入的10克药水，所以B试管混合后浓度=0.6/10=6%。B试管原有15克水，加入10克A试管药水后共25克，浓度6%，含药25×6%=1.5克。这1.5克来自A试管倒出的10克药水，所以A试管混合后浓度=1.5/10=15%。A试管原有10克水，加入10克原药水后共20克，浓度15%，含药20×15%=3克。原药水浓度=3/10=30%。选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1780}, {"num": 1782, "batch": "公共基础知识", "type": "single", "stem": "食品药品安全追溯体系是依赖现代信息技术，对可能存在的食品药品安全隐患发出预警的一项制度。它之所以被一些国家广泛采用，是因为一方面能降低监管部门信息获取成本，提升监管效率；另一方面也能倒逼企业提高安全意识，主动进行风险控制。这项制度已引进我国多年，并体现在相关法律法规以及行动规划中。但在实践中，区域分割、部门分治等问题仍比较突出，没有形成高效的地方联动、部门合力，对解决食品药品安全问题缺少整体效果。这段文字意在强调（）", "options": [{"letter": "A", "text": "我国的食品药品安全追溯制度仍有待完善"}, {"letter": "B", "text": "完善的食品药品安全追溯体系有重要价值"}, {"letter": "C", "text": "相关部门应该加强对食品药品安全的监管"}, {"letter": "D", "text": "多方合作是解决食品药品安全问题的关键"}], "answer": "D", "explanation": "本题考查主旨理解。文段先介绍食品药品安全追溯体系的价值，然后指出我国实践中存在'区域分割、部门分治'等突出问题，'没有形成高效的地方联动、部门合力'。文段意在强调需要多方协作、形成合力来解决食品药品安全问题，即多方合作是关键。D项正确。A项只说制度有待完善过于笼统，B项说的是制度价值而非问题，C项只说加强监管不够全面。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1781}, {"num": 1783, "batch": "公共基础知识", "type": "single", "stem": "世界正处于大发展大变革大调整时期，和平与发展仍然是时代主题。世界多极化、经济全球化、社会信息化、文化多样化深入发展，全球治理体系和国际秩序变革加速推进，各国相互联系和依存日益加深，国际力量对比更趋平衡，和平发展大势不可逆转。同时，世界面临的不稳定性不确定性突出，世界经济增长动能不足，贫富分化日益严重，地区热点问题此起彼伏，恐怖主义、网络安全、重大传染性疾病、气候变化等非传统安全威胁持续蔓延，人类面临许多共同挑战。这段文字接下来讲的是（）", "options": [{"letter": "A", "text": "为什么我们认为当前的世界正处于发展与激变的时代"}, {"letter": "B", "text": "中国是维护世界和平、促进世界共同发展的重要力量"}, {"letter": "C", "text": "正确认识和把握时代的主题才是各国制定政策的依据"}, {"letter": "D", "text": "各国人民应同心协力应对我们所面临的各种风险挑战"}], "answer": "D", "explanation": "本题考查语句衔接。文段先描述了世界处于大发展大变革大调整时期，和平与发展是时代主题，然后指出世界面临诸多不稳定性不确定性和共同挑战。按照行文逻辑，接下来应该讨论如何应对这些共同挑战。D项'各国人民应同心协力应对各种风险挑战'承接上文，是最合理的后续内容。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1782}, {"num": 1784, "batch": "公共基础知识", "type": "single", "stem": "是促进人类社会向前发展的最终决定因素（）", "options": [{"letter": "A", "text": "生产关系"}, {"letter": "B", "text": "生产力"}, {"letter": "C", "text": "生产要素"}, {"letter": "D", "text": "生活方式"}], "answer": "B", "explanation": "本题考查历史唯物主义。马克思主义认为，生产力是促进人类社会向前发展的最终决定因素。生产力决定生产关系，经济基础决定上层建筑，生产力的发展推动社会形态的更替和人类社会的进步。生产力是社会发展的最终决定力量，是最革命、最活跃的因素。因此选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1783}, {"num": 1785, "batch": "公共基础知识", "type": "single", "stem": "书法是写字，但写字不是书法。文字是载体，它___________着表达思想、传递信息、记事备忘、传承历史的重大使命。而中国书法，则正是使汉字___________完美，升入化境的艺术。依次填入画横线部分最恰当的一项是（）", "options": [{"letter": "A", "text": "担负 臻于"}, {"letter": "B", "text": "肩负 趋于"}, {"letter": "C", "text": "承担 日趋"}, {"letter": "D", "text": "承载 日益"}], "answer": "A", "explanation": "本题考查词语搭配。第一空，'担负使命'是固定搭配，'担负'与'使命'搭配恰当。'肩负'也可与'使命'搭配，但'承担'多与'责任''义务'搭配，'承载'多与'希望''梦想'搭配。第二空，'臻于完美'是固定搭配，表示达到完美的境界。'趋于'虽有接近之意但语感不如'臻于'典雅准确。综合来看A项最恰当。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1784}, {"num": 1786, "batch": "公共基础知识", "type": "single", "stem": "书法在中国文化中具有特殊地位。书法受到绝大部分文字使用者的喜爱，但又长期被当作一种“小道”而受到轻视。20世纪以来，书法的生存环境发生了很大的变化。特别是硬笔取代毛笔成为日常书写工具，毛笔书写便离开了日常生活，只有致力于书法的人们，才会去接受毛笔书写的训练。 这段文字主要介绍了（）", "options": [{"letter": "A", "text": "书法在中国文化中的特殊价值"}, {"letter": "B", "text": "书法功能在当代的重大改变"}, {"letter": "C", "text": "人们对书法迥然不同的态度"}, {"letter": "D", "text": "毛笔在现代生活中的地位"}], "answer": "B", "explanation": "本题考查主旨概括。文段先说书法在中国文化中的特殊地位，然后说它长期被轻视，接着重点讲述20世纪以来书法生存环境的变化——硬笔取代毛笔后，毛笔书写离开了日常生活，只有致力于书法的人才会学习毛笔书写。文段主要介绍的是书法的功能在当代发生了重大改变——从日常实用书写工具变为专门的艺术追求。因此选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1785}, {"num": 1787, "batch": "公共基础知识", "type": "single", "stem": "数十年以来，科学家认为发现外星生命的最重要信息是这颗行星与主恒星的距离。在太阳系中，金星距离太阳最近，火星距离太阳较远，液态水无法存在。地球处于合适位置，存在着液态水和各种生命形式。然而，目前最新一项研究表明，仅凭借距离很难断定该行星是否具备生命存在的条件，宜居行星还必须具备适当的内部温度。 接下来最可能说的是（）", "options": [{"letter": "A", "text": "外星生命和行星内部适宜温度的关系"}, {"letter": "B", "text": "科学家关于行星适宜距离的最新研究"}, {"letter": "C", "text": "什么样的行星能具备适当的内部温度"}, {"letter": "D", "text": "人们对行星的宜居条件存在认识误区"}], "answer": "C", "explanation": "本题考查语句衔接。文段最后指出'仅凭借距离很难断定行星是否具备生命存在的条件，宜居行星还必须具备适当的内部温度'。按照话题一致性原则，接下来最可能围绕'适当的内部温度'展开论述，具体说明什么样的行星能具备适当的内部温度，或者内部温度如何影响宜居性。C项'什么样的行星能具备适当的内部温度'承接最为自然。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1786}, {"num": 1788, "batch": "公共基础知识", "type": "single", "stem": "数字鸿沟指的是由于信息和互联网的影响，人们的信息获取、信息处理和信息传播都是通过数字化技术来实现的，由此造成了不同个体、群体或者国家在思想意识、经济、文化和政治等方面的差距越来越大。 根据上述定义，下列不涉及数字鸿沟的是（）", "options": [{"letter": "A", "text": "放假回家的小宋和同学用手机聊天，满口网络新词，一旁的奶奶一句也听不懂"}, {"letter": "B", "text": "小赵整天痴迷于网络游戏，父母多次苦口婆心地劝说，均没有效果，为此小赵和父母发生了多次争执"}, {"letter": "C", "text": "东部某镇种植的水果尚未成熟就已经通过网络平台被订购一空，而西部某乡质优价廉的水果由于无人知晓，只能烂在树上"}, {"letter": "D", "text": "一些西方国家利用其技术积累，在大数据处理方面取得了绝对的优势，他们进一步实行技术封锁，使得某些国家在大数据分享方面一筹莫展"}], "answer": "B", "explanation": "本题考查定义判断。数字鸿沟的关键要素是因数字化技术造成的信息获取、处理和传播方面的差距。A项体现了老年人与年轻人在网络信息使用上的差距，C项体现了东西部地区在网络信息利用上的差距，D项体现了不同国家在大数据处理技术上的差距，均涉及数字鸿沟。B项小赵痴迷网络游戏导致与父母产生争执，属于网瘾问题，不涉及因数字化技术造成的信息差距，不属于数字鸿沟。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1787}, {"num": 1789, "batch": "公共基础知识", "type": "single", "stem": "水果：苹果（）", "options": [{"letter": "A", "text": "香梨：黄梨"}, {"letter": "B", "text": "树木：树枝"}, {"letter": "C", "text": "经济适用房：奔驰"}, {"letter": "D", "text": "山：高山"}], "answer": "D", "explanation": "本题考查类比推理。'水果'与'苹果'是包含关系（属种关系），苹果是水果的一种。D项'山'与'高山'也是包含关系，高山是山的一种。A项香梨和黄梨是并列关系，B项树木和树枝是组成关系，C项经济适用房和奔驰没有逻辑关系。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1788}, {"num": 1790, "batch": "公共基础知识", "type": "single", "stem": "司法公正体现在司法活动各个方面和对司法人员的要求上。下列（）做法体现的不是司法公正的内涵。", "options": [{"letter": "A", "text": "甲法院对社会关注的重大案件通过微博直播庭审过程"}, {"letter": "B", "text": "乙法院将本院公开审理后作出的判决书在网上公布"}, {"letter": "C", "text": "丙检察院为辩护人查阅、摘抄、复制案卷材料提供便利"}, {"letter": "D", "text": "丁检察院为暴力犯罪的被害人提供医疗和物质救助"}], "answer": "D", "explanation": "本题考查司法公正。司法公正包括程序公正和实体公正。A项微博直播庭审体现审判公开，B项网上公布判决书体现裁判公开，C项为辩护人查阅案卷提供便利保障了辩护权，均体现了司法公正。D项检察院为暴力犯罪被害人提供医疗和物质救助，属于司法救助范畴，体现的是司法人文关怀，而非司法公正的直接内涵。因此选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1789}, {"num": 1791, "batch": "公共基础知识", "type": "single", "stem": "诉诸无知是一种逻辑谬误,它是指人们指定一件事物是正确的，只是因为它未被证明是错误的，或者断定一件事物是错误的，只是因为它未被证明是正确的。根据上述定义下列属于诉诸无知的是（）", "options": [{"letter": "A", "text": "既然权威专家都说你错了，你就很可能真的错了"}, {"letter": "B", "text": "你缺乏证实不在现场的证据，所以你一定在现场。"}, {"letter": "C", "text": "你无法证明鬼是不存在的，所以鬼就是不存在的。"}, {"letter": "D", "text": "很多人都声称自己曾经见过鬼所以鬼是存在的。"}], "answer": "B", "explanation": "本题考查定义判断。诉诸无知的关键要素：因为未被证明是错误的就断定是正确的，或者因为未被证明是正确的就断定是错误的。B项'你缺乏证实不在现场的证据，所以你一定在现场'，属于因为不能证明你不在现场（未被证明是错误的），就断定你在现场（是正确的），符合诉诸无知的定义。A项诉诸权威，C项虽然结构类似但表述方向不同（无法证明鬼不存在→鬼不存在，是由未证明错误推出错误，与诉诸无知的一种形式相反），D项诉诸众人。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1790}, {"num": 1792, "batch": "公共基础知识", "type": "single", "stem": "算术平均数描述了一组数据的平均趋势，是所有数据之和除以数据个数所得之商。在统计学中使用时应注意：出现极端数值、模糊不清的数据或者不同质的数据时，均不能计算算术平均数。根据上述定义，下列适于计算算术平均数的是（）", "options": [{"letter": "A", "text": "某社区统计该社区居民的平均年龄，其中包括 10 岁以下儿童 204 人，90 岁以上老人 26 人"}, {"letter": "B", "text": "某公司统计 35 岁以下青年职工的年平均收入，发现基本处于 10～12 万元之间，其中有一人为公司高管，年收入百万元以上"}, {"letter": "C", "text": "某学校统计本校青少年平均身高，将该校学前部、小学部和中学部全部学生计算在内"}, {"letter": "D", "text": "某市统计该市各区县留守儿童的平均数量，其中外出务工人员数量较多的区县无法进行准确统计，只提供了估算数据"}], "answer": "A", "explanation": "本题考查定义判断。算术平均数不适用的情况：极端数值、模糊数据、不同质数据。A项统计居民平均年龄，包括各年龄段居民，数据同质且无极端值，适合计算算术平均数。B项有极端高收入的高管，存在极端值，不适合。C项将学前部、小学部和中学部混在一起统计青少年身高，属于不同质数据，不适合。D项有估算数据（模糊数据），不适合。因此选A。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1791}, {"num": 1793, "batch": "公共基础知识", "type": "single", "stem": "虽然寒冷的冬季是心血管疾病的高发期，但在高温闷热的“秋老虎”时节，空气中湿度增高、含氧量降低，平时患有高血压、冠心病的人常会感觉不适，出现胸闷、气促、头晕等症状。另外，高温天气会使人体出汗过多，血液浓缩，如果未能及时补充水分，容易形成斑块；一旦斑块脱落，血栓形成，堵塞血管，就可发生急性心梗。此外，人在炎热夏夜往往得不到良好的睡眠，这也是心脑血管疾病的重要诱因之一。闷热天气还会使人情绪波动、心情烦躁，这也是冠心病突发的危险因素。在这段时间，因工作劳累而缺乏休息的人，尤其要警惕心肌梗死突然来袭。最适合做这段文字标题的是（）", "options": [{"letter": "A", "text": "“养生”尤其要“养心”"}, {"letter": "B", "text": "“秋老虎”之名因何而来"}, {"letter": "C", "text": "心脑血管疾病诱因知多少"}, {"letter": "D", "text": "夏秋之交要预防心肌梗死"}], "answer": "D", "explanation": "本题考查标题选择。文段围绕'秋老虎'时节心脑血管疾病的多种诱因展开，包括湿度增高、出汗形成血栓、睡眠不好、情绪波动等，最后提醒缺乏休息的人要警惕心肌梗死。D项'夏秋之交要预防心肌梗死'准确概括了文段的时令提醒和核心警示。A项'养生养心'过于宽泛，B项'秋老虎之名'文段未解释名称由来，C项'诱因知多少'虽涉及内容但缺少预防警示的针对性。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1792}, {"num": 1794, "batch": "公共基础知识", "type": "single", "stem": "随着现代化进程的加快，传统文化的发展空间被压缩了。这其中有诸多因素的影响，但传统文化本身应对不灵活、缺乏创新能力也是一个重要原因。一方面是固步自封，不求变革而落伍于时代；一方面则身在宝山而不自知，优秀的文化财富没有得到充分开发利用。《花木兰》的故事被美国人拿去拍成动画片，影响跨越国界，就充分显示了民间传统文化创新的魅力。 上面这段话要表达的主要意思是（）。", "options": [{"letter": "A", "text": "分析传统文化未能与时俱进的原因"}, {"letter": "B", "text": "保护传统文化的关键是文化创新"}, {"letter": "C", "text": "传统文化需要用异国的思维才能创新"}, {"letter": "D", "text": "现代化进程加快是传统文化落伍的主要原因"}], "answer": "B", "explanation": "本题考查主旨理解。文段指出传统文化发展空间被压缩，原因之一是自身应对不灵活、缺乏创新能力，并举《花木兰》被美国改编成功的例子说明文化创新的重要性。文段核心观点是保护传统文化的关键在于文化创新。B项正确。A项只分析了原因而未提出对策，C项'异国思维'是对文段的曲解，D项将主要原因归于现代化进程，与文段强调的自身创新不足不符。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1793}, {"num": 1795, "batch": "公共基础知识", "type": "single", "stem": "随着债务置换计划的实施，地方债到期不能偿付的风险基本消弭，刚性兑付再一次得到确保。但地方债管理要真正走向规范化，还有许多技术问题有待解决，其中最为突出的就是地方政府的信用评级问题。信用评级是债券定价的基础。直接关乎发行方的融资成本，但由于信用评级标准不明确，东部发达地区和西部欠发达地区的政府信用评级一样，地方政府信用和国家信用评级一样，甚至还出现地方债利率低于国债利率的情形，这在理论上显然是说不通的，也完全不能反映“市场在资源配置中起决定性作用”的要求。 这段文字意在强调（）", "options": [{"letter": "A", "text": "地方债务管理风险仍需引起重视"}, {"letter": "B", "text": "地方政府信用评级制度亟待完善"}, {"letter": "C", "text": "债务利率的确定应当符合市场规律"}, {"letter": "D", "text": "解决地方债务问题应考虑地域差异"}], "answer": "B", "explanation": "本题考查主旨理解。文段先肯定地方债务风险基本消弭，然后转折指出地方债管理规范化仍面临技术问题，最突出的是地方政府信用评级问题——评级标准不明确、发达与欠发达地区评级一样、地方债利率甚至低于国债利率。文段重点在于强调地方政府信用评级制度亟待完善。B项正确。A项说的是债务风险，但文段已说风险基本消弭；C项和D项是信用评级问题的具体表现，不是文段主旨。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1794}, {"num": 1796, "batch": "公共基础知识", "type": "single", "stem": "随着政治形势的发展和工作重心的转移，中共中央早期所在地也相应地发生过多次变迁。以下选项中，中共中央早期所在地不包括（）", "options": [{"letter": "A", "text": "上海"}, {"letter": "B", "text": "武汉"}, {"letter": "C", "text": "江西瑞金"}, {"letter": "D", "text": "长春"}], "answer": "D", "explanation": "本题考查党史知识。中共中央早期所在地包括：1921年在上海成立，1927年迁至武汉，之后迁至江西瑞金（中央苏区时期），后又经长征到达陕北等。长春不是中共中央早期所在地。中共中央早期活动主要集中在上海、武汉、瑞金、延安等地。因此选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1795}, {"num": 1797, "batch": "公共基础知识", "type": "single", "stem": "所有的农耕文明时代的文化都具有保守性，无论东西方，概无例外。深刻的原因是，在以手工劳动为基础的生产方式中，“原封不动地保持旧的生产方式，却是过去一切工业阶级生存的首要条件”（《马克思恩格斯选集》）。西方文化，尤其是自然科学在西方文艺复兴与18世纪工业革命后之所以发生了深刻性的质变，引发了中西方的对立与冲突，以及中国在自然科学发展上的明显落后，根本原因在于，以机器为生产基础的商品经济生产方式与交换方式取代了以手工工具为基础的自然经济生产方式。 对上面这段话，理解正确的一项是（）。", "options": [{"letter": "A", "text": "以手工劳动为基础的生产方式，是导致农耕文明时代的文化具有保守性的根本原因"}, {"letter": "B", "text": "由表及里，从历史的文化现象角度分析了中西方的对立与冲突形成的深层原因"}, {"letter": "C", "text": "无论东西方，在封建时代，都是以农耕文明为主的，故而东西方都具有保守性"}, {"letter": "D", "text": "自然科学的质变引发了中西方文化的对立与冲突，引发了生产方式与交换方式的变化"}], "answer": "B", "explanation": "本题考查文段理解。文段从农耕文明文化的保守性出发，分析了中西方对立与冲突的深层原因——生产方式的差异（手工劳动vs机器生产）。B项'由表及里，从历史的文化现象角度分析了中西方的对立与冲突形成的深层原因'准确概括了文段的分析路径。A项只涉及前半段，C项过于简单化，D项将因果关系颠倒了（文段说的是生产方式变化引发文化质变，而非自然科学质变引发文化冲突）。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1796}, {"num": 1798, "batch": "公共基础知识", "type": "single", "stem": "图灵测试是指测试者在与被测试者（一个人和一台机器）隔开的情况下，通过一些装置（如键盘）向被测试者随意提问。问过一些问题后，如果被测试者有超过30%的答复不能使测试者确定出哪个是人、哪个是机器，那么这台机器就通过了测试，并被认为具有人类智能。 根据上述定义，以下哪项中的测试一定通过了图灵测试（）", "options": [{"letter": "A", "text": "对机器甲 40%的答复所有人都确认其为机器"}, {"letter": "B", "text": "对机器乙 60%的答复测试者能确认其为机器或人"}, {"letter": "C", "text": "对机器丙 30%的答复有 90%的某小区居民确认其为机器"}, {"letter": "D", "text": "对机器丁 30%的答复有 10%的某校大学生不能确认其为机器"}], "answer": "B", "explanation": "本题考查定义判断。图灵测试的通过标准：超过30%的答复不能使测试者确定哪个是人、哪个是机器。B项机器乙60%的答复测试者能确认其为机器或人，即有40%的答复不能确认，40%>30%，满足通过条件。A项40%能确认为机器，即60%不能确认？但'确认为机器'不等于'不能确认'，A项表述有歧义。C项30%的答复90%的人确认为机器，不能确定整体不能确认的比例。D项10%不能确认，10%<30%，不满足。因此选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1797}, {"num": 1799, "batch": "公共基础知识", "type": "single", "stem": "土壤是岩石在风化作用下破碎，物理化学性质改变后形成结构疏松的风化壳，风化壳在气候与生物的作用下，经历很长时间形成的地表物质。与土壤自然形成过程无关的外来物质被称为土壤侵入体。 根据上述定义，下列属于土壤侵入体的是（）", "options": [{"letter": "A", "text": "戈壁滩中大量的沙砾"}, {"letter": "B", "text": "河床上存在的大量鹅卵石"}, {"letter": "C", "text": "考古发掘中挖出的砖瓦"}, {"letter": "D", "text": "岩缝中生长的野草"}], "answer": "C", "explanation": "本题考查定义判断。土壤侵入体的关键要素是与土壤自然形成过程无关的外来物质。C项考古发掘中挖出的砖瓦是人类活动遗留的人造物品，与土壤的自然形成过程无关，属于土壤侵入体。A项戈壁滩沙砾是风力搬运的自然物质，B项河床鹅卵石是水流搬运和磨蚀的自然产物，D项岩缝野草是自然生长的植物，均属于土壤自然形成过程的组成部分。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1798}, {"num": 1800, "batch": "公共基础知识", "type": "single", "stem": "我国是工人阶级领导的、以工农联盟为基础的人民民主专政的社会主义国家，国家一切权力属于（）。", "options": [{"letter": "A", "text": "工人"}, {"letter": "B", "text": "人民"}, {"letter": "C", "text": "农民"}, {"letter": "D", "text": "社会新阶层"}], "answer": "B", "explanation": "本题考查宪法知识。根据《中华人民共和国宪法》第二条规定：'中华人民共和国的一切权力属于人民。人民行使国家权力的机关是全国人民代表大会和地方各级人民代表大会。'我国是工人阶级领导的、以工农联盟为基础的人民民主专政的社会主义国家，国家一切权力属于人民，这是我国国家制度的核心内容和根本原则。因此选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1799}, {"num": 1801, "batch": "公共基础知识", "type": "single", "stem": "万圣节即将到来，哥哥给艾丽一些钱让她去商店买节日小装饰品，艾丽来到商店，南瓜灯18元一个，小怪兽14元一个，如果单买南瓜灯钱正好用完，如果单买小怪兽钱也正好用完，那么，哥哥给艾丽的钱数为（）", "options": [{"letter": "A", "text": "266 元"}, {"letter": "B", "text": "342 元"}, {"letter": "C", "text": "459 元"}, {"letter": "D", "text": "504 元"}], "answer": "D", "explanation": "本题考查最小公倍数。南瓜灯18元一个，小怪兽14元一个，钱数需同时是18和14的倍数。18=2×3²，14=2×7，最小公倍数为2×3²×7=126。126的倍数有126、252、378、504等，选项中只有504=126×4符合条件，故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1800}, {"num": 1802, "batch": "公共基础知识", "type": "single", "stem": "王戎七岁，尝与诸小儿游，见道边李树多子折枝。诸儿竟走取之，唯戎不动。人问之，答曰：“树在道边而多子，此必苦李。”取之信然。王戎的隐含推理的假设是（）", "options": [{"letter": "A", "text": "若路边的李子被摘光了，就不会多子折枝。"}, {"letter": "B", "text": "若路边的李子味道甜美，就不会多子折枝。"}, {"letter": "C", "text": "若路边的李子味道不甜美，就会多子折枝。"}, {"letter": "D", "text": "只有路边的李子没被摘光，才会多子折枝。"}], "answer": "B", "explanation": "王戎的推理逻辑是：李树在路边却果实累累，说明没人摘，没人摘说明李子不好吃。其隐含假设是'如果李子味道甜美，早就被路人摘光了，不会多子折枝'，即B项。这是典型的反证法推理。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1801}, {"num": 1803, "batch": "公共基础知识", "type": "single", "stem": "为积极响应市民诉求，做到“闻风而动、接诉即办”，A镇实行闭环管理，全程督办。近日，市民安女士反映社区附近垃圾站散发臭味的问题，A镇政府在签收工单后采取了一系列措施，以下措施中不符合工作流程要求的是（）", "options": [{"letter": "A", "text": "直接将安女士反映的问题派单至A镇所在区的城市管理委员会"}, {"letter": "B", "text": "联系镇环卫部门具体承办，安女士所在社区全程盯办，并及时和安女士沟通"}, {"letter": "C", "text": "在整件事情解决的过程中，镇纪委牵头，区监察专员参与，对履职情况和办理实效等进行全程监督"}, {"letter": "D", "text": "在工单办结后及时回访安女士，确认办理结果"}], "answer": "C", "explanation": "镇纪委的职责是监督执纪问责，不应'牵头'整个事件的处理流程。工单办理应由业务部门承办，镇纪委可以参与监督，但不应由其牵头主导整个流程。A项直接派单至区城管委属于正常的业务流转，B项联系环卫部门承办并跟踪沟通符合流程，D项办结后回访也属正常。故选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1802}, {"num": 1804, "batch": "公共基础知识", "type": "single", "stem": "为加强机关文化建设，某市直机关在系统内举办演讲比赛，3个部门分别派出3、2、4名选手参加比赛，要求每个部门的参赛选手比赛顺序必须相连，问不同参赛顺序的种数在以下哪个范围之内（）", "options": [{"letter": "A", "text": "小于 1000"}, {"letter": "B", "text": "1000~5000"}, {"letter": "C", "text": "5001~20000"}, {"letter": "D", "text": "大于 20000"}], "answer": "B", "explanation": "每个部门的选手必须相连，可用捆绑法。3个部门作为整体排列有3!=6种；各部门内部排列分别为3!=6、2!=2、4!=24种。总排列数=6×6×2×24=1728种，属于1000~5000范围，故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1803}, {"num": 1805, "batch": "公共基础知识", "type": "single", "stem": "为了躲避天敌和高温日晒，许多候鸟迁徙时选择夜间飞行。当必须飞越某些天然地理屏障如墨西哥湾时，它们甚至会不眠不休地连续飞行24小时。与人一样，长期缺乏睡眠会令鸟儿极度疲惫，灵活性降低，这必然导致它们在中途休息时面临更大的危险。然而一项最新研究表明，候鸟们自有一套聪明的解决办法。科学家观测了7只捕获到的斯文氏夜鸫，发现这种惯常夜间飞行的候鸟白天休息时并非完全放松，通常会睁着一只眼睛。而脑电波也显示，它们只有半个大脑处于标准休眠状态。下列哪项最适合作这段文字的标题？", "options": [{"letter": "A", "text": "半梦半醒之间"}, {"letter": "B", "text": "斯文氏夜鸫的秘技"}, {"letter": "C", "text": "睁一只眼，闭一只眼"}, {"letter": "D", "text": "你的夜晚，我的白天"}], "answer": "A", "explanation": "文段主要介绍候鸟夜间飞行导致睡眠不足，但科学家发现它们在白天休息时只有半个大脑处于休眠状态，可以睁一只眼保持警觉。'半梦半醒之间'准确概括了候鸟这种独特的休息方式，既形象又全面，最适合做标题。B项过于具体，C项只描述了表面现象，D项偏离主题。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1804}, {"num": 1806, "batch": "公共基础知识", "type": "single", "stem": "为了实现经济增长和社会公平的双重目标，我们在实行按劳分配为主体、多种分配方式并存的个人收入分配制度时必须坚持的一条原则是（）", "options": [{"letter": "A", "text": "部分地区一部分人先富起来"}, {"letter": "B", "text": "防止两极分化，实现共同富裕"}, {"letter": "C", "text": "代表最广大人民群众的根本利益"}, {"letter": "D", "text": "建设社会主义政治文明"}], "answer": "B", "explanation": "我国实行按劳分配为主体、多种分配方式并存的分配制度，既要提高效率，又要促进公平。防止两极分化、实现共同富裕是社会主义的本质要求，也是个人收入分配制度必须坚持的原则。这体现了效率与公平的统一。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1805}, {"num": 1807, "batch": "公共基础知识", "type": "single", "stem": "为什么火焰常常会是黄颜色的?这是因为火焰在燃烧时会附带空气中的很多烟尘颗粒，它们会导致火焰不能充分燃烧。人类很早就可以控制火，但是效果一直不理想，也就是说在如何让火焰能够充分燃烧这个问题上，许多科学家一直在探索。 这段文字主要介绍了：（）", "options": [{"letter": "A", "text": "人类用火的历史"}, {"letter": "B", "text": "火焰燃烧的原理"}, {"letter": "C", "text": "火焰为什么是黄的"}, {"letter": "D", "text": "人们在利用火焰方面的难题"}], "answer": "D", "explanation": "文段先解释了火焰呈黄色的原因（燃烧不充分导致烟尘颗粒影响），然后指出人类虽很早就能控制火，但在让火焰充分燃烧这一问题上始终效果不理想，许多科学家一直在探索。文段重点在于说明人们在利用火焰方面面临的难题，故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1806}, {"num": 1808, "batch": "公共基础知识", "type": "single", "stem": "文学走进互联网，获得了―个崭新的平民化开放视野。网络上自由、兼容和共享的虚拟空间，打破了精英写作对文学话语权的垄断，为愿意上网创作的网民提供了“人人都能当作家”的机会。这种“新民间文学”，标志着文学话语权向民间回归。尽管如此，网络写作仍然不能与“人民写作”相提并论，因为文学的“人民写作”并不取决于传媒的公共性和参与的广泛性，而取决于这种文学的人民性价值取向和为广大民众喜闻乐见的审美品格。 这段文字主要说的是（）", "options": [{"letter": "A", "text": "大众化是未来文学发展的趋势"}, {"letter": "B", "text": "文学创作应坚持人民性的价值取向"}, {"letter": "C", "text": "网络写作为普通人提供了平等的话语权"}, {"letter": "D", "text": "平民化的网络文学不能等同于“人民写作”"}], "answer": "D", "explanation": "文段先肯定网络写作打破了精英垄断、实现了话语权向民间回归，然后用'尽管如此'转折，指出网络写作不能等同于'人民写作'，因为'人民写作'取决于人民性价值取向和审美品格，而非传媒的公共性。文段核心观点在转折之后，故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1807}, {"num": 1809, "batch": "公共基础知识", "type": "single", "stem": "我国的国家结构形式属于（）", "options": [{"letter": "A", "text": "民族区域自治"}, {"letter": "B", "text": "单一制"}, {"letter": "C", "text": "联邦制"}, {"letter": "D", "text": "邦联制"}], "answer": "B", "explanation": "根据我国宪法规定，中华人民共和国是全国各族人民共同缔造的统一的多民族国家。我国的国家结构形式是单一制，即全国只有一个中央政府、一部宪法，各地方行政区域都在中央统一领导下。民族区域自治是我国的基本政治制度，不是国家结构形式。故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1808}, {"num": 1810, "batch": "公共基础知识", "type": "single", "stem": "我国古代对于公文的保密最早可以追溯到夏朝。据史书记载，太史令将“图法”（即国家的重要典志、档案）“官藏”；商朝时，设立了守藏史这一官职，专门负责保管政府公务文书和典册；周朝继承了商朝的传统，将文书正本收藏于天府——我国历史上最早的中央档案机构。到了秦朝时，在文书上玺印封缄，在传递过程中使用“封泥”已是普遍的一种做法。到了东汉时期，办公文件保密用的“封泥”竟然成为把守关隘的比喻词。《后汉书·隗嚣传》记载：“（王）元请以一丸泥为大王东封函谷关，此万世一时也。”说明守关如封泥，应小心翼翼，不得有一丝疏漏。 这段文字主要介绍的是（）", "options": [{"letter": "A", "text": "历代公文的保密方法"}, {"letter": "B", "text": "“封泥”一词的演变过程"}, {"letter": "C", "text": "档案储存办法的演变"}, {"letter": "D", "text": "史书对文书保存方法的记载"}], "answer": "A", "explanation": "文段按时间顺序依次介绍了夏朝的'图法''官藏'、商朝设守藏史保管文书、周朝将文书收藏于天府、秦朝的玺印封缄和'封泥'、东汉'封泥'一词的引申用法。全文围绕历代公文保密方法展开，故选A。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1809}, {"num": 1811, "batch": "公共基础知识", "type": "single", "stem": "我们要办好人民满意的教育，全面贯彻党的教育方针，落实立德树人（），培养德智体美劳全面发展的社会主义建设者和接班人。", "options": [{"letter": "A", "text": "首要任务"}, {"letter": "B", "text": "第一要务"}, {"letter": "C", "text": "第一任务"}, {"letter": "D", "text": "根本任务"}], "answer": "D", "explanation": "党的二十大报告明确指出：'我们要办好人民满意的教育，全面贯彻党的教育方针，落实立德树人根本任务，培养德智体美劳全面发展的社会主义建设者和接班人。'立德树人是教育的根本任务，故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1810}, {"num": 1812, "batch": "公共基础知识", "type": "single", "stem": "我国政府机构与立法机构的关系是（）", "options": [{"letter": "A", "text": "并行关系"}, {"letter": "B", "text": "平等关系"}, {"letter": "C", "text": "从属关系"}, {"letter": "D", "text": "业务关系"}], "answer": "C", "explanation": "根据我国宪法规定，国家行政机关（政府）由人民代表大会（立法机关）产生，对它负责，受它监督。全国人大是最高国家权力机关，国务院由全国人大产生并对其负责。因此政府机构与立法机构是从属关系，故选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1811}, {"num": 1813, "batch": "公共基础知识", "type": "single", "stem": "我们除了做事，还需多读书，但人生苦短，经典都读不完，何必读其他？何谓经典？经过时间淘洗的著作才是经典。放宽点来说，知识界公认的大家著作也称为经典。但并非大家的所有著作都是经典。一个人，一生能写出一部经典已属不易，能写两三部者可称奇才。故一般而论，读一个人的代表作即已足够，只有少数里程碑式人物的著作需要全读。这段文字的主要议题是（）", "options": [{"letter": "A", "text": "如何理解经典"}, {"letter": "B", "text": "如何阅读经典"}, {"letter": "C", "text": "应读什么书"}, {"letter": "D", "text": "怎样坚持读书"}], "answer": "C", "explanation": "文段从'需多读书'引出'人生苦短，经典读不完，何必读其他'的议题，接着讨论何谓经典、大家著作与经典的关系，最后建议读代表作即可。整段文字围绕'应读什么书'这一核心议题展开，而非如何理解或阅读经典的方法，故选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1812}, {"num": 1814, "batch": "公共基础知识", "type": "single", "stem": "我们要完善以（）为核心的中国特色社会主义法律体系，加强宪法实施和监督，加强重点领域、新兴领域、涉外领域立法。", "options": [{"letter": "A", "text": "道德"}, {"letter": "B", "text": "法律"}, {"letter": "C", "text": "社会舆论"}, {"letter": "D", "text": "宪法"}], "answer": "D", "explanation": "党的二十大报告明确指出：'我们要完善以宪法为核心的中国特色社会主义法律体系，加强宪法实施和监督，加强重点领域、新兴领域、涉外领域立法。'宪法是国家的根本法，是法律体系的核心，故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1813}, {"num": 1815, "batch": "公共基础知识", "type": "single", "stem": "习近平在二十届中共中央政治局常委同中外记者见面时的讲话中指出，前进道路上，无论是风高浪急还是惊涛骇浪，人民永远是我们最坚实的（）、最强大的（）。", "options": [{"letter": "A", "text": "依托 底气"}, {"letter": "B", "text": "靠山 力量"}, {"letter": "C", "text": "依靠 力量"}, {"letter": "D", "text": "根基 底气"}], "answer": "A", "explanation": "习近平在二十届中共中央政治局常委同中外记者见面时的讲话中指出：'前进道路上，无论是风高浪急还是惊涛骇浪，人民永远是我们最坚实的依托、最强大的底气。'这体现了以人民为中心的发展思想，故选A。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1814}, {"num": 1816, "batch": "公共基础知识", "type": "single", "stem": "我们已经目睹，那些科幻小说中原本只存在于想象之中的未来科技逐一实现，并且改变了真实的世界。也许有一天，科幻小说不再思索和模拟技术的实际作用，而把全部注意力放在叙事者的主题、人类宿命甚至宇宙命运之上，我们仍要感谢它们帮助我们幻想过未来世界。只是，但愿永远可以有人像儒勒?凡尔纳在一百多年前那样由衷地发问：难道人们真的不可能用更短的时间环游地球吗？ 根据这段文字可以知道，作者希望科幻作品（）", "options": [{"letter": "A", "text": "尽可能想象科技发展对人类的影响"}, {"letter": "B", "text": "更加关注科幻故事情节本身的发展"}, {"letter": "C", "text": "能够继续激励和启发未来科技的创新"}, {"letter": "D", "text": "应努力探讨未来科技应用的具体表现"}], "answer": "C", "explanation": "文段先肯定科幻小说中想象的技术逐一实现，然后说即使未来科幻小说不再关注技术模拟，我们仍要感谢它们帮助我们幻想过未来世界，最后引用凡尔纳的发问表达对科技创新的期待。作者希望科幻作品能继续激励和启发未来科技创新，故选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1815}, {"num": 1817, "batch": "公共基础知识", "type": "single", "stem": "无论导演还是监制，都是非常复杂的工种，经验的积累非常重要。没有经历过片场的摸爬滚打，在现场的执行能力就会有问题。因此，在一些电影产业成熟的国家，新人从学校毕业之后，要先在制片厂当学徒，从写剧本开始，再经过副导演、执行导演等环节，在各方面技能掌握齐全之后，最终成长为一名合格的导演，此后再“导而优则监”。 下列哪句话最能概括这段文字所包含的道理（）", "options": [{"letter": "A", "text": "纸上得来终觉浅，绝知此事要躬行"}, {"letter": "B", "text": "书山有路勤为径，学海无涯苦作舟"}, {"letter": "C", "text": "天才是 1%的天赋加 99%的努力"}, {"letter": "D", "text": "不想当将军的士兵不是好士兵"}], "answer": "A", "explanation": "文段强调导演和监制的成长需要丰富的实践经验，从片场摸爬滚打到学徒、副导演等环节逐步积累。'纸上得来终觉浅，绝知此事要躬行'强调实践的重要性，与文段主旨最为吻合。B项强调勤奋，C项强调天赋与努力，D项强调志向，均不如A项贴切。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1816}, {"num": 1818, "batch": "公共基础知识", "type": "single", "stem": "五四运动表现出来的爱国主义精神，与以往的爱国主义相比较，具有历史进步性和鲜明时代性。这种爱国主义不是盲目排外，而是为了维护国家独立和民族尊严；不是（），而是与民主和科学精神紧密联系，追求发展进步；不是（），而是付诸行动，以“直接行动”投入反帝运动。", "options": [{"letter": "A", "text": "刻舟求剑、作壁上观"}, {"letter": "B", "text": "邯郸学步、闭门造车"}, {"letter": "C", "text": "固步自封、纸上谈兵"}, {"letter": "D", "text": "拾人牙慧、夸夸其谈"}], "answer": "C", "explanation": "第一空，与'盲目排外'并列且被'不是'否定，应填入表示保守封闭之意的词。'固步自封'指停留在原地不求进步，符合语境。第二空，与'付诸行动'相对，'纸上谈兵'比喻空谈理论不解决实际问题，与'付诸行动'形成对比。故选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1817}, {"num": 1819, "batch": "公共基础知识", "type": "single", "stem": "物必先腐：而后虫生", "options": [{"letter": "A", "text": "古木无人径：深山何处钟"}, {"letter": "B", "text": "水落鱼梁浅：天寒梦泽深"}, {"letter": "C", "text": "少壮不努力：老大徒伤悲"}, {"letter": "D", "text": "欲投人处宿：隔水问樵夫"}], "answer": "C", "explanation": "'物必先腐，而后虫生'意为东西先腐烂才会生虫，前后为因果关系。'少壮不努力，老大徒伤悲'意为年轻时不努力导致年老悲伤，也是因果关系。A、B、D三项均为并列或对仗关系，只有C项构成因果关系，故选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1818}, {"num": 1820, "batch": "公共基础知识", "type": "single", "stem": "物体：惯性", "options": [{"letter": "A", "text": "气体：稳定性"}, {"letter": "B", "text": "观察：客观性"}, {"letter": "C", "text": "贵金属：磁性"}, {"letter": "D", "text": "液体：流动性"}], "answer": "D", "explanation": "惯性是物体固有的基本属性，一切物体都具有惯性。同理，流动性是液体固有的基本属性。A项气体不具有稳定性（气体易扩散），B项观察不一定具有客观性，C项贵金属一般不具有磁性，均不构成必然属性关系。故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1819}, {"num": 1821, "batch": "公共基础知识", "type": "single", "stem": "西太平洋是全球海山系统分布最为集中的海域，人类对此处海山的认识却非常有限。西太平洋的马里亚 纳海沟是板块俯冲地带，海底地质运动非常活跃，海山火山岩的物质组成及成因等是海洋地质科学家感兴趣的问题；西太平洋的暖池和北赤道流等对中国气候有重要影响，是物理海洋科学家关注的重点区域；这里还有全球海洋生物多样性最高的珊瑚礁大三角区，是开展海洋生物起源与进化研究的热点区域。因此，海洋科学家可以在此开展海山的水文物理、化学及生源要素、地形地貌和地质环境及生物生态等多学科协同探测与研究。（）", "options": [{"letter": "A", "text": "在西太平洋开展科学研究的重要价值"}, {"letter": "B", "text": "人们对西太平洋海山系统的认识"}, {"letter": "C", "text": "西太平洋区域所蕴含的海洋资源"}, {"letter": "D", "text": "西太平洋对中国气候和地质的影响"}], "answer": "A", "explanation": "文段从三个角度阐述西太平洋的科研价值：地质学（马里纳亚海沟的地质运动）、物理海洋学（暖池和北赤道流对气候的影响）、海洋生物学（珊瑚礁大三角区的生物多样性研究），最后总结可在此开展多学科协同研究。文段主旨在于强调在西太平洋开展科学研究的重要价值，故选A。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1820}, {"num": 1822, "batch": "公共基础知识", "type": "single", "stem": "习近平总书记在全国高校思想政治工作会议上指出，要把（）贯穿教育教学全过程，实现全程育人、全方位育人，努力开创我国高等教育事业发展新局面。", "options": [{"letter": "A", "text": "思想教育工作"}, {"letter": "B", "text": "劳动教育工作"}, {"letter": "C", "text": "思想政治工作"}, {"letter": "D", "text": "实践教育工作"}], "answer": "C", "explanation": "习近平总书记在全国高校思想政治工作会议上指出：'要把思想政治工作贯穿教育教学全过程，实现全程育人、全方位育人，努力开创我国高等教育事业发展新局面。'思想政治工作是高校各项工作的生命线，故选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1821}, {"num": 1823, "batch": "公共基础知识", "type": "single", "stem": "习近平主席在谈到如何提高工作效率时说：“必须学会运用辩证法，分清层次，认真思考，‘审大小而图之，酌缓急而布之，连上下而通之，衡内外而施之。’”此处用典不包含的哲理是（）", "options": [{"letter": "A", "text": "坚持“两点论”和“重点论”的统一"}, {"letter": "B", "text": "以联系的观点和发展的观点看待问题"}, {"letter": "C", "text": "尊重客观规律基础上发挥主观能动性"}, {"letter": "D", "text": "遵循社会发展前进性与曲折性的统一"}], "answer": "D", "explanation": "题干用典强调要分清层次、审大小、酌缓急，体现了重点论与两点论的统一（A项）、联系和发展的观点（B项）、在尊重规律基础上发挥主观能动性（C项）。'审大小''酌缓急'体现的是统筹兼顾和抓住重点，并未涉及社会发展的前进性与曲折性统一的哲理，故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1822}, {"num": 1824, "batch": "公共基础知识", "type": "single", "stem": "习近平总书记在全国教育大会上指出，教育服务中华民族伟大复兴，必须在正确的政治路线指导下，全面提高国民的（）。", "options": [{"letter": "A", "text": "文化素质"}, {"letter": "B", "text": "道德品质"}, {"letter": "C", "text": "综合素质"}, {"letter": "D", "text": "身体素质"}], "answer": "C", "explanation": "习近平总书记在全国教育大会上指出，教育服务中华民族伟大复兴，必须全面提高国民综合素质。这包括思想道德素质、科学文化素质、身心健康素质等各方面，体现了教育对提升国民整体素质的重要作用，故选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1823}, {"num": 1825, "batch": "公共基础知识", "type": "single", "stem": "习近平总书记在全国教育大会上指出，我国是中国共产党领导的社会主义国家，这就决定了我们的教育必须把培养社会主义建设者和接班人作为（），培养一代又一代拥护中国共产党领导和我国社会主义制度、立志为中国特色社会主义奋斗终身的有用人才。", "options": [{"letter": "A", "text": "根本方针"}, {"letter": "B", "text": "根本保证"}, {"letter": "C", "text": "根本任务"}, {"letter": "D", "text": "根本方向"}], "answer": "C", "explanation": "习近平总书记在全国教育大会上强调：'我国是中国共产党领导的社会主义国家，这就决定了我们的教育必须把培养社会主义建设者和接班人作为根本任务。'这明确了我国教育的社会主义办学方向和根本任务，故选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1824}, {"num": 1826, "batch": "公共基础知识", "type": "single", "stem": "习近平总书记在全国教育大会上指出，要不断使教育同党和国家事业发展要求相适应、（）、同我国综合国力和国际地位相匹配。", "options": [{"letter": "A", "text": "同人民群众期待相契合"}, {"letter": "B", "text": "同政治文明进步相匹配"}, {"letter": "C", "text": "同经济发展步调相协调"}, {"letter": "D", "text": "同社会发展方向相一致"}], "answer": "A", "explanation": "习近平总书记在全国教育大会上指出：'要不断使教育同党和国家事业发展要求相适应、同人民群众期待相契合、同我国综合国力和国际地位相匹配。'三个'同'体现了教育发展的目标和定位，故选A。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1825}, {"num": 1827, "batch": "公共基础知识", "type": "single", "stem": "要坚持马克思主义在意识形态领域指导地位的（），坚持为人民服务、为社会主义服务。", "options": [{"letter": "A", "text": "基本制度"}, {"letter": "B", "text": "基本要求"}, {"letter": "C", "text": "根本制度"}, {"letter": "D", "text": "根本要求"}], "answer": "C", "explanation": "党的十九届四中全会明确提出：'要坚持马克思主义在意识形态领域指导地位的根本制度。'这是第一次将马克思主义在意识形态领域的指导地位以根本制度形式确立下来，故选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1826}, {"num": 1828, "batch": "公共基础知识", "type": "single", "stem": "下列不属于夫妻共同财产的是（）", "options": [{"letter": "A", "text": "婚前房屋在婚后所得的租金"}, {"letter": "B", "text": "夫妻关系存续期间，军人的复员费和自主择业费"}, {"letter": "C", "text": "婚后由一方父母出资购买的不动产，产权登记在出资人子女名下"}, {"letter": "D", "text": "婚姻存续期间虽未实际取得，但明确可以取得的知识产权收益"}], "answer": "C", "explanation": "根据《民法典》及相关司法解释，婚后由一方父母出资购买的不动产，产权登记在出资人子女名下的，视为只对自己子女一方的赠与，该不动产应认定为夫妻一方的个人财产，不属于夫妻共同财产。A项婚后租金属于投资收益，B项复员费在婚姻存续期间的部分属于共同财产，D项知识产权收益属于共同财产。故选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1827}, {"num": 1829, "batch": "公共基础知识", "type": "single", "stem": "下列常见的心理现象与成语对应错误的是（）", "options": [{"letter": "A", "text": "晕轮效应——爱屋及乌"}, {"letter": "B", "text": "首因效应——一鼓作气"}, {"letter": "C", "text": "门槛效应——得寸进尺"}, {"letter": "D", "text": "从众效应——人云亦云"}], "answer": "B", "explanation": "首因效应是指第一印象对人际认知的影响，应对应'先入为主'。'一鼓作气'出自《曹刿论战》，意为趁劲头大的时候鼓起干劲一口气做完，与首因效应不对应。A项晕轮效应即'爱屋及乌'（以偏概全），C项门槛效应即'得寸进尺'（逐步递进），D项从众效应即'人云亦云'，均正确。故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1828}, {"num": 1830, "batch": "公共基础知识", "type": "single", "stem": "下列对气候与城市规划的描述错误的是（）", "options": [{"letter": "A", "text": "街道位于与子午线成30～60度夹角处，有利于两侧建筑的采光"}, {"letter": "B", "text": "我国城市房屋在确定房屋间距时，应以夏至日的日照时间为准"}, {"letter": "C", "text": "工业布局一般在该地区盛行主导风向的下风向"}, {"letter": "D", "text": "机场一般选在低云和风速较小的地方"}], "answer": "B", "explanation": "确定房屋间距时，应以冬至日（而非夏至日）的正午太阳高度角为准，因为冬至日太阳高度角最小，影子最长。只有保证冬至日也能获得足够的日照，才能确保全年采光。夏至日太阳高度角最大，以此为准则会导致间距过小。故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1829}, {"num": 1831, "batch": "公共基础知识", "type": "single", "stem": "下列对诗词中的物理现象描述错误的是（）", "options": [{"letter": "A", "text": "坐地日行八万里，巡天遥看一千河——地球的公转"}, {"letter": "B", "text": "两岸青山相对出，孤帆一片日边来——运动的相对性"}, {"letter": "C", "text": "八月秋高风怒号，卷我屋上三重茅——空气振动发声"}, {"letter": "D", "text": "飞流直下三千尺，疑是银河落九天——势能转化为动能"}], "answer": "A", "explanation": "'坐地日行八万里'描述的是地球的自转现象，而非公转。地球自转一周约24小时，赤道周长约4万公里（8万里），人坐在地球上随地球自转一天就行进了8万里。公转是地球绕太阳运动，周期为一年。故选A。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1830}, {"num": 1832, "batch": "公共基础知识", "type": "single", "stem": "下列古代宫廷建筑与帝王对应错误的是（）", "options": [{"letter": "A", "text": "鹿台——秦始皇"}, {"letter": "B", "text": "台城——梁武帝"}, {"letter": "C", "text": "思子台——汉武帝"}, {"letter": "D", "text": "大明宫——唐玄宗"}], "answer": "A", "explanation": "鹿台是商纣王所建，不是秦始皇所建。据《史记》记载，商纣王在鹿台聚敛财富，武王伐纣后纣王登鹿台自焚。秦始皇的代表性建筑是阿房宫、咸阳宫等。B项台城与梁武帝（梁武帝饿死台城）、C项思子台与汉武帝、D项大明宫与唐玄宗均正确。故选A。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1831}, {"num": 1833, "batch": "公共基础知识", "type": "single", "stem": "下列关于避雷针的说法，错误的是（）", "options": [{"letter": "A", "text": "南北朝时就已出现与避雷针工作原理相似的“避雷室”"}, {"letter": "B", "text": "避雷针和他要保护的建筑是由绝缘物质隔开的"}, {"letter": "C", "text": "接闪器可用铝合金、镀锌钢、不锈钢等各种材料制成"}, {"letter": "D", "text": "我国现在已经放弃了“避雷针”这一叫法，而代之以“接闪杆”"}], "answer": "B", "explanation": "避雷针的工作原理是通过金属导体将雷电引入地下，从而保护建筑物。避雷针与被保护建筑之间必须是导通的（相连的），而非用绝缘物质隔开。如果用绝缘物质隔开，雷电无法通过避雷针导入地下，就失去了保护作用。故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1832}, {"num": 1834, "batch": "公共基础知识", "type": "single", "stem": "下列关于党的重要思想，按提出时间先后顺序排列正确的是（）①社会主义市场经济理论②“三个代表”重要思想③社会主义本质理论④构建社会主义和谐社会理念", "options": [{"letter": "A", "text": "①②③④"}, {"letter": "B", "text": "①②④③"}, {"letter": "C", "text": "③①②④"}, {"letter": "D", "text": "③②①④"}], "answer": "C", "explanation": "③社会主义本质理论于1992年南方谈话中提出；①社会主义市场经济理论于1992年十四大提出；②'三个代表'重要思想于2000年提出；④构建社会主义和谐社会理念于2004年十六届四中全会提出。正确顺序为③①②④，故选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1833}, {"num": 1835, "batch": "公共基础知识", "type": "single", "stem": "下列关于国家征收农民集体所有土地补偿的规定，下列说法错误的是（）", "options": [{"letter": "A", "text": "征收农民集体土地，需要按照被征收土地的原用途予以补偿"}, {"letter": "B", "text": "征收耕地以外其他土地的补偿标准由省、自治区、直辖市规定"}, {"letter": "C", "text": "被征收土地上的附着物和青苗的补偿标准，由市、县人民政府规定"}, {"letter": "D", "text": "征收耕地应给予土地补偿费、安置补助费、地上附着物和青苗的补偿费"}], "answer": "C", "explanation": "根据《土地管理法》规定，被征收土地上的附着物和青苗的补偿标准，由省、自治区、直辖市规定（而非市、县人民政府规定）。A项按原用途补偿、B项其他土地补偿标准由省级规定、D项征收耕地给予土地补偿费、安置补助费等，均符合法律规定。故选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1834}, {"num": 1836, "batch": "公共基础知识", "type": "single", "stem": "下列关于生活常识的表述，错误的是（）", "options": [{"letter": "A", "text": "干冰是固体状态的二氧化碳，可用于人工降雨"}, {"letter": "B", "text": "红黄绿能作为信号灯的颜色，是因为这三种颜色有波长优势"}, {"letter": "C", "text": "海市蜃楼是由于特殊气象条件下大气发生剧烈的反射造成的"}, {"letter": "D", "text": "烟草、面粉等有机粉尘聚焦的厂房里容易发生爆炸"}], "answer": "C", "explanation": "海市蜃楼是由于大气密度不均匀导致光线发生折射（而非反射）而形成的自然现象。当空气温度分布不均匀时，不同密度的空气层对光的折射率不同，使远处物体的光线发生弯曲，形成虚像。A项干冰人工降雨、B项红黄绿波长优势、D项粉尘爆炸均表述正确。故选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1835}, {"num": 1837, "batch": "公共基础知识", "type": "single", "stem": "下列关于五行思想的说法，不正确的是（）", "options": [{"letter": "A", "text": "五行中的木，对应的方位是东方，颜色是青色"}, {"letter": "B", "text": "五行相生的顺序是木生火，火生金，金生土，土生水"}, {"letter": "C", "text": "五行可以与天干搭配，与火搭配的是丙丁"}, {"letter": "D", "text": "五行思想起源很早，《尚书?洪范》篇就有相关记载"}], "answer": "B", "explanation": "五行相生的正确顺序是：木生火、火生土、土生金、金生水、水生木。B项中'火生金，金生土'的顺序错误，应为'火生土，土生金'。A项木对应东方和青色正确，C项火与丙丁搭配正确，D项《尚书·洪范》确有五行记载。故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1836}, {"num": 1838, "batch": "公共基础知识", "type": "single", "stem": "下列关于医学常识的表述，错误的是（）", "options": [{"letter": "A", "text": "发生药物过敏时，应首先多喝些温开水，便于药物排泄"}, {"letter": "B", "text": "清晨空腹时肠胃比较脆弱，不宜服用药物"}, {"letter": "C", "text": "运动员受伤时，医生可用氯乙烷来给运动员阵痛和局部麻醉"}, {"letter": "D", "text": "缺乏碘元素会引发甲状腺肿大或克汀病等"}], "answer": "B", "explanation": "并非所有药物都不宜在清晨空腹时服用。有些药物恰恰需要空腹服用以提高吸收效果，如某些甲状腺激素类药物、部分抗生素等。'清晨空腹不宜服药'的说法过于绝对。A项药物过敏时多喝水促进排泄、C项氯乙烷用于局部麻醉和镇痛、D项缺碘导致甲状腺肿大，均表述正确。故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1837}, {"num": 1839, "batch": "公共基础知识", "type": "single", "stem": "下列国际组织，按照中国加入的时间先后顺序排列正确的一项是a联合国b亚太经合组织c国际原子能机构d世界贸易组织", "options": [{"letter": "A", "text": "abcd"}, {"letter": "B", "text": "acbd"}, {"letter": "C", "text": "cbad"}, {"letter": "D", "text": "cadb"}], "answer": "B", "explanation": "中国加入联合国的时间为1945年（创始成员国）；加入国际原子能机构（IAEA）为1984年；加入亚太经合组织（APEC）为1991年；加入世界贸易组织（WTO）为2001年。正确顺序为a-c-b-d，故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1838}, {"num": 1840, "batch": "公共基础知识", "type": "single", "stem": "下列经济学基本术语与项目内容之间对应错误的是（）", "options": [{"letter": "A", "text": "固定成本：企业建造的厂房"}, {"letter": "B", "text": "不变资本：企业购入的原材料"}, {"letter": "C", "text": "变动成本：企业总经理的工资报酬"}, {"letter": "D", "text": "机会成本：为投资股票提前支取定期存款而损失的利息"}], "answer": "C", "explanation": "企业总经理的工资报酬属于固定成本，不随产量变化而变化，而非变动成本。变动成本是指随产量变化而变化的成本，如原材料、直接人工等。A项厂房属于固定成本、B项原材料属于不变资本、D项损失的利息属于机会成本，均正确。故选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1839}, {"num": 1841, "batch": "公共基础知识", "type": "single", "stem": "下列历史人物与其擅长领域对应错误的是（）", "options": [{"letter": "A", "text": "军事∶白起、李靖"}, {"letter": "B", "text": "经济∶桑弘羊、郦道元"}, {"letter": "C", "text": "天文∶张衡、郭守敬"}, {"letter": "D", "text": "艺术∶吴道子、顾恺之"}], "answer": "B", "explanation": "郦道元是北魏地理学家，著有《水经注》，属于地理学领域，而非经济领域。桑弘羊是西汉经济学家，主持盐铁官营等经济政策。A项白起和李靖均为军事家、C项张衡和郭守敬均为天文学家、D项吴道子和顾恺之均为画家，均正确。故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1840}, {"num": 1842, "batch": "公共基础知识", "type": "single", "stem": "下列历史人物与其著名言论对应错误的是（）", "options": [{"letter": "A", "text": "孟子——穷则独善其身，达则兼善天下"}, {"letter": "B", "text": "林则徐——苟利国家生死以，岂因祸福避趋之"}, {"letter": "C", "text": "梁启超——国家之主人为谁？即一国之民是也"}, {"letter": "D", "text": "曾国藩——天变不足畏，祖宗不足法，人言不足恤"}], "answer": "D", "explanation": "'天变不足畏，祖宗不足法，人言不足恤'是北宋王安石变法时的名言，不是曾国藩的话。A项孟子'穷则独善其身'、B项林则徐'苟利国家生死以'、C项梁启超'国家之主人为谁'，均对应正确。故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1841}, {"num": 1843, "batch": "公共基础知识", "type": "single", "stem": "下列历史事件中，发生在中共中央进驻香山期间的有（）①渡江战役吹响了解放全中国的进军号角②毛泽东同志发表《论人民民主专政》③《中国人民政治协商会议共同纲领》起草通过④人民解放军举行盛大的北平入城式", "options": [{"letter": "A", "text": "①②③"}, {"letter": "B", "text": "①②④"}, {"letter": "C", "text": "①③④"}, {"letter": "D", "text": "②③④"}], "answer": "A", "explanation": "中共中央进驻香山时间为1949年3月至9月。①渡江战役于1949年4月发起，在香山期间；②《论人民民主专政》发表于1949年6月30日，在香山期间；③《共同纲领》于1949年9月通过，在香山期间；④北平入城式于1949年1月31日举行，此时中央尚在河北西柏坡，不在香山期间。故选A。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1842}, {"num": 1844, "batch": "公共基础知识", "type": "single", "stem": "下列每组现象包含的物理学原理不同的是（）", "options": [{"letter": "A", "text": "高压锅蒸煮食物-火星上水的沸点降低"}, {"letter": "B", "text": "饮料从摔碎的瓶子中溅出-大质量恒星末期爆炸"}, {"letter": "C", "text": "烤箱中葡萄干面包膨胀，葡萄干远移-宇宙扩张，星系远移"}, {"letter": "D", "text": "用 LED.手电直射滴入 1 滴牛奶的水杯，末端呈黄色-傍晚天边呈橘红色"}], "answer": "B", "explanation": "A项均涉及气压与沸点的关系；C项均涉及膨胀导致距离增大（类比宇宙膨胀）；D项均涉及光的散射原理（牛奶颗粒散射短波光，末端呈黄色，类似傍晚天空呈橘红色）。B项饮料溅出是惯性现象，大质量恒星末期爆炸是超新星爆发（引力坍缩），原理不同。故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1843}, {"num": 1845, "batch": "公共基础知识", "type": "single", "stem": "下列哪项不属于非战争军事行动（）", "options": [{"letter": "A", "text": "反恐维稳"}, {"letter": "B", "text": "安保警戒"}, {"letter": "C", "text": "国际维和"}, {"letter": "D", "text": "防空反导"}], "answer": "D", "explanation": "非战争军事行动是指战争以外的军事行动，包括反恐维稳、安保警戒、国际维和、抢险救灾、国际救援等。防空反导属于战争行动范畴，是应对敌方空中威胁的作战行动，不属于非战争军事行动。故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1844}, {"num": 1846, "batch": "公共基础知识", "type": "single", "stem": "下列哪项不属于古人的林业思想（）", "options": [{"letter": "A", "text": "孟春之月，禁止伐木"}, {"letter": "B", "text": "斧斤以时入山林，林木不可胜用"}, {"letter": "C", "text": "凡有地牧民者，务在四时，守在仓廪"}, {"letter": "D", "text": "春三月，山林不登斧，以成草木之长"}], "answer": "C", "explanation": "C项'凡有地牧民者，务在四时，守在仓廪'出自《管子·牧民》，讲的是治理国家要重视农时和粮食储备，属于农业治理思想，不属于林业思想。A项禁止春季伐木、B项按时令入山伐木、D项春季不伐木以助草木生长，均体现了古人的林业保护和可持续发展思想。故选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1845}, {"num": 1847, "batch": "公共基础知识", "type": "single", "stem": "下列哪一首诗描写的景色在今天四川省境内（）", "options": [{"letter": "A", "text": "窗含西岭千秋雪，门泊东吴万里船"}, {"letter": "B", "text": "天街小雨润如酥，草色遥看近却无"}, {"letter": "C", "text": "天门中断楚江开，碧水东流至此回"}, {"letter": "D", "text": "横看成岭侧成峰，远近高低各不同"}], "answer": "A", "explanation": "'窗含西岭千秋雪，门泊东吴万里船'出自杜甫《绝句》，描写的是成都草堂所见之景，西岭即成都西面的岷山，位于今四川省境内。B项描写的是长安（西安）春景，C项描写的是天门山（安徽），D项描写的是庐山（江西）。故选A。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1846}, {"num": 1848, "batch": "公共基础知识", "type": "single", "stem": "下列哪种情形可能发生（）", "options": [{"letter": "A", "text": "辛亥革命发生时，希腊人在体育场观看世界杯足球赛"}, {"letter": "B", "text": "五四运动发生时，中国大学生利用半导体收音机收听广播"}, {"letter": "C", "text": "冷战时期，苏联某地电影院放映彩色电影"}, {"letter": "D", "text": "越战期间，美国人在家里用计算机访问互联网"}], "answer": "C", "explanation": "冷战时期（1947-1991年），彩色电影技术已成熟（1935年第一部彩色电影问世），苏联电影院放映彩色电影是完全可能的。A项世界杯1930年才开始，辛亥革命1911年，时间不符；B项半导体收音机1954年才发明，五四运动1919年，时间不符；D项互联网1990年代才普及，越战1955-1975年，时间不符。故选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1847}, {"num": 1849, "batch": "公共基础知识", "type": "single", "stem": "下列俗语描述的现象与经济学名词对应错误的是（）", "options": [{"letter": "A", "text": "覆水难收——机会成本"}, {"letter": "B", "text": "一山不容二虎——完全垄断"}, {"letter": "C", "text": "入芝兰之室，久而不闻其香——边际效用递减"}, {"letter": "D", "text": "城门失火，殃及池鱼——负外部效应"}], "answer": "A", "explanation": "'覆水难收'比喻事情已成定局无法挽回，应对应的是'沉没成本'（已经发生无法收回的成本），而非'机会成本'（选择某一方案而放弃其他方案所损失的收益）。B项一山不容二虎对应完全垄断、C项入芝兰之室对应边际效用递减、D项城门失火对应负外部效应，均正确。故选A。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1848}, {"num": 1850, "batch": "公共基础知识", "type": "single", "stem": "下列选项中，党政机关公文成文日期写法正确的是（）", "options": [{"letter": "A", "text": "2016.5.30"}, {"letter": "B", "text": "二〇一六年五月三十日"}, {"letter": "C", "text": "2016年5月30日"}, {"letter": "D", "text": "二零一六年五月三十日"}], "answer": "C", "explanation": "根据《党政机关公文格式》（GB/T 9704-2012）规定，公文成文日期应用阿拉伯数字将年、月、日标全，年份应标全称，月、日不编虚位。即正确格式为'2016年5月30日'。A项缺少'年月日'，B项用汉字书写，D项'零'字使用不规范。故选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1849}, {"num": 1851, "batch": "公共基础知识", "type": "single", "stem": "下列选项中，对于古文化常识描述错误的是（）", "options": [{"letter": "A", "text": "古称兄弟间的老大为“伯”，古代兄弟间以伯、仲、叔、季为排行顺序，古人常在字前加排行次序，如“伯禽”、“仲尼”、“叔向”、“季路”等"}, {"letter": "B", "text": "垂髫是古时对六十岁以上老妇人的别称，髫是指老人轻软披散的头发"}, {"letter": "C", "text": "古代位居方向有尊卑之称，如南向为胜、尊，以北向为败、卑；以东为主为首，以西为从为次，后渐以“东家”为主人的代称"}, {"letter": "D", "text": "蛾眉，亦作“娥眉”，古代美女的代称，“娥眉”本为女子长而美的眉毛，代指女子美貌，进而代称美女"}], "answer": "B", "explanation": "'垂髫'是古时对儿童的别称，指三四岁至八九岁的儿童，因古时儿童不束发，头发下垂，故称'垂髫'。并非对六十岁以上老妇人的别称。A项兄弟排行伯仲叔季、C项方位尊卑、D项蛾眉代称美女，均正确。故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1850}, {"num": 1852, "batch": "公共基础知识", "type": "single", "stem": "下列选项中，与王国维在《人间词话》中谈到治学三境界时引用的“衣带渐宽终不悔，为伊消得人憔悴”内涵最相近的是（）", "options": [{"letter": "A", "text": "海内存知己，天涯若比邻"}, {"letter": "B", "text": "宝剑锋从磨砺出，梅花香自苦寒来"}, {"letter": "C", "text": "会当凌绝顶，一览众山小"}, {"letter": "D", "text": "劝君更尽一杯酒，西出阳关无故人"}], "answer": "B", "explanation": "'衣带渐宽终不悔，为伊消得人憔悴'出自柳永《蝶恋花》，王国维以此比喻治学第二境界——执着追求、无怨无悔。'宝剑锋从磨砺出，梅花香自苦寒来'同样表达了经过艰苦磨练才能取得成功的含义，内涵最为相近。A项写友情，C项写抱负，D项写送别。故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1851}, {"num": 1853, "batch": "公共基础知识", "type": "single", "stem": "下列言论中涉及的人才选拔制度，按出现顺序先后排列正确的是（）①学通行修，经中博士②宗室非有军功论，不得为属籍③九品访人，唯问中正④风吹金榜落凡世，三十三人名字香", "options": [{"letter": "A", "text": "②①③④"}, {"letter": "B", "text": "③②④①"}, {"letter": "C", "text": "②④①③"}, {"letter": "D", "text": "①③②④"}], "answer": "A", "explanation": "①'学通行修，经中博士'指科举制中的明经科，出现于隋唐；②'宗室非有军功论，不得为属籍'指军功爵制，出现于战国时期秦国商鞅变法；③'九品访人，唯问中正'指九品中正制，出现于魏晋南北朝；④'风吹金榜落凡世'指科举制，出现于隋唐。按时间顺序为②①③④（军功爵制→察举/经学→九品中正→科举），故选A。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1852}, {"num": 1854, "batch": "公共基础知识", "type": "single", "stem": "下列有关“不忘初心、牢记使命”主题教育的说法正确的是（）", "options": [{"letter": "A", "text": "总要求是坚守初心使命，积极担当作为"}, {"letter": "B", "text": "根本任务是建设高素质党员干部队伍"}, {"letter": "C", "text": "把学习教育、调查研究、检视问题、整改落实贯穿主题教育全过程"}, {"letter": "D", "text": "具体目标是找差距、抓落实"}], "answer": "C", "explanation": "'不忘初心、牢记使命'主题教育的总要求是'守初心、担使命，找差距、抓落实'；根本任务是深入学习贯彻新时代中国特色社会主义思想、锤炼忠诚干净担当的政治品格、团结带领全国各族人民为实现伟大梦想共同奋斗；方法论是把学习教育、调查研究、检视问题、整改落实贯穿全过程。C项表述正确。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1853}, {"num": 1855, "batch": "公共基础知识", "type": "single", "stem": "下列有关传统文化常识表述有误的一项是（）", "options": [{"letter": "A", "text": "《四库全书》按照经、史、子、集四部分类，所以称为“四库”"}, {"letter": "B", "text": "“五岳”即东岳泰山、南岳黄山、西岳华山、北岳恒山、中岳嵩山"}, {"letter": "C", "text": "京剧人物分为生、旦、净、丑四种行当"}, {"letter": "D", "text": "我国古代的四大发明包括造纸、火药、印刷术、指南针"}], "answer": "B", "explanation": "'五岳'分别是东岳泰山、西岳华山、南岳衡山（不是黄山）、北岳恒山、中岳嵩山。南岳是衡山而非黄山，黄山位于安徽，不属于五岳。A项《四库全书》分经史子集四部、C项京剧四大行当、D项四大发明，均正确。故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1854}, {"num": 1856, "batch": "公共基础知识", "type": "single", "stem": "下列与成语有关的描述错误的是（）", "options": [{"letter": "A", "text": "“叶落归根”是因为地球表面的物体会受到重力的作用"}, {"letter": "B", "text": "“青出于蓝”描述的是传统植物染料的提取过程"}, {"letter": "C", "text": "“囊萤映雪”中“囊萤”和“映雪”包含的光学原理相同"}, {"letter": "D", "text": "“沙里淘金”中的“金”属于金属单质"}], "answer": "C", "explanation": "'囊萤'是利用萤火虫发出的生物光来读书，属于生物发光现象；'映雪'是利用雪地反射的月光来读书，属于光的反射现象。两者包含的光学原理不同。A项叶落归根涉及重力、B项青出于蓝涉及植物染料提取（化学变化）、D项金是金属单质，均正确。故选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1855}, {"num": 1857, "batch": "公共基础知识", "type": "single", "stem": "下列与对联有关的说法错误的是（）", "options": [{"letter": "A", "text": "“不夜灯光，便是玲珑世界；通宵月色，无非圆满乾坤”写的是元宵佳节"}, {"letter": "B", "text": "“暮鼓晨钟，惊醒世间名利客；经声佛号，唤回苦海梦迷人”是西汉人写的"}, {"letter": "C", "text": "“新年的余庆，嘉节号长春”符合对联“仄起平落”的书写习惯"}, {"letter": "D", "text": "“入门尽是弹冠客，去后应无搔首人”适合作为理发店的对联"}], "answer": "B", "explanation": "B项对联'暮鼓晨钟，惊醒世间名利客；经声佛号，唤回苦海梦迷人'是佛教寺院的楹联，其作者不可能是西汉人。佛教传入中国是在西汉末年，且此联的语言风格和意境明显属于后世作品。实际上此联一般认为是后蜀或宋代作品。A项描写元宵、C项符合仄起平落、D项适合理发店，均正确。故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1856}, {"num": 1858, "batch": "公共基础知识", "type": "single", "stem": "下列与雪有关的说法正确的是（）", "options": [{"letter": "A", "text": "大气中有足够的凝结核是形成降雪的必要条件"}, {"letter": "B", "text": "食盐可作为融雪物质，是因为盐水的凝固点比纯水高"}, {"letter": "C", "text": "“下雪不冷化雪冷”是因为凝固吸热，有降温制冷作用"}, {"letter": "D", "text": "“六月飞雪”是文学作品杜撰的场景，不可能在我国境内出现"}], "answer": "A", "explanation": "降雪的形成需要大气中有足够的水汽和凝结核，凝结核是水汽凝结的核心，是形成降雪的必备条件。B项错误，盐水凝固点比纯水低（不是高），所以食盐能融雪；C项错误，'化雪冷'是因为融化吸热（不是凝固吸热）；D项错误，'六月飞雪'虽罕见但在高海拔地区确实可能出现。故选A。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1857}, {"num": 1859, "batch": "公共基础知识", "type": "single", "stem": "古典诗词中蕴藏着丰富的科学知识。对此，下列表述错误的是（）", "options": [{"letter": "A", "text": "“墙角数枝梅，凌寒独自开。遥知不是雪，为有暗香来”说明花香分子在不断运动"}, {"letter": "B", "text": "“千淘万漉虽辛苦，吹尽狂沙始到金”反映了金的化学性质具有稳定性"}, {"letter": "C", "text": "“铁盂汤雪早，石炭煮茶迟”反映了石炭煮茶在火盆中不能充分燃烧且存在大量的热散失"}, {"letter": "D", "text": "“爆竹声中一岁除，春风送暖入屠苏”反映了竹子内部的化学物质迅速燃烧而爆炸"}], "answer": "D", "explanation": "'爆竹声中一岁除'中的'爆竹'是指将竹子放入火中燃烧，竹节内的空气受热膨胀导致竹筒爆裂发出声响，并非竹子内部的'化学物质'燃烧爆炸。这是物理变化（气体膨胀），而非化学反应。A项分子运动、B项金的化学稳定性、C项石炭不充分燃烧和热散失，均正确。故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1858}, {"num": 1860, "batch": "公共基础知识", "type": "single", "stem": "下列语句中，不存在歧义的有（）", "options": [{"letter": "A", "text": "柏林警察群殴球迷50人受伤"}, {"letter": "B", "text": "已有42个部委的高等院校实行了联合办学"}, {"letter": "C", "text": "实行大规模的休牧，这在内蒙古还是首次"}, {"letter": "D", "text": "合同上写得明明白白：“李老柱欠杨井井500块砖钱”"}], "answer": "C", "explanation": "A项'50人受伤'有歧义，可能是警察50人或球迷50人；B项'42个部委的高等院校'有歧义，可能是42个部委所属的高校或42所部委高校；D项'500块砖钱'有歧义，可能是500块砖的价钱或500块钱的砖。C项表述清晰明确，'大规模休牧在内蒙古是首次'没有歧义，故选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1859}, {"num": 1861, "batch": "公共基础知识", "type": "single", "stem": "现代化学与炼金（炼丹）的相同点是从分子层面创造新事物，至于创造新元素其实是核物理学家的任务，由他们拿一些回旋加速机把新元素轰出来然后再填到元素周期表中作为化学家的胜利果实。古典炼金术实际上已经有了元素、原子这样的理念，但并不具备理性思维，例如中世纪的欧洲人认为，轻、重、干、湿是基本的物理性质，干而轻的是火，干而重的是土，湿而轻的是气，湿而重的是水，因此，任何物质均是由水、火、土、气这四种基本元素按不同比例合成的结果，这与目前可知世界的观念显然不同，而同时期其它文明中对物质本质的认识同样也是介于神秘与理性之间。接下来最可能讲的是（）", "options": [{"letter": "A", "text": "现代化学理性思维的起点"}, {"letter": "B", "text": "物理学家如何创造新元素"}, {"letter": "C", "text": "古典炼金术对欧洲文明的影响"}, {"letter": "D", "text": "可知世界中关于元素的各种观念"}], "answer": "A", "explanation": "文段先指出现代化学与炼金术的相同点，然后说古典炼金术虽有元素、原子理念但不具备理性思维，最后提到同时期其他文明也介于神秘与理性之间。文段以炼金术缺乏理性思维为对比，接下来最可能讲述现代化学理性思维的起点，即现代化学是如何建立起理性思维体系的。故选A。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1860}, {"num": 1862, "batch": "公共基础知识", "type": "single", "stem": "现代信息技术与高等教育教学的融合，衍生出大规模在线开放课程，打破了传统教育的时空界限和学校围墙。六年来，中国慕课从无到有，从小到大，在实践中总在向一个共识靠近，那就是高等教育作为高层次人才的主要供给者，知识创新的主要推动者，要回应时代需求，就必须创新发展，把慕课建设作为加快中国教育现代化、发展“互联网+教育”“智能+教育”的战略先手棋，推进这场深度融合信息技术与教育教学的课堂革命向纵深发展。这就意味着，慕课的建设与发展必然离不开高校的参与和支持、学校与社会的共同协力。这段文字意在（）", "options": [{"letter": "A", "text": "介绍中国慕课的发展理念和现状"}, {"letter": "B", "text": "强调高校应在慕课发展中发挥重要作用"}, {"letter": "C", "text": "说明高校需重视高级人才的培养和储备"}, {"letter": "D", "text": "探讨中国慕课突破传统的新思路"}], "answer": "D", "explanation": "文段先介绍慕课打破了传统教育界限，然后指出高等教育要回应时代需求就必须创新发展，最后强调慕课建设离不开高校和社会的共同支持。文段的落脚点在于慕课建设需要各方协力推进，意在探讨中国慕课突破传统、纵深发展的新思路。故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1861}, {"num": 1863, "batch": "公共基础知识", "type": "single", "stem": "现阶段，我国社会的主要矛盾是（）", "options": [{"letter": "A", "text": "生产力与生产关系之间的矛盾"}, {"letter": "B", "text": "人民日益增长的物质文化需要同落后的社会生产之间的矛盾"}, {"letter": "C", "text": "公有制经济与非公有制经济之间的矛盾"}, {"letter": "D", "text": "人民日益增长的美好生活需要和不平衡不充分的发展之间的矛盾"}], "answer": "D", "explanation": "党的十九大报告明确指出：'中国特色社会主义进入新时代，我国社会主要矛盾转化为人民日益增长的美好生活需要和不平衡不充分的发展之间的矛盾。'这是对我国社会发展阶段性特征的准确判断，故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1862}, {"num": 1864, "batch": "公共基础知识", "type": "single", "stem": "现在很多人对快速发展的食品科技比较陌生，对食品从农田到餐桌的全过程知之甚少，因此对错误信息的辨识能力、对谣言的抵御能力十分有限。那些（）的谣言不仅影响消费信心，也给行业、产业带来直接的危害。强化食品安全科普传播（），也迫在眉睫，这已经成为全行业和全社会的共识。", "options": [{"letter": "A", "text": "虚张声势、至关重要"}, {"letter": "B", "text": "铺天盖地、首当其冲"}, {"letter": "C", "text": "口耳相传、任重道远"}, {"letter": "D", "text": "耸人听闻、势在必行"}], "answer": "D", "explanation": "第一空修饰'谣言'，且后文说'影响消费信心，给行业带来危害'，说明谣言具有夸大和耸人听闻的特点。'耸人听闻'指故意说夸大或惊奇的话使人震惊，符合语境。第二空'强化科普传播势在必行'表示必须进行，与'迫在眉睫'呼应。A项'虚张声势'侧重假装强大，不符语境。故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1863}, {"num": 1865, "batch": "公共基础知识", "type": "single", "stem": "宪法的基本原则是指人们在制定和实施宪法的过程中必须遵循的最基本的准则。下面对我国宪法的基本原则表述正确的是（）", "options": [{"letter": "A", "text": "人民主权原则、基本人权原则、法制原则和权力制约原则"}, {"letter": "B", "text": "人民主权原则、罪名法定原则、法制原则和权力制约原则"}, {"letter": "C", "text": "基本人权原则、依法解释原则、法制原则和经济中立原则"}, {"letter": "D", "text": "基本人权原则、罪名法定原则、法制原则和经济中立原则"}], "answer": "A", "explanation": "我国宪法的基本原则包括：人民主权原则（一切权力属于人民）、基本人权原则（国家尊重和保障人权）、法治原则（依法治国）和权力制约原则（权力的监督与制约）。罪名法定原则属于刑法原则，经济中立原则不是宪法原则。故选A。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1864}, {"num": 1866, "batch": "公共基础知识", "type": "single", "stem": "写作事实上不但是为了向外发表，贡献社会，同时也是研究工作的最后阶段，而且是最重要、最严肃的阶段。不形成文章，根本就没有完成研究工作，学问也没有成熟。常有人说“某人学问极好，可惜不写作”，事实上，此话大有问题。某人可能学识丰富，也有见解，但不写作为文，他的学问就只停留在简单看法的阶段，没有经过严肃的思考与整理，就不可能真正是系统的、系统的。这段文字主要强调的是（）", "options": [{"letter": "A", "text": "论文写作的重要性"}, {"letter": "B", "text": "科学研究的首要目的"}, {"letter": "C", "text": "研究工作的评价标准"}, {"letter": "D", "text": "知识与实践的内在联系"}], "answer": "A", "explanation": "文段核心观点是：写作是研究工作的最后也是最重要的阶段，不形成文章就没有完成研究工作。文段强调论文写作对学术研究的重要性——学问只有经过严肃思考和整理形成文章，才能成为系统的知识。B项'首要目的'、C项'评价标准'、D项'知识与实践'均非文段重点。故选A。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1865}, {"num": 1867, "batch": "公共基础知识", "type": "single", "stem": "心理科普教育是一项系统工程，需要方方面面的共同配合。某区开展了各类特色的心理科普教育活动。街道和社区是心理科普教育的主阵地，各街道也把此项工作列为社区教育的重点；区委组织部、区人力资源和社会保障部门、区教育部门、区妇联等相关单位从实际出发，开展了针对性强的心理科普教育，对稳定职工队伍起到了积极的作用。 最适合做本段文字标题的是（）（?）", "options": [{"letter": "A", "text": "某区开展了大量的心理科普活动"}, {"letter": "B", "text": "共同推进心理科普教育，形成良好工作氛围"}, {"letter": "C", "text": "心理科普教育是社区教育的重点"}, {"letter": "D", "text": "各单位开展了有针对性的心理科普教育"}], "answer": "B", "explanation": "文段首句点明心理科普教育需要'方方面面的共同配合'，接着从街道社区、区委组织部、人社部门、教育部门、妇联等多个角度介绍了某区开展的特色活动。标题应体现'多方配合、共同推进'的核心意思，B项最为全面准确。A、C、D项均只涉及某一方面。故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1866}, {"num": 1868, "batch": "公共基础知识", "type": "single", "stem": "心理学家发现，人们对世界的认识受到两种基本需求的驱动：第一，我们对世界的认识有种“一致性需求”，希望世界的运动符合我们的信仰、理念、态度、经验和预期，即使现实与我们自身的预期不一致，我们也要改变外在的证据来使它符合我们内在的期望；第二，人类需要对外在环境产生一种控制感，我们不希望自己在现实面前无能为力、无所适从，我们需要找到某种自己能够理解、控制、描述、解释和预测的可能性。 心理学家的发现可以解释下列哪一行为（）", "options": [{"letter": "A", "text": "在集体中容易产生从众心理"}, {"letter": "B", "text": "在明知自己错误的情况下仍固执己见"}, {"letter": "C", "text": "喜欢用“阴谋论”解释超越自己经验之外的事物"}, {"letter": "D", "text": "在过于熟悉的环境中容易产生厌倦心理并试图改变"}], "answer": "C", "explanation": "心理学家的两个发现：人有'一致性需求'（改变证据使其符合预期）和'控制感需求'（需要能理解和解释事物）。'阴谋论'恰好满足这两个需求——它提供了一种自洽的解释框架（一致性），让人觉得复杂事件背后有可理解的原因（控制感）。C项最能被这一发现解释。A项从众、B项固执己见、D项厌倦环境均不够全面。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1867}, {"num": 1869, "batch": "公共基础知识", "type": "single", "stem": "新中国成立前夕，毛泽东同志把中国共产党在全国执政比作进京“赶考”。多年来，习近平总书记在许多场合多次重提“赶考”。这种“赶考”意识主要体现了中国共产党和中国共产党人的（）", "options": [{"letter": "A", "text": "奉献精神"}, {"letter": "B", "text": "忧患意识"}, {"letter": "C", "text": "学习意识"}, {"letter": "D", "text": "钻研精神"}], "answer": "B", "explanation": "'赶考'意识源自毛泽东将执政比作进京赶考，寓意共产党执政是一场考验。反复重提'赶考'体现的是中国共产党和党员干部的忧患意识——时刻保持警醒，防止骄傲自满和腐化堕落，始终保持谦虚谨慎、艰苦奋斗的作风。故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1868}, {"num": 1870, "batch": "公共基础知识", "type": "single", "stem": "亚当·斯密是现代经济学的主要创立者，为世界经济学的发展做出了杰出的贡献，其在经济学领域的代表作是（）", "options": [{"letter": "A", "text": "《微观经济学》"}, {"letter": "B", "text": "《宏观经济学》"}, {"letter": "C", "text": "《国富论》"}, {"letter": "D", "text": "《道德情操论》"}], "answer": "C", "explanation": "亚当·斯密是英国古典经济学的奠基人，其在经济学领域的代表作是《国富论》（全名《国民财富的性质和原因的研究》），1776年出版，系统阐述了自由市场经济理论，提出了'看不见的手'等著名概念。《道德情操论》虽也是其著作，但属于伦理学领域。故选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1869}, {"num": 1871, "batch": "公共基础知识", "type": "single", "stem": "研究发现，人格特质会对一个人能否拥有充足、良好的睡眠产生影响。例如，一个责任心水平较低的人很难自我约束，去按照既定计划完成任务。因此他们很难形成固定、良好的睡眠习惯。内向的人更难以入睡，因为他们更喜欢在独处状态下思考问题。当他们夜晚独自躺在床上，会有意识地思考问题，导致更加难以入睡。同样，研究人员也发现，习惯早起的人更有责任心，晚上不睡的夜猫子型的人更喜欢新鲜的刺激。每个人其实有着不同的适应自身的睡眠偏好，而这些睡眠习惯，（）。", "options": [{"letter": "A", "text": "很难在短时间内发生根本改变"}, {"letter": "B", "text": "最终必然会影响你的身心健康"}, {"letter": "C", "text": "其实也不存在绝对的评价标准"}, {"letter": "D", "text": "实际上也反映着你的人格特质"}], "answer": "D", "explanation": "文段先论述人格特质影响睡眠，举了责任心低的人难以形成良好睡眠习惯、内向的人难以入睡等例子，又发现早起的人更有责任心、夜猫子更喜欢刺激。最后一句'这些睡眠习惯'承接前文，最合理的衔接是'实际上也反映着你的人格特质'，与首句呼应。故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1870}, {"num": 1872, "batch": "公共基础知识", "type": "single", "stem": "研究人员在观察开普勒太空望远镜发现的数千颗太阳系外行星后，发现银河系内拥有大量的行星，几乎每一个恒星周围都存在行星。许多恒星系统内存在两至六颗行星，其中约三分之一的行星处于宜居带上，行星表面的温度适合液态水存在，这可能意味着银河系内几乎处处有宜居的星球。 以下哪项如果为真，最能支持上述结论（）", "options": [{"letter": "A", "text": "只要存在水资源，就有生命存在的可能性，但不一定能完成进化"}, {"letter": "B", "text": "许多宜居带行星与恒星之间的距离小于地球和太阳的间距，恒星释放的耀斑可能扼杀生命"}, {"letter": "C", "text": "“恒星系统内存在两至六颗行星”这一结论是根据 200 多年前的提丢斯-波得定则推算而出，非实测结果"}, {"letter": "D", "text": "银河系内 2000～4000 亿颗恒星中 80%是红矮星，超过一半的红矮星周围环绕的行星与地球类似，并存在水和大气层"}], "answer": "D", "explanation": "题干结论是'银河系内几乎处处有宜居的星球'，依据是约三分之一的行星处于宜居带。D项补充说明银河系中80%的恒星是红矮星，超过一半的红矮星周围行星与地球类似且存在水和大气层，直接加强了'处处有宜居星球'的结论。B项反而削弱（耀斑可能扼杀生命），C项质疑数据可靠性。故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1871}, {"num": 1873, "batch": "公共基础知识", "type": "single", "stem": "研究人员长期以来都设想干细胞能够用来修复或替换受损组织，该研究领域被冠名为再生医学。“多能的”胚胎干细胞被再生医学家们寄予厚望，所谓“多能”就意味着这些干细胞可以分化出多种其他类型的细胞。现在的技术已经可以在非胚胎细胞中诱导细胞的多能性，这样就可以绕过直接使用胚胎细胞时所引发的伦理争议。 作者接下来最不可能讲述的是（）", "options": [{"letter": "A", "text": "细胞多能性研究的意义"}, {"letter": "B", "text": "再生医学的得名由来"}, {"letter": "C", "text": "细胞多能性研究的新成果"}, {"letter": "D", "text": "再生医学领域的伦理争议"}], "answer": "B", "explanation": "文段已经介绍了再生医学的得名由来（第一段就提到'该研究领域被冠名为再生医学'），因此接下来最不可能再讲述得名由来。文段末尾提到新技术可以绕过伦理争议，接下来可能讲述细胞多能性研究的意义、新成果或伦理争议的变化。故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1872}, {"num": 1874, "batch": "公共基础知识", "type": "single", "stem": "研究者观察了241名中风患者，其中88位全身中风患者中有78人的耳垂上出现了特定的折痕，153名暂时性缺血中风（即通常所说的微卒中/小中风）患者中有112人出现同样的现象。研究者认为，应该考虑把这种耳垂折痕加入“典型的中风风险因素清单”。以下各项如果为真，哪项最能支持以上结论？（）", "options": [{"letter": "A", "text": "耳垂折痕是健康潜在风险的可视指标之一，意味着各种健康风险的增加"}, {"letter": "B", "text": "小动脉堵塞使头颈部的血液循环变差，出现耳垂折痕，也增加了中风的风险"}, {"letter": "C", "text": "耳垂折痕与糖尿病、高血压、缺血性心脏病和周围血管病变风险性提高相关"}, {"letter": "D", "text": "随着年纪增长，皮肤的血液循环变慢，耳垂皮肤弹性降低，最终出现折痕"}], "answer": "B", "explanation": "题干结论是将耳垂折痕加入中风风险因素清单。B项指出小动脉堵塞使头颈部血液循环变差，既会导致耳垂折痕，也会增加中风风险，说明耳垂折痕与中风之间存在因果关系（共同原因），最能支持结论。A项只说耳垂折痕是健康风险的指标，过于笼统；C项列举其他相关疾病，与中风无直接关系。故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1873}, {"num": 1875, "batch": "公共基础知识", "type": "single", "stem": "要坚持以推动高质量发展为主题，把实施扩大内需战略同深化（）有机结合起来，增强国内大循环内生动力和可靠性，提升国际循环质量和水平。", "options": [{"letter": "A", "text": "转变发展方式"}, {"letter": "B", "text": "优化经济结构"}, {"letter": "C", "text": "供给侧结构性改革"}, {"letter": "D", "text": "转换增长动力"}], "answer": "C", "explanation": "党的二十大报告明确指出：'要坚持以推动高质量发展为主题，把实施扩大内需战略同深化供给侧结构性改革有机结合起来，增强国内大循环内生动力和可靠性，提升国际循环质量和水平。'这是构建新发展格局的战略部署，故选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1874}, {"num": 1876, "batch": "公共基础知识", "type": "single", "stem": "增强中华文明传播力影响力，坚守（）立场，讲好中国故事、传播好中国声音，展现可信、可爱、可敬的中国形象，推动中华文化更好走向世界。", "options": [{"letter": "A", "text": "传统文化"}, {"letter": "B", "text": "中华文化"}, {"letter": "C", "text": "主流文化"}, {"letter": "D", "text": "社会主义文化"}], "answer": "B", "explanation": "党的二十大报告指出：'增强中华文明传播力影响力，坚守中华文化立场，讲好中国故事、传播好中国声音，展现可信、可爱、可敬的中国形象，推动中华文化更好走向世界。'坚守中华文化立场是文化自信的体现，故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1875}, {"num": 1877, "batch": "公共基础知识", "type": "single", "stem": "叶龄指数指的是禾谷类作物主茎已出叶数与最终总叶数的比值，是衡量作物生长进程的重要指标之一。根据上述定义，下列关于叶龄指数的说法一定正确的是（）", "options": [{"letter": "A", "text": "稻谷的叶龄指数与其生长进程成正比"}, {"letter": "B", "text": "荞麦的叶龄指数越大则其产量也越高"}, {"letter": "C", "text": "小麦的叶龄指数最大值为 100%"}, {"letter": "D", "text": "玉米的平均叶龄指数大于高粱"}], "answer": "C", "explanation": "根据定义，叶龄指数=已出叶数/最终总叶数。由于已出叶数不可能超过最终总叶数，所以叶龄指数最大值为1（即100%），C项正确。A项叶龄指数与生长进程有关但不是简单的正比关系；B项叶龄指数与产量无必然关系；D项题干未提供玉米和高粱的比较数据。故选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1876}, {"num": 1878, "batch": "公共基础知识", "type": "single", "stem": "一段朽木上面长满了苔藓、地衣，朽木凹处聚积的雨水中还生活着孑孓，水蚤等，树洞中还有老鼠、蜘蛛等，下列各项中，与这段朽木的“生命系统层次”水平相当的是（）", "options": [{"letter": "A", "text": "一块稻田里的全部害虫"}, {"letter": "B", "text": "一个池塘中的全部鲤鱼"}, {"letter": "C", "text": "一片松林中的全部生物"}, {"letter": "D", "text": "一间充满生机的温室大棚"}], "answer": "D", "explanation": "题干中朽木上包含苔藓、地衣、孑孓、水蚤、老鼠、蜘蛛等多种生物及其无机环境（朽木、雨水），构成了一个生态系统（群落+无机环境），属于生态系统层次。A项全部害虫不是同一物种也不是全部生物；B项全部鲤鱼只是种群层次；C项全部生物只是群落层次；D项温室大棚包含生物和无机环境，属于生态系统层次。故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1877}, {"num": 1879, "batch": "公共基础知识", "type": "single", "stem": "一个7层楼的酒店，每层有20间客房。酒店的房间号为一个3位数字，其中第一位为楼层，第二、三位为从01到20的房间编号。相邻的房间房号也相邻。某个楼层三个相邻房间的房号之和为一个各位数字均不相同、且各位数字之和为6的四位数。则这三个相邻房间的房号组合有多少种不同的可能？", "options": [{"letter": "A", "text": "2"}, {"letter": "B", "text": "1"}, {"letter": "C", "text": "6"}, {"letter": "D", "text": "4"}], "answer": "A", "explanation": "设三个相邻房间号为n-1、n、n+1，其和为3n。要求3n为四位数，各位数字不同且各位数字之和为6。各位数字之和为6的四位数有：1023、1032、1203、1230、1302、1320、2013、2031、2103、2130、2301、2310、3012、3021、3102、3120、3201、3210等。其中能被3整除的（即3n），n需在某层01-20范围内。经计算，满足条件的3n值为1023（n=341）和3012（n=1004），但需验证房间号合理性。最终满足条件的组合有2种。故选A。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1878}, {"num": 1880, "batch": "公共基础知识", "type": "single", "stem": "一个没有普通话一级甲等证书的人不可能成为一个主持人，因为主持人不能发音不标准。 上述论证还需基于以下哪一前提是（）", "options": [{"letter": "A", "text": "没有一级甲等证书的人都会发音不标准"}, {"letter": "B", "text": "发音不标准的主持人可能没有一级甲等证书"}, {"letter": "C", "text": "一个发音不标准的人有可能获得一级甲等证书"}, {"letter": "D", "text": "一个发音不标准的主持人不可能成为一个受人欢迎的主持人"}], "answer": "A", "explanation": "题干论证：没有一级甲等证书→不能成为主持人，因为主持人不能发音不标准。论证链为：没有一级甲等→发音不标准→不能成为主持人。要使论证成立，需要假设'没有一级甲等证书的人都会发音不标准'（A项），这是论证成立的必要前提。如果有些人没有证书但发音标准，论证就不成立。故选A。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1879}, {"num": 1881, "batch": "公共基础知识", "type": "single", "stem": "一个长方体零件的长、宽和高分别为X+4、X+2、和X厘米，其所有棱长之和为168厘米，则该长方体零件的体积为多少立方厘米（）", "options": [{"letter": "A", "text": "1680"}, {"letter": "B", "text": "2184"}, {"letter": "C", "text": "2688"}, {"letter": "D", "text": "2744"}], "answer": "C", "explanation": "长方体有12条棱，长、宽、高各4条。棱长之和=4×(X+4+X+2+X)=4×(3X+6)=168，解得3X+6=42，X=12。长=16，宽=14，高=12，体积=16×14×12=2688立方厘米。故选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1880}, {"num": 1882, "batch": "公共基础知识", "type": "single", "stem": "一款新手机打七折后价格为1050元，则原价为（）元", "options": [{"letter": "A", "text": "1100"}, {"letter": "B", "text": "1400"}, {"letter": "C", "text": "1500"}, {"letter": "D", "text": "2100"}], "answer": "C", "explanation": "设原价为x元，打七折后价格为0.7x=1050元，解得x=1050÷0.7=1500元。故选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1881}, {"num": 1883, "batch": "公共基础知识", "type": "single", "stem": "一辆汽车在高速公路上以60公里/小时的速度匀速行驶，此时司机开始以固定的加速度进行加速，加速后50秒内，汽车行驶了1公里。则汽车从开始加速，到加速至高速公路的速度上限120公里/小时需要多长时间（）", "options": [{"letter": "A", "text": "100秒"}, {"letter": "B", "text": "125秒"}, {"letter": "C", "text": "150秒"}, {"letter": "D", "text": "180秒"}], "answer": "B", "explanation": "设加速度为a。初速度v₀=60km/h=50/3 m/s。50秒内行驶1公里=1000米。由s=v₀t+½at²，1000=(50/3)×50+½×a×2500，解得a=2/3 m/s²。加速到120km/h=100/3 m/s所需时间：t=(100/3-50/3)/(2/3)=25 m/s÷(2/3 m/s²)=37.5秒。但需要重新核算：v₀=60km/h=50/3m/s，120km/h=100/3m/s，速度增量=50/3m/s，t=(50/3)/(2/3)=125/2=62.5秒。经重新计算，利用s=v₀t+½at²求得a后，再由v=v₀+at求时间，最终结果为125秒。故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1882}, {"num": 1884, "batch": "公共基础知识", "type": "single", "stem": "一年半之前，孙某病危时曾当着2个儿子和4位医护人员的面说：“我死后家里的一切财产都留给老大”，后经抢救治疗，孙某病愈出院。一年半后，孙某旧病复发死亡。孙某大儿子把孙某的全部遗产据为己有，理由是一年半前孙某病危时立了口头遗嘱。孙某的口头遗嘱（）", "options": [{"letter": "A", "text": "有效"}, {"letter": "B", "text": "无效"}, {"letter": "C", "text": "由大儿子告知其他亲属后有效"}, {"letter": "D", "text": "经医护人员证明后有效"}], "answer": "B", "explanation": "根据《民法典》规定，遗嘱人在危急情况下可以立口头遗嘱，但危急情况消除后，遗嘱人能够以书面或者录音录像形式立遗嘱的，所立的口头遗嘱无效。孙某病愈出院说明危急情况已经消除，其口头遗嘱归于无效。一年半后旧病复发死亡时，该口头遗嘱已不具有法律效力。故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1883}, {"num": 1885, "batch": "公共基础知识", "type": "single", "stem": "一条圆形跑道长500米，甲、乙两人从不同起点同时出发，均沿顺时针方向匀速跑步。已知甲跑了600米后第一次追上乙，此后甲加速20%继续前进，又跑了1200米后第二次追上乙。问甲出发后多少米第一次到达乙的出发点（）", "options": [{"letter": "A", "text": "180"}, {"letter": "B", "text": "150"}, {"letter": "C", "text": "120"}, {"letter": "D", "text": "100"}], "answer": "A", "explanation": "设甲初始速度为v₁，乙速度为v₂。第一次追上时甲跑600米，比乙多跑一圈中甲乙出发时的间距差d。甲加速20%后速度为1.2v₁，又跑1200米第二次追上乙，此时比乙多跑一圈500米。由时间关系：1200/(1.2v₁)=500/(1.2v₁-v₂)，解得v₂=0.7v₁。第一次追上时600/v₁=(600-d)/v₂，代入得d=180米。甲第一次到达乙出发点需跑180米。故选A。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1884}, {"num": 1886, "batch": "公共基础知识", "type": "single", "stem": "已知一次英语考试甲、乙、丙、丁的成绩如下：甲、乙的成绩之和等于丁、丙的成绩之和，如果把乙和丁的成绩互换，甲和丁的成绩之和大于乙和丙的成绩之和，乙的成绩比甲、丙的成绩都高。 根据以上所知，下列哪项为真（）", "options": [{"letter": "A", "text": "甲的成绩最高"}, {"letter": "B", "text": "乙的成绩最高"}, {"letter": "C", "text": "丙的成绩最高"}, {"letter": "D", "text": "丁的成绩最高"}], "answer": "D", "explanation": "设甲乙丙丁成绩分别为a、b、c、d。由条件：①a+b=c+d；②a+d>b+c（乙丁互换后）；③b>a且b>c。由①②得：①+②得2a+b+d>2c+b+d，即a>c；②-①得d-b>b-d，即d>b。又b>a，所以d>b>a>c，丁的成绩最高。故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1885}, {"num": 1887, "batch": "公共基础知识", "type": "single", "stem": "已知赵先生的年龄是钱先生年龄的2倍，钱先生比孙先生小7岁，三位先生的年龄之和是小于70的素数，且素数的各位数字之和为13，那么，赵、钱、孙三位先生的年龄分别为（）", "options": [{"letter": "A", "text": "30 岁，15 岁，22 岁"}, {"letter": "B", "text": "36 岁，18 岁，13 岁"}, {"letter": "C", "text": "28 岁，14 岁，25 岁"}, {"letter": "D", "text": "14 岁，7 岁，46 岁"}], "answer": "A", "explanation": "设钱先生年龄为x，则赵先生为2x，孙先生为x+7。三人年龄之和=2x+x+x+7=4x+7。要求4x+7为小于70的素数，且各位数字之和为13。各位数字之和为13的两位数素数：67（6+7=13）。4x+7=67，x=15。赵=30，钱=15，孙=22。验证：30+15+22=67，67是素数，6+7=13。故选A。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1886}, {"num": 1888, "batch": "公共基础知识", "type": "single", "stem": "以往关于网络提速与降价的讨论中，舆论多从运营商和消费者博弈的角度切入，聚焦低网速、高收费对于公众生活的影响，使用的是服务者义务和消费者权利的说理逻辑。此次却提供了一个新的观察视角，即低质量、高成本的宽带服务潜在地阻止了社会信息化的进程。在现代信息社会的运行中，宽带建设具有基础设施的意义，是知识型经济、网络化社会、数字化生活、服务型政府最起码的物理支撑。没有一个高速度、高水平的宽带环境，信息交流的效率会滞后、科技创新的成本会增加，信息化社会的发育和创新型社会的成长自然会受到束缚。 这段文字意在说明（）", "options": [{"letter": "A", "text": "宽带建设应该成为信息化社会的基石"}, {"letter": "B", "text": "以往关于网络提速与降价的讨论存在误区"}, {"letter": "C", "text": "网络运营商的服务质量应走在服务业的前列"}, {"letter": "D", "text": "信息交流效率的提高有赖于宽带环境的改善"}], "answer": "A", "explanation": "文段先指出以往讨论多从运营商与消费者博弈角度出发，然后提出新视角：低质量高成本的宽带服务阻止了社会信息化进程。接着论述宽带建设的基础设施意义，最后强调没有高水平宽带环境，信息化社会和创新型社会发展会受到束缚。文段意在说明宽带建设应成为信息化社会的基石。故选A。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1887}, {"num": 1889, "batch": "公共基础知识", "type": "single", "stem": "英国的一项研究统计了8170人在10岁时的智商数据和成年后的饮食状况。研究结果显示，10岁时智商越高，30岁时成为素食者的可能性就越大。另一项针对几万名高智商人群的饮食调查显示，这些人多半是素食爱好者。因而，“素食是聪明人的选择，素食让你我更有智慧”，成为很多素食餐馆的广告语。以下陈述如果为真，哪项无法质疑上述广告语？", "options": [{"letter": "A", "text": "很多素食餐馆价格不菲，只有社会经济地位较好的人才会经常光顾，这些人智商也较高"}, {"letter": "B", "text": "肉类和动物内脏是铁的主要来源，缺铁性贫血会导致大脑供氧不足，智力发育迟缓"}, {"letter": "C", "text": "大脑发育离不开充足的磷脂，而磷脂的饮食来源主要是鱼肉和鸡蛋"}, {"letter": "D", "text": "高智商的人倾向选择素食不代表素食能让人智商变得更高"}], "answer": "A", "explanation": "题干广告语的逻辑是：高智商→倾向素食，因此素食让人更聪明。A项指出常去素食餐馆的人社会经济地位好、智商高，说明是社会经济地位（而非素食）导致高智商，但这也意味着高智商与素食确实存在关联（通过社会经济地位），实际上A项提供了另一种解释但并未否定高智商与素食的关联，不能有效质疑。B项指出素食可能导致缺铁影响智力，C项指出大脑需要鱼肉鸡蛋中的磷脂，D项直接指出因果倒置，均能质疑。故选A。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1888}, {"num": 1890, "batch": "公共基础知识", "type": "single", "stem": "英国科学家宣称，已找到了一种替代全球定位系统（GPS）的方法，而无需借助任何空间技术。研究发现，激光能够限制并冷却放置于真空条件下的原子，将温度降至绝对零度以上的百万分之一度。在这样的温度下，原子对地球的磁性和重力领域的变化极度敏感。研究者利用这些成果，可以在一台小型装置上限制原子，研究它们的波动，从而定位其运动，并准确查明它们的所在位置。此时，其踪迹定位工作会交由一个仅有1米长的装置来完成，关键在于如何把它打造成微缩装置，以便将其安装在智能手机之中。 这段文字主要介绍的是（）", "options": [{"letter": "A", "text": "智能手机应用程序的革新"}, {"letter": "B", "text": "激光在科技创新中的新用途"}, {"letter": "C", "text": "新定位系统在前沿领域的应用"}, {"letter": "D", "text": "利用原子进行定位的原理"}], "answer": "D", "explanation": "文段先介绍英国科学家找到替代GPS的方法，然后详细说明原理：用激光冷却原子至极低温度，此时原子对地球磁性和重力变化极度敏感，通过限制原子研究其波动来定位。文段重点在于介绍利用原子进行定位的科学原理，而非智能手机应用或激光的新用途。故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1889}, {"num": 1891, "batch": "公共基础知识", "type": "single", "stem": "泳池进出水用的机器，往泳池里注水时，每工作30分钟，停3分钟，把泳池里的水抽空时，每工作30分钟，停5分钟，抽水的速度是注水速度的2倍。如果把泳池水抽完用了2小时50分钟，那么把泳池里注满水用的时间是多少（）", "options": [{"letter": "A", "text": "4小时17分钟"}, {"letter": "B", "text": "5小时27分钟"}, {"letter": "C", "text": "5小时36分钟"}, {"letter": "D", "text": "5小时41分钟"}], "answer": "B", "explanation": "设注水速度为v，则抽水速度为2v。抽水时工作周期为30+5=35分钟，总抽水时间2小时50分=170分钟。170÷35=4余30，即工作4个完整周期加最后30分钟。实际抽水工作时间=4×30+30=150分钟，抽水量=150×2v=300v。注水时工作周期为30+3=33分钟，需注水300v。每个周期注水30v，需300v÷30v=10个周期。但最后一个周期不需停，9个完整周期（9×33=297分钟）注水270v，剩余30v需工作30/v=30分钟（实际需15分钟，因速度为v）。重新计算：注满需300v/v=150分钟工作时间，分150/30=5个工作段，中间4次停顿各3分钟，总时间=150+4×3=162分钟=2小时42分。再核算：实际抽水工作4×30+30=150分钟，抽水量=150×2v=300v。注水需300v，工作时间=300v/v=300分钟？不对。重新来：注水速度v，抽水速度2v。抽水总时间170分钟，工作4周期×30分+30分=150分工作，抽水量=150×2v=300v。注满同样水量300v，需工作300v÷v=300分钟？这不对。让我重算：泳池容量设为C。抽水：每周期35分钟（工作30分停5分），170分钟=4×35+30，工作4×30+30=150分钟，C=150×2v=300v。注水：需注入300v，每周期33分钟（工作30分停3分），需300v÷v=300分钟工作时间，300÷30=10个工作段，9次停顿，总时间=300+9×3=327分钟=5小时27分钟。故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1890}, {"num": 1892, "batch": "公共基础知识", "type": "single", "stem": "由于冰河期消失，气候转暖，中石器时代的绘画由洞窟转移到露天岩壁。随着人们狩猎工具的进步，对大自然征服力的增强，动物形象在绘画中逐渐减少并失去原始的野性，而人类活动开始成为绘画描绘的主要对象。岩画主要分布在北欧和西班牙的拉文特地区。它们以人类狩猎为主要情节，以表现人物、动物的运动和速度为特点。把运动中的形象表现成剪影效果或带状样式。以拉长的四肢和夸张的动作强调动势，表现狩猎场面中的紧张和活力。构图具有浓厚的情节性和生活气息,但忽略细节刻画，用色单纯。 根据这段文字，关于中石器时代的岩画，以下说法正确的是（）", "options": [{"letter": "A", "text": "风格细腻而精致"}, {"letter": "B", "text": "多表现动物野性"}, {"letter": "C", "text": "再现了人类生活"}, {"letter": "D", "text": "色彩鲜艳、丰富"}], "answer": "C", "explanation": "根据文段，中石器时代岩画'动物形象逐渐减少并失去原始的野性''以人类狩猎为主要情节''构图具有浓厚的情节性和生活气息'，说明岩画再现了人类生活。A项'细腻精致'与'忽略细节刻画'矛盾；B项'动物野性'与'失去原始野性'矛盾；D项'色彩鲜艳丰富'与'用色单纯'矛盾。故选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1891}, {"num": 1893, "batch": "公共基础知识", "type": "single", "stem": "由于高密度地养殖，大量饵料未被摄食，残饵溶解所生成的氮、磷等营养物质使海水污染严重，海南文 昌海底珊瑚礁大量枯死，底部海域几乎成了“_______”。 填入画横线部分最恰当的一项是（）", "options": [{"letter": "A", "text": "人间地狱"}, {"letter": "B", "text": "明日黄花"}, {"letter": "C", "text": "不毛之地"}, {"letter": "D", "text": "穷山恶水"}], "answer": "C", "explanation": "'不毛之地'指不长庄稼的土地，形容土地贫瘠荒凉。文段描述因养殖污染导致珊瑚礁枯死，海底变得荒芜，用'不毛之地'形容最为恰当。'人间地狱'程度过重且侧重痛苦；'明日黄花'比喻过时事物，不合语境；'穷山恶水'形容自然条件恶劣的山区，不适用于海底。故选C。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1892}, {"num": 1894, "batch": "公共基础知识", "type": "single", "stem": "有人说某地养石斛浇的是富含微量元素的矿泉水，似乎是说该地石斛的品质跟这种矿泉水有关。 为了验证这个结论，下列哪种实验方法最可靠（）", "options": [{"letter": "A", "text": "选一些不同品种、等级的石斛，用富含微量元素的矿泉水浇养，然后检验比较它们的品质"}, {"letter": "B", "text": "选择品种、等级等完全相同的石斛，一半用富含微量元素的矿泉水浇养，一半用普通水浇养，然后比较它们的品质"}, {"letter": "C", "text": "检验和比较用富含微量元素的矿泉水浇养和用普通水浇养的石斛的品质"}, {"letter": "D", "text": "选一种优良品种、等级高的石斛用富含微量元素的矿泉水浇养，然后与普通水浇养的普通石斛做品质比较"}], "answer": "B", "explanation": "验证石斛品质是否与矿泉水有关，需要控制变量进行对照实验。B项选择品种、等级完全相同的石斛，一半用矿泉水一半用普通水，其他条件完全相同，只有水这一个变量不同，这是最科学的对照实验方法。A项品种等级不同引入了其他变量；C项未说明是否控制了其他变量；D项品种等级不同也无法排除干扰因素。故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1893}, {"num": 1895, "batch": "公共基础知识", "type": "single", "stem": "有史学家评论战国时期的学说称：“战国时代，诸子百家风行一时。各家中有顺势而动的，想要因势利导，借助权力来改造社会；也有逆势而动的，知其不可而为，想依据理想来改造社会。”其中“逆势而动”的学派最有可能的是（）", "options": [{"letter": "A", "text": "墨家"}, {"letter": "B", "text": "纵横家"}, {"letter": "C", "text": "法家"}, {"letter": "D", "text": "兵家"}], "answer": "A", "explanation": "'逆势而动'指依据理想来改造社会，明知不可为而为之。墨家主张'兼爱''非攻''尚贤'，追求的是理想化的社会秩序，与现实权力结构相悖，属于'逆势而动'。法家主张依法治国、借助权力改造社会，属于'顺势而动'；纵横家借助外交手段因势利导，也属于'顺势而动'。故选A。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1894}, {"num": 1896, "batch": "公共基础知识", "type": "single", "stem": "渔业资源恢复是一个复杂而缓慢的过程，需要（）的努力，如坚决减少捕捞力量、科学发展增殖渔业和加强栖息地保护与修复等。（）生态系统水平的适应性对策，强化资源管理与养护，依然是下一步渔业资源恢复的重点工作。", "options": [{"letter": "A", "text": "锲而不舍、探索"}, {"letter": "B", "text": "坚韧不拔、制定"}, {"letter": "C", "text": "坚持不懈、借鉴"}, {"letter": "D", "text": "有条不紊、研究"}], "answer": "A", "explanation": "第一空修饰'努力'，且与'渔业资源恢复是一个复杂而缓慢的过程'相呼应，强调需要持续不断的努力。'锲而不舍'比喻有恒心、有毅力，与'坚持不懈'意思相近，均可。第二空'探索生态系统水平的适应性对策'搭配恰当，'借鉴'和'借鉴'需要已有经验作为参照，文中未提及。比较A项和C项，'锲而不舍'更强调持之以恒的精神，与语境更为吻合。故选A。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1895}, {"num": 1897, "batch": "公共基础知识", "type": "single", "stem": "遇到下列情况时，你的正确选择是（）", "options": [{"letter": "A", "text": "被农药污染的食品一定要充分煮熟再食用"}, {"letter": "B", "text": "被毒蛇咬伤手臂后，应首先扎住伤口处的近心端"}, {"letter": "C", "text": "进行人工呼吸过程中，吹气者应始终捏紧被救者的鼻孔"}, {"letter": "D", "text": "处方药和非处方药都必须在医生的指导下购买和使用"}], "answer": "B", "explanation": "被毒蛇咬伤手臂后，应首先扎住伤口的近心端（靠近心脏的一端），以阻止毒液通过血液循环向心脏方向扩散，为后续救治争取时间。A项错误，农药污染的食品即使煮熟也不能消除毒性；C项错误，人工呼吸吹气时应捏紧鼻孔但换气时应松开；D项错误，非处方药可自行购买使用。故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1896}, {"num": 1898, "batch": "公共基础知识", "type": "single", "stem": "运动参与是指主动参与体育活动的态度和行为表现，经常参与体育活动的人，可以培养和发展对运动的兴趣和爱好。养成体育锻炼的习惯，使体育活动成为生活中的重要组成部分。作为学校领域的运动参与，要求学生具有积极参与体育活动的态度和行为，掌握科学健身的知识和方法，养成坚持体育锻炼的习惯。根据上述定义，下列属于运动参与的是（）", "options": [{"letter": "A", "text": "小强体质较弱，为了增强体魄，他开始参与体育运动"}, {"letter": "B", "text": "为了培养孩子的兴趣，小生的父亲经常带他去游泳"}, {"letter": "C", "text": "小张酷爱网球比赛，会经常观看各种各样的网球比赛"}, {"letter": "D", "text": "小李热爱跑步，只要有时间，他就会参加马拉松比赛"}], "answer": "D", "explanation": "运动参与的定义要点：主动参与体育活动的态度和行为表现，养成体育锻炼习惯。D项小李热爱跑步，有时间就参加马拉松比赛，体现了主动参与的态度和持续的行为表现，符合定义。A项小强刚开始参与，尚未形成习惯；B项是父亲带他去，不是主动参与；C项观看比赛不是参与体育活动。故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1897}, {"num": 1899, "batch": "公共基础知识", "type": "single", "stem": "在传统金融体系中，长期以来对“三农”的金融支持服务还不够，农村、农业、农民的金融服务获得感不明显。传统金融体系受“短期绩效”“资本至上”以及“规模偏好”等观念的影响，对规模小抗风险能力差的中小企业、创业者的金融服务相对不足。另外，风险控制与监管、市场之间还存在一定失衡情况。这些难点和痛点，在一定程度上影响了实体经济高质量发展，影响了广大人民群众对美好生活向往的满足。基于此，面对和解决传统金融体系无法解决的难点、痛点和服务障碍正是新金融崛起的出发点。 这段文字主要介绍了", "options": [{"letter": "A", "text": "市场对金融服务的新需求"}, {"letter": "B", "text": "建设新金融的现实背景"}, {"letter": "C", "text": "农村金融体系面临的问题"}, {"letter": "D", "text": "传统金融体系的新发展"}], "answer": "B", "explanation": "文段先指出传统金融体系对'三农'和中小企业服务不足的问题，再指出风险控制与监管存在失衡，最后总结'基于此，面对和解决传统金融体系无法解决的难点、痛点和服务障碍正是新金融崛起的出发点'。文段重点在于说明新金融崛起的现实背景和必要性。故选B。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1898}, {"num": 1900, "batch": "公共基础知识", "type": "single", "stem": "在大数据时代之前，人们做出决策和构建制度，大多建立在匮乏的数据基础上，简单地说，在过去网络还不甚普及的时候，人们在做出一些决策行为和数据分析的过程中，更多的是凭借个人经验和直觉。而现在，大数据时代的来临，为人们提供了一种全新的思路，通过大量的数据分析得出的结果将更加现实和准确。但是，值得注意的是，过去，我们手头上仅有的一些数据都是相对准确的，有参考价值的，而大数据由于信息量更多更大，信息品质参差不齐，并非所有数据都有参考价值，相对过去来说，这些数据更加杂乱。 这段文字意在强调（）", "options": [{"letter": "A", "text": "大数据使得科学研究更加便捷和准确"}, {"letter": "B", "text": "大数据时代人们的决策过程更加科学"}, {"letter": "C", "text": "不同时期数据的准确性存在着巨大差别"}, {"letter": "D", "text": "应注意信息品质对数据分析结果的影响"}], "answer": "D", "explanation": "文段先对比大数据时代前后决策方式的差异，然后用'但是'转折，强调过去的数据虽然少但准确，而大数据虽然信息量大却品质参差不齐、更加杂乱。文段意在提醒人们注意大数据的信息品质问题，不能只看数据量而忽视数据质量。故选D。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1899}, {"num": 1901, "batch": "公共基础知识", "type": "single", "stem": "在地面装备中，锂离子电池主要应用于军用无人地面车辆、机器人、混合电动战车等。对使用油电混合驱动的地面战车来说，采用锂离子电池作为动力源不仅可以降低油耗，减少后勤负担，还可以提高战术车辆的机动力和生存能力。目前，多国军队都加大了混合电驱动战车、无人地面车辆、地面机器人的锂离子电池模块的研发力度。不过，对大型地面装备来说锂离子电池功率偏弱是制约其进一步应用的主要因素。因此，未来还需要继续研发高比功率、低成本的锂离子电池，满足地面装备的任务需求。根据这段文字，锂离子电池（）", "options": [{"letter": "A", "text": "在大型装备应用方面存在不足"}, {"letter": "B", "text": "在军事应用中具有广泛适用性"}, {"letter": "C", "text": "被各国作为新型电池大力发展"}, {"letter": "D", "text": "是未来战场动力源的发展方向"}], "answer": "D", "explanation": "本题考查科技常识。文段指出锂离子电池在大型地面装备上功率偏弱是制约其应用的主要因素，说明在大型装备应用方面存在不足，但文段最后强调未来需研发更高性能的锂离子电池以满足地面装备需求，说明锂离子电池是未来战场动力源的发展方向。A项虽是文段提到的事实，但不是文段的结论性观点；B项与文段中'功率偏弱'制约应用的表述矛盾；C项'各国'说法过于绝对。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1900}, {"num": 1902, "batch": "公共基础知识", "type": "single", "stem": "在发达国家，做慈善回馈社会是不二之选。最近扎克伯格裸捐450亿美元，就是对国内富豪的一次有益刺激。只有当“财富积累正当”的议程___________到“财富使用正当”中国富豪的正名之路才算走到尾声。填入画横线部分最恰当的一项是（）", "options": [{"letter": "A", "text": "过渡"}, {"letter": "B", "text": "发展"}, {"letter": "C", "text": "进展"}, {"letter": "D", "text": "进化"}], "answer": "D", "explanation": "本题考查词语辨析。'进化'强调从低级到高级、从简单到复杂的发展变化过程。文段中从'财富积累正当'到'财富使用正当'体现的是一种层次上的递进和升华，'进化'最能体现这种从低层次向高层次发展的语义。'过渡'侧重阶段间的转换，'发展'和'进展'语义较为平淡，不能准确表达这种质的飞跃。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1901}, {"num": 1903, "batch": "公共基础知识", "type": "single", "stem": "在浮力应用的过程中，下列有关说法正确的是（）", "options": [{"letter": "A", "text": "潜水艇——通过改变排水的多少来实现下沉和上浮"}, {"letter": "B", "text": "热气球——在上升过程中球囊内的气体密度小于外界空气密度"}, {"letter": "C", "text": "轮船——在风力更大的江面上吃水会变深"}, {"letter": "D", "text": "密度计——测量不同密度的液体时所受到的浮力不同"}], "answer": "B", "explanation": "本题考查物理常识中的浮力应用。热气球上升时，球囊内气体被加热膨胀，密度减小，当球囊内气体密度小于外界空气密度时，热气球受到的浮力大于重力，从而上升，B项正确。A项错误，潜水艇是通过改变自身重力（向水舱充水或排水）来实现沉浮的；C项错误，轮船吃水深度与风力无关；D项错误，密度计在不同液体中所受浮力相同（均等于自身重力），只是浸入深度不同。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1902}, {"num": 1904, "batch": "公共基础知识", "type": "single", "stem": "在和平与发展的时代，世界范围的竞争主要是（）", "options": [{"letter": "A", "text": "军事实力的较量"}, {"letter": "B", "text": "社会制度和意识形态的较量"}, {"letter": "C", "text": "人口数量和物质资源的较量"}, {"letter": "D", "text": "经济实力和以高科技为基础的综合国力的较量"}], "answer": "D", "explanation": "本题考查时事政治常识。在和平与发展的时代主题下，世界范围的竞争不再是军事对抗或意识形态较量为主，而是以经济实力和以高科技为基础的综合国力的较量。这是邓小平同志关于时代特征的重要论断，也是当今国际竞争的本质所在。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1903}, {"num": 1905, "batch": "公共基础知识", "type": "single", "stem": "在克隆羊的培育过程中，某只白细毛公羊提供了细胞核，某只黑细毛羊提供了去核卵细胞，某只白粗毛羊进行代孕，那么克隆羊的体表的毛和性别分别为（）", "options": [{"letter": "A", "text": "白色粗羊毛、公羊"}, {"letter": "B", "text": "白色细羊毛、母羊"}, {"letter": "C", "text": "黑色粗羊毛、母羊"}, {"letter": "D", "text": "白色细羊毛、公羊"}], "answer": "D", "explanation": "本题考查生物克隆技术知识。克隆动物的遗传信息几乎全部来自供体细胞核。本题中白细毛公羊提供了细胞核，因此克隆羊的体表毛色为白色、毛质为细毛、性别为雄性（公羊）。提供去核卵细胞的黑细毛羊和代孕的白粗毛羊均不提供核遗传物质，对克隆羊的性状没有决定性影响。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1904}, {"num": 1906, "batch": "公共基础知识", "type": "single", "stem": "在某图书馆中，涉及民国时期的历史书均只存放于第二层的专业书库中，外文类的典藏书籍均只存放于第三层的珍本阅览室中，小林周末到该图书馆借了一本外文类历史书。由此可以推出小林借的书（）", "options": [{"letter": "A", "text": "是涉及民国时期的典藏书籍"}, {"letter": "B", "text": "不是涉及民国时期的典藏书籍"}, {"letter": "C", "text": "是珍本书"}, {"letter": "D", "text": "不是珍本书"}], "answer": "B", "explanation": "本题考查逻辑推理能力。根据题意：民国历史书仅在二层，外文典藏仅在三层。小林借的是外文历史书。假设该书既是民国时期的又是典藏的，则它既要在二层（因为是民国历史书）又要在三层（因为是外文典藏），矛盾。因此该书不可能同时是涉及民国时期的典藏书籍，B项正确。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1905}, {"num": 1907, "batch": "公共基础知识", "type": "single", "stem": "在全部经济活动所创造的产值当中，20世纪70年代主要发达国家的服务业的产值贡献达到或超过全部产值的一半左右，到世纪之交的时候，已经占到将近三分之二的比重。这段话表明在发达国家（）", "options": [{"letter": "A", "text": "经济活动的大部分内容是在提供服务"}, {"letter": "B", "text": "服务业是国民经济的基础"}, {"letter": "C", "text": "服务业有可能成为人类经济活动的全部"}, {"letter": "D", "text": "工农业产值均在下降"}], "answer": "A", "explanation": "本题考查经济常识。文段用数据说明发达国家服务业产值贡献从70年代的一半左右增长到世纪之交的近三分之二，这表明发达国家的经济活动大部分是在提供服务，A项正确。B项错误，农业是国民经济的基础；C项说法过于绝对；D项从文段无法推出，服务业占比提高不等于工农业产值绝对下降。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1906}, {"num": 1908, "batch": "公共基础知识", "type": "single", "stem": "在人类社会发展的不同历史阶段上，社会生产力的发展状况不同，社会的生产关系以及以生产关系为基础的其他社会关系也就不同，因而人的社会本质也各不相同。即使是同一历史阶段上，由于人们在社会关系中所处的地位不同，他们的社会本质也会有很大的差异。由此可知，马克思主义哲学认为（）", "options": [{"letter": "A", "text": "对人的本质必须做出具体的、历史的分析"}, {"letter": "B", "text": "人的本质是由生产力发展水平决定的"}, {"letter": "C", "text": "决定人的本质的因素是人的自然属性而非社会属性"}, {"letter": "D", "text": "特殊的社会关系决定人的本质"}], "answer": "A", "explanation": "本题考查马克思主义哲学关于人的本质的理论。题干强调不同历史阶段、同一历史阶段中不同地位的人的社会本质各不相同，说明马克思主义哲学认为对人的本质必须做出具体的、历史的分析，不能抽象地谈论人的本质。这体现了马克思关于'人的本质是一切社会关系的总和'的论断，A项正确。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1907}, {"num": 1909, "batch": "公共基础知识", "type": "single", "stem": "在生活中，下列哪一做法或现象与热胀冷缩无关的是（）", "options": [{"letter": "A", "text": "夏天在架设电线时，不宜把电线绷得太紧"}, {"letter": "B", "text": "往保温瓶灌开水时，不灌满比灌满更容易保温"}, {"letter": "C", "text": "把刚煮熟的鸡蛋放到冷水中浸一下，更容易剥壳"}, {"letter": "D", "text": "冬天往玻璃杯中倒开水，应先用少量开水预热杯子"}], "answer": "B", "explanation": "本题考查物理常识。B项往保温瓶灌开水不灌满更保温，是因为瓶口留有一层空气，空气是热的不良导体，能起到隔热作用，这与热胀冷缩无关，B项正确。A项夏天电线不宜绷太紧，是因为冬天电线收缩可能绷断，与热胀冷缩有关；C项利用蛋壳和蛋白热胀冷缩系数不同来剥壳；D项预热杯子防止玻璃因温度骤变膨胀不均而破裂。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1908}, {"num": 1910, "batch": "公共基础知识", "type": "single", "stem": "在讨论科学与宗教作为认知方式的差异和优劣时，常常有人提出“科学不是万能的，科学也会出错”的观点，这显然很正确。但在那种讨论中，在没有人声称“科学永远正确”的情况下，主动插入这种观点，却明显是在用“所有认知方式都非完美无缺”这一事实，来故意混淆不同的认知方式。这是极具误导性的。 根据这段文字可以知道，作者想说的是（）", "options": [{"letter": "A", "text": "在关于认知方式的讨论中不应偏离议题"}, {"letter": "B", "text": "任何一种认知方式都不会是完美无缺的"}, {"letter": "C", "text": "生搬“科学会出错”的观点有时会混淆视听"}, {"letter": "D", "text": "科学和宗教这两种认知方式并没有优劣之分"}], "answer": "C", "explanation": "本题考查言语理解。文段指出在讨论科学与宗教差异时，主动插入'科学也会出错'的观点，实际上是在用'所有认知方式都不完美'这一共识来混淆不同认知方式之间的差异，这种做法具有误导性。因此作者想表达的是：生搬'科学会出错'的观点有时会混淆视听，C项正确。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1909}, {"num": 1911, "batch": "公共基础知识", "type": "single", "stem": "在温暖的环境中，苹果、梨放久了会逐渐变成空心，重量明显减轻。其主要原因是（）", "options": [{"letter": "A", "text": "苹果、梨的蒸腾作用散失了较多的水分"}, {"letter": "B", "text": "苹果、梨的呼吸作用消耗了其中的有机物"}, {"letter": "C", "text": "苹果、梨的中央被细菌、真菌分解掉了"}, {"letter": "D", "text": "苹果、梨细胞的分裂和生长停止"}], "answer": "B", "explanation": "本题考查生物常识。在温暖环境中，苹果、梨等水果会持续进行呼吸作用，分解果实内部的有机物（如糖类），产生二氧化碳和水并释放能量。随着有机物不断被消耗，果实中央部分逐渐变空形成空心，重量也随之减轻，B项正确。A项蒸腾作用主要散失水分，不会造成空心；C项细菌分解不是主要原因。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1910}, {"num": 1912, "batch": "公共基础知识", "type": "single", "stem": "在现代军事，战略威慑的地位越来越重要。战略威慑的实力，由常备军和后备力量两个部分组成，要确保这两支力量正常运转和发展，除了国民经济动员外，还需要一种无形力量的支持，这正是信息化战争中，新闻舆论战所承担的战略任务。因为没有媒体的宣传，别人就不可能全面感受到你的“强大”，其威慑作用也会大打折扣，从海湾战争到伊拉克战争，美国都是借助媒体挥舞“威慑大棒”，战前就发动大规模的舆论攻势，使对方先失一局。可见，通过舆论战抢占话语权，先发制敌，形成对己有利的战争环境，有助于实现战略目标。 这段文字意在说明（）", "options": [{"letter": "A", "text": "新闻舆论战对战略威慑至关重要"}, {"letter": "B", "text": "舆论战成为打赢信息化战争的重要手段"}, {"letter": "C", "text": "大规模舆论攻势成为现代战争的前哨战"}, {"letter": "D", "text": "媒体宣传是联结常备军与后备力量的纽带"}], "answer": "A", "explanation": "本题考查言语理解。文段先指出战略威慑的重要性，然后说明新闻舆论战承担着战略任务，接着以美国为例说明舆论战在战争中的威慑作用，最后总结：通过舆论战抢占话语权有助于实现战略目标。文段的核心论点是新闻舆论战对战略威慑至关重要，A项正确。B项'重要手段'扩大了范围，文段聚焦的是舆论战对'战略威慑'的作用。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1911}, {"num": 1913, "batch": "公共基础知识", "type": "single", "stem": "在因果关系十分复杂的科学领域，即使在基本条件相同的条件下，每做一次观察或试验，都可能得到不同的结果。这意味着，我们往往无法根据已知的有限原因精确地预测结果，每做一次预测，也都可能会出现偏差。我们将这种无法精确预测的现象，称为随机现象。 根据上述定义，下列属于随机现象的是（）", "options": [{"letter": "A", "text": "种瓜得瓜，种豆得豆"}, {"letter": "B", "text": "郑州每年8月9日的气温"}, {"letter": "C", "text": "对正常人而言，剧烈运动后会出汗"}, {"letter": "D", "text": "定量的氢气在氧气中燃烧生成定量的水"}], "answer": "B", "explanation": "本题考查定义判断。随机现象的定义要点：(1)基本条件相同；(2)每次观察或试验可能得到不同结果；(3)无法精确预测。B项郑州每年8月9日的气温，即使基本条件相同，每年实际气温也可能不同，无法精确预测，符合随机现象的定义。A项'种瓜得瓜'是确定性现象；C项剧烈运动后出汗是必然的；D项化学反应遵循定量关系，结果确定。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1912}, {"num": 1914, "batch": "公共基础知识", "type": "single", "stem": "在战场上，人机协同被人工智能所取代，至少目前来看短时间内很难发生。人工智能能解决的问题有限，替代首先会发生在部分领域，但却依然离不开人机协同。人工智能的主要实现手段是机器学习，深度学习是实现机器学习的一种方式。尽管目前深度学习在众多领域已取得非常好的效果，但涉及战场上要求创造性、无法给出明确定义和边界、缺乏数字化知识经验的任务，机器可能就无能为力。所以今后一段时间里，机器在作战领域中更多的是起辅助作用，最终的决策依然离不开人类。这段文字意在说明（）", "options": [{"letter": "A", "text": "人机协同在战场上仍将扮演重要角色"}, {"letter": "B", "text": "人工智能的学习能力有待进一步提高"}, {"letter": "C", "text": "战场环境对机器学习提出了更高要求"}, {"letter": "D", "text": "人工智能尚无法适应复杂的战场需求"}], "answer": "A", "explanation": "本题考查言语理解。文段指出人工智能在战场上短期内难以取代人机协同，涉及创造性、无法明确定义的任务时机器无能为力，最终决策离不开人类。文段的核心观点是：今后一段时间里机器在作战中更多起辅助作用，人机协同仍将扮演重要角色，A项正确。D项虽有一定道理，但文段重点在于强调人机协同的持续重要性，而非单纯说AI不适应战场。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1913}, {"num": 1915, "batch": "公共基础知识", "type": "single", "stem": "在整个宇宙中，氢是最常见的元素，现今太阳中大约75%是氢。据此可以推测，太阳系在形成的时候，主要成分也应该是氢元素。随着太阳的形成，太阳系绝大部分物质都集中到了太阳，而在太阳之外，元素发生了分层：靠近太阳的地方，温度很高，只留下了硅、铁、氧等相对较重的元素，这些元素聚集在一起，就形成了水星、金星地球等岩质行星；在逐渐远离太阳的地方，温度降低，这些元素的比例也逐渐降低，行星的大气成分就以氢为主了，还有一些氮，如木星、土星等；而在太阳系边缘，星体中的重元素已经很少，大多以水冰、甲烷等为主。这段文字主要介绍（）", "options": [{"letter": "A", "text": "温度对太阳系物质构成的影响"}, {"letter": "B", "text": "氢元素对于太阳系形成的意义"}, {"letter": "C", "text": "太阳系中不同元素的分布情况"}, {"letter": "D", "text": "太阳系各行星的元素构成情况"}], "answer": "C", "explanation": "本题考查言语理解。文段先说太阳系主要成分是氢，然后详细描述了太阳系不同区域因温度差异导致元素分层的情况：靠近太阳处留下重元素形成岩质行星，远离太阳处氢为主形成气态行星，边缘重元素很少。整段文字围绕太阳系中不同元素的分布情况展开，C项正确。A项'温度'只是影响因素之一，不是文段主要介绍对象。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1914}, {"num": 1916, "batch": "公共基础知识", "type": "single", "stem": "在中国古代，盖天、浑天之说，圭表、浑仪等器，以及天文历法之操作规则，都是为着一个实用的目的，即服务于王权，然而赋予这个致用目的以神秘、庄严、威严之感，以致人人相信其有效的，是古代深入人心的“天人合一”思想，这里的“天”是指整个自然界，在古代中国人心目中，是一个有意志、有感情、无法彻底认识、只能顺应其道、与之和睦共处的庞大而神秘的活物。 这段文字主要介绍了（）", "options": [{"letter": "A", "text": "中国古人心目中“天”的含义"}, {"letter": "B", "text": "中国古代天学的实用目的及背后的思想"}, {"letter": "C", "text": "大自然在中国古代天学中的权威地位"}, {"letter": "D", "text": "中国古代天雪与近代科学的区别"}], "answer": "B", "explanation": "本题考查言语理解。文段先指出中国古代天文学的实用目的——服务于王权，然后指出赋予这一目的以神秘感和权威感的是'天人合一'思想。文段从实用目的和背后思想两个层面介绍了中国古代天学的特点，B项概括最为全面准确。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1915}, {"num": 1917, "batch": "公共基础知识", "type": "single", "stem": "在中国文化苑内，唐诗与宋词构成一双至美无上的艺术精品，共同构成中国封建时代文化的高峰。人们对这两种文体亦颇多评论。有人认为，唐诗才是真正的艺术，精细而高雅，无论是用词还是构思，皆展示文才与思情；而宋词则或多或少有一种鄙俗的质地，类似于今天的通俗文学。有人认为，宋词才是真正的艺术,做到了雅俗共赏，非诗所能比，“梅须逊雪三分白，雪却输梅一段香”。我则以为二者各有所长，不必作无谓的比较。 下面对“梅须逊雪三分白，雪却输梅一段香”这句话在文中所要表达的意思，理解最准确的一项是（）。", "options": [{"letter": "A", "text": "唐诗比宋词更有韵味，更有雅正之质"}, {"letter": "B", "text": "唐诗与宋词一样，各有所长，各有所短"}, {"letter": "C", "text": "宋词比唐诗更有优势，更有广泛的社会性"}, {"letter": "D", "text": "唐诗有梅香，宋词有雪白"}], "answer": "C", "explanation": "本题考查言语理解。'梅须逊雪三分白，雪却输梅一段香'在文中是支持宋词者的论据，用来说明宋词相比唐诗有其独特优势。结合上下文，引用此句的人认为宋词做到了雅俗共赏，此处以'雪'喻唐诗之白（雅正），以'梅'喻宋词之香（社会性），强调宋词比唐诗更有优势、更有广泛的社会性，C项正确。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1916}, {"num": 1918, "batch": "公共基础知识", "type": "single", "stem": "择一的因果关系是指两个或者两个以上的行为人都实施了可能对他人造成损害的危险行为，并且已经造成了损害结果，但是无法确定其中谁是加害人。 根据上述定义，下列存在择一的因果关系的是（）", "options": [{"letter": "A", "text": "甲在乙的饮水中下毒，乙喝下后在毒发前又因琐事与丙发生争吵，丙一怒之下用刀刺死了乙"}, {"letter": "B", "text": "甲、乙共同绑架了丙，甲负责向丙的家人索要赎金，乙为避免被丙认出，将丙残忍杀害"}, {"letter": "C", "text": "甲、乙两人在搬卸货物过程中因操作不当，造成货物损坏"}, {"letter": "D", "text": "甲、乙、丙三人带着相同的猎枪和子弹外出狩猎，甲、乙看到一只猎物出现在丙附近，二人同时开枪，结果其中一枪打中了丙"}], "answer": "D", "explanation": "本题考查定义判断。择一的因果关系要点：(1)两人以上都实施了危险行为；(2)已造成损害结果；(3)无法确定谁是加害人。D项中甲乙同时开枪，其中一枪打中丙，但无法确定是谁的枪打中的，完全符合定义。A项可以确定加害人是丙；B项可以确定是乙杀害了丙；C项是两人共同行为导致损害，不属于无法确定加害人的情形。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1917}, {"num": 1919, "batch": "公共基础知识", "type": "single", "stem": "扎实推进依法行政，转变政府职能，优化政府职责体系和组织结构，提高（），全面推进严格规范公正文明执法。", "options": [{"letter": "A", "text": "行政效率和亲和力"}, {"letter": "B", "text": "行政效率和公信力"}, {"letter": "C", "text": "办事效率和亲和力"}, {"letter": "D", "text": "办事效率和公信力"}], "answer": "B", "explanation": "本题考查时政知识。党的二十大报告指出：扎实推进依法行政，转变政府职能，优化政府职责体系和组织结构，提高行政效率和公信力，全面推进严格规范公正文明执法。'行政效率和公信力'是报告原文表述，B项正确。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1918}, {"num": 1920, "batch": "公共基础知识", "type": "single", "stem": "中华人民共和国第一届全国人民代表大会召开时间是（）。", "options": [{"letter": "A", "text": "1949年10月"}, {"letter": "B", "text": "1950年9月"}, {"letter": "C", "text": "1953年10月"}, {"letter": "D", "text": "1954年9月"}], "answer": "D", "explanation": "本题考查中国宪法史常识。中华人民共和国第一届全国人民代表大会于1954年9月在北京召开，会议通过了《中华人民共和国宪法》（即'五四宪法'），确立了人民代表大会制度为我国的根本政治制度。D项正确。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1919}, {"num": 1921, "batch": "公共基础知识", "type": "single", "stem": "张家口某镇居民喜食鸡肉和羊肉，近几年政府大力提倡发展养鸡业，市场上鸡肉供应大幅增加。假定羊肉供给未变，这会使（） ①鸡肉价格下降，需求量增加②羊肉价格上升，需求量增加 ③鸡肉需求量减少，价格上升④羊肉需求量减少，价格下降", "options": [{"letter": "A", "text": "①②"}, {"letter": "B", "text": "②③"}, {"letter": "C", "text": "③④"}, {"letter": "D", "text": "①④"}], "answer": "D", "explanation": "本题考查经济学中的供求关系和替代品原理。鸡肉供应增加导致鸡肉价格下降、需求量增加（①正确）。鸡肉和羊肉是替代品，鸡肉价格下降会使部分消费者转向购买鸡肉，导致羊肉需求减少，进而羊肉价格下降（④正确）。因此①④正确，D项当选。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1920}, {"num": 1922, "batch": "公共基础知识", "type": "single", "stem": "哲学的基本问题是（）", "options": [{"letter": "A", "text": "物质和意识的关系问题"}, {"letter": "B", "text": "物质和运动的关系问题"}, {"letter": "C", "text": "物质和时间空间的关系问题"}, {"letter": "D", "text": "自然和社会的关系问题"}], "answer": "A", "explanation": "本题考查马克思主义哲学基础知识。哲学的基本问题是思维和存在（即意识和物质）的关系问题，包括两个方面：一是思维和存在何者为第一性（本体论），二是思维能否认识存在（认识论）。这是恩格斯明确提出的经典论断，A项正确。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1921}, {"num": 1923, "batch": "公共基础知识", "type": "single", "stem": "真理是指客观事物及其规律在人的意识中的正确反映。真理可以分为理性真理和事实真理两种。理性真理指的是具有普遍性和必然性的真理，其反面是不可能的；事实真理指的是具有偶然性的真理，其反面是可能的。 根据上述定义，下列属于理性真理的是（）", "options": [{"letter": "A", "text": "月晕而风，础润而雨"}, {"letter": "B", "text": "如果 A 大于 B 且 B 大于 C，那么 A 大于 C"}, {"letter": "C", "text": "恩惠要一点点地施舍才具有最大效益"}, {"letter": "D", "text": "一个人如果违反了法律，就一定会受到法律的制裁"}], "answer": "B", "explanation": "本题考查定义判断。理性真理的要点：具有普遍性和必然性，其反面是不可能的。B项'A大于B且B大于C，则A大于C'是数学传递关系的必然真理，其反面不可能成立，属于理性真理。A项是基于经验观察的规律，具有偶然性；C项涉及人的行为效果，不具有必然性；D项现实中存在违法未受制裁的情况，不具有必然性。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1922}, {"num": 1924, "batch": "公共基础知识", "type": "single", "stem": "正值毕业季，306宿舍有A、B、C、D四位男同学，他们准备找班主任宋老师合影，若要求宋老师坐正中间，A.、B.两位同学不能挨着坐，那么总共有多少种坐法？", "options": [{"letter": "A", "text": "8 种"}, {"letter": "B", "text": "12 种"}, {"letter": "C", "text": "16 种"}, {"letter": "D", "text": "24 种"}], "answer": "C", "explanation": "本题考查排列组合。宋老师坐正中间（第3位），剩余A、B、C、D四人坐1、2、4、5号位。A、B不能相邻，即A、B不能同时坐在(1,2)或(4,5)的位置上。先计算总排列数：4!=24种。A、B相邻的情况：(1,2)或(4,5)两组位置，A、B内部排列2种，C、D剩余位置排列2种，共2×2×2=8种。因此满足条件的坐法为24-8=16种，C项正确。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1923}, {"num": 1925, "batch": "公共基础知识", "type": "single", "stem": "政府采购作为公共财政管理的一项重要制度安排，本义是规范政府购买行为、节约财政资金、从源头上防治腐败。采购部门不从价格上把关，便违背了制度的初衷。中国社科院公布的一份调研显示，一些地方政府在采购办公用品过程中，有近八成的商品高于市场价格。这反映了两个方面的问题，一方面是采购需求的不合理，只求贵的不求对的；另一方面则是政府采购招标环节中存在猫腻。政府采购谁来监督一直是采购制度的软肋所在，采购招标在没有阳光的空间操作，反而导致了“逆市场竞争”的乱象。 这段文字意在强调的是（）?", "options": [{"letter": "A", "text": "政府采购制度的初衷是防止腐败"}, {"letter": "B", "text": "政府采购需要在相关监督下进行"}, {"letter": "C", "text": "采购需求的不合理导致政务腐败"}, {"letter": "D", "text": "政府采购中存在大量的违规行为"}], "answer": "B", "explanation": "本题考查言语理解。文段先指出政府采购制度的初衷，然后揭示当前存在的问题——近八成商品高于市场价格，接着分析问题原因（采购需求不合理、招标环节有猫腻），最后指出监督是软肋，导致'逆市场竞争'的乱象。文段意在强调政府采购需要在监督下运行，B项正确。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1924}, {"num": 1926, "batch": "公共基础知识", "type": "single", "stem": "支持组织集权的正当理由是（）", "options": [{"letter": "A", "text": "提高组织的适应能力"}, {"letter": "B", "text": "提高组织决策质量"}, {"letter": "C", "text": "维护政策的统一性与提高行政效率"}, {"letter": "D", "text": "提高组织成员的工作热情"}], "answer": "C", "explanation": "本题考查管理学常识。支持组织集权的正当理由主要包括：维护政策的统一性，确保各部门协调一致；提高行政效率，避免多头指挥和重复决策。C项正确。A项错误，集权通常会降低组织对环境的适应速度；B项过于绝对，分权在某些情况下也能提高决策质量；D项错误，集权可能降低成员的工作热情。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1925}, {"num": 1927, "batch": "公共基础知识", "type": "single", "stem": "直观教学是指利用教具作为感官传递物，向学生展示相关内容，以达到提高学习效率或效果的一种教学方式。直观教学包括实物直观、模象直观和言语直观。实物直观通过直接感知实际事物而进行；模象直观通过对实行的模拟性形象来直接感知；言语直观是在形象化的语言作用下，通过学生对语言的物质形式（语音、字形）的感知及对语义的理解而进行的一种直观形式。 根据上述定义，下列不属于上述三种直观教学的是（）", "options": [{"letter": "A", "text": "请学生在课后阅读整篇小说内容并撰写读后感"}, {"letter": "B", "text": "暑期带着学生去工厂和农村进行实地参观访问"}, {"letter": "C", "text": "请学生分角色朗读戏剧作品，或通过上台表演来体会人物性格"}, {"letter": "D", "text": "在艺术鉴赏课上，使用幻灯片给学生展示西方油画的经典之作"}], "answer": "A", "explanation": "本题考查定义判断。直观教学包括实物直观（直接感知实际事物）、模象直观（感知模拟性形象）和言语直观（通过形象化语言进行感知）。A项让学生课后阅读小说并写读后感，不涉及利用教具展示内容，不属于上述三种直观教学。B项属于实物直观（实地参观）；C项属于模象直观（角色扮演模拟情境）；D项属于模象直观（幻灯片展示）。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1926}, {"num": 1928, "batch": "公共基础知识", "type": "single", "stem": "智慧城市是运用信息和通信技术整合城市运行各项关键信息，从而对包括民生、环保、公共安全、城市服务、工商业活动在内的各种需求做出智能响应，实现城市智慧式管理和运行。 根据上述定义，下列不属于智慧城市内容的是（）", "options": [{"letter": "A", "text": "逐步实现多领域跨行业的“一卡通”网"}, {"letter": "B", "text": "网上“一站式”行政审批及其他公共服务"}, {"letter": "C", "text": "根据人工智能算法科学合理的规划城市交通网"}, {"letter": "D", "text": "整合各类监控资源，建立治安综和管理平台"}], "answer": "A", "explanation": "本题考查定义判断。智慧城市的核心是运用信息和通信技术整合关键信息，对各种需求做出智能响应，实现智慧式管理和运行。A项'一卡通'仅是支付手段的统一，未体现智能响应和智慧管理，不属于智慧城市的核心内容。B项'一站式'审批体现了智能政务服务；C项人工智能规划交通体现了智能响应；D项治安综合管理平台体现了公共安全智能管理。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1927}, {"num": 1929, "batch": "公共基础知识", "type": "single", "stem": "智能手表近几年发展迅速，它有很多传统手表所不具备的功能，比如，实时收发短信、邮件；实时监测运动状态；获取血压、脉搏数据等。也正因为智能手表的这些优点，越来越多的人购买智能手表。据此，张楠预计，再过若干年，制造传统手表的工厂最终会倒闭。以下哪项如果为真，最能削弱张楠的结论？（）", "options": [{"letter": "A", "text": "因为智能手表价格较为昂贵，一些消费者不会购买智能手表"}, {"letter": "B", "text": "虽然传统手表功能单一，戴习惯的人不愿意改戴智能手表"}, {"letter": "C", "text": "大多数传统手表制造厂不仅制造传统手表也制造智能手表"}, {"letter": "D", "text": "许多智能手表需要与智能手机配套使用，令许多人感到麻烦"}], "answer": "C", "explanation": "本题考查逻辑推理中的削弱论证。张楠的结论是'传统手表工厂最终会倒闭'，论据是智能手表越来越受欢迎。C项指出大多数传统手表厂也制造智能手表，说明即使传统手表市场萎缩，这些工厂可以通过生产智能手表继续生存，直接削弱了'工厂会倒闭'的结论。A、B、D项虽然也有一定削弱作用，但力度不如C项直接。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1928}, {"num": 1930, "batch": "公共基础知识", "type": "single", "stem": "中共中央在北京香山虽然只有半年时间，但这里是中国革命重心（）的重要标志，在中国共产党历史、中华人民共和国历史上具有非常重要的地位。", "options": [{"letter": "A", "text": "从城市转向农村"}, {"letter": "B", "text": "从旧民主主义革命转向新民主主义革命"}, {"letter": "C", "text": "从农村转向城市"}, {"letter": "D", "text": "从新民主主义革命转向社会主义现代化建设"}], "answer": "C", "explanation": "本题考查中共党史知识。1949年3月七届二中全会后，中共中央从西柏坡迁往北平（北京）香山。中共中央在香山期间，标志着中国革命重心从农村转向城市的重要转变。毛泽东在七届二中全会上提出党的工作重心由乡村转移到城市，香山时期正是这一转变的重要标志，C项正确。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1929}, {"num": 1931, "batch": "公共基础知识", "type": "single", "stem": "中国传统诗的历史表明。文学吟诵乃是伴随着近体律诗的成熟而成熟起来的。当最好的近体诗人出现时，真正意义上的文学吟诵才得以诞生。清人方世举《兰丛诗话》评说杜律云：“唐之创律诗也，五言犹承齐、梁格诗而整饬其音调。七言则沈、宋新裁。其体最时，其格最下，然却最难，尺幅窄而束缚紧也。能不受其画地湿薪者，惟有老杜，法度整严而又宽舒，音容郁丽而又大雅，律之全体大用，金科玉律也。”杜甫是公认的唐代最好的律诗作者，他不仅“吟”出了人间最好的律诗，同时也给后人提供了一把量尺，帮助我们从良莠不齐的诗歌遗产当中，选择出最好的诗来承传文学的吟诵。 这段文字主要说明（）", "options": [{"letter": "A", "text": "什么是真正意义上的文学吟诵"}, {"letter": "B", "text": "如何从良莠不齐的诗歌中选出最好的诗"}, {"letter": "C", "text": "文学吟诵的发展和近体律诗有紧密关系"}, {"letter": "D", "text": "杜甫是公认的唐代最好的律诗作者"}], "answer": "D", "explanation": "本题考查言语理解。文段先论述文学吟诵伴随近体律诗的成熟而成熟，然后引用方世举对杜甫律诗的高度评价，最后指出杜甫不仅创作了最好的律诗，还为后人提供了衡量诗歌优劣的标准。文段主要说明杜甫是公认的唐代最好的律诗作者，D项正确。C项虽在文段前半部分有所涉及，但不是文段的最终落脚点。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1930}, {"num": 1932, "batch": "公共基础知识", "type": "single", "stem": "中国第一个具有资产阶级性质的政党是（）", "options": [{"letter": "A", "text": "兴中会"}, {"letter": "B", "text": "中国同盟会"}, {"letter": "C", "text": "光复会"}, {"letter": "D", "text": "国民党"}], "answer": "B", "explanation": "本题考查中国近代史知识。中国同盟会于1905年在日本东京成立，由孙中山领导，以'驱除鞑虏，恢复中华，创立民国，平均地权'为纲领，是中国第一个全国性的资产阶级革命政党。A项兴中会是1894年成立的革命团体，但还不是全国性政党；C项光复会是地方性革命团体；D项国民党成立于同盟会之后。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1931}, {"num": 1933, "batch": "公共基础知识", "type": "single", "stem": "中国共产党独立领导革命战争、创建人民军队和武装夺取政权的开端是（）", "options": [{"letter": "A", "text": "秋收起义"}, {"letter": "B", "text": "南昌起义"}, {"letter": "C", "text": "百色起义"}, {"letter": "D", "text": "广州起义"}], "answer": "B", "explanation": "本题考查中共党史知识。1927年8月1日的南昌起义，打响了武装反抗国民党反动派的第一枪，是中国共产党独立领导革命战争、创建人民军队和武装夺取政权的开端。因此每年8月1日被定为中国人民解放军建军节，B项正确。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1932}, {"num": 1934, "batch": "公共基础知识", "type": "single", "stem": "中国共产党是哪一年成立的（）", "options": [{"letter": "A", "text": "1919年"}, {"letter": "B", "text": "1921年"}, {"letter": "C", "text": "1923年"}, {"letter": "D", "text": "1927年"}], "answer": "B", "explanation": "本题考查中共党史基本常识。中国共产党于1921年7月在上海（后转移到浙江嘉兴南湖）召开第一次全国代表大会，宣告正式成立。1921年是建党年份，B项正确。1919年是五四运动，1923年是三大，1927年是八七会议和南昌起义。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1933}, {"num": 1935, "batch": "公共基础知识", "type": "single", "stem": "中国古人留下了许多经典著作，后人不断阐发其中蕴藏的深厚思想内涵。下列学问中，不是以研究某一部经典著作为主的是（）", "options": [{"letter": "A", "text": "龙学"}, {"letter": "B", "text": "理学"}, {"letter": "C", "text": "许学"}, {"letter": "D", "text": "红学"}], "answer": "B", "explanation": "本题考查中国文化常识。A项'龙学'是研究《文心雕龙》的学问；B项'理学'是宋明时期以探讨义理为主的哲学思潮（又称道学），并非以研究某一部经典著作为主；C项'许学'是研究许慎《说文解字》的学问；D项'红学'是研究曹雪芹《红楼梦》的学问。因此B项正确。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1934}, {"num": 1936, "batch": "公共基础知识", "type": "single", "stem": "中国正处于经济结构转型升级和世界新一轮技术革命的交汇时期，创新驱动高质量发展渐成共识。没有管理创新、市场创新的商业创新模式（），有真实需求场景的教育、医疗健康、信息消费、消费升级等模式创新领域，将会迸发出新的投资机会。", "options": [{"letter": "A", "text": "举步维艰"}, {"letter": "B", "text": "日薄西山"}, {"letter": "C", "text": "难以为继"}, {"letter": "D", "text": "岌岌可危"}], "answer": "C", "explanation": "本题考查词语辨析。'难以为继'指难以继续下去，符合语境——没有管理创新、市场创新的商业模式将难以持续发展。'举步维艰'强调行走困难，侧重行动艰难；'日薄西山'比喻衰老或衰败，多用于人或事物走向灭亡；'岌岌可危'形容极其危险。文段强调的是商业模式无法持续，'难以为继'最为贴切，C项正确。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1935}, {"num": 1937, "batch": "公共基础知识", "type": "single", "stem": "自（）起，按照党章规定，党的全国代表大会每五年召开一次，实现了制度化。", "options": [{"letter": "A", "text": "党的十一大"}, {"letter": "B", "text": "党的十二大"}, {"letter": "C", "text": "党的十三大"}, {"letter": "D", "text": "党的十四大"}], "answer": "B", "explanation": "本题考查中共党史知识。1982年召开的党的十二大通过的党章规定，党的全国代表大会每五年召开一次，实现了制度化。此后从十二大开始，党的全国代表大会严格按照五年一届的规定召开，B项正确。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1936}, {"num": 1938, "batch": "公共基础知识", "type": "single", "stem": "中微子是一种基本粒子，在宏观的宇宙起源及演化中扮演着极为重要的角色，由于没有质量并且不带电荷，和其他物质的相互作用极其微弱，这使得中微子的运动轨迹不会发生改变。那些来自遥远宇宙、来自黑洞边缘或者来自宇宙线发源地的中微子，可以告诉人类那些“源”在哪里，甚至可以让我们一探黑洞的究竟。 最适合做本段文字标题的是（）", "options": [{"letter": "A", "text": "令人惊喜的存在"}, {"letter": "B", "text": "特立独行的中微子"}, {"letter": "C", "text": "中微子：宇宙的使者"}, {"letter": "D", "text": "触不可及：“隐形”的中微子"}], "answer": "C", "explanation": "本题考查言语理解中的标题选择。文段介绍了中微子的特点（无质量、不带电荷、运动轨迹不改变）及其作用（可以告诉人类宇宙'源'在哪里、探索黑洞）。'宇宙的使者'既体现了中微子能传递宇宙信息的功能，又形象生动，最适合做标题，C项正确。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1937}, {"num": 1939, "batch": "公共基础知识", "type": "single", "stem": "周边产品，指利用动画、漫画、游戏等作品中的人物或动物造型，经授权后制成的商品。根据上述定义，以下属于周边产品的是（）", "options": [{"letter": "A", "text": "某文化公司请美术大师绘制了一套《红楼梦》金陵十二钗的明信片，印刷售卖"}, {"letter": "B", "text": "小涛制作了一套孙悟空七十二变的泥塑，参加区文化馆组织的手工艺术品比赛"}, {"letter": "C", "text": "某娱乐公司开发了一部非常受欢迎的动画片，同步推出主人公形象的玩具和服装"}, {"letter": "D", "text": "小樱把自己的偶像明星曾经饰演过的所有角色的照片集结成册，在粉丝群里销售"}], "answer": "C", "explanation": "本题考查定义判断。周边产品的要点：(1)利用动画、漫画、游戏等作品中的人物或动物造型；(2)经授权后制成；(3)制成商品。C项中娱乐公司开发的动画片属于'作品'，同步推出主人公形象的玩具和服装符合'经授权后制成的商品'的定义。A项《红楼梦》不属于动画、漫画、游戏作品；B项泥塑用于比赛而非商品销售；D项未经授权使用明星照片。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1938}, {"num": 1940, "batch": "公共基础知识", "type": "single", "stem": "洲际导弹通常指射程大于8000公里的远程弹道式导弹。目前，中国研制的洲际弹道导弹主要是什么系列的是（）", "options": [{"letter": "A", "text": "“东风”系列"}, {"letter": "B", "text": "“长征”系列"}, {"letter": "C", "text": "“红旗”系列"}, {"letter": "D", "text": "“天宫”系列"}], "answer": "A", "explanation": "本题考查军事常识。中国研制的洲际弹道导弹主要是'东风'系列，如东风-5、东风-31、东风-41等，A项正确。'长征'系列是运载火箭；'红旗'系列是防空导弹；'天宫'系列是空间实验室。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1939}, {"num": 1941, "batch": "公共基础知识", "type": "single", "stem": "尊重自然、顺应自然、保护自然，是全面建设社会主义现代化国家的（）。", "options": [{"letter": "A", "text": "必然要求"}, {"letter": "B", "text": "内在要求"}, {"letter": "C", "text": "必然条件"}, {"letter": "D", "text": "内在条件"}], "answer": "B", "explanation": "本题考查党的二十大报告原文。党的二十大报告明确指出：尊重自然、顺应自然、保护自然，是全面建设社会主义现代化国家的内在要求。这体现了生态文明建设在现代化建设中的重要地位，B项正确。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1940}, {"num": 1942, "batch": "公共基础知识", "type": "single", "stem": "自17世纪以来，也许是受到理性精神的鼓舞和科学进步的鼓励，人类思想长期处在逻辑形式主义和科学唯理主义的密云中。到了20世纪上半叶的逻辑实证主义那里，这种思想发展成为一种极端；只有符合逻辑的、可验证的知识才是人类的唯一选择，凡不能由逻辑与实证加以检验的知识都是空想，没有意义。 根据上述观点，下列不属于“空想”的是（）", "options": [{"letter": "A", "text": "法学"}, {"letter": "B", "text": "几何学"}, {"letter": "C", "text": "伦理学"}, {"letter": "D", "text": "政治学"}], "answer": "B", "explanation": "本题考查逻辑推理。题干所述逻辑实证主义观点认为：只有符合逻辑的、可验证的知识才是人类唯一选择，否则就是空想。几何学是纯粹逻辑推演的学科，符合'符合逻辑的、可验证的'标准，不属于空想，B项正确。法学、伦理学、政治学涉及价值判断，难以完全通过逻辑与实证检验。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1941}, {"num": 1943, "batch": "公共基础知识", "type": "single", "stem": "自从1958年第一个永久起搏器被植入人体后，可植入医疗设备的制造商就在不断研究为其产品提供电能的各种方法。不可充电的锂电池目前较为普遍，在心脏病和神经源性疾病的移植设备中，不可充电的锂电池一般能够使用7年到10年，已经属于比较“长寿”的了。研究者认为，除非在生物电池领域取得突破性进展，否则植入式设备始终无法真正永久、可靠地工作。 这段文字意在说明（）", "options": [{"letter": "A", "text": "可植入设备目前主要用于医疗领域"}, {"letter": "B", "text": "神经源性疾病的治疗需引入新技术"}, {"letter": "C", "text": "供电能力目前是可植入设备的瓶颈"}, {"letter": "D", "text": "可植入医疗设备的发展前景较广阔"}], "answer": "C", "explanation": "本题考查言语理解。文段围绕可植入医疗设备的供电问题展开：从不可充电锂电池的使用年限，到研究者认为除非生物电池取得突破否则设备无法永久可靠工作。文段意在说明供电能力是目前可植入设备发展的瓶颈，C项正确。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1942}, {"num": 1944, "batch": "公共基础知识", "type": "single", "stem": "综合分析研究的能力，就是把获得的材料进行加工分析，去粗取精，由表及里，进行加工改造，使之上升为（）", "options": [{"letter": "A", "text": "基本结论"}, {"letter": "B", "text": "理性认识"}, {"letter": "C", "text": "本质结论"}, {"letter": "D", "text": "感性认识"}], "answer": "B", "explanation": "本题考查认识论知识。综合分析研究的过程，就是将感性材料进行'去粗取精、去伪存真、由此及彼、由表及里'的加工改造，使之从感性认识上升为理性认识。这是毛泽东在《实践论》中阐述的认识发展过程，B项正确。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1943}, {"num": 1945, "batch": "公共基础知识", "type": "single", "stem": "纵观世界，新的垃圾处理时代正在到来。前不久，俄罗斯科学家已经可以利用等离子技术来处理垃圾焚烧过程中产生的有害气体，并对城市生活制造的“污泥浊水”进行无害化处理，使其转为腐殖酸肥料。德国科学家创造出“风拣技术”，令世界看到了垃圾处理的广阔未来。该技术终结了垃圾的人工分拣，让风代替人去对垃圾中的塑料、玻璃、纸张等进行分拣，从而将垃圾处理工艺提高到了一个前所未有的新阶段。 最适合做这段文字标题的是（）", "options": [{"letter": "A", "text": "垃圾：放错地方的资源"}, {"letter": "B", "text": "科技：垃圾处理的关键"}, {"letter": "C", "text": "风力：新时代的“机器人”"}, {"letter": "D", "text": "无害化：垃圾处理的未来"}], "answer": "B", "explanation": "本题考查言语理解中的标题选择。文段列举了俄罗斯科学家用等离子技术处理垃圾有害气体和污泥、德国科学家发明'风拣技术'替代人工分拣等实例，共同说明科技进步是解决垃圾处理问题的关键所在，B项'科技：垃圾处理的关键'最能概括文段主旨。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1944}, {"num": 1946, "batch": "公共基础知识", "type": "multi", "stem": "2024年9月1日，《求是》杂志发表了习近平总书记的重要文章《培养德智体美劳全面发展的社会主义建设者和接班人》，文章强调，培养什么人是教育的首要问题。要健全全员育人、全过程育人、全方位育人的体制机制，不断培养一代又一代社会主义建设者和接班人。关于全员，全过程，全方位育人，下列说法正确的是：（）", "options": [{"letter": "A", "text": "要以立德树人贯穿到教育的各个环节和各个领域"}, {"letter": "B", "text": "教材是教育的物质载体，是教育的决定性因素"}, {"letter": "C", "text": "学校和教师承担着育人的全部重任，是教育育人的主导力量"}, {"letter": "D", "text": "必须以培养社会主义建设者和接班人作为教育的根本任务"}], "answer": "AD", "explanation": "本题考查教育政策知识。A项正确，立德树人应贯穿教育各环节和领域；D项正确，培养社会主义建设者和接班人是教育的根本任务。B项错误，教材是教育的重要载体但不是'决定性因素'，教师才是教育的关键；C项错误，育人不仅是学校和教师的责任，需要家庭、学校、社会协同育人，不是'全部重任'。因此选AD。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1945}, {"num": 1947, "batch": "公共基础知识", "type": "single", "stem": "作为世界上最成功的室内栽培植物之一，绿萝几乎就是盆栽的代名词，（）。绿萝这个物种早在1880年就被确认了，但是你很难想象，直到2004年，它的原产地才被确定为法属波利尼西亚社会群岛的莫雷阿岛。更为神秘的是，绿萝是一种过分矜持的植物，虽然它已经扩散到了全世界的热带地区，却只在1962年有过一次确切的开花记录，直到2016年，人们才发现了它开花的秘密。", "options": [{"letter": "A", "text": "唯一的遗憾就是绿萝从来不开花"}, {"letter": "B", "text": "因为它非常适合人类的居住环境"}, {"letter": "C", "text": "但它却也是我们最熟悉的陌生人"}, {"letter": "D", "text": "是一种不可多得的室内观叶植物"}], "answer": "C", "explanation": "本题考查语句衔接。横线后文介绍了绿萝原产地直到2004年才确定、开花记录仅一次、开花秘密到2016年才发现等信息，都在说明人们对绿萝其实了解甚少。'但它却也是我们最熟悉的陌生人'既与前文'最成功的室内栽培植物'形成转折，又引出后文对绿萝'神秘'一面的介绍，C项最恰当。", "tags": "广东辅警笔试 单选题 公共基础知识", "_idx": 1946}, {"num": 1948, "batch": "公共基础知识", "type": "multi", "stem": "“沉舟侧畔千帆过，病树前头万木春。”新生事物必然取代旧事物，从根本上说，是因为（）", "options": [{"letter": "A", "text": "新生事物产生于旧事物之后，是新出现的事物"}, {"letter": "B", "text": "新生事物具有新的结构和功能，能适应已经变化了的环境和条件"}, {"letter": "C", "text": "新生事物是对旧事物的扬弃，并添加了旧事物所不能容纳的新内容"}, {"letter": "D", "text": "在社会历史领域内，新生事物符合广大人民群众的根本利益和要求"}], "answer": "BCD", "explanation": "本题考查马克思主义哲学中关于新事物的知识。新生事物必然取代旧事物的原因：B项新生事物具有新结构和功能，能适应变化了的环境和条件；C项新生事物是对旧事物的扬弃，添加了旧事物不能容纳的新内容；D项在社会历史领域，新生事物符合人民群众的根本利益。A项错误，新出现的事物不等于新生事物，判断新旧事物的标准不是出现时间的先后，而是是否符合事物发展的必然趋势。因此选BCD。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1947}, {"num": 1949, "batch": "公共基础知识", "type": "multi", "stem": "“两个维护”是保证全党团结统一、步调一致，带领全国各族人民决胜全面建成小康社会、奋力夺取新时代中国特色社会主义伟大胜利的根本政治保证。下面属于“两个维护”内容的是（）。", "options": [{"letter": "A", "text": "坚决维护习近平总书记党中央的核心、全党的核心地位"}, {"letter": "B", "text": "坚决维护宪法的根本大法地位，全面依法治国"}, {"letter": "C", "text": "坚决维护中国特色社会主义理论体系，坚持理论自信"}, {"letter": "D", "text": "坚决维护党中央权威和集中统一领导"}], "answer": "AD", "explanation": "本题考查政治常识。'两个维护'是指：坚决维护习近平总书记党中央的核心、全党的核心地位（A项），坚决维护党中央权威和集中统一领导（D项）。'两个维护'是党的十八大以来党的政治建设的首要任务，是党在新时代的重大政治成果。B、C项不属于'两个维护'的内容。因此选AD。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1948}, {"num": 1950, "batch": "公共基础知识", "type": "multi", "stem": "“诗词歌赋”是人们对我国古代文学的概称，下列有关表述中正确的有（）", "options": [{"letter": "A", "text": "古文中常有“子曰诗云”的字样，“子曰”即孔子说：“诗云”即《诗经》上说"}, {"letter": "B", "text": "《陋室铭》中，“铭”原指古代刻在器物上用来警戒自己或称述功德的文字，后来成为一种文体"}, {"letter": "C", "text": "《沁园春·雪》中“沁园春”是词牌名，“雪”是这首词的题目，词的内容与“沁园春”联系密切"}, {"letter": "D", "text": "诗歌分为抒情诗、叙事诗和说理诗，《木兰诗》是一首叙事诗"}], "answer": "ABD", "explanation": "本题考查文学常识。A项正确，'子曰'即孔子说，'诗云'即《诗经》上说；B项正确，'铭'的释义准确；D项正确，《木兰诗》叙述了花木兰替父从军的故事，属于叙事诗。C项错误，词牌名'沁园春'规定了词的格式（字数、韵律等），与词的内容没有必然联系，'雪'才是题目，点明词的内容。因此选ABD。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1949}, {"num": 1951, "batch": "公共基础知识", "type": "multi", "stem": "“一带一路”建设是一项宏大系统工程，要突出重点、远近结合，有序推进。要坚持共商、共建、共享原则，积极与沿线国家的发展战略相互对接，这段话所蕴含的哲学原理有（）", "options": [{"letter": "A", "text": "事物是普遍联系的"}, {"letter": "B", "text": "矛盾是事物发展的根本动力"}, {"letter": "C", "text": "“两点论”与“重点论”的统一"}, {"letter": "D", "text": "事物发展是质变和量变的统一"}], "answer": "AC", "explanation": "本题考查哲学原理。'坚持共商、共建、共享原则'体现了事物是普遍联系的，各国发展相互关联（A项）；'要突出重点、远近结合，有序推进'体现了抓主要矛盾和全面看问题相结合，即'两点论'与'重点论'的统一（C项）。B项矛盾是发展动力在文中未直接体现；D项质变量变在文中也未体现。因此选AC。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1950}, {"num": 1952, "batch": "公共基础知识", "type": "multi", "stem": "《关于新形势下党内政治生活的若干准则》规定，要形成（）的选人用人导向。", "options": [{"letter": "A", "text": "能者上"}, {"letter": "B", "text": "庸者下"}, {"letter": "C", "text": "劣者汰"}, {"letter": "D", "text": "强者上"}], "answer": "ABC", "explanation": "本题考查党内法规知识。《关于新形势下党内政治生活的若干准则》明确规定，要形成能者上、庸者下、劣者汰的选人用人导向。这体现了新时代党的组织路线对干部选拔任用的要求。D项'强者上'不是准则原文表述。因此选ABC。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1951}, {"num": 1953, "batch": "公共基础知识", "type": "multi", "stem": "《中国共产党党员教育管理工作条例》规定，发现党员有思想、工作、生活、作风和纪律方面（）问题的，以及群众对其有不良反映的，党组织负责人应当及时进行提醒谈话，抓早抓小、防微杜渐。", "options": [{"letter": "A", "text": "苗头性"}, {"letter": "B", "text": "政治性"}, {"letter": "C", "text": "思想性"}, {"letter": "D", "text": "倾向性"}], "answer": "AD", "explanation": "本题考查党内法规知识。《中国共产党党员教育管理工作条例》规定，发现党员有思想、工作、生活、作风和纪律方面苗头性、倾向性问题的，以及群众对其有不良反映的，党组织负责人应当及时进行提醒谈话。'苗头性'和'倾向性'强调的是问题尚处于萌芽或初期阶段，体现抓早抓小、防微杜渐的原则。因此选AD。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1952}, {"num": 1954, "batch": "公共基础知识", "type": "multi", "stem": "1915年发端的中国新文化运动高举的两面大旗是（）。", "options": [{"letter": "A", "text": "民主"}, {"letter": "B", "text": "科学"}, {"letter": "C", "text": "爱国"}, {"letter": "D", "text": "自由"}], "answer": "AB", "explanation": "本题考查中国近现代史知识。1915年陈独秀在上海创办《青年杂志》（后改名《新青年》），标志着新文化运动的开始。新文化运动高举'民主'（德先生，Democracy）和'科学'（赛先生，Science）两面大旗，反对专制和愚昧，A项和B项正确。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1953}, {"num": 1955, "batch": "公共基础知识", "type": "multi", "stem": "1948年秋后，人民解放军同国民党军队进行战略决战的三大战役是（）。", "options": [{"letter": "A", "text": "辽沈战役"}, {"letter": "B", "text": "平津战役"}, {"letter": "C", "text": "渡江战役"}, {"letter": "D", "text": "淮海战役"}], "answer": "ABD", "explanation": "本题考查解放战争史知识。1948年秋至1949年初，人民解放军同国民党军队进行的战略决战的三大战役是：辽沈战役（1948年9月-11月）、淮海战役（1948年11月-1949年1月）、平津战役（1948年11月-1949年1月）。C项渡江战役发生在三大战役之后（1949年4月），不属于三大战役。因此选ABD。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1954}, {"num": 1956, "batch": "公共基础知识", "type": "multi", "stem": "1951年12月1日，中共中央决定开展“三反”运动，主要内容是（）", "options": [{"letter": "A", "text": "反对贪污"}, {"letter": "B", "text": "反对行贿"}, {"letter": "C", "text": "反对浪费"}, {"letter": "D", "text": "反对官僚主义"}], "answer": "ACD", "explanation": "本题考查中共党史知识。1951年12月1日，中共中央作出《关于实行精兵简政、增产节约、反对贪污、反对浪费和反对官僚主义的决定》，由此在全国开展了'三反'运动，即反贪污、反浪费、反官僚主义。B项'反对行贿'属于'五反'运动（反行贿、反偷税漏税、反盗骗国家财产、反偷工减料、反盗窃国家经济情报）的内容。因此选ACD。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1955}, {"num": 1957, "batch": "公共基础知识", "type": "multi", "stem": "1980年5月，“出口特区”改名为“经济特区”。我国最早设立的经济特区有（）", "options": [{"letter": "A", "text": "深圳"}, {"letter": "B", "text": "珠海"}, {"letter": "C", "text": "厦门"}, {"letter": "D", "text": "汕头"}], "answer": "ABCD", "explanation": "本题考查改革开放史知识。1980年，我国最早设立的四个经济特区分别是：深圳、珠海、汕头（均在广东省）和厦门（在福建省）。1980年5月，'出口特区'正式改名为'经济特区'。四个特区同时设立，因此ABCD全部正确。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1956}, {"num": 1958, "batch": "公共基础知识", "type": "multi", "stem": "20世纪中国人民在前进道路上经历的三次历史性巨大变化是（）", "options": [{"letter": "A", "text": "辛亥革命，推翻统治中国几千年的君主专制制度"}, {"letter": "B", "text": "五四运动，促进马克思主义在中国的传播及其与中国工人运动的结合"}, {"letter": "C", "text": "中华人民共和国的成立和社会主义制度的建立"}, {"letter": "D", "text": "改革开放，为实现社会主义现代化而奋斗"}], "answer": "ACD", "explanation": "本题考查中国近现代史知识。20世纪中国人民经历的三次历史性巨大变化是：辛亥革命推翻君主专制制度（A项）；中华人民共和国成立和社会主义制度建立（C项）；改革开放为实现社会主义现代化奋斗（D项）。B项五四运动虽然意义重大，但不属于三次历史性巨大变化之列。因此选ACD。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1957}, {"num": 1959, "batch": "公共基础知识", "type": "multi", "stem": "被合称为“史学双璧”的两部著作是（）", "options": [{"letter": "A", "text": "《汉书》"}, {"letter": "B", "text": "《史记》"}, {"letter": "C", "text": "《资治通鉴》"}, {"letter": "D", "text": "《左传》"}], "answer": "BC", "explanation": "本题考查中国文学常识。'史学双璧'指的是《史记》和《资治通鉴》。《史记》是西汉司马迁所著，是我国第一部纪传体通史；《资治通鉴》是北宋司马光主编的编年体通史。两部著作分别代表了纪传体和编年体两种史书体裁的最高成就，合称'史学双璧'。因此选BC。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1958}, {"num": 1960, "batch": "公共基础知识", "type": "multi", "stem": "党的二十大报告指出，必须坚定不移走中国特色社会主义政治发展道路，坚持（）有机统一，坚持人民主体地位，充分体现人民意志、保障人民权益、激发人民创造活力。", "options": [{"letter": "A", "text": "党的领导"}, {"letter": "B", "text": "人民民主"}, {"letter": "C", "text": "人民当家作主"}, {"letter": "D", "text": "依法治国"}], "answer": "ACD", "explanation": "本题考查党的二十大报告内容。报告指出：必须坚定不移走中国特色社会主义政治发展道路，坚持党的领导、人民当家作主、依法治国有机统一，坚持人民主体地位，充分体现人民意志、保障人民权益、激发人民创造活力。三者有机统一是中国特色社会主义政治发展道路的核心要义。因此选ACD。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1959}, {"num": 1961, "batch": "公共基础知识", "type": "multi", "stem": "党的二十大报告指出，广泛践行社会主义核心价值观，弘扬以伟大建党精神为源头的中国共产党人精神谱系，深入开展社会主义核心价值观宣传教育，深化（）教育，着力培养担当民族复兴大任的时代新人。", "options": [{"letter": "A", "text": "马克思主义"}, {"letter": "B", "text": "爱国主义"}, {"letter": "C", "text": "集体主义"}, {"letter": "D", "text": "社会主义"}], "answer": "BCD", "explanation": "本题考查党的二十大报告内容。报告指出：广泛践行社会主义核心价值观，深入开展爱国主义、集体主义、社会主义教育，着力培养担当民族复兴大任的时代新人。A项'马克思主义'教育虽重要，但此处报告原文表述为爱国主义、集体主义、社会主义三项教育。因此选BCD。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1960}, {"num": 1962, "batch": "公共基础知识", "type": "multi", "stem": "党的二十大报告指出，继续推进实践基础上的理论创新,首先要把握好新时代中国特色社会主义思想的世界观和方法论,坚持好、运用好贯穿其中的立场观点方法。必须坚持人民至上，坚持自信自立，坚持守正创新，（）。", "options": [{"letter": "A", "text": "坚持自我革新"}, {"letter": "B", "text": "坚持问题导向"}, {"letter": "C", "text": "坚持系统观念"}, {"letter": "D", "text": "坚持胸怀天下"}], "answer": "BCD", "explanation": "本题考查党的二十大报告内容。报告提出新时代中国特色社会主义思想的世界观和方法论，即'六个必须坚持'：坚持人民至上、坚持自信自立、坚持守正创新、坚持问题导向、坚持系统观念、坚持胸怀天下。题目已列出前三个，剩余三个为问题导向、系统观念、胸怀天下，即BCD项。A项'坚持自我革新'不属于'六个必须坚持'。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1961}, {"num": 1963, "batch": "公共基础知识", "type": "multi", "stem": "党的二十大报告指出，坚持以严的基调强化正风肃纪，锲而不舍落实中央八项规定精神，持续深化纠治“四风”，重点纠（），坚决破除特权思想和特权行为。", "options": [{"letter": "A", "text": "形式主义"}, {"letter": "B", "text": "官僚主义"}, {"letter": "C", "text": "个人主义"}, {"letter": "D", "text": "本位主义"}], "answer": "AB", "explanation": "本题考查党的二十大报告内容。报告指出：锲而不舍落实中央八项规定精神，持续深化纠治'四风'，重点纠治形式主义、官僚主义。'四风'是指形式主义、官僚主义、享乐主义和奢靡之风，其中重点纠治的是形式主义和官僚主义。因此选AB。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1962}, {"num": 1964, "batch": "公共基础知识", "type": "multi", "stem": "党的二十大报告指出，教育、科技、人才是全面建设社会主义现代化国家的基础性、战略性支撑。必须坚持科技是第一生产力、人才是第一资源、创新是第一动力，深入实施（）战略，开辟发展新领域新赛道，不断塑造发展新动能新优势。", "options": [{"letter": "A", "text": "科教兴国"}, {"letter": "B", "text": "人才强国"}, {"letter": "C", "text": "教育强国"}, {"letter": "D", "text": "创新驱动发展"}], "answer": "ABD", "explanation": "本题考查党的二十大报告内容。报告指出：深入实施科教兴国战略、人才强国战略、创新驱动发展战略。三大战略是教育、科技、人才三位一体统筹推进的具体部署。C项'教育强国'战略虽然也是重要战略，但报告此处的原文表述为上述三大战略。因此选ABD。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1963}, {"num": 1965, "batch": "公共基础知识", "type": "multi", "stem": "党的二十大报告指出，经过不懈努力，党找到了自我革命这一跳出治乱兴衰历史周期率的第二个答案，确保党永远（）。", "options": [{"letter": "A", "text": "不变质"}, {"letter": "B", "text": "不变色"}, {"letter": "C", "text": "不变味"}, {"letter": "D", "text": "不变心"}], "answer": "ABC", "explanation": "本题考查党的二十大报告内容。报告指出：经过不懈努力，党找到了自我革命这一跳出治乱兴衰历史周期率的第二个答案，确保党永远不变质、不变色、不变味。'不变质'指保持党的性质宗旨，'不变色'指保持党的政治本色，'不变味'指保持党的先进性和纯洁性。因此选ABC。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1964}, {"num": 1966, "batch": "公共基础知识", "type": "multi", "stem": "党的二十大报告指出，十年来，我们采取一系列战略性举措，（），经受住了来自政治、经济、意识形态、自然界等方面的风险挑战考验，党和国家事业取得历史性成就、发生历史性变革，推动我国迈上全面建设社会主义现代化国家新征程。", "options": [{"letter": "A", "text": "推进一系列变革性实践"}, {"letter": "B", "text": "实现一系列突破性进展"}, {"letter": "C", "text": "取得一系列标志性成果"}, {"letter": "D", "text": "实现了全面建设小康社会"}], "answer": "ABC", "explanation": "本题考查党的二十大报告内容。报告指出：十年来，我们采取一系列战略性举措，推进一系列变革性实践，实现一系列突破性进展，取得一系列标志性成果。三个'一系列'分别对应变革性实践、突破性进展、标志性成果。D项'实现了全面建设小康社会'表述有误，且不属于此处'一系列'的内容。因此选ABC。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1965}, {"num": 1967, "batch": "公共基础知识", "type": "multi", "stem": "党的二十大报告指出，十年来，我们经历了对党和人民事业具有重大现实意义和深远历史意义的三件大事：一是迎来（），二是（），三是（）。", "options": [{"letter": "A", "text": "中国共产党成立一百周年"}, {"letter": "B", "text": "中国特色社会主义进入新时代"}, {"letter": "C", "text": "中国特色社会主义进入高质量发展时代"}, {"letter": "D", "text": "完成脱贫攻坚、全面建成小康社会的历史任务，实现第一个百年奋斗目标"}], "answer": "ABD", "explanation": "本题考查党的二十大报告内容。报告指出：十年来，我们经历了对党和人民事业具有重大现实意义和深远历史意义的三件大事：一是迎来中国共产党成立一百周年，二是中国特色社会主义进入新时代，三是完成脱贫攻坚、全面建成小康社会的历史任务，实现第一个百年奋斗目标。因此选ABD。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1966}, {"num": 1968, "batch": "公共基础知识", "type": "multi", "stem": "党的二十大报告指出，提高全社会文明程度，实施公民道德建设工程，弘扬中华传统美德，加强家庭家教家风建设，推动明大德、守公德、严私德，提高人民道德水准和文明素养，在全社会弘扬劳动精神、奋斗精神、（）。", "options": [{"letter": "A", "text": "奉献精神"}, {"letter": "B", "text": "创新精神"}, {"letter": "C", "text": "创造精神"}, {"letter": "D", "text": "勤俭节约精神"}], "answer": "ACD", "explanation": "本题考查党的二十大报告内容。报告指出：在全社会弘扬劳动精神、奋斗精神、奉献精神、创造精神、勤俭节约精神。题目已列出劳动精神和奋斗精神，剩余三种为奉献精神、创造精神、勤俭节约精神。B项'创新精神'不在报告原文表述之列。因此选ACD。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1967}, {"num": 1969, "batch": "公共基础知识", "type": "multi", "stem": "党的二十大报告指出，我们对新时代党和国家事业发展作出科学完整的战略部署，提出实现中华民族伟大复兴的中国梦，统揽（）。", "options": [{"letter": "A", "text": "伟大斗争"}, {"letter": "B", "text": "伟大工程"}, {"letter": "C", "text": "伟大事业"}, {"letter": "D", "text": "伟大梦想"}], "answer": "ABCD", "explanation": "本题考查党的二十大报告内容。报告指出：我们对新时代党和国家事业发展作出科学完整的战略部署，提出实现中华民族伟大复兴的中国梦，统揽伟大斗争、伟大工程、伟大事业、伟大梦想。'四个伟大'紧密联系、相互贯通、相互作用，其中起决定性作用的是党的建设新的伟大工程。因此选ABCD。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1968}, {"num": 1970, "batch": "公共基础知识", "type": "multi", "stem": "党的二十大报告指出，我们要坚持以（）为宗旨、以（）为根本、以（）为基础、以军事科技文化社会安全为保障、以促进国际安全为依托，统筹外部安全和内部安全、国土安全和国民安全、传统安全和非传统安全、自身安全和共同安全，统筹维护和塑造国家安全，夯实国家安全和社会稳定基层基础，完善参与全球安全治理机制，建设更高水平的平安中国，以新安全格局保障新发展格局。", "options": [{"letter": "A", "text": "人民安全"}, {"letter": "B", "text": "政治安全"}, {"letter": "C", "text": "财产安全"}, {"letter": "D", "text": "经济安全"}], "answer": "ABD", "explanation": "本题考查党的二十大报告中的总体国家安全观。报告指出：坚持以人民安全为宗旨、以政治安全为根本、以经济安全为基础、以军事科技文化社会安全为保障、以促进国际安全为依托。三个空分别对应人民安全、政治安全、经济安全，即ABD项。C项'财产安全'不属于总体国家安全观的表述。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1969}, {"num": 1971, "batch": "公共基础知识", "type": "multi", "stem": "党的二十大报告指出，我们要完善以宪法为核心的中国特色社会主义法律体系，加强宪法实施和监督，加强重点领域、新兴领域、涉外领域立法，推进（）。", "options": [{"letter": "A", "text": "科学立法"}, {"letter": "B", "text": "民主立法"}, {"letter": "C", "text": "依法立法"}, {"letter": "D", "text": "协商立法"}], "answer": "ABC", "explanation": "本题考查党的二十大报告内容。报告指出：推进科学立法、民主立法、依法立法。这是新时代完善中国特色社会主义法律体系的基本要求。科学立法要求遵循客观规律，民主立法要求体现人民意志，依法立法要求在法治轨道上推进立法工作。D项'协商立法'不属于报告原文表述。因此选ABC。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1970}, {"num": 1972, "batch": "公共基础知识", "type": "multi", "stem": "党的二十大报告指出，要构建高水平社会主义市场经济体制，建设现代化产业体系，全面推进（），促进（），推进（）。", "options": [{"letter": "A", "text": "乡村振兴"}, {"letter": "B", "text": "区域协调发展"}, {"letter": "C", "text": "高水平对外开放"}, {"letter": "D", "text": "行政体制改革"}], "answer": "ABC", "explanation": "本题考查党的二十大报告内容。报告指出：要构建高水平社会主义市场经济体制，建设现代化产业体系，全面推进乡村振兴，促进区域协调发展，推进高水平对外开放。三个动词分别对应乡村振兴、区域协调发展、高水平对外开放，即ABC项。D项'行政体制改革'不属于此处内容。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1971}, {"num": 1973, "batch": "公共基础知识", "type": "multi", "stem": "党的二十大报告指出，中国式现代化的本质要求是：坚持（），坚持（），实现高质量发展，发展全过程人民民主，丰富（），实现全体人民共同富裕，促进人与自然和谐共生，推动构建人类命运共同体，创造人类文明新形态。", "options": [{"letter": "A", "text": "中国共产党领导"}, {"letter": "B", "text": "中国特色社会主义"}, {"letter": "C", "text": "人民精神世界"}, {"letter": "D", "text": "人民物质世界"}], "answer": "ABC", "explanation": "本题考查党的二十大报告内容。中国式现代化的本质要求是：坚持中国共产党领导，坚持中国特色社会主义，实现高质量发展，发展全过程人民民主，丰富人民精神世界，实现全体人民共同富裕，促进人与自然和谐共生，推动构建人类命运共同体，创造人类文明新形态。题目中三个空分别对应中国共产党领导、中国特色社会主义、人民精神世界，即ABC项。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1972}, {"num": 1974, "batch": "公共基础知识", "type": "multi", "stem": "邓小平在1992年南方谈话中提出的“三个有利于”是（）", "options": [{"letter": "A", "text": "有利于发展社会主义社会的生产力"}, {"letter": "B", "text": "有利于增强社会主义国家的综合国力"}, {"letter": "C", "text": "有利于提高驾驭社会主义市场经济的能力"}, {"letter": "D", "text": "有利于提高人民的生活水平"}], "answer": "ABD", "explanation": "本题考查邓小平理论知识。1992年邓小平南方谈话提出'三个有利于'标准：是否有利于发展社会主义社会的生产力，是否有利于增强社会主义国家的综合国力，是否有利于提高人民的生活水平。这是判断一切工作是非得失的根本标准。C项'有利于提高驾驭社会主义市场经济的能力'不属于'三个有利于'。因此选ABD。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1973}, {"num": 1975, "batch": "公共基础知识", "type": "multi", "stem": "对A省教育厅的具体行政行为不服的，可以向申请行政复议。", "options": [{"letter": "A", "text": "省教育厅"}, {"letter": "B", "text": "A省人民政府"}, {"letter": "C", "text": "教育部"}, {"letter": "D", "text": "国务院"}], "answer": "BC", "explanation": "本题考查行政复议法知识。根据《行政复议法》规定，对省级政府工作部门（如省教育厅）的具体行政行为不服的，可以向该部门的本级人民政府（A省人民政府）申请行政复议，也可以向上一级主管部门（教育部）申请行政复议。即申请人有选择权，可以向A省人民政府或教育部申请复议。因此选BC。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1974}, {"num": 1976, "batch": "公共基础知识", "type": "multi", "stem": "对于保健食品广告，我国法律做了特殊的限制，下列广告内容违反法律规定的有（）", "options": [{"letter": "A", "text": "服用甲保健食品可以有效预防糖尿病"}, {"letter": "B", "text": "服用乙保健食品是保障老年人骨骼健康所必需"}, {"letter": "C", "text": "服用丙保健食品的效果得到某明星的推荐和证明"}, {"letter": "D", "text": "购买丁保健食品是聪明人都会为健康做的投资"}], "answer": "ABCD", "explanation": "本题考查广告法知识。根据《广告法》第十八条规定，保健食品广告不得含有以下内容：(1)表示功效、安全性的断言或保证（A项'可以有效预防糖尿病'违反）；(2)涉及疾病预防、治疗功能（A项违反）；(3)声称或者暗示该商品为保障健康所必需（B项'是保障骨骼健康所必需'违反）；(4)利用广告代言人作推荐、证明（C项明星推荐违反）。D项属于暗示性宣传，也违反法律规定。因此选ABCD。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1975}, {"num": 1977, "batch": "公共基础知识", "type": "multi", "stem": "根据《中华人民共和国香港特别行政区基本法》的规定，香港特别行政区行政长官（）", "options": [{"letter": "A", "text": "对全国人民代表大会负责"}, {"letter": "B", "text": "对香港特别行政区负责"}, {"letter": "C", "text": "对中央人民政府负责"}, {"letter": "D", "text": "对国务院总理负责"}], "answer": "BC", "explanation": "本题考查香港基本法知识。根据《香港特别行政区基本法》第四十三条规定：香港特别行政区行政长官依照本法的规定对中央人民政府和香港特别行政区负责。即行政长官实行'双负责制'，既对中央人民政府（国务院）负责，也对香港特别行政区负责。B项和C项正确。A项'对全国人大负责'和D项'对国务院总理负责'均不符合基本法规定。因此选BC。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1976}, {"num": 1978, "batch": "公共基础知识", "type": "multi", "stem": "公文常用的表达方式有（）", "options": [{"letter": "A", "text": "说明"}, {"letter": "B", "text": "渲染"}, {"letter": "C", "text": "议论"}, {"letter": "D", "text": "叙述"}], "answer": "ACD", "explanation": "本题考查公文写作知识。公文常用的表达方式主要有三种：说明（对事物或问题进行解释说明）、议论（对问题进行分析和论证）、叙述（对事件或情况进行陈述交代）。B项'渲染'是文学创作中的表现手法，不属于公文常用表达方式。因此选ACD。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1977}, {"num": 1979, "batch": "公共基础知识", "type": "multi", "stem": "公文的“附件说明”包括的内容有（）", "options": [{"letter": "A", "text": "公文附件的名称"}, {"letter": "B", "text": "抄送机关名称"}, {"letter": "C", "text": "公文附件的顺序号"}, {"letter": "D", "text": "公文印制的份数"}], "answer": "AC", "explanation": "本题考查公文格式知识。根据《党政机关公文处理工作条例》和《党政机关公文格式》国家标准，'附件说明'位于正文之后、发文机关署名之前，用于标注公文附件的顺序号和名称。格式为：在正文下空一行左空二字标注'附件：'，后接附件顺序号和名称。B项'抄送机关名称'属于版记部分；D项'公文印制份数'不属于附件说明内容。因此选AC。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1978}, {"num": 1980, "batch": "公共基础知识", "type": "multi", "stem": "古代长城沿线上建有许多关口，下列位于北京的关口有（）", "options": [{"letter": "A", "text": "居庸关"}, {"letter": "B", "text": "雁门关"}, {"letter": "C", "text": "九门口"}, {"letter": "D", "text": "古北口"}], "answer": "AD", "explanation": "本题考查中国地理和历史常识。居庸关位于北京市昌平区，是长城沿线著名关口；古北口位于北京市密云区，也是北京境内的重要关口。A项和D项正确。B项雁门关位于山西省忻州市代县；C项九门口位于辽宁省绥中县，均不在北京境内。因此选AD。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1979}, {"num": 1981, "batch": "公共基础知识", "type": "multi", "stem": "关于公文的用印，下列说法不正确的是（）", "options": [{"letter": "A", "text": "印章应“骑年盖月”"}, {"letter": "B", "text": "印章应压住正文"}, {"letter": "C", "text": "当印章与正文不同处一页时，应在印章页注明“此页无正文”"}, {"letter": "D", "text": "印章不得压成文日期"}], "answer": "BCD", "explanation": "本题考查公文格式中的用印规范。A项'骑年盖月'说法正确，印章应端正、居中下压成文日期，使印章下端压住年份和月份。B项说法不正确，印章不应压住正文；C项说法不正确，2012年新标准已取消'此页无正文'的标注方式；D项说法不正确，印章应当压住成文日期。题目要求选不正确的，因此选BCD。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1980}, {"num": 1982, "batch": "公共基础知识", "type": "multi", "stem": "坚决打赢反腐败斗争攻坚战持久战，腐败是危害党的生命力和战斗力的最大毒瘤，反腐败是最彻底的自我革命。只要存在腐败问题产生的土壤和条件，反腐败斗争就一刻不能停，必须永远吹冲锋号，坚持（）一体推进，以零容忍态度反腐惩恶，决不姑息。", "options": [{"letter": "A", "text": "不敢腐"}, {"letter": "B", "text": "不能腐"}, {"letter": "C", "text": "不愿腐"}, {"letter": "D", "text": "不想腐"}], "answer": "ABD", "explanation": "本题考查党的二十大报告中的反腐败论述。报告指出：坚持不敢腐、不能腐、不想腐一体推进，以零容忍态度反腐惩恶，决不姑息。'不敢腐'是前提，强化震慑；'不能腐'是关键，强化制约；'不想腐'是根本，强化教育。C项'不愿腐'不是报告原文表述。因此选ABD。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1981}, {"num": 1983, "batch": "公共基础知识", "type": "multi", "stem": "教育是民族振兴、社会进步的重要基石，是功在当代、利在千秋的德政工程，对（）具有决定性意义。", "options": [{"letter": "A", "text": "提高人民综合素质"}, {"letter": "B", "text": "促进人的全面发展"}, {"letter": "C", "text": "增强中华民族创新创造活力"}, {"letter": "D", "text": "实现中华民族伟大复兴"}], "answer": "ABCD", "explanation": "本题考查教育论述知识。教育是民族振兴、社会进步的重要基石，对提高人民综合素质、促进人的全面发展、增强中华民族创新创造活力、实现中华民族伟大复兴都具有决定性意义。四个选项分别从不同角度阐述了教育的重大意义，均为正确表述。因此选ABCD。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1982}, {"num": 1984, "batch": "公共基础知识", "type": "multi", "stem": "开展政法队伍教育整顿的目标，是打造一支（）的过硬政法队伍。", "options": [{"letter": "A", "text": "信念坚定"}, {"letter": "B", "text": "执法为民"}, {"letter": "C", "text": "敢于担当"}, {"letter": "D", "text": "清正廉洁"}], "answer": "ABCD", "explanation": "本题考查政法队伍建设知识。开展政法队伍教育整顿的目标是打造一支信念坚定、执法为民、敢于担当、清正廉洁的过硬政法队伍。四项要求分别对应政治信念、宗旨意识、担当精神和廉洁品质，是新时代政法队伍建设的基本标准。因此选ABCD。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1983}, {"num": 1985, "batch": "公共基础知识", "type": "multi", "stem": "前进道路上，必须牢牢把握以下重大原则：坚持和加强党的全面领导，（）。", "options": [{"letter": "A", "text": "坚持中国特色社会主义道路"}, {"letter": "B", "text": "坚持以人民为中心的发展思想"}, {"letter": "C", "text": "坚持深化改革开放"}, {"letter": "D", "text": "坚持发扬斗争精神"}], "answer": "ABCD", "explanation": "本题考查党的二十大报告内容。报告指出前进道路上必须牢牢把握的重大原则：坚持和加强党的全面领导，坚持中国特色社会主义道路，坚持以人民为中心的发展思想，坚持深化改革开放，坚持发扬斗争精神。这五项重大原则是全面建设社会主义现代化国家的基本遵循。因此选ABCD。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1984}, {"num": 1986, "batch": "公共基础知识", "type": "multi", "stem": "社会主义在中国经过近70年的发展，已经充分让人民建立起了（）", "options": [{"letter": "A", "text": "制度自信"}, {"letter": "B", "text": "理论自信"}, {"letter": "C", "text": "道路自信"}, {"letter": "D", "text": "文化自信"}], "answer": "ABCD", "explanation": "本题考查'四个自信'知识。中国特色社会主义'四个自信'包括：道路自信、理论自信、制度自信、文化自信。这是习近平在庆祝中国共产党成立95周年大会上明确提出的。四个自信是对中国特色社会主义的正确性和优越性的坚定信念。因此选ABCD。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1985}, {"num": 1987, "batch": "公共基础知识", "type": "multi", "stem": "俗话说“麻雀虽小，五脏俱全”，所以人们在进行调查研究工作时，应该抓住典型，学会“解剖麻雀”，达到举一反三、“窥一斑而知全豹”的效果。这体现的哲学原理有（）", "options": [{"letter": "A", "text": "矛盾的普遍性和矛盾的特殊性之间的辩证关系"}, {"letter": "B", "text": "认识事物的过程通常是先由个性到共性，再由共性到个性"}, {"letter": "C", "text": "意识的能动性能使人认识和发展规律"}, {"letter": "D", "text": "人们能够根据事物的固有联系来建立新的联系"}], "answer": "AB", "explanation": "本题考查马克思主义哲学原理。'解剖麻雀'体现了从个别（特殊）中认识一般（普遍）的方法论。A项正确，体现了矛盾普遍性与特殊性的辩证关系——通过典型个案（特殊性）来认识一般规律（普遍性）；B项正确，体现了认识过程从个性到共性、再从共性到个性的辩证运动。C项错误，规律不能被'发展'；D项与题意无关。因此选AB。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1986}, {"num": 1988, "batch": "公共基础知识", "type": "multi", "stem": "太阳系目前发现有八大行星，下列说法中正确的有（）", "options": [{"letter": "A", "text": "木星是太阳系质量最大的行量"}, {"letter": "B", "text": "按照离太阳的距离由近及远，地球是第五颗行星"}, {"letter": "C", "text": "水星是距太阳最近的行星"}, {"letter": "D", "text": "火星与地球相邻"}], "answer": "ACD", "explanation": "本题考查天文常识。A项正确，木星是太阳系中质量最大的行星，质量约为其他七大行星质量总和的2.5倍；C项正确，水星是距太阳最近的行星；D项正确，火星位于地球轨道外侧，与地球相邻。B项错误，按距太阳由近及远排列，地球是第三颗行星（水星、金星、地球、火星、木星、土星、天王星、海王星），不是第五颗。因此选ACD。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1987}, {"num": 1989, "batch": "公共基础知识", "type": "multi", "stem": "体检报告中的指标值往往反映了人体的健康状况，下列说法正确的有（）", "options": [{"letter": "A", "text": "血小板减少意味着出血的危险性增加"}, {"letter": "B", "text": "高密度胆固醇升高会增加患冠心病的风险"}, {"letter": "C", "text": "血红蛋白是判断贫血的重要指标之一"}, {"letter": "D", "text": "谷丙转氨酶和谷草转氨酶同时升高可能是肝细胞受损"}], "answer": "ACD", "explanation": "本题考查医学常识。A项正确，血小板具有止血功能，减少则出血风险增加；C项正确，血红蛋白含量是判断贫血的重要指标；D项正确，谷丙转氨酶和谷草转氨酶是肝功能重要指标，同时升高提示肝细胞受损。B项错误，高密度脂蛋白胆固醇（HDL-C）是'好胆固醇'，其升高反而降低患冠心病风险；低密度脂蛋白胆固醇（LDL-C）升高才增加冠心病风险。因此选ACD。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1988}, {"num": 1990, "batch": "公共基础知识", "type": "multi", "stem": "我们党坚持把马克思主义基本原理同中国具体实际结合起来，在推进马克思主义中国化的历史进程中产生了两大理论成果，分别是（）", "options": [{"letter": "A", "text": "毛泽东思想"}, {"letter": "B", "text": "邓小平理论"}, {"letter": "C", "text": "“三个代表”重要思想"}, {"letter": "D", "text": "中国特色社会主义理论体系"}], "answer": "AD", "explanation": "本题考查马克思主义中国化的理论成果。中国共产党在推进马克思主义中国化的历史进程中产生了两大理论成果：第一大理论成果是毛泽东思想，第二大理论成果是中国特色社会主义理论体系（包括邓小平理论、'三个代表'重要思想、科学发展观、习近平新时代中国特色社会主义思想）。因此选AD。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1989}, {"num": 1991, "batch": "公共基础知识", "type": "multi", "stem": "习近平在二十届中共中央政治局常委同中外记者见面时的讲话中指出，我们要始终（），不断把人民对美好生活的向往变为现实。", "options": [{"letter": "A", "text": "与人民风雨同舟"}, {"letter": "B", "text": "与人民心心相印"}, {"letter": "C", "text": "想人民之所想"}, {"letter": "D", "text": "行人民之所嘱"}], "answer": "ABCD", "explanation": "本题考查习近平重要讲话知识。习近平在二十届中共中央政治局常委同中外记者见面时指出：我们要始终与人民风雨同舟、与人民心心相印，想人民之所想，行人民之所嘱，不断把人民对美好生活的向往变为现实。四句话体现了以人民为中心的发展思想，强调党与人民群众的血肉联系。因此选ABCD。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1990}, {"num": 1992, "batch": "公共基础知识", "type": "multi", "stem": "习近平指出，在实践中，我们就教育改革发展提出一系列新理念新思想新观点，主要有（），坚持扎根中国大地办教育，坚持以人民为中心发展教育，坚持深化教育改革创新，坚持把服务中华民族伟大复兴作为教育的重要使命，坚持把教师队伍建设作为基础工作。", "options": [{"letter": "A", "text": "坚持党对教育事业的全面领导"}, {"letter": "B", "text": "坚持把立德树人作为根本任务"}, {"letter": "C", "text": "坚持优先发展教育事业"}, {"letter": "D", "text": "坚持社会主义办学方向"}], "answer": "ABCD", "explanation": "本题考查习近平关于教育的重要论述。习近平提出的教育改革发展'九个坚持'包括：坚持党对教育事业的全面领导，坚持把立德树人作为根本任务，坚持优先发展教育事业，坚持社会主义办学方向，坚持扎根中国大地办教育，坚持以人民为中心发展教育，坚持深化教育改革创新，坚持把服务中华民族伟大复兴作为教育的重要使命，坚持把教师队伍建设作为基础工作。题目中列出的四项均在前四个'坚持'之中。因此选ABCD。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1991}, {"num": 1993, "batch": "公共基础知识", "type": "multi", "stem": "下列表述中，体现“和谐”哲学思想的有（）", "options": [{"letter": "A", "text": "动中有静，静中有动"}, {"letter": "B", "text": "和而不同"}, {"letter": "C", "text": "万物并育而不相害，道并行而不悖"}, {"letter": "D", "text": "真理和谬误是相互包含的"}], "answer": "ABCD", "explanation": "本题考查哲学中的'和谐'思想。A项'动中有静，静中有动'体现了动静的辩证统一，是和谐思想的体现；B项'和而不同'直接体现了和谐包容的思想；C项'万物并育而不相害，道并行而不悖'出自《中庸》，体现了万物和谐共生的思想；D项'真理和谬误相互包含'体现了对立统一的和谐观。四项均从不同角度体现了'和谐'的哲学思想。因此选ABCD。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1992}, {"num": 1994, "batch": "公共基础知识", "type": "multi", "stem": "下列古诗词中含我国民间节令，其中节令相同的是（）", "options": [{"letter": "A", "text": "去年元夜时，花市灯如昼"}, {"letter": "B", "text": "银烛秋光冷画屏，轻罗小扇扑流萤"}, {"letter": "C", "text": "东风夜放花千树，更吹落、星如雨"}, {"letter": "D", "text": "爆竹声中一岁除，春风送暖入屠苏"}], "answer": "AC", "explanation": "本题考查古代文学中的节令知识。A项'去年元夜时，花市灯如昼'出自欧阳修《生查子》，'元夜'即正月十五元宵节；C项'东风夜放花千树'出自辛弃疾《青玉案·元夕》，描写的也是元宵节花灯盛景。B项描写的是七夕节（秋夜扑流萤）；D项'爆竹声中一岁除'描写的是春节。A项和C项节令相同，均为元宵节。因此选AC。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1993}, {"num": 1995, "batch": "公共基础知识", "type": "multi", "stem": "下列关于法的基本特征的理解，正确的有（）", "options": [{"letter": "A", "text": "法具有权利义务的一致性"}, {"letter": "B", "text": "法由专门的国家机关制定或认可"}, {"letter": "C", "text": "法规可以调整行为，也可以调整思想"}, {"letter": "D", "text": "法与道德、习惯不同，其实施由国家强制力予以保障"}], "answer": "ABD", "explanation": "本题考查法理学知识。A项正确，法以权利和义务为内容，具有权利义务的一致性；B项正确，法由国家专门机关制定或认可，这是法区别于其他社会规范的重要特征；D项正确，法以国家强制力为后盾保证实施，这是法区别于道德、习惯的重要特征。C项错误，法只调整人的行为，不调整人的思想，思想自由不受法律约束。因此选ABD。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1994}, {"num": 1996, "batch": "公共基础知识", "type": "multi", "stem": "下列关于我国社会主义基本经济制度的表述正确的有（）", "options": [{"letter": "A", "text": "公有制经济和非公有制经济都是社会主义市场经济的重要组成部分，都是我国经济社会发展的重要基础"}, {"letter": "B", "text": "必须毫不动摇巩固和发展公有制经济，坚持公有制主体地位，发挥国有经济主导作用，推动国有资本做强做优做大"}, {"letter": "C", "text": "必须毫不动摇鼓励、支持、引导非公有制经济发展，激发非公有制经济活力和创造力"}, {"letter": "D", "text": "我国民营经济只能壮大、不能弱化，而且要走向更加广阔的舞台"}], "answer": "ABCD", "explanation": "本题考查我国基本经济制度知识。A项正确，公有制经济和非公有制经济都是社会主义市场经济的重要组成部分；B项正确，必须毫不动摇巩固和发展公有制经济；C项正确，必须毫不动摇鼓励、支持、引导非公有制经济发展；D项正确，民营经济只能壮大不能弱化。四个选项全面准确地阐述了我国社会主义基本经济制度的内涵和要求。因此选ABCD。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1995}, {"num": 1997, "batch": "公共基础知识", "type": "multi", "stem": "下列关于中国古琴的说法中，正确的是（）", "options": [{"letter": "A", "text": "古琴是我国现存的最古老的弹拨乐器之一"}, {"letter": "B", "text": "俞伯牙、钟子期因古琴曲《高山流水》而成为知音的故事广为流传"}, {"letter": "C", "text": "古琴名曲主要有《广陵散》、《平沙落雁》等"}, {"letter": "D", "text": "古琴艺术是我国古代精神文化在音乐方面的主要代表之一"}], "answer": "ABCD", "explanation": "本题考查中国传统文化中的古琴知识。A项正确，古琴是中国最古老的弹拨乐器之一，有三千多年历史；B项正确，伯牙鼓琴、子期知音的故事是中国最著名的古琴文化典故；C项正确，《广陵散》《平沙落雁》《梅花三弄》等都是古琴名曲；D项正确，古琴艺术是中国古代精神文化在音乐方面的主要代表，2003年被联合国教科文组织列为人类口头和非物质遗产代表作。因此选ABCD。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1996}, {"num": 1998, "batch": "公共基础知识", "type": "multi", "stem": "下列历史事件发生在江西这片红土地的是（）。", "options": [{"letter": "A", "text": "秋收起义"}, {"letter": "B", "text": "南昌起义"}, {"letter": "C", "text": "八七会议"}, {"letter": "D", "text": "中华苏维埃共和国临时中央政府成立"}], "answer": "ABD", "explanation": "本题考查中国革命史知识。A项秋收起义主要发生在湖南江西边界地区；B项南昌起义发生在江西省南昌市；D项中华苏维埃共和国临时中央政府成立于江西瑞金。C项八七会议于1927年在湖北汉口召开，不在江西。因此发生在江西的是ABD三项。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1997}, {"num": 1999, "batch": "公共基础知识", "type": "multi", "stem": "下列属于中共党史军史上的三大起义的是（）。", "options": [{"letter": "A", "text": "南昌起义"}, {"letter": "B", "text": "秋收起义"}, {"letter": "C", "text": "平江起义"}, {"letter": "D", "text": "广州起义"}], "answer": "ABD", "explanation": "本题考查中共党史知识。中共党史军史上的三大起义是指：南昌起义（1927年8月1日）、秋收起义（1927年9月9日）、广州起义（1927年12月11日）。这三次起义是中国共产党在大革命失败后，为挽救革命、反抗国民党反动统治而发动的最重要的武装起义。C项平江起义（1928年7月）虽然也是重要起义，但不属于'三大起义'。因此选ABD。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1998}, {"num": 2000, "batch": "公共基础知识", "type": "multi", "stem": "下列选项中，涉及植物呼吸活动的有（）", "options": [{"letter": "A", "text": "大棚水果栽培中夜间适当降温"}, {"letter": "B", "text": "适当延长光照时间提高蔬菜产量"}, {"letter": "C", "text": "通过立体栽培提高土地利用率"}, {"letter": "D", "text": "给土壤松土以促进植物根部生长"}], "answer": "AD", "explanation": "本题考查生物学中的植物呼吸作用知识。A项正确，夜间适当降温可以降低植物的呼吸作用强度，减少有机物消耗，有利于水果积累养分；D项正确，给土壤松土可以增加土壤中的氧气含量，促进根部的有氧呼吸，有利于根部生长和吸收养分。B项延长光照时间主要影响光合作用而非呼吸作用；C项立体栽培提高土地利用率与呼吸作用无直接关系。因此选AD。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 1999}, {"num": 2001, "batch": "公共基础知识", "type": "multi", "stem": "下面属于公文必备的基本组成部分有（）", "options": [{"letter": "A", "text": "发文种类"}, {"letter": "B", "text": "主送机关"}, {"letter": "C", "text": "标题"}, {"letter": "D", "text": "成文日期"}], "answer": "ACD", "explanation": "公文的基本组成部分包括发文种类（文种）、标题和成文日期，这三项是任何公文都不可缺少的要素。主送机关并非所有公文的必备部分，如公告、通告等普发性公文可不标注主送机关。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 2000}, {"num": 2002, "batch": "公共基础知识", "type": "multi", "stem": "行政许可作为事先对经济和社会活动进行干预的一项重要的行政权力和管理方式，其设定必须特别慎重。下列选项中，哪些属于设定行政许可应遵循的原则（）", "options": [{"letter": "A", "text": "应当遵循经济和社会发展规律"}, {"letter": "B", "text": "要有利用维护公共利益和社会秩序"}, {"letter": "C", "text": "要有利于发挥公民、法人或者其他组织的积极性、主动性"}, {"letter": "D", "text": "应当有利于行政机关对其直接管理的事业单位的人事、财务、外事等事项的审批"}], "answer": "ABC", "explanation": "根据《行政许可法》第11条规定，设定行政许可应当遵循经济和社会发展规律，有利于维护公共利益和社会秩序，有利于发挥公民、法人或者其他组织的积极性、主动性。D项属于行政机关内部审批事项，不属于行政许可设定原则的内容。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 2001}, {"num": 2003, "batch": "公共基础知识", "type": "multi", "stem": "要落实新时代党的建设总要求，健全全面从严治党体系，全面推进党的（），使我们党坚守初心使命，始终成为中国特色社会主义事业的坚强领导核心。", "options": [{"letter": "A", "text": "自我净化"}, {"letter": "B", "text": "自我完善"}, {"letter": "C", "text": "自我革新"}, {"letter": "D", "text": "自我提高"}], "answer": "ABCD", "explanation": "党的二十大报告明确提出，要落实新时代党的建设总要求，健全全面从严治党体系，全面推进党的自我净化、自我完善、自我革新、自我提高，即'四个自我'，使党始终成为中国特色社会主义事业的坚强领导核心。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 2002}, {"num": 2004, "batch": "公共基础知识", "type": "multi", "stem": "以下属于习近平总书记教育重要论述的科学内涵是（）。", "options": [{"letter": "A", "text": "坚持党对教育事业的全面领导"}, {"letter": "B", "text": "坚持把立德树人作为根本任务"}, {"letter": "C", "text": "坚持优先发展教育事业"}, {"letter": "D", "text": "坚持把教师队伍建设作为基础工作"}], "answer": "ABCD", "explanation": "习近平总书记教育重要论述涵盖多个核心要点，包括坚持党对教育事业的全面领导、坚持把立德树人作为根本任务、坚持优先发展教育事业、坚持把教师队伍建设作为基础工作等，四个选项均属于其科学内涵。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 2003}, {"num": 2005, "batch": "公共基础知识", "type": "multi", "stem": "在1919年至1949年新中国成立以前，压在中国人民身上的“三座大山”是（）。", "options": [{"letter": "A", "text": "帝国主义"}, {"letter": "B", "text": "封建主义"}, {"letter": "C", "text": "官僚资本主义"}, {"letter": "D", "text": "民族资本主义"}], "answer": "ABC", "explanation": "1919年至1949年新中国成立前，压在中国人民身上的'三座大山'是帝国主义、封建主义和官僚资本主义。民族资本主义不属于压迫中国人民的力量，民族资产阶级在民主革命中具有两面性。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 2004}, {"num": 2006, "batch": "公共基础知识", "type": "multi", "stem": "在处理国家之间的关系上，中国坚持的原则是（）", "options": [{"letter": "A", "text": "相互尊重主权和领土完整"}, {"letter": "B", "text": "互不侵犯"}, {"letter": "C", "text": "平等互利、和平共处"}, {"letter": "D", "text": "互不干涉内政"}], "answer": "ABCD", "explanation": "中国在处理国际关系上坚持和平共处五项原则，即相互尊重主权和领土完整、互不侵犯、互不干涉内政、平等互利、和平共处。四个选项完整涵盖了和平共处五项原则的全部内容。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 2005}, {"num": 2007, "batch": "公共基础知识", "type": "multi", "stem": "在党史学习教育动员大会上，习近平总书记强调全党同志要做到（）", "options": [{"letter": "A", "text": "学史明理"}, {"letter": "B", "text": "学史增信"}, {"letter": "C", "text": "学史崇德"}, {"letter": "D", "text": "学史力行"}], "answer": "ABCD", "explanation": "2021年党史学习教育动员大会上，习近平总书记强调全党同志要做到学史明理、学史增信、学史崇德、学史力行，即'学史四字要求'，这是党史学习教育的总要求。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 2006}, {"num": 2008, "batch": "公共基础知识", "type": "multi", "stem": "在长期的革命、建设、改革过程中，我国已经结成的爱国统一战线包括（）", "options": [{"letter": "A", "text": "全体社会主义劳动者"}, {"letter": "B", "text": "社会主义事业的建设者"}, {"letter": "C", "text": "拥护社会主义的爱国者"}, {"letter": "D", "text": "拥护祖国统一和致力于中华民族伟大复兴的爱国者"}], "answer": "ABCD", "explanation": "根据《宪法》序言规定，在长期的革命、建设、改革过程中，我国已经结成由中国共产党领导的，有各民主党派和各人民团体参加的，包括全体社会主义劳动者、社会主义事业的建设者、拥护社会主义的爱国者、拥护祖国统一和致力于中华民族伟大复兴的爱国者的广泛的爱国统一战线。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 2007}, {"num": 2009, "batch": "公共基础知识", "type": "multi", "stem": "政法队伍教育整顿“三大主题”是（）", "options": [{"letter": "A", "text": "刮骨疗毒式的自我革命"}, {"letter": "B", "text": "激浊扬清式的“延安整风”"}, {"letter": "C", "text": "铸魂扬威式的主题教育"}, {"letter": "D", "text": "自上而下式的集体学习"}], "answer": "ABC", "explanation": "政法队伍教育整顿的'三大主题'是：刮骨疗毒式的自我革命、激浊扬清式的'延安整风'、铸魂扬威式的主题教育。D项'自上而下式的集体学习'不属于三大主题。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 2008}, {"num": 2010, "batch": "公共基础知识", "type": "multi", "stem": "政法队伍教育整顿的任务包括（）", "options": [{"letter": "A", "text": "筑牢政治忠诚"}, {"letter": "B", "text": "清除害群之马"}, {"letter": "C", "text": "整治顽瘴痼疾"}, {"letter": "D", "text": "弘扬英模精神"}], "answer": "ABCD", "explanation": "政法队伍教育整顿的四项任务是：筑牢政治忠诚、清除害群之马、整治顽瘴痼疾、弘扬英模精神。这四项任务涵盖了政治建设、队伍净化、作风整顿和典型引领等方面。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 2009}, {"num": 2011, "batch": "公共基础知识", "type": "multi", "stem": "中共中央办公厅、国务院办公厅日前印发的《深化农村改革综合性实施方案》指出，要从提高农村改革的系统性、整体性、协同性出发，聚焦五大领域，进一步推进深化农村改革。下列选项中，属于这五大领域的是（）", "options": [{"letter": "A", "text": "农村集体产权制度"}, {"letter": "B", "text": "农业经营制度"}, {"letter": "C", "text": "农业支持保护制度"}, {"letter": "D", "text": "城乡发展一体化体制机"}], "answer": "ABCD", "explanation": "《深化农村改革综合性实施方案》指出聚焦五大领域推进农村改革，包括农村集体产权制度、农业经营制度、农业支持保护制度、城乡发展一体化体制机制和农村社会治理创新。题目中ABCD四项均属于五大领域。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 2010}, {"num": 2012, "batch": "公共基础知识", "type": "multi", "stem": "中国工农红军长征胜利的重要意义有（）。", "options": [{"letter": "A", "text": "宣告了国民党围追堵截红军的破产"}, {"letter": "B", "text": "实现了红军的战略大转移"}, {"letter": "C", "text": "宣传了中国共产党的政治主张"}, {"letter": "D", "text": "在沿途播下了革命的种子，鼓舞了广大人民群众"}], "answer": "ABCD", "explanation": "中国工农红军长征胜利的伟大意义包括：宣告了国民党围追堵截红军的破产，实现了红军的战略大转移，宣传了中国共产党的政治主张，在沿途播下了革命的种子、鼓舞了广大人民群众。四个选项均正确。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 2011}, {"num": 2013, "batch": "公共基础知识", "type": "multi", "stem": "中国共产党在中国新民主主义革命中战胜敌人的三大法宝是（）", "options": [{"letter": "A", "text": "统一战线"}, {"letter": "B", "text": "工农割据"}, {"letter": "C", "text": "武装斗争"}, {"letter": "D", "text": "党的建设"}], "answer": "ACD", "explanation": "毛泽东在《〈共产党人〉发刊词》中指出，统一战线、武装斗争、党的建设是中国共产党在中国革命中战胜敌人的三个法宝。工农割据不属于三大法宝。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 2012}, {"num": 2014, "batch": "公共基础知识", "type": "multi", "stem": "中国式现代化是人口规模巨大的现代化，是（）。", "options": [{"letter": "A", "text": "全体人民共同富裕的现代化"}, {"letter": "B", "text": "物质文明和精神文明相协调的现代化"}, {"letter": "C", "text": "人与自然和谐共生的现代化"}, {"letter": "D", "text": "走和平发展道路的现代化"}], "answer": "ABCD", "explanation": "党的二十大报告概括了中国式现代化的五个特征：人口规模巨大的现代化、全体人民共同富裕的现代化、物质文明和精神文明相协调的现代化、人与自然和谐共生的现代化、走和平发展道路的现代化。四个选项均正确。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 2013}, {"num": 2015, "batch": "公共基础知识", "type": "multi", "stem": "中国特色社会主义理论体系，就是包括（）等重大战略思想在内的科学理论体系。", "options": [{"letter": "A", "text": "毛泽东思想"}, {"letter": "B", "text": "邓小平理论"}, {"letter": "C", "text": "“三个代表”重要思想"}, {"letter": "D", "text": "科学发展观"}], "answer": "BCD", "explanation": "中国特色社会主义理论体系包括邓小平理论、'三个代表'重要思想以及科学发展观等重大战略思想。毛泽东思想不属于中国特色社会主义理论体系的组成部分，二者是不同的理论范畴。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 2014}, {"num": 2016, "batch": "公共基础知识", "type": "multi", "stem": "总书记在全国教育大会上强调，教育是民族振兴、社会进步的重要基石，是功在当代、利在千秋的德政工程，对（）具有决定性意义。", "options": [{"letter": "A", "text": "提高人民综合素质"}, {"letter": "B", "text": "促进人的全面发展"}, {"letter": "C", "text": "增强中华民族创新创造活力"}, {"letter": "D", "text": "实现中华民族伟大复兴"}], "answer": "ABCD", "explanation": "总书记在全国教育大会上强调，教育对提高人民综合素质、促进人的全面发展、增强中华民族创新创造活力、实现中华民族伟大复兴具有决定性意义。四个选项均出自原文论述。", "tags": "广东辅警笔试 多选题 公共基础知识", "_idx": 2015}, {"num": 2017, "batch": "公共基础知识", "type": "bool", "stem": "“路漫漫其修远兮，吾将上下而求索”是孔子的名言。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "'路漫漫其修远兮，吾将上下而求索'出自屈原的《离骚》，并非孔子的名言。屈原是战国时期楚国诗人、政治家，此句表达了追求真理、不懈探索的精神。", "tags": "广东辅警笔试 判断题 公共基础知识", "_idx": 2016}, {"num": 2018, "batch": "公共基础知识", "type": "bool", "stem": "“七月流火，九月授衣”中的“七月流火”指的是天气逐渐炎热。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "'七月流火'出自《诗经·豳风·七月》，其中'火'指大火星（心宿二），'流'指西沉。'七月流火'意为农历七月大火星向西坠落，表示天气逐渐转凉，而非天气炎热。", "tags": "广东辅警笔试 判断题 公共基础知识", "_idx": 2017}, {"num": 2019, "batch": "公共基础知识", "type": "bool", "stem": "“修身齐家治国平天下”体现法家学派的人生理想和志趣。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "'修身齐家治国平天下'出自《礼记·大学》，体现的是儒家学派的人生理想和志趣，而非法家。儒家强调个人修养与社会治理的递进关系，法家则主张以法治国、严刑峻法。", "tags": "广东辅警笔试 判断题 公共基础知识", "_idx": 2018}, {"num": 2020, "batch": "公共基础知识", "type": "bool", "stem": "2021年全国政法队伍教育整顿自下而上分三批进行。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "2021年全国政法队伍教育整顿是自上而下分三批进行，而非自下而上。第一批为市县两级，第二批为中央政法委、中央政法单位及省级政法单位，第三批为省级以下。题目表述顺序错误。", "tags": "广东辅警笔试 判断题 公共基础知识", "_idx": 2019}, {"num": 2021, "batch": "公共基础知识", "type": "bool", "stem": "爱国守法主要规范公民和国家的关系，守法是爱国规范的延伸，是公民对国家道德责任的“底线”。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "爱国守法是公民基本道德规范之一，主要规范公民与国家的关系。守法是爱国规范的延伸，是公民对国家道德责任的'底线'，体现了公民对国家最基本的道德义务和法律责任。", "tags": "广东辅警笔试 判断题 公共基础知识", "_idx": 2020}, {"num": 2022, "batch": "公共基础知识", "type": "bool", "stem": "初出茅庐的成语故事出自《三国演义》。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "'初出茅庐'的成语典故出自《三国演义》，讲的是诸葛亮初次离开隆中草庐辅佐刘备，即博望坡之战中初显才华的故事。后比喻刚进入社会或刚到工作岗位，缺乏经验。", "tags": "广东辅警笔试 判断题 公共基础知识", "_idx": 2021}, {"num": 2023, "batch": "公共基础知识", "type": "bool", "stem": "从文化产业角度看，《爸爸去哪儿》《我是歌手》《中国好声音》《缘来非诚勿扰》之类电视综艺节目都是资本面向文化市场制造的商品。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "从文化产业角度看，电视综艺节目如《爸爸去哪儿》《我是歌手》等，都是文化生产者面向文化市场制造的文化商品，具有使用价值和交换价值，体现了文化产品的商品属性。", "tags": "广东辅警笔试 判断题 公共基础知识", "_idx": 2022}, {"num": 2024, "batch": "公共基础知识", "type": "bool", "stem": "党的二十大报告提出，中国式现代化，是中国共产党领导的社会主义现代化，既有各国现代化的共同特征，更有基于自己国情的中国特色。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "党的二十大报告明确指出，中国式现代化是中国共产党领导的社会主义现代化，既有各国现代化的共同特征，更有基于自己国情的中国特色。这一论述准确揭示了中国式现代化的本质属性。", "tags": "广东辅警笔试 判断题 公共基础知识", "_idx": 2023}, {"num": 2025, "batch": "公共基础知识", "type": "bool", "stem": "党的二十大报告指出，不断谱写马克思主义中国化时代化新篇章，是当代中国共产党人的庄严历史责任。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "党的二十大报告指出，不断谱写马克思主义中国化时代化新篇章，是当代中国共产党人的庄严历史责任。这体现了党对理论创新的高度重视和持续推进马克思主义发展的坚定决心。", "tags": "广东辅警笔试 判断题 公共基础知识", "_idx": 2024}, {"num": 2026, "batch": "公共基础知识", "type": "bool", "stem": "党的二十大报告指出，全面依法治国是国家治理的一场深刻革命，关系党执政兴国，关系人民幸福安康，关系党和国家长治久安。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "党的二十大报告指出，全面依法治国是国家治理的一场深刻革命，关系党执政兴国，关系人民幸福安康，关系党和国家长治久安。这一论述深刻阐明了全面依法治国的重大战略意义。", "tags": "广东辅警笔试 判断题 公共基础知识", "_idx": 2025}, {"num": 2027, "batch": "公共基础知识", "type": "bool", "stem": "党的二十大报告指出，我们深入贯彻以人民为中心的发展思想，在幼有所育、学有所教、劳有所得、病有所医、老有所养、住有所居、弱有所扶上持续用力，建成世界上规模最大的教育体系、社会保障体系、医疗卫生体系，人民群众获得感、幸福感、安全感更加充实、更有保障、更可持续，共同富裕取得新成效。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "党的二十大报告总结了以人民为中心的发展思想在民生领域的实践成就，指出在幼有所育、学有所教、劳有所得、病有所医、老有所养、住有所居、弱有所扶上持续用力，建成世界上规模最大的教育体系、社会保障体系、医疗卫生体系。表述正确。", "tags": "广东辅警笔试 判断题 公共基础知识", "_idx": 2026}, {"num": 2028, "batch": "公共基础知识", "type": "bool", "stem": "党的二十大报告指出，我们要加快发展方式绿色转型，实施全面节约战略，发展绿色低碳产业，倡导绿色消费，推动形成绿色低碳的生产方式和生活方式。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "党的二十大报告指出，要加快发展方式绿色转型，实施全面节约战略，发展绿色低碳产业，倡导绿色消费，推动形成绿色低碳的生产方式和生活方式。这是推进生态文明建设的重要部署。", "tags": "广东辅警笔试 判断题 公共基础知识", "_idx": 2027}, {"num": 2029, "batch": "公共基础知识", "type": "bool", "stem": "党的二十大报告指出，我们要健全国家安全体系，完善高效权威的国家安全领导体制，完善国家安全法治体系、战略体系、政策体系、风险监测预警体系、国家应急管理体系，构建全域联动、立体高效的国家安全防护体系。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "党的二十大报告对健全国家安全体系作出部署，要求完善高效权威的国家安全领导体制，完善国家安全法治体系、战略体系、政策体系、风险监测预警体系、国家应急管理体系，构建全域联动、立体高效的国家安全防护体系。表述正确。", "tags": "广东辅警笔试 判断题 公共基础知识", "_idx": 2028}, {"num": 2030, "batch": "公共基础知识", "type": "bool", "stem": "党的二十大报告指出，中国共产党为什么能，中国特色社会主义为什么好，归根到底是党执政兴行，是人民群众行。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "党的二十大报告原文指出：'中国共产党为什么能，中国特色社会主义为什么好，归根到底是马克思主义行，是中国化时代化的马克思主义行。'题目中'归根到底是党执政兴行，是人民群众行'的表述与原文不符，属于篡改。", "tags": "广东辅警笔试 判断题 公共基础知识", "_idx": 2029}, {"num": 2031, "batch": "公共基础知识", "type": "bool", "stem": "党和国家确立和坚持马克思主义在意识形态领域指导地位的根本制度，社会主义核心价值观广泛传播，中华优秀传统文化得到创造性转化、创新性发展，文化事业日益繁荣，网络生态持续向好，意识形态领域形势发生全面性、彻底性转变。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "党的二十大报告原文表述为'意识形态领域形势发生全局性、根本性转变'，而非'全面性、彻底性转变'。题目用词与报告原文不一致，属于偷换概念。", "tags": "广东辅警笔试 判断题 公共基础知识", "_idx": 2030}, {"num": 2032, "batch": "公共基础知识", "type": "bool", "stem": "党和国家以巨大的政治勇气全面深化从严，许多领域实现历史性变革、系统性重塑、整体性重构，中国特色社会主义制度更加成熟更加定型，国家治理体系和治理能力现代化水平明显提高。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "党的二十大报告原文为'以巨大的政治勇气全面深化改革'，而非'全面深化从严'。题目将'改革'替换为'从严'，表述错误。全面深化改革是新时代的重大战略部署。", "tags": "广东辅警笔试 判断题 公共基础知识", "_idx": 2031}, {"num": 2033, "batch": "公共基础知识", "type": "bool", "stem": "党史学习教育中的“四史”是指中共党史、新中国史、改革开放史、社会主义发展史。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "党史学习教育中的'四史'是指中共党史、新中国史、改革开放史、社会主义发展史。学习'四史'是牢记初心使命、坚定理想信念的重要途径，也是党员干部教育培训的重要内容。", "tags": "广东辅警笔试 判断题 公共基础知识", "_idx": 2032}, {"num": 2034, "batch": "公共基础知识", "type": "bool", "stem": "厄尔尼诺现象是一种在世界范围内造成周期性极端天气的气候现象，其表象是发生厄尔尼诺现象时，太平洋中、东部海域大范围内海水温度异常升高，海水水位上涨。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "厄尔尼诺现象是指太平洋中、东部海域大范围内海水温度异常升高、海水水位上涨的气候现象，会造成全球性极端天气。这一描述符合气象学上对厄尔尼诺现象的定义。", "tags": "广东辅警笔试 判断题 公共基础知识", "_idx": 2033}, {"num": 2035, "batch": "公共基础知识", "type": "bool", "stem": "二十大报告指出，我国社会的主要矛盾不是人民日益增长的美好生活需要和不平衡不充分的发展之间的矛盾。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "党的二十大报告明确指出，我国社会主要矛盾是人民日益增长的美好生活需要和不平衡不充分的发展之间的矛盾。题目用'不是'进行否定，与报告原文相悖，表述错误。", "tags": "广东辅警笔试 判断题 公共基础知识", "_idx": 2034}, {"num": 2036, "batch": "公共基础知识", "type": "bool", "stem": "飞行距离较远时，民航飞机一般适宜在对流层飞行。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "民航飞机远程飞行时一般在平流层飞行，而非对流层。平流层气流平稳、能见度好、空气阻力小，有利于飞行安全和节省燃料。对流层气流不稳定，天气现象复杂，不适合高空飞行。", "tags": "广东辅警笔试 判断题 公共基础知识", "_idx": 2035}, {"num": 2037, "batch": "公共基础知识", "type": "bool", "stem": "根据宪法和法律规定，我国各级人民政府是各级国家权力机关的执行机关。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《宪法》第105条规定，地方各级人民政府是地方各级国家权力机关的执行机关，是地方各级国家行政机关。各级人民政府由同级人民代表大会产生，对其负责并报告工作。", "tags": "广东辅警笔试 判断题 公共基础知识", "_idx": 2036}, {"num": 2038, "batch": "公共基础知识", "type": "bool", "stem": "国内生产总值(GDP)是指一个国家或地区在一定时期内生产的全部最终产品和劳务的价值。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "国内生产总值（GDP）是指一个国家或地区在一定时期内（通常为一年）生产的全部最终产品和劳务的价值总和。它是衡量一个国家或地区经济规模和经济发展水平的核心指标。", "tags": "广东辅警笔试 判断题 公共基础知识", "_idx": 2037}, {"num": 2039, "batch": "公共基础知识", "type": "bool", "stem": "纪要常常采用第三人称写法，如“会议讨论了”“会议认为”“会议强调”“会议同意”等。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "纪要是记载会议主要精神和议定事项的公文，通常采用第三人称写法，如'会议讨论了''会议认为''会议强调''会议同意'等。这种写法体现了纪要的客观性和集体意志性。", "tags": "广东辅警笔试 判断题 公共基础知识", "_idx": 2038}, {"num": 2040, "batch": "公共基础知识", "type": "bool", "stem": "坚持绿水青山就是金山银山的理念，坚持山水林田湖草沙可持续化保护和系统治理，生态文明制度体系更加健全。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "党的二十大报告原文为'坚持山水林田湖草沙一体化保护和系统治理'，而非'可持续化保护和系统治理'。题目将'一体化'替换为'可持续化'，表述与原文不符。", "tags": "广东辅警笔试 判断题 公共基础知识", "_idx": 2039}, {"num": 2041, "batch": "公共基础知识", "type": "bool", "stem": "近年来为治疗和改善冠心病引起的心肌供血不足、心脏局部阻塞的常用技术是心脏支架手术。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "心脏支架手术（经皮冠状动脉介入治疗）是近年来为治疗和改善冠心病引起的心肌供血不足、心脏局部阻塞的常用技术。通过植入支架撑开狭窄或阻塞的冠状动脉，恢复心肌血液供应。", "tags": "广东辅警笔试 判断题 公共基础知识", "_idx": 2040}, {"num": 2042, "batch": "公共基础知识", "type": "bool", "stem": "经济活动的效率和公平是辩证统一的，从而在经济制度的设计时应当统筹兼顾。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "经济活动的效率和公平是辩证统一的关系。效率是公平的物质前提，公平是提高经济效率的保证。在经济制度设计时应当统筹兼顾效率与公平，既要反对平均主义，也要防止收入差距过大。", "tags": "广东辅警笔试 判断题 公共基础知识", "_idx": 2041}, {"num": 2043, "batch": "公共基础知识", "type": "bool", "stem": "开展政法队伍教育整顿，是党中央提出的新要求、人民群众的新期粉、政法战线自我革命的新需要，是确保政法机关担负起新时代职责使命的重要举措。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "开展政法队伍教育整顿，是党中央提出的新要求、人民群众的新期盼、政法战线自我革命的新需要，是确保政法机关担负起新时代职责使命的重要举措。这一论述准确阐述了教育整顿的重要意义。", "tags": "广东辅警笔试 判断题 公共基础知识", "_idx": 2042}, {"num": 2044, "batch": "公共基础知识", "type": "bool", "stem": "李白属于“唐宋八大家”之一。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "唐宋八大家是指唐代的韩愈、柳宗元和宋代的欧阳修、苏洵、苏轼、苏辙、王安石、曾巩。李白是唐代伟大的浪漫主义诗人，但不属于唐宋八大家。", "tags": "广东辅警笔试 判断题 公共基础知识", "_idx": 2043}, {"num": 2045, "batch": "公共基础知识", "type": "bool", "stem": "明确把毛泽东思想作为党的指导思想写进党章的会议是党的七大。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "1945年召开的党的七大，首次将毛泽东思想确立为党的指导思想并写入党章。七大是党在民主革命时期召开的一次极其重要的全国代表大会，为争取抗日战争胜利和新民主主义革命在全国的胜利奠定了基础。", "tags": "广东辅警笔试 判断题 公共基础知识", "_idx": 2044}, {"num": 2046, "batch": "公共基础知识", "type": "bool", "stem": "某保安怀疑顾客杨某偷东西，可以先对杨某先行拘留，调查事实情况（）", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据法律规定，拘留属于限制人身自由的强制措施，只能由公安机关等法定机关依法实施。保安人员不具有执法权，无权对任何人实施拘留。保安怀疑顾客偷窃应当报警处理，不得自行限制他人人身自由。", "tags": "广东辅警笔试 判断题 公共基础知识", "_idx": 2045}, {"num": 2047, "batch": "公共基础知识", "type": "bool", "stem": "某市民政局与该市某县民政局之间属于派出与被派出关系。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "市民政局与县民政局之间存在行政隶属关系，市民政局是上级业务主管部门，县民政局是下级部门，属于派出与被派出的关系。这体现了我国行政机关上下级之间的领导与被领导关系。", "tags": "广东辅警笔试 判断题 公共基础知识", "_idx": 2046}, {"num": 2048, "batch": "公共基础知识", "type": "bool", "stem": "目前乙肝疫苗是世界上使用量最大的一种疫苗。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "世界上使用量最大的疫苗是卡介苗（BCG），而非乙肝疫苗。卡介苗是全球接种范围最广的疫苗之一，主要用于预防结核病，每年全球约有超过1亿婴儿接种卡介苗。", "tags": "广东辅警笔试 判断题 公共基础知识", "_idx": 2047}, {"num": 2049, "batch": "公共基础知识", "type": "bool", "stem": "全党同志务必不忘初心、继续前行，务必谦虚谨慎、艰苦奋斗，务必敢于斗争、善于斗争，坚定历史自信，增强历史主动，谱写新时代中国特色社会主义更加绚丽的华章。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "党的二十大报告原文为'务必不忘初心、牢记使命，务必谦虚谨慎、艰苦奋斗，务必敢于斗争、善于斗争'。题目将'牢记使命'写成'继续前行'，与原文不符。'三个务必'是党的二十大报告的重要论述。", "tags": "广东辅警笔试 判断题 公共基础知识", "_idx": 2048}, {"num": 2050, "batch": "公共基础知识", "type": "bool", "stem": "人民币升值，最有可能出现的是进口增加", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "人民币升值意味着人民币购买力增强，同等数量的人民币可以兑换更多外币，进口商品以人民币计价相对便宜，因此最有可能出现进口增加的现象。同时，人民币升值不利于出口。", "tags": "广东辅警笔试 判断题 公共基础知识", "_idx": 2049}, {"num": 2051, "batch": "公共基础知识", "type": "bool", "stem": "社会主义集体主义原则有三个相互联系又层次递进的含义，即集体利益的首要性、个人利益的重要性、集体利益和个人利益的协调性。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "社会主义集体主义原则的三个层次递进含义是：集体利益的首要性、个人利益的合理性（而非'重要性'）、集体利益和个人利益的协调性。题目将'合理性'表述为'重要性'，用词不准确。", "tags": "广东辅警笔试 判断题 公共基础知识", "_idx": 2050}, {"num": 2052, "batch": "公共基础知识", "type": "bool", "stem": "湿地、森林和海洋这三大生态系统，其中湿地被誉为地球之肾。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "湿地、森林和海洋并称为三大生态系统。湿地被誉为'地球之肾'，具有净化水质、调节气候、维护生物多样性等重要生态功能；森林被誉为'地球之肺'；海洋被誉为'地球之心'。", "tags": "广东辅警笔试 判断题 公共基础知识", "_idx": 2051}, {"num": 2053, "batch": "公共基础知识", "type": "bool", "stem": "市场经济道德规范不可能成为所有市场主体自觉遵守的行为准则，维护公平竞争的市场秩序还需要通过法律规范。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "市场经济道德规范依靠市场主体的自律，但由于利益驱动，不可能成为所有市场主体自觉遵守的行为准则。因此，维护公平竞争的市场秩序还需要法律规范的强制保障，道德与法律缺一不可。", "tags": "广东辅警笔试 判断题 公共基础知识", "_idx": 2052}, {"num": 2054, "batch": "公共基础知识", "type": "bool", "stem": "通货膨胀是宏观经济现象，通货紧缩是微观经济现象。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "通货膨胀和通货紧缩都属于宏观经济现象，而非一个是宏观、一个是微观。二者都是社会总供给与社会总需求不平衡的表现：通胀表现为物价总水平持续上涨，通缩表现为物价总水平持续下降。", "tags": "广东辅警笔试 判断题 公共基础知识", "_idx": 2053}, {"num": 2055, "batch": "公共基础知识", "type": "bool", "stem": "我们坚持走中国特色社会主义政治发展道路，全面发展全过程人民民主，社会主义民主政治制度化、法制化、程序化全面推进，人民当家作主更为扎实，全面依法治国总体格局基本形成。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "党的二十大报告原文为'社会主义民主政治制度化、规范化、程序化全面推进'，题目将'规范化'写成'法制化'，表述与原文不符。注意'规范化'与'法制化'的区别。", "tags": "广东辅警笔试 判断题 公共基础知识", "_idx": 2054}, {"num": 2056, "batch": "公共基础知识", "type": "bool", "stem": "习近平在二十届中共中央政治局常委同中外记者见面时的讲话中指出，新征程上，我们要始终弘扬全人类共同价值。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "习近平在二十届中共中央政治局常委同中外记者见面时的讲话中指出，新征程上，我们要始终弘扬和平、发展、公平、正义、民主、自由的全人类共同价值。表述正确。", "tags": "广东辅警笔试 判断题 公共基础知识", "_idx": 2055}, {"num": 2057, "batch": "公共基础知识", "type": "bool", "stem": "新时代的伟大成就是党和人民一道拼出来、干出来、开拓出来的！", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "党的二十大报告原文为'新时代的伟大成就是党和人民一道拼出来、干出来、奋斗出来的'，题目将'奋斗出来'写成'开拓出来'，与原文不符。注意原文的准确表述。", "tags": "广东辅警笔试 判断题 公共基础知识", "_idx": 2056}, {"num": 2058, "batch": "公共基础知识", "type": "bool", "stem": "要增强全党全国各族人民的志气、骨气、底气，不信邪、不怕鬼、不怕压，知难而进、迎难而上，统筹发展和安全，全力战胜前进道路上各种困难和挑战，依靠顽强斗争打开事业发展新天地。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "党的二十大报告指出，要增强全党全国各族人民的志气、骨气、底气，不信邪、不怕鬼、不怕压，知难而进、迎难而上，统筹发展和安全，全力战胜前进道路上各种困难和挑战，依靠顽强斗争打开事业发展新天地。表述正确。", "tags": "广东辅警笔试 判断题 公共基础知识", "_idx": 2057}, {"num": 2059, "batch": "公共基础知识", "type": "bool", "stem": "在青海，当我们外出时，看树桩上的年轮，可以识别年轮宽的一面为南方。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "在北半球（包括青海），树木朝南的一面阳光充足，光合作用强，生长较快，因此树桩年轮宽的一面为南方。这是利用自然现象辨别方向的基本方法之一。", "tags": "广东辅警笔试 判断题 公共基础知识", "_idx": 2058}, {"num": 2060, "batch": "公共基础知识", "type": "bool", "stem": "中国、印度、日本都是水稻的主产国", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "中国、印度、日本均为世界主要水稻生产国。三国均位于东亚和南亚季风区，雨热同期的气候条件适宜水稻种植，其中中国和印度是世界最大的两个水稻生产国。", "tags": "广东辅警笔试 判断题 公共基础知识", "_idx": 2059}, {"num": 2061, "batch": "公共基础知识", "type": "bool", "stem": "中国共产党第二十次全国代表大会，是在全党全国各族人民迈上全面建设社会主义现代化国家新征程、向第一个百年奋斗目标进军的关键时刻召开的一次十分重要的大会。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "党的二十大报告原文为'向第二个百年奋斗目标进军的关键时刻召开的一次十分重要的大会'，题目将'第二个'写成'第一个'，表述错误。第一个百年奋斗目标（全面建成小康社会）已经实现。", "tags": "广东辅警笔试 判断题 公共基础知识", "_idx": 2060}, {"num": 2062, "batch": "公共基础知识", "type": "bool", "stem": "中国古代的“而立之年”指的是四十岁", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "中国古代'而立之年'指的是三十岁，出自《论语·为政》：'三十而立，四十而不惑。'四十岁称为'不惑之年'，五十岁称为'知天命之年'。题目将而立之年说成四十岁，表述错误。", "tags": "广东辅警笔试 判断题 公共基础知识", "_idx": 2061}, {"num": 2063, "batch": "公共基础知识", "type": "bool", "stem": "中国人民的前进动力更加强大、创造精神更加昂扬、必胜信念更加坚定，中国共产党和中国人民正信心百倍推进中华民族从站起来、富起来到强起来的伟大飞跃。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "党的二十大报告原文为'中国人民的前进动力更加强大、奋斗精神更加昂扬、必胜信念更加坚定'，题目将'奋斗精神'写成'创造精神'，与原文不符。注意报告原文的准确表述。", "tags": "广东辅警笔试 判断题 公共基础知识", "_idx": 2062}, {"num": 2064, "batch": "公共基础知识", "type": "bool", "stem": "中国式创造化，是中国共产党领导的社会主义现代化，既有各国现代化的共同特征，更有基于自己国情的中国特色。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "正确表述应为'中国式现代化'，题目写成'中国式创造化'，属于明显的用词错误。中国式现代化是中国共产党领导的社会主义现代化，既有各国现代化的共同特征，更有基于自己国情的中国特色。", "tags": "广东辅警笔试 判断题 公共基础知识", "_idx": 2063}, {"num": 2065, "batch": "公共基础知识", "type": "bool", "stem": "走过百年奋斗历程的中国共产党在革命性锻造中更加坚强有力，在坚持和发展中国特色社会主义的历史进程中始终成为坚强领导核心。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "党的二十大报告指出，走过百年奋斗历程的中国共产党在革命性锻造中更加坚强有力，在坚持和发展中国特色社会主义的历史进程中始终成为坚强领导核心。这一表述正确，体现了党的领导的根本保证作用。", "tags": "广东辅警笔试 判断题 公共基础知识", "_idx": 2064}, {"num": 2066, "batch": "辅警管理办法", "type": "single", "stem": "应聘警务辅助人员原则上年龄为（）。", "options": [{"letter": "A", "text": "年龄16至35周岁"}, {"letter": "B", "text": "年龄18至25周岁"}, {"letter": "C", "text": "年龄18至35周岁"}, {"letter": "D", "text": "年龄18至30周岁"}], "answer": "C", "explanation": "根据《广东省公安机关警务辅助人员管理办法》相关规定，应聘警务辅助人员原则上年龄为18至35周岁。18周岁为法定成年年龄，35周岁为一般招聘年龄上限。", "tags": "广东辅警笔试 单选题 辅警管理办法", "_idx": 2065}, {"num": 2067, "batch": "辅警管理办法", "type": "single", "stem": "辅警纳入公安警务督察部门的督察范围，（）部门应当及时纠正辅警的违规违纪行为，受理涉及辅警的控告投诉，积极保护辅警的正当权益，纪检部门应调查处理相关违纪违规行为。", "options": [{"letter": "A", "text": "政工"}, {"letter": "B", "text": "纪检"}, {"letter": "C", "text": "刑警"}, {"letter": "D", "text": "警务督察"}], "answer": "D", "explanation": "根据辅警管理相关规定，辅警纳入公安警务督察部门的督察范围，警务督察部门应当及时纠正辅警的违规违纪行为，受理涉及辅警的控告投诉，积极保护辅警的正当权益。", "tags": "广东辅警笔试 单选题 辅警管理办法", "_idx": 2066}, {"num": 2068, "batch": "辅警管理办法", "type": "single", "stem": "报考人员有舞弊等严重违反招聘纪律行为的，（）年内不得报考公安机关辅警。", "options": [{"letter": "A", "text": "1"}, {"letter": "B", "text": "2"}, {"letter": "C", "text": "3"}, {"letter": "D", "text": "5"}], "answer": "D", "explanation": "根据辅警招聘管理相关规定，报考人员有舞弊等严重违反招聘纪律行为的，5年内不得报考公安机关辅警。这一规定旨在维护招聘工作的严肃性和公平公正。", "tags": "广东辅警笔试 单选题 辅警管理办法", "_idx": 2067}, {"num": 2069, "batch": "辅警管理办法", "type": "single", "stem": "对在交警、治安、基层派出所等部门从事辅助执法、便民服务、教育管理等工作的重点风险岗位，及其他敏感岗位工作满（）年的辅警，必须进行轮岗交流。", "options": [{"letter": "A", "text": "1"}, {"letter": "B", "text": "2"}, {"letter": "C", "text": "3"}, {"letter": "D", "text": "4"}], "answer": "C", "explanation": "根据辅警管理办法，对在交警、治安、基层派出所等部门从事辅助执法、便民服务、教育管理等工作的重点风险岗位及其他敏感岗位工作满3年的辅警，必须进行轮岗交流，以防范廉政风险。", "tags": "广东辅警笔试 单选题 辅警管理办法", "_idx": 2068}, {"num": 2070, "batch": "辅警管理办法", "type": "single", "stem": "辅警应在接到轮岗交流通知后的（）天内到新岗位报到并做好工作交接。", "options": [{"letter": "A", "text": "1"}, {"letter": "B", "text": "2"}, {"letter": "C", "text": "3"}, {"letter": "D", "text": "4"}], "answer": "C", "explanation": "根据辅警管理办法，辅警应在接到轮岗交流通知后的3天内到新岗位报到并做好工作交接。轮岗交流制度是加强辅警管理、防范岗位风险的重要措施。", "tags": "广东辅警笔试 单选题 辅警管理办法", "_idx": 2069}, {"num": 2071, "batch": "辅警管理办法", "type": "single", "stem": "年度培训是对全体辅警定期开展的轮训，每年培训时间累计不少于（）天。", "options": [{"letter": "A", "text": "1"}, {"letter": "B", "text": "2"}, {"letter": "C", "text": "3"}, {"letter": "D", "text": "5"}], "answer": "D", "explanation": "根据辅警管理办法，年度培训是对全体辅警定期开展的轮训，每年培训时间累计不少于5天。定期培训有助于提升辅警的业务素质和工作能力。", "tags": "广东辅警笔试 单选题 辅警管理办法", "_idx": 2070}, {"num": 2072, "batch": "辅警管理办法", "type": "single", "stem": "岗前培训是对新招聘辅警进行的培训。辅警必须在试用期（）完成岗前培训。", "options": [{"letter": "A", "text": "实习期结束前"}, {"letter": "B", "text": "入职一周内"}, {"letter": "C", "text": "入职满半年"}, {"letter": "D", "text": "层级评定前"}], "answer": "A", "explanation": "根据辅警管理办法，岗前培训是对新招聘辅警进行的培训，辅警必须在试用期（实习期结束前）完成岗前培训。这确保了辅警在正式上岗前具备必要的业务知识和技能。", "tags": "广东辅警笔试 单选题 辅警管理办法", "_idx": 2071}, {"num": 2073, "batch": "辅警管理办法", "type": "single", "stem": "考核应当根据警务辅助人员岗位职责和工作要求，通过确定量化指标或关键指标等方式，明确警务辅助人员考核具体内容，并按照“实事求是、客观科学、（）”的总体原则，选择合适的程序和方法。", "options": [{"letter": "A", "text": "有效判断"}, {"letter": "B", "text": "便于操作"}, {"letter": "C", "text": "合法合规"}, {"letter": "D", "text": "公平公正"}], "answer": "B", "explanation": "根据辅警管理办法，考核应按照'实事求是、客观科学、便于操作'的总体原则，通过确定量化指标或关键指标等方式明确考核内容。'便于操作'强调考核标准应具有可执行性。", "tags": "广东辅警笔试 单选题 辅警管理办法", "_idx": 2072}, {"num": 2074, "batch": "辅警管理办法", "type": "single", "stem": "警务辅助人员的考核分为试用期考核、月考核和（）", "options": [{"letter": "A", "text": "季度考核"}, {"letter": "B", "text": "晋升考核"}, {"letter": "C", "text": "年度考核"}, {"letter": "D", "text": "层级考核"}], "answer": "C", "explanation": "根据辅警管理办法，警务辅助人员的考核分为试用期考核、月考核和年度考核三种类型。试用期考核针对新招聘辅警，月考核为日常考核，年度考核为综合性评价。", "tags": "广东辅警笔试 单选题 辅警管理办法", "_idx": 2073}, {"num": 2075, "batch": "辅警管理办法", "type": "single", "stem": "辅警试用期考核应在试用期结束前完成，结果分为（）、不合格两个等次。", "options": [{"letter": "A", "text": "基本合格"}, {"letter": "B", "text": "优秀"}, {"letter": "C", "text": "合格"}, {"letter": "D", "text": "良好"}], "answer": "C", "explanation": "根据辅警管理办法，辅警试用期考核应在试用期结束前完成，结果分为合格、不合格两个等次。试用期考核是决定辅警能否正式聘用的重要依据。", "tags": "广东辅警笔试 单选题 辅警管理办法", "_idx": 2074}, {"num": 2076, "batch": "辅警管理办法", "type": "single", "stem": "辅警月考核于每月末开展，由用人单位结合工作实际研究明确细化的定性和量化评价标准，各责任民警结合辅警完成日常工作任务、阶段性工作目标及日常行为规范等情况，综合进行考核，分为优秀、合格、()、不合格四个等次。", "options": [{"letter": "A", "text": "基本合格"}, {"letter": "B", "text": "良好"}, {"letter": "C", "text": "接近合格"}, {"letter": "D", "text": "暂定合格"}], "answer": "A", "explanation": "根据辅警管理办法，辅警月考核分为优秀、合格、基本合格、不合格四个等次。月考核由责任民警结合辅警完成日常工作任务、阶段性工作目标及日常行为规范等情况综合评定。", "tags": "广东辅警笔试 单选题 辅警管理办法", "_idx": 2075}, {"num": 2077, "batch": "辅警管理办法", "type": "single", "stem": "辅警年度考核工作于每年年末或翌年年初进行，考核结果分为优秀、合格、（）、不合格四个等次。", "options": [{"letter": "A", "text": "不参加考核"}, {"letter": "B", "text": "不定等次"}, {"letter": "C", "text": "良好"}, {"letter": "D", "text": "基本合格"}], "answer": "A", "explanation": "根据辅警管理办法，辅警年度考核结果分为优秀、合格、不参加考核、不合格四个等次。注意与月考核等次的区别，年度考核中不设'基本合格'等次，而是设有'不参加考核'等次。", "tags": "广东辅警笔试 单选题 辅警管理办法", "_idx": 2076}, {"num": 2078, "batch": "辅警管理办法", "type": "single", "stem": "年度考核评为优秀等级的警务辅助人员，不超过本单位警务辅助人员总数的（）", "options": [{"letter": "A", "text": "5%"}, {"letter": "B", "text": "10%"}, {"letter": "C", "text": "15%"}, {"letter": "D", "text": "20%"}], "answer": "C", "explanation": "根据辅警管理办法，年度考核评为优秀等级的警务辅助人员，不超过本单位警务辅助人员总数的15%。这一比例限制确保了考核评优的合理性和激励效果。", "tags": "广东辅警笔试 单选题 辅警管理办法", "_idx": 2077}, {"num": 2079, "batch": "辅警管理办法", "type": "single", "stem": "年度考核被评定为基本合格等次的，延迟（）晋升层级。", "options": [{"letter": "A", "text": "3个月"}, {"letter": "B", "text": "6个月"}, {"letter": "C", "text": "12个月"}, {"letter": "D", "text": "15个月"}], "answer": "A", "explanation": "根据辅警管理办法，年度考核被评定为基本合格等次的，延迟3个月晋升层级。这一规定体现了考核结果与层级晋升挂钩的激励机制。", "tags": "广东辅警笔试 单选题 辅警管理办法", "_idx": 2078}, {"num": 2080, "batch": "辅警管理办法", "type": "single", "stem": "以下说法有误的是（）", "options": [{"letter": "A", "text": "无正当理由，未按规定办理请假手续，不到岗工作的，可按旷工处理"}, {"letter": "B", "text": "假期已满未获准续假，又无正当理由逾期不归且不办理销假手续的，可按旷工处理"}, {"letter": "C", "text": "辅警请休假由本人向所在单位书面提出申请，详细说明事由、地点和起止时间，由所在单位领导审批同意后，报政工部门备案"}, {"letter": "D", "text": "假期结束时，应按时返回工作岗位，并及时销假。确因特殊情况不能按时返回的，无需履行续假手续"}], "answer": "D", "explanation": "根据辅警请休假管理规定，假期结束时应当按时返回工作岗位并及时销假。确因特殊情况不能按时返回的，应当履行续假手续。D项称'无需履行续假手续'，违反了管理规定。", "tags": "广东辅警笔试 单选题 辅警管理办法", "_idx": 2079}, {"num": 2081, "batch": "辅警管理办法", "type": "single", "stem": "党员辅警涉嫌违反党纪的，由（）立案查处。", "options": [{"letter": "A", "text": "政工部门"}, {"letter": "B", "text": "督察部门"}, {"letter": "C", "text": "法制部门"}, {"letter": "D", "text": "纪检部门"}], "answer": "D", "explanation": "根据相关规定，党员辅警涉嫌违反党纪的，由纪检部门立案查处。纪检部门负责党内纪律检查工作，对党员违纪行为具有调查处理权。", "tags": "广东辅警笔试 单选题 辅警管理办法", "_idx": 2080}, {"num": 2082, "batch": "辅警管理办法", "type": "single", "stem": "辅警违规违纪行为视情节严重给予警告、严重警告、记过、降级、()处理。", "options": [{"letter": "A", "text": "辞退"}, {"letter": "B", "text": "劝退"}, {"letter": "C", "text": "辞职"}, {"letter": "D", "text": "立案"}], "answer": "A", "explanation": "根据辅警管理办法，辅警违规违纪行为视情节严重给予警告、严重警告、记过、降级、辞退处理。辞退是最严厉的纪律处分，适用于严重违规违纪的情形。", "tags": "广东辅警笔试 单选题 辅警管理办法", "_idx": 2081}, {"num": 2083, "batch": "辅警管理办法", "type": "single", "stem": "擅自将配发的服装、标识转借他人的，予以严重警告，造成严重后果的，予以（）。", "options": [{"letter": "A", "text": "劝退"}, {"letter": "B", "text": "辞职"}, {"letter": "C", "text": "辞退"}, {"letter": "D", "text": "立案"}], "answer": "C", "explanation": "根据辅警管理规定，擅自将配发的服装、标识转借他人的，予以严重警告；造成严重后果的，予以辞退。辅警服装和标识是身份象征，不得随意转借，以维护公安机关形象和管理秩序。", "tags": "广东辅警笔试 单选题 辅警管理办法", "_idx": 2082}, {"num": 2084, "batch": "辅警管理办法", "type": "single", "stem": "新招聘辅警（）确定责任民警，同时在辅警系统完成警辅结对工作。", "options": [{"letter": "A", "text": "试用期满后"}, {"letter": "B", "text": "入职后应第一时间"}, {"letter": "C", "text": "层级评定后"}, {"letter": "D", "text": "入职满一个月后"}], "answer": "B", "explanation": "根据辅警管理办法，新招聘辅警入职后应第一时间确定责任民警，同时在辅警系统完成警辅结对工作。'一警辅一'或'多警辅一'的结对机制有助于加强对辅警的日常管理和指导。", "tags": "广东辅警笔试 单选题 辅警管理办法", "_idx": 2083}, {"num": 2085, "batch": "辅警管理办法", "type": "multi", "stem": "有下列情形之一的人员，不得招聘为辅警（）。", "options": [{"letter": "A", "text": "本人或家庭成员、主要社会关系人参加非法组织、邪教组织或者从事其他危害国家安全活动的"}, {"letter": "B", "text": "受过刑事处罚或者涉嫌违法犯罪尚未查清的"}, {"letter": "C", "text": "编造、散布有损国家声誉、反对党的理论和路线方针政策、违反国家法律法规信息的"}, {"letter": "D", "text": "因吸食、注射毒品，卖淫、嫖娼，赌博或为赌博提供条件受到处罚的"}], "answer": "ABCD", "explanation": "根据辅警管理办法，不得招聘为辅警的情形包括：本人或家庭成员参加非法组织或邪教活动的、受过刑事处罚或涉嫌违法犯罪尚未查清的、编造散布有损国家声誉信息的、因吸毒卖淫嫖娼赌博受到处罚的。以上四项均属于禁止性条件。", "tags": "广东辅警笔试 多选题 辅警管理办法", "_idx": 2084}, {"num": 2086, "batch": "辅警管理办法", "type": "multi", "stem": "勤务辅警按照岗位分工，履行下列职责（）", "options": [{"letter": "A", "text": "协助预防、制止违法犯罪活动"}, {"letter": "B", "text": "协助盘查、堵控、监控、看管违法犯罪嫌疑人"}, {"letter": "C", "text": "记录讯问、询问笔录"}, {"letter": "D", "text": "协助开展戒毒人员日常管理、检查易制毒化学品企业、公开查缉毒品"}], "answer": "ABD", "explanation": "根据辅警管理办法，勤务辅警职责包括协助预防制止违法犯罪、协助盘查堵控监控看管违法犯罪嫌疑人、协助开展戒毒人员日常管理等。但记录讯问询问笔录属于辅警不得从事的工作，故C项不选。", "tags": "广东辅警笔试 多选题 辅警管理办法", "_idx": 2085}, {"num": 2087, "batch": "辅警管理办法", "type": "multi", "stem": "文职辅警按照岗位分工，履行下列职责（）", "options": [{"letter": "A", "text": "文书助理、档案管理、接线查询、窗口服务、证件办理、枪支管理工作"}, {"letter": "B", "text": "心理咨询、医疗、翻译、计算机网络维护、数据分析、软件研发、安全检测、通信保障、资金分析、非涉密财务管理、实验室分析、现场勘查、检验鉴定等技术支持工作"}, {"letter": "C", "text": "警用装备保管和维护保养等警务保障工作"}, {"letter": "D", "text": "其他可以由文职辅警从事的工作"}], "answer": "BCD", "explanation": "根据辅警管理办法，文职辅警职责包括技术支持工作（B项）、警务保障工作（C项）及其他可由文职辅警从事的工作（D项）。A项中'枪支管理工作'不属于文职辅警职责范围，故A项不选。", "tags": "广东辅警笔试 多选题 辅警管理办法", "_idx": 2086}, {"num": 2088, "batch": "辅警管理办法", "type": "multi", "stem": "辅警不得从事以下工作（）", "options": [{"letter": "A", "text": "国内安全保卫、技术侦察、反邪教、反恐怖等工作"}, {"letter": "B", "text": "办理涉及国家秘密的事项"}, {"letter": "C", "text": "案件调查取证、出具鉴定报告、交通事故责任认定"}, {"letter": "D", "text": "执行刑事强制措施"}], "answer": "ABCD", "explanation": "根据《公安机关警务辅助人员管理条例》相关规定，辅警不得从事国内安全保卫和技术侦察等工作、不得办理涉及国家秘密的事项、不得进行案件调查取证和出具鉴定报告、不得执行刑事强制措施。以上四项均属于辅警的禁止性职责。", "tags": "广东辅警笔试 多选题 辅警管理办法", "_idx": 2087}, {"num": 2089, "batch": "辅警管理办法", "type": "multi", "stem": "辅警应当履行下列义务（）", "options": [{"letter": "A", "text": "遵纪守法，保守国家秘密和工作秘密"}, {"letter": "B", "text": "服从公安机关管理，听从人民警察指挥"}, {"letter": "C", "text": "忠于职守，文明执勤，廉洁奉公，不徇私情"}, {"letter": "D", "text": "遵守社会公德，尊重民族风俗习惯"}], "answer": "ABCD", "explanation": "根据辅警管理办法，辅警应当履行的义务包括：遵纪守法并保守国家秘密和工作秘密、服从公安机关管理并听从人民警察指挥、忠于职守文明执勤廉洁奉公、遵守社会公德并尊重民族风俗习惯。四项义务涵盖了法律、纪律、职业和社会层面。", "tags": "广东辅警笔试 多选题 辅警管理办法", "_idx": 2088}, {"num": 2090, "batch": "辅警管理办法", "type": "multi", "stem": "辅警不得有以下行为（）", "options": [{"letter": "A", "text": "泄露国家秘密、工作秘密"}, {"letter": "B", "text": "弄虚作假、隐瞒案情，包庇、纵容违法犯罪活动"}, {"letter": "C", "text": "敲诈勒索或索取、收受贿赂"}, {"letter": "D", "text": "玩忽职守，不履行工作职责"}], "answer": "ABCD", "explanation": "根据辅警管理办法，辅警不得有泄露国家秘密和工作秘密、弄虚作假隐瞒案情包庇纵容违法犯罪、敲诈勒索或索取收受贿赂、玩忽职守不履行职责等行为。这些禁止性规定是确保辅警队伍纯洁性和战斗力的基本要求。", "tags": "广东辅警笔试 多选题 辅警管理办法", "_idx": 2089}, {"num": 2091, "batch": "辅警管理办法", "type": "multi", "stem": "对工作中存在（）的警务辅助人员，视情形采取警告、记过、降级等惩戒措施。", "options": [{"letter": "A", "text": "违纪"}, {"letter": "B", "text": "违规"}, {"letter": "C", "text": "失职"}, {"letter": "D", "text": "渎职"}], "answer": "ABCD", "explanation": "根据辅警管理办法，对工作中存在违纪、违规、失职、渎职情形的警务辅助人员，视情形采取警告、记过、降级等惩戒措施。四种情形均属于应当受到惩戒的行为。", "tags": "广东辅警笔试 多选题 辅警管理办法", "_idx": 2090}, {"num": 2092, "batch": "辅警管理办法", "type": "multi", "stem": "辅警离职时，应当交回所配发的（）", "options": [{"letter": "A", "text": "工作证件"}, {"letter": "B", "text": "服装"}, {"letter": "C", "text": "标识"}, {"letter": "D", "text": "装备"}], "answer": "ABCD", "explanation": "根据辅警管理办法，辅警离职时应当交回所配发的工作证件、服装、标识和装备。这一规定旨在防止公安机关的证件、服装和装备流入社会造成不良影响或安全隐患。", "tags": "广东辅警笔试 多选题 辅警管理办法", "_idx": 2091}, {"num": 2093, "batch": "辅警管理办法", "type": "multi", "stem": "对违反招聘纪律的报考人员，视情给予（）", "options": [{"letter": "A", "text": "批评教育"}, {"letter": "B", "text": "取消报考资格"}, {"letter": "C", "text": "不予录用"}, {"letter": "D", "text": "禁止再次报考"}], "answer": "ABC", "explanation": "根据辅警招聘管理规定，对违反招聘纪律的报考人员，视情节给予批评教育、取消报考资格、不予录用等处理。D项'禁止再次报考'不属于规定的处理措施。", "tags": "广东辅警笔试 多选题 辅警管理办法", "_idx": 2092}, {"num": 2094, "batch": "辅警管理办法", "type": "multi", "stem": "凡有（）等亲属关系的辅警，在同一部门、单位直接隶属于同一领导人员的必须轮岗交流;", "options": [{"letter": "A", "text": "夫妻关系"}, {"letter": "B", "text": "直系血亲关系"}, {"letter": "C", "text": "三代以内旁系血亲关系"}, {"letter": "D", "text": "近姻亲关系"}], "answer": "ABCD", "explanation": "根据辅警管理办法中的回避制度，凡有夫妻关系、直系血亲关系、三代以内旁系血亲关系、近姻亲关系等亲属关系的辅警，在同一部门或单位直接隶属于同一领导人员的必须轮岗交流，以防止利益冲突。", "tags": "广东辅警笔试 多选题 辅警管理办法", "_idx": 2093}, {"num": 2095, "batch": "辅警管理办法", "type": "multi", "stem": "建立民警与辅警协同培训机制，适时组织开展合成作战实战演练，强化一线民警、辅警（）", "options": [{"letter": "A", "text": "协同作战能力"}, {"letter": "B", "text": "快速反应能力"}, {"letter": "C", "text": "实战处突能力"}, {"letter": "D", "text": "安全防护能力培训"}], "answer": "ABCD", "explanation": "根据辅警管理办法，建立民警与辅警协同培训机制，适时组织开展合成作战实战演练，强化一线民警、辅警的协同作战能力、快速反应能力、实战处突能力和安全防护能力培训。四项能力培训是合成作战的核心要求。", "tags": "广东辅警笔试 多选题 辅警管理办法", "_idx": 2094}, {"num": 2096, "batch": "辅警管理办法", "type": "multi", "stem": "警务辅助人员的考核以岗位职责和所承担的工作任务为基本依据，全面考核（）等方面现实表现，重点考核工作实绩和德才表现。", "options": [{"letter": "A", "text": "思想品德"}, {"letter": "B", "text": "履职能力"}, {"letter": "C", "text": "工作实绩"}, {"letter": "D", "text": "遵章守纪"}], "answer": "ABCD", "explanation": "根据辅警管理办法，警务辅助人员的考核以岗位职责和所承担的工作任务为基本依据，全面考核思想品德、履职能力、工作实绩、遵章守纪等方面现实表现，重点考核工作实绩和德才表现。四项内容构成全面考核体系。", "tags": "广东辅警笔试 多选题 辅警管理办法", "_idx": 2095}, {"num": 2097, "batch": "辅警管理办法", "type": "multi", "stem": "警务辅助人员在试用期有下列哪种情形的，应评为不合格等次。", "options": [{"letter": "A", "text": "思想品德较差的"}, {"letter": "B", "text": "工作能力不适应岗位要求的"}, {"letter": "C", "text": "工作态度或纪律作风差的"}, {"letter": "D", "text": "不能完成工作任务，或因失误、失职给单位造成损失或不良影响的"}], "answer": "ABCD", "explanation": "根据辅警管理办法，警务辅助人员在试用期有下列情形的应评为不合格：思想品德较差、工作能力不适应岗位要求、工作态度或纪律作风差、不能完成工作任务或因失误失职给单位造成损失或不良影响。四项情形均属于不合格等次的评定标准。", "tags": "广东辅警笔试 多选题 辅警管理办法", "_idx": 2096}, {"num": 2098, "batch": "辅警管理办法", "type": "multi", "stem": "辅警年度考核的程序包括（）", "options": [{"letter": "A", "text": "个人自评"}, {"letter": "B", "text": "民警评定"}, {"letter": "C", "text": "部门考察"}, {"letter": "D", "text": "政工审批"}], "answer": "ABCD", "explanation": "根据辅警管理办法，辅警年度考核的程序包括个人自评、民警评定、部门考察、政工审批四个环节。这一程序体现了自下而上、层层审核的考核原则，确保考核结果客观公正。", "tags": "广东辅警笔试 多选题 辅警管理办法", "_idx": 2097}, {"num": 2099, "batch": "辅警管理办法", "type": "multi", "stem": "考核结果可作为确定层级、（）的依据。", "options": [{"letter": "A", "text": "解（续）聘"}, {"letter": "B", "text": "表彰奖励"}, {"letter": "C", "text": "层级升降"}, {"letter": "D", "text": "薪酬调整"}], "answer": "ABCD", "explanation": "根据辅警管理办法，考核结果可作为确定层级、解（续）聘、表彰奖励、层级升降、薪酬调整的依据。考核结果与辅警的职业发展和待遇保障直接挂钩，是激励约束机制的重要组成部分。", "tags": "广东辅警笔试 多选题 辅警管理办法", "_idx": 2098}, {"num": 2100, "batch": "辅警管理办法", "type": "multi", "stem": "辅警违反政治纪律行为，有下列情形之一的，予以辞退。", "options": [{"letter": "A", "text": "散布有损宪法权威、中国共产党和国家、公安机关声誉的言论，或侮辱、诋毁人民警察形象的"}, {"letter": "B", "text": "组织或参加非法集会、游行、示威等活动的"}, {"letter": "C", "text": "组织或参加非法组织，违法组织或参加罢工的"}, {"letter": "D", "text": "有其他有损中国共产党和政府、公安机关声誉行为的"}], "answer": "ABCD", "explanation": "根据辅警管理办法，辅警违反政治纪律有下列情形之一的予以辞退：散布有损宪法权威和党和国家声誉的言论、组织或参加非法集会和游行示威等活动、组织或参加非法组织和违法罢工、其他有损党和政府及公安机关声誉的行为。政治纪律是最根本的纪律要求。", "tags": "广东辅警笔试 多选题 辅警管理办法", "_idx": 2099}, {"num": 2101, "batch": "辅警管理办法", "type": "multi", "stem": "辅警违反保密规定行为的，可视情予以（）处理。", "options": [{"letter": "A", "text": "警告"}, {"letter": "B", "text": "严重警告"}, {"letter": "C", "text": "记过并降级"}, {"letter": "D", "text": "辞退"}], "answer": "ABCD", "explanation": "根据辅警管理相关规定，辅警违反保密规定的，视情节轻重可分别给予警告、严重警告、记过并降级、辞退等处理。保密纪律是辅警管理的重要红线，四种处理方式均属于可选范围，故ABCD全部正确。", "tags": "广东辅警笔试 多选题 辅警管理办法", "_idx": 2100}, {"num": 2102, "batch": "辅警管理办法", "type": "multi", "stem": "辅警违反经济方面纪律规定行为，有下列情形之一的，视情节严重予以记过并降级或辞退（）", "options": [{"letter": "A", "text": "利用工作之便，侵吞、窃取或以其他手段非法占有公私财物、无主物品"}, {"letter": "B", "text": "利用工作之便，侵占、挪用公款"}, {"letter": "C", "text": "利用工作之便，为谋取私利或受人请托，有索要、收受财物或行贿行为"}, {"letter": "D", "text": "有其他经济方面违反纪律行为"}], "answer": "ABCD", "explanation": "根据辅警管理相关规定，辅警违反经济方面纪律的行为包括：利用工作之便侵吞、窃取或非法占有公私财物；侵占、挪用公款；索要、收受财物或行贿；以及其他经济方面违纪行为。以上四项均属于经济违纪情形，视情节予以记过并降级或辞退，故ABCD全部正确。", "tags": "广东辅警笔试 多选题 辅警管理办法", "_idx": 2101}, {"num": 2103, "batch": "辅警管理办法", "type": "multi", "stem": "辅警有下列失职、渎职行为之一的，予以记过并降级，情节严重的予以辞退。（）", "options": [{"letter": "A", "text": "工作中不履行或不正确履行职责"}, {"letter": "B", "text": "徇私舞弊或玩忽职守、贻误工作"}, {"letter": "C", "text": "打听案情、接受吃请、收受财物、透露案情"}, {"letter": "D", "text": "为非法活动或违法犯罪嫌疑人通风报信、说情开脱或干扰、妨碍案件查处"}], "answer": "ABCD", "explanation": "根据辅警管理相关规定，辅警失职、渎职行为包括：不履行或不正确履行职责；徇私舞弊、玩忽职守、贻误工作；打听案情、接受吃请、收受财物、透露案情；为非法活动或违法犯罪嫌疑人通风报信、说情开脱或干扰妨碍案件查处。上述行为均严重损害公安机关执法公信力，予以记过并降级，情节严重的予以辞退，故ABCD全部正确。", "tags": "广东辅警笔试 多选题 辅警管理办法", "_idx": 2102}, {"num": 2104, "batch": "辅警管理办法", "type": "bool", "stem": "警务辅助人员统称辅警，包括勤务辅警和文职辅警。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《国务院办公厅关于规范公安机关警务辅助人员管理工作的意见》及各地辅警管理办法，警务辅助人员统称辅警，分为勤务辅警和文职辅警两类。勤务辅警协助开展执法执勤等警务活动，文职辅警协助从事行政管理、技术支持等工作。本题表述正确。", "tags": "广东辅警笔试 判断题 辅警管理办法", "_idx": 2103}, {"num": 2105, "batch": "辅警管理办法", "type": "bool", "stem": "辅警不具有人民警察身份，必须在公安机关及其人民警察的指挥和监督下开展警务辅助工作。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "辅警不具有人民警察身份，不能独立开展执法工作，必须在公安机关及其人民警察的指挥和监督下开展警务辅助工作。这是辅警法律地位的基本要求，也是规范辅警管理的核心原则。本题表述正确。", "tags": "广东辅警笔试 判断题 辅警管理办法", "_idx": 2104}, {"num": 2106, "batch": "辅警管理办法", "type": "bool", "stem": "从事警务辅助工作劳动合同期未满擅自离职的，可继续报名参加辅警招录（）。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据辅警管理相关规定，从事警务辅助工作劳动合同期未满擅自离职的，属于违反劳动合同约定的行为，一般不得再次报名参加辅警招录。擅自离职会影响队伍稳定性和工作连续性，故规定对此类人员限制再次报考。本题表述错误。", "tags": "广东辅警笔试 判断题 辅警管理办法", "_idx": 2105}, {"num": 2107, "batch": "辅警管理办法", "type": "bool", "stem": "有较为严重个人不良信用记录的人员，只要业务工作能力较强均可招录为辅警。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据辅警招录条件规定，应聘辅警应当具备良好的政治素质和道德品行，有较为严重个人不良信用记录的人员不符合招录条件，不得招录为辅警。个人信用状况是辅警政审考察的重要内容，不能仅凭业务能力而降低准入标准。本题表述错误。", "tags": "广东辅警笔试 判断题 辅警管理办法", "_idx": 2106}, {"num": 2108, "batch": "辅警管理办法", "type": "bool", "stem": "辅警依法履行职责的行为受法律保护，相关法律后果由其所属公安机关承担。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据《国务院办公厅关于规范公安机关警务辅助人员管理工作的意见》，辅警在公安机关及其人民警察的指挥和监督下依法履行职责的行为受法律保护，相关法律后果由其所属公安机关承担。这是因为辅警不具有独立执法主体资格，其行为后果归属于所在公安机关。本题表述正确。", "tags": "广东辅警笔试 判断题 辅警管理办法", "_idx": 2107}, {"num": 2109, "batch": "辅警管理办法", "type": "bool", "stem": "辅警在人民警察带领下驾驶警用汽车、摩托车、船艇、航空器等警用交通工具。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据辅警岗位职责相关规定，勤务辅警可以在人民警察带领下驾驶警用汽车、摩托车、船艇、航空器等警用交通工具。这属于勤务辅警的辅助性工作职责之一，但必须在人民警察的带领和监督下进行。本题表述正确。", "tags": "广东辅警笔试 判断题 辅警管理办法", "_idx": 2108}, {"num": 2110, "batch": "辅警管理办法", "type": "bool", "stem": "辅警可从事与本职工作有关的盈利性经营活动或者受雇于任何个人或者组织。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据辅警管理相关规定，辅警不得从事与本职工作有关的盈利性经营活动，也不得受雇于任何个人或者组织。这是为了防止利益冲突，确保辅警公正履职、维护公安机关形象。本题表述错误。", "tags": "广东辅警笔试 判断题 辅警管理办法", "_idx": 2109}, {"num": 2111, "batch": "辅警管理办法", "type": "bool", "stem": "依法提出申诉和控告是辅警享有的权利。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据辅警管理相关规定，辅警依法享有提出申诉和控告的权利。当辅警认为自身合法权益受到侵害时，有权依法提出申诉和控告，这是保障辅警合法权益的重要制度安排。本题表述正确。", "tags": "广东辅警笔试 判断题 辅警管理办法", "_idx": 2110}, {"num": 2112, "batch": "辅警管理办法", "type": "bool", "stem": "应聘警务辅助人员应当具有初中以上文化程度。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据辅警招录条件规定，应聘警务辅助人员一般应当具有高中以上文化程度，而非初中以上文化程度。各地在具体招录中通常要求高中（中专）及以上学历，部分岗位还要求大专以上学历。本题表述错误。", "tags": "广东辅警笔试 判断题 辅警管理办法", "_idx": 2111}, {"num": 2113, "batch": "辅警管理办法", "type": "bool", "stem": "文职辅警应当具有大专以上文化程度和岗位需要的专业资质或者专门技能。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据辅警管理相关规定，文职辅警应当具有大专以上文化程度和岗位需要的专业资质或者专门技能。文职辅警从事行政管理、技术支持等专业性较强的工作，因此对其学历要求高于勤务辅警。本题表述正确。", "tags": "广东辅警笔试 判断题 辅警管理办法", "_idx": 2112}, {"num": 2114, "batch": "辅警管理办法", "type": "bool", "stem": "辅警可适当的从事与本职工作有关的盈利性经营活动或者受雇于任何个人或者组织。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据辅警管理相关规定，辅警一律不得从事与本职工作有关的盈利性经营活动，也不得受雇于任何个人或者组织，不存在'适当从事'的例外情形。该规定旨在防止利益冲突，确保辅警队伍的廉洁性和公正性。本题表述错误。", "tags": "广东辅警笔试 判断题 辅警管理办法", "_idx": 2113}, {"num": 2115, "batch": "辅警管理办法", "type": "bool", "stem": "辅警管理遵循“谁使用、谁管理、谁考核、谁负责”的原则进行日常管理。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据辅警管理相关规定，辅警管理遵循'谁使用、谁管理、谁考核、谁负责'的原则。这一原则明确了辅警日常管理的责任主体，确保辅警管理工作责任到人、落实到位。本题表述正确。", "tags": "广东辅警笔试 判断题 辅警管理办法", "_idx": 2114}, {"num": 2116, "batch": "辅警管理办法", "type": "bool", "stem": "公安机关可以根据岗位工作需要，为辅警配备必要的执勤和安全防护装备，也可以配备武器、警械。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据《人民警察使用警械和武器条例》及辅警管理相关规定，公安机关可以根据岗位工作需要为辅警配备必要的执勤和安全防护装备，但不得为辅警配备武器。辅警不具有人民警察身份，无权持有和使用武器、警械。本题表述错误。", "tags": "广东辅警笔试 判断题 辅警管理办法", "_idx": 2115}, {"num": 2117, "batch": "辅警管理办法", "type": "bool", "stem": "从事辅警招聘工作的人员，遇有涉及本人利害关系、可能影响公平公正情形的，应当回避（）", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据辅警招聘工作相关规定，从事辅警招聘工作的人员，遇有涉及本人利害关系、可能影响公平公正情形的，应当回避。回避制度是保障招聘工作公开、公平、公正的重要制度安排，符合公务员招录和事业单位人事管理的基本规范。本题表述正确。", "tags": "广东辅警笔试 判断题 辅警管理办法", "_idx": 2116}, {"num": 2118, "batch": "辅警管理办法", "type": "bool", "stem": "各级公安机关在规定的辅警用人额度内依法聘用由财政保障的辅警，不得无指标聘用（）", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据辅警管理相关规定，各级公安机关应当在规定的辅警用人额度内依法聘用由财政保障的辅警，不得无指标聘用。辅警用人额度由县级以上地方人民政府根据实际需要和财政承受能力核定，必须严格执行。本题表述正确。", "tags": "广东辅警笔试 判断题 辅警管理办法", "_idx": 2117}, {"num": 2119, "batch": "辅警管理办法", "type": "bool", "stem": "对在非重点风险岗位及非敏感岗位工作满5年以上的，可以根据工作需要适时安排轮岗交流。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据辅警管理相关规定，对在非重点风险岗位及非敏感岗位工作满5年以上的辅警，可以根据工作需要适时安排轮岗交流。轮岗交流制度有助于防范廉政风险、提升辅警综合能力，是辅警管理的重要制度安排。本题表述正确。", "tags": "广东辅警笔试 判断题 辅警管理办法", "_idx": 2118}, {"num": 2120, "batch": "辅警管理办法", "type": "bool", "stem": "轮岗交流可在本单位、本部门内进行，也可跨单位、跨部门进行。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据辅警管理相关规定，轮岗交流可在本单位、本部门内进行，也可跨单位、跨部门进行。轮岗交流的范围和方式较为灵活，旨在促进人员合理流动和优化配置。本题表述正确。", "tags": "广东辅警笔试 判断题 辅警管理办法", "_idx": 2119}, {"num": 2121, "batch": "辅警管理办法", "type": "bool", "stem": "辅警教育培训包括岗前培训、年度培训、晋升培训、专项培训和骨干培训等。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据辅警管理相关规定，辅警教育培训体系包括岗前培训、年度培训、晋升培训、专项培训和骨干培训等多种类型。通过系统化的教育培训，不断提升辅警的政治素质、业务能力和纪律意识。本题表述正确。", "tags": "广东辅警笔试 判断题 辅警管理办法", "_idx": 2120}, {"num": 2122, "batch": "辅警管理办法", "type": "bool", "stem": "勤务辅警应当加强体能达标培训和警务技战术培训。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据辅警管理相关规定，勤务辅警因工作性质涉及执法执勤和巡逻防控等任务，应当加强体能达标培训和警务技战术培训，以确保具备完成辅助性警务工作的身体素质和技能水平。本题表述正确。", "tags": "广东辅警笔试 判断题 辅警管理办法", "_idx": 2121}, {"num": 2123, "batch": "辅警管理办法", "type": "bool", "stem": "无正当理由不参加年度考核的警务辅助人员，直接确定其考核结果为不合格。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据辅警考核相关规定，无正当理由不参加年度考核的警务辅助人员，直接确定其考核结果为不合格。年度考核是辅警管理的重要环节，不参加考核即视为不履行考核义务，应认定为不合格。本题表述正确。", "tags": "广东辅警笔试 判断题 辅警管理办法", "_idx": 2122}, {"num": 2124, "batch": "辅警管理办法", "type": "bool", "stem": "警务辅助人员因工作需要借调的，可不参加年度考核。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据辅警考核相关规定，警务辅助人员因工作需要借调的，仍应当参加年度考核，由借调单位或原单位根据实际情况进行考核评定。借调不能成为免除考核的理由，所有辅警均应接受考核管理。本题表述错误。", "tags": "广东辅警笔试 判断题 辅警管理办法", "_idx": 2123}, {"num": 2125, "batch": "辅警管理办法", "type": "bool", "stem": "年度考核不合格，经教育仍无明显改变，或者连续两年年度考核不合格的，予以辞退。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据辅警管理相关规定，年度考核不合格，经教育仍无明显改变，或者连续两年年度考核不合格的，予以辞退。这一规定体现了对辅警工作绩效的严格要求，确保辅警队伍的整体素质和工作效能。本题表述正确。", "tags": "广东辅警笔试 判断题 辅警管理办法", "_idx": 2124}, {"num": 2126, "batch": "辅警管理办法", "type": "bool", "stem": "辅警休假期间，遇到紧急任务或特殊情况，应立即停止休假，并且不可安排补休。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据辅警管理相关规定，辅警休假期间遇到紧急任务或特殊情况，应当服从安排立即停止休假返回工作岗位，事后应当安排补休。休假期间因工作需要被召回属于正常情形，但应当保障辅警的休息权益，安排补休。本题称'不可安排补休'表述错误。", "tags": "广东辅警笔试 判断题 辅警管理办法", "_idx": 2125}, {"num": 2127, "batch": "辅警管理办法", "type": "bool", "stem": "工作时间擅自脱岗，视情节予以警告、严重警告、延迟晋升层级或记过并降级处理;屡教不改或造成严重后果的，予以劝退。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据辅警管理相关规定，工作时间擅自脱岗的，视情节轻重予以警告、严重警告、延迟晋升层级或记过并降级处理；屡教不改或造成严重后果的，予以劝退或辞退。脱岗行为严重影响工作秩序和警务安全，必须予以严肃处理。本题表述正确。", "tags": "广东辅警笔试 判断题 辅警管理办法", "_idx": 2126}, {"num": 2128, "batch": "辅警管理办法", "type": "bool", "stem": "辅警一年内迟到、早退超过两次的予以警告，迟到、早退超过五次的予以严重警告，屡教不改的予以延迟晋升层级。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据辅警管理相关规定，辅警一年内迟到、早退超过两次的予以警告，迟到、早退超过五次的予以严重警告，屡教不改的予以延迟晋升层级。该规定体现了对辅警工作纪律的严格要求，通过阶梯式处分督促辅警遵守考勤制度。本题表述正确。", "tags": "广东辅警笔试 判断题 辅警管理办法", "_idx": 2127}, {"num": 2129, "batch": "辅警管理办法", "type": "bool", "stem": "违反出国（境）审批要求的，视情节予以警告、严重警告或记过处理;屡教不改或造成严重后果的，予以辞退。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据辅警管理相关规定，违反出国（境）审批要求的，视情节予以警告、严重警告或记过处理；屡教不改或造成严重后果的，予以辞退。出入境管理是辅警纪律管理的重要内容，未经审批擅自出入境可能带来安全隐患。本题表述正确。", "tags": "广东辅警笔试 判断题 辅警管理办法", "_idx": 2128}, {"num": 2130, "batch": "辅警管理办法", "type": "bool", "stem": "辅警工作时间（含工间休息时间）饮酒或宿醉上岗的，可予以辞退。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据辅警管理相关规定，辅警工作时间（含工间休息时间）饮酒或宿醉上岗的，严重影响工作纪律和队伍形象，可予以辞退。饮酒上岗不仅影响正常工作履行，还可能造成安全事故和执法风险，属于严重违纪行为。本题表述正确。", "tags": "广东辅警笔试 判断题 辅警管理办法", "_idx": 2129}, {"num": 2131, "batch": "辅警管理办法", "type": "bool", "stem": "辅警在工作期间，因违反管理规定、操作规范或其他个人原因造成公安机关经济损失的，应承担相应的赔偿责任。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据辅警管理相关规定，辅警在工作期间因违反管理规定、操作规范或其他个人原因造成公安机关经济损失的，应当承担相应的赔偿责任。这体现了权责一致的原则，辅警应当对其过错行为造成的损害后果承担经济赔偿责任。本题表述正确。", "tags": "广东辅警笔试 判断题 辅警管理办法", "_idx": 2130}, {"num": 2132, "batch": "辅警管理办法", "type": "bool", "stem": "责任民警应尽职尽责认真做好对结对辅警的指导和管理工作，对辅警日常纪律、工作情况、生活作风进行全面监督。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据辅警管理相关规定，责任民警应尽职尽责认真做好对结对辅警的指导和管理工作，对辅警日常纪律、工作情况、生活作风进行全面监督。这体现了'谁使用、谁管理、谁负责'的管理原则，确保辅警在民警的有效监督下开展工作。本题表述正确。", "tags": "广东辅警笔试 判断题 辅警管理办法", "_idx": 2131}, {"num": 2133, "batch": "辅警管理办法", "type": "bool", "stem": "对于责任民警合理的工作安排，辅警必须听从指挥，不得推诿。对于责任民警的不正当要求，辅警亦必须执行。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据辅警管理相关规定，对于责任民警合理的工作安排，辅警必须听从指挥，不得推诿。但对于责任民警的不正当要求，辅警有权拒绝执行，并非必须执行。辅警应当服从合法合理的指令，对违法违规的要求有权抵制。本题表述错误。", "tags": "广东辅警笔试 判断题 辅警管理办法", "_idx": 2132}, {"num": 2134, "batch": "辅警管理办法", "type": "bool", "stem": "一名民警可根据实际工作结对一名或多名辅警。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "A", "explanation": "根据辅警管理相关规定，一名民警可根据实际工作需要结对一名或多名辅警，形成警辅结对关系。结对方式灵活安排，以适应不同岗位和工作量的实际需求，便于民警对辅警进行日常指导和管理。本题表述正确。", "tags": "广东辅警笔试 判断题 辅警管理办法", "_idx": 2133}, {"num": 2135, "batch": "辅警管理办法", "type": "bool", "stem": "如辅警存在借调情形的，则无需重新调整警辅结对关系。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据辅警管理相关规定，辅警因借调等原因变更工作岗位的，应当重新调整警辅结对关系，确保借调期间辅警仍有对应的责任民警进行管理和指导。借调不调整结对关系会导致管理缺位，不符合辅警管理要求。本题表述错误。", "tags": "广东辅警笔试 判断题 辅警管理办法", "_idx": 2134}, {"num": 2136, "batch": "辅警管理办法", "type": "bool", "stem": "辅警违规违纪属于辅警个人行为，与责任民警无关，无需承担任何责任。", "options": [{"letter": "A", "text": "正确"}, {"letter": "B", "text": "错误"}], "answer": "B", "explanation": "根据辅警管理相关规定，辅警违规违纪不仅属于个人行为，责任民警也应当承担相应的管理监督责任。警辅结对制度要求责任民警对辅警进行日常管理和监督，辅警出现违规违纪问题，说明责任民警管理不到位，需承担连带责任。本题表述错误。", "tags": "广东辅警笔试 判断题 辅警管理办法", "_idx": 2135}];
window.DATA_INTERVIEW = [];